add_evangelie_matfea {
  ["номер"] = 1,
  ["комментарий"] = "Мф., 1 зач., I, 1–25.",
  ["текст_ру"] = "Кни́га родства́ Иису́са Христа́, Сы́на Дави́дова, Сы́на Авраа́мля. Авраа́м роди́ Исаа́ка. Исаа́к же роди́ Иа́кова. Иа́ков же роди́ Иу́ду и бра́тию его́. Иу́да же роди́ Фаре́са и За́ра от Фама́ры. Фаре́с же роди́ Есро́ма. Есро́м же роди́ Ара́ма. Ара́м же роди́ Аминада́ва. Аминада́в же роди́ Наассо́на. Наассо́н же роди́ Салмо́на. Салмо́н же роди́ Воо́за от Раха́вы. Воо́з же роди́ Ови́да от Ру́фы. Ови́д же роди́ Иессе́я. Иессе́й же роди́ Дави́да царя́. Дави́д же царь роди́ Соломо́на от Ури́ины. Соломо́н же роди́ Ровоа́ма. Ровоа́м же роди́ Ави́я. Ави́я же роди́ А́са. А́са же роди́ Иосафа́та. Иосафа́т же роди́ Иора́ма. Иора́м же роди́ Ози́ю. Ози́я же роди́ Иоафа́ма. Иоафа́м же роди́ Аха́за. Аха́з же роди́ Езеки́ю. Езеки́я же роди́ Манасси́ю. Манасси́я же роди́ Амо́на. Амо́н же роди́ Иоси́ю. Иоси́я же роди́ Иехо́нию и бра́тию его́, в преселе́ние Вавило́нское. По преселе́нии же Вавило́нстем, Иехо́ния роди́ Салафи́иля. Салафи́иль же роди́ Зорова́веля. Зорова́вель же роди́ Авиу́да. Авиу́д же роди́ Елиаки́ма. Елиаки́м же роди́ Азо́ра. Азо́р же роди́ Садо́ка. Садо́к же роди́ Ахи́ма. Ахи́м же роди́ Елиу́да. Елиу́д же роди́ Елеаза́ра. Елеаза́р же роди́ Матфа́на. Матфа́н же роди́ Иа́кова. Иа́ков же роди́ Ио́сифа, му́жа Мари́ина, из Нея́же роди́ся Иису́с, глаго́лемый Христо́с. Всех же родо́в от Авраа́ма до Дави́да, ро́дове четырена́десяте, и от Дави́да до преселе́ния Вавило́нскаго, ро́дове четырена́десяте, и от преселе́ния Вавило́нскаго до Христа́, ро́дове четырена́десяте. Иису́с Христо́во Рождество́ си́це бе: обруче́нней у́бо бы́вши Ма́тери Его́ Мари́и Ио́сифови, пре́жде да́же не сни́тися и́ма, обре́теся иму́щи во чре́ве от Ду́ха Свя́та. Ио́сиф же, муж Ея́, пра́веден сый и не хотя́ Ея́ обличи́ти, восхоте́ тай пусти́ти Ю́. Сия́ же ему́ помы́слившу, се А́нгел Госпо́день во сне яви́ся ему́, глаго́ля: Ио́сифе, сы́не Дави́дов, не убо́йся прия́ти Мариа́м, жены́ твоея́, ро́ждшее бо ся в Ней от Ду́ха есть Свя́та. Роди́т же Сы́на, и нарече́ши и́мя Ему́ Иису́с. Той бо спасе́т лю́ди Своя́ от грех их. Сие́ же все бысть, да сбу́дется рече́нное от Го́спода проро́ком, глаго́лющим: се Де́ва во чре́ве прии́мет и роди́т Сы́на, и нареку́т и́мя Ему́ Емману́ил, е́же есть сказа́емо, с на́ми Бог. Воста́в же Ио́сиф от сна, сотвори́, я́коже повеле́ ему́ А́нгел Госпо́день, и прия́т Жену́ свою́. И не зна́яше Ея́, до́ндеже роди́ Сы́на Своего́ пе́рвенца, и нарече́ и́мя Ему́ Иису́с. ",
  ["текст_цс"] = "Кни́га родства̀ і҆и҃са хрⷭ҇та̀, сн҃а дв҃дова, сн҃а а҆враа́млѧ. а҆враа́мъ родѝ і҆саа́ка. і҆саа́къ же родѝ і҆а́кѡва. і҆а́кѡвъ же родѝ і҆ꙋ́дꙋ, и҆ бра́тїю є҆гѡ̀. і҆ꙋ́да же родѝ фаре́са и҆ за́ра ѿ ѳама́ры. фаре́съ же родѝ є҆срѡ́ма. є҆срѡ́мъ же родѝ а҆ра́ма. а҆ра́мъ же родѝ а҆мїнада́ва. а҆мїнада́въ же родѝ наассѡ́на. наассѡ́нъ же родѝ салмѡ́на. салмѡ́нъ же родѝ воо́за ѿ раха́вы. воо́зъ же родѝ ѡ҆ви́да ѿ рꙋ́ѳы. ѡ҆ви́дъ же родѝ і҆ессе́а. і҆ессе́й же родѝ дв҃да цр҃ѧ̀. дв҃дъ же цр҃ь родѝ соломѡ́на ѿ ᲂу҆рі́ины. соломѡ́нъ же родѝ ровоа́ма. ровоа́мъ же родѝ а҆ві́а. а҆ві́а же родѝ а҆́са. а҆́са же родѝ і҆ѡсафа́та. і҆ѡсафа́тъ же родѝ і҆ѡра́ма. і҆ѡра́мъ же родѝ ѻ҆зі́ю. ѻ҆зі́а же родѝ і҆ѡаѳа́ма. і҆ѡаѳа́мъ же родѝ а҆ха́за. а҆ха́зъ же родѝ є҆зекі́ю. є҆зекі́а же родѝ манассі́ю. манассі́а же родѝ а҆мѡ́на. а҆мѡ́нъ же родѝ і҆ѡсі́ю. і҆ѡсі́а же родѝ і҆ехо́нїю, и҆ бра́тїю є҆гѡ̀, въ преселе́нїе вавѷлѡ́нское. по преселе́нїи же вавѷлѡ́нстѣмъ, і҆ехо́нїа родѝ салаѳі́илѧ. салаѳі́иль же родѝ зорова́велѧ. зорова́вель же родѝ а҆вїꙋ́да. а҆вїꙋ́дъ же родѝ є҆лїакі́ма. є҆лїакі́мъ же родѝ а҆зѡ́ра. а҆зѡ́ръ же родѝ садѡ́ка. садѡ́къ же родѝ а҆хі́ма. а҆хі́мъ же родѝ є҆лїꙋ́да. є҆лїꙋ́дъ же родѝ є҆леаза́ра. є҆леаза́ръ же родѝ матѳа́на. матѳа́нъ же родѝ і҆а́кѡва. і҆а́кѡвъ же родѝ і҆ѡ́сифа, мꙋ́жа мр҃і́ина, и҆з̾ неѧ́же роди́сѧ і҆и҃съ, глаго́лемый хрⷭ҇то́съ. всѣ́хъ же родѡ́въ ѿ а҆враа́ма до дв҃да, ро́дове четырена́десѧте, и҆ ѿ дв҃да до преселе́нїѧ вавѷлѡ́нскагѡ, ро́дове четырена́десѧте, и҆ ѿ преселе́нїѧ вавѷлѡ́нскагѡ до хрⷭ҇та̀, ро́дове четырена́десѧте. і҆и҃съ хрⷭ҇то́во ржⷭ҇тво̀ си́це бѣ̀: ѡ҆брꙋче́ннѣй ᲂу҆́бѡ бы́вши мт҃ри є҆гѡ̀ мр҃і́и і҆ѡ́сифови, пре́жде да́же не сни́тисѧ и҆́ма, ѡ҆брѣ́тесѧ и҆мꙋ́щи во чре́вѣ ѿ дх҃а ст҃а. і҆ѡ́сифъ же мꙋ́жъ є҆ѧ̀ пра́веденъ сы́й и҆ не хотѧ̀ є҆ѧ̀ ѡ҆бличи́ти, восхотѣ̀ та́й пꙋсти́ти ю҆̀. сїѧ̑ же є҆мꙋ̀ помы́слившꙋ, сѐ а҆́гг҃лъ гдⷭ҇нь во снѣ̀ ꙗ҆ви́сѧ є҆мꙋ̀, глаго́лѧ: і҆ѡ́сифе сы́не дв҃довъ, не ᲂу҆бо́йсѧ прїѧ́ти марїа́мъ жены̀ твоеѧ̀: ро́ждшее бо сѧ въ не́й ѿ дх҃а є҆́сть ст҃а. роди́тъ же сн҃а, и҆ нарече́ши и҆́мѧ є҆мꙋ̀ і҆и҃съ, то́й бо спасе́тъ лю́ди своѧ̀ ѿ грѣ̑хъ и҆́хъ. сїе́ же всѐ бы́сть, да сбꙋ́детсѧ рече́нное ѿ гдⷭ҇а проро́комъ, глаго́лющимъ: сѐ дв҃а во чре́вѣ прїи́метъ, и҆ роди́тъ сн҃а, и҆ нарекꙋ́тъ и҆́мѧ є҆мꙋ̀ є҆мманꙋ́илъ, є҆́же є҆́сть сказа́емо, съ на́ми бг҃ъ. воста́въ же і҆ѡ́сифъ ѿ сна̀, сотворѝ ꙗ҆́коже повелѣ̀ є҆мꙋ̀ а҆́гг҃лъ гдⷭ҇нь: и҆ прїѧ́тъ женꙋ̀ свою̀, и҆ не зна́ѧше є҆ѧ̀, до́ндеже родѝ сн҃а своего̀ пе́рвенца, и҆ наречѐ и҆́мѧ є҆мꙋ̀ і҆и҃съ. ",
}

