}

add_evangelie_matfea {
  ["номер"] = 3,
  ["комментарий"] = "Мф., 3 зач., II, 1–12.",
  ["текст_ру"] = "Иису́су ро́ждшуся в Вифлее́ме Иуде́йстем во дни И́рода царя́, се волсви́ от восто́к приидо́ша во Иерусали́м, глаго́люще: где есть рожде́йся Царь Иуде́йский? Ви́дехом бо звезду́ Его́ на восто́це и приидо́хом поклони́тися Ему́. Слы́шав же, И́род царь смути́ся, и весь Иерусали́м с ним. И собра́в вся первосвяще́нники и кни́жники людски́я, вопроша́ше от них: где Христо́с ражда́ется? Они́ же реко́ша ему́: в Вифлее́ме Иуде́йстем. Та́ко бо пи́сано есть проро́ком: и ты, Вифлее́ме, земле́ Иу́дова, ничи́мже ме́ньши еси́ во влады́ках Иу́довых, из тебе́ бо изы́дет Во́ждь, и́же упасе́т лю́ди Моя́ Изра́иля. Тогда́ И́род тай призва́ волхвы́ и испытова́ше от них вре́мя я́вльшияся звезды́. И посла́в их в Вифлее́м, рече́: ше́дше, испыта́йте изве́стно о Отроча́ти; егда́ же обря́щете, возвести́те ми, я́ко да и аз, шед, поклоню́ся Ему́. Они́ же, послу́шавше царя́, идо́ша. И се звезда́, ю́же ви́деша на восто́це, идя́ше пред ни́ми, до́ндеже, прише́дше, ста верху́, иде́же бе Отроча́. Ви́девше же звезду́, возра́довашася ра́достию ве́лиею зело́. И прише́дше в хра́мину, ви́деша Отроча́ с Мари́ею, Ма́терию Его́, и па́дше, поклони́шася Ему́, и отве́рзше сокро́вища своя́, принесо́ша Ему́ да́ры: зла́то, и лива́н, и сми́рну. И весть прие́мше во сне, не возврати́тися ко И́роду, ины́м путе́м отыдо́ша во страну́ свою́. ",
  ["текст_цс"] = "І҆и҃сꙋ ро́ждшꙋсѧ въ виѳлее́мѣ і҆ꙋде́йстѣмъ, во днѝ и҆́рѡда царѧ̀, сѐ волсвѝ ѿ востѡ́къ прїидо́ша во і҆ерꙋсали́мъ, глаго́люще: гдѣ́ є҆сть рожде́йсѧ цр҃ь і҆ꙋде́йскїй; ви́дѣхомъ бо ѕвѣздꙋ̀ є҆гѡ̀ на восто́цѣ, и҆ прїидо́хомъ поклони́тисѧ є҆мꙋ̀. слы́шавъ же и҆́рѡдъ ца́рь, смꙋти́сѧ, ѝ ве́сь  і҆ерꙋсали́м съ ни́мъ. и҆ собра́въ всѧ̀ первосвѧще́нники, и҆ кни́жники людскі́ѧ, вопроша́ше ѿ ни́хъ: гдѣ̀ хрⷭ҇то́съ ражда́етсѧ; ѻ҆ни́ же реко́ша є҆мꙋ̀: въ виѳлее́мѣ і҆ꙋде́йстѣмъ. та́кѡ бо пи́сано є҆́сть проро́комъ: и҆ ты̀ виѳлее́ме землѐ і҆ꙋ́дова, ничи́мже ме́ньши є҆сѝ во влады́кахъ і҆ꙋ́довыхъ: и҆з̾ тебе́ бо и҆зы́детъ во́ждь, и҆́же ᲂу҆пасе́тъ лю́ди моѧ̀ і҆и҃лѧ. тогда̀ и҆́рѡдъ та́й призва̀ волхвы̀, и҆ и҆спытова́ше ѿ ни́хъ вре́мѧ ꙗ҆́вльшїѧсѧ ѕвѣзды̀. и҆ посла́въ и҆̀хъ въ виѳлее́мъ, речѐ: ше́дше и҆спыта́йте и҆звѣ́стнѡ ѡ҆ ѻ҆троча́ти: є҆гда́ же ѡ҆брѧ́щете, возвѣсти́те мѝ, ꙗ҆́кѡ да и҆ а҆́зъ ше́дъ поклоню́сѧ є҆мꙋ̀. ѻ҆ни́ же послꙋ́шавше царѧ̀, и҆до́ша. и҆ сѐ ѕвѣзда̀, ю҆́же ви́дѣша на восто́цѣ, и҆дѧ́ше пред̾ ни́ми, до́ндеже прише́дши ста̀ верхꙋ̀, и҆дѣ́же бѣ̀ ѻ҆троча̀. ви́дѣвше же ѕвѣздꙋ̀, возра́довашасѧ ра́достїю ве́лїею ѕѣлѡ̀. и҆ прише́дше въ хра́минꙋ, ви́дѣша ѻ҆троча̀ съ мр҃і́ею мт҃рїю є҆гѡ̀, и҆ па́дше поклони́шасѧ є҆мꙋ̀: и҆ ѿве́рзше сокрѡ́вища своѧ̀, принесо́ша є҆мꙋ̀ да́ры: зла́то, и҆ лїва́нъ, и҆ смѵ́рнꙋ. и҆ вѣ́сть прїе́мше во снѣ̀, не возврати́тисѧ ко и҆́рѡдꙋ, и҆ны́мъ пꙋте́мъ ѿидо́ша во странꙋ̀ свою̀. ",
}

add_evangelie_matfea {
  ["номер"] = 4,
  ["комментарий"] = "Мф., 4 зач., II, 13–23.",
  ["текст_ру"] = "Отше́дшим волхво́м, се А́нгел Госпо́день во сне яви́ся Ио́сифу, глаго́ля: воста́в, поими́ Отроча́ и Ма́терь Его́, и бежи́ во Еги́пет, и бу́ди та́мо, до́ндеже реку́ ти, хо́щет бо И́род иска́ти Отроча́те, да погуби́т Е́. Он же, воста́в, поя́т Отроча́ и Ма́терь Его́ но́щию и оты́де во Еги́пет. И бе та́мо до уме́ртвия И́родова, да сбу́дется рече́нное от Го́спода проро́ком, глаго́лющим: от Еги́пта воззва́х Сы́на Моего́. Тогда́ И́род, ви́дев, я́ко пору́ган бысть от волхво́в, разгне́вася зело́ и посла́в, изби́ вся де́ти, су́щия в Вифлее́ме и во всех преде́лех его́, от двою́ ле́ту и нижа́йше по вре́мени, е́же изве́стно испыта́ от волхво́в. Тогда́ сбы́стся рече́нное Иереми́ем проро́ком, глаго́лющим: глас в Ра́ме слы́шан бысть, плачь, и рыда́ние, и вопль мног. Рахи́ль пла́чущися чад свои́х и не хотя́ше уте́шитися, я́ко не суть. Уме́ршу же И́роду, се А́нгел Госпо́день во сне яви́ся Ио́сифу во Еги́пте, глаго́ля: воста́в, поими́ Отроча́ и Ма́терь Его́ и иди́ в зе́млю Изра́илеву, изомро́ша бо и́щущии ду́шу Отроча́те. Он же воста́в, поя́т Отроча́ и Ма́терь Его́ и прии́де в зе́млю Изра́илеву. Слы́шав же, я́ко Архела́й ца́рствует во Иуде́и вме́сто И́рода, отца́ своего́, убоя́ся та́мо ити́. Весть же прие́мь во сне, оты́де в преде́лы Галиле́йския. И прише́д, всели́ся во гра́де, нарица́емем Назаре́т. Я́ко да сбу́дется рече́нное проро́ки, я́ко Назоре́й нарече́тся. ",
  ["текст_цс"] = "Ѿше́дшымъ волхвѡ́мъ, сѐ а҆́гг҃лъ гдⷭ҇нь во снѣ̀ ꙗ҆ви́сѧ і҆ѡ́сифꙋ, глаго́лѧ: воста́въ поимѝ ѻ҆троча̀ и҆ мт҃рь є҆гѡ̀, и҆ бѣжѝ во є҆гѵ́петъ, и҆ бꙋ́ди та́мѡ, до́ндеже рекꙋ́ ти: хо́щетъ бо и҆́рѡдъ и҆ска́ти ѻ҆троча́те, да погꙋби́тъ є҆̀. ѻ҆́нъ же воста́въ, поѧ́тъ ѻ҆троча̀ и҆ мт҃рь є҆гѡ̀ но́щїю, и҆ ѿи́де во є҆гѵ́петъ. и҆ бѣ̀ та́мѡ до ᲂу҆ме́ртвїѧ и҆́рѡдова, да сбꙋ́детсѧ рече́нное ѿ гдⷭ҇а проро́комъ глаго́лющимъ: ѿ є҆гѵ́пта воззва́хъ сн҃а моего̀. тогда̀ и҆́рѡдъ ви́дѣвъ, ꙗ҆́кѡ порꙋ́ганъ бы́сть ѿ волхвѡ́въ, разгнѣ́васѧ ѕѣлѡ̀, и҆ посла́въ и҆збѝ всѧ̀ дѣ́ти сꙋ́щыѧ въ виѳлее́мѣ, и҆ во всѣ́хъ предѣ́лѣхъ є҆гѡ̀, ѿ двою̀ лѣ́тꙋ и҆ нижа́йше, по вре́мени, є҆́же и҆звѣ́стнѡ и҆спыта̀ ѿ волхвѡ́въ. тогда̀ сбы́стсѧ рече́нное і҆еремі́емъ проро́комъ, глаго́лющимъ: гла́съ въ ра́мѣ слы́шанъ бы́сть, пла́чь, и҆ рыда́нїе, и҆ во́пль мно́гъ: рахи́ль пла́чꙋщисѧ ча́дъ свои́хъ, и҆ не хотѧ́ше ᲂу҆тѣ́шитисѧ, ꙗ҆́кѡ не сꙋ́ть. ᲂу҆ме́ршꙋ же и҆́рѡдꙋ, сѐ а҆́гг҃лъ гдⷭ҇нь во снѣ̀ ꙗ҆ви́сѧ і҆ѡ́сифꙋ во є҆гѵ́птѣ, глаго́лѧ: воста́въ поимѝ ѻ҆троча̀ и҆ мт҃рь є҆гѡ̀, и҆ и҆дѝ въ зе́млю і҆и҃левꙋ, и҆зомро́ша бо и҆́щꙋщїи дꙋ́шꙋ ѻ҆троча́те. ѻ҆́нъ же воста́въ, поѧ́тъ ѻ҆троча̀ и҆ мт҃рь є҆гѡ̀, и҆ прїи́де въ зе́млю і҆и҃левꙋ. слы́шавъ же, ꙗ҆́кѡ а҆рхела́й ца́рствꙋетъ во і҆ꙋде́и, вмѣ́стѡ и҆́рѡда ѻ҆тца̀ своегѡ̀, ᲂу҆боѧ́сѧ та́мѡ и҆тѝ: вѣ́сть же прїе́мъ во снѣ̀, ѿи́де въ предѣ́лы галїле́йскїѧ. и҆ прише́дъ всели́сѧ во гра́дѣ нарица́емѣмъ назаре́тъ: ꙗ҆́кѡ да сбꙋ́детсѧ рече́нное проро́ки, ꙗ҆́кѡ назѡре́й нарече́тсѧ. ",
}

add_evangelie_matfea {
  ["номер"] = 5,
  ["комментарий"] = "Мф., 5 зач., III, 1–11.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иоа́нн Крести́тель, пропове́дуя в пусты́ни Иуде́йстей и глаго́ля: пока́йтеся, прибли́жи бо ся Ца́рство Небе́сное. Сей бо есть рече́нный Иса́ием проро́ком, глаго́лющим: глас вопию́щаго в пусты́ни, угото́вайте путь Госпо́день, пра́вы твори́те стези́ Его́. Сам же Иоа́нн имя́ше ри́зу свою́ от влас вельблу́ждь и по́яс усме́н о чресле́х свои́х, снедь же его́ бе пру́жие и мед ди́вий. Тогда́ исхожда́ше к нему́ Иерусали́ма и вся Иуде́я, и вся страна́ Иорда́нская. И креща́хуся во Иорда́не от него́, испове́дающе грехи́ своя́. Ви́дев же Иоа́нн мно́ги фарисе́и и саддуке́и, гряду́ща на Креще́ние его́, рече́ им: рожде́ния ехи́днова, кто сказа́ вам бежа́ти от бу́дущаго гне́ва? Сотвори́те у́бо плод, досто́ин покая́ния. И не начина́йте глаго́лати в себе́: отца́ и́мамы Авраа́ма. Глаго́лю бо вам, я́ко мо́жет Бог от ка́мения сего́ воздви́гнути ча́да Авраа́му. Уже́ бо и секи́ра при ко́рени дре́ва лежи́т: вся́ко у́бо дре́во, е́же не твори́т плода́ добра́, посека́емо быва́ет и во огнь вмета́емо. Аз у́бо креща́ю вы водо́ю в покая́ние, Гряды́й же по мне, кре́плий мене́ есть, Ему́же несмь досто́ин сапоги́ понести́, Той вы крести́т Ду́хом Святы́м и огне́м. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆ѡа́ннъ крⷭ҇ти́тель, проповѣ́даѧ въ пꙋсты́ни і҆ꙋде́йстѣй, и҆ глаго́лѧ: пока́йтесѧ, прибли́жи бо сѧ црⷭ҇твїе нбⷭ҇ное. се́й бо є҆́сть рече́нный и҆са́їемъ проро́комъ, глаго́лющимъ: гла́съ вопїю́щагѡ въ пꙋсты́ни, ᲂу҆гото́вайте пꙋ́ть гдⷭ҇нь, пра́вы твори́те стєзѝ є҆гѡ̀. са́мъ же і҆ѡа́ннъ и҆мѧ́ше ри́зꙋ свою̀ ѿ вла̑съ вельблꙋ́ждь, и҆ по́ѧсъ ᲂу҆сме́нъ ѡ҆ чреслѣ́хъ свои́хъ: снѣ́дь же є҆гѡ̀ бѣ̀ прꙋ́жїе и҆ ме́дъ ди́вїй. тогда̀ и҆схожда́ше къ немꙋ̀ і҆ерꙋсали́ма, и҆ всѧ̀ і҆ꙋде́а, и҆ всѧ̀ страна̀ і҆ѻрда́нскаѧ: и҆ креща́хꙋсѧ во і҆ѻрда́нѣ ѿ негѡ̀, и҆сповѣ́дающе грѣхѝ своѧ̀. ви́дѣвъ же і҆ѡа́ннъ мно́ги фарїсе́и и҆ саддꙋке́и грѧдꙋ́щѧ на креще́нїе є҆гѡ̀, речѐ и҆̀мъ: рождє́нїѧ є҆хі́днова, кто̀ сказа̀ ва́мъ бѣжа́ти ѿ бꙋ́дꙋщагѡ гнѣ́ва; сотвори́те ᲂу҆́бѡ пло́дъ досто́инъ покаѧ́нїѧ. и҆ не начина́йте глаго́лати въ себѣ̀: ѻ҆ц҃а̀ и҆́мамы а҆враа́ма. глаго́лю бо ва́мъ, ꙗ҆́кѡ мо́жетъ бг҃ъ ѿ ка́менїѧ сегѡ̀ воздви́гнꙋти ча̑да а҆враа́мꙋ. ᲂу҆же́ бо и҆ сѣки́ра при ко́рени дре́ва лежи́тъ: всѧ́ко ᲂу҆́бѡ дре́во, є҆́же не твори́тъ плода̀ добра̀, посѣка́емо быва́етъ, и҆ во ѻ҆́гнь вмета́емо. а҆́зъ ᲂу҆́бѡ креща́ю вы̀ водо́ю въ покаѧ́нїе: грѧды́й же по мнѣ̀, крѣ́плїй менѐ є҆́сть, є҆мꙋ́же нѣ́смь досто́инъ сапогѝ понестѝ. то́й вы̀ крⷭ҇ти́тъ дх҃омъ ст҃ы́мъ и҆ ѻ҆гне́мъ. ",
}

add_evangelie_matfea {
  ["номер"] = 6,
  ["комментарий"] = "Мф., 6 зач., III, 13–17.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с от Галиле́и на Иорда́н ко Иоа́нну крести́тися от него́. Иоа́нн же возбраня́ше Ему́, глаго́ля: аз тре́бую Тобо́ю крести́тися, и Ты ли гряде́ши ко мне? Отвеща́в же, Иису́с рече́ к нему́: оста́ви ны́не, та́ко бо подо́бно есть нам испо́лнити вся́ку пра́вду. Тогда́ оста́ви Его́. И крести́вся, Иису́с взы́де а́бие от воды́, и се отверзо́шася Ему́ Небеса́, и ви́де Ду́ха Бо́жия, сходя́ща, я́ко го́лубя, и гряду́ща на Него́. И се глас с Небесе́, глаго́ля: Сей есть Сын Мой возлю́бленный, о Не́мже благоволи́х. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ ѿ галїле́и на і҆ѻрда́нъ ко і҆ѡа́ннꙋ, крⷭ҇ти́тисѧ ѿ негѡ̀. і҆ѡа́ннъ же возбранѧ́ше є҆мꙋ̀, глаго́лѧ: а҆́зъ тре́бꙋю тобо́ю крⷭ҇ти́тисѧ, и҆ ты́ ли грѧде́ши ко мнѣ̀; ѿвѣща́въ же і҆и҃съ речѐ къ немꙋ̀: ѡ҆ста́ви ны́нѣ, та́кѡ бо подо́бно є҆́сть на́мъ и҆спо́лнити всѧ́кꙋ пра́вдꙋ. тогда̀ ѡ҆ста́ви є҆го̀. и҆ крⷭ҇ти́всѧ і҆и҃съ взы́де а҆́бїе ѿ воды̀: и҆ сѐ ѿверзо́шасѧ є҆мꙋ̀ нб҃са̀, и҆ ви́дѣ дх҃а бж҃їѧ сходѧ́ща ꙗ҆́кѡ го́лꙋбѧ, и҆ грѧдꙋ́ща на него̀. и҆ сѐ гла́съ съ нб҃сѐ глаго́лѧ: се́й є҆́сть сн҃ъ мо́й возлю́бленный, ѡ҆ не́мже благоволи́хъ. ",
}

add_evangelie_matfea {
  ["номер"] = 7,
  ["комментарий"] = "Мф., 7 зач., IV, 1–11. ",
  ["текст_ру"] = "Во вре́мя о́но, возведе́н бысть Иису́с Ду́хом в пусты́ню искуси́тися от диа́вола, и пости́вся дний четы́ридесять и но́щий четы́ридесять, последи́ взалка́. И присту́пль к Нему́ искуси́тель рече́: а́ще Сын еси́ Бо́жий, рцы, да ка́мение сие́ хле́бы бу́дут. Он же отвеща́в рече́: пи́сано есть, не о хле́бе еди́ном жив бу́дет челове́к, но о вся́ком глаго́ле исходя́щем изоу́ст Бо́жиих. Тогда́ поя́т Его́ диа́вол во святы́й град, и поста́ви Его́ на криле́ церко́внем, и глаго́ла Ему́: а́ще Сын еси́ Бо́жий, ве́рзися ни́зу. Пи́сано бо есть, я́ко А́нгелом Свои́м запове́сть о Тебе́ сохрани́ти Тя, и на рука́х во́змут Тя, да не когда́ преткне́ши о ка́мень но́гу Твою́. Рече́ же ему́ Иису́с: па́ки пи́сано есть, не иску́сиши Го́спода Бо́га твоего́. Па́ки поя́т Его́ диа́вол на гору́ высоку́ зело́, и показа́ Ему́ вся ца́рствия ми́ра и сла́ву их, и глаго́ла Ему́: сия́ вся Тебе́ дам, а́ще пад поклони́ши ми ся. Тогда́ глаго́ла ему́ Иису́с: иди́ за Мно́ю, сатано́. Пи́сано бо есть: Го́споду Бо́гу твоему́ поклони́шися и Тому́ еди́ному послу́жиши. Тогда́ оста́ви Его́ диа́вол, и се А́нгели приступи́ша и служа́ху Ему́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, возведе́нъ бы́сть і҆и҃съ дх҃омъ въ пꙋсты́ню, и҆скꙋси́тисѧ ѿ дїа́вола. и҆ пости́всѧ дні́й четы́ридесѧть, и҆ но́щїй четы́ридесѧть, послѣдѝ взалка̀. и҆ пристꙋ́пль къ немꙋ̀ и҆скꙋси́тель, речѐ: а҆́ще сн҃ъ є҆сѝ бж҃їй, рцы̀, да ка́менїе сїѐ хлѣ́бы бꙋ́дꙋтъ. ѻ҆́нъ же ѿвѣща́въ речѐ: пи́сано є҆́сть, не ѡ҆ хлѣ́бѣ є҆ди́номъ жи́въ бꙋ́детъ человѣ́къ, но ѡ҆ всѧ́комъ глаго́лѣ и҆сходѧ́щемъ и҆зоꙋ́стъ бж҃їихъ. тогда̀ поѧ́тъ є҆го̀ дїа́волъ во ст҃ы́й гра́дъ, и҆ поста́ви є҆го̀ на крилѣ̀ церко́внѣмъ, и҆ глаго́ла є҆мꙋ̀: а҆́ще сн҃ъ є҆сѝ бж҃їй, ве́рзисѧ ни́зꙋ. пи́сано бо є҆́сть: ꙗ҆́кѡ а҆́гг҃лѡмъ свои́мъ заповѣ́сть ѡ҆ тебѣ̀ сохрани́ти тѧ̀, и҆ на рꙋка́хъ во́з̾мꙋтъ тѧ̀, да не когда̀ преткне́ши ѡ҆ ка́мень но́гꙋ твою̀. рече́ же є҆мꙋ̀ і҆и҃съ: па́ки пи́сано є҆́сть: не и҆скꙋ́сиши гдⷭ҇а бг҃а твоегѡ̀. па́ки поѧ́тъ є҆го̀ дїа́волъ на горꙋ̀ высокꙋ̀ ѕѣлѡ̀, и҆ показа̀ є҆мꙋ̀ всѧ̀ ца̑рствїѧ мі́ра, и҆ сла́вꙋ и҆́хъ. и҆ глаго́ла є҆мꙋ̀: сїѧ̑ всѧ̑ тебѣ̀ да́мъ, а҆́ще па́дъ поклони́ши ми сѧ. тогда̀ глаго́ла є҆мꙋ̀ і҆и҃съ: и҆дѝ за мно́ю сатано̀. пи́сано бо є҆́сть: гдⷭ҇ꙋ бг҃ꙋ твоемꙋ̀ поклони́шисѧ, и҆ томꙋ̀ є҆ди́номꙋ послꙋ́жиши. тогда̀ ѡ҆ста́ви є҆го̀ дїа́волъ, и҆ сѐ а҆́гг҃ли пристꙋпи́ша, и҆ слꙋжа́хꙋ є҆мꙋ̀. ",
}

add_evangelie_matfea {
  ["номер"] = 8,
  ["комментарий"] = "Мф., 8 зач., IV, 12–17.",
  ["текст_ру"] = "Во вре́мя о́но, слы́шав Иису́с, я́ко Иоа́нн пре́дан бысть, оты́де в Галиле́ю, и оста́вль Назаре́т, прише́д всели́ся в Капернау́м в помо́рие, в преде́лех Завуло́них и Неффали́млих. Да сбу́дется рече́нное Иса́ием проро́ком, глаго́лющим: земля́ Завуло́ня и земля́ Неффали́мля, путь мо́ря об он пол Иорда́на, Галиле́а язы́к, лю́дие седя́щии во тме ви́деша свет ве́лий, и седя́щым в стране́ и се́ни сме́ртней, свет возсия́ им. Отто́ле нача́т Иису́с пропове́дати и глаго́лати: пока́йтеся, прибли́жися бо Ца́рство Небе́сное. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, слы́шавъ і҆и҃съ, ꙗ҆́кѡ і҆ѡа́ннъ пре́данъ бы́сть, ѿи́де въ галїле́ю. и҆ ѡ҆ста́вль назаре́тъ, прише́дъ всели́сѧ въ капернаꙋ́мъ въ помо́рїе, въ предѣ́лѣхъ завꙋлѡ́нихъ и҆ нефѳалі́млихъ. да сбꙋ́детсѧ рече́нное и҆са́їемъ проро́комъ, глаго́лющимъ: землѧ̀ завꙋлѡ́нѧ, и҆ землѧ̀ нефѳалі́млѧ, пꙋ́ть мо́рѧ ѡ҆б̾ ѻ҆́нъ по́лъ і҆ѻрда́на, галїле́а ꙗ҆зы̑къ. лю́дїе сѣдѧ́щїи во тмѣ̀, ви́дѣша свѣ́тъ ве́лїй, и҆ сѣдѧ́щымъ въ странѣ̀ и҆ сѣ́ни сме́ртнѣй, свѣ́тъ возсїѧ̀ и҆̀мъ. ѿто́лѣ нача́тъ і҆и҃съ проповѣ́дати, и҆ глаго́лати: пока́йтесѧ, прибли́жисѧ бо црⷭ҇тво нбⷭ҇ное. ",
}

add_evangelie_matfea {
  ["номер"] = 9,
  ["комментарий"] = "Мф., 9 зач., IV, 18–23.",
  ["текст_ру"] = "Во вре́мя о́но, ходя́ Иису́с при мо́ри Галиле́йстем, ви́де два бра́та, Си́мона глаго́лемаго Петра́, и Андре́а бра́та его́, вмета́юща мре́жи в мо́ре, бе́ста бо ры́баря. И глаго́ла и́ма: гряди́та по Мне, и сотворю́ вы ловца́ челове́ком. Она́ же а́бие оста́вльша мре́жи, по Нем идо́ста. И преше́д отту́ду, ви́де и́на два бра́та, Иа́кова Зеведе́ева, и Иоа́нна бра́та его́, в корабли́ с Зеведе́ом отце́м ею́, завязу́юща мре́жи своя́, и воззва́ я́. О́на же а́бие оста́вльша кора́бль и отца́ своего́, по Нем идо́ста. И прохожда́ше всю Галиле́ю Иису́с, учя́ на со́нмищих их и пропове́дая Ева́нгелие Ца́рствия, изцеля́я всяк неду́г и вся́ку я́зю в лю́дех. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ходѧ̀ і҆и҃съ при мо́ри галїле́йстѣмъ, ви́дѣ два̀ бра́та, сі́мѡна глаго́лемаго петра̀, и҆ а҆ндре́а бра́та є҆гѡ̀, вмета́юща мрє́жи въ мо́ре, бѣ́ста бо ры́барѧ. и҆ глаго́ла и҆́ма: грѧди́та по мнѣ̀, и҆ сотворю́ вы ловца̀ чл҃вѣ́кѡмъ. ѻ҆́на же а҆́бїе ѡ҆ста́вльша мрє́жи, по не́мъ и҆до́ста. и҆ прише́дъ ѿтꙋ́дꙋ, ви́дѣ и҆́на два̀ бра́та, і҆а́кѡва зеведе́ева и҆ і҆ѡа́нна бра́та є҆гѡ̀, въ кораблѝ съ зеведе́омъ ѻ҆тце́мъ є҆ю̀, завѧзꙋ́юща мрє́жи своѧ̀, и҆ воззва̀ ѧ҆̀. ѻ҆́на же а҆́бїе ѡ҆ста́вльша кора́бль и҆ ѻ҆тца̀ своего̀, по не́мъ и҆до́ста. и҆ прохожда́ше всю̀ галїле́ю і҆и҃съ, ᲂу҆чѧ̀ на со́нмищахъ и҆́хъ, и҆ проповѣ́даѧ є҆ѵⷢ҇лїе црⷭ҇твїѧ, и҆сцѣлѧ́ѧ всѧ́къ недꙋ́гъ, и҆ всѧ́кꙋ ꙗ҆́зю въ лю́дехъ. ",
}

add_evangelie_matfea {
  ["номер"] = 10,
  ["комментарий"] = "Мф., 10 зач., IV, 25 – V, 12.",
  ["текст_ру"] = "Во вре́мя о́но, по Иису́се идо́ша наро́ди мно́зи от Галиле́и и десяти́ град, и от Иерусали́ма и Иуде́и, и со о́наго по́лу Иорда́на. Узре́в же наро́ды, взы́де на гору́, и се́дшу Ему́, приступи́ша к Нему́ ученицы́ Его́. И отве́рз уста́ Своя́, уча́ше их, глаго́ля: блаже́ни ни́щии ду́хом, я́ко тех есть Ца́рствие Небе́сное. Блаже́ни пла́чущии, я́ко ти́и уте́шатся. Блаже́ни кро́тцыи, я́ко ти́и насле́дят зе́млю. Блаже́ни а́лчущии и жа́ждущии пра́вды, я́ко ти́и насы́тятся. Блаже́ни ми́лостивии, я́ко ти́и поми́ловани бу́дут. Блаже́ни чи́стии се́рдцем, я́ко ти́и Бо́га у́зрят. Блаже́ни миротво́рцы, я́ко ти́и сы́нове Бо́жии нареку́тся. Блаже́ни изгна́ни пра́вды ра́ди, я́ко тех есть Ца́рствие Небе́сное. Блаже́ни есте́, егда́ поно́сят вам, и иждену́т, и реку́т всяк зол глаго́л на вы лжу́ще, Мене́ ра́ди. Ра́дуйтеся и весели́теся, я́ко мзда ва́ша мно́га на небесе́х. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, по і҆и҃сѣ и҆до́ша наро́ди мно́зи ѿ галїле́и и҆ десѧтѝ гра́дъ, и҆ ѿ і҆ерⷭ҇ли́ма, и҆ і҆ꙋде́и, и҆ со ѻ҆́нагѡ по́лꙋ і҆ѻрда́на. ᲂу҆зрѣ́въ же наро́ды, взы́де на горꙋ̀: и҆ сѣ́дшꙋ є҆мꙋ̀ пристꙋпи́ша къ немꙋ̀ ᲂу҆чн҃цы̀ є҆гѡ̀. и҆ ѿве́рзъ ᲂу҆ста̀ своѧ̀, ᲂу҆ча́ше и҆̀хъ, глаго́лѧ: бл҃же́ни ни́щїи дх҃омъ: ꙗ҆́кѡ тѣ́хъ є҆́сть црⷭ҇твїе нбⷭ҇ное. бл҃же́ни пла́чꙋщїи: ꙗ҆́кѡ ті́и ᲂу҆тѣ́шатсѧ. бл҃же́ни кро́тцыи: ꙗ҆́кѡ ті́и наслѣ́дѧтъ зе́млю. бл҃же́ни а҆́лчꙋщїи и҆ жа́ждꙋщїи пра́вды: ꙗ҆́кѡ ті́и насы́тѧтсѧ. бл҃же́ни млⷭ҇тивїи: ꙗ҆́кѡ ті́и поми́ловани бꙋ́дꙋтъ. бл҃же́ни чи́стїи се́рдцемъ: ꙗ҆́кѡ ті́и бг҃а ᲂу҆́зрѧтъ. бл҃же́ни миротво́рцы: ꙗ҆́кѡ ті́и сн҃ове бж҃їи нарекꙋ́тсѧ. бл҃же́ни и҆згна́ни пра́вды ра́ди: ꙗ҆́кѡ тѣ́хъ є҆́сть црⷭ҇твїе нбⷭ҇ное. бл҃же́ни є҆стѐ, є҆гда̀ поно́сѧтъ ва́мъ, и҆ и҆жденꙋ́тъ, и҆ рекꙋ́тъ всѧ́къ ѕо́лъ глаго́лъ на вы̀ лжꙋ́ще, менѐ ра́ди: ра́дꙋйтесѧ, и҆ весели́тесѧ, ꙗ҆́кѡ мзда̀ ва́ша мно́га на нб҃сѣ́хъ. ",
}

add_evangelie_matfea {
  ["номер"] = 10,
  ["комментарий"] = "Мф., 10 зач., IV, 25 – V, 13.",
  ["текст_ру"] = "Во вре́мя о́но, по Иису́се идо́ша наро́ди мно́зи от Галиле́и и десяти́ град, и от Иерусали́ма и Иуде́и, и со о́наго по́лу Иорда́на. Узре́в же наро́ды, взы́де на гору́, и се́дшу Ему́, приступи́ша к Нему́ ученицы́ Его́. И отве́рз уста́ Своя́, уча́ше их, глаго́ля: блаже́ни ни́щии ду́хом, я́ко тех есть Ца́рствие Небе́сное. Блаже́ни пла́чущии, я́ко ти́и уте́шатся. Блаже́ни кро́тцыи, я́ко ти́и насле́дят зе́млю. Блаже́ни а́лчущии и жа́ждущии пра́вды, я́ко ти́и насы́тятся. Блаже́ни ми́лостивии, я́ко ти́и поми́ловани бу́дут. Блаже́ни чи́стии се́рдцем, я́ко ти́и Бо́га у́зрят. Блаже́ни миротво́рцы, я́ко ти́и сы́нове Бо́жии нареку́тся. Блаже́ни изгна́ни пра́вды ра́ди, я́ко тех есть Ца́рствие Небе́сное. Блаже́ни есте́, егда́ поно́сят вам, и иждену́т, и реку́т всяк зол глаго́л на вы лжу́ще, Мене́ ра́ди. Ра́дуйтеся и весели́теся, я́ко мзда ва́ша мно́га на небесе́х, та́ко бо изгна́ша проро́ки, и́же бе́ша пре́жде вас. Вы есте́ соль земли́, а́ще же соль обуя́ет, чим осоли́тся? Нивочто́же бу́дет ктому́, то́чию да изсы́пана бу́дет вон и попира́ема челове́ки. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, по і҆и҃сѣ и҆до́ша наро́ди мно́зи ѿ галїле́и и҆ десѧтѝ гра́дъ, и҆ ѿ і҆ерⷭ҇ли́ма, и҆ і҆ꙋде́и, и҆ со ѻ҆́нагѡ по́лꙋ і҆ѻрда́на. ᲂу҆зрѣ́въ же наро́ды, взы́де на горꙋ̀: и҆ сѣ́дшꙋ є҆мꙋ̀ пристꙋпи́ша къ немꙋ̀ ᲂу҆чн҃цы̀ є҆гѡ̀. и҆ ѿве́рзъ ᲂу҆ста̀ своѧ̀, ᲂу҆ча́ше и҆̀хъ, глаго́лѧ: бл҃же́ни ни́щїи дх҃омъ: ꙗ҆́кѡ тѣ́хъ є҆́сть црⷭ҇твїе нбⷭ҇ное. бл҃же́ни пла́чꙋщїи: ꙗ҆́кѡ ті́и ᲂу҆тѣ́шатсѧ. бл҃же́ни кро́тцыи: ꙗ҆́кѡ ті́и наслѣ́дѧтъ зе́млю. бл҃же́ни а҆́лчꙋщїи и҆ жа́ждꙋщїи пра́вды: ꙗ҆́кѡ ті́и насы́тѧтсѧ. бл҃же́ни млⷭ҇тивїи: ꙗ҆́кѡ ті́и поми́ловани бꙋ́дꙋтъ. бл҃же́ни чи́стїи се́рдцемъ: ꙗ҆́кѡ ті́и бг҃а ᲂу҆́зрѧтъ. бл҃же́ни миротво́рцы: ꙗ҆́кѡ ті́и сн҃ове бж҃їи нарекꙋ́тсѧ. бл҃же́ни и҆згна́ни пра́вды ра́ди: ꙗ҆́кѡ тѣ́хъ є҆́сть црⷭ҇твїе нбⷭ҇ное. бл҃же́ни є҆стѐ, є҆гда̀ поно́сѧтъ ва́мъ, и҆ и҆жденꙋ́тъ, и҆ рекꙋ́тъ всѧ́къ ѕо́лъ глаго́лъ на вы̀ лжꙋ́ще, менѐ ра́ди: ра́дꙋйтесѧ, и҆ весели́тесѧ, ꙗ҆́кѡ мзда̀ ва́ша мно́га на нб҃сѣ́хъ. та́кѡ бо и҆згна́ша проро́ки, и҆̀же бѣ́ша пре́жде ва́съ. вы̀ є҆стѐ со́ль землѝ: а҆́ще же со́ль ѡ҆бꙋѧ́етъ, чи́мъ ѡ҆соли́тсѧ; нивочто́же бꙋ́детъ ктомꙋ̀, то́чїю да и҆зсы́пана бꙋ́детъ во́нъ, и҆ попира́ема чл҃вѣ́ки. ",
}

add_evangelie_matfea {
  ["номер"] = 11,
  ["комментарий"] = "Мф., 11 зач., V, 14–19.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: вы есте́ свет ми́ра, не мо́жет град укры́тися верху́ горы́ стоя́. Ниже́ вжига́ют свети́льника и поставля́ют его́ под спу́дом, но на све́щнице, и све́тит всем, и́же в хра́мине суть. Та́ко да просвети́тся свет ваш пред челове́ки, я́ко да ви́дят ва́ша до́брая дела́ и просла́вят Отца́ ва́шего, И́же на небесе́х. Да не мни́те, я́ко приидо́х разори́ти зако́н, или́ проро́ки: не приидо́х разори́ти, но испо́лнити. Ами́нь бо глаго́лю вам: до́ндеже пре́йдет не́бо и земля́, ио́та еди́на, или́ еди́на черта́ не пре́йдет от зако́на, до́ндеже вся бу́дут. И́же а́ще разори́т еди́ну за́поведий сих ма́лых и нау́чит та́ко челове́ки, мний нарече́тся в Ца́рствии Небе́снем, а и́же сотвори́т и нау́чит, сей ве́лий нарече́тся в Ца́рствии Небе́снем. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: вы̀ є҆стѐ свѣ́тъ мі́ра: не мо́жетъ гра́дъ ᲂу҆кры́тисѧ верхꙋ̀ горы̀ стоѧ̀. нижѐ вжига́ютъ свѣти́льника, и҆ поставлѧ́ютъ є҆го̀ под̾ спꙋ́домъ, но на свѣ́щницѣ, и҆ свѣ́титъ всѣ̑мъ, и҆̀же въ хра́минѣ сꙋ́ть. та́кѡ да просвѣти́тсѧ свѣ́тъ ва́шъ пред̾ человѣ́ки, ꙗ҆́кѡ да ви́дѧтъ ва́ша дѡ́браѧ дѣла̀: и҆ просла́вѧтъ ѻ҆ц҃а̀ ва́шего, и҆́же на нб҃сѣ́хъ. да не мни́те, ꙗ҆́кѡ прїидо́хъ разори́ти зако́нъ, и҆лѝ проро́ки: не прїидо́хъ разори́ти, но и҆спо́лнити. а҆ми́нь бо глаго́лю ва́мъ: до́ндеже пре́йдетъ нб҃о и҆ землѧ̀, і҆ѡ́та є҆ди́на, и҆лѝ є҆ди́на черта̀ не пре́йдетъ ѿ зако́на, до́ндеже всѧ̑ бꙋ́дꙋтъ. и҆́же а҆́ще разори́тъ є҆ди́нꙋ за́повѣдей си́хъ ма́лыхъ, и҆ наꙋчи́тъ та́кѡ человѣ́ки, мні́й нарече́тсѧ въ црⷭ҇твїи нбⷭ҇нѣмъ: а҆ и҆́же сотвори́тъ и҆ наꙋчи́тъ, се́й ве́лїй нарече́тсѧ въ црⷭ҇твїи нбⷭ҇нѣмъ. ",
}

add_evangelie_matfea {
  ["номер"] = 12,
  ["комментарий"] = "Мф., 12 зач., V, 20–26.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: я́ко а́ще не избу́дет пра́вда ва́ша па́че кни́жник и фарисе́й, не вни́дете в Ца́рствие Небе́сное. Слы́шасте, я́ко рече́но бысть дре́вним: не убие́ши, и́же бо а́ще убие́т, пови́нен есть суду́. Аз же глаго́лю вам, я́ко всяк гне́ваяйся на бра́та своего́ всу́е пови́нен есть суду́: и́же бо а́ще рече́т бра́ту своему́: рака́, пови́нен есть со́нмищу, а и́же рече́т: уро́де, пови́нен есть гее́нне о́гненней. А́ще у́бо принесе́ши дар твой ко олтарю́ и ту помяне́ши, я́ко брат твой и́мать не́что на тя: оста́ви ту дар твой пред олтаре́м и шед пре́жде смири́ся с бра́том твои́м, и тогда́ прише́д принеси́ дар твой. Бу́ди увещава́яся с сопе́рником твои́м ско́ро, до́ндеже еси́ на пути́ с ним, да не преда́ст тебе́ сопе́рник судии́, и судия́ тя преда́ст слузе́, и в темни́цу вве́ржен бу́деши. Ами́нь глаго́лю тебе́: не изы́деши отту́ду, до́ндеже возда́си после́дний кодра́нт. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: ꙗ҆́кѡ а҆́ще не и҆збꙋ́детъ пра́вда ва́ша па́че кни̑жникъ и҆ фарїсє́й, не вни́дете въ црⷭ҇твїе нбⷭ҇ное. слы́шасте, ꙗ҆́кѡ рече́но бы́сть дрє́внимъ: не ᲂу҆бїе́ши: и҆́же бо а҆́ще ᲂу҆бїе́тъ, пови́ненъ є҆́сть сꙋдꙋ̀. а҆́зъ же глаго́лю ва́мъ: ꙗ҆́кѡ всѧ́къ гнѣ́ваѧйсѧ на бра́та своего̀ всꙋ́е, пови́ненъ є҆́сть сꙋдꙋ̀: и҆́же бо а҆́ще рече́тъ бра́тꙋ своемꙋ̀, рака̀, пови́ненъ є҆́сть со́нмищꙋ: а҆ и҆́же рече́тъ, ᲂу҆ро́де, пови́ненъ є҆́сть гее́ннѣ ѻ҆́гненнѣй. а҆́ще ᲂу҆́бѡ принесе́ши да́ръ тво́й ко ѻ҆лтарю̀, и҆ тꙋ̀ помѧне́ши, ꙗ҆́кѡ бра́тъ тво́й и҆́мать нѣ́что на тѧ̀: ѡ҆ста́ви тꙋ̀ да́ръ тво́й пред̾ ѻ҆лтаре́мъ, и҆ ше́дъ пре́жде смири́сѧ съ бра́томъ твои́мъ, и҆ тогда̀ прише́дъ принесѝ да́ръ тво́й. бꙋ́ди ᲂу҆вѣщава́ѧсѧ съ сопе́рникомъ твои́мъ ско́рѡ, до́ндеже є҆сѝ на пꙋтѝ съ ни́мъ: да не преда́стъ тебѐ сопе́рникъ сꙋдїѝ, и҆ сꙋдїѧ̀ тѧ̀ преда́стъ слꙋзѣ̀, и҆ въ темни́цꙋ вве́рженъ бꙋ́деши. а҆ми́нь глаго́лю тебѣ̀: не и҆зы́деши ѿтꙋ́дꙋ, до́ндеже возда́си послѣ́днїй кодра́нтъ. ",
}

add_evangelie_matfea {
  ["номер"] = 13,
  ["комментарий"] = "Мф., 13 зач., V, 27–32.",
  ["текст_ру"] = "Рече́ Госпо́дь: слы́шасте, я́ко рече́но бысть дре́вним: не прелюбы́ сотвори́ши. Аз же глаго́лю вам, я́ко всяк, и́же воззри́т на жену́ ко е́же вожделе́ти ей, уже́ любоде́йствова с не́ю в се́рдце свое́м. А́ще же о́ко твое́ десно́е соблажня́ет тя, изми́ е́ и ве́рзи от себе́, у́не бо ти есть, да поги́бнет еди́н от уд твои́х, а не все те́ло твое́ вве́ржено бу́дет в гее́нну о́гненную. И а́ще десна́я твоя́ рука́ соблажня́ет тя, усецы́ ю́ и ве́рзи от себе́, у́не бо ти есть, да поги́бнет еди́н от уд твои́х, а не все те́ло твое́ вве́ржено бу́дет в гее́нну. Рече́но же бысть, я́ко и́же а́ще пу́стит жену́ свою́, да даст ей кни́гу распу́стную. Аз же глаго́лю вам, я́ко всяк отпуща́яй жену́ свою́, ра́зве словесе́ любоде́йнаго, твори́т ю́ прелюбоде́йствовати. И и́же пущени́цу по́ймет, прелюбоде́йствует. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: слы́шасте, ꙗ҆́кѡ рече́но бы́сть дрє́внимъ: не прелюбы̀ сотвори́ши. а҆́зъ же глаго́лю ва́мъ: ꙗ҆́кѡ всѧ́къ и҆́же воззри́тъ на женꙋ̀, ко є҆́же вожделѣ́ти є҆́й, ᲂу҆жѐ любодѣ́йствова съ не́ю въ се́рдцѣ свое́мъ. а҆́ще же ѻ҆́ко твоѐ десно́е соблажнѧ́етъ тѧ̀, и҆змѝ є҆̀, и҆ ве́рзи ѿ себѐ: ᲂу҆́не бо тѝ є҆́сть, да поги́бнетъ є҆ди́нъ ѿ ᲂу҆́дъ твои́хъ, а҆ не всѐ тѣ́ло твоѐ вве́ржено бꙋ́детъ въ гее́ннꙋ ѻ҆́гненнꙋю. и҆ а҆́ще десна́ѧ твоѧ̀ рꙋка̀ соблажнѧ́етъ тѧ̀, ᲂу҆сѣцы̀ ю҆̀, и҆ ве́рзи ѿ себѐ: ᲂу҆́не бо тѝ є҆́сть да поги́бнетъ є҆ди́нъ ѿ ᲂу҆́дъ твои́хъ, а҆ не всѐ тѣ́ло твоѐ вве́ржено бꙋ́детъ въ гее́ннꙋ. рече́но же бы́сть: ꙗ҆́кѡ и҆́же а҆́ще пꙋ́ститъ женꙋ̀ свою̀, да да́стъ є҆́й кни́гꙋ распꙋ́стнꙋю. а҆́зъ же глаго́лю ва́мъ: ꙗ҆́кѡ всѧ́къ ѿпꙋща́ѧй женꙋ̀ свою̀, ра́звѣ словесѐ любодѣ́йнагѡ, твори́тъ ю҆̀ прелюбодѣ́йствовати. и҆ и҆́же пꙋщени́цꙋ по́йметъ, прелюбодѣ́йствꙋетъ. ",
}

add_evangelie_matfea {
  ["номер"] = 14,
  ["комментарий"] = "Мф., 14 зач., V, 33–41.",
  ["текст_ру"] = "Рече́ Госпо́дь: слы́шасте, я́ко рече́но бысть дре́вним: не во лжу клене́шися, возда́си же Го́сподеви кля́твы твоя́. Аз же глаго́лю вам не кля́тися вся́ко: ни не́бом, я́ко престо́л есть Бо́жий, ни земле́ю, я́ко подно́жие есть нога́ма Его́, ни Иерусали́мом, я́ко град есть вели́каго Царя́. Ниже́ главо́ю твое́ю клени́ся, я́ко не мо́жеши вла́са еди́наго бе́ла или́ че́рна сотвори́ти. Бу́ди же сло́во ва́ше: ей, ей: ни, ни: ли́шше же сею́ от неприя́зни есть. Слы́шасте, я́ко рече́но бысть: о́ко за о́ко, и зуб за зуб. Аз же глаго́лю вам не проти́витися злу, но а́ще тя кто уда́рит в десну́ю твою́ лани́ту, обрати́ ему́ и другу́ю, и хотя́щему суди́тися с тобо́ю и ри́зу твою́ взя́ти, отпусти́ ему́ и срачи́цу. И а́ще кто тя по́ймет по си́ле по́прище еди́но, иди́ с ним два. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: слы́шасте, ꙗ҆́кѡ рече́но бы́сть дрє́внимъ: не во лжꙋ̀ клене́шисѧ, возда́си же гдⷭ҇ви клѧ́твы твоѧ̀. а҆́зъ же глаго́лю ва́мъ, не клѧ́тисѧ всѧ́кѡ: ни нб҃омъ, ꙗ҆́кѡ престо́лъ є҆́сть бж҃їй: ни земле́ю, ꙗ҆́кѡ подно́жїе є҆́сть нога́ма є҆гѡ̀: ни і҆ерꙋсали́момъ, ꙗ҆́кѡ гра́дъ є҆́сть вели́кагѡ цр҃ѧ̀. нижѐ главо́ю твое́ю клени́сѧ, ꙗ҆́кѡ не мо́жеши вла́са є҆ди́нагѡ бѣ́ла и҆лѝ че́рна сотвори́ти. бꙋ́ди же сло́во ва́ше, є҆́й, є҆́й: нѝ, нѝ: ли́шше же сею̀, ѿ непрїѧ́зни є҆́сть. слы́шасте, ꙗ҆́кѡ рече́но бы́сть: ѻ҆́ко за ѻ҆́ко, и҆ зꙋ́бъ за зꙋ́бъ. а҆́зъ же глаго́лю ва́мъ, не проти́витисѧ ѕлꙋ̀: но а҆́ще тѧ̀ кто̀ ᲂу҆да́ритъ въ деснꙋ́ю твою̀ лани́тꙋ, ѡ҆братѝ є҆мꙋ̀ и҆ дрꙋгꙋ́ю. и҆ хотѧ́щемꙋ сꙋди́тисѧ съ тобо́ю, и҆ ри́зꙋ твою̀ взѧ́ти, ѿпꙋстѝ є҆мꙋ̀ и҆ срачи́цꙋ. и҆ а҆́ще кто̀ тѧ̀ по́йметъ по си́лѣ по́прище є҆ди́но, и҆дѝ съ ни́мъ два̀. ",
}

add_evangelie_matfea {
  ["номер"] = 15,
  ["комментарий"] = "Мф., 15 зач., V, 42–48.",
  ["текст_ру"] = "Рече́ Госпо́дь: прося́щему у тебе́ дай, и хотя́щаго от тебе́ зая́ти не отврати́. Слы́шасте, я́ко рече́но есть: возлю́биши и́скренняго твоего́ и возненави́диши врага́ твоего́. Аз же глаго́лю вам: люби́те враги́ ва́ша, благослови́те клену́щыя вы, добро́ твори́те ненави́дящым вас, и моли́теся за творя́щих вам напа́сть и изгоня́щыя вы. Я́ко да бу́дете сы́нове Отца́ ва́шего, И́же есть на небесе́х, я́ко со́лнце Свое́ сия́ет на злы́я и благи́я и дожди́т на пра́ведныя и на непра́ведныя. А́ще бо лю́бите лю́бящих вас, ку́ю мзду и́мате? Не и мытари́ ли то́жде творя́т? И а́ще целу́ете дру́ги ва́ша то́кмо, что ли́шше творите́? Не и язы́чницы ли та́кожде творя́т? Бу́дите у́бо вы соверше́ни, я́коже Оте́ц ваш Небе́сный соверше́н есть. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: просѧ́щемꙋ ᲂу҆ тебѐ, да́й: и҆ хотѧ́щаго ѿ тебѐ заѧ́ти, не ѿвратѝ. слы́шасте, ꙗ҆́кѡ рече́но є҆́сть: возлю́биши и҆́скреннѧго твоего̀, и҆ возненави́диши врага̀ твоего̀. а҆́зъ же глаго́лю ва́мъ: люби́те врагѝ ва́шѧ: бл҃гослови́те кленꙋ́щыѧ вы̀: добро̀ твори́те ненави́дѧщымъ ва́съ: и҆ моли́тесѧ за творѧ́щихъ ва́мъ напа́сть, и҆ и҆згонѧ́щыѧ вы̀. ꙗ҆́кѡ да бꙋ́дете сы́нове ѻ҆ц҃а̀ ва́шегѡ, и҆́же є҆́сть на нб҃сѣ́хъ: ꙗ҆́кѡ со́лнце своѐ сїѧ́етъ на ѕлы̑ѧ и҆ бл҃гі̑ѧ, и҆ дожди́тъ на пра́вєдныѧ, и҆ на непра́вєдныѧ. а҆́ще бо лю́бите лю́бѧщихъ ва́съ, кꙋ́ю мздꙋ̀ и҆́мате; не и҆ мытари́ ли то́жде творѧ́тъ; и҆ а҆́ще цѣлꙋ́ете дрꙋ́ги ва́шѧ то́кмѡ, что̀ ли́шше творитѐ; не и҆ ꙗ҆зы́чницы ли та́кожде творѧ́тъ; бꙋ́дите ᲂу҆́бѡ вы̀ соверше́ни, ꙗ҆́коже ѻ҆ц҃ъ ва́шъ нбⷭ҇ный соверше́нъ є҆́сть. ",
}

add_evangelie_matfea {
  ["номер"] = 16,
  ["комментарий"] = "Мф., 16 зач., VI, 1–13.",
  ["текст_ру"] = "Рече́ Госпо́дь: внемли́те ми́лостыни ва́шея не твори́ти пред челове́ки, да ви́дими бу́дете и́ми, а́ще ли же ни, мзды не и́мате от Отца́ ва́шего, И́же есть на небесе́х. Егда́ у́бо твори́ши ми́лостыню, не воструби́ пред собо́ю, я́коже лицеме́ри творя́т в со́нмищах и в сто́гнах, я́ко да просла́вятся от челове́к. Ами́нь глаго́лю вам, восприе́млют мзду свою́. Тебе́ же творя́щу ми́лостыню, да не уве́сть шу́йца твоя́, что твори́т десни́ца твоя́, я́ко да бу́дет ми́лостыня твоя́ в та́йне, и Оте́ц твой, ви́дяй в та́йне, той возда́ст тебе́ я́ве. И егда́ мо́лишися, не бу́ди я́коже лицеме́ри, я́ко лю́бят в со́нмищах и в сто́гнах пути́й стоя́ще моли́тися, я́ко да явя́тся челове́ком. Ами́нь глаго́лю вам, я́ко восприе́млют мзду свою́. Ты же, егда́ мо́лишися, вни́ди в клеть твою́, и затвори́в две́ри твоя́, помоли́ся Отцу́ твоему́, И́же в та́йне, и Оте́ц твой, ви́дяй в та́йне, возда́ст тебе́ я́ве. Моля́щеся же не ли́шше глаго́лите, я́коже язы́чницы: мнят бо, я́ко во многоглаго́лании свое́м услы́шани бу́дут. Не подо́битеся у́бо им, весть бо Оте́ц ваш, и́хже тре́буете, пре́жде проше́ния ва́шего. Си́це у́бо моли́теся вы: О́тче наш, и́же еси́ на небесе́х, да святи́тся и́мя Твое́, да прии́дет Ца́рствие Твое́, да бу́дет во́ля Твоя́, я́ко на небеси́, и на земли́. Хлеб наш насу́щный даждь нам днесь, и оста́ви нам до́лги на́ша, я́ко и мы оставля́ем должнико́м на́шым. И не введи́ нас в напа́сть, но изба́ви нас от лука́ваго, я́ко Твое́ есть Ца́рствие и си́ла и сла́ва во ве́ки. Ами́нь. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: внемли́те ми́лостыни ва́шеѧ не твори́ти пред̾ человѣ́ки, да ви́дими бꙋ́дете и҆́ми: а҆́ще ли же нѝ, мзды̀ не и҆́мате ѿ ѻ҆ц҃а̀ ва́шегѡ, и҆́же є҆́сть на нб҃сѣ́хъ. є҆гда̀ ᲂу҆́бѡ твори́ши ми́лостыню, не вострꙋбѝ пред̾ собо́ю, ꙗ҆́коже лицемѣ́ри творѧ́тъ въ со́нмищахъ и҆ въ сто́гнахъ, ꙗ҆́кѡ да просла́вѧтсѧ ѿ человѣ̑къ: а҆ми́нь глаго́лю ва́мъ, воспрїе́млютъ мздꙋ̀ свою̀. тебѣ́ же творѧ́щꙋ ми́лостыню, да не ᲂу҆вѣ́сть шꙋ́йца твоѧ̀, что̀ твори́тъ десни́ца твоѧ̀. ꙗ҆́кѡ да бꙋ́детъ ми́лостынѧ твоѧ̀ въ та́йнѣ: и҆ ѻ҆ц҃ъ тво́й ви́дѧй въ та́йнѣ, то́й возда́стъ тебѣ̀ ꙗ҆́вѣ. и҆ є҆гда̀ мо́лишисѧ, не бꙋ́ди ꙗ҆́коже лицемѣ́ри, ꙗ҆́кѡ лю́бѧтъ въ со́нмищахъ, и҆ въ сто́гнахъ пꙋті́й стоѧ́ще моли́тисѧ, ꙗ҆́кѡ да ꙗ҆вѧ́тсѧ человѣ́кѡмъ. а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ воспрїе́млютъ мздꙋ̀ свою̀. ты́ же є҆гда̀ мо́лишисѧ, вни́ди въ клѣ́ть твою̀, и҆ затвори́въ двє́ри твоѧ̀, помоли́сѧ ѻ҆ц҃ꙋ̀ твоемꙋ̀ и҆́же въ та́йнѣ: и҆ ѻ҆ц҃ъ тво́й, ви́дѧй въ та́йнѣ, возда́стъ тебѣ̀ ꙗ҆́вѣ. молѧ́щесѧ же, не ли́шше глаго́лите, ꙗ҆́коже ꙗ҆зы́чницы: мнѧ́тъ бо, ꙗ҆́кѡ во многоглаго́ланїи свое́мъ ᲂу҆слы́шани бꙋ́дꙋтъ. не подо́битесѧ ᲂу҆̀бо и҆̀мъ: вѣ́сть бо ѻ҆ц҃ъ ва́шъ, и҆́хже тре́бꙋете, пре́жде проше́нїѧ ва́шегѡ. си́це ᲂу҆́бѡ моли́тесѧ вы̀: ѻ҆́ч҃е на́шъ, и҆́же є҆сѝ на нб҃сѣ́хъ, да свѧти́тсѧ и҆́мѧ твоѐ: да прїи́детъ црⷭ҇твїе твоѐ: да бꙋ́детъ во́лѧ твоѧ̀, ꙗ҆́кѡ на нб҃сѝ и҆ на землѝ. хлѣ́бъ на́шъ насꙋ́щный да́ждь на́мъ дне́сь: и҆ ѡ҆ста́ви на́мъ до́лги на́шѧ, ꙗ҆́кѡ и҆ мы̀ ѡ҆ставлѧ́емъ должникѡ́мъ на́шымъ. и҆ не введѝ на́съ въ напа́сть, но и҆зба́ви на́съ ѿ лꙋка́вагѡ: ꙗ҆́кѡ твоѐ є҆́сть црⷭ҇твїе и҆ си́ла и҆ сла́ва во вѣ́ки, а҆ми́нь. ",
}

add_evangelie_matfea {
  ["номер"] = 17,
  ["комментарий"] = "Мф., 17 зач., VI, 14–21.",
  ["текст_ру"] = "Рече́ Госпо́дь: а́ще отпуща́ете челове́ком согреше́ния их, отпу́стит и вам Оте́ц ваш Небе́сный. А́ще ли не отпуща́ете челове́ком согреше́ния их, ни Оте́ц ваш отпу́стит вам согреше́ний ва́ших. Егда́ же постите́ся, не бу́дите я́коже лицеме́ри се́тующе: помрача́ют бо ли́ца своя́, я́ко да явя́тся челове́ком постя́щеся. Ами́нь глаго́лю вам, я́ко восприе́млют мзду свою́. Ты же постя́ся пома́жи главу́ твою́, и лице́ твое́ умы́й, я́ко да не яви́шися челове́ком постя́ся, но Отцу́ твоему́, И́же в та́йне, и Оте́ц твой, ви́дяй в та́йне, возда́ст тебе́ я́ве. Не скрыва́йте себе́ сокро́вищ на земли́, иде́же червь и тля тлит, и иде́же та́тие подко́пывают и кра́дут. Скрыва́йте же себе́ сокро́вище на небеси́, иде́же ни червь, ни тля тлит, и иде́же та́тие не подко́пывают, ни кра́дут. Иде́же бо есть сокро́вище ва́ше, ту бу́дет и се́рдце ва́ше. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: а҆́ще ѿпꙋща́ете человѣ́кѡмъ согрѣшє́нїѧ и҆́хъ, ѿпꙋ́ститъ и҆ ва́мъ ѻ҆ц҃ъ ва́шъ нбⷭ҇ный. а҆́ще ли не ѿпꙋща́ете человѣ́кѡмъ согрѣшє́нїѧ и҆́хъ, ни ѻ҆ц҃ъ ва́шъ ѿпꙋ́ститъ ва́мъ согрѣше́нїй ва́шихъ. є҆гда́ же постите́сѧ, не бꙋ́дите ꙗ҆́коже лицемѣ́ри сѣ́тꙋюще: помрача́ютъ бо ли́ца своѧ̀, ꙗ҆́кѡ да ꙗ҆вѧ́тсѧ человѣ́кѡмъ постѧ́щесѧ. а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ воспрїе́млютъ мздꙋ̀ свою̀. ты́ же постѧ́сѧ, пома́жи главꙋ̀ твою̀, и҆ лицѐ твоѐ ᲂу҆мы́й: ꙗ҆́кѡ да не ꙗ҆ви́шисѧ человѣ́кѡмъ постѧ́сѧ, но ѻ҆ц҃ꙋ̀ твоемꙋ̀ и҆́же въ та́йнѣ: и҆ ѻ҆ц҃ъ тво́й, ви́дѧй въ та́йнѣ, возда́стъ тебѣ̀ ꙗ҆́вѣ. не скрыва́йте себѣ̀ сокро́вищъ на землѝ, и҆дѣ́же че́рвь и҆ тлѧ̀ тли́тъ, и҆ и҆дѣ́же та́тїе подко́пываютъ и҆ кра́дꙋтъ. скрыва́йте же себѣ̀ сокро́вище на нб҃сѝ, и҆дѣ́же ни че́рвь ни тлѧ̀ тли́тъ, и҆ и҆дѣ́же та́тїе не подко́пываютъ, ни кра́дꙋтъ. и҆дѣ́же бо є҆́сть сокро́вище ва́ше, тꙋ̀ бꙋ́детъ и҆ се́рдце ва́ше. ",
}

add_evangelie_matfea {
  ["номер"] = 18,
  ["комментарий"] = "Мф., 18 зач., VI, 22–33.",
  ["текст_ру"] = "Рече́ Госпо́дь: свети́льник те́лу есть о́ко. А́ще у́бо бу́дет о́ко твое́ про́сто, все те́ло твое́ све́тло бу́дет. А́ще ли о́ко твое́ лука́во бу́дет, все те́ло твое́ те́мно бу́дет. А́ще у́бо свет, и́же в тебе́, тма есть, то тма кольми́? Никто́же мо́жет двема́ господи́нома рабо́тати: лю́бо еди́наго возлю́бит, а друга́го возненави́дит, или́ еди́наго держи́тся, о друзе́м же нераде́ти на́чнет. Не мо́жете Бо́гу рабо́тати и мамо́не. Сего́ ра́ди глаго́лю вам: не пецы́теся душе́ю ва́шею, что я́сте, или́ что пие́те, ни те́лом ва́шим, во что облече́теся. Не душа́ ли бо́льши есть пи́щи, и те́ло оде́жди? Воззри́те на пти́цы небе́сныя, я́ко не се́ют, ни жнут, ни собира́ют в жи́тницы, и Оте́ц ваш Небе́сный пита́ет их. Не вы ли па́че лу́чши их есте́? Кто же от вас пеки́йся мо́жет приложи́ти во́зрасту своему́ ла́коть еди́н? И о оде́жди что пече́теся? Смотри́те крин се́льных, ка́ко расту́т, не тружда́ются, ни пряду́т. Глаго́лю же вам, я́ко ни Соломо́н во всей сла́ве свое́й облече́ся, я́ко еди́н от сих. А́ще же се́но се́льное, днесь су́ще и у́тре в пещь вмета́емо, Бог та́ко одева́ет, не мно́го ли па́че вас, малове́ри? Не пецы́теся у́бо, глаго́люще: что я́мы, или́ что пие́м, или́ чим оде́ждемся? Всех бо сих язы́цы и́щут, весть бо Оте́ц ваш Небе́сный, я́ко тре́буете сих всех. Ищи́те же пре́жде Ца́рствия Бо́жия и пра́вды Его́, и сия́ вся приложа́тся вам. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: свѣти́льникъ тѣ́лꙋ є҆́сть ѻ҆́ко. а҆́ще ᲂу҆́бѡ бꙋ́детъ ѻ҆́ко твоѐ про́сто всѐ тѣ́ло твоѐ свѣ́тло бꙋ́детъ. а҆́ще ли ѻ҆́ко твоѐ лꙋка́во бꙋ́детъ, всѐ тѣ́ло твоѐ те́мно бꙋ́детъ. а҆́ще ᲂу҆́бѡ свѣ́тъ, и҆́же въ тебѣ̀, тма̀ є҆́сть, то̀ тма̀ кольмѝ; никто́же мо́жетъ двѣма̀ господи́нома рабо́тати: лю́бо є҆ди́наго возлю́битъ, а҆ дрꙋга́го возненави́дитъ: и҆лѝ є҆ди́нагѡ держи́тсѧ, ѡ҆ дрꙋзѣ́мъ же нерадѣ́ти на́чнетъ. не мо́жете бг҃ꙋ рабо́тати, и҆ мамѡ́нѣ. сегѡ̀ ра́ди глаго́лю ва́мъ: не пецы́тесѧ дꙋше́ю ва́шею, что̀ ꙗ҆́сте, и҆лѝ что̀ пїе́те, ни тѣ́ломъ ва́шимъ во что̀ ѡ҆блече́тесѧ. не дꙋша́ ли бо́льши є҆́сть пи́щи, и҆ тѣ́ло ѻ҆де́жди; воззри́те на пти̑цы нбⷭ҇ныѧ, ꙗ҆́кѡ не сѣ́ютъ, ни жнꙋ́тъ, ни собира́ютъ въ жи́тницы, и҆ ѻ҆ц҃ъ ва́шъ нбⷭ҇ный пита́етъ и҆̀хъ: не вы́ ли па́че лꙋ́чши и҆́хъ є҆стѐ; кто́ же ѿ ва́съ пекі́йсѧ, мо́жетъ приложи́ти во́зрастꙋ своемꙋ̀ ла́коть є҆ди́нъ; и҆ ѡ҆ ѻ҆де́жди что̀ пече́тесѧ; смотри́те крі́нъ се́льныхъ, ка́кѡ растꙋ́тъ; не трꙋжда́ютсѧ, ни прѧдꙋ́тъ. глаго́лю же ва́мъ, ꙗ҆́кѡ ни соломѡ́нъ во все́й сла́вѣ свое́й ѡ҆блече́сѧ, ꙗ҆́кѡ є҆ди́нъ ѿ си́хъ. а҆́ще же сѣ́но се́льное дне́сь сꙋ́ще, и҆ ᲂу҆́трѣ въ пе́щь вмета́емо, бг҃ъ та́кѡ ѡ҆дѣва́етъ, не мно́гѡ ли па́че ва́съ маловѣ́ри; не пецы́тесѧ ᲂу҆́бѡ, глаго́люще, что̀ ꙗ҆́мы, и҆лѝ что̀ пїе́мъ, и҆лѝ чи́мъ ѡ҆де́ждемсѧ; всѣ́хъ бо си́хъ ꙗ҆зы́цы и҆́щꙋтъ: вѣ́сть бо ѻ҆ц҃ъ ва́шъ нбⷭ҇ный, ꙗ҆́кѡ тре́бꙋете си́хъ всѣ́хъ. и҆щи́те же пре́жде црⷭ҇твїѧ бж҃їѧ, и҆ пра́вды є҆гѡ̀, и҆ сїѧ̑ всѧ̑ приложа́тсѧ ва́мъ. ",
}

add_evangelie_matfea {
  ["номер"] = 19,
  ["комментарий"] = "Мф., 19 зач., VI, 31–34; VII, 9–11.",
  ["текст_ру"] = "Рече́ Госпо́дь: не пецы́теся, глаго́люще: что я́мы, или́ что пие́м, или́ чим оде́ждемся? Всех бо сих язы́цы и́щут, весть бо Оте́ц ваш Небе́сный, я́ко тре́буете сих всех. Ищи́те же пре́жде Ца́рствия Бо́жия и пра́вды Его́, и сия́ вся приложа́тся вам. Не пецы́теся у́бо на у́трей, у́трений бо собо́ю пече́тся, довле́ет дне́ви зло́ба его́. Или́ кто есть от вас челове́к, его́же а́ще воспро́сит сын его́ хле́ба, еда́ ка́мень пода́ст ему́? Или́ а́ще ры́бы про́сит, еда́ змию́ пода́ст ему́? А́ще у́бо вы, лука́ви су́ще, уме́ете дая́ния бла́га дая́ти ча́дом ва́шым, ко́льми па́че Оте́ц ваш Небе́сный даст бла́га прося́щым у Него́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: не пецы́тесѧ, глаго́люще, что̀ ꙗ҆́мы, и҆лѝ что̀ пїе́мъ, и҆лѝ чи́мъ ѡ҆де́ждемсѧ; всѣ́хъ бо си́хъ ꙗ҆зы́цы и҆́щꙋтъ: вѣ́сть бо ѻ҆ц҃ъ ва́шъ нбⷭ҇ный, ꙗ҆́кѡ тре́бꙋете си́хъ всѣ́хъ. и҆щи́те же пре́жде црⷭ҇твїѧ бж҃їѧ, и҆ пра́вды є҆гѡ̀, и҆ сїѧ̑ всѧ̑ приложа́тсѧ ва́мъ. не пецы́тесѧ ᲂу҆́бѡ на ᲂу҆́трѣй, ᲂу҆́тренїй бо собо́ю пече́тсѧ: довлѣ́етъ дне́ви ѕло́ба є҆гѡ̀. и҆лѝ кто̀ є҆́сть ѿ ва́съ человѣ́къ, є҆гѡ́же а҆́ще воспро́ситъ сы́нъ є҆гѡ̀ хлѣ́ба, є҆да̀ ка́мень пода́стъ є҆мꙋ̀; и҆лѝ а҆́ще ры́бы про́ситъ, є҆да̀ ѕмїю̀ пода́стъ є҆мꙋ̀; а҆́ще ᲂу҆́бѡ вы̀, лꙋка́ви сꙋ́ще, ᲂу҆мѣ́ете даѧ̑нїѧ бла̑га даѧ́ти ча́дѡмъ ва́шымъ: кольмѝ па́че ѻ҆ц҃ъ ва́шъ нбⷭ҇ный да́стъ бла̑га просѧ́щымъ ᲂу҆ негѡ̀. ",
}

add_evangelie_matfea {
  ["номер"] = 20,
  ["комментарий"] = "Мф., 20 зач., VII, 1–8.",
  ["текст_ру"] = "Рече́ Госпо́дь: не суди́те, да не суди́ми бу́дете. И́мже бо судо́м су́дите, су́дят вам, и в ню́же ме́ру ме́рите, возме́рится вам. Что же ви́диши суче́ц, и́же во о́це бра́та твоего́, бервна́ же, е́же есть во о́це твое́м, не чу́еши? Или́ ка́ко рече́ши бра́ту твоему́: оста́ви, да изму́ суче́ц из очесе́ твоего́, и се бервно́ во о́це твое́м? Лицеме́ре, изми́ пе́рвее бервно́ из очесе́ твоего́, и тогда́ у́зриши изъя́ти суче́ц из очесе́ бра́та твоего́. Не дади́те свята́я псом, ни помета́йте би́сер ва́ших пред свиния́ми, да не поперу́т их нога́ми свои́ми и вра́щшеся расто́ргнут вы. Проси́те и да́стся вам, ищи́те и обря́щете, толцы́те и отве́рзется вам. Всяк бо прося́й прие́млет, и ищя́й обрета́ет, и толку́щему отве́рзется. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: не сꙋди́те, да не сꙋди́ми бꙋ́дете. и҆́мже бо сꙋдо́мъ сꙋ́дите, сꙋ́дѧтъ ва́мъ: и҆ въ ню́же мѣ́рꙋ мѣ́рите, возмѣ́ритсѧ ва́мъ. что́ же ви́диши сꙋче́цъ, и҆́же во ѻ҆́цѣ бра́та твоегѡ̀, бервна́ же, є҆́же є҆́сть во ѻ҆́цѣ твое́мъ, не чꙋ́еши; и҆лѝ ка́кѡ рече́ши бра́тꙋ твоемꙋ̀: ѡ҆ста́ви, да и҆змꙋ̀ сꙋче́цъ и҆з̾ ѻ҆чесѐ твоегѡ̀, и҆ сѐ бервно̀ во ѻ҆́цѣ твое́мъ; лицемѣ́ре, и҆змѝ пе́рвѣе бервно̀ и҆з̾ ѻ҆чесѐ твоегѡ̀, и҆ тогда̀ ᲂу҆́зриши и҆з̾ѧ́ти сꙋче́цъ и҆з̾ ѻ҆чесѐ бра́та твоегѡ̀. не дади́те ст҃а̑ѧ псѡ́мъ, ни помета́йте би́сєръ ва́шихъ пред̾ свинїѧ́ми, да не поперꙋ́тъ и҆́хъ нога́ми свои́ми, и҆ вра́щшесѧ расто́ргнꙋтъ вы̀. проси́те, и҆ да́стсѧ ва́мъ: и҆щи́те, и҆ ѡ҆брѧ́щете: толцы́те, и҆ ѿве́рзетсѧ ва́мъ. всѧ́къ бо просѧ́й прїе́млетъ, и҆ и҆щѧ́й ѡ҆брѣта́етъ, и҆ толкꙋ́щемꙋ ѿве́рзетсѧ. ",
}

add_evangelie_matfea {
  ["номер"] = 20,
  ["комментарий"] = "Мф., 20 зач., VII, 7-11.",
  ["текст_ру"] = "Рече́ Госпо́дь: проси́те и да́стся вам, ищи́те и обря́щете, толцы́те и отве́рзется вам. Всяк бо прося́й прие́млет, и ищя́й обрета́ет, и толку́щему отве́рзется. Или́ кто есть от вас челове́к, его́же а́ще воспро́сит сын его́ хле́ба, еда́ ка́мень пода́ст ему́? Или́ а́ще ры́бы про́сит, еда́ змию́ пода́ст ему́? А́ще у́бо вы, лука́ви су́ще, уме́ете дая́ния бла́га дая́ти ча́дом ва́шым, ко́льми па́че Оте́ц ваш Небе́сный даст бла́га прося́щым у Него́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: проси́те, и҆ да́стсѧ ва́мъ: и҆щи́те, и҆ ѡ҆брѧ́щете: толцы́те, и҆ ѿве́рзетсѧ ва́мъ. всѧ́къ бо просѧ́й прїе́млетъ, и҆ и҆щѧ́й ѡ҆брѣта́етъ, и҆ толкꙋ́щемꙋ ѿве́рзетсѧ. и҆лѝ кто̀ є҆́сть ѿ ва́съ человѣ́къ, є҆гѡ́же а҆́ще воспро́ситъ сы́нъ є҆гѡ̀ хлѣ́ба, є҆да̀ ка́мень пода́стъ є҆мꙋ̀; и҆лѝ а҆́ще ры́бы про́ситъ, є҆да̀ ѕмїю̀ пода́стъ є҆мꙋ̀; а҆́ще ᲂу҆́бѡ вы̀, лꙋка́ви сꙋ́ще, ᲂу҆мѣ́ете даѧ̑нїѧ бла̑га даѧ́ти ча́дѡмъ ва́шымъ: кольмѝ па́че ѻ҆ц҃ъ ва́шъ нбⷭ҇ный да́стъ бла̑га просѧ́щымъ ᲂу҆ негѡ̀. ",
}

add_evangelie_matfea {
  ["номер"] = 21,
  ["комментарий"] = "Мф., 21 зач., VII, 12–21.",
  ["текст_ру"] = "Рече́ Госпо́дь: вся ели́ка а́ще хо́щете, да творя́т вам челове́цы, та́ко и вы твори́те им, се бо есть зако́н и проро́цы. Вни́дите у́зкими враты́, я́ко простра́нная врата́ и широ́кий путь вводя́й в па́губу, и мно́зи суть входя́щии им. Что у́зкая врата́, и те́сный путь вводя́й в живо́т, и ма́ло их есть, и́же обрета́ют его́. Внемли́те же от лжи́вых проро́к, и́же прихо́дят к вам во оде́ждах о́вчих, внутрь же суть во́лцы хи́щницы. От плод их позна́ете их. Еда́ объе́млют от те́рния гро́зды, или́ от ре́пия смо́квы? Та́ко вся́ко дре́во до́брое плоды́ добры́ твори́т, а зло́е дре́во плоды́ злы твори́т. Не мо́жет дре́во добро́ плоды́ злы твори́ти, ни дре́во зло плоды́ добры́ твори́ти. Вся́ко у́бо дре́во, е́же не твори́т плода́ добра́, посека́ют е́ и во огнь вмета́ют. Те́мже у́бо от плод их позна́ете их. Не всяк глаго́ляй Ми: Го́споди, Го́споди, вни́дет в Ца́рствие Небе́сное, но творя́й во́лю Отца́ Моего́, И́же есть на небесе́х. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: всѧ̑ є҆ли́ка а҆́ще хо́щете да творѧ́тъ ва́мъ человѣ́цы, та́кѡ и҆ вы̀ твори́те и҆̀мъ: се́ бо є҆́сть зако́нъ и҆ проро́цы. вни́дите ᲂу҆́зкими враты̀, ꙗ҆́кѡ простра́ннаѧ врата̀, и҆ широ́кїй пꙋ́ть вводѧ́й въ па́гꙋбꙋ, и҆ мно́зи сꙋ́ть входѧ́щїи и҆́мъ. что̀ ᲂу҆́зкаѧ врата̀, и҆ тѣ́сный пꙋ́ть вводѧ́й въ живо́тъ, и҆ ма́лѡ и҆́хъ є҆́сть, и҆̀же ѡ҆брѣта́ютъ є҆го̀; внемли́те же ѿ лжи́выхъ прорѡ́къ, и҆̀же прихо́дѧтъ къ ва́мъ во ѻ҆де́ждахъ ѻ҆́вчихъ, внꙋ́трь же сꙋ́ть во́лцы хи́щницы. ѿ плѡ́дъ и҆́хъ позна́ете и҆̀хъ. є҆да̀ ѡ҆б̾е́млютъ ѿ те́рнїѧ гро́зды, и҆лѝ ѿ ре́пїѧ смѡ́квы; та́кѡ всѧ́ко дре́во до́брое, плоды̀ добры̀ твори́тъ: а҆ ѕло́е дре́во, плоды̀ ѕлы̀ твори́тъ. не мо́жетъ дре́во добро̀ плоды̀ ѕлы̀ твори́ти: ни дре́во ѕло̀ плоды̀ добры̀ твори́ти. всѧ́ко ᲂу҆́бѡ дре́во, є҆́же не твори́тъ плода̀ добра̀, посѣка́ютъ є҆̀, и҆ во ѻ҆́гнь вмета́ютъ. тѣ́мже ᲂу҆́бѡ ѿ плѡ́дъ и҆́хъ позна́ете и҆̀хъ. не всѧ́къ глаго́лѧй мѝ: гдⷭ҇и гдⷭ҇и, вни́детъ въ црⷭ҇твїе нбⷭ҇ное, но творѧ́й во́лю ѻ҆ц҃а̀ моегѡ̀, и҆́же є҆́сть на нб҃сѣ́хъ. ",
}

add_evangelie_matfea {
  ["номер"] = 22,
  ["комментарий"] = "Мф., 22 зач., VII, 15–21.",
  ["текст_ру"] = "Рече́ Госпо́дь: внемли́те от лжи́вых проро́к, и́же прихо́дят к вам во оде́ждах о́вчих, внутрь же суть во́лцы хи́щницы. От плод их позна́ете их. Еда́ объе́млют от те́рния гро́зды, или́ от ре́пия смо́квы? Та́ко вся́ко дре́во до́брое плоды́ добры́ твори́т, а зло́е дре́во плоды́ злы твори́т. Не мо́жет дре́во добро́ плоды́ злы твори́ти, ни дре́во зло плоды́ добры́ твори́ти. Вся́ко у́бо дре́во, е́же не твори́т плода́ добра́, посека́ют е́ и во огнь вмета́ют. Те́мже у́бо от плод их позна́ете их. Не всяк глаго́ляй Ми: Го́споди, Го́споди, вни́дет в Ца́рствие Небе́сное, но творя́й во́лю Отца́ Моего́, И́же есть на небесе́х. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: внемли́те ѿ лжи́выхъ прорѡ́къ, и҆̀же прихо́дѧтъ къ ва́мъ во ѻ҆де́ждахъ ѻ҆́вчихъ, внꙋ́трь же сꙋ́ть во́лцы хи́щницы. ѿ плѡ́дъ и҆́хъ позна́ете и҆̀хъ. є҆да̀ ѡ҆б̾е́млютъ ѿ те́рнїѧ гро́зды, и҆лѝ ѿ ре́пїѧ смѡ́квы; та́кѡ всѧ́ко дре́во до́брое, плоды̀ добры̀ твори́тъ: а҆ ѕло́е дре́во, плоды̀ ѕлы̀ твори́тъ. не мо́жетъ дре́во добро̀ плоды̀ ѕлы̀ твори́ти: ни дре́во ѕло̀ плоды̀ добры̀ твори́ти. всѧ́ко ᲂу҆́бѡ дре́во, є҆́же не твори́тъ плода̀ добра̀, посѣка́ютъ є҆̀, и҆ во ѻ҆́гнь вмета́ютъ. тѣ́мже ᲂу҆́бѡ ѿ плѡ́дъ и҆́хъ позна́ете и҆̀хъ. не всѧ́къ глаго́лѧй мѝ: гдⷭ҇и гдⷭ҇и, вни́детъ въ црⷭ҇твїе нбⷭ҇ное, но творѧ́й во́лю ѻ҆ц҃а̀ моегѡ̀, и҆́же є҆́сть на нб҃сѣ́хъ. ",
}

add_evangelie_matfea {
  ["номер"] = 23,
  ["комментарий"] = "Мф., 23 зач., VII, 21–23.",
  ["текст_ру"] = "Рече́ Госпо́дь: не всяк глаго́ляй Ми: Го́споди, Го́споди, вни́дет в Ца́рствие Небе́сное, но творя́й во́лю Отца́ Моего́, И́же есть на небесе́х. Мно́зи реку́т Мне во он день: Го́споди, Го́споди, не в Твое́ ли и́мя проро́чествовахом, и Твои́м и́менем бе́сы изгони́хом, и Твои́м и́менем си́лы мно́ги сотвори́хом? И тогда́ испове́м им, я́ко николи́же знах вас, отиди́те от Мене́, де́лающии беззако́ние. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: не всѧ́къ глаго́лѧй мѝ: гдⷭ҇и гдⷭ҇и, вни́детъ въ црⷭ҇твїе нбⷭ҇ное, но творѧ́й во́лю ѻ҆ц҃а̀ моегѡ̀, и҆́же є҆́сть на нб҃сѣ́хъ. мно́зи рекꙋ́тъ мнѣ̀ во ѻ҆́нъ де́нь: гдⷭ҇и гдⷭ҇и, не въ твое́ ли и҆́мѧ проро́чествовахомъ, и҆ твои́мъ и҆́менемъ бѣ́сы и҆згони́хомъ, и҆ твои́мъ и҆́менемъ си̑лы мнѡ́ги сотвори́хомъ; и҆ тогда̀ и҆сповѣ́мъ и҆̀мъ, ꙗ҆́кѡ николи́же зна́хъ ва́съ: ѿиди́те ѿ менѐ дѣ́лающїи беззако́нїе. ",
}

add_evangelie_matfea {
  ["номер"] = 24,
  ["комментарий"] = "Мф., 24 зач., VII, 24 – VIII, 4.",
  ["текст_ру"] = "Рече́ Госпо́дь: всяк, и́же слы́шит словеса́ Моя́ сия́ и твори́т я́, уподо́блю его́ му́жу му́дру, и́же созда́ хра́мину свою́ на ка́мени. И сни́де дождь, и приидо́ша ре́ки, и возве́яша ве́три, и нападо́ша на хра́мину ту, и не паде́ся, основана́ бо бе на ка́мени. И всяк слы́шай словеса́ Моя́ сия́, и не творя́ их, уподо́бится му́жу уро́диву, и́же созда́ хра́мину свою́ на песце́. И сни́де дождь, и приидо́ша ре́ки, и возве́яша ве́три, и опро́шася хра́мине той, и паде́ся, и бе разруше́ние ея́ ве́лие. И бысть егда́ сконча́ Иису́с словеса́ сия́, дивля́хуся наро́ди о уче́нии Его́. Бе бо учя́ их я́ко власть име́я, и не я́ко кни́жницы и фарисе́е. Сше́дшу же Ему́ с горы́, в след Его́ идя́ху наро́ди мно́зи. И се прокаже́н прише́д кла́няшеся Ему́, глаго́ля: Го́споди, а́ще хо́щеши, мо́жеши мя очи́стити. И просте́р ру́ку Иису́с, косну́ся ему́, глаго́ля: хощу́, очи́стися. И а́бие очи́стися ему́ прока́за. И глаго́ла ему́ Иису́с: виждь, никому́же пове́ждь, но шед покажи́ся иере́ови и принеси́ дар, его́же повеле́ в зако́не Моисе́й, во свиде́тельство им. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: всѧ́къ, и҆́же слы́шитъ словеса̀ моѧ̀ сїѧ̀, и҆ твори́тъ ѧ҆̀, ᲂу҆подо́блю є҆го̀ мꙋ́жꙋ мꙋ́дрꙋ, и҆́же созда̀ хра́минꙋ свою̀ на ка́мени. и҆ сни́де до́ждь, и҆ прїидо́ша рѣ́ки, и҆ возвѣ́ѧша вѣ́три, и҆ нападо́ша на хра́минꙋ тꙋ̀, и҆ не паде́сѧ: ѡ҆снована̀ бо бѣ̀ на ка́мени. и҆ всѧ́къ слы́шай словеса̀ моѧ̀ сїѧ̀, и҆ не творѧ̀ и҆́хъ, ᲂу҆подо́битсѧ мꙋ́жꙋ ᲂу҆ро́дивꙋ, и҆́же созда̀ хра́минꙋ свою̀ на песцѣ̀. и҆ сни́де до́ждь, и҆ прїидо́ша рѣ́ки, и҆ возвѣ́ѧша вѣ́три, и҆ ѡ҆про́шасѧ хра́минѣ то́й, и҆ паде́сѧ: и҆ бѣ̀ разрꙋше́нїе є҆ѧ̀ ве́лїе. и҆ бы́сть, є҆гда̀ сконча̀ і҆и҃съ словеса̀ сїѧ̀, дивлѧ́хꙋсѧ наро́ди ѡ҆ ᲂу҆че́нїи є҆гѡ̀. бѣ́ бо ᲂу҆чѧ̀ и҆̀хъ ꙗ҆́кѡ вла́сть и҆мѣ́ѧ, и҆ не ꙗ҆́кѡ кни́жницы и҆ фарїсе́є. сше́дшꙋ же є҆мꙋ̀ съ горы̀, въ слѣ́дъ є҆гѡ̀ и҆дѧ́хꙋ наро́ди мно́зи. и҆ сѐ прокаже́нъ прише́дъ, кла́нѧшесѧ є҆мꙋ̀, глаго́лѧ: гдⷭ҇и, а҆́ще хо́щеши, мо́жеши мѧ̀ ѡ҆чи́стити. и҆ просте́ръ рꙋ́кꙋ і҆и҃съ, коснꙋ́сѧ є҆мꙋ̀, глаго́лѧ: хощꙋ̀, ѡ҆чи́стисѧ. и҆ а҆́бїе ѡ҆чи́стисѧ є҆мꙋ̀ прока́за. и҆ глаго́ла є҆мꙋ̀ і҆и҃съ: ви́ждь, никомꙋ́же повѣ́ждь: но ше́дъ покажи́сѧ і҆ере́ови, и҆ принесѝ да́ръ, и҆́же повелѣ̀ въ зако́нѣ мѡѷсе́й, во свидѣ́тельство и҆̀мъ. ",
}

add_evangelie_matfea {
  ["номер"] = 25,
  ["комментарий"] = "Мф., 25 зач., VIII, 5–13.",
  ["текст_ру"] = "Во вре́мя о́но, вше́дшу Иису́су в Капернау́м, приступи́ к Нему́ со́тник, моля́ Его́ и глаго́ля: Го́споди, о́трок мой лежи́т в дому́ осла́блен, лю́те стражда́. И глаго́ла ему́ Иису́с: Аз прише́д изцелю́ его́. И отвеща́в со́тник, рече́ Ему́: Го́споди, несмь досто́ин, да под кров мой вни́деши, но то́кмо рцы сло́во, и изцеле́ет о́трок мой. И́бо аз челове́к есмь под вла́стию, имы́й под собо́ю во́ины, и глаго́лю сему́: иди́, и и́дет. И друго́му: прииди́, и прии́дит. И рабу́ моему́: сотвори́ сие́, и сотвори́т. Слы́шав же Иису́с, удиви́ся, и рече́ гряду́щим по Нем: ами́нь глаго́лю вам, ни во Изра́или толи́ки ве́ры обрето́х. Глаго́лю же вам, я́ко мно́зи от восто́к и за́пад прии́дут и возля́гут со Авраа́мом и Исаа́ком и Иа́ковом во Ца́рствии Небе́снем. Сы́нове же ца́рствия изгна́ни бу́дут во тму кроме́шнюю, ту бу́дет плачь и скре́жет зубо́м. И рече́ Иису́с со́тнику: иди́, и я́коже ве́ровал еси́, бу́ди тебе́. И изцеле́ о́трок его́ в той час. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, вше́дшꙋ і҆и҃сꙋ въ капернаꙋ́мъ, пристꙋпѝ къ немꙋ̀ со́тникъ молѧ̀ є҆го̀, и҆ глаго́лѧ: гдⷭ҇и, ѻ҆́трокъ мо́й лежи́тъ въ домꙋ̀ ѡ҆сла́бленъ, лю́тѣ стражда̀. и҆ глаго́ла є҆мꙋ̀ і҆и҃съ: а҆́зъ прише́дъ и҆сцѣлю̀ є҆го̀. и҆ ѿвѣща́въ со́тникъ, речѐ є҆мꙋ̀: гдⷭ҇и, нѣ́смь досто́инъ да под̾ кро́въ мо́й вни́деши, но то́кмѡ рцы̀ сло́во, и҆ и҆сцѣлѣ́етъ ѻ҆́трокъ мо́й. и҆́бо а҆́зъ человѣ́къ є҆́смь под̾ вла́стїю, и҆мы́й под̾ собо́ю во́ины. и҆ глаго́лю семꙋ̀: и҆дѝ, и҆ и҆́детъ. и҆ дрꙋго́мꙋ: прїидѝ, и҆ прїи́детъ. и҆ рабꙋ̀ моемꙋ̀: сотворѝ сїѐ, и҆ сотвори́тъ. слы́шавъ же і҆и҃съ, ᲂу҆диви́сѧ, и҆ речѐ грѧдꙋ́щымъ по не́мъ: а҆ми́нь глаго́лю ва́мъ, ни во і҆и҃ли толи́ки вѣ́ры ѡ҆брѣто́хъ. глаго́лю же ва́мъ: ꙗ҆́кѡ мно́зи ѿ востѡ́къ и҆ за̑падъ прїи́дꙋтъ, и҆ возлѧ́гꙋтъ со а҆враа́момъ, и҆ і҆саа́комъ, и҆ і҆а́кѡвомъ во црⷭ҇твїи нбⷭ҇нѣмъ. сы́нове же црⷭ҇твїѧ и҆згна́ни бꙋ́дꙋтъ во тмꙋ̀ кромѣ́шнюю: тꙋ̀ бꙋ́детъ пла́чь и҆ скре́жетъ зꙋбѡ́мъ. и҆ речѐ і҆и҃съ со́тникꙋ: и҆дѝ, и҆ ꙗ҆́коже вѣ́ровалъ є҆сѝ, бꙋ́ди тебѣ̀. и҆ и҆сцѣлѣ̀ ѻ҆́трокъ є҆гѡ̀ въ то́й ча́съ. ",
}

add_evangelie_matfea {
  ["номер"] = 26,
  ["комментарий"] = "Мф., 26 зач., VIII, 14–23.",
  ["текст_ру"] = "Во вре́мя о́но, прише́д Иису́с в дом Петро́в, ви́де те́щу его́ лежа́щу и огне́м жего́му, и прикосну́ся руце́ ея́, и оста́ви ю́ огнь, и воста́ и служа́ше ему́. По́зде же бы́вшу, приведо́ша к Нему́ бе́сны мно́ги, и изгна́ ду́хи сло́вом и вся боля́щия исцели́. Да сбу́дется рече́нное Иса́ием проро́ком, глаго́лющим: Той неду́ги на́ша прия́т и боле́зни понесе́. Ви́дев же Иису́с мно́ги наро́ды о́крест Себе́, повеле́ ити́ на он пол. И присту́пль еди́н кни́жник, рече́ Ему́: Учи́телю, иду́ по Тебе́, а́може а́ще и́деши. Глаго́ла ему́ Иису́с: ли́си я́звины и́мут, и пти́цы небе́сныя гне́зда, Сын же Челове́ческий не и́мать где главы́ подклони́ти. Други́й же от учени́к Его́ рече́ Ему́: Го́споди, повели́ ми пре́жде ити́ и погребсти́ отца́ моего́. Иису́с же рече́ ему́: гряди́ по Мне и оста́ви ме́ртвых погребсти́ своя́ мертвецы́. И вле́зшу Ему́ в кора́бль, по Нем идо́ша ученицы́ Его́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прише́дъ і҆и҃съ въ до́мъ петро́въ, ви́дѣ те́щꙋ є҆гѡ̀ лежа́щꙋ, и҆ ѻ҆гне́мъ жего́мꙋ. и҆ прикоснꙋ́сѧ рꙋцѣ̀ є҆ѧ̀, и҆ ѡ҆ста́ви ю҆̀ ѻ҆́гнь: и҆ воста̀, и҆ слꙋжа́ше є҆мꙋ̀. по́здѣ же бы́вшꙋ, приведо́ша къ немꙋ̀ бѣ́сны мно́ги, и҆ и҆згна̀ дꙋ́хи сло́вомъ, и҆ всѧ̀ болѧ́щыѧ и҆сцѣлѝ. да сбꙋ́детсѧ рече́нное и҆са́їемъ проро́комъ, глаго́лющимъ: то́й недꙋ́ги на́шѧ прїѧ́тъ, и҆ болѣ̑зни понесѐ. ви́дѣвъ же і҆и҃съ мно́ги наро́ды ѻ҆́крестъ себѐ, повелѣ̀ и҆тѝ на ѻ҆́нъ по́лъ. и҆ пристꙋ́пль є҆ди́нъ кни́жникъ, речѐ є҆мꙋ̀: ᲂу҆чт҃лю, и҆дꙋ̀ по тебѣ̀, а҆́може а҆́ще и҆́деши. глаго́ла є҆мꙋ̀ і҆и҃съ: ли́си ꙗ҆́звины и҆́мꙋтъ, и҆ пти̑цы нбⷭ҇ныѧ гнѣ́зда: сн҃ъ же человѣ́ческїй не и҆́мать гдѣ̀ главы̀ подклони́ти. дрꙋгі́й же ѿ ᲂу҆ч҃ни̑къ є҆гѡ̀ речѐ є҆мꙋ̀: гдⷭ҇и, повели́ ми пре́жде и҆тѝ, и҆ погребстѝ ѻ҆тца̀ моего̀. і҆и҃съ же речѐ є҆мꙋ̀: грѧдѝ по мнѣ̀, и҆ ѡ҆ста́ви ме́ртвыхъ погребстѝ своѧ̀ мертвецы̀. и҆ влѣ́зшꙋ є҆мꙋ̀ въ кора́бль, по не́мъ и҆до́ша ᲂу҆ченицы̀ є҆гѡ̀. ",
}

add_evangelie_matfea {
  ["номер"] = 27,
  ["комментарий"] = "Мф., 27 зач., VIII, 23–27.",
  ["текст_ру"] = "Во вре́мя о́но, вле́зшу Иису́су в кора́бль, по Нем идо́ша ученицы́ Его́. И се трус вели́к бысть в мо́ри, я́коже кораблю́ покрыва́тися волна́ми, То́йже же спа́ше. И прише́дше ученицы́ Его́ возбуди́ша Его́, глаго́люще: Го́споди, спаси́ ны, погиба́ем. И глаго́ла им: что страшли́ви есте́, малове́ри? Тогда́ воста́в запрети́ ве́тром и мо́рю, и бысть тишина́ ве́лия. Челове́цы же чуди́шася, глаго́люще: кто есть Сей, я́ко и ве́три и мо́ре послу́шают Его́? ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, влѣ́зшꙋ і҆и҃сꙋ въ кора́бль, по не́мъ и҆до́ша ᲂу҆ченицы̀ є҆гѡ̀. и҆ сѐ трꙋ́съ вели́къ бы́сть въ мо́ри, ꙗ҆́коже кораблю̀ покрыва́тисѧ волна́ми: то́й же спа́ше. и҆ прише́дше ᲂу҆чн҃цы̀ є҆гѡ̀, возбꙋди́ша є҆го̀, глаго́люще: гдⷭ҇и, спаси́ ны, погиба́емъ. и҆ глаго́ла и҆̀мъ: что̀ страшли́ви є҆стѐ маловѣ́ри; тогда̀ воста́въ запретѝ вѣ́трѡмъ и҆ мо́рю, и҆ бы́сть тишина̀ ве́лїѧ. человѣ́цы же чꙋди́шасѧ, глаго́люще: кто̀ є҆́сть се́й, ꙗ҆́кѡ и҆ вѣ́три и҆ мо́ре послꙋ́шаютъ є҆гѡ̀; ",
}

add_evangelie_matfea {
  ["номер"] = 28,
  ["комментарий"] = "Мф., 28 зач., VIII, 28 - IX, 1.",
  ["текст_ру"] = "Во вре́мя о́но, прише́дшу Иису́су в страну́ Гергеси́нскую, срето́ста Его́ два бе́сна от гроб исходя́ща, лю́та зело́, я́ко не мощи́ никому́ мину́ти путе́м тем. И се возопи́ста глаго́люще: что нам и Тебе́, Иису́се Сы́не Бо́жий? Прише́л еси́ се́мо пре́жде вре́мене му́чити нас. Бя́ше же дале́че от нею́ ста́до свини́й мно́го пасо́мо. Бе́си же моля́ху Его́, глаго́люще: а́ще изго́ниши ны, повели́ нам ити́ в ста́до свино́е. И рече́ им: иди́те. Они́ же изше́дше идо́ша в ста́до свино́е, и се а́бие устреми́ся ста́до все по бре́гу в мо́ре, и утопо́ша в вода́х. Пасу́щии же бежа́ша, и ше́дше во град, возвести́ша вся, и о бесно́ю. И се весь град изы́де в сре́тение Иису́сови, и ви́девше Его́, моли́ша, я́ко дабы́ преше́л от преде́л их. И влез в кора́бль, пре́йде и прии́де во Свой град. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прише́дшꙋ і҆и҃сꙋ въ странꙋ̀ гергеси́нскꙋю, срѣто́ста є҆го̀ два̀ бѣ́сна ѿ грѡ́бъ и҆сходѧ́ща, лю̑та ѕѣлѡ̀, ꙗ҆́кѡ не мощѝ никомꙋ̀ минꙋ́ти пꙋте́мъ тѣ́мъ. и҆ сѐ возопи́ста, глаго́люще: что̀ на́мъ и҆ тебѣ̀ і҆и҃се сн҃е бж҃їй; прише́лъ є҆сѝ сѣ́мѡ пре́жде вре́мене мꙋ́чити на́съ. бѧ́ше же дале́че ѿ нею̀ ста́до свині́й мно́го пасо́мо. бѣ́си же молѧ́хꙋ є҆го̀ глаго́люще: а҆́ще и҆зго́ниши ны̀, повелѝ на́мъ и҆тѝ въ ста́до свино́е. и҆ речѐ и҆̀мъ: и҆ди́те. ѻ҆ни́ же и҆зше́дше и҆до́ша въ ста́до свино́е: и҆ сѐ а҆́бїе ᲂу҆стреми́сѧ ста́до всѐ по бре́гꙋ въ мо́ре, и҆ ᲂу҆топо́ша въ вода́хъ. пасꙋ́щїи же бѣжа́ша, и҆ ше́дше во гра́дъ возвѣсти́ша всѧ̀, и҆ ѡ҆ бѣсно́ю. и҆ сѐ ве́сь гра́дъ и҆зы́де въ срѣ́тенїе і҆и҃сови: и҆ ви́дѣвше є҆го̀, моли́ша, ꙗ҆́кѡ дабы̀ преше́лъ ѿ предѣ́лъ и҆́хъ. и҆ влѣ́зъ въ кора́бль, пре́йде, и҆ прїи́де во сво́й гра́дъ. ",
}

add_evangelie_matfea {
  ["номер"] = 29,
  ["комментарий"] = "Мф., 29 зач., IX, 1–8.",
  ["текст_ру"] = "Во вре́мя о́но, влез Иису́с в кора́бль, пре́йде и прии́де во Свой град. И се принесо́ша Ему́ разсла́блена жи́лами, на одре́ лежа́ща, и ви́дев Иису́с ве́ру их, рече́ разсла́бленному: дерза́й, ча́до, отпуща́ются ти греси́ твои́. И се не́цыи от кни́жник ре́ша в себе́: Сей ху́лит. И ви́дев Иису́с помышле́ния их, рече́: вску́ю вы мы́слите лука́вая в сердца́х свои́х? Что бо есть удо́бее рещи́: отпуща́ются ти греси́, или́ рещи́: воста́ни и ходи́? Но да уве́сте, я́ко власть и́мать Сын Челове́ческий на земли́ отпуща́ти грехи́, тогда́ глаго́ла разсла́бленному: воста́ни, возми́ твой одр и иди́ в дом твой. И воста́в, взем одр свой, и́де в дом свой. Ви́девше же наро́ди чуди́шася и просла́виша Бо́га, да́вшаго власть такову́ю челове́ком. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, влѣ́зъ і҆и҃съ въ кора́бль, пре́йде, и҆ прїи́де во сво́й гра́дъ. и҆ сѐ принесо́ша є҆мꙋ̀ разсла́бленна жи́лами, на ѻ҆дрѣ̀ лежа́ща. и҆ ви́дѣвъ і҆и҃съ вѣ́рꙋ и҆́хъ, речѐ разсла́бленномꙋ: дерза́й ча́до, ѿпꙋща́ютсѧ тѝ грѣсѝ твоѝ. и҆ сѐ нѣ́цыи ѿ кни̑жникъ рѣ́ша въ себѣ̀: се́й хꙋ́литъ. и҆ ви́дѣвъ і҆и҃съ помышлє́нїѧ и҆́хъ, речѐ: вскꙋ́ю вы̀ мы́слите лꙋка̑ваѧ въ сердца́хъ свои́хъ; что́ бо є҆́сть ᲂу҆до́бѣе рещѝ: ѿпꙋща́ютсѧ тѝ грѣсѝ; и҆лѝ рещѝ: воста́ни и҆ ходѝ; но да ᲂу҆вѣ́сте, ꙗ҆́кѡ вла́сть и҆́мать сн҃ъ человѣ́ческїй на землѝ ѿпꙋща́ти грѣхѝ тогда̀ глаго́ла разсла́бленномꙋ: воста́ни, воз̾мѝ тво́й ѻ҆́дръ, и҆ и҆дѝ въ до́мъ тво́й. и҆ воста́въ взе́мъ ѻ҆́дръ сво́й, и҆́де въ до́мъ сво́й. ви́дѣвше же наро́ди чꙋди́шасѧ, и҆ просла́виша бг҃а, да́вшаго вла́сть таковꙋ́ю человѣ́кѡмъ. ",
}

add_evangelie_matfea {
  ["номер"] = 30,
  ["комментарий"] = "Мф., 30 зач., IX, 9–13.",
  ["текст_ру"] = "Во вре́мя о́но, преходя́ Иису́с, ви́де челове́ка седя́ща на мы́тнице, Матфе́а глаго́лема, и глаго́ла ему́: по Мне гряди́. И воста́в по Нем и́де. И бысть Ему́ возлежа́щу в дому́, и се мно́зи мытари́ и гре́шницы прише́дше возлежа́ху со Иису́сом и со ученики́ Его́. И ви́девше фарисе́е, глаго́лаху ученико́м Его́: почто́ с мытари́ и гре́шники Учи́тель ваш яст и пие́т? Иису́с же слы́шав рече́ им: не тре́буют здра́вии врача́, но боля́щии. Ше́дше же научи́теся, что есть: ми́лости хощу́, а не же́ртвы? Не приидо́х бо призва́ти пра́ведники, но гре́шники на покая́ние. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, преходѧ̀ і҆и҃съ ви́дѣ человѣ́ка сѣдѧ́ща на мы́тницѣ, матѳе́а глаго́лема, и҆ глаго́ла є҆мꙋ̀: по мнѣ̀ грѧдѝ. и҆ воста́въ по не́мъ и҆́де. и҆ бы́сть є҆мꙋ̀ возлежа́щꙋ въ домꙋ̀, и҆ сѐ мно́зи мытарѝ и҆ грѣ̑шницы прише́дше возлежа́хꙋ со і҆и҃сомъ, и҆ со ᲂу҆ченикѝ є҆гѡ̀. и҆ ви́дѣвше фарїсе́є, глаго́лахꙋ ᲂу҆ченикѡ́мъ є҆гѡ̀: почто̀ съ мытарѝ и҆ грѣ́шники ᲂу҆чи́тель ва́шъ ꙗ҆́стъ и҆ пїе́тъ; і҆и҃съ же слы́шавъ, речѐ и҆̀мъ: не тре́бꙋютъ здра́вїи врача̀, но болѧ́щїи. ше́дше же наꙋчи́тесѧ, что̀ є҆́сть: ми́лости хощꙋ̀, а҆ не же́ртвы. не прїидо́хъ бо призва́ти пра́ведники, но грѣ́шники на покаѧ́нїе. ",
}

add_evangelie_matfea {
  ["номер"] = 31,
  ["комментарий"] = "Мф., 31 зач., IX, 14–17.",
  ["текст_ру"] = "Во вре́мя о́но, приступи́ша ко Иису́су ученицы́ Иоа́нновы, глаго́люще: почто́ мы и фарисе́и пости́мся мно́го, ученицы́ же Твои́ не постя́тся? И рече́ им Иису́с: еда́ мо́гут сы́нове бра́чнии пла́кати, донели́ко вре́мя с ни́ми есть жени́х? Прии́дут же дни́е, егда́ оти́мется от них жени́х, и тогда́ постя́тся. Никто́же бо приставля́ет приставле́ния пла́та небе́лена ри́зе ве́тсе: во́змет бо кончи́ну свою́ от ри́зы, и го́рша дира́ бу́дет. Ниже́ влива́ют вина́ но́ва в ме́хи ве́тхи, а́ще ли же ни, то просадя́тся ме́си, и вино́ пролие́тся, и ме́си поги́бнут, но влива́ют вино́ но́во в ме́хи но́вы, и обое́ соблюде́тся. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋпи́ша ко і҆и҃сꙋ ᲂу҆ченицы̀ і҆ѡа́нновы, глаго́люще: почто̀ мы̀ и҆ фарїсе́и пости́мсѧ мно́гѡ, ᲂу҆ченицы́ же твоѝ не постѧ́тсѧ; и҆ речѐ и҆̀мъ і҆и҃съ: є҆да̀ мо́гꙋтъ сы́нове бра́чнїи пла́кати, донели́ко вре́мѧ съ ни́ми є҆́сть жени́хъ; прїи́дꙋтъ же дні́е, є҆гда̀ ѿи́метсѧ ѿ ни́хъ жени́хъ, и҆ тогда̀ постѧ́тсѧ. никто́же бо приставлѧ́етъ приставле́нїѧ пла́та небѣ́лена ри́зѣ ве́тсѣ: во́з̾метъ бо кончи́нꙋ свою̀ ѿ ри́зы, и҆ го́рша дира̀ бꙋ́детъ. нижѐ влива́ютъ вїна̀ но́ва въ мѣ́хи ве́тхи. а҆́ще ли же нѝ, то̀ просадѧ́тсѧ мѣ́си, и҆ вїно̀ пролїе́тсѧ, и҆ мѣ́си поги́бнꙋтъ: но влива́ютъ вїно̀ но́во въ мѣ́хи но́вы, и҆ ѻ҆боѐ соблюде́тсѧ. ",
}

add_evangelie_matfea {
  ["номер"] = 32,
  ["комментарий"] = "Мф., 32 зач., IX, 18–26.",
  ["текст_ру"] = "Во вре́мя о́но, князь не́кий прише́д ко Иису́су, кла́няшеся Ему́ глаго́ля, я́ко дщи моя́ ны́не у́мре, но прише́д возложи́ на ню ру́ку Твою́, и оживе́т. И воста́в Иису́с по нем и́де, и ученицы́ Его́. И се жена́ кровоточи́ва двана́десяте лет, присту́пльши созади́, прикосну́ся воскри́лию ри́зы Его́, глаго́лаше бо в себе́: а́ще то́кмо прикосну́ся ри́зе Его́, спасе́на бу́ду. Иису́с же обра́щься и ви́дев ю́, рече́: дерза́й, дщи, ве́ра твоя́ спасе́ тя. И спасе́на бысть жена́ от часа́ того́. И прише́д Иису́с в дом княжь, и ви́де сопца́ и наро́д мо́лвящь, глаго́ла им: отиди́те, не у́мре бо деви́ца, но спит. И руга́хуся Ему́. Егда́ же изгна́н бысть наро́д, вшед ят ю́ за ру́ку, и воста́ деви́ца. И изы́де весть сия́ по всей земли́ той. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, кнѧ́зь нѣ́кїй прише́дъ ко і҆и҃сꙋ, кла́нѧшесѧ є҆мꙋ̀, глаго́лѧ, ꙗ҆́кѡ дщѝ моѧ̀ ны́нѣ ᲂу҆́мре: но прише́дъ возложѝ на ню̀ рꙋ́кꙋ твою̀, и҆ ѡ҆живе́тъ. и҆ воста́въ і҆и҃съ по не́мъ и҆́де, и҆ ᲂу҆ч҃нцы̀ є҆гѡ̀. и҆ сѐ жена̀ кровоточи́ва двана́десѧте лѣ́тъ, пристꙋ́пльши созадѝ, прикоснꙋ́сѧ воскри́лїю ри́зы є҆гѡ̀. глаго́лаше бо въ себѣ̀: а҆́ще то́кмѡ прикоснꙋ́сѧ ри́зѣ є҆гѡ̀, спасе́на бꙋ́дꙋ. і҆и҃съ же ѡ҆бра́щсѧ, и҆ ви́дѣвъ ю҆̀, речѐ: дерза́й дщѝ, вѣ́ра твоѧ̀ спасѐ тѧ̀. и҆ спасе́на бы́сть жена̀ ѿ часа̀ тогѡ̀. и҆ прише́дъ і҆и҃съ въ до́мъ кнѧ́жь, и҆ ви́дѣ сопца̑ и҆ наро́дъ мо́лвѧщъ, глаго́ла и҆̀мъ: ѿиди́те, не ᲂу҆́мре бо дѣви́ца, но спи́тъ. и҆ рꙋга́хꙋсѧ є҆мꙋ̀. є҆гда́ же и҆згна́нъ бы́сть наро́дъ, вше́дъ ꙗ҆́тъ ю҆̀ за рꙋ́кꙋ: и҆ воста̀ дѣви́ца. и҆ и҆зы́де вѣ́сть сїѧ̀ по все́й землѝ то́й. ",
}

add_evangelie_matfea {
  ["номер"] = 33,
  ["комментарий"] = "Мф., 33 зач., IX, 27–35.",
  ["текст_ру"] = "Во вре́мя о́но, преходя́щу Иису́сови, по Нем идо́ста два слепца́, зову́ща и глаго́люща: поми́луй ны, Иису́се сы́не Дави́дов. Прише́дшу же Ему́ в дом, приступи́ста к Нему́ слепца́, и глаго́ла и́ма Иису́с: ве́руета ли, я́ко могу́ сие́ сотвори́ти? Глаго́ласта Ему́: ей, Го́споди. Тогда́ прикосну́ся о́чию их, глаго́ля: по ве́ре ва́ю бу́ди ва́ма. И отверзо́стася о́чи и́ма, и запрети́ и́ма Иису́с, глаго́ля: блюди́та, да никто́же уве́сть. О́на же изше́дша просла́виста Его́ по всей земли́ той. Те́ма же исходя́щема, се приведо́ша к Нему́ челове́ка не́ма бесну́ема. И изгна́ну бе́су, проглаго́ла немы́й. И диви́шася наро́ди, глаго́люще, я́ко николи́же яви́ся та́ко во Изра́или. Фарисе́е же глаго́лаху: о кня́зе бесо́встем изго́нит бе́сы. И прохожда́ше Иису́с гра́ды вся и ве́си, учя́ на со́нмищах их, и пропове́дая Ева́нгелие Ца́рствия, и целя́ всяк неду́г и вся́ку я́зю в лю́дех. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, преходѧ́щꙋ і҆и҃сови, по не́мъ и҆до́ста два̀ слѣпца̀, зовꙋ́ща и҆ глаго́люща: поми́лꙋй ны̀ і҆и҃се сн҃е дв҃довъ. прише́дшꙋ же є҆мꙋ̀ въ до́мъ, пристꙋпи́ста къ немꙋ̀ слѣпца̑, и҆ глаго́ла и҆́ма і҆и҃съ: вѣ́рꙋета ли, ꙗ҆́кѡ могꙋ̀ сїѐ сотвори́ти; глаго́ласта є҆мꙋ̀: є҆́й гдⷭ҇и. тогда̀ прикоснꙋ́сѧ ѻ҆́чїю и҆́хъ, глаго́лѧ: по вѣ́рѣ ва́ю бꙋ́ди ва́ма. и҆ ѿверзо́стасѧ ѻ҆́чи и҆́ма: и҆ запретѝ и҆́ма і҆и҃съ, глаго́лѧ: блюди́та, да никто́же ᲂу҆вѣ́сть. ѻ҆́на же и҆зше́дша, просла́виста є҆го̀ по все́й землѝ то́й. тѣ́ма же и҆сходѧ́щема, сѐ приведо́ша къ немꙋ̀ человѣ́ка нѣ́ма, бѣснꙋ́ема. и҆ и҆згна́нꙋ бѣ́сꙋ, проглаго́ла нѣмы́й: и҆ диви́шасѧ наро́ди, глаго́люще, ꙗ҆́кѡ николи́же ꙗ҆ви́сѧ та́кѡ во і҆и҃ли. фарїсе́є же глаго́лахꙋ: ѡ҆ кнѧ́зѣ бѣсо́встѣмъ и҆зго́нитъ бѣ́сы. и҆ прохожда́ше і҆и҃съ гра́ды всѧ̑ и҆ вє́си, ᲂу҆чѧ̀ на со́нмищахъ и҆́хъ, и҆ проповѣ́даѧ є҆ѵⷢ҇лїе црⷭ҇твїѧ, и҆ цѣлѧ̀ всѧ́къ недꙋ́гъ, и҆ всѧ́кꙋ ꙗ҆́зю въ лю́дехъ. ",
}

add_evangelie_matfea {
  ["номер"] = 34,
  ["комментарий"] = "Мф., 34 зач., IX, 36 – X, 8.",
  ["текст_ру"] = "Во вре́мя о́но, ви́дев Иису́с наро́ды, милосе́рдова о них, я́ко бя́ху смяте́ни и отве́ржени, я́ко о́вцы не иму́щыя па́стыря. Тогда́ глаго́ла ученико́м Свои́м: жа́тва у́бо мно́га, де́лателей же ма́ло. Моли́теся у́бо Господи́ну жа́твы, я́ко да изведе́т де́латели на жа́тву Свою́. И призва́ обана́десять ученики́ Своя́, даде́ им власть на дусе́х нечи́стых, я́ко да изго́нят их, и цели́ти всяк неду́г и вся́ку боле́знь. Двана́десятих же Апо́столов имена́ суть сия́: пе́рвый Си́мон, и́же нарица́ется Петр, и Андре́й брат его́, Иа́ков Зеведе́ев и Иоа́нн брат его́, Фили́пп и Варфоломе́й, Фома́ и Матфе́й мыта́рь, Иа́ков Алфе́ев и Левве́й, нарече́нный Фадде́й, Си́мон Канани́т и Иу́да Искарио́тский, и́же и предаде́ Его́. Сия́ обана́десять посла́ Иису́с, запове́да им, глаго́ля: на путь язы́к не иди́те и во град Самаря́нский не вни́дите. Иди́те же па́че ко овца́м поги́бшым до́му Изра́илева. Ходя́ще же пропове́дуйте, глаго́люще, я́ко прибли́жися Ца́рствие Небе́сное. Боля́щыя изцеля́йте, прокаже́нныя очища́йте, ме́ртвыя воскреша́йте, бе́сы изгоня́йте, ту́не прия́сте, ту́не дади́те. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ви́дѣвъ і҆и҃съ наро́ды, милосе́рдова ѡ҆ ни́хъ, ꙗ҆́кѡ бѧ́хꙋ смѧте́ни, и҆ ѿве́ржени ꙗ҆́кѡ ѻ҆́вцы не и҆мꙋ́щыѧ па́стырѧ. тогда̀ глаго́ла ᲂу҆ченикѡ́мъ свои́мъ: жа́тва ᲂу҆́бѡ мно́га, дѣ́лателей же ма́лѡ. моли́тесѧ ᲂу҆́бѡ гдⷭ҇и́нꙋ жа́твы, ꙗ҆́кѡ да и҆зведе́тъ дѣ́латели на жа́твꙋ свою̀. и҆ призва̀ ѻ҆бана́десѧть ᲂу҆ченикѝ своѧ̀, дадѐ и҆̀мъ вла́сть на дꙋсѣ́хъ нечи́стыхъ, ꙗ҆́кѡ да и҆зго́нѧтъ и҆̀хъ, и҆ цѣли́ти всѧ́къ недꙋ́гъ, и҆ всѧ́кꙋ болѣ́знь. двана́десѧтихъ же а҆пⷭ҇лѡвъ и҆мена̀ сꙋ́ть сїѧ̑: пе́рвый сі́мѡнъ, и҆́же нарица́етсѧ пе́тръ, и҆ а҆ндре́й бра́тъ є҆гѡ̀: і҆а́кѡвъ зеведе́евъ, и҆ і҆ѡа́ннъ бра́тъ є҆гѡ̀: фїлі́ппъ, и҆ варѳоломе́й: ѳѡма̀, и҆ матѳе́й мыта́рь: і҆а́кѡвъ а҆лфе́евъ, и҆ левве́й, нарече́нный ѳадде́й: сі́мѡнъ канані́тъ, и҆ і҆ꙋ́да і҆скарїѡ́тскїй, и҆́же и҆ предадѐ є҆го̀. сїѧ̑ ѻ҆бана́десѧть посла̀ і҆и҃съ, заповѣ́да и҆̀мъ, глаго́лѧ: на пꙋ́ть ꙗ҆зы̑къ не и҆ди́те, и҆ во гра́дъ самарѧ́нскїй не вни́дите. и҆ди́те же па́че ко ѻ҆вца́мъ поги́бшымъ до́мꙋ і҆и҃лева. ходѧ́ще же проповѣ́дꙋйте, глаго́люще: ꙗ҆́кѡ прибли́жисѧ црⷭ҇твїе нбⷭ҇ное. болѧ́щыѧ и҆сцѣлѧ́йте, прокажє́нныѧ ѡ҆чища́йте, мє́ртвыѧ воскреша́йте, бѣ́сы и҆згонѧ́йте: тꙋ́не прїѧ́сте, тꙋ́не дади́те. ",
}

add_evangelie_matfea {
