}

add_evangelie_matfea {
  ["номер"] = 35,
  ["комментарий"] = "Мф., 35 зач., X, 9–15.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: не стяжи́те зла́та, ни сребра́, ни ме́ди при поясе́х ва́ших, ни пи́ры на пути́, ни двою́ ри́зу, ни сапо́г, ни жезл, досто́ин бо есть де́латель мзды своея́. Во́ньже а́ще коли́ждо град или́ весь вни́дете, испыта́йте, кто в нем досто́ин есть, и ту пребу́дите, до́ндеже изы́дете. Входя́ще же в дом целу́йте его́, глаго́люще: мир до́му сему́, и а́ще у́бо бу́дет дом досто́ин, прии́дет мир ваш нань, а́ще ли же не бу́дет досто́ин, мир ваш к вам возврати́тся. И и́же а́ще не прии́мет вас, ниже́ послу́шает слове́с ва́ших, исходя́ще из до́му или́ из гра́да того́, оттряси́те прах ног ва́ших. Ами́нь, глаго́лю вам, отра́днее бу́дет земли́ Содо́мстей и Гомо́ррстей в день су́дный, не́же гра́ду тому́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: не стѧжи́те зла́та, ни сребра̀, ни мѣ́ди при поѧсѣ́хъ ва́шихъ: ни пи́ры на пꙋтѝ, ни двою̀ ри́зꙋ, ни сапѡ́гъ, ни жє́злъ, досто́инъ бо є҆́сть дѣ́латель мзды̀ своеѧ̀. во́ньже а҆́ще коли́ждо гра́дъ и҆лѝ ве́сь вни́дете, и҆спыта́йте, кто̀ въ не́мъ досто́инъ є҆́сть: и҆ тꙋ̀ пребꙋ́дите, до́ндеже и҆зы́дете. входѧ́ще же въ до́мъ, цѣлꙋ́йте є҆го̀ глаго́люще: ми́ръ до́мꙋ семꙋ̀: и҆ а҆́ще ᲂу҆́бѡ бꙋ́детъ до́мъ досто́инъ, прїи́детъ ми́ръ ва́шъ на́нь: а҆́ще ли же не бꙋ́детъ досто́инъ, ми́ръ ва́шъ къ ва́мъ возврати́тсѧ. и҆ и҆́же а҆́ще не прїи́метъ ва́съ, нижѐ послꙋ́шаетъ слове́съ ва́шихъ, и҆сходѧ́ще и҆з̾ до́мꙋ, и҆лѝ и҆з̾ гра́да тогѡ̀, ѿтрѧси́те пра́хъ но́гъ ва́шихъ. а҆ми́нь глаго́лю ва́мъ: ѿра́днѣе бꙋ́детъ землѝ содо́мстѣй и҆ гомо́ррстѣй въ де́нь сꙋ́дный, не́же гра́дꙋ томꙋ̀. ",
}

add_evangelie_matfea {
  ["номер"] = 36,
  ["комментарий"] = "Мф., 36 зач., X, 16–22.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: се Аз посыла́ю вас я́ко о́вцы посреде́ волко́в, бу́дите у́бо му́дри я́ко змия́, и це́ли я́ко го́лубие. Внемли́те же от челове́к, предадя́т бо вы на со́нмы, и на собо́рищах их бию́т вас. И пред влады́ки же и цари́ веде́ни бу́дете Мене́ ра́ди, во свиде́тельство им и язы́ком. Егда́ же предаю́т вы, не пецы́теся, ка́ко или́ что возглаго́лете: даст бо ся вам в той час, что возглаго́лете. Не вы бо бу́дете глаго́лющии, но Дух Отца́ ва́шего глаго́ляй в вас. Преда́ст же брат бра́та на смерть и оте́ц ча́до, и воста́нут ча́да на роди́тели и убию́т их. И бу́дете ненави́дими все́ми и́мени Моего́ ра́ди. Претерпе́вый же до конца́, той спасе́н бу́дет. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: сѐ а҆́зъ посыла́ю ва́съ ꙗ҆́кѡ ѻ҆́вцы посредѣ̀ волкѡ́въ: бꙋ́дите ᲂу҆́бѡ мꙋ́дри ꙗ҆́кѡ ѕмїѧ̑, и҆ цѣ́ли ꙗ҆́кѡ го́лꙋбїе. внемли́те же ѿ чл҃вѣ̑къ: предадѧ́тъ бо вы̀ на со́нмы, и҆ на собо́рищахъ и҆́хъ бїю́тъ ва́съ. и҆ пред̾ влады́ки же и҆ царѝ веде́ни бꙋ́дете менѐ ра́ди, во свидѣ́тельство и҆̀мъ и҆ ꙗ҆зы́кѡмъ. є҆гда́ же предаю́тъ вы̀, не пецы́тесѧ, ка́кѡ и҆лѝ что̀ возглаго́лете: да́стъ бо сѧ ва́мъ въ то́й ча́съ что̀ возглаго́лете. не вы́ бо бꙋ́дете глаго́лющїи, но дх҃ъ ѻ҆ц҃а̀ ва́шегѡ глаго́лѧй въ ва́съ. преда́стъ же бра́тъ бра́та на сме́рть, и҆ ѻ҆те́цъ ча́до: и҆ воста́нꙋтъ ча̑да на роди́тели, и҆ ᲂу҆бїю́тъ и҆̀хъ. и҆ бꙋ́дете ненави́дими всѣ́ми и҆́мене моегѡ̀ ра́ди. претерпѣ́вый же до конца̀, то́й спасе́нъ бꙋ́детъ. ",
}

add_evangelie_matfea {
  ["номер"] = 37,
  ["комментарий"] = "Мф., 37 зач., X, 23–31.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: егда́ го́нят вы во гра́де сем, бе́гайте в други́й. Ами́нь бо, глаго́лю вам, не и́мате сконча́ти гра́ды Изра́илевы, до́ндеже прии́дет Сын Челове́ческий. Несть учени́к над учи́телем свои́м, ниже́ раб над господи́ном свои́м. Довле́ет ученику́, да бу́дет я́ко учи́тель его́, и раб я́ко госпо́дь его́. А́ще господи́на до́му веельзеву́ла нареко́ша, кольми́ па́че дома́шния его́? Не убо́йтеся у́бо их, ничто́же бо есть покрове́но, е́же не откры́ется, и та́йно, е́же не уве́дено бу́дет. Е́же глаго́лю вам во тме, рцы́те во све́те: и е́же во у́шы слы́шите, пропове́дите на кро́вех. И не убо́йтеся от убива́ющих те́ло, ду́шу же не могу́щих уби́ти, убо́йтеся же па́че могу́щаго и ду́шу и те́ло погуби́ти в гее́нне. Не две ли пти́це цени́теся еди́ному асса́рию? И ни еди́на от нею́ паде́т на земли́ без Отца́ ва́шего. Вам же и вла́си главни́и вси изочте́ни суть. Не убо́йтеся у́бо, мно́зех птиц лу́чши есте́ вы. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: є҆гда̀ го́нѧтъ вы̀ во гра́дѣ се́мъ, бѣ́гайте въ дрꙋгі́й. а҆ми́нь бо глаго́лю ва́мъ: не и҆́мате сконча́ти гра́ды і҆и҃левы, до́ндеже прїи́детъ сн҃ъ чл҃вѣ́ческїй. нѣ́сть ᲂу҆ч҃нкъ над̾ ᲂу҆чи́телемъ свои́мъ, нижѐ ра́бъ над̾ господи́номъ свои́мъ. довлѣ́етъ ᲂу҆чн҃кꙋ̀, да бꙋ́детъ ꙗ҆́кѡ ᲂу҆ч҃тль є҆гѡ̀, и҆ ра́бъ, ꙗ҆́кѡ госпо́дь є҆гѡ̀. а҆́ще господи́на до́мꙋ веельзевꙋ́ла нареко́ша, кольмѝ па́че дома̑шнїѧ є҆гѡ̀. не ᲂу҆бо́йтесѧ ᲂу҆̀бо и҆́хъ: ничто́же бо є҆́сть покрове́но, є҆́же не ѿкры́етсѧ: и҆ та́йно, є҆́же не ᲂу҆вѣ́дѣно бꙋ́детъ. є҆́же глаго́лю ва́мъ во тмѣ̀, рцы́те во свѣ́тѣ: и҆ є҆́же во ᲂу҆́ши слы́шите, проповѣ́дите на кро́вѣхъ. и҆ не ᲂу҆бо́йтесѧ ѿ ᲂу҆бива́ющихъ тѣ́ло, дꙋ́шꙋ же не могꙋ́щихъ ᲂу҆би́ти: ᲂу҆бо́йтесѧ же па́че могꙋ́щагѡ и҆ дꙋ́шꙋ и҆ тѣ́ло погꙋби́ти въ гее́ннѣ. не двѣ́ ли пти́цѣ цѣни́тѣсѧ є҆ди́номꙋ а҆сса́рїю; и҆ ни є҆ди́на ѿ нею̀ паде́тъ на землѝ без̾ ѻ҆ц҃а̀ ва́шегѡ. ва́мъ же и҆ вла́си главні́и всѝ и҆зочте́ни сꙋ́ть. не ᲂу҆бо́йтесѧ ᲂу҆̀бо: мно́зѣхъ пти́цъ лꙋ́чши є҆стѐ вы̀. ",
}

add_evangelie_matfea {
  ["номер"] = 38,
  ["комментарий"] = "Мф., 38 зач., X, 32–33, 37–38; XIX, 27–30.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: всяк и́же испове́сть Мя пред челове́ки, испове́м его́ и Аз пред Отце́м Мои́м, и́же на небесе́х, а и́же отве́ржется Мене́ пред челове́ки, отве́ргуся его́ и Аз пред Отце́м Мои́м, и́же на небесе́х. И́же лю́бит отца́ или́ ма́терь па́че Мене́, несть Мене́ досто́ин, и и́же лю́бит сы́на или́ дщерь па́че Мене́, несть Мене́ досто́ин, и и́же не прии́мет креста́ своего́ и в след Мене́ гряде́т, несть Мене́ досто́ин. Тогда́ отвеща́в Петр рече́ Ему́: се мы оста́вихом вся и в след Тебе́ идо́хом, что у́бо бу́дет нам? Иису́с же рече́ им: ами́нь глаго́лю вам, я́ко вы ше́дшии по Мне, в пакибытие́, егда́ ся́дет Сын Челове́ческий на престо́ле сла́вы Своея́, ся́дете и вы на двоюна́десяте престо́лу, судя́ще обемана́десяте коле́нома Изра́илевома. И всяк, и́же оста́вит дом, или́ бра́тию, или́ сестры́, или́ отца́, или́ ма́терь, или́ жену́, или́ ча́да, или́ се́ла, и́мене Моего́ ра́ди, стори́цею прии́мет и живо́т ве́чный насле́дит. Мно́зи же бу́дут пе́рви после́днии, и после́дни пе́рвии. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: всѧ́къ и҆́же и҆сповѣ́сть мѧ̀ пред̾ человѣ́ки, и҆сповѣ́мъ є҆го̀ и҆ а҆́зъ пред̾ ѻ҆ц҃е́мъ мои́мъ, и҆́же на нб҃сѣ́хъ. а҆ и҆́же ѿве́ржетсѧ менѐ пред̾ человѣ́ки, ѿве́ргꙋсѧ є҆гѡ̀ и҆ а҆́зъ пред̾ ѻ҆ц҃е́мъ мои́мъ, и҆́же на нб҃сѣ́хъ. и҆́же лю́битъ ѻ҆тца̀ и҆лѝ ма́терь па́че менѐ, нѣ́сть менѐ досто́инъ: и҆ и҆́же лю́битъ сы́на и҆лѝ дще́рь па́че менѐ, нѣ́сть менѐ досто́инъ. и҆ и҆́же не прїи́метъ крⷭ҇та̀ своегѡ̀, и҆ въ слѣ́дъ менѐ грѧде́тъ, нѣ́сть менѐ досто́инъ. тогда̀ ѿвѣща́въ пе́тръ речѐ є҆мꙋ̀: сѐ мы̀ ѡ҆ста́вихомъ всѧ̑, и҆ въ слѣ́дъ тебѐ и҆до́хомъ, что̀ ᲂу҆̀бо бꙋ́детъ на́мъ; і҆и҃съ же речѐ и҆̀мъ: а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ вы̀ ше́дшїи по мнѣ̀, въ пакибытїѐ, є҆гда̀ сѧ́детъ сн҃ъ человѣ́ческїй на престо́лѣ сла́вы своеѧ̀, сѧ́дете и҆ вы̀ на двоюна́десѧте престѡ́лꙋ, сꙋдѧ́ще ѻ҆бѣмана́десѧте колѣ́нома і҆и҃левома. и҆ всѧ́къ и҆́же ѡ҆ста́витъ до́мъ, и҆лѝ бра́тїю, и҆лѝ сєстры̀, и҆лѝ ѻ҆тца̀, и҆лѝ ма́терь, и҆лѝ женꙋ̀, и҆лѝ ча̑да, и҆лѝ сє́ла, и҆́мене моегѡ̀ ра́ди, стори́цею прїи́метъ, и҆ живо́тъ вѣ́чный наслѣ́дитъ. мно́зи же бꙋ́дꙋтъ пе́рви, послѣ́днїи: и҆ послѣ́дни, пе́рвїи. ",
}

add_evangelie_matfea {
  ["номер"] = 38,
  ["комментарий"] = "Мф., 38 зач., X, 32–36; XI, 1.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: всяк и́же испове́сть Мя пред челове́ки, испове́м его́ и Аз пред Отце́м Мои́м, и́же на Небесе́х, а и́же отве́ржется мене́ пред челове́ки, отве́ргуся его́ и Аз пред Отце́м Мои́м, и́же на Небесе́х. Не мни́те, я́ко приидо́х воврещи́ мир на зе́млю, не приидо́х бо воврещи́ мир, но мечь. Приидо́х бо разлучи́ти челове́ка на отца́ своего́, и дщерь на ма́терь свою́, и неве́сту на свекро́вь свою́. И врази́ челове́ку дома́шнии его́. И бысть, егда́ соверши́ Иису́с запове́дая обемана́десяте ученико́ма свои́ма, пре́йде отту́ду учи́ти, и пропове́дати во гра́дех их. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: всѧ́къ и҆́же и҆сповѣ́сть мѧ̀ пред̾ человѣ́ки, и҆сповѣ́мъ є҆го̀ и҆ а҆́зъ пред̾ ѻ҆ц҃е́мъ мои́мъ, и҆́же на нб҃сѣ́хъ. а҆ и҆́же ѿве́ржетсѧ менѐ пред̾ человѣ́ки, ѿве́ргꙋсѧ є҆гѡ̀ и҆ а҆́зъ пред̾ ѻ҆ц҃е́мъ мои́мъ, и҆́же на нб҃сѣ́хъ. не мни́те, ꙗ҆́кѡ прїидо́хъ воврещѝ ми́ръ на зе́млю: не прїидо́хъ бо воврещѝ ми́ръ, но ме́чь. прїидо́хъ бо разлꙋчи́ти человѣ́ка на ѻ҆тца̀ своего̀, и҆ дще́рь на ма́терь свою̀, и҆ невѣ́стꙋ на свекро́вь свою̀. и҆ вразѝ человѣ́кꙋ дома́шнїи є҆гѡ̀. и҆ бы́сть, є҆гда̀ совершѝ і҆и҃съ, заповѣ́даѧ ѻ҆бѣмана́десѧте ᲂу҆ченико́ма свои́ма, пре́йде ѿтꙋ́дꙋ ᲂу҆чи́ти, и҆ проповѣ́дати во гра́дѣхъ и҆́хъ. ",
}

add_evangelie_matfea {
  ["номер"] = 39,
  ["комментарий"] = "Мф., 39 зач., X, 37 – XI, 1.",
  ["текст_ру"] = "Рече́ Госпо́дь: и́же лю́бит отца́ или́ ма́терь па́че Мене́, несть Мене́ досто́ин, и и́же лю́бит сы́на или́ дщерь па́че Мене́, несть Мене́ досто́ин. И и́же не прии́мет креста́ своего́ и в след Мене́ гряде́т, несть Мене́ досто́ин. Обреты́й ду́шу свою́ погуби́т ю́, а и́же погуби́т ду́шу свою́ Мене́ ра́ди, обря́щет ю́. И́же вас прие́млет, Мене́ прие́млет, и и́же прие́млет Мене́, прие́млет Посла́вшаго Мя. Прие́мляй проро́ка во и́мя проро́че, мзду проро́чу прии́мет, и прие́мляй пра́ведника во и́мя пра́ведниче, мзду пра́ведничу прии́мет. И и́же а́ще напои́т еди́наго от ма́лых сих ча́шу студены́ воды́ то́кмо, во и́мя ученика́, ами́нь глаго́лю вам, не погуби́т мзды своея́. И бысть, егда́ соверши́ Иису́с запове́дая обемана́десяте ученико́ма Свои́ма, пре́йде отту́ду учи́ти и пропове́дати во гра́дех их. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: и҆́же лю́битъ ѻ҆тца̀ и҆лѝ ма́терь па́че менѐ, нѣ́сть менѐ досто́инъ: и҆ и҆́же лю́битъ сы́на и҆лѝ дще́рь па́че менѐ, нѣ́сть менѐ досто́инъ. и҆ и҆́же не прїи́метъ крⷭ҇та̀ своегѡ̀, и҆ въ слѣ́дъ менѐ грѧде́тъ, нѣ́сть менѐ досто́инъ. ѡ҆брѣты́й дꙋ́шꙋ свою̀, погꙋби́тъ ю҆̀: а҆ и҆́же погꙋби́тъ дꙋ́шꙋ свою̀ менѐ ра́ди, ѡ҆брѧ́щетъ ю҆̀. и҆́же ва́съ прїе́млетъ, менѐ прїе́млетъ: и҆ и҆́же прїе́млетъ менѐ, прїе́млетъ посла́вшаго мѧ̀. прїе́млѧй проро́ка во и҆́мѧ проро́че, мздꙋ̀ проро́чꙋ прїи́метъ: и҆ прїе́млѧй пра́ведника во и҆́мѧ пра́ведниче, мздꙋ̀ пра́ведничꙋ прїи́метъ. и҆ и҆́же а҆́ще напои́тъ є҆ди́наго ѿ ма́лыхъ си́хъ ча́шꙋ стꙋдены̀ воды̀, то́кмѡ во и҆́мѧ ᲂу҆ченика̀, а҆ми́нь глаго́лю ва́мъ, не погꙋби́тъ мзды̀ своеѧ̀. и҆ бы́сть, є҆гда̀ совершѝ і҆и҃съ, заповѣ́даѧ ѻ҆бѣмана́десѧте ᲂу҆ченико́ма свои́ма, пре́йде ѿтꙋ́дꙋ ᲂу҆чи́ти, и҆ проповѣ́дати во гра́дѣхъ и҆́хъ. ",
}

add_evangelie_matfea {
  ["номер"] = 40,
  ["комментарий"] = "Мф., 40 зач., XI, 2–15.",
  ["текст_ру"] = "Во вре́мя о́но, слы́шав Иоа́нн во узи́лищи дела́ Христо́ва, посла́ два от учени́к свои́х, рече́ Ему́: Ты ли еси́ Гряды́й, или́ ино́го ча́ем? И отвеща́в Иису́с рече́ им: ше́дша возвести́та Иоа́ннови, я́же слы́шита и ви́дита. Слепи́и прозира́ют и хро́мии хо́дят, прокаже́ннии очища́ются и глуси́и слы́шат, ме́ртвии востаю́т и ни́щии благовеству́ют. И блаже́н есть, и́же а́ще не соблазни́тся о Мне. Те́ма же исходя́щема, нача́т Иису́с наро́дом глаго́лати о Иоа́нне: чесо́ изыдо́сте в пусты́ню ви́дети? Трость ли ве́тром коле́блему? Но чесо́ изыдо́сте ви́дети? Челове́ка ли в мя́кки ри́зы облече́нна? Се, и́же мя́ккая нося́щии, в доме́х ца́рских суть. Но чесо́ изыдо́сте ви́дети? Проро́ка ли? Ей, глаго́лю вам, и ли́шше проро́ка. Сей бо есть, о не́мже есть пи́сано: се Аз посыла́ю А́нгела Моего́ пред лице́м Твои́м, и́же угото́вит путь Твой пред Тобо́ю. Ами́нь глаго́лю вам, не воста́ в рожде́нных жена́ми бо́лий Иоа́нна Крести́теля, мний же во Ца́рствии Небе́снем бо́лий его́ есть. От дней же Иоа́нна Крести́теля досе́ле Ца́рствие Небе́сное ну́дится, и ну́ждницы восхища́ют е́. Вси бо проро́цы и зако́н до Иоа́нна прореко́ша. И а́ще хо́щете прия́ти, той есть Илиа́ хотя́й приити́. Име́яй у́ши слы́шати да слы́шит. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, слы́шавъ і҆ѡа́ннъ во ᲂу҆зи́лищи дѣла̀ хрⷭ҇то́ва, посла̀ два̀ ѿ ᲂу҆ч҃ни̑къ свои́хъ, речѐ є҆мꙋ̀: ты́ ли є҆сѝ грѧды́й, и҆лѝ и҆но́гѡ ча́емъ; и҆ ѿвѣща́въ і҆и҃съ речѐ и҆̀мъ: ше́дша возвѣсти́та і҆ѡа́ннови, ꙗ҆̀же слы́шита и҆ ви́дита. слѣпі́и прозира́ютъ, и҆ хро́мїи хо́дѧтъ: прокаже́ннїи ѡ҆чища́ютсѧ, и҆ глꙋсі́и слы́шатъ: ме́ртвїи востаю́тъ, и҆ ни́щїи благовѣствꙋ́ютъ. и҆ блаже́нъ є҆́сть, и҆́же а҆́ще не соблазни́тсѧ ѡ҆ мнѣ̀. тѣ́ма же и҆сходѧ́щема, нача́тъ і҆и҃съ наро́дѡмъ глаго́лати ѡ҆ і҆ѡа́ннѣ: чесѡ̀ и҆зыдо́сте въ пꙋсты́ню ви́дѣти; тро́сть ли вѣ́тромъ коле́блемꙋ; но чесѡ̀ и҆зыдо́сте ви́дѣти; человѣ́ка ли въ мѧ́кки ри̑зы ѡ҆блече́нна; сѐ и҆̀же мѧ̑ккаѧ носѧ́щїи, въ домѣ́хъ црⷭ҇кихъ сꙋ́ть. но чесѡ̀ и҆зыдо́сте ви́дѣти; проро́ка ли; є҆́й глаго́лю ва́мъ, и҆ ли́шше проро́ка. се́й бо є҆́сть, ѡ҆ не́мже є҆́сть пи́сано: сѐ а҆́зъ посыла́ю а҆́гг҃ла моего̀ предъ лице́мъ твои́мъ, и҆́же ᲂу҆гото́витъ пꙋ́ть тво́й пред̾ тобо́ю. а҆ми́нь глаго́лю ва́мъ, не воста̀ въ рожде́нныхъ жена́ми бо́лїй і҆ѡа́нна крⷭ҇ти́телѧ: мні́й же во црⷭ҇твїи нбⷭ҇нѣмъ, бо́лїй є҆гѡ̀ є҆́сть. ѿ дне́й же і҆ѡа́нна крⷭ҇ти́телѧ досе́лѣ, црⷭ҇твїе нбⷭ҇ное нꙋ́дитсѧ, и҆ нꙋ́ждницы восхища́ютъ є҆̀. вси́ бо проро́цы и҆ зако́нъ до і҆ѡа́нна прореко́ша. и҆ а҆́ще хо́щете прїѧ́ти, то́й є҆́сть и҆лїа̀ хотѧ́й прїитѝ. и҆мѣ́ѧй ᲂу҆́ши слы́шати, да слы́шитъ. ",
}

add_evangelie_matfea {
  ["номер"] = 41,
  ["комментарий"] = "Мф., 41 зач., XI, 16–20.",
  ["текст_ру"] = "Рече́ Госпо́дь: кому́ уподо́блю род сей? Подо́бен есть де́тем седя́щым на то́ржищих, и возглаша́ющым друго́м свои́м и глаго́лющым: писка́хом вам, и не пляса́сте, пла́кахом вам, и не рыда́сте. Прии́де бо Иоа́нн ни яды́й, ни пия́, и глаго́лют: бе́са и́мать. Прии́де Сын Челове́ческий яды́й и пия́й, и глаго́лют: се челове́к я́дца и винопи́йца, мытаре́м друг и гре́шником. И оправди́ся прему́дрость от чад свои́х. Тогда́ нача́т Иису́с поноша́ти градово́м, в ни́хже бы́ша мно́жайшыя си́лы Его́, зане́ не пока́яшася. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: комꙋ̀ ᲂу҆подо́блю ро́дъ се́й; подо́бенъ є҆́сть дѣ́темъ, сѣдѧ́щымъ на то́ржищахъ, и҆ возглаша́ющымъ дрꙋгѡ́мъ свои́мъ, и҆ глаго́лющымъ: писка́хомъ ва́мъ, и҆ не плѧса́сте: пла́кахомъ ва́мъ, и҆ не рыда́сте. прїи́де бо і҆ѡа́ннъ, ни ꙗ҆ды́й, ни пїѧ̀, и҆ глаго́лютъ: бѣ́са и҆́мать. прїи́де сн҃ъ чл҃вѣ́ческїй, ꙗ҆ды́й и҆ пїѧ́й, и҆ глаго́лютъ: сѐ человѣ́къ ꙗ҆́дца и҆ вїнопі́йца, мытарє́мъ дрꙋ́гъ и҆ грѣ́шникѡмъ. и҆ ѡ҆правди́сѧ премꙋ́дрость ѿ ча̑дъ свои́хъ. тогда̀ нача́тъ і҆и҃съ поноша́ти градовѡ́мъ, въ ни́хже бы́ша мно́жайшыѧ си́лы є҆гѡ̀, занѐ не пока́ѧшасѧ. ",
}

add_evangelie_matfea {
  ["номер"] = 42,
  ["комментарий"] = "Мф., 42 зач., XI, 20–26.",
  ["текст_ру"] = "Во вре́мя о́но, нача́т Иису́с поноша́ти градово́м, в ни́хже бы́ша мно́жайшыя си́лы Его́, зане́ не пока́яшася: го́ре тебе́, Хорази́не, го́ре тебе́, Вифсаи́до, я́ко а́ще в Ти́ре и Сидо́не бы́ша си́лы бы́ли бы́вшыя в вас, дре́вле у́бо во вре́тищи и пе́пеле пока́ялися бы́ша. Оба́че глаго́лю вам Ти́ру и Сидо́ну отра́днее бу́дет в день су́дный, не́же вам. И ты, Капернау́ме, и́же до небе́с вознесы́йся, до а́да сни́деши, зане́ а́ще в Содо́мех бы́ша си́лы бы́ли бы́вшыя в тебе́, пребы́ли у́бо бы́ша до дне́шняго дне. Оба́че глаго́лю вам, я́ко земли́ Содо́мстей отра́днее бу́дет в день су́дный, не́же тебе́. В то вре́мя отвеща́в Иису́с рече́: испове́даю Ти ся, О́тче, Го́споди небесе́ и земли́, я́ко утаи́л еси́ сия́ от прему́дрых и разу́мных и откры́л еси́ та младе́нцем. Ей, О́тче, я́ко та́ко бысть благоволе́ние пред Тобо́ю. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, нача́тъ і҆и҃съ поноша́ти градовѡ́мъ, въ ни́хже бы́ша мно́жайшыѧ си́лы є҆гѡ̀, занѐ не пока́ѧшасѧ. го́ре тебѣ̀ хоразі́не, го́ре тебѣ̀ виѳсаі́до: ꙗ҆́кѡ а҆́ще въ тѵ́рѣ и҆ сїдѡ́нѣ бы́ша си́лы бы́ли бы́вшыѧ въ ва́съ, дре́вле ᲂу҆́бѡ во вре́тищи и҆ пе́пелѣ пока́ѧлисѧ бы́ша. ѻ҆ба́че глаго́лю ва́мъ: тѵ́рꙋ и҆ сїдѡ́нꙋ ѿра́днѣе бꙋ́детъ въ де́нь сꙋ́дный, не́же ва́мъ. и҆ ты̀ капернаꙋ́ме, и҆́же до нб҃съ вознесы́йсѧ, до а҆́да сни́деши: занѐ а҆́ще въ содо́мѣхъ бы́ша си̑лы бы́ли бы́вшыѧ въ тебѣ̀, пребы́ли ᲂу҆́бѡ бы́ша до дне́шнѧгѡ днѐ. ѻ҆ба́че глаго́лю ва́мъ, ꙗ҆́кѡ землѝ содо́мстѣй ѿра́днѣе бꙋ́детъ въ де́нь сꙋ́дный, не́же тебѣ̀. въ то̀ вре́мѧ ѿвѣща́въ і҆и҃съ, речѐ: и҆сповѣ́даю ти сѧ ѻ҆́ч҃е, гдⷭ҇и нб҃сѐ и҆ землѝ, ꙗ҆́кѡ ᲂу҆таи́лъ є҆сѝ сїѧ̑ ѿ премꙋ́дрыхъ и҆ разꙋ́мныхъ, и҆ ѿкры́лъ є҆сѝ та̑ младе́нцємъ. є҆́й, ѻ҆́ч҃е, ꙗ҆́кѡ та́кѡ бы́сть бл҃говоле́нїе пред̾ тобо́ю. ",
}

add_evangelie_matfea {
  ["номер"] = 43,
  ["комментарий"] = "Мф., 43 зач., XI, 27–30.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: вся Мне предана́ суть Отце́м Мои́м, и никто́же зна́ет Сы́на, то́кмо Оте́ц, ни Отца́ кто зна́ет, то́кмо Сын, и ему́же а́ще во́лит Сын откры́ти. Прииди́те ко Мне вси тружда́ющиися и обремене́ннии, и Аз упоко́ю вы. Возми́те и́го Мое́ на себе́, и научи́теся от Мене́, я́ко кро́ток есмь и смире́н се́рдцем, и обря́щете поко́й душа́м ва́шим. И́го бо Мое́ бла́го, и бре́мя Мое́ легко́ есть. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: всѧ̑ мнѣ̀ предана̀ сꙋ́ть ѻ҆ц҃е́мъ мои́мъ, и҆ никто́же зна́етъ сн҃а, то́кмѡ ѻ҆ц҃ъ: ни ѻ҆ц҃а̀ кто̀ зна́етъ, то́кмѡ сн҃ъ, и҆ є҆мꙋ́же а҆́ще во́литъ сн҃ъ ѿкры́ти. прїиди́те ко мнѣ̀ всѝ трꙋжда́ющїисѧ и҆ ѡ҆бремене́ннїи, и҆ а҆́зъ ᲂу҆поко́ю вы̀. воз̾ми́те и҆́го моѐ на себѐ, и҆ наꙋчи́тесѧ ѿ менѐ, ꙗ҆́кѡ кро́токъ є҆́смь и҆ смире́нъ се́рдцемъ, и҆ ѡ҆брѧ́щете поко́й дꙋша́мъ ва́шымъ. и҆́го бо моѐ бла́го, и҆ бре́мѧ моѐ легко̀ є҆́сть. ",
}

add_evangelie_matfea {
  ["номер"] = 44,
  ["комментарий"] = "Мф., 44 зач., XII, 1–8.",
  ["текст_ру"] = "Во вре́мя о́но, и́де Иису́с в суббо́ты сквозе́ се́яния, ученицы́ же Его́ взалка́ша и нача́ша востерза́ти кла́сы и я́сти. Фарисе́е же ви́девше ре́ша Ему́: се ученицы́ Твои́ творя́т, его́же не досто́ит твори́ти в суббо́ту. Он же рече́ им: не́сте ли чли, что сотвори́ Дави́д, егда́ взалка́ сам и су́щии с ним? Ка́ко вни́де в храм Бо́жий и хле́бы предложе́ния снеде́, и́хже не досто́йно бе ему́ я́сти, ни су́щым с ним, то́кмо иере́ем еди́ным? Или́ не́сте чли в зако́не, я́ко в суббо́ты свяще́нницы в це́ркви суббо́ты скверня́т и непови́нни суть? Глаго́лю же вам, я́ко це́ркве бо́ле есть зде, а́ще ли бы́сте ве́дали, что есть: ми́лости хощу́, а не же́ртвы, николи́же у́бо бы́сте осужда́ли непови́нных. Госпо́дь бо есть и суббо́ты Сын Челове́ческий. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆́де і҆и҃съ въ сꙋббѡ́ты сквозѣ̀ сѣ̑ѧнїѧ: ᲂу҆чн҃цы́ же є҆гѡ̀ взалка́шасѧ, и҆ нача́ша востерза́ти кла́сы, и҆ ꙗ҆́сти. фарїсе́є же ви́дѣвше, рѣ́ша є҆мꙋ̀: сѐ ᲂу҆ченицы̀ твоѝ творѧ́тъ, є҆гѡ́же не досто́итъ твори́ти въ сꙋббѡ́тꙋ. ѻ҆́нъ же речѐ и҆̀мъ: нѣ́сте ли члѝ, что̀ сотворѝ дв҃дъ, є҆гда̀ взалка̀ са́мъ и҆ сꙋ́щїи съ ни́мъ; ка́кѡ вни́де въ хра́мъ бж҃їй, и҆ хлѣ́бы предложе́нїѧ снѣдѐ, и҆́хже не досто́йно бѣ̀ є҆мꙋ̀ ꙗ҆́сти, ни сꙋ́щымъ съ ни́мъ, то́кмѡ і҆ере́ємъ є҆ди́нымъ; и҆лѝ нѣ́сте члѝ въ зако́нѣ, ꙗ҆́кѡ въ сꙋббѡ́ты сщ҃е́нницы въ це́ркви сꙋббѡ́ты сквернѧ́тъ, и҆ непови́нни сꙋ́ть; глаго́лю же ва́мъ, ꙗ҆́кѡ це́ркве бо́лѣ є҆́сть здѣ̀. а҆́ще ли бы́сте вѣ́дали что̀ є҆́сть, ми́лости хощꙋ̀, а҆ не же́ртвы: николи́же ᲂу҆́бѡ бы́сте ѡ҆сꙋжда́ли непови́нныхъ. гдⷭ҇ь бо є҆́сть и҆ сꙋббѡ́ты сн҃ъ человѣ́ческїй. ",
}

add_evangelie_matfea {
  ["номер"] = 45,
  ["комментарий"] = "Мф., 45 зач., XII, 9-13.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с на со́нмище иуде́йское. И се челове́к бе ту, ру́ку имы́й су́ху. И вопроси́ша Его́, глаго́люще: а́ще досто́ит в суббо́ты цели́ти? Да на Него́ возглаго́лют. Он же рече́ им: кто есть от вас челове́к, и́же и́мать овча́ еди́но, и а́ще впаде́тся в суббо́ты в я́му, не и́мет ли е́ и и́змет? Кольми́ у́бо лу́чше есть челове́к овча́те? Те́мже досто́ит в суббо́ты добро́ твори́ти. Тогда́ глаго́ла челове́ку: простри́ ру́ку твою́. И простре́, и утверди́ся цела́ я́ко друга́я. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ на со́нмище і҆ꙋде́йское, и҆ сѐ человѣ́къ бѣ̀ тꙋ̀, рꙋ́кꙋ и҆мы́й сꙋ́хꙋ, и҆ вопроси́ша є҆го̀ глаго́люще: а҆́ще досто́итъ въ сꙋббѡ́ты цѣли́ти; да на него̀ возглаго́лютъ. ѻ҆́нъ же речѐ и҆̀мъ: кто́ є҆сть ѿ ва́съ человѣ́къ, и҆́же и҆́мать ѻ҆вча̀ є҆ди́но, и҆ а҆́ще впаде́тсѧ въ сꙋббѡ́ты въ ꙗ҆́мꙋ, не и҆́метъ ли є҆̀, и҆ и҆́зметъ; кольмѝ ᲂу҆́бѡ лꙋ́чше є҆́сть человѣ́къ ѻ҆вча́те; тѣ́мже досто́итъ въ сꙋббѡ́ты добро̀ твори́ти. тогда̀ глаго́ла человѣ́кꙋ, прострѝ рꙋ́кꙋ твою̀. и҆ прострѐ: и҆ ᲂу҆тверди́сѧ цѣла̀ ꙗ҆́кѡ дрꙋга́ѧ. ",
}

add_evangelie_matfea {
  ["номер"] = 46,
  ["комментарий"] = "Мф., 46 зач., XII, 14–16, 22–30.",
  ["текст_ру"] = "Во вре́мя о́но, сове́т сотвори́ша фарисе́е на Иису́са, ка́ко Его́ погубя́т. Иису́с же разуме́в оты́де отту́ду. И по Нем идо́ша наро́ди мно́зи, и исцели́ их всех. И запрети́ им, да не я́ве Его́ творя́т. Тогда́ приведо́ша к Нему́ бесную́щася сле́па и не́ма, и исцели́ его́, я́ко слепо́му и немо́му глаго́лати и гля́дати. И дивля́хуся вси наро́ди глаго́люще: еда́ Сей есть Христо́с сын Дави́дов? Фарисе́е же слы́шавше ре́ша: Сей не изго́нит бе́сы, то́кмо о веельзеву́ле кня́зе бесо́встем. Ве́дый же Иису́с мы́сли их, рече́ им: вся́кое ца́рство разде́льшееся на ся запусте́ет, и всяк град или́ дом раздели́выйся на ся не ста́нет. И а́ще сатана́ сатану́ изго́нит, на ся раздели́лся есть: ка́ко у́бо ста́нет ца́рство его́? И а́ще Аз о веельзеву́ле изгоню́ бе́сы, сы́нове ва́ши о ком изго́нят? Сего́ ра́ди ти́и вам бу́дут судии́. А́ще ли же Аз о Ду́се Бо́жии изгоню́ бе́сы, у́бо пости́же на вас Ца́рствие Бо́жие. Или́ ка́ко мо́жет кто вни́ти в дом кре́пкаго и сосу́ды его́ расхи́тити, а́ще не пе́рвее свя́жет кре́пкаго, и тогда́ дом его́ расхи́тит? И́же несть со Мно́ю, на Мя есть, и и́же не собира́ет со Мно́ю, расточа́ет. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, совѣ́тъ сотвори́ша фарїсе́є на і҆и҃са, ка́кѡ є҆го̀ погꙋбѧ́тъ: і҆и҃съ же разꙋмѣ́въ ѿи́де ѿтꙋ́дꙋ. и҆ по не́мъ и҆до́ша наро́ди мно́зи: и҆ и҆сцѣлѝ и҆̀хъ всѣ́хъ. и҆ запретѝ и҆̀мъ, да не ꙗ҆́вѣ є҆го̀ творѧ́тъ. тогда̀ приведо́ша къ немꙋ̀ бѣснꙋ́ющасѧ, слѣ́па и҆ нѣ́ма: и҆ и҆сцѣлѝ є҆го̀ ꙗ҆́кѡ слѣпо́мꙋ и҆ нѣмо́мꙋ глаго́лати и҆ глѧ́дати. и҆ дивлѧ́хꙋсѧ всѝ наро́ди глаго́люще: є҆да̀ се́й є҆́сть хрⷭ҇то́съ, сн҃ъ дв҃довъ; фарїсе́є же слы́шавше, рѣ́ша: се́й не и҆зго́нитъ бѣ́сы, то́кмѡ ѡ҆ веельзевꙋ́лѣ кнѧ́зѣ бѣсо́встѣмъ. вѣ́дый же і҆и҃съ мы̑сли и҆́хъ, речѐ и҆̀мъ: всѧ́кое црⷭ҇тво, раздѣ́льшеесѧ на сѧ̀, запꙋстѣ́етъ: и҆ всѧ́къ гра́дъ и҆лѝ до́мъ, раздѣли́выйсѧ на сѧ̀, не ста́нетъ. и҆ а҆́ще сатана̀ сатанꙋ̀ и҆зго́нитъ, на сѧ̀ раздѣли́лсѧ є҆́сть, ка́кѡ ᲂу҆́бѡ ста́нетъ црⷭ҇тво є҆гѡ̀; и҆ а҆́ще а҆́зъ ѡ҆ веельзевꙋ́лѣ и҆згоню̀ бѣ́сы, сы́нове ва́ши ѡ҆ ко́мъ и҆зго́нѧтъ; сегѡ̀ ра́ди ті́и ва́мъ бꙋ́дꙋтъ сꙋдїѝ. а҆́ще ли же а҆́зъ ѡ҆ дс҃ѣ бж҃їи и҆згоню̀ бѣ́сы, ᲂу҆̀бо пости́же на ва́съ црⷭ҇твїе бж҃їе. и҆лѝ ка́кѡ мо́жетъ кто̀ вни́ти въ до́мъ крѣ́пкагѡ, и҆ сосꙋ́ды є҆гѡ̀ расхи́тити, а҆́ще не пе́рвѣе свѧ́жетъ крѣ́пкаго, и҆ тогда̀ до́мъ є҆гѡ̀ расхи́титъ; и҆́же нѣ́сть со мно́ю, на мѧ̀ є҆́сть: и҆ и҆́же не собира́етъ со мно́ю, расточа́етъ. ",
}

add_evangelie_matfea {
  ["номер"] = 46,
  ["комментарий"] = "Мф., 46 зач., XII, 15-21.",
  ["текст_ру"] = "Во вре́мя о́но, по Иису́се идо́ша наро́ди мно́зи, и исцели́ их всех. И запрети́ им, да не я́ве Его́ творя́т. Я́ко да сбу́дется рече́нное Иса́ием проро́ком, глаго́лющим: се О́трок Мой, Его́же изво́лих, Возлю́бленный Мой, Нань же благоволи́ душа́ Моя́. Положу́ дух Мой на Нем, и суд язы́ком возвести́т, не пререче́т, ни возопие́т, ниже́ услы́шит кто на распу́тиих гла́са Его́. Тро́сти сокруше́нны не прело́мит и ле́на вне́мшася не угаси́т, до́ндеже изведе́т в побе́ду суд. И на и́мя Его́ язы́цы упова́ют. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, по і҆и҃сѣ и҆до́ша наро́ди мно́зи: и҆ и҆сцѣлѝ и҆̀хъ всѣ́хъ. и҆ запретѝ и҆̀мъ, да не ꙗ҆́вѣ є҆го̀ творѧ́тъ. ꙗ҆́кѡ да сбꙋ́детсѧ рече́нное и҆са́їемъ проро́комъ, глаго́лющимъ: сѐ ѻ҆́трокъ мо́й, є҆го́же и҆зво́лихъ: возлю́бленный мо́й, на́нь же благоволѝ дꙋша̀ моѧ̀: положꙋ̀ дꙋ́хъ мо́й на не́мъ, и҆ сꙋ́дъ ꙗ҆зы́кѡмъ возвѣсти́тъ. не пререче́тъ, ни возопїе́тъ, нижѐ ᲂу҆слы́шитъ кто̀ на распꙋ́тїихъ гла́са є҆гѡ̀. тро́сти сокрꙋше́нны не прело́митъ, и҆ ле́на вне́мшасѧ не ᲂу҆гаси́тъ, до́ндеже и҆зведе́тъ въ побѣ́дꙋ сꙋ́дъ. и҆ на и҆́мѧ є҆гѡ̀ ꙗ҆зы́цы ᲂу҆пова́ютъ. ",
}

add_evangelie_matfea {
  ["номер"] = 47,
  ["комментарий"] = "Мф., 47 зач., XII, 30–37.",
  ["текст_ру"] = "Рече́ Госпо́дь: и́же несть со Мно́ю, на Мя есть, и и́же не собира́ет со Мно́ю, расточа́ет. Сего́ ра́ди глаго́лю вам: всяк грех и хула́ отпу́стится челове́ком, а я́же на Ду́ха хула́ не отпу́стится челове́ком. И и́же а́ще рече́т сло́во на Сы́на Челове́ческаго, отпу́стится ему́, а и́же рече́т на Ду́ха Свята́го, не отпу́стится ему́ ни в сий век, ни в бу́дущий. Или́ сотворите́ дре́во добро́ и плод его́ добр, или́ сотворите́ дре́во зло и плод его́ зол, от плода́ бо дре́во позна́но бу́дет. Порожде́ния ехи́днова, ка́ко мо́жете добро́ глаго́лати, зли су́ще? От избы́тка бо се́рдца уста́ глаго́лют. Благи́й челове́к от блага́го сокро́вища изно́сит блага́я, и лука́вый челове́к от лука́ваго сокро́вища изно́сит лука́вая. Глаго́лю же вам, я́ко вся́ко сло́во пра́здное, е́же а́ще реку́т челове́цы, воздадя́т о нем сло́во в день су́дный. От слове́с бо свои́х оправди́шися, и от слове́с свои́х осу́дишися. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: и҆́же нѣ́сть со мно́ю, на мѧ̀ є҆́сть: и҆ и҆́же не собира́етъ со мно́ю, расточа́етъ. сегѡ̀ ра́ди глаго́лю ва́мъ, всѧ́къ грѣ́хъ и҆ хꙋла̀ ѿпꙋ́ститсѧ человѣ́кѡмъ: а҆ ꙗ҆́же на дх҃а хꙋла̀, не ѿпꙋ́ститсѧ человѣ́кѡмъ. и҆ и҆́же а҆́ще рече́тъ сло́во на сн҃а чл҃вѣ́ческаго, ѿпꙋ́ститсѧ є҆мꙋ̀: а҆ и҆́же рече́тъ на дх҃а ст҃а́го, не ѿпꙋ́ститсѧ є҆мꙋ̀, ни въ сі́й вѣ́къ, ни въ бꙋ́дꙋщїй. и҆лѝ сотворитѐ дре́во добро̀ и҆ пло́дъ є҆гѡ̀ до́бръ: и҆лѝ сотворитѐ дре́во ѕло̀, и҆ пло́дъ є҆гѡ̀ ѕо́лъ: ѿ плода́ бо дре́во позна́но бꙋ́детъ. порождє́нїѧ є҆хі́днова, ка́кѡ мо́жете добро̀ глаго́лати, ѕлѝ сꙋ́ще; ѿ и҆збы́тка бо се́рдца ᲂу҆ста̀ глаго́лютъ. благі́й человѣ́къ, ѿ блага́гѡ сокро́вища, и҆зно́ситъ бл҃га̑ѧ: и҆ лꙋка́вый человѣ́къ, ѿ лꙋка́вагѡ сокро́вища, и҆зно́ситъ лꙋка̑ваѧ. глаго́лю же ва́мъ, ꙗ҆́кѡ всѧ́ко сло́во пра́здное, є҆́же а҆́ще рекꙋ́тъ человѣ́цы, воздадѧ́тъ ѡ҆ не́мъ сло́во въ де́нь сꙋ́дный. ѿ слове́съ бо свои́хъ ѡ҆правди́шисѧ, и҆ ѿ слове́съ свои́хъ ѡ҆сꙋ́дишисѧ. ",
}

add_evangelie_matfea {
  ["номер"] = 48,
  ["комментарий"] = "Мф., 48 зач., XII, 38–45.",
  ["текст_ру"] = "Во вре́мя о́но, приступи́ша ко Иису́су не́цыи от кни́жник и фарисе́й, глаго́люще: Учи́телю, хо́щем от Тебе́ зна́мение ви́дети. Он же отвеща́в рече́ им: род лука́в и прелюбоде́й зна́мения и́щет, и зна́мение не да́стся ему́, то́кмо зна́мение Ио́ны проро́ка. Я́коже бо бе Ио́на во чре́ве ки́тове три дни и три но́щи, та́ко бу́дет и Сын Челове́ческий в се́рдцы земли́ три дни и три но́щи. Му́жие Ниневи́тстии воста́нут на суд с ро́дом сим и осу́дят его́, я́ко пока́яшася про́поведию Ио́ниною, и се бо́ле Ио́ны зде. Цари́ца ю́жская воста́нет на суд с ро́дом сим и осу́дит и я́ко прии́де от коне́ц земли́ слы́шати прему́дрость Соломо́нову, и се бо́ле Соломо́на зде. Егда́ же нечи́стый дух изы́дет от челове́ка, прехо́дит сквозе́ безво́дная ме́ста, ищя́ поко́я, и не обрета́ет. Тогда́ рече́т: возвращу́ся в дом мой, отню́дуже изыдо́х. И прише́д обря́щет пра́зден, помете́н и укра́шен. Тогда́ и́дет и по́ймет с собо́ю седмь ины́х духо́в люте́йших себе́, и вше́дше живу́т ту, и бу́дут после́дняя челове́ку тому́ го́рша пе́рвых. Та́ко бу́дет и ро́ду сему́ лука́вому. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋпи́ша ко і҆и҃сꙋ нѣ́цыи ѿ кни̑жникъ и҆ фарїсє́й, глаго́люще: ᲂу҆чи́телю, хо́щемъ ѿ тебѐ зна́менїе ви́дѣти. ѻ҆́нъ же ѿвѣща́въ речѐ и҆̀мъ: ро́дъ лꙋка́въ и҆ прелюбодѣ́й зна́менїѧ и҆́щетъ, и҆ зна́менїе не да́стсѧ є҆мꙋ̀, то́кмѡ зна́менїе і҆ѡ́ны проро́ка. ꙗ҆́коже бо бѣ̀ і҆ѡ́на во чре́вѣ ки́товѣ трѝ днѝ и҆ трѝ нѡ́щи: та́кѡ бꙋ́детъ и҆ сн҃ъ чл҃вѣ́ческїй въ се́рдцы землѝ, трѝ днѝ и҆ трѝ нѡ́щи. мꙋ́жїе нїнеѵі́тстїи воста́нꙋтъ на сꙋ́дъ съ ро́домъ си́мъ, и҆ ѡ҆сꙋ́дѧтъ и҆̀: ꙗ҆́кѡ пока́ѧшасѧ про́повѣдїю і҆ѡ́ниною, и҆ сѐ бо́лѣ і҆ѡ́ны здѣ̀. цари́ца ю҆́жскаѧ воста́нетъ на сꙋ́дъ съ ро́домъ си́мъ, и҆ ѡ҆сꙋ́дитъ и҆̀: ꙗ҆́кѡ прїи́де ѿ конє́цъ землѝ слы́шати премꙋ́дрость соломѡ́новꙋ, и҆ сѐ бо́лѣ соломѡ́на здѣ̀. є҆гда́ же нечи́стый дꙋ́хъ и҆зы́детъ ѿ человѣ́ка, прехо́дитъ сквозѣ̀ безвѡ́днаѧ мѣ́ста, и҆щѧ̀ поко́ѧ, и҆ не ѡ҆брѣта́етъ. тогда̀ рече́тъ: возвращꙋ́сѧ въ до́мъ мо́й, ѿню́дꙋже и҆зыдо́хъ: и҆ прише́дъ ѡ҆брѧ́щетъ пра́зденъ, помете́нъ и҆ ᲂу҆кра́шенъ. тогда̀ и҆́детъ, и҆ по́йметъ съ собо́ю се́дмь и҆ны́хъ дꙋхѡ́въ лютѣ́йшихъ себѐ, и҆ вше́дше живꙋ́тъ тꙋ̀: и҆ бꙋ́дꙋтъ послѣ̑днѧѧ человѣ́кꙋ томꙋ̀ гѡ́рша пе́рвыхъ. та́кѡ бꙋ́детъ и҆ ро́дꙋ семꙋ̀ лꙋка́вомꙋ. ",
}

add_evangelie_matfea {
  ["номер"] = 49,
  ["комментарий"] = "Мф., 49 зач., XII, 46 – XIII, 3.",
  ["текст_ру"] = "Во вре́мя о́но, глаго́лющу Иису́су к наро́дом, се Ма́ти Его́ и бра́тия Его́ стоя́ху вне, и́щуще глаго́лати Ему́. Рече́ же не́кий Ему́: се Ма́ти Твоя́ и бра́тия Твоя́ вне стоя́т, хотя́ще глаго́лати Тебе́. Он же отвеща́в рече́ ко глаго́лющему Ему́: кто есть Ма́ти Моя́, и кто суть бра́тия Моя́? И просте́р ру́ку Свою́ на ученики́ Своя́, рече́: се ма́ти Моя́ и бра́тия Моя́. И́же бо а́ще сотвори́т во́лю Отца́ Моего́, И́же есть на небесе́х, той брат Мой, и сестра́, и ма́ти Ми есть. В день же той изше́д Иису́с из до́му, седя́ше при мо́ри. И собра́шася к Нему́ наро́ди мно́зи, я́коже Ему́ в кора́бль вле́зти и се́сти, и весь наро́д на бре́зе стоя́ше. И глаго́ла им при́тчами мно́го. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, глаго́лющꙋ і҆и҃сꙋ къ наро́дѡмъ, сѐ мт҃и є҆гѡ̀, и҆ бра́тїѧ є҆гѡ̀ стоѧ́хꙋ внѣ̀, и҆́щꙋще глаго́лати є҆мꙋ̀. рече́ же нѣ́кїй є҆мꙋ̀: сѐ мт҃и твоѧ̀, и҆ бра́тїѧ твоѧ̀ внѣ̀ стоѧ́тъ, хотѧ́ще глаго́лати тебѣ̀. ѻ҆́нъ же ѿвѣща́въ речѐ ко глаго́лющемꙋ є҆мꙋ̀: кто́ є҆сть мт҃и моѧ̀; и҆ кто̀ сꙋ́ть бра́тїѧ моѧ̀; и҆ просте́ръ рꙋ́кꙋ свою̀ на ᲂу҆ченикѝ своѧ̀, речѐ: сѐ мт҃и моѧ̀, и҆ бра́тїѧ моѧ̀: и҆́же бо а҆́ще сотвори́тъ во́лю ѻ҆ц҃а̀ моегѡ̀, и҆́же є҆́сть на нб҃сѣ́хъ, то́й бра́тъ мо́й, и҆ сестра̀, и҆ ма́ти мѝ є҆́сть. въ де́нь же то́й и҆зше́дъ і҆и҃съ и҆з̾ до́мꙋ сѣдѧ́ше при мо́ри. и҆ собра́шасѧ къ немꙋ̀ наро́ди мно́зи, ꙗ҆́коже є҆мꙋ̀ въ кора́бль влѣ́зти, и҆ сѣ́сти, и҆ ве́сь наро́дъ на бре́зѣ стоѧ́ше. и҆ глаго́ла и҆̀мъ при́тчами мно́гѡ. ",
}

add_evangelie_matfea {
  ["номер"] = 50,
  ["комментарий"] = "Мф., 50 зач., XIII, 3–9.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: се изы́де се́яй, да се́ет. И се́ющу ему́, о́ва падо́ша при пути́, и приидо́ша пти́цы и позоба́ша я́. Друга́я же падо́ша на ка́менных, иде́же не име́яше земли́ мно́ги, и а́бие прозябо́ша, зане́ не име́яше глубины́ земли́. Со́лнцу же возсия́вшу присвя́нуша, и зане́ не име́яху коре́ния, изсхо́ша. Друга́я же падо́ша в те́рнии, и взы́де те́рние и подави́ их. Друга́я же падо́ша на земли́ до́брей и дая́ху плод, о́во у́бо сто, о́во же шестьдеся́т, о́во же три́десять. Име́яй у́ши слы́шати да слы́шит. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: сѐ и҆зы́де сѣ́ѧй да сѣ́етъ. и҆ сѣ́ющꙋ є҆мꙋ̀, ѻ҆́ва падо́ша при пꙋтѝ: и҆ прїидо́ша пти́цы, и҆ позоба́ша ѧ҆̀. дрꙋга̑ѧ же падо́ша на ка́менныхъ, и҆дѣ́же не и҆мѣ́ѧше землѝ мно́ги: и҆ а҆́бїе прозѧбо́ша, занѐ не и҆мѣ́ѧше глꙋбины̀ землѝ. со́лнцꙋ же возсїѧ́вшꙋ присвѧ́нꙋша, и҆ занѐ не и҆мѣ́ѧхꙋ коре́нїѧ, и҆зсхо́ша. дрꙋга̑ѧ же падо́ша въ те́рнїи, и҆ взы́де те́рнїе, и҆ подавѝ и҆̀хъ. дрꙋга̑ѧ же падо́ша на землѝ до́брѣй, и҆ даѧ́хꙋ пло́дъ: ѻ҆́во ᲂу҆́бѡ сто̀, ѻ҆́во же шестьдесѧ́тъ, ѻ҆́во же три́десѧть. и҆мѣ́ѧй ᲂу҆́ши слы́шати, да слы́шитъ. ",
}

add_evangelie_matfea {
  ["номер"] = 51,
  ["комментарий"] = "Мф., 51 зач., XIII, 10–23.",
  ["текст_ру"] = "Во вре́мя о́но, приступи́вше ко Иису́су ученицы́ Его́, реко́ша: почто́ при́тчами глаго́леши к наро́дом? Он же отвеща́в рече́ им: я́ко вам дано́ есть разуме́ти та́йны Ца́рствия Небе́снаго, о́нем же не дано́ есть. И́же бо и́мать, да́стся ему́ и преизбу́дет ему́, а и́же не и́мать, и е́же и́мать, во́змется от него́. Сего́ ра́ди в при́тчах глаго́лю им, я́ко ви́дяще не ви́дят, и слы́шаще не слы́шат, ни разуме́ют. И сбыва́ется в них проро́чество Иса́иино, глаго́лющее: слу́хом услы́шите, и не и́мате разуме́ти, и зря́ще у́зрите, и не и́мате ви́дети. Отолсте́ бо се́рдце люде́й сих, и уши́ма тя́жко слы́шаша, и о́чи свои́ смежи́ша, да не когда́ у́зрят очи́ма, и уши́ма услы́шат, и се́рдцем уразуме́ют, и обратя́тся, и изцелю́ их. Ва́ша же блаже́нна очеса́, я́ко ви́дят, и у́ши ва́ши, я́ко слы́шат. Ами́нь бо глаго́лю вам, я́ко мно́зи проро́цы и пра́ведницы вожделе́ша ви́дети, я́же ви́дите, и не ви́деша, и слы́шати, я́же слы́шите, и не слы́шаша. Вы же услы́шите при́тчу се́ющаго. Вся́кому слы́шащему сло́во Ца́рствия и не разумева́ющу, прихо́дит лука́вый и восхища́ет все́янное в се́рдце его́, сие́ есть, е́же при пути́ се́янное. А на ка́мени се́янное, сие́ есть слы́шай сло́во и а́бие с ра́достию прие́млет е́, не и́мать же ко́рене в себе́, но привре́менен есть, бы́вши же печа́ли или́ гоне́нию словесе́ ра́ди, а́бие соблажня́ется. А се́янное в те́рнии, се есть слы́шай сло́во, и печа́ль ве́ка сего́ и лесть бога́тства подавля́ет сло́во, и без плода́ быва́ет. А се́янное на до́брей земли́, се есть слы́шай сло́во и разумева́я, и́же у́бо плод прино́сит и твори́т о́во сто, о́во же шестьдеся́т, о́во три́десять. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋпи́вше ко і҆и҃сꙋ ᲂу҆ченицы̀ є҆гѡ̀ реко́ша: почто̀ при́тчами глаго́леши къ наро́дѡмъ; ѻ҆́нъ же ѿвѣща́въ речѐ и҆̀мъ: ꙗ҆́кѡ ва́мъ дано̀ є҆́сть разꙋмѣ́ти та̑йны црⷭ҇твїѧ нбⷭ҇нагѡ: ѻ҆́нѣмъ же не дано̀ є҆́сть. и҆́же бо и҆́мать, да́стсѧ є҆мꙋ̀, и҆ преизбꙋ́детъ є҆мꙋ̀: а҆ и҆́же не и҆́мать, и҆ є҆́же и҆́мать, во́з̾метсѧ ѿ негѡ̀. сегѡ̀ ра́ди въ при́тчахъ глаго́лю и҆̀мъ: ꙗ҆́кѡ ви́дѧще не ви́дѧтъ, и҆ слы́шаще не слы́шатъ, ни разꙋмѣ́ютъ. и҆ сбыва́етсѧ въ ни́хъ проро́чество и҆са́їино, глаго́лющее: слꙋ́хомъ ᲂу҆слы́шите, и҆ не и҆́мате разꙋмѣ́ти: и҆ зрѧ́ще ᲂу҆́зрите, и҆ не и҆́мате ви́дѣти. ѡ҆толстѣ́ бо се́рдце люде́й си́хъ, и҆ ᲂу҆ши́ма тѧ́жкѡ слы́шаша, и҆ ѻ҆́чи своѝ смѣжи́ша, да не когда̀ ᲂу҆́зрѧтъ ѻ҆чи́ма, и҆ ᲂу҆ши́ма ᲂу҆слы́шатъ, и҆ се́рдцемъ ᲂу҆разꙋмѣ́ютъ, и҆ ѡ҆братѧ́тсѧ, и҆ и҆сцѣлю̀ и҆̀хъ. ва́ша же бл҃же́нна ѻ҆чеса̀, ꙗ҆́кѡ ви́дѧтъ: и҆ ᲂу҆́ши ва́ши, ꙗ҆́кѡ слы́шатъ. а҆ми́нь бо глаго́лю ва́мъ, ꙗ҆́кѡ мно́зи проро́цы и҆ пра́ведницы вожделѣ́ша ви́дѣти, ꙗ҆̀же ви́дите, и҆ не ви́дѣша: и҆ слы́шати, ꙗ҆̀же слы́шите, и҆ не слы́шаша. вы́ же ᲂу҆слы́шите при́тчꙋ сѣ́ющагѡ. всѧ́комꙋ слы́шащемꙋ сло́во црⷭ҇твїѧ, и҆ не разꙋмѣва́ющꙋ, прихо́дитъ лꙋка́вый, и҆ восхища́етъ всѣ́ѧнное въ се́рдцѣ є҆гѡ̀: сїѐ є҆́сть, и҆́же при пꙋтѝ сѣ́ѧнное. а҆ на ка́мени сѣ́ѧнное, сїѐ є҆́сть, слы́шай сло́во, и҆ а҆́бїе съ ра́достїю прїе́млетъ є҆̀: не и҆́мать же ко́рене въ себѣ̀, но привре́мененъ є҆́сть, бы́вши же печа́ли и҆лѝ гоне́нїю словесѐ ра́ди, а҆́бїе соблажнѧ́етсѧ. а҆ сѣ́ѧнное въ те́рнїи, сѐ є҆́сть, слы́шай сло́во, и҆ печа́ль вѣ́ка сегѡ̀, и҆ ле́сть бога́тства, подавлѧ́етъ сло́во, и҆ без̾ плода̀ быва́етъ. а҆ сѣ́ѧнное на до́брѣй землѝ, сѐ є҆́сть, слы́шай сло́во и҆ разꙋмѣва́ѧ: и҆́же ᲂу҆́бѡ пло́дъ прино́ситъ, и҆ твори́тъ, ѻ҆́во сто̀, ѻ҆́во же шестьдесѧ́тъ, ѻ҆́во три́десѧть. ",
}

add_evangelie_matfea {
  ["номер"] = 52,
  ["комментарий"] = "Мф., 52 зач., XIII, 24–30.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: уподо́бися Ца́рствие Небе́сное челове́ку, се́явшу до́брое се́мя на селе́ свое́м. Спя́щым же челове́ком, прии́де враг его́ и все́я пле́велы посреде́ пшени́цы и оты́де. Егда́ же прозябе́ трава́ и плод сотвори́, тогда́ яви́шася и пле́велие. Прише́дше же раби́ господи́на, ре́ша ему́: го́споди, не до́брое ли се́мя сеял еси́ на селе́ твое́м? Отку́ду у́бо и́мать пле́велы? Он же рече́ им: враг челове́к сие́ сотвори́. Раби́ же ре́ша ему́: хо́щеши ли у́бо, да ше́дше исплеве́м я́? Он же рече́ им: ни, да не когда́ восторга́юще пле́велы, восто́ргнете ку́пно с ни́ми и пшени́цу. Оста́вите расти́ обое́ ку́пно до жа́твы, и во вре́мя жа́твы реку́ жа́телем: собери́те пе́рвее пле́велы и свяжи́те их в снопы́, я́ко сожещи́ я́, а пшени́цу собери́те в жи́тницу мою́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: ᲂу҆подо́бисѧ црⷭ҇твїе нбⷭ҇ное человѣ́кꙋ сѣ́ѧвшꙋ до́брое сѣ́мѧ на селѣ̀ свое́мъ. спѧ́щымъ же человѣ́кѡмъ, прїи́де вра́гъ є҆гѡ̀, и҆ всѣ́ѧ пле́велы посредѣ̀ пшени́цы, и҆ ѿи́де. є҆гда́ же прозѧбѐ трава̀, и҆ пло́дъ сотворѝ, тогда̀ ꙗ҆ви́шасѧ и҆ пле́велїе. прише́дше же рабѝ гдⷭ҇и́на, рѣ́ша є҆мꙋ̀: гдⷭ҇и, не до́брое ли сѣ́мѧ сѣ́ѧлъ є҆сѝ на селѣ̀ твое́мъ; ѿкꙋ́дꙋ ᲂу҆́бѡ и҆́мать пле́велы; ѻ҆́нъ же речѐ и҆̀мъ: вра́гъ человѣ́къ сїѐ сотворѝ. раби́ же рѣ́ша є҆мꙋ̀: хо́щеши ли ᲂу҆̀бо, да ше́дше и҆сплеве́мъ ѧ҆̀; ѻ҆́нъ же речѐ и҆̀мъ: нѝ, да не когда̀ восторга́юще пле́велы, восто́ргнете кꙋ́пнѡ съ ни́ми и҆ пшени́цꙋ. ѡ҆ста́вите растѝ ѻ҆боѐ кꙋ́пнѡ до жа́твы: и҆ во вре́мѧ жа́твы рекꙋ̀ жа́телємъ: собери́те пе́рвѣе пле́велы, и҆ свѧжи́те и҆̀хъ въ снопы̀, ꙗ҆́кѡ сожещѝ ѧ҆̀, а҆ пшени́цꙋ собери́те въ жи́тницꙋ мою̀. ",
}

add_evangelie_matfea {
  ["номер"] = 52,
  ["комментарий"] = "Мф., 52 зач., XIII, 24–30, 36-43.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: уподо́бися Ца́рствие Небе́сное челове́ку, се́явшу до́брое се́мя на селе́ свое́м. Спя́щым же челове́ком, прии́де враг его́ и все́я пле́велы посреде́ пшени́цы и оты́де. Егда́ же прозябе́ трава́ и плод сотвори́, тогда́ яви́шася и пле́велие. Прише́дше же раби́ господи́на, ре́ша ему́: го́споди, не до́брое ли се́мя се́ял еси́ на селе́ твое́м? Отку́ду у́бо и́мать пле́велы? Он же рече́ им: враг челове́к сие́ сотвори́. Раби́ же ре́ша ему́: хо́щеши ли у́бо, да ше́дше исплеве́м я́? Он же рече́ им: ни, да не когда́ восторга́юще пле́велы, восто́ргнете ку́пно с ни́ми и пшени́цу. Оста́вите расти́ обое́ ку́пно до жа́твы, и во вре́мя жа́твы реку́ жа́телем: собери́те пе́рвее пле́велы и свяжи́те их в снопы́, я́ко сожещи́ я́, а пшени́цу собери́те в жи́тницу мою́. И приступи́ша к Нему́ ученицы́ Его́, глаго́люще: скажи́ нам при́тчу пле́вел се́льных. Он же отвеща́в рече́ им: се́явый до́брое се́мя есть Сын Челове́ческий, а село́ есть мир. До́брое же се́мя, си́и суть сы́нове Ца́рствия, а пле́велие суть сы́нове неприя́зненнии, а враг все́явый их есть диа́вол, а жа́тва кончи́на ве́ка есть, а жа́тели А́нгели суть. Я́коже у́бо собира́ют пле́велы и огне́м сожига́ют, та́ко бу́дет в сконча́ние ве́ка сего́. По́слет Сын Челове́ческий А́нгелы Своя́, и соберу́т от Ца́рствия Его́ вся собла́зны и творя́щия беззако́ние и вве́ргут их в пещь о́гненну, ту бу́дет плачь и скре́жет зубо́м. Тогда́ пра́ведницы просветя́тся я́ко со́лнце в Ца́рствии Отца́ их. Име́яй у́ши слы́шати да слы́шит. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: ᲂу҆подо́бисѧ црⷭ҇твїе нбⷭ҇ное человѣ́кꙋ сѣ́ѧвшꙋ до́брое сѣ́мѧ на селѣ̀ свое́мъ. спѧ́щымъ же человѣ́кѡмъ, прїи́де вра́гъ є҆гѡ̀, и҆ всѣ́ѧ пле́велы посредѣ̀ пшени́цы, и҆ ѿи́де. є҆гда́ же прозѧбѐ трава̀, и҆ пло́дъ сотворѝ, тогда̀ ꙗ҆ви́шасѧ и҆ пле́велїе. прише́дше же рабѝ гдⷭ҇и́на, рѣ́ша є҆мꙋ̀: гдⷭ҇и, не до́брое ли сѣ́мѧ сѣ́ѧлъ є҆сѝ на селѣ̀ твое́мъ; ѿкꙋ́дꙋ ᲂу҆́бѡ и҆́мать пле́велы; ѻ҆́нъ же речѐ и҆̀мъ: вра́гъ человѣ́къ сїѐ сотворѝ. раби́ же рѣ́ша є҆мꙋ̀: хо́щеши ли ᲂу҆̀бо, да ше́дше и҆сплеве́мъ ѧ҆̀; ѻ҆́нъ же речѐ и҆̀мъ: нѝ, да не когда̀ восторга́юще пле́велы, восто́ргнете кꙋ́пнѡ съ ни́ми и҆ пшени́цꙋ. ѡ҆ста́вите растѝ ѻ҆боѐ кꙋ́пнѡ до жа́твы: и҆ во вре́мѧ жа́твы рекꙋ̀ жа́телємъ: собери́те пе́рвѣе пле́велы, и҆ свѧжи́те и҆̀хъ въ снопы̀, ꙗ҆́кѡ сожещѝ ѧ҆̀, а҆ пшени́цꙋ собери́те въ жи́тницꙋ мою̀. и҆ пристꙋпи́ша къ немꙋ̀ ᲂу҆ч҃нцы̀ є҆гѡ̀, глаго́люще: скажѝ на́мъ при́тчꙋ пле́вєлъ се́льныхъ. ѻ҆́нъ же ѿвѣща́въ речѐ и҆̀мъ: сѣ́ѧвый до́брое сѣ́мѧ, є҆́сть сн҃ъ человѣ́ческїй: а҆ село̀, є҆́сть мі́ръ. до́брое же сѣ́мѧ, сі́и сꙋ́ть сы́нове црⷭ҇твїѧ: а҆ пле́велы, сꙋ́ть сы́нове непрїѧ́зненнїи, а҆ вра́гъ всѣ́ѧвый и҆̀хъ, є҆́сть дїа́волъ. а҆ жа́тва, кончи́на вѣ́ка є҆́сть: а҆ жа́тели, а҆́гг҃ли сꙋ́ть. ꙗ҆́коже ᲂу҆́бѡ собира́ютъ пле́велы, и҆ ѻ҆гне́мъ сожига́ютъ, та́кѡ бꙋ́детъ въ сконча́нїе вѣ́ка сегѡ̀. по́слетъ сн҃ъ человѣ́ческїй а҆́гг҃лы своѧ̀, и҆ соберꙋ́тъ ѿ црⷭ҇твїѧ є҆гѡ̀ всѧ̀ собла́зны, и҆ творѧ́щыѧ беззако́нїе: и҆ вве́ргꙋтъ и҆̀хъ въ пе́щь ѻ҆́гненнꙋ: тꙋ̀ бꙋ́детъ пла́чь и҆ скре́жетъ зꙋбѡ́мъ. тогда̀ пра́вєдницы просвѣтѧ́тсѧ ꙗ҆́кѡ со́лнце въ црⷭ҇твїи ѻ҆ц҃а̀ и҆́хъ. и҆мѣ́ѧй ᲂу҆́ши слы́шати, да слы́шитъ. ",
}

add_evangelie_matfea {
  ["номер"] = 53,
  ["комментарий"] = "Мф., 53 зач., XIII, 31–36.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: подо́бно есть Ца́рствие Небе́сное зе́рну гору́шичну, е́же взем челове́к все́я на селе́ свое́м. Е́же ма́лейше у́бо есть от всех се́мен, егда́ же возрасте́т, бо́лее всех зе́лий есть и быва́ет дре́во, я́ко приити́ пти́цам небе́сным и вита́ти на ве́твех его́. И́ну при́тчу глаго́ла им: подо́бно есть Ца́рствие Небе́сное ква́су, и́же взе́мши жена́ скры в мучны́х са́тех три, до́ндеже вскисо́ша вся. Сия́ вся глаго́ла Иису́с в при́тчах наро́дом, и без при́тчи ничесо́же глаго́лаше к ним. Я́ко да сбу́дется рече́нное проро́ком, глаго́лющим: отве́рзу в при́тчах уста́ Моя́, отры́гну сокрове́нная от сложе́ния ми́ра. Тогда́ оста́вль наро́ды, прии́де в дом Иису́с. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: подо́бно є҆́сть црⷭ҇твїе нбⷭ҇ное зе́рнꙋ горꙋ́шичнꙋ, є҆́же взе́мъ человѣ́къ всѣ́ѧ на селѣ̀ свое́мъ. є҆́же ма́лѣйше ᲂу҆́бѡ є҆́сть ѿ всѣ́хъ сѣ́менъ: є҆гда́ же возрасте́тъ, бо́лѣе всѣ́хъ ѕе́лїй є҆́сть, и҆ быва́етъ дре́во: ꙗ҆́кѡ прїитѝ пти́цамъ нбⷭ҇нымъ, и҆ вита́ти на вѣ́твехъ є҆гѡ̀. и҆́нꙋ при́тчꙋ глаго́ла и҆̀мъ: подо́бно є҆́сть црⷭ҇твїе нбⷭ҇ное ква́сꙋ, и҆́же взе́мши жена̀ скры̀ въ мꙋчны́хъ са́тѣхъ трѝ, до́ндеже вскисо́ша всѧ̑. сїѧ̑ всѧ̑ глаго́ла і҆и҃съ въ при́тчахъ наро́дѡмъ, и҆ без̾ при́тчи ничесо́же глаго́лаше къ ни́мъ. ꙗ҆́кѡ да сбꙋ́детсѧ рече́нное проро́комъ глаго́лющимъ: ѿве́рзꙋ въ при́тчахъ ᲂу҆ста̀ моѧ̀, ѿры́гнꙋ сокровє́ннаѧ ѿ сложе́нїѧ мі́ра. тогда̀ ѡ҆ста́вль наро́ды, прїи́де въ до́мъ і҆и҃съ. ",
}

