add_evangelie_matfea {
  ["номер"] = 55,
  ["комментарий"] = "Мф., 55 зач., XIII, 44–54.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: подо́бно есть Ца́рствие Небе́сное сокро́вищу сокрове́ну на селе́, е́же обре́т челове́к скры, и от ра́дости его́ и́дет, и вся, ели́ка и́мать, продае́т, и купу́ет село́ то. Па́ки подо́бно есть Ца́рствие Небе́сное челове́ку купцу́, и́щущу до́брыя би́серы, и́же обре́т еди́н многоце́нен би́сер, шед продаде́ вся, ели́ка имя́ше, и купи́ его́. Па́ки подо́бно есть Ца́рствие Небе́сное не́воду вве́ржену в мо́ре и от вся́каго ро́да собра́вшу, и́же егда́ испо́лнися, извлеко́ша и на край, и се́дше избра́ша до́брыя в сосу́ды, а злы́я изверго́ша вон. Та́ко бу́дет в сконча́ние ве́ка: изы́дут А́нгели, и отлуча́т злы́я от среды́ пра́ведных, и вве́ргут их в пещь о́гненную, ту бу́дет плачь и скре́жет зубо́м. Глаго́ла им Иису́с: разуме́сте ли сия́ вся? Глаго́лаша Ему́: ей, Го́споди. Он же рече́ им: сего́ ра́ди всяк кни́жник, научи́вся Ца́рствию Небе́сному, подо́бен есть челове́ку домови́ту, и́же изно́сит от сокро́вища своего́ но́вая и ве́тхая. И бысть, егда́ сконча́ Иису́с при́тчи сия́, пре́йде отту́ду. И прише́д во оте́чествие Свое́, уча́ше их на со́нмищи их. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: подо́бно є҆́сть црⷭ҇твїе нбⷭ҇ное сокро́вищꙋ сокрове́нꙋ на селѣ̀, є҆́же ѡ҆брѣ́тъ человѣ́къ скры̀. и҆ ѿ ра́дости є҆гѡ̀ и҆́детъ и҆ всѧ̑, є҆ли̑ка и҆́мать, продае́тъ, и҆ кꙋпꙋ́етъ село̀ то̀. па́ки подо́бно є҆́сть црⷭ҇твїе нбⷭ҇ное человѣ́кꙋ кꙋпцꙋ̀, и҆́щꙋщꙋ дѡ́брыѧ би́серы: и҆́же ѡ҆брѣ́тъ є҆ди́нъ многоцѣ́ненъ би́серъ, ше́дъ продадѐ всѧ̑, є҆ли̑ка и҆мѧ́ше, и҆ кꙋпѝ є҆го̀. па́ки подо́бно є҆́сть црⷭ҇твїе нбⷭ҇ное не́водꙋ вве́рженꙋ въ мо́ре, и҆ ѿ всѧ́кагѡ ро́да собра́вшꙋ: и҆́же є҆гда̀ и҆спо́лнисѧ, и҆звлеко́ша и҆ на кра́й, и҆ сѣ́дше и҆збра́ша дѡ́брыѧ въ сосꙋ́ды, а҆ ѕлы̑ѧ и҆зверго́ша во́нъ. та́кѡ бꙋ́детъ въ сконча́нїе вѣ́ка: и҆зы́дꙋтъ а҆́гг҃ли, и҆ ѿлꙋча́тъ ѕлы̑ѧ ѿ среды̀ пра́ведныхъ: и҆ вве́ргꙋтъ и҆̀хъ въ пе́щь ѻ҆́гненнꙋю, тꙋ̀ бꙋ́детъ пла́чь и҆ скре́жетъ зꙋбѡ́мъ. глаго́ла и҆̀мъ і҆и҃съ: разꙋмѣ́сте ли сїѧ̑ всѧ̑; глаго́лаша є҆мꙋ̀: є҆́й гдⷭ҇и. ѻ҆́нъ же речѐ и҆̀мъ: сегѡ̀ ра́ди всѧ́къ кни́жникъ, наꙋчи́всѧ црⷭ҇твїю нбⷭ҇номꙋ, подо́бенъ є҆́сть человѣ́кꙋ домови́тꙋ, и҆́же и҆зно́ситъ ѿ сокро́вища своегѡ̀ нѡ́ваѧ и҆ вє́тхаѧ. и҆ бы́сть, є҆гда̀ сконча̀ і҆и҃съ при̑тчи сїѧ̑, пре́йде ѿтꙋ́дꙋ. и҆ прише́дъ во ѻ҆те́чествїе своѐ, ᲂу҆ча́ше и҆̀хъ на со́нмищи и҆́хъ. ",
}

add_evangelie_matfea {
  ["номер"] = 56,
  ["комментарий"] = "Мф., 56 зач., XIII, 54–58.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с во оте́чествие Свое́, и уча́ше наро́ды на со́нмищи их, я́ко диви́тися им и глаго́лати: отку́ду Сему́ прему́дрость сия́ и си́лы? Не Сей ли есть текто́нов сын? Не Ма́ти ли Его́ нарица́ется Мариа́м, и бра́тия Его́ Иа́ков и Иоси́й, и Си́мон и Иу́да? И сестры́ Его́ не вся ли в нас суть? Отку́ду у́бо Сему́ сия́ вся? И блажня́хуся о Нем. Иису́с же рече́ им: несть проро́к без че́сти, то́кмо во оте́чествии свое́м и в дому́ свое́м. И не сотвори́ ту сил мно́ги за неве́рство их. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ во ѻ҆ч҃ествїе своѐ, и҆ ᲂу҆ча́ше наро́ды на со́нмищи и҆́хъ, ꙗ҆́кѡ диви́тисѧ и҆̀мъ, и҆ глаго́лати: ѿкꙋ́дꙋ семꙋ̀ премꙋ́дрость сїѧ̀, и҆ си̑лы; не се́й ли є҆́сть текто́новъ сн҃ъ; не мт҃и ли є҆гѡ̀ нарица́етсѧ марїа́мъ, и҆ бра́тїѧ є҆гѡ̀, і҆а́кѡвъ, и҆ і҆ѡсі́й, и҆ сі́мѡнъ, и҆ і҆ꙋ́да; и҆ сєстры̀ є҆гѡ̀ не всѧ́ ли въ на́съ сꙋ́ть; ѿкꙋ́дꙋ ᲂу҆́бѡ семꙋ̀ сїѧ̑ всѧ̑; и҆ блажнѧ́хꙋсѧ ѡ҆ не́мъ. і҆и҃съ же речѐ и҆̀мъ: нѣ́сть проро́къ без̾ че́сти то́кмѡ во ѻ҆ч҃ествїи свое́мъ, и҆ въ домꙋ̀ свое́мъ: и҆ не сотворѝ тꙋ̀ си́лы мнѡ́ги, за невѣ́рство и҆́хъ. ",
}

add_evangelie_matfea {
  ["номер"] = 57,
  ["комментарий"] = "Мф., 57 зач., XIV, 1–13.",
  ["текст_ру"] = "Во вре́мя о́но, услы́шав И́род четвертовла́стник слух Иису́сов, рече́ отроко́м свои́м: Сей есть Иоа́нн Крести́тель, той воскре́се от ме́ртвых, и сего́ ра́ди си́лы де́ются о нем. И́род бо есмь Иоа́нна, связа́ его́, и всади́ в темни́цу, Иродиа́ды ра́ди жены́ Фили́ппа бра́та своего́. Глаго́лаше бо ему́ Иоа́нн: не досто́ит ти име́ти ея́. И хотя́ше его́ уби́ти, убоя́ся наро́да, зане́ я́ко проро́ка его́ име́яху. Дни же бы́вшу рождества́ И́родова, пляса́ дщи Иродиа́дина посреде́, и угоди́ И́родови. Те́мже и с кля́твою изрече́ ей да́ти, его́же а́ще воспро́сит. Она́ же нава́ждена ма́терию свое́ю, даждь ми, рече́, зде на блю́де главу́ Иоа́нна Крести́теля. И печа́лен бысть царь, кля́твы же ра́ди, и за возлежа́щих с ним, повеле́ да́ти ей. И посла́в усе́кну Иоа́нна в темни́це. И принесо́ша главу́ его́ на блю́де, и да́ша деви́це, и отнесе́ ма́тери свое́й. И присту́пльше ученицы́ его́, взя́ша те́ло его́, и погребо́ша е́, и прише́дше возвести́ша Иису́сови. И слы́шав Иису́с оты́де отту́ду в корабли́, в пу́сто ме́сто еди́н. И слы́шавше наро́ди, по Нем идо́ша пе́ши от градо́в. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ᲂу҆слы́шавъ и҆́рѡдъ четвертовла́стникъ слꙋ́хъ і҆и҃совъ, речѐ ѻ҆трокѡ́мъ свои́мъ: се́й є҆́сть і҆ѡа́ннъ крⷭ҇ти́тель, то́й воскре́се ѿ ме́ртвыхъ, и҆ сегѡ̀ ра́ди си̑лы дѣ́ютсѧ ѡ҆ не́мъ. и҆́рѡдъ бо є҆́мъ і҆ѡа́нна, свѧза̀ є҆го̀, и҆ всадѝ въ темни́цꙋ, и҆рѡдїа́ды ра́ди жены̀ фїлі́ппа бра́та своегѡ̀. глаго́лаше бо є҆мꙋ̀ і҆ѡа́ннъ: не досто́итъ тѝ и҆мѣ́ти є҆ѧ̀. и҆ хотѧ́ше є҆го̀ ᲂу҆би́ти, ᲂу҆боѧ́сѧ наро́да: занѐ ꙗ҆́кѡ проро́ка є҆го̀ и҆мѣ́ѧхꙋ. дни́ же бы́вшꙋ рождества̀ и҆́рѡдова, плѧса̀ дщѝ и҆рѡдїа́дина посредѣ̀, и҆ ᲂу҆годѝ и҆́рѡдови. тѣ́мже и҆ съ клѧ́твою и҆зречѐ є҆́й да́ти, є҆гѡ́же а҆́ще воспро́ситъ. ѻ҆на́ же нава́ждена ма́терїю свое́ю, да́ждь мѝ, речѐ, здѣ̀ на блю́дѣ главꙋ̀ і҆ѡа́нна крести́телѧ. и҆ печа́ленъ бы́сть ца́рь: клѧ́твы же ра́ди, и҆ за возлежа́щихъ съ ни́мъ, повелѣ̀ да́ти є҆́й. и҆ посла́въ ᲂу҆сѣ́кнꙋ і҆ѡа́нна въ темни́цѣ. и҆ принесо́ша главꙋ̀ є҆гѡ̀ на блю́дѣ, и҆ да́ша дѣви́цѣ: и҆ ѿнесѐ ма́тери свое́й. и҆ пристꙋ́пльше ᲂу҆ченицы̀ є҆гѡ̀, взѧ́ша тѣ́ло є҆гѡ̀, и҆ погребо́ша є҆̀: и҆ прише́дше возвѣсти́ша і҆и҃сови. и҆ слы́шавъ і҆и҃съ, ѿи́де ѿтꙋ́дꙋ въ кораблѝ, въ пꙋ́сто мѣ́сто є҆ди́нъ. и҆ слы́шавше наро́ди, по не́мъ и҆до́ша пѣ́ши ѿ градѡ́въ. ",
}

add_evangelie_matfea {
  ["номер"] = 58,
  ["комментарий"] = "Мф., 58 зач., XIV, 14–22.",
  ["текст_ру"] = "Во вре́мя о́но, ви́де Иису́с мног наро́д, и милосе́рдова о них, и исцели́ неду́жныя их. По́зде же бы́вшу, приступи́ша к Нему́ ученицы́ Его́, глаго́люще: пу́сто есть ме́сто, и час уже́ мину́, отпусти́ наро́ды, да ше́дше в ве́си ку́пят бра́шна себе́. Иису́с же рече́ им: не тре́буют отити́, дади́те им вы я́сти. Они́ же глаго́лаша Ему́: не и́мамы зде то́кмо пять хлеб и две ры́бе. Он же рече́: принеси́те Ми их се́мо. И повеле́в наро́дом возлещи́ на траве́, и прие́м пять хлеб и о́бе ры́бе, воззре́в на не́бо, благослови́ и преломи́в даде́ ученико́м хле́бы, ученицы́ же наро́дом. И ядо́ша вси и насы́тишася, и взя́ша избы́тки укру́х, двана́десять ко́шя испо́лнь. Яду́щих же бе муже́й я́ко пять ты́сящ, ра́зве жен и дете́й. И а́бие пону́ди Иису́с ученики́ Своя́ вле́зти в кора́бль и вари́ти Его́ на о́ном полу́, до́ндеже отпу́стит наро́ды. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ви́дѣ і҆и҃съ мно́гъ наро́дъ, и҆ милосе́рдова ѡ҆ ни́хъ, и҆ и҆сцѣлѝ недꙋ̑жныѧ и҆́хъ. по́здѣ же бы́вшꙋ, пристꙋпи́ша къ немꙋ̀ ᲂу҆ченицы̀ є҆гѡ̀, глаго́люще: пꙋ́сто є҆́сть мѣ́сто, и҆ ча́съ ᲂу҆жѐ минꙋ̀: ѿпꙋстѝ наро́ды, да ше́дше въ вє́си, кꙋ́пѧтъ бра̑шна себѣ̀. і҆и҃съ же речѐ и҆̀мъ: не тре́бꙋютъ ѿитѝ, дади́те и҆̀мъ вы̀ ꙗ҆́сти. ѻ҆ни́ же глаго́лаша є҆мꙋ̀: не и҆́мамы здѣ̀ то́кмѡ пѧ́ть хлѣ̑бъ и҆ двѣ̀ ры́бѣ. ѻ҆́нъ же речѐ: принеси́те мѝ и҆̀хъ сѣ́мѡ. и҆ повелѣ́въ наро́дѡмъ возлещѝ на травѣ̀, и҆ прїе́мъ пѧ́ть хлѣ̑бъ и҆ ѻ҆́бѣ ры́бѣ, воззрѣ́въ на нб҃о, бл҃гословѝ: и҆ преломи́въ дадѐ ᲂу҆ченикѡ́мъ хлѣ́бы, ᲂу҆ченицы́ же наро́дѡмъ. и҆ ꙗ҆до́ша всѝ, и҆ насы́тишасѧ: и҆ взѧ́ша и҆збы́тки ᲂу҆крꙋ̑хъ, двана́десѧть ко́шѧ и҆спо́лнь. ꙗ҆дꙋ́щихъ же бѣ̀ мꙋже́й ꙗ҆́кѡ пѧ́ть ты́сѧщъ, ра́звѣ же́нъ и҆ дѣте́й. и҆ а҆́бїе понꙋ́ди і҆и҃съ ᲂу҆ченикѝ своѧ̀ влѣ́зти въ кора́бль, и҆ вари́ти є҆го̀ на ѻ҆́номъ полꙋ̀, до́ндеже ѿпꙋ́ститъ наро́ды. ",
}

add_evangelie_matfea {
  ["номер"] = 59,
  ["комментарий"] = "Мф., 59 зач., XIV, 22–34.",
  ["текст_ру"] = "Во вре́мя о́но, пону́ди Иису́с ученики́ Своя́ вле́зти в кора́бль и вари́ти Его́ на о́ном полу́, до́ндеже отпу́стит наро́ды. И отпусти́в наро́ды, взы́де на гору́ еди́н помоли́тися. По́зде же бы́вшу, еди́н бе ту. Кора́бль же бе посреде́ мо́ря вла́яся волна́ми, бе бо проти́вен ветр. В четве́ртую же стра́жу но́щи и́де к ним Иису́с, ходя́ по мо́рю. И ви́девше Его́ ученицы́ по мо́рю ходя́ща, смути́шася, глаго́люще, я́ко призра́к есть, и от стра́ха возопи́ша. А́бие же рече́ им Иису́с, глаго́ля: дерза́йте, Аз есмь, не бо́йтеся. Отвеща́в же Петр рече́: Го́споди, а́ще Ты еси́, повели́ ми приити́ к Тебе́ по вода́м. Он же рече́: прииди́. И изле́з из корабля́ Петр, хожда́ше по вода́м, приити́ ко Иису́сови. Ви́дя же ветр кре́пок, убоя́ся, и наче́н утопа́ти, возопи́, глаго́ля: Го́споди, спаси́ мя. И а́бие Иису́с просте́р ру́ку, ят его́ и глаго́ла ему́: малове́ре, почто́ усумне́лся еси́? И вле́зшема и́ма в кора́бль, преста́ ветр. Су́щии же в корабли́ прише́дше поклони́шася Ему́, глаго́люще: вои́стинну Бо́жий Сын еси́. И преше́дше приидо́ша в зе́млю Геннисаре́фскую. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, понꙋ́ди і҆и҃съ ᲂу҆ченикѝ своѧ̀ влѣ́зти въ кора́бль, и҆ вари́ти є҆го̀ на ѻ҆́номъ полꙋ̀, до́ндеже ѿпꙋ́ститъ наро́ды. и҆ ѿпꙋсти́въ наро́ды, взы́де на горꙋ̀ є҆ди́нъ помоли́тисѧ. по́здѣ же бы́вшꙋ, є҆ди́нъ бѣ̀ тꙋ̀. кора́бль же бѣ̀ посредѣ̀ мо́рѧ, вла́ѧсѧ волна́ми: бѣ́ бо проти́венъ вѣ́тръ. въ четве́ртꙋю же стра́жꙋ но́щи, и҆́де къ ни́мъ і҆и҃съ, ходѧ̀ по мо́рю. и҆ ви́дѣвше є҆го̀ ᲂу҆ченицы̀ по мо́рю ходѧ́ща, смꙋти́шасѧ, глаго́люще, ꙗ҆́кѡ призра́къ є҆́сть: и҆ ѿ стра́ха возопи́ша. а҆́бїе же речѐ и҆̀мъ і҆и҃съ, глаго́лѧ: дерза́йте, а҆́зъ є҆́смь, не бо́йтесѧ. ѿвѣща́въ же пе́тръ речѐ: гдⷭ҇и, а҆́ще ты̀ є҆сѝ, повели́ ми прїитѝ къ тебѣ̀ по вода́мъ. ѻ҆́нъ же речѐ: прїидѝ. и҆ и҆злѣ́зъ и҆з̾ кораблѧ̀ пе́тръ, хожда́ше по вода́мъ, прїитѝ ко і҆и҃сови. ви́дѧ же вѣ́тръ крѣ́покъ, ᲂу҆боѧ́сѧ, и҆ наче́нъ ᲂу҆топа́ти, возопѝ, глаго́лѧ: гдⷭ҇и, спаси́ мѧ. и҆ а҆́бїе і҆и҃съ просте́ръ рꙋ́кꙋ, ꙗ҆́тъ є҆го̀, и҆ глаго́ла є҆мꙋ̀: маловѣ́ре, почто̀ ᲂу҆сꙋмнѣ́лсѧ є҆сѝ; и҆ влѣ́зшема и҆́ма въ кора́бль, преста̀ вѣ́тръ. сꙋ́щїи же въ кораблѝ, прише́дше поклони́шасѧ є҆мꙋ̀, глаго́люще: вои́стиннꙋ бж҃їй сн҃ъ є҆сѝ. и҆ преше́дше прїидо́ша въ зе́млю геннисаре́ѳскꙋю. ",
}

add_evangelie_matfea {
  ["номер"] = 60,
  ["комментарий"] = "Мф., 60 зач., XIV, 35 – XV, 11.",
  ["текст_ру"] = "Во вре́мя о́но, позна́вше Иису́са му́жие земли́ Геннисаре́фски, посла́ша во всю страну́ ту, и принесо́ша к Нему́ вся боля́щия. И моля́ху Его́, да то́кмо прико́снутся вскри́лию ри́зы Его́, и ели́цы прикосну́шася, спасе́ни бы́ша. Тогда́ приступи́ша ко Иису́сови и́же от Иерусали́ма кни́жницы и фарисе́е, глаго́люще: почто́ ученицы́ Твои́ преступа́ют преда́ние ста́рец? Не умыва́ют бо рук свои́х, егда́ хлеб ядя́т. Он же отвеща́в рече́ им: почто́ и вы преступа́ете за́поведь Бо́жию за преда́ние ва́ше? Бог бо запове́да, глаго́ля: чти отца́ и ма́терь, и и́же злосло́вит отца́ или́ ма́терь, сме́ртию да у́мрет. Вы же глаго́лете: и́же а́ще рече́т отцу́ или́ ма́тери: дар, е́же а́ще от мене́ по́льзовался еси́. И да не почти́т отца́ своего́ или́ ма́тере. И разори́сте за́поведь Бо́жию за преда́ние ва́ше. Лицеме́ри, до́бре проро́чествова о вас Иса́иа, глаго́ля: приближа́ются Мне лю́дие си́и усты́ свои́ми и устна́ми чтут Мя, се́рдце же их дале́че отстои́т от Мене́. Всу́е же чтут Мя, уча́ще уче́нием, за́поведем челове́ческим. И призва́в наро́ды, рече́ им: слы́шите и разуме́йте, не входя́щее во уста́ скверни́т челове́ка, но исходя́щее изоу́ст, то скверни́т челове́ка. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, позна́вше і҆и҃са мꙋ́жїе землѝ геннисаре́ѳски, посла́ша во всю̀ странꙋ̀ тꙋ̀: и҆ принесо́ша къ немꙋ̀ всѧ̑ болѧ́щыѧ. и҆ молѧ́хꙋ є҆го̀, да то́кмѡ прико́снꙋтсѧ вскри́лїю ри́зы є҆гѡ̀: и҆ є҆ли́цы прикоснꙋ́шасѧ, спасе́ни бы́ша. тогда̀ пристꙋпи́ша ко і҆и҃сови, и҆̀же ѿ і҆ерꙋсали́ма кни́жницы и҆ фарїсе́є, глаго́люще: почто̀ ᲂу҆ченицы̀ твоѝ престꙋпа́ютъ преда́нїе ста́рєцъ; не ᲂу҆мыва́ютъ бо рꙋ́къ свои́хъ, є҆гда̀ хлѣ́бъ ꙗ҆дѧ́тъ. ѻ҆́нъ же ѿвѣща́въ речѐ и҆̀мъ: почто̀ и҆ вы̀ престꙋпа́ете за́повѣдь бж҃їю за преда́нїе ва́ше; бг҃ъ бо заповѣ́да, глаго́лѧ: чтѝ ѻ҆тца̀ и҆ ма́терь: и҆ и҆́же ѕлосло́витъ ѻ҆тца̀ и҆лѝ ма́терь, сме́ртїю да ᲂу҆́мретъ. вы́ же глаго́лете: и҆́же а҆́ще рече́тъ ѻ҆тцꙋ̀, и҆лѝ ма́тери: да́ръ, є҆́же а҆́ще ѿ менѐ по́льзовалсѧ є҆сѝ. и҆ да не почти́тъ ѻ҆тца̀ своегѡ̀, и҆лѝ ма́тере: и҆ разори́сте за́повѣдь бж҃їю за преда́нїе ва́ше. лицемѣ́ри, до́брѣ проро́чествова ѡ҆ ва́съ и҆са́їа, глаго́лѧ: приближа́ютсѧ мнѣ̀ лю́дїе сі́и ᲂу҆сты̀ свои́ми, и҆ ᲂу҆стна́ми чтꙋ́тъ мѧ̀: се́рдце же и҆́хъ дале́че ѿстои́тъ ѿ менѐ. всꙋ́е же чтꙋ́тъ мѧ̀, ᲂу҆ча́ще ᲂу҆че́нїємъ, за́повѣдемъ человѣ́ческимъ. и҆ призва́въ наро́ды, речѐ и҆̀мъ: слы́шите, и҆ разꙋмѣ́йте: не входѧ́щее во ᲂу҆ста̀ скверни́тъ человѣ́ка: но и҆сходѧ́щее и҆зоꙋ́стъ, то̀ скверни́тъ человѣ́ка. ",
}

add_evangelie_matfea {
  ["номер"] = 61,
  ["комментарий"] = "Мф., 61 зач., XV, 12–21.",
  ["текст_ру"] = "Во вре́мя о́но, присту́пльше ко Иису́су ученицы́ Его́, ре́ша Ему́: ве́си ли, я́ко фарисе́е слы́шавше сло́во соблазни́шася? Он же отвеща́в рече́: всяк сад, его́же не насади́ Оте́ц Мой Небе́сный, искорени́тся. Оста́вите их, вожди́ суть сле́пи слепце́м, слепе́ц же слепца́ а́ще во́дит, о́ба в я́му впаде́тася. Отвеща́в же Петр рече́ Ему́: скажи́ нам при́тчу сию́. Иису́с же рече́ им: едина́че ли и вы без ра́зума есте́? Не у ли разумева́ете, я́ко вся́ко, е́же вхо́дит во уста́, во чре́во вмеща́ется и афедро́ном исхо́дит? Исходя́щая же изоу́ст, от се́рдца исхо́дят, и та скверня́т челове́ка. От се́рдца бо исхо́дят помышле́ния зла́я, уби́йства, прелюбодея́ния, любодея́ния, татьбы́, лжесвиде́тельства, хулы́. Сия́ суть скверня́щая челове́ка, а е́же неумове́нныма рука́ма я́сти, не скверни́т челове́ка. И изше́д отту́ду Иису́с, оты́де во страны́ Ти́рския и Сидо́нския. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋ́пльше ко і҆и҃сꙋ ᲂу҆ченицы̀ є҆гѡ̀, рѣ́ша є҆мꙋ̀: вѣ́си ли, ꙗ҆́кѡ фарїсе́є слы́шавше сло́во, соблазни́шасѧ; ѻ҆́нъ же ѿвѣща́въ речѐ: всѧ́къ са́дъ, є҆гѡ́же не насадѝ ѻ҆ц҃ъ мо́й небе́сный, и҆скорени́тсѧ. ѡ҆ста́вите и҆̀хъ: вождѝ сꙋ́ть слѣ́пи слѣпцє́мъ: слѣпе́цъ же слѣпца̀ а҆́ще во́дитъ, ѻ҆́ба въ ꙗ҆́мꙋ впаде́тасѧ. ѿвѣща́въ же пе́тръ, речѐ є҆мꙋ̀: скажѝ на́мъ при́тчꙋ сїю̀. і҆и҃съ же речѐ и҆̀мъ: є҆дина́че ли и҆ вы̀ без̾ ра́зꙋма є҆стѐ; не ᲂу҆̀ ли разꙋмѣва́ете, ꙗ҆́кѡ всѧ́ко, є҆́же вхо́дитъ во ᲂу҆ста̀, во чре́во вмѣща́етсѧ, и҆ а҆федрѡ́номъ и҆схо́дитъ; и҆сходѧ̑щаѧ же и҆зоꙋ́стъ, ѿ се́рдца и҆схо́дѧтъ, и҆ та̑ сквернѧ́тъ человѣ́ка. ѿ се́рдца бо и҆схо́дѧтъ помышлє́нїѧ ѕла̑ѧ, ᲂу҆бі̑йства, прелюбодѣѧ̑нїѧ, любодѣѧ̑нїѧ, татьбы̑, лжесвидѣ́тєльства, хꙋлы̑. сїѧ̑ сꙋ́ть сквернѧ̑щаѧ человѣ́ка: а҆ є҆́же неꙋмове́нныма рꙋка́ма ꙗ҆́сти, не скверни́тъ человѣ́ка. и҆ и҆зше́дъ ѿтꙋ́дꙋ і҆и҃съ, ѿи́де во страны̀ тѵ́рскїѧ и҆ сїдѡ́нскїѧ. ",
}

add_evangelie_matfea {
  ["номер"] = 62,
  ["комментарий"] = "Мф., 62 зач., XV, 21–28.",
  ["текст_ру"] = "Во вре́мя о́но, вни́де Иису́с во страны́ Ти́рския и Сидо́нския. И се жена́ Ханане́йска, от преде́л тех изше́дши, возопи́ к Нему́ глаго́лющи: поми́луй мя, Го́споди, сы́не Дави́дов, дщи моя́ зле бесну́ется. Он же не отвеща́ ей словесе́. И присту́пльше ученицы́ Его́, моля́ху Его́, глаго́люще: отпусти́ ю́, я́ко вопие́т в след нас. Он же отвеща́в рече́: несмь по́слан, то́кмо ко овца́м поги́бшым до́му Изра́илева. Она́ же прише́дши поклони́ся Ему́, глаго́лющи: Го́споди, помози́ ми. Он же отвеща́в рече́: несть добро́ отя́ти хле́ба ча́дом и поврещи́ псом. Она́ же рече́: ей, Го́споди, и́бо и пси ядя́т от крупи́ц па́дающих от трапе́зы господе́й свои́х. Тогда́ отвеща́в Иису́с рече́ ей: о, же́но, ве́лия ве́ра твоя́, бу́ди тебе́ я́коже хо́щеши. И изцеле́ дщи ея́ от того́ часа́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, вни́де і҆и҃съ во страны̀ тѵ́рскїѧ и҆ сїдѡ́нскїѧ. и҆ сѐ жена̀ ханане́йска ѿ предѣ́лъ тѣ́хъ и҆зше́дши, возопѝ къ немꙋ̀, глаго́лющи: поми́лꙋй мѧ̀ гдⷭ҇и, сн҃е дв҃довъ: дщѝ моѧ̀ ѕлѣ̀ бѣснꙋ́етсѧ. ѻ҆́нъ же не ѿвѣща̀ є҆́й словесѐ. и҆ пристꙋ́пльше ᲂу҆ченицы̀ є҆гѡ̀, молѧ́хꙋ є҆го̀ глаго́люще: ѿпꙋстѝ ю҆̀, ꙗ҆́кѡ вопїе́тъ въ слѣ́дъ на́съ. ѻ҆́нъ же ѿвѣща́въ, речѐ: нѣ́смь по́сланъ, то́кмѡ ко ѻ҆вца́мъ поги́бшымъ до́мꙋ і҆и҃лева. ѻ҆на́ же прише́дши поклони́сѧ є҆мꙋ̀, глаго́лющи: гдⷭ҇и, помози́ ми. ѻ҆́нъ же ѿвѣща́въ, речѐ: нѣ́сть добро̀ ѿѧ́ти хлѣ́ба ча́дѡмъ, и҆ поврещѝ псѡ́мъ. ѻ҆на́ же речѐ: є҆́й гдⷭ҇и: и҆́бо и҆ псѝ ꙗ҆дѧ́тъ ѿ крꙋпи́цъ па́дающихъ ѿ трапе́зы господе́й свои́хъ. тогда̀ ѿвѣща́въ і҆и҃съ, речѐ є҆́й: ѽ же́но, ве́лїѧ вѣ́ра твоѧ̀! бꙋ́ди тебѣ̀, ꙗ҆́коже хо́щеши. и҆ и҆сцѣлѣ̀ дщѝ є҆ѧ̀ ѿ тогѡ̀ часа̀. ",
}

add_evangelie_matfea {
  ["номер"] = 63,
  ["комментарий"] = "Мф., 63 зач., XV, 29–31.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с на мо́ре Галиле́йское, и возше́д на гору́, се́де ту. И приступи́ша к Нему́ наро́ди мно́зи, иму́ще с собо́ю хромы́я, слепы́я, немы́я, бе́дныя и и́ны мно́ги, и приверго́ша их к нога́ма Иису́совыма, и исцели́ их. Я́коже наро́дом диви́тися, ви́дящым немы́я глаго́люща, бе́дныя здра́вы, хромы́я ходя́щя и слепы́я ви́дящя, и сла́вляху Бо́га Изра́илева. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ на мо́ре галїле́йское: и҆ возше́дъ на горꙋ̀, сѣ́де тꙋ̀. и҆ пристꙋпи́ша къ немꙋ̀ наро́ди мно́зи, и҆мꙋ́ще съ собо́ю хрѡмы́ѧ, слѣпы̑ѧ, нѣмы̑ѧ, бѣ̑дныѧ, и҆ и҆́ны мно́ги: и҆ приверго́ша и҆̀хъ къ нога́ма і҆и҃совыма, и҆ и҆сцѣлѝ и҆̀хъ. ꙗ҆́коже наро́дѡмъ диви́тисѧ ви́дѧщымъ нѣмы̑ѧ глаго́лющѧ, бѣ̑дныѧ здра́вы, хрѡмы́ѧ ходѧ́щѧ, и҆ слѣпы̑ѧ ви́дѧщѧ, и҆ сла́влѧхꙋ бг҃а і҆и҃лева. ",
}

add_evangelie_matfea {
  ["номер"] = 64,
  ["комментарий"] = "Мф., 64 зач., XV, 32–39.",
  ["текст_ру"] = "Во вре́мя о́но, призва́в Иису́с ученики́ Своя́, рече́ им: милосе́рдую о наро́де сем, я́ко уже́ дни три приседя́т Мне и не и́мут чесо́ я́сти, и отпусти́ти их не я́дша не хощу́, да не ка́ко ослабе́ют на пути́. И глаго́лаша Ему́ ученицы́ Его́: отку́ду нам в пусты́ни хле́би толи́цы, я́ко да насы́тится толи́к наро́д? И глаго́ла им Иису́с: коли́ко хле́бы и́мате? Они́ же ре́ша: седмь, и ма́ло ры́биц. И повеле́ наро́дом возлещи́ на земли́, и прие́м седмь хле́бы и ры́бы, хвалу́ возда́в преломи́ и даде́ ученико́м Свои́м, ученицы́ же наро́дом. И ядо́ша вси и насы́тишася, и взя́ша избы́тки укру́х, седмь ко́шниц испо́лнь. Я́дших же бя́ше четы́ре ты́сящи муже́й, ра́зве жен и дете́й. И отпусти́в наро́ды, вле́зе в кора́бль и прии́де в преде́лы Магдали́нски. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, призва́въ і҆и҃съ ᲂу҆ченикѝ своѧ̀, речѐ и҆̀мъ: милосе́рдꙋю ѡ҆ наро́дѣ се́мъ, ꙗ҆́кѡ ᲂу҆жѐ днѝ трѝ присѣдѧ́тъ мнѣ̀, и҆ не и҆́мꙋтъ чесѡ̀ ꙗ҆́сти: и҆ ѿпꙋсти́ти и҆̀хъ не ꙗ҆́дшѧ не хощꙋ̀, да не ка́кѡ ѡ҆слабѣ́ютъ на пꙋтѝ. и҆ глаго́лаша є҆мꙋ̀ ᲂу҆ченицы̀ є҆гѡ̀: ѿкꙋ́дꙋ на́мъ въ пꙋсты́ни хлѣ́би толи́цы, ꙗ҆́кѡ да насы́титсѧ толи́къ наро́дъ; и҆ глаго́ла и҆̀мъ і҆и҃съ: коли́кѡ хлѣ́бы и҆́мате; ѻ҆ни́ же рѣ́ша: се́дмь, и҆ ма́лѡ ры́бицъ. и҆ повелѣ̀ наро́дѡмъ возлещѝ на землѝ. и҆ прїе́мъ се́дмь хлѣ́бы и҆ ры̑бы, хвалꙋ̀ возда́въ преломѝ, и҆ дадѐ ᲂу҆ченикѡ́мъ свои́мъ, ᲂу҆ченицы́ же наро́дѡмъ. и҆ ꙗ҆до́ша всѝ, и҆ насы́тишасѧ: и҆ взѧ́ша и҆збы́тки ᲂу҆крꙋ̑хъ, се́дмь ко́шницъ и҆спо́лнь. ꙗ҆́дшихъ же бѧ́ше четы́ре ты́сѧщи мꙋже́й, ра́звѣ же́нъ и҆ дѣте́й. и҆ ѿпꙋсти́въ наро́ды, влѣ́зе въ кора́бль, и҆ прїи́де въ предѣ́лы магдали́нски. ",
}

add_evangelie_matfea {
  ["номер"] = 65,
  ["комментарий"] = "Мф., 65 зач., XVI, 1-6.",
  ["текст_ру"] = "Во вре́мя о́но, приступи́ша ко Иису́су фарисе́е и саддуке́е, искуша́юще вопроси́ша Его́ зна́мение с небесе́ показа́ти им. Он же отвеща́в рече́ им: ве́черу бы́вшу, глаго́лете, ве́дро, чермну́ет бо ся не́бо. И у́тру, днесь зима́, чермну́ет бо ся дряселу́я не́бо. Лицеме́ри, лице́ у́бо небесе́ уме́ете разсужда́ти, зна́мений же времено́м не мо́жете искуси́ти. Род лука́в и прелюбоде́йный зна́мения и́щет, и зна́мение не да́стся ему́, то́кмо зна́мение Ио́ны проро́ка. И оста́вль их, оты́де. И преше́дше ученицы́ Его́ на он пол, забы́ша хле́бы взя́ти. Иису́с же рече́ им: внемли́те и блюди́теся от ква́са фарисе́йска и саддуке́йска. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋпи́ша ко і҆и҃сꙋ фарїсе́є и҆ саддꙋке́є и҆скꙋша́юще вопроси́ша є҆го̀, зна́менїе съ небесѐ показа́ти и҆̀мъ. ѻ҆́нъ же ѿвѣща́въ речѐ и҆̀мъ: ве́черꙋ бы́вшꙋ, глаго́лете, ве́дро: чермнꙋ́етъ бо сѧ не́бо. и҆ ᲂу҆́трꙋ, дне́сь зима̀: чермнꙋ́етъ бо сѧ дрѧселꙋ́ѧ не́бо. лицемѣ́ри, лицѐ ᲂу҆́бѡ нб҃сѐ ᲂу҆мѣ́ете разсꙋжда́ти, зна́менїй же временѡ́мъ не мо́жете и҆скꙋси́ти. ро́дъ лꙋка́въ и҆ прелюбодѣ́йный зна́менїѧ и҆́щетъ: и҆ зна́менїе не да́стсѧ є҆мꙋ̀, то́кмѡ зна́менїе і҆ѡ́ны проро́ка. и҆ ѡ҆ста́вль и҆̀хъ, ѿи́де. и҆ преше́дше ᲂу҆чн҃цы̀ є҆гѡ̀ на ѻ҆́нъ по́лъ, забы́ша хлѣ́бы взѧ́ти. і҆и҃съ же речѐ и҆̀мъ: внемли́те и҆ блюди́тесѧ ѿ ква́са фарїсе́йска и҆ саддꙋке́йска. ",
}

add_evangelie_matfea {
  ["номер"] = 66,
  ["комментарий"] = "Мф., 66 зач., XVI, 6-12.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: внемли́те и блюди́теся от ква́са фарисе́йска и саддуке́йска. Они́ же помышля́ху в себе́, глаго́люще: я́ко хле́бы не взя́хом. Разуме́в же Иису́с рече́ им: что мы́слите в себе́, малове́ри, я́ко хле́бы не взя́сте? Не у ли разуме́ете, ниже́ по́мните пять хле́бы пяти́м ты́сящам, и коли́ко кош взя́сте? Ни ли седмь хле́бы четы́рем ты́сящам, и коли́ко ко́шниц взя́сте? Ка́ко не разуме́ете, я́ко не о хле́бех рех вам внима́ти, но от ква́са фарисе́йска и саддуке́йска? Тогда́ разуме́ша, я́ко не рече́ храни́тися от ква́са хле́бнаго, но от уче́ния фарисе́йска и саддуке́йска. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: внемли́те и҆ блюди́тесѧ ѿ ква́са фарїсе́йска и҆ саддꙋке́йска. ѻ҆ни́ же помышлѧ́хꙋ въ себѣ̀, глаго́люще: ꙗ҆́кѡ хлѣ́бы не взѧ́хомъ. разꙋмѣ́въ же і҆и҃съ речѐ и҆̀мъ: что̀ мы́слите въ себѣ̀, маловѣ́ри, ꙗ҆́кѡ хлѣ́бы не взѧ́сте; не ᲂу҆̀ ли разꙋмѣ́ете, нижѐ по́мните, пѧ́ть хлѣ́бы пѧти́мъ ты́сѧщамъ, и҆ коли́кѡ кѡ́шъ взѧ́сте; ни лѝ се́дмь хлѣ́бы четы́ремъ ты́сѧщамъ, и҆ коли́кѡ ко́шницъ взѧ́сте; ка́кѡ не разꙋмѣ́ете, ꙗ҆́кѡ не ѡ҆ хлѣ́бѣхъ рѣ́хъ ва́мъ внима́ти, но ѿ ква́са фарїсе́йска и҆ саддꙋке́йска; тогда̀ разꙋмѣ́ша, ꙗ҆́кѡ не речѐ храни́тисѧ ѿ ква́са хлѣ́бнагѡ, но ѿ ᲂу҆че́нїѧ фарїсе́йска и҆ саддꙋке́йска. ",
}

add_evangelie_matfea {
  ["номер"] = 67,
  ["комментарий"] = "Мф., 67 зач., XVI, 13–19.",
  ["текст_ру"] = "Во вре́мя о́но, прише́д Иису́с во страны́ Кесари́и Фили́пповы, вопроша́ше ученики́ Своя́, глаго́ля: кого́ Мя глаго́лют челове́цы бы́ти, Сы́на Челове́ческаго? Они́ же ре́ша: о́ви у́бо Иоа́нна Крести́теля, ини́и же Илию́, друзи́и же Иереми́ю, или́ еди́наго от проро́к. Глаго́ла им Иису́с: вы же кого́ Мя глаго́лете бы́ти? Отвеща́в же Си́мон Петр рече́: Ты еси́ Христо́с, Сын Бо́га жива́го. И отвеща́в Иису́с рече́ ему́: блаже́н еси́, Си́моне, вар Ио́на, я́ко плоть и кровь не яви́ тебе́, но Оте́ц Мой, и́же на Небесе́х. И Аз же тебе́ глаго́лю, я́ко ты еси́ Петр, и на сем ка́мени сози́жду Це́рковь Мою́, и врата́ а́дова не одоле́ют ей. И дам ти ключи́ Ца́рства Небе́снаго, и е́же а́ще свя́жеши на земли́, бу́дет свя́зано на Небесе́х, и е́же а́ще разреши́ши на земли́, бу́дет разреше́но на Небесе́х. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прише́дъ і҆и҃съ во страны̑ кесарі́и фїлі́пповы, вопроша́ше ᲂу҆ченикѝ своѧ̀, глаго́лѧ: кого́ мѧ глаго́лютъ человѣ́цы бы́ти, сн҃а человѣ́ческаго; ѻ҆ни́ же рѣ́ша: ѻ҆́ви ᲂу҆́бѡ і҆ѡа́нна крести́телѧ, и҆ні́и же и҆лїю̀, дрꙋзі́и же і҆еремі́ю, и҆лѝ є҆ди́наго ѿ прорѡ́къ. глаго́ла и҆̀мъ і҆и҃съ: вы́ же кого́ мѧ глаго́лете бы́ти; ѿвѣща́въ же сі́мѡнъ пе́тръ речѐ: ты̀ є҆сѝ хрⷭ҇то́съ, сн҃ъ бг҃а жива́гѡ. и҆ ѿвѣща́въ і҆и҃съ речѐ є҆мꙋ̀: блаже́нъ є҆сѝ сі́мѡне ва́ръ і҆ѡ́на, ꙗ҆́кѡ пло́ть и҆ кро́вь не ꙗ҆вѝ тебѣ̀, но ѻ҆ц҃ъ мо́й и҆́же на нб҃сѣ́хъ. и҆ а҆́зъ же тебѣ̀ глаго́лю, ꙗ҆́кѡ ты̀ є҆сѝ пе́тръ, и҆ на се́мъ ка́мени сози́ждꙋ цр҃ковь мою̀, и҆ врата̀ а҆́дова не ѡ҆долѣ́ютъ є҆́й. и҆ да́мъ тѝ ключѝ црⷭ҇тва нбⷭ҇нагѡ: и҆ є҆́же а҆́ще свѧ́жеши на землѝ, бꙋ́детъ свѧ́зано на нб҃сѣ́хъ: и҆ є҆́же а҆́ще разрѣши́ши на землѝ, бꙋ́детъ разрѣше́но на небесѣ́хъ. ",
}

