add_evangelie_matfea {
  ["номер"] = 68,
  ["комментарий"] = "Мф., 68 зач., XVI, 20–24.",
  ["текст_ру"] = "Во вре́мя о́но, запрети́ Иису́с ученико́м Свои́м, да никому́же реку́т, я́ко Сей есть Иису́с Христо́с. Отто́ле нача́т Иису́с ска́зовати ученико́м Свои́м, я́ко подоба́ет Ему́ ити́ во Иерусали́м и мно́го пострада́ти от ста́рец и архиере́й и кни́жник, и убие́ну бы́ти, и тре́тий день воста́ти. И пое́м Его́ Петр, нача́т пререца́ти Ему́ глаго́ля: милосе́рд Ты, Го́споди, не и́мать бы́ти Тебе́ сие́. Он же обра́щся рече́ Петро́ви: иди́ за Мно́ю, сатано́, собла́зн Ми еси́, я́ко не мы́слиши я́же суть Бо́жия, но челове́ческая. Тогда́ Иису́с рече́ ученико́м Свои́м: а́ще кто хо́щет по Мне ити́, да отве́ржется себе́ и во́змет крест свой и по Мне гряде́т. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, запретѝ і҆и҃съ ᲂу҆ченикѡ́мъ свои́мъ, да никомꙋ́же рекꙋ́тъ, ꙗ҆́кѡ се́й є҆́сть і҆и҃съ хрⷭ҇то́съ. ѿто́лѣ нача́тъ і҆и҃съ ска́зовати ᲂу҆ченикѡ́мъ свои́мъ, ꙗ҆́кѡ подоба́етъ є҆мꙋ̀ и҆тѝ во і҆ерꙋсали́мъ, и҆ мно́гѡ пострада́ти ѿ ста́рєцъ и҆ а҆рхїерє́й и҆ кни̑жникъ, и҆ ᲂу҆бїе́нꙋ бы́ти, и҆ тре́тїй де́нь воста́ти. и҆ пое́мъ є҆го̀ пе́тръ, нача́тъ прерѣца́ти є҆мꙋ̀, глаго́лѧ: млⷭ҇рдъ ты̀ гдⷭ҇и, не и҆́мать бы́ти тебѣ̀ сі́е. ѻ҆́нъ же ѡ҆бра́щсѧ речѐ петро́ви: и҆дѝ за мно́ю сатано̀, собла́знъ мѝ є҆сѝ: ꙗ҆́кѡ не мы́слиши, ꙗ҆̀же сꙋ́ть бж҃їѧ, но человѣ́чєскаѧ. тогда̀ і҆и҃съ речѐ ᲂу҆ченикѡ́мъ свои́мъ: а҆́ще кто̀ хо́щетъ по мнѣ̀ и҆тѝ, да ѿве́ржетсѧ себѐ, и҆ во́з̾метъ крⷭ҇тъ сво́й, и҆ по мнѣ̀ грѧде́тъ. ",
}

add_evangelie_matfea {
  ["номер"] = 69,
  ["комментарий"] = "Мф., 69 зач., XVI, 24–28.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: а́ще кто хо́щет по Мне ити́, да отве́ржется себе́ и во́змет крест свой и по Мне гряде́т. И́же бо а́ще хо́щет ду́шу свою́ спасти́, погуби́т ю́, и и́же а́ще погуби́т ду́шу свою́ Мене́ ра́ди, обря́щет ю́. Ка́я бо по́льза челове́ку, а́ще мир весь приобря́щет, ду́шу же свою́ отщети́т? Или́ что даст челове́к изме́ну за ду́шу свою́? Приити́ бо и́мать Сын Челове́ческий во сла́ве Отца́ Своего́ со А́нгелы Свои́ми, и тогда́ возда́ст кому́ждо по дея́нием его́. Ами́нь глаго́лю вам, я́ко суть не́цыи от зде стоя́щих, и́же не и́мут вкуси́ти сме́рти, до́ндеже ви́дят Сы́на Челове́ческаго гряду́ща во Ца́рствии Свое́м. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: а҆́ще кто̀ хо́щетъ по мнѣ̀ и҆тѝ, да ѿве́ржетсѧ себѐ, и҆ во́з̾метъ крⷭ҇тъ сво́й, и҆ по мнѣ̀ грѧде́тъ. и҆́же бо а҆́ще хо́щетъ дꙋ́шꙋ свою̀ спастѝ, погꙋби́тъ ю҆̀: и҆ и҆́же а҆́ще погꙋби́тъ дꙋ́шꙋ свою̀ менѐ ра́ди, ѡ҆брѧ́щетъ ю҆̀. ка́ѧ бо по́льза человѣ́кꙋ, а҆́ще мі́ръ ве́сь прїѡбрѧ́щетъ, дꙋ́шꙋ же свою̀ ѿтщети́тъ; и҆лѝ что̀ да́стъ человѣ́къ и҆змѣ́нꙋ за дꙋ́шꙋ свою̀; прїити́ бо и҆́мать сн҃ъ человѣ́ческїй во сла́вѣ ѻ҆ц҃а̀ своегѡ̀, со а҆́гг҃лы свои́ми: и҆ тогда̀ возда́стъ комꙋ́ждо по дѣѧ́нїємъ є҆гѡ̀. а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ сꙋ́ть нѣ́цыи ѿ здѣ̀ стоѧ́щихъ, и҆̀же не и҆́мꙋтъ вкꙋси́ти сме́рти, до́ндеже ви́дѧтъ сн҃а человѣ́ческаго грѧдꙋ́ща во црⷭ҇твїи свое́мъ. ",
}

add_evangelie_matfea {
  ["номер"] = 70,
  ["комментарий"] = "Мф., 70 зач., XVII, 1–9.",
  ["текст_ру"] = "Во вре́мя о́но, поя́т Иису́с Петра́ и Иа́кова и Иоа́нна бра́та его́, и возведе́ их на гору́ высоку́ еди́ны. И преобрази́ся пред ни́ми, и просвети́ся лице́ Его́ я́ко со́лнце, ри́зы же Его́ бы́ша белы́ я́ко свет. И се яви́стася им Моисе́й и Илиа́, с Ним глаго́люща. Отвеща́в же Петр рече́ ко Иису́сови: Го́споди, добро́ есть нам зде бы́ти, а́ще хо́щеши, сотвори́м зде три се́ни, Тебе́ еди́ну, и Моисе́ови еди́ну, и еди́ну Илии́. Еще́ же ему́ глаго́лющу, се о́блак све́тел осени́ их, и се глас из о́блака глаго́ля: Сей есть Сын Мой Возлю́бленный, о Не́мже благоволи́х, Того́ послу́шайте. И слы́шавше ученицы́, падо́ша ни́цы, и убоя́шася зело́. И присту́пль Иису́с, прикосну́ся их, и рече́: воста́ните, и не бо́йтеся. Возве́дше же о́чи свои́, никого́же ви́деша, то́кмо Иису́са еди́наго. И сходя́щим им с горы́, запове́да им Иису́с, глаго́ля: никому́же пове́дите виде́ния, до́ндеже Сын Челове́ческий из ме́ртвых воскре́снет. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, поѧ́тъ і҆и҃съ петра̀ и҆ і҆а́кѡва и҆ і҆ѡа́нна бра́та є҆гѡ̀, и҆ возведѐ и҆̀хъ на горꙋ̀ высокꙋ̀ є҆ди́ны. и҆ преѡбрази́сѧ пред̾ ни́ми: и҆ просвѣти́сѧ лицѐ є҆гѡ̀ ꙗ҆́кѡ со́лнце: ри̑зы же є҆гѡ̀ бы́ша бѣлы̀ ꙗ҆́кѡ свѣ́тъ. и҆ сѐ ꙗ҆ви́стасѧ и҆̀мъ мѡѷсе́й и҆ и҆лїа̀, съ ни́мъ глаго́люща. ѿвѣща́въ же пе́тръ речѐ ко і҆и҃сови: гдⷭ҇и, добро̀ є҆́сть на́мъ здѣ̀ бы́ти: а҆́ще хо́щеши, сотвори́мъ здѣ̀ трѝ сѣ́ни, тебѣ̀ є҆ди́нꙋ, и҆ мѡѷсе́ови є҆ди́нꙋ, и҆ є҆ди́нꙋ и҆лїѝ. є҆ще́ же є҆мꙋ̀ глаго́лющꙋ, сѐ ѻ҆́блакъ свѣ́телъ ѡ҆сѣнѝ и҆̀хъ: и҆ сѐ гла́съ и҆з̾ ѻ҆́блака глаго́лѧ: се́й є҆́сть сн҃ъ мо́й возлю́бленный, ѡ҆ не́мже благоволи́хъ: тогѡ̀ послꙋ́шайте. и҆ слы́шавше ᲂу҆ченицы̀, падо́ша ни́цы, и҆ ᲂу҆боѧ́шасѧ ѕѣлѡ̀. и҆ пристꙋ́пль і҆и҃съ, прикоснꙋ́сѧ и҆́хъ, и҆ речѐ: воста́ните, и҆ не бо́йтесѧ. возве́дше же ѻ҆́чи своѝ, никого́же ви́дѣша, то́кмѡ і҆и҃са є҆ди́наго. и҆ сходѧ́щымъ и҆̀мъ съ горы̀, заповѣ́да и҆̀мъ і҆и҃съ, глаго́лѧ: никомꙋ́же повѣ́дите видѣ́нїѧ, до́ндеже сн҃ъ человѣ́ческїй и҆з̾ ме́ртвыхъ воскре́снетъ. ",
}

add_evangelie_matfea {
  ["номер"] = 71,
  ["комментарий"] = "Мф., 71 зач., XVII, 10-18.",
  ["текст_ру"] = "Во вре́мя о́но, вопроси́ша Иису́са ученицы́ Его́, глаго́люще: что у́бо кни́жницы глаго́лют, я́ко Илии́ подоба́ет приити́ пре́жде? Иису́с же отвеща́в рече́ им: Илиа́ у́бо прии́дет пре́жде и устро́ит вся. Глаго́лю же вам, я́ко Илиа́ уже́ прии́де, и не позна́ша его́, но сотвори́ша о нем, ели́ка восхоте́ша, та́ко и Сын Челове́ческий и́мать пострада́ти от них. Тогда́ разуме́ша ученицы́, я́ко о Иоа́нне Крести́тели рече́ им. И прише́дшым им к наро́ду, приступи́ к Нему́ челове́к, кла́няяся Ему́ и глаго́ля: Го́споди, поми́луй сы́на моего́, я́ко на но́вы ме́сяцы бесну́ется и зле стра́ждет, мно́жицею бо па́дает во огнь и мно́жицею в во́ду. И приведо́х его́ ко ученико́м Твои́м, и не возмого́ша его́ исцели́ти. Отвеща́в же Иису́с рече́: о, ро́де неве́рный и развраще́нный, доко́ле бу́ду с ва́ми? Доко́ле терплю́ вас? Приведи́те Ми его́ се́мо. И запрети́ ему́ Иису́с, и изы́де из него́ бес, и изцеле́ о́трок от часа́ того́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, вопроси́ша і҆и҃са ᲂу҆ч҃нцы̀ є҆гѡ̀, глаго́люще: что̀ ᲂу҆́бѡ кни́жницы глаго́лютъ, ꙗ҆́кѡ и҆лїѝ подоба́етъ прїитѝ пре́жде; і҆и҃съ же ѿвѣща́въ речѐ и҆̀мъ: и҆лїа̀ ᲂу҆́бѡ прїи́детъ пре́жде, и҆ ᲂу҆стро́итъ всѧ̑. глаго́лю же ва́мъ, ꙗ҆́кѡ и҆лїа̀ ᲂу҆жѐ прїи́де: и҆ не позна́ша є҆гѡ̀, но сотвори́ша ѡ҆ не́мъ, є҆ли̑ка восхотѣ́ша. та́кѡ и҆ сн҃ъ человѣ́ческїй и҆́мать пострада́ти ѿ ни́хъ. тогда̀ разꙋмѣ́ша ᲂу҆ч҃нцы̀, ꙗ҆́кѡ ѡ҆ і҆ѡа́ннѣ крести́тели речѐ и҆̀мъ. и҆ прише́дшымъ и҆̀мъ къ наро́дꙋ, пристꙋпѝ къ немꙋ̀ человѣ́къ, кла́нѧѧсѧ є҆мꙋ̀, и҆ глаго́лѧ: гдⷭ҇и, поми́лꙋй сы́на моего̀, ꙗ҆́кѡ на но́вы мѣ́сѧцы бѣснꙋ́етсѧ, и҆ ѕлѣ̀ стра́ждетъ: мно́жицею бо па́даетъ во ѻ҆́гнь, и҆ мно́жицею въ во́дꙋ. и҆ приведо́хъ є҆го̀ ко ᲂу҆ченикѡ́мъ твои́мъ, и҆ не возмого́ша є҆го̀ и҆сцѣли́ти. ѿвѣща́въ же і҆и҃съ речѐ: ѽ ро́де невѣ́рный, и҆ развраще́нный, доко́лѣ бꙋ́дꙋ съ ва́ми; доко́лѣ терплю̀ ва́съ; приведи́те мѝ є҆го̀ сѣ́мѡ. и҆ запретѝ є҆мꙋ̀ і҆и҃съ: и҆ и҆зы́де и҆з̾ негѡ̀ бѣ́съ, и҆ и҆сцѣлѣ̀ ѻ҆́трокъ ѿ часа̀ тогѡ̀. ",
}

add_evangelie_matfea {
  ["номер"] = 72,
  ["комментарий"] = "Мф., 72 зач., XVII, 14–23.",
  ["текст_ру"] = "Во вре́мя о́но, челове́к не́кий приступи́ ко Иису́су, кла́няяся Ему́ и глаго́ля: Го́споди, поми́луй сы́на моего́, я́ко на но́вы ме́сяцы бесну́ется и зле стра́ждет, мно́жицею бо па́дает во огнь и мно́жицею в во́ду. И приведо́х его́ ко ученико́м Твои́м, и не возмого́ша его́ исцели́ти. Отвеща́в же Иису́с рече́: о, ро́де неве́рный и развраще́нный, доко́ле бу́ду с ва́ми? Доко́ле терплю́ вам? Приведи́те Ми его́ се́мо. И запрети́ ему́ Иису́с, и изы́де из него́ бес, и изцеле́ о́трок от часа́ того́. Тогда́ присту́пльше ученицы́ Иису́сови еди́ному, ре́ша: почто́ мы не возмого́хом изгна́ти его́? Иису́с же рече́ им: за неве́рствие ва́ше. Ами́нь бо глаго́лю вам, а́ще и́мате ве́ру я́ко зе́рно гору́шно, рече́те горе́ сей: прейди́ отсю́ду та́мо, и пре́йдет, и ничто́же невозмо́жно бу́дет вам. Сей же род не исхо́дит, то́кмо моли́твою и посто́м. Живу́щым же им в Галиле́и, рече́ им Иису́с: пре́дан и́мать бы́ти Сын Челове́ческий в ру́це челове́ком, и убию́т Его́, и в тре́тий день воста́нет. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, человѣ́къ нѣ́кїй пристꙋпѝ ко і҆и҃сꙋ кла́нѧѧсѧ є҆мꙋ̀, и҆ глаго́лѧ: гдⷭ҇и, поми́лꙋй сы́на моего̀, ꙗ҆́кѡ на но́вы мѣ́сѧцы бѣснꙋ́етсѧ, и҆ ѕлѣ̀ стра́ждетъ: мно́жицею бо па́даетъ во ѻ҆́гнь, и҆ мно́жицею въ во́дꙋ. и҆ приведо́хъ є҆го̀ ко ᲂу҆ченикѡ́мъ твои́мъ, и҆ не возмого́ша є҆го̀ и҆сцѣли́ти. ѿвѣща́въ же і҆и҃съ речѐ: ѽ ро́де невѣ́рный, и҆ развраще́нный, доко́лѣ бꙋ́дꙋ съ ва́ми; доко́лѣ терплю̀ ва́съ; приведи́те мѝ є҆го̀ сѣ́мѡ. и҆ запретѝ є҆мꙋ̀ і҆и҃съ: и҆ и҆зы́де и҆з̾ негѡ̀ бѣ́съ, и҆ и҆сцѣлѣ̀ ѻ҆́трокъ ѿ часа̀ тогѡ̀. тогда̀ пристꙋ́пльше ᲂу҆ченицы̀ і҆и҃сови є҆ди́номꙋ, рѣ́ша: почто̀ мы̀ не возмого́хомъ и҆згна́ти є҆го̀; і҆и҃съ же речѐ и҆̀мъ: за невѣ́рствїе ва́ше. а҆ми́нь бо глаго́лю ва́мъ: а҆́ще и҆́мате вѣ́рꙋ ꙗ҆́кѡ зе́рно горꙋ́шно, рече́те горѣ̀ се́й, прейдѝ ѿсю́дꙋ та́мѡ, и҆ пре́йдетъ: и҆ ничто́же невозмо́жно бꙋ́детъ ва́мъ. се́й же ро́дъ не и҆схо́дитъ, то́кмѡ моли́твою и҆ посто́мъ. живꙋ́щымъ же и҆̀мъ въ галїле́и, речѐ и҆̀мъ і҆и҃съ: пре́данъ и҆́мать бы́ти сн҃ъ человѣ́ческїй въ рꙋ́цѣ человѣ́кѡмъ: и҆ ᲂу҆бїю́тъ є҆го̀, и҆ въ тре́тїй де́нь воста́нетъ. ",
}

add_evangelie_matfea {
  ["номер"] = 73,
  ["комментарий"] = "Мф., 73 зач., XVII, 24 – XVIII, 4.",
  ["текст_ру"] = "Во вре́мя о́но, приступи́ша прие́млющии дидра́хма к Петро́ви и ре́ша: Учи́тель ваш не даст ли дидра́хма? Глаго́ля: ей. И егда́ вни́де в дом, предвари́ его́ Иису́с, глаго́ля: что ти мни́тся, Си́моне? Ца́рие зе́мстии от ки́их прие́млют да́ни или́ кинсо́н? От свои́х ли сыно́в, или́ от чужи́х? Глаго́ла Ему́ Петр: от чужи́х. Рече́ ему́ Иису́с: у́бо свобо́дни суть сы́нове. Но да не соблазни́м их, шед на мо́ре, ве́рзи у́дицу, и ю́же пре́жде и́меши ры́бу, возми́, и отве́рз уста́ ей, обря́щеши стати́р, той взем даждь им за Мя и за ся. В той час приступи́ша ученицы́ ко Иису́су, глаго́люще: кто у́бо бо́лий есть в Ца́рствии Небе́снем? И призва́в Иису́с отроча́, поста́ви е́ посреде́ их и рече́: ами́нь глаго́лю вам, а́ще не обратите́ся и бу́дете я́ко де́ти, не вни́дете в Ца́рство Небе́сное. И́же бо смири́тся я́ко отроча́ сие́, той есть бо́лий во Ца́рствии Небе́снем. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋпи́ша прїе́млющїи дїдра́хма къ петро́ви, и҆ рѣ́ша: ᲂу҆чи́тель ва́шъ не да́стъ ли дїдра́хма; глаго́ла, є҆́й. и҆ є҆гда̀ вни́де въ до́мъ, предварѝ є҆го̀ і҆и҃съ, глаго́лѧ: что́ ти мни́тсѧ, сі́мѡне; ца́рїе зе́мстїи ѿ кі́ихъ прїе́млютъ да̑ни, и҆лѝ кинсо́нъ; ѿ свои́хъ ли сынѡ́въ, и҆лѝ ѿ чꙋжи́хъ; глаго́ла є҆мꙋ̀ пе́тръ: ѿ чꙋжи́хъ. речѐ є҆мꙋ̀ і҆и҃съ: ᲂу҆̀бо свобо́дни сꙋ́ть сы́нове. но да не соблазни́мъ и҆̀хъ, ше́дъ въ мо́ре ве́рзи ᲂу҆́дицꙋ, и҆ ю҆́же пре́жде и҆́меши ры́бꙋ, воз̾мѝ: и҆ ѿве́рзъ ᲂу҆ста̀ є҆́й, ѡ҆брѧ́щеши стати́ръ: то́й взе́мъ да́ждь и҆̀мъ за мѧ̀ и҆ за сѧ̀. въ то́й ча́съ пристꙋпи́ша ᲂу҆ченицы̀ ко і҆и҃сꙋ, глаго́люще: кто̀ ᲂу҆́бѡ бо́лїй є҆́сть въ црⷭ҇твїи нбⷭ҇нѣмъ; и҆ призва́въ і҆и҃съ ѻ҆троча̀, поста́ви є҆̀ посредѣ̀ и҆́хъ, и҆ речѐ: а҆ми́нь глаго́лю ва́мъ, а҆́ще не ѡ҆братите́сѧ, и҆ бꙋ́дете ꙗ҆́кѡ дѣ́ти, не вни́дете въ црⷭ҇тво нбⷭ҇ное. и҆́же бо смири́тсѧ ꙗ҆́кѡ ѻ҆троча̀ сїѐ, то́й є҆́сть бо́лїй во црⷭ҇твїи нбⷭ҇нѣмъ. ",
}

add_evangelie_matfea {
  ["номер"] = 74,
  ["комментарий"] = "Мф., 74 зач., XVIII, 1–11.",
  ["текст_ру"] = "Во вре́мя о́но, приступи́ша ученицы́ ко Иису́су, глаго́люще: кто у́бо бо́лий есть в Ца́рствии Небе́снем? И призва́в Иису́с отроча́, поста́ви е́ посреде́ их и рече́: ами́нь глаго́лю вам, а́ще не обратите́ся и бу́дете я́ко де́ти, не вни́дете в Ца́рство Небе́сное. И́же бо смири́тся я́ко отроча́ сие́, той есть бо́лий во Ца́рствии Небе́снем. И и́же а́ще прии́мет отроча́ таково́ во и́мя Мое́, Мене́ прие́млет, а и́же а́ще соблазни́т еди́наго ма́лых сих ве́рующих в Мя, у́не есть ему́, да обе́сится же́рнов осе́льский на вы́и его́, и пото́нет в пучи́не морсте́й. Го́ре ми́ру от собла́зн, ну́жда бо есть приити́ собла́зном, оба́че го́ре челове́ку тому́, и́мже собла́зн прихо́дит. А́ще ли рука́ твоя́ или́ нога́ твоя́ соблажня́ет тя, отсецы́ ю́ и ве́рзи от себе́, добре́йше ти есть вни́ти в живо́т хро́му или́ бе́дну, не́жели две ру́це и две но́зе иму́щу вве́ржену бы́ти во огнь ве́чный. И а́ще о́ко твое́ соблажня́ет тя, изми́ е́ и ве́рзи от себе́, добре́йше ти есть со еди́нем о́ком в живо́т вни́ти, не́же две о́це иму́щу вве́ржену бы́ти в гее́нну о́гненную. Блюди́те, да не пре́зрите еди́наго от ма́лых сих, глаго́лю бо вам, я́ко А́нгели их на небесе́х вы́ну ви́дят лице́ Отца́ Моего́ Небе́снаго. Прии́де бо Сын Челове́ческий взыска́ти и спасти́ поги́бшаго. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋпи́ша ᲂу҆ченицы̀ ко і҆и҃сꙋ, глаго́люще: кто̀ ᲂу҆́бѡ бо́лїй є҆́сть въ црⷭ҇твїи нбⷭ҇нѣмъ; и҆ призва́въ і҆и҃съ ѻ҆троча̀, поста́ви є҆̀ посредѣ̀ и҆́хъ, и҆ речѐ: а҆ми́нь глаго́лю ва́мъ, а҆́ще не ѡ҆братите́сѧ, и҆ бꙋ́дете ꙗ҆́кѡ дѣ́ти, не вни́дете въ црⷭ҇тво нбⷭ҇ное. и҆́же бо смири́тсѧ ꙗ҆́кѡ ѻ҆троча̀ сїѐ, то́й є҆́сть бо́лїй во црⷭ҇твїи нбⷭ҇нѣмъ. и҆ и҆́же а҆́ще прїи́метъ ѻ҆троча̀ таково̀ во и҆́мѧ моѐ, менѐ прїе́млетъ. а҆ и҆́же а҆́ще соблазни́тъ є҆ди́наго ма́лыхъ си́хъ вѣ́рꙋющихъ въ мѧ̀, ᲂу҆́не є҆́сть є҆мꙋ̀, да ѡ҆бѣ́ситсѧ же́рновъ ѻ҆се́льскїй на вы́и є҆гѡ̀, и҆ пото́нетъ въ пꙋчи́нѣ морстѣ́й. го́ре мі́рꙋ ѿ собла̑знъ: нꙋ́жда бо є҆́сть прїитѝ собла́знѡмъ. ѻ҆ба́че го́ре человѣ́кꙋ томꙋ̀, и҆́мже собла́знъ прихо́дитъ. а҆́ще ли рꙋка̀ твоѧ̀, и҆лѝ нога̀ твоѧ̀ соблажнѧ́етъ тѧ̀, ѿсѣцы̀ ю҆̀, и҆ ве́рзи ѿ себѐ: добрѣ́йше тѝ є҆́сть вни́ти въ живо́тъ хро́мꙋ и҆лѝ бѣ́днꙋ, не́жели двѣ̀ рꙋ́цѣ, и҆ двѣ̀ но́зѣ и҆мꙋ́щꙋ, вве́рженꙋ бы́ти во ѻ҆́гнь вѣ́чный. и҆ а҆́ще ѻ҆́ко твоѐ соблажнѧ́етъ тѧ̀, и҆з̾мѝ є҆̀, и҆ ве́рзи ѿ себѐ: добрѣ́йше тѝ є҆́сть со є҆ди́нѣмъ ѻ҆́комъ въ живо́тъ вни́ти, не́же двѣ̀ ѻ҆́цѣ и҆мꙋ́щꙋ, вве́рженꙋ бы́ти въ гее́ннꙋ ѻ҆́гненнꙋю. блюди́те, да не пре́зрите є҆ди́нагѡ ѿ ма́лыхъ си́хъ: глаго́лю бо ва́мъ, ꙗ҆́кѡ а҆́гг҃ли и҆́хъ на нб҃сѣ́хъ вы́нꙋ ви́дѧтъ лицѐ ѻ҆ц҃а̀ моегѡ̀ нбⷭ҇нагѡ. прїи́де бо сн҃ъ человѣ́ческїй взыска́ти и҆ спастѝ поги́бшаго. ",
}

add_evangelie_matfea {
  ["номер"] = 75,
  ["комментарий"] = "Мф., 75 зач., XVIII, 10–20.",
  ["текст_ру"] = "Рече́ Госпо́дь: блюди́те, да не пре́зрите еди́наго от ма́лых сих, глаго́лю бо вам, я́ко А́нгели их на небесе́х вы́ну ви́дят лице́ Отца́ Моего́ Небе́снаго. Прии́де бо Сын Челове́ческий взыска́ти и спасти́ поги́бшаго. Что вам мни́тся? А́ще бу́дет не́коему челове́ку сто ове́ц, и заблу́дит еди́на от них, не оста́вит ли де́вятьдесят и де́вять в гора́х и шед и́щет заблу́ждшия? И а́ще бу́дет обрести́ ю́, ами́нь глаго́лю вам, я́ко ра́дуется о ней па́че, не́же о девяти́десятих и девяти́ не заблу́ждших. Та́ко несть во́ля пред Отце́м ва́шим Небе́сным, да поги́бнет еди́н от ма́лых сих. А́ще же согреши́т к тебе́ брат твой, иди́ и обличи́ его́ между́ тобо́ю и тем еди́нем. А́ще тебе́ послу́шает, приобре́л еси́ бра́та твоего́. А́ще ли тебе́ не послу́шает, пойми́ с собо́ю па́ки еди́наго или́ два, да при усте́х двою́ или́ трие́х свиде́телей ста́нет всяк глаго́л. А́ще же не послу́шает их, пове́ждь це́ркви, а́ще же и це́рковь преслу́шает, бу́ди тебе́ я́коже язы́чник и мыта́рь. Ами́нь бо глаго́лю вам, ели́ка а́ще свя́жете на земли́, бу́дут свя́зана на небеси́, и ели́ка а́ще разрешите́ на земли́, бу́дут разреше́на на небесе́х. Па́ки ами́нь глаго́лю вам, я́ко а́ще два от вас совеща́ета на земли́ о вся́кой ве́щи, е́же а́ще про́сита, бу́дет и́ма от Отца́ Моего́, И́же на небесе́х. Иде́же бо еста́ два или́ трие́ со́брани во и́мя Мое́, ту есмь посреде́ их. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: блюди́те, да не пре́зрите є҆ди́нагѡ ѿ ма́лыхъ си́хъ: глаго́лю бо ва́мъ, ꙗ҆́кѡ а҆́гг҃ли и҆́хъ на нб҃сѣ́хъ вы́нꙋ ви́дѧтъ лицѐ ѻ҆ц҃а̀ моегѡ̀ нбⷭ҇нагѡ. прїи́де бо сн҃ъ человѣ́ческїй взыска́ти и҆ спастѝ поги́бшаго. что̀ ва́мъ мни́тсѧ: а҆́ще бꙋ́детъ нѣ́коемꙋ человѣ́кꙋ сто̀ ѻ҆ве́цъ, и҆ заблꙋ́дитъ є҆ди́на ѿ ни́хъ: не ѡ҆ста́витъ ли де́вѧтьдесѧтъ и҆ де́вѧть въ гора́хъ, и҆ ше́дъ и҆́щетъ заблꙋ́ждшїѧ; и҆ а҆́ще бꙋ́детъ ѡ҆брѣстѝ ю҆̀, а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ ра́дꙋетсѧ ѡ҆ не́й па́че, не́же ѡ҆ девѧти́десѧтихъ и҆ девѧтѝ не заблꙋ́ждшихъ. та́кѡ нѣ́сть во́лѧ пред̾ ѻ҆ц҃е́мъ ва́шимъ нбⷭ҇нымъ, да поги́бнетъ є҆ди́нъ ѿ ма́лыхъ си́хъ. а҆́ще же согрѣши́тъ къ тебѣ̀ бра́тъ тво́й, и҆дѝ и҆ ѡ҆бличѝ є҆го̀ междꙋ̀ тобо́ю и҆ тѣ́мъ є҆ди́нѣмъ. а҆́ще тебѐ послꙋ́шаетъ, прїѡбрѣ́лъ є҆сѝ бра́та твоего̀. а҆́ще ли тебѐ не послꙋ́шаетъ, поймѝ съ собо́ю па́ки є҆ди́наго и҆лѝ два̀, да при ᲂу҆стѣ́хъ двою̀ и҆лѝ трїе́хъ свидѣ́телей ста́нетъ всѧ́къ глаго́лъ. а҆́ще же не послꙋ́шаетъ и҆́хъ, повѣ́ждь це́ркви: а҆́ще же и҆ це́рковь преслꙋ́шаетъ, бꙋ́ди тебѣ̀ ꙗ҆́коже ꙗ҆зы́чникъ и҆ мыта́рь. а҆ми́нь бо глаго́лю ва́мъ: є҆ли̑ка а҆́ще свѧ́жете на землѝ, бꙋ́дꙋтъ свѧ̑зана на нб҃сѝ: и҆ є҆ли̑ка а҆́ще разрѣшитѐ на землѝ, бꙋ́дꙋтъ разрѣшє́на на небесѣ́хъ. па́ки а҆ми́нь глаго́лю ва́мъ: ꙗ҆́кѡ а҆́ще два̀ ѿ ва́съ совѣща́ета на землѝ ѡ҆ всѧ́кой ве́щи, є҆́же а҆́ще про́сита, бꙋ́детъ и҆́ма ѿ ѻ҆ц҃а̀ моегѡ̀ и҆́же на небесѣ́хъ. и҆дѣ́же бо є҆ста̀ два̀ и҆лѝ трїѐ со́брани во и҆́мѧ моѐ, тꙋ̀ є҆́смь посредѣ̀ и҆́хъ. ",
}

add_evangelie_matfea {
  ["номер"] = 76,
  ["комментарий"] = "Мф., 76 зач., XVIII, 18–22; XIX, 1–2, 13–15.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: ами́нь глаго́лю вам, ели́ка а́ще свя́жете на земли́, бу́дут свя́зана на небеси́, и ели́ка а́ще разрешите́ на земли́, бу́дут разреше́на на небесе́х. Па́ки ами́нь глаго́лю вам, я́ко а́ще два от вас совеща́ета на земли́ о вся́кой ве́щи, е́же а́ще про́сита, бу́дет и́ма от Отца́ Моего́, И́же на небесе́х. Иде́же бо еста́ два или́ трие́ со́брани во и́мя Мое́, ту есмь посреде́ их. Тогда́ присту́пль к Нему́ Петр рече́: Го́споди, коль кра́ты а́ще согреши́т в мя брат мой, и отпущу́ ли ему́ до седмь крат? Глаго́ла ему́ Иису́с: не глаго́лю тебе́ до седмь крат, но до се́дмьдесят крат седмери́цею. И бысть егда́ сконча́ Иису́с словеса́ сия́, пре́йде от Галиле́и и прии́де в преде́лы Иуде́йския об он пол Иорда́на. И по Нем идо́ша наро́ди мно́зи, и исцели́ их ту. Тогда́ приведо́ша к Нему́ де́ти, да ру́це возложи́т на них и помо́лится, ученицы́ же запрети́ша им. Иису́с же рече́ им: оста́вите дете́й и не возбраня́йте им приити́ ко Мне, таковы́х бо есть Ца́рство Небе́сное. И возло́жь на них ру́це, оты́де отту́ду. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: а҆ми́нь глаго́лю ва́мъ: є҆ли̑ка а҆́ще свѧ́жете на землѝ, бꙋ́дꙋтъ свѧ̑зана на нб҃сѝ: и҆ є҆ли̑ка а҆́ще разрѣшитѐ на землѝ, бꙋ́дꙋтъ разрѣшє́на на небесѣ́хъ. па́ки а҆ми́нь глаго́лю ва́мъ: ꙗ҆́кѡ а҆́ще два̀ ѿ ва́съ совѣща́ета на землѝ ѡ҆ всѧ́кой ве́щи, є҆́же а҆́ще про́сита, бꙋ́детъ и҆́ма ѿ ѻ҆ц҃а̀ моегѡ̀ и҆́же на небесѣ́хъ. и҆дѣ́же бо є҆ста̀ два̀ и҆лѝ трїѐ со́брани во и҆́мѧ моѐ, тꙋ̀ є҆́смь посредѣ̀ и҆́хъ. тогда̀ пристꙋ́пль къ немꙋ̀ пе́тръ речѐ: гдⷭ҇и, ко́ль кра́ты а҆́ще согрѣши́тъ въ мѧ̀ бра́тъ мо́й, и҆ ѿпꙋщꙋ́ ли є҆мꙋ̀ до се́дмь кра́тъ; глаго́ла є҆мꙋ̀ і҆и҃съ: не глаго́лю тебѣ̀ до се́дмь кра́тъ, но до се́дмьдесѧтъ кра́тъ седмери́цею. и҆ бы́сть є҆гда̀ сконча̀ і҆и҃съ словеса̀ сїѧ̀, пре́йде ѿ галїле́и, и҆ прїи́де въ предѣ́лы і҆ꙋде́йскїѧ ѡ҆б̾ ѻ҆́нъ по́лъ і҆ѻрда́на. и҆ по не́мъ и҆до́ша наро́ди мно́зи, и҆ и҆сцѣлѝ и҆̀хъ тꙋ̀. тогда̀ приведо́ша къ немꙋ̀ дѣ́ти, да рꙋ́цѣ возложи́тъ на ни́хъ, и҆ помо́литсѧ: ᲂу҆чн҃цы́ же запрети́ша и҆̀мъ. і҆и҃съ же речѐ и҆̀мъ: ѡ҆ста́вите дѣте́й, и҆ не возбранѧ́йте и҆̀мъ прїитѝ ко мнѣ̀: таковы́хъ бо є҆́сть црⷭ҇тво нбⷭ҇ное. и҆ возло́жь на ни́хъ рꙋ́цѣ, ѿи́де ѿтꙋ́дꙋ. ",
}

add_evangelie_matfea {
  ["номер"] = 77,
  ["комментарий"] = "Мф., 77 зач., XVIII, 23–35.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: уподо́бися Ца́рствие Небе́сное челове́ку царю́, и́же восхоте́ стяза́тися о словеси́ с рабы́ свои́ми. Наче́ншу же ему́ стяза́тися, приведо́ша ему́ еди́наго должника́ тмо́ю тала́нт. Не иму́щу же ему́ возда́ти, повеле́ и госпо́дь его́ прода́ти, и жену́ его́, и ча́да, и вся, ели́ка име́яше, и отда́ти. Пад у́бо раб той, кла́няшеся ему́, глаго́ля: го́споди, потерпи́ на мне, и вся ти возда́м. Милосе́рдовав же госпо́дь раба́ того́, прости́ его́ и долг отпусти́ ему́. Изше́д же раб той, обре́те еди́наго от клевре́т свои́х, и́же бе до́лжен ему́ стом пе́нязь, и ем его́ давля́ше, глаго́ля: отда́ждь ми, и́мже ми еси́ до́лжен. Пад у́бо клевре́т его́ на но́зе его́, моля́ше его́, глаго́ля: потерпи́ на мне, и вся возда́м ти. Он же не хотя́ше, но вед всади́ его́ в темни́цу, до́ндеже возда́ст до́лжное. Ви́девше же клевре́ти его́ бы́вшая, сжа́лиша си зело́ и прише́дше сказа́ша господи́ну своему́ вся бы́вшая. Тогда́ призва́в его́ господи́н его́, глаго́ла ему́: ра́бе лука́вый, весь долг он отпусти́х тебе́, поне́же умоли́л мя еси́, не подоба́ше ли и тебе́ поми́ловати клевре́та твоего́, я́коже и аз тя поми́ловах? И прогне́вався госпо́дь его́, предаде́ его́ мучи́телем, до́ндеже возда́ст весь долг свой. Та́ко и Оте́ц Мой Небе́сный сотвори́т вам, а́ще не отпустите́ ко́ждо бра́ту своему́ от серде́ц ва́ших прегреше́ния их. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: ᲂу҆подо́бисѧ црⷭ҇твїе нбⷭ҇ное чл҃вѣ́кꙋ царю̀, и҆́же восхотѣ̀ стѧза́тисѧ ѡ҆ словесѝ съ рабы̀ свои́ми. наче́ншꙋ же є҆мꙋ̀ стѧза́тисѧ, приведо́ша є҆мꙋ̀ є҆ди́наго должника̀ тмо́ю тала̑нтъ. не и҆мꙋ́щꙋ же є҆мꙋ̀ возда́ти, повелѣ̀ и҆̀ гдⷭ҇ь є҆гѡ̀ прода́ти, и҆ женꙋ̀ є҆гѡ̀, и҆ ча̑да, и҆ всѧ̑ є҆ли́ка и҆мѣ́ѧше, и҆ ѿда́ти. па́дъ ᲂу҆́бѡ ра́бъ то́й кла́нѧшесѧ є҆мꙋ̀, глаго́лѧ: гдⷭ҇и, потерпѝ на мнѣ̀, и҆ всѧ̑ тѝ возда́мъ. млⷭ҇рдовавъ же гдⷭ҇ь раба̀ тогѡ̀, простѝ є҆го̀, и҆ до́лгъ ѿпꙋстѝ є҆мꙋ̀. и҆зше́дъ же ра́бъ то́й, ѡ҆брѣ́те є҆ди́наго ѿ клеврє́тъ свои́хъ, и҆́же бѣ̀ до́лженъ є҆мꙋ̀ сто́мъ пѣ̑нѧзь, и҆ є҆́мъ є҆го̀ давлѧ́ше, глаго́лѧ: ѿда́ждь мѝ, и҆́мже мѝ є҆сѝ до́лженъ. па́дъ ᲂу҆́бѡ клевре́тъ є҆гѡ̀ на но́зѣ є҆гѡ̀, молѧ́ше є҆го̀, глаго́лѧ: потерпѝ на мнѣ̀, и҆ всѧ̑ возда́мъ тѝ. ѻ҆́нъ же не хотѧ́ше: но ве́дъ всадѝ є҆го̀ въ темни́цꙋ, до́ндеже возда́стъ до́лжное. ви́дѣвше же клевре́ти є҆гѡ̀ бы̑вшаѧ, сжа́лиша сѝ ѕѣлѡ̀ и҆ прише́дше сказа́ша гдⷭ҇и́нꙋ своемꙋ̀ всѧ̑ бы̑вшаѧ. тогда̀ призва́въ є҆го̀ гдⷭ҇и́нъ є҆гѡ̀, глаго́ла є҆мꙋ̀: ра́бе лꙋка́вый, ве́сь до́лгъ ѻ҆́нъ ѿпꙋсти́хъ тебѣ̀, поне́же ᲂу҆моли́лъ мѧ є҆сѝ̀: не подоба́ше ли и҆ тебѣ̀ поми́ловати клевре́та твоего̀, ꙗ҆́коже и҆ а҆́зъ тѧ̀ поми́ловахъ; и҆ прогнѣ́вавсѧ гдⷭ҇ь є҆гѡ̀, предадѐ є҆го̀ мꙋчи́телємъ, до́ндеже возда́стъ ве́сь до́лгъ сво́й. та́кѡ и҆ ѻ҆ц҃ъ мо́й нбⷭ҇ный сотвори́тъ ва́мъ, а҆́ще не ѿпꙋститѐ ко́ждо бра́тꙋ своемꙋ̀ ѿ серде́цъ ва́шихъ прегрѣшє́нїѧ и҆́хъ. ",
}

add_evangelie_matfea {
  ["номер"] = 78,
  ["комментарий"] = "Мф., 78 зач., XIX, 3–12.",
  ["текст_ру"] = "Во вре́мя о́но, приступи́ша ко Иису́су фарисе́е искуша́юще Его́ и глаго́лаша Ему́: а́ще досто́ит челове́ку пусти́ти жену́ свою́ по вся́кой вине́? Он же отвеща́в рече́ им: не́сте ли чли, я́ко Сотвори́вый искони́, му́жеский пол и же́нский сотвори́л я́ есть? И рече́: сего́ ра́ди оста́вит челове́к отца́ своего́ и ма́терь и прилепи́тся к жене́ свое́й, и бу́дета о́ба в плоть еди́ну, я́коже ктому́ не́ста два, но плоть еди́на. Е́же у́бо Бог сочета́, челове́к да не разлуча́ет. Глаго́лаша Ему́: что у́бо Моисе́й запове́да да́ти кни́гу распу́стную и отпусти́ти ю́? Глаго́ла им: я́ко Моисе́й по жестосе́рдию ва́шему повеле́ вам пусти́ти жены́ ва́ша, изнача́ла же не бысть та́ко. Глаго́лю же вам, я́ко и́же а́ще пу́стит жену́ свою́, ра́зве словесе́ прелюбоде́йна, и оже́нится ино́ю, прелюбы́ твори́т, и женя́йся пущени́цею прелюбы́ де́ет. Глаго́лаша Ему́ ученицы́ Его́: а́ще та́ко есть вина́ челове́ку с жено́ю, лу́чше есть не жени́тися. Он же рече́ им: не вси вмеща́ют словесе́ сего́, но и́мже дано́ есть. Суть бо скопцы́, и́же из чре́ва ма́терня роди́шася та́ко, и суть скопцы́, и́же скопи́шася от челове́к, и суть скопцы́, и́же искази́ша са́ми себе́ Ца́рствия ра́ди Небе́снаго. Моги́й вмести́ти да вмести́т. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋпи́ша ко і҆и҃сꙋ фарїсе́є и҆скꙋша́юще є҆го̀, и҆ глаго́лаша є҆мꙋ̀: а҆́ще досто́итъ человѣ́кꙋ пꙋсти́ти женꙋ̀ свою̀ по всѧ́кой винѣ̀; ѻ҆́нъ же ѿвѣща́въ, речѐ и҆̀мъ: нѣ́сте ли члѝ, ꙗ҆́кѡ сотвори́вый и҆сконѝ, мꙋ́жескїй по́лъ и҆ же́нскїй сотвори́лъ ѧ҆̀ є҆́сть; и҆ речѐ: сегѡ̀ ра́ди ѡ҆ста́витъ человѣ́къ ѻ҆тца̀ своего̀ и҆ ма́терь, и҆ прилѣпи́тсѧ къ женѣ̀ свое́й, и҆ бꙋ́дета ѻ҆́ба въ пло́ть є҆ди́нꙋ: ꙗ҆́коже ктомꙋ̀ нѣ́ста два̀, но пло́ть є҆ди́на. є҆́же ᲂу҆́бѡ бг҃ъ сочета̀, человѣ́къ да не разлꙋча́етъ. глаго́лаша є҆мꙋ̀: что̀ ᲂу҆́бѡ мѡѷсе́й заповѣ́да да́ти кни́гꙋ распꙋ́стнꙋю, и҆ ѿпꙋсти́ти ю҆̀; глаго́ла и҆̀мъ: ꙗ҆́кѡ мѡѷсе́й по жестосе́рдїю ва́шемꙋ повелѣ̀ ва́мъ пꙋсти́ти жєны̀ ва́шѧ, и҆з̾нача́ла же не бы́сть та́кѡ. глаго́лю же ва́мъ, ꙗ҆́кѡ и҆́же а҆́ще пꙋ́ститъ женꙋ̀ свою̀, ра́звѣ словесѐ прелюбодѣ́йна, и҆ ѡ҆же́нитсѧ и҆но́ю, прелюбы̀ твори́тъ: и҆ женѧ́йсѧ пꙋщени́цею, прелюбы̀ дѣ́етъ. глаго́лаша є҆мꙋ̀ ᲂу҆ченицы̀ є҆гѡ̀: а҆́ще та́кѡ є҆́сть вина̀ человѣ́кꙋ съ жено́ю, лꙋ́чше є҆́сть не жени́тисѧ. ѻ҆́нъ же речѐ и҆̀мъ: не всѝ вмѣща́ютъ словесѐ сегѡ̀, но и҆̀мже дано̀ є҆́сть. сꙋ́ть бо скопцы̀, и҆̀же и҆з̾ чре́ва ма́тернѧ роди́шасѧ та́кѡ: и҆ сꙋ́ть скопцы̀, и҆̀же скопи́шасѧ ѿ человѣ̑къ: и҆ сꙋ́ть скопцы̀, и҆̀же и҆скази́ша са́ми себѐ црⷭ҇твїѧ ра́ди нбⷭ҇нагѡ. могі́й вмѣсти́ти, да вмѣсти́тъ. ",
}

add_evangelie_matfea {
  ["номер"] = 79,
  ["комментарий"] = "Мф., 79 зач., XIX, 16–26.",
  ["текст_ру"] = "Во вре́мя о́но, ю́ноша не́кий приступи́ ко Иису́су, кла́няяся Ему́ и глаго́ля: Учи́телю благи́й, что бла́го сотворю́, да и́мам живо́т ве́чный? Он же рече́ ему́: что Мя глаго́леши бла́га? Никто́же благ, то́кмо еди́н Бог. А́ще ли хо́щеши вни́ти в живо́т, соблюди́ за́поведи. Глаго́ла Ему́: ки́я? Иису́с же рече́: е́же не убие́ши, не прелюбы́ сотвори́ши, не укра́деши, не лжесвиде́тельствуеши, чти отца́ и ма́терь, и возлю́биши и́скренняго твоего́ я́ко сам себе́. Глаго́ла Ему́ ю́ноша: вся сия́ сохрани́х от ю́ности моея́, что есмь еще́ не доконча́л? Рече́ ему́ Иису́с: а́ще хо́щеши соверше́н бы́ти, иди́, прода́ждь име́ние твое́ и даждь ни́щым, и име́ти и́маши сокро́вище на небеси́, и гряди́ в след Мене́. Слы́шав же ю́ноша сло́во, оты́де скорбя́, бе бо име́я стяжа́ния мно́га. Иису́с же рече́ ученико́м Свои́м: ами́нь глаго́лю вам, я́ко неудо́бь бога́тый вни́дет в Ца́рствие Небе́сное. Па́ки же глаго́лю вам: я́ко  удо́бее есть вельбу́ду сквозе́ иглины́ у́ши проити́, не́же бога́ту в Ца́рствие Бо́жие вни́ти. Слы́шавше же ученицы́ Его́, дивля́хуся зело́, глаго́люще: кто у́бо мо́жет спасе́н бы́ти? Воззре́в же Иису́с рече́ им: у челове́к сие́ невозмо́жно есть, у Бо́га же вся возмо́жна. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ю҆́ноша нѣ́кїй пристꙋпѝ ко і҆и҃сꙋ, кла́нѧѧсѧ є҆мꙋ̀ и҆ глаго́лѧ: ᲂу҆чи́телю бл҃гі́й, что̀ бла́го сотворю̀, да и҆́мамъ живо́тъ вѣ́чный; ѻ҆́нъ же речѐ є҆мꙋ̀: что́ мѧ глаго́леши бл҃га; никто́же бл҃гъ, то́кмѡ є҆ди́нъ бг҃ъ. а҆́ще ли хо́щеши вни́ти въ живо́тъ, соблюдѝ за́пѡвѣди. глаго́ла є҆мꙋ̀: кі́ѧ; і҆и҃съ же речѐ: є҆́же не ᲂу҆бїе́ши, не прелюбы̀ сотвори́ши, не ᲂу҆кра́деши, не лжесвидѣ́тельствꙋеши. чтѝ ѻ҆тца̀ и҆ ма́терь, и҆ возлю́биши и҆́скреннѧго твоего̀ ꙗ҆́кѡ са́мъ себѐ. глаго́ла є҆мꙋ̀ ю҆́ноша: всѧ̑ сїѧ̑ сохрани́хъ ѿ ю҆́ности моеѧ̀, что̀ є҆́смь є҆щѐ не доконча́лъ; речѐ є҆мꙋ̀ і҆и҃съ: а҆́ще хо́щеши соверше́нъ бы́ти, и҆дѝ, прода́ждь и҆мѣ́нїе твоѐ и҆ да́ждь ни́щымъ, и҆ и҆мѣ́ти и҆́маши сокро́вище на небесѝ: и҆ грѧдѝ въ слѣ́дъ менѐ. слы́шавъ же ю҆́ноша сло́во, ѿи́де скорбѧ̀: бѣ́ бо и҆мѣ́ѧ стѧжа̑нїѧ мнѡ́га. і҆и҃съ же речѐ ᲂу҆ченикѡ́мъ свои́мъ: а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ неꙋдо́бь бога́тый вни́детъ въ црⷭ҇твїе нбⷭ҇ное. па́ки же глаго́лю ва́мъ: ꙗ҆́кѡ ᲂу҆до́бѣе є҆́сть вельбꙋ́дꙋ сквозѣ̀ и҆глины̀ ᲂу҆́ши проитѝ, не́же бога́тꙋ въ ца́рствїе бж҃їе вни́ти. слы́шавше же ᲂу҆ченицы̀ є҆гѡ̀, дивлѧ́хꙋсѧ ѕѣлѡ̀, глаго́люще: кто̀ ᲂу҆́бѡ мо́жетъ спасе́нъ бы́ти; воззрѣ́въ же і҆и҃съ речѐ и҆̀мъ: ᲂу҆ человѣ̑къ сїѐ невозмо́жно є҆́сть, ᲂу҆ бг҃а же всѧ̑ возмѡ́жна. ",
}

add_evangelie_matfea {
  ["номер"] = 80,
  ["комментарий"] = "Мф., 80 зач., XX, 1–16.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: уподо́бися Ца́рствие Небе́сное челове́ку домови́ту, и́же изы́де ку́пно у́тро ная́ти де́латели в виногра́д свой, и совеща́в с де́латели по пе́нязю на день, посла́ их в виногра́д свой. И изше́д в тре́тий час, ви́де и́ны стоя́щя на то́ржищи пра́здны, и тем рече́: иди́те и вы в виногра́д мой, и е́же бу́дет пра́вда, дам вам. Они́ же идо́ша. Па́ки же изше́д в шесты́й и девя́тый час, сотвори́ та́коже. Во еди́ный же на́десять час изше́д, обре́те други́я стоя́щя пра́здны и глаго́ла им: что зде стоите́ весь день пра́здни? Глаго́лаша ему́: я́ко никто́же нас ная́т. И глаго́ла им: иди́те и вы в виногра́д мой, и е́же бу́дет пра́ведно, прии́мете. Ве́черу же бы́вшу, глаго́ла господи́н виногра́да к приста́внику своему́: призови́ де́латели и даждь им мзду, наче́н от после́дних до пе́рвых. И прише́дше и́же во единыйна́десять час, прия́ша по пе́нязю. Прише́дше же пе́рвии мня́ху вя́щше прия́ти, и прия́ша и ти́и по пе́нязю. Прие́мше же ропта́ху на господи́на, глаго́люще, я́ко си́и после́днии еди́н час сотвори́ша, и ра́вны нам сотвори́л их еси́, поне́сшым тяготу́ дне и вар. Он же отвеща́в рече́ еди́ному их: дру́же, не оби́жу тебе́, не по пе́нязю ли совеща́ со мно́ю? Возми́ твое́ и иди́, хощу́ же и сему́ после́днему да́ти, я́коже и тебе́. Или́ несть ми леть сотвори́ти, е́же хощу́, во свои́х ми? А́ще о́ко твое́ лука́во есть, я́ко аз благ есмь? Та́ко бу́дут после́днии пе́рви, и пе́рвии после́дни, мно́зи бо суть зва́ни, ма́ло же избра́нных. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: ᲂу҆подо́бисѧ црⷭ҇твїе нбⷭ҇ное человѣ́кꙋ домови́тꙋ, и҆́же и҆зы́де кꙋ́пнѡ ᲂу҆́трѡ наѧ́ти дѣ́латели въ вїногра́дъ сво́й. и҆ совѣща́въ съ дѣ́латели по пѣ́нѧзю на де́нь, посла̀ и҆̀хъ въ вїногра́дъ сво́й. и҆ и҆зше́дъ въ тре́тїй ча́съ, ви́дѣ и҆́ны стоѧ́щѧ на то́ржищи пра́здны. и҆ тѣ́мъ речѐ: и҆ди́те и҆ вы̀ въ вїногра́дъ мо́й, и҆ є҆́же бꙋ́детъ пра́вда, да́мъ ва́мъ. ѻ҆ни́ же и҆до́ша. па́ки же и҆зше́дъ въ шесты́й, и҆ девѧ́тый ча́съ, сотворѝ та́коже. во є҆ди́ный же на́десѧть ча́съ и҆зше́дъ, ѡ҆брѣ́те дрꙋгі̑ѧ стоѧ́щѧ пра́здны, и҆ глаго́ла и҆̀мъ: что̀ здѣ̀ стоитѐ ве́сь де́нь пра́здны; глаго́лаша є҆мꙋ̀, ꙗ҆́кѡ никто́же на́съ наѧ́тъ. и҆ глаго́ла и҆̀мъ: и҆ди́те и҆ вы̀ въ вїногра́дъ мо́й, и҆ є҆́же бꙋ́детъ пра́ведно, прїи́мете. ве́черꙋ же бы́вшꙋ, глаго́ла гдⷭ҇и́нъ вїногра́да къ приста́вникꙋ своемꙋ̀: призовѝ дѣ́латели, и҆ да́ждь и҆̀мъ мздꙋ̀, наче́нъ ѿ послѣ́днихъ до пе́рвыхъ. и҆ прише́дше и҆̀же во є҆диныйна́десѧть ча́съ, прїѧ́ша по пѣ́нѧзю. прише́дше же пе́рвїи мнѧ́хꙋ вѧ́щше прїѧ́ти: и҆ прїѧ́ша и҆ ті́и по пѣ́нѧзю. прїе́мше же ропта́хꙋ на гдⷭ҇и́на, глаго́люще: ꙗ҆́кѡ сі́и послѣ́днїи є҆ди́нъ ча́съ сотвори́ша, и҆ ра́вны на́мъ сотвори́лъ и҆̀хъ є҆сѝ, поне́сшымъ тѧготꙋ̀ днѐ, и҆ ва́ръ. ѻ҆́нъ же ѿвѣща́въ речѐ є҆ди́номꙋ и҆́хъ: дрꙋ́же, не ѡ҆би́жꙋ тебѐ: не по пѣ́нѧзю ли совѣща̀ со мно́ю; воз̾мѝ твоѐ, и҆ и҆дѝ: хощꙋ́ же и҆ семꙋ̀ послѣ́днемꙋ да́ти ꙗ҆́коже и҆ тебѣ̀. и҆лѝ нѣ́сть мѝ лѣ́ть сотвори́ти є҆́же хощꙋ̀ во свои́хъ мѝ; а҆́ще ѻ҆́ко твоѐ лꙋка́во є҆́сть, ꙗ҆́кѡ а҆́зъ бл҃гъ є҆́смь; та́кѡ бꙋ́дꙋтъ послѣ́днїи, пе́рви: и҆ пе́рвїи, послѣ́дни: мно́зи бо сꙋ́ть зва́ни, ма́лѡ же и҆збра́нныхъ. ",
}

add_evangelie_matfea {
  ["номер"] = 81,
  ["комментарий"] = "Мф., 81 зач., XX, 17–28.",
  ["текст_ру"] = "Во вре́мя о́но, восходя́ Иису́с во Иерусали́м, поя́т обана́десять ученика́ еди́ны на пути́ и рече́ им: се восхо́дим во Иерусали́м, и Сын Челове́ческий пре́дан бу́дет архиере́ем и кни́жником, и осу́дят Его́ на смерть, и предадя́т Его́ язы́ком на поруга́ние и бие́ние и пропя́тие, и в тре́тий день воскре́снет. Тогда́ приступи́ к Нему́ ма́ти сы́ну Зеведе́ову с сыно́ма свои́ма, кла́няющися и прося́щи не́что от Него́. Он же рече́ ей: чесо́ хо́щеши? Глаго́ла Ему́: рцы, да ся́дета сия́ о́ба сы́на моя́, еди́н одесну́ю Тебе́, и еди́н ошу́юю Тебе́, во Ца́рствии Твое́м. Отвеща́в же Иису́с рече́: не ве́стася, чесо́ про́сита. Мо́жета ли пи́ти ча́шу, ю́же Аз и́мам пи́ти, или́ креще́нием, и́мже Аз креща́юся, крести́тися? Глаго́ласта Ему́: мо́жева. И глаго́ла и́ма: ча́шу у́бо Мою́ испие́та, и креще́нием, и́мже Аз креща́юся, крести́тися, а е́же се́сти одесну́ю Мене́ и ошу́юю Мене́, несть Мое́ да́ти, но и́мже угото́вася от Отца́ Моего́. И слы́шавше де́сять, негодова́ша о обою́ бра́ту. Иису́с же призва́в их, рече́: ве́сте, я́ко кня́зи язы́к госпо́дствуют и́ми, и вели́цыи облада́ют и́ми. Не та́ко же бу́дет в вас, но и́же а́ще хо́щет в вас вя́щший бы́ти, да бу́дет вам слуга́, и и́же а́ще хо́щет в вас бы́ти пе́рвый, бу́ди вам раб, я́коже Сын Челове́ческий не прии́де, да послу́жат Ему́, но послужи́ти и да́ти ду́шу Свою́ избавле́ние за мно́гих. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, восходѧ̀ і҆и҃съ во і҆ерⷭ҇ли́мъ, поѧ́тъ ѻ҆бана́десѧть ᲂу҆ченика̀ є҆ди́ны на пꙋтѝ, и҆ речѐ и҆̀мъ: сѐ восхо́димъ во і҆ерⷭ҇ли́мъ, и҆ сн҃ъ человѣ́ческїй пре́данъ бꙋ́детъ а҆рхїере́ємъ, и҆ кни́жникѡмъ, и҆ ѡ҆сꙋ́дѧтъ є҆го̀ на сме́рть: и҆ предадѧ́тъ є҆го̀ ꙗ҆зы́кѡмъ на порꙋга́нїе и҆ бїе́нїе и҆ пропѧ́тїе, и҆ въ тре́тїй де́нь воскре́снетъ. тогда̀ пристꙋпѝ къ немꙋ̀ мт҃и сы́нꙋ зеведе́ѡвꙋ съ сыно́ма свои́ма, кла́нѧющисѧ и҆ просѧ́щи нѣ́что ѿ негѡ̀. ѻ҆́нъ же речѐ є҆́й: чесѡ̀ хо́щеши; глаго́ла є҆мꙋ̀: рцы̀, да сѧ́дета сїѧ̀ ѻ҆́ба сы́на моѧ̀, є҆ди́нъ ѡ҆деснꙋ́ю тебѐ, и҆ є҆ди́нъ ѡ҆шꙋ́юю тебѐ во црⷭ҇твїи твое́мъ. ѿвѣща́въ же і҆и҃съ, речѐ: не вѣ́стасѧ чесѡ̀ про́сита. мо́жета ли пи́ти ча́шꙋ, ю҆́же а҆́зъ и҆́мамъ пи́ти; и҆лѝ креще́нїемъ, и҆́мже а҆́зъ креща́юсѧ, крⷭ҇ти́тисѧ; глаго́ласта є҆мꙋ̀: мо́жева. и҆ глаго́ла и҆́ма: ча́шꙋ ᲂу҆́бѡ мою̀ и҆спїе́та, и҆ креще́нїемъ, и҆́мже а҆́зъ креща́юсѧ, крⷭ҇ти́тасѧ: а҆ є҆́же сѣ́сти ѡ҆деснꙋ́ю менѐ, и҆ ѡ҆шꙋ́юю менѐ, нѣ́сть моѐ да́ти, но и҆́мже ᲂу҆гото́васѧ ѿ ѻ҆ц҃а̀ моегѡ̀. и҆ слы́шавше де́сѧть негодова́ша ѡ҆ ѻ҆бою̀ бра́тꙋ. і҆и҃съ же призва́въ и҆̀хъ, речѐ: вѣ́сте, ꙗ҆́кѡ кнѧ́зи ꙗ҆зы̑къ госпо́дствꙋютъ и҆́ми, и҆ вели́цыи ѡ҆блада́ютъ и҆́ми. не та́кѡ же бꙋ́детъ въ ва́съ: но и҆́же а҆́ще хо́щетъ въ ва́съ вѧ́щшїй бы́ти, да бꙋ́детъ ва́мъ слꙋга̀. и҆ и҆́же а҆́ще хо́щетъ въ ва́съ бы́ти пе́рвый, бꙋ́ди ва́мъ ра́бъ. ꙗ҆́коже сн҃ъ чл҃вѣ́ческїй не прїи́де да послꙋ́жатъ є҆мꙋ̀, но послꙋжи́ти, и҆ да́ти дꙋ́шꙋ свою̀ и҆збавле́нїе за мно́гихъ. ",
}

add_evangelie_matfea {
  ["номер"] = 82,
  ["комментарий"] = "Мф., 82 зач., XX, 29–34.",
  ["текст_ру"] = "Во вре́мя о́но, исходя́щу Иису́су от Иерихо́на, по Нем и́де наро́д мног. И се два слепца́ седя́ща при пути́, слы́шавша, я́ко Иису́с мимохо́дит, возопи́ста, глаго́люща: поми́луй ны, Го́споди, Сы́не Дави́дов. Наро́д же запрети́ и́ма, да умолчи́та, о́на же па́че вопия́ста, глаго́люща: поми́луй ны, Го́споди, Сы́не Дави́дов. И воста́в Иису́с возгласи́ я́ и рече́: что хо́щета, да сотворю́ ва́ма? Глаго́ласта Ему́: Го́споди, да отве́рзетеся о́чи на́ю. Милосе́рдовав же Иису́с прикосну́ся о́чию и́ма, и а́бие прозре́ста и́ма о́чи, и по Нем идо́ста. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆сходѧ́щꙋ і҆и҃сꙋ ѿ і҆ерїхѡ́на, по не́мъ и҆́де наро́дъ мно́гъ. и҆ сѐ два̀ слѣпца̀ сѣдѧ́ща при пꙋтѝ, слы́шавша, ꙗ҆́кѡ і҆и҃съ мимохо́дитъ, возопи́ста глаго́люща: поми́лꙋй ны̀ гдⷭ҇и, сн҃е дв҃довъ. наро́дъ же запретѝ и҆́ма да ᲂу҆молчи́та. ѻ҆́на же па́че вопїѧ́ста, глаго́люща: поми́лꙋй ны̀ гдⷭ҇и, сн҃е дв҃довъ. и҆ воста́въ і҆и҃съ возгласѝ ѧ҆̀, и҆ речѐ: что̀ хо́щета да сотворю̀ ва́ма; глаго́ласта є҆мꙋ̀: гдⷭ҇и, да ѿве́рзетѣсѧ ѻ҆́чи на́ю. милосе́рдовавъ же і҆и҃съ, прикоснꙋ́сѧ ѻ҆́чїю и҆́ма: и҆ а҆́бїе прозрѣ́ста и҆́ма ѻ҆́чи, и҆ по не́мъ и҆до́ста. ",
}

add_evangelie_matfea {
  ["номер"] = 83,
  ["комментарий"] = "Мф., 83 зач., XXI, 1–11, 15–17.",
  ["текст_ру"] = "Во вре́мя о́но, егда́ прибли́жися Иису́с во Иерусали́м и приидо́ша в Вифсфаги́ю к горе́ Елео́нстей, тогда́ Иису́с посла́ два ученика́, глаго́ля и́ма: иди́та в весь, я́же пря́мо ва́ма, и а́бие обря́щета осля́ привя́зано, и жребя́ с ним, отреши́вша приведи́та Ми. И а́ще ва́ма кто рече́т что, рече́та, я́ко Госпо́дь ею́ тре́бует, а́бие же по́слет я́. Сие́ же все бысть, да сбу́дется рече́нное проро́ком, глаго́лющим: рцы́те дще́ри Сио́нове, се Царь твой гряде́т тебе́ кро́ток, и всед на осля́ и жребя́, сы́на подъяре́мнича. Ше́дша же ученика́ и сотво́рша, я́коже повеле́ и́ма Иису́с, приведо́ста осля́ и жребя́, и возложи́ша верху́ ею́ ри́зы своя́, и все́де верху́ их. Мно́жайшии же наро́ди постила́ху ри́зы своя́ по пути́, друзи́и же ре́заху ве́тви от древ и постила́ху по пути́. Наро́ди же предходя́щии ему́ и всле́дствующии зва́ху, глаго́люще: оса́нна Сы́ну Дави́дову, благослове́н Гряды́й во и́мя Госпо́дне, оса́нна в вы́шних. И вше́дшу Ему́ во Иерусали́м, потрясе́ся весь град, глаго́ля: кто есть Сей? Наро́ди же глаго́лаху: Сей есть Иису́с Проро́к, и́же от Назаре́та Галиле́йска. Ви́девше же архиере́е и кни́жницы чудеса́, я́же сотвори́, и о́троки зову́щя в це́ркви и глаго́лющя: оса́нна Сы́ну Дави́дову, негодова́ша. И ре́ша Ему́: слы́шиши ли, что си́и глаго́лют? Иису́с же рече́ им: ей, не́сте ли чли николи́же, я́ко изоу́ст младе́нец и ссу́щих соверши́л еси́ хвалу́? И оста́вль их, изы́де вон из гра́да в Вифа́нию и водвори́ся ту. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, є҆гда̀ прибли́жисѧ і҆и҃съ во і҆ерꙋсали́мъ, и҆ прїидо́ша въ виѳсфагі́ю къ горѣ̀ є҆леѡ́нстѣй: тогда̀ і҆и҃съ посла̀ два̀ ᲂу҆ченика̀, глаго́лѧ и҆́ма: и҆ди́та въ ве́сь ꙗ҆́же прѧ́мѡ ва́ма, и҆ а҆́бїе ѡ҆брѧ́щета ѻ҆слѧ̀ привѧ́зано, и҆ жребѧ̀ съ ни́мъ: ѿрѣши́вша приведи́та мѝ. и҆ а҆́ще ва́ма кто̀ рече́тъ что̀, рече́та, ꙗ҆́кѡ гдⷭ҇ь є҆ю̀ тре́бꙋетъ: а҆́бїе же по́слетъ ѧ҆̀. сїе́ же всѐ бы́сть, да сбꙋ́детсѧ рече́нное проро́комъ, глаго́лющимъ: рцы́те дще́ри сїѡ́новѣ, сѐ цр҃ь тво́й грѧде́тъ тебѣ̀ кро́токъ, и҆ всѣ́дъ на ѻ҆слѧ̀ и҆ жребѧ̀, сы́на под̾ѧре́мнича. ше́дша же ᲂу҆ченика̀, и҆ сотво́рша, ꙗ҆́коже повелѣ̀ и҆́ма і҆и҃съ, приведо́ста ѻ҆слѧ̀ и҆ жребѧ̀, и҆ возложи́ша верхꙋ̀ є҆ю̀ ри̑зы своѧ̀, и҆ всѣ́де верхꙋ̀ и҆́хъ. мно́жайшїи же наро́ди постила́хꙋ ри̑зы своѧ̀ по пꙋтѝ: дрꙋзі́и же рѣ́захꙋ вѣ̑тви ѿ дре́въ, и҆ постила́хꙋ по пꙋтѝ. наро́ди же предходѧ́щїи є҆мꙋ̀ и҆ вслѣ́дствꙋющїи, зва́хꙋ глаго́люще: ѡ҆са́нна сн҃ꙋ дв҃довꙋ, бл҃гослове́нъ грѧды́й во и҆́мѧ гдⷭ҇не: ѡ҆са́нна въ вы́шнихъ. и҆ вше́дшꙋ є҆мꙋ̀ во і҆ерⷭ҇ли́мъ, потрѧсе́сѧ ве́сь гра́дъ, глаго́лѧ: кто́ є҆сть се́й; наро́ди же глаго́лахꙋ: се́й є҆́сть і҆и҃съ проро́къ, и҆́же ѿ назаре́та галїле́йска. ви́дѣвше же а҆рхїере́є и҆ кни́жницы чꙋдеса̀ ꙗ҆̀же сотворѝ, и҆ ѻ҆́троки зовꙋ́щѧ въ цр҃кви, и҆ глаго́лющѧ: ѡ҆са́нна сн҃ꙋ дв҃довꙋ, негодова́ша. и҆ рѣ́ша є҆мꙋ̀: слы́шиши ли, что̀ сі́и глаго́лютъ; і҆и҃съ же речѐ и҆̀мъ: є҆́й. нѣ́сте ли члѝ николи́же, ꙗ҆́кѡ и҆зоꙋ́стъ младе́нєцъ и҆ ссꙋ́щихъ сверши́лъ є҆сѝ хвалꙋ̀; и҆ ѡ҆ста́вль и҆̀хъ, и҆зы́де во́нъ и҆з̾ гра́да въ виѳа́нїю, и҆ водвори́сѧ тꙋ̀. ",
}

add_evangelie_matfea {
  ["номер"] = 83,
  ["комментарий"] = "Мф., 83 зач., XXI, 12–14, 17–20.",
  ["текст_ру"] = "Во вре́мя о́но, вни́де Иису́с в це́рковь Бо́жию и изгна́ вся продаю́щыя и купу́ющыя в це́ркви, и трапе́зы торжнико́м испрове́рже и седа́лища продаю́щих го́луби, и глаго́ла им: пи́сано есть, храм Мой храм моли́твы нарече́тся, вы же сотвори́сте и верте́п разбо́йником. И приступи́ша к Нему́ хро́мии и слепи́и в це́ркви, и исцели́ их. И оста́вль их, изы́де вон из гра́да в Вифа́нию и водвори́ся ту. У́тру же возвра́щься во град, взалка́, и узре́в смоко́вницу еди́ну при пути́, прии́де к ней, и ничто́же обре́те на ней, то́кмо ли́ствие еди́но, и глаго́ла ей: да николи́же от тебе́ плода́ бу́дет во ве́ки. И а́бие и́зсше смоко́вница. И ви́девше ученицы́ диви́шася, глаго́люще: ка́ко а́бие и́зсше смоко́вница? ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, вни́де і҆и҃съ въ цр҃ковь бж҃їю, и҆ и҆згна̀ всѧ̑ продаю́щыѧ, и҆ кꙋпꙋ́ющыѧ въ це́ркви, и҆ трапє́зы торжникѡ́мъ и҆спрове́рже, и҆ сѣда̑лища продаю́щихъ го́лꙋби. и҆ глаго́ла и҆̀мъ: пи́сано є҆́сть, хра́мъ мо́й, хра́мъ моли́твы нарече́тсѧ: вы́ же сотвори́сте и҆̀ верте́пъ разбо́йникѡмъ. и҆ пристꙋпи́ша къ немꙋ̀ хро́мїи и҆ слѣпі́и въ цр҃кви: и҆ и҆сцѣлѝ и҆̀хъ. и҆ ѡ҆ста́вль и҆̀хъ, и҆зы́де во́нъ и҆з̾ гра́да въ виѳа́нїю, и҆ водвори́сѧ тꙋ̀. ᲂу҆́трꙋ же возвра́щсѧ во гра́дъ, взалка̀. и҆ ᲂу҆зрѣ́въ смоко́вницꙋ є҆ди́нꙋ при пꙋтѝ, прїи́де къ не́й, и҆ ничто́же ѡ҆брѣ́те на не́й, то́кмѡ ли́ствїе є҆ди́но, и҆ глаго́ла є҆́й: да николи́же ѿ тебѐ плода̀ бꙋ́детъ во вѣ́ки. и҆ а҆́бїе и҆́зсше смоко́вница. и҆ ви́дѣвше ᲂу҆ч҃нцы̀ диви́шасѧ, глаго́люще: ка́кѡ а҆́бїе и҆́зсше смоко́вница; ",
}

add_evangelie_matfea {
  ["номер"] = 84,
  ["комментарий"] = "Мф., 84 зач., XXI, 18–22.",
  ["текст_ру"] = "Во вре́мя о́но, возвра́щься Иису́с во град, взалка́. И узре́в смоко́вницу еди́ну при пути́, прии́де к ней, и ничто́же обре́те на ней, то́кмо ли́ствие еди́но, и глаго́ла ей: да николи́же от тебе́ плода́ бу́дет во ве́ки. И а́бие и́зсше смоко́вница. И ви́девше ученицы́ диви́шася, глаго́люще: ка́ко а́бие и́зсше смоко́вница? Отвеща́в же Иису́с рече́ им: ами́нь глаго́лю вам, а́ще и́мате ве́ру и не усумните́ся, не то́кмо смоко́вничное сотворите́, но а́ще и горе́ сей рече́те: дви́гнися и ве́рзися в мо́ре, бу́дет. И вся, ели́ка а́ще воспро́сите в моли́тве ве́рующе, прии́мете. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, возвра́щсѧ і҆и҃съ во гра́дъ, взалка̀. и҆ ᲂу҆зрѣ́въ смоко́вницꙋ є҆ди́нꙋ при пꙋтѝ, прїи́де къ не́й, и҆ ничто́же ѡ҆брѣ́те на не́й, то́кмѡ ли́ствїе є҆ди́но, и҆ глаго́ла є҆́й: да николи́же ѿ тебѐ плода̀ бꙋ́детъ во вѣ́ки. и҆ а҆́бїе и҆́зсше смоко́вница. и҆ ви́дѣвше ᲂу҆ч҃нцы̀ диви́шасѧ, глаго́люще: ка́кѡ а҆́бїе и҆́зсше смоко́вница; ѿвѣща́въ же і҆и҃съ речѐ и҆̀мъ: а҆ми́нь глаго́лю ва́мъ: а҆́ще и҆́мате вѣ́рꙋ, и҆ не ᲂу҆сꙋмните́сѧ, не то́кмѡ смоко́вничное сотворитѐ: но а҆́ще и҆ горѣ̀ се́й рече́те: дви́гнисѧ и҆ ве́рзисѧ въ мо́ре, бꙋ́детъ. и҆ всѧ̑, є҆ли̑ка а҆́ще воспро́сите въ моли́твѣ вѣ́рꙋюще, прїи́мете. ",
}

add_evangelie_matfea {
  ["номер"] = 84,
  ["комментарий"] = "Мф., 84 зач., XXI, 18–43.",
  ["текст_ру"] = "Во вре́мя о́но, возвра́щься Иису́с во град, взалка́. И узре́в смоко́вницу еди́ну при пути́, прии́де к ней, и ничто́же обре́те на ней, то́кмо ли́ствие еди́но, и глаго́ла ей: да николи́же от тебе́ плода́ бу́дет во ве́ки. И а́бие и́зсше смоко́вница. И ви́девше ученицы́ диви́шася, глаго́люще: ка́ко а́бие и́зсше смоко́вница? Отвеща́в же Иису́с рече́ им: ами́нь глаго́лю вам, а́ще и́мате ве́ру и не усумни́теся, не то́кмо смоко́вничное сотворите́, но а́ще и горе́ сей рече́те: дви́гнися и ве́рзися в мо́ре, бу́дет. И вся, ели́ка а́ще воспро́сите в моли́тве ве́рующе, прии́мете. И прише́дшу Ему́ в це́рковь, приступи́ша к Нему́ уча́щу архиере́е и ста́рцы людсти́и, глаго́люще: ко́ею вла́стию сия́ твори́ши? И кто Ти даде́ власть сию́? Отвеща́в же Иису́с рече́ им: вопрошу́ вы и Аз сло́во еди́но, е́же а́ще рече́те Мне, и Аз вам реку́, ко́ею вла́стию сия́ творю́, креще́ние Иоа́нново отку́ду бе? С небесе́ ли, или́ от челове́к? Они́ же помышля́ху в себе́, глаго́люще: а́ще рече́м, с небесе́, рече́т нам: почто́ у́бо не ве́ровасте ему́? А́ще ли рече́м, от челове́к, бои́мся наро́да, вси бо и́мут Иоа́нна я́ко проро́ка. И отвеща́вше Иису́сови ре́ша: не ве́мы. Рече́ им и Той: ни Аз вам глаго́лю, ко́ею вла́стию сия́ творю́. Что же ся вам мнит? Челове́к не́кий имя́ше два сы́на, и прише́д к пе́рвому, рече́: ча́до, иди́ днесь, де́лай в виногра́де мое́м. Он же отвеща́в рече́: не хощу́, последи́ же раска́явся, и́де. И присту́пль к друго́му, рече́ та́коже. Он же отвеща́в рече́: аз, го́споди иду́, и не и́де. Кий от обою́ сотвори́ во́лю о́тчу? Глаго́лаша Ему́: пе́рвый. Глаго́ла им Иису́с: ами́нь глаго́лю вам, я́ко мытари́ и любоде́йцы варя́ют вы в Ца́рствии Бо́жии. Прии́де бо к вам Иоа́нн Крести́тель путе́м пра́ведным, и не ве́ровасте ему́, мытари́ же и любоде́йцы ве́роваша ему́, вы же ви́девше, не раска́ястеся последи́ ве́ровати ему́. И́ну при́тчу слы́шите. Челове́к не́кий бе домови́т, и́же насади́ виногра́д, и опло́том огради́ его́, и ископа́ в нем точи́ло, и созда́ столп, и вдаст и де́лателем, и оты́де. Егда́ же прибли́жися вре́мя плодо́в, посла́ рабы́ своя́ к де́лателем прия́ти плоды́ его́, и е́мше де́лателе рабы́ его́, о́ваго у́бо би́ша, о́ваго же уби́ша, о́ваго же ка́мением поби́ша. Па́ки посла́ и́ны рабы́ мно́жайшя пе́рвых, и сотвори́ша им та́коже. Последи́ же посла́ к ним сы́на своего́, глаго́ля: усрамя́тся сы́на моего́. Де́лателе же ви́девше сы́на, ре́ша в себе́: сей есть насле́дник, прииди́те, убие́м его́ и удержи́м достоя́ние его́. И е́мше его́ изведо́ша вон из виногра́да и уби́ша. Егда́ у́бо прии́дет господи́н виногра́да, что сотвори́т де́лателем тем? Глаго́лаша Ему́: злых зле погуби́т их, и виногра́д преда́ст ины́м де́лателем, и́же воздадя́т ему́ плоды́ во времена́ своя́. Глаго́ла им Иису́с: не́сте ли чли николи́же в Писа́ниих, ка́мень, его́же не в ряду́ сотвори́ша зи́ждущии, сей бысть во главу́ у́гла? От Го́спода бысть сие́, и есть ди́вно во о́чию ва́шею. Сего́ ра́ди глаго́лю вам, я́ко оти́мется от вас Ца́рствие Бо́жие и да́стся язы́ку творя́щему плоды́ его́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, возвра́щсѧ і҆и҃съ во гра́дъ, взалка̀. и҆ ᲂу҆зрѣ́въ смоко́вницꙋ є҆ди́нꙋ при пꙋтѝ, прїи́де къ не́й, и҆ ничто́же ѡ҆брѣ́те на не́й, то́кмѡ ли́ствїе є҆ди́но, и҆ глаго́ла є҆́й: да николи́же ѿ тебѐ плода̀ бꙋ́детъ во вѣ́ки. и҆ а҆́бїе и҆́зсше смоко́вница. и҆ ви́дѣвше ᲂу҆ч҃нцы̀ диви́шасѧ, глаго́люще: ка́кѡ а҆́бїе и҆́зсше смоко́вница; ѿвѣща́въ же і҆и҃съ речѐ и҆̀мъ: а҆ми́нь глаго́лю ва́мъ: а҆́ще и҆́мате вѣ́рꙋ, и҆ не ᲂу҆сꙋмните́сѧ, не то́кмѡ смоко́вничное сотворитѐ: но а҆́ще и҆ горѣ̀ се́й рече́те: дви́гнисѧ и҆ ве́рзисѧ въ мо́ре, бꙋ́детъ. и҆ всѧ̑, є҆ли̑ка а҆́ще воспро́сите въ моли́твѣ вѣ́рꙋюще, прїи́мете. и҆ прише́дшꙋ є҆мꙋ̀ въ це́рковь, пристꙋпи́ша къ немꙋ̀ ᲂу҆ча́щꙋ а҆рхїере́є и҆ ста́рцы людсті́и, глаго́люще: ко́ею вла́стїю сїѧ̑ твори́ши; и҆ кто́ ти дадѐ вла́сть сїю̀; ѿвѣща́въ же і҆и҃съ, речѐ и҆̀мъ: вопрошꙋ̀ вы̀ и҆ а҆́зъ сло́во є҆ди́но, є҆́же а҆́ще рече́те мнѣ̀, и҆ а҆́зъ ва́мъ рекꙋ̀, ко́ею вла́стїю сїѧ̑ творю̀. креще́нїе і҆ѡа́нново ѿкꙋ́дꙋ бѣ̀: съ небесе́ ли, и҆лѝ ѿ человѣ̑къ; ѻ҆ни́ же помышлѧ́хꙋ въ себѣ̀, глаго́люще: а҆́ще рече́мъ, съ небесѐ: рече́тъ на́мъ, почто̀ ᲂу҆́бѡ не вѣ́ровасте є҆мꙋ̀; а҆́ще ли рече́мъ, ѿ человѣ̑къ: бои́мсѧ наро́да, вси́ бо и҆́мꙋтъ і҆ѡа́нна ꙗ҆́кѡ проро́ка. и҆ ѿвѣща́вше і҆и҃сови рѣ́ша: не вѣ́мы. речѐ и҆̀мъ и҆ то́й: ни а҆́зъ ва́мъ глаго́лю, ко́ею вла́стїю сїѧ̑ творю̀. что́ же сѧ ва́мъ мни́тъ; человѣ́къ нѣ́кїй и҆мѧ́ше два̀ сы́на, и҆ прише́дъ къ пе́рвомꙋ речѐ: ча́до, и҆дѝ дне́сь дѣ́лай въ вїногра́дѣ мое́мъ. ѻ҆́нъ же ѿвѣща́въ речѐ: не хощꙋ̀. послѣди́ же раска́ѧвсѧ и҆́де. и҆ пристꙋ́пль къ дрꙋго́мꙋ, речѐ та́коже. ѻ҆́нъ же ѿвѣща́въ речѐ: а҆́зъ гдⷭ҇и и҆дꙋ̀. и҆ не и҆́де. кі́й ѿ ѻ҆бою̀ сотворѝ во́лю ѻ҆́ч҃ꙋ! глаго́лаша є҆мꙋ̀: пе́рвый. глаго́ла и҆̀мъ і҆и҃съ: а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ мытарѝ, и҆ любодѣ́йцы варѧ́ютъ вы̀ въ црⷭ҇твїи бж҃їи. прїи́де бо къ ва́мъ і҆ѡа́ннъ крести́тель пꙋте́мъ пра́веднымъ, и҆ не вѣ́ровасте є҆мꙋ̀: мытари́ же и҆ любодѣ́йцы вѣ́роваша є҆мꙋ̀. вы́ же ви́дѣвше не раска́ѧстесѧ послѣдѝ, вѣ́ровати є҆мꙋ̀. и҆́нꙋ при́тчꙋ слы́шите: человѣ́къ нѣ́кїй бѣ̀ домови́тъ, и҆́же насадѝ вїногра́дъ, и҆ ѡ҆пло́томъ ѡ҆градѝ є҆го̀, и҆ и҆скопа̀ въ не́мъ точи́ло, и҆ созда̀ сто́лпъ, и҆ вда́стъ и҆̀ дѣ́лателємъ: и҆ ѿи́де. є҆гда́ же прибли́жисѧ вре́мѧ плодѡ́въ, посла̀ рабы̑ своѧ̀ къ дѣ́лателємъ, прїѧ́ти плоды̀ є҆гѡ̀. и҆ є҆́мше дѣ́лателє рабы̑ є҆гѡ̀, ѻ҆́ваго ᲂу҆́бѡ би́ша, ѻ҆́ваго же ᲂу҆би́ша, ѻ҆́ваго же ка́менїемъ поби́ша. па́ки посла̀ и҆́ны рабы̑ мно́жайшѧ пе́рвыхъ: и҆ сотвори́ша и҆̀мъ та́коже. послѣди́ же посла̀ къ ни́мъ сн҃а своего̀, глаго́лѧ: ᲂу҆срамѧ́тсѧ сн҃а моегѡ̀. дѣ́лателє же ви́дѣвше сн҃а, рѣ́ша въ себѣ̀: се́й є҆́сть наслѣ́дникъ, прїиди́те, ᲂу҆бїе́мъ є҆го̀, и҆ ᲂу҆держи́мъ достоѧ́нїе є҆гѡ̀. и҆ є҆́мше є҆го̀, и҆зведо́ша во́нъ и҆з̾ вїногра́да, и҆ ᲂу҆би́ша. є҆гда̀ ᲂу҆́бѡ прїи́детъ гдⷭ҇и́нъ вїногра́да, что̀ сотвори́тъ дѣ́лателємъ тѣ́мъ; глаго́лаша є҆мꙋ̀: ѕлы́хъ ѕлѣ̀ погꙋби́тъ и҆̀хъ, и҆ вїногра́дъ преда́стъ и҆ны́мъ дѣ́лателємъ, и҆̀же воздадѧ́тъ є҆мꙋ̀ плоды̀ во времена̀ своѧ̀. глаго́ла и҆̀мъ і҆и҃съ: нѣ́сте ли члѝ николи́же въ писа́нїихъ: ка́мень, є҆го́же не въ рѧдꙋ̀ сотвори́ша зи́ждꙋщїи, се́й бы́сть во главꙋ̀ ᲂу҆́гла, ѿ гдⷭ҇а бы́сть се́й, и҆ є҆́сть ди́вна во ѻ҆́чїю ва́шею. сегѡ̀ ра́ди глаго́лю ва́мъ, ꙗ҆́кѡ ѿи́метсѧ ѿ ва́съ црⷭ҇твїе бж҃їе, и҆ да́стсѧ ꙗ҆зы́кꙋ творѧ́щемꙋ плоды̀ є҆гѡ̀. ",
}

add_evangelie_matfea {
