  ["номер"] = 87,
  ["комментарий"] = "Мф., 87 зач., XXI, 33–42.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: челове́к не́кий бе домови́т, и́же насади́ виногра́д, и опло́том огради́ его́, и ископа́ в нем точи́ло, и созда́ столп, и вдаст и де́лателем, и оты́де. Егда́ же прибли́жися вре́мя плодо́в, посла́ рабы́ своя́ к де́лателем прия́ти плоды́ его́, и е́мше де́лателе рабы́ его́, о́ваго у́бо би́ша, о́ваго же уби́ша, о́ваго же ка́мением поби́ша. Па́ки посла́ и́ны рабы́ мно́жайшя пе́рвых, и сотвори́ша им та́коже. Последи́ же посла́ к ним сы́на своего́, глаго́ля: усрамя́тся сы́на моего́. Де́лателе же ви́девше сы́на, ре́ша в себе́: сей есть насле́дник, прииди́те, убие́м его́ и удержи́м достоя́ние его́. И е́мше его́ изведо́ша вон из виногра́да и уби́ша. Егда́ у́бо прии́дет господи́н виногра́да, что сотвори́т де́лателем тем? Глаго́лаша Ему́: злых зле погуби́т их, и виногра́д преда́ст ины́м де́лателем, и́же воздадя́т ему́ плоды́ во времена́ своя́. Глаго́ла им Иису́с: не́сте ли чли николи́же в Писа́ниих, ка́мень, его́же не в ряду́ сотвори́ша зи́ждущии, сей бысть во главу́ у́гла? От Го́спода бысть сие́, и есть ди́вно во о́чию ва́шею. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: человѣ́къ нѣ́кїй бѣ̀ домови́тъ, и҆́же насадѝ вїногра́дъ, и҆ ѡ҆пло́томъ ѡ҆градѝ є҆го̀, и҆ и҆скопа̀ въ не́мъ точи́ло, и҆ созда̀ сто́лпъ, и҆ вда́стъ и҆̀ дѣ́лателємъ: и҆ ѿи́де. є҆гда́ же прибли́жисѧ вре́мѧ плодѡ́въ, посла̀ рабы̑ своѧ̀ къ дѣ́лателємъ, прїѧ́ти плоды̀ є҆гѡ̀. и҆ є҆́мше дѣ́лателє рабы̑ є҆гѡ̀, ѻ҆́ваго ᲂу҆́бѡ би́ша, ѻ҆́ваго же ᲂу҆би́ша, ѻ҆́ваго же ка́менїемъ поби́ша. па́ки посла̀ и҆́ны рабы̑ мно́жайшѧ пе́рвыхъ: и҆ сотвори́ша и҆̀мъ та́коже. послѣди́ же посла̀ къ ни́мъ сн҃а своего̀, глаго́лѧ: ᲂу҆срамѧ́тсѧ сн҃а моегѡ̀. дѣ́лателє же ви́дѣвше сн҃а, рѣ́ша въ себѣ̀: се́й є҆́сть наслѣ́дникъ, прїиди́те, ᲂу҆бїе́мъ є҆го̀, и҆ ᲂу҆держи́мъ достоѧ́нїе є҆гѡ̀. и҆ є҆́мше є҆го̀, и҆зведо́ша во́нъ и҆з̾ вїногра́да, и҆ ᲂу҆би́ша. є҆гда̀ ᲂу҆́бѡ прїи́детъ гдⷭ҇и́нъ вїногра́да, что̀ сотвори́тъ дѣ́лателємъ тѣ́мъ; глаго́лаша є҆мꙋ̀: ѕлы́хъ ѕлѣ̀ погꙋби́тъ и҆̀хъ, и҆ вїногра́дъ преда́стъ и҆ны́мъ дѣ́лателємъ, и҆̀же воздадѧ́тъ є҆мꙋ̀ плоды̀ во времена̀ своѧ̀. глаго́ла и҆̀мъ і҆и҃съ: нѣ́сте ли члѝ николи́же въ писа́нїихъ: ка́мень, є҆го́же не въ рѧдꙋ̀ сотвори́ша зи́ждꙋщїи, се́й бы́сть во главꙋ̀ ᲂу҆́гла, ѿ гдⷭ҇а бы́сть се́й, и҆ є҆́сть ди́вна во ѻ҆́чїю ва́шею. ",
}

add_evangelie_matfea {
