  ["комментарий"] = "Мф., 88 зач., XXI, 43-46.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: глаго́лю вам, я́ко оти́мется от вас Ца́рствие Бо́жие и да́стся язы́ку творя́щему плоды́ его́. И пады́й на ка́мени сем сокруши́тся, а на не́мже паде́т, сотры́ет и́. И слы́шавше архиере́е и фарисе́е при́тчи Его́, разуме́ша, я́ко о них глаго́лет, и и́щуще Его́ я́ти, убоя́шася наро́да, поне́же я́ко Проро́ка Его́ име́яху. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: глаго́лю ва́мъ, ꙗ҆́кѡ ѿи́метсѧ ѿ ва́съ црⷭ҇твїе бж҃їе, и҆ да́стсѧ ꙗ҆зы́кꙋ творѧ́щемꙋ плоды̀ є҆гѡ̀. и҆ пады́й на ка́мени се́мъ, сокрꙋши́тсѧ: а҆ на не́мже паде́тъ, сотры́етъ и҆̀. и҆ слы́шавше а҆рхїере́є и҆ фарїсе́є при̑тчи є҆гѡ̀, разꙋмѣ́ша, ꙗ҆́кѡ ѡ҆ ни́хъ глаго́летъ. и҆ и҆́щꙋще є҆го̀ ꙗ҆́ти, ᲂу҆боѧ́шасѧ наро́да: поне́же ꙗ҆́кѡ проро́ка є҆го̀ и҆мѣ́ѧхꙋ. ",
}

add_evangelie_matfea {
  ["номер"] = 89,
  ["комментарий"] = "Мф., 89 зач., XXII, 1–14.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: уподо́бися Ца́рствие Небе́сное челове́ку царю́, и́же сотвори́ бра́ки сы́ну своему́ и посла́ рабы́ своя́ призва́ти зва́нныя на бра́ки, и не хотя́ху приити́. Па́ки посла́ и́ны рабы́, глаго́ля: рцы́те зва́нным, се обе́д мой угото́вах, юнцы́ мои́ и упита́нная исколе́на, и вся гото́ва, прииди́те на бра́ки. Они́ же небре́гше отидо́ша, ов у́бо на село́ свое́, ов же на ку́пли своя́, про́чии же е́мше рабы́ его́, досади́ша им и уби́ша их. И слы́шав царь той разгне́вася, и посла́в во́я своя́, погуби́ уби́йцы о́ны и град их зажже́. Тогда́ глаго́ла рабо́м свои́м: брак у́бо гото́в есть, зва́ннии же не бы́ша досто́йни, иди́те у́бо на исхо́дища путе́й, и ели́цех а́ще обря́щете, призови́те на бра́ки. И изше́дше раби́ они́ на распу́тия, собра́ша всех, ели́цех обрето́ша, злы́я же и до́брыя, и испо́лнися брак возлежа́щих. Вшед же царь ви́дети возлежа́щих, ви́де ту челове́ка не оболче́на во одея́ние бра́чное, и глаго́ла ему́: дру́же, ка́ко вшел еси́ се́мо не имы́й одея́ния бра́чна? Он же умолча́. Тогда́ рече́ царь слуга́м: связа́вше ему́ ру́це и но́зе, возьми́те его́ и вве́рзите во тму кроме́шнюю, ту бу́дет плачь и скре́жет зубо́м, мно́зи бо суть зва́ни, ма́ло же избра́нных. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: ᲂу҆подо́бисѧ црⷭ҇твїе нбⷭ҇ное чл҃вѣ́кꙋ цр҃ю̀, и҆́же сотворѝ бра́ки сн҃ꙋ своемꙋ̀. и҆ посла̀ рабы̑ своѧ̀, призва́ти зва̑нныѧ на бра́ки: и҆ не хотѧ́хꙋ прїитѝ. па́ки посла̀ и҆́ны рабы̑, глаго́лѧ: рцы́те зва̑ннымъ, сѐ ѡ҆бѣ́дъ мо́й ᲂу҆гото́вахъ, ю҆нцы̀ моѝ и҆ ᲂу҆пита̑ннаѧ и҆сколє́на, и҆ всѧ̀ готѡ́ва: прїиди́те на бра́ки. ѻ҆ни́ же небре́гше ѿидо́ша, ѻ҆́въ ᲂу҆́бѡ на село̀ своѐ, ѻ҆́въ же на кꙋ̑пли своѧ̀. про́чїи же є҆́мше рабы̑ є҆гѡ̀, досади́ша и҆̀мъ, и҆ ᲂу҆би́ша и҆̀хъ. и҆ слы́шавъ ца́рь то́й разгнѣ́васѧ, и҆ посла́въ вѡ́ѧ своѧ̀, погꙋбѝ ᲂу҆бі́йцы ѻ҆́ны, и҆ гра́дъ и҆́хъ зажжѐ. тогда̀ глаго́ла рабѡ́мъ свои́мъ: бра́къ ᲂу҆́бѡ гото́въ є҆́сть, зва́ннїи же не бы́ша досто́йни. и҆ди́те ᲂу҆́бѡ на и҆схѡ́дища пꙋте́й, и҆ є҆ли́цѣхъ а҆́ще ѡ҆брѧ́щете, призови́те на бра́ки. и҆ и҆зше́дше рабѝ ѻ҆́ни на распꙋ́тїѧ, собра́ша всѣ́хъ є҆ли́цѣхъ ѡ҆брѣто́ша, ѕлы̑ѧ же и҆ дѡ́брыѧ: и҆ и҆спо́лнисѧ бра́къ возлежа́щихъ. вше́дъ же цр҃ь ви́дѣти возлежа́щихъ, ви́дѣ тꙋ̀ человѣ́ка не ѡ҆болче́на во ѡ҆дѣѧ́нїе бра́чное: и҆ глаго́ла є҆мꙋ̀: дрꙋ́же, ка́кѡ вше́лъ є҆сѝ сѣ́мѡ, не и҆мы́й ѡ҆дѣѧ́нїѧ бра́чна; ѻ҆́нъ же ᲂу҆молча̀. тогда̀ речѐ цр҃ь слꙋга́мъ: свѧза́вше є҆мꙋ̀ рꙋ́цѣ и҆ но́зѣ, воз̾ми́те є҆го̀, и҆ вве́рзите во тмꙋ̀ кромѣ́шнюю: тꙋ̀ бꙋ́детъ пла́чь и҆ скре́жетъ зꙋбѡ́мъ. мно́зи бо сꙋ́ть зва́ни, ма́лѡ же и҆збра́нныхъ. ",
}

add_evangelie_matfea {
  ["номер"] = 90,
  ["комментарий"] = "Мф., 90 зач., XXII, 15-22.",
  ["текст_ру"] = "Во вре́мя о́но, сове́т прие́мше вси фарисе́е на Иису́са, я́ко да обольстя́т Его́ сло́вом, посыла́ют к Нему́ ученики́ своя́ со иродиа́ны, глаго́люще: Учи́телю, ве́мы, я́ко и́стинен еси́, и пути́ Бо́жию вои́стинну учи́ши, и неради́ши ни о ко́мже, не зри́ши бо на лице́ челове́ком. Рцы у́бо нам, что Ти ся мнит? Досто́йно ли есть да́ти кинсо́н ке́сареви, или́ ни? Разуме́в же Иису́с лука́вство их, рече́: что Мя искуша́ете, лицеме́ри? Покажи́те Ми злати́цу кинсо́нную. Они́ же принесо́ша Ему́ пе́нязь. И глаго́ла им: чий о́браз сей и написа́ние? И глаго́лаша Ему́: ке́сарев. Тогда́ глаго́ла им: воздади́те у́бо ке́сарева ке́сареви, и Бо́жия Бо́гови. И слы́шавше диви́шася, и оста́вльше Его́ отидо́ша. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, совѣ́тъ прїе́мше всѝ фарїсе́є на і҆и҃са, ꙗ҆́кѡ да ѡ҆больстѧ́тъ є҆го̀ сло́вомъ, посыла́ютъ къ немꙋ̀ ᲂу҆чн҃кѝ своѧ̀ съ и҆рѡдїа́ны, глаго́люще: ᲂу҆чи́телю, вѣ́мы, ꙗ҆́кѡ и҆́стиненъ є҆сѝ, и҆ пꙋтѝ бж҃їю вои́стиннꙋ ᲂу҆чи́ши, и҆ неради́ши ни ѡ҆ ко́мже: не зри́ши бо на лицѐ чл҃вѣ́кѡмъ. рцы̀ ᲂу҆́бѡ на́мъ, что́ ти сѧ мни́тъ; досто́йно ли є҆́сть да́ти кинсо́нъ ке́сареви, и҆лѝ нѝ; разꙋмѣ́въ же і҆и҃съ лꙋка́вство и҆́хъ, речѐ: что́ мѧ и҆скꙋша́ете лицемѣ́ри; покажи́те мѝ злати́цꙋ кинсо́ннꙋю. ѻ҆ни́ же принесо́ша є҆мꙋ̀ пѣ́нѧзь. и҆ глаго́ла и҆̀мъ: чі́й ѻ҆́бразъ се́й и҆ написа́нїе; и҆ глаго́лаша є҆мꙋ̀: ке́саревъ. тогда̀ глаго́ла и҆̀мъ: воздади́те ᲂу҆́бѡ ке́сарєва ке́сареви, и҆ бж҃їѧ бг҃ови. и҆ слы́шавше диви́шасѧ: и҆ ѡ҆ста́вльше є҆го̀ ѿидо́ша. ",
}

add_evangelie_matfea {
  ["номер"] = 90,
  ["комментарий"] = "Мф., 90 зач., XXII, 15 – XXIII, 39.",
  ["текст_ру"] = "Во вре́мя о́но, сове́т прие́мше вси фарисе́е на Иису́са, я́ко да обольстя́т Его́ сло́вом, посыла́ют к Нему́ ученики́ своя́ со иродиа́ны, глаго́люще: Учи́телю, ве́мы, я́ко и́стинен еси́, и пути́ Бо́жию вои́стинну учи́ши, и неради́ши ни о ко́мже, не зри́ши бо на лице́ челове́ком, рцы у́бо нам, что Ти ся мнит? Досто́йно ли есть да́ти кинсо́н ке́сареви, или́ ни? Разуме́в же Иису́с лука́вство их, рече́: что Мя искуша́ете, лицеме́ри? Покажи́те Ми зла́тицу кинсо́нную. Они́ же принесо́ша Ему́ пе́нязь. И глаго́ла им: чий о́браз сей и написа́ние? И глаго́лаша Ему́: ке́сарев. Тогда́ глаго́ла им: воздади́те у́бо ке́сарева ке́сареви, и Бо́жия Бо́гови. И слы́шавше диви́шася, и оста́вльше Его́ отидо́ша. В той день приступи́ша к Нему́ саддуке́е, и́же глаго́лют не бы́ти воскресе́нию, и вопроси́ша Его́, глаго́люще: Учи́телю, Моисе́й рече́, а́ще кто у́мрет не имы́й чад, да по́ймет брат его́ жену́ его́ и воскреси́т се́мя бра́та своего́. Бе́ша же в нас седмь бра́тия, и пе́рвый оже́нься у́мре, и не имы́й се́мене, оста́ви жену́ свою́ бра́ту своему́, та́кожде же и вторы́й, и тре́тий, да́же до седма́го, последи́ же всех у́мре и жена́. В воскреше́ние у́бо, кото́раго от седми́х бу́дет жена́? Вси бо име́ша ю́. Отвеща́в же Иису́с рече́ им: прельща́етеся, не ве́дуще Писа́ния, ни си́лы Бо́жия. В воскресе́ние бо ни же́нятся, ни посяга́ют, но я́ко А́нгели Бо́жии на небеси́ суть, о воскресе́нии же ме́ртвых не́сте ли чли рече́ннаго вам Бо́гом, глаго́лющим: Аз есмь Бог Авраа́мов, и Бог Исаа́ков, и Бог Иа́ковль? Несть Бог Бог ме́ртвых, но Бог живы́х. И слы́шавше наро́ди дивля́хуся о уче́нии Его́. Фарисе́е же слы́шавше, я́ко посрами́ саддуке́и, собра́шася вку́пе. И вопроси́ еди́н от них законоучи́тель, искуша́я Его́ и глаго́ля: Учи́телю, ка́я за́поведь бо́льши есть в зако́не? Иису́с же рече́ ему́: возлю́биши Го́спода Бо́га твоего́ всем се́рдцем твои́м, и все́ю душе́ю твое́ю, и все́ю мы́слию твое́ю. Сия́ есть пе́рвая и бо́льшая за́поведь. Втора́я же подо́бна ей: возлю́биши и́скренняго твоего́ я́ко сам себе́. В сию́ обою́ за́поведию весь зако́н и проро́цы ви́сят. Со́браном же фарисе́ом, вопроси́ их Иису́с, глаго́ля: что ся вам мни́т о Христе́? Чий есть Сын? Глаго́лаша Ему́: Дави́дов. Глаго́ла им: ка́ко у́бо Дави́д Ду́хом Го́спода Его́ нарица́ет, глаго́ля: рече́ Госпо́дь Го́сподеви моему́, седи́ одесну́ю Мене́, до́ндеже положу́ враги́ Твоя́ подно́жие нога́ма Твои́ма? А́ще у́бо Дави́д нарица́ет Его́ Го́спода, ка́ко сын ему́ есть? И никто́же можа́ше отвеща́ти Ему́ словесе́, ниже́ сме́я кто от того́ дне вопроси́ти Его́ ктому́. Тогда́ Иису́с глаго́ла к наро́дом и ученико́м Свои́м, глаго́ля: на Моисе́ове седа́лищи седо́ша кни́жницы и фарисе́е. Вся у́бо, ели́ка а́ще реку́т вам блюсти́, соблюда́йте и твори́те, по дело́м же их не твори́те. Глаго́лют бо, и не творя́т, связу́ют бо бремена́ тя́жка и бе́дне носи́ма, и возлага́ют на плеща́ челове́ческа, пе́рстом же свои́м не хотя́т дви́гнути их. Вся же дела́ своя́ творя́т, да ви́дими бу́дут челове́ки, разширя́ют же храни́лища своя́ и велича́ют воскри́лия риз свои́х, лю́бят же преждевозлега́ния на ве́черях, и преждеседа́ния на со́нмищах, и целова́ния на то́ржищих, и зва́тися от челове́к: учи́телю, учи́телю. Вы же не нарица́йтеся учи́тели, еди́н бо есть ваш Учи́тель, Христо́с, вси же вы бра́тия есте́. И отца́ не зови́те себе́ на земли́, еди́н бо есть Оте́ц ваш, И́же на небесе́х. Ниже́ нарица́йтеся наста́вницы, еди́н бо есть Наста́вник ваш, Христо́с. Бо́лий же в вас да бу́дет вам слуга́, и́же бо вознесе́тся, смири́тся, и смиря́яйся вознесе́тся. Го́ре вам, кни́жницы и фарисе́е, лицеме́ри, я́ко снеда́ете до́мы вдови́ц, и вино́ю дале́че моли́твы творя́ще, сего́ ра́ди ли́шшее прии́мете осужде́ние. Го́ре вам, кни́жницы и фарисе́е, лицеме́ри, я́ко затворя́ете Ца́рствие Небе́сное пред челове́ки, вы бо не вхо́дите, ни входя́щих оставля́ете вни́ти. Го́ре вам, кни́жницы и фарисе́е, лицеме́ри, я́ко прехо́дите мо́ре и су́шу, сотвори́ти еди́наго прише́льца, и егда́ бу́дет, твори́те его́ сы́на гее́нны сугу́бейша вас. Го́ре вам, вожди́ слепи́и, глаго́лющии, и́же а́ще клене́тся це́рковию, ничесо́же есть, а и́же клене́тся зла́том церко́вным, до́лжен есть. Бу́и и слепи́и, ко́е бо бо́ле есть, зла́то ли, или́ це́рковь, святя́щая зла́то? И и́же а́ще клене́тся олтаре́м, ничесо́же есть, а и́же клене́тся да́ром, и́же верху́ его́, до́лжен есть. Бу́и и слепи́и, что бо бо́ле, дар ли, или́ олта́рь, святя́й дар? И́же у́бо клене́тся олтаре́м, клене́тся им и Су́щим верху́ его́, и и́же клене́тся це́рковию, клене́тся ею́ и Живу́щим в ней, и клены́йся небесе́м клене́тся Престо́лом Бо́жиим и Седя́щим на нем. Го́ре вам, кни́жницы и фарисе́е, лицеме́ри, я́ко одеся́тствуете мя́тву и копр и ки́мин, и оста́висте вя́щшая зако́ну, суд и ми́лость и ве́ру, сия́ же подоба́ше твори́ти, и о́нех не оставля́ти. Вожди́ слепи́и, оцежда́ющии комары́, вельблу́ды же пожира́юще. Го́ре вам, кни́жницы и фарисе́е лицеме́ри, я́ко очища́ете вне́шнее сткля́ницы и блю́да, внутрью́ду же суть по́лни хище́ния и непра́вды. Фарисе́е слепы́й, очи́сти пре́жде вну́треннее сткля́ницы и блю́да, да бу́дет и вне́шнее и́ма чи́сто. Го́ре вам, кни́жницы и фарисе́е, лицеме́ри, я́ко подо́битеся гробо́м пова́пленым, и́же внеу́ду у́бо явля́ются красны́, внутрью́ду же по́лни суть косте́й ме́ртвых и вся́кия нечистоты́. Та́ко и вы, внеу́ду у́бо явля́етеся челове́ком пра́ведни, внутрью́ду же есте́ по́лни лицеме́рия и беззако́ния. Го́ре вам, кни́жницы и фарисе́е, лицеме́ри, я́ко зи́ждете гро́бы проро́ческия, и кра́сите ра́ки пра́ведных, и глаго́лете: а́ще бы́хом бы́ли во дни оте́ц на́ших, не бы́хом у́бо о́бщницы им бы́ли в кро́ви проро́к. Те́мже са́ми свиде́тельствуете себе́, я́ко сы́нове есте́ изби́вших проро́ки, и вы испо́лните ме́ру оте́ц ва́ших. Змия́, порожде́ния ехи́днова, ка́ко убежите́ от суда́ огня́ гее́нскаго? Сего́ ра́ди, се Аз послю́ к вам проро́ки и прему́дры и кни́жники, и от них убие́те и ра́спнете, и от них бие́те на со́нмищах ва́ших, и изжене́те от гра́да во град, я́ко да прии́дет на вы вся́ка кровь пра́ведна, пролива́емая на земли́, от кро́ве А́веля пра́веднаго до кро́ве Заха́рии сы́на Варахи́ина, его́же уби́сте между́ це́рковию и олтаре́м. Ами́нь глаго́лю вам, я́ко прии́дут вся сия́ на род сей. Иерусали́ме, Иерусали́ме, изби́вый проро́ки и ка́мением побива́яй по́сланныя к тебе́, колькра́ты восхоте́х собра́ти ча́да твоя́, я́коже собира́ет ко́кош птенцы́ своя́ под криле́, и не восхоте́сте? Се, оставля́ется вам дом ваш пуст. Глаго́лю бо вам, я́ко не и́мате Мене́ ви́дети отсе́ле, до́ндеже рече́те: благослове́н Гряды́й во и́мя Госпо́дне. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, совѣ́тъ прїе́мше всѝ фарїсе́є на і҆и҃са, ꙗ҆́кѡ да ѡ҆больстѧ́тъ є҆го̀ сло́вомъ, посыла́ютъ къ немꙋ̀ ᲂу҆чн҃кѝ своѧ̀ съ и҆рѡдїа́ны, глаго́люще: ᲂу҆чи́телю, вѣ́мы, ꙗ҆́кѡ и҆́стиненъ є҆сѝ, и҆ пꙋтѝ бж҃їю вои́стиннꙋ ᲂу҆чи́ши, и҆ неради́ши ни ѡ҆ ко́мже: не зри́ши бо на лицѐ чл҃вѣ́кѡмъ. рцы̀ ᲂу҆́бѡ на́мъ, что́ ти сѧ мни́тъ; досто́йно ли є҆́сть да́ти кинсо́нъ ке́сареви, и҆лѝ нѝ; разꙋмѣ́въ же і҆и҃съ лꙋка́вство и҆́хъ, речѐ: что́ мѧ и҆скꙋша́ете лицемѣ́ри; покажи́те мѝ злати́цꙋ кинсо́ннꙋю. ѻ҆ни́ же принесо́ша є҆мꙋ̀ пѣ́нѧзь. и҆ глаго́ла и҆̀мъ: чі́й ѻ҆́бразъ се́й и҆ написа́нїе; и҆ глаго́лаша є҆мꙋ̀: ке́саревъ. тогда̀ глаго́ла и҆̀мъ: воздади́те ᲂу҆́бѡ ке́сарєва ке́сареви, и҆ бж҃їѧ бг҃ови. и҆ слы́шавше диви́шасѧ: и҆ ѡ҆ста́вльше є҆го̀ ѿидо́ша. въ то́й де́нь пристꙋпи́ша къ немꙋ̀ саддꙋке́є, и҆̀же глаго́лютъ не бы́ти воскресе́нїю, и҆ вопроси́ша є҆го̀, глаго́люще: ᲂу҆чи́телю, мѡѷсе́й речѐ: а҆́ще кто̀ ᲂу҆́мретъ не и҆мы́й ча̑дъ, да по́йметъ бра́тъ є҆гѡ̀ женꙋ̀ є҆гѡ̀, и҆ воскреси́тъ сѣ́мѧ бра́та своегѡ̀. бѣ́ша же въ на́съ се́дмь бра́тїѧ, и҆ пе́рвый ѡ҆же́ньсѧ ᲂу҆́мре: и҆ не и҆мы́й сѣ́мене, ѡ҆ста́ви женꙋ̀ свою̀ бра́тꙋ своемꙋ̀. та́кожде же и҆ вторы́й, и҆ тре́тїй, да́же до седма́гѡ. послѣди́ же всѣ́хъ ᲂу҆́мре и҆ жена̀. въ воскреше́нїе ᲂу҆́бѡ, кото́рагѡ ѿ седми́хъ бꙋ́детъ жена̀; вси́ бо и҆мѣ́ша ю҆̀. ѿвѣща́въ же і҆и҃съ речѐ и҆̀мъ: прельща́етесѧ, не вѣ́дꙋще писа́нїѧ, ни си́лы бж҃їѧ. въ воскресе́нїе бо ни же́нѧтсѧ, ни посѧга́ютъ: но ꙗ҆́кѡ а҆́гг҃ли бж҃їи на нб҃сѝ сꙋ́ть. ѡ҆ воскресе́нїи же ме́ртвыхъ нѣ́сте ли члѝ рече́ннагѡ ва́мъ бг҃омъ, глаго́лющимъ: а҆́зъ є҆́смь бг҃ъ а҆враа́мовъ, и҆ бг҃ъ і҆саа́ковъ, и҆ бг҃ъ і҆а́кѡвль, нѣ́сть бг҃ъ, бг҃ъ ме́ртвыхъ, но бг҃ъ живы́хъ; и҆ слы́шавше наро́ди, дивлѧ́хꙋсѧ ѡ҆ ᲂу҆че́нїи є҆гѡ̀. фарїсе́є же слы́шавше, ꙗ҆́кѡ посрамѝ саддꙋке́и, собра́шасѧ вкꙋ́пѣ. и҆ вопросѝ є҆ди́нъ ѿ ни́хъ законоꙋчи́тель, и҆скꙋша́ѧ є҆го̀, и҆ глаго́лѧ: ᲂу҆чи́телю, ка́ѧ за́повѣдь бо́льши є҆́сть въ зако́нѣ; і҆и҃съ же речѐ є҆мꙋ̀: возлю́биши гдⷭ҇а бг҃а твоего̀ всѣ́мъ се́рдцемъ твои́мъ, и҆ все́ю дꙋше́ю твое́ю, и҆ все́ю мы́слїю твое́ю. сїѧ̀ є҆́сть пе́рваѧ и҆ бо́льшаѧ за́повѣдь. втора́ѧ же подо́бна є҆́й: возлю́биши и҆́скреннѧго твоего̀, ꙗ҆́кѡ са́мъ себѐ. въ сїю̀ ѻ҆бою̀ за́повѣдїю ве́сь зако́нъ и҆ проро́цы ви́сѧтъ. со́бранѡмъ же фарїсе́ѡмъ, вопросѝ и҆̀хъ і҆и҃съ, глаго́лѧ: что́ сѧ ва́мъ мни́тъ ѡ҆ хрⷭ҇тѣ̀, чі́й є҆́сть сн҃ъ; глаго́лаша є҆мꙋ̀: дв҃довъ. глаго́ла и҆̀мъ: ка́кѡ ᲂу҆́бѡ дв҃дъ дх҃омъ гдⷭ҇а є҆го̀ нарица́етъ, глаго́лѧ: речѐ гдⷭ҇ь гдⷭ҇еви моемꙋ̀, сѣдѝ ѡ҆деснꙋ́ю менѐ, до́ндеже положꙋ̀ врагѝ твоѧ̀ подно́жїе нога́ма твои́ма. а҆́ще ᲂу҆́бѡ дв҃дъ нарица́етъ є҆го̀ гдⷭ҇а, ка́кѡ сн҃ъ є҆мꙋ̀ є҆́сть; и҆ никто́же можа́ше ѿвѣща́ти є҆мꙋ̀ словесѐ: нижѐ смѣ́ѧ кто̀ ѿ тогѡ̀ днѐ вопроси́ти є҆го̀ ктомꙋ̀. тогда̀ і҆и҃съ глаго́ла къ наро́дѡмъ и҆ ᲂу҆ченикѡ́мъ свои́мъ, глаго́лѧ: на мѡѷсе́овѣ сѣда́лищи сѣдо́ша кни́жницы и҆ фарїсе́є. всѧ̑ ᲂу҆́бѡ, є҆ли̑ка а҆́ще рекꙋ́тъ ва́мъ блюстѝ, соблюда́йте и҆ твори́те: по дѣлѡ́мъ же и҆́хъ не твори́те, глаго́лютъ бо, и҆ не творѧ́тъ. свѧзꙋ́ютъ бо бремена̀ тѧ́жка и҆ бѣ́днѣ носи̑ма, и҆ возлага́ютъ на плеща̀ чл҃вѣ́ческа, пе́рстомъ же свои́мъ не хотѧ́тъ дви́гнꙋти и҆̀хъ. всѧ́ же дѣла̀ своѧ̀ творѧ́тъ, да ви́дими бꙋ́дꙋтъ человѣ́ки: разширѧ́ютъ же храни́лища своѧ̀, и҆ велича́ютъ воскри̑лїѧ ри́зъ свои́хъ. лю́бѧтъ же преждевозлега̑нїѧ на ве́черѧхъ, и҆ преждесѣда̑нїѧ на со́нмищахъ, и҆ цѣлова̑нїѧ на то́ржищахъ, и҆ зва́тисѧ ѿ человѣ̑къ: ᲂу҆чи́телю, ᲂу҆чи́телю. вы́ же не нарица́йтесѧ ᲂу҆чи́тели: є҆ди́нъ бо є҆́сть ва́шъ ᲂу҆чи́тель, хрⷭ҇то́съ, вси́ же вы̀ бра́тїѧ є҆стѐ. и҆ ѻ҆тца̀ не зови́те себѣ̀ на землѝ: є҆ди́нъ бо є҆́сть ѻ҆ц҃ъ ва́шъ, и҆́же на нб҃сѣ́хъ. нижѐ нарица́йтесѧ наста̑вницы: є҆ди́нъ бо є҆́сть наста́вникъ ва́шъ хрⷭ҇то́съ. бо́лїй же въ ва́съ, да бꙋ́детъ ва́мъ слꙋга̀. и҆́же бо вознесе́тсѧ, смири́тсѧ: и҆ смирѧ́ѧйсѧ, вознесе́тсѧ. го́ре ва́мъ кни́жницы и҆ фарїсе́є лицемѣ́ри, ꙗ҆́кѡ снѣда́ете до́мы вдови́цъ, и҆ вино́ю дале́че моли̑твы творѧ́ще: сегѡ̀ ра́ди ли́шшее прїи́мете ѡ҆сꙋжде́нїе. го́ре ва́мъ кни́жницы и҆ фарїсе́є лицемѣ́ри, ꙗ҆́кѡ затворѧ́ете црⷭ҇твїе нбⷭ҇ное пред̾ человѣ́ки: вы́ бо не вхо́дите, ни входѧ́щихъ ѡ҆ставлѧ́ете вни́ти. го́ре ва́мъ кни́жницы и҆ фарїсе́є лицемѣ́ри, ꙗ҆́кѡ прехо́дите мо́ре и҆ сꙋ́шꙋ, сотвори́ти є҆ди́наго прише́льца: и҆ є҆гда̀ бꙋ́детъ, творитѐ є҆го̀ сы́на гее́нны сꙋгꙋ́бѣйша ва́съ. го́ре ва́мъ вождѝ слѣпі́и, глаго́люще: и҆́же а҆́ще клене́тсѧ це́рковїю, ничесо́же є҆́сть: а҆ и҆́же клене́тсѧ зла́томъ церко́внымъ, до́лженъ є҆́сть. бꙋ́и и҆ слѣпі́и, ко́е бо бо́ле є҆́сть; зла́то ли, и҆лѝ це́рковь свѧтѧ́щаѧ зла́то; и҆ и҆́же а҆́ще клене́тсѧ ѻ҆лтаре́мъ, ничесо́же є҆́сть: а҆ и҆́же клене́тсѧ да́ромъ, и҆́же верхꙋ̀ є҆гѡ̀, до́лженъ є҆́сть. бꙋ́и и҆ слѣпі́и, что́ бо бо́ле; да́ръ ли, и҆лѝ ѻ҆лта́рь ст҃ѧ́й да́ръ; и҆́же ᲂу҆́бѡ клене́тсѧ ѻ҆лтаре́мъ, клене́тсѧ и҆́мъ, и҆ сꙋ́щимъ верхꙋ̀ є҆гѡ̀. и҆ и҆́же клене́тсѧ цр҃ковїю, клене́тсѧ є҆́ю, и҆ живꙋ́щимъ въ не́й. и҆ клены́йсѧ небесе́мъ, клене́тсѧ прⷭ҇то́ломъ бж҃їимъ, и҆ сѣдѧ́щимъ на не́мъ. го́ре ва́мъ кни́жницы и҆ фарїсе́є лицемѣ́ри, ꙗ҆́кѡ ѡ҆десѧ́тствꙋете мѧ́твꙋ, и҆ ко́пръ, и҆ кѵ́мїнъ: и҆ ѡ҆ста́висте вѧ̑щшаѧ зако́нꙋ, сꙋ́дъ, и҆ ми́лость, и҆ вѣ́рꙋ. сїѧ̑ же подоба́ше твори́ти, и҆ ѻ҆́нѣхъ не ѡ҆ставлѧ́ти. вождѝ слѣпі́и, ѡ҆цѣжда́ющїи комары̀, вельблꙋ́ды же пожира́юще. го́ре ва́мъ кни́жницы и҆ фарїсе́є лицемѣ́ри, ꙗ҆́кѡ ѡ҆чища́ете внѣ́шнее стклѧ́ницы и҆ блю́да: внꙋтрью́дꙋ же сꙋ́ть по́лни хище́нїѧ и҆ непра́вды. фарїсе́е слѣпы́й, ѡ҆чи́сти пре́жде внꙋ́треннее стклѧ́ницы и҆ блю́да, да бꙋ́детъ и҆ внѣ́шнее и҆́ма чи́сто. го́ре ва́мъ кни́жницы и҆ фарїсе́є лицемѣ́ри, ꙗ҆́кѡ подо́битесѧ гробѡ́мъ пова́плєнымъ, и҆̀же внѣю́дꙋ ᲂу҆́бѡ ꙗ҆влѧ́ютсѧ красны̀, внꙋтрью́дꙋ же по́лни сꙋ́ть косте́й ме́ртвыхъ, и҆ всѧ́кїѧ нечистоты̀. та́кѡ и҆ вы̀, внѣю́дꙋ ᲂу҆́бѡ ꙗ҆влѧ́етесѧ чл҃вѣ́кѡмъ пра́ведни: внꙋтрью́дꙋ же є҆стѐ по́лни лицемѣ́рїѧ и҆ беззако́нїѧ. го́ре ва́мъ кни́жницы и҆ фарїсе́є лицемѣ́ри, ꙗ҆́кѡ зи́ждете гро́бы проро́чєскїѧ, и҆ кра́сите ра̑ки пра́ведныхъ, и҆ глаго́лете: а҆́ще бы́хомъ бы́ли во днѝ ѻ҆тє́цъ на́шихъ, не бы́хомъ ᲂу҆́бѡ ѻ҆́бщницы и҆̀мъ бы́ли въ кро́ви прорѡ́къ. тѣ́мже са́ми свидѣ́тельствꙋете себѣ̀, ꙗ҆́кѡ сы́нове є҆стѐ и҆зби́вшихъ проро́ки. и҆ вы̀ и҆спо́лните мѣ́рꙋ ѻ҆тє́цъ ва́шихъ. ѕмїѧ̑, порождє́нїѧ є҆хі́днова, ка́кѡ ᲂу҆бѣжитѐ ѿ сꙋда̀ ѻ҆гнѧ̀ гее́нскагѡ; сегѡ̀ ра́ди сѐ а҆́зъ послю̀ къ ва́мъ проро́ки, и҆ премꙋ́дры, и҆ кни́жники: и҆ ѿ ни́хъ ᲂу҆бїе́те и҆ ра́спнете, и҆ ѿ ни́хъ бїе́те на со́нмищахъ ва́шихъ, и҆ и҆зжене́те ѿ гра́да во гра́дъ. ꙗ҆́кѡ да прїи́детъ на вы̀ всѧ́ка кро́вь пра́ведна, пролива́емаѧ на землѝ, ѿ кро́ве а҆́велѧ пра́веднагѡ, до кро́ве заха́рїи сы́на варахі́ина, є҆го́же ᲂу҆би́сте междꙋ̀ це́рковїю и҆ ѻ҆лтаре́мъ. а҆ми́нь глаго́лю ва́мъ: ꙗ҆́кѡ прїи́дꙋтъ всѧ̑ сїѧ̑ на ро́дъ се́й. і҆ерꙋсали́ме, і҆ерꙋсали́ме и҆зби́вый проро́ки, и҆ ка́менїемъ побива́ѧй пѡ́сланныѧ къ немꙋ̀, колькра́ты восхотѣ́хъ собра́ти ча̑да твоѧ̀, ꙗ҆́коже собира́етъ ко́кошъ птенцы̀ своѧ̀ под̾ крилѣ̀, и҆ не восхотѣ́сте! сѐ ѡ҆ставлѧ́етсѧ ва́мъ до́мъ ва́шъ пꙋ́стъ. глаго́лю бо ва́мъ, ꙗ҆́кѡ не и҆́мате менѐ ви́дѣти ѿсе́лѣ, до́ндеже рече́те: бл҃гослове́нъ грѧды́й во и҆́мѧ гдⷭ҇не. ",
}

add_evangelie_matfea {
  ["номер"] = 91,
  ["комментарий"] = "Мф., 91 зач., XXII, 23–33.",
  ["текст_ру"] = "Во вре́мя о́но, приступи́ша к Иису́су саддуке́е, и́же глаго́лют не бы́ти воскресе́нию, и вопроси́ша Его́, глаго́люще: Учи́телю, Моисе́й рече́, а́ще кто у́мрет не имы́й чад, да по́ймет брат его́ жену́ его́ и воскреси́т се́мя бра́та своего́. Бе́ша же в нас седмь бра́тия, и пе́рвый оже́нься у́мре, и не имы́й се́мене, оста́ви жену́ свою́ бра́ту своему́, та́кожде же и вторы́й, и тре́тий, да́же до седма́го, последи́ же всех у́мре и жена́. В воскреше́ние у́бо, кото́раго от седми́х бу́дет жена́? Вси бо име́ша ю́. Отвеща́в же Иису́с рече́ им: прельща́етеся, не ве́дуще Писа́ния, ни си́лы Бо́жия. В воскресе́ние бо ни же́нятся, ни посяга́ют, но я́ко А́нгели Бо́жии на небеси́ суть, о воскресе́нии же ме́ртвых не́сте ли чли рече́ннаго вам Бо́гом, глаго́лющим: Аз есмь Бог Авраа́мов, и Бог Исаа́ков, и Бог Иа́ковль? Несть Бог Бог ме́ртвых, но Бог живы́х. И слы́шавше наро́ди дивля́хуся о уче́нии Его́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋпи́ша ко і҆и҃сꙋ саддꙋке́є, и҆̀же глаго́лютъ не бы́ти воскресе́нїю, и҆ вопроси́ша є҆го̀, глаго́люще: ᲂу҆чи́телю, мѡѷсе́й речѐ: а҆́ще кто̀ ᲂу҆́мретъ не и҆мы́й ча̑дъ, да по́йметъ бра́тъ є҆гѡ̀ женꙋ̀ є҆гѡ̀, и҆ воскреси́тъ сѣ́мѧ бра́та своегѡ̀. бѣ́ша же въ на́съ се́дмь бра́тїѧ, и҆ пе́рвый ѡ҆же́ньсѧ ᲂу҆́мре: и҆ не и҆мы́й сѣ́мене, ѡ҆ста́ви женꙋ̀ свою̀ бра́тꙋ своемꙋ̀. та́кожде же и҆ вторы́й, и҆ тре́тїй, да́же до седма́гѡ. послѣди́ же всѣ́хъ ᲂу҆́мре и҆ жена̀. въ воскреше́нїе ᲂу҆́бѡ, кото́рагѡ ѿ седми́хъ бꙋ́детъ жена̀; вси́ бо и҆мѣ́ша ю҆̀. ѿвѣща́въ же і҆и҃съ речѐ и҆̀мъ: прельща́етесѧ, не вѣ́дꙋще писа́нїѧ, ни си́лы бж҃їѧ. въ воскресе́нїе бо ни же́нѧтсѧ, ни посѧга́ютъ: но ꙗ҆́кѡ а҆́гг҃ли бж҃їи на нб҃сѝ сꙋ́ть. ѡ҆ воскресе́нїи же ме́ртвыхъ нѣ́сте ли члѝ рече́ннагѡ ва́мъ бг҃омъ, глаго́лющимъ: а҆́зъ є҆́смь бг҃ъ а҆враа́мовъ, и҆ бг҃ъ і҆саа́ковъ, и҆ бг҃ъ і҆а́кѡвль, нѣ́сть бг҃ъ, бг҃ъ ме́ртвыхъ, но бг҃ъ живы́хъ; и҆ слы́шавше наро́ди, дивлѧ́хꙋсѧ ѡ҆ ᲂу҆че́нїи є҆гѡ̀. ",
}

add_evangelie_matfea {
  ["номер"] = 92,
  ["комментарий"] = "Мф., 92 зач., XXII, 35–46.",
  ["текст_ру"] = "Во вре́мя о́но, зако́нник не́кий приступи́ ко Иису́су, искуша́я Его́ и глаго́ля: Учи́телю, ка́я за́поведь бо́льши есть в зако́не? Иису́с же рече́ ему́: возлю́биши Го́спода Бо́га твоего́ всем се́рдцем твои́м, и все́ю душе́ю твое́ю, и все́ю мы́слию твое́ю. Сия́ есть пе́рвая и бо́льшая за́поведь. Втора́я же подо́бна ей: возлю́биши и́скренняго твоего́ я́ко сам себе́. В сию́ обою́ за́поведию весь зако́н и проро́цы ви́сят. Со́браном же фарисе́ом, вопроси́ их Иису́с, глаго́ля: что ся вам мнит о Христе́? Чий есть Сын? Глаго́лаша Ему́: Дави́дов. Глаго́ла им: ка́ко у́бо Дави́д Ду́хом Го́спода Его́ нарица́ет, глаго́ля: рече́ Госпо́дь Го́сподеви моему́, седи́ одесну́ю Мене́, до́ндеже положу́ враги́ Твоя́ подно́жие нога́ма Твои́ма? А́ще у́бо Дави́д нарица́ет Его́ Го́спода, ка́ко сын ему́ есть? И никто́же можа́ше отвеща́ти Ему́ словесе́, ниже́ сме́я кто от того́ дне вопроси́ти Его́ ктому́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, зако́нникъ нѣ́кїй пристꙋпѝ ко і҆и҃сꙋ и҆скꙋша́ѧ є҆го̀, и҆ глаго́лѧ: ᲂу҆чи́телю, ка́ѧ за́повѣдь бо́льши є҆́сть въ зако́нѣ; і҆и҃съ же речѐ є҆мꙋ̀: возлю́биши гдⷭ҇а бг҃а твоего̀ всѣ́мъ се́рдцемъ твои́мъ, и҆ все́ю дꙋше́ю твое́ю, и҆ все́ю мы́слїю твое́ю. сїѧ̀ є҆́сть пе́рваѧ и҆ бо́льшаѧ за́повѣдь. втора́ѧ же подо́бна є҆́й: возлю́биши и҆́скреннѧго твоего̀, ꙗ҆́кѡ са́мъ себѐ. въ сїю̀ ѻ҆бою̀ за́повѣдїю ве́сь зако́нъ и҆ проро́цы ви́сѧтъ. со́бранѡмъ же фарїсе́ѡмъ, вопросѝ и҆̀хъ і҆и҃съ, глаго́лѧ: что́ сѧ ва́мъ мни́тъ ѡ҆ хрⷭ҇тѣ̀, чі́й є҆́сть сн҃ъ; глаго́лаша є҆мꙋ̀: дв҃довъ. глаго́ла и҆̀мъ: ка́кѡ ᲂу҆́бѡ дв҃дъ дх҃омъ гдⷭ҇а є҆го̀ нарица́етъ, глаго́лѧ: речѐ гдⷭ҇ь гдⷭ҇еви моемꙋ̀, сѣдѝ ѡ҆деснꙋ́ю менѐ, до́ндеже положꙋ̀ врагѝ твоѧ̀ подно́жїе нога́ма твои́ма. а҆́ще ᲂу҆́бѡ дв҃дъ нарица́етъ є҆го̀ гдⷭ҇а, ка́кѡ сн҃ъ є҆мꙋ̀ є҆́сть; и҆ никто́же можа́ше ѿвѣща́ти є҆мꙋ̀ словесѐ: нижѐ смѣ́ѧ кто̀ ѿ тогѡ̀ днѐ вопроси́ти є҆го̀ ктомꙋ̀. ",
}

add_evangelie_matfea {
  ["номер"] = 93,
  ["комментарий"] = "Мф., 93 зач., XXIII, 1–12.",
  ["текст_ру"] = "Во вре́мя о́но, глаго́ла Иису́с к наро́дом и ученико́м Свои́м, глаго́ля: на Моисе́ове седа́лищи седо́ша кни́жницы и фарисе́е. Вся у́бо, ели́ка а́ще реку́т вам блюсти́, соблюда́йте и твори́те, по дело́м же их не твори́те. Глаго́лют бо, и не творя́т, связу́ют бо бремена́ тя́жка и бе́дне носи́ма, и возлага́ют на плеща́ челове́ческа, пе́рстом же свои́м не хотя́т дви́гнути их. Вся же дела́ своя́ творя́т, да ви́дими бу́дут челове́ки, разширя́ют же храни́лища своя́ и велича́ют воскри́лия риз свои́х, лю́бят же преждевозлега́ния на ве́черях, и преждеседа́ния на со́нмищах, и целова́ния на то́ржищих, и зва́тися от челове́к: учи́телю, учи́телю. Вы же не нарица́йтеся учи́тели, еди́н бо есть ваш Учи́тель, Христо́с, вси же вы бра́тия есте́. И отца́ не зови́те себе́ на земли́, еди́н бо есть Оте́ц ваш, И́же на небесе́х. Ниже́ нарица́йтеся наста́вницы, еди́н бо есть Наста́вник ваш, Христо́с. Бо́лий же в вас да бу́дет вам слуга́, и́же бо вознесе́тся, смири́тся, и смиря́яйся вознесе́тся. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, глаго́ла і҆и҃съ къ наро́дѡмъ и҆ ᲂу҆ченикѡ́мъ свои́мъ, глаго́лѧ: на мѡѷсе́овѣ сѣда́лищи сѣдо́ша кни́жницы и҆ фарїсе́є. всѧ̑ ᲂу҆́бѡ, є҆ли̑ка а҆́ще рекꙋ́тъ ва́мъ блюстѝ, соблюда́йте и҆ твори́те: по дѣлѡ́мъ же и҆́хъ не твори́те, глаго́лютъ бо, и҆ не творѧ́тъ. свѧзꙋ́ютъ бо бремена̀ тѧ́жка и҆ бѣ́днѣ носи̑ма, и҆ возлага́ютъ на плеща̀ чл҃вѣ́ческа, пе́рстомъ же свои́мъ не хотѧ́тъ дви́гнꙋти и҆̀хъ. всѧ́ же дѣла̀ своѧ̀ творѧ́тъ, да ви́дими бꙋ́дꙋтъ человѣ́ки: разширѧ́ютъ же храни́лища своѧ̀, и҆ велича́ютъ воскри̑лїѧ ри́зъ свои́хъ. лю́бѧтъ же преждевозлега̑нїѧ на ве́черѧхъ, и҆ преждесѣда̑нїѧ на со́нмищахъ, и҆ цѣлова̑нїѧ на то́ржищахъ, и҆ зва́тисѧ ѿ человѣ̑къ: ᲂу҆чи́телю, ᲂу҆чи́телю. вы́ же не нарица́йтесѧ ᲂу҆чи́тели: є҆ди́нъ бо є҆́сть ва́шъ ᲂу҆чи́тель, хрⷭ҇то́съ, вси́ же вы̀ бра́тїѧ є҆стѐ. и҆ ѻ҆тца̀ не зови́те себѣ̀ на землѝ: є҆ди́нъ бо є҆́сть ѻ҆ц҃ъ ва́шъ, и҆́же на нб҃сѣ́хъ. нижѐ нарица́йтесѧ наста̑вницы: є҆ди́нъ бо є҆́сть наста́вникъ ва́шъ хрⷭ҇то́съ. бо́лїй же въ ва́съ, да бꙋ́детъ ва́мъ слꙋга̀. и҆́же бо вознесе́тсѧ, смири́тсѧ: и҆ смирѧ́ѧйсѧ, вознесе́тсѧ. ",
}

add_evangelie_matfea {
  ["номер"] = 94,
  ["комментарий"] = "Мф., 94 зач., XXIII, 13–22.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: го́ре вам, кни́жницы и фарисе́е, лицеме́ри, я́ко снеда́ете до́мы вдови́ц, и вино́ю дале́че моли́твы творя́ще, сего́ ра́ди ли́шшее прии́мете осужде́ние. Го́ре вам, кни́жницы и фарисе́е, лицеме́ри, я́ко затворя́ете Ца́рствие Небе́сное пред челове́ки, вы бо не вхо́дите, ни входя́щих оставля́ете вни́ти. Го́ре вам, кни́жницы и фарисе́е, лицеме́ри, я́ко прехо́дите мо́ре и су́шу, сотвори́ти еди́наго прише́льца, и егда́ бу́дет, творите́ его́ сы́на гее́нны сугу́бейша вас. Го́ре вам, вожди́ слепи́и, глаго́люще, и́же а́ще клене́тся це́рковию, ничесо́же есть, а и́же клене́тся зла́том церко́вным, до́лжен есть. Бу́и и слепи́и, что бо бо́ле есть, зла́то ли, или́ це́рковь, святя́щая зла́то? И и́же а́ще клене́тся олтаре́м, ничесо́же есть, а и́же клене́тся да́ром, и́же верху́ его́, до́лжен есть. Бу́и и слепи́и, что бо бо́ле, дар ли, или́ олта́рь, святя́й дар? И́же у́бо клене́тся олтаре́м, клене́тся им и Су́щим верху́ его́, и и́же клене́тся це́рковию, клене́тся ею́ и Живу́щим в ней, и клены́йся небесе́м клене́тся Престо́лом Бо́жиим и Седя́щим на нем. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: го́ре ва́мъ кни́жницы и҆ фарїсе́є лицемѣ́ри, ꙗ҆́кѡ снѣда́ете до́мы вдови́цъ, и҆ вино́ю дале́че моли̑твы творѧ́ще: сегѡ̀ ра́ди ли́шшее прїи́мете ѡ҆сꙋжде́нїе. го́ре ва́мъ кни́жницы и҆ фарїсе́є лицемѣ́ри, ꙗ҆́кѡ затворѧ́ете црⷭ҇твїе нбⷭ҇ное пред̾ человѣ́ки: вы́ бо не вхо́дите, ни входѧ́щихъ ѡ҆ставлѧ́ете вни́ти. го́ре ва́мъ кни́жницы и҆ фарїсе́є лицемѣ́ри, ꙗ҆́кѡ прехо́дите мо́ре и҆ сꙋ́шꙋ, сотвори́ти є҆ди́наго прише́льца: и҆ є҆гда̀ бꙋ́детъ, творитѐ є҆го̀ сы́на гее́нны сꙋгꙋ́бѣйша ва́съ. го́ре ва́мъ вождѝ слѣпі́и, глаго́люще: и҆́же а҆́ще клене́тсѧ це́рковїю, ничесо́же є҆́сть: а҆ и҆́же клене́тсѧ зла́томъ церко́внымъ, до́лженъ є҆́сть. бꙋ́и и҆ слѣпі́и, ко́е бо бо́ле є҆́сть; зла́то ли, и҆лѝ це́рковь свѧтѧ́щаѧ зла́то; и҆ и҆́же а҆́ще клене́тсѧ ѻ҆лтаре́мъ, ничесо́же є҆́сть: а҆ и҆́же клене́тсѧ да́ромъ, и҆́же верхꙋ̀ є҆гѡ̀, до́лженъ є҆́сть. бꙋ́и и҆ слѣпі́и, что́ бо бо́ле; да́ръ ли, и҆лѝ ѻ҆лта́рь ст҃ѧ́й да́ръ; и҆́же ᲂу҆́бѡ клене́тсѧ ѻ҆лтаре́мъ, клене́тсѧ и҆́мъ, и҆ сꙋ́щимъ верхꙋ̀ є҆гѡ̀. и҆ и҆́же клене́тсѧ цр҃ковїю, клене́тсѧ є҆́ю, и҆ живꙋ́щимъ въ не́й. и҆ клены́йсѧ небесе́мъ, клене́тсѧ прⷭ҇то́ломъ бж҃їимъ, и҆ сѣдѧ́щимъ на не́мъ. ",
}

add_evangelie_matfea {
  ["номер"] = 95,
  ["комментарий"] = "Мф., 95 зач., XXIII, 23-28.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: го́ре вам, кни́жницы и фарисе́е, лицеме́ри, я́ко одеся́тствуете мя́тву и копр и ки́мин, и оста́висте вя́щшая зако́на, суд и ми́лость, и ве́ру, сия́ же подоба́ше твори́ти, и о́нех не оставля́ти. Вожди́ слепи́и, оцежда́ющии комары́, вельблу́ды же пожира́юще. Го́ре вам, кни́жницы и фарисе́е лицеме́ри, я́ко очища́ете вне́шнее сткля́ницы и блю́да, внутрью́ду же суть по́лни хище́ния и непра́вды. Фарисе́е слепы́й, очи́сти пре́жде вну́треннее сткля́ницы и блю́да, да бу́дет и вне́шнее и́ма чи́сто. Го́ре вам, кни́жницы и фарисе́е, лицеме́ри, я́ко подо́битеся гробо́м пова́пленым, и́же внеу́ду у́бо явля́ются красны́, внутрью́ду же по́лни суть косте́й ме́ртвых и вся́кия нечистоты́. Та́ко и вы, внеу́ду у́бо явля́етеся челове́ком пра́ведни, внутрью́ду же есте́ по́лни лицеме́рия и беззако́ния. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: го́ре ва́мъ кни́жницы и҆ фарїсе́є лицемѣ́ри, ꙗ҆́кѡ ѡ҆десѧ́тствꙋете мѧ́твꙋ, и҆ ко́пръ, и҆ кѵ́мїнъ: и҆ ѡ҆ста́висте вѧ̑щшаѧ зако́нꙋ, сꙋ́дъ, и҆ ми́лость, и҆ вѣ́рꙋ. сїѧ̑ же подоба́ше твори́ти, и҆ ѻ҆́нѣхъ не ѡ҆ставлѧ́ти. вождѝ слѣпі́и, ѡ҆цѣжда́ющїи комары̀, вельблꙋ́ды же пожира́юще. го́ре ва́мъ кни́жницы и҆ фарїсе́є лицемѣ́ри, ꙗ҆́кѡ ѡ҆чища́ете внѣ́шнее стклѧ́ницы и҆ блю́да: внꙋтрью́дꙋ же сꙋ́ть по́лни хище́нїѧ и҆ непра́вды. фарїсе́е слѣпы́й, ѡ҆чи́сти пре́жде внꙋ́треннее стклѧ́ницы и҆ блю́да, да бꙋ́детъ и҆ внѣ́шнее и҆́ма чи́сто. го́ре ва́мъ кни́жницы и҆ фарїсе́є лицемѣ́ри, ꙗ҆́кѡ подо́битесѧ гробѡ́мъ пова́плєнымъ, и҆̀же внѣю́дꙋ ᲂу҆́бѡ ꙗ҆влѧ́ютсѧ красны̀, внꙋтрью́дꙋ же по́лни сꙋ́ть косте́й ме́ртвыхъ, и҆ всѧ́кїѧ нечистоты̀. та́кѡ и҆ вы̀, внѣю́дꙋ ᲂу҆́бѡ ꙗ҆влѧ́етесѧ чл҃вѣ́кѡмъ пра́ведни: внꙋтрью́дꙋ же є҆стѐ по́лни лицемѣ́рїѧ и҆ беззако́нїѧ. ",
}

add_evangelie_matfea {
  ["номер"] = 96,
  ["комментарий"] = "Мф., 96 зач., XXIII, 29–39.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: го́ре вам, кни́жницы и фарисе́е, лицеме́ри, я́ко зи́ждете гро́бы проро́ческия, и кра́сите ра́ки пра́ведных, и глаго́лете: а́ще бы́хом бы́ли во дни оте́ц на́ших, не бы́хом у́бо о́бщницы им бы́ли в кро́ви проро́к. Те́мже са́ми свиде́тельствуете себе́, я́ко сы́нове есте́ изби́вших проро́ки, и вы испо́лните ме́ру оте́ц ва́ших. Змия́, порожде́ния ехи́днова, ка́ко убежите́ от суда́ огня́ гее́нскаго? Сего́ ра́ди, се Аз послю́ к вам проро́ки и прему́дры и кни́жники, и от них убие́те и ра́спнете, и от них бие́те на со́нмищах ва́ших, и изжене́те от гра́да во град, я́ко да прии́дет на вы вся́ка кровь пра́ведна, пролива́емая на земли́, от кро́ве А́веля пра́веднаго до кро́ве Заха́рии сы́на Варахи́ина, его́же уби́сте между́ це́рковию и олтаре́м. Ами́нь глаго́лю вам, я́ко прии́дут вся сия́ на род сей. Иерусали́ме, Иерусали́ме, изби́вый проро́ки и ка́мением побива́яй по́сланныя к нему́, колькра́ты восхоте́х собра́ти ча́да твоя́, я́коже собира́ет ко́кош птенцы́ своя́ под криле́, и не восхоте́сте? Се, оставля́ется вам дом ваш пуст. Глаго́лю бо вам, я́ко не и́мате Мене́ ви́дети отсе́ле, до́ндеже рече́те: благослове́н Гряды́й во и́мя Госпо́дне. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: го́ре ва́мъ кни́жницы и҆ фарїсе́є лицемѣ́ри, ꙗ҆́кѡ зи́ждете гро́бы проро́чєскїѧ, и҆ кра́сите ра̑ки пра́ведныхъ, и҆ глаго́лете: а҆́ще бы́хомъ бы́ли во днѝ ѻ҆тє́цъ на́шихъ, не бы́хомъ ᲂу҆́бѡ ѻ҆́бщницы и҆̀мъ бы́ли въ кро́ви прорѡ́къ. тѣ́мже са́ми свидѣ́тельствꙋете себѣ̀, ꙗ҆́кѡ сы́нове є҆стѐ и҆зби́вшихъ проро́ки. и҆ вы̀ и҆спо́лните мѣ́рꙋ ѻ҆тє́цъ ва́шихъ. ѕмїѧ̑, порождє́нїѧ є҆хі́днова, ка́кѡ ᲂу҆бѣжитѐ ѿ сꙋда̀ ѻ҆гнѧ̀ гее́нскагѡ; сегѡ̀ ра́ди сѐ а҆́зъ послю̀ къ ва́мъ проро́ки, и҆ премꙋ́дры, и҆ кни́жники: и҆ ѿ ни́хъ ᲂу҆бїе́те и҆ ра́спнете, и҆ ѿ ни́хъ бїе́те на со́нмищахъ ва́шихъ, и҆ и҆зжене́те ѿ гра́да во гра́дъ. ꙗ҆́кѡ да прїи́детъ на вы̀ всѧ́ка кро́вь пра́ведна, пролива́емаѧ на землѝ, ѿ кро́ве а҆́велѧ пра́веднагѡ, до кро́ве заха́рїи сы́на варахі́ина, є҆го́же ᲂу҆би́сте междꙋ̀ це́рковїю и҆ ѻ҆лтаре́мъ. а҆ми́нь глаго́лю ва́мъ: ꙗ҆́кѡ прїи́дꙋтъ всѧ̑ сїѧ̑ на ро́дъ се́й. і҆ерꙋсали́ме, і҆ерꙋсали́ме и҆зби́вый проро́ки, и҆ ка́менїемъ побива́ѧй пѡ́сланныѧ къ немꙋ̀, колькра́ты восхотѣ́хъ собра́ти ча̑да твоѧ̀, ꙗ҆́коже собира́етъ ко́кошъ птенцы̀ своѧ̀ под̾ крилѣ̀, и҆ не восхотѣ́сте! сѐ ѡ҆ставлѧ́етсѧ ва́мъ до́мъ ва́шъ пꙋ́стъ. глаго́лю бо ва́мъ, ꙗ҆́кѡ не и҆́мате менѐ ви́дѣти ѿсе́лѣ, до́ндеже рече́те: бл҃гослове́нъ грѧды́й во и҆́мѧ гдⷭ҇не. ",
}

add_evangelie_matfea {
  ["номер"] = 97,
  ["комментарий"] = "Мф., 97 зач., XXIV, 1–13.",
  ["текст_ру"] = "Во вре́мя о́но, приступи́ша ко Иису́су ученицы́ Его́ показа́ти Ему́ зда́ния церко́вная. Иису́с же рече́ им: не ви́дите ли вся сия́? Ами́нь глаго́лю вам, не и́мать оста́ти зде ка́мень на ка́мени, и́же не разори́тся. Седя́щу же Ему́ на го́ре Елео́нстей, приступи́ша к Нему́ ученицы́ наедине́, глаго́люще: рцы нам, когда́ сия́ бу́дут? И что есть зна́мение Твоего́ прише́ствия и кончи́на ве́ка? И отвеща́в Иису́с рече́ им: блюди́те, да никто́же вас прельсти́т. Мно́зи бо прии́дут во и́мя Мое́, глаго́люще: аз есмь Христо́с, и мно́ги прельстя́т. Услы́шати же и́мате бра́ни и слы́шания бра́нем. Зри́те, не ужаса́йтеся, подоба́ет бо всем сим бы́ти, но не тогда́ есть кончи́на. Воста́нет бо язы́к на язы́к, и ца́рство на ца́рство, и бу́дут гла́ди и па́губы и тру́си по ме́стом, вся же сия́ нача́ло боле́знем. Тогда́ предадя́т вы в ско́рби и убию́т вы, и бу́дете ненави́дими все́ми язы́ки и́мене Моего́ ра́ди. И тогда́ соблазня́тся мно́зи, и друг дру́га предадя́т, и возненави́дят друг дру́га, и мно́зи лжепроро́цы воста́нут и прельстя́т мно́гия, и за умноже́ние беззако́ния, изся́кнет любы́ мно́гих. Претерпе́вый же до конца́, той спасе́тся. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋпи́ша ко і҆и҃сꙋ ᲂу҆ченицы̀ є҆гѡ̀, показа́ти є҆мꙋ̀ зда́нїѧ церкѡ́внаѧ. і҆и҃съ же речѐ и҆̀мъ: не ви́дите ли всѧ̑ сїѧ̑; а҆ми́нь глаго́лю ва́мъ, не и҆́мать ѡ҆ста́ти здѣ̀ ка́мень на ка́мени, и҆́же не разори́тсѧ. сѣдѧ́щꙋ же є҆мꙋ̀ на горѣ̀ є҆леѡ́нстѣй, пристꙋпи́ша къ немꙋ̀ ᲂу҆ченицы̀, наединѣ̀ глаго́люще: рцы̀ на́мъ, когда̀ сїѧ̑ бꙋ́дꙋтъ; и҆ что̀ є҆́сть зна́менїе твоегѡ̀ прише́ствїѧ, и҆ кончи́на вѣ́ка; и҆ ѿвѣща́въ і҆и҃съ, речѐ и҆̀мъ: блюди́те, да никто́же ва́съ прельсти́тъ. мно́зи бо прїи́дꙋтъ во и҆́мѧ моѐ, глаго́люще: а҆́зъ є҆́смь хрⷭ҇то́съ, и҆ мнѡ́ги прельстѧ́тъ: ᲂу҆слы́шати же и҆́мате бра̑ни, и҆ слы̑шанїѧ бра́нємъ, зри́те, не ᲂу҆жаса́йтесѧ: подоба́етъ бо всѣ̑мъ си̑мъ бы́ти, но не тогда̀ є҆́сть кончи́на. воста́нетъ бо ꙗ҆зы́къ на ꙗ҆зы́къ, и҆ црⷭ҇тво на црⷭ҇тво: и҆ бꙋ́дꙋтъ гла́ди, и҆ па̑гꙋбы, и҆ трꙋ́си по мѣ́стѡмъ: всѧ̑ же сїѧ̑, нача́ло болѣ́знемъ. тогда̀ предадѧ́тъ вы̀ въ скѡ́рби, и҆ ᲂу҆бїю́тъ вы̀: и҆ бꙋ́дете ненави́дими всѣ́ми ꙗ҆зы́ки и҆́мене моегѡ̀ ра́ди. и҆ тогда̀ соблазнѧ́тсѧ мно́зи, и҆ дрꙋ́гъ дрꙋ́га предадѧ́тъ, и҆ возненави́дитъ дрꙋ́гъ дрꙋ́га: и҆ мно́зи лжепроро́цы воста́нꙋтъ, и҆ прельстѧ́тъ мнѡ́гїѧ: и҆ за ᲂу҆множе́нїе беззако́нїѧ, и҆зсѧ́кнетъ любы̀ мно́гихъ. претерпѣ́вый же до конца̀, то́й спасе́тсѧ. ",
}

add_evangelie_matfea {
  ["номер"] = 98,
  ["комментарий"] = "Мф., 98 зач., XXIV, 3–35.",
  ["текст_ру"] = "Во вре́мя о́но, седя́щу Иису́су на го́ре Елео́нстей, приступи́ша к Нему́ ученицы́ наедине́, глаго́люще: рцы нам, когда́ сия́ бу́дут? И что есть зна́мение Твоего́ прише́ствия и кончи́на ве́ка? И отвеща́в Иису́с рече́ им: блюди́те, да никто́же вас прельсти́т. Мно́зи бо прии́дут во и́мя Мое́, глаго́люще: Аз есмь Христо́с, и мно́ги прельстя́т. Услы́шати же и́мате бра́ни и слы́шания бра́нем. Зри́те, не ужаса́йтеся, подоба́ет бо всем сим бы́ти, но не тогда́ есть кончи́на. Воста́нет бо язы́к на язы́к, и ца́рство на ца́рство, и бу́дут гла́ди и па́губы и тру́си по ме́стом, вся же сия́ нача́ло боле́знем. Тогда́ предадя́т вы в ско́рби и убию́т вы, и бу́дете ненави́дими все́ми язы́ки и́мене Моего́ ра́ди. И тогда́ соблазня́тся мно́зи, и друг дру́га предадя́т, и возненави́дят друг дру́га, и мно́зи лжепроро́цы воста́нут и прельстя́т мно́гия, и за умноже́ние беззако́ния, изся́кнет любы́ мно́гих. Претерпе́вый же до конца́, той спасе́тся. И пропове́стся сие́ Ева́нгелие Ца́рствия по всей вселе́нней, во свиде́тельство всем язы́ком, и тогда́ прии́дет кончи́на. Егда́ у́бо у́зрите ме́рзость запусте́ния, рече́нную Дании́лом проро́ком, стоя́щу на ме́сте свя́те, и́же чтет, да разуме́ет, тогда́ су́щии во Иуде́и да бежа́т на го́ры, и и́же на кро́ве, да не схо́дит взя́ти я́же в дому́ его́, и и́же на селе́, да не возврати́тся вспять взя́ти риз свои́х. Го́ре же непра́здным и доя́щым в ты́я дни. Моли́теся же, да не бу́дет бе́гство ва́ше в зиме́, ни в суббо́ту. Бу́дет бо тогда́ скорбь ве́лия, якова́ же несть была́ от нача́ла ми́ра досе́ле, ниже́ и́мать бы́ти. И а́ще не бы́ша прекрати́лися дни́е о́ны, не бы у́бо спасла́ся вся́ка плоть, избра́нных же ра́ди прекратя́тся дни́е о́ны. Тогда́ а́ще кто рече́т вам: се зде Христо́с, или́ о́нде, не ими́те ве́ры. Воста́нут бо лжехри́сти и лжепроро́цы и дадя́т зна́мения ве́лия и чудеса́, я́коже прельсти́ти, а́ще возмо́жно, и избра́нныя. Се, пре́жде рех вам. А́ще у́бо реку́т вам: се в пусты́ни есть, не изыди́те, се в сокро́вищих, не ими́те ве́ры. Я́коже бо мо́лния исхо́дит от восто́к и явля́ется до за́пад, та́ко бу́дет прише́ствие Сы́на Челове́ческаго, иде́же бо а́ще бу́дет труп, та́мо соберу́тся орли́. А́бие же, по ско́рби дний тех, со́лнце поме́ркнет, и луна́ не даст све́та своего́, и зве́зды спа́днут с небесе́, и си́лы небе́сныя подви́гнутся, и тогда́ яви́тся зна́мение Сы́на Челове́ческаго на небеси́, и тогда́ воспла́чутся вся коле́на земна́я и у́зрят Сы́на Челове́ческаго гряду́ща на о́блацех небе́сных с си́лою и сла́вою мно́гою, и по́слет А́нгелы Своя́ с тру́бным гла́сом ве́лиим, и соберу́т избра́нныя Его́ от четы́рех ветр, от коне́ц небе́с до коне́ц их. От смоко́вницы же научи́теся при́тчи: егда́ уже́ ва́ия ея́ бу́дут мла́да, и ли́ствие прозя́бнет, ве́дите, я́ко близ есть жа́тва. Та́ко и вы, егда́ ви́дите сия́ вся, ве́дите, я́ко близ есть, при две́рех. Ами́нь глаго́лю вам, не мимои́дет род сей, до́ндеже вся сия́ бу́дут, не́бо и земля́ мимои́дет, словеса́ же Моя́ не мимои́дут. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, сѣдѧ́щꙋ і҆и҃сꙋ на горѣ̀ є҆леѡ́нстѣй, пристꙋпи́ша къ немꙋ̀ ᲂу҆ченицы̀, наединѣ̀ глаго́люще: рцы̀ на́мъ, когда̀ сїѧ̑ бꙋ́дꙋтъ; и҆ что̀ є҆́сть зна́менїе твоегѡ̀ прише́ствїѧ, и҆ кончи́на вѣ́ка; и҆ ѿвѣща́въ і҆и҃съ, речѐ и҆̀мъ: блюди́те, да никто́же ва́съ прельсти́тъ. мно́зи бо прїи́дꙋтъ во и҆́мѧ моѐ, глаго́люще: а҆́зъ є҆́смь хрⷭ҇то́съ, и҆ мнѡ́ги прельстѧ́тъ: ᲂу҆слы́шати же и҆́мате бра̑ни, и҆ слы̑шанїѧ бра́нємъ, зри́те, не ᲂу҆жаса́йтесѧ: подоба́етъ бо всѣ̑мъ си̑мъ бы́ти, но не тогда̀ є҆́сть кончи́на. воста́нетъ бо ꙗ҆зы́къ на ꙗ҆зы́къ, и҆ црⷭ҇тво на црⷭ҇тво: и҆ бꙋ́дꙋтъ гла́ди, и҆ па̑гꙋбы, и҆ трꙋ́си по мѣ́стѡмъ: всѧ̑ же сїѧ̑, нача́ло болѣ́знемъ. тогда̀ предадѧ́тъ вы̀ въ скѡ́рби, и҆ ᲂу҆бїю́тъ вы̀: и҆ бꙋ́дете ненави́дими всѣ́ми ꙗ҆зы́ки и҆́мене моегѡ̀ ра́ди. и҆ тогда̀ соблазнѧ́тсѧ мно́зи, и҆ дрꙋ́гъ дрꙋ́га предадѧ́тъ, и҆ возненави́дитъ дрꙋ́гъ дрꙋ́га: и҆ мно́зи лжепроро́цы воста́нꙋтъ, и҆ прельстѧ́тъ мнѡ́гїѧ: и҆ за ᲂу҆множе́нїе беззако́нїѧ, и҆зсѧ́кнетъ любы̀ мно́гихъ. претерпѣ́вый же до конца̀, то́й спасе́тсѧ. и҆ проповѣ́стсѧ сїѐ є҆ѵⷢ҇лїе црⷭ҇твїѧ по все́й вселе́ннѣй, во свидѣ́тельство всѣ́мъ ꙗ҆зы́кѡмъ: и҆ тогда̀ прїи́детъ кончи́на. є҆гда̀ ᲂу҆́бѡ ᲂу҆́зрите ме́рзость запꙋстѣ́нїѧ, рече́ннꙋю данїи́ломъ проро́комъ, стоѧ́щꙋ на мѣ́стѣ ст҃ѣ: и҆́же чте́тъ, да разꙋмѣ́етъ: тогда̀ сꙋ́щїи во і҆ꙋде́и, да бѣжа́тъ на го́ры. и҆ и҆́же на кро́вѣ, да не схо́дитъ взѧ́ти ꙗ҆̀же въ домꙋ̀ є҆гѡ̀: и҆ и҆́же на селѣ̀, да не возврати́тсѧ вспѧ́ть взѧ́ти ри́зъ свои́хъ. го́ре же непра̑зднымъ, и҆ доѧ́щымъ въ ты́ѧ днѝ. моли́тесѧ же, да не бꙋ́детъ бѣ́гство ва́ше въ зимѣ̀, ни въ сꙋббѡ́тꙋ. бꙋ́детъ бо тогда̀ ско́рбь ве́лїѧ, ꙗ҆кова́ же нѣ́сть была̀ ѿ нача́ла мі́ра досе́лѣ, нижѐ и҆́мать бы́ти. и҆ а҆́ще не бы́ша прекрати́лисѧ дні́е ѻ҆́ны, не бы̀ ᲂу҆́бѡ спасла́сѧ всѧ́ка пло́ть: и҆збра́нныхъ же ра́ди прекратѧ́тсѧ дні́е ѻ҆́ны. тогда̀ а҆́ще кто̀ рече́тъ ва́мъ: сѐ здѣ̀ хрⷭ҇то́съ, и҆лѝ ѻ҆́ндѣ, не и҆ми́те вѣ́ры. воста́нꙋтъ бо лжехрі́сти и҆ лжепроро́цы, и҆ дадѧ́тъ зна́мєнїѧ вє́лїѧ и҆ чꙋдеса̀: ꙗ҆́коже прельсти́ти, а҆́ще возмо́жно, и҆ и҆збра̑нныѧ. сѐ пре́жде рѣ́хъ ва́мъ. а҆́ще ᲂу҆́бѡ рекꙋ́тъ ва́мъ, сѐ въ пꙋсты́ни є҆́сть, не и҆зыди́те: сѐ въ сокро́вищахъ, не и҆ми́те вѣ́ры. ꙗ҆́коже бо мо́лнїѧ и҆схо́дитъ ѿ востѡ́къ и҆ ꙗ҆влѧ́етсѧ до за̑падъ: та́кѡ бꙋ́детъ прише́ствїе сн҃а человѣ́ческагѡ. и҆дѣ́же бо а҆́ще бꙋ́детъ трꙋ́пъ, та́мѡ соберꙋ́тсѧ ѻ҆рлѝ. а҆́бїе же по ско́рби дні́й тѣ́хъ со́лнце поме́ркнетъ, и҆ лꙋна̀ не да́стъ свѣ́та своегѡ̀, и҆ ѕвѣ́зды спа́днꙋтъ съ небесѐ, и҆ си̑лы небє́сныѧ подви́гнꙋтсѧ. и҆ тогда̀ ꙗ҆ви́тсѧ зна́менїе сн҃а человѣ́ческагѡ на нб҃сѝ: и҆ тогда̀ воспла́чꙋтсѧ всѧ̀ колѣ́на земна̑ѧ, и҆ ᲂу҆́зрѧтъ сн҃а человѣ́ческаго, грѧдꙋ́ща на ѻ҆́блацѣхъ небе́сныхъ съ си́лою и҆ сла́вою мно́гою. и҆ по́слетъ а҆́гг҃лы своѧ̀ съ трꙋ́бнымъ гла́сомъ ве́лїимъ, и҆ соберꙋ́тъ и҆збра̑нныѧ є҆гѡ̀ ѿ четы́рехъ вѣ̑тръ, ѿ конє́цъ нб҃съ до конє́цъ и҆́хъ. ѿ смоко́вницы же наꙋчи́тесѧ при́тчи: є҆гда̀ ᲂу҆жѐ ва̑їѧ є҆ѧ̀ бꙋ́дꙋтъ мла̑да и҆ ли́ствїе прозѧ́бнетъ, вѣ́дите, ꙗ҆́кѡ бли́зъ є҆́сть жа́тва. та́кѡ и҆ вы̀, є҆гда̀ ви́дите сїѧ̑ всѧ̑, вѣ́дите, ꙗ҆́кѡ бли́зъ є҆́сть при две́рехъ. а҆ми́нь глаго́лю ва́мъ: не мимои́детъ ро́дъ се́й, до́ндеже всѧ̑ сїѧ̑ бꙋ́дꙋтъ. не́бо и҆ землѧ̀ мимои́детъ: словеса́ же моѧ̀ не мимои́дꙋтъ. ",
}

