add_evangelie_matfea {
  ["номер"] = 100,
  ["комментарий"] = "Мф., 100 зач., XXIV, 27–33, 42–51.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: я́коже мо́лния исхо́дит от восто́к и явля́ется до за́пад, та́ко бу́дет прише́ствие Сы́на Челове́ческаго, иде́же бо а́ще бу́дет труп, та́мо соберу́тся орли́. А́бие же, по ско́рби дний тех, со́лнце поме́ркнет, и луна́ не даст све́та своего́, и зве́зды спа́днут с небесе́, и си́лы небе́сныя подви́гнутся, и тогда́ яви́тся зна́мение Сы́на Челове́ческаго на небеси́, и тогда́ воспла́чутся вся коле́на земна́я и у́зрят Сы́на Челове́ческаго гряду́ща на о́блацех небе́сных с си́лою и сла́вою мно́гою, и по́слет А́нгелы Своя́ с тру́бным гла́сом ве́лиим, и соберу́т избра́нныя Его́ от четы́рех ветр, от коне́ц небе́с до коне́ц их. От смоко́вницы же научи́теся при́тчи: егда́ уже́ ва́ия ея́ бу́дут мла́да, и ли́ствие прозя́бнет, ве́дите, я́ко близ есть жа́тва. Та́ко и вы, егда́ ви́дите сия́ вся, ве́дите, я́ко близ есть, при две́рех. Бди́те у́бо, я́ко не ве́сте, в кий час Госпо́дь ваш прии́дет. Сие́ же ве́дите, я́ко а́ще бы ве́дал до́му влады́ка, в ку́ю стра́жу тать прии́дет, бдел у́бо бы и не бы дал подкопа́ти хра́ма своего́. Сего́ ра́ди и вы бу́дите гото́ви, я́ко во́ньже час не мните́, Сын Челове́ческий прии́дет. Кто у́бо есть ве́рный раб и му́дрый, его́же поста́вит господи́н его́ над до́мом свои́м, е́же дая́ти им пи́щу во вре́мя их? Блаже́н раб той, его́же, прише́д господи́н его́, обря́щет та́ко творя́ща. Ами́нь глаго́лю вам, я́ко над всем име́нием свои́м поста́вит его́. А́ще ли же рече́т злый раб той в се́рдцы свое́м: косни́т господи́н мой приити́, и на́чнет би́ти клевре́ты своя́, я́сти же и пи́ти с пия́ницами, прии́дет господи́н раба́ того́ в день, во́ньже не ча́ет, и в час, во́ньже не весть, и проте́шет его́ полма́, и часть его́ с неве́рными положи́т, ту бу́дет плачь и скре́жет зубо́м. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: ꙗ҆́коже мо́лнїѧ и҆схо́дитъ ѿ востѡ́къ и҆ ꙗ҆влѧ́етсѧ до за̑падъ: та́кѡ бꙋ́детъ прише́ствїе сн҃а человѣ́ческагѡ. и҆дѣ́же бо а҆́ще бꙋ́детъ трꙋ́пъ, та́мѡ соберꙋ́тсѧ ѻ҆рлѝ. а҆́бїе же по ско́рби дні́й тѣ́хъ со́лнце поме́ркнетъ, и҆ лꙋна̀ не да́стъ свѣ́та своегѡ̀, и҆ ѕвѣ́зды спа́днꙋтъ съ небесѐ, и҆ си̑лы небє́сныѧ подви́гнꙋтсѧ. и҆ тогда̀ ꙗ҆ви́тсѧ зна́менїе сн҃а человѣ́ческагѡ на нб҃сѝ: и҆ тогда̀ воспла́чꙋтсѧ всѧ̀ колѣ́на земна̑ѧ, и҆ ᲂу҆́зрѧтъ сн҃а человѣ́ческаго, грѧдꙋ́ща на ѻ҆́блацѣхъ небе́сныхъ съ си́лою и҆ сла́вою мно́гою. и҆ по́слетъ а҆́гг҃лы своѧ̀ съ трꙋ́бнымъ гла́сомъ ве́лїимъ, и҆ соберꙋ́тъ и҆збра̑нныѧ є҆гѡ̀ ѿ четы́рехъ вѣ̑тръ, ѿ конє́цъ нб҃съ до конє́цъ и҆́хъ. ѿ смоко́вницы же наꙋчи́тесѧ при́тчи: є҆гда̀ ᲂу҆жѐ ва̑їѧ є҆ѧ̀ бꙋ́дꙋтъ мла̑да и҆ ли́ствїе прозѧ́бнетъ, вѣ́дите, ꙗ҆́кѡ бли́зъ є҆́сть жа́тва. та́кѡ и҆ вы̀, є҆гда̀ ви́дите сїѧ̑ всѧ̑, вѣ́дите, ꙗ҆́кѡ бли́зъ є҆́сть при две́рехъ. бди́те ᲂу҆́бѡ, ꙗ҆́кѡ не вѣ́сте, въ кі́й ча́съ гдⷭ҇ь ва́шъ прїи́детъ. сїе́ же вѣ́дите, ꙗ҆́кѡ а҆́ще бы вѣ́далъ до́мꙋ влады́ка, въ кꙋ́ю стра́жꙋ та́ть прїи́детъ, бдѣ́лъ ᲂу҆́бѡ бы, и҆ не бы̀ да́лъ подкопа́ти хра́ма своегѡ̀. сегѡ̀ ра́ди и҆ вы̀ бꙋ́дите гото́ви, ꙗ҆́кѡ во́ньже ча́съ не мнитѐ, сн҃ъ человѣ́ческїй прїи́детъ. кто̀ ᲂу҆̀бо є҆́сть вѣ́рный ра́бъ и҆ мꙋ́дрый, є҆го́же поста́витъ гдⷭ҇и́нъ є҆гѡ̀ над̾ до́момъ свои́мъ, є҆́же даѧ́ти и҆̀мъ пи́щꙋ во вре́мѧ и҆́хъ; бл҃же́нъ ра́бъ то́й, є҆го́же прише́дъ гдⷭ҇и́нъ є҆гѡ̀ ѡ҆брѧ́щетъ та́кѡ творѧ́ща. а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ над̾ всѣ́мъ и҆мѣ́нїемъ свои́мъ поста́витъ є҆го̀. а҆́ще ли же рече́тъ ѕлы́й ра́бъ то́й въ се́рдцы свое́мъ, косни́тъ гдⷭ҇и́нъ мо́й прїитѝ: и҆ на́чнетъ би́ти клевре́ты своѧ̀, ꙗ҆́сти же и҆ пи́ти съ пїѧ́ницами: прїи́детъ гдⷭ҇и́нъ раба̀ тогѡ̀ въ де́нь, во́ньже не ча́етъ, и҆ въ ча́съ, во́ньже не вѣ́сть. и҆ проте́шетъ є҆го̀ полма̀, и҆ ча́сть є҆гѡ̀ съ невѣ́рными положи́тъ: тꙋ̀ бꙋ́детъ пла́чь и҆ скре́жетъ зꙋбѡ́мъ. ",
}

add_evangelie_matfea {
  ["номер"] = 101,
  ["комментарий"] = "Мф., 101 зач., XXIV, 34–44.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: ами́нь глаго́лю вам, не мимои́дет род сей, до́ндеже вся сия́ бу́дут, не́бо и земля́ мимои́дет, словеса́ же Моя́ не мимои́дут. О дни же том и часе́ никто́же весть, ни А́нгели небе́снии, то́кмо Оте́ц Мой еди́н. Я́коже бо бысть во дни Но́евы, та́ко бу́дет и прише́ствие Сы́на Челове́ческаго. Я́коже бо бе́ху во дни пре́жде пото́па яду́ще и пию́ще, женя́щеся и посяга́юще, до него́же дне вни́де Но́е в ковче́г, и не уве́деша, до́ндеже прии́де вода́ и взят вся, та́ко бу́дет и прише́ствие Сы́на Челове́ческаго. Тогда́ два бу́дета на селе́, еди́н пое́млется, а други́й оставля́ется. Две ме́люще в же́рновех, еди́на пое́млется, и еди́на оставля́ется. Бди́те у́бо, я́ко не ве́сте, в кий час Госпо́дь ваш прии́дет. Сие́ же ве́дите, я́ко а́ще бы ве́дал до́му влады́ка, в ку́ю стра́жу тать прии́дет, бдел у́бо бы и не бы дал подкопа́ти хра́ма своего́. Сего́ ра́ди и вы бу́дите гото́ви, я́ко, во́ньже час не мните́, Сын Челове́ческий прии́дет. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: а҆ми́нь глаго́лю ва́мъ: не мимои́детъ ро́дъ се́й, до́ндеже всѧ̑ сїѧ̑ бꙋ́дꙋтъ. не́бо и҆ землѧ̀ мимои́детъ: словеса́ же моѧ̀ не мимои́дꙋтъ. ѡ҆ дни́ же то́мъ и҆ часѣ̀ никто́же вѣ́сть, ни а҆́гг҃ли нбⷭ҇нїи, то́кмѡ ѻ҆ц҃ъ мо́й є҆ди́нъ. ꙗ҆́коже бо бы́сть во днѝ нѡ́евы: та́кѡ бꙋ́детъ и҆ прише́ствїе сн҃а человѣ́ческагѡ. ꙗ҆́коже бо бѣ́хꙋ во днѝ пре́жде пото́па, ꙗ҆дꙋ́ще и҆ пїю́ще, женѧ́щесѧ и҆ посѧга́юще, до негѡ́же днѐ вни́де нѡ́е въ ковче́гъ: и҆ не ᲂу҆вѣ́дѣша, до́ндеже прїи́де вода̀, и҆ взѧ́тъ всѧ̑: та́кѡ бꙋ́детъ и҆ прише́ствїе сн҃а человѣ́ческагѡ. тогда̀ два̀ бꙋ́дета на селѣ̀: є҆ди́нъ пое́млетсѧ, а҆ дрꙋгі́й ѡ҆ставлѧ́етсѧ, двѣ̀ ме́лющѣ въ же́рновахъ: є҆ди́на пое́млетсѧ, и҆ є҆ди́на ѡ҆ставлѧ́етсѧ. бди́те ᲂу҆́бѡ, ꙗ҆́кѡ не вѣ́сте, въ кі́й ча́съ гдⷭ҇ь ва́шъ прїи́детъ. сїе́ же вѣ́дите, ꙗ҆́кѡ а҆́ще бы вѣ́далъ до́мꙋ влады́ка, въ кꙋ́ю стра́жꙋ та́ть прїи́детъ, бдѣ́лъ ᲂу҆́бѡ бы, и҆ не бы̀ да́лъ подкопа́ти хра́ма своегѡ̀. сегѡ̀ ра́ди и҆ вы̀ бꙋ́дите гото́ви, ꙗ҆́кѡ во́ньже ча́съ не мнитѐ, сн҃ъ человѣ́ческїй прїи́детъ. ",
}

add_evangelie_matfea {
  ["номер"] = 102,
  ["комментарий"] = "Мф., 102 зач., XXIV, 36 - XXVI, 2.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: о дни и часе́ прише́ствия Сы́на Челове́ческаго никто́же весть, ни А́нгели Небе́снии, то́кмо Оте́ц Мой еди́н. Я́коже бо бысть во дни Но́евы, та́ко бу́дет и прише́ствие Сы́на Челове́ческаго. Я́коже бо бе́ху во дни пре́жде пото́па я́дуще и пию́ще, женя́щеся и посяга́юще, до него́же дне вни́де Но́е в ковче́г, и не уве́деша, до́ндеже прии́де вода́ и взят вся, та́ко бу́дет и прише́ствие Сы́на Челове́ческаго. Тогда́ два бу́дета на селе́, еди́н пое́млется, а други́й оставля́ется, две ме́люще в же́рновах, еди́на пое́млется, и еди́на оставля́ется. Бди́те у́бо, я́ко не ве́сте, в кий час Госпо́дь ваш прии́дет. Сие́ же ве́дите, я́ко а́ще бы ве́дал до́му влады́ка, в ку́ю стра́жу тать прии́дет, бдел у́бо бы и не бы дал подкопа́ти хра́ма своего́. Сего́ ра́ди и вы бу́дите гото́ви, я́ко, во́ньже час не мните́, Сын Челове́ческий прии́дет. Кто у́бо есть ве́рный раб и му́дрый, его́же поста́вит господи́н его́ над до́мом свои́м, е́же дая́ти им пи́щу во вре́мя их? Блаже́н раб той, его́же, прише́д господи́н его́, обря́щет та́ко творя́ща, ами́нь глаго́лю вам, я́ко над всем име́нием свои́м поста́вит его́. А́ще ли же рече́т злый раб той в се́рдцы свое́м: косни́т господи́н мой приити́, и на́чнет би́ти клевре́ты своя́, я́сти же и пи́ти с пия́ницами, прии́дет господи́н раба́ того́ в день, во́ньже не ча́ет, и в час, во́ньже не весть, и проте́шет его́ полма́, и часть его́ с неве́рными положи́т, ту бу́дет плачь и скре́жет зубо́м. Тогда́ уподо́бися Ца́рствие Небе́сное десяти́м де́вам, я́же прия́ша свети́льники своя́ и изыдо́ша в сре́тение жениху́, пять же бе от них мудры́ и пять юро́дивы. Юро́дивыя же, прие́мшя свети́льники своя́, не взя́ша с собо́ю еле́а, му́дрыя же прия́ша еле́й в сосу́дех со свети́льники свои́ми, косня́щу же жениху́, воздрема́шася вся и спа́ху. Полу́нощи же вопль бысть: се жени́х гряде́т, исходи́те в сре́тение его́. Тогда́ воста́вша вся де́вы ты́я и украси́ша свети́льники своя́. Юро́дивыя же му́дрым ре́ша: дади́те нам от еле́а ва́шего, я́ко свети́льницы на́ши угаса́ют. Отвеща́ша же му́дрыя, глаго́люще: еда́ ка́ко не доста́нет нам и вам, иди́те же па́че к продаю́щым и купи́те себе́. Иду́щым же им купи́ти, прии́де жени́х, и гото́выя внидо́ша с ним на бра́ки, и затворе́ны бы́ша две́ри. Последи́ же приидо́ша и про́чыя де́вы, глаго́люще: Го́споди, Го́споди, отве́рзи нам. Он же отвеща́в рече́ им: ами́нь глаго́лю вам, не вем вас. Бди́те у́бо, я́ко не ве́сте дне ни часа́, во́ньже Сын Челове́ческий прии́дет. Я́коже бо челове́к не́кий отходя́ призва́ своя́ рабы́ и предаде́ им име́ние свое́. И о́вому у́бо даде́ пять тала́нт, о́вому же два, о́вому же еди́н, кому́ждо проти́ву си́лы его́, и оты́де а́бие. Шед же прие́мый пять тала́нт, де́ла в них и сотвори́ други́я пять тала́нт. Та́кожде и и́же два, приобре́те и той друга́я два. Прие́мый же еди́н, шед вкопа́ его́ в зе́млю и скры сребро́ господи́на своего́. По мно́зе же вре́мени прии́де господи́н раб тех и стяза́ся с ни́ми о словеси́. И присту́пль пять тала́нт прие́мый, принесе́ други́я пять тала́нт, глаго́ля: го́споди, пять тала́нт ми еси́ пре́дал, се други́я пять тала́нт приобрето́х и́ми. Рече́ же ему́ госпо́дь его́: до́брый, ра́бе благи́й и ве́рный, о ма́ле был еси́ ве́рен, над мно́гими тя поста́влю, вни́ди в ра́дость го́спода твоего́. Присту́пль же и и́же два тала́нта прие́мый, рече́: го́споди, два тала́нта ми еси́ пре́дал, се друга́я два тала́нта приобрето́х и́ма. Рече́ же ему́ госпо́дь его́: до́брый ра́бе, благи́й и ве́рный, о ма́ле ми был еси́ ве́рен, над мно́гими тя поста́влю, вни́ди в ра́дость го́спода твоего́. Присту́пль же и прие́мый еди́н тала́нт, рече́: го́споди, ве́дях тя, я́ко же́сток еси́ челове́к, жне́ши, иде́же не се́ял еси́, и собира́еши ю́дуже не расточи́л еси́, и убоя́вся, шед скрых тала́нт твой в земли́, и се и́маши твое́. Отвеща́в же госпо́дь его́ рече́ ему́: лука́вый ра́бе и лени́вый, ве́дяше, я́ко жну иде́же не се́ях, и собира́ю иде́же не расточи́х, подоба́ше у́бо тебе́ вда́ти сребро́ мое́ торжнико́м, и прише́д аз взял бых свое́ с ли́хвою. Возми́те у́бо от него́ тала́нт и дади́те иму́щему де́сять тала́нт, иму́щему бо везде́ дано́ бу́дет и преизбу́дет, от неиму́щаго же, и е́же мни́тся име́я, взя́то бу́дет от него́. И неключи́маго раба́ вве́рзите во тму кроме́шнюю, ту бу́дет плачь и скре́жет зубо́м. Сия́ глаго́ля возгласи́: име́яй у́ши слы́шати да слы́шит. Егда́ же прии́дет Сын Челове́ческий в сла́ве Свое́й и вси святи́и А́нгели с Ним, тогда́ ся́дет на престо́ле сла́вы Своея́, и соберу́тся пред Ним вси язы́цы, и разлучи́т их друг от дру́га, я́коже па́стырь разлуча́ет о́вцы от ко́злищ, и поста́вит о́вцы одесну́ю Себе́, а ко́злища ошу́юю. Тогда́ рече́т Царь су́щым одесну́ю Его́: прииди́те, благослове́ннии Отца́ Моего́, насле́дуйте угото́ванное вам Ца́рствие от сложе́ния ми́ра, взалка́хся бо, и да́сте Ми я́сти, возжада́хся, и напои́сте Мя, стра́нен бех, и введо́сте Мене́, наг, и оде́ясте Мя, бо́лен, и посети́сте Мене́, в темни́це бех, и приидо́сте ко Мне. Тогда́ отвеща́ют Ему́ пра́ведницы, глаго́люще: Го́споди, когда́ Тя ви́дехом а́лчуща, и напита́хом? Или́ жа́ждуща, и напои́хом? Когда́ же Тя ви́дехом стра́нна, и введо́хом? Или́ на́га, и оде́яхом? Когда́ же Тя ви́дехом боля́ща, или́ в темни́це, и приидо́хом к Тебе́? И отвеща́в Царь рече́т им: ами́нь глаго́лю вам, поне́же сотвори́сте еди́ному сих бра́тий Мои́х ме́ньших, Мне сотвори́сте. Тогда́ рече́т и су́щым ошу́юю Его́: иди́те от Мене́, прокля́тии, во огнь ве́чный, угото́ванный диа́волу и а́ггелом его́, взалка́хся бо, и не да́сте Ми я́сти, возжада́хся, и не напои́сте Мене́, стра́нен бех, и не введо́сте Мене́, наг, и не оде́ясте Мене́, бо́лен и в темни́це, и не посети́сте Мене́. Тогда́ отвеща́ют Ему́ и ти́и, глаго́люще: Го́споди, когда́ Тя ви́дехом а́лчуща, или́ жа́ждуща, или́ стра́нна, или́ на́га, или́ бо́льна, или́ в темни́це, и не послужи́хом Тебе́? Тогда́ отвеща́ет им, глаго́ля: ами́нь глаго́лю вам, поне́же не сотвори́сте еди́ному сих ме́ньших, ни Мне сотвори́сте. И и́дут си́и в му́ку ве́чную, пра́ведницы же в живо́т ве́чный. И бысть, егда́ сконча́ Иису́с вся словеса́ сия́, рече́ ученико́м Свои́м: ве́сте, я́ко по двою́ дню Па́сха бу́дет, и Сын Челове́ческий пре́дан бу́дет на пропя́тие. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: ѡ҆ днѝ и҆ часѣ̀ прише́ствїѧ сн҃а человѣ́ческагѡ никто́же вѣ́сть, ни а҆́гг҃ли нбⷭ҇нїи, то́кмѡ ѻ҆ц҃ъ мо́й є҆ди́нъ. ꙗ҆́коже бо бы́сть во днѝ нѡ́евы: та́кѡ бꙋ́детъ и҆ прише́ствїе сн҃а человѣ́ческагѡ. ꙗ҆́коже бо бѣ́хꙋ во днѝ пре́жде пото́па, ꙗ҆дꙋ́ще и҆ пїю́ще, женѧ́щесѧ и҆ посѧга́юще, до негѡ́же днѐ вни́де нѡ́е въ ковче́гъ: и҆ не ᲂу҆вѣ́дѣша, до́ндеже прїи́де вода̀, и҆ взѧ́тъ всѧ̑: та́кѡ бꙋ́детъ и҆ прише́ствїе сн҃а человѣ́ческагѡ. тогда̀ два̀ бꙋ́дета на селѣ̀: є҆ди́нъ пое́млетсѧ, а҆ дрꙋгі́й ѡ҆ставлѧ́етсѧ, двѣ̀ ме́лющѣ въ же́рновахъ: є҆ди́на пое́млетсѧ, и҆ є҆ди́на ѡ҆ставлѧ́етсѧ. бди́те ᲂу҆́бѡ, ꙗ҆́кѡ не вѣ́сте, въ кі́й ча́съ гдⷭ҇ь ва́шъ прїи́детъ. сїе́ же вѣ́дите, ꙗ҆́кѡ а҆́ще бы вѣ́далъ до́мꙋ влады́ка, въ кꙋ́ю стра́жꙋ та́ть прїи́детъ, бдѣ́лъ ᲂу҆́бѡ бы, и҆ не бы̀ да́лъ подкопа́ти хра́ма своегѡ̀. сегѡ̀ ра́ди и҆ вы̀ бꙋ́дите гото́ви, ꙗ҆́кѡ во́ньже ча́съ не мнитѐ, сн҃ъ человѣ́ческїй прїи́детъ. кто̀ ᲂу҆̀бо є҆́сть вѣ́рный ра́бъ и҆ мꙋ́дрый, є҆го́же поста́витъ гдⷭ҇и́нъ є҆гѡ̀ над̾ до́момъ свои́мъ, є҆́же даѧ́ти и҆̀мъ пи́щꙋ во вре́мѧ и҆́хъ; бл҃же́нъ ра́бъ то́й, є҆го́же прише́дъ гдⷭ҇и́нъ є҆гѡ̀ ѡ҆брѧ́щетъ та́кѡ творѧ́ща. а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ над̾ всѣ́мъ и҆мѣ́нїемъ свои́мъ поста́витъ є҆го̀. а҆́ще ли же рече́тъ ѕлы́й ра́бъ то́й въ се́рдцы свое́мъ, косни́тъ гдⷭ҇и́нъ мо́й прїитѝ: и҆ на́чнетъ би́ти клевре́ты своѧ̀, ꙗ҆́сти же и҆ пи́ти съ пїѧ́ницами: прїи́детъ гдⷭ҇и́нъ раба̀ тогѡ̀ въ де́нь, во́ньже не ча́етъ, и҆ въ ча́съ, во́ньже не вѣ́сть. и҆ проте́шетъ є҆го̀ полма̀, и҆ ча́сть є҆гѡ̀ съ невѣ́рными положи́тъ: тꙋ̀ бꙋ́детъ пла́чь и҆ скре́жетъ зꙋбѡ́мъ. тогда̀ ᲂу҆подо́бисѧ црⷭ҇твїе нбⷭ҇ное десѧти́мъ дѣ́вамъ, ꙗ҆̀же прїѧ́ша свѣти́льники своѧ̀, и҆ и҆зыдо́ша въ срѣ́тенїе женихꙋ̀. пѧ́ть же бѣ̀ ѿ ни́хъ мꙋдры̀, и҆ пѧ́ть ю҆рѡ́дивы. ю҆рѡ́дивыѧ же прїе́мше свѣти́льники своѧ̀, не взѧ́ша съ собо́ю є҆ле́а. мꙋ́дрыѧ же прїѧ́ша є҆ле́й въ сосꙋ́дѣхъ, со свѣти́льники свои́ми. коснѧ́щꙋ же женихꙋ̀, воздрема́шасѧ всѧ̑, и҆ спа́хꙋ. полꙋ́нощи же во́пль бы́сть: сѐ жени́хъ грѧде́тъ, и҆сходи́те въ срѣ́тенїе є҆гѡ̀. тогда̀ воста́вше всѧ̀ дѣ́вы ты́ѧ, и҆ ᲂу҆краси́ша свѣти́льники своѧ̀. ю҆рѡ́дивыѧ же мꙋ̑дрымъ рѣ́ша: дади́те на́мъ ѿ є҆ле́а ва́шегѡ, ꙗ҆́кѡ свѣти́льницы на́ши ᲂу҆гаса́ютъ. ѿвѣща́ша же мꙋ́дрыѧ, глаго́люще: є҆да̀ ка́кѡ не доста́нетъ на́мъ и҆ ва́мъ: и҆ди́те же па́че къ продаю́щымъ, и҆ кꙋпи́те себѣ̀. и҆дꙋ́щымъ же и҆̀мъ кꙋпи́ти, прїи́де жени́хъ, и҆ готѡ́выѧ внидо́ша съ ни́мъ на бра́ки: и҆ затворе́ны бы́ша двє́ри. послѣди́ же прїидо́ша и҆ про́чыѧ дѣ́вы, глаго́люще: гдⷭ҇и, гдⷭ҇и, ѿве́рзи на́мъ. ѻ҆́нъ же ѿвѣща́въ, речѐ и҆̀мъ: а҆ми́нь глаго́лю ва́мъ, не вѣ́мъ ва́съ. бди́те ᲂу҆̀бо, ꙗ҆́кѡ не вѣ́сте днѐ, ни часа̀, во́ньже сн҃ъ человѣ́ческїй прїи́детъ. ꙗ҆́коже бо человѣ́къ нѣ́кїй ѿходѧ̀ призва̀ своѧ̀ рабы̑, и҆ предадѐ и҆̀мъ и҆мѣ́нїе своѐ. и҆ ѻ҆́вомꙋ ᲂу҆́бѡ дадѐ пѧ́ть тала̑нтъ, ѻ҆́вомꙋ же два̀, ѻ҆́вомꙋ же є҆ди́нъ, комꙋ́ждо проти́вꙋ си́лы є҆гѡ̀: и҆ ѿи́де а҆́бїе. ше́дъ же прїе́мый пѧ́ть тала̑нтъ, дѣ́ла въ ни́хъ, и҆ сотворѝ дрꙋгі́ѧ пѧ́ть тала̑нтъ. та́кожде и҆ и҆́же два̀, прїѡбрѣ́те и҆ то́й дрꙋга̑ѧ два̀. прїе́мый же є҆ди́нъ, ше́дъ вкопа̀ є҆го̀ въ зе́млю, и҆ скры̀ сребро̀ гдⷭ҇и́на своегѡ̀. по мно́зѣ же вре́мени прїи́де гдⷭ҇и́нъ ра̑бъ тѣ́хъ, и҆ стѧза́сѧ съ ни́ми ѡ҆ словесѝ. и҆ пристꙋ́пль пѧ́ть тала̑нтъ прїе́мый, принесѐ дрꙋгі́ѧ пѧ́ть тала̑нтъ, глаго́лѧ: гдⷭ҇и, пѧ́ть тала̑нтъ мѝ є҆сѝ пре́далъ, сѐ дрꙋгі́ѧ пѧ́ть тала̑нтъ прїѡбрѣто́хъ и҆́ми. рече́ же є҆мꙋ̀ гдⷭ҇ь є҆гѡ̀: до́брый ра́бе, бл҃гі́й и҆ вѣ́рный, ѡ҆ ма́лѣ бы́лъ є҆сѝ вѣ́ренъ, над̾ мно́гими тѧ̀ поста́влю: вни́ди въ ра́дость гдⷭ҇а твоегѡ̀. пристꙋ́пль же и҆ и҆́же два̀ тала́нта прїе́мый, речѐ: гдⷭ҇и, два̀ тала́нта мѝ є҆сѝ пре́далъ, сѐ дрꙋга̑ѧ два̀ тала́нта прїѡбрѣто́хъ и҆́ма. рече́ же є҆мꙋ̀ гдⷭ҇ь є҆гѡ̀: до́брый ра́бе, благі́й и҆ вѣ́рный, ѡ҆ ма́лѣ мѝ бы́лъ є҆сѝ вѣ́ренъ, над̾ мно́гими тѧ̀ поста́влю: вни́ди въ ра́дость гдⷭ҇а твоегѡ̀. пристꙋ́пль же и҆ прїе́мый є҆ди́нъ тала́нтъ, речѐ: гдⷭ҇и, вѣ́дѧхъ тѧ̀, ꙗ҆́кѡ же́стокъ є҆сѝ человѣ́къ: жне́ши, и҆дѣ́же не сѣ́ѧлъ є҆сѝ, и҆ собира́еши, ю҆́дꙋже не расточи́лъ є҆сѝ: и҆ ᲂу҆боѧ́всѧ ше́дъ скры́хъ тала́нтъ тво́й въ землѝ, и҆ сѐ и҆́маши твоѐ. ѿвѣща́въ же гдⷭ҇ь є҆гѡ̀, речѐ є҆мꙋ̀: лꙋка́вый ра́бе и҆ лѣни́вый, вѣ́дѧше, ꙗ҆́кѡ жнꙋ̀, и҆дѣ́же не сѣ́ѧхъ, и҆ собира́ю, ю҆́дꙋже не расточи́хъ: подоба́ше ᲂу҆̀бо тебѣ̀ вда́ти сребро̀ моѐ торжникѡ́мъ, и҆ прише́дъ а҆́зъ взѧ́лъ бы́хъ своѐ съ ли́хвою. воз̾ми́те ᲂу҆̀бо ѿ негѡ̀ тала́нтъ, и҆ дади́те и҆мꙋ́щемꙋ де́сѧть тала̑нтъ. и҆мꙋ́щемꙋ бо вездѣ̀ дано̀ бꙋ́детъ, и҆ преизбꙋ́детъ: ѿ неимꙋ́щагѡ же, и҆ є҆́же мни́тсѧ и҆мѣ́ѧ, взѧ́то бꙋ́детъ ѿ негѡ̀. и҆ неключи́маго раба̀ вве́рзите во тмꙋ̀ кромѣ́шнюю: тꙋ̀ бꙋ́детъ пла́чь и҆ скре́жетъ зꙋбѡ́мъ. сїѧ̑ глаго́лѧ возгласѝ: и҆мѣ́ѧй ᲂу҆́ши слы́шати, да слы́шитъ. є҆гда́ же прїи́детъ сн҃ъ человѣ́ческїй въ сла́вѣ свое́й, и҆ всѝ ст҃і́и а҆́гг҃ли съ ни́мъ, тогда̀ сѧ́детъ на прⷭ҇то́лѣ сла́вы своеѧ̀: и҆ соберꙋ́тсѧ пред̾ ни́мъ всѝ ꙗ҆зы́цы, и҆ разлꙋчи́тъ и҆̀хъ дрꙋ́гъ ѿ дрꙋ́га, ꙗ҆́коже па́стырь разлꙋча́етъ ѻ҆́вцы ѿ ко́злищъ. и҆ поста́витъ ѻ҆́вцы ѡ҆деснꙋ́ю себѐ, а҆ кѡ́злища ѡ҆шꙋ́юю. тогда̀ рече́тъ цр҃ь сꙋ́щымъ ѡ҆деснꙋ́ю є҆гѡ̀: прїиди́те благослове́ннїи ѻ҆ц҃а̀ моегѡ̀, наслѣ́дꙋйте ᲂу҆гото́ванное ва́мъ црⷭ҇твїе ѿ сложе́нїѧ мі́ра. взалка́хсѧ бо, и҆ да́сте мѝ ꙗ҆́сти: возжада́хсѧ, и҆ напои́сте мѧ̀: стра́ненъ бѣ́хъ, и҆ введо́сте менѐ: на́гъ, и҆ ѡ҆дѣ́ѧсте мѧ̀: бо́ленъ, и҆ посѣти́сте менѐ: въ темни́цѣ бѣ́хъ, и҆ прїидо́сте ко мнѣ̀. тогда̀ ѿвѣща́ютъ є҆мꙋ̀ пра́вєдницы, глаго́люще: гдⷭ҇и, когда́ тѧ ви́дѣхомъ а҆́лчꙋща, и҆ напита́хомъ; и҆лѝ жа́ждꙋща, и҆ напои́хомъ; когда́ же тѧ̀ ви́дѣхомъ стра́нна, и҆ введо́хомъ; и҆лѝ на́га, и҆ ѡ҆дѣ́ѧхомъ; когда́ же тѧ̀ ви́дѣхомъ болѧ́ща, и҆лѝ въ темни́цѣ, и҆ прїидо́хомъ къ тебѣ̀; и҆ ѿвѣща́въ цр҃ь рече́тъ и҆̀мъ: а҆ми́нь глаго́лю ва́мъ, поне́же сотвори́сте є҆ди́номꙋ си́хъ бра́тїй мои́хъ ме́ньшихъ, мнѣ̀ сотвори́сте. тогда̀ рече́тъ и҆ сꙋ́щымъ ѡ҆шꙋ́юю є҆гѡ̀: и҆ди́те ѿ менѐ проклѧ́тїи ко ѻ҆́гнь вѣ́чный, ᲂу҆гото́ванный дїа́волꙋ и҆ а҆́ггелѡмъ є҆гѡ̀. взалка́хсѧ бо, и҆ не да́сте мѝ ꙗ҆́сти: возжада́хсѧ, и҆ не напои́сте менѐ. стра́ненъ бѣ́хъ, и҆ не введо́сте менѐ: на́гъ, и҆ не ѡ҆дѣ́ѧсте менѐ: бо́ленъ, и҆ въ темни́цѣ, и҆ не посѣти́сте менѐ. тогда̀ ѿвѣща́ютъ є҆мꙋ̀ и҆ ті́и, глаго́люще: гдⷭ҇и, когда́ тѧ ви́дѣхомъ а҆́лчꙋща, и҆лѝ жа́ждꙋща, и҆лѝ стра́нна, и҆лѝ на́га, и҆лѝ бо́льна, и҆лѝ въ темни́цѣ, и҆ не послꙋжи́хомъ тебѣ̀; тогда̀ ѿвѣща́етъ и҆̀мъ, глаго́лѧ: а҆ми́нь глаго́лю ва́мъ, поне́же не сотвори́сте є҆ди́номꙋ си́хъ ме́ньшихъ, ни мнѣ̀ сотвори́сте. и҆ и҆́дꙋтъ сі́и въ мꙋ́кꙋ вѣ́чнꙋю, пра́вєдницы же въ живо́тъ вѣ́чный. и҆ бы́сть, є҆гда̀ сконча̀ і҆и҃съ всѧ̀ словеса̀ сїѧ̀, речѐ ᲂу҆ченикѡ́мъ свои́мъ: вѣ́сте, ꙗ҆́кѡ по двою̀ дню̀ па́сха бꙋ́детъ, и҆ сн҃ъ человѣ́ческїй пре́данъ бꙋ́детъ на пропѧ́тїе. ",
}

add_evangelie_matfea {
