add_evangelie_matfea {
  ["номер"] = 104,
  ["комментарий"] = "Мф., 104 зач., XXV, 1–13.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: уподо́бися Ца́рствие Небе́сное десяти́м де́вам, я́же прия́ша свети́льники своя́ и изыдо́ша в сре́тение жениху́, пять же бе от них мудры́ и пять юро́дивы. Юро́дивыя же, прие́мше свети́льники своя́, не взя́ша с собо́ю еле́а, му́дрыя же прия́ша еле́й в сосу́дех со свети́льники свои́ми, косня́щу же жениху́, воздрема́шася вся и спа́ху. Полу́нощи же вопль бысть: се жени́х гряде́т, исходи́те в сре́тение его́. Тогда́ воста́вше вся де́вы ты́я и украси́ша свети́льники своя́. Юро́дивыя же му́дрым ре́ша: дади́те нам от еле́а ва́шего, я́ко свети́льницы на́ши угаса́ют. Отвеща́ша же му́дрыя, глаго́люще: еда́ ка́ко не доста́нет нам и вам, иди́те же па́че к продаю́щым и купи́те себе́. Иду́щым же им купи́ти, прии́де жени́х, и гото́выя внидо́ша с ним на бра́ки, и затворе́ны бы́ша две́ри. Последи́ же приидо́ша и про́чыя де́вы, глаго́люще: Го́споди, Го́споди, отве́рзи нам. Он же отвеща́в рече́ им: ами́нь глаго́лю вам, не вем вас. Бди́те у́бо, я́ко не ве́сте дне ни часа́, во́ньже Сын Челове́ческий прии́дет. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: ᲂу҆подо́бисѧ црⷭ҇твїе нбⷭ҇ное десѧти́мъ дѣ́вамъ, ꙗ҆̀же прїѧ́ша свѣти́льники своѧ̀, и҆ и҆зыдо́ша въ срѣ́тенїе женихꙋ̀. пѧ́ть же бѣ̀ ѿ ни́хъ мꙋдры̀, и҆ пѧ́ть ю҆рѡ́дивы. ю҆рѡ́дивыѧ же прїе́мше свѣти́льники своѧ̀, не взѧ́ша съ собо́ю є҆ле́а. мꙋ́дрыѧ же прїѧ́ша є҆ле́й въ сосꙋ́дѣхъ, со свѣти́льники свои́ми. коснѧ́щꙋ же женихꙋ̀, воздрема́шасѧ всѧ̑, и҆ спа́хꙋ. полꙋ́нощи же во́пль бы́сть: сѐ жени́хъ грѧде́тъ, и҆сходи́те въ срѣ́тенїе є҆гѡ̀. тогда̀ воста́вше всѧ̀ дѣ́вы ты́ѧ, и҆ ᲂу҆краси́ша свѣти́льники своѧ̀. ю҆рѡ́дивыѧ же мꙋ̑дрымъ рѣ́ша: дади́те на́мъ ѿ є҆ле́а ва́шегѡ, ꙗ҆́кѡ свѣти́льницы на́ши ᲂу҆гаса́ютъ. ѿвѣща́ша же мꙋ́дрыѧ, глаго́люще: є҆да̀ ка́кѡ не доста́нетъ на́мъ и҆ ва́мъ: и҆ди́те же па́че къ продаю́щымъ, и҆ кꙋпи́те себѣ̀. и҆дꙋ́щымъ же и҆̀мъ кꙋпи́ти, прїи́де жени́хъ, и҆ готѡ́выѧ внидо́ша съ ни́мъ на бра́ки: и҆ затворе́ны бы́ша двє́ри. послѣди́ же прїидо́ша и҆ про́чыѧ дѣ́вы, глаго́люще: гдⷭ҇и, гдⷭ҇и, ѿве́рзи на́мъ. ѻ҆́нъ же ѿвѣща́въ, речѐ и҆̀мъ: а҆ми́нь глаго́лю ва́мъ, не вѣ́мъ ва́съ. бди́те ᲂу҆̀бо, ꙗ҆́кѡ не вѣ́сте днѐ, ни часа̀, во́ньже сн҃ъ человѣ́ческїй прїи́детъ. ",
}

add_evangelie_matfea {
  ["номер"] = 105,
  ["комментарий"] = "Мф., 105 зач., XXV, 14-30.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: челове́к не́кий отходя́ призва́ своя́ рабы́ и предаде́ им име́ние свое́. И о́вому у́бо даде́ пять тала́нт, о́вому же два, о́вому же еди́н, кому́ждо проти́ву си́лы его́, и оты́де а́бие. Шед же прие́мый пять тала́нт, де́ла в них и сотвори́ други́я пять тала́нт. Та́кожде и и́же два, приобре́те и той друга́я два. Прие́мый же еди́н, шед вкопа́ его́ в зе́млю и скры сребро́ господи́на своего́. По мно́зе же вре́мени прии́де господи́н раб тех и стяза́ся с ни́ми о словеси́. И присту́пль пять тала́нт прие́мый, принесе́ други́я пять тала́нт, глаго́ля: го́споди, пять тала́нт ми еси́ пре́дал, се други́я пять тала́нт приобрето́х и́ми. Рече́ же ему́ госпо́дь его́: до́бре, ра́бе благи́й и ве́рный, о ма́ле был еси́ ве́рен, над мно́гими тя поста́влю, вни́ди в ра́дость го́спода твоего́. Присту́пль же и и́же два тала́нта прие́мый, рече́: го́споди, два тала́нта ми еси́ пре́дал, се друга́я два тала́нта приобрето́х и́ма. Рече́ же ему́ госпо́дь его́: до́бре, ра́бе благи́й и ве́рный, о ма́ле ми был еси́ ве́рен, над мно́гими тя поста́влю, вни́ди в ра́дость го́спода твоего́. Присту́пль же и прие́мый еди́н тала́нт, рече́: го́споди, ве́дях тя, я́ко же́сток еси́ челове́к, жне́ши, иде́же не се́ял еси́, и собира́еши ю́дуже не расточи́л еси́, и убоя́вся, шед скрых тала́нт твой в земли́, и се и́маши твое́. Отвеща́в же госпо́дь его́ рече́ ему́: лука́вый ра́бе и лени́вый, ве́дяше, я́ко жну иде́же не се́ях, и собира́ю иде́же не расточи́х, подоба́ше у́бо тебе́ вда́ти сребро́ мое́ торжнико́м, и прише́д аз взял бых свое́ с ли́хвою. Возми́те у́бо от него́ тала́нт и дади́те иму́щему де́сять тала́нт, иму́щему бо везде́ дано́ бу́дет и преизбу́дет, от неиму́щаго же, и е́же мни́тся име́я, взя́то бу́дет от него́. И неключи́маго раба́ вве́рзите во тму кроме́шнюю, ту бу́дет плачь и скре́жет зубо́м. Сия́ глаго́ля возгласи́: име́яй у́ши слы́шати да слы́шит. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: человѣ́къ нѣ́кїй ѿходѧ̀ призва̀ своѧ̀ рабы̑, и҆ предадѐ и҆̀мъ и҆мѣ́нїе своѐ. и҆ ѻ҆́вомꙋ ᲂу҆́бѡ дадѐ пѧ́ть тала̑нтъ, ѻ҆́вомꙋ же два̀, ѻ҆́вомꙋ же є҆ди́нъ, комꙋ́ждо проти́вꙋ си́лы є҆гѡ̀: и҆ ѿи́де а҆́бїе. ше́дъ же прїе́мый пѧ́ть тала̑нтъ, дѣ́ла въ ни́хъ, и҆ сотворѝ дрꙋгі́ѧ пѧ́ть тала̑нтъ. та́кожде и҆ и҆́же два̀, прїѡбрѣ́те и҆ то́й дрꙋга̑ѧ два̀. прїе́мый же є҆ди́нъ, ше́дъ вкопа̀ є҆го̀ въ зе́млю, и҆ скры̀ сребро̀ гдⷭ҇и́на своегѡ̀. по мно́зѣ же вре́мени прїи́де гдⷭ҇и́нъ ра̑бъ тѣ́хъ, и҆ стѧза́сѧ съ ни́ми ѡ҆ словесѝ. и҆ пристꙋ́пль пѧ́ть тала̑нтъ прїе́мый, принесѐ дрꙋгі́ѧ пѧ́ть тала̑нтъ, глаго́лѧ: гдⷭ҇и, пѧ́ть тала̑нтъ мѝ є҆сѝ пре́далъ, сѐ дрꙋгі́ѧ пѧ́ть тала̑нтъ прїѡбрѣто́хъ и҆́ми. рече́ же є҆мꙋ̀ гдⷭ҇ь є҆гѡ̀: до́брый ра́бе, бл҃гі́й и҆ вѣ́рный, ѡ҆ ма́лѣ бы́лъ є҆сѝ вѣ́ренъ, над̾ мно́гими тѧ̀ поста́влю: вни́ди въ ра́дость гдⷭ҇а твоегѡ̀. пристꙋ́пль же и҆ и҆́же два̀ тала́нта прїе́мый, речѐ: гдⷭ҇и, два̀ тала́нта мѝ є҆сѝ пре́далъ, сѐ дрꙋга̑ѧ два̀ тала́нта прїѡбрѣто́хъ и҆́ма. рече́ же є҆мꙋ̀ гдⷭ҇ь є҆гѡ̀: до́брый ра́бе, благі́й и҆ вѣ́рный, ѡ҆ ма́лѣ мѝ бы́лъ є҆сѝ вѣ́ренъ, над̾ мно́гими тѧ̀ поста́влю: вни́ди въ ра́дость гдⷭ҇а твоегѡ̀. пристꙋ́пль же и҆ прїе́мый є҆ди́нъ тала́нтъ, речѐ: гдⷭ҇и, вѣ́дѧхъ тѧ̀, ꙗ҆́кѡ же́стокъ є҆сѝ человѣ́къ: жне́ши, и҆дѣ́же не сѣ́ѧлъ є҆сѝ, и҆ собира́еши, ю҆́дꙋже не расточи́лъ є҆сѝ: и҆ ᲂу҆боѧ́всѧ ше́дъ скры́хъ тала́нтъ тво́й въ землѝ, и҆ сѐ и҆́маши твоѐ. ѿвѣща́въ же гдⷭ҇ь є҆гѡ̀, речѐ є҆мꙋ̀: лꙋка́вый ра́бе и҆ лѣни́вый, вѣ́дѧше, ꙗ҆́кѡ жнꙋ̀, и҆дѣ́же не сѣ́ѧхъ, и҆ собира́ю, ю҆́дꙋже не расточи́хъ: подоба́ше ᲂу҆̀бо тебѣ̀ вда́ти сребро̀ моѐ торжникѡ́мъ, и҆ прише́дъ а҆́зъ взѧ́лъ бы́хъ своѐ съ ли́хвою. воз̾ми́те ᲂу҆̀бо ѿ негѡ̀ тала́нтъ, и҆ дади́те и҆мꙋ́щемꙋ де́сѧть тала̑нтъ. и҆мꙋ́щемꙋ бо вездѣ̀ дано̀ бꙋ́детъ, и҆ преизбꙋ́детъ: ѿ неимꙋ́щагѡ же, и҆ є҆́же мни́тсѧ и҆мѣ́ѧ, взѧ́то бꙋ́детъ ѿ негѡ̀. и҆ неключи́маго раба̀ вве́рзите во тмꙋ̀ кромѣ́шнюю: тꙋ̀ бꙋ́детъ пла́чь и҆ скре́жетъ зꙋбѡ́мъ. сїѧ̑ глаго́лѧ возгласѝ: и҆мѣ́ѧй ᲂу҆́ши слы́шати, да слы́шитъ. ",
}

add_evangelie_matfea {
  ["номер"] = 106,
  ["комментарий"] = "Мф., 106 зач., XXV, 31–46.",
  ["текст_ру"] = "Рече́ Госпо́дь: егда́ прии́дет Сын Челове́ческий в сла́ве Свое́й и вси святи́и А́нгели с Ним, тогда́ ся́дет на престо́ле сла́вы Своея́, и соберу́тся пред Ним вси язы́цы, и разлучи́т их друг от дру́га, я́коже па́стырь разлуча́ет о́вцы от ко́злищ, и поста́вит о́вцы одесну́ю Себе́, а ко́злища ошу́юю. Тогда́ рече́т Царь су́щым одесну́ю Его́: прииди́те, благослове́ннии Отца́ Моего́, насле́дуйте угото́ванное вам Ца́рствие от сложе́ния ми́ра, взалка́хся бо, и да́сте Ми я́сти, возжада́хся, и напои́сте Мя, стра́нен бех, и введо́сте Мене́, наг, и оде́ясте Мя, бо́лен, и посети́сте Мене́, в темни́це бех, и приидо́сте ко Мне. Тогда́ отвеща́ют Ему́ пра́ведницы, глаго́люще: Го́споди, когда́ Тя ви́дехом а́лчуща, и напита́хом? Или́ жа́ждуща, и напои́хом? Когда́ же Тя ви́дехом стра́нна, и введо́хом? Или́ нага, и оде́яхом? Когда́ же Тя ви́дехом боля́ща, или́ в темни́це, и приидо́хом к Тебе́? И отвеща́в Царь рече́т им: ами́нь глаго́лю вам, поне́же сотвори́сте еди́ному сих бра́тий Мои́х ме́ньших, Мне сотвори́сте. Тогда́ рече́т и су́щым ошу́юю Его́: иди́те от Мене́, прокля́тии, во огнь ве́чный, угото́ванный диа́волу и а́ггелом его́, взалка́хся бо, и не да́сте Ми я́сти, возжада́хся, и не напои́сте Мене́, стра́нен бех, и не введо́сте Мене́, наг, и не оде́ясте Мене́, бо́лен и в темни́це, и не посети́сте Мене́. Тогда́ отвеща́ют Ему́ и ти́и, глаго́люще: Го́споди, когда́ Тя ви́дехом а́лчуща, или́ жа́ждуща, или́ стра́нна, или́ на́га, или́ бо́льна, или́ в темни́це, и не послужи́хом Тебе́? Тогда́ отвеща́ет им, глаго́ля: ами́нь глаго́лю вам, поне́же не сотвори́сте еди́ному сих ме́ньших, ни Мне сотвори́сте. И и́дут си́и в му́ку ве́чную, пра́ведницы же в живо́т ве́чный. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: є҆гда̀ прїи́детъ сн҃ъ человѣ́ческїй въ сла́вѣ свое́й, и҆ всѝ ст҃і́и а҆́гг҃ли съ ни́мъ, тогда̀ сѧ́детъ на прⷭ҇то́лѣ сла́вы своеѧ̀: и҆ соберꙋ́тсѧ пред̾ ни́мъ всѝ ꙗ҆зы́цы, и҆ разлꙋчи́тъ и҆̀хъ дрꙋ́гъ ѿ дрꙋ́га, ꙗ҆́коже па́стырь разлꙋча́етъ ѻ҆́вцы ѿ ко́злищъ. и҆ поста́витъ ѻ҆́вцы ѡ҆деснꙋ́ю себѐ, а҆ кѡ́злища ѡ҆шꙋ́юю. тогда̀ рече́тъ цр҃ь сꙋ́щымъ ѡ҆деснꙋ́ю є҆гѡ̀: прїиди́те благослове́ннїи ѻ҆ц҃а̀ моегѡ̀, наслѣ́дꙋйте ᲂу҆гото́ванное ва́мъ црⷭ҇твїе ѿ сложе́нїѧ мі́ра. взалка́хсѧ бо, и҆ да́сте мѝ ꙗ҆́сти: возжада́хсѧ, и҆ напои́сте мѧ̀: стра́ненъ бѣ́хъ, и҆ введо́сте менѐ: на́гъ, и҆ ѡ҆дѣ́ѧсте мѧ̀: бо́ленъ, и҆ посѣти́сте менѐ: въ темни́цѣ бѣ́хъ, и҆ прїидо́сте ко мнѣ̀. тогда̀ ѿвѣща́ютъ є҆мꙋ̀ пра́вєдницы, глаго́люще: гдⷭ҇и, когда́ тѧ ви́дѣхомъ а҆́лчꙋща, и҆ напита́хомъ; и҆лѝ жа́ждꙋща, и҆ напои́хомъ; когда́ же тѧ̀ ви́дѣхомъ стра́нна, и҆ введо́хомъ; и҆лѝ на́га, и҆ ѡ҆дѣ́ѧхомъ; когда́ же тѧ̀ ви́дѣхомъ болѧ́ща, и҆лѝ въ темни́цѣ, и҆ прїидо́хомъ къ тебѣ̀; и҆ ѿвѣща́въ цр҃ь рече́тъ и҆̀мъ: а҆ми́нь глаго́лю ва́мъ, поне́же сотвори́сте є҆ди́номꙋ си́хъ бра́тїй мои́хъ ме́ньшихъ, мнѣ̀ сотвори́сте. тогда̀ рече́тъ и҆ сꙋ́щымъ ѡ҆шꙋ́юю є҆гѡ̀: и҆ди́те ѿ менѐ проклѧ́тїи ко ѻ҆́гнь вѣ́чный, ᲂу҆гото́ванный дїа́волꙋ и҆ а҆́ггелѡмъ є҆гѡ̀. взалка́хсѧ бо, и҆ не да́сте мѝ ꙗ҆́сти: возжада́хсѧ, и҆ не напои́сте менѐ. стра́ненъ бѣ́хъ, и҆ не введо́сте менѐ: на́гъ, и҆ не ѡ҆дѣ́ѧсте менѐ: бо́ленъ, и҆ въ темни́цѣ, и҆ не посѣти́сте менѐ. тогда̀ ѿвѣща́ютъ є҆мꙋ̀ и҆ ті́и, глаго́люще: гдⷭ҇и, когда́ тѧ ви́дѣхомъ а҆́лчꙋща, и҆лѝ жа́ждꙋща, и҆лѝ стра́нна, и҆лѝ на́га, и҆лѝ бо́льна, и҆лѝ въ темни́цѣ, и҆ не послꙋжи́хомъ тебѣ̀; тогда̀ ѿвѣща́етъ и҆̀мъ, глаго́лѧ: а҆ми́нь глаго́лю ва́мъ, поне́же не сотвори́сте є҆ди́номꙋ си́хъ ме́ньшихъ, ни мнѣ̀ сотвори́сте. и҆ и҆́дꙋтъ сі́и въ мꙋ́кꙋ вѣ́чнꙋю, пра́вєдницы же въ живо́тъ вѣ́чный. ",
}

add_evangelie_matfea {
  ["номер"] = 107,
  ["комментарий"] = "Мф., 107 зач., XXVI, 1–20. Ин., 44 зач., XIII, 3–17. Мф., 108 зач.(от полу́), XXVI, 21–39. Лк., 109 зач., XXII, 43–45. Мф., 108 зач., XXVI, 40 – XXVII, 2.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: ве́сте, я́ко по двою́ дню Па́сха бу́дет, и Сын Челове́ческий пре́дан бу́дет на пропя́тие. Тогда́ собра́шася архиере́е, и кни́жницы и ста́рцы людсти́и во двор архиере́ов, глаго́лемаго Каиа́фы. И совеща́ша, да Иису́са ле́стию и́мут, и убию́т. Глаго́лаху же: но не в пра́здник, да не молва́ бу́дет в лю́дех. Иису́су же бы́вшу в Вифа́нии, в дому́ Си́мона прокаже́ннаго. Приступи́ к Нему́ жена́, сткля́ницу ми́ра иму́щи многоце́ннаго, и возлива́ше на главу́ Его́, возлежа́щу. Ви́девше же ученицы́ Его́, негодова́ша, глаго́люще: чесо́ ра́ди ги́бель сия́ бысть? Можа́ше бо сие́ ми́ро продано́ бы́ти на мно́зе, и да́тися ни́щим. Разуме́в же Иису́с рече́ им: что тружда́ете жену́? Де́ло бо добро́ соде́ла о Мне. Всегда́ бо ни́щия и́мате с собо́ю, Мене́ же не всегда́ и́мате. Возлия́вши бо сия́ ми́ро сие́ на те́ло Мое́, на погребе́ние Мя сотвори́. Ами́нь глаго́лю вам, иде́же а́ще пропове́дано бу́дет Ева́нгелие сие́ во всем ми́ре, рече́тся, и е́же сотвори́ сия́, в па́мять ея́. Тогда́ шед еди́н от обоюна́десяте, глаго́лемый Иу́да Искарио́тский, ко архиере́ом. Рече́: что ми хо́щете да́ти, и аз вам преда́м Его́? Они́ же поста́виша ему́ три́десять сре́бреник. И отто́ле иска́ше подо́бна вре́мене, да Его́ преда́ст. В пе́рвый же день опресно́чный приступи́ша ученицы́ Иису́сови, глаго́люще Ему́: где хо́щеши, угото́ваем Ти я́сти па́сху? Он же рече́: иди́те во град ко о́нсице. И рцы́те ему́: Учи́тель глаго́лет, вре́мя Мое́ близ есть, у тебе́ сотворю́ па́сху со ученики́ Мои́ми. И сотвори́ша ученицы́, я́коже повеле́ им Иису́с, и угото́ваша па́сху. Ве́черу же бы́вшу возлежа́ше со обемана́десяте ученико́ма. Ве́дый Иису́с, я́ко вся даде́ Ему́ Оте́ц в ру́це, и я́ко от Бо́га изы́де, и к Бо́гу гряде́т. Воста́в с ве́чери, и положи́ ри́зы, и прие́м ле́нтион, препоя́сася. Пото́м же влия́ во́ду во умыва́льницу, и нача́т умыва́ти но́ги ученико́м, и отира́ти ле́нтием, и́мже бе препоя́сан. Прии́де же к Си́мону Петру́, и глаго́ла Ему́ той: Го́споди, Ты ли мои́ умы́еши но́зе? Отвеща́ Иису́с, и рече́ ему́: е́же Аз творю́, ты не ве́си ны́не, разуме́еши же по сих. Глаго́ла Ему́ Петр: не умы́еши но́гу мое́ю во ве́ки. Отвеща́ ему́ Иису́с: а́ще не умы́ю тебе́, не и́маши ча́сти со Мно́ю. Глаго́ла Ему́ Си́мон Петр: Го́споди, не но́зе мои́ то́кмо, но и ру́це и главу́. Глаго́ла ему́ Иису́с: измове́нный не тре́бует, то́кмо но́зе умы́ти, есть бо весь чист, и вы чи́сти есте́, но не вси. Ве́дяше бо предаю́щаго Его́, сего́ ра́ди рече́, я́ко не вси чи́сти есте́. Егда́ же умы́ но́ги их, прия́т ри́зы Своя́, возле́г па́ки, рече́ им: ве́сте ли что сотвори́х вам? Вы глаша́ете Мя Учи́теля и Го́спода, и до́бре глаго́лете, есмь бо. А́ще у́бо Аз умы́х ва́ши но́зе, Госпо́дь и Учи́тель, и вы до́лжни есте́ друг дру́гу умыва́ти но́зе. О́браз бо дах вам, да я́коже Аз сотвори́х вам, и вы твори́те. Ами́нь ами́нь глаго́лю вам: несть раб бо́лий го́спода своего́, ни посла́нник бо́лий посла́вшаго его́. А́ще сия́ ве́сте, блаже́ни есте́, а́ще творите́ я́. И яду́щим им, рече́: ами́нь глаго́лю вам, я́ко еди́н от вас преда́ст Мя. И скорбя́ще зело́, нача́ша глаго́лати Ему́ еди́н ки́йждо их: еда́ аз есмь, Го́споди? Он же отвеща́в рече́: омочи́вый со Мно́ю в соли́ло ру́ку, той Мя преда́ст. Сын же Челове́ческий и́дет, я́коже есть пи́сано о Нем. Го́ре же челове́ку тому́, и́мже Сын Челове́ческий преда́стся, добро́ бы бы́ло ему́, а́ще не бы роди́лся челове́к той. Отвеща́в же Иу́да предая́й Его́, рече́: еда́ аз есмь, Равви́? Глаго́ла ему́: ты рече́. Яду́щим же им, прие́м Иису́с хлеб, и благослови́в преломи́, и дая́ше ученико́м, и рече́: приими́те, яди́те, сие́ есть Те́ло Мое́. И прие́м ча́шу, хвалу́ возда́в, даде́ им, глаго́ля: пи́йте от нея́ вси. Сия́ бо есть Кровь Моя́, Но́ваго Заве́та, я́же за мно́гия излива́ема, во оставле́ние грехо́в. Глаго́лю же вам: я́ко не и́мам пи́ти от ны́не от сего́ плода́ ло́знаго, до дне того́, егда́ и пию́ с ва́ми но́во во Ца́рствии Отца́ Моего́. И воспе́вше, изыдо́ша в го́ру Елео́нску. Тогда́ глаго́ла им Иису́с: вси вы соблазните́ся о Мне в нощь сию́. Пи́сано бо есть: поражу́ па́стыря, и разы́дутся о́вцы ста́да. По воскресе́нии же Мое́м, варя́ю вы в Галиле́и. Отвеща́в же Петр рече́ Ему́: а́ще и вси соблазня́тся о Тебе́, аз никогда́же соблажню́ся. Рече́ ему́ Иису́с: ами́нь глаго́лю тебе́, я́ко в сию́ нощь, пре́жде да́же але́ктор не возгласи́т, трикра́ты отве́ржешися Мене́. Глаго́ла Ему́ Петр: а́ще ми есть и умре́ти с Тобо́ю, не отве́ргуся Тебе́. Та́кожде и вси ученицы́ ре́ша. Тогда́ прии́де с ни́ми Иису́с в весь, нарица́емую Гефсима́ниа, и глаго́ла ученико́м: седи́те ту, до́ндеже шед помолю́ся та́мо. И пое́м Петра́ и оба сы́на Зеведе́ова, нача́т скорбе́ти и тужи́ти. Тогда́ глаго́ла им Иису́с: приско́рбна есть душа́ Моя́ до сме́рти, пожди́те зде, и бди́те со Мно́ю. И преше́д ма́ло, паде́ на лице́ Свое́м, моля́ся и глаго́ля: О́тче Мой, а́ще возмо́жно есть, да мимои́дет от Мене́ ча́ша сия́, оба́че не я́коже Аз хощу́, но я́коже Ты. Яви́ся же Ему́ А́нгел с небесе́, укрепля́я Его́. И быв в по́двизе, приле́жнее моля́шеся, бысть же пот Его́, я́ко ка́пля кро́ве ка́плющи на зе́млю. И воста́в от моли́твы, и прише́д ко ученико́м, и обре́те их спя́ща, и глаго́ла Петро́ви: та́ко ли не возмого́сте еди́наго часа́ побде́ти со Мно́ю? Бди́те и моли́теся, да не вни́дете в напа́сть, дух бо бодр, плоть же немощна́. Па́ки втори́цею шед помоли́ся, глаго́ля: О́тче мой, а́ще не мо́жет сия́ ча́ша мимоити́ от Мене́, а́ще не пию́ ея́, бу́ди во́ля Твоя́. И прише́д обре́те их па́ки спя́ща, бе́ста бо им очи отяготе́не. И оста́вль их, шед па́ки помоли́ся трети́цею, то́жде сло́во рек. Тогда́ прии́де ко ученико́м Свои́м и глаго́ла им: спи́те про́чее, и почива́йте, се прибли́жися час, и Сын Челове́ческий предае́тся в ру́ки гре́шников. Воста́ните, и́дем, се прибли́жися предая́й Мя. И еще́ Ему́ глаго́лющу, се Иу́да, еди́н от обоюна́десяте прии́де, и с ним наро́д мног, со ору́жием и дреко́льми, от архиере́й и ста́рец людски́х. Предая́й же Его́, даде́ им зна́мение, глаго́ля: Его́же а́ще лобжу́, Той есть, ими́те Его́. И а́бие присту́пль ко Иису́сови, рече́: ра́дуйся, Равви́, и облобыза́ Его́. Иису́с же рече́ ему́: дру́же, твори́ на не́же еси́ прише́л. Тогда́ присту́пльше возложи́ша ру́це на Иису́са, и я́ша Его́. И се еди́н от су́щих со Иису́сом, просте́р ру́ку, извлече́ нож свой, и уда́ри раба́ архиере́ова, и уре́за ему́ у́хо. Тогда́ глаго́ла ему́ Иису́с: возврати́ нож твой в ме́сто его́, вси бо прие́мшии нож ноже́м поги́бнут. Или́ мни́тся ти, я́ко не могу́ ны́не умоли́ти Отца́ Моего́, и предста́вит Ми вя́щше или́ двана́десяте легео́на А́нгел? Ка́ко у́бо сбу́дутся писа́ния, я́ко та́ко подоба́ет бы́ти? В той час рече́ Иису́с наро́дом: я́ко на разбо́йника ли изыдо́сте со ору́жием и дреко́льми, я́ти Мя; по вся дни при вас седе́х уча́ в це́ркви, и не я́сте Мене́. Се же все бысть, да сбу́дутся писа́ния проро́ческая. Тогда́ ученицы́ вси оста́вльше Его́, бежа́ша. Во́ини же е́мше Иису́са ведо́ша к Каиа́фе архиере́ови, иде́же кни́жницы и ста́рцы собра́шася. Петр же идя́ше по Нем издале́ча, до двора́ архиере́ова, и вшед внутрь, седя́ше со слуга́ми, ви́дети кончи́ну. Архиере́е же и ста́рцы, и сонм весь иска́ху лжесвиде́тельства на Иису́са, я́ко да убию́т Его́. И не обрета́ху, и мно́гим лжесвиде́телем присту́пльшим, не обрето́ша. По́слежде же приступи́ша два лжесвиде́теля, ре́ста: Сей рече́, могу́ разори́ти це́рковь Бо́жию и треми́ де́ньми созда́ти ю́. И воста́в архиере́й, рече́ Ему́: ничесо́же ли отвещава́еши, что си́и на Тя свиде́тельствуют? Иису́с же молча́ше. И отвеща́в архиере́й, рече́ Ему́: заклина́ю Тя Бо́гом живы́м, да рече́ши нам, а́ще Ты еси́ Христо́с, Сын Бо́жий? Глаго́ла ему́ Иису́с: ты рече́. Оба́че глаго́лю вам: отсе́ле у́зрите Сы́на Челове́ческаго седя́ща одесну́ю си́лы, и гряду́ща на о́блацех небе́сных. Тогда́ архиере́й растерза́ ри́зы своя́, глаго́ля, я́ко хулу́ глаго́ла, что еще́ тре́буем свиде́телей? Се ны́не слы́шасте хулу́ Его́. Что ся вам мнит? Они́ же отвеща́вше, ре́ша: пови́нен есть сме́рти. Тогда́ заплева́ша лице́ Его́, и па́кости Ему́ де́яху, о́вии же за лани́ту уда́риша, глаго́люще: прорцы́ нам, Христе́, кто есть ударе́й Тя? Петр же вне седя́ше во дворе́, и приступи́ к нему́ еди́на рабы́ня, глаго́лющи: и ты бе со Иису́сом Галиле́йским. Он же отве́ржеся пред все́ми, глаго́ля: не вем, что глаго́леши. Изше́дшу же ему́ ко врато́м, узре́ его́ друга́я, и глаго́ла им ту: и сей бе со Иису́сом Назоре́ом. И па́ки отве́ржеся с кля́твою: я́ко не зна́ю Челове́ка. По ма́ле же приступи́вше стоя́щии, ре́ша Петро́ви: вои́стинну и ты от них еси́, и́бо бесе́да твоя́ я́ве тя твори́т. Тогда́ нача́т роти́тися и кля́тися, я́ко не зна́ю Челове́ка. И а́бие пе́тель возгласи́. И помяну́ Петр глаго́л Иису́сов, рече́нный ему́: я́ко пре́жде да́же пе́тель не возгласи́т, трикра́ты отве́ржешися Мене́. И изше́д вон пла́кася го́рько. У́тру же бы́вшу, сове́т сотвори́ша вси архиере́е и ста́рцы людсти́и на Иису́са, я́ко уби́ти Его́. И связа́вше Его́ ведо́ша, и преда́ша Его́ Понти́йскому Пила́ту иге́мону. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: вѣ́сте, ꙗ҆́кѡ по двою̀ дню̀ па́сха бꙋ́детъ, и҆ сн҃ъ человѣ́ческїй пре́данъ бꙋ́детъ на пропѧ́тїе. тогда̀ собра́шасѧ а҆рхїере́є, и҆ кни́жницы и҆ ста́рцы людсті́и, во дво́ръ а҆рхїере́овъ, глаго́лемагѡ каїа́фы: и҆ совѣща́ша, да і҆и҃са ле́стїю и҆́мꙋтъ, и҆ ᲂу҆бїю́тъ. глаго́лахꙋ же: но не въ пра́здникъ, да не молва̀ бꙋ́детъ въ лю́дехъ. і҆и҃сꙋ же бы́вшꙋ въ виѳа́нїи, въ домꙋ̀ сі́мѡна прокаже́ннагѡ, пристꙋпѝ къ немꙋ̀ жена̀, стклѧ́ницꙋ мѵ́ра и҆мꙋ́щи многоцѣ́ннагѡ, и҆ возлива́ше на главꙋ̀ є҆гѡ̀, возлежа́щꙋ. ви́дѣвше же ᲂу҆ченицы̀ є҆гѡ̀, негодова́ша, глаго́люще. чесѡ̀ ра́ди ги́бель сїѧ̀ бы́сть; можа́ше бо сїѐ мѵ́ро продано̀ бы́ти на мно́зѣ, и҆ да́тисѧ ни́щымъ. разꙋмѣ́въ же і҆и҃съ речѐ и҆̀мъ: что̀ трꙋжда́ете женꙋ̀; дѣ́ло бо добро̀ содѣ́ла ѡ҆ мнѣ̀. всегда́ бо ни́щыѧ и҆́мате съ собо́ю: мене́ же не всегда̀ и҆́мате. возлїѧ́вши бо сїѧ̀ мѵ́ро сїѐ на тѣ́ло моѐ, на погребе́нїе мѧ̀ сотворѝ. а҆ми́нь глаго́лю ва́мъ: и҆дѣ́же а҆́ще проповѣ́дано бꙋ́детъ є҆ѵⷢ҇лїе сїѐ во все́мъ мі́рѣ, рече́тсѧ, и҆ є҆́же сотворѝ сїѧ̀, въ па́мѧть є҆ѧ̀. тогда̀ ше́дъ є҆ди́нъ ѿ ѻ҆боюна́десѧте, глаго́лемый і҆ꙋ́да і҆скарїѡ́тскїй, ко а҆рхїере́ѡмъ, речѐ: что́ ми хо́щете да́ти, и҆ а҆́зъ ва́мъ преда́мъ є҆го̀; ѻ҆ни́ же поста́виша є҆мꙋ̀ три́десѧть сре́брєникъ. и҆ ѿто́лѣ и҆ска́ше подо́бна вре́мене, да є҆го̀ преда́стъ. въ пе́рвый же де́нь ѡ҆прѣсно́чный пристꙋпи́ша ᲂу҆ченицы̀ і҆и҃сови, глаго́люще є҆мꙋ̀: гдѣ̀ хо́щеши, ᲂу҆гото́ваемъ тѝ ꙗ҆́сти па́схꙋ; ѻ҆́нъ же речѐ: и҆ди́те во гра́дъ ко ѻ҆́нсицѣ, и҆ рцы́те є҆мꙋ̀: ᲂу҆чи́тель глаго́летъ, вре́мѧ моѐ бли́зъ є҆́сть, ᲂу҆ тебѐ сотворю̀ па́схꙋ со ᲂу҆ченикѝ мои́ми. и҆ сотвори́ша ᲂу҆ченицы̀, ꙗ҆́коже повелѣ̀ и҆̀мъ і҆и҃съ: и҆ ᲂу҆гото́ваша па́схꙋ. ве́черꙋ же бы́вшꙋ возлежа́ше со ѻ҆бѣмана́десѧте ᲂу҆ченико́ма. вѣ́дый і҆и҃съ, ꙗ҆́кѡ всѧ̑ дадѐ є҆мꙋ̀ ѻ҆ц҃ъ въ рꙋ́цѣ, и҆ ꙗ҆́кѡ ѿ бг҃а и҆зы́де, и҆ къ бг҃ꙋ грѧде́тъ: воста́въ съ ве́чери, и҆ положѝ ри̑зы, и҆ прїе́мъ ле́нтїонъ, препоѧ́сасѧ. пото́мъ же влїѧ̀ во́дꙋ во ᲂу҆мыва́льницꙋ, и҆ нача́тъ ᲂу҆мыва́ти но́ги ᲂу҆ченикѡ́мъ, и҆ ѡ҆тира́ти ле́нтїемъ, и҆́мже бѣ̀ препоѧ́санъ. прїи́де же къ сі́мѡнꙋ петрꙋ̀, и҆ глаго́ла є҆мꙋ̀ то́й: гдⷭ҇и, ты́ ли моѝ ᲂу҆мы́еши но́зѣ; ѿвѣща̀ і҆и҃съ, и҆ речѐ є҆мꙋ̀: є҆́же а҆́зъ творю̀, ты̀ не вѣ́си ны́нѣ, разꙋмѣ́еши же по си́хъ. глаго́ла є҆мꙋ̀ пе́тръ: не ᲂу҆мы́еши нѡ́гꙋ мое́ю во вѣ́ки. ѿвѣща̀ є҆мꙋ̀ і҆и҃съ: а҆́ще не ᲂу҆мы́ю тебѐ, не и҆́маши ча́сти со мно́ю. глаго́ла є҆мꙋ̀ сі́мѡнъ пе́тръ: гдⷭ҇и, не но́зѣ моѝ то́кмѡ, но и҆ рꙋ́цѣ и҆ главꙋ̀. глаго́ла є҆мꙋ̀ і҆и҃съ: и҆змове́нный не тре́бꙋетъ, то́кмѡ но́зѣ ᲂу҆мы́ти, є҆́сть бо ве́сь чи́стъ: и҆ вы̀ чи́сти є҆стѐ, но не всѝ. вѣ́дѧше бо предаю́щаго є҆го̀ сегѡ̀ ра́ди речѐ: ꙗ҆́кѡ не всѝ чи́сти є҆стѐ. є҆гда́ же ᲂу҆мы̀ но́ги и҆́хъ, прїѧ́тъ ри̑зы своѧ̀, возле́гъ па́ки, речѐ и҆̀мъ: вѣ́сте ли что̀ сотвори́хъ ва́мъ; вы̀ глаша́ете мѧ̀ ᲂу҆чи́телѧ и҆ гдⷭ҇а: и҆ до́брѣ глаго́лете, є҆́смь бо. а҆́ще ᲂу҆́бѡ а҆́зъ ᲂу҆мы́хъ ва́ши но́зѣ, гдⷭ҇ь и҆ ᲂу҆чи́тель: и҆ вы̀ до́лжни є҆стѐ дрꙋ́гъ дрꙋ́гꙋ ᲂу҆мыва́ти но́зѣ. ѻ҆́бразъ бо да́хъ ва́мъ, да ꙗ҆́коже а҆́зъ сотвори́хъ ва́мъ, и҆ вы̀ твори́те. а҆ми́нь а҆ми́нь глаго́лю ва́мъ: нѣ́сть ра́бъ бо́лїй гдⷭ҇а своегѡ̀, ни посла́нникъ бо́лїй посла́вшагѡ є҆го̀. а҆́ще сїѧ̑ вѣ́сте, блаже́ни є҆стѐ, а҆́ще творитѐ ѧ҆̀. и҆ ꙗ҆дꙋ́щымъ и҆̀мъ речѐ: а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ є҆ди́нъ ѿ ва́съ преда́стъ мѧ̀. и҆ скорбѧ́ще ѕѣлѡ̀, нача́ша глаго́лати є҆мꙋ̀ є҆ди́нъ кі́йждо и҆́хъ: є҆да̀ а҆́зъ є҆́смь, гдⷭ҇и; ѻ҆́нъ же ѿвѣща́въ речѐ: ѡ҆мочи́вый со мно́ю въ соли́ло рꙋ́кꙋ, то́й мѧ̀ преда́стъ. сн҃ъ же человѣ́ческїй и҆́детъ, ꙗ҆́коже є҆́сть пи́сано ѡ҆ не́мъ. го́ре же человѣ́кꙋ томꙋ̀, и҆́мже сн҃ъ чл҃вѣ́ческїй преда́стсѧ: добро̀ бы бы́ло є҆мꙋ̀, а҆́ще не бы̀ роди́лсѧ человѣ́къ то́й. ѿвѣща́въ же і҆ꙋ́да предаѧ́й є҆го̀, речѐ: є҆да̀ а҆́зъ є҆́смь, равві̀; глаго́ла є҆мꙋ̀: ты̀ речѐ. ꙗ҆дꙋ́щымъ же и҆̀мъ, прїе́мъ і҆и҃съ хлѣ́бъ, и҆ благослови́въ преломѝ, и҆ даѧ́ше ᲂу҆ченикѡ́мъ, и҆ речѐ: прїими́те, ꙗ҆ди́те, сїѐ є҆́сть тѣ́ло моѐ. и҆ прїе́мъ ча́шꙋ, хвалꙋ̀ возда́въ, дадѐ и҆̀мъ, глаго́лѧ: пі́йте ѿ неѧ̀ всѝ. сїѧ́ бо є҆́сть кро́вь моѧ̀ но́вагѡ завѣ́та, ꙗ҆́же за мнѡ́гїѧ и҆злива́ема, во ѡ҆ставле́нїе грѣхѡ́въ. глаго́лю же ва́мъ: ꙗ҆́кѡ не и҆́мамъ пи́ти ѿ ны́нѣ ѿ сегѡ̀ плода̀ ло́знагѡ, до днѐ тогѡ̀, є҆гда̀ и҆̀ пїю̀ съ ва́ми но́во во црⷭ҇твїи ѻ҆ц҃а̀ моегѡ̀. и҆ воспѣ́вше, и҆зыдо́ша въ го́рꙋ є҆леѡ́нскꙋ. тогда̀ глаго́ла и҆̀мъ і҆и҃съ: всѝ вы̀ соблазните́сѧ ѡ҆ мнѣ̀ въ но́щь сїю̀. пи́сано бо є҆́сть: поражꙋ̀ па́стырѧ, и҆ разы́дꙋтсѧ ѻ҆́вцы ста́да. по воскресе́нїи же мое́мъ, варѧ́ю вы̀ въ галїле́и. ѿвѣща́въ же пе́тръ речѐ є҆мꙋ̀: а҆́ще и҆ всѝ соблазнѧ́тсѧ ѡ҆ тебѣ̀, а҆́зъ никогда́же соблажню́сѧ. речѐ є҆мꙋ̀ і҆и҃съ: а҆ми́нь глаго́лю тебѣ̀, ꙗ҆́кѡ въ сїю̀ но́щь, пре́жде да́же а҆ле́ктѡръ не возгласи́тъ, трикра́ты ѿве́ржешисѧ менѐ. глаго́ла є҆мꙋ̀ пе́тръ: а҆́ще мѝ є҆́сть и҆ ᲂу҆мре́ти съ тобо́ю, не ѿве́ргꙋсѧ тебѐ. та́кожде и҆ всѝ ᲂу҆ченицы̀ рѣ́ша. тогда̀ прїи́де съ ни́ми і҆и҃съ въ ве́сь нарица́емꙋю геѳсима́нїа, и҆ глаго́ла ᲂу҆ченикѡ́мъ: сѣди́те тꙋ̀, до́ндеже ше́дъ помолю́сѧ та́мѡ. и҆ пое́мъ петра̀ и҆ ѻ҆́ба сы́на зеведе́ова, нача́тъ скорбѣ́ти и҆ тꙋжи́ти. тогда̀ глаго́ла и҆̀мъ і҆и҃съ: приско́рбна є҆́сть дꙋша̀ моѧ̀ до сме́рти: пожди́те здѣ̀, и҆ бди́те со мно́ю. и҆ преше́дъ ма́лѡ, падѐ на лицѣ̀ свое́мъ, молѧ́сѧ, и҆ глаго́лѧ: ѻ҆́ч҃е мо́й, а҆́ще возмо́жно є҆́сть, да мимои́детъ ѿ менѐ ча́ша сїѧ̀: ѻ҆ба́че не ꙗ҆́коже а҆́зъ хощꙋ̀, но ꙗ҆́коже ты̀. ꙗ҆ви́сѧ же є҆мꙋ̀ а҆́гг҃лъ съ небесѐ ᲂу҆крѣплѧ́ѧ є҆го̀. и҆ бы́въ въ по́двизѣ, прилѣ́жнѣе молѧ́шесѧ: бы́сть же по́тъ є҆гѡ̀, ꙗ҆́кѡ ка́плѧ кро́ве ка́плющи на зе́млю. и҆ воста́въ ѿ моли́твы, и҆ прише́дъ ко ᲂу҆ченикѡ́мъ, и҆ ѡ҆брѣ́те и҆̀хъ спѧ́щѧ, и҆ глаго́ла петро́ви: та́кѡ ли не возмого́сте є҆ди́нагѡ часа̀ побдѣ́ти со мно́ю; бди́те и҆ моли́тесѧ, да не вни́дете въ напа́сть: дꙋ́хъ бо бо́дръ, пло́ть же немощна̀. па́ки втори́цею ше́дъ помоли́сѧ, глаго́лѧ: ѻ҆́ч҃е мо́й, а҆́ще не мо́жетъ сїѧ̀ ча́ша мимоитѝ ѿ менѐ, а҆́ще не пїю̀ є҆ѧ̀, бꙋ́ди во́лѧ твоѧ̀. и҆ прише́дъ ѡ҆брѣ́те и҆̀хъ па́ки спѧ́щѧ, бѣ́ста бо и҆̀мъ ѻ҆́чи ѡ҆тѧготѣ́нѣ. и҆ ѡ҆ста́вль и҆̀хъ, ше́дъ па́ки помоли́сѧ трети́цею, то́жде сло́во ре́къ. тогда̀ прїи́де ко ᲂу҆ченикѡ́мъ свои́мъ, и҆ глаго́ла и҆̀мъ: спи́те про́чее, и҆ почива́йте: сѐ прибли́жисѧ ча́съ, и҆ сн҃ъ человѣ́ческїй предае́тсѧ въ рꙋ́ки грѣ́шникѡвъ. воста́ните, и҆́демъ: сѐ прибли́жисѧ предаѧ́й мѧ̀. и҆ є҆щѐ є҆мꙋ̀ глаго́лющꙋ, сѐ і҆ꙋ́да є҆ди́нъ ѿ ѻ҆боюна́десѧте прїи́де, и҆ съ ни́мъ наро́дъ мно́гъ, со ѻ҆рꙋ́жїемъ и҆ дреко́льми, ѿ а҆рхїерє́й и҆ ста́рєцъ людски́хъ. предаѧ́й же є҆го̀, дадѐ и҆̀мъ зна́менїе, глаго́лѧ: є҆го́же а҆́ще лобжꙋ̀, то́й є҆́сть, и҆ми́те є҆го̀. и҆ а҆́бїе пристꙋ́пль ко і҆и҃сови, речѐ: ра́дꙋйсѧ равві̀, и҆ ѡ҆блобыза̀ є҆го̀. і҆и҃съ же речѐ є҆мꙋ̀: дрꙋ́же, творѝ на не́же є҆сѝ прише́лъ. тогда̀ пристꙋ́пльше возложи́ша рꙋ́цѣ на і҆и҃са, и҆ ꙗ҆́ша є҆го̀. и҆ сѐ є҆ди́нъ ѿ сꙋ́щихъ со і҆и҃сомъ, просте́ръ рꙋ́кꙋ, и҆звлечѐ но́жъ сво́й: и҆ ᲂу҆да́ри раба̀ а҆рхїере́ова, и҆ ᲂу҆рѣ́за є҆мꙋ̀ ᲂу҆́хо. тогда̀ глаго́ла є҆мꙋ̀ і҆и҃съ: возвратѝ но́жъ тво́й въ мѣ́сто є҆гѡ̀: вси́ бо прїе́мшїи но́жъ ноже́мъ поги́бнꙋтъ: и҆лѝ мни́тсѧ тѝ, ꙗ҆́кѡ не могꙋ̀ ны́нѣ ᲂу҆моли́ти ѻ҆ц҃а̀ моего̀, и҆ предста́витъ мѝ вѧ́щше и҆лѝ двана́десѧте легеѡ́на а҆́гг҃лъ; ка́кѡ ᲂу҆̀бо сбꙋ́дꙋтсѧ писа̑нїѧ, ꙗ҆́кѡ та́кѡ подоба́етъ бы́ти; въ то́й ча́съ речѐ і҆и҃съ наро́дѡмъ: ꙗ҆́кѡ на разбо́йника ли и҆зыдо́сте со ѻ҆рꙋ́жїемъ и҆ дреко́льми, ꙗ҆́ти мѧ̀; по всѧ̀ днѝ при ва́съ сѣдѣ́хъ ᲂу҆чѧ̀ въ цр҃кви, и҆ не ꙗ҆́сте менѐ. се́ же всѐ бы́сть, да сбꙋ́дꙋтсѧ писа̑нїѧ проро́чєскаѧ. тогда̀ ᲂу҆ченицы̀ всѝ ѡ҆ста́вльше є҆го̀, бѣжа́ша. во́ини же є҆́мше і҆и҃са ведо́ша къ каїа́фѣ а҆рхїере́ови, и҆дѣ́же кни́жницы и҆ ста́рцы собра́шасѧ. пе́тръ же и҆дѧ́ше по не́мъ и҆здале́ча, до двора̀ а҆рхїере́ова: и҆ вше́дъ внꙋ́трь, сѣдѧ́ше со слꙋга́ми, ви́дѣти кончи́нꙋ. а҆рхїере́є же и҆ ста́рцы, и҆ со́нмъ ве́сь, и҆ска́хꙋ лжесвидѣ́тельства на і҆и҃са, ꙗ҆́кѡ да ᲂу҆бїю́тъ є҆го̀, и҆ не ѡ҆брѣта́хꙋ: и҆ мнѡ́гимъ лжесвидѣ́телємъ пристꙋ́пльшымъ, не ѡ҆брѣто́ша. по́слѣжде же пристꙋпи́ша два̀ лжесвидѣ́телѧ, рѣ́ста: се́й речѐ, могꙋ̀ разори́ти цр҃ковь бж҃їю, и҆ тремѝ де́ньми созда́ти ю҆̀. и҆ воста́въ а҆рхїере́й, речѐ є҆мꙋ̀: ничесѡ́же ли ѿвѣщава́еши, что̀ сі́и на тѧ̀ свидѣ́тельствꙋютъ. і҆и҃съ же молча́ше. и҆ ѿвѣща́въ а҆рхїере́й, речѐ є҆мꙋ̀: заклина́ю тѧ̀ бг҃омъ живы́мъ, да рече́ши на́мъ, а҆́ще ты̀ є҆сѝ хрⷭ҇то́съ сн҃ъ бж҃їй; глаго́ла є҆мꙋ̀ і҆и҃съ: ты̀ ре́клъ є҆си. ѻ҆ба́че глаго́лю ва́мъ: ѿсе́лѣ ᲂу҆́зрите сн҃а человѣ́ческаго сѣдѧ́ща ѡ҆деснꙋ́ю си́лы, и҆ грѧдꙋ́ща на ѻ҆́блацѣхъ нбⷭ҇ныхъ. тогда̀ а҆рхїере́й растерза̀ ри̑зы своѧ̀, глаго́лѧ: ꙗ҆́кѡ хꙋлꙋ̀ глаго́ла, что̀ є҆щѐ тре́бꙋемъ свидѣ́телей; сѐ ны́нѣ слы́шасте хꙋлꙋ̀ є҆гѡ̀: что́ ва́мъ мни́тъ; ѻ҆ни́ же ѿвѣща́вше, рѣ́ша: пови́ненъ є҆́сть сме́рти. тогда̀ заплева́ша лицѐ є҆гѡ̀, и҆ па́кѡсти є҆мꙋ̀ дѣ́ѧхꙋ, ѻ҆́вїи же за лани́тꙋ ᲂу҆да́риша, глаго́люще: прорцы̀ на́мъ хрⷭ҇тѐ, кто́ є҆сть ᲂу҆даре́й тѧ̀; пе́тръ же внѣ̀ сѣдѧ́ше во дворѣ̀, и҆ пристꙋпѝ къ немꙋ̀ є҆ди́на рабы́нѧ, глаго́лющи: и҆ ты̀ бѣ̀ со і҆и҃сомъ галїле́йскимъ. ѻ҆́нъ же ѿве́ржесѧ пред̾ всѣ́ми, глаго́лѧ: не вѣ́мъ, что̀ глаго́леши. и҆зше́дшꙋ же є҆мꙋ̀ ко вратѡ́мъ, ᲂу҆зрѣ̀ є҆го̀ дрꙋга́ѧ, и҆ глаго́ла и҆̀мъ тꙋ̀: и҆ се́й бѣ̀ со і҆и҃сомъ назѡре́омъ. и҆ па́ки ѿве́ржесѧ съ клѧ́твою: ꙗ҆́кѡ не зна́ю человѣ́ка. по ма́лѣ же пристꙋпи́вше стоѧ́щїи, рѣ́ша петро́ви: вои́стиннꙋ и҆ ты̀ ѿ ни́хъ є҆сѝ: и҆́бо бесѣ́да твоѧ̀ ꙗ҆́вѣ тѧ̀ твори́тъ. тогда̀ нача́тъ роти́тисѧ и҆ клѧ́тисѧ, ꙗ҆́кѡ не зна́ю человѣ́ка. и҆ а҆́бїе пѣ́телъ возгласѝ. и҆ помѧнꙋ̀ пе́тръ глаго́лъ і҆и҃совъ, рече́нный є҆мꙋ̀: ꙗ҆́кѡ пре́жде да́же пѣ́телъ не возгласи́тъ, трикра́ты ѿве́ржешисѧ менѐ, и҆ и҆зше́дъ во́нъ пла́касѧ го́рькѡ. ᲂу҆́трꙋ же бы́вшꙋ, совѣ́тъ сотвори́ша всѝ а҆рхїере́є и҆ ста́рцы людсті́и на і҆и҃са, ꙗ҆́кѡ ᲂу҆би́ти є҆го̀. и҆ свѧза́вше є҆го̀ ведо́ша, и҆ преда́ша є҆го̀ понті́йскомꙋ пїла́тꙋ и҆ге́мѡнꙋ. ",
}

