  ["номер"] = 108,
  ["комментарий"] = "Мф., 108 зач., XXVI, 6-16.",
  ["текст_ру"] = "Во вре́мя о́но, Иису́су бы́вшу в Вифа́нии, в дому́ Си́мона прокаже́ннаго, приступи́ к Нему́ жена́, сткля́ницу ми́ра иму́щи многоце́ннаго, и возлива́ше на главу́ Его́ возлежа́щу. Ви́девше же ученицы́ Его́ негодова́ша, глаго́люще: чесо́ ра́ди ги́бель сия́ бысть? Можа́ше бо сие́ ми́ро продано́ бы́ти на мно́зе и да́тися ни́щым. Разуме́в же Иису́с рече́ им: что тружда́ете жену́? Де́ло бо добро́ соде́ла о Мне, всегда́ бо ни́щыя и́мате с собо́ю, Мене́ же не всегда́ и́мате. Возлия́вши бо сия́ ми́ро сие́ на те́ло Мое́, на погребе́ние Мя сотвори́. Ами́нь глаго́лю вам: иде́же а́ще пропове́дано бу́дет Ева́нгелие сие́ во всем ми́ре, рече́тся и е́же сотвори́ сия́, в па́мять ея́. Тогда́ шед еди́н от обоюна́десяте, глаго́лемый Иу́да Искарио́тский, ко архиере́ом, рече́: что ми хо́щете да́ти, и аз вам преда́м Его́? Они́ же поста́виша ему́ три́десять сре́бреник, и отто́ле иска́ше подо́бна вре́мене, да Его́ преда́ст. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, і҆и҃сꙋ бы́вшꙋ въ виѳа́нїи, въ домꙋ̀ сі́мѡна прокаже́ннагѡ, пристꙋпѝ къ немꙋ̀ жена̀, стклѧ́ницꙋ мѵ́ра и҆мꙋ́щи многоцѣ́ннагѡ, и҆ возлива́ше на главꙋ̀ є҆гѡ̀, возлежа́щꙋ. ви́дѣвше же ᲂу҆ченицы̀ є҆гѡ̀, негодова́ша, глаго́люще. чесѡ̀ ра́ди ги́бель сїѧ̀ бы́сть; можа́ше бо сїѐ мѵ́ро продано̀ бы́ти на мно́зѣ, и҆ да́тисѧ ни́щымъ. разꙋмѣ́въ же і҆и҃съ речѐ и҆̀мъ: что̀ трꙋжда́ете женꙋ̀; дѣ́ло бо добро̀ содѣ́ла ѡ҆ мнѣ̀. всегда́ бо ни́щыѧ и҆́мате съ собо́ю: мене́ же не всегда̀ и҆́мате. возлїѧ́вши бо сїѧ̀ мѵ́ро сїѐ на тѣ́ло моѐ, на погребе́нїе мѧ̀ сотворѝ. а҆ми́нь глаго́лю ва́мъ: и҆дѣ́же а҆́ще проповѣ́дано бꙋ́детъ є҆ѵⷢ҇лїе сїѐ во все́мъ мі́рѣ, рече́тсѧ, и҆ є҆́же сотворѝ сїѧ̀, въ па́мѧть є҆ѧ̀. тогда̀ ше́дъ є҆ди́нъ ѿ ѻ҆боюна́десѧте, глаго́лемый і҆ꙋ́да і҆скарїѡ́тскїй, ко а҆рхїере́ѡмъ, речѐ: что́ ми хо́щете да́ти, и҆ а҆́зъ ва́мъ преда́мъ є҆го̀; ѻ҆ни́ же поста́виша є҆мꙋ̀ три́десѧть сре́брєникъ. и҆ ѿто́лѣ и҆ска́ше подо́бна вре́мене, да є҆го̀ преда́стъ. ",
}

add_evangelie_matfea {
  ["номер"] = 109,
  ["комментарий"] = "Мф., 109 зач., XXVI, 57–75.",
  ["текст_ру"] = "Во вре́мя о́но, во́ини е́мше Иису́са ведо́ша к Каиа́фе архиере́ови, иде́же кни́жницы и ста́рцы собра́шася. Петр же идя́ше по Нем издале́ча до двора́ архиере́ова, и вшед внутрь, седя́ше со слуга́ми, ви́дети кончи́ну. Архиере́е же и ста́рцы и сонм весь иска́ху лжесвиде́тельства на Иису́са, я́ко да убию́т Его́, и не обрета́ху, и мно́гим лжесвиде́телем присту́пльшым, не обрето́ша. По́слежде же приступи́ша два лжесвиде́теля, ре́ста: Сей рече́, могу́ разори́ти це́рковь Бо́жию и треми́ де́ньми созда́ти ю́. И воста́в архиере́й рече́ Ему́: ничесо́же ли отвещава́еши, что си́и на Тя свиде́тельствуют? Иису́с же молча́ше. И отвеща́в архиере́й рече́ Ему́: заклина́ю Тя Бо́гом живы́м, да рече́ши нам, а́ще Ты еси́ Христо́с, Сын Бо́жий? Глаго́ла ему́ Иису́с: ты рекл еси́. Оба́че глаго́лю вам: отсе́ле у́зрите Сы́на Челове́ческаго седя́ща одесну́ю си́лы и гряду́ща на о́блацех небе́сных. Тогда́ архиере́й растерза́ ри́зы своя́, глаго́ля, я́ко хулу́ глаго́ла, что еще́ тре́буем свиде́телей? Се, ны́не слы́шасте хулу́ Его́, что вам мнит? Они́ же отвеща́вше ре́ша: пови́нен есть сме́рти. Тогда́ заплева́ша лице́ Его́ и па́кости Ему́ де́яху, о́вии же за лани́ту уда́риша, глаго́люще: прорцы́ нам, Христе́, кто есть ударе́й Тя? Петр же вне седя́ше во дворе́. И приступи́ к нему́ еди́на рабы́ня, глаго́лющи: и ты бе со Иису́сом Галиле́йским. Он же отве́ржеся пред все́ми, глаго́ля: не вем, что глаго́леши. Изше́дшу же ему́ ко врато́м, узре́ его́ друга́я, и глаго́ла им та́мо: и сей бе со Иису́сом Назоре́ом. И па́ки отве́ржеся с кля́твою, я́ко не зна́ю Челове́ка. По ма́ле же приступи́вше стоя́щии, ре́ша Петро́ви: вои́стинну и ты от них еси́, и́бо бесе́да твоя́ я́ве тя твори́т. Тогда́ нача́т роти́тися и кля́тися, я́ко не зна́ю Челове́ка. И а́бие пе́тель возгласи́. И помяну́ Петр глаго́л Иису́сов, рече́нный ему́, я́ко пре́жде да́же пе́тель не возгласи́т, трикра́ты отве́ржешися Мене́. И изше́д вон пла́кася го́рько. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, во́ини є҆́мше і҆и҃са ведо́ша къ каїа́фѣ а҆рхїере́ови, и҆дѣ́же кни́жницы и҆ ста́рцы собра́шасѧ. пе́тръ же и҆дѧ́ше по не́мъ и҆здале́ча, до двора̀ а҆рхїере́ова: и҆ вше́дъ внꙋ́трь, сѣдѧ́ше со слꙋга́ми, ви́дѣти кончи́нꙋ. а҆рхїере́є же и҆ ста́рцы, и҆ со́нмъ ве́сь, и҆ска́хꙋ лжесвидѣ́тельства на і҆и҃са, ꙗ҆́кѡ да ᲂу҆бїю́тъ є҆го̀, и҆ не ѡ҆брѣта́хꙋ: и҆ мнѡ́гимъ лжесвидѣ́телємъ пристꙋ́пльшымъ, не ѡ҆брѣто́ша. по́слѣжде же пристꙋпи́ша два̀ лжесвидѣ́телѧ, рѣ́ста: се́й речѐ, могꙋ̀ разори́ти цр҃ковь бж҃їю, и҆ тремѝ де́ньми созда́ти ю҆̀. и҆ воста́въ а҆рхїере́й, речѐ є҆мꙋ̀: ничесѡ́же ли ѿвѣщава́еши, что̀ сі́и на тѧ̀ свидѣ́тельствꙋютъ. і҆и҃съ же молча́ше. и҆ ѿвѣща́въ а҆рхїере́й, речѐ є҆мꙋ̀: заклина́ю тѧ̀ бг҃омъ живы́мъ, да рече́ши на́мъ, а҆́ще ты̀ є҆сѝ хрⷭ҇то́съ сн҃ъ бж҃їй; глаго́ла є҆мꙋ̀ і҆и҃съ: ты̀ ре́клъ є҆си. ѻ҆ба́че глаго́лю ва́мъ: ѿсе́лѣ ᲂу҆́зрите сн҃а человѣ́ческаго сѣдѧ́ща ѡ҆деснꙋ́ю си́лы, и҆ грѧдꙋ́ща на ѻ҆́блацѣхъ нбⷭ҇ныхъ. тогда̀ а҆рхїере́й растерза̀ ри̑зы своѧ̀, глаго́лѧ: ꙗ҆́кѡ хꙋлꙋ̀ глаго́ла, что̀ є҆щѐ тре́бꙋемъ свидѣ́телей; сѐ ны́нѣ слы́шасте хꙋлꙋ̀ є҆гѡ̀: что́ ва́мъ мни́тъ; ѻ҆ни́ же ѿвѣща́вше, рѣ́ша: пови́ненъ є҆́сть сме́рти. тогда̀ заплева́ша лицѐ є҆гѡ̀, и҆ па́кѡсти є҆мꙋ̀ дѣ́ѧхꙋ, ѻ҆́вїи же за лани́тꙋ ᲂу҆да́риша, глаго́люще: прорцы̀ на́мъ хрⷭ҇тѐ, кто́ є҆сть ᲂу҆даре́й тѧ̀; пе́тръ же внѣ̀ сѣдѧ́ше во дворѣ̀, и҆ пристꙋпѝ къ немꙋ̀ є҆ди́на рабы́нѧ, глаго́лющи: и҆ ты̀ бѣ̀ со і҆и҃сомъ галїле́йскимъ. ѻ҆́нъ же ѿве́ржесѧ пред̾ всѣ́ми, глаго́лѧ: не вѣ́мъ, что̀ глаго́леши. и҆зше́дшꙋ же є҆мꙋ̀ ко вратѡ́мъ, ᲂу҆зрѣ̀ є҆го̀ дрꙋга́ѧ, и҆ глаго́ла и҆̀мъ тꙋ̀: и҆ се́й бѣ̀ со і҆и҃сомъ назѡре́омъ. и҆ па́ки ѿве́ржесѧ съ клѧ́твою: ꙗ҆́кѡ не зна́ю человѣ́ка. по ма́лѣ же пристꙋпи́вше стоѧ́щїи, рѣ́ша петро́ви: вои́стиннꙋ и҆ ты̀ ѿ ни́хъ є҆сѝ: и҆́бо бесѣ́да твоѧ̀ ꙗ҆́вѣ тѧ̀ твори́тъ. тогда̀ нача́тъ роти́тисѧ и҆ клѧ́тисѧ, ꙗ҆́кѡ не зна́ю человѣ́ка. и҆ а҆́бїе пѣ́телъ возгласѝ. и҆ помѧнꙋ̀ пе́тръ глаго́лъ і҆и҃совъ, рече́нный є҆мꙋ̀: ꙗ҆́кѡ пре́жде да́же пѣ́телъ не возгласи́тъ, трикра́ты ѿве́ржешисѧ менѐ, и҆ и҆зше́дъ во́нъ пла́касѧ го́рькѡ. ",
}

add_evangelie_matfea {
  ["номер"] = 110,
  ["комментарий"] = "Мф., 110 зач., XXVII, 1–56.",
  ["текст_ру"] = "Во вре́мя о́но, у́тру бы́вшу, сове́т сотвори́ша вси архиере́е и ста́рцы людсти́и на Иису́са, я́ко уби́ти Его́, и связа́вше Его́ ведо́ша и преда́ша Его́ Понти́йскому Пила́ту иге́мону. Тогда́ ви́дев Иу́да преда́вый Его́, я́ко осуди́ша Его́, раска́явся возврати́ три́десять сре́бреники архиере́ем и ста́рцем, глаго́ля: согреши́х преда́в кровь непови́нную. Они́ же ре́ша: что есть нам? Ты у́зриши. И пове́рг сре́бреники в це́ркви, оты́де, и шед удави́ся. Архиере́е же прие́мше сре́бреники, ре́ша: недосто́йно есть вложи́ти их в корва́ну, поне́же цена́ кро́ве есть. Сове́т же сотво́рше, купи́ша и́ми село́ скуде́льничо, в погреба́ние стра́нным. Те́мже нарече́ся село́ то село́ кро́ве, до сего́ дне. Тогда́ сбы́стся рече́нное Иереми́ем проро́ком, глаго́лющим: и прия́ша три́десять сре́бреник, це́ну Цене́ннаго, Его́же цени́ша от сыно́в Изра́илев, и да́ша я́ на селе́ скуде́льничи, я́коже сказа́ мне Госпо́дь. Иису́с же ста пред иге́моном. И вопроси́ Его́ иге́мон, глаго́ля: Ты ли еси́ Царь Иуде́йский? Иису́с же рече́ ему́: ты глаго́леши. И егда́ Нань глаго́лаху архиере́е и ста́рцы, ничесо́же отвещава́ше. Тогда́ глаго́ла Ему́ Пила́т: не слы́шиши ли, коли́ко на Тя свиде́тельствуют? И не отвеща́ ему́ ни к еди́ному глаго́лу, я́ко диви́тися иге́мону зело́. На всяк же пра́здник обы́чай бе иге́мону отпуща́ти еди́наго наро́ду свя́зня, его́же хотя́ху. Имя́ху же тогда́ свя́зана наро́чита, глаго́лемаго Вара́вву. Со́бранным же им, рече́ им Пила́т: кого́ хо́щете от обою́ отпущу́ вам, Вара́вву ли, или́ Иису́са глаго́лемаго Христа́? Ве́дяше бо, я́ко за́висти ра́ди преда́ша Его́. Седя́щу же ему́ на суди́щи, посла́ к нему́ жена́ его́, глаго́лющи, ничто́же тебе́ и Пра́веднику Тому́, мно́го бо пострада́х днесь во сне Его́ ра́ди. Архиере́е же и ста́рцы наусти́ша наро́ды, да испро́сят Вара́вву, Иису́са же погубя́т. Отвеща́в же иге́мон рече́ им: кого́ хо́щете от обою́ отпущу́ вам? Они́ же ре́ша: Вара́вву. Глаго́ла им Пила́т: что у́бо сотворю́ Иису́су глаго́лемому Христу́? Глаго́лаша ему́ вси: да ра́спят бу́дет. Иге́мон же рече́: ко́е у́бо зло сотвори́? Они́ же и́злиха вопия́ху, глаго́люще: да про́пят бу́дет. Ви́дев же Пила́т, я́ко ничто́же успева́ет, но па́че молва́ быва́ет, прие́мь во́ду, умы́ ру́це пред наро́дом, глаго́ля: непови́нен есмь от кро́ве Пра́веднаго Сего́, вы у́зрите. И отвеща́вше вси лю́дие ре́ша: кровь Его́ на нас и на ча́дех на́ших. Тогда́ отпусти́ им Вара́вву, Иису́са же бив предаде́ им, да Его́ про́пнут. Тогда́ во́ини иге́моновы, прие́мше Иису́са на суди́ще, собра́ша Нань все мно́жество во́ин. И совле́кше Его́, оде́яша Его́ хлами́дою червле́ною. И спле́тше вене́ц от те́рния, возложи́ша на главу́ Его́, и трость в десни́цу Его́, и покло́ньшеся на коле́ну пред Ним руга́хуся Ему́, глаго́люще: ра́дуйся, Царю́ Иуде́йский. И плю́нувше Нань, прия́ша трость и бия́ху по главе́ Его́. И егда́ поруга́шася Ему́, совлеко́ша с Него́ багряни́цу и облеко́ша Его́ в ри́зы Его́, и ведо́ша Его́ на пропя́тие. Исходя́ще же обрето́ша челове́ка Кирине́йска, и́менем Си́мона, и сему́ заде́ша понести́ крест Его́. И прише́дше на ме́сто нарица́емое Голго́фа, е́же есть глаго́лемо Кра́ниево ме́сто, да́ша Ему́ пи́ти о́цет с же́лчию сме́шен, и вкушь, не хотя́ше пи́ти. Распе́ншии же Его́ раздели́ша ри́зы Его́, ве́ргше жре́бия, и седя́ще стрежа́ху Его́ ту, и возложи́ша верху́ главы́ Его́ вину́ Его́ напи́сану: Сей есть Иису́с, Царь Иуде́йский. Тогда́ распя́ша с Ним два разбо́йника: еди́наго одесну́ю, и еди́наго ошу́юю. Мимоходя́щии же ху́ляху Его́, покива́юще глава́ми свои́ми и глаго́люще: Разоря́яй це́рковь и треми́ де́ньми Созида́яй, спаси́ся Сам, а́ще Сын еси́ Бо́жий, сни́ди со креста́. Та́кожде же и архиере́е руга́ющеся с кни́жники и ста́рцы и фарисе́и, глаго́лаху: ины́я спасе́, Себе́ ли не мо́жет спасти́? А́ще Царь Изра́илев есть, да сни́дет ны́не со креста́, и ве́руем в Него́. Упова́ на Бо́га, да изба́вит ны́не Его́, а́ще хо́щет Ему́. Рече́ бо, я́ко Бо́жий есмь Сын. То́жде же и разбо́йника распя́тая с Ним поноша́ста Ему́. От шеста́го же часа́ тма бысть по всей земли́ до часа́ девя́таго. О девя́том же часе́ возопи́ Иису́с гла́сом ве́лиим, глаго́ля: Или́, Или́, лима́ савахфани́? Е́же есть, Бо́же Мой, Бо́же Мой, вску́ю Мя еси́ оста́вил? Не́цыи же от ту стоя́щих слы́шавше глаго́лаху, я́ко Илию́ глаша́ет Сей. И а́бие тек еди́н от них, и прие́м гу́бу, испо́лнив же о́цта, и вонзе́ на трость, напая́ше Его́. Про́чии же глаго́лаху: оста́ви, да ви́дим, а́ще прии́дет Илиа́ спасти́ Его́. Иису́с же, па́ки возопи́в гла́сом ве́лиим, испусти́ дух. И се заве́са церко́вная раздра́ся на дво́е с вы́шняго кра́я до ни́жняго, и земля́ потрясе́ся, и ка́мение распаде́ся, и гро́би отверзо́шася, и мно́га телеса́ усо́пших святы́х воста́ша, и изше́дше из гроб, по воскресе́нии Его́, внидо́ша во святы́й град и яви́шася мно́зем. Со́тник же и и́же с ним стрегу́щии Иису́са, ви́девше трус и бы́вшая, убоя́шася зело́, глаго́люще: вои́стинну Бо́жий Сын бе Сей. Бя́ху же ту и жены́ мно́ги издале́ча зря́ще, я́же идо́ша по Иису́се от Галиле́и, служа́ще Ему́. В ни́хже бе Мари́а Магдали́на, и Мари́а Иа́кова и Иоси́и ма́ти, и ма́ти сы́ну Зеведе́ову. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ᲂу҆́трꙋ бы́вшꙋ, совѣ́тъ сотвори́ша всѝ а҆рхїере́є и҆ ста́рцы людсті́и на і҆и҃са, ꙗ҆́кѡ ᲂу҆би́ти є҆го̀. и҆ свѧза́вше є҆го̀ ведо́ша, и҆ преда́ша є҆го̀ понті́йскомꙋ пїла́тꙋ и҆ге́мѡнꙋ. тогда̀ ви́дѣвъ і҆ꙋ́да преда́вый є҆го̀, ꙗ҆́кѡ ѡ҆сꙋди́ша є҆го̀, раска́ѧвсѧ возвратѝ три́десѧть сре́бреники а҆рхїере́ємъ и҆ ста́рцємъ, глаго́лѧ: согрѣши́хъ, преда́въ кро́вь непови́ннꙋю. ѻ҆ни́ же рѣ́ша: что̀ є҆́сть на́мъ; ты̀ ᲂу҆́зриши. и҆ пове́ргъ сре́бреники въ цр҃кви, ѿи́де, и҆ ше́дъ ᲂу҆дави́сѧ. а҆рхїере́є же прїе́мше сре́бреники, рѣ́ша: недосто́йно є҆́сть вложи́ти и҆̀хъ въ корва́нꙋ, поне́же цѣна̀ кро́ве є҆́сть. совѣ́тъ же сотво́рше, кꙋпи́ша и҆́ми село̀ скꙋде́льниче, въ погреба́нїе стра̑ннымъ. тѣ́мже нарече́сѧ село̀ то̀, село̀ кро́ве, до сегѡ̀ днѐ. тогда̀ сбы́стсѧ рече́нное і҆еремі́емъ проро́комъ, глаго́лющимъ: и҆ прїѧ́ша три́десѧть сре́брєникъ, цѣ́нꙋ цѣне́ннаго, є҆го́же цѣни́ша ѿ сынѡ́въ і҆и҃лєвъ: и҆ да́ша ѧ҆̀ на селѣ̀ скꙋде́льничи, ꙗ҆́коже сказа̀ мнѣ̀ гдⷭ҇ь. і҆и҃съ же ста̀ пред̾ и҆ге́мѡномъ, и҆ вопросѝ є҆го̀ и҆ге́мѡнъ, глаго́лѧ: ты́ ли є҆сѝ цр҃ь і҆ꙋде́йскїй; і҆и҃съ же речѐ є҆мꙋ̀: ты̀ глаго́леши. и҆ є҆гда̀ на́нь глаго́лахꙋ а҆рхїере́є и҆ ста́рцы, ничесѡ́же ѿвѣщава́ше. тогда̀ глаго́ла є҆мꙋ̀ пїла́тъ: не слы́шиши ли, коли́кѡ на тѧ̀ свидѣ́тельствꙋютъ; и҆ не ѿвѣща̀ є҆мꙋ̀ ни къ є҆ди́номꙋ глаго́лꙋ: ꙗ҆́кѡ диви́тисѧ и҆ге́мѡнꙋ ѕѣлѡ̀. на всѧ́къ же пра́здникъ ѻ҆бы́чай бѣ̀ и҆ге́мѡнꙋ ѿпꙋща́ти є҆ди́наго наро́дꙋ свѧ́знѧ, є҆го́же хотѧ́хꙋ. и҆мѧ́хꙋ же тогда̀ свѧ́зана наро́чита, глаго́лемаго вара́ввꙋ. сѡ́браннымъ же и҆̀мъ, речѐ и҆̀мъ пїла́тъ: кого̀ хо́щете ѿ ѻ҆бою̀ ѿпꙋщꙋ̀ ва́мъ, вара́ввꙋ ли, и҆лѝ і҆и҃са глаго́лемаго хрⷭ҇та̀; вѣ́дѧше бо, ꙗ҆́кѡ за́висти ра́ди преда́ша є҆го̀. сѣдѧ́щꙋ же є҆мꙋ̀ на сꙋди́щи, посла̀ къ немꙋ̀ жена̀ є҆гѡ̀, глаго́лющи: ничто́же тебѣ̀, и҆ пра́ведникꙋ томꙋ̀, мно́гѡ бо пострада́хъ дне́сь во снѣ̀ є҆гѡ̀ ра́ди. а҆рхїере́є же и҆ ста́рцы наꙋсти́ша наро́ды, да и҆спро́сѧтъ вара́ввꙋ: і҆и҃са же погꙋбѧ́тъ. ѿвѣща́въ же и҆ге́мѡнъ, речѐ и҆̀мъ: кого̀ хо́щете ѿ ѻ҆бою̀ ѿпꙋщꙋ̀ ва́мъ; ѻ҆ни́ же рѣ́ша: вара́ввꙋ. глаго́ла и҆̀мъ пїла́тъ: что̀ ᲂу҆́бѡ сотворю̀ і҆и҃сꙋ, глаго́лемомꙋ хрⷭ҇тꙋ̀; глаго́лаша є҆мꙋ̀ всѝ: да ра́спѧтъ бꙋ́детъ. и҆ге́мѡнъ же речѐ: ко́е ᲂу҆́бѡ ѕло̀ сотворѝ; ѻ҆ни́ же и҆́злиха вопїѧ́хꙋ, глаго́люще: да про́пѧтъ бꙋ́детъ. ви́дѣвъ же пїла́тъ, ꙗ҆́кѡ ничто́же ᲂу҆спѣва́етъ, но па́че молва̀ быва́етъ, прїе́мъ во́дꙋ, ᲂу҆мы̀ рꙋ́цѣ пред̾ наро́домъ, глаго́лѧ: непови́ненъ є҆́смь ѿ кро́ве пра́веднагѡ сегѡ̀, вы̀ ᲂу҆́зрите. и҆ ѿвѣща́вше всѝ лю́дїе, рѣ́ша: кро́вь є҆гѡ̀ на на́съ, и҆ на ча́дѣхъ на́шихъ. тогда̀ ѿпꙋстѝ и҆̀мъ вара́ввꙋ: і҆и҃са же би́въ, предадѐ и҆̀мъ, да є҆го̀ про́пнꙋтъ. тогда̀ во́ини и҆ге́мѡновы прїе́мше і҆и҃са на сꙋди́ще, собра́ша на́нь всѐ мно́жество вѡ́инъ. и҆ совле́кше є҆го̀, ѡ҆дѣ́ѧша є҆го̀ хламѵ́дою червле́ною. и҆ спле́тше вѣне́цъ ѿ те́рнїѧ, возложи́ша на главꙋ̀ є҆гѡ̀, и҆ тро́сть въ десни́цꙋ є҆гѡ̀: и҆ покло́ньшесѧ на колѣ̑нꙋ пред̾ ни́мъ, рꙋга́хꙋсѧ є҆мꙋ̀, глаго́люще: ра́дꙋйсѧ цр҃ю̀ і҆ꙋде́йскїй. и҆ плю́нꙋвше на́нь, прїѧ́ша тро́сть, и҆ бїѧ́хꙋ по главѣ̀ є҆гѡ̀. и҆ є҆гда̀ порꙋга́шасѧ є҆мꙋ̀, совлеко́ша съ негѡ̀ багрѧни́цꙋ: и҆ ѡ҆блеко́ша є҆го̀ въ ри̑зы є҆гѡ̀, и҆ ведо́ша є҆го̀ на пропѧ́тїе. и҆сходѧ́ще же ѡ҆брѣто́ша человѣ́ка кѷрине́йска, и҆́менемъ сі́мѡна: и҆ семꙋ̀ задѣ́ша понестѝ крⷭ҇тъ є҆гѡ̀. и҆ прише́дше на мѣ́сто нарица́емое голго́ѳа, є҆́же є҆́сть глаго́лемо кра́нїево мѣ́сто: да́ша є҆мꙋ̀ пи́ти ѻ҆́цетъ съ же́лчїю смѣ́шенъ, и҆ вкꙋ́шъ не хотѧ́ше пи́ти. распе́ншїи же є҆го̀ раздѣли́ша ри̑зы є҆гѡ̀, ве́ргше жрє́бїѧ: и҆ сѣдѧ́ще стрежа́хꙋ є҆го̀ тꙋ̀. и҆ возложи́ша верхꙋ̀ главы̀ є҆гѡ̀ винꙋ̀ є҆гѡ̀ напи́санꙋ: се́й є҆́сть і҆и҃съ цр҃ь і҆ꙋде́йскїй. тогда̀ распѧ́ша съ ни́мъ два̀ разбѡ́йника: є҆ди́наго ѡ҆деснꙋ́ю, и҆ є҆ди́наго ѡ҆шꙋ́юю. мимоходѧ́щїи же хꙋ́лѧхꙋ є҆го̀, покива́юще глава́ми свои́ми, и҆ глаго́люще: разорѧ́ѧй цр҃ковь, и҆ тремѝ де́ньми созида́ѧй, спаси́сѧ са́мъ: а҆́ще сн҃ъ є҆сѝ бж҃їй, сни́ди со крⷭ҇та̀. та́кожде же и҆ а҆рхїере́є рꙋга́ющесѧ съ кни́жники, и҆ ста́рцы, и҆ фарїсе́и, глаго́лахꙋ: и҆ны̑ѧ спасѐ, себе́ ли не мо́жетъ спастѝ; а҆́ще цр҃ь і҆и҃левъ є҆́сть, да сни́детъ ны́нѣ со крⷭ҇та̀, и҆ вѣ́рꙋемъ въ него̀: ᲂу҆пова̀ на бг҃а: да и҆зба́витъ ны́нѣ є҆го̀, а҆́ще хо́щетъ є҆мꙋ̀: рече́ бо, ꙗ҆́кѡ бж҃їй є҆́смь сн҃ъ. то́жде же и҆ разбѡ́йника распѧ́таѧ съ ни́мъ поноша́ста є҆мꙋ̀. ѿ шеста́гѡ же часа̀ тма̀ бы́сть по все́й землѝ, до часа̀ девѧ́тагѡ. ѡ҆ девѧ́томъ же часѣ̀ возопѝ і҆и҃съ гла́сомъ ве́лїимъ, глаго́лѧ: и҆лі̀, и҆лі̀, лїма̀ савахѳані̀; є҆́же є҆́сть, бж҃е мо́й, бж҃е мо́й, вскꙋ́ю мѧ̀ є҆сѝ ѡ҆ста́вилъ; нѣ́цыи же ѿ тꙋ̀ стоѧ́щихъ слы́шавше, глаго́лахꙋ: ꙗ҆́кѡ и҆лїю̀ глаша́етъ се́й. и҆ а҆́бїе те́къ є҆ди́нъ ѿ ни́хъ, и҆ прїе́мъ гꙋ́бꙋ, и҆спо́лнивъ же ѻ҆́цта, и҆ вонзѐ на тро́сть, напаѧ́ше є҆го̀. про́чїи же глаго́лахꙋ: ѡ҆ста́ви, да ви́димъ, а҆́ще прїи́детъ и҆лїа̀ спастѝ є҆го̀. і҆и҃съ же па́ки возопи́въ гла́сомъ ве́лїимъ, и҆спꙋстѝ дх҃ъ. и҆ сѐ завѣ́са цр҃ко́внаѧ раздра́сѧ на дво́е, съ вы́шнѧгѡ кра́ѧ до ни́жнѧгѡ: и҆ землѧ̀ потрѧсе́сѧ, и҆ ка́менїе распаде́сѧ: и҆ гро́би ѿверзо́шасѧ, и҆ мнѡ́га тѣлеса̀ ᲂу҆со́пшихъ ст҃ы́хъ воста́ша: и҆ и҆зше́дше и҆з̾ грѡ́бъ по воскресе́нїи є҆гѡ̀, внидо́ша во ст҃ы́й гра́дъ, и҆ ꙗ҆ви́шасѧ мнѡ́зѣмъ. со́тникъ же и҆ и҆̀же съ ни́мъ стрегꙋ́щїи і҆и҃са, ви́дѣвше трꙋ́съ и҆ бы̑вшаѧ, ᲂу҆боѧ́шасѧ ѕѣлѡ̀, глаго́люще: вои́стиннꙋ бж҃їй сн҃ъ бѣ̀ се́й. бѧ́хꙋ же тꙋ̀ и҆ жєны̀ мно́ги и҆здале́ча зрѧ́ще, ꙗ҆̀же и҆до́ша по і҆и҃сѣ ѿ галїле́и, слꙋжа́ще є҆мꙋ̀. въ ни́хже бѣ̀ марі́а магдали́на и҆ марі́а і҆а́кѡвлѧ, и҆ і҆ѡсі́и ма́ти, и҆ ма́ти сы́нꙋ зеведе́ѡвꙋ. ",
}

add_evangelie_matfea {
  ["номер"] = 110,
  ["комментарий"] = "Мф., 110 зач., XXVII, 1–44; Лк., XXIII, 39–43; Мф., XXVII, 45–54; Ин., XIX, 31–37; Мф., XXVII, 55–61.",
  ["текст_ру"] = "Во вре́мя о́но, сове́т сотвори́ша вси архиере́е и ста́рцы людсти́и на Иису́са, я́ко уби́ти Его́. И связа́вше Его́ ведо́ша, и преда́ша Его́ Понти́йскому Пила́ту иге́мону. Тогда́ ви́дев Иу́да преда́вый Иису́са, я́ко осуди́ша Его́, раска́явся возврати́ три́десять сре́бреники архиере́ем и ста́рцем, глаго́ля: согреши́х, преда́в кровь непови́нную. Они́ же ре́ша: что есть нам? Ты у́зриши. И пове́рг сре́бреники в це́ркви, оты́де, и шед удави́ся. Архиере́е же прие́мше сре́бреники, ре́ша: недосто́йно есть вложи́ти их в корва́ну, поне́же цена́ кро́ве есть. Сове́т же сотво́рше, купи́ша и́ми село́ скуде́льниче, в погреба́ние стра́нным. Те́мже нарече́ся село́ то, село́ кро́ве, до сего́ дне. Тогда́ сбы́стся рече́нное Иереми́ем проро́ком, глаго́лющим: и прия́ша три́десять сре́бреник, це́ну Цене́ннаго, Его́же цени́ша от сыно́в Изра́илев. И да́ша я́ на селе́ скуде́льничи, я́коже сказа́ мне Госпо́дь. Иису́с же ста пред иге́моном. И вопроси́ Его́ иге́мон, глаго́ля: Ты ли еси́ Царь Иуде́йский? Иису́с же рече́ ему́: ты глаго́леши. И егда́ Нань глаго́лаху архиере́е и ста́рцы, ничесо́же отвещава́ше. Тогда́ глаго́ла Ему́ Пила́т: не слы́шиши ли, коли́ко на Тя свиде́тельствуют? И не отвеща́ ему́ ни к еди́ному глаго́лу, я́ко диви́тися иге́мону зело́. На всяк же пра́здник обы́чай бе иге́мону отпуща́ти еди́наго наро́ду свя́зня, его́же хотя́ху. Имя́ху же тогда́ свя́зана наро́чита, глаго́лемаго Вара́вву. Со́бранным же им, рече́ им Пила́т: кого́ хо́щете от обою́ отпущу́ вам; Вара́вву ли, или́ Иису́са глаго́лемаго Христа́? Ве́дяше бо, я́ко за́висти ра́ди преда́ша Его́. Седя́щу же ему́ на суди́щи, посла́ к нему́ жена́ его́, глаго́лющи: ничто́же тебе́, и Пра́веднику Тому́, мно́го бо пострада́х днесь во сне Его́ ра́ди. Архиере́е же и ста́рцы наусти́ша наро́ды, да испро́сят Вара́вву, Иису́са же погубя́т. Отвеща́в же иге́мон рече́ им: кого́ хо́щете от обою́ отпущу́ вам? Они́ же ре́ша: Вара́вву. Глаго́ла им Пила́т: что у́бо сотворю́ Иису́су, глаго́лемому Христу́? Глаго́лаша ему́ вси: да ра́спят бу́дет. Иге́мон же рече́: ко́е у́бо зло сотвори́? Они́ же и́злиха вопия́ху, глаго́люще: да про́пят бу́дет. Ви́дев же Пила́т, я́ко ничто́же успева́ет, но па́че молва́ быва́ет, прие́мь во́ду, умы́ ру́це пред наро́дом, глаго́ля: непови́нен есмь от кро́ве Пра́веднаго Сего́, вы у́зрите. И отвеща́вше вси лю́дие, ре́ша: кровь Его́ на нас, и на ча́дех на́ших. Тогда́ отпусти́ им Вара́вву, Иису́са же бив, предаде́ им, да Его́ про́пнут. Тогда́ во́ини иге́моновы, прие́мше Иису́са на суди́ще, собра́ша Нань все мно́жество во́ин. И совле́кше Его́, оде́яша Его́ хлами́дою червле́ною. И спле́тше вене́ц от те́рния, возложи́ша на главу́ Его́, и трость в десни́цу Его́. И покло́ньшеся на коле́ну пред Ним, руга́хуся Ему́, глаго́люще: ра́дуйся, Царю́ Иуде́йский. И плю́нувше Нань, прия́ша трость, и бия́ху по главе́ Его́. И егда́ поруга́шася Ему́, совлеко́ша с Него́ багряни́цу, и облеко́ша Его́ в ри́зы Его́, и ведо́ша Его́ на пропя́тие. Исходя́ще же обрето́ша челове́ка Кирине́йска, и́менем Си́мона, и сему́ заде́ша понести́ крест Его́. И прише́дше на ме́сто нарица́емое Голго́фа, е́же есть глаго́лемо Кра́ниево ме́сто, да́ша Ему́ пи́ти о́цет с же́лчию сме́шен, и вкушь не хотя́ше пи́ти. Распе́ншии же Его́ раздели́ша ри́зы Его́, ве́ргше жре́бия. И седя́ще стрежа́ху Его́ ту. И возложи́ша верху́ главы́ Его́ вину́ Его́ напи́сану: Сей есть Иису́с, Царь Иуде́йский. Тогда́ распя́ша с Ним два разбо́йника, еди́наго одесну́ю, и еди́наго ошу́юю. Еди́н же от обе́шеною злоде́ю ху́ляше Его́, глаго́ля: а́ще Ты еси́ Христо́с, спаси́ Себе́ и на́ю. Отвеща́в же други́й, преща́ше ему́, глаго́ля: ни ли ты бои́шися Бо́га, я́ко в то́мже осужде́н еси́? И мы у́бо в пра́вду, досто́йная бо по дело́м на́ю восприе́млева, Сей же ни еди́наго зла сотвори́. И глаго́лаше Иису́сови: помяни́ мя, Го́споди, егда́ прии́деши во Ца́рствии Си. И рече́ ему́ Иису́с: ами́нь глаго́лю тебе́, днесь со Мно́ю бу́деши в раи́. Мимоходя́щии же ху́ляху Его́, покива́юще глава́ми свои́ми, и глаго́люще: разоря́яй це́рковь и треми́ де́ньми созида́яй, спаси́ся Сам, а́ще Сын еси́ Бо́жий, сни́ди со креста́. Та́кожде же и архиере́е руга́ющеся с кни́жники, и ста́рцы, и фарисе́и, глаго́лаху: ины́я спасе́, Себе́ ли не мо́жет спасти́? А́ще Царь Изра́илев есть, да сни́дет ны́не со креста́, и ве́руем в Него́. Упова́ на Бо́га, да изба́вит ны́не Его́, а́ще хо́щет Ему́, рече́ бо, я́ко Бо́жий есмь Сын. То́жде же и разбо́йника распя́тая с Ним поноша́ста Ему́. От шеста́го же часа́ тма бысть по всей земли́, до часа́ девя́таго. О девя́том же часе́ возопи́ Иису́с гла́сом ве́лиим, глаго́ля: Или́, Или́, лима́ савахфани́? Е́же есть, Бо́же Мой, Бо́же Мой, вску́ю Мя еси́ оста́вил? Не́цыи же от ту стоя́щих слы́шавше, глаго́лаху, я́ко Илию́ глаша́ет Сей. И а́бие тек еди́н от них, и прие́м гу́бу, испо́лнив же о́цта, и вонзе́ на трость, напая́ше Его́. Про́чии же глаго́лаху: оста́ви, да ви́дим, а́ще прии́дет Илиа́ спасти́ Его́. Иису́с же, па́ки возопи́в гла́сом ве́лиим, испусти́ дух. И се заве́са церко́вная раздра́ся на дво́е, с вы́шняго кра́я до ни́жняго; и земля́ потрясе́ся, и ка́мение распаде́ся. И гро́би отверзо́шася, и мно́га телеса́ усо́пших святы́х воста́ша. И изше́дше из гроб по воскресе́нии Его́, внидо́ша во святы́й град, и яви́шася мно́зем. Со́тник же и и́же с ним стрегу́щии Иису́са, ви́девше трус и бы́вшая, убоя́шася зело́, глаго́люще: вои́стинну Бо́жий Сын бе Сей. Иуде́е же, поне́же пято́к бе, да не оста́нут на кресте́ телеса́ в суббо́ту, бе бо вели́к день тоя́ суббо́ты, моли́ша Пила́та, да пребию́т го́лени их, и во́змут. Приидо́ша же во́ини, и пе́рвому у́бо преби́ша го́лени, и друго́му распя́тому с Ним. На Иису́са же прише́дше, я́ко ви́деша Его́ уже́ уме́рша, не преби́ша Ему́ го́лений. Но еди́н от во́ин копие́м ре́бра Ему́ прободе́, и а́бие изы́де кровь и вода́. И ви́девый свиде́тельствова, и и́стинно есть свиде́тельство его́, и той весть, я́ко и́стину глаго́лет, да вы ве́ру и́мете. Бы́ша бо сия́, да сбу́дется Писа́ние: кость не сокруши́тся от Него́. И па́ки друго́е Писа́ние глаго́лет: воззря́т Нань, Его́же прободо́ша. Бя́ху же ту и жены́ мно́ги издале́ча зря́ще, я́же идо́ша по Иису́се от Галиле́и, служа́ще Ему́. В ни́хже бе Мари́а Магдали́на и Мари́а Иа́ковля, и Иоси́и ма́ти, и ма́ти сы́ну Зеведе́ову. По́зде же бы́вшу, прии́де челове́к бога́т от Аримафе́а, и́менем Ио́сиф, и́же и той учи́ся у Иису́са. Сей присту́пль к Пила́ту, проси́ телесе́ Иису́сова. Тогда́ Пила́т повеле́ да́ти те́ло. И прие́мь те́ло Ио́сиф, обви́т е́ плащани́цею чи́стою, и положи́ е́ в но́вем свое́м гро́бе, и́же изсече́ в ка́мени. И возвали́в ка́мень ве́лий над две́ри гро́ба, оты́де. Бе же ту Мари́а Магдали́на, и друга́я Мари́а, седя́ще пря́мо гро́ба. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, совѣ́тъ сотвори́ша всѝ а҆рхїере́є и҆ ста́рцы людсті́и на і҆и҃са, ꙗ҆́кѡ ᲂу҆би́ти є҆го̀. и҆ свѧза́вше є҆го̀ ведо́ша, и҆ преда́ша є҆го̀ понті́йскомꙋ пїла́тꙋ и҆ге́мѡнꙋ. тогда̀ ви́дѣвъ і҆ꙋ́да преда́вый є҆го̀, ꙗ҆́кѡ ѡ҆сꙋди́ша є҆го̀, раска́ѧвсѧ возвратѝ три́десѧть сре́бреники а҆рхїере́ємъ и҆ ста́рцємъ, глаго́лѧ: согрѣши́хъ, преда́въ кро́вь непови́ннꙋю. ѻ҆ни́ же рѣ́ша: что̀ є҆́сть на́мъ; ты̀ ᲂу҆́зриши. и҆ пове́ргъ сре́бреники въ цр҃кви, ѿи́де, и҆ ше́дъ ᲂу҆дави́сѧ. а҆рхїере́є же прїе́мше сре́бреники, рѣ́ша: недосто́йно є҆́сть вложи́ти и҆̀хъ въ корва́нꙋ, поне́же цѣна̀ кро́ве є҆́сть. совѣ́тъ же сотво́рше, кꙋпи́ша и҆́ми село̀ скꙋде́льниче, въ погреба́нїе стра̑ннымъ. тѣ́мже нарече́сѧ село̀ то̀, село̀ кро́ве, до сегѡ̀ днѐ. тогда̀ сбы́стсѧ рече́нное і҆еремі́емъ проро́комъ, глаго́лющимъ: и҆ прїѧ́ша три́десѧть сре́брєникъ, цѣ́нꙋ цѣне́ннаго, є҆го́же цѣни́ша ѿ сынѡ́въ і҆и҃лєвъ: и҆ да́ша ѧ҆̀ на селѣ̀ скꙋде́льничи, ꙗ҆́коже сказа̀ мнѣ̀ гдⷭ҇ь. і҆и҃съ же ста̀ пред̾ и҆ге́мѡномъ, и҆ вопросѝ є҆го̀ и҆ге́мѡнъ, глаго́лѧ: ты́ ли є҆сѝ цр҃ь і҆ꙋде́йскїй; і҆и҃съ же речѐ є҆мꙋ̀: ты̀ глаго́леши. и҆ є҆гда̀ на́нь глаго́лахꙋ а҆рхїере́є и҆ ста́рцы, ничесѡ́же ѿвѣщава́ше. тогда̀ глаго́ла є҆мꙋ̀ пїла́тъ: не слы́шиши ли, коли́кѡ на тѧ̀ свидѣ́тельствꙋютъ; и҆ не ѿвѣща̀ є҆мꙋ̀ ни къ є҆ди́номꙋ глаго́лꙋ: ꙗ҆́кѡ диви́тисѧ и҆ге́мѡнꙋ ѕѣлѡ̀. на всѧ́къ же пра́здникъ ѻ҆бы́чай бѣ̀ и҆ге́мѡнꙋ ѿпꙋща́ти є҆ди́наго наро́дꙋ свѧ́знѧ, є҆го́же хотѧ́хꙋ. и҆мѧ́хꙋ же тогда̀ свѧ́зана наро́чита, глаго́лемаго вара́ввꙋ. сѡ́браннымъ же и҆̀мъ, речѐ и҆̀мъ пїла́тъ: кого̀ хо́щете ѿ ѻ҆бою̀ ѿпꙋщꙋ̀ ва́мъ, вара́ввꙋ ли, и҆лѝ і҆и҃са глаго́лемаго хрⷭ҇та̀; вѣ́дѧше бо, ꙗ҆́кѡ за́висти ра́ди преда́ша є҆го̀. сѣдѧ́щꙋ же є҆мꙋ̀ на сꙋди́щи, посла̀ къ немꙋ̀ жена̀ є҆гѡ̀, глаго́лющи: ничто́же тебѣ̀, и҆ пра́ведникꙋ томꙋ̀, мно́гѡ бо пострада́хъ дне́сь во снѣ̀ є҆гѡ̀ ра́ди. а҆рхїере́є же и҆ ста́рцы наꙋсти́ша наро́ды, да и҆спро́сѧтъ вара́ввꙋ: і҆и҃са же погꙋбѧ́тъ. ѿвѣща́въ же и҆ге́мѡнъ, речѐ и҆̀мъ: кого̀ хо́щете ѿ ѻ҆бою̀ ѿпꙋщꙋ̀ ва́мъ; ѻ҆ни́ же рѣ́ша: вара́ввꙋ. глаго́ла и҆̀мъ пїла́тъ: что̀ ᲂу҆́бѡ сотворю̀ і҆и҃сꙋ, глаго́лемомꙋ хрⷭ҇тꙋ̀; глаго́лаша є҆мꙋ̀ всѝ: да ра́спѧтъ бꙋ́детъ. и҆ге́мѡнъ же речѐ: ко́е ᲂу҆́бѡ ѕло̀ сотворѝ; ѻ҆ни́ же и҆́злиха вопїѧ́хꙋ, глаго́люще: да про́пѧтъ бꙋ́детъ. ви́дѣвъ же пїла́тъ, ꙗ҆́кѡ ничто́же ᲂу҆спѣва́етъ, но па́че молва̀ быва́етъ, прїе́мъ во́дꙋ, ᲂу҆мы̀ рꙋ́цѣ пред̾ наро́домъ, глаго́лѧ: непови́ненъ є҆́смь ѿ кро́ве пра́веднагѡ сегѡ̀, вы̀ ᲂу҆́зрите. и҆ ѿвѣща́вше всѝ лю́дїе, рѣ́ша: кро́вь є҆гѡ̀ на на́съ, и҆ на ча́дѣхъ на́шихъ. тогда̀ ѿпꙋстѝ и҆̀мъ вара́ввꙋ: і҆и҃са же би́въ, предадѐ и҆̀мъ, да є҆го̀ про́пнꙋтъ. тогда̀ во́ини и҆ге́мѡновы прїе́мше і҆и҃са на сꙋди́ще, собра́ша на́нь всѐ мно́жество вѡ́инъ. и҆ совле́кше є҆го̀, ѡ҆дѣ́ѧша є҆го̀ хламѵ́дою червле́ною. и҆ спле́тше вѣне́цъ ѿ те́рнїѧ, возложи́ша на главꙋ̀ є҆гѡ̀, и҆ тро́сть въ десни́цꙋ є҆гѡ̀: и҆ покло́ньшесѧ на колѣ̑нꙋ пред̾ ни́мъ, рꙋга́хꙋсѧ є҆мꙋ̀, глаго́люще: ра́дꙋйсѧ цр҃ю̀ і҆ꙋде́йскїй. и҆ плю́нꙋвше на́нь, прїѧ́ша тро́сть, и҆ бїѧ́хꙋ по главѣ̀ є҆гѡ̀. и҆ є҆гда̀ порꙋга́шасѧ є҆мꙋ̀, совлеко́ша съ негѡ̀ багрѧни́цꙋ: и҆ ѡ҆блеко́ша є҆го̀ въ ри̑зы є҆гѡ̀, и҆ ведо́ша є҆го̀ на пропѧ́тїе. и҆сходѧ́ще же ѡ҆брѣто́ша человѣ́ка кѷрине́йска, и҆́менемъ сі́мѡна: и҆ семꙋ̀ задѣ́ша понестѝ крⷭ҇тъ є҆гѡ̀. и҆ прише́дше на мѣ́сто нарица́емое голго́ѳа, є҆́же є҆́сть глаго́лемо кра́нїево мѣ́сто: да́ша є҆мꙋ̀ пи́ти ѻ҆́цетъ съ же́лчїю смѣ́шенъ, и҆ вкꙋ́шъ не хотѧ́ше пи́ти. распе́ншїи же є҆го̀ раздѣли́ша ри̑зы є҆гѡ̀, ве́ргше жрє́бїѧ: и҆ сѣдѧ́ще стрежа́хꙋ є҆го̀ тꙋ̀. и҆ возложи́ша верхꙋ̀ главы̀ є҆гѡ̀ винꙋ̀ є҆гѡ̀ напи́санꙋ: се́й є҆́сть і҆и҃съ цр҃ь і҆ꙋде́йскїй. тогда̀ распѧ́ша съ ни́мъ два̀ разбѡ́йника: є҆ди́наго ѡ҆деснꙋ́ю, и҆ є҆ди́наго ѡ҆шꙋ́юю. є҆ди́нъ же ѿ ѡ҆бѣ́шеною ѕлодѣ̑ю хꙋ́лѧше є҆го̀, глаго́лѧ: а҆́ще ты̀ є҆сѝ хрⷭ҇то́съ, спасѝ себѐ и҆ на́ю. ѿвѣща́въ же дрꙋгі́й, преща́ше є҆мꙋ̀, глаго́лѧ: ни лѝ ты̀ бои́шисѧ бг҃а, ꙗ҆́кѡ въ то́мже ѡ҆сꙋжде́нъ є҆сѝ; и҆ мы̀ ᲂу҆́бѡ въ пра́вдꙋ, достѡ́йнаѧ бо по дѣлѡ́мъ на́ю воспрїе́млева: се́й же ни є҆ди́нагѡ ѕла̀ сотворѝ. и҆ глаго́лаше і҆и҃сови: помѧни́ мѧ гдⷭ҇и, є҆гда̀ прїи́деши во црⷭ҇твїи сѝ. и҆ речѐ є҆мꙋ̀ і҆и҃съ: а҆ми́нь глаго́лю тебѣ̀, дне́сь со мно́ю бꙋ́деши въ раѝ. мимоходѧ́щїи же хꙋ́лѧхꙋ є҆го̀, покива́юще глава́ми свои́ми, и҆ глаго́люще: разорѧ́ѧй цр҃ковь, и҆ тремѝ де́ньми созида́ѧй, спаси́сѧ са́мъ: а҆́ще сн҃ъ є҆сѝ бж҃їй, сни́ди со крⷭ҇та̀. та́кожде же и҆ а҆рхїере́є рꙋга́ющесѧ съ кни́жники, и҆ ста́рцы, и҆ фарїсе́и, глаго́лахꙋ: и҆ны̑ѧ спасѐ, себе́ ли не мо́жетъ спастѝ; а҆́ще цр҃ь і҆и҃левъ є҆́сть, да сни́детъ ны́нѣ со крⷭ҇та̀, и҆ вѣ́рꙋемъ въ него̀: ᲂу҆пова̀ на бг҃а: да и҆зба́витъ ны́нѣ є҆го̀, а҆́ще хо́щетъ є҆мꙋ̀: рече́ бо, ꙗ҆́кѡ бж҃їй є҆́смь сн҃ъ. то́жде же и҆ разбѡ́йника распѧ́таѧ съ ни́мъ поноша́ста є҆мꙋ̀. ѿ шеста́гѡ же часа̀ тма̀ бы́сть по все́й землѝ, до часа̀ девѧ́тагѡ. ѡ҆ девѧ́томъ же часѣ̀ возопѝ і҆и҃съ гла́сомъ ве́лїимъ, глаго́лѧ: и҆лі̀, и҆лі̀, лїма̀ савахѳані̀; є҆́же є҆́сть, бж҃е мо́й, бж҃е мо́й, вскꙋ́ю мѧ̀ є҆сѝ ѡ҆ста́вилъ; нѣ́цыи же ѿ тꙋ̀ стоѧ́щихъ слы́шавше, глаго́лахꙋ: ꙗ҆́кѡ и҆лїю̀ глаша́етъ се́й. и҆ а҆́бїе те́къ є҆ди́нъ ѿ ни́хъ, и҆ прїе́мъ гꙋ́бꙋ, и҆спо́лнивъ же ѻ҆́цта, и҆ вонзѐ на тро́сть, напаѧ́ше є҆го̀. про́чїи же глаго́лахꙋ: ѡ҆ста́ви, да ви́димъ, а҆́ще прїи́детъ и҆лїа̀ спастѝ є҆го̀. і҆и҃съ же па́ки возопи́въ гла́сомъ ве́лїимъ, и҆спꙋстѝ дх҃ъ. и҆ сѐ завѣ́са цр҃ко́внаѧ раздра́сѧ на дво́е, съ вы́шнѧгѡ кра́ѧ до ни́жнѧгѡ: и҆ землѧ̀ потрѧсе́сѧ, и҆ ка́менїе распаде́сѧ: и҆ гро́би ѿверзо́шасѧ, и҆ мнѡ́га тѣлеса̀ ᲂу҆со́пшихъ ст҃ы́хъ воста́ша: и҆ и҆зше́дше и҆з̾ грѡ́бъ по воскресе́нїи є҆гѡ̀, внидо́ша во ст҃ы́й гра́дъ, и҆ ꙗ҆ви́шасѧ мнѡ́зѣмъ. со́тникъ же и҆ и҆̀же съ ни́мъ стрегꙋ́щїи і҆и҃са, ви́дѣвше трꙋ́съ и҆ бы̑вшаѧ, ᲂу҆боѧ́шасѧ ѕѣлѡ̀, глаго́люще: вои́стиннꙋ бж҃їй сн҃ъ бѣ̀ се́й. і҆ꙋде́є же, поне́же пѧто́къ бѣ̀, да не ѡ҆ста́нꙋтъ на крⷭ҇тѣ̀ тѣлеса̀ въ сꙋббѡ́тꙋ: бѣ́ бо вели́къ де́нь тоѧ̀ сꙋббѡ́ты, моли́ша пїла́та, да пребїю́тъ го́лєни и҆́хъ, и҆ во́з̾мꙋтъ. прїидо́ша же во́ини, и҆ пе́рвомꙋ ᲂу҆́бѡ преби́ша го́лєни, и҆ дрꙋго́мꙋ распѧ́томꙋ съ ни́мъ. на і҆и҃са же прише́дше, ꙗ҆́кѡ ви́дѣша є҆го̀ ᲂу҆жѐ ᲂу҆ме́рша, не преби́ша є҆мꙋ̀ го́ленїй: но є҆ди́нъ ѿ вѡ́инъ копїе́мъ ре́бра є҆мꙋ̀ прободѐ, и҆ а҆́бїе и҆зы́де кро́вь и҆ вода̀. и҆ ви́дѣвый свидѣ́тельствова, и҆ и҆́стинно є҆́сть свидѣ́тельство є҆гѡ̀. и҆ то́й вѣ́сть, ꙗ҆́кѡ и҆́стинꙋ глаго́летъ, да вы̀ вѣ́рꙋ и҆́мете. бы́ша бо сїѧ̑, да сбꙋ́детсѧ писа́нїе: ко́сть не сокрꙋши́тсѧ ѿ негѡ̀. и҆ па́ки дрꙋго́е писа́нїе глаго́летъ: воззрѧ́тъ на́нь, є҆го́же прободо́ша. бѧ́хꙋ же тꙋ̀ и҆ жєны̀ мно́ги и҆здале́ча зрѧ́ще, ꙗ҆̀же и҆до́ша по і҆и҃сѣ ѿ галїле́и, слꙋжа́ще є҆мꙋ̀. въ ни́хже бѣ̀ марі́а магдали́на и҆ марі́а і҆а́кѡвлѧ, и҆ і҆ѡсі́и ма́ти, и҆ ма́ти сы́нꙋ зеведе́ѡвꙋ. по́здѣ же бы́вшꙋ, прїи́де человѣ́къ бога́тъ ѿ а҆рїмаѳе́а, и҆́менемъ і҆ѡ́сифъ: и҆́же и҆ то́й ᲂу҆чи́сѧ ᲂу҆ і҆и҃са. се́й пристꙋ́пль къ пїла́тꙋ, просѝ тѣлесѐ і҆и҃сова: тогда̀ пїла́тъ повелѣ̀ да́ти тѣ́ло. и҆ прїе́мъ тѣ́ло і҆ѡ́сифъ, ѡ҆бви́тъ є҆̀ плащани́цею чи́стою: и҆ положѝ є҆̀ въ но́вѣмъ свое́мъ гро́бѣ, и҆́же и҆зсѣчѐ въ ка́мени: и҆ возвали́въ ка́мень ве́лїй над̾ двє́ри гро́ба, ѿи́де. бѣ́ же тꙋ̀ марі́а магдали́на, и҆ дрꙋга́ѧ марі́а, сѣдѧ́щѣ прѧ́мѡ гро́ба. ",
}

