  ["номер"] = 111,
  ["комментарий"] = "Мф., 111 зач., XXVII, 3–32.",
  ["текст_ру"] = "Во вре́мя о́но, ви́дев Иу́да преда́вый Иису́са, я́ко осуди́ша Его́, раска́явся возврати́ три́десять сре́бреники архиере́ем и ста́рцем, глаго́ля: согреши́х преда́в кровь непови́нную. Они́ же ре́ша: что есть нам? Ты у́зриши. И пове́рг сре́бреники в це́ркви, оты́де, и шед удави́ся. Архиере́е же прие́мше сре́бреники, ре́ша: недосто́йно есть вложи́ти их в корва́ну, поне́же цена́ кро́ве есть. Сове́т же сотво́рше, купи́ша и́ми село́ скуде́льниче, в погреба́ние стра́нным. Те́мже нарече́ся село́ то село́ кро́ве, до сего́ дне. Тогда́ сбы́стся рече́нное Иереми́ем проро́ком, глаго́лющим: и прия́ша три́десять сре́бреник, це́ну Цене́ннаго, Его́же цени́ша от сыно́в Изра́илев, и да́ша я́ на селе́ скуде́льничи, я́коже сказа́ мне Госпо́дь. Иису́с же ста пред иге́моном. И вопроси́ Его́ иге́мон, глаго́ля: Ты ли еси́ Царь Иуде́йский? Иису́с же рече́ ему́: ты глаго́леши. И егда́ Нань глаго́лаху архиере́е и ста́рцы, ничесо́же отвещава́ше. Тогда́ глаго́ла Ему́ Пила́т: не слы́шиши ли, коли́ко на Тя свиде́тельствуют? И не отвеща́ ему́ ни к еди́ному глаго́лу, я́ко диви́тися иге́мону зело́. На всяк же пра́здник обы́чай бе иге́мону отпуща́ти еди́наго наро́ду свя́зня, его́же хотя́ху. Имя́ху же тогда́ свя́зана наро́чита, глаго́лемаго Вара́вву. Со́бранным же им, рече́ им Пила́т: кого́ хо́щете от обою́ отпущу́ вам, Вара́вву ли, или́ Иису́са глаго́лемаго Христа́? Ве́дяше бо, я́ко за́висти ра́ди преда́ша Его́. Седя́щу же ему́ на суди́щи, посла́ к нему́ жена́ его́, глаго́лющи, ничто́же тебе́ и Пра́веднику Тому́, мно́го бо пострада́х днесь во сне Его́ ра́ди. Архиере́е же и ста́рцы наусти́ша наро́ды, да испро́сят Вара́вву, Иису́са же погубя́т. Отвеща́в же иге́мон рече́ им: кого́ хо́щете от обою́ отпущу́ вам? Они́ же ре́ша: Вара́вву. Глаго́ла им Пила́т: что у́бо сотворю́ Иису́су глаго́лемому Христу́? Глаго́лаша ему́ вси: да ра́спят бу́дет. Иге́мон же рече́: ко́е у́бо зло сотвори́? Они́ же и́злиха вопия́ху, глаго́люще: да про́пят бу́дет. Ви́дев же Пила́т, я́ко ничто́же успева́ет, но па́че молва́ быва́ет, прие́мь во́ду, умы́ ру́це пред наро́дом, глаго́ля: непови́нен есмь от кро́ве Пра́веднаго Сего́, вы у́зрите. И отвеща́вше вси лю́дие ре́ша: кровь Его́ на нас и на ча́дех на́ших. Тогда́ отпусти́ им Вара́вву, Иису́са же бив предаде́ им, да Его́ про́пнут. Тогда́ во́ини иге́моновы, прие́мше Иису́са на суди́ще, собра́ша Нань все мно́жество во́ин. И совле́кше Его́, оде́яша Его́ хлами́дою червле́ною. И спле́тше вене́ц от те́рния, возложи́ша на главу́ Его́, и трость в десни́цу Его́, и покло́ньшеся на коле́ну пред Ним руга́хуся Ему́, глаго́люще: ра́дуйся, Царю́ Иуде́йский. И плю́нувше Нань, прия́ша трость и бия́ху по главе́ Его́. И егда́ поруга́шася Ему́, совлеко́ша с Него́ багряни́цу и облеко́ша Его́ в ри́зы Его́, и ведо́ша Его́ на пропя́тие. Исходя́ще же обрето́ша челове́ка Кирине́йска, и́менем Си́мона, и сему́ заде́ша понести́ крест Его́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ви́дѣвъ і҆ꙋ́да преда́вый і҆и҃са, ꙗ҆́кѡ ѡ҆сꙋди́ша є҆го̀, раска́ѧвсѧ возвратѝ три́десѧть сре́бреники а҆рхїере́ємъ и҆ ста́рцємъ, глаго́лѧ: согрѣши́хъ, преда́въ кро́вь непови́ннꙋю. ѻ҆ни́ же рѣ́ша: что̀ є҆́сть на́мъ; ты̀ ᲂу҆́зриши. и҆ пове́ргъ сре́бреники въ цр҃кви, ѿи́де, и҆ ше́дъ ᲂу҆дави́сѧ. а҆рхїере́є же прїе́мше сре́бреники, рѣ́ша: недосто́йно є҆́сть вложи́ти и҆̀хъ въ корва́нꙋ, поне́же цѣна̀ кро́ве є҆́сть. совѣ́тъ же сотво́рше, кꙋпи́ша и҆́ми село̀ скꙋде́льниче, въ погреба́нїе стра̑ннымъ. тѣ́мже нарече́сѧ село̀ то̀, село̀ кро́ве, до сегѡ̀ днѐ. тогда̀ сбы́стсѧ рече́нное і҆еремі́емъ проро́комъ, глаго́лющимъ: и҆ прїѧ́ша три́десѧть сре́брєникъ, цѣ́нꙋ цѣне́ннаго, є҆го́же цѣни́ша ѿ сынѡ́въ і҆и҃лєвъ: и҆ да́ша ѧ҆̀ на селѣ̀ скꙋде́льничи, ꙗ҆́коже сказа̀ мнѣ̀ гдⷭ҇ь. і҆и҃съ же ста̀ пред̾ и҆ге́мѡномъ, и҆ вопросѝ є҆го̀ и҆ге́мѡнъ, глаго́лѧ: ты́ ли є҆сѝ цр҃ь і҆ꙋде́йскїй; і҆и҃съ же речѐ є҆мꙋ̀: ты̀ глаго́леши. и҆ є҆гда̀ на́нь глаго́лахꙋ а҆рхїере́є и҆ ста́рцы, ничесѡ́же ѿвѣщава́ше. тогда̀ глаго́ла є҆мꙋ̀ пїла́тъ: не слы́шиши ли, коли́кѡ на тѧ̀ свидѣ́тельствꙋютъ; и҆ не ѿвѣща̀ є҆мꙋ̀ ни къ є҆ди́номꙋ глаго́лꙋ: ꙗ҆́кѡ диви́тисѧ и҆ге́мѡнꙋ ѕѣлѡ̀. на всѧ́къ же пра́здникъ ѻ҆бы́чай бѣ̀ и҆ге́мѡнꙋ ѿпꙋща́ти є҆ди́наго наро́дꙋ свѧ́знѧ, є҆го́же хотѧ́хꙋ. и҆мѧ́хꙋ же тогда̀ свѧ́зана наро́чита, глаго́лемаго вара́ввꙋ. сѡ́браннымъ же и҆̀мъ, речѐ и҆̀мъ пїла́тъ: кого̀ хо́щете ѿ ѻ҆бою̀ ѿпꙋщꙋ̀ ва́мъ, вара́ввꙋ ли, и҆лѝ і҆и҃са глаго́лемаго хрⷭ҇та̀; вѣ́дѧше бо, ꙗ҆́кѡ за́висти ра́ди преда́ша є҆го̀. сѣдѧ́щꙋ же є҆мꙋ̀ на сꙋди́щи, посла̀ къ немꙋ̀ жена̀ є҆гѡ̀, глаго́лющи: ничто́же тебѣ̀, и҆ пра́ведникꙋ томꙋ̀, мно́гѡ бо пострада́хъ дне́сь во снѣ̀ є҆гѡ̀ ра́ди. а҆рхїере́є же и҆ ста́рцы наꙋсти́ша наро́ды, да и҆спро́сѧтъ вара́ввꙋ: і҆и҃са же погꙋбѧ́тъ. ѿвѣща́въ же и҆ге́мѡнъ, речѐ и҆̀мъ: кого̀ хо́щете ѿ ѻ҆бою̀ ѿпꙋщꙋ̀ ва́мъ; ѻ҆ни́ же рѣ́ша: вара́ввꙋ. глаго́ла и҆̀мъ пїла́тъ: что̀ ᲂу҆́бѡ сотворю̀ і҆и҃сꙋ, глаго́лемомꙋ хрⷭ҇тꙋ̀; глаго́лаша є҆мꙋ̀ всѝ: да ра́спѧтъ бꙋ́детъ. и҆ге́мѡнъ же речѐ: ко́е ᲂу҆́бѡ ѕло̀ сотворѝ; ѻ҆ни́ же и҆́злиха вопїѧ́хꙋ, глаго́люще: да про́пѧтъ бꙋ́детъ. ви́дѣвъ же пїла́тъ, ꙗ҆́кѡ ничто́же ᲂу҆спѣва́етъ, но па́че молва̀ быва́етъ, прїе́мъ во́дꙋ, ᲂу҆мы̀ рꙋ́цѣ пред̾ наро́домъ, глаго́лѧ: непови́ненъ є҆́смь ѿ кро́ве пра́веднагѡ сегѡ̀, вы̀ ᲂу҆́зрите. и҆ ѿвѣща́вше всѝ лю́дїе, рѣ́ша: кро́вь є҆гѡ̀ на на́съ, и҆ на ча́дѣхъ на́шихъ. тогда̀ ѿпꙋстѝ и҆̀мъ вара́ввꙋ: і҆и҃са же би́въ, предадѐ и҆̀мъ, да є҆го̀ про́пнꙋтъ. тогда̀ во́ини и҆ге́мѡновы прїе́мше і҆и҃са на сꙋди́ще, собра́ша на́нь всѐ мно́жество вѡ́инъ. и҆ совле́кше є҆го̀, ѡ҆дѣ́ѧша є҆го̀ хламѵ́дою червле́ною. и҆ спле́тше вѣне́цъ ѿ те́рнїѧ, возложи́ша на главꙋ̀ є҆гѡ̀, и҆ тро́сть въ десни́цꙋ є҆гѡ̀: и҆ покло́ньшесѧ на колѣ̑нꙋ пред̾ ни́мъ, рꙋга́хꙋсѧ є҆мꙋ̀, глаго́люще: ра́дꙋйсѧ цр҃ю̀ і҆ꙋде́йскїй. и҆ плю́нꙋвше на́нь, прїѧ́ша тро́сть, и҆ бїѧ́хꙋ по главѣ̀ є҆гѡ̀. и҆ є҆гда̀ порꙋга́шасѧ є҆мꙋ̀, совлеко́ша съ негѡ̀ багрѧни́цꙋ: и҆ ѡ҆блеко́ша є҆го̀ въ ри̑зы є҆гѡ̀, и҆ ведо́ша є҆го̀ на пропѧ́тїе. и҆сходѧ́ще же ѡ҆брѣто́ша человѣ́ка кѷрине́йска, и҆́менемъ сі́мѡна: и҆ семꙋ̀ задѣ́ша понестѝ крⷭ҇тъ є҆гѡ̀. ",
}

add_evangelie_matfea {
