add_evangelie_matfea {
  ["номер"] = 113,
  ["комментарий"] = "Мф., 113 зач., XXVII, 33-54.",
  ["текст_ру"] = "Во вре́мя о́но, прише́дше во́ини на ме́сто нарица́емое Голго́фа, е́же есть Кра́ниево ме́сто, да́ша Иису́су пи́ти о́цет с же́лчию сме́шен, и вкуш, не хотя́ше пи́ти. Распе́ншии же Его́ раздели́ша ри́зы Его́, ве́ргше жре́бия, и седя́ще стрежа́ху Его́ ту, и возложи́ша верху́ главы́ Его́ вину́ Его́ напи́сану: Сей есть Иису́с, Царь Иуде́йский. Тогда́ распя́ша с Ним два разбо́йника: еди́наго одесну́ю, и еди́наго ошу́юю. Мимоходя́щии же ху́ляху Его́, покива́юще глава́ми свои́ми и глаго́люще: Разоря́яй це́рковь и треми́ де́ньми Созида́яй, спаси́ся Сам, а́ще Сын еси́ Бо́жий, сни́ди со креста́. Та́кожде же и архиере́е руга́ющеся с кни́жники и ста́рцы и фарисе́и, глаго́лаху: ины́я спасе́, Себе́ ли не мо́жет спасти́? А́ще Царь Изра́илев есть, да сни́дет ны́не со креста́, и ве́руем в Него́. Упова́ на Бо́га, да изба́вит ны́не Его́, а́ще хо́щет Ему́. Рече́ бо, я́ко Бо́жий есмь Сын. То́жде же и разбо́йника распя́тая с Ним поноша́ста Ему́. От шеста́го же часа́ тма бысть по всей земли́ до часа́ девя́таго. О девя́том же часе́ возопи́ Иису́с гла́сом ве́лиим, глаго́ля: Или́, Или́, лима́ савахфани́? Е́же есть, Бо́же Мой, Бо́же Мой, вску́ю Мя еси́ оста́вил? Не́цыи же от ту стоя́щих слы́шавше глаго́лаху, я́ко Илию́ глаша́ет Сей. И а́бие тек еди́н от них, и прие́м гу́бу, испо́лнив же о́цта, и вонзе́ на трость, напая́ше Его́. Про́чии же глаго́лаху: оста́ви, да ви́дим, а́ще прии́дет Илиа́ спасти́ Его́. Иису́с же, па́ки возопи́в гла́сом ве́лиим, испусти́ дух. И се заве́са церко́вная раздра́ся на дво́е с вы́шняго кра́я до ни́жняго, и земля́ потрясе́ся, и ка́мение распаде́ся, и гро́би отверзо́шася, и мно́га телеса́ усо́пших святы́х воста́ша, и изше́дше из гроб, по воскресе́нии Его́, внидо́ша во святы́й град и яви́шася мно́зем. Со́тник же и и́же с ним стрегу́щии Иису́са, ви́девше трус и бы́вшая, убоя́шася зело́, глаго́люще: вои́стинну Бо́жий Сын бе Сей. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прише́дше во́ини на мѣ́сто нарица́емое голго́ѳа, є҆́же є҆́сть кра́нїево мѣ́сто, да́ша і҆и҃сꙋ пи́ти ѻ҆́цетъ съ же́лчїю смѣ́шенъ, и҆ вкꙋ́шъ не хотѧ́ше пи́ти. распе́ншїи же є҆го̀ раздѣли́ша ри̑зы є҆гѡ̀, ве́ргше жрє́бїѧ: и҆ сѣдѧ́ще стрежа́хꙋ є҆го̀ тꙋ̀. и҆ возложи́ша верхꙋ̀ главы̀ є҆гѡ̀ винꙋ̀ є҆гѡ̀ напи́санꙋ: се́й є҆́сть і҆и҃съ цр҃ь і҆ꙋде́йскїй. тогда̀ распѧ́ша съ ни́мъ два̀ разбѡ́йника: є҆ди́наго ѡ҆деснꙋ́ю, и҆ є҆ди́наго ѡ҆шꙋ́юю. мимоходѧ́щїи же хꙋ́лѧхꙋ є҆го̀, покива́юще глава́ми свои́ми, и҆ глаго́люще: разорѧ́ѧй цр҃ковь, и҆ тремѝ де́ньми созида́ѧй, спаси́сѧ са́мъ: а҆́ще сн҃ъ є҆сѝ бж҃їй, сни́ди со крⷭ҇та̀. та́кожде же и҆ а҆рхїере́є рꙋга́ющесѧ съ кни́жники, и҆ ста́рцы, и҆ фарїсе́и, глаго́лахꙋ: и҆ны̑ѧ спасѐ, себе́ ли не мо́жетъ спастѝ; а҆́ще цр҃ь і҆и҃левъ є҆́сть, да сни́детъ ны́нѣ со крⷭ҇та̀, и҆ вѣ́рꙋемъ въ него̀: ᲂу҆пова̀ на бг҃а: да и҆зба́витъ ны́нѣ є҆го̀, а҆́ще хо́щетъ є҆мꙋ̀: рече́ бо, ꙗ҆́кѡ бж҃їй є҆́смь сн҃ъ. то́жде же и҆ разбѡ́йника распѧ́таѧ съ ни́мъ поноша́ста є҆мꙋ̀. ѿ шеста́гѡ же часа̀ тма̀ бы́сть по все́й землѝ, до часа̀ девѧ́тагѡ. ѡ҆ девѧ́томъ же часѣ̀ возопѝ і҆и҃съ гла́сомъ ве́лїимъ, глаго́лѧ: и҆лі̀, и҆лі̀, лїма̀ савахѳані̀; є҆́же є҆́сть, бж҃е мо́й, бж҃е мо́й, вскꙋ́ю мѧ̀ є҆сѝ ѡ҆ста́вилъ; нѣ́цыи же ѿ тꙋ̀ стоѧ́щихъ слы́шавше, глаго́лахꙋ: ꙗ҆́кѡ и҆лїю̀ глаша́етъ се́й. и҆ а҆́бїе те́къ є҆ди́нъ ѿ ни́хъ, и҆ прїе́мъ гꙋ́бꙋ, и҆спо́лнивъ же ѻ҆́цта, и҆ вонзѐ на тро́сть, напаѧ́ше є҆го̀. про́чїи же глаго́лахꙋ: ѡ҆ста́ви, да ви́димъ, а҆́ще прїи́детъ и҆лїа̀ спастѝ є҆го̀. і҆и҃съ же па́ки возопи́въ гла́сомъ ве́лїимъ, и҆спꙋстѝ дх҃ъ. и҆ сѐ завѣ́са цр҃ко́внаѧ раздра́сѧ на дво́е, съ вы́шнѧгѡ кра́ѧ до ни́жнѧгѡ: и҆ землѧ̀ потрѧсе́сѧ, и҆ ка́менїе распаде́сѧ: и҆ гро́би ѿверзо́шасѧ, и҆ мнѡ́га тѣлеса̀ ᲂу҆со́пшихъ ст҃ы́хъ воста́ша: и҆ и҆зше́дше и҆з̾ грѡ́бъ по воскресе́нїи є҆гѡ̀, внидо́ша во ст҃ы́й гра́дъ, и҆ ꙗ҆ви́шасѧ мнѡ́зѣмъ. со́тникъ же и҆ и҆̀же съ ни́мъ стрегꙋ́щїи і҆и҃са, ви́дѣвше трꙋ́съ и҆ бы̑вшаѧ, ᲂу҆боѧ́шасѧ ѕѣлѡ̀, глаго́люще: вои́стиннꙋ бж҃їй сн҃ъ бѣ̀ се́й. ",
}

add_evangelie_matfea {
  ["номер"] = 114,
  ["комментарий"] = "Мф., 114 зач., XXVII, 62–66.",
  ["текст_ру"] = "Во у́трий день, и́же есть по пятце́, собра́шася архиере́е и фарисе́е к Пила́ту, глаго́люще: го́споди, помяну́хом, я́ко льстец он рече́, еще́ сый жив, по трие́х днех воста́ну. Повели́ у́бо утверди́ти гроб до тре́тияго дне, да не ка́ко прише́дше ученицы́ Его́ но́щию укра́дут Его́ и реку́т лю́дем: воста́ от ме́ртвых, и бу́дет после́дняя лесть го́рша пе́рвыя. Рече́ же им Пила́т: и́мате кустоди́ю, иди́те, утверди́те, я́коже ве́сте. Они́ же ше́дше утверди́ша гроб, зна́менавше ка́мень с кустоди́ею. ",
  ["текст_цс"] = "Во ᲂу҆́трїй де́нь, и҆́же є҆́сть по пѧтцѣ̀, собра́шасѧ а҆рхїере́є и҆ фарїсе́є къ пїла́тꙋ: глаго́люще: го́споди, помѧнꙋ́хомъ, ꙗ҆́кѡ льсте́цъ ѻ҆́нъ речѐ є҆щѐ сы́й жи́въ: по трїе́хъ дне́хъ воста́нꙋ. повелѝ ᲂу҆̀бо ᲂу҆тверди́ти гро́бъ до тре́тїѧгѡ днѐ: да не ка́кѡ прише́дше ᲂу҆ченицы̀ є҆гѡ̀ но́щїю, ᲂу҆кра́дꙋтъ є҆го̀, и҆ рекꙋ́тъ лю́демъ: воста̀ ѿ ме́ртвыхъ, и҆ бꙋ́детъ послѣ́днѧѧ ле́сть го́рша пе́рвыѧ. рече́ же и҆̀мъ пїла́тъ: и҆́мате кꙋстѡді́ю, и҆ди́те, ᲂу҆тверди́те, ꙗ҆́коже вѣ́сте. ѻ҆ни́ же ше́дше ᲂу҆тверди́ша гро́бъ, зна́менавше ка́мень съ кꙋстѡді́ею. ",
}

add_evangelie_matfea {
  ["номер"] = 115,
  ["комментарий"] = "Мф., 115 зач., XXVIII, 1–20.",
  ["текст_ру"] = "В ве́чер суббо́тный, свита́ющи во еди́ну от суббо́т, прии́де Мари́а Магдали́на и друга́я Мари́а, ви́дети гроб. И се трус бысть ве́лий: А́нгел бо Госпо́день сшед с небесе́, присту́пль отвали́ ка́мень от две́рий гро́ба и седя́ше на нем. Бе же зрак его́ я́ко мо́лния, и одея́ние его́ бело́ я́ко снег. От стра́ха же его́ сотрясо́шася стрегу́щии и бы́ша я́ко ме́ртви. Отвеща́в же А́нгел рече́ жена́м: не бо́йтеся вы, вем бо, я́ко Иису́са распя́таго и́щете. Несть зде, воста́ бо, я́коже рече́, прииди́те, ви́дите ме́сто, иде́же лежа́ Госпо́дь, и ско́ро ше́дше рцы́те ученико́м Его́, я́ко воста́ от ме́ртвых и се варя́ет вы в Галиле́и, та́мо Его́ у́зрите, се рех вам. И изше́дше ско́ро от гро́ба со стра́хом и ра́достию ве́лиею, теко́сте возвести́ти ученико́м Его́. Я́коже идя́сте возвести́ти ученико́м Его́, и се Иису́с сре́те я́, глаго́ля: ра́дуйтеся. Оне́ же присту́пльше я́стеся за но́зе Его́ и поклони́стеся Ему́. Тогда́ глаго́ла и́ма Иису́с: не бо́йтеся, иди́те, возвести́те бра́тии Мое́й, да и́дут в Галиле́ю, и ту Мя ви́дят. Иду́щема же и́ма, се не́цыи от кусто́диа прише́дше во град, возвести́ша архиере́ом вся бы́вшая. И собра́вшеся со ста́рцы, сове́т сотвори́ша, сре́бреники дово́льны да́ша во́ином, глаго́люще: рцы́те, я́ко ученицы́ Его́ но́щию прише́дше украдо́ша Его́, нам спя́щым. И а́ще сие́ услы́шано бу́дет у иге́мона, мы утоли́м его́ и вас безпеча́льны сотвори́м. Они́ же прие́мше сре́бреники, сотвори́ша, я́коже науче́ни бы́ша. И промче́ся сло́во сие́ во иуде́ех да́же до сего́ дне. Еди́нии же на́десяте ученицы́ идо́ша в Галиле́ю, в гору́, а́може повеле́ им Иису́с, и ви́девше Его́, поклони́шася Ему́, о́ви же усумне́шася. И присту́пль Иису́с, рече́ им, глаго́ля: даде́ся Ми вся́ка власть на небеси́ и на земли́. Ше́дше у́бо научи́те вся язы́ки, крестя́ще их во и́мя Отца́ и Сы́на и Свята́го Ду́ха, уча́ще их блюсти́ вся, ели́ка запове́дах вам, и се Аз с ва́ми есмь во вся дни до сконча́ния ве́ка. Ами́нь. ",
  ["текст_цс"] = "Въ ве́черъ сꙋббѡ́тный, свита́ющи во є҆ди́нꙋ ѿ сꙋббѡ́тъ, прїи́де марі́а магдали́на, и҆ дрꙋга́ѧ марі́а, ви́дѣти гро́бъ. и҆ сѐ трꙋ́съ бы́сть ве́лїй: а҆́гг҃лъ бо гдⷭ҇нь сше́дъ съ небесѐ, пристꙋ́пль ѿвалѝ ка́мень ѿ две́рїй гро́ба, и҆ сѣдѧ́ше на не́мъ. бѣ́ же зра́къ є҆гѡ̀ ꙗ҆́кѡ мо́лнїѧ, и҆ ѡ҆дѣѧ́нїе є҆гѡ̀ бѣло̀ ꙗ҆́кѡ снѣ́гъ. ѿ стра́ха же є҆гѡ̀ сотрѧсо́шасѧ стрегꙋ́щїи, и҆ бы́ша ꙗ҆́кѡ ме́ртви. ѿвѣща́въ же а҆́гг҃лъ речѐ жена́мъ: не бо́йтесѧ вы̀, вѣ́мъ бо ꙗ҆́кѡ і҆и҃са распѧ́таго и҆́щете. нѣ́сть здѣ̀, воста́ бо, ꙗ҆́коже речѐ: прїиди́те, ви́дите мѣ́сто, и҆дѣ́же лежа̀ гдⷭ҇ь. и҆ ско́рѡ ше́дше рцы́те ᲂу҆ченикѡ́мъ є҆гѡ̀, ꙗ҆́кѡ воста̀ ѿ ме́ртвыхъ. и҆ сѐ варѧ́етъ вы̀ въ галїле́и: та́мѡ є҆го̀ ᲂу҆́зрите. сѐ рѣ́хъ ва́мъ. и҆ и҆зше́дше ско́рѡ ѿ гро́ба, со стра́хомъ и҆ ра́достїю ве́лїею теко́стѣ возвѣсти́ти ᲂу҆ченикѡ́мъ є҆гѡ̀. ꙗ҆́коже и҆дѧ́стѣ возвѣсти́ти ᲂу҆ченикѡ́мъ є҆гѡ̀, и҆ сѐ і҆и҃съ срѣ́те ѧ҆̀, глаго́лѧ: ра́дꙋйтесѧ. ѻ҆нѣ́ же пристꙋ́пльше, ꙗ҆́стѣсѧ за нѡ́зѣ є҆гѡ̀, и҆ поклони́стѣсѧ є҆мꙋ̀. тогда̀ глаго́ла и҆́ма і҆и҃съ: не бо́йтесѧ, и҆ди́те, возвѣсти́те бра́тїи мое́й, да и҆́дꙋтъ въ галїле́ю, и҆ тꙋ̀ мѧ̀ ви́дѧтъ. и҆дꙋ́щема же и҆́ма, сѐ нѣ́цыи ѿ кꙋстѡ́дїа прише́дше во гра́дъ, возвѣсти́ша а҆рхїере́ѡмъ всѧ̀ бы̑вшаѧ. и҆ собра́вшесѧ со ста́рцы совѣ́тъ сотвори́ша, сре́бреники дово́льны да́ша во́инѡмъ, глаго́люще: рцы́те, ꙗ҆́кѡ ᲂу҆ченицы̀ є҆гѡ̀ но́щїю прише́дше ᲂу҆крадо́ша є҆го̀, на́мъ спѧ́щымъ. и҆ а҆́ще сїѐ ᲂу҆слы́шано бꙋ́детъ ᲂу҆ и҆ге́мѡна, мы̀ ᲂу҆толи́мъ є҆го̀, и҆ ва́съ безпеча́льны сотвори́мъ. ѻ҆ни́ же прїе́мше сре́бреники, сотвори́ша, ꙗ҆́коже наꙋче́ни бы́ша: и҆ промче́сѧ сло́во сїѐ во і҆ꙋде́ехъ, да́же до сегѡ̀ днѐ. є҆ди́нїи же на́десѧте ᲂу҆ченицы̀ и҆до́ша въ галїле́ю, въ го́рꙋ, а҆́може повелѣ̀ и҆̀мъ і҆и҃съ: и҆ ви́дѣвше є҆го̀ поклони́шасѧ є҆мꙋ̀: ѻ҆́ви же ᲂу҆сꙋмнѣ́шасѧ. и҆ пристꙋ́пль і҆и҃съ речѐ и҆̀мъ, глаго́лѧ: даде́сѧ мѝ всѧ́ка вла́сть на нб҃сѝ и҆ на землѝ. ше́дше ᲂу҆́бѡ наꙋчи́те всѧ̀ ꙗ҆зы́ки, крестѧ́ще и҆̀хъ во и҆́мѧ ѻ҆ц҃а̀, и҆ сн҃а, и҆ ст҃а́гѡ дх҃а: ᲂу҆ча́ще и҆̀хъ блюстѝ всѧ̑, є҆ли̑ка заповѣ́дахъ ва́мъ. и҆ сѐ а҆́зъ съ ва́ми є҆́смь во всѧ̀ днѝ, до сконча́нїѧ вѣ́ка, а҆ми́нь. ",
}

add_evangelie_matfea {
  ["номер"] = 116,
  ["комментарий"] = "Мф., 116 зач., XXVIII, 16–20.",
  ["текст_ру"] = "Во вре́мя о́но, единиина́десять ученицы́ идо́ша в Галиле́ю, в гору́, а́може повеле́ им Иису́с, и ви́девше Его́, поклони́шася Ему́, о́ви же усумне́шася. И присту́пль Иису́с, рече́ им, глаго́ля: даде́ся Ми вся́ка власть на небеси́ и на земли́. Ше́дше у́бо научи́те вся язы́ки, крестя́ще их во и́мя Отца́ и Сы́на и Свята́го Ду́ха, уча́ще их блюсти́ вся, ели́ка запове́дах вам, и се Аз с ва́ми есмь во вся дни до сконча́ния ве́ка. Ами́нь. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, є҆динїина́десѧть ᲂу҆ченицы̀ и҆до́ша въ галїле́ю, въ го́рꙋ, а҆́може повелѣ̀ и҆̀мъ і҆и҃съ: и҆ ви́дѣвше є҆го̀ поклони́шасѧ є҆мꙋ̀: ѻ҆́ви же ᲂу҆сꙋмнѣ́шасѧ. и҆ пристꙋ́пль і҆и҃съ речѐ и҆̀мъ, глаго́лѧ: даде́сѧ мѝ всѧ́ка вла́сть на нб҃сѝ и҆ на землѝ. ше́дше ᲂу҆́бѡ наꙋчи́те всѧ̀ ꙗ҆зы́ки, крестѧ́ще и҆̀хъ во и҆́мѧ ѻ҆ц҃а̀, и҆ сн҃а, и҆ ст҃а́гѡ дх҃а: ᲂу҆ча́ще и҆̀хъ блюстѝ всѧ̑, є҆ли̑ка заповѣ́дахъ ва́мъ. и҆ сѐ а҆́зъ съ ва́ми є҆́смь во всѧ̀ днѝ, до сконча́нїѧ вѣ́ка, а҆ми́нь. ",
}

add_evangelie_marka {
  ["номер"] = 1,
  ["комментарий"] = "Мк., 1 зач., I, 1–8.",
  ["текст_ру"] = "Зача́ло Ева́нгелия Иису́са Христа́, Сы́на Бо́жия, я́коже есть пи́сано во проро́цех: се Аз посыла́ю А́нгела Моего́ пред лице́м Твои́м, и́же угото́вит путь Твой пред Тобо́ю. Глас вопию́щаго в пусты́ни: угото́вайте путь Госпо́день, пра́вы твори́те стези́ Его́. Бысть Иоа́нн, крестя́й в пусты́ни, и пропове́дая креще́ние покая́ния во отпуще́ние грехо́в. И исхожда́ше к нему́ вся Иуде́йская страна́ и иерусали́мляне, и креща́хуся вси во Иорда́не реце́ от него́, испове́дающе грехи́ своя́. Бе же Иоа́нн оболче́н власы́ вельблу́жди, и по́яс усме́н о чресле́х его́, и яды́й акри́ды, и мед ди́вий. И пропове́даше, глаго́ля: гряде́т Кре́плий мене́, во след мене́, Ему́же несмь досто́ин, прекло́нься, разреши́ти реме́нь сапо́г Его́. Аз у́бо крести́х вы в воде́, Той же крести́т вы Ду́хом Святы́м. ",
  ["текст_цс"] = "Зача́ло є҆ѵⷢ҇лїа і҆и҃са хрⷭ҇та̀ сн҃а бж҃їѧ. ꙗ҆́коже є҆́сть пи́сано во проро́цѣхъ: сѐ а҆́зъ посыла́ю а҆́гг҃ла моего̀ пред̾ лице́мъ твои́мъ, и҆́же ᲂу҆гото́витъ пꙋ́ть тво́й пред̾ тобо́ю. гла́съ вопїю́щагѡ въ пꙋсты́ни: ᲂу҆гото́вайте пꙋ́ть гдⷭ҇нь, пра́вы твори́те стєзѝ є҆гѡ̀. бы́сть і҆ѡа́ннъ крестѧ́й въ пꙋсты́ни, и҆ проповѣ́даѧ креще́нїе покаѧ́нїѧ, во ѿпꙋще́нїе грѣхѡ́въ. и҆ и҆схожда́ше къ немꙋ̀ всѧ̀ і҆ꙋде́йскаѧ страна̀, и҆ і҆ерꙋсали́млѧне, и҆ креща́хꙋсѧ всѝ во і҆ѻрда́нѣ рѣцѣ̀ ѿ негѡ̀, и҆сповѣ́дающе грѣхѝ своѧ̀. бѣ́ же і҆ѡа́ннъ ѡ҆болче́нъ власы̀ вельблꙋ́жди, и҆ по́ѧсъ ᲂу҆сме́нъ ѡ҆ чреслѣ́хъ є҆гѡ̀: и҆ ꙗ҆ды́й а҆крі́ды и҆ ме́дъ ди́вїй. и҆ проповѣ́даше глаго́лѧ: грѧде́тъ крѣ́плїй менѐ во слѣ́дъ менѐ, є҆мꙋ́же нѣ́смь досто́инъ, прекло́ньсѧ, разрѣши́ти реме́нь сапѡ́гъ є҆гѡ̀. а҆́зъ ᲂу҆́бѡ крести́хъ вы̀ въ водѣ̀: то́й же крести́тъ вы̀ дх҃омъ ст҃ы́мъ. ",
}

add_evangelie_marka {
  ["номер"] = 2,
  ["комментарий"] = "Мк., 2 зач., I, 9–15.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с от Назаре́та Галиле́йскаго и крести́ся от Иоа́нна во Иорда́не. И а́бие восходя́ от воды́, ви́де разводя́щася Небеса́ и Дух, я́ко го́лубь, сходя́щ Нань. И глас бысть с Небесе́: Ты еси́ Сын Мой возлю́бленный, о Не́мже благоволи́х. И а́бие Дух изведе́ Его́ в пусты́ню. И бе ту в пусты́ни дней четы́редесять, искуша́емь сатано́ю, и бе со зверьми́, и А́нгели служа́ху Ему́. По преда́нии же Иоа́ннове, прии́де Иису́с в Галиле́ю, пропове́дая Ева́нгелие Ца́рствия Бо́жия и глаго́ля: я́ко испо́лнися вре́мя и прибли́жися Ца́рствие Бо́жие. Пока́йтеся и ве́руйте во Ева́нгелие. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но прїи́де і҆и҃съ ѿ назаре́та галїле́йскагѡ, и҆ крести́сѧ ѿ і҆ѡа́нна во і҆ѻрда́нѣ. и҆ а҆́бїе восходѧ̀ ѿ воды̀, ви́дѣ разводѧ́щасѧ нб҃са̀, и҆ дх҃ъ ꙗ҆́кѡ го́лꙋбь, сходѧ́щъ на́нь. и҆ гла́съ бы́сть съ нб҃сѐ: ты̀ є҆сѝ сн҃ъ мо́й возлю́бленный, ѡ҆ не́мже бл҃говоли́хъ. и҆ а҆́бїе дх҃ъ и҆зведѐ є҆го̀ въ пꙋсты́ню. и҆ бѣ̀ тꙋ̀ въ пꙋсты́ни дне́й четы́редесѧть, и҆скꙋша́емь сатано́ю, и҆ бѣ̀ со ѕвѣрьмѝ: и҆ а҆́гг҃ли слꙋжа́хꙋ є҆мꙋ̀. по преда́нїи же і҆ѡа́нновѣ, прїи́де і҆и҃съ въ галїле́ю, проповѣ́даѧ є҆ѵⷢ҇лїе црⷭ҇твїѧ бж҃їѧ, и҆ глаго́лѧ: ꙗ҆́кѡ и҆спо́лнисѧ вре́мѧ, и҆ прибли́жисѧ црⷭ҇твїе бж҃їе: пока́йтесѧ и҆ вѣ́рꙋйте во є҆ѵⷢ҇лїе. ",
}

add_evangelie_marka {
