add_evangelie_marka {
  ["номер"] = 3,
  ["комментарий"] = "Мк., 3 зач., I, 16–22.",
  ["текст_ру"] = "Во вре́мя о́но, ходя́ Иису́с при мо́ри Галиле́йстем, ви́де Си́мона и Андре́а бра́та того́ Си́мона, вмета́юща мре́жи в мо́ре, бе́ста бо рыбаря́. И рече́ и́ма Иису́с: прииди́та в след Мене́, и сотворю́ вас бы́ти ловца́ челове́ком. И а́бие оста́вльша мре́жи своя́, по Нем идо́ста. И преше́д ма́ло отту́ду, узре́ Иа́кова Зеведе́ова и Иоа́нна бра́та его́, и та в корабли́ стро́яща мре́жа, и а́бие воззва́ я́. И оста́вльша отца́ своего́ Зеведе́а в корабли́ с нае́мники, по Нем идо́ста. И внидо́ша в Капернау́м, и а́бие в суббо́ты вшед в со́нмище, уча́ше. И дивля́хуся о уче́нии Его́, бе бо учя́ их я́ко власть имы́й, и не я́ко кни́жницы. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ходѧ̀ і҆и҃съ при мо́ри галїле́йстѣмъ, ви́дѣ сі́мѡна и҆ а҆ндре́а бра́та тогѡ̀ сі́мѡна, вмета́юща мрє́жи въ мо́ре, бѣ́ста бо рыбарѧ̑: и҆ речѐ и҆́ма і҆и҃съ: прїиди́та во слѣ́дъ менѐ, и҆ сотворю̀ ва́съ бы́ти ловца̑ человѣ́кѡмъ. и҆ а҆́бїе ѡ҆ста́вльша мрє́жи своѧ̀, по не́мъ и҆до́ста. и҆ преше́дъ ма́лѡ ѿтꙋ́дꙋ, ᲂу҆зрѣ̀ і҆а́кѡва зеведе́ова, и҆ і҆ѡа́нна бра́та є҆гѡ̀, и҆ та̀ въ кораблѝ стро́ѧща мрє́жа. и҆ а҆́бїе воззва̀ ѧ҆̀: и҆ ѡ҆ста́вльша ѻ҆тца̀ своего̀ зеведе́а въ кораблѝ съ нае́мники, по не́мъ и҆до́ста. и҆ внидо́ша въ капернаꙋ́мъ: и҆ а҆́бїе въ сꙋббѡ́ты вше́дъ въ со́нмище, ᲂу҆ча́ше. и҆ дивлѧ́хꙋсѧ ѡ҆ ᲂу҆че́нїи є҆гѡ̀: бѣ́ бо ᲂу҆чѧ̀ и҆̀хъ ꙗ҆́кѡ вла́сть и҆мы́й, и҆ не ꙗ҆́кѡ кни́жницы. ",
}

add_evangelie_marka {
  ["номер"] = 4,
  ["комментарий"] = "Мк., 4 зач., I, 23–28.",
  ["текст_ру"] = "Во вре́мя о́но, челове́к не́кий бе в со́нмищи иуде́йсте в ду́се нечи́сте, и воззва́, глаго́ля: оста́ви, что нам и Тебе́, Иису́се Назоряни́не? Прише́л еси́ погуби́ти нас, вем Тя, кто еси́, Святы́й Бо́жий. И запрети́ ему́ Иису́с, глаго́ля: умолчи́ и изы́ди из него́. И стрясе́ его́ дух нечи́стый, и возопи́ гла́сом вели́ким, и изы́де из него́. И ужасо́шася вси, я́коже стяза́тися им к себе́, глаго́лющым: что есть сие́? И что уче́ние но́вое сие́, я́ко по о́бласти и духово́м нечи́стым вели́т, и послу́шают Его́? Изы́де же слух Его́ а́бие во всю страну́ Галиле́йску. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, человѣ́къ нѣ́кїй бѣ̀ въ со́нмищи і҆ꙋде́йстѣ въ дꙋ́сѣ нечи́стѣ, и҆ воззва̀, глаго́лѧ: ѡ҆ста́ви, что̀ на́мъ и҆ тебѣ̀, і҆и҃се назѡрѧни́не; прише́лъ є҆сѝ погꙋби́ти на́съ; вѣ́мъ тѧ̀, кто̀ є҆сѝ, ст҃ы́й бж҃їй. и҆ запретѝ є҆мꙋ̀ і҆и҃съ, глаго́лѧ: ᲂу҆молчѝ, и҆ и҆зы́ди и҆з̾ негѡ̀. и҆ стрѧсѐ є҆го̀ дꙋ́хъ нечи́стый, и҆ возопѝ гла́сомъ вели́кимъ, и҆ и҆зы́де и҆з̾ негѡ̀. и҆ ᲂу҆жасо́шасѧ всѝ, ꙗ҆́коже стѧза́тисѧ и҆̀мъ къ себѣ̀, глаго́лющымъ: что́ є҆сть сїѐ; и҆ что̀ ᲂу҆че́нїе но́вое сїѐ, ꙗ҆́кѡ по ѻ҆́бласти и҆ дꙋховѡ́мъ нечи́стымъ вели́тъ, и҆ послꙋ́шаютъ є҆гѡ̀; и҆зы́де же слꙋ́хъ є҆гѡ̀ а҆́бїе во всю̀ странꙋ̀ галїле́йскꙋ. ",
}

add_evangelie_marka {
  ["номер"] = 5,
  ["комментарий"] = "Мк., 5 зач., I, 29-35.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с в дом Си́монов и Андре́ов со Иа́ковом и Иоа́нном. Те́ща же Си́монова лежа́ше огне́м жего́ма, и а́бие глаго́лаша Ему́ о ней. И присту́пль воздви́же ю́, ем за ру́ку ея́, и оста́ви ю́ огнь а́бие, и служа́ше им. По́зде же бы́вшу, егда́ захожда́ше со́лнце, приноша́ху к Нему́ вся неду́жныя и бесны́я. И бе весь град собра́лся к две́рем. И исцели́ мно́ги зле стра́ждущыя разли́чными неду́ги, и бе́сы мно́ги изгна́, и не оставля́ше глаго́лати бе́сы, я́ко ве́дяху Его́ Христа́ су́ща. И у́тро, но́щи су́щи зело́, воста́в изы́де, и и́де в пу́сто ме́сто, и ту моли́тву де́яше. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ въ до́мъ сі́мѡновъ и҆ а҆ндре́овъ со і҆а́кѡвомъ и҆ і҆ѡа́нномъ. те́ща же сі́мѡнова лежа́ше, ѻ҆гне́мъ жего́ма: и҆ а҆́бїе глаго́лаша є҆мꙋ̀ ѡ҆ не́й. и҆ пристꙋ́пль воздви́же ю҆̀, є҆́мъ за рꙋ́кꙋ є҆ѧ̀: и҆ ѡ҆ста́ви ю҆̀ ѻ҆́гнь а҆́бїе, и҆ слꙋжа́ше и҆̀мъ. по́здѣ же бы́вшꙋ, є҆гда̀ захожда́ше со́лнце, приноша́хꙋ къ немꙋ̀ всѧ̀ недꙋ̑жныѧ, и҆ бѣсны̑ѧ. и҆ бѣ̀ ве́сь гра́дъ собра́лсѧ къ две́ремъ. и҆ и҆сцѣлѝ мнѡ́ги ѕлѣ̀ стра́ждꙋщыѧ разли́чными недꙋ́ги: и҆ бѣ́сы мнѡ́ги и҆згна̀, и҆ не ѡ҆ставлѧ́ше глаго́лати бѣ́сы, ꙗ҆́кѡ вѣ́дѧхꙋ є҆го̀ хрⷭ҇та̀ сꙋ́ща. и҆ ᲂу҆́трѡ но́щи сꙋ́щи ѕѣлѡ̀, воста́въ и҆зы́де, и҆ и҆́де въ пꙋ́сто мѣ́сто, и҆ тꙋ̀ моли́твꙋ дѣ́ѧше. ",
}

add_evangelie_marka {
  ["номер"] = 6,
  ["комментарий"] = "Мк., 6 зач., I, 35–44.",
  ["текст_ру"] = "Во вре́мя о́но, и́де Иису́с в пу́сто ме́сто, и ту моли́тву де́яше. И гна́ша Его́ Си́мон и и́же с ним, и обре́тше Его́, глаго́лаша Ему́, я́ко вси Тебе́ и́щут. И глаго́ла им: и́дем в бли́жния ве́си и гра́ды, да и ту пропове́м, на сие́ бо изыдо́х. И бе пропове́дая на со́нмищах их, во всей Галиле́и, и бе́сы изгоня́. И прии́де к Нему́ прокаже́н, моля́ Его́ и на коле́ну припа́дая пред Ним, и глаго́ля Ему́, я́ко, а́ще хо́щеши, мо́жеши мя очи́стити. Иису́с же милосе́рдовав, просте́р ру́ку, косну́ его́, и глаго́ла ему́: хощу́, очи́стися. И ре́кшу ему́, а́бие оты́де от него́ прокаже́ние, и чист бысть. И запре́щь ему́, а́бие изгна́ его́, и глаго́ла ему́: блюди́, никому́же ничесо́же рцы, но шед покажи́ся иере́еви и принеси́ за очище́ние твое́, я́же повеле́ Моисе́й, во свиде́тельство им. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆́де і҆и҃съ въ пꙋ́сто мѣ́сто, и҆ тꙋ̀ моли́твꙋ дѣ́ѧше. и҆ гна́ша є҆го̀ сі́мѡнъ и҆ и҆̀же съ ни́мъ, и҆ ѡ҆брѣ́тше є҆го̀, глаго́лаша є҆мꙋ̀: ꙗ҆́кѡ всѝ тебѐ и҆́щꙋтъ. и҆ глаго́ла и҆̀мъ: и҆́демъ въ бли́жнїѧ вє́си и҆ гра́ды, да и҆ тꙋ̀ проповѣ́мъ: на сїе́ бо и҆зыдо́хъ. и҆ бѣ̀ проповѣ́даѧ на со́нмищахъ и҆́хъ, во все́й галїле́и: и҆ бѣ́сы и҆згонѧ̀. и҆ прїи́де къ немꙋ̀ прокаже́нъ, молѧ̀ є҆го̀, и҆ на колѣ́нꙋ припа́даѧ пред̾ ни́мъ, и҆ глаго́лѧ є҆мꙋ̀: ꙗ҆́кѡ а҆́ще хо́щеши, мо́жеши мѧ̀ ѡ҆чи́стити. і҆и҃съ же милосе́рдовавъ, просте́ръ рꙋ́кꙋ, коснꙋ̀ є҆гѡ̀, и҆ глаго́ла є҆мꙋ̀: хощꙋ̀, ѡ҆чи́стисѧ. и҆ ре́кшꙋ є҆мꙋ̀, а҆́бїе ѿи́де ѿ негѡ̀ прокаже́нїе, и҆ чи́стъ бы́сть. и҆ запре́щъ є҆мꙋ̀, а҆́бїе и҆згна̀ є҆го̀. и҆ глаго́ла є҆мꙋ̀: блюдѝ, никомꙋ́же ничесо́же рцы̀: но ше́дъ покажи́сѧ і҆ере́еви, и҆ принесѝ за ѡ҆чище́нїе твоѐ, ꙗ҆̀же повелѣ̀ мѡѷсе́й, во свидѣ́тельство и҆̀мъ. ",
}

add_evangelie_marka {
  ["номер"] = 7,
  ["комментарий"] = "Мк., 7 зач., II, 1–12.",
  ["текст_ру"] = "Во вре́мя о́но, вни́де Иису́с в Капернау́м по днех, и слы́шано бысть, я́ко в дому́ есть. И а́бие собра́шася мно́зи, я́коже ктому́ не вмеща́тися ни при две́рех, и глаго́лаше им сло́во. И приидо́ша к Нему́ нося́ще разсла́бленна жи́лами, носи́ма четы́рми, и не могу́щым прибли́житися к Нему́ наро́да ра́ди, откры́ша покро́в, иде́же бе, и прокопа́вше све́сиша одр, на не́мже разсла́бленный лежа́ше. Ви́дев же Иису́с ве́ру их, глаго́ла разсла́бленному: ча́до, отпуща́ются тебе́ греси́ твои́. Бя́ху же не́цыи от кни́жник ту седя́ще и помышля́юще в сердца́х свои́х: что Сей та́ко глаго́лет хулы́? Кто мо́жет оставля́ти грехи́, то́кмо еди́н Бог? И а́бие разуме́в Иису́с ду́хом Свои́м, я́ко та́ко ти́и помышля́ют в себе́, рече́ им: что сия́ помышля́ете в сердца́х ва́ших? Что есть удо́бее? Рещи́ разсла́бленному: отпуща́ются тебе́ греси́? Или́ рещи́: воста́ни, и возми́ одр твой, и ходи́? Но да уве́сте, я́ко власть и́мать Сын Челове́ческий на земли́ отпуща́ти грехи́, глаго́ла разсла́бленному: тебе́ глаго́лю, воста́ни, и возми́ одр твой, и иди́ в дом твой. И воста́ а́бие, и взем одр, изы́де пред все́ми, я́ко диви́тися всем и сла́вити Бо́га, глаго́лющым, я́ко николи́же та́ко ви́дехом. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, вни́де і҆и҃съ въ капернаꙋ́мъ по дне́хъ, и҆ слы́шано бы́сть, ꙗ҆́кѡ въ домꙋ̀ є҆́сть. и҆ а҆́бїе собра́шасѧ мно́зи, ꙗ҆́коже ктомꙋ̀ не вмѣща́тисѧ ни при две́рехъ: и҆ глаго́лаше и҆̀мъ сло́во. и҆ прїидо́ша къ немꙋ̀, носѧ́ще разсла́бленна жи́лами, носи́ма четы́рми. и҆ не могꙋ́щымъ прибли́житисѧ къ немꙋ̀ наро́да ра́ди, ѿкры́ша покро́въ и҆дѣ́же бѣ̀: и҆ прокопа́вше свѣ́сиша ѻ҆́дръ, на не́мже разсла́бленный лежа́ше. ви́дѣвъ же і҆и҃съ вѣ́рꙋ и҆́хъ, глаго́ла разсла́бленномꙋ: ча́до, ѿпꙋща́ютсѧ тебѣ̀ грѣсѝ твоѝ. бѧ́хꙋ же нѣ́цыи ѿ кни̑жникъ тꙋ̀ сѣдѧ́ще, и҆ помышлѧ́юще въ сердца́хъ свои́хъ: что̀ се́й та́кѡ глаго́летъ хꙋлы̑; кто̀ мо́жетъ ѡ҆ставлѧ́ти грѣхѝ, то́кмѡ є҆ди́нъ бг҃ъ; и҆ а҆́бїе разꙋмѣ́въ і҆и҃съ дх҃омъ свои́мъ, ꙗ҆́кѡ та́кѡ ті́и помышлѧ́ютъ въ себѣ̀, речѐ и҆̀мъ: что̀ сїѧ̑ помышлѧ́ете въ сердца́хъ ва́шихъ; что̀ є҆́сть ᲂу҆до́бѣе рещѝ разсла́бленномꙋ: ѿпꙋща́ютсѧ тебѣ̀ грѣсѝ; и҆лѝ рещѝ: воста́ни, и҆ воз̾мѝ ѻ҆́дръ тво́й и҆ ходѝ; но да ᲂу҆вѣ́сте, ꙗ҆́кѡ вла́сть и҆́мать сн҃ъ человѣ́ческїй на землѝ ѿпꙋща́ти грѣхѝ, глаго́ла разсла́бленномꙋ: тебѣ̀ глаго́лю, воста́ни, и҆ воз̾мѝ ѻ҆́дръ тво́й, и҆ и҆дѝ въ до́мъ тво́й. и҆ воста̀ а҆́бїе, и҆ взе́мъ ѻ҆́дръ и҆зы́де пред̾ всѣ́ми, ꙗ҆́кѡ диви́тисѧ всѣ̑мъ, и҆ сла́вити бг҃а, глаго́лющымъ: ꙗ҆́кѡ николи́же та́кѡ ви́дѣхомъ. ",
}

add_evangelie_marka {
  ["номер"] = 8,
  ["комментарий"] = "Мк., 8 зач., II, 14–17.",
  ["текст_ру"] = "Во вре́мя о́но, мимогряды́й Иису́с ви́де Леви́ю Алфе́ова, седя́ща на мы́тнице, и глаго́ла ему́: по Мне гряди́. И воста́в в след Его́ и́де. И бысть возлежа́щу Ему́ в дому́ его́, и мно́зи мытари́ и гре́шницы возлежа́ху со Иису́сом и со ученики́ Его́, бя́ху бо мно́зи, и по Нем идо́ша. И кни́жницы и фарисе́е, ви́девше Его́ яду́ща с мытари́ и гре́шники, глаго́лаху ученико́м Его́: что я́ко с мытари́ и гре́шники яст и пие́т? И слы́шав Иису́с глаго́ла им: не тре́буют здра́вии врача́, но боля́щии, не приидо́х призва́ти пра́ведники, но гре́шники на покая́ние. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, мимогрѧды́й і҆и҃съ ви́дѣ леѵі́ю а҆лфе́ова, сѣдѧ́ща на мы́тницѣ, и҆ глаго́ла є҆мꙋ̀: по мнѣ̀ грѧдѝ. и҆ воста́въ въ слѣ́дъ є҆гѡ̀ и҆́де. и҆ бы́сть возлежа́щꙋ є҆мꙋ̀ въ домꙋ̀ є҆гѡ̀, и҆ мно́зи мытарѝ и҆ грѣ́шницы возлежа́хꙋ со і҆и҃сомъ, и҆ со ᲂу҆ченикѝ є҆гѡ̀: бѧ́хꙋ бо мно́зи, и҆ по не́мъ и҆до́ша. и҆ кни́жницы и҆ фарїсе́є, ви́дѣвше є҆го̀ ꙗ҆дꙋ́ща съ мытарѝ и҆ грѣ́шники, глаго́лахꙋ ᲂу҆ченикѡ́мъ є҆гѡ̀: что̀ ꙗ҆́кѡ съ мытарѝ и҆ грѣ́шники ꙗ҆́стъ и҆ пїе́тъ; и҆ слы́шавъ і҆и҃съ глаго́ла и҆̀мъ: не тре́бꙋютъ здра́вїи врача̀, но болѧ́щїи: не прїидо́хъ призва́ти пра́ведники, но грѣ́шники на покаѧ́нїе. ",
}

add_evangelie_marka {
  ["номер"] = 9,
  ["комментарий"] = "Мк., 9 зач., II, 18–22.",
  ["текст_ру"] = "Во вре́мя о́но, бя́ху ученицы́ Иоа́нновы и фарисе́йстии постя́щеся, и приидо́ша и глаго́лаша Иису́су: почто́ ученицы́ Иоа́нновы и фарисе́йстии постя́тся, а Твои́ ученицы́ не постя́тся? И рече́ им Иису́с: еда́ мо́гут сы́нове бра́чнии, до́ндеже жени́х с ни́ми есть, пости́тися? Ели́ко вре́мя с собо́ю и́мут жениха́, не мо́гут пости́тися. Прии́дут же дни́е, егда́ оти́мется от них жени́х, и тогда́ постя́тся в ты́я дни. И никто́же приложе́ния пла́та небе́лена пришива́ет к ри́зе ве́тсе а́ще ли же ни, во́змет коне́ц его́ но́вое от ве́тхаго, и го́рши дира́ бу́дет. И никто́же влива́ет вина́ но́ва в ме́хи ве́тхи, а́ще ли же ни, просади́т вино́ но́вое ме́хи, и вино́ пролие́тся, и ме́си поги́бнут, но вино́ но́вое в ме́хи но́вы влия́ти подоба́ет. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бѧ́хꙋ ᲂу҆чн҃цы̀ і҆ѡа́нновы и҆ фарїсе́йстїи постѧ́щесѧ, и҆ прїидо́ша и҆ глаго́лаша і҆и҃сꙋ почто̀ ᲂу҆ченицы̀ і҆ѡа́нновы и҆ фарїсе́йстїи постѧ́тсѧ, а҆ твоѝ ᲂу҆ченицы̀ не постѧ́тсѧ; и҆ речѐ и҆̀мъ і҆и҃съ: є҆да̀ мо́гꙋтъ сы́нове бра́чнїи, до́ндеже жени́хъ съ ни́ми є҆́сть, пости́тисѧ; є҆ли́ко вре́мѧ съ собо́ю и҆́мꙋтъ жениха̀, не мо́гꙋтъ пости́тисѧ. прїи́дꙋтъ же дні́е, є҆гда̀ ѿи́метсѧ ѿ ни́хъ жени́хъ, и҆ тогда̀ постѧ́тсѧ въ ты́ѧ днѝ. и҆ никто́же приложе́нїѧ пла́та небѣ́лена пришива́етъ къ ри́зѣ ве́тсѣ: а҆́ще ли же нѝ, во́з̾метъ коне́цъ є҆гѡ̀ но́вое ѿ ве́тхагѡ, и҆ го́рши дира̀ бꙋ́детъ. и҆ никто́же влива́етъ вїна̀ но́ва въ мѣ́хи ве́тхи: а҆́ще ли же нѝ, просади́тъ вїно̀ но́вое мѣ́хи, и҆ вїно̀ пролїе́тсѧ, и҆ мѣ́си поги́бнꙋтъ: но вїно̀ но́вое въ мѣ́хи но́вы влїѧ́ти подоба́етъ. ",
}

add_evangelie_marka {
  ["номер"] = 10,
  ["комментарий"] = "Мк., 10 зач., II, 23 – III, 5.",
  ["текст_ру"] = "Во вре́мя о́но, идя́ше Иису́с в суббо́ты сквозе́ се́яния, и нача́ша ученицы́ Его́ путь твори́ти, востерза́юще кла́сы. И фарисе́е глаго́лаху Ему́: виждь, что творя́т в суббо́ты, его́же не досто́ит? И Той глаго́лаше им: не́сте ли николи́же чли, что сотвори́ Дави́д, егда́ тре́бование име́ и взалка́ сам и и́же с ним? Ка́ко вни́де в дом Бо́жий при Авиафа́ре архиере́и, и хле́бы предложе́ния снеде́, и́хже не досто́яше я́сти то́кмо иере́ем, и даде́ и су́щым с ним? И глаго́лаше им: суббо́та челове́ка ра́ди бысть, а не челове́к суббо́ты ра́ди, те́мже госпо́дь есть Сын Челове́ческий и суббо́те. И вни́де па́ки в со́нмище, и бе та́мо челове́к, су́ху имы́й ру́ку. И назира́ху Его́, а́ще в суббо́ты исцели́т его́, да Нань возглаго́лют. И глаго́ла челове́ку су́ху иму́щему ру́ку: ста́ни посреде́. И глаго́ла им: досто́ит ли в суббо́ты добро́ твори́ти, или́ зло твори́ти? Ду́шу спасти́, или́ погуби́ти? Они́ же молча́ху. И воззре́в на них со гне́вом, скорбя́ о окамене́нии серде́ц их, глаго́ла челове́ку: простри́ ру́ку твою́. И простре́, и утверди́ся рука́ его́ цела́ я́ко друга́я. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆дѧ́ше і҆и҃съ въ сꙋббѡ́ты сквозѣ̀ сѣ́ѧнїѧ, и҆ нача́ша ᲂу҆ченицы̀ є҆гѡ̀ пꙋ́ть твори́ти, востерза́юще кла́сы. и҆ фарїсе́є глаго́лахꙋ є҆мꙋ̀: ви́ждь, что̀ творѧ́тъ въ сꙋббѡ́ты, є҆́же не досто́итъ; и҆ то́й глаго́лаше и҆̀мъ: нѣ́сте ли николи́же члѝ, что̀ сотворѝ дв҃дъ, є҆гда̀ тре́бованїе и҆мѣ̀, и҆ взалка̀ са́мъ, и҆ и҆̀же съ ни́мъ; ка́кѡ вни́де въ до́мъ бж҃їй при а҆вїаѳа́рѣ а҆рхїере́и, и҆ хлѣ́бы предложе́нїѧ снѣдѐ, и҆́хже не досто́ѧше ꙗ҆́сти, то́кмѡ і҆ере́ємъ, и҆ дадѐ и҆ сꙋ́щымъ съ ни́мъ; и҆ глаго́лаше и҆̀мъ: сꙋббѡ́та человѣ́ка ра́ди бы́сть, а҆ не человѣ́къ сꙋббѡ́ты ра́ди. тѣ́мже гдⷭ҇ь є҆́сть сн҃ъ человѣ́ческїй и҆ сꙋббѡ́тѣ. и҆ вни́де па́ки въ со́нмище: и҆ бѣ̀ та́мѡ человѣ́къ сꙋ́хꙋ и҆мы́й рꙋ́кꙋ. и҆ назира́хꙋ є҆го̀, а҆́ще въ сꙋббѡ́ты и҆сцѣли́тъ є҆го̀, да на́нь возглаго́лютъ. и҆ глаго́ла человѣ́кꙋ сꙋ́хꙋ и҆мꙋ́щемꙋ рꙋ́кꙋ: ста́ни посредѣ̀. и҆ глаго́ла и҆̀мъ: досто́итъ ли въ сꙋббѡ́ты добро̀ твори́ти, и҆лѝ ѕло̀ твори́ти; дꙋ́шꙋ спастѝ, и҆лѝ погꙋби́ти; ѻ҆ни́ же молча́хꙋ. и҆ воззрѣ́въ на ни́хъ со гнѣ́вомъ, скорбѧ̀ ѡ҆ ѡ҆камене́нїи серде́цъ и҆́хъ, глаго́ла человѣ́кꙋ: прострѝ рꙋ́кꙋ твою̀. и҆ прострѐ: и҆ ᲂу҆тверди́сѧ рꙋка̀ є҆гѡ̀ цѣла̀, ꙗ҆́кѡ дрꙋга́ѧ. ",
}

add_evangelie_marka {
  ["номер"] = 11,
  ["комментарий"] = "Мк., 11 зач., III, 6–12.",
  ["текст_ру"] = "Во вре́мя о́но, сове́т сотвори́ша фарисе́е на Иису́са со иродиа́ны, ка́ко Его́ погубя́т. Иису́с же оты́де со ученики́ Свои́ми к мо́рю, и мног наро́д от Галиле́и по Нем и́де, и от Иуде́и, и от Иерусали́ма, и от Идуме́и, и со о́наго по́лу Иорда́на. И от Ти́ра и Сидо́на мно́жество мно́гое, слы́шавше, ели́ка творя́ше, и приидо́ша к Нему́. И рече́ ученико́м Свои́м, да кора́бль бу́дет у Него́ наро́да ра́ди, да не стужа́ют Ему́. Мно́ги бо исцели́, я́коже напа́дати Ем, да Ему́ прико́снутся, ели́цы име́яху ра́ны. И ду́си нечи́стии, егда́ ви́дяху Его́, припа́даху к Нему́ и зва́ху, глаго́люще, я́ко Ты еси́ Сын Бо́жий. И мно́го преща́ше им, да не явле́нна Его́ сотворя́т. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, совѣ́тъ сотвори́ша фарїсе́є на і҆и҃са со и҆рѡдїа́ны, ка́кѡ є҆го̀ погꙋбѧ́тъ. і҆и҃съ же ѿи́де со ᲂу҆ченикѝ свои́ми къ мо́рю: и҆ мно́гъ наро́дъ ѿ галїле́и по не́мъ и҆́де, и҆ ѿ і҆ꙋде́и, и҆ ѿ і҆ерꙋсали́ма, и҆ ѿ і҆дꙋме́и, и҆ со ѻ҆́нагѡ по́лꙋ і҆ѻрда́на, и҆ ѿ тѵ́ра и҆ сїдѡ́на, мно́жество мно́гое: слы́шавше є҆ли̑ка творѧ́ше, и҆ прїидо́ша къ немꙋ̀. и҆ речѐ ᲂу҆ченикѡ́мъ свои́мъ, да кора́бль бꙋ́детъ ᲂу҆ негѡ̀, наро́да ра́ди, да не стꙋжа́ютъ є҆мꙋ̀. мно́ги бо и҆сцѣлѝ, ꙗ҆́коже напа́дати є҆́мъ, да є҆мꙋ̀ прико́снꙋтсѧ, є҆ли́цы и҆мѣ́ѧхꙋ ра̑ны. и҆ дꙋ́си нечи́стїи, є҆гда̀ ви́дѧхꙋ є҆го̀, припа́дахꙋ къ немꙋ̀ и҆ зва́хꙋ, глаго́люще: ꙗ҆́кѡ ты̀ є҆сѝ сн҃ъ бж҃їй. и҆ мно́гѡ преща́ше и҆̀мъ, да не ꙗ҆вле́нна є҆го̀ сотворѧ́тъ. ",
}

add_evangelie_marka {
  ["номер"] = 12,
  ["комментарий"] = "Мк., 12 зач., III, 13–19.",
  ["текст_ру"] = "Во вре́мя о́но, взы́де Иису́с на гору́ и призва́, и́хже хотя́ше Сам, и приидо́ша к Нему́. И сотвори́ двана́десяте, да бу́дут с Ним, и да посыла́ет их пропове́дати, и име́ти власть цели́ти неду́ги и изгони́ти бе́сы. И нарече́ Си́мону и́мя Петр, и Иа́кова Зеведе́ова и Иоа́нна бра́та Иа́ковля, и нарече́ и́ма имена́ Воанерге́с, е́же есть сы́на гро́мова, и Андре́а, и Фили́ппа, и Варфоломе́а, и Матфе́а, и Фому́, и Иа́кова Алфе́ова, и Фадде́а, и Си́мона Канани́та, и Иу́ду Искарио́тскаго, и́же и предаде́ Его́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, взы́де і҆и҃съ на горꙋ̀, и҆ призва̀ и҆̀хже хотѧ́ше са́мъ: и҆ прїидо́ша къ немꙋ̀. и҆ сотворѝ двана́десѧте, да бꙋ́дꙋтъ съ ни́мъ, и҆ да посыла́етъ и҆̀хъ проповѣ́дати, и҆ и҆мѣ́ти вла́сть цѣли́ти недꙋ́ги, и҆ и҆згони́ти бѣ́сы. и҆ наречѐ сі́мѡнꙋ и҆́мѧ, пе́тръ: и҆ і҆а́кѡва зеведе́ова, и҆ і҆ѡа́нна бра́та і҆а́кѡвлѧ: и҆ наречѐ и҆́ма и҆мена̀ воанерге́съ, є҆́же є҆́сть сы́на гро́мова. и҆ а҆ндре́а, и҆ фїлі́ппа, и҆ варѳоломе́а, и҆ матѳе́а, и҆ ѳѡмꙋ̀, и҆ і҆а́кѡва а҆лфе́ова, и҆ ѳадде́а, и҆ сі́мѡна канані́та: и҆ і҆ꙋ́дꙋ і҆скарїѡ́тскаго, и҆́же и҆ предадѐ є҆го̀. ",
}

add_evangelie_marka {
  ["номер"] = 13,
  ["комментарий"] = "Мк., 13 зач., III, 20–27.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с в дом, и собра́ся па́ки наро́д, я́ко не мощи́ им ни хле́ба я́сти. И слы́шавше и́же бя́ху у Него́, изыдо́ша, да и́мут Его́, глаго́лаху бо, я́ко неи́стов есть. И кни́жницы, и́же от Иерусали́ма низше́дшии, глаго́лаху, я́ко веельзеву́ла и́мать и я́ко о кня́зе бесо́встем изго́нит бе́сы. И призва́в их, в при́тчах глаго́лаше им: ка́ко мо́жет сатана́ сатану́ изгони́ти? И а́ще ца́рство на ся раздели́тся, не мо́жет ста́ти ца́рство то, и а́ще дом на ся раздели́тся, не мо́жет ста́ти дом той, и а́ще сатана́ воста́ на ся сам и раздели́ся, не мо́жет ста́ти, но коне́ц и́мать. Никто́же мо́жет сосу́ды кре́пкаго, вшед в дом его́, расхи́тити, а́ще не пе́рвее кре́пкаго свя́жет, и тогда́ дом его́ расхи́тит. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ въ до́мъ, и҆ собра́сѧ па́ки наро́дъ, ꙗ҆́кѡ не мощѝ и҆̀мъ ни хлѣ́ба ꙗ҆́сти. и҆ слы́шавше и҆̀же бѧ́хꙋ ᲂу҆ негѡ̀, и҆зыдо́ша, да и҆́мꙋтъ є҆го̀: глаго́лахꙋ бо, ꙗ҆́кѡ неи́стовъ є҆́сть. и҆ кни́жницы, и҆̀же ѿ і҆ерꙋсали́ма низше́дшїи, глаго́лахꙋ: ꙗ҆́кѡ веелзевꙋ́ла и҆́мать, и҆ ꙗ҆́кѡ ѡ҆ кнѧ́зѣ бѣсо́встѣмъ и҆зго́нитъ бѣ́сы. и҆ призва́въ и҆̀хъ, въ при́тчахъ глаго́лаше и҆̀мъ: ка́кѡ мо́жетъ сатана̀ сатанꙋ̀ и҆згони́ти; и҆ а҆́ще црⷭ҇тво на сѧ̀ раздѣли́тсѧ, не мо́жетъ ста́ти црⷭ҇тво то̀. и҆ а҆́ще до́мъ на сѧ̀ раздѣли́тсѧ, не мо́жетъ ста́ти до́мъ то́й. и҆ а҆́ще сатана̀ воста̀ на сѧ̀ са́мъ, и҆ раздѣли́сѧ: не мо́жетъ ста́ти, но коне́цъ и҆́мать. никто́же мо́жетъ сосꙋ́ды крѣ́пкагѡ, вше́дъ въ до́мъ є҆гѡ̀, расхи́тити, а҆́ще не пе́рвѣе крѣ́пкаго свѧ́жетъ, и҆ тогда̀ до́мъ є҆гѡ̀ расхи́титъ. ",
}

add_evangelie_marka {
  ["номер"] = 14,
  ["комментарий"] = "Мк., 14 зач., III, 28–35.",
  ["текст_ру"] = "Рече́ Госпо́дь: ами́нь глаго́лю вам, я́ко вся отпу́стятся согреше́ния сыно́м челове́ческим, и хуле́ния, ели́ка а́ще восху́лят, а и́же восху́лит на Ду́ха Свята́го, не и́мать отпуще́ния во ве́ки, но пови́нен есть ве́чному суду́. Зане́ глаго́лаху: ду́ха нечи́стаго и́мать. Приидо́ша у́бо Ма́ти и бра́тия Его́, и вне стоя́ще посла́ша к Нему́, зову́ще Его́. И седя́ше наро́д о Нем. Ре́ша же Ему́: се Ма́ти Твоя́ и бра́тия Твоя́ и сестры́ Твоя́ вне и́щут Тебе́. И отвеща́ им, глаго́ля: кто есть ма́ти Моя́, или́ бра́тия Моя́? И согля́дав о́крест Себе́ седя́щыя, глаго́ла: се ма́ти Моя́ и бра́тия Моя́, и́же бо а́ще сотвори́т во́лю Бо́жию, сей брат Мой и сестра́ Моя́ и ма́ти Ми есть. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: а҆ми́нь глаго́лю ва́мъ: ꙗ҆́кѡ всѧ̑ ѿпꙋ́стѧтсѧ согрѣшє́нїѧ сынѡ́мъ человѣ́чєскимъ, и҆ хꙋлє́нїѧ, є҆ли̑ка а҆́ще восхꙋ́лѧтъ. а҆ и҆́же восхꙋ́литъ на дх҃а ст҃а́го, не и҆́мать ѿпꙋще́нїѧ во вѣ́ки, но пови́ненъ є҆́сть вѣ́чномꙋ сꙋдꙋ̀: занѐ глаго́лахꙋ: дꙋ́ха нечи́стаго и҆́мать. прїидо́ша ᲂу҆́бѡ мт҃и и҆ бра́тїѧ є҆гѡ̀, и҆ внѣ̀ стоѧ́ще, посла́ша къ немꙋ̀ зовꙋ́ще є҆го̀. и҆ сѣдѧ́ше наро́дъ ѡ҆ не́мъ: рѣ́ша же є҆мꙋ̀: сѐ мт҃и твоѧ̀, и҆ бра́тїѧ твоѧ̀, и҆ сєстры̀ твоѧ̀, внѣ̀ и҆́щꙋтъ тебѐ. и҆ ѿвѣща̀ и҆̀мъ, глаго́лѧ: кто́ є҆сть мт҃и моѧ̀, и҆лѝ бра́тїѧ моѧ̀; и҆ соглѧ́давъ ѻ҆́крестъ себѐ сѣдѧ́щыѧ, глаго́ла: сѐ мт҃и моѧ̀, и҆ бра́тїѧ моѧ̀: и҆́же бо а҆́ще сотвори́тъ во́лю бж҃їю, се́й бра́тъ мо́й, и҆ сестра̀ моѧ̀, и҆ мт҃и мѝ є҆́сть. ",
}

add_evangelie_marka {
  ["номер"] = 15,
  ["комментарий"] = "Мк., 15 зач., IV, 1–9.",
  ["текст_ру"] = "Во вре́мя о́но, нача́т Иису́с учи́ти при мо́ри, и собра́ся к Нему́ наро́д мног, я́коже Самому́ вле́зшу в кора́бль, седе́ти в мо́ри, и весь наро́д при мо́ри на земли́ бя́ше. И уча́ше их при́тчами мно́го и глаго́лаше им во уче́нии Свое́м: слы́шите, се изы́де се́яй се́яти, и бысть егда́ се́яше, о́во паде́ при пути́, и приидо́ша пти́цы, и позоба́ша е́. Друго́е же паде́ на ка́мени, иде́же не имя́ше земли́ мно́ги, и а́бие прозябе́, зане́ не имя́ше глубины́ земны́я. Со́лнцу же возсия́вшу присвя́де, и зане́ не имя́ше ко́рене, и́зсше. И друго́е паде́ в те́рнии, и взы́де те́рние, и подави́ е́, и плода́ не даст. И друго́е паде́ на земли́ до́брей, и дая́ше плод восходя́щь и расту́щь, и припло́доваше на три́десять, и на шестьдеся́т, и на сто. И глаго́лаше: име́яй у́ши слы́шати да слы́шит. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, нача́тъ і҆и҃съ ᲂу҆чи́ти при мо́ри: и҆ собра́сѧ къ немꙋ̀ наро́дъ мно́гъ, ꙗ҆́коже самомꙋ̀ влѣ́зшꙋ въ кора́бль сѣдѣ́ти въ мо́ри, и҆ ве́сь наро́дъ при мо́ри на землѝ бѧ́ше. и҆ ᲂу҆ча́ше и҆̀хъ при́тчами мно́гѡ, и҆ глаго́лаше и҆̀мъ во ᲂу҆че́нїи свое́мъ: слы́шите, сѐ и҆зы́де сѣ́ѧй сѣ́ѧти. и҆ бы́сть є҆гда̀ сѣ́ѧше, ѻ҆́во падѐ на пꙋтѝ: и҆ прїидо́ша пти̑цы, и҆ позоба́ша є҆̀. дрꙋго́е же падѐ на ка́мени, и҆дѣ́же не и҆мѧ́ше землѝ мно́ги: и҆ а҆́бїе прозѧбѐ, занѐ не и҆мѧ́ше глꙋбины̀ земны́ѧ. со́лнцꙋ же возсїѧ́вшꙋ присвѧ́де, и҆ занѐ не и҆мѧ́ше ко́рене, и҆́зсше. и҆ дрꙋго́е падѐ въ те́рнїи, и҆ взы́де те́рнїе, и҆ подавѝ є҆̀, и҆ плода̀ не да́стъ. и҆ дрꙋго́е падѐ на землѝ до́брѣй, и҆ даѧ́ше пло́дъ восходѧ́щъ и҆ растꙋ́щъ: и҆ припло́доваше на три́десѧть, и҆ на шестьдесѧ́тъ, и҆ на сто̀. и҆ глаго́лаше: и҆мѣ́ѧй ᲂу҆́ши слы́шати, да слы́шитъ. ",
}

add_evangelie_marka {
  ["номер"] = 16,
  ["комментарий"] = "Мк., 16 зач., IV, 10–23.",
  ["текст_ру"] = "Во вре́мя о́но, приступи́ша ученицы́ ко Иису́су наедине́, и вопроси́ша Его́ о при́тчи. И глаго́лаше им: вам есть дано́ ве́дати та́йны Ца́рствия Бо́жия, о́нем же вне́шним в при́тчах вся быва́ют, да ви́дяще ви́дят, и не у́зрят, и слы́шаще слы́шат, и не разуме́ют, да не когда́ обратя́тся, и оста́вятся им греси́. И глаго́ла им: не ве́сте ли при́тчи сея́? И ка́ко вся при́тчи разуме́ете? Се́яй, сло́во се́ет. Си́и же суть, и́же на пути́, иде́же се́ется сло́во, и егда́ услы́шат, а́бие прии́дет сатана́ и оти́мет сло́во се́янное в сердца́х их. И си́и суть та́кожде и́же на ка́менных се́емии, и́же егда́ услы́шат сло́во, а́бие с ра́достию прие́млют е́. И не и́мут коре́ния в себе́, но привре́менни суть, та́же бы́вши печа́ли или́ гоне́нию словесе́ ра́ди, а́бие соблажня́ются. А си́и суть, и́же в те́рнии се́емии, слы́шащии сло́во, и печа́ли ве́ка сего́, и лесть бога́тства, и о про́чих по́хотию входя́ще подавля́ют сло́во, и безпло́дно быва́ет. И си́и суть, и́же на земли́ до́брей се́яннии, и́же слы́шат сло́во и прие́млют, и пло́дствуют на три́десять, и на шестьдеся́т, и на сто. И глаго́лаше им: еда́ свети́льник прихо́дит, да под спу́дом положа́т его́ или́ под одро́м? Не да ли на све́щнице положе́н бу́дет? Несть бо та́йно, е́же не яви́тся, ниже́ бысть потае́но, но да прии́дет в явле́ние. А́ще кто и́мать у́ши слы́шати, да слы́шит. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋпи́ша ᲂу҆ченицы̀ ко і҆и҃сꙋ нає҆динѣ̀, и҆ вопроси́ша є҆го ѡ҆ при́тчи. и҆ глаго́лаше и҆̀мъ: ва́мъ є҆́сть дано̀ вѣ́дати та̑йны црⷭ҇твїѧ бж҃їѧ, ѻ҆́нѣмъ же внѣ̑шнимъ, въ при́тчахъ всѧ̑ быва́ютъ. да ви́дѧще ви́дѧтъ, и҆ не ᲂу҆́зрѧтъ: и҆ слы́шаще слы́шатъ, и҆ не разꙋмѣ́ютъ: да не когда̀ ѡ҆братѧ́тсѧ, и҆ ѡ҆ста́вѧтсѧ и҆̀мъ грѣсѝ. и҆ глаго́ла и҆̀мъ: не вѣ́сте ли при́тчи сеѧ̀; и҆ ка́кѡ всѧ̑ при̑тчи разꙋмѣ́ете; сѣ́ѧй, сло́во сѣ́етъ. сі́и же сꙋ́ть, и҆̀же на пꙋтѝ, и҆дѣ́же сѣ́етсѧ сло́во: и҆ є҆гда̀ ᲂу҆слы́шатъ, а҆́бїе прїи́детъ сатана̀, и҆ ѿи́метъ сло́во сѣ́ѧнное въ сердца́хъ и҆́хъ. и҆ сі́и сꙋ́ть та́кожде, и҆̀же на ка́менныхъ сѣ́емїи: и҆̀же є҆гда̀ ᲂу҆слы́шатъ сло́во а҆́бїе съ ра́достїю прїе́млютъ є҆̀. и҆ не и҆́мꙋтъ коре́нїѧ въ себѣ̀, но привре́менни сꙋ́ть: та́же бы́вши печа́ли, и҆лѝ гоне́нїю словесѐ ра́ди, а҆́бїе соблажнѧ́ютсѧ. а҆ сі́и сꙋ́ть, и҆̀же въ те́рнїи сѣ́емїи: слы́шащїи сло́во. и҆ печа̑ли вѣ́ка сегѡ̀, и҆ ле́сть бога́тства, и҆ ѡ҆ про́чихъ по́хотїю входѧ́ще подавлѧ́ютъ сло́во, и҆ безпло́дно быва́етъ. и҆ сі́и сꙋ́ть, и҆̀же на землѝ до́брѣй сѣ́ѧннїи, и҆̀же слы́шатъ сло́во, и҆ прїе́млютъ: и҆ пло́дствꙋютъ на три́десѧть, и҆ на шестьдесѧ́тъ, и҆ на сто̀. и҆ глаго́лаше и҆̀мъ: є҆да̀ свѣти́льникъ прихо́дитъ, да под̾ спꙋ́домъ положа́тъ є҆го̀, и҆лѝ под̾ ѻ҆дро́мъ; не да лѝ на свѣ́щницѣ положе́нъ бꙋ́детъ; нѣ́сть бо та́йно, є҆́же не ꙗ҆ви́тсѧ: нижѐ бы́сть потае́но, но да прїи́детъ въ ꙗ҆вле́нїе. а҆́ще кто̀ и҆́мать ᲂу҆́ши слы́шати, да слы́шитъ. ",
}

add_evangelie_marka {
  ["номер"] = 17,
  ["комментарий"] = "Мк., 17 зач., IV, 24–34.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: блюди́те что слы́шите, в ню́же ме́ру ме́рите, возме́рится вам, и приложи́тся вам слы́шащым. И́же бо а́ще и́мать, да́стся ему́, а и́же не и́мать, и е́же и́мать, оти́мется от него́. И глаго́лаше: та́ко есть и Ца́рствие Бо́жие, я́коже челове́к вмета́ет се́мя в зе́млю, и спит, и востае́т но́щию и дни́ю, и се́мя прозяба́ет и расте́т, я́коже не весть он. В себе́ бо земля́ плоди́т пре́жде траву́, пото́м клас, та́же исполня́ет пшени́цу в кла́се. Егда́ же созре́ет плод, а́бие по́слет серп, я́ко наста́ жа́тва. И глаго́лаше: чесому́ уподо́бим Ца́рствие Бо́жие? Или́ ко́ей при́тчи приложи́м е́? Я́ко зе́рно гору́шично, е́же егда́ все́яно бу́дет в земли́, мне́е всех се́мен есть земны́х. И егда́ все́яно бу́дет, возрасте́т, и бу́дет бо́ле всех зе́лий, и сотвори́т ве́тви ве́лия, я́ко мощи́ под се́нию его́ пти́цам небе́сным вита́ти. И таковы́ми при́тчами мно́гими глаго́лаше им сло́во, я́коже можа́ху слы́шати. Без при́тчи же не глаго́лаше им словесе́, осо́бь же ученико́м Свои́м сказа́ше вся. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ. блюди́те, что̀ слы́шите: въ ню́же мѣ́рꙋ мѣ́рите, возмѣ́ритсѧ ва́мъ, и҆ приложи́тсѧ ва́мъ слы́шащымъ. и҆́же бо а҆́ще и҆́мать, да́стсѧ є҆мꙋ̀: а҆ и҆́же не и҆́мать, и҆ є҆́же и҆́мать, ѿи́метсѧ ѿ негѡ̀. и҆ глаго́лаше: та́кѡ є҆́сть и҆ црⷭ҇твїе бж҃їе, ꙗ҆́коже человѣ́къ вмета́етъ сѣ́мѧ въ зе́млю, и҆ спи́тъ, и҆ востае́тъ но́щїю, и҆ дні́ю, и҆ сѣ́мѧ прозѧба́етъ и҆ расте́тъ, ꙗ҆́коже не вѣ́сть ѻ҆́нъ. въ себѣ́ бо землѧ̀ плоди́тъ пре́жде травꙋ̀, пото́мъ кла́съ, та́же и҆сполнѧ́етъ пшени́цꙋ въ кла́сѣ. є҆гда́ же созрѣ́етъ пло́дъ, а҆́бїе по́слетъ се́рпъ, ꙗ҆́кѡ наста̀ жа́тва. и҆ глаго́лаше: чесомꙋ̀ ᲂу҆подо́бимъ црⷭ҇твїе бж҃їе; и҆лѝ ко́ей при́тчи приложи́мъ є҆̀; ꙗ҆́кѡ зе́рно горꙋ́шично, є҆́же є҆гда̀ всѣ́ѧно бꙋ́детъ въ землѝ, мнѣ́е всѣ́хъ сѣ́менъ є҆́сть земны́хъ. и҆ є҆гда̀ всѣ́ѧно бꙋ́детъ, возрасте́тъ, и҆ бꙋ́детъ бо́лѣ всѣ́хъ ѕе́лїй, и҆ сотвори́тъ вѣ̑тви ве́лїѧ, ꙗ҆́кѡ мощѝ под̾ сѣ́нїю є҆гѡ̀ пти́цамъ нбⷭ҇нымъ вита́ти. и҆ таковы́ми при́тчами мно́гими глаго́лаше и҆̀мъ сло́во, ꙗ҆́коже можа́хꙋ слы́шати: без̾ при́тчи же не глаго́лаше и҆̀мъ словесѐ, ѻ҆со́бь же ᲂу҆ченикѡ́мъ свои́мъ сказа́ше всѧ̑. ",
}

add_evangelie_marka {
  ["номер"] = 18,
  ["комментарий"] = "Мк., 18 зач., IV, 35–41.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: пре́йдем на он пол. И отпу́щше наро́ды, поя́ша Его́ я́коже бе в корабли́, и ини́и же корабли́ бя́ху с Ним. И бысть бу́ря ве́трена вели́ка, во́лны же влива́хуся в кора́бль, я́ко уже́ погружа́тися ему́. И бе Сам на корме́ на возгла́внице спя. И возбуди́ша Его́ и глаго́лаша Ему́: Учи́телю, неради́ши ли, я́ко погиба́ем? И воста́в запрети́ ве́тру, и рече́ мо́рю: молчи́, преста́ни. И уле́же ветр, и бысть тишина́ ве́лия. И рече́ им: что та́ко страшли́ви есте́? Ка́ко не и́мате ве́ры? И убоя́шася стра́хом ве́лиим и глаго́лаху друг ко дру́гу: кто у́бо Сей есть, я́ко и ветр и мо́ре послу́шают Его́? ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: пре́йдемъ на ѻ҆́нъ по́лъ. и҆ ѿпꙋ́щше наро́ды, поѧ́ша є҆го̀, ꙗ҆́коже бѣ̀ въ кораблѝ: и҆ и҆ні́и же кораблѝ бѧ́хꙋ съ ни́мъ. и҆ бы́сть бꙋ́рѧ вѣ́трена вели́ка: во́лны же влива́хꙋсѧ въ кора́бль, ꙗ҆́кѡ ᲂу҆жѐ погрꙋжа́тисѧ є҆мꙋ̀. и҆ бѣ̀ са́мъ на кормѣ̀, на возгла́вницѣ спѧ̀. и҆ возбꙋди́ша є҆го̀, и҆ глаго́лаша є҆мꙋ̀: ᲂу҆чи́телю, неради́ши ли, ꙗ҆́кѡ погиба́емъ; и҆ воста́въ запретѝ вѣ́трꙋ, и҆ речѐ мо́рю: молчѝ, преста́ни. и҆ ᲂу҆ле́же вѣ́тръ, и҆ бы́сть тишина̀ ве́лїѧ. и҆ речѐ и҆̀мъ: что̀ та́кѡ страшли́ви є҆стѐ; ка́кѡ не и҆́мате вѣ́рꙋ; и҆ ᲂу҆боѧ́шасѧ стра́хомъ ве́лїимъ, и҆ глаго́лахꙋ дрꙋ́гъ ко дрꙋ́гꙋ: кто̀ ᲂу҆́бѡ се́й є҆́сть, ꙗ҆́кѡ и҆ вѣ́тръ и҆ мо́ре послꙋ́шаютъ є҆гѡ̀; ",
}

add_evangelie_marka {
  ["номер"] = 19,
  ["комментарий"] = "Мк., 19 зач., V, 1-20.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с на он пол мо́ря, во страну́ Гадари́нскую. И изле́зшу Ему́ из корабля́, а́бие сре́те Его́ от гро́б челове́к в ду́се нечи́сте, и́же жили́ще имя́ше во гробе́х, и ни вери́гами никто́же можа́ше его́ связа́ти, зане́ ему́ мно́гажды пу́ты и у́жи желе́зны свя́зану су́щу, и растерза́тися от него́ у́жем желе́зным и пу́том сокруша́тися, и никто́же можа́ше его́ уму́чити, и вы́ну нощь и день во гробе́х и в гора́х бе, вопия́ и толки́йся ка́мением. Узре́в же Иису́са издале́ча, тече́ и поклони́ся Ему́, и возопи́в гла́сом ве́лиим, рече́: что мне и Тебе́, Иису́се Сы́не Бо́га Вы́шняго? Заклина́ю Тя Бо́гом, не му́чи мене́. Глаго́лаше бо ему́: изы́ди, ду́ше нечи́стый, от челове́ка. И вопроша́ше его́: что ти есть и́мя? И отвеща́ глаго́ля: легео́н и́мя мне, я́ко мно́зи есмы́. И моли́ша Его́ мно́го, да не по́слет их вне страны́. Бе же ту при горе́ ста́до свино́е ве́лие пасо́мо. И моли́ша Его́ вси бе́си, глаго́люще: посли́ ны во свиния́, да в ня вни́дем. И повеле́ им а́бие Иису́с. И изше́дше ду́си нечи́стии, внидо́ша во свиния́, и устреми́ся ста́до по бре́гу в мо́ре, бя́ху же я́ко две ты́сящи, и утопа́ху в мо́ри. Пасу́щии же свиния́ бежа́ша и возвести́ша во гра́де и в се́лех. И изыдо́ша ви́дети, что есть бы́вшее. И приидо́ша ко Иису́сови, и ви́деша беснова́вшагося седя́ща и оболче́на и смы́сляща, име́вшаго легео́н, и убоя́шася. Пове́даша же им ви́девшии, ка́ко бысть бесно́му, и о свиния́х. И нача́ша моли́ти Его́ отити́ от преде́л их. И вле́зшу Ему́ в кора́бль, моля́ше Его́ беснова́выйся, дабы́ был с Ним. Иису́с же не даст ему́, но рече́ ему́: иди́ в дом твой ко твои́м и возвести́ им, ели́ка ти Госпо́дь сотвори́ и поми́лова тя. И и́де и нача́ пропове́дати в десяти́ граде́х, ели́ка сотвори́ ему́ Иису́с. И вси дивля́хуся. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ на ѻ҆́нъ по́лъ мо́рѧ во странꙋ̀ гадари́нскꙋю. и҆ и҆злѣ́зшꙋ є҆мꙋ̀ и҆з̾ кораблѧ̀, а҆́бїе срѣ́те є҆го̀ ѿ грѡ́бъ человѣ́къ въ дꙋ́сѣ нечи́стѣ: и҆́же жили́ще и҆мѧ́ше во гробѣ́хъ, и҆ ни вери́гами никто́же можа́ше є҆го̀ свѧза́ти: занѐ є҆мꙋ̀ мно́гажды пꙋ́ты, и҆ ᲂу҆́жи желѣ́зны свѧ́занꙋ сꙋ́щꙋ, и҆ растерза́тисѧ ѿ негѡ̀ ᲂу҆́жємъ желѣ́знымъ, и҆ пꙋ́тѡмъ сокрꙋша́тисѧ: и҆ никто́же можа́ше є҆го̀ ᲂу҆мꙋ́чити. и҆ вы́нꙋ но́щь и҆ де́нь во гробѣ́хъ, и҆ въ гора́хъ бѣ̀ вопїѧ̀, и҆ толкі́йсѧ ка́менїемъ. ᲂу҆зрѣ́въ же і҆и҃са и҆здале́ча, течѐ, и҆ поклони́сѧ є҆мꙋ̀. и҆ возопи́въ гла́сомъ ве́лїимъ, речѐ: что̀ мнѣ̀ и҆ тебѣ̀ і҆и҃се, сн҃е бг҃а вы́шнѧгѡ; заклина́ю тѧ̀ бг҃омъ, не мꙋ́чи менѐ. глаго́лаше бо є҆мꙋ̀: и҆зы́ди дꙋ́ше нечи́стый ѿ человѣ́ка. и҆ вопроша́ше є҆го̀: что́ ти є҆́сть и҆́мѧ, и҆ ѿвѣща̀ глаго́лѧ: легеѡ́нъ и҆́мѧ мнѣ̀, ꙗ҆́кѡ мно́зи є҆смы̀. и҆ моли́ша є҆го̀ мно́гѡ, да не по́слетъ и҆̀хъ внѣ̀ страны̀. бѣ́ же тꙋ̀ при горѣ̀ ста́до свино́е ве́лїе пасо́мо. и҆ моли́ша є҆го̀ всѝ бѣ́си глаго́люще: посли́ ны во свинїѧ̑, да въ нѧ̀ вни́демъ. и҆ повелѣ̀ и҆̀мъ а҆́бїе і҆и҃съ: и҆ и҆зше́дше дꙋ́си нечи́стїи внидо́ша во свинїѧ̑: и҆ ᲂу҆стреми́сѧ ста́до по бре́гꙋ въ мо́ре: бѧ́хꙋ же ꙗ҆́кѡ двѣ̀ ты́сѧщи, и҆ ᲂу҆топа́хꙋ въ мо́ри: пасꙋ́щїи же свинїѧ̑ бѣжа́ша, и҆ возвѣсти́ша во гра́дѣ, и҆ въ се́лѣхъ: и҆ и҆зыдо́ша ви́дѣти, что́ є҆сть бы́вшее; и҆ прїидо́ша ко і҆и҃сови, и҆ ви́дѣша бѣснова́вшагосѧ сѣдѧ́ща, и҆ ѡ҆болче́на, и҆ смы́слѧща, и҆мѣ́вшаго легеѡ́нъ: и҆ ᲂу҆боѧ́шасѧ. повѣ́даша же и҆̀мъ ви́дѣвшїи, ка́кѡ бы́сть бѣсно́мꙋ, и҆ ѡ҆ свинїѧ́хъ. и҆ нача́ша моли́ти є҆го̀, ѿитѝ ѿ предѣ̑лъ и҆́хъ. и҆ влѣ́зшꙋ є҆мꙋ̀ въ кора́бль, молѧ́ше є҆го̀ бѣснова́выйсѧ, дабы̀ бы́лъ съ ни́мъ. і҆и҃съ же не да́стъ є҆мꙋ̀, но речѐ є҆мꙋ̀: и҆дѝ въ до́мъ тво́й ко твои́мъ, и҆ возвѣстѝ и҆̀мъ, є҆ли̑ка тѝ гдⷭ҇ь сотворѝ, и҆ поми́лова тѧ̀. и҆ и҆́де, и҆ нача̀ проповѣ́дати въ десѧтѝ градѣ́хъ, є҆ли̑ка сотворѝ є҆мꙋ̀ і҆и҃съ. и҆ всѝ дивлѧ́хꙋсѧ. ",
}

add_evangelie_marka {
  ["номер"] = 20,
  ["комментарий"] = "Мк., 20 зач., V, 22–24, 35 – VI, 1.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де ко Иису́су еди́н от архисинаго́г, и́менем Иаи́р, и ви́дев Его́, паде́ при ногу́ Его́ и моля́ше Его́ мно́го, глаго́ля, я́ко дщи моя́ на кончи́не есть, да прише́д возложи́ши на ню ру́це, я́ко да спасе́тся и жива́ бу́дет. И и́де с ним, и по Нем идя́ху наро́ди мно́зи и угнета́ху Его́. И приидо́ша от архисинаго́га, глаго́люще, я́ко дщи твоя́ у́мре, что еще́ дви́жеши Учи́теля? Иису́с же а́бие слы́шав сло́во глаго́лемое, глаго́ла архисинаго́гови: не бо́йся, то́кмо ве́руй. И не оста́ви по Себе́ ни еди́наго ити́, то́кмо Петра́ и Иа́кова и Иоа́нна бра́та Иа́ковля. И прии́де в дом архисинаго́гов и ви́де молву́, пла́чущыяся и крича́щыя мно́го. И вшед глаго́ла им: что мо́лвите и пла́четеся? Отрокови́ца несть умерла́, но спит. И руга́хуся Ему́. Он же изгна́в вся, поя́т отца́ отрокови́цы и ма́терь, и и́же бе́ху с Ним, и вни́де, иде́же бе отрокови́ца лежа́щи. И ем за ру́ку отрокови́цу, глаго́ла ей: талифа́ ку́ми, е́же есть сказа́емо, деви́це, тебе́ глаго́лю, воста́ни. И а́бие воста́ деви́ца и хожда́ше, бе бо лет двоюна́десяте. И ужасо́шася у́жасом ве́лиим. И запрети́ им мно́го, да никто́же уве́сть сего́, и рече́: дади́те ей я́сти. И изы́де отту́ду и прии́де во оте́чествие Свое́, и по Нем идо́ша ученицы́ Его́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де ко і҆и҃сꙋ є҆ди́нъ ѿ а҆рхїсѷнагѡ́гъ, и҆́менемъ і҆аі́ръ: и҆ ви́дѣвъ є҆го̀, падѐ при ногꙋ̀ є҆гѡ̀. и҆ молѧ́ше є҆го̀ мно́гѡ, глаго́лѧ: ꙗ҆́кѡ дщѝ моѧ̀ на кончи́нѣ є҆́сть, да прише́дъ возложи́ши на ню̀ рꙋ́цѣ, ꙗ҆́кѡ да спасе́тсѧ, и҆ жива̀ бꙋ́детъ. и҆ и҆́де съ ни́мъ: и҆ по не́мъ и҆дѧ́хꙋ наро́ди мно́зи, и҆ ᲂу҆гнѣта́хꙋ є҆го̀. и҆ прїидо́ша ѿ а҆рхїсѷнагѡ́га, глаго́люще: ꙗ҆́кѡ дщѝ твоѧ̀ ᲂу҆́мре, что̀ є҆щѐ дви́жеши ᲂу҆чи́телѧ; і҆и҃съ же а҆́бїе слы́шавъ сло́во глаго́лемое, глаго́ла а҆рхїсѷнагѡ́гови: не бо́йсѧ, то́кмѡ вѣ́рꙋй. и҆ не ѡ҆ста́ви по себѣ̀ ни є҆ди́нагѡ и҆тѝ, то́кмѡ петра̀, и҆ і҆а́кѡва, и҆ і҆ѡа́нна бра́та і҆а́кѡвлѧ. и҆ прїи́де въ до́мъ а҆рхїсѷнагѡ́говъ, и҆ ви́дѣ молвꙋ̀, пла́чꙋщыѧсѧ и҆ крича́щыѧ мно́гѡ. и҆ вше́дъ глаго́ла и҆̀мъ: что̀ мо́лвите и҆ пла́четесѧ; ѻ҆трокови́ца нѣ́сть ᲂу҆мерла̀, но спи́тъ. и҆ рꙋга́хꙋсѧ є҆мꙋ̀: ѻ҆́нъ же и҆згна́въ всѧ̑, поѧ́тъ ѻ҆тца̀ ѻ҆трокови́цы и҆ ма́терь, и҆ и҆̀же бѣ́хꙋ съ ни́мъ, и҆ вни́де и҆дѣ́же бѣ̀ ѻ҆трокови́ца лежа́щи. и҆ є҆́мъ за рꙋ́кꙋ ѻ҆трокови́цꙋ, глаго́ла є҆́й: талїѳа̀ кꙋ́мї: є҆́же є҆́сть сказа́емо, дѣви́це, тебѣ̀ глаго́лю воста́ни. и҆ а҆́бїе воста̀ дѣви́ца, и҆ хожда́ше: бѣ́ бо лѣ́тъ двоюна́десѧте: и҆ ᲂу҆жасо́шасѧ ᲂу҆́жасомъ ве́лїимъ. и҆ запретѝ и҆̀мъ мно́гѡ, да никто́же ᲂу҆вѣ́сть сегѡ̀. и҆ речѐ: дади́те є҆́й ꙗ҆́сти. и҆ и҆зы́де ѿтꙋ́дꙋ, и҆ прїи́де во ѻ҆те́чествїе своѐ: и҆ по не́мъ и҆до́ша ᲂу҆ченицы̀ є҆гѡ̀. ",
}

add_evangelie_marka {
  ["номер"] = 21,
  ["комментарий"] = "Мк., 21 зач., V, 24–34.",
  ["текст_ру"] = "Во вре́мя о́но, по Иису́се идя́ху наро́ди мно́зи и угнета́ху Его́. И жена́ не́кая су́щи в точе́нии кро́ве лет двана́десяте, и мно́го пострада́вши от мног враче́в, и изда́вши своя́ вся, и ни еди́ныя по́льзы обре́тши, но па́че в го́ршее прише́дши, слы́шавши о Иису́се прише́дши в наро́де созади́, прикосну́ся ри́зе Его́. Глаго́лаше бо, я́ко, а́ще прикосну́ся ри́зам Его́, спасе́на бу́ду. И а́бие изся́кну исто́чник кро́ве ея́, и разуме́ те́лом, я́ко изцеле́ от ра́ны. И а́бие Иису́с разуме́ в Себе́ си́лу изше́дшую от Него́, и обра́щься в наро́де, глаго́лаше: кто прикосну́ся ри́зам Мои́м? И глаго́лаху Ему́ ученицы́ Его́: ви́диши наро́д угнета́ющ Тя, и глаго́леши, кто ся прикосну́ Мне? И обгля́даше ви́дети сотво́ршую сие́. Жена́ же убоя́вшися и трепе́щущи, ве́дящи, е́же бысть ей, прии́де и припаде́ к Нему́ и рече́ Ему́ всю и́стину. Он же рече́ ей: дщи, ве́ра твоя́ спасе́ тя. Иди́ в ми́ре и бу́ди цела́ от ра́ны твоея́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, по і҆и҃сѣ и҆дѧ́хꙋ наро́ди мно́зи, и҆ ᲂу҆гнѣта́хꙋ є҆го̀. и҆ жена̀ нѣ́каѧ сꙋ́щи въ точе́нїи кро́ве лѣ́тъ двана́десѧте: и҆ мно́гѡ пострада́вши ѿ мнѡ́гъ врачє́въ, и҆ и҆зда́вши своѧ̑ всѧ̑, и҆ ни є҆ди́ныѧ по́льзы ѡ҆брѣ́тши, но па́че въ го́ршее прише́дши: слы́шавши ѡ҆ і҆и҃сѣ, прише́дши въ наро́дѣ созадѝ, прикоснꙋ́сѧ ри́зѣ є҆гѡ̀. глаго́лаше бо: ꙗ҆́кѡ а҆́ще прикоснꙋ́сѧ ри́замъ є҆гѡ̀, спасе́на бꙋ́дꙋ. и҆ а҆́бїе и҆зсѧ́кнꙋ и҆сто́чникъ кро́ве є҆ѧ̀: и҆ разꙋмѣ̀ тѣ́ломъ, ꙗ҆́кѡ и҆сцѣлѣ̀ ѿ ра́ны. и҆ а҆́бїе і҆и҃съ разꙋмѣ̀ въ себѣ̀ си́лꙋ и҆зше́дшꙋю ѿ негѡ̀, и҆ ѡ҆бра́щсѧ въ наро́дѣ, глаго́лаше: кто̀ прикоснꙋ́сѧ ри́замъ мои́мъ; и҆ глаго́лахꙋ є҆мꙋ̀ ᲂу҆ч҃нцы̀ є҆гѡ̀: ви́диши наро́дъ ᲂу҆гнѣта́ющъ тѧ̀, и҆ глаго́леши: кто́ сѧ прикоснꙋ̀ мнѣ̀; и҆ ѡ҆бглѧ́даше ви́дѣти сотво́ршꙋю сїѐ. жена́ же ᲂу҆боѧ́вшисѧ и҆ трепе́щꙋщи, вѣ́дѧщи є҆́же бы́сть є҆́й, прїи́де и҆ припадѐ къ немꙋ̀, и҆ речѐ є҆мꙋ̀ всю̀ и҆́стинꙋ. ѻ҆́нъ же речѐ є҆́й: дщѝ, вѣ́ра твоѧ̀ спасе́ тѧ. и҆дѝ въ ми́рѣ, и҆ бꙋ́ди цѣла̀ ѿ ра́ны твоеѧ̀. ",
}

add_evangelie_marka {
  ["номер"] = 22,
  ["комментарий"] = "Мк., 22 зач., VI, 1-7.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с во оте́чествие Свое́, и по Нем идо́ша ученицы́ Его́. И бы́вши суббо́те, нача́т на со́нмищи учи́ти. И мно́зи слы́шащии дивля́хуся, глаго́люще: отку́ду Сему́ сия́? И что прему́дрость да́ная Ему́, и си́лы таковы́ рука́ма Его́ быва́ют? Не Сей ли есть текто́н, сын Мари́ин, брат же Иа́кову и Иоси́и и Иу́де и Си́мону? И не сестры́ ли Его́ зде суть в нас? И блажня́хуся о Нем. Глаго́лаше же им Иису́с, я́ко несть проро́к без че́сти, то́кмо во оте́чествии свое́м, и в сро́дстве и в дому́ свое́м. И не можа́ше ту ни еди́ныя си́лы сотвори́ти, то́кмо ма́ло неду́жных, возло́жь ру́це, исцели́. И дивля́шеся за неве́рствие их, и обхожда́ше ве́си о́крест учя́. И призва́ обана́десяте, и нача́т их посыла́ти два два, и дая́ше им власть над ду́хи нечи́стыми. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ во ѻ҆те́чествїе своѐ: и҆ по не́мъ и҆до́ша ᲂу҆ченицы̀ є҆гѡ̀. и҆ бы́вши сꙋббѡ́тѣ нача́тъ на со́нмищи ᲂу҆чи́ти, и҆ мно́зи слы́шащїи дивлѧ́хꙋсѧ, глаго́люще: ѿкꙋ́дꙋ семꙋ̀ сїѧ̑; и҆ что̀ премꙋ́дрость да́наѧ є҆мꙋ̀, и҆ си̑лы таковы̀ рꙋка́ма є҆гѡ̀ быва́ютъ; не се́й ли є҆́сть тектѡ́нъ, сн҃ъ мр҃і́инъ, бра́тъ же і҆а́кѡвꙋ, и҆ і҆ѡсі́и, и҆ і҆ꙋ́дѣ, и҆ сі́мѡнꙋ; и҆ не сєстры́ ли є҆гѡ̀ здѣ̀ сꙋ́ть въ на́съ; и҆ блажнѧ́хꙋсѧ ѡ҆ не́мъ. глаго́лаше же и҆̀мъ і҆и҃съ: ꙗ҆́кѡ нѣ́сть проро́къ без̾ че́сти, то́кмѡ во ѻ҆те́чествїи свое́мъ, и҆ въ сро́дствѣ, и҆ въ домꙋ̀ свое́мъ. и҆ не можа́ше тꙋ̀ ни є҆ди́ныѧ си́лы сотвори́ти, то́кмѡ ма́лѡ недꙋ́жныхъ, возло́жь рꙋ́цѣ, и҆сцѣлѝ. и҆ дивлѧ́шесѧ за невѣ́рствїе и҆́хъ: и҆ ѡ҆бхожда́ше вє́си ѻ҆́крестъ, ᲂу҆чѧ̀. и҆ призва̀ ѻ҆бана́десѧте, и҆ нача́тъ и҆̀хъ посыла́ти два̀ два̀: и҆ даѧ́ше и҆̀мъ вла́сть над̾ дꙋ́хи нечи́стыми. ",
}

add_evangelie_marka {
  ["номер"] = 23,
  ["комментарий"] = "Мк., 23 зач., VI, 7–13.",
  ["текст_ру"] = "Во вре́мя о́но, призва́ Иису́с обана́десяте, и нача́т их посыла́ти два два, и дая́ше им власть над ду́хи нечи́стыми. И запове́да им, да ничесо́же во́змут на путь, то́кмо жезл еди́н, ни пи́ры, ни хле́ба, ни при по́ясе ме́ди, но обуве́ни в санда́лия, и не облачи́тися в две ри́зе. И глаго́лаше им: иде́же а́ще вни́дете в дом, ту пребыва́йте, до́ндеже изы́дете отту́ду. И ели́цы а́ще не прии́мут вы, ниже́ послу́шают вас, исходя́ще отту́ду, оттряси́те прах, и́же под нога́ми ва́шими, во свиде́тельство им. Ами́нь глаго́лю вам, отра́днее бу́дет Содо́мом и Гомо́рром в день су́дный, не́же гра́ду тому́. И изше́дше пропове́даху, да пока́ются. И бе́сы мно́ги изгоня́ху, и ма́заху ма́слом мно́ги неду́жныя, и изцелева́ху. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, призва̀ і҆и҃съ ѻ҆бана́десѧте, и҆ нача́тъ и҆̀хъ посыла́ти два̀ два̀: и҆ даѧ́ше и҆̀мъ вла́сть над̾ дꙋ́хи нечи́стыми. и҆ заповѣ́да и҆̀мъ, да ничесо́же во́з̾мꙋтъ на пꙋ́ть, то́кмѡ же́злъ є҆ди́нъ: ни пи́ры, ни хлѣ́ба, ни при по́ѧсѣ мѣ́ди: но ѡ҆бꙋве́ни въ санда́лїѧ: и҆ не ѡ҆блачи́тисѧ въ двѣ̀ ри́зѣ. и҆ глаго́лаше и҆̀мъ: и҆дѣ́же а҆́ще вни́дете въ до́мъ, тꙋ̀ пребыва́йте, до́ндеже и҆зы́дете ѿтꙋ́дꙋ. и҆ є҆ли́цы а҆́ще не прїи́мꙋтъ вы̀, нижѐ послꙋ́шаютъ ва́съ, и҆сходѧ́ще ѿтꙋ́дꙋ, ѿтрѧси́те пра́хъ, и҆́же под̾ нога́ми ва́шими, во свидѣ́тельство и҆̀мъ. а҆ми́нь глаго́лю ва́мъ: ѿра́днѣе бꙋ́детъ содо́мѡмъ и҆ гомо́ррѡмъ въ де́нь сꙋ́дный, не́же гра́дꙋ томꙋ̀. и҆ и҆зше́дше проповѣ́дахꙋ, да пока́ютсѧ: и҆ бѣ́сы мнѡ́ги и҆згонѧ́хꙋ, и҆ ма́захꙋ ма́сломъ мнѡ́ги недꙋ̑жныѧ, и҆ и҆сцѣлѣва́хꙋ. ",
}

add_evangelie_marka {
  ["номер"] = 24,
  ["комментарий"] = "Мк., 24 зач., VI, 14–30.",
  ["текст_ру"] = "Во вре́мя о́но, слы́ша И́род царь слух Иису́сов, я́ве бо бысть и́мя его́, и глаго́лаше, я́ко Иоа́нн Крестя́й от ме́ртвых воста́, и сего́ ра́ди си́лы де́ются о нем. Ини́и глаго́лаху, я́ко Илиа́ есть, ини́и же глаго́лаху, я́ко проро́к есть, или́ я́ко еди́н от проро́к. Слы́шав же И́род рече́, я́ко, его́же аз усе́кнух Иоа́нна, той есть, той воста́ от ме́ртвых. Той бо И́род посла́в, ят Иоа́нна и связа́ его́ в темни́це, Иродиа́ды ра́ди, жены́ Фили́ппа, бра́та своего́, я́ко ожени́ся ею́. Глаго́лаше бо Иоа́нн И́родови: не досто́ит тебе́ име́ти жену́ Фили́ппа, бра́та твоего́. Ироди́я же гне́вашеся на него́ и хотя́ше его́ уби́ти, и не можа́ше. И́род бо боя́шеся Иоа́нна, ве́дый его́ му́жа пра́ведна и свя́та, и соблюда́ше его́, и послу́шав его́, мно́га творя́ше, и в сла́дость его́ послу́шаше. И приклю́чшуся дни потре́бну, егда́ И́род рождеству́ своему́ ве́черю творя́ше, князе́м свои́м, ты́сящником, и старе́йшинам галиле́йским. И вше́дши дщерь тоя́ Иродиа́ды, и пляса́вши, и уго́ждши И́родови и возлежа́щым с ним. Рече́ царь деви́це: проси́ у мене́, е́же а́ще хо́щеши, и дам ти. И кля́тся ей: я́ко а́ще попро́сиши у мене́, дам ти, и до полца́рствия моего́. Она́ же изше́дши рече́ ма́тери свое́й: чесо́ прошу́? Она́ же рече́: главу́ Иоа́нна Крести́теля. И вше́дши а́бие со тща́нием к царю́, проси́, глаго́лющи: хощу́, да ми да́си от него́ на блю́де главу́ Иоа́нна Крести́теля. И приско́рбен быв царь, кля́твы же ра́ди, и за возлежа́щих с ним, не восхоте́ отрещи́ся ея́. И а́бие посла́в царь спекула́тора, повеле́ принести́ главу́ его́. Он же шед усе́кну его́ в темни́це. И принесе́ главу́ его́ на блю́де, и даде́ ю́ деви́це, и деви́ца даде́ ю́ ма́тери свое́й. И слы́шавше ученицы́ его́, приидо́ша и взя́ша труп его́, и положи́ша его́ во гро́бе. И собра́шася апо́столи ко Иису́су, и возвести́ша Ему́ вся, и ели́ка сотвори́ша, и научи́ша. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, слы́ша и҆́рѡдъ ца́рь слꙋ́хъ і҆и҃совъ ꙗ҆́вѣ бо бы́сть и҆́мѧ є҆гѡ̀, и҆ глаго́лаше: ꙗ҆́кѡ і҆ѡа́ннъ крестѧ́й ѿ ме́ртвыхъ воста̀, и҆ сегѡ̀ ра́ди си̑лы дѣ́ютсѧ ѡ҆ не́мъ. и҆ні́и глаго́лахꙋ, ꙗ҆́кѡ и҆лїа̀ є҆́сть, и҆ні́и же глаго́лахꙋ, ꙗ҆́кѡ проро́къ є҆́сть, и҆лѝ ꙗ҆́кѡ є҆ди́нъ ѿ прорѡ́къ. слы́шавъ же и҆́рѡдъ речѐ: ꙗ҆́кѡ є҆го́же а҆́зъ ᲂу҆сѣ́кнꙋхъ і҆ѡа́нна, то́й є҆́сть: то́й воста̀ ѿ ме́ртвыхъ. то́й бо и҆́рѡдъ посла́въ ꙗ҆́тъ і҆ѡа́нна, и҆ свѧза̀ є҆го̀ въ темни́цѣ, и҆рѡдїа́ды ра́ди, жены̀ фїлі́ппа бра́та своегѡ̀, ꙗ҆́кѡ ѡ҆жени́сѧ є҆́ю. глаго́лаше бо і҆ѡа́ннъ и҆́рѡдови: не досто́итъ тебѣ̀ и҆мѣ́ти женꙋ̀ фїлі́ппа бра́та твоегѡ̀. и҆рѡді́а же гнѣ́вашесѧ на него̀, и҆ хотѧ́ше є҆го̀ ᲂу҆би́ти. и҆ не можа́ше. и҆́рѡдъ бо боѧ́шесѧ і҆ѡа́нна, вѣ́дый є҆го̀ мꙋ́жа пра́ведна и҆ ст҃а, и҆ соблюда́ше є҆го̀: и҆ послꙋ́шавъ є҆гѡ̀, мнѡ́га творѧ́ше, и҆ въ сла́дость є҆гѡ̀ послꙋ́шаше. и҆ приклю́чшꙋсѧ днѝ потре́бнꙋ, є҆гда̀ и҆́рѡдъ рождествꙋ̀ своемꙋ̀ ве́черю творѧ́ше кнѧзє́мъ свои́мъ, ты́сѧщникѡмъ, и҆ старѣ́йшинамъ галїле́йскимъ: и҆ вше́дши дще́рь тоѧ̀ и҆рѡдїа́ды, и҆ плѧса́вши, и҆ ᲂу҆го́ждши и҆́рѡдови, и҆ возлежа́щымъ съ ни́мъ, речѐ ца́рь дѣви́цѣ: просѝ ᲂу҆ менѐ, є҆́же а҆́ще хо́щеши, и҆ да́мъ тѝ. и҆ клѧ́тсѧ є҆́й: ꙗ҆́кѡ а҆́ще попро́сиши ᲂу҆ менѐ, да́мъ тѝ, и҆ до полца́рствїѧ моегѡ̀. ѻ҆на́ же и҆зше́дши речѐ ма́тери свое́й: чесѡ̀ прошꙋ̀; ѻ҆на́ же речѐ: главꙋ̀ і҆ѡа́нна крести́телѧ. и҆ вше́дши а҆́бїе со тща́нїемъ къ царю̀, просѝ глаго́лющи: хощꙋ̀, да мѝ да́си ѿ негѡ̀ на блю́дѣ главꙋ̀ і҆ѡа́нна крести́телѧ. и҆ приско́рбенъ бы́въ ца́рь, клѧ́твы же ра́ди, и҆ за возлежа́щихъ съ ни́мъ, не восхотѣ̀ ѿрещи́сѧ є҆ѧ̀. и҆ а҆́бїе посла́въ ца́рь спекꙋла́тора, повелѣ̀ принестѝ главꙋ̀ є҆гѡ̀. ѻ҆́нъ же ше́дъ ᲂу҆сѣ́кнꙋ є҆го̀ въ темни́цѣ. и҆ принесѐ главꙋ̀ є҆гѡ̀ на блю́дѣ, и҆ дадѐ ю҆̀ дѣви́цѣ: и҆ дѣви́ца дадѐ ю҆̀ ма́тери свое́й. и҆ слы́шавше ᲂу҆ченицы̀ є҆гѡ̀ прїидо́ша, и҆ взѧ́ша трꙋ́пъ є҆гѡ̀, и҆ положи́ша є҆го̀ во гро́бѣ. и҆ собра́шасѧ а҆пⷭ҇ли ко і҆и҃сꙋ, и҆ возвѣсти́ша є҆мꙋ̀ всѧ̑: и҆ є҆ли̑ка сотвори́ша, и҆ наꙋчи́ша. ",
}

add_evangelie_marka {
  ["номер"] = 25,
  ["комментарий"] = "Мк., 25 зач., VI, 30–45.",
  ["текст_ру"] = "Во вре́мя о́но, собра́шася Апо́столи ко Иису́су и возвести́ша Ему́ вся, и ели́ка сотвори́ша, и ели́ка научи́ша. И рече́ им: прииди́те вы са́ми в пу́сто ме́сто еди́ни и почи́йте ма́ло. Бя́ху бо приходя́щии и отходя́щии мно́зи, и ни я́сти им бе когда́. И идо́ша в пу́сто ме́сто корабле́м еди́ни. И ви́деша их иду́щя, и позна́ша их мно́зи, и пе́ши от всех градо́в стица́хуся та́мо, и предвари́ша их, и снидо́шася к Нему́. И изше́д ви́де Иису́с наро́д мног и милосе́рдова о них, зане́ бя́ху я́ко о́вцы не иму́щыя па́стыря, и нача́т их учи́ти мно́го. И уже́ часу́ мно́гу бы́вшу, присту́пльше к Нему́ ученицы́ Его́, глаго́лаша, я́ко пу́сто есть ме́сто, и уже́ час мног. Отпусти́ их, да ше́дше во окре́стных се́лех и ве́сех ку́пят себе́ хле́бы, не и́мут бо чесо́ я́сти. Он же отвеща́в рече́ им: дади́те им вы я́сти. И глаго́лаша Ему́: да ше́дше ку́пим двема́ сто́ма пе́нязь хле́бы и да́мы им я́сти? Он же рече́ им: коли́ко хле́бы и́мате? Иди́те и ви́дите. И уве́девше глаго́лаша: пять хлеб, и две ры́бе. И повеле́ им посади́ти вся на спо́ды на спо́ды на траве́ зелене́. И возлего́ша на ле́хи на ле́хи по сту и по пяти́десят. И прие́м пять хлеб и две ры́бе, воззре́в на не́бо, благослови́ и преломи́ хле́бы, и дая́ше ученико́м Свои́м, да предлага́ют пред ни́ми, и о́бе ры́бе раздели́ всем. И ядо́ша вси и насы́тишася. И взя́ша укру́хи, двана́десяте ко́шя испо́лнь, и от ры́бу. Бя́ше же я́дших хле́бы я́ко пять ты́сящ муже́й. И а́бие пону́ди ученики́ Своя́ вни́ти в кора́бль и вари́ти Его́ на о́ном полу́ к Вифсаи́де, до́ндеже Сам отпу́стит наро́ды. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, собра́шасѧ а҆пⷭ҇ли ко і҆и҃сꙋ, и҆ возвѣсти́ша є҆мꙋ̀ всѧ̑: и҆ є҆ли̑ка сотвори́ша, и҆ є҆ли̑ка наꙋчи́ша. и҆ речѐ и҆̀мъ: прїиди́те вы̀ са́ми въ пꙋ́сто мѣ́сто є҆ди́ни, и҆ почі́йте ма́лѡ. бѧ́хꙋ бо приходѧ́щїи, и҆ ѿходѧ́щїи мно́зи: и҆ ни ꙗ҆́сти и҆̀мъ бѣ̀ когда̀. и҆ и҆до́ша въ пꙋ́сто мѣ́сто корабле́мъ є҆ди́ни. и҆ ви́дѣша и҆̀хъ и҆дꙋ́щѧ, и҆ позна́ша и҆̀хъ мно́зи: и҆ пѣ́ши ѿ всѣ́хъ градѡ́въ стица́хꙋсѧ та́мѡ, и҆ предвари́ша и҆̀хъ, и҆ снидо́шасѧ къ немꙋ̀. и҆ и҆зше́дъ, ви́дѣ і҆и҃съ наро́дъ мно́гъ, и҆ милосе́рдова ѡ҆ ни́хъ: занѐ бѧ́хꙋ ꙗ҆́кѡ ѻ҆́вцы не и҆мꙋ́щыѧ па́стырѧ: и҆ нача́тъ и҆̀хъ ᲂу҆чи́ти мно́гѡ. и҆ ᲂу҆жѐ часꙋ̀ мно́гꙋ бы́вшꙋ, пристꙋ́пльше къ немꙋ̀ ᲂу҆ченицы̀ є҆гѡ̀, глаго́лаша: ꙗ҆́кѡ пꙋ́сто є҆́сть мѣ́сто, и҆ ᲂу҆жѐ ча́съ мно́гъ. ѿпꙋстѝ и҆̀хъ, да ше́дше во ѻ҆кре́стныхъ се́лѣхъ и҆ ве́сѣхъ, кꙋ́пѧтъ себѣ̀ хлѣ́бы, не и҆́мꙋтъ бо чесѡ̀ ꙗ҆́сти. ѻ҆́нъ же ѿвѣща́въ речѐ и҆̀мъ: дади́те и҆̀мъ вы̀ ꙗ҆́сти. и҆ глаго́лаша є҆мꙋ̀: да ше́дше кꙋ́пимъ двѣма̀ сто́ма пѣ̑нѧзь хлѣ́бы, и҆ да́мы и҆̀мъ ꙗ҆́сти. ѻ҆́нъ же речѐ и҆̀мъ: коли́кѡ хлѣ́бы и҆́мате; и҆ди́те и҆ ви́дите. и҆ ᲂу҆вѣ́дѣвше, глаго́лаша: пѧ́ть хлѣ̑бъ, и҆ двѣ̀ ры́бѣ. и҆ повелѣ̀ и҆̀мъ посади́ти всѧ̑ на спо́ды, на спо́ды, на травѣ̀ зеленѣ̀. и҆ возлего́ша на лѣ́хи, на лѣ́хи, по стꙋ̀ и҆ по пѧти́десѧтъ. и҆ прїе́мъ пѧ́ть хлѣ̑бъ и҆ двѣ̀ ры́бѣ, воззрѣ́въ на нб҃о, благословѝ, и҆ преломѝ хлѣ́бы: и҆ даѧ́ше ᲂу҆ченикѡ́мъ свои́мъ, да предлага́ютъ пред̾ ни́ми: и҆ ѻ҆́бѣ ры́бѣ раздѣлѝ всѣ̑мъ. и҆ ꙗ҆до́ша всѝ, и҆ насы́тишасѧ. и҆ взѧ́ша ᲂу҆крꙋ́хи двана́десѧте кѡ́шѧ и҆спо́лнь: и҆ ѿ ры́бꙋ. бѧ́ше же ꙗ҆́дшихъ хлѣ́бы, ꙗ҆́кѡ пѧ́ть ты́сѧщъ мꙋже́й. и҆ а҆́бїе понꙋ́ди ᲂу҆ченикѝ своѧ̀ вни́ти въ кора́бль, и҆ вари́ти є҆го̀ на ѻ҆́номъ полꙋ̀ къ виѳсаі́дѣ, до́ндеже са́мъ ѿпꙋ́ститъ наро́ды. ",
}

add_evangelie_marka {
  ["номер"] = 26,
  ["комментарий"] = "Мк., 26 зач., VI, 45–53.",
  ["текст_ру"] = "Во вре́мя о́но, пону́ди Иису́с ученики́ Своя́ вни́ти в кора́бль и вари́ти Его́ на он пол к Вифсаи́де, до́ндеже Сам отпу́стит наро́ды. И отре́кся им, и́де в го́ру помоли́тися. И ве́черу бы́вшу, бе кора́бль посреде́ мо́ря, и Сам еди́н на земли́. И ви́де их стра́ждущих в пла́вании, бе бо ветр проти́вен им, и о четве́ртей стра́жи нощне́й прии́де к ним, по мо́рю ходя́й, и хотя́ше мину́ти их. Они́ же ви́девше Его́ ходя́ща по мо́рю, мня́ху призра́к бы́ти и возопи́ша. Вси бо Его́ ви́деша и смути́шася. И а́бие глаго́ла с ни́ми и рече́ им: дерза́йте, Аз есмь, не бо́йтеся. И вни́де к ним в кора́бль, и уле́же ветр. И зело́ и́злиха в себе́ ужаса́хуся и дивля́хуся. Не разуме́ша бо о хле́бех, бе бо се́рдце их окамене́но. И преше́дше приидо́ша в зе́млю Генисаре́тску и приста́ша. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, понꙋ́ди і҆и҃съ ᲂу҆ченикѝ своѧ̀ вни́ти въ кора́бль, и҆ вари́ти є҆го̀ на ѻ҆́номъ полꙋ̀ къ виѳсаі́дѣ, до́ндеже са́мъ ѿпꙋ́ститъ наро́ды. і҆ ѿре́ксѧ и҆̀мъ, и҆́де въ го́рꙋ помоли́тисѧ. и҆ ве́черꙋ бы́вшꙋ, бѣ̀ кора́бль посредѣ̀ мо́рѧ, и҆ са́мъ є҆ди́нъ на землѝ. и҆ ви́дѣ и҆̀хъ стра́ждꙋщихъ въ пла́ванїи, бѣ́ бо вѣ́тръ проти́венъ и҆̀мъ: и҆ ѡ҆ четве́ртѣй стра́жи нощнѣ́й прїи́де къ ни́мъ, по мо́рю ходѧ́й: и҆ хотѧ́ше минꙋ́ти и҆̀хъ. ѻ҆ни́ же ви́дѣвше є҆го̀ ходѧ́ща по мо́рю, мнѧ́хꙋ призра́къ бы́ти: и҆ возопи́ша. вси́ бо є҆го̀ ви́дѣша, и҆ смꙋти́шасѧ. и҆ а҆́бїе глаго́ла съ ни́ми, и҆ речѐ и҆̀мъ: дерза́йте, а҆́зъ є҆́смь, не бо́йтесѧ. и҆ вни́де къ ни́мъ въ кора́бль, и҆ ᲂу҆ле́же вѣ́тръ: и҆ ѕѣлѡ̀ и҆́злиха въ себѣ̀ ᲂу҆жаса́хꙋсѧ, и҆ дивлѧ́хꙋсѧ. не разꙋмѣ́ша бо ѡ҆ хлѣ́бѣхъ: бѣ́ бо се́рдце и҆́хъ ѡ҆камене́но. и҆ преше́дше прїидо́ша въ зе́млю генисаре́тскꙋ: и҆ приста́ша. ",
}

add_evangelie_marka {
  ["номер"] = 27,
  ["комментарий"] = "Мк., 27 зач., VI, 54 - VII, 8.",
  ["текст_ру"] = "Во вре́мя о́но, изше́дшу Иису́сови из корабля́, позна́ша Его́, му́жие земли́ Генисаре́тски, обте́кше всю страну́ ту, нача́ша на одре́х приноси́ти боля́щия, иде́же слы́шаху, я́ко ту есть. И а́може а́ще вхожда́ше в ве́си, или́ во гра́ды, или́ се́ла, на распу́тиях полага́ху неду́жныя и моля́ху Его́, да поне́ воскри́лию ри́зы Его́ прико́снутся, и ели́цы а́ще прикаса́хуся Ему́, спаса́хуся. И собра́шася к Нему́ фарисе́е и не́цыи от кни́жник, прише́дшии от Иерусали́ма, и ви́девше не́кия от учени́к Его́ нечи́стыми рука́ми, си́речь неумове́нными, яду́щих хле́бы, руга́хуся. Фарисе́е бо и вси иуде́е, а́ще не тры́юще умы́ют рук, не ядя́т, держа́ще преда́ния ста́рец, и от то́ржища, а́ще не поку́плются, не ядя́т. И и́на мно́га суть, я́же прия́ша держа́ти, погруже́ния сткля́ницам и чва́ном и котло́м и одро́м. Пото́м же вопроша́ху Его́ фарисе́е и кни́жницы: почто́ ученицы́ Твои́ не хо́дят по преда́нию ста́рец, но неумове́нными рука́ми ядя́т хлеб? Он же отвеща́в рече́ им, я́ко до́бре проро́чествова Иса́иа о вас лицеме́рех, я́коже есть пи́сано: си́и лю́дие устна́ми Мя чтут, се́рдце же их дале́че отстои́т от Мене́, всу́е же чтут Мя, уча́ще уче́нием, за́поведем челове́ческим. Оста́вльше бо за́поведь Бо́жию, держите́ преда́ния челове́ческая. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆зше́дшꙋ і҆и҃сови и҆з̾ кораблѧ̀, позна́ша є҆го̀ мꙋ́жїе землѝ генисаре́тски: ѡ҆бте́кше всю̀ странꙋ̀ тꙋ̀, нача́ша на ѻ҆дрѣ́хъ приноси́ти болѧ́щыѧ, и҆дѣ́же слы́шахꙋ, ꙗ҆́кѡ тꙋ̀ є҆́сть. и҆ а҆́може а҆́ще вхожда́ше въ вє́си, и҆лѝ во гра́ды, и҆лѝ се́ла, на распꙋ́тїѧхъ полага́хꙋ недꙋ̑жныѧ: и҆ молѧ́хꙋ є҆го̀, да понѐ воскри́лїю ри́зы є҆гѡ̀ прико́снꙋтсѧ: и҆ є҆ли́цы а҆́ще прикаса́хꙋсѧ є҆мꙋ̀, спаса́хꙋсѧ. и҆ собра́шасѧ къ немꙋ̀ фарїсе́є, и҆ нѣ́цыи ѿ кни̑жникъ, прише́дшїи ѿ і҆ерꙋсали́ма: и҆ ви́дѣвше нѣ̑кїѧ ѿ ᲂу҆чени̑къ є҆гѡ̀ нечи́стыми рꙋка́ми, си́рѣчь неꙋмове́нными, ꙗ҆дꙋ́щихъ хлѣ́бы: рꙋга́хꙋсѧ. фарїсе́є бо и҆ всѝ і҆ꙋде́є, а҆́ще не тры́юще ᲂу҆мы́ютъ рꙋ́къ, не ꙗ҆дѧ́тъ, держа́ще преда̑нїѧ ста́рєцъ. и҆ ѿ то́ржища а҆́ще не покꙋ́плютсѧ, не ꙗ҆дѧ́тъ. и҆ и҆́на мнѡ́га сꙋ́ть, ꙗ҆̀же прїѧ́ша держа́ти, погрꙋжє́нїѧ стклѧ́ницамъ, и҆ чва́нѡмъ, и҆ котлѡ́мъ, и҆ ѻ҆дрѡ́мъ. пото́мъ же вопроша́хꙋ є҆го̀ фарїсе́є и҆ кни́жницы: почто̀ ᲂу҆чн҃цы̀ твоѝ не хо́дѧтъ по преда́нїю ста́рєцъ, но неꙋмове́нными рꙋка́ми ꙗ҆дѧ́тъ хлѣ́бъ; ѻ҆́нъ же ѿвѣща́въ речѐ и҆̀мъ: ꙗ҆́кѡ до́брѣ проро́чествова и҆са́їа ѡ҆ ва́съ лицемѣ́рѣхъ, ꙗ҆́коже є҆́сть пи́сано: сі́и лю́дїе ᲂу҆стна́ми мѧ̀ чтꙋ́тъ, се́рдце же и҆́хъ дале́че ѿстои́тъ ѿ менѐ. всꙋ́е же чтꙋ́тъ мѧ̀, ᲂу҆ча́ще ᲂу҆че́нїємъ, за́повѣдемъ человѣ́чєскимъ. ѡ҆ста́вльше бо за́повѣдь бж҃їю, держитѐ преда̑нїѧ чл҃вѣ́чєскаѧ. ",
}

add_evangelie_marka {
  ["номер"] = 28,
  ["комментарий"] = "Мк., 28 зач., VII, 5-16.",
  ["текст_ру"] = "Во вре́мя о́но, вопроша́ху Иису́са фарисе́е и кни́жницы: почто́ ученицы́ Твои́ не хо́дят по преда́нию ста́рец, но неумове́нными рука́ми ядя́т хлеб? Он же отвеща́в рече́ им, я́ко до́бре проро́чествова Иса́иа о вас лицеме́рех, я́коже есть пи́сано: си́и лю́дие устна́ми Мя чтут, се́рдце же их дале́че отстои́т от Мене́, всу́е же чтут Мя, уча́ще уче́нием, за́поведем челове́ческим. Оста́вльше бо за́поведь Бо́жию, держите́ преда́ния челове́ческая, креще́ния чва́ном и сткля́ницам, и и́на подо́бна такова́ мно́га творите́. И глаго́лаше им: до́бре отмета́ете за́поведь Бо́жию, да преда́ние ва́ше соблюдете́. Моисе́й бо рече́: чти отца́ твоего́ и ма́терь твою́, и и́же злосло́вит отца́ или́ ма́терь, сме́ртию да у́мрет. Вы же глаго́лете: а́ще рече́т челове́к отцу́ или́ ма́тери, корва́н, е́же есть дар, и́же а́ще по́льзовался еси́ от мене́. И не ктому́ оставля́ете его́ ничесо́же сотвори́ти отцу́ своему́ или́ ма́тери свое́й, преступа́юще сло́во Бо́жие преда́нием ва́шим, е́же преда́сте, и подо́бна такова́ мно́га твори́те. И призва́в весь наро́д, глаго́лаше им: послу́шайте Мене́ вси и разуме́йте. Ничесо́же есть внеу́ду челове́ка входи́мо в онь, е́же мо́жет оскверни́ти его́, но исходя́щая от него́, та суть скверня́щая челове́ка. А́ще кто и́мать у́ши слы́шати, да слы́шит. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, вопроша́хꙋ і҆и҃са фарїсе́є и҆ кни́жницы: почто̀ ᲂу҆чн҃цы̀ твоѝ не хо́дѧтъ по преда́нїю ста́рєцъ, но неꙋмове́нными рꙋка́ми ꙗ҆дѧ́тъ хлѣ́бъ; ѻ҆́нъ же ѿвѣща́въ речѐ и҆̀мъ: ꙗ҆́кѡ до́брѣ проро́чествова и҆са́їа ѡ҆ ва́съ лицемѣ́рѣхъ, ꙗ҆́коже є҆́сть пи́сано: сі́и лю́дїе ᲂу҆стна́ми мѧ̀ чтꙋ́тъ, се́рдце же и҆́хъ дале́че ѿстои́тъ ѿ менѐ. всꙋ́е же чтꙋ́тъ мѧ̀, ᲂу҆ча́ще ᲂу҆че́нїємъ, за́повѣдемъ человѣ́чєскимъ. ѡ҆ста́вльше бо за́повѣдь бж҃їю, держитѐ преда̑нїѧ чл҃вѣ́чєскаѧ: крещє́нїѧ чва́нѡмъ и҆ стклѧ́ницамъ, и҆ и҆́на подѡ́бна такова̀ мнѡ́га творитѐ. и҆ глаго́лаше и҆̀мъ: до́брѣ ѿмета́ете за́повѣдь бж҃їю, да преда́нїе ва́ше соблюдетѐ. мѡѷсе́й бо речѐ: чтѝ ѻ҆тца̀ твоего̀ и҆ ма́терь твою̀, и҆ и҆́же ѕлосло́витъ ѻ҆тца̀ и҆лѝ ма́терь, сме́ртїю да ᲂу҆́мретъ. вы́ же глаго́лете: а҆́ще рече́тъ человѣ́къ ѻ҆тцꙋ̀ и҆лѝ ма́тери, корва́нъ, є҆́же є҆́сть да́ръ, і҆́же а҆́ще по́льзовалсѧ є҆сѝ ѿ менѐ. и҆ не ктомꙋ̀ ѡ҆ставлѧ́ете є҆го̀ ничесо́же сотвори́ти ѻ҆тцꙋ̀ своемꙋ̀ и҆лѝ ма́тери свое́й, престꙋпа́юще сло́во бж҃їе преда́нїемъ ва́шимъ, є҆́же преда́сте: и҆ подѡ́бна такова̀ мнѡ́га творитѐ. и҆ призва́въ ве́сь наро́дъ, глаго́лаше и҆̀мъ: послꙋ́шайте менѐ всѝ, и҆ разꙋмѣ́йте. ничесо́же є҆́сть внѣꙋ́дꙋ человѣ́ка входи́мо въ ѻ҆́нь, є҆́же мо́жетъ ѡ҆скверни́ти є҆го̀: но и҆сходѧ̑щаѧ ѿ негѡ̀, та̑ сꙋ́ть сквернѧ̑щаѧ человѣ́ка. а҆́ще кто̀ и҆́мать ᲂу҆́ши слы́шати, да слы́шитъ. ",
}

add_evangelie_marka {
  ["номер"] = 29,
  ["комментарий"] = "Мк., 29 зач., VII, 14–24.",
  ["текст_ру"] = "Во вре́мя о́но, призва́в Иису́с весь наро́д, глаго́лаше им: послу́шайте Мене́ вси и разуме́йте. Ничесо́же есть внеу́ду челове́ка входи́мо в онь, е́же мо́жет оскверни́ти его́, но исходя́щая от него́, та суть скверня́щая челове́ка. А́ще кто и́мать у́ши слы́шати, да слы́шит. И егда́ вни́де в дом от наро́да, вопроша́ху Его́ ученицы́ Его́ о при́тчи. И глаго́ла им: та́ко ли и вы неразу́мливи есте́? Не разуме́ете ли, я́ко все е́же извне́ входи́мое в челове́ка, не мо́жет оскверни́ти его́? Я́ко не вхо́дит ему́ в се́рдце, но во чре́во, и афедро́ном исхо́дит, истребля́я вся бра́шна. Глаго́лаше же, я́ко исходя́щее от челове́ка, то скверни́т челове́ка. Изутрьу́ду бо от се́рдца челове́ческа помышле́ния зла́я исхо́дят, прелюбодея́ния, любодея́ния, уби́йства, татьбы́, лихои́мства, оби́ды, лука́вствия, лесть, студодея́ния, о́ко лука́во, хула́, горды́ня, безу́мство. Вся сия́ злая изу́трь исхо́дят и скверня́т челове́ка. И отту́ду воста́в, и́де в преде́лы Ти́рски и Сидо́нски. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, призва́въ і҆и҃съ ве́сь наро́дъ, глаго́лаше и҆̀мъ: послꙋ́шайте менѐ всѝ, и҆ разꙋмѣ́йте. ничесо́же є҆́сть внѣꙋ́дꙋ человѣ́ка входи́мо въ ѻ҆́нь, є҆́же мо́жетъ ѡ҆скверни́ти є҆го̀: но и҆сходѧ̑щаѧ ѿ негѡ̀, та̑ сꙋ́ть сквернѧ̑щаѧ человѣ́ка. а҆́ще кто̀ и҆́мать ᲂу҆́ши слы́шати, да слы́шитъ. и҆ є҆гда̀ вни́де въ до́мъ ѿ наро́да, вопроша́хꙋ є҆го̀ ᲂу҆ченицы̀ є҆гѡ̀ ѡ҆ при́тчи. и҆ глаго́ла и҆̀мъ: та́кѡ ли и҆ вы̀ неразꙋ́мливи є҆стѐ; не разꙋмѣ́ете ли, ꙗ҆́кѡ всѐ є҆́же и҆звнѣ̀ входи́мое въ человѣ́ка, не мо́жетъ ѡ҆скверни́ти є҆го̀; ꙗ҆́кѡ не вхо́дитъ є҆мꙋ̀ въ се́рдце, но во чре́во, и҆ а҆федрѡ́номъ и҆схо́дитъ, и҆стреблѧ́ѧ всѧ̑ бра̑шна. глаго́лаше же, ꙗ҆́кѡ и҆сходѧ́щее ѿ человѣ́ка, то̀ скверни́тъ человѣ́ка. и҆з̾ꙋтрьꙋ́дꙋ бо ѿ се́рдца человѣ́ческа помышлє́нїѧ ѕла̑ѧ и҆схо́дѧтъ: прелюбодѣѧ̑нїѧ, любодѣѧ̑нїѧ, ᲂу҆бі̑йства, татьбы̑, лихои̑мства, ѡ҆би̑ды, лꙋка̑вствїѧ, ле́сть, стꙋдодѣѧ̑нїѧ, ѻ҆́ко лꙋка́во, хꙋла̀, горды́нѧ, безꙋ́мство. всѧ̑ сїѧ̑ ѕла̑ѧ и҆з̾ꙋ́трь и҆схо́дѧтъ, и҆ сквернѧ́тъ человѣ́ка. и҆ ѿтꙋ́дꙋ воста́въ и҆́де въ предѣ́лы тѵ́рски и҆ сїдѡ́нски. ",
}

add_evangelie_marka {
  ["номер"] = 30,
  ["комментарий"] = "Мк., 30 зач., VII, 24–30.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с в преде́лы Ти́рски и Сидо́нски, и вшед в дом, никого́же хотя́ше, дабы́ его́ чул, и не мо́же утаи́тися. Слы́шавши бо жена́ о Нем, ея́же дщи имя́ше ду́х нечи́ст, прише́дши припаде́ к нога́ма Его́, жена́ же бе е́ллинска, сирофиники́сса ро́дом, и моля́ше Его́, да бе́са изжене́т из дще́ре ея́. Иису́с же рече́ ей: оста́ви, да пе́рвее насы́тятся ча́да, несть бо добро́ отя́ти хле́ба ча́дом и поврещи́ псом. Она́ же отвеща́вши глаго́ла Ему́: ей, Го́споди, и́бо и пси под трапе́зою ядя́т от крупи́ц дете́й. И рече́ ей: за сие́ сло́во, иди́, изы́де бес из дще́ре твоея́. И ше́дши в дом свой, обре́те бе́са изше́дша и дщерь лежа́щу на одре́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ въ предѣ́лы тѵ́рски и҆ сїдѡ́нски: и҆ вше́дъ въ до́мъ, никого́же хотѧ́ше, дабы̀ є҆го̀ чꙋ́лъ: и҆ не мо́же ᲂу҆таи́тисѧ. слы́шавши бо жена̀ ѡ҆ не́мъ, є҆ѧ́же дщѝ и҆мѧ́ше дꙋ́хъ нечи́стъ, прише́дши припадѐ къ нога́ма є҆гѡ̀: жена́ же бѣ̀ є҆́ллинска, сѷрофїнїкі́сса ро́домъ: и҆ молѧ́ше є҆го̀, да бѣ́са и҆зжене́тъ и҆з̾ дще́ре є҆ѧ̀. і҆и҃съ же речѐ є҆́й: ѡ҆ста́ви, да пе́рвѣе насы́тѧтсѧ ча̑да: нѣ́сть бо добро̀ ѿѧ́ти хлѣ́ба ча́дѡмъ, и҆ поврещѝ псѡ́мъ. ѻ҆на́ же ѿвѣща́вши, глаго́ла є҆мꙋ̀: є҆́й гдⷭ҇и, и҆́бо и҆ псѝ под̾ трапе́зою ꙗ҆дѧ́тъ ѿ крꙋпи́цъ дѣте́й. и҆ речѐ є҆́й: за сїѐ сло́во и҆дѝ, и҆зы́де бѣ́съ и҆з̾ дще́ре твоеѧ̀. и҆ ше́дши въ до́мъ сво́й, ѡ҆брѣ́те бѣ́са и҆зше́дша, и҆ дще́рь лежа́щꙋ на ѻ҆дрѣ̀. ",
}

add_evangelie_marka {
  ["номер"] = 31,
  ["комментарий"] = "Мк., 31 зач., VII, 31–37.",
  ["текст_ру"] = "Во вре́мя о́но, изше́д Иису́с от преде́л Ти́рских и Сидо́нских, прии́де на мо́ре Галиле́йско, между́ преде́лы Декапо́льски. И приведо́ша к Нему́ глу́ха и гугни́ва, и моля́ху Его́, да возложи́т нань ру́ку. И пое́м его́ от наро́да еди́наго, вложи́ пе́рсты Своя́ во у́ши его́, и плю́нув косну́ его́ в язы́к. И воззре́в на не́бо, воздохну́ и глаго́ла ему́: еффафа́, е́же есть разве́рзися. И а́бие разверзо́стася слу́ха его́, и разреши́ся у́за язы́ка его́, и глаго́лаше пра́во. И запрети́ им, да никому́же пове́дят, ели́ко же им Той запреща́ше, па́че и́злиха пропове́даху. И преи́злиха дивля́хуся, глаго́люще: до́бре все твори́т, и глухи́я твори́т слы́шати, и немы́я глаго́лати. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆зше́дъ і҆и҃съ ѿ предѣ̑лъ тѵ́рскихъ и҆ сїдѡ́нскихъ, прїи́де на мо́ре галїле́йско, междꙋ̀ предѣ́лы декапо́льски. и҆ приведо́ша къ немꙋ̀ глꙋ́ха и҆ гꙋгни́ва, и҆ молѧ́хꙋ є҆го̀, да возложи́тъ на́нь рꙋ́кꙋ. и҆ пое́мъ є҆го̀ ѿ наро́да є҆ди́наго, вложѝ пе́рсты своѧ̀ во ᲂу҆́ши є҆гѡ̀: и҆ плю́нꙋвъ, коснꙋ̀ є҆гѡ̀ въ ѧ҆зы́къ. и҆ воззрѣ́въ на не́бо, воздохнꙋ̀, и҆ глаго́ла є҆мꙋ̀: є҆ффаѳа̀, є҆́же є҆́сть, разве́рзисѧ. и҆ а҆́бїе разверзо́стасѧ слꙋ̑ха є҆гѡ̀, и҆ разрѣши́сѧ ᲂу҆́за ѧ҆зы́ка є҆гѡ̀, и҆ глаго́лаше пра́вѡ. и҆ запретѝ и҆̀мъ, да никомꙋ́же повѣ́дѧтъ. є҆ли́кѡ же и҆̀мъ то́й запреща́ше, па́че и҆́злиха проповѣ́дахꙋ. и҆ преи́злиха дивлѧ́хꙋсѧ, глаго́люще: до́брѣ всѐ твори́тъ, и҆ глꙋхі̑ѧ твори́тъ слы́шати, и҆ нѣмы̑ѧ глаго́лати. ",
}

add_evangelie_marka {
  ["номер"] = 32,
  ["комментарий"] = "Мк., 32 зач., VIII, 1-10.",
  ["текст_ру"] = "Во вре́мя о́но, зело́ мно́гу наро́ду су́щу, и не иму́щем чесо́ я́сти, призва́в Иису́с ученики́ Своя́, глаго́ла им: милосе́рдую о наро́де, я́ко уже́ три дни приседя́т Мне и не и́мут чесо́ я́сти, и а́ще отпущу́ их не я́дша в до́мы своя́, ослабе́ют на пути́, мно́зи бо от них издале́ча пришли́ суть. И отвеща́ша Ему́ ученицы́ Его́: отку́ду сих возмо́жет кто зде насы́тити хле́бы в пусты́ни? И вопроси́ их: коли́ко и́мате хле́бы? Они́ же ре́ша: седмь. И повеле́ наро́ду возлещи́ на земли́, и прие́м седмь хле́бы, хвалу́ возда́в, преломи́ и дая́ше ученико́м Свои́м, да предлага́ют, и предложи́ша пред наро́дом. И имя́ху ры́биц ма́ло, и сия́ благослови́в, рече́ предложи́ти и ты́я. Ядо́ша же и насы́тишася, и взя́ша избы́тки укру́х, седмь ко́шниц. Бя́ху же я́дших я́ко четы́ре ты́сящи. И отпусти́ их. И а́бие влез в кора́бль со ученики́ Свои́ми, прии́де во страны́ Далмануфа́нски. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ѕѣлѡ̀ мно́гꙋ наро́дꙋ сꙋ́щꙋ, и҆ не и҆мꙋ́щємъ чесѡ̀ ꙗ҆́сти, призва́въ і҆и҃съ ᲂу҆ченикѝ своѧ̀, глаго́ла и҆̀мъ: млⷭ҇рдꙋю ѡ҆ наро́дѣ, ꙗ҆́кѡ ᲂу҆жѐ трѝ днѝ присѣдѧ́тъ мнѣ̀, и҆ не и҆́мꙋтъ чесѡ̀ ꙗ҆́сти: и҆ а҆́ще ѿпꙋщꙋ̀ и҆̀хъ не ꙗ҆́дшѧ въ до́мы своѧ̀, ѡ҆слабѣ́ютъ на пꙋтѝ: мно́зи бо ѿ ни́хъ и҆здале́ча пришлѝ сꙋ́ть. и҆ ѿвѣща́ша є҆мꙋ̀ ᲂу҆ченицы̀ є҆гѡ̀: ѿкꙋ́дꙋ си́хъ возмо́жетъ кто̀ здѣ̀ насы́тити хлѣ́ба въ пꙋсты́ни; и҆ вопросѝ и҆̀хъ: коли́кѡ и҆́мате хлѣ́бы; ѻ҆ни́ же рѣ́ша: се́дмь. и҆ повелѣ̀ наро́дꙋ возлещѝ на землѝ: и҆ прїе́мъ се́дмь хлѣ́бы, хвалꙋ̀ возда́въ, преломѝ, и҆ даѧ́ше ᲂу҆ченикѡ́мъ свои́мъ, да предлага́ютъ: и҆ предложи́ша пред̾ наро́домъ. и҆ и҆мѧ́хꙋ ры́бицъ ма́лѡ: и҆ сїѧ̑ благослови́въ, речѐ предложи́ти и҆ ты̑ѧ. ꙗ҆до́ша же и҆ насы́тишасѧ: и҆ взѧ́ша и҆збы́тки ᲂу҆крꙋ̑хъ, се́дмь ко́шницъ: бѧ́хꙋ же ꙗ҆́дшихъ ꙗ҆́кѡ четы́ре ты́сѧщи: и҆ ѿпꙋстѝ и҆̀хъ. и҆ а҆́бїе влѣ́зъ въ кора́бль со ᲂу҆ченикѝ свои́ми, прїи́де во страны̀ далманꙋѳа́нски. ",
}

add_evangelie_marka {
  ["номер"] = 33,
  ["комментарий"] = "Мк., 33 зач., VIII, 11–21.",
  ["текст_ру"] = "Во вре́мя о́но, изы́доша фарисе́е и нача́ша стяза́тися со Иису́сом, и́щуще от Него́ зна́мения с небесе́, искуша́юще Его́. И воздохну́в ду́хом Свои́м, глаго́ла: что род сей зна́мения и́щет? Ами́нь глаго́лю вам, а́ще да́стся ро́ду сему́ зна́мение. И оста́вль их, влез па́ки в кора́бль, и и́де на он пол. И забы́ша ученицы́ Его́ взя́ти хле́бы и ра́зве еди́наго хле́ба не имя́ху с собо́ю в корабли́. И преща́ше им, глаго́ля: зри́те, блюди́теся от ква́са фарисе́йска и от ква́са и́родова. И помышля́ху, друг ко дру́гу глаго́люще, я́ко хле́бы не и́мамы. И разуме́в Иису́с, глаго́ла им: что помышля́ете, я́ко хле́бы не и́мате? Не у ли чу́ете, ниже́ разуме́ете? Еще́ ли окамене́но се́рдце ва́ше и́мате? О́чи иму́ще не ви́дите? И у́ши иму́ще не слы́шите? И не по́мните ли, егда́ пять хле́бы преломи́х в пять ты́сящ, коли́ко кош испо́лнь укру́х прия́сте? Глаго́лаша Ему́: двана́десять. Егда́ же седмь в четы́ре ты́сящи, коли́ко ко́шниц исполне́ния укру́х взя́сте? Они́ же ре́ша: седмь. И глаго́ла им: ка́ко не разуме́ете? ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆зыдо́ша фарїсе́и, и҆ нача́ша стѧза́тисѧ со і҆и҃сомъ, и҆́щꙋще ѿ негѡ̀ зна́менїѧ съ небесѐ, и҆скꙋша́юще є҆го̀. и҆ воздохнꙋ́въ дх҃омъ свои́мъ, глаго́ла: что̀ ро́дъ се́й зна́менїѧ и҆́щетъ; а҆ми́нь глаго́лю ва́мъ: а҆́ще да́стсѧ ро́дꙋ семꙋ̀ зна́менїе. и҆ ѡ҆ста́вль и҆̀хъ, влѣ́зъ па́ки въ кора́бль, и҆ и҆́де на ѻ҆́нъ по́лъ. и҆ забы́ша ᲂу҆ченицы̀ є҆гѡ̀ взѧ́ти хлѣ́бы, и҆ ра́звѣ є҆ди́нагѡ хлѣ́ба не и҆мѧ́хꙋ съ собо́ю въ кораблѝ. и҆ преща́ше и҆̀мъ, глаго́лѧ: зри́те, блюди́тесѧ ѿ ква́са фарїсе́йска, и҆ ѿ ква́са и҆́рѡдова. и҆ помышлѧ́хꙋ, дрꙋ́гъ ко дрꙋ́гꙋ глаго́люще: ꙗ҆́кѡ хлѣ́бы не и҆́мамы. и҆ разꙋмѣ́въ і҆и҃съ глаго́ла и҆̀мъ: что̀ помышлѧ́ете, ꙗ҆́кѡ хлѣ́бы не и҆́мате; не ᲂу҆̀ ли чꙋ́ете, нижѐ разꙋмѣ́ете; є҆ще́ ли ѡ҆камене́но се́рдце ва́ше и҆́мате; ѻ҆́чи и҆мꙋ́ще, не ви́дите: и҆ ᲂу҆́ши и҆мꙋ́ще, не слы́шите: и҆ не по́мните ли, є҆гда̀ пѧ́ть хлѣ́бы преломи́хъ въ пѧ́ть ты́сѧщъ, коли́кѡ кѡ́шъ и҆спо́лнь ᲂу҆крꙋ̑хъ прїѧ́сте; глаго́лаша є҆мꙋ̀, двана́десѧть. є҆гда́ же се́дмь въ четы́ре ты́сѧщи, коли́кѡ ко́шницъ и҆сполне́нїѧ ᲂу҆крꙋ̑хъ взѧ́сте; ѻ҆ни́ же рѣ́ша, се́дмь. и҆ глаго́ла и҆̀мъ: ка́кѡ не разꙋмѣ́ете; ",
}

add_evangelie_marka {
  ["номер"] = 34,
  ["комментарий"] = "Мк., 34 зач., VIII, 22–26.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с в Вифсаи́ду, и приведо́ша к Нему́ сле́па, и моля́ху Его́, да его́ ко́снется. И ем за ру́ку слепа́го, изведе́ его́ вон из ве́си, и плю́нув на о́чи его́, и возло́жь ру́це нань, вопроша́ше его́, а́ще что ви́дит? И воззре́в глаго́лаше: ви́жу челове́ки я́ко дре́вие ходя́щя. Пото́м же па́ки возложи́ ру́це на о́чи его́ и сотвори́ его́ прозре́ти, и утвори́ся, и узре́ све́тло все. И посла́ его́ в дом его́, глаго́ля: ни в весь вни́ди, ни пове́ждь кому́ в ве́си. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ въ виѳсаі́дꙋ: и҆ приведо́ша къ немꙋ̀ слѣ́па, и҆ молѧ́хꙋ є҆го̀, да є҆го̀ ко́снетъ. и҆ є҆́мъ за рꙋ́кꙋ слѣпа́го, и҆зведѐ є҆го̀ во́нъ и҆з̾ ве́си: и҆ плю́нꙋвъ на ѻ҆́чи є҆гѡ̀, и҆ возло́жь рꙋ́цѣ на́нь, вопроша́ше є҆го̀: а҆́ще что̀ ви́дитъ; и҆ воззрѣ́въ глаго́лаше: ви́жꙋ человѣ́ки ꙗ҆́кѡ дре́вїе ходѧ́щѧ. пото́мъ же па́ки возложѝ рꙋ́цѣ на ѻ҆́чи є҆гѡ̀, и҆ сотворѝ є҆го̀ прозрѣ́ти: и҆ ᲂу҆твори́сѧ, и҆ ᲂу҆зрѣ̀ свѣ́тлѡ всѐ. и҆ посла̀ є҆го̀ въ до́мъ є҆гѡ̀, глаго́лѧ: ни въ ве́сь вни́ди, ни повѣ́ждь комꙋ̀ въ ве́си. ",
}

add_evangelie_marka {
  ["номер"] = 35,
  ["комментарий"] = "Мк., 35 зач., VIII, 27–31.",
  ["текст_ру"] = "Во вре́мя о́но, изы́де Иису́с и ученицы́ Его́ в ве́си Кесари́и Фили́пповы, и на пути́ вопроша́ше ученики́ Своя́, глаго́ля им: кого́ Мя глаго́лют челове́цы бы́ти? Они́ же отвеща́ша: Иоа́нна Крести́теля, и ини́и Илию́, друзи́и же еди́наго от проро́к. И Той глаго́ла им: вы же кого́ Мя глаго́лете бы́ти? Отвеща́в же Петр глаго́ла Ему́: Ты еси́ Христо́с. И запрети́ им, да никому́же глаго́лют о Нем. И нача́т учи́ти их, я́ко подоба́ет Сы́ну Челове́ческому мно́го пострада́ти, и искуше́ну бы́ти от ста́рец и архиере́й и кни́жник, и убие́ну бы́ти, и в тре́тий день воскре́снути. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆зы́де і҆и҃съ и҆ ᲂу҆ченицы̀ є҆гѡ̀ въ вє́си кесарі́и фїлі́пповы: и҆ на пꙋтѝ вопроша́ше ᲂу҆ченикѝ своѧ̀, глаго́лѧ и҆̀мъ: кого́ мѧ глаго́лютъ человѣ́цы бы́ти; ѻ҆ни́ же ѿвѣща́ша: і҆ѡа́нна крⷭ҇ти́телѧ, и҆ и҆ні́и и҆лїю̀, дрꙋзі́и же є҆ди́наго ѿ прорѡ́къ. и҆ то́й глаго́ла и҆̀мъ: вы́ же кого́ мѧ глаго́лете бы́ти; ѿвѣща́въ же пе́тръ глаго́ла є҆мꙋ̀: ты̀ є҆сѝ хрⷭ҇то́съ. и҆ запретѝ и҆̀мъ, да никомꙋ́же глаго́лютъ ѡ҆ не́мъ. и҆ нача́тъ ᲂу҆чи́ти и҆̀хъ, ꙗ҆́кѡ подоба́етъ сн҃ꙋ чл҃вѣ́ческомꙋ мно́гѡ пострада́ти, и҆ и҆скꙋше́нꙋ бы́ти ѿ ста́рєцъ и҆ а҆рхїерє́й, и҆ кни̑жникъ: и҆ ᲂу҆бїе́нꙋ бы́ти, и҆ въ тре́тїй де́нь воскре́снꙋти. ",
}

add_evangelie_marka {
  ["номер"] = 36,
  ["комментарий"] = "Мк., 36 зач., VIII, 30–34.",
  ["текст_ру"] = "Во вре́мя о́но, запрети́ Иису́с ученико́м Свои́м, да никому́же глаго́лют о Нем. И нача́т учи́ти их, я́ко подоба́ет Сы́ну Челове́ческому мно́го пострада́ти, и искуше́ну бы́ти от ста́рец и архиере́й и кни́жник, и убие́ну бы́ти, и в тре́тий день воскре́снути. И не обину́яся сло́во глаго́лаше. И прие́мь Его́ Петр, нача́т прети́ти Ему́. Он же обра́щься и воззре́в на ученики́ Своя́, запрети́ Петро́ви, глаго́ля: иди́ за Мно́ю, сатано́, я́ко не мы́слиши, я́же суть Бо́жия, но я́же челове́ческа. И призва́в наро́ды со ученики́ Свои́ми, рече́ им: и́же хо́щет по Мне ити́, да отве́ржется себе́, и во́змет крест свой, и по Мне гряде́т. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, запретѝ і҆и҃съ ᲂу҆ченикѡ́мъ свои́мъ, да никомꙋ́же глаго́лютъ ѡ҆ не́мъ. и҆ нача́тъ ᲂу҆чи́ти и҆̀хъ, ꙗ҆́кѡ подоба́етъ сн҃ꙋ чл҃вѣ́ческомꙋ мно́гѡ пострада́ти, и҆ и҆скꙋше́нꙋ бы́ти ѿ ста́рєцъ и҆ а҆рхїерє́й, и҆ кни̑жникъ: и҆ ᲂу҆бїе́нꙋ бы́ти, и҆ въ тре́тїй де́нь воскре́снꙋти. и҆ не ѡ҆бинꙋ́ѧсѧ сло́во глаго́лаше: и҆ прїе́мъ є҆го̀ пе́тръ, нача́тъ прети́ти є҆мꙋ̀. ѻ҆́нъ же ѡ҆бра́щсѧ, и҆ воззрѣ́въ на ᲂу҆чн҃кѝ своѧ̀, запретѝ петро́ви, глаго́лѧ: и҆дѝ за мно́ю сатано̀, ꙗ҆́кѡ не мы́слиши ꙗ҆̀же сꙋ́ть бж҃їѧ, но ꙗ҆̀же человѣ́чєска. и҆ призва́въ наро́ды со ᲂу҆ченикѝ свои́ми, речѐ и҆̀мъ: и҆́же хо́щетъ по мнѣ̀ и҆тѝ, да ѿве́ржетсѧ себѐ, и҆ во́з̾метъ крⷭ҇тъ сво́й, и҆ по мнѣ̀ грѧде́тъ. ",
}

add_evangelie_marka {
  ["номер"] = 37,
  ["комментарий"] = "Мк., 37 зач., VIII, 34 – IX, 1.",
  ["текст_ру"] = "Рече́ Госпо́дь: и́же хо́щет по Мне ити́, да отве́ржется себе́, и во́змет крест свой, и по Мне гряде́т. И́же бо а́ще хо́щет ду́шу свою́ спасти́, погуби́т ю́, а и́же погуби́т ду́шу свою́ Мене́ ра́ди и Ева́нгелиа, той спасе́т ю́. Ка́я бо по́льза челове́ку, а́ще приобря́щет мир весь, и отщети́т ду́шу свою́? Или́ что даст челове́к изме́ну на души́ свое́й? И́же бо а́ще постыди́тся Мене́ и Мои́х слове́с в ро́де сем прелюбоде́йнем и гре́шнем, и Сын Челове́ческий постыди́тся его́, егда́ прии́дет во сла́ве Отца́ Своего́ со А́нгелы святы́ми. И глаго́лаше им: ами́нь глаго́лю вам, я́ко суть не́цыи от зде стоя́щих, и́же не и́мут вкуси́ти сме́рти, до́ндеже ви́дят Ца́рствие Бо́жие прише́дшее в си́ле. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: и҆́же хо́щетъ по мнѣ̀ и҆тѝ, да ѿве́ржетсѧ себѐ, и҆ во́з̾метъ крⷭ҇тъ сво́й, и҆ по мнѣ̀ грѧде́тъ. и҆́же бо а҆́ще хо́щетъ дꙋ́шꙋ свою̀ спастѝ, погꙋби́тъ ю҆̀: а҆ и҆́же погꙋби́тъ дꙋ́шꙋ свою̀ менѐ ра́ди и҆ є҆ѵⷢ҇лїа, то́й спасе́тъ ю҆̀. ка́ѧ бо по́льза чл҃вѣ́кꙋ, а҆́ще прїѡбрѧ́щетъ мі́ръ ве́сь, и҆ ѿтщети́тъ дꙋ́шꙋ свою̀; и҆лѝ что̀ да́стъ чл҃вѣ́къ и҆змѣ́нꙋ на дꙋшѝ свое́й; и҆́же бо а҆́ще постыди́тсѧ менѐ, и҆ мои́хъ слове́съ, въ ро́дѣ се́мъ прелюбодѣ́йнѣмъ и҆ грѣ́шнѣмъ, и҆ сн҃ъ человѣ́ческїй постыди́тсѧ є҆гѡ̀, є҆гда̀ прїи́детъ во сла́вѣ ѻ҆ц҃а̀ своегѡ̀ со а҆́гг҃лы ст҃ы́ми. и҆ глаго́лаше и҆̀мъ: а҆ми́нь глаго́лю ва́мъ: ꙗ҆́кѡ сꙋ́ть нѣ́цыи ѿ здѣ̀ стоѧ́щихъ, и҆̀же не и҆́мꙋтъ вкꙋси́ти сме́рти, до́ндеже ви́дѧтъ црⷭ҇твїе бж҃їе прише́дшее въ си́лѣ. ",
}

add_evangelie_marka {
  ["номер"] = 38,
  ["комментарий"] = "Мк., 38 зач., IX, 2-9.",
  ["текст_ру"] = "Во вре́мя о́но, поя́т Иису́с Петра́ и Иа́кова и Иоа́нна, и возведе́ их на гору́ высоку́ осо́бь еди́ны, и преобрази́ся пред ни́ми. И ри́зы Его́ бы́ша блеща́щяся, белы́ зело́ я́ко снег, яце́х же не мо́жет бели́льник убели́ти на земли́. И яви́ся им Илиа́ с Моисе́ем, и бе́ста со Иису́сом глаго́люще. И отвеща́в Петр глаго́ла Иису́сови: Равви́, добро́ есть нам зде бы́ти, и сотвори́м кро́вы три, Тебе́ еди́н, и Моисе́еви еди́н, и Илии́ еди́н. Не ве́дяше бо, что рещи́, бя́ху бо пристра́шни. И бысть о́блак осеня́я их, и прии́де глас из о́блака, глаго́ля: Сей есть Сын Мой возлю́бленный, Того́ послу́шайте. И внеза́пу воззре́вше, ктому́ никого́же ви́деша, то́кмо Иису́са еди́наго с собо́ю. Сходя́щым же им с горы́, запрети́ им, да никому́же пове́дят, я́же ви́деша, то́кмо егда́ Сын Челове́ческий из ме́ртвых воскре́снет. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, поѧ́тъ і҆и҃съ петра̀, и҆ і҆а́кѡва, и҆ і҆ѡа́нна, и҆ возведѐ и҆̀хъ на горꙋ̀ высокꙋ̀ ѻ҆со́бь є҆ди́ны: и҆ преѡбрази́сѧ пред̾ ни́ми. и҆ ри̑зы є҆гѡ̀ бы́ша блеща́щѧсѧ, бѣлы̀ ѕѣлѡ̀ ꙗ҆́кѡ снѣ́гъ, ꙗ҆цѣ́хъ же не мо́жетъ бѣли́льникъ ᲂу҆бѣли́ти на землѝ. и҆ ꙗ҆ви́сѧ и҆̀мъ и҆лїа̀ съ мѡѷсе́емъ, и҆ бѣ́ста со і҆и҃сомъ глаго́люще. и҆ ѿвѣща́въ пе́тръ глаго́ла і҆и҃сови: равві̀, добро̀ є҆́сть на́мъ здѣ̀ бы́ти: и҆ сотвори́мъ кро́вы трѝ, тебѣ̀ є҆ди́нъ, и҆ мѡѷсе́еви є҆ди́нъ, и҆ и҆лїѝ є҆ди́нъ. не вѣ́дѧше бо что̀ рещѝ: бѧ́хꙋ бо пристра́шни. и҆ бы́сть ѻ҆́блакъ ѡ҆сѣнѧ́ѧ и҆̀хъ, и҆ прїи́де гла́съ и҆з̾ ѻ҆́блака, глаго́лѧ: се́й є҆́сть сн҃ъ мо́й возлю́бленный, тогѡ̀ послꙋ́шайте. и҆ внеза́пꙋ воззрѣ́вше, ктомꙋ̀ никого́же ви́дѣша, то́кмѡ і҆и҃са є҆ди́наго съ собо́ю. сходѧ́щымъ же и҆̀мъ съ горы̀ запретѝ и҆̀мъ, да никомꙋ́же повѣ́дѧтъ ꙗ҆̀же ви́дѣша, то́кмѡ є҆гда̀ сн҃ъ человѣ́ческїй и҆з̾ ме́ртвыхъ воскрⷭ҇нетъ. ",
}

add_evangelie_marka {
  ["номер"] = 39,
  ["комментарий"] = "Мк., 39 зач., IX, 10–16.",
  ["текст_ру"] = "Во вре́мя о́но, удержа́ша в себе́ ученицы́ сло́во Иису́сово, стяза́ющеся, что есть, е́же из ме́ртвых воскре́снути. И вопроша́ху Его́ глаго́люще: ка́ко глаго́лют кни́жницы, я́ко Илии́ подоба́ет приити́ пре́жде? Он же отвеща́в рече́ им: Илиа́ у́бо прише́д пре́жде, устро́ит вся, и ка́ко есть пи́сано о Сы́не Челове́честем, да мно́го постра́ждет и уничиже́н бу́дет, но глаго́лю вам, я́ко и Илиа́ прии́де, и сотвори́ша ему́, ели́ка хоте́ша, я́коже есть пи́сано о нем. И прише́д ко ученико́м, ви́де наро́д мног о них и кни́жники стяза́ющяся с ни́ми. И а́бие весь наро́д ви́дев Его́ ужасе́ся, и прири́щуще целова́ху Его́. И вопроси́ кни́жники: что стяза́етеся к себе́? ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ᲂу҆держа́ша въ себѣ̀ ᲂу҆ченицы̀ сло́во і҆и҃сово, стѧза́ющесѧ: что̀ є҆́сть, є҆́же и҆з̾ ме́ртвыхъ воскре́снꙋти; и҆ вопроша́хꙋ є҆го̀, глаго́люще: ка́кѡ глаго́лютъ кни́жницы, ꙗ҆́кѡ и҆лїѝ подоба́етъ прїитѝ пре́жде; ѻ҆́нъ же ѿвѣща́въ речѐ и҆̀мъ: и҆лїа̀ ᲂу҆́бѡ прише́дъ пре́жде, ᲂу҆стро́итъ всѧ̑: и҆ ка́кѡ є҆́сть пи́сано ѡ҆ сн҃ѣ чл҃вѣ́честѣмъ, да мно́гѡ постра́ждетъ, и҆ ᲂу҆ничиже́нъ бꙋ́детъ; но глаго́лю ва́мъ, ꙗ҆́кѡ и҆ и҆лїа̀ прїи́де, и҆ сотвори́ша є҆мꙋ̀ є҆ли̑ка хотѣ́ша, ꙗ҆́коже є҆́сть пи́сано ѡ҆ не́мъ. и҆ прише́дъ ко ᲂу҆ченикѡ́мъ, ви́дѣ наро́дъ мно́гъ ѡ҆ ни́хъ, и҆ кни́жники стѧза́ющѧсѧ съ ни́ми. и҆ а҆́бїе ве́сь наро́дъ ви́дѣвъ є҆го̀, ᲂу҆жасе́сѧ: и҆ прири́щꙋще цѣлова́хꙋ є҆го̀. и҆ вопросѝ кни́жники: что̀ стѧза́етесѧ къ себѣ̀; ",
}

add_evangelie_marka {
  ["номер"] = 40,
  ["комментарий"] = "Мк., 40 зач., IX, 17–31.",
  ["текст_ру"] = "Во вре́мя о́но, челове́к не́кий прии́де ко Иису́сови, кла́няяся Ему́, и глаго́ля: Учи́телю, приведо́х сы́на моего́ к Тебе́, иму́ща ду́ха не́ма, и иде́же коли́ждо и́мет его́, разбива́ет его́, и пе́ны тещи́т, и скреже́щет зубы́ свои́ми, и оцепенева́ет, и рех ученико́м Твои́м, да изжену́т его́, и не возмого́ша. Он же отвеща́в ему́ глаго́ла: о, ро́де неве́рен, доко́ле в вас бу́ду? Доко́ле терплю́ вы? Приведи́те его́ ко Мне. И приведо́ша его́ к Нему́. И ви́дев Его́, а́бие дух стрясе́ его́, и пад на земли́, валя́шеся, пе́ны тещя́. И вопроси́ отца́ его́: коли́ко лет есть, отне́леже сие́ бысть ему́? Он же рече́: изде́тска. И мно́гажды во огнь вве́рже его́ и в во́ды, да погуби́т его́, но а́ще что мо́жеши, помози́ нам, милосе́рдовав о нас. Иису́с же рече́ ему́: е́же а́ще что мо́жеши ве́ровати, вся возмо́жна ве́рующему. И а́бие возопи́в оте́ц отроча́те, со слеза́ми глаго́лаше: ве́рую, Го́споди, помози́ моему́ неве́рию. Ви́дев же Иису́с, я́ко сри́щется наро́д, запрети́ ду́ху нечи́стому, глаго́ля ему́: ду́ше немы́й и глухи́й, Аз ти повелева́ю, изы́ди из него́ и ктому́ не вни́ди в него́. И возопи́в и мно́го пружа́вся, изы́де, и бысть я́ко мертв, я́коже мно́зем глаго́лати, я́ко у́мре. Иису́с же емь его́ за ру́ку, воздви́же его́, и воста́. И вше́дшу Ему́ в дом, ученицы́ Его́ вопроша́ху Его́ еди́наго, я́ко мы не возмого́хом изгна́ти его́? И рече́ им: сей род ничи́мже мо́жет изы́ти, то́кмо моли́твою и посто́м. И отту́ду изше́дше, идя́ху сквозе́ Галиле́ю, и не хотя́ше, да кто уве́сть. Уча́ше бо ученики́ Своя́ и глаго́лаше им, я́ко Сын Челове́ческий пре́дан бу́дет в ру́це челове́честе, и убию́т Его́, и убие́н быв, в тре́тий день воскре́снет. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, человѣ́къ нѣ́кїй прїи́де ко і҆и҃сови, кла́нѧѧсѧ є҆мꙋ̀, и҆ глаго́лѧ: ᲂу҆чи́телю, приведо́хъ сы́на моего̀ къ тебѣ̀, и҆мꙋ́ща дꙋ́ха нѣ́ма. и҆ и҆дѣ́же коли́ждо и҆́метъ є҆го̀, разбива́етъ є҆го̀, и҆ пѣ̑ны тещи́тъ, и҆ скреже́щетъ зꙋбы̀ свои́ми, и҆ ѡ҆цѣпенѣва́етъ, и҆ рѣ́хъ ᲂу҆ченикѡ́мъ твои́мъ, да и҆зженꙋ́тъ є҆го̀, и҆ не возмого́ша. ѻ҆́нъ же ѿвѣща́въ є҆мꙋ̀ глаго́ла: ѽ ро́де невѣ́ренъ, доко́лѣ въ ва́съ бꙋ́дꙋ; доко́лѣ терплю̀ вы̀; приведи́те є҆го̀ ко мнѣ̀. и҆ приведо́ша є҆го̀ къ немꙋ̀: и҆ ви́дѣвъ є҆го̀, а҆́бїе дꙋ́хъ стрѧсѐ є҆го̀: и҆ па́дъ на землѝ, валѧ́шесѧ пѣ̑ны тещѧ̀. и҆ вопросѝ ѻ҆тца̀ є҆гѡ̀: коли́кѡ лѣ́тъ є҆́сть, ѿне́лѣже сїѐ бы́сть є҆мꙋ̀; ѻ҆́нъ же речѐ, и҆здѣ́тска. и҆ мно́гажды во ѻ҆́гнь вве́рже є҆го̀, и҆ въ во́ды, да погꙋби́тъ є҆го̀: но а҆́ще что̀ мо́жеши, помозѝ на́мъ, млⷭ҇рдовавъ ѡ҆ на́съ. і҆и҃съ же речѐ є҆мꙋ̀: є҆́же а҆́ще что̀ мо́жеши вѣ́ровати, всѧ̑ возмѡ́жна вѣ́рꙋющемꙋ. и҆ а҆́бїе возопи́въ ѻ҆те́цъ ѻ҆троча́те, со слеза́ми глаго́лаше: вѣ́рꙋю гдⷭ҇и, помозѝ моемꙋ̀ невѣ́рїю. ви́дѣвъ же і҆и҃съ, ꙗ҆́кѡ сри́щетсѧ наро́дъ, запретѝ дꙋ́хꙋ нечи́стомꙋ, глаго́лѧ є҆мꙋ̀: дꙋ́ше нѣмы́й и҆ глꙋхі́й, а҆́зъ тѝ повелѣва́ю, и҆зы́ди и҆з̾ негѡ̀, и҆ ктомꙋ̀ не вни́ди въ него̀. и҆ возопи́въ, и҆ мно́гѡ прꙋжа́всѧ, и҆зы́де: и҆ бы́сть ꙗ҆́кѡ ме́ртвъ, ꙗ҆́коже мно́зѣмъ глаго́лати, ꙗ҆́кѡ ᲂу҆́мре. і҆и҃съ же є҆́мъ є҆го̀ за рꙋ́кꙋ, воздви́же є҆го̀: и҆ воста̀. и҆ вше́дшꙋ є҆мꙋ̀ въ до́мъ, ᲂу҆ченицы̀ є҆гѡ̀ вопроша́хꙋ є҆го̀ є҆ди́наго: ꙗ҆́кѡ мы̀ не возмого́хомъ и҆згна́ти є҆го̀; и҆ речѐ и҆̀мъ: се́й ро́дъ ничи́мже мо́жетъ и҆зы́ти, то́кмѡ моли́твою и҆ посто́мъ. и҆ ѿтꙋ́дꙋ и҆зше́дше, и҆дѧ́хꙋ сквозѣ̀ галїле́ю: и҆ не хотѧ́ше, да кто̀ ᲂу҆вѣ́сть. ᲂу҆ча́ше бо ᲂу҆чн҃кѝ своѧ̀, и҆ глаго́лаше и҆̀мъ: ꙗ҆́кѡ сн҃ъ чл҃вѣ́ческїй пре́данъ бꙋ́детъ въ рꙋ́цѣ чл҃вѣ́честѣ, и҆ ᲂу҆бїю́тъ є҆го̀: и҆ ᲂу҆бїе́нъ бы́въ, въ тре́тїй де́нь воскре́снетъ. ",
}

add_evangelie_marka {
  ["номер"] = 41,
  ["комментарий"] = "Мк., 41 зач., IX, 33–41.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с и ученицы́ Его́ в Капернау́м, и в дому́ быв, вопроша́ше их: что на пути́ в себе́ помышля́сте? Они́ же молча́ху, друг ко дру́гу бо стяза́шася на пути́, кто есть бо́лий. И сед пригласи́ обана́десяте и глаго́ла им: а́ще кто хо́щет ста́рей бы́ти, да бу́дет всех ме́ньший и всем слуга́. И прии́мь отроча́, поста́ви е́ посреде́ их, и обе́м е́, рече́ им: и́же а́ще еди́но таковы́х отроча́т прии́мет во и́мя Мое́, Мене́ прие́млет, и и́же Мене́ прие́млет, не Мене́ прие́млет, но Посла́вшаго Мя. Отвеща́ Ему́ Иоа́нн, глаго́ля: Учи́телю, ви́дехом не́коего и́менем Твои́м изгоня́ща бе́сы, и́же не хо́дит по нас, и возбрани́хом ему́, я́ко не после́дует нам. Иису́с же рече́: не брани́те ему́, никто́же бо есть, и́же сотвори́т си́лу о и́мени Мое́м, и возмо́жет вско́ре злосло́вити Мя. И́же бо несть на вы, по вас есть. И́же бо а́ще напои́т вы ча́шею воды́ во и́мя Мое́, я́ко Христо́вы есте́, ами́нь глаго́лю вам, не погуби́т мзды своея́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ и҆ ᲂу҆ченицы̀ є҆гѡ̀ въ капернаꙋ́мъ: и҆ въ домꙋ̀ бы́въ, вопроша́ше и҆̀хъ, что̀ на пꙋтѝ въ себѣ̀ помышлѧ́сте, ѻ҆ни́ же молча́хꙋ: дрꙋ́гъ ко дрꙋ́гꙋ бо стѧза́шасѧ на пꙋтѝ, кто́ є҆сть бо́лїй; и҆ сѣ́дъ пригласѝ ѻ҆бана́десѧте, и҆ глаго́ла и҆̀мъ: а҆́ще кто̀ хо́щетъ ста́рѣй бы́ти, да бꙋ́детъ всѣ́хъ ме́ньшїй, и҆ всѣ̑мъ слꙋга̀. и҆ прїи́мъ ѻ҆троча̀, поста́ви є҆̀ посредѣ̀ и҆́хъ, и҆ ѡ҆б̾е́мъ є҆̀, речѐ и҆̀мъ: и҆́же а҆́ще є҆ди́но таковы́хъ ѻ҆троча́тъ прїи́метъ во и҆́мѧ моѐ, менѐ прїе́млетъ: и҆ и҆́же менѐ прїе́млетъ, не менѐ прїе́млетъ, но посла́вшаго мѧ̀. ѿвѣща̀ є҆мꙋ̀ і҆ѡа́ннъ, глаго́лѧ: ᲂу҆чт҃лю, ви́дѣхомъ нѣ́коего и҆́менемъ твои́мъ и҆згонѧ́ща бѣ́сы, и҆́же не хо́дитъ по на́съ: и҆ возбрани́хомъ є҆мꙋ̀, ꙗ҆́кѡ не послѣ́дꙋетъ на́мъ. і҆и҃съ же речѐ, не брани́те є҆мꙋ̀: никто́же бо є҆́сть, и҆́же сотвори́тъ си́лꙋ ѡ҆ и҆́мени мое́мъ, и҆ возмо́жетъ вско́рѣ ѕлосло́вити мѧ̀. и҆́же бо нѣ́сть на вы̀, по ва́съ є҆́сть. и҆́же бо а҆́ще напои́тъ вы̀, ча́шꙋ воды̀ во и҆́мѧ моѐ, ꙗ҆́кѡ хрⷭ҇то́вы є҆стѐ: а҆ми́нь глаго́лю ва́мъ, не погꙋби́тъ мзды̀ своеѧ̀. ",
}

add_evangelie_marka {
  ["номер"] = 42,
  ["комментарий"] = "Мк., 42 зач., IX, 42 – X, 1.",
  ["текст_ру"] = "Рече́ Госпо́дь: и́же а́ще соблазни́т еди́наго от ма́лых сих ве́рующих в Мя, до́брее есть ему́ па́че, а́ще облежи́т ка́мень же́рновный о вы́и его́, и вве́ржен бу́дет в мо́ре. И а́ще соблажня́ет тя рука́ твоя́, отсецы́ ю́, до́бре ти есть бе́днику в живо́т вни́ти, не́же о́бе ру́це иму́щу вни́ти в гее́нну, во огнь неугаса́ющий, иде́же червь их не умира́ет, и огнь не угаса́ет. И а́ще нога́ твоя́ соблажня́ет тя, отсецы́ ю́, до́бре ти есть вни́ти в живо́т хро́му, не́же две но́зе иму́щу вве́ржену бы́ти в гее́нну, во огнь неугаса́ющий, иде́же червь их не умира́ет, и огнь не угаса́ет. И а́ще о́ко твое́ соблажня́ет тя, исткни́ е́, до́бре ти есть со еди́нем о́ком вни́ти в Ца́рствие Бо́жие, не́же две о́це иму́щу вве́ржену бы́ти в гее́нну о́гненную, иде́же червь их не умира́ет, и огнь не угаса́ет. Всяк бо огне́м осоли́тся, и вся́ка же́ртва со́лию осоли́тся. Добро́ соль, а́ще же соль не слана́ бу́дет, чим осоли́тся? Име́йте соль в себе́, и мир име́йте между́ собо́ю. И отту́ду воста́ пре́йде в преде́лы Иуде́йския, чрез страну́ я́же об он пол Иорда́на. И снидо́шася па́ки наро́ди к Нему́, и я́ко обы́чай име́, па́ки уча́ше их. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: и҆́же а҆́ще соблазни́тъ є҆ди́наго ѿ ма́лыхъ си́хъ вѣ́рꙋющихъ въ мѧ̀, до́брѣе є҆́сть є҆мꙋ̀ па́че, а҆́ще ѡ҆блежи́тъ ка́мень же́рновный ѡ҆ вы́и є҆гѡ̀, и҆ вве́рженъ бꙋ́детъ въ мо́ре. и҆ а҆́ще соблажнѧ́етъ тѧ̀ рꙋка̀ твоѧ̀, ѿсѣцы̀ ю҆̀: до́брѣ тѝ є҆́сть бѣ́дникꙋ въ живо́тъ вни́ти, не́же ѻ҆́бѣ рꙋ́цѣ и҆мꙋ́щꙋ вни́ти въ гее́ннꙋ, во ѻ҆́гнь неꙋгаса́ющїй: и҆дѣ́же че́рвь и҆́хъ не ᲂу҆мира́етъ, и҆ ѻ҆́гнь не ᲂу҆гаса́етъ. и҆ а҆́ще нога̀ твоѧ̀ соблажнѧ́етъ тѧ̀, ѿсѣцы̀ ю҆̀: до́брѣ тѝ є҆́сть вни́ти въ живо́тъ хро́мꙋ, не́же двѣ̀ но́зѣ и҆мꙋ́щꙋ, вве́рженꙋ бы́ти въ гее́ннꙋ, во ѻ҆́гнь неꙋгаса́ющїй: и҆дѣ́же че́рвь и҆́хъ не ᲂу҆мира́етъ, и҆ ѻ҆́гнь не ᲂу҆гаса́етъ. и҆ а҆́ще ѻ҆́ко твоѐ соблажнѧ́етъ тѧ̀, и҆сткнѝ є҆̀: до́брѣ тѝ є҆́сть со є҆ди́нѣмъ ѻ҆́комъ вни́ти въ црⷭ҇твїе бж҃їе, не́же двѣ̀ ѻ҆́цѣ и҆мꙋ́щꙋ вве́рженꙋ бы́ти въ гее́ннꙋ ѻ҆́гненнꙋю: и҆дѣ́же че́рвь и҆́хъ не ᲂу҆мира́етъ, и҆ ѻ҆́гнь не ᲂу҆гаса́етъ. всѧ́къ бо ѻ҆гне́мъ ѡ҆соли́тсѧ: и҆ всѧ́ка же́ртва со́лїю ѡ҆соли́тсѧ. добро̀ со́ль: а҆́ще же со́ль не слана̀ бꙋ́детъ, чи́мъ ѡ҆соли́тсѧ; и҆мѣ́йте со́ль въ себѣ̀, и҆ ми́ръ и҆мѣ́йте междꙋ̀ собо́ю. и҆ ѿтꙋ́дꙋ воста̀ пре́йде въ предѣ́лы і҆ꙋде́йскїѧ, чрез̾ странꙋ̀ ꙗ҆́же ѡ҆б̾ ѻ҆́нъ по́лъ і҆ѻрда́на. и҆ снидо́шасѧ па́ки наро́ди къ немꙋ̀, и҆ ꙗ҆́кѡ ѻ҆бы́чай и҆мѣ̀, па́ки ᲂу҆ча́ше и҆̀хъ. ",
}

add_evangelie_marka {
  ["номер"] = 43,
  ["комментарий"] = "Мк., 43 зач., X, 2–12.",
  ["текст_ру"] = "Во вре́мя о́но, присту́пльше фарисе́е вопроси́ша Иису́са: а́ще досто́ит му́жу жену́ пусти́ти? Искуша́юще Его́. Он же отвеща́в рече́ им: что вам запове́да Моисе́й? Они́ же ре́ша: Моисе́й повеле́ кни́гу распу́стную написа́ти, и пусти́ти. И отвеща́в Иису́с рече́ им: по жестосе́рдию ва́шему написа́ вам за́поведь сию́. От зача́ла же созда́ния, му́жа и жену́ сотвори́л я́ есть Бог. Сего́ ра́ди оста́вит челове́к отца́ своего́ и ма́терь и прилепи́тся к жене́ свое́й, и бу́дета о́ба в плоть еди́ну. Те́мже уже́ не́ста два, но плоть еди́на. Е́же у́бо Бог сочета́, челове́к да не разлуча́ет. И в дому́ па́ки ученицы́ Его́ о сем вопроси́ша Его́. И глаго́ла им: и́же а́ще пу́стит жену́ свою́ и оже́нится ино́ю, прелюбы́ твори́т на ню. И а́ще жена́ пу́стит му́жа своего́ и пося́гнет за ино́го, прелюбы́ твори́т. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋ́пльше фарїсе́є вопроси́ша і҆и҃са: а҆́ще досто́итъ мꙋ́жꙋ женꙋ̀ пꙋсти́ти; и҆скꙋша́юще є҆го̀. ѻ҆́нъ же ѿвѣща́въ речѐ и҆̀мъ: что̀ ва́мъ заповѣ́да мѡѷсе́й; ѻ҆ни́ же рѣ́ша: мѡѷсе́й повелѣ̀ кни́гꙋ распꙋ́стнꙋю написа́ти, и҆ пꙋсти́ти. и҆ ѿвѣща́въ і҆и҃съ речѐ и҆̀мъ: по жестосе́рдїю ва́шемꙋ написа̀ ва́мъ за́повѣдь сїю̀. ѿ зача́ла же созда́нїѧ, мꙋ́жа и҆ женꙋ̀ сотвори́лъ ѧ҆̀ є҆́сть бг҃ъ. сегѡ̀ ра́ди ѡ҆ста́витъ человѣ́къ ѻ҆тца̀ своего̀ и҆ ма́терь, и҆ прилѣпи́тсѧ къ женѣ̀ свое́й, и҆ бꙋ́дета ѻ҆́ба въ пло́ть є҆ди́нꙋ. тѣ́мже ᲂу҆жѐ нѣ́ста два̀, но пло́ть є҆ди́на. є҆́же ᲂу҆́бѡ бг҃ъ сочета̀, человѣ́къ да не разлꙋча́етъ. и҆ въ домꙋ̀ па́ки ᲂу҆ченицы̀ є҆гѡ̀ ѡ҆ се́мъ вопроси́ша є҆го̀. и҆ глаго́ла и҆̀мъ: и҆́же а҆́ще пꙋ́ститъ женꙋ̀ свою̀, и҆ ѡ҆же́нитсѧ и҆но́ю, прелюбы̀ твори́тъ на ню̀. и҆ а҆́ще жена̀ пꙋ́ститъ мꙋ́жа своего̀, и҆ посѧ́гнетъ за и҆но́го, прелюбы̀ твори́тъ. ",
}

add_evangelie_marka {
  ["номер"] = 44,
  ["комментарий"] = "Мк., 44 зач., X, 11–16.",
  ["текст_ру"] = "Рече́ Госпо́дь: и́же а́ще пу́стит жену́ свою́ и оже́нится ино́ю, прелюбы́ твори́т на ню. И а́ще жена́ пу́стит му́жа своего́ и пося́гнет за ино́го, прелюбы́ твори́т. И приноша́ху к Нему́ де́ти, да ко́снется их, ученицы́ же преща́ху принося́щым. Ви́дев же Иису́с негодова́ и рече́ им: оста́вите дете́й приходи́ти ко Мне и не брани́те им, таце́х бо есть Ца́рствие Бо́жие. Ами́нь глаго́лю вам, и́же а́ще не прии́мет Ца́рствия Бо́жия я́ко отроча́, не и́мать вни́ти в не. И обе́м их, возло́жь ру́це на них, благословля́ше их. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: и҆́же а҆́ще пꙋ́ститъ женꙋ̀ свою̀, и҆ ѡ҆же́нитсѧ и҆но́ю, прелюбы̀ твори́тъ на ню̀. и҆ а҆́ще жена̀ пꙋ́ститъ мꙋ́жа своего̀, и҆ посѧ́гнетъ за и҆но́го, прелюбы̀ твори́тъ. и҆ приноша́хꙋ къ немꙋ̀ дѣ́ти, да ко́снетсѧ и҆́хъ: ᲂу҆ченицы́ же преща́хꙋ приносѧ́щымъ. ви́дѣвъ же і҆и҃съ, негодова̀, и҆ речѐ и҆̀мъ: ѡ҆ста́вите дѣте́й приходи́ти ко мнѣ̀, и҆ не брани́те и҆̀мъ: тацѣ́хъ бо є҆́сть црⷭ҇твїе бж҃їе. а҆ми́нь глаго́лю ва́мъ: и҆́же а҆́ще не прїи́метъ црⷭ҇твїѧ бж҃їѧ ꙗ҆́кѡ ѻ҆троча̀, не и҆́мать вни́ти въ нѐ. и҆ ѡ҆б̾е́мъ и҆̀хъ, возло́жь рꙋ́цѣ на ни́хъ, благословлѧ́ше и҆̀хъ. ",
}

add_evangelie_marka {
  ["номер"] = 45,
  ["комментарий"] = "Мк., 45 зач., X, 17–27.",
  ["текст_ру"] = "Во вре́мя о́но, исходя́щу Иису́сови на путь, прите́к не́кий и покло́нься на коле́ну Ему́, вопроша́ше Его́: Учи́телю благи́й, что сотворю́, да живо́т ве́чный насле́дствую? Иису́с же рече́ ему́: что Мя глаго́леши бла́га? Никто́же благ, то́кмо еди́н Бог. За́поведи ве́си: не прелюбы́ сотвори́ши, не уби́й, не укра́ди, не лжесвиде́тельствуй, не оби́ди, чти отца́ твоего́ и ма́терь. Он же отвеща́в рече́ Ему́: Учи́телю, сия́ вся сохрани́х от ю́ности моея́. Иису́с же воззре́в нань, возлюби́ его́ и рече́ ему́: еди́наго еси́ не доконча́л, иди́, ели́ка и́маши, прода́ждь и даждь ни́щым, и име́ти и́маши сокро́вище на небеси́, и прииди́ и ходи́ в след Мене́, взем крест. Он же дряхл быв о словеси́ сем, оты́де скорбя́, бе бо име́я стяжа́ния мно́га. И воззре́в Иису́с глаго́ла ученико́м Свои́м: ка́ко неудо́бь иму́щии бога́тство в Ца́рствие Бо́жие вни́дут. Ученицы́ же ужаса́хуся о словесе́х Его́. Иису́с же па́ки отвеща́в глаго́ла им: ча́да, ка́ко неудо́бь упова́ющым на бога́тство в Ца́рствие Бо́жие вни́ти! Удо́бее бо есть вельбу́ду сквозе́ иглине́ у́ши проити́, не́же бога́ту в Ца́рствие Бо́жие вни́ти. Они́ же и́злиха дивля́хуся, глаго́люще к себе́: то кто мо́жет спасе́н бы́ти? Воззре́в же на них Иису́с глаго́ла: от челове́к невозмо́жно, но не от Бо́га, вся бо возмо́жна суть у Бо́га. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆сходѧ́щꙋ і҆и҃сови на пꙋ́ть, прите́къ нѣ́кїй, и҆ покло́ньсѧ на колѣ́нꙋ є҆мꙋ̀, вопроша́ше є҆го̀: ᲂу҆чт҃лю благі́й, что̀ сотворю̀, да живо́тъ вѣ́чный наслѣ́дствꙋю; і҆и҃съ же речѐ є҆мꙋ̀: что́ мѧ глаго́леши бла́га; никто́же бла́гъ то́кмѡ є҆ди́нъ бг҃ъ. за́пѡвѣди вѣ́си: не прелюбы̀ сотвори́ши. не ᲂу҆бі́й. не ᲂу҆кра́ди. не лжесвидѣ́тельствꙋй. не ѡ҆би́ди. чтѝ ѻ҆тца̀ твоего̀ и҆ ма́терь. ѻ҆́нъ же ѿвѣща́въ речѐ є҆мꙋ̀: ᲂу҆чи́телю, сїѧ̑ всѧ̑ сохрани́хъ ѿ ю҆́ности моеѧ̀. і҆и҃съ же воззрѣ́въ на́нь, возлюбѝ є҆го̀, и҆ речѐ є҆мꙋ̀: є҆ди́нагѡ є҆сѝ не доконча́лъ: и҆дѝ, є҆ли̑ка и҆́маши прода́ждь, и҆ да́ждь ни́щымъ, и҆ и҆мѣ́ти и҆́маши сокро́вище на небесѝ: и҆ прїидѝ, и҆ ходѝ въ слѣ́дъ менѐ, взе́мъ крⷭ҇тъ. ѻ҆́нъ же дрѧ́хлъ бы́въ ѡ҆ словесѝ се́мъ, ѿи́де скорбѧ̀: бѣ́ бо и҆мѣ́ѧ стѧжа̑нїѧ мнѡ́га. и҆ воззрѣ́въ і҆и҃съ, глаго́ла ᲂу҆ченикѡ́мъ свои́мъ: ка́кѡ неꙋдо́бь и҆мꙋ́щїи бога́тство въ црⷭ҇твїе бж҃їе вни́дꙋтъ; ᲂу҆ченицы́ же ᲂу҆жаса́хꙋсѧ ѡ҆ словесѣ́хъ є҆гѡ̀. і҆и҃съ же па́ки ѿвѣща́въ глаго́ла и҆̀мъ: ча̑да, ка́кѡ неꙋдо́бь ᲂу҆пова́ющымъ на бога́тство въ црⷭ҇твїе бж҃їе вни́ти; ᲂу҆до́бѣе бо є҆́сть вельбꙋ́дꙋ сквозѣ̀ и҆глинѣ̀ ᲂу҆́ши проитѝ, не́же бога́тꙋ въ црⷭ҇твїе бж҃їе вни́ти. ѻ҆ни́ же и҆́злиха дивлѧ́хꙋсѧ, глаго́люще къ себѣ̀: то̀ кто̀ мо́жетъ спасе́нъ бы́ти; воззрѣ́въ же на ни́хъ і҆и҃съ глаго́ла: ѿ человѣ̑къ невозмо́жно, но не ѿ бг҃а: всѧ̑ бо возмѡ́жна сꙋ́ть ѿ бг҃а. ",
}

add_evangelie_marka {
  ["номер"] = 46,
  ["комментарий"] = "Мк., 46 зач., X, 23–32.",
  ["текст_ру"] = "Рече́ Госпо́дь: ка́ко неудо́бь иму́щии бога́тство в Ца́рствие Бо́жие вни́дут. Ученицы́ же ужаса́хуся о словесе́х Его́. Иису́с же па́ки отвеща́в глаго́ла им: ча́да, ка́ко неудо́бь упова́ющым на бога́тство в Ца́рствие Бо́жие вни́ти! Удо́бее бо есть вельбу́ду сквозе́ иглине́ у́ши проити́, не́же бога́ту в Ца́рствие Бо́жие вни́ти. Они́ же и́злиха дивля́хуся, глаго́люще к себе́: то кто мо́жет спасе́н бы́ти? Воззре́в же на них Иису́с глаго́ла: от челове́к невозмо́жно, но не от Бо́га, вся бо возмо́жна суть у Бо́га. Нача́т же Петр глаго́лати Ему́: се мы оста́вихом вся и в след Тебе́ идо́хом. Отвеща́в же Иису́с рече́: ами́нь глаго́лю вам, никто́же есть, и́же оста́вил есть дом, или́ бра́тию, или́ сестры́, или́ отца́, или́ ма́терь, или́ жену́, или́ ча́да, или́ се́ла, Мене́ ра́ди и Ева́нгелиа ра́ди, а́ще не прии́мет стори́цею ны́не во вре́мя сие́, домо́в, и бра́тий, и сестр, и отца́, и ма́тере, и чад, и сел, по изгна́нии, и в век гряду́щий живо́т ве́чный. Мно́зи же бу́дут пе́рвии после́дни, и после́днии пе́рви. Бя́ху же на пути́, восходя́ще во Иерусали́м, и бе варя́я их Иису́с, и ужаса́хуся, и во след иду́ще боя́хуся. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: ка́кѡ неꙋдо́бь и҆мꙋ́щїи бога́тство въ црⷭ҇твїе бж҃їе вни́дꙋтъ; ᲂу҆ченицы́ же ᲂу҆жаса́хꙋсѧ ѡ҆ словесѣ́хъ є҆гѡ̀. і҆и҃съ же па́ки ѿвѣща́въ глаго́ла и҆̀мъ: ча̑да, ка́кѡ неꙋдо́бь ᲂу҆пова́ющымъ на бога́тство въ црⷭ҇твїе бж҃їе вни́ти; ᲂу҆до́бѣе бо є҆́сть вельбꙋ́дꙋ сквозѣ̀ и҆глинѣ̀ ᲂу҆́ши проитѝ, не́же бога́тꙋ въ црⷭ҇твїе бж҃їе вни́ти. ѻ҆ни́ же и҆́злиха дивлѧ́хꙋсѧ, глаго́люще къ себѣ̀: то̀ кто̀ мо́жетъ спасе́нъ бы́ти; воззрѣ́въ же на ни́хъ і҆и҃съ глаго́ла: ѿ человѣ̑къ невозмо́жно, но не ѿ бг҃а: всѧ̑ бо возмѡ́жна сꙋ́ть ѿ бг҃а. нача́тъ же пе́тръ глаго́лати є҆мꙋ̀: сѐ мы̀ ѡ҆ста́вихомъ всѧ̑, и҆ въ слѣ́дъ тебѐ и҆до́хомъ. ѿвѣща́въ же і҆и҃съ речѐ: а҆ми́нь глаго́лю ва́мъ, никто́же є҆́сть и҆́же ѡ҆ста́вилъ є҆́сть до́мъ, и҆лѝ бра́тїю, и҆лѝ сєстры̀, и҆лѝ ѻ҆тца̀, и҆лѝ ма́терь, и҆лѝ женꙋ̀: и҆лѝ ча̑да, и҆лѝ сє́ла, менѐ ра́ди, и҆ є҆ѵⷢ҇лїа ра́ди: а҆́ще не прїи́метъ стори́цею ны́нѣ во вре́мѧ сїѐ, домѡ́въ, и҆ бра́тїй, и҆ се́стръ, и҆ ѻ҆тца̀, и҆ ма́тере, и҆ ча̑дъ, и҆ се́лъ, по и҆згна́нїи, и҆ въ вѣ́къ грѧдꙋ́щїй живо́тъ вѣ́чный. мно́зи же бꙋ́дꙋтъ пе́рвїи послѣ́дни, и҆ послѣ́днїи пе́рви. бѧ́хꙋ же на пꙋтѝ восходѧ́ще во і҆ерꙋсали́мъ, и҆ бѣ̀ варѧ́ѧ и҆̀хъ і҆и҃съ, и҆ ᲂу҆жаса́хꙋсѧ, и҆ во слѣ́дъ и҆дꙋ́ще боѧ́хꙋсѧ. ",
}

add_evangelie_marka {
  ["номер"] = 47,
  ["комментарий"] = "Мк., 47 зач., X, 32–45.",
  ["текст_ру"] = "Во вре́мя о́но, поя́т Иису́с обана́десять, нача́т им глаго́лати, я́же хотя́ху Ему́ бы́ти, я́ко се восхо́дим во Иерусали́м, и Сын Челове́ческий пре́дан бу́дет архиере́ом и кни́жником, и осу́дят Его́ на смерть, и предадя́т Его́ язы́ком, и поруга́ются Ему́, и уя́звят Его́, и оплю́ют Его́, и убию́т Его́, и в тре́тий день воскре́снет. И пред Ним приидо́ста Иа́ков и Иоа́нн, сы́на Зеведе́ева, глаго́люща: Учи́телю, хо́щева, да, е́же а́ще про́сива, сотвори́ши на́ма. Он же рече́ и́ма: что хо́щета, да сотворю́ ва́ма? Она́ же ре́ста Ему́: даждь нам, да еди́н одесну́ю Тебе́ и еди́н ошу́юю Тебе́ ся́дева во сла́ве Твое́й. Иису́с же рече́ и́ма: не ве́стася, чесо́ про́сита. Мо́жета ли пи́ти ча́шу, ю́же Аз пию́, и креще́нием, и́мже Аз креща́юся, крести́тися? Она́ же ре́ста Ему́: мо́жева. Иису́с же рече́ и́ма: ча́шу у́бо, ю́же Аз пию́, испие́та, и креще́нием, и́мже Аз креща́юся, крести́тася, а е́же се́сти одесну́ю Мене́ и ошу́юю, несть Мне да́ти, но и́мже угото́вано есть. И слы́шавше де́сять, нача́ша негодова́ти о Иа́кове и Иоа́нне. Иису́с же призва́в их, глаго́ла им: ве́сте, я́ко мня́щиися владе́ти язы́ки, соодолева́ют им, и вели́цыи их облада́ют и́ми. Не та́ко же бу́дет в вас, но и́же а́ще хо́щет в вас вя́щший бы́ти, да бу́дет вам слуга́, и и́же а́ще хо́щет в вас бы́ти ста́рей, да бу́дет всем раб. И́бо Сын Челове́чь не прии́де, да послу́жат Ему́, но да послу́жит и да́ти ду́шу Свою́ избавле́ние за мно́ги. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, поѧ́тъ і҆и҃съ ѻ҆бана́десѧть, нача́тъ и҆̀мъ глаго́лати ꙗ҆̀же хотѧ́хꙋ є҆мꙋ̀ бы́ти: ꙗ҆́кѡ сѐ восхо́димъ во і҆ерꙋсали́мъ, и҆ сн҃ъ человѣ́ческїй пре́данъ бꙋ́детъ а҆рхїере́ѡмъ и҆ кни́жникѡмъ: и҆ ѡ҆сꙋ́дѧтъ є҆го̀ на сме́рть, и҆ предадѧ́тъ є҆го̀ ꙗ҆зы́кѡмъ. и҆ порꙋга́ютсѧ є҆мꙋ̀, и҆ ᲂу҆ѧ́звѧтъ є҆го̀, и҆ ѡ҆плю́ютъ є҆го̀, и҆ ᲂу҆бїю́тъ є҆го̀, и҆ въ тре́тїй де́нь воскре́снетъ. и҆ пред̾ ни́мъ прїидо́ста і҆а́кѡвъ и҆ і҆ѡа́ннъ, сы́на зеведе́єва, глаго́люща: ᲂу҆чи́телю, хо́щева да є҆́же а҆́ще про́сива, сотвори́ши на́ма. ѻ҆́нъ же речѐ и҆́ма: что̀ хо́щета да сотворю̀ ва́ма; ѻ҆на̑ же рѣ́ста є҆мꙋ̀: да́ждь на́мъ, да є҆ди́нъ ѡ҆деснꙋ́ю тебѐ, и҆ є҆ди́нъ ѡ҆шꙋ́юю тебѐ сѧ́дева во сла́вѣ твое́й. і҆и҃съ же речѐ и҆́ма: не вѣ́стасѧ чесѡ̀ про́сита. мо́жета ли пи́ти ча́шꙋ, ю҆́же а҆́зъ пїю̀, и҆ креще́нїемъ, и҆́мже а҆́зъ креща́юсѧ, крести́тисѧ; ѻ҆на̑ же рѣ́ста є҆мꙋ̀, мо́жева. і҆и҃съ же речѐ и҆́ма: ча́шꙋ ᲂу҆́бѡ, ю҆́же а҆́зъ пїю̀, и҆спїе́та, и҆ креще́нїемъ, и҆́мже а҆́зъ креща́юсѧ, крести́тасѧ: а҆ є҆́же сѣ́сти ѡ҆деснꙋ́ю менѐ и҆ ѡ҆шꙋ́юю, нѣ́сть мнѣ̀ да́ти, но и҆̀мже ᲂу҆гото́вано є҆́сть. и҆ слы́шавше де́сѧть, нача́ша негодова́ти ѡ҆ і҆а́кѡвѣ и҆ і҆ѡа́ннѣ. і҆и҃съ же призва́въ и҆̀хъ, глаго́ла и҆̀мъ: вѣ́сте, ꙗ҆́кѡ мнѧ́щїисѧ владѣ́ти ꙗ҆зы́ки, соѡдолѣва́ютъ и҆̀мъ, и҆ вели́цыи и҆́хъ ѡ҆блада́ютъ и҆́ми. не та́кѡ же бꙋ́детъ въ ва́съ: но и҆́же а҆́ще хо́щетъ въ ва́съ вѧ́щшїй бы́ти, да бꙋ́детъ ва́мъ слꙋга̀. и҆ и҆́же а҆́ще хо́щетъ въ ва́съ бы́ти ста́рѣй, да бꙋ́детъ всѣ́мъ ра́бъ. и҆́бо сн҃ъ человѣ́чь не прїи́де, да послꙋ́жатъ є҆мꙋ̀: но да послꙋ́житъ, и҆ да́ти дш҃ꙋ свою̀ и҆збавле́нїе за мно́ги. ",
}

add_evangelie_marka {
  ["номер"] = 48,
  ["комментарий"] = "Мк., 48 зач., X, 46–52.",
  ["текст_ру"] = "Во вре́мя о́но, исходя́щу Иису́сови от Иерихо́на, и ученико́м Его́, и наро́ду мно́гу, сын Тиме́ов Варти́мей слепы́й седя́ше при пути́, прося́. И слы́шав, я́ко Иису́с Назоряни́н есть, нача́т зва́ти и глаго́лати: Сы́не Дави́дов Иису́се поми́луй мя. И преща́ху ему́ мно́зи, да умолчи́т. Он же мно́жае па́че зва́ше: Сы́не Дави́дов, поми́луй мя. И став Иису́с, рече́ его́ возгласи́ти. И возгласи́ша слепца́, глаго́люще ему́: дерза́й, воста́ни, зове́т тя. Он же отве́рг ри́зы своя́, воста́в прии́де ко Иису́сови. И отвеща́в глаго́ла ему́ Иису́с: что хо́щеши, да сотворю́ Тебе́? Слепы́й же глаго́ла Ему́: Учи́телю, да прозрю́. Иису́с же рече́ ему́: иди́, ве́ра твоя́ спасе́ тя. И а́бие прозре́ и по Иису́се и́де в путь. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆сходѧ́щꙋ і҆и҃сови ѿ і҆ерїхѡ́на, и҆ ᲂу҆ченикѡ́мъ є҆гѡ̀ и҆ наро́дꙋ мно́гꙋ, сы́нъ тїме́овъ варті́мей слѣпы́й сѣдѧ́ше при пꙋтѝ просѧ̀. и҆ слы́шавъ ꙗ҆́кѡ і҆и҃съ назѡрѧни́нъ є҆́сть, нача́тъ зва́ти и҆ глаго́лати: сн҃е дв҃довъ і҆и҃се, поми́лꙋй мѧ̀. и҆ преща́хꙋ є҆мꙋ̀ мно́зи, да ᲂу҆молчи́тъ. ѻ҆́нъ же мно́жае па́че зва́ше: сн҃е дв҃довъ, поми́лꙋй мѧ̀. и҆ ста́въ і҆и҃съ речѐ є҆го̀ возгласи́ти. и҆ возгласи́ша слѣпца̀, глаго́люще є҆мꙋ̀: дерза́й, воста́ни: зове́тъ тѧ̀. ѻ҆́нъ же ѿве́ргъ ри̑зы своѧ̀, воста́въ прїи́де ко і҆и҃сови. и҆ ѿвѣща́въ глаго́ла є҆мꙋ̀ і҆и҃съ: что̀ хо́щеши, да сотворю̀ тебѣ̀; слѣпы́й же глаго́ла є҆мꙋ̀: ᲂу҆чи́телю, да прозрю̀. і҆и҃съ же речѐ є҆мꙋ̀: и҆дѝ, вѣ́ра твоѧ̀ спасѐ тѧ̀. и҆ а҆́бїе прозрѣ̀. и҆ по і҆и҃сѣ и҆́де въ пꙋ́ть. ",
}

add_evangelie_marka {
  ["номер"] = 49,
  ["комментарий"] = "Мк., 49 зач., XI, 1–11.",
  ["текст_ру"] = "Во вре́мя о́но, прибли́жися Иису́с во Иерусали́м, и прии́де в Вифсфаги́ю и Вифа́нию, к горе́ Елео́нстей, посла́ два от учени́к Свои́х и глаго́ла и́ма: иди́та в весь, я́же есть пря́мо ва́ма, и а́бие входя́ща в ню, обря́щета жребя́ привя́зано, на не́же никто́же от челове́к все́де, отре́шша е́, приведи́та. И а́ще кто ва́ма рече́т: что твори́та сие́? Рцы́та, я́ко Госпо́дь тре́бует е́, и а́бие по́слет е́ се́мо. Идо́ста же, и обрето́ста жребя́ привя́зано при две́рех вне на распу́тии, и отреши́ста е́. И не́цыи от стоя́щих ту глаго́лаху и́ма: что де́ета отреша́юща жребя́? Она́ же ре́ста им, я́коже запове́да и́ма Иису́с, и оста́виша я́. И приведо́ста жребя́ ко Иису́сови, и возложи́ша на не ри́зы своя́, и все́де на не. Мно́зи же ри́зы своя́ постла́ша по пути́, друзи́и же ва́иа ре́заху от дре́вия и постила́ху по пути́. И предходя́щии и в след гряду́щии вопия́ху, глаго́люще: оса́нна, благослове́н Гряды́й во и́мя Госпо́дне, благослове́но гряду́щее ца́рство во и́мя Го́спода отца́ на́шего Дави́да, оса́нна в вы́шних. И вни́де во Иерусали́м Иису́с и в це́рковь, и согля́дав вся, по́зде уже́ су́щу часу́, изы́де в Вифа́нию со обемана́десяте. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прибли́жисѧ і҆и҃съ во і҆ерꙋсали́мъ, и҆ прїи́де въ виѳсфагі́ю и҆ виѳа́нїю къ горѣ̀ є҆леѡ́нстѣй, посла̀ два̀ ѿ ᲂу҆чєни́къ свои́хъ. и҆ глаго́ла и҆̀мъ: и҆ди́та въ ве́сь, ꙗ҆́же є҆́сть прѧ́мѡ ва́ма: и҆ а҆́бїе входѧ́ща въ ню̀ ѡ҆брѧ́щета жребѧ̀ привѧ́зано, на не́же никто́же ѿ человѣ́къ всѣ́де: ѿрѣ́шша є҆̀ приведи́та. и҆ а҆́ще кто̀ ва́ма рече́тъ: что̀ твори́та сїѐ, рцы́та, ꙗ҆́кѡ гдⷭ҇ь тре́бꙋетъ є҆̀, и҆ а҆́бїе по́слетъ є҆̀ сѣ́мѡ. и҆до́ста же, и҆ ѡ҆брѣто́ста жребѧ̀ привѧ́зано при две́рехъ внѣ̀ на распꙋ́тїи, и҆ ѿрѣши́ста є҆̀. и҆ нѣ́цыи ѿ стоѧ́щихъ тꙋ̀ глаго́лахꙋ и҆́ма: что̀ дѣ́ета ѿрѣша́юща жребѧ̀; ѻ҆на̑ же рѣ́ста и҆̀мъ, ꙗ҆́коже заповѣ́да и҆́ма і҆и҃съ: и҆ ѡ҆ста́виша ѧ҆̀. и҆ приведо́ста жребѧ̀ ко і҆и҃сови:  и҆ возложи́ша на нѐ ри̑зы своѧ̀: и҆ всѣ́де на нѐ. мно́зи же ри̑зы своѧ̀ постла́ша по пꙋтѝ: дрꙋзі́и же ва̑їа рѣ́захꙋ ѿ дре́вїѧ, и҆ постила́хꙋ по пꙋтѝ. и҆ предходѧ́щїи и҆ въ слѣ́дъ грѧдꙋ́щїи вопїѧ́хꙋ, глаго́люще: ѡ҆са́нна, благослове́нъ грѧды́й во и҆́мѧ гдⷭ҇не. благослове́но грѧдꙋ́щее ца́рство во и҆́мѧ гдⷭ҇не ѻ҆ц҃а̀ на́шегѡ дв҃да: ѡ҆са́нна въ вы́шнихъ. и҆ вни́де во і҆ерꙋсали́мъ і҆и҃съ, и҆ въ цр҃ковь, и҆ соглѧ́давъ всѧ̑: по́здѣ ᲂу҆жѐ сꙋ́щꙋ часꙋ̀, и҆зы́де въ виѳа́нїю со ѻ҆бѣмана́десѧте. ",
}

add_evangelie_marka {
  ["номер"] = 50,
  ["комментарий"] = "Мк., 50 зач., XI, 11–23.",
  ["текст_ру"] = "Во вре́мя о́но, вни́де Иису́с во Иерусали́м и в це́рковь, и согля́дав вся, по́зде уже́ су́щу часу́, изы́де в Вифа́нию со обемана́десяте. И нау́трия изше́дшым им от Вифа́нии, взалка́. И ви́дев смоко́вницу издале́ча, иму́щу ли́ствие, прии́де, а́ще у́бо что обря́щет на ней, и прише́д к ней, ничесо́же обре́те, то́кмо ли́ствие, не у бо бе вре́мя смо́квам. И отвеща́в Иису́с рече́ ей: да не ктому́ от тебе́ во ве́ки никто́же плода́ снесть. И слы́шаху ученицы́ Его́. И приидо́ша па́ки во Иерусали́м. И вшед Иису́с в це́рковь, нача́т изгони́ти продаю́щыя и купу́ющыя в це́ркви, и трапе́зы торжнико́м и седа́лища продаю́щих го́луби испрове́рже. И не дая́ше, да кто мимонесе́т сосу́д сквозе́ це́рковь. И уча́ше, глаго́ля им: несть ли пи́сано, я́ко храм Мой храм моли́твы нарече́тся всем язы́ком? Вы же сотвори́сте его́ верте́п разбо́йником. И слы́шаша кни́жницы и архиере́е, и иска́ху, ка́ко Его́ погубя́т, боя́ху бо ся Его́, я́ко весь наро́д дивля́шеся о уче́нии Его́. И я́ко по́зде бысть, исхожда́ше вон из гра́да. И у́тро мимоходя́ще, ви́деша смоко́вницу изсо́хшу из коре́ния. И воспомяну́в Петр глаго́ла Ему́: Равви́, виждь, смоко́вницу, ю́же прокля́т, у́сше. И отвеща́в Иису́с глаго́ла им: име́йте ве́ру Бо́жию. Ами́нь бо глаго́лю вам, я́ко, и́же а́ще рече́т горе́ сей: дви́гнися и ве́рзися в мо́ре, и не размы́слит в се́рдце свое́м, но ве́ру и́мет, я́ко е́же глаго́лет, быва́ет, бу́дет ему́, е́же а́ще рече́т. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, вни́де і҆и҃съ во і҆ерⷭ҇ли́мъ и҆ въ цр҃ковь, и҆ соглѧ́давъ всѧ̑: по́здѣ ᲂу҆жѐ сꙋ́щꙋ часꙋ̀, и҆зы́де въ виѳа́нїю со ѻ҆бѣмана́десѧте. и҆ наꙋ́трїѧ и҆зше́дшымъ и҆̀мъ ѿ виѳа́нїи, взалка̀. и҆ ви́дѣвъ смоко́вницꙋ и҆здале́ча, и҆мꙋ́щꙋ ли́ствїе, прїи́де а҆́ще ᲂу҆́бѡ что̀ ѡ҆брѧ́щетъ на не́й: и҆ прише́дъ къ не́й, ничесо́же ѡ҆брѣ́те, то́кмѡ ли́ствїе: не ᲂу҆́ бо бѣ̀ вре́мѧ смо́квамъ. и҆ ѿвѣща́въ і҆и҃съ речѐ є҆́й: да не ктомꙋ̀ ѿ тебѐ во вѣ́ки никто́же плода̀ снѣ́сть: и҆ слы́шахꙋ ᲂу҆ченицы̀ є҆гѡ̀. и҆ прїидо́ша па́ки во і҆ерꙋсали́мъ: и҆ вше́дъ і҆и҃съ въ це́рковь, нача́тъ и҆згони́ти продаю́щыѧ и҆ кꙋпꙋ́ющыѧ въ це́ркви, и҆ трапє́зы торжникѡ́мъ, и҆ сѣда̑лища продаю́щихъ го́лꙋби и҆спрове́рже. и҆ не даѧ́ше, да кто̀ мимонесе́тъ сосꙋ́дъ сквозѣ̀ це́рковь. и҆ ᲂу҆ча́ше глаго́лѧ и҆̀мъ: нѣ́сть ли пи́сано, ꙗ҆́кѡ хра́мъ мо́й, хра́мъ моли́твы нарече́тсѧ всѣ́мъ ꙗ҆зы́кѡмъ; вы́ же сотвори́сте є҆го̀ верте́пъ разбо́йникѡмъ. и҆ слы́шаша кни́жницы, и҆ а҆рхїере́є, и҆ и҆ска́хꙋ, ка́кѡ є҆го̀ погꙋбѧ́тъ: боѧ́хꙋ бо сѧ є҆гѡ̀, ꙗ҆́кѡ ве́сь наро́дъ дивлѧ́шесѧ ѡ҆ ᲂу҆че́нїи є҆гѡ̀. и҆ ꙗ҆́кѡ по́здѣ бы́сть, и҆схожда́ше во́нъ и҆з̾ гра́да. и҆ ᲂу҆́трѡ мимоходѧ́ще, ви́дѣша смоко́вницꙋ и҆зсо́хшꙋ и҆з̾ коре́нїѧ. и҆ воспомѧнꙋ́въ пе́тръ глаго́ла є҆мꙋ̀: равві̀, ви́ждь смоко́вницꙋ, ю҆́же проклѧ́тъ, ᲂу҆́сше. и҆ ѿвѣща́въ і҆и҃съ, глаго́ла и҆̀мъ: и҆мѣ́йте вѣ́рꙋ бж҃їю. а҆ми́нь бо глаго́лю ва́мъ, ꙗ҆́кѡ и҆́же а҆́ще рече́тъ горѣ̀ се́й, дви́гнисѧ, и҆ ве́рзисѧ въ мо́ре: и҆ не размы́слитъ въ се́рдцѣ свое́мъ, но вѣ́рꙋ и҆́метъ, ꙗ҆́кѡ є҆́же глаго́летъ, быва́етъ: бꙋ́детъ є҆мꙋ̀, є҆́же а҆́ще рече́тъ. ",
}

add_evangelie_marka {
  ["номер"] = 51,
  ["комментарий"] = "Мк., 51 зач., XI, 23–26.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: име́йте ве́ру Бо́жию. Ами́нь бо глаго́лю вам, я́ко, и́же а́ще рече́т го́ре сей: дви́гнися и ве́рзися в мо́ре, и не размы́слит в се́рдце свое́м, но ве́ру и́мет, я́ко е́же глаго́лет, быва́ет, бу́дет ему́, е́же а́ще рече́т. Сего́ ра́ди глаго́лю вам: вся ели́ка а́ще моля́щеся про́сите, ве́руйте, я́ко прие́млете, и бу́дет вам. И егда́ стоите́ моля́щеся, отпуща́йте, а́ще что и́мате на кого́, да и Оте́ц ваш, И́же есть на небесе́х, отпу́стит вам согреше́ния ва́ша. А́ще ли же вы не отпуща́ете, ни Оте́ц ваш, И́же есть на небесе́х, отпу́стит вам согреше́ний ва́ших. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: и҆мѣ́йте вѣ́рꙋ бж҃їю. а҆ми́нь бо глаго́лю ва́мъ, ꙗ҆́кѡ и҆́же а҆́ще рече́тъ горѣ̀ се́й, дви́гнисѧ, и҆ ве́рзисѧ въ мо́ре: и҆ не размы́слитъ въ се́рдцѣ свое́мъ, но вѣ́рꙋ и҆́метъ, ꙗ҆́кѡ є҆́же глаго́летъ, быва́етъ: бꙋ́детъ є҆мꙋ̀, є҆́же а҆́ще рече́тъ. сегѡ̀ ра́ди глаго́лю ва́мъ: всѧ̑ є҆ли̑ка а҆́ще молѧ́щесѧ про́сите, вѣ́рꙋйте, ꙗ҆́кѡ прїе́млете: и҆ бꙋ́детъ ва́мъ. и҆ є҆гда̀ стоитѐ молѧ́щесѧ, ѿпꙋща́йте, а҆́ще что̀ и҆́мате на кого̀: да и҆ ѻ҆ц҃ъ ва́шъ, и҆́же є҆́сть на нб҃сѣ́хъ, ѿпꙋ́ститъ ва́мъ согрѣшє́нїѧ ва́ша. а҆́ще ли же вы̀ не ѿпꙋща́ете, ни ѻ҆ц҃ъ ва́шъ, и҆́же є҆́сть на нб҃сѣ́хъ, ѿпꙋ́ститъ ва́мъ согрѣше́нїй ва́шихъ. ",
}

add_evangelie_marka {
  ["номер"] = 52,
  ["комментарий"] = "Мк., 52 зач., XI, 27–33.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с во Иерусали́м. И в це́ркви ходя́щу Ему́, приидо́ша к Нему́ архиере́е, и кни́жницы, и ста́рцы. И глаго́лаша Ему́: ко́ею о́бластию сия́ твори́ши? И кто Ти о́бласть сию́ даде́, да сия́ твори́ши? Иису́с же отвеща́в рече́ им: вопрошу́ вы и Аз сло́во еди́но, и отвеща́йте Ми, и реку́ вам, ко́ею о́бластию сия́ творю́. Креще́ние Иоа́нново с небесе́ ли бе, или́ от челове́к? Отвеща́йте Ми. И мы́сляху в себе́, глаго́люще: а́ще рече́м, с небесе́, рече́т: почто́ у́бо не ве́ровасте ему́? Но а́ще рече́м, от челове́к: боя́хуся люде́й, вси бо име́яху Иоа́нна, я́ко вои́стинну проро́к бе. И отвеща́вше глаго́лаша Иису́сови: не ве́мы. И отвеща́в Иису́с глаго́ла им: ни Аз глаго́лю вам, ко́ею о́бластию сия́ творю́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ во і҆ерꙋсали́мъ: и҆ въ це́ркви ходѧ́щꙋ є҆мꙋ̀, прїидо́ша къ немꙋ̀ а҆рхїере́є, и҆ кни́жницы, и҆ ста́рцы, и҆ глаго́лаша є҆мꙋ̀: ко́ею ѻ҆́бластїю сїѧ̑ твори́ши; и҆ кто̀ тѝ ѻ҆́бласть сїю̀ дадѐ, да сїѧ̑ твори́ши; і҆и҃съ же ѿвѣща́въ, речѐ и҆̀мъ: вопрошꙋ̀ вы̀ и҆ а҆́зъ сло́во є҆ди́но, и҆ ѿвѣща́йте мѝ, и҆ рекꙋ̀ ва́мъ, ко́ею ѻ҆́бластїю сїѧ̑ творю̀. креще́нїе і҆ѡа́нново съ небесе́ ли бѣ̀, и҆лѝ ѿ человѣ̑къ; ѿвѣща́йте мѝ. и҆ мы́слѧхꙋ въ себѣ̀, глаго́люще: а҆́ще рече́мъ, съ небесѐ: рече́тъ: почто̀ ᲂу҆́бѡ не вѣ́ровасте є҆мꙋ̀; но а҆́ще рече́мъ: ѿ человѣ̑къ, боѧ́хꙋсѧ люде́й. вси́ бо и҆мѣ́ѧхꙋ і҆ѡа́нна, ꙗ҆́кѡ вои́стиннꙋ проро́къ бѣ̀. и҆ ѿвѣща́вше глаго́лаша і҆и҃сови: не вѣ́мы. и҆ ѿвѣща́въ і҆и҃съ глаго́ла и҆̀мъ: ни а҆́зъ глаго́лю ва́мъ, ко́ею ѻ҆́бластїю сїѧ̑ творю̀. ",
}

add_evangelie_marka {
  ["номер"] = 53,
  ["комментарий"] = "Мк., 53 зач., XII, 1–12.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: виногра́д насади́ челове́к, и огради́ опло́том, и ископа́ точи́ло, и созда́ столп, и предаде́ его́ тяжа́телем, и оты́де. И посла́ к тяжа́телем во вре́мя раба́, да от тяжа́тель прии́мет от плода́ виногра́да. Они́ же е́мше его́ би́ша и посла́ша тощ. И па́ки посла́ к ним друга́го раба́, и того́ ка́мением би́вше, проби́ша главу́ ему́ и посла́ша безче́стна. И па́ки ино́го посла́, и того́ уби́ша, и мно́ги и́ны, о́вы у́бо бию́ще, о́вы же убива́юще. Еще́ у́бо еди́наго сы́на име́ возлю́бленнаго своего́, посла́ и того́ к ним последи́, глаго́ля, я́ко усрамя́тся сы́на моего́. Они́ же тяжа́теле ре́ша к себе́, я́ко сей есть насле́дник, прииди́те, убие́м его́, и на́ше бу́дет насле́дствие. И е́мше его́ уби́ша и изверго́ша его́ вон из виногра́да. Что у́бо сотвори́т госпо́дь виногра́да? Прии́дет и погуби́т тяжа́тели и даст виногра́д ине́м. Ни Писа́ния ли сего́ чли есте́: ка́мень, его́же не в ряду́ сотвори́ша зи́ждущии, сей бысть во главу́ у́гла, от Го́спода бысть сей, и есть ди́вно во о́чию на́шею? И иска́ху Его́ я́ти, и убоя́шася наро́да, разуме́ша бо, я́ко к ним при́тчу рече́, и оста́вльше Его́ отидо́ша. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: вїногра́дъ насадѝ человѣ́къ, и҆ ѡ҆градѝ ѡ҆пло́томъ и҆ и҆скопа̀ точи́ло, и҆ созда̀ сто́лпъ, и҆ предадѐ є҆го̀ тѧжа́телємъ: и҆ ѿи́де. и҆ посла̀ къ тѧжа́телємъ во вре́мѧ раба̀, да ѿ тѧжа́тєль прїи́метъ ѿ плода̀ вїногра́да. ѻ҆ни́ же є҆́мше є҆го̀ би́ша, и҆ посла́ша то́щь. и҆ па́ки посла̀ къ ни́мъ дрꙋга́го раба̀, и҆ того̀ ка́менїемъ би́вше проби́ша главꙋ̀ є҆мꙋ̀, и҆ посла́ша безче́стна. и҆ па́ки и҆но́го посла̀, и҆ того̀ ᲂу҆би́ша: и҆ мно́ги и҆́ны, ѻ҆́вы ᲂу҆́бѡ бїю́ще, ѻ҆́вы же ᲂу҆бива́юще. є҆щѐ ᲂу҆́бѡ є҆ди́наго сн҃а и҆мѣ̀ возлю́бленнаго своего̀, посла̀ и҆ того̀ къ ни́мъ послѣдѝ, глаго́лѧ: ꙗ҆́кѡ ᲂу҆срамѧ́тсѧ сы́на моегѡ̀. ѻ҆ни́ же тѧжа́телє рѣ́ша къ себѣ̀: ꙗ҆́кѡ се́й є҆́сть наслѣ́дникъ, прїиди́те, ᲂу҆бїе́мъ є҆го̀, и҆ на́ше бꙋ́детъ наслѣ́дствїе. и҆ є҆́мше є҆го̀ ᲂу҆би́ша, и҆ и҆зверго́ша є҆го̀ во́нъ и҆з̾ вїногра́да. что̀ ᲂу҆́бѡ сотвори́тъ гдⷭ҇ь вїногра́да; прїи́детъ и҆ погꙋби́тъ тѧжа́тели, и҆ да́стъ вїногра́дъ и҆нѣ̑мъ. ни писа́нїѧ ли сегѡ̀ члѝ є҆стѐ: ка́мень є҆го́же не въ рѧдꙋ̀ сотвори́ша зи́ждꙋщїи, се́й бы́сть во главꙋ̀ ᲂу҆́гла; ѿ гдⷭ҇а бы́сть се́й: и҆ є҆́сть ди́вна во ѻ҆́чїю на́шею. и҆ и҆ска́хꙋ є҆го̀ ꙗ҆́ти, и҆ ᲂу҆боѧ́шасѧ наро́да, разꙋмѣ́ша бо, ꙗ҆́кѡ къ ни́мъ при́тчꙋ речѐ: и҆ ѡ҆ста́вльше є҆го̀ ѿидо́ша. ",
}

add_evangelie_marka {
  ["номер"] = 54,
  ["комментарий"] = "Мк., 54 зач., XII, 13–17.",
  ["текст_ру"] = "Во вре́мя о́но, посла́ша ко Иису́су архиере́е и ста́рцы иуде́йстии не́кия от фарисе́й и ироди́ан, да Его́ обольстя́т сло́вом. Они́ же прише́дше глаго́лаша Ему́: Учи́телю, ве́мы, я́ко и́стинен еси́, и неради́ши ни о ко́мже, не зри́ши бо на лице́ челове́ков, но вои́стинну пути́ Бо́жию учи́ши. Досто́ит ли кинсо́н ке́сареви да́ти, или́ ни? Да́мы ли, или́ не да́мы? Он же ве́дый их лицеме́рие, рече́ им: что Мя искуша́ете? Принеси́те Ми пе́нязь, да ви́жу. Они́ же принесо́ша. И глаго́ла им: чий о́браз сий и написа́ние? Они́ же ре́ша Ему́: ке́сарев. И отвеща́в Иису́с рече́ им: воздади́те ке́сарева ке́сареви и Бо́жия Бо́гови. И чуди́шася о Нем. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, посла́ша ко і҆и҃сꙋ а҆рхїере́є и҆ ста́рцы і҆ꙋде́йстїи нѣ̑кїѧ ѿ фарїсє́й, и҆ и҆рѡдїа́нъ, да є҆го̀ ѡ҆больстѧ́тъ сло́вомъ. ѻ҆ни́ же прише́дше глаго́лаша є҆мꙋ̀: ᲂу҆чи́телю, вѣ́мы, ꙗ҆́кѡ и҆́стиненъ є҆сѝ, и҆ неради́ши ни ѡ҆ ко́мже: не зри́ши бо на лицѐ человѣ́кѡвъ, но вои́стиннꙋ пꙋтѝ бж҃їю ᲂу҆чи́ши. досто́итъ ли кинсо́нъ ке́сареви да́ти, и҆лѝ нѝ; да́мы ли, и҆лѝ не да́мы; ѻ҆́нъ же вѣ́дый и҆́хъ лицемѣ́рїе, речѐ и҆̀мъ: что́ мѧ и҆скꙋша́ете; принеси́те мѝ пѣ́нѧзь, да ви́жꙋ. ѻ҆ни́ же принесо́ша. и҆ глаго́ла и҆̀мъ: чі́й ѻ҆́бразъ сі́й и҆ написа́нїе; ѻ҆ни́ же рѣ́ша є҆мꙋ̀: ке́саревъ. и҆ ѿвѣща́въ і҆и҃съ речѐ и҆̀мъ: воздади́те ке́сарєва ке́сареви, и҆ бж҃їѧ бг҃ови. и҆ чꙋди́шасѧ ѡ҆ не́мъ. ",
}

add_evangelie_marka {
  ["номер"] = 55,
  ["комментарий"] = "Мк., 55 зач., XII, 18–27.",
  ["текст_ру"] = "Во вре́мя о́но, приидо́ша саддуке́е ко Иису́су, и́же глаго́лют воскресе́нию не бы́ти, и вопроси́ша Его́, глаго́люще: Учи́телю, Моисе́й написа́ нам, я́ко а́ще кому́ брат у́мрет и оста́вит жену́, а чад не оста́вит, да по́ймет брат его́ жену́ его́ и воскреси́т се́мя бра́ту своему́. Седмь бра́тий бе, и пе́рвый поя́т жену́ и умира́я не оста́ви се́мене, и вторы́й поя́т ю́ и у́мре, и ни той оста́ви се́мене, и тре́тий та́кожде, и поя́ша ю́ седмь и не оста́виша се́мене, последи́ же всех у́мре и жена́. В воскреше́ние, егда́ воскре́снут, кото́рому их бу́дет жена́, седмь бо име́ша ю́ жену́. И отвеща́в Иису́с рече́ им: не сего́ ли ра́ди прельща́етеся, не ве́дуще Писа́ния, ни си́лы Бо́жия? Егда́ бо из ме́ртвых воскре́снут, ни же́нятся, ни посяга́ют, но суть я́ко А́нгели на небесе́х. О ме́ртвых же, я́ко востаю́т, не́сте ли чли в кни́гах Моисе́овых, при купине́ я́ко рече́ ему́ Бог, глаго́ля: Аз Бог Авраа́мов и Бог Исаа́ков и Бог Иа́ковль? Несть Бог ме́ртвых, но Бог живы́х, вы у́бо мно́го прельща́етеся. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїидо́ша саддꙋке́є ко і҆и҃сꙋ, и҆̀же глаго́лютъ воскресе́нїю не бы́ти, и҆ вопроси́ша є҆го̀, глаго́люще: ᲂу҆чи́телю, мѡѷсе́й написа̀ на́мъ: ꙗ҆́кѡ а҆́ще комꙋ̀ бра́тъ ᲂу҆́мретъ, и҆ ѡ҆ста́витъ женꙋ̀, а҆ ча̑дъ не ѡ҆ста́витъ, да по́йметъ бра́тъ є҆гѡ̀ женꙋ̀ є҆гѡ̀, и҆ воскреси́тъ сѣ́мѧ бра́тꙋ своемꙋ̀. се́дмь бра́тїй бѣ̀: и҆ пе́рвый поѧ́тъ женꙋ̀, и҆ ᲂу҆мира́ѧ не ѡ҆ста́ви сѣ́мене. и҆ вторы́й поѧ́тъ ю҆̀, и҆ ᲂу҆́мре: и҆ ни то́й ѡ҆ста́ви сѣ́мене, и҆ тре́тїй та́кожде. и҆ поѧ́ша ю҆̀ се́дмь, и҆ не ѡ҆ста́виша сѣ́мене: послѣди́ же всѣ́хъ ᲂу҆́мре и҆ жена̀. въ воскреше́нїе, є҆гда̀ воскре́снꙋтъ, кото́ромꙋ и҆́хъ бꙋ́детъ жена̀; се́дмь бо и҆мѣ́ша ю҆̀ женꙋ̀. и҆ ѿвѣща́въ і҆и҃съ речѐ и҆̀мъ: не сегѡ́ ли ра́ди прельща́етесѧ, не вѣ́дꙋще писа́нїѧ, ни си́лы бж҃їѧ; є҆гда́ бо и҆з̾ ме́ртвыхъ воскре́снꙋтъ, ни же́нѧтсѧ, ни посѧга́ютъ: но сꙋ́ть ꙗ҆́кѡ а҆́гг҃ли на небесѣ́хъ. ѡ҆ ме́ртвыхъ же, ꙗ҆́кѡ востаю́тъ, нѣ́сте ли члѝ въ кни́гахъ мѡѷсе́овыхъ, при кꙋпинѣ̀, ꙗ҆́кѡ речѐ є҆мꙋ̀ бг҃ъ, глаго́лѧ: а҆́зъ бг҃ъ а҆враа́мовъ, и҆ бг҃ъ і҆саа́ковъ, и҆ бг҃ъ і҆а́кѡвль. нѣ́сть бг҃ъ ме́ртвыхъ, но бг҃ъ живы́хъ. вы̀ ᲂу҆́бѡ мно́зи прельща́етесѧ. ",
}

add_evangelie_marka {
  ["номер"] = 56,
  ["комментарий"] = "Мк., 56 зач., XII, 28–37.",
  ["текст_ру"] = "Во вре́мя о́но, присту́пль ко Иису́су еди́н от кни́жник, и слы́шав саддуке́и стяза́ющася с Ним, и ви́дев, я́ко до́бре отвеща́ им, вопроси́ Его́: ка́я есть пе́рвая всех за́поведий? Иису́с же отвеща́ ему́: я́ко пе́рвейши всех за́поведий, слы́ши, Изра́илю, Госпо́дь Бог ваш Госпо́дь еди́н есть, и возлю́биши Го́спода Бо́га твоего́ всем се́рдцем твои́м, и все́ю душе́ю твое́ю, и всем умо́м твои́м, и все́ю кре́постию твое́ю, сия́ есть пе́рвая за́поведь. И втора́я подо́бна ей: возлю́биши бли́жняго своего́ я́ко сам себе́. Бо́льши сею́ и́на за́поведь несть. И рече́ Ему́ кни́жник: до́бре, Учи́телю, вои́стинну рече́, я́ко еди́н есть Бог, и несть ин ра́зве Его́, и е́же люби́ти Его́ всем се́рдцем, и всем ра́зумом, и все́ю душе́ю, и все́ю кре́постию, и е́же люби́ти бли́жняго я́ко себе́, бо́ле есть всех всесожже́ний и жертв. Иису́с же ви́дев, я́ко смы́сленно отвеща́, рече́ ему́: не дале́че еси́ от Ца́рствия Бо́жия. И никто́же сме́яше ктому́ Его́ вопроси́ти. И отвеща́в Иису́с глаго́лаше, учя́ в це́ркви: ка́ко глаго́лют кни́жницы, я́ко Христо́с Сын есть Дави́дов? Той бо Дави́д рече́ Ду́хом Святы́м: глаго́ла Госпо́дь Го́сподеви моему́, седи́ одесну́ю Мене́, до́ндеже положу́ враги́ Твоя́ подно́жие нога́ма Твои́ма. Сам у́бо Дави́д глаго́лет Его́ Го́спода, и отку́ду Сын ему́ есть? И мног наро́д послу́шаше Его́ в сла́дость. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋ́пль ко і҆и҃сꙋ є҆ди́нъ ѿ кни̑жникъ, и҆ слы́шавъ саддꙋке́и стѧза́ющѧсѧ съ ни́мъ, и҆ ви́дѣвъ, ꙗ҆́кѡ до́брѣ ѿвѣща̀ и҆̀мъ, вопросѝ є҆го̀: ка́ѧ є҆́сть пе́рваѧ всѣ́хъ за́повѣдїй; і҆и҃съ же ѿвѣща̀ є҆мꙋ̀: ꙗ҆́кѡ пе́рвѣйши всѣ́хъ за́повѣдїй: слы́ши і҆и҃лю, гдⷭ҇ь бг҃ъ ва́шъ, гдⷭ҇ь є҆ди́нъ є҆́сть. и҆ возлю́биши гдⷭ҇а бг҃а твоего̀ всѣ́мъ се́рдцемъ твои́мъ, и҆ все́ю дꙋше́ю твое́ю, и҆ всѣ́мъ ᲂу҆мо́мъ твои́мъ, и҆ все́ю крѣ́постїю твое́ю: сїѧ̀ є҆́сть пе́рваѧ за́повѣдь. и҆ втора́ѧ подо́бна є҆́й: возлю́биши бли́жнѧго своего̀ ꙗ҆́кѡ са́мъ себѐ. бо́льши сею̀ и҆́на за́повѣдь нѣ́сть. и҆ речѐ є҆мꙋ̀ кни́жникъ: до́брѣ ᲂу҆чи́телю, вои́стиннꙋ речѐ, ꙗ҆́кѡ є҆ди́нъ є҆́сть бг҃ъ, и҆ нѣ́сть и҆́нъ ра́звѣ є҆гѡ̀. и҆ є҆́же люби́ти є҆го̀ всѣ́мъ се́рдцемъ, и҆ всѣ́мъ ра́зꙋмомъ, и҆ все́ю дꙋше́ю, и҆ все́ю крѣ́постїю: и҆ є҆́же люби́ти бли́жнѧго ꙗ҆́кѡ себѐ, бо́ле є҆́сть всѣ́хъ всесожже́нїй и҆ же́ртвъ. і҆и҃съ же ви́дѣвъ, ꙗ҆́кѡ смы́сленнѡ ѿвѣща̀, речѐ є҆мꙋ̀: не дале́че є҆сѝ ѿ црⷭ҇твїѧ бж҃їѧ. и҆ никто́же смѣ́ѧше ктомꙋ̀ є҆го̀ вопроси́ти. и҆ ѿвѣща́въ і҆и҃съ глаго́лаше, ᲂу҆чѧ̀ въ це́ркви: ка́кѡ глаго́лютъ кни́жницы, ꙗ҆́кѡ хрⷭ҇то́съ сн҃ъ є҆́сть дв҃довъ; то́й бо дв҃дъ речѐ дх҃омъ ст҃ы́мъ: глаго́ла гдⷭ҇ь гдⷭ҇еви моемꙋ̀: сѣдѝ ѡ҆деснꙋ́ю менѐ, до́ндеже положꙋ̀ врагѝ твоѧ̀ подно́жїе нога́ма твои́ма. са́мъ ᲂу҆́бѡ дв҃дъ глаго́летъ є҆го̀ гдⷭ҇а: и҆ ѿкꙋ́дꙋ сн҃ъ є҆мꙋ̀ є҆́сть; и҆ мно́гъ наро́дъ послꙋ́шаше є҆гѡ̀ въ сла́дость. ",
}

add_evangelie_marka {
  ["номер"] = 57,
  ["комментарий"] = "Мк., 57 зач., XII, 38–44.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: блюди́теся от кни́жник, хотя́щих во одея́ниих ходи́ти, и целова́ния на то́ржищих, и преждеседа́ния на со́нмищах, и первовозлежа́ния на ве́черях, пояда́юще до́мы вдови́ц и непщева́нием дале́че моля́щеся, си́и прии́мут ли́шшее осужде́ние. И сед Иису́с пря́мо сокро́вищному храни́лищу, зря́ше, ка́ко наро́д ме́щет медь в сокро́вищное храни́лище. И мно́зи бога́тии вмета́ху мно́га. И прише́дши еди́на вдови́ца убо́га, вве́рже ле́пте две, е́же есть кодра́нт. И призва́в ученики́ Своя́, рече́ им: ами́нь глаго́лю вам, я́ко вдови́ца сия́ убо́гая мно́жае всех вве́рже вмета́ющих в сокро́вищное храни́лище. Вси бо от избы́тка своего́ вверго́ша, сия́ же от лише́ния своего́ вся, ели́ка име́яше, вве́рже, все житие́ свое́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: блюди́тесѧ ѿ кни̑жникъ, хотѧ́щихъ въ ѡ҆дѣѧ́нїихъ ходи́ти, и҆ цѣлова̑нїѧ на то́ржищахъ: и҆ преждесѣда̑нїѧ на со́нмищахъ, и҆ первовозлежа̑нїѧ на ве́черѧхъ: поѧда́юще до́мы вдови́цъ, и҆ непщева́нїемъ дале́че молѧ́щесѧ, сі́и прїи́мꙋтъ ли́шшее ѡ҆сꙋжде́нїе. и҆ сѣ́дъ і҆и҃съ прѧ́мѡ сокро́вищномꙋ храни́лищꙋ, зрѧ́ше, ка́кѡ наро́дъ ме́щетъ мѣ́дь въ сокро́вищное храни́лище: и҆ мно́зи бога́тїи вмета́хꙋ мнѡ́га. и҆ прише́дши є҆ди́на вдови́ца ᲂу҆бо́га, вве́рже ле́птѣ двѣ̀, є҆́же є҆́сть кодра́нтъ. и҆ призва́въ ᲂу҆ченикѝ своѧ̀, речѐ и҆̀мъ: а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ вдови́ца сїѧ̀ ᲂу҆бо́гаѧ мно́жае всѣ́хъ вве́рже вмета́ющихъ въ сокро́вищное храни́лище. вси́ бо ѿ и҆збы́тка своегѡ̀ вверго́ша, сїѧ́ же ѿ лише́нїѧ своегѡ̀, всѧ̑ є҆ли̑ка и҆мѣ́ѧше вве́рже, всѐ житїѐ своѐ. ",
}

add_evangelie_marka {
  ["номер"] = 58,
  ["комментарий"] = "Мк., 58 зач., XIII, 1–8.",
  ["текст_ру"] = "Во вре́мя о́но, исходя́щу Иису́сови от це́ркве, глаго́ла Ему́ еди́н от учени́к Его́: Учи́телю, виждь, каково́ ка́мение и какова́ зда́ния. И отвеща́в Иису́с рече́ ему́: ви́диши ли сия́ вели́ка зда́ния? Не и́мать оста́ти зде ка́мень на ка́мени, и́же не разори́тся. И седя́щу Ему́ на горе́ Елео́нстей пря́мо це́ркве, вопроша́ху Его́ еди́наго Петр и Иа́ков, и Иоа́нн и Андре́й: рцы нам, когда́ сия́ бу́дут? И ко́е бу́дет зна́мение, егда́ и́мут вся сия́ сконча́тися? Иису́с же отвеща́в им, нача́т глаго́лати: блюди́теся, да не кто вас прельсти́т. Мно́зи бо прии́дут во и́мя Мое́, глаго́люще, я́ко Аз есмь, и мно́ги прельстя́т. Егда́ же услы́шите бра́ни и слы́шания бра́нем, не ужаса́йтеся, подоба́ет бо бы́ти, но не у кончи́на. Воста́нет бо язы́к на язы́к, и ца́рство на ца́рство, и бу́дут тру́си по места́м, и бу́дут гла́ди и мяте́жи. Нача́ло боле́знем сия́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆сходѧ́щꙋ і҆и҃сови ѿ це́ркве, глаго́ла є҆мꙋ̀ є҆ди́нъ ѿ ᲂу҆чени́къ є҆гѡ̀: ᲂу҆чи́телю, ви́ждь каково̀ ка́менїе, и҆ какова̀ зда̑нїѧ. и҆ ѿвѣща́въ і҆и҃съ речѐ є҆мꙋ̀: ви́диши ли сїѧ̀ вели̑ка зда́нїѧ; не и҆́мать ѡ҆ста́ти здѣ̀ ка́мень на ка́мени, и҆́же не разори́тсѧ. и҆ сѣдѧ́щꙋ є҆мꙋ̀ на горѣ̀ є҆леѡ́нстѣй прѧ́мѡ це́ркве, вопроша́хꙋ є҆го̀ є҆ди́наго пе́тръ, и҆ і҆а́кѡвъ, и҆ і҆ѡа́ннъ, и҆ а҆ндре́й: рцы̀ на́мъ, когда̀ сїѧ̑ бꙋ́дꙋтъ; и҆ ко́е бꙋ́детъ зна́менїе, є҆гда̀ и҆́мꙋтъ всѧ̑ сїѧ̑ сконча́тисѧ; і҆и҃съ же ѿвѣща́въ и҆̀мъ, нача́тъ глаго́лати: блюди́тесѧ, да не кто̀ ва́съ прельсти́тъ. мно́зи бо прїи́дꙋтъ во и҆́мѧ моѐ, глаго́люще, ꙗ҆́кѡ а҆́зъ є҆́смь: и҆ мнѡ́ги прельстѧ́тъ. є҆гда́ же ᲂу҆слы́шите бра̑ни, и҆ слы̑шанїѧ бра́нємъ, не ᲂу҆жаса́йтесѧ: подоба́етъ бо бы́ти, но не ᲂу҆̀ кончи́на. воста́нетъ бо ꙗ҆зы́къ на ꙗ҆зы́къ, и҆ црⷭ҇тво на црⷭ҇тво: и҆ бꙋ́дꙋтъ трꙋ́си по мѣста́мъ, и҆ бꙋ́дꙋтъ гла́ди и҆ мѧте́жи, нача́ло болѣ́знемъ сїѧ̑. ",
}

add_evangelie_marka {
  ["номер"] = 59,
  ["комментарий"] = "Мк., 59 зач., XIII, 9–13.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: блюди́теся вы са́ми, предадя́т бо вы в со́нмища, и на собо́рищах бие́ни бу́дете, и пред воево́дами и цари́ веде́ни бу́дете Мене́ ра́ди, во свиде́тельство им. И во всех язы́цех подоба́ет пре́жде пропове́датися Ева́нгелию. Егда́ же поведу́т вы предаю́ще, не пре́жде пецы́теся, что возглаго́лете, ни поуча́йтеся, но е́же а́ще да́стся вам в той час, се глаго́лите, не вы бо бу́дете глаго́лющии, но Дух Святы́й. Преда́ст же брат бра́та на смерть, и оте́ц ча́до, и воста́нут ча́да на роди́тели и убию́т их. И бу́дете ненави́дими все́ми и́мене Моего́ ра́ди, претерпе́вый же до конца́, сей спасе́н бу́дет. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: блюди́тесѧ вы̀ са́ми: предадѧ́тъ бо вы̀ въ со́нмища, и҆ на собо́рищахъ бїе́ни бꙋ́дете, и҆ пред̾ воево́дами и҆ царѝ веде́ни бꙋ́дете менѐ ра́ди, во свидѣ́тельство и҆̀мъ. и҆ во всѣ́хъ ꙗ҆зы́цѣхъ подоба́етъ пре́жде проповѣ́датисѧ є҆ѵⷢ҇лїю. є҆гда́ же поведꙋ́тъ вы̀ предаю́ще, не пре́жде пецы́тесѧ, что̀ возглаго́лете, ни поꙋча́йтесѧ: но є҆́же а҆́ще да́стсѧ ва́мъ въ то́й ча́съ, сѐ глаго́лите: не вы́ бо бꙋ́дете глаго́лющїи, но дх҃ъ ст҃ы́й. преда́стъ же бра́тъ бра́та на сме́рть, и҆ ѻ҆те́цъ ча́до: и҆ воста́нꙋтъ ча̑да на роди́тели, и҆ ᲂу҆бїю́тъ и҆̀хъ. и҆ бꙋ́дете ненави́дими всѣ́ми и҆́мене моегѡ̀ ра́ди: претерпѣ́вый же до конца̀, се́й спасе́нъ бꙋ́детъ. ",
}

add_evangelie_marka {
  ["номер"] = 60,
  ["комментарий"] = "Мк., 60 зач., XIII, 14-23.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: егда́ у́зрите ме́рзость запусте́ния, рече́нную Дании́лом проро́ком, стоя́щу, иде́же не подоба́ет, чтый да разуме́ет, тогда́ су́щии во Иуде́и да бежа́т на го́ры, и и́же на кро́ве, да не сла́зит в дом, ни да вни́дет взя́ти чесо́ от до́му своего́, и и́же на селе́ сый, да не возврати́тся вспять взя́ти ри́зу свою́. Го́ре же непра́здным и доя́щым в ты́я дни. Моли́теся же, да не бу́дет бе́жество ва́ше в зиме́. Бу́дут бо дни ти́и скорбь, якова́ не бысть такова́ от нача́ла созда́ния, е́же созда́ Бог, до ны́не, и не бу́дет. И а́ще не бы Госпо́дь прекрати́л дний, не бы у́бо спасла́ся вся́ка плоть, но избра́нных ра́ди, и́хже избра́, прекрати́т дни. Тогда́ а́ще кто рече́т вам: се зде Христо́с, или́ се о́нде, не ими́те ве́ры. Воста́нут бо лжехри́сти и лжепроро́цы и дадя́т зна́мения и чудеса́, е́же прельсти́ти, а́ще возмо́жно, и избра́нныя. Вы же блюди́теся, се пре́жде рех вам вся. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: є҆гда̀ ᲂу҆́зрите ме́рзость запꙋстѣ́нїѧ, рече́ннꙋю данїи́ломъ проро́комъ, стоѧ́щꙋ и҆дѣ́же не подоба́етъ, чты́й да разꙋмѣ́етъ: тогда̀ сꙋ́щїи во і҆ꙋде́и да бѣжа́тъ на го́ры. и҆ и҆́же на кро́вѣ, да не сла́зитъ въ до́мъ, ни да вни́детъ взѧ́ти чесѡ̀ ѿ до́мꙋ своегѡ̀. и҆ и҆́же на селѣ̀ сы́й, да не возврати́тсѧ вспѧ́ть взѧ́ти ри́зꙋ свою̀. го́ре же непра̑зднымъ и҆ доѧ́щымъ въ ты́ѧ днѝ. моли́тесѧ же, да не бꙋ́детъ бѣ́жество ва́ше въ зимѣ̀. бꙋ́дꙋтъ бо днѝ ті́и ско́рбь, ꙗ҆кова̀ не бы́сть такова̀ ѿ нача́ла созда́нїѧ, є҆́же созда̀ бг҃ъ, до ны́нѣ, и҆ не бꙋ́детъ. и҆ а҆́ще не бы̀ гдⷭ҇ь прекрати́лъ дні́й, не бы̀ ᲂу҆́бѡ спасла́сѧ всѧ́ка пло́ть: но и҆збра́нныхъ ра́ди, и҆̀хже и҆збра̀, прекрати́тъ днѝ. тогда̀ а҆́ще кто̀ рече́тъ ва́мъ: сѐ здѣ̀ хрⷭ҇то́съ, и҆лѝ сѐ ѻ҆́ндѣ: не и҆ми́те вѣ́ры. воста́нꙋтъ бо лжехрі́сти и҆ лжепроро́цы, и҆ дадѧ́тъ зна́мєнїѧ и҆ чꙋдеса̀ є҆́же прельсти́ти, а҆́ще возмо́жно, и҆ и҆збра̑нныѧ: вы́ же блюди́тесѧ: сѐ пре́жде рѣ́хъ ва́мъ всѧ̑. ",
}

add_evangelie_marka {
  ["номер"] = 61,
  ["комментарий"] = "Мк., 61 зач., XIII, 24–31.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: в ты́я дни, по ско́рби той, со́лнце поме́ркнет, и луна́ не даст све́та своего́, и зве́зды бу́дут с небесе́ спа́дающя, и си́лы, я́же на небесе́х, подви́жутся. И тогда́ у́зрят Сы́на Челове́ческаго гряду́ща на о́блацех с си́лою и сла́вою мно́гою. И тогда́ по́слет А́нгелы Своя́ и собере́т избра́нныя Своя́ от четы́рех ветр, от конца́ земли́ до конца́ не́ба. От смоко́вницы же научи́теся при́тчи: егда́ уже́ ве́твие ея́ бу́дет мла́до и израща́ет ли́ствие, ве́дите, я́ко близ есть жа́тва. Та́ко и вы, егда́ сия́ ви́дите быва́юща, ве́дите, я́ко близ есть, при две́рех. Ами́нь глаго́лю вам, я́ко не и́мать прейти́ род сей, до́ндеже вся сия́ бу́дут. Не́бо и земля́ пре́йдут, словеса́ же Моя́ не пре́йдут. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: въ ты́ѧ днѝ по ско́рби то́й со́лнце поме́ркнетъ, и҆ лꙋна̀ не да́стъ свѣ́та своегѡ̀. и҆ ѕвѣ́зды бꙋ́дꙋтъ съ нб҃сѐ спа́дающе, и҆ си̑лы ꙗ҆̀же на нб҃сѣ́хъ, подви́жꙋтсѧ. и҆ тогда̀ ᲂу҆́зрѧтъ сн҃а чл҃вѣ́ческаго грѧдꙋ́ща на ѻ҆́блацѣхъ, съ си́лою и҆ сла́вою мно́гою. и҆ тогда̀ по́слетъ а҆́гг҃лы своѧ̀, и҆ собере́тъ и҆збра̑нныѧ своѧ̀ ѿ четы́рехъ вѣ̑тръ, ѿ конца̀ землѝ до конца̀ не́ба. ѿ смоко́вницы же наꙋчи́тесѧ при́тчи: є҆гда̀ ᲂу҆жѐ вѣ́твїе є҆ѧ̀ бꙋ́детъ мла́до, и҆ и҆зраща́етъ ли́ствїе, вѣ́дите, ꙗ҆́кѡ бли́зъ є҆́сть жа́тва. та́кѡ и҆ вы̀, є҆гда̀ сїѧ̑ ви́дите быва́юща, вѣ́дите, ꙗ҆́кѡ бли́зъ є҆́сть при две́рехъ. а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ не и҆́мать прейтѝ ро́дъ се́й, до́ндеже всѧ̑ сїѧ̑ бꙋ́дꙋтъ. нб҃о и҆ землѧ̀ пре́йдетъ, словеса́ же моѧ̀ не пре́йдꙋтъ. ",
}

add_evangelie_marka {
  ["номер"] = 62,
  ["комментарий"] = "Мк., 62 зач., XIII, 31 – XIV, 2.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: не́бо и земля́ пре́йдут, словеса́ же Моя́ не пре́йдут. О дни же том или́ о часе́ никто́же весть, ни А́нгели, и́же суть на небесе́х, ни Сын, то́кмо Оте́ц. Блюди́те, бди́те и моли́теся, не ве́сте бо, когда́ вре́мя бу́дет. Я́коже челове́к отходя́ оста́вль дом свой, и дав рабо́м свои́м власть, и кому́ждо де́ло свое́, и вратарю́ повеле́, да бдит. Бди́те у́бо, не ве́сте бо, когда́ госпо́дь до́му прии́дет, ве́чер, или́ полу́нощи, или́ в петлоглаше́ние, или́ у́тро, да не прише́д внеза́пу, обря́щет вы спя́щя. А я́же вам глаго́лю, всем глаго́лю: бди́те. Бе же Па́сха и опресно́цы по двою́ дни́ю, и иска́ху архиере́е и кни́жницы, ка́ко Его́ ле́стию е́мше убию́т. Глаго́лаху же: но не в пра́здник, еда́ ка́ко молва́ бу́дет лю́дска. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: нб҃о и҆ землѧ̀ пре́йдетъ, словеса́ же моѧ̀ не пре́йдꙋтъ. ѡ҆ дни́ же то́мъ, и҆лѝ ѡ҆ часѣ̀, никто́же вѣ́сть, ни а҆́гг҃ли, и҆̀же сꙋ́ть на нб҃сѣ́хъ, ни сн҃ъ, то́кмѡ ѻ҆ц҃ъ. блюди́те, бди́те, и҆ моли́тесѧ: не вѣ́сте бо когда̀ вре́мѧ бꙋ́детъ. ꙗ҆́коже человѣ́къ ѿходѧ̀ ѡ҆ста́вль до́мъ сво́й, и҆ да́въ рабѡ́мъ свои́мъ вла́сть, и҆ комꙋ́ждо дѣ́ло своѐ: и҆ вратарю̀ повелѣ̀, да бди́тъ. бди́те ᲂу҆́бѡ, не вѣ́сте бо когда̀ гдⷭ҇ь до́мꙋ прїи́детъ: ве́черъ, и҆лѝ полꙋ́нощи, и҆лѝ въ пѣтлоглаше́нїе, и҆лѝ ᲂу҆́трѡ. да не прише́дъ внеза́пꙋ, ѡ҆брѧ́щетъ вы̀ спѧ́щѧ. а҆ ꙗ҆̀же ва́мъ глаго́лю, всѣ̑мъ глаго́лю: бди́те. бѣ́ же па́сха, и҆ ѻ҆прѣсно́цы по двою̀ дні́ю. и҆ и҆ска́хꙋ а҆рхїере́є и҆ кни́жницы, ка́кѡ є҆го̀ ле́стїю є҆́мше ᲂу҆бїю́тъ. глаго́лахꙋ же: но не въ пра́здникъ, є҆да̀ ка́кѡ молва̀ бꙋ́детъ лю́дска. ",
}

add_evangelie_marka {
  ["номер"] = 63,
  ["комментарий"] = "Мк., 63 зач., XIV, 3-9.",
  ["текст_ру"] = "Во вре́мя о́но, су́щу Иису́сови в Вифа́нии, в дому́ Си́мона прокаже́ннаго, возлежа́щу Ему́, прии́де жена́, иму́щи алава́стр ми́ра на́рднаго пистики́я многоце́нны, и сокру́шши алава́стр, возлива́ше Ему́ на главу́. Бя́ху же не́цыи негоду́юще в себе́ и глаго́люще: во что ги́бель сия́ ми́рная бысть? Можа́ше бо сие́ продано́ бы́ти вя́щше трех сот пе́нязь и да́тися ни́щым. И преща́ху ей. Иису́с же рече́: оста́вите ю́, что ей труды́ даете́? Добро́ де́ло соде́ла о Мне. Всегда́ бо ни́щыя и́мате с собо́ю, и егда́ хо́щете, мо́жете им добро́ твори́ти, Мене́ же не всегда́ и́мате. Е́же име́ сия́, сотвори́, предвари́ пома́зати Мое́ те́ло на погребе́ние. Ами́нь глаго́лю вам: иде́же а́ще пропове́стся Ева́нгелие сие́ во всем ми́ре, и е́же сотвори́ сия́, глаго́лано бу́дет в па́мять ея́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, сꙋ́щꙋ і҆и҃сови въ виѳа́нїи, въ домꙋ̀ сі́мѡна прокаже́ннагѡ, возлежа́щꙋ є҆мꙋ̀, прїи́де жена̀ и҆мꙋ́щи а҆лава́стръ мѵ́ра на́рднагѡ пїстїкі́ѧ многоцѣ́нны: и҆ сокрꙋ́шши а҆лава́стръ, возлива́ше є҆мꙋ̀ на главꙋ̀. бѧ́хꙋ же нѣ́цыи негодꙋ́юще въ себѣ̀, и҆ глаго́люще: во что̀ ги́бель сїѧ̀ мѵ́рнаѧ бы́сть; можа́ше бо сїѐ продано̀ бы́ти вѧ́щше тре́хъ сѡ́тъ пѣ́нѧзь, и҆ да́тисѧ ни́щымъ: и҆ преща́хꙋ є҆́й. і҆и҃съ же речѐ: ѡ҆ста́вите ю҆̀, что̀ є҆́й трꙋды̀ даетѐ; добро̀ дѣ́ло содѣ́ла ѡ҆ мнѣ̀. всегда́ бо ни́щыѧ и҆́мате съ собо́ю, и҆ є҆гда̀ хо́щете, мо́жете и҆̀мъ добро̀ твори́ти: мене́ же не всегда̀ и҆́мате. є҆́же і҆мѣ̀ сїѧ̀, сотворѝ: предварѝ пома́зати моѐ тѣ́ло на погребе́нїе. а҆ми́нь глаго́лю ва́мъ: и҆дѣ́же а҆́ще проповѣ́стсѧ є҆ѵⷢ҇лїе сїѐ во все́мъ мі́рѣ, и҆ є҆́же сотворѝ сїѧ̀, глаго́лано бꙋ́детъ въ па́мѧть є҆ѧ̀. ",
}

add_evangelie_marka {
  ["номер"] = 64,
  ["комментарий"] = "Мк., 64 зач., XIV, 10–42.",
  ["текст_ру"] = "Во вре́мя о́но, Иу́да Искарио́тский, еди́н от обоюна́десяте, и́де ко архиере́ем, да преда́ст Его́ им. Они́ же слы́шавше возра́довашася и обеща́ша ему́ сре́бреники да́ти. И иска́ше, ка́ко Его́ в подо́бно вре́мя преда́ст. И в пе́рвый день опресно́к, егда́ па́сху жря́ху, глаго́лаша Ему́ ученицы́ Его́: где хо́щеши, ше́дше угото́ваем, да я́си па́сху? И посла́ два от учени́к Свои́х и глаго́ла и́ма: иди́та во град, и сря́щет вас челове́к в скуде́льнице во́ду нося́, по нем иди́та. И иде́же а́ще вни́дет, рцы́та господи́ну до́му, я́ко Учи́тель глаго́лет: где есть вита́льница, иде́же па́сху со ученики́ Мои́ми снем? И той ва́ма пока́жет го́рницу ве́лию, по́стлану, гото́ву, ту угото́вайта нам. И изыдо́ста ученика́ Его́, и приидо́ста во град, и обрето́ста, я́коже рече́ и́ма, и угото́васта па́сху. И ве́черу бы́вшу прии́де со обемана́десяте. И возлежа́щым им и яду́щым, рече́ Иису́с: ами́нь глаго́лю вам, я́ко еди́н от вас преда́ст Мя, яды́й со Мно́ю. Они́ же нача́ша скорбе́ти и глаго́лати Ему́ еди́н по еди́ному: еда́ аз? И други́й: еда́ аз? Он же отвеща́в рече́ им: еди́н от обоюна́десяте, омочи́вый со Мно́ю в соли́ло. Сын у́бо Челове́ческий и́дет, я́коже есть пи́сано о Нем, го́ре же челове́ку тому́, и́мже Сын Челове́ческий преда́стся, добре́е бы́ло бы ему́, а́ще не бы роди́лся челове́к той. И яду́щым им, прие́м Иису́с хлеб, и благослови́в, преломи́ и даде́ им, и рече́: приими́те, яди́те, сие́ есть Те́ло Мое́. И прии́м ча́шу, хвалу́ возда́в, даде́ им, и пи́ша от нея́ вси. И рече́ им: сия́ есть Кровь Моя́ Но́ваго Заве́та, за мно́ги излива́ема. Ами́нь глаго́лю вам, я́ко ктому́ не и́мам пи́ти от плода́ ло́знаго до дне того́, егда́ е́ пию́ но́во во Ца́рствии Бо́жии. И воспе́вше изыдо́ша в го́ру Елео́нскую. И глаго́ла им Иису́с, я́ко вси соблазните́ся о Мне в нощь сию́. Пи́сано бо есть: поражу́ па́стыря, и разы́дутся о́вцы. Но пото́м, егда́ воскре́сну, варя́ю вы в Галиле́и. Петр же рече́ Ему́: а́ще и вси соблазня́тся, но не аз. И глаго́ла ему́ Иису́с: ами́нь глаго́лю тебе́, я́ко ты днесь в нощь сию́, пре́жде да́же втори́цею пе́тель не возгласи́т, трикра́ты отве́ржешися Мене́. Он же мно́жае глаго́лаше па́че: а́ще же ми есть с Тобо́ю и умре́ти, не отве́ргуся Тебе́. Та́кожде и вси глаго́лаху. И приидо́ша в весь, е́йже и́мя Гефсима́ниа, и глаго́ла ученико́м Свои́м: седи́те зде, до́ндеже шед помолю́ся. И поя́т Петра́ и Иа́кова и Иоа́нна с Собо́ю, и нача́т ужаса́тися и тужи́ти. И глаго́ла им: приско́рбна есть душа́ Моя́ до сме́рти, бу́дите зде и бди́те. И преше́д ма́ло, паде́ на земли́ и моля́шеся, да а́ще возмо́жно есть, мимои́дет от Него́ час, и глаго́лаше: А́вва О́тче, вся возмо́жна Тебе́, мимонеси́ от Мене́ ча́шу сию́, но не е́же Аз хощу́, но е́же Ты. И прии́де, и обре́те их спя́щя, и глаго́ла Петро́ви: Си́моне, спи́ши ли? Не возмо́же еди́наго часа́ побде́ти? Бди́те и моли́теся, да не вни́дете в напа́сть, дух у́бо бодр, плоть же немощна́. И па́ки шед помоли́ся, то́жде сло́во рек. И возвра́щься обре́те я́ па́ки спя́щя, бя́ху бо очеса́ им тя́готна, и не ве́дяху, что бы́ша Ему́ отвеща́ли. И прии́де трети́цею и глаго́ла им: спи́те про́чее и почива́йте, приспе́ коне́ц, прии́де час, се предае́тся Сын Челове́ческий в ру́ки гре́шником. Воста́ните, и́дем, се предая́й Мя прибли́жися. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, і҆ꙋ́да і҆скарїѡ́тскїй, є҆ди́нъ ѿ ѻ҆боюна́десѧте, и҆́де ко а҆рхїере́ємъ, да преда́стъ є҆го̀ и҆̀мъ. ѻ҆ни́ же слы́шавше возра́довашасѧ, и҆ ѡ҆бѣща́ша є҆мꙋ̀ сре́бреники да́ти. и҆ и҆ска́ше, ка́кѡ є҆го̀ въ подо́бно вре́мѧ преда́стъ. и҆ въ пе́рвый де́нь ѻ҆прѣснѡ́къ, є҆гда̀ па́схꙋ жрѧ́хꙋ, глаго́лаша є҆мꙋ̀ ᲂу҆ченицы̀ є҆гѡ̀: гдѣ̀ хо́щеши, ше́дше ᲂу҆гото́ваемъ, да ꙗ҆́си па́схꙋ; и҆ посла̀ два̀ ѿ ᲂу҆чєни́къ свои́хъ, и҆ глаго́ла и҆̀мъ: и҆ди́та во гра́дъ, и҆ срѧ́щетъ ва́съ человѣ́къ, въ скꙋде́льницѣ во́дꙋ носѧ̀: по не́мъ и҆ди́та. и҆ и҆дѣ́же а҆́ще вни́детъ, рцы́та господи́нꙋ до́мꙋ, ꙗ҆́кѡ ᲂу҆чи́тель глаго́летъ: гдѣ̀ є҆́сть вита́льница, и҆дѣ́же па́схꙋ со ᲂу҆ченикѝ мои́ми снѣ́мъ; и҆ то́й ва́ма пока́жетъ го́рницꙋ ве́лїю по́стланꙋ, гото́вꙋ: тꙋ̀ ᲂу҆гото́вайта на́мъ. и҆ и҆зыдо́ста ᲂу҆чєника̀ є҆гѡ̀, и҆ прїидо́ста во гра́дъ, и҆ ѡ҆брѣто́ста ꙗ҆́коже речѐ и҆́ма: и҆ ᲂу҆гото́васта па́схꙋ. и҆ ве́черꙋ бы́вшꙋ прїи́де со ѻ҆бѣмана́десѧте: и҆ возлежа́щымъ и҆̀мъ, и҆ ꙗ҆дꙋ́щымъ, речѐ і҆и҃съ: а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ є҆ди́нъ ѿ ва́съ преда́стъ мѧ̀, ꙗ҆ды́й со мно́ю. ѻ҆ни́ же нача́ша скорбѣ́ти, и҆ глаго́лати є҆мꙋ̀ є҆ди́нъ по є҆ди́номꙋ: є҆да̀ а҆́зъ; и҆ дрꙋгі́й, є҆да̀ а҆́зъ; ѻ҆́нъ же ѿвѣща́въ речѐ и҆̀мъ: є҆ди́нъ ѿ ѻ҆боюна́десѧте, ѡ҆мочи́вый со мно́ю въ соли́ло. сн҃ъ ᲂу҆́бѡ человѣ́ческїй и҆́детъ, ꙗ҆́коже є҆́сть пи́сано ѡ҆ не́мъ: го́ре же человѣ́кꙋ томꙋ̀, и҆́мже сн҃ъ человѣ́ческїй преда́стсѧ. добрѣ́е бы́ло бы є҆мꙋ̀, а҆́ще не бы̀ роди́лсѧ человѣ́къ то́й. и҆ ꙗ҆дꙋ́щымъ и҆̀мъ, прїе́мъ і҆и҃съ хлѣ́бъ, и҆ благослови́въ преломѝ, и҆ дадѐ и҆̀мъ, и҆ речѐ: прїими́те, ꙗ҆ди́те: сїѐ є҆́сть тѣ́ло моѐ. и҆ прїи́мъ ча́шꙋ, хвалꙋ̀ возда́въ дадѐ и҆̀мъ: и҆ пи́ша ѿ неѧ̀ всѝ. и҆ речѐ и҆̀мъ: сїѧ̀ є҆́сть кро́вь моѧ̀ но́вагѡ завѣ́та, за мнѡ́ги и҆злива́ема. а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ ктомꙋ̀ не и҆́мамъ пи́ти ѿ плода̀ ло́знагѡ, до днѐ тогѡ̀, є҆гда̀ є҆̀ пїю̀ но́во во црⷭ҇твїи бж҃їи. и҆ воспѣ́вше и҆зыдо́ша въ го́рꙋ є҆леѡ́нскꙋю. и҆ глаго́ла и҆̀мъ і҆и҃съ, ꙗ҆́кѡ всѝ соблазните́сѧ ѡ҆ мнѣ̀ въ но́щь сїю̀. пи́сано бо є҆́сть: поражꙋ̀ па́стырѧ, и҆ разы́дꙋтсѧ ѻ҆́вцы. но пото́мъ є҆гда̀ воскре́снꙋ, варѧ́ю вы̀ въ галїле́и. пе́тръ же речѐ є҆мꙋ̀: и҆ а҆́ще всѝ соблазнѧ́тсѧ, но не а҆́зъ. и҆ глаго́ла є҆мꙋ̀ і҆и҃съ: а҆ми́нь глаго́лю тебѣ̀, ꙗ҆́кѡ ты̀ дне́сь въ но́щь сїю̀, пре́жде да́же втори́цею пѣ́телъ не возгласи́тъ, трикра́ты ѿве́ржешисѧ менѐ. ѻ҆́нъ же мно́жае глаго́лаше па́че: а҆́ще же мѝ є҆́сть съ тобо́ю и҆ ᲂу҆мре́ти, не ѿве́ргꙋсѧ тебѐ: та́кожде и҆ всѝ глаго́лахꙋ. и҆ прїидо́ша въ ве́сь, є҆́йже и҆́мѧ геѳсїма́нїа, и҆ глаго́ла ᲂу҆ченикѡ́мъ свои́мъ: сѣди́те здѣ̀, до́ндеже ше́дъ помолю́сѧ. и҆ поѧ́тъ петра̀, и҆ і҆а́кѡва, и҆ і҆ѡа́нна съ собо́ю: и҆ нача́тъ ᲂу҆жаса́тисѧ и҆ тꙋжи́ти. и҆ глаго́ла и҆̀мъ: приско́рбна є҆́сть дꙋша̀ моѧ̀ до сме́рти: бꙋ́дите здѣ̀, и҆ бди́те. и҆ преше́дъ ма́лѡ, падѐ на землѝ: и҆ молѧ́шесѧ, да а҆́ще возмо́жно є҆́сть, мимои́детъ ѿ негѡ̀ ча́съ. и҆ глаго́лаше: а҆́вва ѻ҆́ч҃е, всѧ̑ возмѡ́жна тебѣ̀, мимонесѝ ѿ менѐ ча́шꙋ сїю̀: но не є҆́же а҆́зъ хощꙋ̀, но є҆́же ты̀. и҆ прїи́де, и҆ ѡ҆брѣ́те и҆̀хъ спѧ́щѧ, и҆ глаго́ла петро́ви: сі́мѡне, спи́ши ли; не возмо́же є҆ди́нагѡ часа̀ побдѣ́ти. бди́те, и҆ моли́тесѧ, да не вни́дете въ напа́сть: дх҃ъ бо бо́дръ, пло́ть же немощна̀. и҆ па́ки ше́дъ помоли́сѧ, то́жде сло́во ре́къ. и҆ возвра́щсѧ ѡ҆брѣ́те ѧ҆̀ па́ки спѧ́щѧ, бѧ́хꙋ бо ѻ҆чеса̀ и҆̀мъ тѧ́готна, и҆ не вѣ́дѧхꙋ, что̀ бы́ша є҆мꙋ̀ ѿвѣща́ли. и҆ прїи́де трети́цею, и҆ глаго́ла и҆̀мъ: спи́те про́чее, и҆ почива́йте. приспѣ̀ коне́цъ, прїи́де ча́съ: сѐ предае́тсѧ сн҃ъ чл҃вѣ́ческїй въ рꙋ́ки грѣ́шникѡмъ. воста́ните и҆́демъ, сѐ предаѧ́й мѧ̀ прибли́жисѧ. ",
}

add_evangelie_marka {
  ["номер"] = 65,
  ["комментарий"] = "Мк., 65 зач., XIV, 43 – XV, 1.",
  ["текст_ру"] = "Во вре́мя о́но, глаго́лющу Иису́сови ко ученико́м Свои́м, прии́де Иу́да, еди́н сый от обоюна́десяте, и с ним наро́д мног со ору́жием и дреко́льми, от архиере́й и кни́жник и ста́рец. Даде́ же предая́й Его́ зна́мение им, глаго́ля: Его́же а́ще лобжу́, Той есть, ими́те Его́ и веди́те Его́ сохра́нно. И прише́д, а́бие присту́пль к Нему́, глаго́ла Ему́: Равви́, Равви́. И облобыза́ Его́. Они́ же возложи́ша ру́це свои́ на него́ и я́ша Его́. Еди́н же не́кто от стоя́щих извле́к нож, уда́ри раба́ архиере́ова и уре́за ему́ у́хо. И отвеща́в Иису́с рече́ им: я́ко на разбо́йника ли изыдо́сте со ору́жием и дреко́льми я́ти Мя? По вся дни бех при вас в це́ркви учя́, и не я́сте Мене́, но да сбу́дется Писа́ние. И оста́вльше Его́, вси бежа́ша. И еди́н не́кто ю́ноша и́де по Нем, оде́ян в плащани́цу по на́гу, и я́ша того́ ю́ношу. Он же оста́вль плащани́цу, наг бежа́ от них. И ведо́ша Иису́са ко архиере́ю, и снидо́шася к нему́ вси архиере́е и кни́жницы и ста́рцы. И Петр издале́ча в след Его́ и́де до внутрь во двор архиере́ов, и бе седя́ со слуга́ми и гре́яся при свещи́. Архиере́е же и весь сонм иска́ху на Иису́са свиде́тельства, да умертвя́т Его́, и не обрета́ху. Мно́зи бо лжесвиде́тельствоваху на Него́, и ра́вна свиде́телства не бя́ху. И не́цыи воста́вше лжесвиде́тельствоваху на Него́, глаго́люще: я́ко мы слы́шахом Его́ глаго́люща, я́ко Аз разорю́ це́рковь сию́ рукотворе́ную и треми́ де́ньми и́ну нерукотворе́ну сози́жду. И ни та́ко ра́вно бе свиде́тельство их. И воста́в архиере́й посреде́, вопроси́ Иису́са, глаго́ля: не отвещава́еши ли ничесо́же? Что си́и на Тя свиде́тельствуют? Он же молча́ше и ничто́же отвещава́ше. Па́ки архиере́й вопроси́ Его́ и глаго́ла Ему́: Ты ли еси́ Христо́с, Сын Благослове́ннаго? Иису́с же рече́: Аз есмь, и у́зрите Сы́на Челове́ческаго одесну́ю седя́ща си́лы и гряду́ща со о́блаки небе́сными. Архиере́й же растерза́в ри́зы своя́, глаго́ла: что еще́ тре́буем свиде́телей? Слы́шасте хулу́, что вам мни́тся? Они́ же вси осуди́ша Его́ бы́ти пови́нна сме́рти. И нача́ша не́цыи плюва́ти Нань, и прикрыва́ти лице́ Его́, и му́чити Его́, и глаго́лати Ему́: прорцы́. И слуги́ по лани́тома Его́ бия́ху. И су́щу Петро́ви во дворе́ ни́зу, прии́де еди́на от рабы́нь архиере́овых, и ви́девши Петра́ гре́ющася, воззре́вши на него́, глаго́ла: и ты с Назаряни́ном Иису́сом был еси́. Он же отве́ржеся, глаго́ля: не вем, ниже́ зна́ю, что ты глаго́леши. И изы́де вон на преддво́рие, и але́ктор возгласи́. И рабы́ня ви́девши его́ па́ки, нача́т глаго́лати предстоя́щым, я́ко сей от них есть. Он же па́ки отмета́шеся. И по ма́ле па́ки предстоя́щии глаго́лаху Петро́ви: вои́стинну от них еси́, и́бо Галиле́анин еси́, и бесе́да твоя́ подо́бится. Он же нача́ роти́тися и кля́тися, я́ко не вем Челове́ка Сего́, Его́же вы глаго́лете. И второ́е але́ктор возгласи́. И помяну́ Петр глаго́л, его́же рече́ ему́ Иису́с, я́ко пре́жде да́же пе́тель не возгласи́т двакра́ты, отве́ржешися Мене́ трикра́ты. И наче́н пла́кашеся. И а́бие нау́трия сове́т сотвори́ша архиере́е со ста́рцы и кни́жники, и весь сонм, связа́вше Иису́са ведо́ша и преда́ша Его́ Пила́ту. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, глаго́лющꙋ і҆и҃сови ко ᲂу҆ченикѡ́мъ свои́мъ, прїи́де і҆ꙋ́да є҆ди́нъ сы́й ѿ ѻ҆боюна́десѧти, и҆ съ ни́мъ наро́дъ мно́гъ со ѻ҆рꙋ́жїемъ и҆ дреко́льми, ѿ а҆рхїерє́й и҆ кни̑жникъ и҆ ста́рєцъ. даде́ же предаѧ́й є҆го̀ зна́менїе и҆̀мъ, глаго́лѧ: є҆го́же а҆́ще лобжꙋ̀, то́й є҆́сть: и҆ми́те є҆го̀, и҆ веди́те є҆го̀ сохра́ннѡ. и҆ прише́дъ, а҆́бїе пристꙋ́пль къ немꙋ̀, глаго́ла є҆мꙋ̀: равві̀, равві̀: и҆ ѡ҆блобыза̀ є҆го̀. ѻ҆ни́ же возложи́ша рꙋ́цѣ своѝ на него̀, и҆ ꙗ҆́ша є҆го̀. є҆ди́нъ же нѣ́кто ѿ стоѧ́щихъ и҆звле́къ но́жъ, ᲂу҆да́ри раба̀ а҆рхїере́ова, и҆ ᲂу҆рѣ́за є҆мꙋ̀ ᲂу҆́хо. и҆ ѿвѣща́въ і҆и҃съ речѐ и҆̀мъ: ꙗ҆́кѡ на разбо́йника ли и҆зыдо́сте со ѻ҆рꙋ́жїемъ и҆ дреко́льми, ꙗ҆́ти мѧ̀; по всѧ̀ днѝ бѣ́хъ при ва́съ въ цр҃кви ᲂу҆чѧ̀, и҆ не ꙗ҆́сте менѐ: но да сбꙋ́детсѧ писа́нїе. и҆ ѡ҆ста́вльше є҆го̀, всѝ бѣжа́ша. и҆ є҆ди́нъ нѣ́кто ю҆́ноша и҆́де по не́мъ, ѡ҆дѣ́ѧнъ въ плащани́цꙋ по на́гꙋ: и҆ ꙗ҆́ша того̀ ю҆́ношꙋ. ѻ҆́нъ же ѡ҆ста́вль плащани́цꙋ, на́гъ бѣжа̀ ѿ ни́хъ. и҆ ведо́ша і҆и҃са ко а҆рхїере́ю: и҆ снидо́шасѧ къ немꙋ̀ всѝ а҆рхїере́є, и҆ кни́жницы, и҆ ста́рцы. и҆ пе́тръ и҆здале́ча въ слѣ́дъ є҆гѡ̀ и҆́де, до внꙋ́трь во дво́ръ а҆рхїере́овъ: и҆ бѣ̀ сѣдѧ̀ со слꙋга́ми, и҆ грѣ́ѧсѧ при свѣщѝ. а҆рхїере́є же и҆ ве́сь со́нмъ и҆ска́хꙋ на і҆и҃са свидѣ́тельства, да ᲂу҆мертвѧ́тъ є҆го̀: и҆ не ѡ҆брѣта́хꙋ. мно́зи бо лжесвидѣ́тельствовахꙋ на него̀, и҆ ра́вна свидѣ́тєльства не бѧ́хꙋ. и҆ нѣ́цыи воста́вше лжесвидѣ́тельствовахꙋ на него̀, глаго́люще, ꙗ҆́кѡ мы̀ слы́шахомъ є҆го̀ глаго́люща: ꙗ҆́кѡ а҆́зъ разорю̀ це́рковь сїю̀ рꙋкотворе́нꙋю, и҆ тремѝ де́ньми и҆́нꙋ нерꙋкотворе́нꙋ сози́ждꙋ. и҆ ни та́кѡ ра́вно бѣ̀ свидѣ́тельство и҆́хъ. и҆ воста́въ а҆рхїере́й посредѣ̀, вопросѝ і҆и҃са, глаго́лѧ: не ѿвѣщава́еши ли ничесѡ́же, что̀ сі́и на тѧ̀ свидѣ́тельствꙋютъ; ѻ҆́нъ же молча́ше, и҆ ничто́же ѿвѣщава́ше. па́ки а҆рхїере́й вопросѝ є҆го̀, и҆ глаго́ла є҆мꙋ̀: ты́ ли є҆сѝ хрⷭ҇то́съ, сн҃ъ бл҃гослове́ннагѡ; і҆и҃съ же речѐ, а҆́зъ є҆́смь: и҆ ᲂу҆́зрите сн҃а чл҃вѣ́ческаго ѻ҆деснꙋ́ю сѣдѧ́ща си́лы, и҆ грѧдꙋ́ща со ѻ҆́блаки нбⷭ҇ными. а҆рхїере́й же растерза́въ ри́зы своѧ̀, глаго́ла: что̀ є҆щѐ тре́бꙋемъ свидѣ́телей; слы́шасте хꙋлꙋ̀, что̀ ва́мъ мни́тсѧ; ѻ҆ни́ же всѝ ѡ҆сꙋди́ша є҆го̀ бы́ти пови́нна сме́рти. и҆ нача́ша нѣ́цыи плюва́ти на́нь, и҆ прикрыва́ти лицѐ є҆гѡ̀, и҆ мꙋ́чити є҆го̀, и҆ глаго́лати є҆мꙋ̀: прорцы̀. и҆ слꙋгѝ по лани́тома є҆го̀ бїѧ́хꙋ. и҆ сꙋ́щꙋ петро́ви во дворѣ̀ ни́зꙋ, прїи́де є҆ди́на ѿ рабы́нь а҆рхїере́овыхъ: и҆ ви́дѣвши петра̀ грѣ́ющасѧ, воззрѣ́вши на него̀, глаго́ла: и҆ ты̀ съ назарѧни́номъ і҆и҃сомъ бы́лъ є҆сѝ. ѻ҆́нъ же ѿве́ржесѧ, глаго́лѧ: не вѣ́мъ, нижѐ зна́ю, что̀ ты̀ глаго́леши. и҆ и҆зы́де во́нъ на преддво́рїе: и҆ а҆ле́ктѡръ возгласѝ: и҆ рабы́нѧ ви́дѣвши є҆го̀ па́ки, нача́тъ глаго́лати предстоѧ́щымъ: ꙗ҆́кѡ се́й ѿ ни́хъ є҆́сть. ѻ҆́нъ же па́ки ѿмета́шесѧ. и҆ по ма́лѣ па́ки предстоѧ́щїи глаго́лахꙋ петро́ви: вои́стиннꙋ ѿ ни́хъ є҆сѝ, и҆́бо галїле́анинъ є҆сѝ, и҆ бесѣ́да твоѧ̀ подо́битсѧ. ѻ҆́нъ же нача̀ роти́тисѧ и҆ клѧ́тисѧ, ꙗ҆́кѡ не вѣ́мъ человѣ́ка сегѡ̀, є҆го́же вы̀ глаго́лете. и҆ второ́е а҆ле́ктѡръ возгласѝ. и҆ помѧнꙋ̀ пе́тръ глаго́лъ, є҆́же речѐ є҆мꙋ̀ і҆и҃съ: ꙗ҆́кѡ пре́жде да́же пѣ́телъ не возгласи́тъ двакра́ты, ѿве́ржешисѧ менѐ трикра́ты, и҆ наче́нъ пла́кашесѧ. и҆ а҆́бїе наꙋ́трїѧ, совѣ́тъ сотвори́ша а҆рхїере́є со ста́рцы и҆ кни́жники, и҆ ве́сь со́нмъ, свѧза́вше і҆и҃са ведо́ша, и҆ преда́ша є҆го̀ пїла́тꙋ. ",
}

add_evangelie_marka {
  ["номер"] = 66,
  ["комментарий"] = "Мк., 66 зач., XV, 1–15.",
  ["текст_ру"] = "Во вре́мя о́но, сове́т сотвори́ша архиере́е со ста́рцы и кни́жники, и весь сонм, связа́вше Иису́са ведо́ша и преда́ша Его́ Пила́ту. И вопроси́ Его́ Пила́т: Ты ли еси́ Царь Иуде́йский? Он же отвеща́в рече́ ему́: ты глаго́леши. И глаго́лаху на Него́ архиере́е мно́го. Пила́т же па́ки вопроси́ Его́, глаго́ля: не отвещава́еши ли ничто́же? Виждь, коли́ко на Тя свиде́тельствуют. Иису́с же ктому́ ничто́же отвеща́, я́ко диви́тися Пила́ту. На всяк же пра́здник отпуща́ше им еди́наго свя́зня, его́же проша́ху. Бе же нарица́емый Вара́вва с ко́вники свои́ми свя́зан, и́же в ко́ве уби́йство сотвори́ша. И возопи́в наро́д нача́ проси́ти, я́коже всегда́ творя́ше им. Пила́т же отвеща́ им, глаго́ля: хо́щете ли, пущу́ вам Царя́ Иуде́йска? Ве́дяше бо, я́ко за́висти ра́ди преда́ша Его́ архиере́е. Архиере́е же поману́ша наро́ду, да па́че Вара́вву пу́стит им. Пила́т же отвеща́в па́ки рече́ им: что у́бо хо́щете сотворю́, Его́же глаго́лете Царя́ Иуде́йска? Они́ же па́ки возопи́ша глаго́люще: пропни́ Его́. Пила́т же глаго́лаше им: что бо зло сотвори́? Они́ же и́злиха вопия́ху: пропни́ Его́. Пила́т же хотя́ наро́ду хоте́ние сотвори́ти, пусти́ им Вара́вву, и предаде́ Иису́са, бив, да про́пнут Его́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, совѣ́тъ сотвори́ша а҆рхїере́є со ста́рцы и҆ кни́жники, и҆ ве́сь со́нмъ, свѧза́вше і҆и҃са ведо́ша, и҆ преда́ша є҆го̀ пїла́тꙋ. и҆ вопросѝ є҆го̀ пїла́тъ: ты́ ли є҆сѝ цр҃ь і҆ꙋде́йскїй; ѻ҆́нъ же ѿвѣща́въ речѐ є҆мꙋ̀: ты̀ глаго́леши. и҆ глаго́лахꙋ на него̀ а҆рхїере́є мно́гѡ. пїла́тъ же па́ки вопросѝ є҆го̀, глаго́лѧ: не ѿвѣщава́еши ли ничто́же; ви́ждь, коли́кѡ на тѧ̀ свидѣ́тельствꙋютъ. і҆и҃съ же ктомꙋ̀ ничто́же ѿвѣща̀, ꙗ҆́кѡ диви́тисѧ пїла́тꙋ. на всѧ́къ же пра́здникъ ѿпꙋща́ше и҆̀мъ є҆ди́наго свѧ́знѧ, є҆го́же проша́хꙋ. бѣ́ же нарица́емый вара́вва, съ ко́вники свои́ми свѧ́занъ, и҆̀же въ ко́вѣ ᲂу҆бі́йство сотвори́ша. и҆ возопи́въ наро́дъ, нача̀ проси́ти, ꙗ҆́коже всегда̀ творѧ́ше и҆̀мъ. пїла́тъ же ѿвѣща̀ и҆̀мъ, глаго́лѧ: хо́щете ли, пꙋщꙋ̀ ва́мъ цр҃ѧ̀ і҆ꙋде́йска; вѣ́дѧше бо, ꙗ҆́кѡ за́висти ра́ди преда́ша є҆го̀ а҆рхїере́є. а҆рхїере́є же поманꙋ́ша наро́дꙋ, да па́че вара́ввꙋ пꙋ́ститъ и҆̀мъ. пїла́тъ же ѿвѣща́въ, па́ки речѐ и҆̀мъ: что̀ ᲂу҆́бѡ хо́щете сотворю̀, є҆го́же глаго́лете цр҃ѧ̀ і҆ꙋде́йска; ѻ҆ни́ же па́ки возопи́ша, глаго́люще: пропнѝ є҆го̀. пїла́тъ же глаго́лаше и҆̀мъ: что́ бо ѕло̀ сотворѝ; ѻ҆ни́ же и҆́злиха вопїѧ́хꙋ: пропнѝ є҆го̀. пїла́тъ же хотѧ̀ наро́дꙋ хотѣ́нїе сотвори́ти, пꙋстѝ и҆̀мъ вара́ввꙋ: и҆ предадѐ і҆и҃са, би́въ, да про́пнꙋтъ є҆го̀. ",
}

add_evangelie_marka {
  ["номер"] = 67,
  ["комментарий"] = "Мк., 67 зач., XV, 16–32.",
  ["текст_ру"] = "Во вре́мя о́но, во́ини ведо́ша Иису́са внутрь двора́, е́же есть прето́р, и созва́ша всю спи́ру, и облеко́ша Его́ в препря́ду, и возложи́ша на Него́ спле́тше терно́в вене́ц, и нача́ша целова́ти Его́ и глаго́лати: ра́дуйся, Царю́ Иуде́йский. И бия́ху Его́ по главе́ тро́стию, и плюва́ху на Него́, и прегиба́юще коле́на покланя́хуся Ему́. И егда́ поруга́шася Ему́, совлеко́ша с Него́ препря́ду и облеко́ша Его́ в ри́зы Своя́, и изведо́ша Его́, да про́пнут Его́. И заде́ша мимоходя́щу не́коему Си́мону Кирине́ю, гряду́щу с села́, отцу́ Алекса́ндрову и Ру́фову, да во́змет крест Его́. И приведо́ша Его́ на Голго́фу ме́сто, е́же есть сказа́емо Ло́бное ме́сто. И дая́ху Ему́ пи́ти есмирнисме́но вино́, Он же не прия́т. И распе́ншии Его́ раздели́ша ри́зы Его́, мета́юще жре́бий о них, кто что во́змет. Бе же час тре́тий, и распя́ша Его́. И бе написа́ние вины́ Его́ напи́сано: Царь Иуде́йск. И с Ним распя́ша два разбо́йника, еди́наго одесну́ю и еди́наго ошу́юю Его́. И сбы́стся Писа́ние, е́же глаго́лет: и со беззако́нными вмени́ся. И мимоходя́щии ху́ляху Его́, покива́юще глава́ми свои́ми и глаго́люще: уа́, разоря́яй це́рковь и треми́ де́ньми созида́яй, спаси́ся Сам и сни́ди со креста́. Та́кожде и архиере́е руга́ющеся, друг ко дру́гу с кни́жники глаго́лаху: и́ны спасе́, Себе́ ли не мо́жет спасти́? Христо́с, Царь Изра́илев, да сни́дет ны́не со креста́, да ви́дим и ве́ру име́м Ему́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, во́ини ведо́ша і҆и҃са: внꙋ́трь двора̀, є҆́же є҆́сть претѡ́ръ, и҆ созва́ша всю̀ спі́рꙋ: и҆ ѡ҆блеко́ша є҆го̀ въ препрѧ́дꙋ, и҆ возложи́ша на него̀ спле́тше терно́въ вѣне́цъ: и҆ нача́ша цѣлова́ти є҆го̀, и҆ глаго́лати: ра́дꙋйсѧ цр҃ю̀ і҆ꙋде́йскїй. и҆ бїѧ́хꙋ є҆го̀ по главѣ̀ тро́стїю, и҆ плюва́хꙋ на него̀, и҆ прегиба́юще колѣ́на, покланѧ́хꙋсѧ є҆мꙋ̀. и҆ є҆гда̀ порꙋга́шасѧ є҆мꙋ̀, совлеко́ша съ негѡ̀ препрѧ́дꙋ, и҆ ѡ҆блеко́ша є҆го̀ въ ри̑зы своѧ̀: и҆ и҆зведо́ша є҆го̀, да про́пнꙋтъ є҆го̀. и҆ задѣ́ша мимоходѧ́щꙋ нѣ́коемꙋ сі́мѡнꙋ кѷрине́ю, грѧдꙋ́щꙋ съ села̀, ѻ҆тцꙋ̀ а҆леѯа́ндровꙋ и҆ рꙋ́фовꙋ, да во́з̾метъ крⷭ҇тъ є҆гѡ̀. и҆ приведо́ша є҆го̀ на голго́ѳꙋ мѣ́сто: є҆́же є҆́сть сказа́емо, ло́бное мѣ́сто. и҆ даѧ́хꙋ є҆мꙋ̀ пи́ти є҆смѷрнїсме́но вїно̀: ѻ҆́нъ же не прїѧ́тъ. и҆ распе́ншїи є҆го̀ раздѣли́ша ри̑зы є҆гѡ̀, мета́юще жре́бїй ѡ҆ ни́хъ, кто̀ что̀ во́з̾метъ. бѣ́ же ча́съ тре́тїй, и҆ распѧ́ша є҆го̀. и҆ бѣ̀ написа́нїе вины̀ є҆гѡ̀ напи́сано: цр҃ь і҆ꙋде́йскъ. и҆ съ ни́мъ распѧ́ша два̀ разбѡ́йника, є҆ди́наго ѡ҆деснꙋ́ю, и҆ є҆ди́наго ѡ҆шꙋ́юю є҆гѡ̀. и҆ сбы́стсѧ писа́нїе є҆́же глаго́летъ: и҆ со беззако́нными вмѣни́сѧ. и҆ мимоходѧ́щїи хꙋ́лѧхꙋ є҆го̀, покива́юще глава́ми свои́ми, и҆ глаго́люще: ᲂу҆а̀, разорѧ́ѧй цр҃ковь, и҆ тремѝ де́ньми созида́ѧй, спаси́сѧ са́мъ, и҆ сни́ди съ крⷭ҇та̀. та́коже и҆ а҆рхїере́є рꙋга́ющесѧ дрꙋ́гъ ко дрꙋ́гꙋ съ кни́жники, глаго́лахꙋ: и҆́ны спасѐ, себе́ ли не мо́жетъ спастѝ; хрⷭ҇то́съ цр҃ь і҆и҃левъ да сни́детъ ны́нѣ съ крⷭ҇та̀, да ви́димъ и҆ вѣ́рꙋ и҆ме́мъ є҆мꙋ̀. ",
}

add_evangelie_marka {
  ["номер"] = 67,
