  ["комментарий"] = "Мк., 68 зач., XV, 22, 25, 33–41.",
  ["текст_ру"] = "Во вре́мя о́но, во́ини пое́мше Иису́са, ведо́ша да Его́ ра́спнут, и приведо́ша Его́ на Голго́фу ме́сто, е́же есть сказа́емо Ло́бное ме́сто. Бе же час тре́тий, и распя́ша Его́. Бы́вшу же часу́ шесто́му, тма бысть по всей земли́ до часа́ девя́таго. И в час девя́тый возопи́ Иису́с гла́сом ве́лиим, глаго́ля: Елои́, Елои́, лима́ савахфани́? Е́же есть сказа́емо: Бо́же Мой, Бо́же Мой, почто́ Мя оста́вил еси́? И не́цыи от предстоя́щих слы́шавше, глаго́лаху: се Илию́ гласи́т. Тек же еди́н, и напо́лнив гу́бу о́цта, и возло́жь на трость, напоя́ше Его́, глаго́ля: оста́вите, да ви́дим, а́ще прии́дет Илиа́ сня́ти Его́. Иису́с же пущь глас ве́лий, и́здше. И заве́са церко́вная раздра́ся на дво́е, свы́ше до ни́зу. Ви́дев же со́тник стоя́й пря́мо Ему́, я́ко та́ко возопи́в и́здше, рече́: вои́стинну Челове́к Сей Сын бе Бо́жий. Бя́ху же и жены́ издале́ча зря́ще, в ни́хже бе Мари́а Магдали́на, и Мари́а Иа́кова ма́лаго и Иоси́и ма́ти, и Саломи́а, я́же, и егда́ бе в Галиле́и, хожда́ху по Нем и служа́ху Ему́, и и́ны мно́гия, я́же взыдо́ша с Ним во Иерусали́м. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, во́ини пое́мше і҆и҃са, ведо́ша да є҆го̀ ра́спнꙋтъ: и҆ приведо́ша є҆го̀ на голго́ѳꙋ мѣ́сто: є҆́же є҆́сть сказа́емо, ло́бное мѣ́сто. бѣ́ же ча́съ тре́тїй, и҆ распѧ́ша є҆го̀. бы́вшꙋ же часꙋ̀ шесто́мꙋ, тма̀ бы́сть по все́й землѝ до часа̀ девѧ́тагѡ. и҆ въ ча́съ девѧ́тый возопѝ і҆и҃съ гла́сомъ ве́лїимъ, глаго́лѧ: є҆лѡі̀ є҆лѡі̀, лїма̀ савахѳані̀; є҆́же є҆́сть сказа́емо: бж҃е мо́й, бж҃е мо́й, почто́ мѧ ѡ҆ста́вилъ є҆сѝ; и҆ нѣ́цыи ѿ предстоѧ́щихъ слы́шавше, глаго́лахꙋ: сѐ и҆лїю̀ гласи́тъ. те́къ же є҆ди́нъ, и҆ напо́лнивъ гꙋ́бꙋ ѻ҆́цта, и҆ возло́жь на тро́сть, напоѧ́ше є҆го̀, глаго́лѧ: ѡ҆ста́вите, да ви́димъ, а҆́ще прїи́детъ и҆лїа̀ снѧ́ти є҆го̀. і҆и҃съ же пꙋ́щь гла́съ ве́лїй, и҆́здше. и҆ завѣ́са церко́внаѧ раздра́сѧ на дво́е, свы́ше до ни́зꙋ. ви́дѣвъ же со́тникъ стоѧ́й прѧ́мѡ є҆мꙋ̀, ꙗ҆́кѡ та́кѡ возопи́въ и҆́здше, речѐ: вои́стиннꙋ человѣ́къ се́й, сн҃ъ бѣ̀ бж҃їй. бѧ́хꙋ же и҆ жєны̀ и҆здале́ча зрѧ́ще, въ ни́хже бѣ̀ марі́а магдали́на, и҆ марі́а і҆а́кѡва ма́лагѡ, и҆ і҆ѡсі́и ма́ти, и҆ салѡмі́а: ꙗ҆́же и҆ є҆гда̀ бѣ̀ въ галїле́и, хожда́хꙋ по не́мъ, и҆ слꙋжа́хꙋ є҆мꙋ̀: и҆ и҆́ны мнѡ́гїѧ, ꙗ҆̀же взыдо́ша съ ни́мъ во і҆ерꙋсали́мъ. ",
}

add_evangelie_marka {
  ["номер"] = 69,
  ["комментарий"] = "Мк., 69 зач., XV, 43–47.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Ио́сиф, и́же от Аримафе́а, благообра́зен сове́тник, и́же и той бе ча́я Ца́рствия Бо́жия, дерзну́в вни́де к Пила́ту, и проси́ те́ло Иису́сово. Пила́т же диви́ся, а́ще уже́ у́мре, и призва́в со́тника, вопроси́ его́: а́ще уже́ у́мре? И уве́дев от со́тника, даде́ те́ло Ио́сифови. И купи́в плащани́цу и снем Его́, обви́т плащани́цею, и положи́ Его́ во гроб, и́же бе изсе́чен от ка́мене, и привали́ ка́мень над две́ри гро́ба. Мари́а же Магдали́на и Мари́а Иоси́ева зря́сте, где Его́ полага́ху. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆ѡ́сифъ, и҆́же ѿ а҆рїмаѳе́а, бл҃гоѻбра́зенъ совѣ́тникъ, и҆́же и҆ то́й бѣ̀ ча́ѧ црⷭ҇твїѧ бж҃їѧ, дерзнꙋ́въ вни́де къ пїла́тꙋ, и҆ просѝ тѣ́ло і҆и҃сово. пїла́тъ же диви́сѧ, а҆́ще ᲂу҆жѐ ᲂу҆́мре: и҆ призва́въ со́тника, вопросѝ є҆го̀: а҆́ще ᲂу҆жѐ ᲂу҆́мре; и҆ ᲂу҆вѣ́дѣвъ ѿ со́тника, дадѐ тѣ́ло і҆ѡ́сифови. и҆ кꙋпи́въ плащани́цꙋ, и҆ сне́мъ є҆го̀, ѡ҆бви́тъ плащани́цею, и҆ положѝ є҆го̀ во гро́бъ, и҆́же бѣ̀ и҆зсѣ́ченъ ѿ ка́мене: и҆ привалѝ ка́мень над̾ двє́ри гро́ба. марі́а же магдали́на, и҆ марі́а і҆ѡсі́ева, зрѧ́стѣ, гдѣ̀ є҆го̀ полага́хꙋ. ",
}

add_evangelie_marka {
  ["номер"] = 69,
  ["комментарий"] = "Мк., 69 зач., XV, 43 - XVI, 8.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Ио́сиф, и́же от Аримафе́а, благообра́зен сове́тник, и́же и той бе ча́я Ца́рствия Бо́жия, дерзну́в вни́де к Пила́ту, и проси́ те́ло Иису́сово. Пила́т же диви́ся, а́ще уже́ у́мре, и призва́в со́тника, вопроси́ его́: а́ще уже́ у́мре? И уве́дев от со́тника, даде́ те́ло Ио́сифови. И купи́в плащани́цу и снем Его́, обви́т плащани́цею, и положи́ Его́ во гроб, и́же бе изсе́чен от ка́мене, и привали́ ка́мень над две́ри гро́ба. Мари́а же Магдали́на и Мари́а Иоси́ева зря́сте, где Его́ полага́ху. И мину́вши суббо́те, Мари́а Магдали́на и Мари́а Иа́ковля и Саломи́а купи́ша арома́ты, да прише́дше пома́жут Иису́са. И зело́ зау́тра во еди́ну от суббо́т приидо́ша на гроб, возсия́вшу со́лнцу, и глаго́лаху к себе́: кто отвали́т нам ка́мень от две́рий гро́ба? И воззре́вше ви́деша, я́ко отвале́н бе ка́мень, бе бо ве́лий зело́. И вле́зше во гроб, ви́деша ю́ношу седя́ща в десны́х, оде́яна во оде́жду белу́, и ужасо́шася. Он же глаго́ла им: не ужаса́йтеся, Иису́са и́щете Назаряни́на распя́таго, воста́, несть зде, се ме́сто, иде́же положи́ша Его́. Но иди́те, рцы́те ученико́м Его́ и Петро́ви, я́ко варя́ет вы в Галиле́и, та́мо Его́ ви́дите, я́коже рече́ вам. И изше́дше бежа́ша от гро́ба, имя́ше же их тре́пет и у́жас, и никому́же ничто́же ре́ша, боя́ху бо ся. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆ѡ́сифъ, и҆́же ѿ а҆рїмаѳе́а, бл҃гоѻбра́зенъ совѣ́тникъ, и҆́же и҆ то́й бѣ̀ ча́ѧ црⷭ҇твїѧ бж҃їѧ, дерзнꙋ́въ вни́де къ пїла́тꙋ, и҆ просѝ тѣ́ло і҆и҃сово. пїла́тъ же диви́сѧ, а҆́ще ᲂу҆жѐ ᲂу҆́мре: и҆ призва́въ со́тника, вопросѝ є҆го̀: а҆́ще ᲂу҆жѐ ᲂу҆́мре; и҆ ᲂу҆вѣ́дѣвъ ѿ со́тника, дадѐ тѣ́ло і҆ѡ́сифови. и҆ кꙋпи́въ плащани́цꙋ, и҆ сне́мъ є҆го̀, ѡ҆бви́тъ плащани́цею, и҆ положѝ є҆го̀ во гро́бъ, и҆́же бѣ̀ и҆зсѣ́ченъ ѿ ка́мене: и҆ привалѝ ка́мень над̾ двє́ри гро́ба. марі́а же магдали́на, и҆ марі́а і҆ѡсі́ева, зрѧ́стѣ, гдѣ̀ є҆го̀ полага́хꙋ. и҆ минꙋ́вши сꙋббѡ́тѣ, марі́а магдали́на, и҆ марі́а і҆а́кѡвлѧ и҆ салѡмі́а, кꙋпи́ша а҆рѡма́ты, да прише́дше пома́жꙋтъ і҆и҃са. и҆ ѕѣлѡ̀ заꙋ́тра во є҆ди́нꙋ ѿ сꙋббѡ́тъ прїидо́ша на гро́бъ, возсїѧ́вшꙋ со́лнцꙋ. и҆ глаго́лахꙋ къ себѣ̀: кто̀ ѿвали́тъ на́мъ ка́мень ѿ две́рїй гро́ба; и҆ воззрѣ́вше ви́дѣша, ꙗ҆́кѡ ѿвале́нъ бѣ̀ ка́мень: бѣ́ бо ве́лїй ѕѣлѡ̀. и҆ влѣ́зше во гро́бъ, ви́дѣша ю҆́ношꙋ сѣдѧ́ща въ десны́хъ, ѡ҆дѣ́ѧна во ѻ҆де́ждꙋ бѣлꙋ̀, и҆ ᲂу҆жасо́шасѧ. ѻ҆́нъ же глаго́ла и҆̀мъ: не ᲂу҆жаса́йтесѧ. і҆и҃са и҆́щете назарѧни́на распѧ́таго: воста̀, нѣ́сть здѣ̀: сѐ мѣ́сто, и҆дѣ́же положи́ша є҆го̀. но и҆ди́те, рцы́те ᲂу҆ченикѡ́мъ є҆гѡ̀, и҆ петро́ви, ꙗ҆́кѡ варѧ́етъ вы̀ въ галїле́и: та́мѡ є҆го̀ ви́дите, ꙗ҆́коже речѐ ва́мъ. и҆ и҆зше́дше бѣжа́ша ѿ гро́ба. и҆мѧ́ше же и҆̀хъ тре́петъ и҆ ᲂу҆́жасъ. и҆ никомꙋ́же ничто́же рѣ́ша, боѧ́хꙋ бо сѧ. ",
}

