add_evangelie_marka {
  ["номер"] = 71,
  ["комментарий"] = "Мк., 71 зач., XVI, 9–20.",
  ["текст_ру"] = "Во вре́мя о́но, воскре́с Иису́с зау́тра в пе́рвую суббо́ту, яви́ся пре́жде Мари́и Магдали́ни, из нея́же изгна́ седмь бесо́в. Она́ же ше́дши возвести́ с Ним бы́вшым, пла́чущымся и рыда́ющым, и они́ слы́шавше, я́ко жив есть и ви́ден бысть от нея́, не я́ша ве́ры. По сих же двема́ от них гряду́щема яви́ся ине́м о́бразом, иду́щема на село́. И та ше́дша возвести́ста про́чым, и ни те́ма ве́ры я́ша. Последи́ же возлежа́щым им единомуна́десяте яви́ся, и поноси́ неве́рствию их и жестосе́рдию, я́ко ви́девшым Его́ воста́вша не я́ша ве́ры. И рече́ им: ше́дше в мир весь, пропове́дите Ева́нгелие всей тва́ри. И́же ве́ру име́т и крести́тся, спасе́н бу́дет, а и́же не име́т ве́ры, осужде́н бу́дет. Зна́мения же ве́ровавшым сия́ после́дуют: и́менем Мои́м бе́сы иждену́т, язы́ки возглаго́лют но́вы, змия́ во́змут, а́ще и что сме́ртно испию́т, не вреди́т их, на неду́жныя ру́ки возложа́т, и здра́ви бу́дут. Госпо́дь же у́бо, по глаго́лании Его́ к ним, вознесе́ся на не́бо и се́де одесну́ю Бо́га. Они́ же изше́дше пропове́даша всю́ду, Го́споду поспе́шствующу и сло́во утвержда́ющу после́дствующими зна́меньми. Ами́нь. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, воскре́съ і҆и҃съ заꙋ́тра, въ пе́рвꙋю сꙋббѡ́тꙋ, ꙗ҆ви́сѧ пре́жде марі́и магдали́ни, и҆з̾ неѧ́же и҆згна̀ се́дмь бѣсѡ́въ. ѻ҆на́ же ше́дши возвѣстѝ съ ни́мъ бы́вшымъ, пла́чꙋщымсѧ и҆ рыда́ющымъ. и҆ ѻ҆нѝ слы́шавше, ꙗ҆́кѡ жи́въ є҆́сть, и҆ ви́дѣнъ бы́сть ѿ неѧ̀, не ꙗ҆́ша вѣ́ры. по си́хъ же двѣма̀ ѿ ни́хъ грѧдꙋ́щема ꙗ҆ви́сѧ и҆нѣ́мъ ѻ҆́бразомъ, и҆дꙋ́щема на село̀. и҆ та̀ ше́дша возвѣсти́ста про́чымъ: и҆ ни тѣ́ма вѣ́ры ꙗ҆́ша. послѣди́ же возлежа́щымъ и҆̀мъ є҆диномꙋна́десѧте ꙗ҆ви́сѧ, и҆ поносѝ невѣ́рствїю и҆́хъ, и҆ жестосе́рдїю, ꙗ҆́кѡ ви́дѣвшымъ є҆го̀ воста́вша не ꙗ҆́ша вѣ́ры. и҆ речѐ и҆̀мъ: ше́дше въ мі́ръ ве́сь, проповѣ́дите є҆ѵⷢ҇лїе все́й тва́ри. и҆́же вѣ́рꙋ и҆ме́тъ и҆ крести́тсѧ, спасе́нъ бꙋ́детъ: а҆ и҆́же не и҆ме́тъ вѣ́ры, ѡ҆сꙋжде́нъ бꙋ́детъ. зна́мєнїѧ же вѣ́ровавшымъ сїѧ̀ послѣ́дꙋютъ: и҆́менемъ мои́мъ бѣ́сы и҆жденꙋ́тъ, ѧ҆зы́ки возглаго́лютъ но́вы: ѕмїѧ̑ во́з̾мꙋтъ: а҆́ще и҆ что̀ сме́ртно и҆спїю́тъ, не вреди́тъ и҆́хъ: на недꙋ̑жныѧ рꙋ́ки возложа́тъ, и҆ здра́ви бꙋ́дꙋтъ. гдⷭ҇ь же ᲂу҆̀бо по глаго́ланїи є҆гѡ̀ къ ни́мъ, вознесе́сѧ на нб҃о, и҆ сѣ́де ѡ҆деснꙋ́ю бг҃а. ѻ҆ни́ же и҆зше́дше проповѣ́даша всю́дꙋ, гдⷭ҇ꙋ поспѣ́шствꙋющꙋ, и҆ сло́во ᲂу҆твержа́ющꙋ послѣ́дствꙋющими зна́меньми, а҆ми́нь. ",
}

add_evangelie_luki {
  ["номер"] = 1,
  ["комментарий"] = "Лк., 1 зач., I, 1–25, 57–68, 76, 80.",
  ["текст_ру"] = "Поне́же у́бо мно́зи нача́ша чини́ти по́весть о изве́ствованных в нас ве́щех, я́коже преда́ша нам, и́же испе́рва самови́дцы и слуги́ бы́вшии словеси́, изво́лися и мне после́довавшу вы́ше всех испы́тно, поря́ду писа́ти тебе́, держа́вный Фео́филе, да разуме́еши, о ни́хже научи́лся еси́ словесе́х утвержде́ние. Бысть во дни И́рода, царя́ Иуде́йска, иере́й не́кий, и́менем Заха́риа, от дневны́я чреды́ Авиа́ни, и жена́ его́ от дще́рей Ааро́новех, и и́мя ей Елисаве́ть. Бе́ста же пра́ведна о́ба пред Бо́гом, ходя́ще во всех за́поведех и оправда́ниих Госпо́дних безпоро́чна. И не бе и́ма ча́да, поне́же Елисаве́ть бе непло́ды, и о́ба заматоре́вша во днех свои́х бе́ста. Бысть же служа́щу ему́ в чину́ чреды́ своея́ пред Бо́гом, по обы́чаю свяще́нничества, ключи́ся ему́ покади́ти вшед в це́рковь Госпо́дню, и все мно́жество люде́й бе моли́тву де́я вне, в год фимиа́ма. Яви́ся же ему́ А́нгел Госпо́день, стоя́ одесну́ю олтаря́ кади́льнаго, и смути́ся Заха́риа ви́дев, и страх нападе́ нань. Рече́ же к нему́ А́нгел: не бо́йся, Заха́рие, зане́ услы́шана бысть моли́тва твоя́, и жена́ твоя́ Елисаве́ть роди́т сы́на тебе́, и нарече́ши и́мя ему́ Иоа́нн, и бу́дет тебе́ ра́дость и весе́лие, и мно́зи о рождестве́ его́ возра́дуются. Бу́дет бо ве́лий пред Го́сподем, и вина́ и сике́ра не и́мать пи́ти, и Ду́ха Свята́го испо́лнится еще́ из чре́ва ма́тере своея́. И мно́ги от сыно́в изра́илевых обрати́т ко Го́споду Бо́гу их. И той преды́дет пред Ним ду́хом и си́лою Илиино́ю, обрати́ти се́рдца отце́м на ча́да, и проти́вныя в му́дрости пра́ведных, угото́вати Го́сподеви лю́ди соверше́ны. И рече́ Заха́риа ко А́нгелу: по чесому́ разуме́ю сие́? Аз бо есмь стар, и жена́ моя́ заматоре́вши во днех свои́х. И отвеща́в А́нгел, рече́ ему́: аз есмь Гаврии́л предстоя́й пред Бо́гом, и по́слан есмь глаго́лати к тебе́ и благовести́ти тебе́ сия́. И се бу́деши молчя́, и не моги́й проглаго́лати, до него́же дне бу́дут сия́, зане́ не ве́ровал еси́ словесе́м мои́м, я́же сбу́дутся во вре́мя свое́. И бе́ша лю́дие жду́ще Заха́рию, и чудя́хуся косня́щу ему́ в це́ркви. Изше́д же не можа́ше глаго́лати к ним, и разуме́ша, я́ко виде́ние ви́де в це́ркви, и той бе помава́я им, и пребыва́ше нем. И бысть я́ко испо́лнишася дни́е слу́жбы его́, и́де в дом свой. По сих же днех зача́т Елисаве́т, жена́ его́, и тая́шеся ме́сяц пять, глаго́лющи: я́ко та́ко мне сотвори́ Госпо́дь во дни, в ня́же призре́ отъя́ти поноше́ние мое́ в челове́цех. Елисаве́ти же испо́лнися вре́мя роди́ти ей, и роди́ сы́на. И слы́шаша о́крест живу́щии и у́жики ея́, я́ко возвели́чил есть Госпо́дь ми́лость свою́ с не́ю, и ра́довахуся с не́ю. И бысть во осмы́й день, приидо́ша обре́зати отроча́, и нарица́ху е́ и́менем отца́ его́, Заха́рию. И отвеща́вши ма́ти его́, рече́: ни, но да нарече́тся Иоа́нн. И ре́ша к ней: я́ко никто́же есть в родстве́ твое́м, и́же нарица́ется и́менем тем. И помава́ху отцу́ его́, е́же ка́ко бы хоте́л нарещи́ е́. И испро́шь дщи́цу, написа́, глаго́ля: Иоа́нн бу́дет и́мя ему́. И чудя́хуся вси. Отверзо́шася же уста́ его́ а́бие и язы́к его́, и глаго́лаше благословя́ Бо́га. И бысть на всех страх живу́щих о́крест их, и во всей стране́ иуде́йстей пове́даеми бя́ху вси глаго́ли си́и. И положи́ша вси слы́шавшии в се́рдце свое́м, глаго́люще: что у́бо отроча́ сие́ бу́дет? И рука́ Госпо́дня бе с ним. И Заха́риа оте́ц его́ испо́лнися Ду́ха Свя́та, и проро́чествова, глаго́ля: благослове́н Госпо́дь Бог Изра́илев, я́ко посети́ и сотвори́ избавле́ние лю́дем свои́м. И ты, отроча́, проро́к Вы́шняго нарече́шися, преды́деши бо пред лице́м Госпо́дним, угото́вати пути́ Его́. Отроча́ же растя́ше и крепля́шеся ду́хом, и бе в пусты́нях до дне явле́ния своего́ ко Изра́илю. ",
  ["текст_цс"] = "Поне́же ᲂу҆́бѡ мно́зи нача́ша чини́ти по́вѣсть ѡ҆ и҆звѣ́ствованныхъ въ на́съ ве́щехъ, ꙗ҆́коже преда́ша на́мъ, и҆̀же и҆спе́рва самови́дцы и҆ слꙋгѝ бы́вшїи словесѝ: и҆зво́лисѧ и҆ мнѣ̀ послѣ́довавшꙋ вы́ше всѣ́хъ и҆спы́тнѡ, порѧ́дꙋ писа́ти тебѣ̀, держа́вный ѳео́фїле: да разꙋмѣ́еши, ѡ҆ ни́хже наꙋчи́лсѧ є҆сѝ словесѣ́хъ ᲂу҆твержде́нїе. бы́сть во днѝ и҆́рѡда царѧ̀ і҆ꙋде́йска, і҆ере́й нѣ́кїй и҆́менемъ заха́рїа, ѿ дневны́ѧ чреды̀ а҆вїа́ни: и҆ жена̀ є҆гѡ̀ ѿ дще́рей а҆арѡ́новѣхъ, и҆ и҆́мѧ є҆́й є҆лїсаве́тъ. бѣ́ста же пра́вєдна ѻ҆́ба пред̾ бг҃омъ, ходѧ́ще во всѣ́хъ за́повѣдехъ, и҆ ѡ҆правда́нїихъ гдⷭ҇нихъ безпорѡ́чна: и҆ не бѣ̀ и҆́ма ча́да, поне́же є҆лїсаве́тъ бѣ̀ непло́ды, и҆ ѻ҆́ба заматорѣ́вша во дне́хъ свои́хъ бѣ́ста. бы́сть же слꙋжа́щꙋ є҆мꙋ̀ въ чинꙋ̀ чреды̀ своеѧ̀ пред̾ бг҃омъ: по ѻ҆бы́чаю свѧще́нничества, ключи́сѧ є҆мꙋ̀ покади́ти вше́дъ въ це́рковь гдⷭ҇ню: и҆ всѐ мно́жество люде́й бѣ̀ моли́твꙋ дѣ́ѧ внѣ̀ въ го́дъ ѳѷмїа́ма. ꙗ҆ви́сѧ же є҆мꙋ̀ а҆́гг҃лъ гдⷭ҇нь, стоѧ̀ ѡ҆деснꙋ́ю ѻ҆лтарѧ̀ кади́льнагѡ: и҆ смꙋти́сѧ заха́рїа ви́дѣвъ, и҆ стра́хъ нападѐ на́нь. рече́ же къ немꙋ̀ а҆́гг҃лъ: не бо́йсѧ заха́рїе, занѐ ᲂу҆слы́шана бы́сть моли́тва твоѧ̀: и҆ жена̀ твоѧ̀ є҆лїсаве́тъ роди́тъ сы́на тебѣ̀, и҆ нарече́ши и҆́мѧ є҆мꙋ̀ і҆ѡа́ннъ. и҆ бꙋ́детъ тебѣ̀ ра́дость и҆ весе́лїе: и҆ мно́зи ѡ҆ рождествѣ̀ є҆гѡ̀ возра́дꙋютсѧ. бꙋ́детъ бо ве́лїй пред̾ гдⷭ҇емъ, и҆ вїна̀ и҆ сїке́ра не и҆́мать пи́ти: и҆ дх҃а ст҃а́гѡ и҆спо́лнитсѧ є҆щѐ и҆з̾ чре́ва ма́тере своеѧ̀. и҆ мно́ги ѿ сынѡ́въ і҆и҃левыхъ ѡ҆брати́тъ ко гдⷭ҇ꙋ бг҃ꙋ и҆́хъ. и҆ то́й пред̾и́детъ пред̾ ни́мъ дх҃омъ и҆ си́лою и҆лїино́ю, ѡ҆брати́ти сердца̀ ѻ҆тцє́мъ на ча̑да, и҆ проти̑вныѧ въ мꙋ́дрости пра́ведныхъ: ᲂу҆гото́вати гдⷭ҇ви лю́ди соверше́ны. и҆ речѐ заха́рїа ко а҆́гг҃лꙋ: по чесомꙋ̀ разꙋмѣ́ю сїѐ; а҆́зъ бо є҆́смь ста́ръ, и҆ жена̀ моѧ̀ заматорѣ́вши во дне́хъ свои́хъ. и҆ ѿвѣща́въ а҆́гг҃лъ речѐ є҆мꙋ̀: а҆́зъ є҆́смь гаврїи́лъ предстоѧ́й пред̾ бг҃омъ, и҆ по́сланъ є҆́смь глаго́лати къ тебѣ̀, и҆ благовѣсти́ти тебѣ̀ сїѧ̑. и҆ сѐ бꙋ́деши молчѧ̀, и҆ не могі́й проглаго́лати, до негѡ́же днѐ бꙋ́дꙋтъ сїѧ̑: занѐ не вѣ́ровалъ є҆сѝ словесє́мъ мои́мъ, ꙗ҆̀же сбꙋ́дꙋтсѧ во вре́мѧ своѐ. и҆ бѣ́ша лю́дїе ждꙋ́ще заха́рїю, и҆ чꙋдѧ́хꙋсѧ коснѧ́щꙋ є҆мꙋ̀ въ це́ркви. и҆зше́дъ же не можа́ше глаго́лати къ ни́мъ. и҆ разꙋмѣ́ша, ꙗ҆́кѡ видѣ́нїе ви́дѣ въ це́ркви: и҆ то́й бѣ̀ помава́ѧ и҆̀мъ, и҆ пребыва́ше нѣ́мъ. и҆ бы́сть ꙗ҆́кѡ и҆спо́лнишасѧ дні́е слꙋ́жбы є҆гѡ̀, и҆́де въ до́мъ сво́й. по си́хъ же дне́хъ зача́тъ є҆лїсаве́тъ жена̀ є҆гѡ̀, и҆ таѧ́шесѧ мѣ̑сѧцъ пѧ́ть, глаго́лющи: ꙗ҆́кѡ та́кѡ мнѣ̀ сотворѝ гдⷭ҇ь во днѝ, въ нѧ́же призрѣ̀ ѿѧ́ти поноше́нїе моѐ въ человѣ́цѣхъ. є҆лїсаве́ти же и҆спо́лнисѧ вре́мѧ роди́ти є҆́й, и҆ родѝ сы́на. и҆ слы́шаша ѻ҆́крестъ живꙋ́щїи, и҆ ᲂу҆́жики є҆ѧ̀, ꙗ҆́кѡ возвели́чилъ є҆́сть гдⷭ҇ь млⷭ҇ть свою̀ съ не́ю: и҆ ра́довахꙋсѧ съ не́ю. и҆ бы́сть во ѻ҆смы́й де́нь, прїидо́ша ѡ҆брѣ́зати ѻ҆троча̀. и҆ нарица́хꙋ є҆̀ и҆́менемъ ѻ҆тца̀ є҆гѡ̀, заха́рїю. и҆ ѿвѣща́вши ма́ти є҆гѡ̀ речѐ: нѝ, но да нарече́тсѧ і҆ѡа́ннъ. и҆ рѣ́ша къ не́й: ꙗ҆́кѡ никто́же є҆́сть въ родствѣ̀ твое́мъ, и҆́же нарица́етсѧ и҆́менемъ тѣ́мъ. и҆ помава́хꙋ ѻ҆тцꙋ̀ є҆гѡ̀, є҆́же ка́кѡ бы хотѣ́лъ нарещѝ є҆̀; и҆ и҆спро́шъ дщи́цꙋ, написа̀ глаго́лѧ: і҆ѡа́ннъ бꙋ́детъ и҆́мѧ є҆мꙋ̀: и҆ чꙋдѧ́хꙋсѧ всѝ. ѿверзо́шасѧ же ᲂу҆ста̀ є҆гѡ̀ а҆́бїе, и҆ ѧ҆зы́къ є҆гѡ̀, и҆ глаго́лаше бл҃гословѧ̀ бг҃а. и҆ бы́сть на всѣ́хъ стра́хъ живꙋ́щихъ ѻ҆́крестъ и҆́хъ, и҆ во все́й странѣ̀ і҆ꙋде́йстѣй повѣ́даеми бѧ́хꙋ всѝ глаго́ли сі́и. и҆ положи́ша всѝ слы́шавшїи въ се́рдцѣ свое́мъ, глаго́люще: что̀ ᲂу҆́бѡ ѻ҆троча̀ сїѐ бꙋ́детъ; и҆ рꙋка̀ гдⷭ҇нѧ бѣ̀ съ ни́мъ. и҆ заха́рїа ѻ҆те́цъ є҆гѡ̀ и҆спо́лнисѧ дх҃а ст҃а, и҆ проро́чествова, глаго́лѧ: бл҃гослове́нъ гдⷭ҇ь бг҃ъ і҆и҃левъ, ꙗ҆́кѡ посѣтѝ, и҆ сотворѝ и҆збавле́нїе лю́демъ свои́мъ. и҆ ты̀ ѻ҆троча̀, проро́къ вы́шнѧгѡ нарече́шисѧ: пред̾и́деши бо пред̾ лице́мъ гдⷭ҇нимъ, ᲂу҆гото́вати пꙋти̑ є҆гѡ̀. ѻ҆троча́ же растѧ́ше и҆ крѣплѧ́шесѧ дх҃омъ: и҆ бѣ̀ въ пꙋсты́нѧхъ до днѐ ꙗ҆вле́нїѧ своегѡ̀ ко і҆и҃лю. ",
}

add_evangelie_luki {
  ["номер"] = 2,
  ["комментарий"] = "Лк., 2 зач., I, 5–25.",
  ["текст_ру"] = "Во вре́мя о́но, бысть во дни И́рода, царя́ Иуде́йска, иере́й не́кий, и́менем Заха́риа, от дневны́я чреды́ Авиа́ни, и жена́ его́ от дще́рей Ааро́новех, и и́мя ей Елисаве́ть. Бе́ста же пра́ведна о́ба пред Бо́гом, ходя́ще во всех за́поведех и оправда́ниих Госпо́дних безпоро́чна. И не бе и́ма ча́да, поне́же Елисаве́т бе непло́ды, и о́ба заматоре́вша во днех свои́х бе́ста. Бысть же служа́щу ему́ в чину́ чреды́ своея́ пред Бо́гом, по обы́чаю свяще́нничества, ключи́ся ему́ покади́ти вшед в це́рковь Госпо́дню, и все мно́жество люде́й бе моли́тву де́я вне, в год фимиа́ма. Яви́ся же ему́ А́нгел Госпо́день, стоя́ одесну́ю олтаря́ кади́льнаго, и смути́ся Заха́риа ви́дев, и страх нападе́ нань. Рече́ же к нему́ А́нгел: не бо́йся, Заха́рие, зане́ услы́шана бысть моли́тва твоя́, и жена́ твоя́ Елисаве́ть роди́т сы́на тебе́, и нарече́ши и́мя ему́ Иоа́нн, и бу́дет тебе́ ра́дость и весе́лие, и мно́зи о рождестве́ его́ возра́дуются. Бу́дет бо ве́лий пред Го́сподем, и вина́ и сике́ра не и́мать пи́ти, и Ду́ха Свята́го испо́лнится еще́ из чре́ва ма́тере своея́. И мно́ги от сыно́в изра́илевых обрати́т ко Го́споду Бо́гу их. И той преды́дет пред Ним ду́хом и си́лою Илиино́ю, обрати́ти сердца́ отце́м на ча́да, и проти́вныя в му́дрости пра́ведных, угото́вати Го́сподеви лю́ди соверше́ны. И рече́ Заха́риа ко А́нгелу: по чесому́ разуме́ю сие́? Аз бо есмь стар, и жена́ моя́ заматоре́вши во днех свои́х. И отвеща́в А́нгел, рече́ ему́: аз есмь Гаврии́л предстоя́й пред Бо́гом, и по́слан есмь глаго́лати к тебе́ и благовести́ти тебе́ сия́. И се бу́деши молчя́, и не моги́й проглаго́лати, до него́же дне бу́дут сия́, зане́ не ве́ровал еси́ словесе́м мои́м, я́же сбу́дутся во вре́мя свое́. И бе́ша лю́дие жду́ще Заха́рию, и чудя́хуся косня́щу ему́ в це́ркви. Изше́д же не можа́ше глаго́лати к ним, и разуме́ша, я́ко виде́ние ви́де в це́ркви, и той бе помава́я им, и пребыва́ше нем. И бысть я́ко испо́лнишася дни́е слу́жбы его́, и́де в дом свой. По сих же днех зача́т Елисаве́т, жена́ его́, и тая́шеся ме́сяц пять, глаго́лющи: я́ко та́ко мне сотвори́ Госпо́дь во дни, в ня́же призре́ отъя́ти поноше́ние мое́ в челове́цех. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бы́сть во днѝ и҆́рѡда царѧ̀ і҆ꙋде́йска, і҆ере́й нѣ́кїй и҆́менемъ заха́рїа, ѿ дневны́ѧ чреды̀ а҆вїа́ни: и҆ жена̀ є҆гѡ̀ ѿ дще́рей а҆арѡ́новѣхъ, и҆ и҆́мѧ є҆́й є҆лїсаве́тъ. бѣ́ста же пра́вєдна ѻ҆́ба пред̾ бг҃омъ, ходѧ́ще во всѣ́хъ за́повѣдехъ, и҆ ѡ҆правда́нїихъ гдⷭ҇нихъ безпорѡ́чна: и҆ не бѣ̀ и҆́ма ча́да, поне́же є҆лїсаве́тъ бѣ̀ непло́ды, и҆ ѻ҆́ба заматорѣ́вша во дне́хъ свои́хъ бѣ́ста. бы́сть же слꙋжа́щꙋ є҆мꙋ̀ въ чинꙋ̀ чреды̀ своеѧ̀ пред̾ бг҃омъ: по ѻ҆бы́чаю свѧще́нничества, ключи́сѧ є҆мꙋ̀ покади́ти вше́дъ въ це́рковь гдⷭ҇ню: и҆ всѐ мно́жество люде́й бѣ̀ моли́твꙋ дѣ́ѧ внѣ̀ въ го́дъ ѳѷмїа́ма. ꙗ҆ви́сѧ же є҆мꙋ̀ а҆́гг҃лъ гдⷭ҇нь, стоѧ̀ ѡ҆деснꙋ́ю ѻ҆лтарѧ̀ кади́льнагѡ: и҆ смꙋти́сѧ заха́рїа ви́дѣвъ, и҆ стра́хъ нападѐ на́нь. рече́ же къ немꙋ̀ а҆́гг҃лъ: не бо́йсѧ заха́рїе, занѐ ᲂу҆слы́шана бы́сть моли́тва твоѧ̀: и҆ жена̀ твоѧ̀ є҆лїсаве́тъ роди́тъ сы́на тебѣ̀, и҆ нарече́ши и҆́мѧ є҆мꙋ̀ і҆ѡа́ннъ. и҆ бꙋ́детъ тебѣ̀ ра́дость и҆ весе́лїе: и҆ мно́зи ѡ҆ рождествѣ̀ є҆гѡ̀ возра́дꙋютсѧ. бꙋ́детъ бо ве́лїй пред̾ гдⷭ҇емъ, и҆ вїна̀ и҆ сїке́ра не и҆́мать пи́ти: и҆ дх҃а ст҃а́гѡ и҆спо́лнитсѧ є҆щѐ и҆з̾ чре́ва ма́тере своеѧ̀. и҆ мно́ги ѿ сынѡ́въ і҆и҃левыхъ ѡ҆брати́тъ ко гдⷭ҇ꙋ бг҃ꙋ и҆́хъ. и҆ то́й пред̾и́детъ пред̾ ни́мъ дх҃омъ и҆ си́лою и҆лїино́ю, ѡ҆брати́ти сердца̀ ѻ҆тцє́мъ на ча̑да, и҆ проти̑вныѧ въ мꙋ́дрости пра́ведныхъ: ᲂу҆гото́вати гдⷭ҇ви лю́ди соверше́ны. и҆ речѐ заха́рїа ко а҆́гг҃лꙋ: по чесомꙋ̀ разꙋмѣ́ю сїѐ; а҆́зъ бо є҆́смь ста́ръ, и҆ жена̀ моѧ̀ заматорѣ́вши во дне́хъ свои́хъ. и҆ ѿвѣща́въ а҆́гг҃лъ речѐ є҆мꙋ̀: а҆́зъ є҆́смь гаврїи́лъ предстоѧ́й пред̾ бг҃омъ, и҆ по́сланъ є҆́смь глаго́лати къ тебѣ̀, и҆ благовѣсти́ти тебѣ̀ сїѧ̑. и҆ сѐ бꙋ́деши молчѧ̀, и҆ не могі́й проглаго́лати, до негѡ́же днѐ бꙋ́дꙋтъ сїѧ̑: занѐ не вѣ́ровалъ є҆сѝ словесє́мъ мои́мъ, ꙗ҆̀же сбꙋ́дꙋтсѧ во вре́мѧ своѐ. и҆ бѣ́ша лю́дїе ждꙋ́ще заха́рїю, и҆ чꙋдѧ́хꙋсѧ коснѧ́щꙋ є҆мꙋ̀ въ це́ркви. и҆зше́дъ же не можа́ше глаго́лати къ ни́мъ. и҆ разꙋмѣ́ша, ꙗ҆́кѡ видѣ́нїе ви́дѣ въ це́ркви: и҆ то́й бѣ̀ помава́ѧ и҆̀мъ, и҆ пребыва́ше нѣ́мъ. и҆ бы́сть ꙗ҆́кѡ и҆спо́лнишасѧ дні́е слꙋ́жбы є҆гѡ̀, и҆́де въ до́мъ сво́й. по си́хъ же дне́хъ зача́тъ є҆лїсаве́тъ жена̀ є҆гѡ̀, и҆ таѧ́шесѧ мѣ̑сѧцъ пѧ́ть, глаго́лющи: ꙗ҆́кѡ та́кѡ мнѣ̀ сотворѝ гдⷭ҇ь во днѝ, въ нѧ́же призрѣ̀ ѿѧ́ти поноше́нїе моѐ въ человѣ́цѣхъ. ",
}

add_evangelie_luki {
  ["номер"] = 3,
  ["комментарий"] = "Лк., 3 зач., I, 24–38.",
  ["текст_ру"] = "Во днех о́нех зача́т Елисаве́т, жена́ Заха́риина, и тая́шеся ме́сяц пять, глаго́лющи: я́ко та́ко мне сотвори́ Госпо́дь во дни, в ня́же призре́ отъя́ти поноше́ние мое́ в челове́цех. В ме́сяц же шесты́й по́слан бысть А́нгел Гаврии́л от Бо́га во град Галиле́йский, ему́же и́мя Назаре́т, к Де́ве обруче́нней му́жеви, ему́же и́мя Ио́сиф, от до́му Дави́дова, и и́мя Де́ве, Мариа́м. И вшед к Ней А́нгел, рече́: ра́дуйся Благода́тная, Госпо́дь с Тобо́ю, благослове́на Ты в жена́х. Она́ же ви́девши смути́ся о словеси́ его́, и помышля́ше, каково́ бу́дет целова́ние сие́. И рече́ А́нгел Ей: не бо́йся Мариа́м, обре́те бо благода́ть от Бо́га. И се зачне́ши во чре́ве, и роди́ши Сы́на, и нарече́ши и́мя Ему́ Иису́с. Сей бу́дет ве́лий, и Сын Вы́шняго нарече́тся, и даст Ему́ Госпо́дь Бог престо́л Дави́да отца́ Его́, и воцари́тся в дому́ Иа́ковли во ве́ки, и Ца́рствию Его́ не бу́дет конца́. Рече́ же Мариа́м ко А́нгелу: ка́ко бу́дет сие́, иде́же му́жа не зна́ю? И отвеща́в А́нгел, рече́ Ей: Дух Святы́й на́йдет на Тя, и си́ла Вы́шняго осени́т Тя, те́мже и ражда́емое Свя́то, нарече́тся Сын Бо́жий. И се Елисаве́т, ю́жика Твоя́, и та зача́т сы́на в ста́рости свое́й, и сей ме́сяц шесты́й есть ей, нарица́емей непло́ды. Я́ко не изнемо́жет от Бо́га всяк глаго́л. Рече́ же Мариа́м: се раба́ Госпо́дня, бу́ди Мне по глаго́лу твоему́. И оты́де от Нея́ А́нгел. ",
  ["текст_цс"] = "Во дне́хъ ѻ҆́нѣхъ, зача́тъ є҆лїсаве́тъ жена̀ заха́рїина и҆ таѧ́шесѧ мѣ̑сѧцъ пѧ́ть, глаго́лющи: ꙗ҆́кѡ та́кѡ мнѣ̀ сотворѝ гдⷭ҇ь во днѝ, въ нѧ́же призрѣ̀ ѿѧ́ти поноше́нїе моѐ въ человѣ́цѣхъ. въ мѣ́сѧцъ же шесты́й по́сланъ бы́сть а҆́гг҃лъ гаврїи́лъ ѿ бг҃а во гра́дъ галїле́йскїй, є҆мꙋ́же и҆́мѧ назаре́тъ, къ дв҃ѣ ѡ҆брꙋче́ннѣй мꙋ́жеви, є҆мꙋ́же и҆́мѧ і҆ѡ́сифъ, ѿ до́мꙋ даві́дова: и҆ и҆́мѧ дв҃ѣ, марїа́мъ. и҆ вше́дъ къ не́й а҆́гг҃лъ, речѐ: ра́дꙋйсѧ благода́тнаѧ, гдⷭ҇ь съ тобо́ю: благослове́на ты̀ въ жена́хъ. ѻ҆на́ же ви́дѣвши смꙋти́сѧ ѡ҆ словесѝ є҆гѡ̀, и҆ помышлѧ́ше, каково̀ бꙋ́детъ цѣлова́нїе сїѐ. и҆ речѐ а҆́гг҃лъ є҆́й: не бо́йсѧ марїа́мъ, ѡ҆брѣ́те бо бл҃года́ть ѿ бг҃а. и҆ сѐ зачне́ши во чре́вѣ, и҆ роди́ши сн҃а, и҆ нарече́ши и҆́мѧ є҆мꙋ̀ і҆и҃съ. се́й бꙋ́детъ ве́лїй, и҆ сн҃ъ вы́шнѧгѡ нарече́тсѧ: и҆ да́стъ є҆мꙋ̀ гдⷭ҇ь бг҃ъ прⷭ҇то́лъ даві́да ѻ҆тца̀ є҆гѡ̀: и҆ воцари́тсѧ въ домꙋ̀ і҆а́кѡвли во вѣ́ки, и҆ црⷭ҇твїю є҆гѡ̀ не бꙋ́детъ конца̀. рече́ же марїа́мъ ко а҆́гг҃лꙋ: ка́кѡ бꙋ́детъ сїѐ, и҆дѣ́же мꙋ́жа не зна́ю; и҆ ѿвѣща́въ а҆́гг҃лъ, речѐ є҆́й: дх҃ъ ст҃ы́й на́йдетъ на тѧ̀, и҆ си́ла вы́шнѧгѡ ѡ҆сѣни́тъ тѧ̀. тѣ́мже и҆ ражда́емое ст҃о, нарече́тсѧ сн҃ъ бж҃їй. и҆ сѐ є҆лїсаве́тъ ю҆́жика твоѧ̀, и҆ та̀ зача́тъ сы́на въ ста́рости свое́й: и҆ се́й мцⷭ҇ъ шесты́й є҆́сть є҆́й, нарица́емѣй непло́ды. ꙗ҆́кѡ не и҆знемо́жетъ ѿ бг҃а всѧ́къ глаго́лъ. рече́ же марїа́мъ: сѐ раба̀ гдⷭ҇нѧ, бꙋ́ди мнѣ̀ по глаго́лꙋ твоемꙋ̀, и҆ ѿи́де ѿ неѧ̀ а҆́гг҃лъ. ",
}

add_evangelie_luki {
  ["номер"] = 3,
  ["комментарий"] = "Лк., 3 зач., I, 24–25, 57-68, 76, 80.",
  ["текст_ру"] = "Во днех о́нех зача́т Елисаве́т, жена́ Заха́риина, и тая́шеся ме́сяц пять, глаго́лющи: я́ко та́ко мне сотвори́ Госпо́дь во дни, в ня́же призре́ отъя́ти поноше́ние мое́ в челове́цех. Елисаве́ти же испо́лнися вре́мя роди́ти ей, и роди́ сы́на. И слы́шаша о́крест живу́щии и у́жики ея́, я́ко возвели́чил есть Госпо́дь ми́лость свою́ с не́ю, и ра́довахуся с не́ю. И бысть во осмы́й день, приидо́ша обре́зати отроча́, и нарица́ху е́ и́менем отца́ его́, Заха́рию. И отвеща́вши ма́ти его́, рече́: ни, но да нарече́тся Иоа́нн. И ре́ша к ней: я́ко никто́же есть в родстве́ твое́м, и́же нарица́ется и́менем тем. И помава́ху отцу́ его́, е́же ка́ко бы хоте́л нарещи́ е́. И испро́ш дщи́цу, написа́, глаго́ля: Иоа́нн бу́дет и́мя ему́. И чудя́хуся вси. Отверзо́шася же уста́ его́ а́бие и язы́к его́, и глаго́лаше благословя́ Бо́га. И бысть на всех страх живу́щих о́крест их, и во всей стране́ иуде́йстей пове́даеми бя́ху вси глаго́ли си́и. И положи́ша вси слы́шавшии в се́рдце свое́м, глаго́люще: что у́бо отроча́ сие́ бу́дет? И рука́ Госпо́дня бе с ним. И Заха́риа оте́ц его́ испо́лнися Ду́ха Свя́та, и проро́чествова, глаго́ля: благослове́н Госпо́дь Бог Изра́илев, я́ко посети́ и сотвори́ избавле́ние лю́дем свои́м. И ты, отроча́, проро́к Вы́шняго нарече́шися, преды́деши бо пред лице́м Госпо́дним, угото́вати пути́ Его́. Отроча́ же растя́ше и крепля́шеся ду́хом, и бе в пусты́нях до дне явле́ния своего́ ко Изра́илю. ",
  ["текст_цс"] = "Во дне́хъ ѻ҆́нѣхъ, зача́тъ є҆лїсаве́тъ жена̀ заха́рїина и҆ таѧ́шесѧ мѣ̑сѧцъ пѧ́ть, глаго́лющи: ꙗ҆́кѡ та́кѡ мнѣ̀ сотворѝ гдⷭ҇ь во днѝ, въ нѧ́же призрѣ̀ ѿѧ́ти поноше́нїе моѐ въ человѣ́цѣхъ. є҆лїсаве́ти же и҆спо́лнисѧ вре́мѧ роди́ти є҆́й, и҆ родѝ сы́на. и҆ слы́шаша ѻ҆́крестъ живꙋ́щїи, и҆ ᲂу҆́жики є҆ѧ̀, ꙗ҆́кѡ возвели́чилъ є҆́сть гдⷭ҇ь млⷭ҇ть свою̀ съ не́ю: и҆ ра́довахꙋсѧ съ не́ю. и҆ бы́сть во ѻ҆смы́й де́нь, прїидо́ша ѡ҆брѣ́зати ѻ҆троча̀. и҆ нарица́хꙋ є҆̀ и҆́менемъ ѻ҆тца̀ є҆гѡ̀, заха́рїю. и҆ ѿвѣща́вши ма́ти є҆гѡ̀ речѐ: нѝ, но да нарече́тсѧ і҆ѡа́ннъ. и҆ рѣ́ша къ не́й: ꙗ҆́кѡ никто́же є҆́сть въ родствѣ̀ твое́мъ, и҆́же нарица́етсѧ и҆́менемъ тѣ́мъ. и҆ помава́хꙋ ѻ҆тцꙋ̀ є҆гѡ̀, є҆́же ка́кѡ бы хотѣ́лъ нарещѝ є҆̀; и҆ и҆спро́шъ дщи́цꙋ, написа̀ глаго́лѧ: і҆ѡа́ннъ бꙋ́детъ и҆́мѧ є҆мꙋ̀: и҆ чꙋдѧ́хꙋсѧ всѝ. ѿверзо́шасѧ же ᲂу҆ста̀ є҆гѡ̀ а҆́бїе, и҆ ѧ҆зы́къ є҆гѡ̀, и҆ глаго́лаше бл҃гословѧ̀ бг҃а. и҆ бы́сть на всѣ́хъ стра́хъ живꙋ́щихъ ѻ҆́крестъ и҆́хъ, и҆ во все́й странѣ̀ і҆ꙋде́йстѣй повѣ́даеми бѧ́хꙋ всѝ глаго́ли сі́и. и҆ положи́ша всѝ слы́шавшїи въ се́рдцѣ свое́мъ, глаго́люще: что̀ ᲂу҆́бѡ ѻ҆троча̀ сїѐ бꙋ́детъ; и҆ рꙋка̀ гдⷭ҇нѧ бѣ̀ съ ни́мъ. и҆ заха́рїа ѻ҆те́цъ є҆гѡ̀ и҆спо́лнисѧ дх҃а ст҃а, и҆ проро́чествова, глаго́лѧ: бл҃гослове́нъ гдⷭ҇ь бг҃ъ і҆и҃левъ, ꙗ҆́кѡ посѣтѝ, и҆ сотворѝ и҆збавле́нїе лю́демъ свои́мъ. и҆ ты̀ ѻ҆троча̀, проро́къ вы́шнѧгѡ нарече́шисѧ: пред̾и́деши бо пред̾ лице́мъ гдⷭ҇нимъ, ᲂу҆гото́вати пꙋти̑ є҆гѡ̀. ѻ҆троча́ же растѧ́ше и҆ крѣплѧ́шесѧ дх҃омъ: и҆ бѣ̀ въ пꙋсты́нѧхъ до днѐ ꙗ҆вле́нїѧ своегѡ̀ ко і҆и҃лю. ",
}

add_evangelie_luki {
  ["номер"] = 4,
  ["комментарий"] = "Лк., 4 зач., I, 39–49, 56.",
  ["текст_ру"] = "Во дни о́ны, воста́вши, Мариа́м, и́де в го́рняя со тща́нием, во град Иу́дов. И вни́де в дом Заха́риин, и целова́ Елисаве́т. И бысть я́ко услы́ша Елисаве́т целова́ние Мари́ино, взыгра́ся младе́нец во чре́ве ея́, и испо́лнися Ду́ха Свя́та Елисаве́т. И возопи́ гла́сом ве́лиим, и рече́: благослове́на Ты в жена́х, и благослове́н плод чре́ва Твоего́. И отку́ду мне сие́, да прии́де Ма́ти Го́спода моего́ ко мне? Се бо, я́ко бысть глас целова́ния Твоего́ во у́шию мое́ю, взыгра́ся младе́нец ра́дощами во чре́ве мое́м. И блаже́нна Ве́ровавшая, я́ко бу́дет соверше́ние глаго́ланным Ей от Го́спода. И рече́ Мариа́м: вели́чит душа́ Моя́ Го́спода, и возра́довася дух Мой о Бо́зе Спа́се Мое́м. Я́ко призре́ на смире́ние рабы́ Своея́, се бо, от ны́не ублажа́т Мя вси роди́. Я́ко сотвори́ Мне вели́чие Си́льный, и свя́то и́мя Его́. Пребы́сть же Мариа́м с не́ю я́ко три ме́сяцы, и возврати́ся в дом Свой. ",
  ["текст_цс"] = "Во днѝ ѻ҆́ны воста́вши марїа́мъ, и҆́де въ гѡ́рнѧѧ со тща́нїемъ, во гра́дъ і҆ꙋ́довъ. и҆ вни́де въ до́мъ заха́рїинъ, и҆ цѣлова̀ є҆лїсаве́тъ. и҆ бы́сть, ꙗ҆́кѡ ᲂу҆слы́ша є҆лїсаве́тъ цѣлова́нїе марі́ино, взыгра́сѧ младе́нецъ во чре́вѣ є҆ѧ̀: и҆ и҆спо́лнисѧ дх҃а ст҃а є҆лїсаве́тъ. и҆ возопѝ гла́сомъ ве́лїимъ, и҆ речѐ: благослове́на ты̀ въ жена́хъ, и҆ благослове́нъ пло́дъ чре́ва твоегѡ̀. и҆ ѿкꙋ́дꙋ мнѣ̀ сїѐ, да прїи́де мт҃и гдⷭ҇а моегѡ̀ ко мнѣ̀; се́ бо ꙗ҆́кѡ бы́сть гла́съ цѣлова́нїѧ твоегѡ̀ во ᲂу҆́шїю мое́ю, взыгра́сѧ младе́нецъ ра́дощами во чре́вѣ мое́мъ: и҆ блаже́нна вѣ́ровавшаѧ, ꙗ҆́кѡ бꙋ́детъ соверше́нїе глагѡ́ланнымъ є҆́й ѿ гдⷭ҇а. и҆ речѐ марїа́мъ: вели́читъ дꙋша̀ моѧ̀ гдⷭ҇а, и҆ возра́довасѧ дх҃ъ мо́й ѡ҆ бз҃ѣ сп҃сѣ мое́мъ: ꙗ҆́кѡ призрѣ̀ на смире́нїе рабы̀ своеѧ̀: се́ бо ѿ ны́нѣ ᲂу҆блажа́тъ мѧ̀ всѝ ро́ди. ꙗ҆́кѡ сотворѝ мнѣ̀ вели́чїе си́льный, и҆ ст҃о и҆́мѧ є҆гѡ̀. пребы́сть же марїа́мъ съ не́ю ꙗ҆́кѡ трѝ мѣ́сѧцы: и҆ возврати́сѧ въ до́мъ сво́й. ",
}

add_evangelie_luki {
  ["номер"] = 5,
  ["комментарий"] = "Лк., 5 зач., II, 1–20.",
  ["текст_ру"] = "Во днех о́нех изы́де повеле́ние от ке́саря А́вгуста написа́ти всю вселе́нную. Сие́ написа́ние пе́рвое бысть, владя́щу Сири́ею Кирини́ю. И идя́ху вси написа́тися, ко́ждо во свой град. Взы́де же и Ио́сиф от Галиле́и из гра́да Назаре́та во Иуде́ю, во град Дави́дов, и́же нарица́ется Вифлее́м, зане́ бы́ти ему́ от до́му и оте́чества Дави́дова, написа́тися с Мари́ею, обруче́ною ему́ жено́ю, су́щею непра́здною. Бысть же, егда́ бы́ша та́мо, испо́лнишася дни́е роди́ти Ей. И роди́ Сы́на Своего́ пе́рвенца, и пови́т Его́, и положи́ Его́ в я́слех, зане́ не бе им ме́ста во оби́тели. И па́стырие бе́ху в то́йже стране́, бдя́ще, и стрегу́ще стра́жу нощну́ю о ста́де свое́м. И се А́нгел Госпо́день ста в них, и сла́ва Госпо́дня осия́ их, и убоя́шася стра́хом ве́лиим. И рече́ им А́нгел: не бо́йтеся, се бо благовеству́ю вам ра́дость ве́лию, я́же бу́дет всем лю́дем, я́ко роди́ся вам днесь Спас, и́же есть Христо́с Госпо́дь, во гра́де Дави́дове. И се вам зна́мение: обря́щете Младе́нец пови́т, лежа́щ в я́слех. И внеза́пу бысть со А́нгелом мно́жество вой Небе́сных, хва́лящих Бо́га и глаго́лющих: сла́ва в Вы́шних Бо́гу, и на земли́ мир, во челове́цех благоволе́ние. И бысть, я́ко отыдо́ша от них на Не́бо А́нгели, и челове́цы па́стырие ре́ша друг ко дру́гу: пре́йдем до Вифлее́ма и ви́дим глаго́л сей бы́вший, и́же Госпо́дь сказа́ нам. И приидо́ша, поспе́шшеся, и обрето́ша Мариа́м же и Ио́сифа и Младе́нец, лежа́щ во я́слех. Ви́девше же, сказа́ша о глаго́ле, глаго́ланном им о Отроча́ти Сем. И вси слы́шавшии диви́шася о глаго́ланных от па́стырей к ним. Мариа́м же соблюда́ше вся глаго́лы сия́, слага́ющи в се́рдцы Свое́м. И возврати́шася па́стырие, сла́вяще и хва́ляще Бо́га о всех я́же слы́шаша и ви́деша, я́коже глаго́лано бысть к ним. ",
  ["текст_цс"] = "Во дне́хъ ѻ҆́нѣхъ и҆зы́де повелѣ́нїе ѿ ке́сарѧ а҆́ѵгꙋста, написа́ти всю̀ вселе́ннꙋю. сїѐ написа́нїе пе́рвое бы́сть, владѧ́щꙋ сѷрі́ею кѷрині́ю. и҆ и҆дѧ́хꙋ всѝ написа́тисѧ, ко́ждо во сво́й гра́дъ. взы́де же и҆ і҆ѡ́сифъ ѿ галїле́и, и҆з̾ гра́да назаре́та во і҆ꙋде́ю, во гра́дъ даві́довъ, и҆́же нарица́етсѧ виѳлее́мъ, занѐ бы́ти є҆мꙋ̀ ѿ до́мꙋ и҆ ѻ҆те́чества даві́дова, написа́тисѧ съ марі́ею ѡ҆брꙋче́ною є҆мꙋ̀ жено́ю, сꙋ́щею непра́здною. бы́сть же є҆гда̀ бы́ша та́мѡ, и҆спо́лнишасѧ дні́е роди́ти є҆́й. и҆ родѝ сн҃а своего̀ пе́рвенца, и҆ пови́тъ є҆го̀, и҆ положѝ є҆го̀ въ ꙗ҆́слехъ: занѐ не бѣ̀ и҆̀мъ мѣ́ста во ѻ҆би́тели. и҆ па́стырїе бѣ́хꙋ въ то́йже странѣ̀ бдѧ́ще, и҆ стрегꙋ́ще стра́жꙋ нощнꙋ́ю ѡ҆ ста́дѣ свое́мъ. и҆ сѐ а҆́гг҃лъ гдⷭ҇нь ста̀ въ ни́хъ, и҆ сла́ва гдⷭ҇нѧ ѡ҆сїѧ̀ и҆̀хъ: и҆ ᲂу҆боѧ́шасѧ стра́хомъ ве́лїимъ. и҆ речѐ и҆̀мъ а҆́гг҃лъ: не бо́йтесѧ, се́ бо благовѣствꙋ́ю ва́мъ ра́дость ве́лїю, ꙗ҆́же бꙋ́детъ всѣ́мъ лю́демъ. ꙗ҆́кѡ роди́сѧ ва́мъ дне́сь сп҃съ, и҆́же є҆́сть хрⷭ҇то́съ гдⷭ҇ь, во гра́дѣ даві́довѣ. и҆ сѐ ва́мъ зна́менїе: ѡ҆брѧ́щете младе́нецъ пови́тъ, лежа́щъ въ ꙗ҆́слехъ. и҆ внеза́пꙋ бы́сть со а҆́гг҃ломъ мно́жество вѡ́й нбⷭ҇ныхъ, хва́лѧщихъ бг҃а, и҆ глаго́лющихъ: сла́ва въ вы́шнихъ бг҃ꙋ, и҆ на землѝ ми́ръ, во чл҃вѣ́цѣхъ бл҃говоле́нїе. и҆ бы́сть ꙗ҆́кѡ ѿидо́ша ѿ ни́хъ на нб҃о а҆́гг҃ли, и҆ чл҃вѣ́цы па́стырїе рѣ́ша дрꙋ́гъ ко дрꙋ́гꙋ: пре́йдемъ до виѳлее́ма, и҆ ви́димъ глаго́лъ се́й бы́вшїй, и҆́же гдⷭ҇ь сказа̀ на́мъ. и҆ прїидо́ша поспѣ́шшесѧ, и҆ ѡ҆брѣто́ша марїа́мъ же и҆ і҆ѡ́сифа: и҆ младе́нецъ лежа́щъ во ꙗ҆́слехъ. ви́дѣвше же сказа́ша ѡ҆ глаго́лѣ глаго́ланномъ и҆̀мъ ѡ҆ ѻ҆троча́ти се́мъ. и҆ всѝ слы́шавшїи диви́шасѧ ѡ҆ глаго́ланныхъ ѿ па́стырей къ ни́мъ. марїа́мъ же соблюда́ше всѧ̀ глаго́лы сїѧ̀, слага́ющи въ се́рдцы свое́мъ. и҆ возврати́шасѧ па́стырїе, сла́вѧще и҆ хва́лѧще бг҃а ѡ҆ всѣ́хъ, ꙗ҆̀же слы́шаша и҆ ви́дѣша, ꙗ҆́коже глаго́лано бы́сть къ ни́мъ. ",
}

add_evangelie_luki {
  ["номер"] = 6,
  ["комментарий"] = "Лк., 6 зач., II, 20–21, 40–52.",
  ["текст_ру"] = "Во вре́мя о́но, возврати́шася па́стырие, сла́вяще и хва́ляще Бо́га о всех, я́же слы́шаша и ви́деша, я́коже глаго́лано бысть к ним. И егда́ испо́лнишася осмь дний, да обре́жут Его́, и нареко́ша и́мя Ему́ Иису́с, нарече́нное А́нгелом пре́жде да́же не зача́тся во чре́ве. Отроча́ же растя́ше, и крепля́шеся ду́хом, исполня́яся прему́дрости, и благода́ть Бо́жия бе на Нем. И хожда́ста роди́теля Его́ на вся́ко ле́то во Иерусали́м в пра́здник па́схи. И егда́ бысть двоюна́десяте ле́ту, восходя́щым им во Иерусали́м по обы́чаю пра́здника. И сконча́вшем дни, и возвраща́ющимся им, оста́ о́трок Иису́с во Иерусали́ме. И не разуме́ Ио́сиф и Ма́ти Его́. Мне́вша же Его́ во дружи́не су́ща, преидо́ста дне путь, и иска́ста Его́ во сро́дницех, и в зна́емых. И не обре́тша Его́, возврати́стася во Иерусали́м, взыска́юща Его́. И бысть, по трие́х днех, обрето́ста Его́ в це́ркви, седя́ща посреде́ учи́телей, и послу́шающа их, и вопроша́юща их. Ужаса́хуся же вси послу́шающии Его́ о ра́зуме и о отве́тех Его́. И ви́девша Его́, диви́стася, и к Нему́ Ма́ти Его́ рече́: Ча́до, что сотвори́ на́ма та́ко? Се, оте́ц Твой и Аз боля́ща иска́хома Тебе́. И рече́ к ни́ма: что я́ко иска́ста Мене́? Не ве́ста ли, я́ко в тех, я́же Отца́ Моего́, досто́ит бы́ти Ми? И та не разуме́ста глаго́ла, и́же глаго́ла и́ма. И сни́де с ни́ма, и прии́де в Назаре́т, и бе повину́яся и́ма. И Ма́ти Его́ соблюда́ше вся глаго́лы сия́ в се́рдцы Свое́м. И Иису́с преспева́ше прему́дростию и во́зрастом, и благода́тию у Бо́га и челове́к. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но возврати́шасѧ па́стырїе, сла́вѧще и҆ хва́лѧще бг҃а ѡ҆ всѣ́хъ, ꙗ҆̀же слы́шаша и҆ ви́дѣша, ꙗ҆́коже глаго́лано бы́сть къ ни́мъ. и҆ є҆гда̀ и҆спо́лнишасѧ ѻ҆́смь дні́й, да ѡ҆брѣ́жꙋтъ є҆го̀, и҆ нареко́ша и҆́мѧ є҆мꙋ̀ і҆и҃съ, нарече́нное а҆́гг҃ломъ, пре́жде да́же не зача́тсѧ во чре́вѣ. ѻ҆троча́ же растѧ́ше, и҆ крѣплѧ́шесѧ дх҃омъ, и҆сполнѧ́ѧсѧ премꙋ́дрости: и҆ бл҃года́ть бж҃їѧ бѣ̀ на не́мъ. и҆ хожда́ста роди́тєлѧ є҆гѡ̀ на всѧ́ко лѣ́то во і҆ерꙋсали́мъ, въ пра́здникъ па́схи. и҆ є҆гда̀ бы́сть двоюна́десѧте лѣ́тꙋ, восходѧ́щымъ и҆̀мъ во і҆ерꙋсали́мъ по ѻ҆бы́чаю пра́здника: и҆ сконча́вшємъ днѝ, и҆ возвраща́ющымсѧ и҆̀мъ, ѡ҆ста̀ ѻ҆́трокъ і҆и҃съ во і҆ерꙋсали́мѣ, и҆ не разꙋмѣ̀ і҆ѡ́сифъ и҆ мт҃и є҆гѡ̀. мнѣ́вша же є҆го̀ во дрꙋжи́нѣ сꙋ́ща, преидо́ста днѐ пꙋ́ть, и҆ и҆ска́ста є҆го̀ во сро́дницѣхъ, и҆ въ зна́емыхъ. и҆ не ѡ҆брѣ́тша є҆го̀, возврати́стасѧ во і҆ерꙋсали́мъ, взыска́юща є҆го̀. и҆ бы́сть по трїе́хъ дне́хъ, ѡ҆брѣто́ста є҆го̀ въ це́ркви, сѣдѧ́ща посредѣ̀ ᲂу҆чи́телей, и҆ послꙋ́шающа и҆́хъ, и҆ вопроша́юща и҆̀хъ. ᲂу҆жаса́хꙋсѧ же всѝ послꙋ́шающїи є҆гѡ̀, ѡ҆ ра́зꙋмѣ и҆ ѡ҆ ѿвѣ́тѣхъ є҆гѡ̀. и҆ ви́дѣвша є҆го̀, диви́стасѧ, и҆ къ немꙋ̀ мт҃и є҆гѡ̀ речѐ: ча́до, что̀ сотворѝ на́ма та́кѡ; сѐ ѻ҆те́цъ тво́й, и҆ а҆́зъ болѧ́ща и҆ска́хома тебѐ. и҆ речѐ къ ни́ма: что̀ ꙗ҆́кѡ и҆ска́ста менѐ; не вѣ́ста ли, ꙗ҆́кѡ въ тѣ́хъ, ꙗ҆̀же ѻ҆ц҃а̀ моегѡ̀, досто́итъ бы́ти мѝ; и҆ та̀ не разꙋмѣ́ста глаго́ла, и҆́же глаго́ла и҆́ма. и҆ сни́де съ ни́ма, и҆ прїи́де въ назаре́тъ, и҆ бѣ̀ повинꙋ́ѧсѧ и҆́ма: и҆ мт҃и є҆гѡ̀ соблюда́ше всѧ̀ глаго́лы сїѧ̀ въ се́рдцы свое́мъ. и҆ і҆и҃съ преспѣва́ше премꙋ́дростїю и҆ во́зрастомъ, и҆ благода́тїю ѿ бг҃а и҆ человѣ̑къ. ",
}

add_evangelie_luki {
  ["номер"] = 7,
  ["комментарий"] = "Лк., 7 зач., II, 22–40.",
  ["текст_ру"] = "Во вре́мя о́но, вознесо́ста роди́теля Отроча́ Иису́са во Иерусали́м, поста́вити Его́ пред Го́сподем. Я́коже есть пи́сано в зако́не Госпо́дни: я́ко всяк младе́нец му́жеска по́лу, разверза́я ложесна́, свя́то Го́сподеви нарече́тся. И еже да́ти же́ртву, по рече́нному в зако́не Госпо́дни: два го́рличища или́ два птенца́ голуби́на. И се бе челове́к во Иерусали́ме, ему́же и́мя Симео́н. И челове́к сей пра́веден и благочести́в, ча́я уте́хи Изра́илевы, и Дух бе Свят в нем. И бе ему́ обеща́но Ду́хом Святы́м, не ви́дети сме́рти, пре́жде да́же не ви́дит Христа́ Госпо́дня. И прии́де ду́хом в це́рковь. И егда́ введо́ста роди́теля Отроча́ Иису́са, сотвори́ти и́ма по обы́чаю зако́нному о Нем. И той прие́м Его́ на руку́ свое́ю, и благослови́ Бо́га, и рече́: ны́не отпуща́еши раба́ Твоего́, Влады́ко, по глаго́лу Твоему́ с ми́ром. Я́ко ви́десте очи мои́ спасе́ние Твое́, Еже еси́ угото́вал пред лице́м всех люде́й. Свет во открове́ние язы́ком и сла́ву люде́й Твои́х Изра́иля. И бе Ио́сиф и Ма́ти Его́ чудя́щася о глаго́лемых о Нем. И благослови́ я́ Симео́н, и рече́ к Мари́и, Ма́тери Его́: се лежи́т Сей на паде́ние и на воста́ние мно́гим во Изра́или, и в зна́мение пререка́емо. И Тебе́ же Само́й ду́шу про́йдет ору́жие, я́ко да откры́ются от мног серде́ц помышле́ния. И бе А́нна проро́чица, дщи Фану́илева, от коле́на Аси́рова. Сия́ заматоре́вши во днех мно́зех, жи́вши с му́жем седмь лет от де́вства своего́. И та вдова́ я́ко лет о́смьдесят и четы́ре, я́же не отхожда́ше от це́ркве, посто́м и моли́твами служа́щи день и нощь. И та в той час приста́вши, испове́дашеся Го́сподеви, и глаго́лаше о Нем всем ча́ющим избавле́ния во Иерусали́ме. И я́ко сконча́шася вся по зако́ну Госпо́дню, возврати́шася в Галиле́ю, во град свой Назаре́т. Отроча́ же растя́ше и крепля́шеся ду́хом, исполня́яся прему́дрости, и благода́ть Бо́жия бе на Нем. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, вознесо́ста роди́тєлѧ ѻ҆троча̀ і҆и҃са во і҆ерꙋсали́мъ, поста́вити є҆го̀ пред̾ гдⷭ҇емъ. ꙗ҆́коже є҆́сть пи́сано въ зако́нѣ гдⷭ҇ни: ꙗ҆́кѡ всѧ́къ младе́нецъ мꙋ́жеска по́лꙋ, разверза́ѧ ложесна̀, ст҃о гдⷭ҇ви нарече́тсѧ. и҆ є҆́же да́ти же́ртвꙋ, по рече́нномꙋ въ зако́нѣ гдⷭ҇ни: два̀ го́рличища и҆лѝ два̀ птенца̀ голꙋби́на. и҆ сѐ бѣ̀ человѣ́къ во і҆ерꙋсали́мѣ, є҆мꙋ́же и҆́мѧ сѷмеѡ́нъ: и҆ человѣ́къ се́й пра́веденъ, и҆ благочести́въ, ча́ѧ ᲂу҆тѣ́хи і҆и҃левы: и҆ дх҃ъ бѣ̀ ст҃ъ въ не́мъ. и҆ бѣ̀ є҆мꙋ̀ ѡ҆бѣща́но дх҃омъ ст҃ы́мъ, не ви́дѣти сме́рти, пре́жде да́же не ви́дитъ хрⷭ҇та̀ гдⷭ҇нѧ. и҆ прїи́де дх҃омъ въ цр҃ковь, и҆ є҆гда̀ введо́ста роди́тєлѧ ѻ҆троча̀ і҆и҃са, сотвори́ти и҆́ма по ѻ҆бы́чаю зако́нномꙋ ѡ҆ не́мъ: и҆ то́й прїе́мъ є҆го̀ на рꙋкꙋ̀ свое́ю, и҆ бл҃гословѝ бг҃а, и҆ речѐ: ны́нѣ ѿпꙋща́еши раба̀ твоего̀ влⷣко, по глаго́лꙋ твоемꙋ̀ съ ми́ромъ: ꙗ҆́кѡ ви́дѣстѣ ѻ҆́чи моѝ спасе́нїе твоѐ, є҆́же є҆сѝ ᲂу҆гото́валъ пред̾ лице́мъ всѣ́хъ люде́й: свѣ́тъ во ѿкрове́нїе ꙗ҆зы́кѡмъ, и҆ сла́вꙋ люде́й твои́хъ і҆и҃лѧ. и҆ бѣ̀ і҆ѡ́сифъ и҆ мт҃и є҆гѡ̀ чꙋдѧ́щасѧ ѡ҆ глаго́лемыхъ ѡ҆ не́мъ. и҆ бл҃гословѝ ѧ҆̀ сѷмеѡ́нъ, и҆ речѐ къ мр҃і́и мт҃ри є҆гѡ̀: сѐ лежи́тъ се́й на паде́нїе, и҆ на воста́нїе мнѡ́гимъ во і҆и҃ли, и҆ въ зна́менїе прерѣка́емо: и҆ тебѣ́ же само́й дꙋ́шꙋ про́йдетъ ѻ҆рꙋ́жїе, ꙗ҆́кѡ да ѿкры́ютсѧ ѿ мнѡ́гъ серде́цъ помышлє́нїѧ. и҆ бѣ̀ а҆́нна проро́чица, дщѝ фанꙋ́илева, ѿ колѣ́на а҆си́рова: сїѧ̀ заматорѣ́вши во дне́хъ мно́зѣхъ, жи́вши съ мꙋ́жемъ се́дмь лѣ́тъ ѿ дѣ́вства своегѡ̀: и҆ та̀ вдова̀ ꙗ҆́кѡ лѣ́тъ ѻ҆́смьдесѧтъ и҆ четы́ре, ꙗ҆́же не ѿхожда́ше ѿ це́ркве, посто́мъ и҆ моли́твами слꙋжа́щи де́нь и҆ но́щь. и҆ та̀ въ то́й ча́съ приста́вши, и҆сповѣ́дашесѧ гдⷭ҇ви, и҆ глаго́лаше ѡ҆ не́мъ всѣ̑мъ ча́ющымъ и҆збавле́нїѧ во і҆ерꙋсали́мѣ. и҆ ꙗ҆́кѡ сконча́шасѧ всѧ̑ по зако́нꙋ гдⷭ҇ню, возврати́шасѧ въ галїле́ю, во гра́дъ сво́й назаре́тъ. ѻ҆троча́ же растѧ́ше, и҆ крѣплѧ́шесѧ дх҃омъ, и҆сполнѧ́ѧсѧ премꙋ́дрости: и҆ бл҃года́ть бж҃їѧ бѣ̀ на не́мъ. ",
}

add_evangelie_luki {
