add_evangelie_luki {
  ["номер"] = 8,
  ["комментарий"] = "Лк., 8 зач., II, 25–38.",
  ["текст_ру"] = "Во вре́мя о́но, бе челове́к во Иерусали́ме, ему́же и́мя Симео́н. И челове́к сей пра́веден и благочести́в, ча́я уте́хи Изра́илевы, и Дух бе Свят в нем. И бе ему́ обеща́но Ду́хом Святы́м, не ви́дети сме́рти, пре́жде да́же не ви́дит Христа́ Госпо́дня. И прии́де Ду́хом в це́рковь. И егда́ введо́ста роди́теля Отроча́ Иису́са, сотвори́ти и́ма по обы́чаю зако́нному о Нем, и той прие́м Его́ на руку́ свое́ю, и благослови́ Бо́га, и рече́: ны́не отпуща́еши раба́ Твоего́, Влады́ко, по глаго́лу Твоему́, с ми́ром, я́ко ви́десте о́чи мои́ спасе́ние Твое́, е́же еси́ угото́вал пред лице́м всех люде́й, свет во открове́ние язы́ком, и сла́ву люде́й Твои́х Изра́иля. И бе Ио́сиф и Ма́ти Его́ чудя́щася о глаго́лемых о Нем. И благослови́ я́ Симео́н, и рече́ к Мари́и Ма́тери Его́: се лежи́т Сей на паде́ние и на воста́ние мно́гим во Изра́или, и в зна́мение пререка́емо, и Тебе́ же Само́й ду́шу про́йдет ору́жие, я́ко да откры́ются от мно́г серде́ц помышле́ния. И бе А́нна проро́чица, дщи Фану́илева, от коле́на Аси́рова, сия́ заматоре́вши во днех мно́зех, жи́вши с му́жем седмь лет от де́вства своего́, и та вдова́ я́ко лет о́смьдесят и четы́ре, я́же не отхожда́ше от це́ркве, посто́м и моли́твами служа́щи день и нощь. И та в той час приста́вши испове́дашеся Го́сподеви и глаго́лаше о Нем всем ча́ющым избавле́ния во Иерусали́ме. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бѣ̀ человѣ́къ во і҆ерꙋсали́мѣ, є҆мꙋ́же и҆́мѧ сѷмеѡ́нъ: и҆ человѣ́къ се́й пра́веденъ, и҆ благочести́въ, ча́ѧ ᲂу҆тѣ́хи і҆и҃левы: и҆ дх҃ъ бѣ̀ ст҃ъ въ не́мъ. и҆ бѣ̀ є҆мꙋ̀ ѡ҆бѣща́но дх҃омъ ст҃ы́мъ, не ви́дѣти сме́рти, пре́жде да́же не ви́дитъ хрⷭ҇та̀ гдⷭ҇нѧ. и҆ прїи́де дх҃омъ въ цр҃ковь, и҆ є҆гда̀ введо́ста роди́тєлѧ ѻ҆троча̀ і҆и҃са, сотвори́ти и҆́ма по ѻ҆бы́чаю зако́нномꙋ ѡ҆ не́мъ: и҆ то́й прїе́мъ є҆го̀ на рꙋкꙋ̀ свое́ю, и҆ бл҃гословѝ бг҃а, и҆ речѐ: ны́нѣ ѿпꙋща́еши раба̀ твоего̀ влⷣко, по глаго́лꙋ твоемꙋ̀ съ ми́ромъ: ꙗ҆́кѡ ви́дѣстѣ ѻ҆́чи моѝ спасе́нїе твоѐ, є҆́же є҆сѝ ᲂу҆гото́валъ пред̾ лице́мъ всѣ́хъ люде́й: свѣ́тъ во ѿкрове́нїе ꙗ҆зы́кѡмъ, и҆ сла́вꙋ люде́й твои́хъ і҆и҃лѧ. и҆ бѣ̀ і҆ѡ́сифъ и҆ мт҃и є҆гѡ̀ чꙋдѧ́щасѧ ѡ҆ глаго́лемыхъ ѡ҆ не́мъ. и҆ бл҃гословѝ ѧ҆̀ сѷмеѡ́нъ, и҆ речѐ къ мр҃і́и мт҃ри є҆гѡ̀: сѐ лежи́тъ се́й на паде́нїе, и҆ на воста́нїе мнѡ́гимъ во і҆и҃ли, и҆ въ зна́менїе прерѣка́емо: и҆ тебѣ́ же само́й дꙋ́шꙋ про́йдетъ ѻ҆рꙋ́жїе, ꙗ҆́кѡ да ѿкры́ютсѧ ѿ мнѡ́гъ серде́цъ помышлє́нїѧ. и҆ бѣ̀ а҆́нна проро́чица, дщѝ фанꙋ́илева, ѿ колѣ́на а҆си́рова: сїѧ̀ заматорѣ́вши во дне́хъ мно́зѣхъ, жи́вши съ мꙋ́жемъ се́дмь лѣ́тъ ѿ дѣ́вства своегѡ̀: и҆ та̀ вдова̀ ꙗ҆́кѡ лѣ́тъ ѻ҆́смьдесѧтъ и҆ четы́ре, ꙗ҆́же не ѿхожда́ше ѿ це́ркве, посто́мъ и҆ моли́твами слꙋжа́щи де́нь и҆ но́щь. и҆ та̀ въ то́й ча́съ приста́вши, и҆сповѣ́дашесѧ гдⷭ҇ви, и҆ глаго́лаше ѡ҆ не́мъ всѣ̑мъ ча́ющымъ и҆збавле́нїѧ во і҆ерꙋсали́мѣ. ",
}

add_evangelie_luki {
  ["номер"] = 9,
  ["комментарий"] = "Лк., 9 зач., III, 1–18.",
  ["текст_ру"] = "В пя́тое на́десяте ле́то влады́чества Тиве́рия ке́саря, облада́ющу Понти́йскому Пила́ту Иуде́ею, и четвертовла́ствующу Галиле́ею И́роду, Фили́ппу же, бра́ту его́ четвертовла́ствующу Тири́ею и Трахони́тскою страно́ю, и Лиса́нию Авилини́ею четвертовла́ствующу, при архиере́и А́нне и Каиа́фе, бысть глаго́л Бо́жий ко Иоа́нну, Заха́риину сы́ну, в пусты́ни. И прии́де во всю страну́ Иорда́нскую, пропове́дая креще́ние покая́ния во оставле́ние грехо́в. Я́коже есть пи́сано в кни́зе слове́с Иса́ии проро́ка, глаго́люща: глас вопию́щаго в пусты́ни, угото́вайте путь Госпо́день, пра́вы твори́те стези́ Его́. Вся́ка дебрь испо́лнится, и вся́ка гора́ и холм смири́тся, и бу́дут стропо́тная в пра́вая и о́стрии в пути́ гла́дки. И у́зрит вся́ка плоть спасе́ние Бо́жие. Глаго́лаше же исходя́щим наро́дом крести́тися от него́: порожде́ния ехи́днова, кто сказа́ вам бежа́ти от гряду́щаго гне́ва? Сотвори́те у́бо плоды́ досто́йны покая́ния, и не начина́йте глаго́лати в себе́: отца́ и́мамы Авраа́ма. Глаго́лю бо вам, я́ко мо́жет Бог от ка́мения сего́ воздви́гнути ча́да Авраа́му. Уже́ бо и секи́ра при ко́рени дре́ва лежи́т: вся́ко у́бо дре́во, не творя́щее плода́ добра́, посека́ется и во огнь вмета́ется. И вопроша́ху его́ наро́ди, глаго́люще: что у́бо сотвори́м? Отвеща́в же глаго́ла им: име́яй две ри́зе, да пода́ст неиму́щему, и име́яй бра́шна, та́кожде да твори́т. Приидо́ша же и мытари́ крести́тися от него́, и ре́ша к нему́: учи́телю, что сотвори́м? Он же рече́ к ним: ничто́же бо́ле от повеле́ннаго вам твори́те. Вопроша́ху же его́ и во́ини, глаго́люще: и мы что сотвори́м? И рече́ к ним: никого́же оби́дите, ни оклеветава́йте, и дово́льни бу́дите обро́ки ва́шими. Ча́ющим же лю́дем, и помышля́ющим всем в сердца́х свои́х о Иоа́нне, еда́ той есть Христо́с, отвещава́ше Иоа́нн всем глаго́ля: аз у́бо водо́ю креща́ю вы: гряде́т же Кре́плий мене́, Ему́же несмь досто́ин отреши́ти реме́нь сапогу́ Его́. Той вы крести́т Ду́хом Святы́м и огне́м. Ему́же лопа́та в руку́ Его́, и потреби́т гумно́ Свое́, и собере́т пщени́цу в жи́тницу Свою́, пле́вы же сожже́т огне́м негаса́ющим. Мно́га же у́бо и и́на, утеша́я благовествова́ше лю́дем. ",
  ["текст_цс"] = "Въ пѧ́тое на́десѧте лѣ́то влады́чества тїве́рїа ке́сарѧ: ѡ҆блада́ющꙋ понті́йскомꙋ пїла́тꙋ і҆ꙋде́ею, и҆ четвертовла́стствꙋющꙋ галїле́ею и҆́рѡдꙋ: фїлі́ппꙋ же, бра́тꙋ є҆гѡ̀, четвертовла́стствꙋющꙋ тѷрі́ею и҆ трахоні́тскою страно́ю: и҆ лѷса́нїю а҆вїлині́ею четвертовла́стствꙋющꙋ: при а҆рхїере́и а҆́ннѣ и҆ каїа́фѣ, бы́сть глаго́лъ бж҃їй ко і҆ѡа́ннꙋ, заха́рїинꙋ сы́нꙋ, въ пꙋсты́ни. и҆ прїи́де во всю̀ странꙋ̀ і҆ѻрда́нскꙋю, проповѣ́даѧ креще́нїе покаѧ́нїѧ, во ѡ҆ставле́нїе грѣхѡ́въ. ꙗ҆́коже є҆́сть пи́сано въ кни́зѣ слове́съ и҆са́їи проро́ка, глаго́люща: гла́съ вопїю́щагѡ въ пꙋсты́ни, ᲂу҆гото́вайте пꙋ́ть гдⷭ҇нь, пра́вы твори́те стєзѝ є҆гѡ̀. всѧ́ка де́брь и҆спо́лнитсѧ, и҆ всѧ́ка гора̀ и҆ хо́лмъ смири́тсѧ: и҆ бꙋ́дꙋтъ стропѡ́тнаѧ въ пра̑ваѧ и҆ ѻ҆́стрїи въ пꙋтѝ гла́дки. и҆ ᲂу҆́зритъ всѧ́ка пло́ть спасе́нїе бж҃їе. глаго́лаше же и҆сходѧ́щымъ наро́дѡмъ крести́тисѧ ѿ негѡ̀: порождє́нїѧ є҆хі́днова, кто̀ сказа̀ ва́мъ бѣжа́ти ѿ грѧдꙋ́щагѡ гнѣ́ва; сотвори́те ᲂу҆́бѡ плоды̀ досто́йны покаѧ́нїѧ, и҆ не начина́йте глаго́лати въ себѣ̀: ѻ҆тца̀ и҆́мамы а҆враа́ма. глаго́лю бо ва́мъ, ꙗ҆́кѡ мо́жетъ бг҃ъ ѿ ка́менїѧ сегѡ̀ воздви́гнꙋти ча̑да а҆враа́мꙋ. ᲂу҆же́ бо и҆ сѣки́ра при ко́рени дре́ва лежи́тъ: всѧ́ко ᲂу҆́бѡ дре́во, не творѧ́щее плода̀ добра̀, посѣка́етсѧ, и҆ во ѻ҆́гнь вмета́етсѧ. и҆ вопроша́хꙋ є҆го̀ наро́ди, глаго́люще: что̀ ᲂу҆́бѡ сотвори́мъ; ѿвѣща́въ же, глаго́ла и҆̀мъ: и҆мѣ́ѧй двѣ̀ ри́зѣ, да пода́стъ неимꙋ́щемꙋ, и҆ и҆мѣ́ѧй бра̑шна, та́кожде да твори́тъ. прїидо́ша же и҆ мытарѝ крести́тисѧ ѿ негѡ̀, и҆ рѣ́ша къ немꙋ̀: ᲂу҆чи́телю, что̀ сотвори́мъ; ѻ҆́нъ же речѐ къ ни́мъ: ничто́же бо́ле ѿ повелѣ́ннагѡ ва́мъ твори́те. вопроша́хꙋ же є҆го̀ и҆ во́ини, глаго́люще: и҆ мы̀ что̀ сотвори́мъ; и҆ речѐ къ ни́мъ: никого́же ѡ҆би́дите, ни ѡ҆клеветава́йте: и҆ дово́льни бꙋ́дите ѡ҆бро́ки ва́шими. ча́ющымъ же лю́демъ, и҆ помышлѧ́ющымъ всѣ́мъ въ сердца́хъ свои́хъ ѡ҆ і҆ѡа́ннѣ, є҆да̀ то́й є҆́сть хрⷭ҇то́съ; ѿвѣщава́ше і҆ѡа́ннъ всѣ̑мъ глаго́лѧ: а҆́зъ ᲂу҆́бѡ водо́ю креща́ю вы̀: грѧде́тъ же крѣ́плїй менѐ, є҆мꙋ́же нѣ́смь досто́инъ ѿрѣши́ти реме́нь сапогꙋ̀ є҆гѡ̀, то́й вы̀ крести́тъ дх҃омъ ст҃ы́мъ и҆ ѻ҆гне́мъ. є҆мꙋ́же лопа́та въ рꙋкꙋ̀ є҆гѡ̀, и҆ потреби́тъ гꙋмно̀ своѐ, и҆ собере́тъ пшени́цꙋ въ жи́тницꙋ свою̀: плє́вы же сожже́тъ ѻ҆гне́мъ негаса́ющимъ. мнѡ́га же ᲂу҆́бѡ и҆ и҆́на, ᲂу҆тѣша́ѧ, благовѣствова́ше лю́демъ. ",
}

add_evangelie_luki {
  ["номер"] = 10,
  ["комментарий"] = "Лк., 10 зач., III, 19–22.",
  ["текст_ру"] = "Во вре́мя о́но, И́род четвертовла́стник, облича́емь от Иоа́нна о Иродиа́де жене́ бра́та своего́, и о всех, я́же сотвори́ зла́я И́род, приложи́ и сие́ над все́ми, и затвори́ Иоа́нна в темни́це. Бысть же егда́ крести́шася вси лю́дие, и Иису́су кре́щшуся и моля́щуся, отве́рзеся не́бо, и сни́де Дух Святы́й теле́сным о́бразом, я́ко го́лубь, Нань, и глас с небесе́ бысть, глаго́ля: Ты еси́ Сын Мой Возлю́бленный, о Тебе́ благоволи́х. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆́рѡдъ четвертовла́стникъ ѡ҆блича́емь ѿ і҆ѡа́нна ѡ҆ и҆рѡдїа́дѣ женѣ̀ бра́та своегѡ̀, и҆ ѡ҆ всѣ́хъ, ꙗ҆̀же сотворѝ ѕла̑ѧ и҆́рѡдъ: приложѝ и҆ сїѐ над̾ всѣ́ми, и҆ затворѝ і҆ѡа́нна въ темни́цѣ. бы́сть же є҆гда̀ крести́шасѧ всѝ лю́дїе, и҆ і҆и҃сꙋ кре́щшꙋсѧ и҆ молѧ́щꙋсѧ, ѿве́рзесѧ нб҃о. и҆ сни́де дх҃ъ ст҃ы́й тѣле́снымъ ѻ҆́бразомъ, ꙗ҆́кѡ го́лꙋбь на́нь, и҆ гла́съ съ нб҃сѐ бы́сть, глаго́лѧ: ты̀ є҆сѝ сн҃ъ мо́й возлю́бленный, ѡ҆ тебѣ̀ благоволи́хъ. ",
}

add_evangelie_luki {
  ["номер"] = 11,
  ["комментарий"] = "Лк., 11 зач., III, 23 – IV, 1.",
  ["текст_ру"] = "Во вре́мя о́но, бе Иису́с я́ко ле́том три́десять начина́я, сый, я́ко мнимь, сын Ио́сифов, Или́ев, Матфа́тов, Леви́ин, Мелхи́ин, Ианна́ев, Ио́сифов, Маттафи́ев, Амо́сов, Нау́мов, Если́мов, Нагге́ов, Маа́фов, Маттафи́ев, Семеи́ев, Ио́сифов, Иу́дин, Иоанна́нов, Риса́ев, Зорова́велев, Салафии́лев, Нири́ев, Мелхи́ев, Адди́ев, Коса́мов, Елмода́мов, И́ров, Иоси́ев, Елиезе́ров, Иори́мов, Матфа́тов, Леви́ин, Симео́нов, Иу́дин, Ио́сифов, Иона́нов, Елиаки́мов, Мелеа́ев, Маина́нов, Маттафа́ев, Нафа́нов, Дави́дов, Иессе́ов, Ови́дов, Воо́зов, Салмо́нов, Наассо́нов, Аминада́вов, Ара́мов, [Иора́мов,] Есро́мов, Фаре́сов, Иу́дин, Иа́ковль, Исаа́ков, Авраа́мов, Фара́нов, Нахо́ров, Серу́хов, Рага́вов, Фале́ков, Еве́ров, Сала́нов, Каина́нов, Арфакса́дов, Си́мов, Но́ев, Ламе́хов, Мафуса́лев, Ено́хов, Иа́редов, Малелеи́лов, Каина́нов, Ено́сов, Си́фов, Ада́мов, Бо́жий. Иису́с же испо́лнь Ду́ха Свя́та возврати́ся от Иорда́на, и ведя́шеся Ду́хом в пусты́ню. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бѣ̀ і҆и҃съ ꙗ҆́кѡ лѣ́тѡмъ три́десѧть начина́ѧ, сы́й, ꙗ҆́кѡ мни́мь, сн҃ъ і҆ѡ́сифовъ, и҆лі́евъ, матѳа́товъ, леѵі́инъ, мелхі́инъ, і҆анна́евъ, і҆ѡ́сифовъ, маттаѳі́евъ, а҆мѡ́совъ, наꙋ́мовъ, є҆слі́мовъ, нагге́овъ, маа́ѳовъ, маттаѳі́евъ, семеі́евъ, і҆ѡ́сифовъ, і҆ꙋ́динъ, і҆ѡанна́новъ, риса́евъ, зорова́велевъ, салаѳїи́левъ, нирі́евъ, мелхі́евъ, а҆дді́евъ, кѡса́мовъ, є҆лмѡда́мовъ, и҆́ровъ, і҆ѡсі́евъ, є҆лїезе́ровъ, і҆ѡрі́мовъ, матѳа́товъ, леѵі́инъ, сѷмеѡ́новъ, і҆ꙋ́динъ, і҆ѡ́сифовъ, і҆ѡна́новъ, є҆лїакі́мовъ, мелеа́евъ, маїна́новъ, маттаѳа́евъ, наѳа́новъ, даві́довъ, і҆ессе́овъ, ѡ҆ви́довъ, воо́зовъ, салмѡ́новъ, наассѡ́новъ, а҆мїнада́вовъ, а҆ра́мовъ, і҆ѡра́мовъ, є҆срѡ́мовъ, фаре́совъ, і҆ꙋ́динъ, і҆а́кѡвль, і҆саа́ковъ, а҆враа́мовъ, ѳара́новъ, нахѡ́ровъ, серꙋ́ховъ, рага́вовъ, фале́ковъ, є҆ве́ровъ, сала́новъ, каїна́новъ, а҆рфаѯа́довъ, си́мовъ, нѡ́евъ, ламе́ховъ, маѳꙋса́левъ, є҆нѡ́ховъ, і҆а́редовъ, малелеи́ловъ, каїна́новъ, є҆нѡ́совъ, си́ѳовъ, а҆да́мовъ, бж҃їй. і҆и҃съ же и҆спо́лнь дх҃а ст҃а, возврати́сѧ ѿ і҆ѻрда́на, и҆ ведѧ́шесѧ дх҃омъ въ пꙋсты́ню. ",
