add_evangelie_luki {
  ["номер"] = 12,
  ["комментарий"] = "Лк., 12 зач., IV, 1-15.",
  ["текст_ру"] = "Во вре́мя о́но, возврати́ся Иису́с испо́лнь Ду́ха Свя́та от Иорда́на, и ведя́шеся Ду́хом в пусты́ню. Дний четы́ридесять искуша́емь от диа́вола, и не яст ничесо́же во дни ты́я, и сконча́вшымся им, последи́ взалка́. И рече́ Ему́ диа́вол: а́ще Сын еси́ Бо́жий, рцы ка́меневи сему́, да бу́дет хлеб. И отвеща́в Иису́с к нему́, глаго́ля: пи́сано есть, я́ко не о хле́бе еди́ном жив бу́дет челове́к, но о вся́ком глаго́ле Бо́жии. И возве́д Его́ диа́вол на гору́ высоку́, показа́ Ему́ вся ца́рствия вселе́нныя в часе́ вре́менне, и рече́ Ему́ диа́вол: Тебе́ дам власть сию́ всю и сла́ву их, я́ко мне предана́ есть, и ему́же а́ще хощу́, дам ю́. Ты у́бо а́ще поклони́шися пре́до мно́ю, бу́дут Тебе́ вся. И отвеща́в рече́ ему́ Иису́с: иди́ за Мно́ю, сатана́. Пи́сано есть: поклони́шися Го́споду Бо́гу твоему́, и Тому́ еди́ному послу́жиши. И веде́ Его́ во Иерусали́м, и поста́ви Его́ на криле́ церко́внем, и рече́ Ему́: а́ще Сын еси́ Бо́жий, ве́рзися отсю́ду до́лу. Пи́сано бо есть, я́ко А́нгелом Свои́м запове́сть о Тебе́ сохрани́ти Тя, и на рука́х во́змут Тя, да не когда́ преткне́ши о ка́мень но́гу Твою́. И отвеща́в рече́ ему́ Иису́с, я́ко рече́но есть: не иску́сиши Го́спода Бо́га твоего́. И сконча́в все искуше́ние диа́вол, оты́де от Него́ до вре́мене. И возврати́ся Иису́с в си́ле духо́вней в Галиле́ю, и весть изы́де по всей стране́ о Нем. И той уча́ше на со́нмищах их, сла́вимь все́ми. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, возврати́сѧ і҆и҃съ и҆спо́лнь дх҃а ст҃а ѿ і҆ѻрда́на, и҆ ведѧ́шесѧ дх҃омъ въ пꙋсты́ню, дні́й четы́ридесѧть и҆скꙋша́емь ѿ дїа́вола, и҆ не ꙗ҆́стъ ничесѡ́же во днѝ ты́и: и҆ сконча́вшымсѧ и҆̀мъ, послѣдѝ взалка̀. и҆ речѐ є҆мꙋ̀ дїа́волъ: а҆́ще сн҃ъ є҆сѝ бж҃їй, рцы̀ ка́меневи семꙋ̀, да бꙋ́детъ хлѣ́бъ. и҆ ѿвѣща́въ і҆и҃съ къ немꙋ̀, глаго́лѧ: пи́сано є҆́сть, ꙗ҆́кѡ не ѡ҆ хлѣ́бѣ є҆ди́номъ жи́въ бꙋ́детъ человѣ́къ, но ѡ҆ всѧ́комъ глаго́лѣ бж҃їи. и҆ возве́дъ є҆го̀ дїа́волъ на горꙋ̀ высокꙋ̀, показа̀ є҆мꙋ̀ всѧ̑ црⷭ҇твїѧ вселе́нныѧ въ часѣ̀ вре́меннѣ. и҆ речѐ є҆мꙋ̀ дїа́волъ: тебѣ̀ да́мъ вла́сть сїю̀ всю̀, и҆ сла́вꙋ и҆́хъ, ꙗ҆́кѡ мнѣ̀ предана̀ є҆́сть, и҆ є҆мꙋ́же а҆́ще хощꙋ̀ да́мъ ю҆̀. ты̀ ᲂу҆́бѡ а҆́ще поклони́шисѧ предо мно́ю, бꙋ́дꙋтъ тебѣ̀ всѧ̑. и҆ ѿвѣща́въ речѐ є҆мꙋ̀ і҆и҃съ: и҆дѝ за мно́ю сатана̀. пи́сано є҆́сть: поклони́шисѧ гдⷭ҇ꙋ бг҃ꙋ твоемꙋ̀, и҆ томꙋ̀ є҆ди́номꙋ послꙋ́жиши. и҆ ведѐ є҆го̀ во і҆ерꙋсали́мъ, и҆ поста́ви є҆го̀ на крилѣ̀ церко́внѣмъ, и҆ речѐ є҆мꙋ̀: а҆́ще сн҃ъ є҆сѝ бж҃їй, ве́рзисѧ ѿсю́дꙋ до́лꙋ. пи́сано бо є҆́сть, ꙗ҆́кѡ а҆́г҃глѡмъ свои́мъ заповѣ́сть ѡ҆ тебѣ̀, сохрани́ти тѧ̀: и҆ на рꙋка́хъ во́з̾мꙋтъ тѧ̀, да не когда̀ преткне́ши ѡ҆ ка́мень но́гꙋ твою̀. и҆ ѿвѣща́въ речѐ є҆мꙋ̀ і҆и҃съ: ꙗ҆́кѡ рече́но є҆́сть, не и҆скꙋ́сиши гдⷭ҇а бг҃а твоегѡ̀. и҆ сконча́въ всѐ и҆скꙋше́нїе дїа́волъ, ѿи́де ѿ негѡ̀ до вре́мене. и҆ возврати́сѧ і҆и҃съ въ си́лѣ дх҃о́внѣй въ галїле́ю, и҆ вѣ́сть и҆зы́де по все́й странѣ̀ ѡ҆ не́мъ. и҆ то́й ᲂу҆ча́ше на со́нмищахъ и҆́хъ, сла́вимь всѣ́ми. ",
}

add_evangelie_luki {
  ["номер"] = 13,
  ["комментарий"] = "Лк., 13 зач., IV, 16–22.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с в Назаре́т, иде́же бе воспита́н. И вни́де, по обы́чаю Своему́, в день суббо́тный в со́нмище, и воста́ чести́. И да́ша Ему́ кни́гу Иса́ии проро́ка, и разгну́в кни́гу, обре́те ме́сто, иде́же бе напи́сано: Дух Госпо́день на Мне, Его́же ра́ди пома́за Мя благовести́ти ни́щым, посла́ Мя исцели́ти сокруше́нныя се́рдцем, пропове́дати плене́нным отпуще́ние и слепы́м прозре́ние, отпусти́ти сокруше́нныя во отра́ду, пропове́дати ле́то Госпо́дне прия́тно. И согну́в кни́гу, отда́в слузе́, се́де, и всем в со́нмищи о́чи бе́ху зря́ще Нань. И нача́т глаго́лати к ним, я́ко днесь сбы́стся писа́ние сие́ во у́шию ва́шею. И вси свиде́тельствоваху Ему́, и дивля́хуся о словесе́х благода́ти, исходя́щих из уст Его́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ въ назаре́тъ, и҆дѣ́же бѣ̀ воспита́нъ: и҆ вни́де по ѻ҆бы́чаю своемꙋ̀ въ де́нь сꙋббѡ́тный въ со́нмище, и҆ воста̀ честѝ. и҆ да́ша є҆мꙋ̀ кни́гꙋ и҆са́їи проро́ка, и҆ разгнꙋ́въ кни́гꙋ, ѡ҆брѣ́те мѣ́сто, и҆дѣ́же бѣ̀ напи́сано: дх҃ъ гдⷭ҇нь на мнѣ̀, є҆гѡ́же ра́ди пома́за мѧ̀ благовѣсти́ти ни́щымъ, посла́ мѧ, и҆сцѣли́ти сокрꙋшє́нныѧ се́рдцемъ, проповѣ́дати плѣнє́ннымъ ѿпꙋще́нїе, и҆ слѣпы̑мъ прозрѣ́нїе, ѿпꙋсти́ти сокрꙋшє́нныѧ во ѿра́дꙋ. проповѣ́дати лѣ́то гдⷭ҇не прїѧ́тно. и҆ согнꙋ́въ кни́гꙋ, ѿда́въ слꙋзѣ̀, сѣ́де: и҆ всѣ̑мъ въ со́нмищи ѻ҆́чи бѣ́хꙋ зрѧ́ще на́нь. и҆ нача́тъ глаго́лати къ ни́мъ: ꙗ҆́кѡ дне́сь сбы́стсѧ писа́нїе сїѐ во ᲂу҆́шїю ва́шею. и҆ всѝ свидѣ́тельствовахꙋ є҆мꙋ̀. и҆ дивлѧ́хꙋсѧ ѡ҆ словесѣ́хъ благода́ти, и҆сходѧ́щихъ и҆з̾ ᲂу҆́стъ є҆гѡ̀. ",
}

add_evangelie_luki {
  ["номер"] = 14,
  ["комментарий"] = "Лк., 14 зач., IV, 22–30.",
  ["текст_ру"] = "Во вре́мя о́но, дивля́хуся наро́ди о словесе́х благода́ти, исходя́щих из уст Иису́совых, и глаго́лаху: не Сей ли есть сын Ио́сифов? И рече́ к ним: вся́ко рече́те Ми при́тчу сию́: врачу́, исцели́ся Сам, ели́ка слы́шахом бы́вшая в Капернау́ме, сотвори́ и зде во оте́чествии Свое́м. Рече́ же: ами́нь глаго́лю вам, я́ко ни кото́рый проро́к прия́тен есть во оте́чествии свое́м. Пои́стинне же глаго́лю вам: мно́ги вдови́цы бе́ша во дни Илиины́ во Изра́или, егда́ заключи́ся не́бо три ле́та и ме́сяц шесть, я́ко бысть глад вели́к по всей земли́, и ни ко еди́ной их по́слан бысть Илиа́, то́кмо в Саре́пту Сидо́нскую к жене́ вдови́це. И мно́зи прокаже́ни бе́ху при Елиссе́и проро́це во Изра́или, и ни еди́н же от них очи́стися, то́кмо Неема́н Сириани́н. И испо́лнишася вси я́рости в со́нмищи, слы́шавшии сия́. И воста́вше изгна́ша Его́ вон из гра́да, и ведо́ша Его́ до верху́ горы́, на не́йже град их со́здан бя́ше, да бы́ша Его́ низри́нули. Он же проше́д посреде́ их, идя́ше. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, дивлѧ́хꙋсѧ наро́ди ѡ҆ словесѣ́хъ бл҃года́ти, и҆сходѧ́щихъ и҆з̾ ᲂу҆́стъ і҆и҃совыхъ и҆ глаго́лахꙋ: не се́й ли є҆́сть сн҃ъ і҆ѡ́сифовъ; и҆ речѐ къ ни́мъ: всѧ́кѡ рече́те мѝ при́тчꙋ сїю̀, врачꙋ̀ и҆сцѣли́сѧ са́мъ: є҆ли̑ка слы́шахомъ бы̑вшаѧ въ капернаꙋ́мѣ, сотворѝ и҆ здѣ̀ во ѻ҆те́чествїи свое́мъ. рече́ же: а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ ни кото́рый проро́къ прїѧ́тенъ є҆́сть во ѻ҆те́чествїи свое́мъ. пои́стиннѣ же глаго́лю ва́мъ: мно́ги вдови̑цы бѣ́ша во днѝ и҆лїины̀ во і҆и҃ли, є҆гда̀ заключи́сѧ не́бо трѝ лѣ̑та и҆ мцⷭ҇ъ ше́сть, ꙗ҆́кѡ бы́сть гла́дъ вели́къ по все́й землѝ. и҆ ни ко є҆ди́ной и҆́хъ по́сланъ бы́сть и҆лїа̀, то́кмѡ въ саре́птꙋ сїдѡ́нскꙋю, къ женѣ̀ вдови́цѣ. и҆ мно́зи прокаже́ни бѣ́хꙋ при є҆лїссе́и проро́цѣ во і҆и҃ли: и҆ ни є҆ди́нъ же ѿ ни́хъ ѡ҆чи́стисѧ, то́кмѡ неема́нъ сѷрїани́нъ. и҆ и҆спо́лнишасѧ всѝ ꙗ҆́рости въ со́нмищи, слы́шавшїи сїѧ̑. и҆ воста́вше, и҆згна́ша є҆го̀ во́нъ и҆з̾ гра́да: и҆ ведо́ша є҆го̀ до верхꙋ̀ горы̀, на не́йже гра́дъ и҆́хъ со́зданъ бѧ́ше, да бы́ша є҆го̀ низри́нꙋли. ѻ҆́нъ же проше́дъ посредѣ̀ и҆́хъ и҆дѧ́ше. ",
}

add_evangelie_luki {
  ["номер"] = 15,
  ["комментарий"] = "Лк., 15 зач., IV, 31–36.",
  ["текст_ру"] = "Во вре́мя о́но, сни́де Иису́с в Капернау́м град Галиле́йский, и бе учя́ наро́ды в суббо́ты. И ужаса́хуся о уче́нии Его́, я́ко со вла́стию бе сло́во Его́. И в со́нмищи бе челове́к имы́й ду́ха бе́са нечи́ста, и возопи́ гла́сом ве́лиим, глаго́ля: оста́ви, что нам и Тебе́, Иису́се Назаряни́не? Прише́л еси́ погуби́ти нас, вем Тя, кто еси́, Святы́й Бо́жий. И запрети́ ему́ Иису́с, глаго́ля: премолчи́ и изы́ди из него́. И пове́рг его́ бес посреде́, изы́де из него́, ника́коже вреди́в его́. И бысть у́жас на всех, и стяза́хуся друг ко дру́гу, глаго́люще: что сло́во сие́, я́ко вла́стию и си́лою вели́т нечи́стым духово́м, и исхо́дят? ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, сни́де і҆и҃съ въ капернаꙋ́мъ гра́дъ галїле́йскїй, и҆ бѣ̀ ᲂу҆чѧ̀ наро́ды въ сꙋббѡ́ты и҆ ᲂу҆жаса́хꙋсѧ ѡ҆ ᲂу҆че́нїи є҆гѡ̀, ꙗ҆́кѡ со вла́стїю бѣ̀ сло́во є҆гѡ̀. и҆ въ со́нмищи бѣ̀ человѣ́къ, и҆мы́й дꙋ́хъ бѣ́са нечи́ста, и҆ возопѝ гла́сомъ ве́лїимъ, глаго́лѧ: ѡ҆ста́ви, что̀ на́мъ и҆ тебѣ̀ і҆и҃се назарѧни́не; прише́лъ є҆сѝ погꙋби́ти на́съ: вѣ́мъ тѧ̀, кто̀ є҆сѝ ст҃ы́й бж҃їй. и҆ запретѝ є҆мꙋ̀ і҆и҃съ, глаго́лѧ: премолчѝ, и҆ и҆зы́ди и҆з̾ негѡ̀. и҆ пове́ргъ є҆го̀ бѣ́съ посредѣ̀, и҆зы́де и҆з̾ негѡ̀, ника́коже вреди́въ є҆го̀. и҆ бы́сть ᲂу҆́жасъ на всѣ́хъ, и҆ стѧза́хꙋсѧ дрꙋ́гъ ко дрꙋ́гꙋ, глаго́люще: что̀ сло́во сїѐ, ꙗ҆́кѡ вла́стїю и҆ си́лою вели́тъ нечи́стымъ дꙋховѡ́мъ, и҆ и҆схо́дѧтъ; ",
}

add_evangelie_luki {
  ["номер"] = 16,
  ["комментарий"] = "Лк., 16 зач., IV, 37–44.",
  ["текст_ру"] = "Во вре́мя о́но, вни́де Иису́с в дом Си́монов, и исхожда́ше глас о Нем во вся́кое ме́сто страны́. Те́ща же Си́монова бе одержи́ма огне́м ве́лиим, и моли́ша Его́ о ней. И став над не́ю, запрети́ огню́, и оста́ви ю́. А́бие же воста́вши служа́ше им. Заходя́щу же со́лнцу, вси, ели́цы име́яху боля́щия неду́ги разли́чными, привожда́ху их к Нему́, Он же на еди́ном коего́ждо их ру́це возло́жь, исцеля́ше их. Исхожда́ху же и бе́си от мно́гих, вопию́ще и глаго́люще, я́ко Ты еси́ Христо́с Сын Бо́жий. И запреща́я не дая́ше им глаго́лати, я́ко ве́дяху Христа́ Самаго́ су́ща. Бы́вшу же дню, изше́д и́де в пу́сто ме́сто, и наро́ди иска́ху Его́, и приидо́ша до Него́, и держа́хуся Его́, да не бы отше́л от них. Он же рече́ к ним, я́ко и други́м градово́м благовести́ти Ми подоба́ет Ца́рствие Бо́жие, я́ко на се по́слан есмь. И бе пропове́дая на со́нмищах галиле́йских. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, вни́де і҆и҃съ въ до́мъ сі́мѡновъ, и҆ и҆схожда́ше гла́съ ѡ҆ не́мъ во всѧ́кое мѣ́сто страны̀. те́ща же сі́мѡнова бѣ̀ ѡ҆держи́ма ѻ҆гне́мъ ве́лїимъ, и҆ моли́ша є҆го̀ ѡ҆ не́й. и҆ ста́въ над̾ не́ю, запретѝ ѻ҆гню̀, и҆ ѡ҆ста́ви ю҆̀: а҆́бїе же воста́вши слꙋжа́ше и҆̀мъ. заходѧ́щꙋ же со́лнцꙋ, всѝ є҆ли́цы и҆мѣ́ѧхꙋ болѧ́щыѧ недꙋ́ги разли́чными, привожда́хꙋ и҆̀хъ къ немꙋ̀: ѻ҆́нъ же на є҆ди́номъ коегѡ́ждо и҆́хъ рꙋ́цѣ возло́жъ, и҆сцѣлѧ́ше и҆̀хъ. и҆схожда́хꙋ же и҆ бѣ́си ѿ мно́гихъ вопїю́ще и҆ глаго́люще: ꙗ҆́кѡ ты̀ є҆сѝ хрⷭ҇то́съ сн҃ъ бж҃їй. и҆ запреща́ѧ не даѧ́ше и҆̀мъ глаго́лати, ꙗ҆́кѡ вѣ́дѧхꙋ хрⷭ҇та̀ самаго̀ сꙋ́ща. бы́вшꙋ же днѝ и҆зше́дъ и҆́де въ пꙋ́сто мѣ́сто: и҆ наро́ди и҆ска́хꙋ є҆го̀, и҆ прїидо́ша до негѡ̀, и҆ держа́хꙋсѧ є҆гѡ̀, да не бы̀ ѿше́лъ ѿ ни́хъ. ѻ҆́нъ же речѐ къ ни́мъ: ꙗ҆́кѡ и҆ дрꙋги́мъ градовѡ́мъ благовѣсти́ти мѝ подоба́етъ црⷭ҇твїе бж҃їе, ꙗ҆́кѡ на сѐ по́сланъ є҆́смь. и҆ бѣ̀ проповѣ́даѧ на со́нмищахъ галїле́йскихъ. ",
}

add_evangelie_luki {
  ["номер"] = 17,
  ["комментарий"] = "Лк., 17 зач., V, 1–11.",
  ["текст_ру"] = "Во вре́мя о́но, стоя́ше Иису́с при е́зере Геннисаре́тсте, и ви́де два корабля́ стоя́ща при е́зере, ры́барие же отше́дше от нею́, измыва́ху мре́жи. Влез же в еди́н от кораблю́, и́же бе Си́монов, моли́ его́ от земли́ отступи́ти ма́ло, и сед уча́ше из корабля́ наро́ды. Я́коже преста́ глаго́ля, рече́ к Си́мону: поступи́ во глубину́, и вве́рзите мре́жи ва́ша в лови́тву. И отвеща́в Си́мон рече́ Ему́: Наста́вниче, обно́щь всю тру́ждшеся, ничесо́же я́хом, по глаго́лу же Твоему́ вве́ргу мре́жу. И се сотво́рше, я́ша мно́жество рыб мно́го, протерза́шеся же мре́жа их. И поману́ша прича́стником, и́же бе́ху во друзе́м корабли́, да прише́дше помо́гут им, и приидо́ша, и испо́лниша о́ба корабля́, я́ко погружа́тися и́ма. Ви́дев же Си́мон Петр, припаде́ к коле́нома Иису́совома, глаго́ля: изы́ди от мене́, я́ко муж гре́шен есмь, Го́споди. У́жас бо одержа́ше его́ и вся су́щыя с ним, о лови́тве рыб, я́же я́ша, та́кожде же Иа́кова и Иоа́нна сы́на Зеведе́ова, я́же бе́ста обе́щника Си́монови. И рече́ к Си́мону Иису́с: не бо́йся, отсе́ле бу́деши челове́ки ловя́. И извле́кше о́ба корабля́ на зе́млю, оста́вльше вся, в след Его́ идо́ша. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, стоѧ́ше і҆и҃съ при є҆́зерѣ геннисаре́тстѣ: и҆ ви́дѣ два̀ кораблѧ̀ стоѧ́ща при є҆́зерѣ: ры́барїе же ѿше́дше ѿ нею̀, и҆змыва́хꙋ мрє́жи. влѣ́зъ же въ є҆ди́нъ ѿ кораблю̀, и҆́же бѣ̀ сі́мѡновъ, молѝ є҆го̀ ѿ землѝ ѿстꙋпи́ти ма́лѡ: и҆ сѣ́дъ ᲂу҆ча́ше и҆з̾ кораблѧ̀ наро́ды. ꙗ҆́коже преста̀ глаго́лѧ, речѐ къ сі́мѡнꙋ: постꙋпѝ во глꙋбинꙋ̀, и҆ вве́рзите мрє́жи ва́шѧ въ лови́твꙋ. и҆ ѿвѣща́въ сі́мѡнъ речѐ є҆мꙋ̀: наста́вниче, ѡ҆бно́щь всю̀ трꙋ́ждшесѧ, ничесѡ́же ꙗ҆́хомъ: по глаго́лꙋ же твоемꙋ̀ вве́ргꙋ мре́жꙋ. и҆ сѐ сотво́рше, ꙗ҆́ша мно́жество ры́бъ мно́го, протерза́шесѧ же мре́жа и҆́хъ. и҆ поманꙋ́ша прича́стникѡмъ, и҆̀же бѣ́хꙋ во дрꙋзѣ́мъ кораблѝ, да прише́дше помо́гꙋтъ и҆̀мъ: и҆ прїидо́ша, и҆ и҆спо́лниша ѻ҆́ба кораблѧ̀, ꙗ҆́кѡ погрꙋжа́тисѧ и҆́ма. ви́дѣвъ же сі́мѡнъ пе́тръ, припадѐ къ колѣ́нома і҆и҃совома, глаго́лѧ: и҆зы́ди ѿ менѐ, ꙗ҆́кѡ мꙋ́жъ грѣ́шенъ є҆́смь, гдⷭ҇и. ᲂу҆́жасъ бо ѡ҆держа́ше є҆го̀ и҆ всѧ̑ сꙋ́щыѧ съ ни́мъ, ѡ҆ лови́твѣ ры́бъ, ꙗ҆̀же ꙗ҆́ша: та́кожде же і҆а́кѡва и҆ і҆ѡа́нна, сы́на зеведе́ѡва, ꙗ҆̀же бѣ́ста ѡ҆бе́щника сі́мѡнови. и҆ речѐ къ сі́мѡнꙋ і҆и҃съ: не бо́йсѧ, ѿсе́лѣ бꙋ́деши человѣ́ки ловѧ̀. и҆ и҆звле́кше ѻ҆́ба кораблѧ̀ на зе́млю, ѡ҆ста́вльше всѧ̑ въ слѣ́дъ є҆гѡ̀ и҆до́ша. ",
}

add_evangelie_luki {
  ["номер"] = 18,
  ["комментарий"] = "Лк., 18 зач., V, 12-16.",
  ["текст_ру"] = "Во вре́мя о́но, бе Иису́с во еди́ном от градо́в, и се муж испо́лнь прокаже́ния, и ви́дев Иису́са, пад ниц, моля́ся Ему́, глаго́ля: Го́споди, а́ще хо́щеши, мо́жеши мя очи́стити. И просте́р ру́ку, косну́ его́, рек: хощу́, очи́стися. И а́бие прока́за оты́де от него́. И Той запове́да ему́ никому́же пове́дати, но шед покажи́ся иере́ови, и принеси́ о очище́нии твое́м, я́коже повеле́ Моисе́й, во свиде́тельство им. Прохожда́ше же па́че сло́во о Нем, и схожда́хуся наро́ди мно́зи слы́шати и цели́тися от Него́ от неду́г свои́х. Тойже бе отходя́ в пусты́ню и моля́ся. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бѣ̀ і҆и҃съ во є҆ди́номъ ѿ градѡ́въ, и҆ сѐ мꙋ́жъ и҆спо́лнь прокаже́нїѧ: и҆ ви́дѣвъ і҆и҃са, па́дъ ни́цъ молѧ́сѧ є҆мꙋ̀, глаго́лѧ: гдⷭ҇и, а҆́ще хо́щеши, мо́жеши мѧ̀ ѡ҆чи́стити. и҆ просте́ръ рꙋ́кꙋ, коснꙋ̀ є҆гѡ̀, ре́къ: хощꙋ̀, ѡ҆чи́стисѧ. и҆ а҆́бїе прока́за ѿи́де ѿ негѡ̀. и҆ то́й заповѣ́да є҆мꙋ̀ никомꙋ́же повѣ́дати: но ше́дъ покажи́сѧ і҆ере́ови, и҆ принесѝ ѡ҆ ѡ҆чище́нїи твое́мъ, ꙗ҆́коже повелѣ̀ мѡѷсе́й, во свидѣ́тельство и҆̀мъ. прохожда́ше же па́че сло́во ѡ҆ не́мъ: и҆ схожда́хꙋсѧ наро́ди мно́зи слы́шати, и҆ цѣли́тисѧ ѿ негѡ̀ ѿ недꙋ̑гъ свои́хъ. то́йже бѣ̀ ѿходѧ̀ въ пꙋсты́ню, и҆ молѧ́сѧ. ",
}

add_evangelie_luki {
  ["номер"] = 19,
  ["комментарий"] = "Лк., 19 зач., V, 17–26.",
  ["текст_ру"] = "Во вре́мя о́но, бе учя́ Иису́с, и бе́ху седя́ще фарисе́е и законоучи́телие, и́же бе́ху пришли́ от вся́кия ве́си Галиле́йския и Иуде́йския и Иерусали́мския, и си́ла Госпо́дня бе изцеля́ющи их. И се му́жие нося́ще на одре́ челове́ка, и́же бе разсла́блен, и иска́ху внести́ его́ и положи́ти пред Ним. И не обре́тше куде́ внести́ его́ наро́да ра́ди, взле́зше на храм, сквозе́ скуде́лы низве́сиша его́ со одро́м на среду́ пред Иису́са. И ви́дев ве́ру их, рече́ ему́: челове́че, оставля́ют ти ся греси́ твои́. И нача́ша помышля́ти кни́жницы и фарисе́е, глаго́люще: кто есть сей, и́же глаго́лет хулы́? Кто мо́жет оставля́ти грехи́, то́кмо еди́н Бог? Разуме́в же Иису́с помышле́ния их, отвеща́в рече́ к ним: что помышля́ете в сердца́х ва́ших? Что есть удо́бее рещи́: оставля́ют ти ся греси́ твои́? Или́ рещи́: воста́ни и ходи́? Но да уве́сте, я́ко власть и́мать Сын Челове́ческий на земли́ отпуща́ти грехи́, рече́ разсла́бленному: тебе́ глаго́лю, воста́ни, и возми́ одр твой, и иди́ в дом твой. И а́бие воста́в пред ни́ми, взем, на не́мже лежа́ше, и́де в дом свой, сла́вя Бо́га. И у́жас прия́т вся, и сла́вляху Бо́га, и испо́лнишася стра́ха, глаго́люще, я́ко ви́дехом пресла́вная днесь. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бѣ̀ ᲂу҆чѧ̀ і҆и҃съ и҆ бѣ́хꙋ сѣдѧ́ще фарїсе́є и҆ законоꙋчи́телїе, и҆̀же бѣ́хꙋ пришлѝ ѿ всѧ́кїѧ ве́си галїле́йскїѧ, и҆ і҆ꙋде́йскїѧ, и҆ і҆ерꙋсали́мскїѧ: и҆ си́ла гдⷭ҇нѧ бѣ̀ и҆сцѣлѧ́ющи и҆̀хъ. и҆ сѐ мꙋ́жїе носѧ́ще на ѻ҆дрѣ̀ человѣ́ка, и҆́же бѣ̀ разсла́бленъ: и҆ и҆ска́хꙋ внестѝ є҆го̀, и҆ положи́ти пред̾ ни́мъ. и҆ не ѡ҆брѣ́тше кꙋдѣ̀ внестѝ є҆го̀, наро́да ра́ди, взлѣ́зше на хра́мъ, сквозѣ̀ скꙋде́лы низвѣ́сиша є҆го̀ со ѻ҆дро́мъ на средꙋ̀ пред̾ і҆и҃са. и҆ ви́дѣвъ вѣ́рꙋ и҆́хъ, речѐ є҆мꙋ̀: человѣ́че, ѡ҆ставлѧ́ютъ ти сѧ грѣсѝ твоѝ. и҆ нача́ша помышлѧ́ти кни́жницы и҆ фарїсе́є, глаго́люще: кто́ є҆сть се́й, и҆́же глаго́летъ хꙋлы̑; кто̀ мо́жетъ ѡ҆ставлѧ́ти грѣхѝ, то́кмѡ є҆ди́нъ бг҃ъ; разꙋмѣ́въ же і҆и҃съ помышлє́нїѧ и҆́хъ, ѿвѣща́въ речѐ къ ни́мъ: что̀ помышлѧ́ете въ сердца́хъ ва́шихъ; что́ є҆сть ᲂу҆до́бѣе рещѝ: ѡ҆ставлѧ́ютъ ти сѧ грѣсѝ твоѝ; и҆лѝ рещѝ: воста́ни и҆ ходѝ; но да ᲂу҆вѣ́сте, ꙗ҆́кѡ вла́сть и҆́мать сн҃ъ человѣ́ческїй на землѝ ѿпꙋща́ти грѣхѝ, речѐ разсла́бленномꙋ: тебѣ̀ глаго́лю, воста́ни и҆ воз̾мѝ ѻ҆́дръ тво́й, и҆ и҆дѝ въ до́мъ тво́й. и҆ а҆́бїе воста́въ пред̾ ни́ми, взе́мъ на не́мже лежа́ше, и҆́де въ до́мъ сво́й, сла́вѧ бг҃а. и҆ ᲂу҆́жасъ прїѧ́тъ всѧ̑, и҆ сла́влѧхꙋ бг҃а, и҆ и҆спо́лнишасѧ стра́ха, глаго́люще: ꙗ҆́кѡ ви́дѣхомъ пресла̑внаѧ дне́сь. ",
}

add_evangelie_luki {
  ["номер"] = 20,
  ["комментарий"] = "Лк., 20 зач., V, 27–32.",
  ["текст_ру"] = "Во вре́мя о́но, преходя́ Иису́с узре́ мытаря́ и́менем Леви́ю, седя́ща на мы́тнице, и рече́ ему́: иди́ по Мне. И оста́вль вся, воста́в в след Его́ и́де. И сотвори́ чрежде́ние ве́лие Леви́й Ему́ в дому́ свое́м, и бе наро́д мытаре́й мног, и ине́х, и́же бя́ху с ним возлежа́ще. И ропта́ху кни́жницы на Него́ и фарисе́е, ко ученико́м Его́ глаго́люще: почто́ с мытари́ и гре́шники я́сте и пие́те? И отвеща́в Иису́с рече́ к ним: не тре́буют здра́вии врача́, но боля́щии. Не приидо́х призва́ти пра́ведных, но гре́шныя в покая́ние. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, преходѧ̀ і҆и҃съ, ᲂу҆зрѣ̀ мытарѧ̀, и҆́менемъ леѵі́ю, сѣдѧ́ща на мы́тницѣ, и҆ речѐ є҆мꙋ̀ и҆дѝ по мнѣ̀. и҆ ѡ҆ста́вль всѧ̑, воста́въ во слѣ́дъ є҆гѡ̀ и҆́де. и҆ сотворѝ чрежде́нїе ве́лїе леѵі́й є҆мꙋ̀ въ домꙋ̀ свое́мъ, и҆ бѣ̀ наро́дъ мытаре́й мно́гъ, и҆ и҆нѣ́хъ, и҆̀же бѧ́хꙋ съ ни́мъ возлежа́ще. и҆ ропта́хꙋ кни́жницы на него̀ и҆ фарїсе́є, ко ᲂу҆ч҃нкѡ́мъ є҆гѡ̀ глаго́люще: почто̀ съ мытарѝ и҆ грѣ́шники ꙗ҆́сте и҆ пїе́те; и҆ ѿвѣща́въ і҆и҃съ речѐ къ ни́мъ: не тре́бꙋютъ здра́вїи врача̀, но болѧ́щїи. не прїидо́хъ призва́ти пра́ведныхъ, но грѣ̑шныѧ въ покаѧ́нїе. ",
}

add_evangelie_luki {
  ["номер"] = 21,
  ["комментарий"] = "Лк., 21 зач., V, 33–39.",
  ["текст_ру"] = "Во вре́мя о́но, приступи́ша фарисе́и ко Иису́су, глаго́люще: почто́ ученицы́ Иоа́нновы постя́тся ча́сто и моли́твы творя́т, та́кожде и фарисе́йстии, а Твои́ ядя́т и пию́т? Он же рече́ к ним: еда́ мо́жете сы́ны бра́чныя, до́ндеже жени́х с ни́ми есть, сотвори́ти пости́тися? Прии́дут же дни́е, егда́ отя́т бу́дет от них жени́х, и тогда́ постя́тся в ты́я дни. Глаго́лаше же и при́тчу к ним, я́ко никто́же приставле́ния ри́зы но́вы приставля́ет на ри́зу ве́тху, а́ще ли же ни, и но́вую раздере́т, и ве́тсей не согласу́ет е́же от но́ваго. И никто́же влива́ет вина́ но́ва в ме́хи ве́тхи, а́ще ли же ни, расто́ргнет но́вое вино́ ме́хи, и са́мо излие́тся, и ме́си поги́бнут, но вино́ но́вое в ме́хи но́вы влива́ти, и обое́ соблюде́тся. И никто́же пив ве́тхое, а́бие хо́щет но́вому, глаго́лет бо: ве́тхое лу́чше есть. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋпи́ша фарїсе́и ко і҆и҃сꙋ, глаго́люще: почто̀ ᲂу҆ченицы̀ і҆ѡа́нновы постѧ́тсѧ ча́стѡ, и҆ моли̑твы творѧ́тъ, та́кожде и҆ фарїсе́йстїи, а҆ твоѝ ꙗ҆дѧ́тъ и҆ пїю́тъ; ѻ҆́нъ же речѐ къ ни́мъ: є҆да̀ мо́жете сы́ны бра́чныѧ, до́ндеже жени́хъ съ ни́ми є҆́сть, сотвори́ти пости́тисѧ; прїи́дꙋтъ же дні́е, є҆гда̀ ѿѧ́тъ бꙋ́детъ ѿ ни́хъ жени́хъ, и҆ тогда̀ постѧ́тсѧ въ ты́ѧ днѝ. глаго́лаше же и҆ при́тчꙋ къ ни́мъ: ꙗ҆́кѡ никто́же приставле́нїѧ ри́зы но́вы приставлѧ́етъ на ри́зꙋ ве́тхꙋ: а҆́ще ли же нѝ, и҆ но́вꙋю раздере́тъ, и҆ ве́тсѣй не согласꙋ́етъ є҆́же ѿ но́вагѡ. и҆ никто́же влива́етъ вїна̀ но́ва въ мѣ́хи ве́тхи: а҆́ще ли же нѝ, расто́ргнетъ но́вое вїно̀ мѣ́хи, и҆ са́мо и҆злїе́тсѧ, и҆ мѣ́си поги́бнꙋтъ. но вїно̀ но́вое въ мѣ́хи но́вы влива́ти, и҆ ѻ҆боѐ соблюде́тсѧ. и҆ никто́же пи́въ ве́тхое, а҆́бїе хо́щетъ но́вомꙋ: глаго́летъ бо, ве́тхое лꙋ́чше є҆́сть. ",
}

add_evangelie_luki {
  ["номер"] = 22,
  ["комментарий"] = "Лк., 22 зач., VI, 1–10.",
  ["текст_ру"] = "Во вре́мя о́но, хожда́ше Иису́с в суббо́ту сквозе́ се́яния, и восторга́ху ученицы́ Его́ кла́сы, и ядя́ху, стира́юще рука́ми. Не́цыи же от фарисе́й ре́ша им: что твори́те, его́же не досто́ит твори́ти в суббо́ты? И отвеща́в Иису́с рече́ к ним: ни ли сего́ чли есте́, е́же сотвори́ Дави́д, егда́ взалка́ся сам и и́же с ним су́щии? Ка́ко вни́де в дом Бо́жий, и хле́бы предложе́ния взем, и яде́, и даде́ и су́щым с ним, и́хже не досто́яше я́сти, то́кмо еди́нем иере́ем? И глаго́лаше им, я́ко госпо́дь есть Сын Челове́ческий и суббо́те. Бысть же и в другу́ю суббо́ту вни́ти Ему́ в со́нмище и учи́ти, и бе та́мо челове́к, и рука́ ему́ десна́я бе суха́. Назира́ху же кни́жницы и фарисе́и, а́ще в суббо́ту исцели́т, да обря́щут речь Нань. Он же ве́дяше помышле́ния их и рече́ челове́ку иму́щему су́ху ру́ку: воста́ни и ста́ни посреде́. Он же воста́в ста. Рече́ же Иису́с к ним: вопрошу́ вы, что досто́ит в суббо́ты, добро́ твори́ти, или́ зло твори́ти? Ду́шу спасти́, или́ погуби́ти? Они́ же умолча́ша. И воззре́в на вся их, рече́ ему́: простри́ ру́ку твою́. Он же сотвори́ та́ко, и утверди́ся рука́ его́ здра́ва я́ко друга́я. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, хожда́ше і҆и҃съ въ сꙋббѡ́тꙋ сквозѣ̀ сѣ̑ѧнїѧ: и҆ восторга́хꙋ ᲂу҆чн҃цы̀ є҆гѡ̀ кла́сы, и҆ ꙗ҆дѧ́хꙋ, стира́юще рꙋка́ми. нѣ́цыи же ѿ фарїсє́й рѣ́ша и҆̀мъ: что̀ творитѐ, є҆гѡ́же не досто́итъ твори́ти въ сꙋббѡ́ты; и҆ ѿвѣща́въ і҆и҃съ речѐ къ ни́мъ: ни лѝ сегѡ̀ члѝ є҆стѐ, є҆́же сотворѝ дв҃дъ, є҆гда̀ взалка́сѧ са́мъ, и҆ и҆̀же съ ни́мъ сꙋ́щїи; ка́кѡ вни́де въ до́мъ бж҃їй, и҆ хлѣ́бы предложе́нїѧ взе́мъ, и҆ ꙗ҆дѐ, и҆ дадѐ и҆ сꙋ́щымъ съ ни́мъ, и҆́хже не досто́ѧше ꙗ҆́сти, то́кмѡ є҆ди́нѣмъ і҆ере́ємъ; и҆ глаго́лаше и҆̀мъ: ꙗ҆́кѡ гдⷭ҇ь є҆́сть сн҃ъ чл҃вѣ́ческїй и҆ сꙋббѡ́тѣ. бы́сть же и҆ въ дрꙋгꙋ́ю сꙋббѡ́тꙋ вни́ти є҆мꙋ̀ въ со́нмище, и҆ ᲂу҆чи́ти: и҆ бѣ̀ та́мѡ человѣ́къ, и҆ рꙋка̀ є҆мꙋ̀ десна́ѧ бѣ̀ сꙋха̀. назира́хꙋ же кни́жницы и҆ фарїсе́и, а҆́ще въ сꙋббѡ́тꙋ и҆сцѣли́тъ, да ѡ҆брѧ́щꙋтъ рѣ́чь на́нь. ѻ҆́нъ же вѣ́дѧше помышлє́нїѧ и҆́хъ, и҆ речѐ человѣ́кꙋ и҆мꙋ́щемꙋ сꙋ́хꙋ рꙋ́кꙋ: воста́ни, и҆ ста́ни посредѣ̀. ѻ҆́нъ же воста́въ, ста̀. рече́ же і҆и҃съ къ ни́мъ: вопрошꙋ̀ вы̀, что̀ досто́итъ въ сꙋббѡ́ты, добро̀ твори́ти, и҆лѝ ѕло̀ твори́ти; дꙋ́шꙋ спастѝ, и҆лѝ погꙋби́ти; ѻ҆ни́ же ᲂу҆молча́ша. и҆ воззрѣ́въ на всѧ̑ и҆̀хъ, речѐ є҆мꙋ̀: прострѝ рꙋ́кꙋ твою̀. ѻ҆́нъ же сотворѝ та́кѡ: и҆ ᲂу҆тверди́сѧ рꙋка̀ є҆гѡ̀ здра́ва ꙗ҆́кѡ дрꙋга́ѧ. ",
}

add_evangelie_luki {
  ["номер"] = 23,
  ["комментарий"] = "Лк., 23 зач., VI, 12–19.",
  ["текст_ру"] = "Во вре́мя о́но, изы́де Иису́с в го́ру помоли́тися, и бе обно́щь в моли́тве Бо́жии. И егда́ бысть день, призва́ ученики́ Своя́, и избра́ от них двана́десяте, и́хже и Апо́столы нарече́: Си́мона, его́же именова́ Петра́, и Андре́а бра́та его́, Иа́кова и Иоа́нна, Фили́ппа и Варфоломе́а, Матфе́а и Фому́, Иа́кова Алфе́ева и Си́мона нарица́емаго Зило́та, Иу́ду Иа́ковля, и Иу́ду Искарио́тскаго, и́же и бысть преда́тель. Изше́д с ни́ми, ста на ме́сте ра́вне, и наро́д учени́к Его́, и мно́жество мно́го люде́й от всея́ Иуде́и и Иерусали́ма, и помо́рия Ти́рска и Сидо́нска, и́же приидо́ша послу́шати Его́ и исцели́тися от неду́г свои́х, и стра́ждущии от дух нечи́стых, и исцеля́хуся. И весь наро́д иска́ше прикаса́тися Ему́, я́ко си́ла от Него́ исхожда́ше и исцеля́ше вся. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆зы́де і҆и҃съ въ го́рꙋ помоли́тисѧ, и҆ бѣ̀ ѡ҆бно́щь въ моли́твѣ бж҃їи. и҆ є҆гда̀ бы́сть де́нь, призва̀ ᲂу҆ченикѝ своѧ̑, и҆ и҆збра̀ ѿ ни́хъ двана́десѧте, и҆̀хже и҆ а҆пⷭ҇лы наречѐ: сі́мѡна, є҆го́же и҆менова̀ петра̀, и҆ а҆ндре́а бра́та є҆гѡ̀: і҆а́кѡва и҆ і҆ѡа́нна: фїлі́ппа и҆ варѳоломе́а: матѳе́а и҆ ѳѡмꙋ̀: і҆а́кѡва а҆лфе́ева и҆ сі́мѡна нарица́емаго зилѡ́та: і҆ꙋ́дꙋ і҆а́кѡвлѧ, и҆ і҆ꙋ́дꙋ і҆скарїѡ́тскаго, и҆́же и҆ бы́сть преда́тель. и҆зше́дъ съ ни́ми, ста̀ на мѣ́стѣ ра́внѣ, и҆ наро́дъ ᲂу҆чєни́къ є҆гѡ̀, и҆ мно́жество мно́го люде́й ѿ всеѧ̀ і҆ꙋде́и, и҆ і҆ерꙋсали́ма, и҆ помо́рїѧ тѵ́рска и҆ сїдѡ́нска: и҆̀же прїидо́ша послꙋ́шати є҆гѡ̀, и҆ и҆сцѣли́тисѧ ѿ недꙋ̑гъ свои́хъ, и҆ стра́ждꙋщїи ѿ дꙋ̑хъ нечи́стыхъ, и҆ и҆сцѣлѧ́хꙋсѧ. и҆ ве́сь наро́дъ и҆ска́ше прикаса́тисѧ є҆мꙋ̀: ꙗ҆́кѡ си́ла ѿ негѡ̀ и҆схожда́ше, и҆ и҆сцѣлѧ́ше всѧ̑. ",
}

add_evangelie_luki {
  ["номер"] = 24,
  ["комментарий"] = "Лк., 24 зач., VI, 17–23.",
  ["текст_ру"] = "Во вре́мя о́но, ста Иису́с на ме́сте ра́вне, и наро́д учени́к Его́, и мно́жество мно́го люде́й от всея́ Иуде́и и Иерусали́ма, и помо́рия Ти́рска и Сидо́нска, и́же приидо́ша послу́шати Его́ и исцели́тися от неду́г свои́х, и стра́ждущии от дух нечи́стых, и исцеля́хуся. И весь наро́д иска́ше прикаса́тися Ему́, я́ко си́ла от Него́ исхожда́ше, и исцеля́ше вся. И той возве́д о́чи свои́ на ученики́ своя́, глаго́лаше: блаже́ни ни́щии ду́хом, я́ко ва́ше есть Ца́рствие Бо́жие. Блаже́ни, а́лчущии ны́не, я́ко насы́титеся. Блаже́ни, пла́чущии ны́не, я́ко возсмее́теся. Блаже́ни бу́дете, егда́ возненави́дят вас челове́цы, и егда́ разлуча́т вы и поно́сят, и пронесу́т и́мя ва́ше я́ко зло, Сы́на Челове́ческаго ра́ди. Возра́дуйтеся в той день и взыгра́йте, се бо мзда ва́ша мно́га на небеси́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ста̀ і҆и҃съ на мѣ́стѣ ра́внѣ, и҆ наро́дъ ᲂу҆чєни́къ є҆гѡ̀, и҆ мно́жество мно́го люде́й ѿ всеѧ̀ і҆ꙋде́и, и҆ і҆ерꙋсали́ма, и҆ помо́рїѧ тѵ́рска и҆ сїдѡ́нска: и҆̀же прїидо́ша послꙋ́шати є҆гѡ̀, и҆ и҆сцѣли́тисѧ ѿ недꙋ̑гъ свои́хъ, и҆ стра́ждꙋщїи ѿ дꙋ̑хъ нечи́стыхъ, и҆ и҆сцѣлѧ́хꙋсѧ. и҆ ве́сь наро́дъ и҆ска́ше прикаса́тисѧ є҆мꙋ̀: ꙗ҆́кѡ си́ла ѿ негѡ̀ и҆схожда́ше, и҆ и҆сцѣлѧ́ше всѧ̑. и҆ то́й возве́дъ ѻ҆́чи своѝ на ᲂу҆ченикѝ своѧ̀, глаго́лаше: блаже́ни ни́щїи дх҃омъ, ꙗ҆́кѡ ва́ше є҆́сть црⷭ҇твїе бж҃їе. блаже́ни а҆́лчꙋщїи ны́нѣ, ꙗ҆́кѡ насы́титесѧ. блаже́ни пла́чꙋщїи ны́нѣ, ꙗ҆́кѡ возсмѣе́тесѧ. блаже́ни бꙋ́дете, є҆гда̀ возненави́дѧтъ ва́съ человѣ́цы, и҆ є҆гда̀ разлꙋча́тъ вы̀, и҆ поно́сѧтъ, и҆ пронесꙋ́тъ и҆́мѧ ва́ше ꙗ҆́кѡ ѕло̀, сн҃а человѣ́ческагѡ ра́ди. возра́дꙋйтесѧ въ то́й де́нь и҆ взыгра́йте: се́ бо мзда̀ ва́ша мно́га на небесѝ. ",
}

add_evangelie_luki {
  ["номер"] = 25,
  ["комментарий"] = "Лк., 25 зач., VI, 24–30.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: го́ре вам бога́тым, я́ко отстоите́ утеше́ния ва́шего. Го́ре вам, насыще́ннии ны́не, я́ко вза́лчете. Го́ре вам смею́щымся ны́не, я́ко возрыда́ете и воспла́чете. Го́ре, егда́ до́бре реку́т вам вси челове́цы. По сим бо творя́ху лжепроро́ком отцы́ их. Но вам глаго́лю слы́шащым: люби́те враги́ ва́ша, добро́ твори́те ненави́дящым вас, благослови́те клену́щыя вы, и моли́теся за творя́щих вам оби́ду. Бию́щему тя в лани́ту, пода́ждь и другу́ю, и от взима́ющаго ти ри́зу, и срачи́цу не возбрани́. Вся́кому же прося́щему у тебе́ дай, и от взима́ющаго твоя́ не истязу́й. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: го́ре ва́мъ бога̑тымъ, ꙗ҆́кѡ ѿстоитѐ ᲂу҆тѣше́нїѧ ва́шегѡ. го́ре ва́мъ насыще́ннїи ны́нѣ, ꙗ҆́кѡ вза́лчете: го́ре ва́мъ смѣю́щымсѧ ны́нѣ, ꙗ҆́кѡ возрыда́ете и҆ воспла́чете. го́ре, є҆гда̀ до́брѣ рекꙋ́тъ ва́мъ всѝ человѣ́цы: по си̑мъ бо творѧ́хꙋ лжепроро́кѡмъ ѻ҆тцы̀ и҆́хъ. но ва́мъ глаго́лю слы́шащымъ: люби́те врагѝ ва́шѧ, добро̀ твори́те ненави́дѧщымъ ва́съ: благослови́те кленꙋ́щыѧ вы̀, и҆ моли́тесѧ за творѧ́щихъ ва́мъ ѻ҆би́дꙋ. бїю́щемꙋ тѧ̀ въ лани́тꙋ, пода́ждь и҆ дрꙋгꙋ́ю: и҆ ѿ взима́ющагѡ тѝ ри́зꙋ, и҆ срачи́цꙋ не возбранѝ. всѧ́комꙋ же просѧ́щемꙋ ᲂу҆ тебѐ да́й, и҆ ѿ взима́ющагѡ твоѧ̑ не и҆стѧзꙋ́й. ",
}

add_evangelie_luki {
  ["номер"] = 26,
  ["комментарий"] = "Лк., 26 зач., VI, 31–36.",
  ["текст_ру"] = "Рече́ Госпо́дь: я́коже хо́щете да творя́т вам челове́цы, и вы твори́те им та́кожде. И а́ще лю́бите лю́бящыя вы, ка́я вам благода́ть есть? И́бо и гре́шницы лю́бящыя их лю́бят. И а́ще благотворите́ благотворя́щым вам, ка́я вам благода́ть есть? И́бо и гре́шницы то́жде творя́т. И а́ще взаи́м даете́, от ни́хже ча́ете восприя́ти, ка́я вам благода́ть есть, и́бо и гре́шницы гре́шником взаи́м дава́ют, да восприи́мут ра́вная. Оба́че люби́те враги́ ва́ша, и благотвори́те, и взаи́м да́йте, ничесо́же ча́юще, и бу́дет мзда ва́ша мно́га, и бу́дете сы́нове Вы́шняго, я́ко Той благ есть на безблагода́тныя и злы́я. Бу́дите у́бо милосе́рди, я́коже и Оте́ц ваш милосе́рд есть. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: ꙗ҆́коже хо́щете да творѧ́тъ ва́мъ человѣ́цы, и҆ вы̀ твори́те и҆̀мъ та́кожде. и҆ а҆́ще лю́бите лю́бѧщыѧ вы̀, ка́ѧ ва́мъ благода́ть є҆́сть; и҆́бо и҆ грѣ́шницы лю́бѧщыѧ и҆́хъ лю́бѧтъ. и҆ а҆́ще благотворитѐ благотворѧ́щымъ ва́мъ, ка́ѧ ва́мъ благода́ть є҆́сть; и҆́бо и҆ грѣ́шницы то́жде творѧ́тъ. и҆ а҆́ще взаи́мъ даетѐ, ѿ ни́хже ча́ете воспрїѧ́ти, ка́ѧ ва́мъ благода́ть є҆́сть; и҆́бо и҆ грѣ́шницы грѣ́шникѡмъ взаи́мъ дава́ютъ, да воспрїи́мꙋтъ ра̑внаѧ. ѻ҆ба́че люби́те врагѝ ва́шѧ, и҆ благотвори́те, и҆ взаи́мъ да́йте, ничесѡ́же ча́юще. и҆ бꙋ́детъ мзда̀ ва́ша мно́га, и҆ бꙋ́дете сы́нове вы́шнѧгѡ: ꙗ҆́кѡ то́й бл҃гъ є҆́сть на безблагода̑тныѧ и҆ ѕлы̑ѧ. бꙋ́дите ᲂу҆́бѡ милосе́рди, ꙗ҆́коже и҆ ѻ҆ц҃ъ ва́шъ милосе́рдъ є҆́сть. ",
}

add_evangelie_luki {
  ["номер"] = 27,
  ["комментарий"] = "Лк., 27 зач., VI, 37–45.",
  ["текст_ру"] = "Рече́ Госпо́дь: не суди́те, и не су́дят вам, и не осужда́йте, да не осужде́ни бу́дете, отпуща́йте, и отпу́стят вам. Да́йте, и да́стся вам, ме́ру добру́, натка́ну и потря́сну и прелива́ющуся дадя́т на ло́но ва́ше, то́ю бо ме́рою, е́юже ме́рите, возме́рится вам. Рече́ же при́тчу им: еда́ мо́жет слепе́ц слепца́ води́ти? Не о́ба ли в я́му впаде́тася? Несть учени́к над учи́телем свои́м, соверше́н же всяк бу́дет, я́коже и учи́тель его́. Что же ви́диши суче́ц, и́же есть во очеси́ бра́та твоего́, бервна́ же, е́же есть во очеси́ твое́м, не чу́еши? Или́ ка́ко мо́жеши рещи́ бра́ту твоему́: бра́те, оста́ви, да изму́ суче́ц, и́же есть во очеси́ твое́м, сам су́щаго во очеси́ твое́м бервна́ не ви́дя? Лицеме́ре, изми́ пе́рвее бервно́ из очесе́ твоего́, и тогда́ про́зриши изъя́ти суче́ц из очесе́ бра́та твоего́. Несть бо дре́во добро́, творя́ плода́ зла, ниже́ дре́во зло, творя́ плода́ добра́. Вся́ко бо дре́во от плода́ своего́ позна́ется, не от те́рния бо че́шут смо́квы, ни от купины́ е́млют гро́здия. Благи́й челове́к от блага́го сокро́вища се́рдца своего́ изно́сит благо́е, и злый челове́к от зла́го сокро́вища се́рдца своего́ изно́сит зло́е, от избы́тка бо се́рдца глаго́лют уста́ его́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: не сꙋди́те и҆ не сꙋ́дѧтъ ва́мъ: и҆ не ѡ҆сꙋжда́йте, да не ѡ҆сꙋжде́ни бꙋ́дете: ѿпꙋща́йте, и҆ ѿпꙋ́стѧтъ ва́мъ. да́йте, и҆ да́стсѧ ва́мъ: мѣ́рꙋ добрꙋ̀, натка́нꙋ, и҆ потрѧ́снꙋ, и҆ прелива́ющꙋсѧ дадѧ́тъ на ло́но ва́ше: то́ю бо мѣ́рою, є҆́юже мѣ́рите, возмѣ́ритсѧ ва́мъ. рече́ же при́тчꙋ и҆̀мъ: є҆да̀ мо́жетъ слѣпе́цъ слѣпца̀ води́ти; не ѻ҆́ба ли въ ꙗ҆́мꙋ впаде́тасѧ; нѣ́сть ᲂу҆чени́къ над̾ ᲂу҆чи́телемъ свои́мъ: соверше́нъ же всѧ́къ бꙋ́детъ ꙗ҆́коже и҆ ᲂу҆чи́тель є҆гѡ̀. что́ же ви́диши сꙋче́цъ, и҆́же є҆́сть во ѻ҆чесѝ бра́та твоегѡ̀: бервна́ же, є҆́же є҆́сть во ѻ҆чесѝ твое́мъ, не чꙋ́еши; и҆лѝ ка́кѡ мо́жеши рещѝ бра́тꙋ твоемꙋ̀: бра́те, ѡ҆ста́ви, да и҆змꙋ̀ сꙋче́цъ, и҆́же є҆́сть во ѻ҆чесѝ твое́мъ, са́мъ сꙋ́щагѡ во ѻ҆чесѝ твое́мъ бервна̀ не ви́дѧ; лицемѣ́ре, и҆змѝ пе́рвѣе бервно̀ и҆з̾ ѻ҆чесѐ твоегѡ̀, и҆ тогда̀ про́зриши и҆з̾ѧ́ти сꙋче́цъ и҆з̾ ѻ҆чесѐ бра́та твоегѡ̀. нѣ́сть бо дре́во добро̀, творѧ̀ плода̀ ѕла̀: нижѐ дре́во ѕло̀, творѧ̀ плода̀ добра̀. всѧ́ко бо дре́во ѿ плода̀ своегѡ̀ позна́етсѧ: не ѿ те́рнїѧ бо че́шꙋтъ смѡ́квы, ни ѿ кꙋпины̀ є҆́млютъ грѡ́здїѧ. благі́й человѣ́къ ѿ блага́гѡ сокро́вища се́рдца своегѡ̀ и҆зно́ситъ благо́е: и҆ ѕлы́й человѣ́къ ѿ ѕла́гѡ сокро́вища се́рдца своегѡ̀ и҆зно́ситъ ѕло́е: ѿ и҆збы́тка бо се́рдца глаго́лютъ ᲂу҆ста̀ є҆гѡ̀. ",
}

add_evangelie_luki {
  ["номер"] = 28,
  ["комментарий"] = "Лк., 28 зач., VI, 46 – VII, 1.",
  ["текст_ру"] = "Рече́ Госпо́дь: что Мя зовете́, Го́споди, Го́споди, и не твори́те, я́же глаго́лю? Всяк гряды́й ко Мне и слы́шай словеса́ Моя́ и творя́ я́, скажу́ вам, кому́ есть подо́бен. Подо́бен есть челове́ку зи́ждущу хра́мину, и́же ископа́ и углуби́, и положи́ основа́ние на ка́мени, наводне́нию же бы́вшу, припаде́ река́ к хра́мине той, и не мо́же поколеба́ти ея́, основана́ бо бе на ка́мени. Слы́шавый же и не сотвори́вый подо́бен есть челове́ку созда́вшему хра́мину на земли́ без основа́ния, е́йже припаде́ река́, и а́бие паде́ся, и бысть разруше́ние хра́мины тоя́ ве́лие. Егда́ же сконча́ вся глаго́лы Своя́ в слу́хи лю́дем, вни́де в Капернау́м. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: что́ мѧ зоветѐ: гдⷭ҇и, гдⷭ҇и, и҆ не творитѐ, ꙗ҆̀же глаго́лю; всѧ́къ грѧды́й ко мнѣ̀, и҆ слы́шай словеса̀ моѧ̀, и҆ творѧ̀ ѧ҆̀, скажꙋ̀ ва́мъ, комꙋ̀ є҆́сть подо́бенъ. подо́бенъ: є҆́сть человѣ́кꙋ зи́ждꙋщꙋ хра́минꙋ, и҆́же и҆скопа̀, и҆ ᲂу҆глꙋбѝ, и҆ положѝ ѡ҆снова́нїе на ка́мени: наводне́нїю же бы́вшꙋ, припадѐ рѣка̀ къ хра́минѣ то́й, и҆ не мо́же поколеба́ти є҆ѧ̀, ѡ҆снована̀ бо бѣ̀ на ка́мени. слы́шавый же, и҆ не сотвори́вый, подо́бенъ є҆́сть человѣ́кꙋ, созда́вшемꙋ хра́минꙋ на землѝ без̾ ѡ҆снова́нїѧ: є҆́йже припадѐ рѣка̀, и҆ а҆́бїе паде́сѧ, и҆ бы́сть разрꙋше́нїе хра́мины тоѧ̀ ве́лїе. є҆гда́ же сконча̀ всѧ̀ глаго́лы своѧ̀ въ слꙋ́хи лю́демъ, вни́де въ капернаꙋ́мъ. ",
}

add_evangelie_luki {
  ["номер"] = 29,
  ["комментарий"] = "Лк., 29 зач., VII, 1–10.",
  ["текст_ру"] = "Во вре́мя о́но, вни́де Иису́с в Капернау́м. Со́тнику же не́коему раб боля́ зле, хотя́ше умре́ти, и́же бе ему́ че́стен. Слы́шав же о Иису́се посла́ к Нему́ ста́рцы иуде́йския, моля́ Его́, я́ко да прише́д спасе́т раба́ его́. Они́ же прише́дше ко Иису́сови, моля́ху Его́ то́щно, глаго́люще, я́ко досто́ин есть, е́же а́ще да́си ему́, лю́бит бо язы́к наш, и со́нмище той созда́ нам. Иису́с же идя́ше с ни́ми. Еще́ же Ему́ не дале́че су́щу от хра́мины, посла́ к Нему́ со́тник дру́ги, глаго́ля Ему́: Го́споди, не дви́жися, несмь бо досто́ин, да под кров мой вни́деши. Те́мже ни себе́ досто́йна сотвори́х приити́ к Тебе́, но рцы сло́во, и исцеле́ет о́трок мой. И́бо и аз челове́к есмь под влады́кою учине́н, име́я под собо́ю во́ины, и глаго́лю сему́: иди́, и и́дет, и друго́му: прииди́, и прии́дет, и рабу́ моему́: сотвори́ сие́, и сотвори́т. Слы́шав же сия́ Иису́с, чуди́ся ему́, и обра́щься иду́щему по Нем наро́ду рече́: глаго́лю вам, ни во Изра́или толи́ки ве́ры обрето́х. И возвра́щшеся по́сланнии обрето́ша боля́щаго раба́ исцеле́вша. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, вни́де і҆и҃съ въ капернаꙋ́мъ. со́тникꙋ же нѣ́коемꙋ ра́бъ болѧ̀ ѕлѣ̀, хотѧ́ше ᲂу҆мре́ти, и҆́же бѣ̀ є҆мꙋ̀ че́стенъ. слы́шавъ же ѡ҆ і҆и҃сѣ, посла̀ къ немꙋ̀ ста́рцы і҆ꙋде́йскїѧ, молѧ̀ є҆го̀, ꙗ҆́кѡ да прише́дъ спасе́тъ раба̀ є҆гѡ̀. ѻ҆ни́ же прише́дше ко і҆и҃сови, молѧ́хꙋ є҆го̀ то́щнѡ, глаго́люще: ꙗ҆́кѡ досто́инъ є҆́сть, є҆́же а҆́ще да́си є҆мꙋ̀: лю́битъ бо ꙗ҆зы́къ на́шъ, и҆ со́нмище то́й созда̀ на́мъ. і҆и҃съ же и҆дѧ́ше съ ни́ми. є҆ще́ же є҆мꙋ̀ не дале́че сꙋ́щꙋ ѿ хра́мины, посла̀ къ немꙋ̀ со́тникъ дрꙋ́ги, глаго́лѧ є҆мꙋ̀: гдⷭ҇и, не дви́жисѧ: нѣ́смь бо досто́инъ, да под̾ кро́въ мо́й вни́деши. тѣ́мже ни себѐ досто́йна сотвори́хъ прїитѝ къ тебѣ̀: но рцы̀ сло́во, и҆ и҆сцѣлѣ́етъ ѻ҆́трокъ мо́й. и҆́бо и҆ а҆́зъ человѣ́къ є҆́смь под̾ влады́кою ᲂу҆чине́нъ, и҆мѣ́ѧ под̾ собо́ю во́ины, и҆ глаго́лю семꙋ̀: и҆дѝ, и҆ и҆́детъ, и҆ дрꙋго́мꙋ: прїидѝ, и҆ прїи́детъ. и҆ рабꙋ̀ моемꙋ̀: сотворѝ сїѐ, и҆ сотвори́тъ. слы́шавъ же сїѧ̑ і҆и҃съ чꙋди́сѧ є҆мꙋ̀, и҆ ѡ҆бра́щсѧ, и҆дꙋ́щемꙋ по не́мъ наро́дꙋ речѐ: глаго́лю ва́мъ, ни во і҆и҃ли толи́ки вѣ́ры ѡ҆брѣто́хъ. и҆ возвра́щшесѧ по́сланнїи, ѡ҆брѣто́ша болѧ́щаго раба̀ и҆сцѣлѣ́вша. ",
}

add_evangelie_luki {
  ["номер"] = 30,
  ["комментарий"] = "Лк., 30 зач., VII, 11–16.",
  ["текст_ру"] = "Во вре́мя о́но, идя́ше Иису́с во град, нарица́емый Наи́н, и с Ним идя́ху ученицы́ Его́ мно́зи и наро́д мног. Я́коже прибли́жися ко врато́м гра́да, и се изноша́ху уме́рша, сы́на единоро́дна ма́тери свое́й, и та бе вдова́, и наро́д от гра́да мног с не́ю. И ви́дев ю́ Госпо́дь, милосе́рдова о ней, и рече́ ей: не пла́чи. И присту́пль косну́ся во одр, нося́щии же ста́ша. И рече́: ю́ноше, тебе́ глаго́лю, воста́ни. И се́де ме́ртвый, и нача́т глаго́лати, и даде́ его́ ма́тери его́. Прия́т же страх вся, и сла́вляху Бо́га, глаго́люще: я́ко проро́к ве́лий воста́ в нас, и я́ко посети́ Бог люде́й Свои́х. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆дѧ́ше і҆и҃съ во гра́дъ нарица́емый наі́нъ: и҆ съ ни́мъ и҆дѧ́хꙋ ᲂу҆ченицы̀ є҆гѡ̀ мно́зи, и҆ наро́дъ мно́гъ. ꙗ҆́коже прибли́жисѧ ко вратѡ́мъ гра́да, и҆ сѐ и҆зноша́хꙋ ᲂу҆ме́рша сы́на є҆диноро́дна ма́тери свое́й, и҆ та̀ бѣ̀ вдова̀: и҆ наро́дъ ѿ гра́да мно́гъ съ не́ю. и҆ ви́дѣвъ ю҆̀ гдⷭ҇ь, милосе́рдова ѡ҆ не́й, и҆ речѐ є҆́й: не пла́чи. и҆ пристꙋ́пль коснꙋ́сѧ во ѻ҆́дръ, носѧ́щїи же ста́ша. и҆ речѐ: ю҆́ноше, тебѣ̀ глаго́лю, воста́ни. и҆ сѣ́де ме́ртвый, и҆ нача́тъ глаго́лати: и҆ дадѐ є҆го̀ ма́тери є҆гѡ̀. прїѧ́тъ же стра́хъ всѧ̑, и҆ сла́влѧхꙋ бг҃а, глаго́люще: ꙗ҆́кѡ проро́къ ве́лїй воста̀ въ на́съ, и҆ ꙗ҆́кѡ посѣтѝ бг҃ъ люде́й свои́хъ. ",
}

add_evangelie_luki {
  ["номер"] = 31,
  ["комментарий"] = "Лк., 31 зач., VII, 17–30.",
  ["текст_ру"] = "Во вре́мя о́но, изы́де сло́во о Иису́се по всей Иуде́и, и по всей стране́. И возвести́ша Иоа́нну ученицы́ его́ о всех сих. И призва́в два не́кая от учени́к свои́х Иоа́нн, посла́ ко Иису́су, глаго́ля: Ты ли еси́ Гряды́й, или́ ино́го ча́ем? Прише́дша же к Нему́ му́жа, ре́ста: Иоа́нн Крести́тель посла́ нас к Тебе́, глаго́ля: Ты ли еси́ Гряды́й, или́ ино́го ча́ем, в Той же час исцели́ мно́ги от неду́г и ран и дух злых и мно́гим слепы́м дарова́ прозре́ние. И отвеща́в Иису́с рече́ и́ма: ше́дша возвести́та Иоа́нну, я́же ви́деста и слы́шаста, я́ко слепи́и прозира́ют, хро́мии хо́дят, прокаже́ннии очища́ются, глуси́и слы́шат, ме́ртвии востаю́т, ни́щии благовеству́ют. И блаже́н есть, и́же а́ще не соблазни́тся о Мне. Отше́дшема же ученико́ма Иоа́нновома, нача́т глаго́лати к наро́дом о Иоа́нне: чесо́ изыдо́сте в пусты́ню ви́дети, трость ли ве́тром коле́блемь? Но чесо́ изыдо́сте ви́дети? Челове́ка ли в мя́кки ри́зы оде́яна? Се, и́же во оде́жди сла́вней и пи́щи су́щии, во ца́рствии суть. Но чесо́ изыдо́сте ви́дети? Проро́ка ли? Ей, глаго́лю вам, и ли́шше проро́ка. Сей бо есть, о не́мже пи́сано есть: се Аз послю́ А́нгела Моего́ пред лице́м Твои́м, и́же устро́ит путь Твой пред Тобо́ю. Глаго́лю бо вам: бо́лий в рожде́нных жена́ми проро́к Иоа́нна Крести́теля никто́же есть, мний же во Ца́рствии Бо́жии бо́лий его́ есть. И вси лю́дие слы́шавше и мытари́е оправди́ша Бо́га, кре́щшеся креще́нием Иоа́нновым. Фарисе́е же и зако́нницы сове́т Бо́жий отверго́ша в себе́, не кре́щшеся от него́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆зы́де сло́во ѡ҆ і҆и҃сѣ по все́й і҆ꙋде́и, и҆ по все́й странѣ̀. и҆ возвѣсти́ша і҆ѡа́ннꙋ ᲂу҆ченицы̀ є҆гѡ̀ ѡ҆ всѣ́хъ си́хъ. и҆ призва́въ два̀ нѣ́каѧ ѿ ᲂу҆чєни́къ свои́хъ і҆ѡа́ннъ, посла̀ ко і҆и҃сꙋ, глаго́лѧ: ты́ ли є҆сѝ грѧды́й, и҆лѝ и҆но́гѡ ча́емъ; прише́дша же къ немꙋ̀ мꙋ̑жа, рѣ́ста: і҆ѡа́ннъ крести́тель посла̀ на́съ къ тебѣ̀, глаго́лѧ: ты́ ли є҆сѝ грѧды́й, и҆лѝ и҆но́гѡ ча́емъ; въ то́й же ча́съ и҆сцѣлѝ мнѡ́ги ѿ недꙋ̑гъ, и҆ ра́нъ, и҆ дꙋ̑хъ ѕлы́хъ: и҆ мнѡ́гимъ слѣпы̑мъ дарова̀ прозрѣ́нїе. и҆ ѿвѣща́въ і҆и҃съ речѐ и҆́ма: ше́дша возвѣсти́та і҆ѡа́ннꙋ, ꙗ҆̀же ви́дѣста и҆ слы́шаста: ꙗ҆́кѡ слѣпі́и прозира́ютъ, хро́мїи хо́дѧтъ, прокаже́ннїи ѡ҆чища́ютсѧ, глꙋсі́и слы́шатъ, ме́ртвїи востаю́тъ, ни́щїи благовѣствꙋ́ютъ. и҆ блаже́нъ є҆́сть, и҆́же а҆́ще не соблазни́тсѧ ѡ҆ мнѣ̀. ѿше́дшема же ᲂу҆ченико́ма і҆ѡа́нновома, нача́тъ глаго́лати къ наро́дѡмъ ѡ҆ і҆ѡа́ннѣ: чесѡ̀ и҆зыдо́сте въ пꙋсты́ню ви́дѣти; тро́сть ли вѣ́тромъ коле́блемь; но чесѡ̀ и҆зыдо́сте ви́дѣти; человѣ́ка ли въ мѧ́кки ри̑зы ѡ҆дѣ́ѧна; сѐ и҆́же во ѻ҆де́жди сла́внѣй, и҆ пи́щи сꙋ́щїи, во ца́рствїи сꙋ́ть. но чесѡ̀ и҆зыдо́сте ви́дѣти; проро́ка ли; є҆́й, глаго́лю ва́мъ, и҆ ли́шше проро́ка. се́й бо є҆́сть, ѡ҆ не́мже пи́сано є҆́сть: сѐ а҆́зъ послю̀ а҆́гг҃ла моего̀ пред̾ лице́мъ твои́мъ, и҆́же ᲂу҆стро́итъ пꙋ́ть тво́й пред̾ тобо́ю. глаго́лю бо ва́мъ: бо́лїй въ рожде́нныхъ жена́ми проро́къ і҆ѡа́нна крести́телѧ никто́же є҆́сть: мні́й же, во црⷭ҇твїи бж҃їи бо́лїй є҆гѡ̀ є҆́сть. и҆ всѝ лю́дїе слы́шавше, и҆ мытарі́е ѡ҆правди́ша бг҃а кре́щшесѧ креще́нїемъ і҆ѡа́нновымъ. фарїсе́є же и҆ зако́нницы совѣ́тъ бж҃їй ѿверго́ша въ себѣ̀, не кре́щшесѧ ѿ негѡ̀. ",
}

add_evangelie_luki {
  ["номер"] = 32,
  ["комментарий"] = "Лк., 32 зач., VII, 31–35.",
  ["текст_ру"] = "Рече́ Госпо́дь: кому́ уподо́блю челове́ки ро́да сего́, и кому́ суть подо́бни? Подо́бни суть о́трочищем седя́щым на то́ржищих, и приглаша́ющым друг дру́га, и глаго́лющым: писка́хом вам, и не пляса́сте, рыда́хом вам, и не пла́касте. Прии́де бо Иоа́нн Крести́тель ни хле́ба яды́й, ни вина́ пия́, и глаго́лете: бе́са и́мать. Прии́де Сын Челове́ческий яды́й и пия́, и глаго́лете: сей челове́к я́дца и винопи́йца, друг мытаре́м и гре́шником. И оправди́ся прему́дрость от чад свои́х всех. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: комꙋ̀ ᲂу҆подо́блю человѣ́ки ро́да сегѡ̀, и҆ комꙋ̀ сꙋ́ть подо́бни; подо́бни сꙋ́ть ѻ҆́трочищємъ, сѣдѧ́щымъ на то́ржищахъ, и҆ приглаша́ющымъ дрꙋ́гъ дрꙋ́га, и҆ глаго́лющымъ: писка́хомъ ва́мъ, и҆ не плѧса́сте: рыда́хомъ ва́мъ, и҆ не пла́касте. прїи́де бо і҆ѡа́ннъ крести́тель, ни хлѣ́ба ꙗ҆ды́й, ни вїна̀ пїѧ̀, и҆ глаго́лете: бѣ́съ и҆́мать. прїи́де сн҃ъ человѣ́ческїй, ꙗ҆ды́й и҆ пїѧ̀, и҆ глаго́лете: се́й чл҃вѣ́къ ꙗ҆́дца и҆ вїнопі́йца, дрꙋ́гъ мытарє́мъ и҆ грѣ́шникѡмъ. и҆ ѡ҆правди́сѧ премꙋ́дрость ѿ ча̑дъ свои́хъ всѣ́хъ. ",
}

add_evangelie_luki {
  ["номер"] = 33,
  ["комментарий"] = "Лк., 33 зач., VII, 36–50.",
  ["текст_ру"] = "Во вре́мя о́но, моля́ше Иису́са не́кий от фарисе́й, дабы́ ял с ним, и вшед в дом фарисе́ов, возлеже́. И се жена́ во гра́де, я́же бе гре́шница, и уве́девши, я́ко возлежи́т во хра́мине фарисе́ове, прине́сши алава́стр ми́ра, и ста́вши при ногу́ Его́ созади́, пла́чущися, нача́т умыва́ти но́зе Его́ слеза́ми, и власы́ главы́ своея́ отира́ше, и облобыза́ше но́зе Его́, и ма́заше ми́ром. Ви́дев же фарисе́й возва́вый Его́, рече́ в себе́, глаго́ля: Сей а́ще бы был проро́к, ве́дел бы, кто и какова́ жена́ прикаса́ется Ему́, я́ко гре́шница есть. И отвеща́в Иису́с рече́ к нему́: Си́моне, и́мам ти не́что рещи́. Он же рече́: Учи́телю, рцы. Иису́с же рече́: два должника́ бе́ста заимода́вцу не́коему, еди́н бе до́лжен пятию́сот дина́рий, други́й же пятию́десят. Не иму́щема же и́ма возда́ти, обе́ма отда́. Кото́рый у́бо ею́, рцы, па́че возлю́бит его́? Отвеща́в же Си́мон рече́: мню, я́ко ему́же вя́щше отда́. Он же рече́ ему́: пра́во суди́л еси́. И обра́щься к жене́, Си́монови рече́: ви́диши ли сию́ жену́? Внидо́х в дом твой, воды́ на но́зе Мои́ не даде́, сия́ же слеза́ми облия́ Ми но́зе и власы́ главы́ своея́ отре́. Лобза́ния Ми не даде́, сия́ же, отне́лиже внидо́х, не преста́ облобыза́ющи Ми но́зе. Ма́слом главы́ Моея́ не пома́за, сия́ же ми́ром пома́за Ми но́зе. Его́же ра́ди, глаго́лю ти, отпуща́ются греси́ ея́ мно́зи, я́ко возлюби́ мно́го, а ему́же ма́ло оставля́ется, ме́ньше лю́бит. Рече́ же ей: отпуща́ются тебе́ греси́. И нача́ша возлежа́щии с Ним глаго́лати в себе́: кто Сей есть, и́же и грехи́ отпуща́ет? Рече́ же к жене́: ве́ра твоя́ спасе́ тя, иди́ в ми́ре. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, молѧ́ше і҆и҃са нѣ́кїй ѿ фарїсє́й, дабы̀ ꙗ҆́лъ съ ни́мъ: и҆ вше́дъ въ до́мъ фарїсе́овъ, возлежѐ. и҆ сѐ жена̀ во гра́дѣ, ꙗ҆́же бѣ̀ грѣ́шница, и҆ ᲂу҆вѣ́дѣвши, ꙗ҆́кѡ возлежи́тъ во хра́минѣ фарїсе́овѣ, прине́сши а҆лава́стръ мѵ́ра, и҆ ста́вши при ногꙋ̀ є҆гѡ̀ созадѝ пла́чꙋщисѧ, нача́тъ ᲂу҆мыва́ти но́зѣ є҆гѡ̀ слеза́ми, и҆ власы̀ главы̀ своеѧ̀ ѡ҆тира́ше, и҆ ѡ҆блобыза́ше но́зѣ є҆гѡ̀, и҆ ма́заше мѵ́ромъ. ви́дѣвъ же фарїсе́й возва́вый є҆го̀, речѐ въ себѣ̀, глаго́лѧ: се́й а҆́ще бы бы́лъ проро́къ, вѣ́дѣлъ бы, кто̀ и҆ какова̀ жена̀ прикаса́етсѧ є҆мꙋ̀, ꙗ҆́кѡ грѣ́шница є҆́сть. и҆ ѿвѣща́въ і҆и҃съ речѐ къ немꙋ̀: сі́мѡне, и҆́мамъ тѝ нѣ́что рещѝ. ѻ҆́нъ же речѐ: ᲂу҆чи́телю, рцы̀. і҆и҃съ же речѐ: два̀ должника̀ бѣ́ста заимода́вцꙋ нѣ́коемꙋ, є҆ди́нъ бѣ̀ до́лженъ пѧтїю́сѡтъ дина́рїй, дрꙋгі́й же пѧтїю́десѧть. не и҆мꙋ́щема же и҆́ма возда́ти, ѻ҆бѣ́ма ѿда̀: кото́рый ᲂу҆́бѡ є҆ю̀, рцы̀, па́че возлю́битъ є҆го̀; ѿвѣща́въ же сі́мѡнъ речѐ: мню̀, ꙗ҆́кѡ є҆мꙋ́же вѧ́щше ѿда̀. ѻ҆́нъ же речѐ є҆мꙋ̀: пра́вѡ сꙋди́лъ є҆сѝ. и҆ ѡ҆бра́щсѧ къ женѣ̀, сі́мѡнови речѐ: ви́диши ли сїю̀ женꙋ̀; внидо́хъ въ до́мъ тво́й, воды̀ на но́зѣ моѝ не дадѐ: сїѧ́ же слеза́ми ѡ҆блїѧ́ ми но́зѣ, и҆ власы̀ главы̀ своеѧ̀ ѡ҆трѐ. лобза́нїѧ мѝ не дадѐ: сїѧ́ же ѿне́лиже внидо́хъ, не преста̀ ѡ҆блобыза́ющи мѝ но́зѣ. ма́сломъ главы̀ моеѧ̀ не пома́за: сїѧ́ же мѵ́ромъ пома́за мѝ но́зѣ. є҆гѡ́же ра́ди глаго́лю тѝ: ѿпꙋща́ютсѧ грѣсѝ є҆ѧ̀ мно́зи, ꙗ҆́кѡ возлюбѝ мно́гѡ: а҆ є҆мꙋ́же ма́лѡ ѡ҆ставлѧ́етсѧ, ме́ньше лю́битъ. рече́ же є҆́й: ѿпꙋща́ютсѧ тебѣ̀ грѣсѝ. и҆ нача́ша возлежа́щїи съ ни́мъ глаго́лати въ себѣ̀: кто̀ се́й є҆́сть, и҆́же и҆ грѣхѝ ѿпꙋща́етъ; рече́ же къ женѣ̀: вѣ́ра твоѧ̀ спасе́ тѧ, и҆дѝ въ ми́рѣ. ",
}

add_evangelie_luki {
  ["номер"] = 34,
  ["комментарий"] = "Лк., 34 зач., VIII, 1–3.",
  ["текст_ру"] = "Во вре́мя о́но, прохожда́ше Иису́с сквозе́ гра́ды и ве́си, пропове́дуя и благовеству́я Ца́рствие Бо́жие, и обана́десяте с Ним. И жены́ не́кия, я́же бя́ху исцеле́ны от духо́в злых и неду́г, Мари́а нарица́емая Магдали́на, из нея́же бесо́в седмь изы́де, и Иоа́нна жена́ Хуза́ня, приста́вника И́родова, и Суса́нна, и и́ны мно́ги, я́же служа́ху Ему́ от име́ний свои́х. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прохожда́ше і҆и҃съ сквозѣ̀ гра́ды и҆ вє́си, проповѣ́дꙋѧ и҆ благовѣствꙋ́ѧ ца́рствїе бж҃їе: и҆ ѻ҆бана́десѧте съ ни́мъ. и҆ жєны̀ нѣ́кїѧ, ꙗ҆̀же бѧ́хꙋ и҆сцѣле́ны ѿ дꙋхѡ́въ ѕлы́хъ и҆ недꙋ̑гъ: марі́а нарица́емаѧ магдали́на, и҆з̾ неѧ́же бѣсѡ́въ се́дмь и҆зы́де: и҆ і҆ѡа́нна жена̀ хꙋза́нѧ, приста́вника и҆́рѡдова: и҆ сꙋса́нна, и҆ и҆́ны мнѡ́ги, ꙗ҆̀же слꙋжа́хꙋ є҆мꙋ̀ ѿ и҆мѣ́нїй свои́хъ. ",
}

add_evangelie_luki {
  ["номер"] = 35,
  ["комментарий"] = "Лк., 35 зач., VIII, 5–15.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: изы́де се́яй се́яти се́мене своего́, и егда́ се́яше, о́во паде́ при пути́, и попра́но бысть, и пти́цы небе́сныя позоба́ша е́. А друго́е паде́ на ка́мени, и прозя́б у́сше, зане́ не име́яше вла́ги. И друго́е паде́ посреде́ те́рния, и возрасте́ те́рние, и подави́ е́. Друго́е же паде́ на земли́ бла́зе, и прозя́б сотвори́ плод стори́цею. Сия́ глаго́ля, возгласи́: име́яй у́ши слы́шати, да слы́шит. Вопроша́ху же Его́ ученицы́ Его́, глаго́люще: что есть при́тча сия́? Он же рече́: вам есть дано́ ве́дати та́йны Ца́рствия Бо́жия, про́чым же в при́тчах, да ви́дяще не ви́дят и слы́шаще не разуме́ют. Есть же сия́ при́тча: се́мя есть сло́во Бо́жие, а и́же при пути́, суть слы́шащии, пото́м же прихо́дит диа́вол и взе́млет сло́во от се́рдца их, да не ве́ровавше спасу́тся, а и́же на ка́мени, и́же егда́ услы́шат, с ра́достию прие́млют сло́во, и си́и ко́рене не и́мут, и́же во вре́мя ве́руют, и во вре́мя напа́сти отпа́дают. А е́же в те́рнии па́дшее, си́и суть слы́шавшии, и от печа́ли и бога́тства и сластьми́ жите́йскими ходя́ще подавля́ются, и не сверша́ют плода́. А и́же на до́брей земли́, си́и суть, и́же до́брым се́рдцем и благи́м слы́шавше сло́во, держа́т и плод творя́т в терпе́нии. Сия́ глаго́ля, возгласи́: име́яй у́ши слы́шати, да слы́шит. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: и҆зы́де сѣ́ѧй сѣ́ѧти сѣ́мене своегѡ̀: и҆ є҆гда̀ сѣ́ѧше, ѻ҆́во падѐ при пꙋтѝ, и҆ попра́но бы́сть, и҆ пти́цы нбⷭ҇ныѧ позоба́ша є҆̀. а҆ дрꙋго́е падѐ на ка́мени, и҆ прозѧ́бъ ᲂу҆́сше, занѐ не и҆мѣ́ѧше вла́ги. и҆ дрꙋго́е падѐ посредѣ̀ те́рнїѧ: и҆ возрастѐ те́рнїе и҆ подавѝ є҆̀. дрꙋго́е же падѐ на землѝ бла́зѣ, и҆ прозѧ́бъ сотворѝ пло́дъ стори́цею. сїѧ̑ глаго́лѧ возгласѝ: и҆мѣ́ѧй ᲂу҆́ши слы́шати, да слы́шитъ. вопроша́хꙋ же є҆го̀ ᲂу҆ченицы̀ є҆гѡ̀, глаго́люще: что́ є҆сть при́тча сїѧ̀; ѻ҆́нъ же речѐ: ва́мъ є҆́сть дано̀ вѣ́дати та̑йны црⷭ҇твїѧ бж҃їѧ: про́чымъ же въ при́тчахъ, да ви́дѧще не ви́дѧтъ, и҆ слы́шаще не разꙋмѣ́ютъ. є҆́сть же сїѧ̀ при́тча: сѣ́мѧ є҆́сть сло́во бж҃їе. а҆ и҆̀же при пꙋтѝ, сꙋ́ть слы́шащїи: пото́мъ же прихо́дитъ дїа́волъ, и҆ взе́млетъ сло́во ѿ се́рдца и҆́хъ, да не вѣ́ровавше спасꙋ́тсѧ. а҆ и҆̀же на ка́мени, и҆̀же є҆гда̀ ᲂу҆слы́шатъ, съ ра́достїю прїе́млютъ сло́во: и҆ сі́и ко́рене не и҆́мꙋтъ, и҆̀же во вре́мѧ вѣ́рꙋютъ, и҆ во вре́мѧ напа́сти ѿпа́даютъ. а҆ є҆́же въ те́рнїи па́дшее, сі́и сꙋ́ть слы́шавшїи, и҆ ѿ печа́ли и҆ бога́тства, и҆ сластьмѝ жите́йскими ходѧ́ще, подавлѧ́ютсѧ, и҆ не сверша́ютъ плода̀. а҆ и҆̀же на до́брѣй землѝ, сі́и сꙋ́ть, и҆̀же до́брымъ се́рдцемъ и҆ бл҃ги́мъ слы́шавше сло́во держа́тъ, и҆ пло́дъ творѧ́тъ въ терпѣ́нїи. сїѧ̑ глаго́лѧ, возгласѝ: и҆мѣ́ѧй ᲂу҆́ши слы́шати, да слы́шитъ. ",
}

add_evangelie_luki {
  ["номер"] = 36,
  ["комментарий"] = "Лк., 36 зач., VIII, 16–21.",
  ["текст_ру"] = "Рече́ Госпо́дь: никто́же свети́льника вжег, покрыва́ет его́ сосу́дом, или́ под одр подлага́ет, но на све́щник возлага́ет, да входя́щии ви́дят свет. Несть бо та́йно, е́же не явле́но бу́дет, ниже́ утае́но, е́же не позна́ется и в явле́ние прии́дет. Блюди́теся у́бо, ка́ко слы́шите, и́же бо и́мать, да́стся ему́, и и́же а́ще не и́мать, и е́же мни́тся име́я, во́змется от него́. Приидо́ша же к Нему́ Ма́ти и бра́тия Его́, и не можа́ху бесе́довати к Нему́ наро́да ра́ди. И возвести́ша Ему́, глаго́люще: Ма́ти Твоя́ и бра́тия Твоя́ вне стоя́т, ви́дети Тя хотя́ще. Он же отвеща́в рече́ к ним: ма́ти Моя́ и бра́тия Моя́ си́и суть, слы́шащии сло́во Бо́жие, и творя́ще е́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: никто́же свѣти́льника вже́гъ, покрыва́етъ є҆го̀ сосꙋ́домъ, и҆лѝ под̾ ѻ҆́дръ подлага́етъ: но на свѣ́щникъ возлага́етъ, да входѧ́щїи ви́дѧтъ свѣ́тъ. нѣ́сть бо та́йно, є҆́же не ꙗ҆вле́но бꙋ́детъ, нижѐ ᲂу҆тае́но, є҆́же не позна́етсѧ, и҆ въ ꙗ҆вле́нїе прїи́детъ. блюди́тесѧ ᲂу҆́бѡ, ка́кѡ слы́шите. и҆́же бо и҆́мать, да́стсѧ є҆мꙋ̀: и҆ и҆́же а҆́ще не и҆́мать, и҆ є҆́же мни́тсѧ и҆мѣ́ѧ, во́з̾метсѧ ѿ негѡ̀. прїидо́ша же къ немꙋ̀ мт҃и и҆ бра́тїѧ є҆гѡ̀, и҆ не можа́хꙋ бесѣ́довати къ немꙋ̀ наро́да ра́ди. и҆ возвѣсти́ша є҆мꙋ̀, глаго́люще: мт҃и твоѧ̀ и҆ бра́тїѧ твоѧ̀ внѣ̀ стоѧ́тъ, ви́дѣти тѧ̀ хотѧ́ще. ѻ҆́нъ же ѿвѣща́въ речѐ къ ни́мъ: мт҃и моѧ̀, и҆ бра́тїѧ моѧ̀ сі́и сꙋ́ть, слы́шащїи сло́во бж҃їе, и҆ творѧ́ще є҆̀. ",
}

add_evangelie_luki {
  ["номер"] = 37,
  ["комментарий"] = "Лк., 37 зач., VIII, 22–25.",
  ["текст_ру"] = "Во вре́мя о́но, влез Иису́с в кора́бль и ученицы́ Его́, и рече́ к ним: пре́йдем на он пол е́зера. И поидо́ша. Иду́щым же им, у́спе. И сни́де бу́ря ве́треная в е́зеро, и скончава́хуся и в беде́ бе́ху. И присту́пльше воздвиго́ша Его́, глаго́люще: Наста́вниче, Наста́вниче, погиба́ем. Он же воста́в запрети́ ве́тру и волне́нию водно́му, и улего́ста, и бысть тишина́. Рече́ же им: где есть ве́ра ва́ша? Убоя́вшеся же чуди́шася, глаго́люще друг ко дру́гу: кто у́бо Сей есть, я́ко и ве́тром повелева́ет и воде́, и послу́шают Его́? ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, влѣ́зъ і҆и҃съ въ кора́бль, и҆ ᲂу҆ченицы̀ є҆гѡ̀, и҆ речѐ къ ни́мъ: пре́йдемъ на ѻ҆́нъ по́лъ є҆́зера. и҆ поидо́ша. и҆дꙋ́щымъ же и҆̀мъ, ᲂу҆́спе: и҆ сни́де бꙋ́рѧ вѣ́тренаѧ въ є҆́зеро: и҆ скончава́хꙋсѧ, и҆ въ бѣдѣ̀ бѣ́хꙋ. и҆ пристꙋ́пльше воздвиго́ша є҆го̀, глаго́люще: наста́вниче, наста́вниче, погиба́емъ. ѻ҆́нъ же воста́въ запретѝ вѣ́трꙋ, и҆ волне́нїю водно́мꙋ: и҆ ᲂу҆лего́ста, и҆ бы́сть тишина̀. рече́ же и҆̀мъ: гдѣ́ є҆сть вѣ́ра ва́ша; ᲂу҆боѧ́вшесѧ же чꙋди́шасѧ, глаго́люще дрꙋ́гъ ко дрꙋ́гꙋ: кто̀ ᲂу҆́бѡ се́й є҆́сть, ꙗ҆́кѡ и҆ вѣ́трѡмъ повелѣва́етъ, и҆ водѣ̀, и҆ послꙋ́шаютъ є҆гѡ̀; ",
}

add_evangelie_luki {
  ["номер"] = 38,
  ["комментарий"] = "Лк., 38 зач., VIII, 26–39.",
  ["текст_ру"] = "Во вре́мя о́но, прише́дшу Иису́су во страну́ Гадари́нску, я́же есть об он пол Галиле́и. Изше́дшу же Ему́ на зе́млю, сре́те Его́ муж не́кий от гра́да, и́же имя́ше бе́сы от лет мно́гих, и в ри́зу не облача́шеся, и во хра́ме не живя́ше, но во гробе́х. Узре́в же Иису́са и возопи́в, припаде́ к Нему́, и гла́сом ве́лиим рече́: что мне и Тебе́, Иису́се Сы́не Бо́га Вы́шняго? Молю́ся Ти, не му́чи мене́. Повеле́ у́бо ду́хови нечи́стому изы́ти от челове́ка, от мног бо лет восхища́ше его́, и вяза́ху его́ у́зы желе́зны и пу́ты, стрегу́ще его́, и растерза́я у́зы, гони́мь быва́ше бе́сом сквозе́ пусты́ни. Вопроси́ же его́ Иису́с, глаго́ля: что ти есть и́мя? Он же рече́: легео́н, я́ко бе́си мно́зи внидо́ша в онь. И моля́ху Его́, да не повели́т им в бе́здну ити́. Бе же ту ста́до свине́й мно́го пасо́мо в горе́, и моля́ху Его́, да повели́т им в ты вни́ти. И повеле́ им. Изше́дше же бе́си от челове́ка, внидо́ша во свиния́, и устреми́ся ста́до по бре́гу в е́зеро, и истопе́. Ви́девше же пасу́щии бы́вшее, бежа́ша, и возвести́ша во гра́де и в се́лех. Изыдо́ша же ви́дети бы́вшее, и приидо́ша ко Иису́сови и обрето́ша челове́ка седя́ща, из него́же бе́си изыдо́ша, оболче́на и смы́сляща, при ногу́ Иису́сову, и убоя́шася. Возвести́ша же им ви́девшии, ка́ко спасе́ся беснова́вый. И моли́ Его́ весь наро́д страны́ Гадари́нския отити́ от них, я́ко стра́хом ве́лиим одержи́ми бе́ху. Он же влез в кора́бль, возврати́ся. Моля́шеся же Ему́ муж, из него́же изыдо́ша бе́си, дабы́ с Ним был. Отпусти́ же его́ Иису́с, глаго́ля: возврати́ся в дом твой и пове́дай, ели́ка ти сотвори́ Бог. И и́де, по всему́ гра́ду пропове́дая, ели́ка сотвори́ ему́ Иису́с. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прише́дшꙋ і҆и҃сꙋ во странꙋ̀ гадари́нскꙋ, ꙗ҆́же є҆́сть ѡ҆б̾ ѻ҆́нъ по́лъ галїле́и. и҆зше́дшꙋ же є҆мꙋ̀ на зе́млю, срѣ́те є҆го̀ мꙋ́жъ нѣ́кїй ѿ гра́да, и҆́же и҆мѧ́ше бѣ́сы ѿ лѣ́тъ мно́гихъ, и҆ въ ри́зꙋ не ѡ҆блача́шесѧ, и҆ во хра́мѣ не живѧ́ше, но во гробѣ́хъ. ᲂу҆зрѣ́въ же і҆и҃са, и҆ возопи́въ, припадѐ къ немꙋ̀, и҆ гла́сомъ ве́лїимъ речѐ: что̀ мнѣ̀ и҆ тебѣ̀, і҆и҃се сн҃е бг҃а вы́шнѧгѡ; молю́сѧ тѝ, не мꙋ́чи менѐ. повелѣ̀ ᲂу҆́бѡ дꙋ́хови нечи́стомꙋ и҆зы́ти ѿ человѣ́ка: ѿ мнѡ́гъ бо лѣ́тъ восхища́ше є҆го̀, и҆ вѧза́хꙋ є҆го̀ ᲂу҆́зы желѣ́зны и҆ пꙋ́ты, стрегꙋ́ще є҆го̀: и҆ растерза́ѧ ᲂу҆́зы, гони́мь быва́ше бѣ́сомъ сквозѣ̀ пꙋсты̑ни. вопроси́ же є҆го̀ і҆и҃съ, глаго́лѧ: что́ ти є҆́сть и҆́мѧ; ѻ҆́нъ же речѐ: легеѡ́нъ: ꙗ҆́кѡ бѣ́си мно́зи внидо́ша въ ѻ҆́нь. и҆ молѧ́хꙋ є҆го̀, да не повели́тъ и҆̀мъ въ бе́зднꙋ и҆тѝ: бѣ́ же тꙋ̀ ста́до свине́й мно́го пасо́мо въ горѣ̀. и҆ молѧ́хꙋ є҆го̀, да повели́тъ и҆̀мъ въ ты̑ вни́ти, и҆ повелѣ̀ и҆̀мъ. и҆зше́дше же бѣ́си ѿ человѣ́ка, внидо́ша во свинїѧ̑: и҆ ᲂу҆стреми́сѧ ста́до по бре́гꙋ въ є҆́зеро, и҆ и҆стопѐ. ви́дѣвше же пасꙋ́щїи бы́вшее, бѣжа́ша: и҆ возвѣсти́ша во гра́дѣ и҆ въ се́лѣхъ. и҆зыдо́ша же ви́дѣти бы́вшее: и҆ прїидо́ша ко і҆и҃сови, и҆ ѡ҆брѣто́ша человѣ́ка сѣдѧ́ща, и҆з̾ негѡ́же бѣ́си и҆зыдо́ша, ѡ҆болче́на и҆ смы́слѧща, при ногꙋ̀ і҆и҃совꙋ, и҆ ᲂу҆боѧ́шасѧ. возвѣсти́ша же и҆̀мъ ви́дѣвшїи, ка́кѡ спасе́сѧ бѣснова́вый. и҆ молѝ є҆го̀ ве́сь наро́дъ страны̀ гадари́нскїѧ ѿитѝ ѿ ни́хъ, ꙗ҆́кѡ стра́хомъ ве́лїимъ ѡ҆держи́ми бѣ́хꙋ: ѻ҆́нъ же влѣ́зъ въ кора́бль, возврати́сѧ. молѧ́шесѧ же є҆мꙋ̀ мꙋ́жъ, и҆з̾ негѡ́же и҆зыдо́ша бѣ́си, дабы̀ съ ни́мъ бы́лъ. ѿпꙋсти́ же є҆го̀ і҆и҃съ, глаго́лѧ: возврати́сѧ въ до́мъ тво́й, и҆ повѣ́дай, є҆ли̑ка тѝ сотворѝ бг҃ъ. и҆ и҆́де по всемꙋ̀ гра́дꙋ проповѣ́даѧ, є҆ли̑ка сотворѝ є҆мꙋ̀ і҆и҃съ. ",
}

add_evangelie_luki {
  ["номер"] = 39,
  ["комментарий"] = "Лк., 39 зач., VIII, 41–56.",
  ["текст_ру"] = "Во вре́мя о́но, челове́к не́кий приступи́ ко Иису́су, ему́же и́мя Иаи́р, и той князь со́нмищу бе, и пад при ногу́ Иису́сову, моля́ше Его́ вни́ти в дом свой, я́ко дщи единоро́дна бе ему́, я́ко лет двоюна́десяте, и та умира́ше. Егда́ же идя́ше, наро́ди угнета́ху Его́. И жена́ су́щи в точе́нии кро́ве от двоюна́десяте ле́ту, я́же враче́м изда́вши все име́ние, и не возмо́же ни от еди́наго исцеле́ти, и присту́пльши созади́, косну́ся кра́я риз Его́, и а́бие ста ток кро́ве ея́. И рече́ Иису́с: кто есть косну́выйся Мне? Отмета́ющымся же всем, рече́ Петр и и́же с Ним: Наста́вниче, наро́ди одержа́т Тя и гнету́т, и глаго́леши: кто есть косну́выйся Мне? Иису́с же рече́: прикосну́ся Мне не́кто, Аз бо чух си́лу изше́дшую из Мене́. Ви́девши же жена́, я́ко не утаи́ся, трепе́щущи прии́де, и па́дши пред Ним, за ню́же вину́ прикосну́ся Ему́, пове́да Ему́ пред все́ми людьми́, и я́ко исцеле́ а́бие. Он же рече́ ей: дерза́й дщи, ве́ра твоя́ спасе́ тя, иди́ в ми́ре. Еще́ Ему́ глаго́лющу, прии́де не́кий от архисинаго́га, глаго́ля ему́, я́ко у́мре дщи твоя́, не дви́жи Учи́теля. Иису́с же слы́шав отвеща́ ему́, глаго́ля: не бо́йся, то́кмо ве́руй, и спасе́на бу́дет. Прише́д же в дом, не оста́ви ни еди́наго вни́ти, то́кмо Петра́ и Иоа́нна и Иа́кова, и отца́ отрокови́цы, и ма́тере. Пла́кахуся же вси и рыда́ху ея́. Он же рече́: не пла́читеся, не у́мре бо, но спит. И руга́хуся Ему́, ве́дяще, я́ко у́мре. Он же изгна́в вон всех, и ем за ру́ку ея́, возгласи́, глаго́ля: отрокови́це, воста́ни. И возврати́ся дух ея́, и воскре́се а́бие, и повеле́ да́ти ей я́сти. И диви́стася роди́теля ея́. Он же повеле́ и́ма никому́же пове́дати бы́вшее. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, человѣ́къ нѣ́кїй пристꙋпѝ ко і҆и҃сꙋ, є҆мꙋ́же и҆́мѧ і҆аі́ръ, и҆ то́й кнѧ́зь со́нмищꙋ бѣ̀: и҆ па́дъ при ногꙋ̀ і҆и҃совꙋ, молѧ́ше є҆го̀ вни́ти въ до́мъ сво́й: ꙗ҆́кѡ дщѝ є҆диноро́дна бѣ̀ є҆мꙋ̀, ꙗ҆́кѡ лѣ́тъ двоюна́десѧте, и҆ та̀ ᲂу҆мира́ше: є҆гда́ же и҆дѧ́ше, наро́ди ᲂу҆гнѣта́хꙋ є҆го̀. и҆ жена̀ сꙋ́щи въ точе́нїи кро́ве ѿ двоюна́десѧте лѣ́тꙋ, ꙗ҆́же врачє́мъ и҆зда́вши всѐ и҆мѣ́нїе, и҆ не возмо́же ни ѿ є҆ди́нагѡ и҆сцѣлѣ́ти. и҆ пристꙋ́пльши созадѝ, коснꙋ́сѧ кра́ѧ ри́зъ є҆гѡ̀: и҆ а҆́бїе ста̀ то́къ кро́ве є҆ѧ̀. и҆ речѐ і҆и҃съ: кто́ є҆сть коснꙋ́выйсѧ мнѣ̀; ѿмета́ющымсѧ же всѣ́мъ, речѐ пе́тръ, и҆ и҆̀же съ ни́мъ: наста́вниче, наро́ди ѡ҆держа́тъ тѧ̀, и҆ гнѣтꙋ́тъ, и҆ глаго́леши: кто́ є҆сть коснꙋ́выйсѧ мнѣ̀; і҆и҃съ же речѐ: прикоснꙋ́сѧ мнѣ̀ нѣ́кто, а҆́зъ бо чꙋ́хъ си́лꙋ и҆зше́дшꙋю и҆з̾ менѐ. ви́дѣвши же жена̀, ꙗ҆́кѡ не ᲂу҆таи́сѧ, трепе́щꙋщи прїи́де, и҆ па́дши пред̾ ни́мъ, за ню́же винꙋ̀ прикоснꙋ́сѧ є҆мꙋ̀, повѣ́да є҆мꙋ̀ пред̾ всѣ́ми людьмѝ, и҆ ꙗ҆́кѡ и҆сцѣлѣ̀ а҆́бїе. ѻ҆́нъ же речѐ є҆́й: дерза́й дщѝ, вѣ́ра твоѧ̀ спасе́ тѧ, и҆дѝ въ ми́рѣ. є҆щѐ є҆мꙋ̀ глаго́лющꙋ, прїи́де нѣ́кїй ѿ а҆рхїсѷнагѡ́га, глаго́лѧ є҆мꙋ̀: ꙗ҆́кѡ ᲂу҆́мре дщѝ твоѧ̀, не дви́жи ᲂу҆чи́телѧ. і҆и҃съ же слы́шавъ, ѿвѣща̀ є҆мꙋ̀ глаго́лѧ: не бо́йсѧ, то́кмѡ вѣ́рꙋй, и҆ спасе́на бꙋ́детъ. прише́дъ же въ до́мъ, не ѡ҆ста́ви ни є҆ди́нагѡ вни́ти, то́кмѡ петра̀ и҆ і҆ѡа́нна и҆ і҆а́кѡва, и҆ ѻ҆тца̀ ѻ҆трокови́цы, и҆ ма́тере. пла́кахꙋсѧ же всѝ и҆ рыда́хꙋ є҆ѧ̀. ѻ҆́нъ же речѐ: не пла́читесѧ: не ᲂу҆́мре бо, но спи́тъ. и҆ рꙋга́хꙋсѧ є҆мꙋ̀ вѣ́дѧще, ꙗ҆́кѡ ᲂу҆́мре. ѻ҆́нъ же и҆згна́въ во́нъ всѣ́хъ, и҆ є҆́мъ за рꙋ́кꙋ є҆ѧ̀, возгласѝ глаго́лѧ: ѻ҆трокови́це, воста́ни. и҆ возврати́сѧ дꙋ́хъ є҆ѧ̀, и҆ воскре́се а҆́бїе: и҆ повелѣ̀ да́ти є҆́й ꙗ҆́сти. и҆ диви́стасѧ роди́тєлѧ є҆ѧ̀. ѻ҆́нъ же повелѣ̀ и҆́ма никомꙋ́же повѣ́дати бы́вшее. ",
}

add_evangelie_luki {
  ["номер"] = 40,
  ["комментарий"] = "Лк., 40 зач., IX, 1–6.",
  ["текст_ру"] = "Во вре́мя о́но, созва́ Иису́с обана́десяте ученика́ Своя́, даде́ им си́лу и власть на вся бе́сы, и неду́ги цели́ти, и посла́ их пропове́дати Ца́рствие Бо́жие и исцели́ти боля́щия. И рече́ к ним: ничесо́же возьми́те на путь, ни жезла́, ни пи́ры, ни хле́ба, ни сребра́, ни по двема́ ри́зама име́ти. И во́ньже дом вни́дете, ту пребыва́йте, и отту́ду исходи́те. И ели́цы а́ще не прие́млют вас, исходя́ще от гра́да того́, и прах от ног ва́ших оттряси́те, во свиде́тельство на ня. Исходя́ще же прохожда́ху сквозе́ ве́си, благовеству́юще и исцеля́юще всю́ду. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, созва̀ і҆и҃съ ѻ҆бана́десѧте ᲂу҆ченика̀ своѧ̀, дадѐ и҆̀мъ си́лꙋ и҆ вла́сть на всѧ̀ бѣ́сы, и҆ недꙋ́ги цѣли́ти. и҆ посла̀ и҆̀хъ проповѣ́дати црⷭ҇твїе бж҃їе, и҆ и҆сцѣли́ти болѧ́щыѧ. и҆ речѐ къ ни́мъ: ничесѡ́же воз̾ми́те на пꙋ́ть, ни жезла̀, ни пи́ры, ни хлѣ́ба, ни сребра̀, ни по двѣма̀ ри́зама и҆мѣ́ти. и҆ во́ньже до́мъ вни́дете, тꙋ̀ пребыва́йте, и҆ ѿтꙋ́дꙋ и҆сходи́те. и҆ є҆ли́цы а҆́ще не прїе́млютъ ва́съ, и҆сходѧ́ще ѿ гра́да тогѡ̀, и҆ пра́хъ ѿ но́гъ ва́шихъ ѿтрѧси́те во свидѣ́тельство на нѧ̀. и҆сходѧ́ще же прохожда́хꙋ сквозѣ̀ вє́си, благовѣствꙋ́юще, и҆ и҆сцѣлѧ́юще всю́дꙋ. ",
}

add_evangelie_luki {
  ["номер"] = 41,
  ["комментарий"] = "Лк., 41 зач., IX, 7–11.",
  ["текст_ру"] = "Во вре́мя о́но, слы́шав И́род четвертовла́стник о Иису́се быва́ющая от Него́ вся и недоумева́шеся, зане́ глаго́лемо бе от не́ких, я́ко Иоа́нн воста́ от ме́ртвых, от ине́х же, я́ко Илиа́ яви́ся, от други́х же, я́ко проро́к еди́н от дре́вних воскре́се. И рече́ И́род: Иоа́нна аз усе́кнух, кто же есть Сей, о Не́мже аз слы́шу такова́я? И иска́ше ви́дети Его́. И возвра́щшеся Апо́столи пове́даша Ему́, ели́ка сотвори́ша, и пои́м их, оты́де еди́н на ме́сто пу́сто гра́да, нарица́емаго Вифсаи́да. Народи́ же разуме́вше, по Нем идо́ша, и прие́м их, глаго́лаше им о Ца́рствии Бо́жии и тре́бующыя исцеле́ния целя́ше. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, слы́шавъ и҆́рѡдъ четвертовла́стникъ ѡ҆ і҆и҃сѣ, быва̑ющаѧ ѿ негѡ̀ всѧ̑ и҆ недоꙋмѣва́шесѧ: занѐ глаго́лемо бѣ̀ ѿ нѣ́кихъ, ꙗ҆́кѡ і҆ѡа́ннъ воста̀ ѿ ме́ртвыхъ: ѿ и҆нѣ́хъ же, ꙗ҆́кѡ и҆лїа̀ ꙗ҆ви́сѧ: ѿ дрꙋги́хъ же, ꙗ҆́кѡ проро́къ є҆ди́нъ ѿ дре́внихъ воскре́се. и҆ речѐ и҆́рѡдъ: і҆ѡа́нна а҆́зъ ᲂу҆сѣ́кнꙋхъ: кто́ же є҆́сть се́й, ѡ҆ не́мже а҆́зъ слы́шꙋ такѡва́ѧ; и҆ и҆ска́ше ви́дѣти є҆го̀. и҆ возвра́щшесѧ а҆пⷭ҇ли повѣ́даша є҆мꙋ̀, є҆ли̑ка сотвори́ша. и҆ пои́мъ и҆̀хъ, ѿи́де є҆ди́нъ на мѣ́сто пꙋ́сто гра́да нарица́емагѡ виѳсаі́да. наро́ди же разꙋмѣ́вше, по не́мъ и҆до́ша: и҆ прїе́мъ и҆̀хъ, глаго́лаше и҆̀мъ ѡ҆ црⷭ҇твїи бж҃їи, и҆ тре́бꙋющыѧ и҆сцѣле́нїѧ цѣлѧ́ше. ",
}

add_evangelie_luki {
  ["номер"] = 42,
  ["комментарий"] = "Лк., 42 зач., IX, 12–18.",
  ["текст_ру"] = "Во вре́мя о́но, присту́пльше ко Иису́су обана́десяте ученика́ Его́, реко́ша Ему́: отпусти́ наро́д, да ше́дше во окре́стныя ве́си и се́ла вита́ют и обря́щут бра́шно, я́ко зде в пу́сте ме́сте есмы́. Рече́ же к ним: дади́те им вы я́сти. Они́ же ре́ша: несть у нас вя́щше, то́кмо пять хлеб и ры́бе две, а́ще у́бо не ше́дше мы ку́пим во вся лю́ди сия́ бра́шна. Бе́ху бо муже́й я́ко пять ты́сящ. Рече́ же ко ученико́м Свои́м: посади́те их на ку́пы по пяти́десят. И сотвори́ша та́ко, и посади́ша их вся. Прии́м же пять хлеб и о́бе ры́бе, воззре́в на не́бо, благослови́ их, и сломи́, и дая́ше ученико́м предложи́ти наро́ду. И ядо́ша, и насы́тишася вси, и взя́ша избы́вшыя им укру́хи ко́шя двана́десяте. И бысть егда́ моля́шеся еди́н, с Ним бе́ху ученицы́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋпи́ша ко і҆и҃сꙋ ѻ҆бана́десѧте ᲂу҆ченика̀ є҆гѡ̀ реко́ша є҆мꙋ̀: ѿпꙋстѝ наро́дъ, да ше́дше во ѻ҆крє́стныѧ вє́си и҆ се́ла вита́ютъ, и҆ ѡ҆брѧ́щꙋтъ бра́шно: ꙗ҆́кѡ здѣ̀ въ пꙋ́стѣ мѣ́стѣ є҆смы̀. рече́ же къ ни́мъ: дади́те и҆̀мъ вы̀ ꙗ҆́сти. ѻ҆ни́ же рѣ́ша: нѣ́сть ᲂу҆ на́съ вѧ́щше, то́кмѡ пѧ́ть хлѣ̑бъ, и҆ ры́бѣ двѣ̀, а҆́ще ᲂу҆́бѡ не ше́дше мы̀ кꙋ́пимъ во всѧ̀ лю́ди сїѧ̀ бра́шна; бѣ́хꙋ бо мꙋже́й ꙗ҆́кѡ пѧ́ть ты́сѧщъ. рече́ же ко ᲂу҆ченикѡ́мъ свои́мъ: посади́те и҆̀хъ на кꙋ́пы по пѧти́десѧтъ. и҆ сотвори́ша та́кѡ: и҆ посади́ша и҆̀хъ всѧ̑. прїи́мъ же пѧ́ть хлѣ̑бъ и҆ ѻ҆́бѣ ры́бѣ, воззрѣ́въ на нб҃о, благословѝ и҆̀хъ: и҆ сломѝ, и҆ даѧ́ше ᲂу҆ченикѡ́мъ предложи́ти наро́дꙋ. и҆ ꙗ҆до́ша, и҆ насы́тишасѧ всѝ, и҆ взѧ́ша и҆збы́вшыѧ и҆̀мъ ᲂу҆крꙋ́хи, кѡ́шѧ двана́десѧте. и҆ бы́сть є҆гда̀ молѧ́шесѧ є҆ди́нъ, съ ни́мъ бѣ́хꙋ ᲂу҆ченицы̀. ",
}

add_evangelie_luki {
  ["номер"] = 43,
  ["комментарий"] = "Лк., 43 зач., IX, 18–22.",
  ["текст_ру"] = "Во вре́мя о́но, бысть егда́ Иису́с моля́шеся еди́н, с Ним бе́ху ученицы́, и вопроси́ их, глаго́ля: кого́ Мя глаго́лют наро́ди бы́ти? Они́ же отвеща́вше ре́ша: Иоа́нна Крести́теля, ини́и же Илию́, друзи́и же, я́ко проро́к не́кий от дре́вних воскре́се. Рече́ же им: вы же кого́ Мя глаго́лете бы́ти? Отвеща́в же Петр рече́: Христа́ Бо́жия. Он же запре́щь им, повеле́ никому́же глаго́лати сего́, рек, я́ко подоба́ет Сы́ну Челове́ческому мно́го пострада́ти, и искуше́ну бы́ти от ста́рец и архиере́й и кни́жник, и убие́ну бы́ти, и в тре́тий день воста́ти. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бы́сть є҆гда̀ і҆и҃съ молѧ́шесѧ є҆ди́нъ, съ ни́мъ бѣ́хꙋ ᲂу҆ченицы̀. и҆ вопросѝ и҆̀хъ глаго́лѧ: кого́ мѧ глаго́лютъ наро́ди бы́ти; ѻ҆ни́ же ѿвѣща́вше рѣ́ша: і҆ѡа́нна крести́телѧ, и҆ні́и же и҆лїю̀: дрꙋзі́и же, ꙗ҆́кѡ проро́къ нѣ́кїй ѿ дре́внихъ воскре́се. рече́ же и҆̀мъ: вы́ же кого́ мѧ глаго́лете бы́ти; ѿвѣща́въ же пе́тръ речѐ: хрⷭ҇та̀ бж҃їѧ. ѻ҆́нъ же запре́щь и҆̀мъ, повелѣ̀ никомꙋ́же глаго́лати сегѡ̀, ре́къ: ꙗ҆́кѡ подоба́етъ сн҃ꙋ человѣ́ческомꙋ мно́гѡ пострада́ти, и҆ и҆скꙋше́нꙋ бы́ти ѿ ста́рєцъ, и҆ а҆рхїерє́й, и҆ кни̑жникъ, и҆ ᲂу҆бїе́нꙋ бы́ти, и҆ въ тре́тїй де́нь воста́ти. ",
}

add_evangelie_luki {
  ["номер"] = 44,
  ["комментарий"] = "Лк., 44 зач., IX, 23-27.",
  ["текст_ру"] = "Рече́ Госпо́дь: а́ще кто хо́щет по Мне ити́, да отве́ржется себе́, и во́змет крест свой, и после́дует Ми. И́же бо а́ще хо́щет ду́шу свою́ спасти́, погуби́т ю́, а и́же погуби́т ду́шу свою́ Мене́ ра́ди, сей спасе́т ю́. Что бо по́льзует челове́к приобре́т мир весь, себе́ же погуби́в или́ отщети́в? И́же бо а́ще постыди́тся Мене́ и Мои́х слове́с, сего́ Сын Челове́ческий постыди́тся, егда́ прии́дет во сла́ве Свое́й и О́тчей и святы́х А́нгел. Глаго́лю же вам вои́стинну: суть не́цыи от зде стоя́щих, и́же не и́мут вкуси́ти сме́рти, до́ндеже ви́дят Ца́рствие Бо́жие. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: а҆́ще кто̀ хо́щетъ по мнѣ̀ и҆тѝ, да ѿве́ржетсѧ себѐ, и҆ во́з̾метъ кре́стъ сво́й, и҆ послѣ́дꙋетъ мѝ. и҆́же бо а҆́ще хо́щетъ дꙋ́шꙋ свою̀ спастѝ, погꙋби́тъ ю҆̀: а҆ и҆́же погꙋби́тъ дꙋ́шꙋ свою̀ менѐ ра́ди, се́й спасе́тъ ю҆̀. что́ бо по́льзꙋетъ человѣ́къ прїѡбрѣ́тъ мі́ръ ве́сь, себе́ же погꙋби́въ, и҆лѝ ѿтщети́въ; и҆́же бо а҆́ще постыди́тсѧ менѐ, и҆ мои́хъ слове́съ, сегѡ̀ сн҃ъ человѣ́ческїй постыди́тсѧ, є҆гда̀ прїи́детъ во сла́вѣ свое́й, и҆ ѻ҆́ч҃ей, и҆ ст҃ы́хъ а҆́гг҃лъ. глаго́лю же ва́мъ вои́стиннꙋ: сꙋ́ть нѣ́цыи ѿ здѣ̀ стоѧ́щихъ, и҆̀же не и҆́мꙋтъ вкꙋси́ти сме́рти, до́ндеже ви́дѧтъ црⷭ҇твїе бж҃їе. ",
}

add_evangelie_luki {
  ["номер"] = 45,
  ["комментарий"] = "Лк., 45 зач., IX, 28–36.",
  ["текст_ру"] = "Во вре́мя о́но, пое́м Иису́с Петра́, и Иоа́нна, и Иа́кова, взы́де на гору́ помоли́тися. И бысть, егда́ моля́шеся, виде́ние лица́ Его́ и́но, и одея́ние Его́ бело́ блиста́яся. И се му́жа два с Ним глаго́люща, я́же бе́ста Моисе́й и Илиа́, я́вльшася во сла́ве, глаго́ласта же исхо́д Его́, и́же хотя́ше сконча́ти во Иерусали́ме. Петр же, и су́щии с ним, бя́ху отягче́ни сном, убу́ждшеся же ви́деша сла́ву Его́, и о́ба му́жа стоя́ща с Ним. И бысть, егда́ разлучи́стася от Него́, рече́ Петр ко Иису́су: Наста́вниче, добро́ есть нам зде бы́ти, и сотвори́м се́ни три, еди́ну Тебе́, и еди́ну Моисе́ови, и еди́ну Илии́, не ве́дый, е́же глаго́лаше. Се же ему́ глаго́лющу, бысть о́блак, и осени́ их, убоя́шася же, вше́дшим им во о́блак. И глас бысть из о́блака, глаго́ля: Сей есть Сын Мой Возлю́бленный, Того́ послу́шайте. И егда́ бысть глас, обре́теся Иису́с еди́н, и ти́и умолча́ша, и никому́же возвести́ша в ты́я дни ничесо́же от тех, я́же ви́деша. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пое́мъ і҆и҃съ петра̀, и҆ і҆ѡа́нна, и҆ і҆а́кѡва, взы́де на горꙋ̀ помоли́тисѧ. и҆ бы́сть є҆гда̀ молѧ́шесѧ, видѣ́нїе лица̀ є҆гѡ̀ и҆́но, и҆ ѡ҆дѣѧ́нїе є҆гѡ̀ бѣло̀ блиста́ѧсѧ. и҆ сѐ мꙋ́жа два̀ съ ни́мъ глаго́люща, ꙗ҆̀же бѣ́ста мѡѷсе́й и҆ и҆лїа̀, ꙗ҆́вльшасѧ во сла́вѣ: глаго́ласта же и҆схо́дъ є҆гѡ̀, и҆́же хотѧ́ше сконча́ти во і҆ерꙋсали́мѣ. пе́тръ же и҆ сꙋ́щїи съ ни́мъ, бѧ́хꙋ ѡ҆тѧгче́ни сно́мъ: ᲂу҆бꙋ́ждшесѧ же ви́дѣша сла́вꙋ є҆гѡ̀, и҆ ѻ҆́ба мꙋ́жа стоѧ́ща съ ни́мъ. и҆ бы́сть є҆гда̀ разлꙋчи́стасѧ ѿ негѡ̀, речѐ пе́тръ ко і҆и҃сꙋ: наста́вниче, добро̀ є҆́сть на́мъ здѣ̀ бы́ти: и҆ сотвори́мъ сѣ́ни трѝ, є҆ди́нꙋ тебѣ̀, и҆ є҆ди́нꙋ мѡѷсе́ови, и҆ є҆ди́нꙋ и҆лїѝ: не вѣ́дый є҆́же глаго́лаше. се́ же є҆мꙋ̀ глаго́лющꙋ, бы́сть ѻ҆́блакъ, и҆ ѡ҆сѣнѝ и҆̀хъ: ᲂу҆боѧ́шасѧ же, вше́дшымъ и҆̀мъ во ѻ҆́блакъ. и҆ гла́съ бы́сть и҆з̾ ѻ҆́блака, глаго́лѧ: се́й є҆́сть сн҃ъ мо́й возлю́бленный, тогѡ̀ послꙋ́шайте. и҆ є҆гда̀ бы́сть гла́съ, ѡ҆брѣ́тесѧ і҆и҃съ є҆ди́нъ: и҆ ті́и ᲂу҆молча́ша, и҆ никомꙋ́же возвѣсти́ша въ ты́ѧ днѝ ничесѡ́же ѿ тѣ́хъ, ꙗ҆̀же ви́дѣша. ",
}

add_evangelie_luki {
  ["номер"] = 46,
  ["комментарий"] = "Лк., 46 зач., IX, 37–43.",
  ["текст_ру"] = "Во вре́мя о́но, соше́дшу Иису́су с горы, сре́те Его́ наро́д мног. И се муж из наро́да возопи́, глаго́ля: Учи́телю, молю́ Ти ся, при́зри на сы́на моего́, я́ко единоро́ден ми есть, и се дух е́млет его́, и внеза́пу вопие́т, и пружа́ется с пе́нами, и едва́ отхо́дит от него́, сокруша́я его́, и моли́хся ученико́м Твои́м, да иждену́т его́, и не возмого́ша. Отвеща́в же Иису́с рече́: о, ро́де неве́рный и развраще́нный, доко́ле бу́ду в вас и терплю́ вы? Приведи́ Ми сы́на твоего́ се́мо. Еще́ же гряду́щу ему́, пове́рже его́ бес и стрясе́. Запрети́ же Иису́с ду́хови нечи́стому, и исцели́ о́трока, и вдаде́ его́ отцу́ его́. Дивля́хуся же вси о вели́чии Бо́жии. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, соше́дшꙋ і҆и҃сꙋ съ горы̀, срѣ́те є҆го̀ наро́дъ мно́гъ. и҆ сѐ мꙋ́жъ и҆з̾ наро́да возопѝ, глаго́лѧ: ᲂу҆чи́телю, молю́ ти сѧ, при́зри на сы́на моего̀, ꙗ҆́кѡ є҆диноро́денъ мѝ є҆́сть: и҆ сѐ дꙋ́хъ є҆́млетъ є҆го̀, и҆ внеза́пꙋ вопїе́тъ и҆ прꙋжа́етсѧ съ пѣ́нами, и҆ є҆два̀ ѿхо́дитъ ѿ негѡ̀, сокрꙋша́ѧ є҆го̀. и҆ моли́хсѧ ᲂу҆ченикѡ́мъ твои́мъ, да и҆жденꙋ́тъ є҆го̀: и҆ не возмого́ша. ѿвѣща́въ же і҆и҃съ речѐ: ѽ ро́де невѣ́рный и҆ развраще́нный, доко́лѣ бꙋ́дꙋ въ ва́съ, и҆ терплю̀ вы̀; приведи́ ми сы́на твоего̀ сѣ́мѡ. є҆́ще же грѧдꙋ́щꙋ є҆мꙋ̀, пове́рже є҆го̀ бѣ́съ, и҆ стрѧсѐ: запрети́ же і҆и҃съ дꙋ́хови нечи́стомꙋ, и҆ и҆сцѣлѝ ѻ҆́трока, и҆ вдадѐ є҆го̀ ѻ҆тцꙋ̀ є҆гѡ̀. дивлѧ́хꙋсѧ же всѝ ѡ҆ вели́чїи бж҃їи. ",
}

add_evangelie_luki {
  ["номер"] = 47,
  ["комментарий"] = "Лк., 47 зач., IX, 44–50.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: вложи́те вы во у́ши ва́ши словеса́ сия́: Сын бо Челове́ческий и́мать преда́тися в ру́це челове́честе. Они́ же не разуме́ша глаго́ла сего́, бе бо прикрове́н от них, да не ощутя́т его́, и боя́хуся вопроси́ти Его́ о глаго́ле сем. Вни́де же помышле́ние в них, кто их вя́щший бы был. Иису́с же ве́дый помышле́ние серде́ц их, прие́м отроча́, поста́ви е́ у Себе́ и рече́ им: и́же а́ще прии́мет сие́ отроча́ во и́мя Мое́, Мене́ прие́млет, и и́же а́ще Мене́ прие́млет, прие́млет Посла́вшаго Мя, и́же бо ме́ньший есть в вас, сей есть вели́к. Отвеща́в же Иоа́нн рече́: Наста́вниче, ви́дехом не́коего о и́мени Твое́м изгоня́ща бе́сы, и возбрани́хом ему́, я́ко в след не хо́дит с на́ми. И рече́ к нему́ Иису́с: не брани́те, и́же бо несть на вы, по вас есть. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: вложи́те вы̀ во ᲂу҆́ши ва́ши словеса̀ сїѧ̀: сн҃ъ бо человѣ́ческїй и҆́мать преда́тисѧ въ рꙋ́цѣ человѣ́честѣ. ѻ҆ни́ же не разꙋмѣ́ша глаго́ла сегѡ̀, бѣ́ бо прикрове́нъ ѿ ни́хъ, да не ѡ҆щꙋтѧ́тъ є҆го̀: и҆ боѧ́хꙋсѧ вопроси́ти є҆го̀ ѡ҆ глаго́лѣ се́мъ. вни́де же помышле́нїе въ ни́хъ: кто̀ и҆́хъ вѧ́щшїй бы бы́лъ; і҆и҃съ же вѣ́дый помышле́нїе серде́цъ и҆́хъ, прїе́мъ ѻ҆троча̀, поста́ви є҆̀ ᲂу҆ себѐ, и҆ речѐ и҆̀мъ: и҆́же а҆́ще. прїи́метъ сїѐ ѻ҆троча̀ во и҆́мѧ моѐ, менѐ прїе́млетъ: и҆ и҆́же а҆́ще менѐ прїе́млетъ, прїе́млетъ посла́вшаго мѧ̀: и҆́же бо ме́ньшїй є҆́сть въ ва́съ, се́й є҆́сть вели́къ. ѿвѣща́въ же і҆ѡа́ннъ, речѐ: наста́вниче, ви́дѣхомъ нѣ́коего ѡ҆ и҆́мени твое́мъ и҆згонѧ́ща бѣ́сы, и҆ возбрани́хомъ є҆мꙋ̀, ꙗ҆́кѡ во слѣ́дъ не хо́дитъ съ на́ми. и҆ речѐ къ немꙋ̀ і҆и҃съ, не брани́те: и҆́же бо нѣ́сть на вы̀, по ва́съ є҆́сть. ",
}

add_evangelie_luki {
  ["номер"] = 48,
  ["комментарий"] = "Лк., 48 зач., IX, 49–56.",
  ["текст_ру"] = "Во вре́мя о́но, приступи́ ко Иису́су еди́н от учени́к Его́, и рече́ Ему́: Наста́вниче, ви́дехом не́коего о и́мени Твое́м изгоня́ща бе́сы, и возбрани́хом ему́, я́ко во след не хо́дит с на́ми. И рече́ к нему́ Иису́с: не брани́те, и́же бо несть на вы, по вас есть. Бысть же егда́ скончава́хуся дни́е восхожде́нию Его́, и Той утверди́ лице́ Свое́ ити́ во Иерусали́м. И посла́ ве́стники пред лице́м Свои́м, и изше́дше внидо́ша в весь Самаря́нску, я́ко да угото́вят Ему́. И не прия́ша Его́, я́ко лице́ Его́ бе гряды́й во Иерусали́м. Ви́девша же ученика́ Его́ Иа́ков и Иоа́нн, ре́ста: Го́споди, хо́щеши ли, рече́ма, да огнь сни́дет с небесе́ и потреби́т их, я́коже и Илиа́ сотвори́? Обра́щься же запрети́ и́ма, и рече́: не ве́ста, ко́его ду́ха еста́ вы. Сын бо Челове́ческий не прии́де душ челове́ческих погуби́ти, но спасти́. И идо́ша во и́ну весь. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋпѝ ко і҆и҃сꙋ є҆ди́нъ ѿ ᲂу҆чени́къ є҆гѡ̀, и҆ речѐ є҆мꙋ̀: наста́вниче, ви́дѣхомъ нѣ́коего ѡ҆ и҆́мени твое́мъ и҆згонѧ́ща бѣ́сы, и҆ возбрани́хомъ є҆мꙋ̀, ꙗ҆́кѡ во слѣ́дъ не хо́дитъ съ на́ми. и҆ речѐ къ немꙋ̀ і҆и҃съ, не брани́те: и҆́же бо нѣ́сть на вы̀, по ва́съ є҆́сть. бы́сть же, є҆гда̀ скончава́хꙋсѧ дні́е восхожде́нїю є҆гѡ̀, и҆ то́й ᲂу҆твердѝ лицѐ своѐ и҆тѝ во і҆ерꙋсали́мъ. и҆ посла̀ вѣ́стники пред̾ лице́мъ свои́мъ: и҆ и҆зше́дше внидо́ша въ ве́сь самарѧ́нскꙋ, ꙗ҆́кѡ да ᲂу҆гото́вѧтъ є҆мꙋ̀. и҆ не прїѧ́ша є҆гѡ̀, ꙗ҆́кѡ лицѐ є҆гѡ̀ бѣ̀ грѧды́й во і҆ерꙋсали́мъ. ви́дѣвша же ᲂу҆чєника̀ є҆гѡ̀ і҆а́кѡвъ и҆ і҆ѡа́ннъ, рѣ́ста: гдⷭ҇и, хо́щеши ли, рече́ма, да ѻ҆́гнь сни́детъ съ нб҃сѐ, и҆ потреби́тъ и҆̀хъ, ꙗ҆́коже и҆ и҆лїа̀ сотворѝ; ѡ҆бра́щсѧ же запретѝ и҆́ма, и҆ речѐ: не вѣ́ста, ко́егѡ дꙋ́ха є҆ста̀ вы̀. сн҃ъ бо человѣ́ческїй не прїи́де дꙋ́шъ человѣ́ческихъ погꙋби́ти, но спастѝ: и҆ и҆до́ша во и҆́нꙋ ве́сь. ",
}

add_evangelie_luki {
  ["номер"] = 48,
  ["комментарий"] = "Лк., 48 зач., IX, 51-56; X, 22-24.",
  ["текст_ру"] = "Во вре́мя о́но, бысть егда́ скончава́хуся дни́е восхожде́нию Иису́сову, и Той утверди́ лице́ Свое́ ити́ во Иерусали́м. И посла́ ве́стники пред лице́м Свои́м, и изше́дше внидо́ша в весь Самаря́нску, я́ко да угото́вят Ему́. И не прия́ша Его́, я́ко лице́ Его́ бе гряды́й во Иерусали́м. Ви́девша же ученика́ Его́ Иа́ков и Иоа́нн, ре́ста: Го́споди, хо́щеши ли, рече́ма, да огнь сни́дет с небесе́ и потреби́т их, я́коже и Илиа́ сотвори́? Обра́щься же запрети́ и́ма, и рече́: не ве́ста, ко́его ду́ха еста́ вы. Сын бо Челове́ческий не прии́де душ челове́ческих погуби́ти, но спасти́. И идо́ша во и́ну весь. И обра́щься ко ученико́м, рече́: вся Мне предана́ бы́ша от Отца́ Моего́, и никто́же весть, кто есть Сын, то́кмо Оте́ц: и кто есть Оте́ц, то́кмо Сын, и ему́же а́ще хо́щет Сын откры́ти. И обра́щься ко ученико́м, еди́н рече́: блаже́ни о́чи ви́дящии, я́же ви́дите. Глаго́лю бо вам, я́ко мно́зи проро́цы и ца́рие восхоте́ша ви́дети, я́же вы ви́дите, и не ви́деша, и слы́шати, я́же слы́шите, и не слы́шаша. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бы́сть є҆гда̀ скончава́хꙋсѧ дні́е восхожде́нїю і҆и҃совꙋ, и҆ то́й ᲂу҆твердѝ лицѐ своѐ и҆тѝ во і҆ерꙋсали́мъ. и҆ посла̀ вѣ́стники пред̾ лице́мъ свои́мъ: и҆ и҆зше́дше внидо́ша въ ве́сь самарѧ́нскꙋ, ꙗ҆́кѡ да ᲂу҆гото́вѧтъ є҆мꙋ̀. и҆ не прїѧ́ша є҆гѡ̀, ꙗ҆́кѡ лицѐ є҆гѡ̀ бѣ̀ грѧды́й во і҆ерꙋсали́мъ. ви́дѣвша же ᲂу҆чєника̀ є҆гѡ̀ і҆а́кѡвъ и҆ і҆ѡа́ннъ, рѣ́ста: гдⷭ҇и, хо́щеши ли, рече́ма, да ѻ҆́гнь сни́детъ съ нб҃сѐ, и҆ потреби́тъ и҆̀хъ, ꙗ҆́коже и҆ и҆лїа̀ сотворѝ; ѡ҆бра́щсѧ же запретѝ и҆́ма, и҆ речѐ: не вѣ́ста, ко́егѡ дꙋ́ха є҆ста̀ вы̀. сн҃ъ бо человѣ́ческїй не прїи́де дꙋ́шъ человѣ́ческихъ погꙋби́ти, но спастѝ: и҆ и҆до́ша во и҆́нꙋ ве́сь. и҆ ѡ҆бра́щсѧ ко ᲂу҆ченикѡ́мъ, речѐ: всѧ̑ мнѣ̀ предана̀ бы́ша ѿ ѻ҆ц҃а̀ моегѡ̀: и҆ никто́же вѣ́сть кто̀ є҆́сть сн҃ъ, то́кмѡ ѻ҆ц҃ъ: и҆ кто̀ є҆́сть ѻ҆ц҃ъ, то́кмѡ сн҃ъ, и҆ є҆мꙋ́же а҆́ще хо́щетъ сн҃ъ ѿкры́ти. и҆ ѡ҆бра́щсѧ ко ᲂу҆ченикѡ́мъ, є҆ди́нъ речѐ: блаже́ни ѻ҆́чи ви́дѧщїи, ꙗ҆̀же ви́дите. глаго́лю бо ва́мъ: ꙗ҆́кѡ мно́зи проро́цы и҆ ца́рїе восхотѣ́ша ви́дѣти, ꙗ҆̀же вы̀ ви́дите, и҆ не ви́дѣша: и҆ слы́шати ꙗ҆̀же слы́шите, и҆ не слы́шаша. ",
}

add_evangelie_luki {
  ["номер"] = 49,
  ["комментарий"] = "Лк., 49 зач., IX, 57–62.",
  ["текст_ру"] = "Во вре́мя о́но, иду́щу Иису́су по пути́, рече́ не́кий к Нему́: иду́ по Тебе́, а́може а́ще и́деши, Го́споди. И рече́ ему́ Иису́с: ли́си я́звины и́мут, и пти́цы небе́сныя гне́зда, Сын же Челове́ческий не и́мать где главу́ подклони́ти. Рече́ же ко друго́му: ходи́ в след Мене́. Он же рече́: Го́споди, повели́ ми, да шед пре́жде погребсти́ отца́ моего́. Рече́ же ему́ Иису́с: оста́ви ме́ртвыя погребсти́ своя́ мертвецы́, ты же шед возвеща́й Ца́рствие Бо́жие. Рече́ же и други́й: иду́ по Тебе́, Го́споди, пре́жде же повели́ ми отвеща́ти ми ся, и́же суть в дому́ мое́м. Рече́ же к нему́ Иису́с: никто́же возло́ж ру́ку свою́ на ра́ло и зря вспять, упра́влен есть в Ца́рствии Бо́жии. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆дꙋ́щꙋ і҆и҃сꙋ по пꙋтѝ, речѐ нѣ́кїй къ немꙋ̀: и҆дꙋ̀ по тебѣ̀, а҆́може а҆́ще и҆́деши, гдⷭ҇и. и҆ речѐ є҆мꙋ̀ і҆и҃съ: ли́си ꙗ҆́звины и҆́мꙋтъ, и҆ пти̑цы нбⷭ҇ныѧ гнѣ́зда. сн҃ъ же человѣ́ческїй не и҆́мать гдѣ̀ главꙋ̀ подклони́ти. рече́ же ко дрꙋго́мꙋ: ходѝ въ слѣ́дъ менѐ. ѻ҆́нъ же речѐ: гдⷭ҇и, повели́ ми да ше́дъ пре́жде погребстѝ ѻ҆тца̀ моего̀. рече́ же є҆мꙋ̀ і҆и҃съ: ѡ҆ста́ви ме́ртвыѧ погребстѝ своѧ̀ мертвецы̀: ты́ же ше́дъ возвѣща́й црⷭ҇твїе бж҃їе. рече́ же и҆ дрꙋгі́й: и҆дꙋ̀ по тебѣ̀ гдⷭ҇и: пре́жде же повели́ ми ѿвѣща́ти ми сѧ и҆̀же сꙋ́ть въ домꙋ̀ мое́мъ. рече́ же къ немꙋ̀ і҆и҃съ: никто́же возло́жъ рꙋ́кꙋ свою̀ на ра́ло, и҆ зрѧ̀ вспѧ́ть, ᲂу҆пра́вленъ є҆́сть въ црⷭ҇твїи бж҃їи. ",
}

add_evangelie_luki {
  ["номер"] = 50,
  ["комментарий"] = "Лк., 50 зач., X, 1–15.",
  ["текст_ру"] = "Во вре́мя о́но, яви́ Госпо́дь и ине́х се́дмьдесят учени́к Свои́х, и посла́ их по двема́ пред лице́м Свои́м во всяк град и ме́сто, а́може хотя́ше Сам ити́. Глаго́лаше же к ним: жа́тва у́бо мно́га, де́лателей же ма́ло, моли́теся у́бо Господи́ну жа́тве, да изведе́т де́латели на жа́тву Свою́. Иди́те, се Аз посыла́ю вы я́ко а́гнцы посреде́ волко́в. Не носи́те влага́лища, ни пи́ры, ни сапоги́, и никого́же на пути́ целу́йте. Во́ньже а́ще дом вни́дете, пе́рвее глаго́лите: мир до́му сему́. И а́ще у́бо бу́дет ту сын ми́ра, почи́ет на нем мир ваш, а́ще ли же ни, к вам возврати́тся. В том же дому́ пребыва́йте, я́дуще и пию́ще, я́же суть у них, досто́ин бо есть де́латель мзды своея́. Не преходи́те из до́му в дом. И во́ньже а́ще град вхо́дите, и прие́млют вы, яди́те предлага́емая вам, и исцели́те неду́жныя, и́же суть в нем, и глаго́лите им: прибли́жися на вы Ца́рствие Бо́жие. И во́ньже а́ще град вхо́дите, и не прие́млют вас, изше́дше на распу́тия его́, рцы́те: и прах, приле́пший нам от гра́да ва́шего, оттряса́ем вам. Оба́че сие́ ве́дите, я́ко прибли́жися на вы Ца́рствие Бо́жие. Глаго́лю вам, я́ко Содо́мляном в день той отра́днее бу́дет, не́же гра́ду тому́. Го́ре тебе́, Хорази́не, го́ре тебе́, Вифсаи́до, я́ко а́ще в Ти́ре и Сидо́не бы́ша си́лы бы́ли бы́вшыя в ва́ю, дре́вле у́бо во вре́тищи и пе́пеле седя́ще пока́ялися бы́ша, оба́че Ти́ру и Сидо́ну отра́днее бу́дет на суде́, не́же ва́ма. И ты, Капернау́ме, и́же до небе́с вознесы́йся, до а́да низведе́шися. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ꙗ҆вѝ гдⷭ҇ь и҆ и҆нѣ́хъ се́дмьдесѧтъ ᲂу҆чени̑къ свои́хъ, и҆ посла̀ и҆̀хъ по двѣма̀ пред̾ лице́мъ свои́мъ, во всѧ́къ гра́дъ и҆ мѣ́сто, а҆́може хотѧ́ше са́мъ и҆тѝ. глаго́лаше же къ ни́мъ: жа́тва ᲂу҆́бѡ мно́га, дѣ́лателей же ма́лѡ: моли́тесѧ ᲂу҆́бѡ господи́нꙋ жа́твѣ, да и҆зведе́тъ дѣ́латели на жа́твꙋ свою̀. и҆ди́те: сѐ а҆́зъ посыла́ю вы̀ ꙗ҆́кѡ а҆́гнцы посредѣ̀ волкѡ́въ. не носи́те влага́лища, ни пи́ры, ни сапогѝ: и҆ никого́же на пꙋтѝ цѣлꙋ́йте. во́ньже а҆́ще до́мъ вни́дете, пе́рвѣе глаго́лите: ми́ръ до́мꙋ семꙋ̀. и҆ а҆́ще ᲂу҆́бѡ бꙋ́детъ тꙋ̀ сы́нъ ми́ра, почі́етъ на не́мъ ми́ръ ва́шъ: а҆́ще ли же нѝ, къ ва́мъ возврати́тсѧ. въ то́мъ же домꙋ̀ пребыва́йте, ꙗ҆дꙋ́ще и҆ пїю́ще ꙗ҆̀же сꙋ́ть ᲂу҆ ни́хъ: досто́инъ бо є҆́сть дѣ́латель мзды̀ своеѧ̀. не преходи́те и҆з̾ до́мꙋ въ до́мъ. и҆ во́ньже а҆́ще гра́дъ вхо́дите, и҆ прїе́млютъ вы̀, ꙗ҆ди́те предлага́ємаѧ ва́мъ. и҆ и҆сцѣли́те недꙋ̑жныѧ, и҆̀же сꙋ́ть въ не́мъ, и҆ глаго́лите и҆̀мъ: прибли́жисѧ на вы̀ црⷭ҇твїе бж҃їе. и҆ во́ньже а҆́ще гра́дъ вхо́дите, и҆ не прїе́млютъ ва́съ, и҆зше́дше на распꙋ̑тїѧ є҆гѡ̀, рцы́те: и҆ пра́хъ прилѣ́пшїй на́мъ ѿ гра́да ва́шегѡ, ѿтрѧса́емъ ва́мъ: ѻ҆ба́че сїѐ вѣ́дите, ꙗ҆́кѡ прибли́жисѧ на вы̀ црⷭ҇твїе бж҃їе. глаго́лю ва́мъ, ꙗ҆́кѡ содо́млѧнѡмъ въ де́нь то́й ѿра́днѣе бꙋ́детъ, не́же гра́дꙋ томꙋ̀. го́ре тебѣ̀ хорази́не, го́ре тебѣ̀ виѳсаі́до, ꙗ҆́кѡ а҆́ще въ тѵ́рѣ и҆ сїдѡ́нѣ бы́ша си̑лы бы́ли бы́вшыѧ въ ва́ю, дре́вле ᲂу҆́бѡ во вре́тищи и҆ пе́пелѣ сѣдѧ́ще пока́ѧлисѧ бы́ша. ѻ҆ба́че тѵ́рꙋ и҆ сїдѡ́нꙋ ѿра́днѣе бꙋ́детъ на сꙋдѣ̀, не́же ва́ма. и҆ ты̀ капернаꙋ́ме, и҆́же до небе́съ вознесы́йсѧ, до а҆́да низведе́шисѧ. ",
}

add_evangelie_luki {
  ["номер"] = 50,
  ["комментарий"] = "Лк., 50 зач., X, 1-21.",
  ["текст_ру"] = "Во вре́мя о́но, яви́ Госпо́дь и ине́х се́дмьдесят учени́к Свои́х, и посла́ их по двема́ пред лице́м Свои́м во всяк град и ме́сто, а́може хотя́ше Сам ити́. Глаго́лаше же к ним: жа́тва у́бо мно́га, де́лателей же ма́ло, моли́теся у́бо Господи́ну жа́тве, да изведе́т де́латели на жа́тву Свою́. Иди́те, се Аз посыла́ю вы я́ко а́гнцы посреде́ волко́в. Не носи́те влага́лища, ни пи́ры, ни сапоги́, и никого́же на пути́ целу́йте. Во́ньже а́ще дом вни́дете, пе́рвее глаго́лите: мир дому́ сему́. И а́ще у́бо бу́дет ту сын ми́ра, почи́ет на нем мир ваш, а́ще ли же ни, к вам возврати́тся. В том же дому́ пребыва́йте, яду́ще и пию́ще, я́же суть у них, досто́ин бо есть де́латель мзды своея́. Не преходи́те из до́му в дом. И во́ньже а́ще град вхо́дите, и прие́млют вы, яди́те предлага́емая вам, и исцели́те неду́жныя, и́же суть в нем, и глаго́лите им: прибли́жися на вы Ца́рствие Бо́жие. И во́ньже а́ще град вхо́дите, и не прие́млют вас, изше́дше на распу́тия его́, рцы́те: и прах, приле́пший нас от гра́да ва́шего, оттряса́ем вам. Оба́че сие́ ве́дите, я́ко прибли́жися на вы Ца́рствие Бо́жие. Глаго́лю вам, я́ко Содо́мляном в день той отра́днее бу́дет, не́же гра́ду тому́. Го́ре тебе́, Хорази́не, го́ре тебе́, Вифсаи́до, я́ко а́ще в Ти́ре и Сидо́не бы́ша си́лы бы́ли бы́вшыя в ва́ю, дре́вле у́бо во вре́тищи и пе́пеле седя́ще пока́ялися бы́ша, оба́че Ти́ру и Сидо́ну отра́днее бу́дет на суде́, не́же ва́ма. И ты, Капернау́ме, и́же до небе́с вознесы́йся, до а́да низведе́шися. Слу́шаяй вас, Мене́ слу́шает, и отмета́яйся вас, Мене́ отмета́ется, отмета́яйся же Мене́, отмета́ется Посла́вшаго Мя. Возврати́шася же се́дмьдесят с ра́достию, глаго́люще: Го́споди, и бе́си повину́ются нам о и́мени Твое́м. Рече́ же им: ви́дех сатану́ я́ко мо́лнию с небесе́ спа́дша. Се, даю́ вам власть наступа́ти на змию́ и на скорпи́ю и на всю си́лу вра́жию, и ничесо́же вас вреди́т. Оба́че о сем не ра́дуйтеся, я́ко ду́си вам повину́ются, ра́дуйтеся же, я́ко имена́ ва́ша напи́сана суть на небесе́х. В той час возра́довася ду́хом Иису́с и рече́: испове́даю Ти ся, О́тче, Го́споди небесе́ и земли́, я́ко утаи́л еси́ сия́ от прему́дрых и разу́мных, и откры́л еси́ та младе́нцем, ей, О́тче, я́ко та́ко бысть благоволе́ние пред Тобо́ю. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ꙗ҆вѝ гдⷭ҇ь и҆ и҆нѣ́хъ се́дмьдесѧтъ ᲂу҆чени̑къ свои́хъ, и҆ посла̀ и҆̀хъ по двѣма̀ пред̾ лице́мъ свои́мъ, во всѧ́къ гра́дъ и҆ мѣ́сто, а҆́може хотѧ́ше са́мъ и҆тѝ. глаго́лаше же къ ни́мъ: жа́тва ᲂу҆́бѡ мно́га, дѣ́лателей же ма́лѡ: моли́тесѧ ᲂу҆́бѡ господи́нꙋ жа́твѣ, да и҆зведе́тъ дѣ́латели на жа́твꙋ свою̀. и҆ди́те: сѐ а҆́зъ посыла́ю вы̀ ꙗ҆́кѡ а҆́гнцы посредѣ̀ волкѡ́въ. не носи́те влага́лища, ни пи́ры, ни сапогѝ: и҆ никого́же на пꙋтѝ цѣлꙋ́йте. во́ньже а҆́ще до́мъ вни́дете, пе́рвѣе глаго́лите: ми́ръ до́мꙋ семꙋ̀. и҆ а҆́ще ᲂу҆́бѡ бꙋ́детъ тꙋ̀ сы́нъ ми́ра, почі́етъ на не́мъ ми́ръ ва́шъ: а҆́ще ли же нѝ, къ ва́мъ возврати́тсѧ. въ то́мъ же домꙋ̀ пребыва́йте, ꙗ҆дꙋ́ще и҆ пїю́ще ꙗ҆̀же сꙋ́ть ᲂу҆ ни́хъ: досто́инъ бо є҆́сть дѣ́латель мзды̀ своеѧ̀. не преходи́те и҆з̾ до́мꙋ въ до́мъ. и҆ во́ньже а҆́ще гра́дъ вхо́дите, и҆ прїе́млютъ вы̀, ꙗ҆ди́те предлага́ємаѧ ва́мъ. и҆ и҆сцѣли́те недꙋ̑жныѧ, и҆̀же сꙋ́ть въ не́мъ, и҆ глаго́лите и҆̀мъ: прибли́жисѧ на вы̀ црⷭ҇твїе бж҃їе. и҆ во́ньже а҆́ще гра́дъ вхо́дите, и҆ не прїе́млютъ ва́съ, и҆зше́дше на распꙋ̑тїѧ є҆гѡ̀, рцы́те: и҆ пра́хъ прилѣ́пшїй на́мъ ѿ гра́да ва́шегѡ, ѿтрѧса́емъ ва́мъ: ѻ҆ба́че сїѐ вѣ́дите, ꙗ҆́кѡ прибли́жисѧ на вы̀ црⷭ҇твїе бж҃їе. глаго́лю ва́мъ, ꙗ҆́кѡ содо́млѧнѡмъ въ де́нь то́й ѿра́днѣе бꙋ́детъ, не́же гра́дꙋ томꙋ̀. го́ре тебѣ̀ хорази́не, го́ре тебѣ̀ виѳсаі́до, ꙗ҆́кѡ а҆́ще въ тѵ́рѣ и҆ сїдѡ́нѣ бы́ша си̑лы бы́ли бы́вшыѧ въ ва́ю, дре́вле ᲂу҆́бѡ во вре́тищи и҆ пе́пелѣ сѣдѧ́ще пока́ѧлисѧ бы́ша. ѻ҆ба́че тѵ́рꙋ и҆ сїдѡ́нꙋ ѿра́днѣе бꙋ́детъ на сꙋдѣ̀, не́же ва́ма. и҆ ты̀ капернаꙋ́ме, и҆́же до небе́съ вознесы́йсѧ, до а҆́да низведе́шисѧ. слꙋ́шаѧй ва́съ, менѐ слꙋ́шаетъ: и҆ ѿмета́ѧйсѧ ва́съ, менѐ ѿмета́етсѧ. ѿмета́ѧйсѧ же менѐ, ѿмета́етсѧ посла́вшагѡ мѧ̀. возврати́шасѧ же се́дмьдесѧтъ съ ра́достїю, глаго́люще: гдⷭ҇и, и҆ бѣ́си повинꙋ́ютсѧ на́мъ ѡ҆ и҆́мени твое́мъ. рече́ же и҆̀мъ: ви́дѣхъ сатанꙋ̀ ꙗ҆́кѡ мо́лнїю съ небесѐ спа́дша. сѐ даю̀ ва́мъ вла́сть настꙋпа́ти на ѕмїю̀, и҆ на скорпі́ю, и҆ на всю̀ си́лꙋ вра́жїю: и҆ ничесо́же ва́съ вреди́тъ. ѻ҆ба́че ѡ҆ се́мъ не ра́дꙋйтесѧ, ꙗ҆́кѡ дꙋ́си ва́мъ повинꙋ́ютсѧ: ра́дꙋйтесѧ же, ꙗ҆́кѡ и҆мена̀ ва́ша напи́сана сꙋ́ть на небесѣ́хъ. въ то́й ча́съ возра́довасѧ дх҃омъ і҆и҃съ, и҆ речѐ: и҆сповѣ́даю ти сѧ ѻ҆́ч҃е, гдⷭ҇и небесѐ и҆ землѝ, ꙗ҆́кѡ ᲂу҆таи́лъ є҆сѝ сїѧ̑ ѿ премꙋ́дрыхъ и҆ разꙋ́мныхъ, и҆ ѿкры́лъ є҆сѝ та̑ младе́нцємъ: є҆́й ѻ҆́ч҃е, ꙗ҆́кѡ та́кѡ бы́сть благоволе́нїе пред̾ тобо́ю. ",
}

add_evangelie_luki {
