add_evangelie_luki {
  ["номер"] = 51,
  ["комментарий"] = "Лк., 51 зач., X, 19–21.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: се даю́ вам власть наступа́ти на змию́ и на скорпи́ю и на всю си́лу вра́жию, и ничесо́же вас вреди́т. Оба́че о сем не ра́дуйтеся, я́ко ду́си вам повину́ются, ра́дуйтеся же, я́ко имена́ ва́ша напи́сана суть на небесе́х. В той час возра́довася ду́хом Иису́с и рече́: испове́даю Ти ся, О́тче, Го́споди небесе́ и земли́, я́ко утаи́л еси́ сия́ от прему́дрых и разу́мных, и откры́л еси́ та младе́нцем, ей, О́тче, я́ко та́ко бысть благоволе́ние пред Тобо́ю. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: сѐ даю̀ ва́мъ вла́сть настꙋпа́ти на ѕмїю̀, и҆ на скорпі́ю, и҆ на всю̀ си́лꙋ вра́жїю: и҆ ничесо́же ва́съ вреди́тъ. ѻ҆ба́че ѡ҆ се́мъ не ра́дꙋйтесѧ, ꙗ҆́кѡ дꙋ́си ва́мъ повинꙋ́ютсѧ: ра́дꙋйтесѧ же, ꙗ҆́кѡ и҆мена̀ ва́ша напи́сана сꙋ́ть на небесѣ́хъ. въ то́й ча́съ возра́довасѧ дх҃омъ і҆и҃съ, и҆ речѐ: и҆сповѣ́даю ти сѧ ѻ҆́ч҃е, гдⷭ҇и небесѐ и҆ землѝ, ꙗ҆́кѡ ᲂу҆таи́лъ є҆сѝ сїѧ̑ ѿ премꙋ́дрыхъ и҆ разꙋ́мныхъ, и҆ ѿкры́лъ є҆сѝ та̑ младе́нцємъ: є҆́й ѻ҆́ч҃е, ꙗ҆́кѡ та́кѡ бы́сть благоволе́нїе пред̾ тобо́ю. ",
}

add_evangelie_luki {
  ["номер"] = 52,
  ["комментарий"] = "Лк., 52 зач., X, 22–24.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: вся Мне предана́ бы́ша от Отца́ Моего́, и никто́же весть, кто есть Сын, то́кмо Оте́ц, и кто есть Оте́ц, то́кмо Сын, и ему́же а́ще хо́щет Сын откры́ти. И обра́щься ко ученико́м, еди́н рече́: блаже́ни о́чи ви́дящии, я́же ви́дите. Глаго́лю бо вам, я́ко мно́зи проро́цы и ца́рие восхоте́ша ви́дети, я́же вы ви́дите, и не ви́деша, и слы́шати, я́же слы́шите, и не слы́шаша. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: всѧ̑ мнѣ̀ предана̀ бы́ша ѿ ѻ҆ц҃а̀ моегѡ̀: и҆ никто́же вѣ́сть кто̀ є҆́сть сн҃ъ, то́кмѡ ѻ҆ц҃ъ: и҆ кто̀ є҆́сть ѻ҆ц҃ъ, то́кмѡ сн҃ъ, и҆ є҆мꙋ́же а҆́ще хо́щетъ сн҃ъ ѿкры́ти. и҆ ѡ҆бра́щсѧ ко ᲂу҆ченикѡ́мъ, є҆ди́нъ речѐ: блаже́ни ѻ҆́чи ви́дѧщїи, ꙗ҆̀же ви́дите. глаго́лю бо ва́мъ: ꙗ҆́кѡ мно́зи проро́цы и҆ ца́рїе восхотѣ́ша ви́дѣти, ꙗ҆̀же вы̀ ви́дите, и҆ не ви́дѣша: и҆ слы́шати ꙗ҆̀же слы́шите, и҆ не слы́шаша. ",
}

add_evangelie_luki {
  ["номер"] = 53,
  ["комментарий"] = "Лк., 53 зач., X, 25–37.",
  ["текст_ру"] = "Во вре́мя о́но, зако́нник не́кий приступи́ ко Иису́су, искуша́я Его́ и глаго́ля: Учи́телю, что сотвори́в, живо́т ве́чный насле́дую? Он же рече́ к нему́: в зако́не что пи́сано есть? Ка́ко чте́ши? Он же отвеща́в рече́: возлю́биши Го́спода Бо́га твоего́ от всего́ се́рдца твоего́, и от всея́ души́ твоея́, и все́ю кре́постию твое́ю, и всем помышле́нием твои́м, и бли́жняго своего́ я́ко сам себе́. Рече́ же ему́: пра́во отвеща́ еси́, сие́ сотвори́, и жив бу́деши. Он же хотя́ оправди́тися сам, рече́ ко Иису́су: и кто есть бли́жний мой? Отвеща́в же Иису́с рече́: челове́к не́кий схожда́ше от Иерусали́ма во Иерихо́н, и в разбо́йники впаде́, и́же совле́кше его́, и я́звы возло́жше отидо́ша, оста́вльше е́ле жи́ва су́ща. По слу́чаю же свяще́нник не́кий схожда́ше путе́м тем, и ви́дев его́, мимои́де. Та́кожде же и леви́т, быв на том ме́сте, прише́д и ви́дев, мимои́де. Самаряни́н же не́кто гряды́й, прии́де над него́, и ви́дев его́, милосе́рдова, и присту́пль обвяза́ стру́пы его́, возлива́я ма́сло и вино́. Всади́в же его́ на свой скот, приведе́ его́ в гости́нницу и прилежа́ ему́, и нау́трия изше́д, изе́м два сре́бреника, даде́ гости́ннику и рече́ ему́: прилежи́ ему́, и е́же а́ще прииждиве́ши, аз егда́ возвращу́ся, возда́м ти. Кто у́бо от тех трие́х бли́жний мни́ттися бы́ти впа́дшему в разбо́йники? Он же рече́: сотвори́вый ми́лость с ним. Рече́ же ему́ Иису́с: иди́, и ты твори́ та́кожде. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, зако́нникъ нѣ́кїй пристꙋпѝ ко і҆и҃сꙋ, и҆скꙋша́ѧ є҆го̀, и҆ глаго́лѧ: ᲂу҆чи́телю, что̀ сотвори́въ живо́тъ вѣ́чный наслѣ́дꙋю; ѻ҆́нъ же речѐ къ немꙋ̀: въ зако́нѣ что̀ пи́сано є҆́сть; ка́кѡ чте́ши; ѻ҆́нъ же ѿвѣща́въ речѐ: возлю́биши гдⷭ҇а бг҃а твоего̀ ѿ всегѡ̀ се́рдца твоегѡ̀, и҆ ѿ всеѧ̀ дꙋшѝ твоеѧ̀, и҆ все́ю крѣ́постїю твое́ю, и҆ всѣ́мъ помышле́нїемъ твои́мъ: и҆ бли́жнѧго своего̀, ꙗ҆́кѡ са́мъ себѐ. рече́ же є҆мꙋ̀, пра́вѡ ѿвѣща̀ є҆сѝ, сїѐ сотворѝ, и҆ жи́въ бꙋ́деши. ѻ҆́нъ же хотѧ̀ ѡ҆правди́тисѧ са́мъ, речѐ ко і҆и҃сꙋ: и҆ кто́ є҆сть бли́жнїй мо́й; ѿвѣща́въ же і҆и҃съ речѐ: человѣ́къ нѣ́кїй схожда́ше ѿ і҆ерꙋсали́ма во і҆ерїхѡ́нъ, и҆ въ разбо́йники впадѐ, и҆̀же совле́кше є҆го̀, и҆ ꙗ҆́звы возло́жше ѿидо́ша, ѡ҆ста́вльше є҆́ле жи́ва сꙋ́ща. по слꙋ́чаю же сщ҃е́нникъ нѣ́кїй схожда́ше пꙋте́мъ тѣ́мъ: и҆ ви́дѣвъ є҆го̀, мимои́де. та́кожде же и҆ леѵі́тъ, бы́въ на то́мъ мѣ́стѣ, прише́дъ и҆ ви́дѣвъ, мимои́де. самарѧни́нъ же нѣ́кто грѧды́й, прїи́де над̾ него̀, и҆ ви́дѣвъ є҆го̀, милосе́рдова: и҆ пристꙋ́пль ѡ҆бвѧза̀ стрꙋ́пы є҆гѡ̀, возлива́ѧ ма́сло и҆ вїно̀: всади́въ же є҆го̀ на сво́й ско́тъ приведѐ є҆го̀ въ гости́нницꙋ, и҆ прилѣжа̀ є҆мꙋ̀. и҆ наꙋ́трїѧ и҆зше́дъ, и҆з̾е́мъ два̀ сре́бреника, дадѐ гости́нникꙋ, и҆ речѐ є҆мꙋ̀: прилѣжѝ є҆мꙋ̀, и҆ є҆́же а҆́ще прїиждиве́ши, а҆́зъ є҆гда̀ возвращꙋ́сѧ, возда́мъ тѝ. кто̀ ᲂу҆́бѡ ѿ тѣ́хъ трїе́хъ, бли́жнїй мни́ттисѧ бы́ти впа́дшемꙋ въ разбо́йники; ѻ҆́нъ же речѐ: сотвори́вый ми́лость съ ни́мъ. рече́ же є҆мꙋ̀ і҆и҃съ: и҆дѝ, и҆ ты̀ творѝ та́кожде. ",
}

add_evangelie_luki {
  ["номер"] = 54,
  ["комментарий"] = "Лк., 54 зач., X, 38–42; XI, 27–28.",
  ["текст_ру"] = "Во вре́мя о́но, вни́де Иису́с в весь не́кую, жена́ же не́кая и́менем Ма́рфа прия́т Его́ в дом свой. И сестра́ ей бе нарица́емая Мари́а, я́же и се́дши при ногу́ Иису́сову, слы́шаше сло́во Его́. Ма́рфа же мо́лвяше о мно́зе слу́жбе, ста́вши же рече́: Го́споди, не бреже́ши ли, я́ко сестра́ моя́ еди́ну мя оста́ви служи́ти; рцы у́бо ей, да ми помо́жет. Отвеща́в же Иису́с, рече́ ей: Ма́рфо, Ма́рфо, пече́шися и мо́лвиши о мно́зе. Еди́но же есть на потре́бу. Мари́а же благу́ю часть избра́, я́же не оты́мется от нея́. Бысть же егда́ глаго́лаше сия́, воздви́гши не́кая жена́ глас от наро́да, рече́ Ему́: блаже́но чре́во носи́вшее Тя, и сосца́, я́же еси́ ссал. Он же рече́: те́мже у́бо блаже́ни слы́шащии сло́во Бо́жие, и храня́ще е́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, вни́де і҆и҃съ въ ве́сь нѣ́кꙋю: жена́ же нѣ́каѧ и҆́менемъ ма́рѳа прїѧ́тъ є҆го̀ въ до́мъ сво́й. и҆ сестра̀ є҆́й бѣ̀ нарица́емаѧ марі́а, ꙗ҆́же и҆ сѣ́дши при ногꙋ̀ і҆и҃совꙋ слы́шаше сло́во є҆гѡ̀. ма́рѳа же мо́лвѧше ѡ҆ мно́зѣ слꙋ́жбѣ, ста́вши же речѐ: гдⷭ҇и, не бреже́ши ли, ꙗ҆́кѡ сестра̀ моѧ̀ є҆ди́нꙋ мѧ̀ ѡ҆ста́ви слꙋжи́ти; рцы̀ ᲂу҆́бѡ є҆́й, да мѝ помо́жетъ. ѿвѣща́въ же і҆и҃съ, речѐ є҆́й: ма́рѳо, ма́рѳо, пече́шисѧ, и҆ мо́лвиши ѡ҆ мно́зѣ. є҆ди́но же є҆́сть на потре́бꙋ: марі́а же благꙋ́ю ча́сть и҆збра̀, ꙗ҆́же не ѿи́метсѧ ѿ неѧ̀. бы́сть же є҆гда̀ глаго́лаше сїѧ̀, воздви́гши нѣ́каѧ жена̀ гла́съ ѿ наро́да, речѐ є҆мꙋ̀: блаже́но чре́во носи́вшее тѧ̀, и҆ сосца̀ ꙗ҆̀же є҆сѝ сса́лъ. ѻ҆́нъ же речѐ: тѣ́мже ᲂу҆́бѡ блаже́ни слы́шащїи сло́во бж҃їе, и҆ хранѧ́ще є҆̀. ",
}

add_evangelie_luki {
  ["номер"] = 55,
  ["комментарий"] = "Лк., 55 зач., XI, 1–10.",
  ["текст_ру"] = "Во вре́мя о́но, бысть внегда́ бы́ти Иису́су на ме́сте не́коем моля́щуся, и я́ко преста́, рече́ не́кий от учени́к Его́ к Нему́: Го́споди, научи́ ны моли́тися, я́коже и Иоа́нн научи́ ученики́ своя́. Рече́ же им: егда́ моли́теся, глаго́лите: О́тче наш, и́же на небесе́х, да святи́тся и́мя Твое́, да прии́дет Ца́рствие Твое́, да бу́дет во́ля Твоя́, я́ко на небеси́, и на земли́, хлеб наш насу́щный подава́й нам на всяк день, и оста́ви нам грехи́ на́ша, и́бо и са́ми оставля́ем вся́кому должнику́ на́шему, и не введи́ нас во искуше́ние, но изба́ви нас от лука́ваго. И рече́ к ним: кто от вас и́мать дру́га, и и́дет к нему́ в полу́нощи, и рече́т ему́: дру́же, даждь ми взаи́м три хле́бы, поне́же друг прии́де с пути́ ко мне, и не и́мам чесо́ предложи́ти ему́. И той извну́трь отвеща́в рече́т: не твори́ ми труды́, уже́ две́ри затворе́ны суть, и де́ти моя́ со мно́ю на ло́жи суть, и не могу́ воста́в да́ти тебе́. Глаго́лю же вам: а́ще и не даст ему́ воста́в, зане́ есть друг ему́, но за безо́чьство его́, воста́в даст ему́, ели́ка тре́бует. И Аз вам глаго́лю: проси́те, и да́стся вам, ищи́те, и обря́щете, толцы́те, и отве́рзется вам. Всяк бо прося́й прие́млет, и ищя́й обрета́ет, и толку́щему отве́рзется. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бы́сть внегда̀ бы́ти і҆и҃сꙋ на мѣ́стѣ нѣ́коемъ молѧ́щꙋсѧ, и҆ ꙗ҆́кѡ преста̀, речѐ нѣ́кїй ѿ ᲂу҆чєни́къ є҆гѡ̀ къ немꙋ̀: гдⷭ҇и, наꙋчи́ ны моли́тисѧ, ꙗ҆́коже и҆ і҆ѡа́ннъ наꙋчѝ ᲂу҆ченикѝ своѧ̀. рече́ же и҆̀мъ, є҆гда̀ мо́литесѧ, глаго́лите: ѻ҆́ч҃е на́шъ, и҆́же на нб҃сѣ́хъ! да ст҃и́тсѧ и҆́мѧ твоѐ: да прїи́детъ црⷭ҇твїе твоѐ: да бꙋ́детъ во́лѧ твоѧ̀, ꙗ҆́кѡ на нб҃сѝ, и҆ на землѝ. хлѣ́бъ на́шъ насꙋ́щный подава́й на́мъ на всѧ́къ де́нь. и҆ ѡ҆ста́ви на́мъ грѣхѝ на́шѧ: и҆́бо и҆ са́ми ѡ҆ставлѧ́емъ всѧ́комꙋ должникꙋ̀ на́шемꙋ: и҆ не введѝ на́съ во и҆скꙋше́нїе, но и҆зба́ви на́съ ѿ лꙋка́вагѡ. и҆ речѐ къ ни́мъ: кто̀ ѿ ва́съ и҆́мать дрꙋ́га, и҆ и҆́детъ къ немꙋ̀ въ полꙋ́нощи, и҆ рече́тъ є҆мꙋ̀: дрꙋ́же, да́ждь мѝ взаи́мъ трѝ хлѣ́бы. поне́же дрꙋ́гъ прїи́де съ пꙋтѝ ко мнѣ̀, и҆ не и҆́мамъ чесѡ̀ предложи́ти є҆мꙋ̀. и҆ то́й и҆звнꙋ́трь ѿвѣща́въ рече́тъ: не твори́ ми трꙋды̀: ᲂу҆жѐ двє́ри затворе́ны сꙋ́ть, и҆ дѣ́ти моѧ̀ со мно́ю на ло́жи сꙋ́ть, и҆ не могꙋ̀ воста́въ да́ти тебѣ̀. глаго́лю же ва́мъ, а҆́ще и҆ не да́стъ є҆мꙋ̀ воста́въ, занѐ є҆́сть дрꙋ́гъ є҆мꙋ̀: но за безѻ́чьство є҆гѡ̀ воста́въ да́стъ є҆мꙋ̀, є҆ли̑ка тре́бꙋетъ. и҆ а҆́зъ ва́мъ глаго́лю: проси́те и҆ да́стсѧ ва́мъ: и҆щи́те и҆ ѡ҆брѧ́щете: толцы́те и҆ ѿве́рзетсѧ ва́мъ. всѧ́къ бо просѧ́й прїе́млетъ, и҆ и҆щѧ́й ѡ҆брѣта́етъ: и҆ толкꙋ́щемꙋ ѿве́рзетсѧ. ",
}

add_evangelie_luki {
  ["номер"] = 56,
  ["комментарий"] = "Лк., 56 зач., XI, 9–13.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: проси́те, и да́стся вам, ищи́те, и обря́щете, толцы́те, и отве́рзется вам. Всяк бо прося́й прие́млет, и ищя́й обрета́ет, и толку́щему отве́рзется. Кото́раго же вас отца́ воспро́сит сын хле́ба, еда́ ка́мень пода́ст ему́? Или́ ры́бы, еда́ в ры́бы ме́сто змию́ пода́ст ему́? Или́ а́ще про́сит яица́, еда́ пода́ст ему́ скорпи́ю? А́ще у́бо вы зли су́ще, уме́ете дая́ния бла́га дая́ти ча́дом ва́шым, ко́льми па́че Оте́ц, и́же с небесе́, даст Ду́х Свят прося́щим у Него́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: проси́те и҆ да́стсѧ ва́мъ: и҆щи́те и҆ ѡ҆брѧ́щете: толцы́те и҆ ѿве́рзетсѧ ва́мъ. всѧ́къ бо просѧ́й прїе́млетъ, и҆ и҆щѧ́й ѡ҆брѣта́етъ: и҆ толкꙋ́щемꙋ ѿве́рзетсѧ. кото́рагѡ же ва́съ ѻ҆тца̀ воспро́ситъ сы́нъ хлѣ́ба: є҆да̀ ка́мень пода́стъ є҆мꙋ̀; и҆лѝ ры́бы, є҆да̀ къ ры́бы мѣ́сто ѕмїю̀ пода́стъ є҆мꙋ̀; и҆лѝ а҆́ще про́ситъ ꙗ҆ица̀, є҆да̀ пода́стъ є҆мꙋ̀ скорпі́ю; а҆́ще ᲂу҆́бѡ вы̀ ѕлѝ сꙋ́ще, ᲂу҆мѣ́ете даѧ̑нїѧ бла̑га даѧ́ти ча́дѡмъ ва́шымъ: кольмѝ па́че ѻ҆ц҃ъ, и҆́же съ нб҃сѐ, да́стъ дх҃ъ ст҃ъ просѧ́щымъ ᲂу҆ негѡ̀. ",
}

add_evangelie_luki {
  ["номер"] = 57,
  ["комментарий"] = "Лк., 57 зач., XI, 14–23.",
  ["текст_ру"] = "Во вре́мя о́но, бе Иису́с изгоня́ бе́са, и той бе нем, бысть же бе́су изше́дшу, проглаго́ла немы́й, и диви́шася наро́ди. Не́цыи же от них ре́ша: о веельзеву́ле кня́зе бесо́встем изго́нит бе́сы. Друзи́и же искуша́юще, зна́мения от Него́ иска́ху с небесе́. Он же ве́дый помышле́ния их, рече́ им: вся́ко ца́рство са́мо в себе́ разделя́яся, запусте́ет, и дом на дом, па́дает. А́ще же и сатана́ сам в себе́ раздели́ся, ка́ко ста́нет ца́рство его́, я́коже глаго́лете, о веельзеву́ле изгоня́ща Мя бе́сы. А́ще же Аз о веельзеву́ле изгоню́ бе́сы, сы́нове ва́ши о ком изго́нят? Сего́ ра́ди ти́и бу́дут вам судии́. А́ще ли же о пе́рсте Бо́жии изгоню́ бе́сы, у́бо пости́же на вас Ца́рствие Бо́жие. Егда́ кре́пкий вооружи́вся храни́т свой двор, во смире́нии суть име́ния его́. Егда́ же кре́плей его́ наше́д победи́т его́, все ору́жие его́ во́змет, на не́же упова́ше, и коры́сть его́ раздае́т. И́же несть со Мно́ю, на Мя есть, и и́же не собира́ет со Мно́ю, расточа́ет. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бѣ̀ і҆и҃съ и҆згонѧ̀ бѣ́са, и҆ то́й бѣ̀ нѣ́мъ: бы́сть же бѣ́сꙋ и҆зше́дшꙋ, проглаго́ла нѣмы́й: и҆ диви́шасѧ наро́ди. нѣ́цыи же ѿ ни́хъ рѣ́ша: ѡ҆ веелзевꙋ́лѣ кнѧ́зѣ бѣсо́встѣмъ и҆зго́нитъ бѣ́сы. дрꙋзі́и же и҆скꙋша́юще, зна́менїѧ ѿ негѡ̀ и҆ска́хꙋ съ небесѐ. ѻ҆́нъ же вѣ́дый помышлє́нїѧ и҆́хъ, речѐ и҆̀мъ: всѧ́ко ца́рство са́мо въ себѣ̀ раздѣлѧ́ѧсѧ, запꙋстѣ́етъ: и҆ до́мъ на до́мъ, па́даетъ. а҆́ще же и҆ сатана̀ са́мъ въ себѣ̀ раздѣли́сѧ, ка́кѡ ста́нетъ црⷭ҇тво є҆гѡ̀; ꙗ҆́коже глаго́лете, ѡ҆ веелзевꙋ́лѣ и҆згонѧ́ща мѧ̀ бѣ́сы. а҆́ще же а҆́зъ ѡ҆ веелзевꙋ́лѣ и҆згоню̀ бѣ́сы, сы́нове ва́ши ѡ҆ ко́мъ и҆зго́нѧтъ; сегѡ̀ ра́ди ті́и бꙋ́дꙋтъ ва́мъ сꙋдїѝ. а҆́ще ли же ѡ҆ пе́рстѣ бж҃їи и҆згоню̀ бѣ́сы, ᲂу҆̀бо пости́же на ва́съ црⷭ҇твїе бж҃їе. є҆гда̀ крѣ́пкїй воѡрꙋжи́всѧ храни́тъ сво́й дво́ръ, во смире́нїи сꙋ́ть и҆мѣ̑нїѧ є҆гѡ̀. є҆гда́ же крѣ́плѣй є҆гѡ̀ наше́дъ побѣди́тъ є҆го̀, всѐ ѻ҆рꙋ́жїе є҆гѡ̀ во́з̾метъ, на не́же ᲂу҆пова́ше, и҆ коры́сть є҆гѡ̀ раздае́тъ. и҆́же нѣ́сть со мно́ю, на мѧ̀ є҆́сть: и҆ и҆́же не собира́етъ со мно́ю, расточа́етъ. ",
}

add_evangelie_luki {
  ["номер"] = 58,
  ["комментарий"] = "Лк., 58 зач., XI, 23–26.",
  ["текст_ру"] = "Рече́ Госпо́дь: и́же несть со Мно́ю, на Мя есть, и и́же не собира́ет со Мно́ю, расточа́ет. Егда́ же нечи́стый дух изы́дет от челове́ка, прехо́дит сквозе́ безво́дная ме́ста, ищя́ поко́я, и не обрета́я, глаго́лет: возвращу́ся в дом мой, отню́дуже изыдо́х. И прише́д обря́щет и помете́н и украше́н, тогда́ и́дет и по́ймет седмь други́х духо́в го́рших себе́, и вше́дше живу́т ту, и быва́ют после́дняя челове́ку тому́ го́рша пе́рвых. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: и҆́же нѣ́сть со мно́ю, на мѧ̀ є҆́сть: и҆ и҆́же не собира́етъ со мно́ю, расточа́етъ. є҆гда́ же нечи́стый дꙋ́хъ и҆зы́детъ ѿ человѣ́ка, прехо́дитъ сквозѣ̀ безвѡ́днаѧ мѣ́ста, и҆щѧ̀ поко́ѧ, и҆ не ѡ҆брѣта́ѧ, глаго́летъ: возвращꙋ́сѧ въ до́мъ мо́й, ѿню́дꙋже и҆зыдо́хъ. и҆ прише́дъ ѡ҆брѧ́щетъ и҆̀ помете́нъ, и҆ ᲂу҆краше́нъ. тогда̀ и҆́детъ и҆ по́йметъ се́дмь дрꙋги́хъ дꙋхѡ́въ го́ршихъ себѐ, и҆ вше́дше живꙋ́тъ тꙋ̀. и҆ быва́ютъ послѣ̑днѧѧ человѣ́кꙋ томꙋ̀ го́рша пе́рвыхъ. ",
}

add_evangelie_luki {
  ["номер"] = 59,
  ["комментарий"] = "Лк., 59 зач., XI, 29–33.",
  ["текст_ру"] = "Во вре́мя о́но, наро́дом собира́ющымся, нача́т Иису́с глаго́лати: род сей лука́в есть, зна́мения и́щет, и зна́мение не да́стся ему́, то́кмо зна́мение Ио́ны проро́ка. Я́коже бо бысть Ио́на зна́мение Ниневи́том, та́ко бу́дет и Сын Челове́ческий ро́ду сему́. Цари́ца ю́жская воста́нет на суд с му́жи ро́да сего́, и осу́дит их, я́ко прии́де от коне́ц земли́ слы́шати прему́дрость Соломо́нову, и се мно́жае Соломо́на зде. Му́жие Ниневи́тстии воста́нут на суд с ро́дом сим и осу́дят и я́ко пока́яшася про́поведию Ио́ниною, и се мно́жае Ио́ны зде. Никто́же у́бо свети́льника вжег, в скро́ве полага́ет, ни под спу́дом, но на све́щнице, да входя́щии свет ви́дят. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, наро́дѡмъ собира́ющымсѧ, нача́тъ і҆и҃съ глаго́лати: ро́дъ се́й лꙋка́въ є҆́сть: зна́менїѧ и҆́щетъ, и҆ зна́менїе не да́стсѧ є҆мꙋ̀, то́кмѡ зна́менїе і҆ѡ́ны проро́ка. ꙗ҆́коже бо бы́сть і҆ѡ́на зна́менїе нїнеѵі́тѡмъ: та́кѡ бꙋ́детъ и҆ сн҃ъ чл҃вѣ́ческїй ро́дꙋ семꙋ̀. цари́ца ю҆́жскаѧ воста́нетъ на сꙋ́дъ съ мꙋ́жи ро́да сегѡ̀, и҆ ѡ҆сꙋ́дитъ и҆̀хъ, ꙗ҆́кѡ прїи́де ѿ конє́цъ землѝ слы́шати премꙋ́дрость соломѡ́новꙋ: и҆ сѐ мно́жае соломѡ́на здѣ̀. мꙋ́жїе нїнеѵі́тстїи воста́нꙋтъ на сꙋ́дъ съ ро́домъ си́мъ, и҆ ѡ҆сꙋ́дѧтъ и҆̀, ꙗ҆́кѡ пока́ѧшасѧ про́повѣдїю і҆ѡ́ниною: и҆ сѐ мно́жае і҆ѡ́ны здѣ̀. никто́же ᲂу҆́бѡ свѣти́льника вже́гъ въ скро́вѣ полага́етъ, ни под̾ спꙋ́домъ: но на свѣ́щницѣ, да входѧ́щїи свѣ́тъ ви́дѧтъ. ",
}

add_evangelie_luki {
  ["номер"] = 60,
  ["комментарий"] = "Лк., 60 зач., XI, 34–41.",
  ["текст_ру"] = "Рече́ Госпо́дь: свети́льник телу есть о́ко, егда́ у́бо о́ко твое́ про́сто бу́дет, все те́ло твое́ све́тло бу́дет, егда́ же лука́во бу́дет, и те́ло твое́ те́мно. Блюди́ у́бо, еда́ свет, и́же в тебе́, тма есть. А́ще бо те́ло твое́ все све́тло, не имы́й не́кия ча́сти те́мны, бу́дет све́тло все я́коже егда́ свети́льник блиста́нием просвеща́ет тя. Егда́ же глаго́лаше, моля́ше Его́ фарисе́й не́кий, да обе́дует у него́, вшед же возлеже́. Фарисе́й же ви́дев диви́ся, я́ко не пре́жде крести́ся пе́рвее обе́да. Рече́ же Госпо́дь к нему́: ны́не вы, фарисе́е, вне́шняя сткля́ницы и блю́да очища́ете, вну́треннее же ва́ше по́лно грабле́ния есть и лука́вства. Безу́мнии, не И́же ли сотвори́ вне́шнее, и вну́треннее сотвори́л есть? Оба́че от су́щих дади́те ми́лостыню, и се вся чи́ста вам бу́дут. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: свѣти́льникъ тѣ́лꙋ є҆́сть ѻ҆́ко, є҆гда̀ ᲂу҆́бѡ ѻ҆́ко твоѐ про́сто бꙋ́детъ, всѐ тѣ́ло твоѐ свѣ́тло бꙋ́детъ: є҆гда́ же лꙋка́во бꙋ́детъ, и҆ тѣ́ло твоѐ те́мно. блюдѝ ᲂу҆́бѡ, є҆да̀ свѣ́тъ, и҆́же въ тебѣ̀, тма̀ є҆́сть; а҆́ще бо тѣ́ло твоѐ всѐ свѣ́тло, не и҆мы́й нѣ́кїѧ ча́сти те́мны: бꙋ́детъ свѣ́тло всѐ, ꙗ҆кожѐ є҆гда̀ свѣти́льникъ блиста́нїемъ просвѣща́етъ тѧ̀. є҆гда́ же глаго́лаше, молѧ́ше є҆го̀ фарїсе́й нѣ́кїй, да ѻ҆бѣ́дꙋетъ ᲂу҆ негѡ̀: вше́дъ же возлежѐ. фарїсе́й же ви́дѣвъ диви́сѧ, ꙗ҆́кѡ не пре́жде крести́сѧ пе́рвѣе ѻ҆бѣ́да. рече́ же гдⷭ҇ь къ немꙋ̀: ны́нѣ вы̀ фарїсе́є, внѣ̑шнѧѧ стклѧ́ницы и҆ блю́да ѡ҆чища́ете: внꙋ́треннее же ва́ше по́лно грабле́нїѧ є҆́сть и҆ лꙋка́вства. безꙋ́мнїи, не и҆́же ли сотворѝ внѣ́шнее, и҆ внꙋ́треннее сотвори́лъ є҆́сть; ѻ҆ба́че въ сꙋ́щихъ дади́те ми́лостыню, и҆ сѐ всѧ̑ чи́ста ва́мъ бꙋ́дꙋтъ. ",
}

add_evangelie_luki {
  ["номер"] = 61,
  ["комментарий"] = "Лк., 61 зач., XI, 42–46.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: го́ре вам фарисе́ом, я́ко одеся́тствуете от мя́твы и пига́на и вся́каго зе́лия, и мимохо́дите суд и любве́ Бо́жию, сия́ же подоба́ше сотвори́ти, и о́нех не оставля́ти. Го́ре вам фарисе́ом, я́ко лю́бите председа́ния на со́нмищах и целова́ния на то́ржищех. Го́ре вам, кни́жницы и фарисе́е, лицеме́ри, я́ко есте́ я́ко гро́би неве́доми, и челове́цы ходя́щии верху́ не ве́дят. Отвеща́в же не́кий от зако́нник рече́ Ему́: Учи́телю, сия́ глаго́ля и нам досажда́еши. Он же рече́: и вам зако́нником го́ре, я́ко накла́даете на челове́ки бремена́ не удо́бь носи́ма, и са́ми еди́нем пе́рстом ва́шим не прикаса́етеся бремене́м. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: го́ре ва́мъ фарїсе́ѡмъ, ꙗ҆́кѡ ѡ҆десѧ́тствꙋете ѿ мѧ́твы и҆ пига́на, и҆ всѧ́кагѡ ѕе́лїѧ, и҆ мимохо́дите сꙋ́дъ и҆ любвѐ бж҃їѧ. сїѧ̑ же подоба́ше сотвори́ти, и҆ ѻ҆́нѣхъ не ѡ҆ставлѧ́ти. го́ре ва́мъ фарїсе́ѡмъ, ꙗ҆́кѡ лю́бите предсѣда̑нїѧ на со́нмищехъ, и҆ цѣлова̑нїѧ на то́ржищехъ. го́ре ва́мъ кни́жницы и҆ фарїсе́є лицемѣ́ри, ꙗ҆́кѡ є҆стѐ ꙗ҆́кѡ гро́би невѣ́доми, и҆ человѣ́цы ходѧ́щїи верхꙋ̀, не вѣ́дѧтъ. ѿвѣща́въ же нѣ́кїй ѿ закѡ́нникъ речѐ є҆мꙋ̀: ᲂу҆чи́телю, сїѧ̑ глаго́лѧ и҆ на́мъ досажда́еши. ѻ҆́нъ же речѐ: и҆ ва́мъ зако́нникѡмъ го́ре, ꙗ҆́кѡ накла́даете на человѣ́ки бремена̀ не ᲂу҆до́бь носи́ма, и҆ са́ми є҆ди́нѣмъ пе́рстомъ ва́шимъ не прикаса́етесѧ бременє́мъ. ",
}

add_evangelie_luki {
  ["номер"] = 62,
  ["комментарий"] = "Лк., 62 зач., XI, 47 – XII, 1.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: го́ре вам, кни́жницы и фарисе́е, я́ко зи́ждете гро́бы проро́к, отцы́ же ва́ши изби́ша их. У́бо свиде́тельствуете и сблаговолите́ дело́м оте́ц ва́ших, я́ко ти́и у́бо изби́ша их, вы же зи́ждете их гро́бы. Сего́ ра́ди и прему́дрость Бо́жия рече́: послю́ в них проро́ки и Апо́столы, и от них убию́т и изжену́т. Да взы́щется кровь всех проро́к, пролива́емая от сложе́ния ми́ра, от ро́да сего́, от кро́ве А́веля да́же до кро́ве Заха́рии, поги́бшаго между́ олтаре́м и хра́мом. Ей, глаго́лю вам, взы́щется от ро́да сего́. Го́ре вам зако́нником, я́ко взя́сте ключь разуме́ния, са́ми не внидо́сте, и входя́щым возбрани́сте. Глаго́лющу же Ему́ сия́ к ним, нача́ша кни́жницы и фарисе́е бе́дне гне́ватися Нань и преста́ти Его́ о мно́зе, ла́юще Его́, и́щуще улови́ти не́что от уст Его́, да Нань возглаго́лют. О ни́хже собра́вшымся тмам наро́да, я́ко попира́ти друг дру́га, нача́т глаго́лати ученико́м Свои́м пе́рвее, внемли́те себе́ от ква́са фарисе́йска, е́же есть лицеме́рие. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: го́ре ва́мъ кни́жницы и҆ фарїсе́є, ꙗ҆́кѡ зи́ждете гро́бы прорѡ́къ, ѻ҆тцы́ же ва́ши и҆зби́ша и҆̀хъ: Оу҆̀бо свидѣ́тельствꙋете и҆ с̾благоволитѐ дѣлѡ́мъ ѻ҆тє́цъ ва́шихъ: ꙗ҆́кѡ ті́и ᲂу҆́бѡ и҆зби́ша и҆̀хъ, вы́ же зи́ждете и҆́хъ гро́бы. сегѡ̀ ра́ди и҆ премꙋ́дрость бж҃їѧ речѐ: послю̀ въ ни́хъ проро́ки и҆ а҆по́столы, и҆ ѿ ни́хъ ᲂу҆бїю́тъ и҆ и҆зженꙋ́тъ. да взы́щетсѧ кро́вь всѣ́хъ прорѡ́къ, пролива́емаѧ ѿ сложе́нїѧ мі́ра, ѿ ро́да сегѡ̀, ѿ кро́ве а҆́велѧ, да́же до кро́ве заха́рїи, поги́бшагѡ междꙋ̀ ѻ҆лтаре́мъ и҆ хра́момъ. є҆́й, глаго́лю ва́мъ: взы́щетсѧ ѿ ро́да сегѡ̀. го́ре ва́мъ зако́нникѡмъ, ꙗ҆́кѡ взѧ́сте клю́чь разꙋмѣ́нїѧ, са́ми не внидо́сте, и҆ входѧ́щымъ возбрани́сте. глаго́лющꙋ же є҆мꙋ̀ сїѧ̑ къ ни́мъ, нача́ша кни́жницы и҆ фарїсе́є бѣ́днѣ гнѣ́ватисѧ на́нь, и҆ преста́ти є҆го̀ ѡ҆ мно́зѣ, ла́юще є҆го̀, и҆́щꙋще ᲂу҆лови́ти нѣ́что ѿ ᲂу҆́стъ є҆гѡ̀, да на́нь возглаго́лютъ. ѡ҆ ни́хже собра́вшымсѧ тма́мъ наро́да, ꙗ҆́кѡ попира́ти дрꙋ́гъ дрꙋ́га, нача́тъ глаго́лати ᲂу҆чн҃кѡ́мъ свои́мъ пе́рвѣе: внемли́те себѣ̀ ѿ ква́са фарїсе́йска, є҆́же є҆́сть лицемѣ́рїе. ",
}

add_evangelie_luki {
  ["номер"] = 63,
  ["комментарий"] = "Лк., 63 зач., XII, 2–12.",
  ["текст_ру"] = "Рече́ Госпо́дь: ничто́же покрове́но есть, е́же не откры́ется, и та́йно, е́же не разуме́ется. Зане́, ели́ка во тме ре́сте, во све́те услы́шится, и е́же ко у́ху глаго́ласте во хра́мех, пропове́стся на кро́вех. Глаго́лю же вам друго́м Свои́м: не убо́йтеся от убива́ющих те́ло и пото́м не могу́щих ли́шше что сотвори́ти. Сказу́ю же вам, кого́ убо́йтеся, убо́йтеся иму́щаго власть по убие́нии воврещи́ в дебрь о́гненную, ей, глаго́лю вам, того́ убо́йтеся. Не пять ли птиц цени́тся пе́нязема двема́? И ни еди́на от них несть забве́на пред Бо́гом. Но и вла́си главы́ ва́шея вси изочте́ни суть. Не убо́йтеся у́бо, мно́зех птиц у́нши есте́ вы. Глаго́лю же вам: всяк, и́же а́ще испове́сть Мя пред челове́ки, и Сын Челове́ческий испове́сть его́ пред А́нгелы Бо́жиими, а отверги́йся Мене́ пред челове́ки отве́ржен бу́дет пред А́нгелы Бо́жиими. И всяк и́же рече́т сло́во на Сы́на Челове́ческаго, оста́вится ему́, а на Свята́го Ду́ха ху́лившему не оста́вится. Егда́ же приведу́т вы на собо́рища и вла́сти и влады́чества, не пецы́теся, ка́ко или́ что отвеща́ете, или́ что рече́те, Святы́й бо Дух научи́т вы в той час, я́же подоба́ет рещи́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: ничто́же покрове́но є҆́сть, є҆́же не ѿкры́етсѧ: и҆ та́йно, є҆́же не разꙋмѣ́етсѧ. занѐ, є҆ли̑ка во тмѣ̀ рѣ́сте, во свѣ́тѣ ᲂу҆слы́шитсѧ: и҆ є҆́же ко ᲂу҆́хꙋ глаго́ласте во хра́мѣхъ, проповѣ́стсѧ на кро́вѣхъ. глаго́лю же ва́мъ дрꙋгѡ́мъ свои́мъ: не ᲂу҆бо́йтесѧ ѿ ᲂу҆бива́ющихъ тѣ́ло, и҆ пото́мъ не могꙋ́щихъ ли́шше что̀ сотвори́ти. сказꙋ́ю же ва́мъ, когѡ̀ ᲂу҆бо́йтесѧ: ᲂу҆бо́йтесѧ и҆мꙋ́щагѡ вла́сть по ᲂу҆бїе́нїи воврещѝ въ де́брь ѻ҆́гненнꙋю: є҆́й глаго́лю ва́мъ, тогѡ̀ ᲂу҆бо́йтесѧ. не пѧ́ть ли пти́цъ цѣни́тсѧ пѣ́нѧзема двѣма̀; и҆ ни є҆ди́на ѿ ни́хъ нѣ́сть забве́на пред̾ бг҃омъ. но и҆ вла́си главы̀ ва́шеѧ всѝ и҆зочте́ни сꙋ́ть. не ᲂу҆бо́йтесѧ ᲂу҆̀бо: мно́зѣхъ пти́цъ ᲂу҆́нши є҆стѐ вы̀. глаго́лю же ва́мъ: всѧ́къ и҆́же а҆́ще и҆сповѣ́сть мѧ̀ пред̾ человѣ́ки, и҆ сн҃ъ человѣ́ческїй и҆сповѣ́сть є҆го̀ пред̾ а҆́гг҃лы бж҃їими. а҆ ѿвергі́йсѧ менѐ пред̾ человѣ́ки, ѿве́рженъ бꙋ́детъ пред̾ а҆́гг҃лы бж҃їими. и҆ всѧ́къ и҆́же рече́тъ сло́во на сн҃а чл҃вѣ́ческаго, ѡ҆ста́витсѧ є҆мꙋ̀: а҆ на ст҃а́го дх҃а хꙋ́лившемꙋ не ѡ҆ста́витсѧ. є҆гда́ же приведꙋ́тъ вы̀ на собѡ́рища и҆ вла̑сти, и҆ влады́чєства, не пецы́тесѧ, ка́кѡ и҆лѝ что̀ ѿвѣща́ете, и҆лѝ что̀ рече́те: ст҃ы́й бо дх҃ъ наꙋчи́тъ вы̀ въ то́й ча́съ, ꙗ҆̀же подоба́етъ рещѝ. ",
}

add_evangelie_luki {
