add_evangelie_luki {
  ["номер"] = 65,
  ["комментарий"] = "Лк., 65 зач., XII, 13–15, 22–31.",
  ["текст_ру"] = "Во вре́мя о́но, уча́щу Иису́су, рече́ Ему́ не́кий от наро́да: Учи́телю, рцы бра́ту моему́ раздели́ти со мно́ю достоя́ние. Он же рече́ ему́: челове́че, кто Мя поста́ви судию́ или́ дели́теля над ва́ми? Рече́ же к ним: блюди́те и храни́теся от лихои́мства, я́ко не от избы́тка кому́ живо́т его́ есть от име́ния его́. Сего́ ра́ди глаго́лю вам: не пецы́теся душе́ю ва́шею, что я́сте, ни те́лом, во что облече́теся, душа́ бо́льши есть пи́щи, и те́ло оде́жды. Смотри́те вран, я́ко не се́ют, ни жнут, и́мже несть сокро́вища, ни жи́тницы, и Бог пита́ет их, кольми́ па́че вы есте́ лу́чши птиц? Кто же от вас пеки́йся мо́жет приложи́ти во́зрасту своему́ ла́коть еди́н? А́ще у́бо ни ма́ла чесо́ мо́жете, что о про́чих пече́теся? Смотри́те кри́ны, ка́ко расту́т, не тружда́ются, ни пряду́т. Глаго́лю же вам, я́ко ни Соломо́н во всей сла́ве свое́й облече́ся, я́ко еди́н от сих. А́ще же траву́, на селе́ днесь су́щу и у́тре в пещь вме́щему, Бог та́ко оде́ет, кольми́ па́че вас, малове́ри? И вы не ищи́те, что я́сте, или́ что пие́те, и не возноси́теся. Всех бо сих язы́цы ми́ра сего́ и́щут, ваш же Оте́ц весть, я́ко тре́буете сих. Оба́че ищи́те Ца́рствия Бо́жия, и сия́ вся приложа́тся вам. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ᲂу҆ча́щꙋ і҆и҃сꙋ, речѐ є҆мꙋ̀ нѣ́кїй ѿ наро́да: ᲂу҆чт҃лю, рцы̀ бра́тꙋ моемꙋ̀ раздѣли́ти со мно́ю достоѧ́нїе. ѻ҆́нъ же речѐ є҆мꙋ̀: человѣ́че, кто́ мѧ поста́ви сꙋдїю̀, и҆лѝ дѣли́телѧ над̾ ва́ми; рече́ же къ ни́мъ: блюди́те, и҆ храни́тесѧ ѿ лихои́мства: ꙗ҆́кѡ не ѿ и҆збы́тка комꙋ̀ живо́тъ є҆гѡ̀ є҆́сть ѿ и҆мѣ́нїѧ є҆гѡ̀. сегѡ̀ ра́ди глаго́лю ва́мъ, не пецы́тесѧ дꙋше́ю ва́шею, что̀ ꙗ҆́сте: ни тѣ́ломъ, во что̀ ѡ҆блече́тесѧ. дꙋша̀ бо́льши є҆́сть пи́щи, и҆ тѣ́ло ѻ҆де́жды. смотри́те вра̑нъ, ꙗ҆́кѡ не сѣ́ютъ, ни жнꙋ́тъ, и҆̀мже нѣ́сть сокро́вища, ни жи́тницы, и҆ бг҃ъ пита́етъ и҆̀хъ. кольмѝ па́че вы̀ є҆стѐ лꙋ́чши пти́цъ; кто́ же ѿ ва́съ пекі́йсѧ, мо́жетъ приложи́ти во́зрастꙋ своемꙋ̀ ла́коть є҆ди́нъ; а҆́ще ᲂу҆̀бо ни ма́ла чесѡ̀ мо́жете, что̀ ѡ҆ про́чихъ пече́тесѧ; смотри́те крі́ны, ка́кѡ растꙋ́тъ: не трꙋжда́ютсѧ, ни прѧдꙋ́тъ. глаго́лю же ва́мъ, ꙗ҆́кѡ ни соломѡ́нъ во все́й сла́вѣ свое́й ѡ҆блече́сѧ, ꙗ҆́кѡ є҆ди́нъ ѿ си́хъ. а҆́ще же травꙋ̀ на селѣ̀ дне́сь сꙋ́щꙋ, и҆ ᲂу҆́трѣ въ пе́щь вме́щемꙋ, бг҃ъ та́кѡ ѡ҆дѣ́етъ, кольмѝ па́че ва́съ, маловѣ́ри; и҆ вы̀ не и҆щи́те что̀ ꙗ҆́сте, и҆лѝ что̀ пїе́те: и҆ не возноси́тесѧ. всѣ́хъ бо си́хъ ꙗ҆зы́цы мі́ра сегѡ̀ и҆́щꙋтъ: ва́шъ же ѻ҆ц҃ъ вѣ́сть, ꙗ҆́кѡ тре́бꙋете си́хъ. ѻ҆ба́че и҆щи́те црⷭ҇твїѧ бж҃їѧ, и҆ сїѧ̑ всѧ̑ приложа́тсѧ ва́мъ. ",
}

add_evangelie_luki {
  ["номер"] = 66,
  ["комментарий"] = "Лк., 66 зач., XII, 16–21.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: челове́ку не́коему бога́ту угобзи́ся ни́ва, и мы́сляше в себе́, глаго́ля: что сотворю́, я́ко не и́мам где собра́ти плодо́в мои́х? И рече́: се сотворю́, разорю́ жи́тницы моя́, и бо́льшыя сози́жду, и соберу́ ту вся жи́та моя́ и блага́я моя́. И реку́ души́ мое́й: душе́, и́маши мно́га бла́га, лежа́ща на ле́та мно́га, почива́й, яждь, пий, весели́ся. Рече́ же ему́ Бог: безу́мне, в сию́ нощь ду́шу твою́ истя́жут от тебе́, а я́же угото́вал еси́, кому́ бу́дут? Та́ко собира́яй себе́, а не в Бо́га богате́я. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: человѣ́кꙋ нѣ́коемꙋ бога́тꙋ ᲂу҆гобзи́сѧ ни́ва. и҆ мы́слѧше въ себѣ̀, глаго́лѧ: что̀ сотворю̀, ꙗ҆́кѡ не и҆́мамъ гдѣ̀ собра́ти плодѡ́въ мои́хъ; и҆ речѐ: сѐ сотворю̀, разорю̀ жи̑тницы моѧ̀, и҆ бо́льшыѧ сози́ждꙋ, и҆ соберꙋ̀ тꙋ̀ всѧ̀ жи́та моѧ̀, и҆ блага̑ѧ моѧ̀. и҆ рекꙋ̀ дꙋшѝ мое́й: дꙋшѐ, и҆́маши мнѡ́га бла̑га, лежа́ща на лѣ́та мнѡ́га: почива́й, ꙗ҆́ждь, пі́й, весели́сѧ. рече́ же є҆мꙋ̀ бг҃ъ: безꙋ́мне, въ сїю̀ но́щь дꙋ́шꙋ твою̀ и҆стѧ́жꙋтъ ѿ тебѐ: а҆ ꙗ҆̀же ᲂу҆гото́валъ є҆сѝ, комꙋ̀ бꙋ́дꙋтъ; та́кѡ собира́ѧй себѣ̀, а҆ не въ бг҃а богатѣ́ѧ. ",
}

add_evangelie_luki {
  ["номер"] = 67,
  ["комментарий"] = "Лк., 67 зач., XII, 32–40.",
  ["текст_ру"] = "Рече́ Госпо́дь: не бо́йся, ма́лое ста́до, я́ко благоизво́ли Оте́ц ваш да́ти вам Ца́рство. Продади́те име́ния ва́ша и дади́те ми́лостыня. Сотвори́те себе́ влага́лища неветша́юща, сокро́вище неоскуде́емо на небесе́х, иде́же тать не приближа́ется, ни моль растлева́ет. Иде́же бо есть сокро́вище ва́ше, ту и се́рдце ва́ше бу́дет. Да бу́дут чресла́ ва́ша препоя́сана, и свети́льницы горя́щии, и вы подо́бни челове́ком ча́ющым го́спода своего́, когда́ возврати́тся от брак, да прише́дшу и толкну́вшу, а́бие отве́рзут ему́. Блаже́ни раби́ ти́и, и́хже прише́д госпо́дь обря́щет бдя́щя. Ами́нь глаго́лю вам, я́ко препоя́шется и посади́т их, и мину́в послу́жит им. И а́ще прии́дет во втору́ю стра́жу, лю́бо в тре́тию стра́жу прии́дет, и обря́щет их та́ко, блаже́ни суть раби́ ти́и. Се же ве́дите, я́ко а́ще бы ве́дал господи́н хра́мины, в кий час тать прии́дет, бдел у́бо бы, и не бы дал подкопа́ти до́му своего́. И вы у́бо бу́дите гото́ви, я́ко во́ньже час не мните́, Сын Челове́ческий прии́дет. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: не бо́йсѧ ма́лое ста́до: ꙗ҆́кѡ благоизво́ли ѻ҆ц҃ъ ва́шъ да́ти ва́мъ црⷭ҇тво. продади́те и҆мѣ̑нїѧ ва́ша, и҆ дади́те ми́лѡстынѧ. сотвори́те себѣ̀ влага̑лища неветша́юща, сокро́вище неѡскꙋдѣ́емо на небесѣ́хъ: и҆дѣ́же та́ть не приближа́етсѧ, ни мо́ль растлѣва́етъ. и҆дѣ́же бо є҆́сть сокро́вище ва́ше, тꙋ̀ и҆ се́рдце ва́ше бꙋ́детъ. да бꙋ́дꙋтъ чресла̀ ва́ша препоѧ́сана, и҆ свѣти́льницы горѧ́щїи: и҆ вы̀ подо́бни человѣ́кѡмъ ча́ющымъ гдⷭ҇а своегѡ̀, когда̀ возврати́тсѧ ѿ бра̑къ, да прише́дшꙋ и҆ толкнꙋ́вшꙋ, а҆́бїе ѿве́рзꙋтъ є҆мꙋ̀. блаже́ни рабѝ ті́и, и҆̀хже прише́дъ гдⷭ҇ь ѡ҆брѧ́щетъ бдѧ́щѧ. а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ препоѧ́шетсѧ, и҆ посади́тъ и҆̀хъ: и҆ минꙋ́въ послꙋ́житъ и҆̀мъ. и҆ а҆́ще прїи́детъ во вторꙋ́ю стра́жꙋ, лю́бо въ тре́тїю стра́жꙋ прїи́детъ, и҆ ѡ҆брѧ́щетъ и҆̀хъ та́кѡ: блаже́ни сꙋ́ть рабѝ ті́и. се́ же вѣ́дите, ꙗ҆́кѡ а҆́ще бы вѣ́далъ господи́нъ хра́мины, въ кі́й ча́съ та́ть прїи́детъ, бдѣ́лъ ᲂу҆́бѡ бы̀, и҆ не бы̀ да́лъ подкопа́ти до́мꙋ своегѡ̀. и҆ вы̀ ᲂу҆́бѡ бꙋ́дите гото́ви: ꙗ҆́кѡ во́ньже ча́съ не мнитѐ, сн҃ъ человѣ́ческїй прїи́детъ. ",
}

add_evangelie_luki {
  ["номер"] = 68,
  ["комментарий"] = "Лк., 68 зач., XII, 42–48.",
  ["текст_ру"] = "Рече́ Госпо́дь: кто у́бо есть ве́рный строи́тель и му́дрый, его́же поста́вит госпо́дь над че́лядию свое́ю, дая́ти во вре́мя житоме́рие? Блаже́н раб той, его́же прише́д госпо́дь его́ обря́щет творя́ща та́ко. Вои́стинну глаго́лю вам, я́ко над всем име́нием свои́м поста́вит его́. А́ще ли же рече́т раб той в се́рдцы свое́м: косни́т господи́н мой приити́, и на́чнет би́ти рабы́ и рабы́ни, я́сти же и пи́ти, и упива́тися. Прии́дет господи́н раба́ того́ в день, во́ньже не ча́ет, и в час, во́ньже не весть, и проте́шет его́, и часть его́ с неве́рными положи́т. Той же раб ве́девый во́лю господи́на своего́, и не угото́вав, ни сотвори́в по во́ли его́, бие́н бу́дет мно́го. Не ве́девый же, сотвори́в же досто́йная ра́нам, бие́н бу́дет ма́ло. Вся́кому же, ему́же дано́ бу́дет мно́го, мно́го взы́щется от него́, и ему́же преда́ша мно́жайше, мно́жайше про́сят от него́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: кто̀ ᲂу҆̀бо є҆́сть вѣ́рный строи́тель и҆ мꙋ́дрый, є҆го́же поста́витъ гдⷭ҇ь над̾ че́лѧдїю свое́ю, даѧ́ти во вре́мѧ житомѣ́рїе; блаже́нъ ра́бъ то́й, є҆го́же прише́дъ гдⷭ҇ь є҆гѡ̀ ѡ҆брѧ́щетъ творѧ́ща та́кѡ. вои́стиннꙋ глаго́лю ва́мъ, ꙗ҆́кѡ над̾ всѣ́мъ и҆мѣ́нїемъ свои́мъ поста́витъ є҆го̀. а҆́ще ли же рече́тъ ра́бъ то́й въ се́рдцы свое́мъ: косни́тъ господи́нъ мо́й прїитѝ, и҆ на́чнетъ би́ти рабы̑ и҆ рабы̑ни, ꙗ҆́сти же и҆ пи́ти, и҆ ᲂу҆пива́тисѧ: прїи́детъ господи́нъ раба̀ тогѡ̀ въ де́нь, во́ньже не ча́етъ, и҆ въ ча́съ во́ньже не вѣ́сть: и҆ проте́шетъ є҆го̀, и҆ ча́сть є҆гѡ̀ съ невѣ́рными положи́тъ. то́й же ра́бъ вѣ́дѣвый во́лю господи́на своегѡ̀, и҆ не ᲂу҆гото́вавъ, ни сотвори́въ по во́ли є҆гѡ̀, бїе́нъ бꙋ́детъ мно́гѡ. не вѣ́дѣвый же, сотвори́въ же достѡ́йнаѧ ра́намъ, бїе́нъ бꙋ́детъ ма́лѡ. всѧ́комꙋ же, є҆мꙋ́же дано̀ бꙋ́детъ мно́гѡ, мно́гѡ взы́щетсѧ ѿ негѡ̀: и҆ є҆мꙋ́же преда́ша мно́жайше, мно́жайше про́сѧтъ ѿ негѡ̀. ",
}

add_evangelie_luki {
  ["номер"] = 69,
  ["комментарий"] = "Лк., 69 зач., XII, 48-59.",
  ["текст_ру"] = "Рече́ Госпо́дь: вся́кому, ему́же дано́ бу́дет мно́го, мно́го взы́щется от него́, и ему́же преда́ша мно́жайше, мно́жайше про́сят от него́. Огня́ приидо́х воврещи́ на зе́млю, и что хощу́, а́ще уже́ возгоре́ся? Креще́нием же и́мам крести́тися, и ка́ко удержу́ся, до́ндеже сконча́ются? Мните́ ли, я́ко ми́ра приидо́х да́ти на зе́млю? Ни, глаго́лю вам, но разделе́ния. Бу́дут бо отсе́ле пять во еди́ном дому́ разделе́ни, трие́ на два, и два на три. Раздели́тся оте́ц на сы́на, и сын на отца́, ма́ти на дщерь, и дщи на ма́терь, свекры́ на неве́сту свою́, и неве́ста на свекро́вь свою́. Глаго́лаше же и наро́дом: егда́ у́зрите о́блак восходя́щь от за́пада, а́бие глаго́лете: ту́ча гряде́т, и быва́ет та́ко. И егда́ юг ве́ющь, глаго́лете: зной бу́дет, и быва́ет. Лицеме́ри, лице́ не́бу и земли́ ве́сте искуша́ти, вре́мене же сего́ ка́ко не искуша́ете? Что же и о себе́ не су́дите пра́ведное? Егда́ бо гряде́ши с сопе́рником твои́м ко кня́зю, на пути́ даждь де́лание избы́ти от него́, да не ка́ко привлече́т тебе́ к судии́, и судия́ тя преда́ст слузе́, и слуга́ всади́т тя в темни́цу. Глаго́лю тебе́: не изы́деши отту́ду, до́ндеже и после́днюю ме́дницу возда́си. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: всѧ́комꙋ є҆мꙋ́же дано̀ бꙋ́детъ мно́гѡ, мно́гѡ взы́щетсѧ ѿ негѡ̀: и҆ є҆мꙋ́же преда́ша мно́жайше, мно́жайше про́сѧтъ ѿ негѡ̀. ѻ҆гнѧ̀ прїидо́хъ воврещѝ на зе́млю, и҆ что̀ хощꙋ̀, а҆́ще ᲂу҆жѐ возгорѣ́сѧ; креще́нїемъ же и҆́мамъ крⷭ҇ти́тисѧ, и҆ ка́кѡ ᲂу҆держꙋ́сѧ, до́ндеже сконча́ютсѧ; мните́ ли, ꙗ҆́кѡ ми́ра прїидо́хъ да́ти на зе́млю; нѝ, глаго́лю ва́мъ, но раздѣле́нїѧ. бꙋ́дꙋтъ бо ѿсе́лѣ пѧ́ть во є҆ди́номъ домꙋ̀ раздѣле́ны: трїѐ на два̀, и҆ два̀ на трѝ. раздѣли́тсѧ ѻ҆те́цъ на сы́на, и҆ сы́нъ на ѻ҆тца̀: ма́ти на дще́рь, и҆ дщѝ на ма́терь: свекры̀ на невѣ́стꙋ свою̀, и҆ невѣ́ста на свекро́вь свою̀. глаго́лаше же и҆ наро́дѡмъ: є҆гда̀ ᲂу҆́зрите ѻ҆́блакъ восходѧ́щъ ѿ за́пада, а҆́бїе глаго́лете: тꙋ́ча грѧде́тъ, и҆ быва́етъ та́кѡ. и҆ є҆гда̀ ю҆́гъ вѣ́ющъ, глаго́лете: зно́й бꙋ́детъ, и҆ быва́етъ. лицемѣ́ри, лицѐ не́бꙋ и҆ землѝ вѣ́сте и҆скꙋша́ти: вре́мене же сегѡ̀ ка́кѡ не и҆скꙋша́ете; что́ же и҆ ѡ҆ себѣ̀ не сꙋ́дите пра́ведное; є҆гда́ бо грѧде́ши съ сопе́рникомъ твои́мъ ко кнѧ́зю, на пꙋтѝ да́ждь дѣ́ланїе и҆збы́ти ѿ негѡ̀: да не ка́кѡ привлече́тъ тебѐ къ сꙋдїѝ, и҆ сꙋдїѧ́ тѧ преда́стъ слꙋзѣ̀, и҆ слꙋга̀ всади́тъ тѧ̀ въ темни́цꙋ. глаго́лю тебѣ̀: не и҆зы́деши ѿтꙋ́дꙋ, до́ндеже и҆ послѣ́днюю мѣ́дницꙋ возда́си. ",
}

add_evangelie_luki {
  ["номер"] = 70,
  ["комментарий"] = "Лк., 70 зач., XIII, 1–9.",
  ["текст_ру"] = "Во вре́мя о́но, приидо́ша не́цыи ко Иису́сови, пове́дающе Ему́ о Галиле́ех, и́хже кровь Пила́т смеси́ с же́ртвами их. И отвеща́в Иису́с рече́ им: мните́ ли, я́ко Галиле́ане си́и гре́шнейши па́че всех Галиле́ан бя́ху, я́ко та́ко пострада́ша? Ни, глаго́лю вам, но а́ще не пока́етеся, вси та́кожде поги́бнете. Или́ они́ осмьна́десяте, на ни́хже паде́ столп Силоа́мский и поби́ их, мните́ ли, я́ко ти́и до́лжнейши бя́ху па́че всех живу́щих во Иерусали́ме? Ни, глаго́лю вам, но а́ще не пока́етеся, вси та́кожде поги́бнете. Глаго́лаше же сию́ при́тчу: смоко́вницу имя́ше не́кий в виногра́де свое́м всаждену́, и прии́де ищя́ плода́ на ней, и не обре́те. Рече́ же к винаре́ви: се тре́тие ле́то, отне́лиже прихожду́ ищя́ плода́ на смоко́внице сей, и не обрета́ю, посецы́ ю́ у́бо, вску́ю и зе́млю упражня́ет? Он же отвеща́в рече́ ему́: го́споди, оста́ви ю́ и се ле́то, до́ндеже окопа́ю о́крест ея́ и осы́плю гно́ем. И а́ще у́бо сотвори́т плод, а́ще ли же ни, во гряду́щее посече́ши ю́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїидо́ша нѣ́цыи ко і҆и҃сови повѣ́дающе є҆мꙋ̀ ѡ҆ галїле́ехъ, и҆́хже кро́вь пїла́тъ смѣсѝ съ же́ртвами и҆́хъ. и҆ ѿвѣща́въ і҆и҃съ речѐ и҆̀мъ: мнитѐ ли, ꙗ҆́кѡ галїле́ане сі́и грѣ́шнѣйши па́че всѣ́хъ галїле́анъ бѧ́хꙋ, ꙗ҆́кѡ та́кѡ пострада́ша; нѝ, глаго́лю ва́мъ: но а҆́ще не пока́етесѧ, всѝ та́кожде поги́бнете. и҆лѝ ѻ҆нѝ ѻ҆смьна́десѧте, на ни́хже падѐ сто́лпъ сїлѡа́мскїй, и҆ побѝ и҆̀хъ, мнитѐ ли, ꙗ҆́кѡ ті́и до́лжнѣйши бѧ́хꙋ па́че всѣ́хъ живꙋ́щихъ во і҆ерꙋсали́мѣ; нѝ, глаго́лю ва́мъ: но а҆́ще не пока́етесѧ, всѝ та́кожде поги́бнете. глаго́лаше же сїю̀ при́тчꙋ: смоко́вницꙋ и҆мѧ́ше нѣ́кїй въ вїногра́дѣ свое́мъ всажденꙋ̀, и҆ прїи́де и҆щѧ̀ плода̀ на не́й, и҆ не ѡ҆брѣ́те. рече́ же къ вїнаре́ви: сѐ тре́тїе лѣ́то, ѿне́лиже прихождꙋ̀, и҆щѧ̀ плода̀ на смоко́вницѣ се́й, и҆ не ѡ҆брѣта́ю: посѣцы̀ ю҆̀ ᲂу҆́бѡ, вскꙋ́ю и҆ зе́млю ᲂу҆пражнѧ́етъ; ѻ҆́нъ же ѿвѣща́въ, речѐ є҆мꙋ̀: гдⷭ҇и, ѡ҆ста́ви ю҆̀ и҆ сѐ лѣ́то, до́ндеже ѡ҆копа́ю ѻ҆́крестъ є҆ѧ̀, и҆ ѡ҆сы́плю гно́емъ. и҆ а҆́ще ᲂу҆́бѡ сотвори́тъ пло́дъ: а҆́ще ли же нѝ, во грѧдꙋ́щее посѣче́ши ю҆̀. ",
}

add_evangelie_luki {
  ["номер"] = 71,
  ["комментарий"] = "Лк., 71 зач., XIII, 10–17.",
  ["текст_ру"] = "Во вре́мя о́но, бе учя́ Иису́с на еди́ном от со́нмищ в суббо́ту. И се жена́ бе иму́щи дух неду́жен лет осмьна́десять, и бе слука́ и не могу́щи восклони́тися отню́д. Ви́дев же ю́ Иису́с, пригласи́ и рече́ ей: же́но, отпущена́ еси́ от неду́га твоего́. И возложи́ на ню ру́це, и а́бие простре́ся и сла́вляше Бо́га. Отвеща́в же старе́йшина собо́ру, негоду́я, зане́ в суббо́ту исцели́ ю́ Иису́с, глаго́лаше наро́ду: шесть дний есть, в ня́же досто́ит де́лати, в ты́я у́бо приходя́ще цели́теся, а не в день суббо́тный. Отвеща́в же у́бо ему́ Госпо́дь и рече́: лицеме́ре, ко́ждо вас в суббо́ту не отреша́ет ли своего́ вола́ или́ осла́ от я́слий, и вед напая́ет? Сию́ же дщерь Авраа́млю су́щу, ю́же связа́ сатана́, се осмоена́десяте ле́то, не досто́яше ли разреши́тися ей от ю́зы сея́ в день суббо́тный? И сия́ Ему́ глаго́лющу, стыдя́хуся вси противля́ющиися Ему́, и вси лю́дие ра́довахуся о всех сла́вных быва́ющих от Него́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бѣ̀ ᲂу҆чѧ̀ і҆и҃съ на є҆ди́номъ ѿ со́нмищъ въ сꙋббѡ́тꙋ. и҆ сѐ жена̀ бѣ̀ и҆мꙋ́щи дꙋ́хъ недꙋ́женъ лѣ́тъ ѻ҆смьна́десѧть, и҆ бѣ̀ слꙋка̀: и҆ не могꙋ́щи восклони́тисѧ ѿню́дъ. ви́дѣвъ же ю҆̀ і҆и҃съ, пригласѝ, и҆ речѐ є҆́й: же́но, ѿпꙋщена̀ є҆сѝ ѿ недꙋ́га твоегѡ̀. и҆ возложѝ на ню̀ рꙋ́цѣ: и҆ а҆́бїе простре́сѧ, и҆ сла́влѧше бг҃а. ѿвѣща́въ же старѣ́йшина собо́рꙋ, негодꙋ́ѧ, занѐ въ сꙋббѡ́тꙋ и҆сцѣлѝ ю҆̀ і҆и҃съ, глаго́лаше наро́дꙋ: ше́сть дні́й є҆́сть, въ нѧ́же досто́итъ дѣ́лати, въ ты́ѧ ᲂу҆́бѡ приходѧ́ще цѣли́тесѧ, а҆ не въ де́нь сꙋббѡ́тный. ѿвѣща́въ же ᲂу҆́бѡ є҆мꙋ̀ гдⷭ҇ь, и҆ речѐ: лицемѣ́ре, ко́ждо ва́съ въ сꙋббѡ́тꙋ не ѿрѣша́етъ ли своегѡ̀ вола̀, и҆лѝ ѻ҆сла̀ ѿ ꙗ҆́слїй, и҆ ве́дъ напаѧ́етъ; сїю́ же дще́рь а҆враа́млю сꙋ́щꙋ, ю҆́же свѧза̀ сатана̀ сѐ ѻ҆смоена́десѧте лѣ́то, не досто́ѧше ли разрѣши́тисѧ є҆́й ѿ ю҆́зы сеѧ̀ въ де́нь сꙋббѡ́тный; и҆ сїѧ̑ є҆мꙋ̀ глаго́лющꙋ, стыдѧ́хꙋсѧ всѝ противлѧ́ющїисѧ є҆мꙋ̀: и҆ всѝ лю́дїе ра́довахꙋсѧ ѡ҆ всѣ́хъ сла́вныхъ быва́ющихъ ѿ негѡ̀. ",
}

add_evangelie_luki {
  ["номер"] = 72,
  ["комментарий"] = "Лк., 72 зач., XIII, 18–29.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: кому́ подо́бно есть Ца́рствие Бо́жие? И кому́ уподо́блю е́? Подо́бно есть зе́рну гору́шну, е́же прие́м челове́к вве́рже в вертогра́д свой, и возрасте́, и бысть дре́во ве́лие, и пти́цы небе́сныя всели́шася в ве́твия его́. Па́ки рече́: кому́ уподо́блю Ца́рствие Бо́жие? Подо́бно есть ква́су, е́же прие́мши жена́, скры в муце́ са́та три, до́ндеже вски́се все. И прохожда́ше сквозе́ гра́ды и ве́си, учя́ и ше́ствие творя́ во Иерусали́м. Рече́ же не́кий Ему́: Го́споди, а́ще ма́ло есть спаса́ющихся? Он же рече́ к ним: подвиза́йтеся вни́ти сквозе́ те́сная врата́, я́ко мно́зи, глаго́лю вам, взы́щут вни́ти, и не возмо́гут. Отне́лиже воста́нет до́му влады́ка и затвори́т две́ри, и на́чнете вне стоя́ти и ударя́ти в две́ри, глаго́люще: Го́споди, Го́споди, отве́рзи нам. И отвеща́в рече́т вам: не вем вас, отку́ду есте́. Тогда́ на́чнете глаго́лати: ядо́хом пред Тобо́ю и пи́хом, и на распу́тиях на́ших учи́л еси́. И рече́т: глаго́лю вам, не вем вас, отку́ду есте́, отступи́те от Мене́ вси де́лателие непра́вды. Ту бу́дет плачь и скре́жет зубо́м, егда́ у́зрите Авраа́ма и Исаа́ка и Иа́кова и вся проро́ки во Ца́рствии Бо́жии, вас же изгони́мых вон. И прии́дут от восто́к и за́пад и се́вера и ю́га, и во́злягут в Ца́рствии Бо́жии. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: комꙋ̀ подо́бно є҆́сть црⷭ҇твїе бж҃їе; и҆ комꙋ̀ ᲂу҆подо́блю є҆̀; подо́бно є҆́сть зе́рнꙋ горꙋ́шнꙋ, є҆́же прїе́мъ человѣ́къ вве́рже въ вертогра́дъ сво́й: и҆ возрастѐ, и҆ бы́сть дре́во ве́лїе, и҆ пти̑цы небє́сныѧ всели́шасѧ въ вѣ́твїѧ є҆гѡ̀. па́ки речѐ: комꙋ̀ ᲂу҆подо́блю црⷭ҇твїе бж҃їе; подо́бно є҆́сть ква́сꙋ, є҆́же прїе́мши жена̀, скры̀ въ мꙋцѣ̀ са́та трѝ, до́ндеже вски́се всѐ. и҆ прохожда́ше сквозѣ̀ гра́ды и҆ вє́си ᲂу҆чѧ̀, и҆ ше́ствїе творѧ̀ во і҆ерꙋсали́мъ. рече́ же нѣ́кїй є҆мꙋ̀: гдⷭ҇и, а҆́ще ма́лѡ є҆́сть спаса́ющихсѧ; ѻ҆́нъ же речѐ къ ни́мъ: подвиза́йтесѧ вни́ти сквозѣ̀ тѣ́снаѧ врата̀: ꙗ҆́кѡ мно́зи, глаго́лю ва́мъ, взы́щꙋтъ вни́ти, и҆ не возмо́гꙋтъ. ѿне́лиже воста́нетъ до́мꙋ влⷣка, и҆ затвори́тъ двє́ри, и҆ на́чнете внѣ̀ стоѧ́ти, и҆ ᲂу҆дарѧ́ти въ двє́ри, глаго́люще: гдⷭ҇и, гдⷭ҇и, ѿве́рзи на́мъ. и҆ ѿвѣща́въ рече́тъ ва́мъ: не вѣ́мъ ва́съ, ѿкꙋ́дꙋ є҆стѐ. тогда̀ на́чнете глаго́лати: ꙗ҆до́хомъ пред̾ тобо́ю и҆ пи́хомъ, и҆ на распꙋ́тїѧхъ на́шихъ ᲂу҆чи́лъ є҆сѝ. и҆ рече́тъ, глаго́лю ва́мъ: не вѣ́мъ ва́съ, ѿкꙋ́дꙋ є҆стѐ, ѿстꙋпи́те ѿ менѐ всѝ дѣ́лателїе непра́вды. тꙋ̀ бꙋ́детъ пла́чь и҆ скре́жетъ зꙋбѡ́мъ: є҆гда̀ ᲂу҆́зрите а҆враа́ма, и҆ і҆саа́ка, и҆ і҆а́кѡва, и҆ всѧ̀ проро́ки во црⷭ҇твїи бж҃їи, ва́съ же и҆згони́мыхъ во́нъ. и҆ прїи́дꙋтъ ѿ востѡ́къ, и҆ за̑падъ, и҆ сѣ́вера, и҆ ю҆́га, и҆ во́злѧгꙋтъ въ црⷭ҇твїи бж҃їи. ",
}

add_evangelie_luki {
  ["номер"] = 73,
  ["комментарий"] = "Лк., 73 зач., XIII, 31–35.",
  ["текст_ру"] = "Во вре́мя о́но, приступи́ша ко Иису́су не́цыи от фарисе́й, глаго́люще Ему́: изы́ди и иди́ отсю́ду, я́ко И́род хо́щет Тя уби́ти. И рече́ им: ше́дше рцы́те ли́су тому́, се изгоню́ бе́сы и исцеле́ния творю́ днесь и у́тре, и в тре́тий сконча́ю. Оба́че подоба́ет Ми днесь и у́тре и в бли́жний ити́, я́ко невозмо́жно есть проро́ку поги́бнути кроме́ Иерусали́ма. Иерусали́ме, Иерусали́ме, изби́вый проро́ки и ка́мением побива́я по́сланныя к тебе́, колькра́ты восхоте́х собра́ти ча́да твоя́, я́коже ко́кош гнездо́ свое́ под криле́, и не восхоте́сте? Се оставля́ется вам дом ваш пуст. Глаго́лю же вам, я́ко не и́мате Мене́ ви́дети, до́ндеже прии́дет, егда́ рече́те: благослове́н Гряды́й во и́мя Госпо́дне. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋпи́ша ко і҆и҃сꙋ нѣ́цыи ѿ фарїсє́й, глаго́люще є҆мꙋ̀: и҆зы́ди, и҆ и҆дѝ ѿсю́дꙋ, ꙗ҆́кѡ и҆́рѡдъ хо́щетъ тѧ̀ ᲂу҆би́ти. и҆ речѐ и҆̀мъ: ше́дше рцы́те ли́сꙋ томꙋ̀, сѐ и҆згоню̀ бѣ́сы, и҆ и҆сцѣлє́нїѧ творю̀ дне́сь и҆ ᲂу҆́трѣ, и҆ въ тре́тїй сконча́ю. ѻ҆ба́че подоба́етъ мѝ дне́сь и҆ ᲂу҆́трѣ, и҆ въ бли́жнїй и҆тѝ, ꙗ҆́кѡ невозмо́жно є҆́сть проро́кꙋ поги́бнꙋти кромѣ̀ і҆ерꙋсали́ма. і҆ерꙋсали́ме і҆ерꙋсали́ме, и҆зби́вый проро́ки, и҆ ка́менїемъ побива́ѧ пѡ́сланныѧ къ тебѣ̀: колькра́ты восхотѣ́хъ собра́ти ча̑да твоѧ̀, ꙗ҆́коже ко́кошъ гнѣздо̀ своѐ под̾ крилѣ̀, и҆ не восхотѣ́сте! сѐ ѡ҆ставлѧ́етсѧ ва́мъ до́мъ ва́шъ пꙋ́стъ. глаго́лю же ва́мъ, ꙗ҆́кѡ не и҆́мате менѐ ви́дѣти, до́ндеже прїи́детъ, є҆гда̀ рече́те: бл҃гослове́нъ грѧды́й во и҆́мѧ гдⷭ҇не. ",
}

add_evangelie_luki {
  ["номер"] = 74,
  ["комментарий"] = "Лк., 74 зач., XIV, 1–11.",
  ["текст_ру"] = "Во вре́мя о́но, вни́де Иису́с в дом не́коего кня́зя фарисе́йска в суббо́ту хлеб я́сти, и ти́и бя́ху назира́юще Его́. И се челове́к не́кий, имы́й водны́й труд, бе пред Ним. И отвеща́в Иису́с рече́ к зако́нником и фарисе́ом, глаго́ля: а́ще досто́ит в суббо́ту цели́ти? Они́ же умолча́ша. И прие́м исцели́ его́, и отпусти́. И отвеща́в к ним рече́: кото́раго от вас осе́л или́ вол в студене́ц впаде́т, и не а́бие ли исто́ргнет его́ в день суббо́тный? И не возмого́ша отвеща́ти Ему́ к сим. Глаго́лаше же к зва́нным при́тчу, обдержя́, ка́ко председа́ния избира́ху, глаго́ля к ним: егда́ зван бу́деши ким на брак, не ся́ди на пре́днем ме́сте, еда́ кто честне́е тебе́ бу́дет зва́нных, и прише́д и́же тебе́ зва́вый и о́наго, рече́т ти: даждь сему́ ме́сто, и тогда́ на́чнеши со студо́м после́днее ме́сто держа́ти. Но егда́ зван бу́деши, шед ся́ди на после́днем ме́сте, да егда́ прии́дет зва́вый тя, рече́т ти: дру́же, пося́ди вы́ше, тогда́ бу́дет ти сла́ва пред зва́нными с тобо́ю. Я́ко всяк вознося́йся смири́тся, и смиря́яйся вознесе́тся. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, вни́де і҆и҃съ въ до́мъ нѣ́коегѡ кнѧ́зѧ фарїсе́йска, въ сꙋббѡ́тꙋ хлѣ́бъ ꙗ҆́сти: и҆ ті́и бѧ́хꙋ назира́юще є҆го̀. и҆ сѐ человѣ́къ нѣ́кїй, и҆мы́й водны́й трꙋ́дъ, бѣ̀ пред̾ ни́мъ. и҆ ѿвѣща́въ і҆и҃съ речѐ къ зако́нникѡмъ и҆ фарїсе́ѡмъ, глаго́лѧ: а҆́ще досто́итъ въ сꙋббѡ́тꙋ цѣли́ти; ѻ҆ни́ же ᲂу҆молча́ша: и҆ прїе́мъ и҆сцѣлѝ є҆го̀, и҆ ѿпꙋстѝ. и҆ ѿвѣща́въ къ ни́мъ, речѐ: кото́рагѡ ѿ ва́съ ѻ҆се́лъ, и҆лѝ во́лъ, въ стꙋдене́цъ впаде́тъ, и҆ не а҆́бїе ли и҆сто́ргнетъ є҆го̀ въ де́нь сꙋббѡ́тный; и҆ не возмого́ша ѿвѣща́ти є҆мꙋ̀ къ си̑мъ. глаго́лаше же къ зва́ннымъ при́тчꙋ, ѡ҆бдержѧ̀, ка́кѡ предсѣда̑нїѧ и҆збира́хꙋ, глаго́лѧ къ ни́мъ: є҆гда̀ зва́нъ бꙋ́деши ки́мъ на бра́къ, не сѧ́ди на пре́днѣмъ мѣ́стѣ: є҆да̀ кто̀ честнѣ́е тебѐ бꙋ́детъ зва́нныхъ: и҆ прише́дъ и҆́же тебѐ зва́вый и҆ ѻ҆́наго, рече́тъ тѝ: да́ждь семꙋ̀ мѣ́сто: и҆ тогда̀ на́чнеши со стꙋдо́мъ послѣ́днее мѣ́сто держа́ти. но є҆гда̀ зва́нъ бꙋ́деши, ше́дъ сѧ́ди на послѣ́днѣмъ мѣ́стѣ: да є҆гда̀ прїи́детъ зва́вый тѧ̀, рече́тъ тѝ: дрꙋ́же, посѧ́ди вы́ше: тогда̀ бꙋ́детъ тѝ сла́ва пред̾ зва́нными съ тобо́ю. ꙗ҆́кѡ всѧ́къ возносѧ́йсѧ, смири́тсѧ: и҆ смирѧ́ѧйсѧ, вознесе́тсѧ. ",
}

add_evangelie_luki {
  ["номер"] = 75,
  ["комментарий"] = "Лк., 75 зач., XIV, 12–15.",
  ["текст_ру"] = "Во вре́мя о́но, вни́де Иису́с в дом не́коего кня́зя фарисе́йска в день суббо́тный сне́сти хлеб, и глаго́лаше ко зва́вшему Его́: егда́ сотвори́ши обед или́ ве́черю, не зови́ друго́в твои́х, ни бра́тии твоея́, ни сро́дник твои́х, ни сосе́д бога́тых, еда́ когда́ и ти́и тя та́кожде воззову́т, и бу́дет ти воздая́ние. Но егда́ твори́ши пир, зови́ ни́щыя, маломо́щи, хро́мыя, слепы́я, и блаже́н бу́деши, я́ко не и́мут ти что возда́ти, возда́ст же ти ся в воскреше́ние пра́ведных. Слы́шав же не́кий от возлежа́щих с Ним сия́, рече́ Ему́: блаже́н, и́же снесть обед в Ца́рствии Бо́жии. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, вни́де і҆и҃съ въ до́мъ нѣ́коегѡ кнѧ́зѧ фарїсе́йска въ де́нь сꙋббѡ́тный снѣ́сти хлѣ́бъ, и҆ глаго́лаше ко зва́вшемꙋ є҆го̀: є҆гда̀ сотвори́ши ѻ҆бѣ́дъ, и҆лѝ ве́черю, не зовѝ дрꙋгѡ́въ твои́хъ, ни бра́тїи твоеѧ̀, ни срѡ́дникъ твои́хъ, ни сосѣ̑дъ бога́тыхъ: є҆да̀ когда̀ и҆ ті́и тѧ̀ та́кожде воззовꙋ́тъ, и҆ бꙋ́детъ тѝ воздаѧ́нїе. но є҆гда̀ твори́ши пи́ръ, зовѝ ни́щыѧ, маломѡ́щи, хрѡ́мыѧ, слѣпы̑ѧ: и҆ блаже́нъ бꙋ́деши, ꙗ҆́кѡ не и҆́мꙋтъ тѝ что̀ возда́ти: возда́стъ же ти сѧ въ воскреше́нїе пра́ведныхъ. слы́шавъ же нѣ́кїй ѿ возлежа́щихъ съ ни́мъ сїѧ̑, речѐ є҆мꙋ̀: блаже́нъ, и҆́же снѣ́сть ѻ҆бѣ́дъ въ црⷭ҇твїи бж҃їи. ",
}

add_evangelie_luki {
  ["номер"] = 76,
  ["комментарий"] = "Лк., 76 зач., XIV, 16–24.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: челове́к не́кий сотвори́ ве́черю ве́лию, и зва мно́ги. И посла́ раба́ своего́ в год ве́чери рещи́ зва́нным: гряди́те, я́ко уже́ гото́ва суть вся. И нача́ша вку́пе отрица́тися вси. Пе́рвый рече́ ему́: село́ купи́х, и и́мам ну́жду изы́ти и ви́дети е́. Молю́ ти ся, име́й мя отрече́на. И други́й рече́: супру́г воло́вных купи́х пять, и гряду́ искуси́ти их. Молю́ тя, име́й мя отрече́на. И други́й рече́: жену́ поях, и сего́ ра́ди не могу́ приити́. И прише́д раб той, пове́да господи́ну своему́ сия́. Тогда́ разгне́вався до́му влады́ка, рече́ рабу́ своему́: изы́ди ско́ро на распу́тия и сто́гны гра́да, и ни́щия, и бе́дныя, и слепы́я, и хро́мыя введи́ се́мо. И рече́ раб: го́споди, бысть я́коже повеле́, и еще́ ме́сто есть. И рече́ господи́н к рабу́: изы́ди на пути́ и халу́ги, и убеди́ вни́ти, да напо́лнится дом мой. Глаго́лю бо вам: я́ко ни еди́н муже́й тех зва́нных вку́сит моея́ ве́чери, мно́зи бо суть зва́ни, ма́ло же избра́нных. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: человѣ́къ нѣ́кїй сотворѝ ве́черю ве́лїю, и҆ зва̀ мнѡ́ги. и҆ посла̀ раба̀ своего̀ въ го́дъ ве́чери, рещѝ зва̑ннымъ: грѧди́те, ꙗ҆́кѡ ᲂу҆жѐ готѡ́ва сꙋ́ть всѧ̑. и҆ нача́ша вкꙋ́пѣ ѿрица́тисѧ всѝ. пе́рвый речѐ є҆мꙋ̀: село̀ кꙋпи́хъ, и҆ и҆́мамъ нꙋ́ждꙋ и҆зы́ти, и҆ ви́дѣти є҆̀: молю́ ти сѧ, и҆мѣ́й мѧ̀ ѿрече́на. и҆ дрꙋгі́й речѐ: сꙋпрꙋ̑гъ воло́вныхъ кꙋпи́хъ пѧ́ть, и҆ грѧдꙋ̀ и҆скꙋси́ти и҆̀хъ: молю́ тѧ, и҆мѣ́й мѧ̀ ѿрече́на. и҆ дрꙋгі́й речѐ: женꙋ̀ поѧ́хъ, и҆ сегѡ̀ ра́ди не могꙋ̀ прїитѝ. и҆ прише́дъ ра́бъ то́й, повѣ́да господи́нꙋ своемꙋ̀ сїѧ̑. тогда̀ разгнѣ́вавсѧ до́мꙋ влады́ка, речѐ рабꙋ̀ своемꙋ̀: и҆зы́ди ско́рѡ на распꙋ̑тїѧ и҆ стѡ́гны гра́да, и҆ ни́щыѧ, и҆ бѣ̑дныѧ, и҆ слѣпы̑ѧ, и҆ хрѡ́мыѧ введѝ сѣ́мѡ. и҆ речѐ ра́бъ: гдⷭ҇и, бы́сть ꙗ҆́коже повелѣ̀, и҆ є҆щѐ мѣ́сто є҆́сть. и҆ речѐ господи́нъ къ рабꙋ̀: и҆зы́ди на пꙋти̑ и҆ халꙋ̑ги, и҆ ᲂу҆бѣдѝ вни́ти, да напо́лнитсѧ до́мъ мо́й. глаго́лю бо ва́мъ: ꙗ҆́кѡ ни є҆ди́нъ мꙋже́й тѣ́хъ зва́нныхъ вкꙋ́ситъ моеѧ̀ ве́чери: мно́зи бо сꙋ́ть зва́ни, ма́лѡ же и҆збра́нныхъ. ",
}

add_evangelie_luki {
  ["номер"] = 77,
  ["комментарий"] = "Лк., 77 зач., XIV, 25–35.",
  ["текст_ру"] = "Во вре́мя о́но, идя́ху со Иису́сом наро́ди мно́зи, и обра́щься рече́ к ним: а́ще кто гряде́т ко Мне, и не возненави́дит отца́ своего́ и ма́терь, и жену́ и чад, и бра́тию и сестр, еще́ же и ду́шу свою́, не мо́жет Мой бы́ти учени́к. И и́же не но́сит креста́ своего́ и в след Мене́ гряде́т, не мо́жет Мой бы́ти учени́к. Кто бо от вас, хотя́й столп созда́ти, не пре́жде ли сед разчте́т име́ние, а́ще и́мать, е́же есть на соверше́ние? Да не, когда́ положи́т основа́ние и не возмо́жет соверши́ти, вси ви́дящии начну́т руга́тися ему́, глаго́люще, я́ко сей челове́к нача́т зда́ти и не мо́же соверши́ти? Или́ кий царь иды́й ко ино́му царю́ сни́тися с ним на брань, не сед ли пре́жде совещава́ет, а́ще си́лен есть сре́стися с десятию́ ты́сящ гряду́щаго со двема́десятма ты́сящама нань? А́ще ли же ни, еще́ дале́че ему́ су́щу, моле́ние посла́в мо́лится о смире́нии. Та́ко у́бо всяк от вас, и́же не отрече́тся всего́ своего́ име́ния, не мо́жет бы́ти Мой учени́к. Добро́ есть соль, а́ще же соль обуя́ет, в чем осоли́тся? Ни в земли́, ни в гно́и тре́бует, вон изсы́плют ю́. Име́яй у́ши слы́шати, да слы́шит. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆дѧ́хꙋ со і҆и҃сомъ наро́ди мно́зи, и҆ ѡ҆бра́щсѧ речѐ къ ни́мъ: а҆́ще кто̀ грѧде́тъ ко мнѣ̀, и҆ не возненави́дитъ ѻ҆тца̀ своего̀, и҆ ма́терь, и҆ женꙋ̀, и҆ ча̑дъ, и҆ бра́тїю, и҆ се́стръ, є҆ще́ же и҆ дꙋ́шꙋ свою̀, не мо́жетъ мо́й бы́ти ᲂу҆чени́къ. и҆ и҆́же не но́ситъ крⷭ҇та̀ своегѡ̀, и҆ въ слѣ́дъ менѐ грѧде́тъ, не мо́жетъ мо́й бы́ти ᲂу҆чени́къ. кто́ бо ѿ ва́съ, хотѧ́й сто́лпъ созда́ти, не пре́жде ли сѣ́дъ разчте́тъ и҆мѣ́нїе, а҆́ще и҆́мать є҆́же є҆́сть на соверше́нїе: да не когда̀ положи́тъ ѡ҆снова́нїе, и҆ не возмо́жетъ соверши́ти, всѝ ви́дѧщїи начнꙋ́тъ рꙋга́тисѧ є҆мꙋ̀, глаго́люще: ꙗ҆́кѡ се́й человѣ́къ нача́тъ зда́ти, и҆ не мо́же соверши́ти. и҆лѝ кі́й ца́рь и҆ды́й ко и҆но́мꙋ царю̀ сни́тисѧ съ ни́мъ на бра́нь, не сѣ́дъ ли пре́жде совѣщава́етъ, а҆́ще си́ленъ є҆́сть срѣ́стисѧ съ десѧтїю̀ ты́сѧщъ, грѧдꙋ́щаго со двѣма́десѧтма ты́сѧщама на́нь; а҆́ще ли же нѝ, є҆щѐ дале́че є҆мꙋ̀ сꙋ́щꙋ, моле́нїе посла́въ, мо́литсѧ ѡ҆ смире́нїи. та́кѡ ᲂу҆́бѡ всѧ́къ ѿ ва́съ, и҆́же не ѿрече́тсѧ всегѡ̀ своегѡ̀ и҆мѣ́нїѧ, не мо́жетъ бы́ти мо́й ᲂу҆чени́къ. добро̀ є҆́сть со́ль: а҆́ще же со́ль ѡ҆бꙋѧ́етъ, въ че́мъ ѡ҆соли́тсѧ; ни въ землѝ, ни въ гно́и тре́бꙋетъ: во́нъ и҆зсы́плютъ ю҆̀. и҆мѣ́ѧй ᲂу҆́ши слы́шати, да слы́шитъ. ",
}

add_evangelie_luki {
  ["номер"] = 78,
  ["комментарий"] = "Лк., 78 зач., XV, 1–10.",
  ["текст_ру"] = "Во вре́мя о́но, бя́ху приближа́ющеся Иису́су вси мытари́е и гре́шницы, послу́шати Его́. И ропта́ху фарисе́е и кни́жницы, глаго́люще, я́ко Сей гре́шники прие́млет и с ни́ми яст. Рече́ же к ним при́тчу сию́, глаго́ля: кий челове́к от вас имы́й сто ове́ц, и погу́бль еди́ну от них, не оста́вит ли девяти́десят и девяти́ в пусты́ни и и́дет в след поги́бшия, до́ндеже обря́щет ю́? И обре́т возлага́ет на ра́ме свои́ ра́дуяся. И прише́д в дом, созыва́ет дру́ги и сосе́ды, глаго́ля им: ра́дуйтеся со мно́ю, я́ко обрето́х овцу́ мою́ поги́бшую. Глаго́лю вам, я́ко та́ко ра́дость бу́дет на небеси́ о еди́нем гре́шнице ка́ющемся, не́жели о девяти́десятих и девяти́ пра́ведник, и́же не тре́буют покая́ния. Или́ ка́я жена́ иму́щи де́сять драхм, а́ще погуби́т дра́хму еди́ну, не вжига́ет ли свети́льника, и помете́т хра́мину, и и́щет приле́жно, до́ндеже обря́щет? И обре́тши созыва́ет други́ни и сосе́ды, глаго́лющи: ра́дуйтеся со мно́ю, я́ко обрето́х дра́хму поги́бшую. Та́ко, глаго́лю вам, ра́дость быва́ет пред А́нгелы Бо́жиими о еди́ном гре́шнице ка́ющемся. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бѧ́хꙋ приближа́ющесѧ і҆и҃сꙋ всѝ мытарі́е и҆ грѣ́шницы, послꙋ́шати є҆гѡ̀. и҆ ропта́хꙋ фарїсе́є и҆ кни́жницы, глаго́люще: ꙗ҆́кѡ се́й грѣ́шники прїе́млетъ, и҆ съ ни́ми ꙗ҆́стъ. рече́ же къ ни́мъ при́тчꙋ сїю̀, глаго́лѧ: кі́й человѣ́къ ѿ ва́съ и҆мы́й сто̀ ѻ҆ве́цъ, и҆ погꙋ́бль є҆ди́нꙋ ѿ ни́хъ, не ѡ҆ста́витъ ли девѧти́десѧтъ и҆ девѧтѝ въ пꙋсты́ни, и҆ и҆́детъ въ слѣ́дъ поги́бшїѧ, до́ндеже ѡ҆брѧ́щетъ ю҆̀; и҆ ѡ҆брѣ́тъ, возлага́етъ на ра́мѣ своѝ ра́дꙋѧсѧ. и҆ прише́дъ въ до́мъ, созыва́етъ дрꙋ́ги и҆ сосѣ́ды, глаго́лѧ и҆̀мъ: ра́дꙋйтесѧ со мно́ю, ꙗ҆́кѡ ѡ҆брѣто́хъ ѻ҆вцꙋ̀ мою̀ поги́бшꙋю. глаго́лю ва́мъ: ꙗ҆́кѡ та́кѡ ра́дость бꙋ́детъ на небесѝ ѡ҆ є҆ди́номъ грѣ́шницѣ ка́ющемсѧ, не́жели ѡ҆ девѧти́десѧтихъ и҆ девѧтѝ пра́вєдникъ, и҆̀же не тре́бꙋютъ покаѧ́нїѧ. и҆лѝ ка́ѧ жена̀ и҆мꙋ́щи де́сѧть дра́хмъ, а҆́ще погꙋби́тъ дра́хмꙋ є҆ди́нꙋ, не вжига́етъ ли свѣти́льника, и҆ помете́тъ хра́минꙋ, и҆ и҆́щетъ прилѣ́жнѡ, до́ндеже ѡ҆брѧ́щетъ; и҆ ѡ҆брѣ́тши, созыва́етъ дрꙋги̑ни и҆ сосѣ́ды, глаго́лющи: ра́дꙋйтесѧ со мно́ю, ꙗ҆́кѡ ѡ҆брѣто́хъ дра́хмꙋ поги́бшꙋю. та́кѡ, глаго́лю ва́мъ, ра́дость быва́етъ пред̾ а҆́гг҃лы бж҃їими ѡ҆ є҆ди́номъ грѣ́шницѣ ка́ющемсѧ. ",
}

add_evangelie_luki {
  ["номер"] = 79,
  ["комментарий"] = "Лк., 79 зач., XV, 11–32.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: челове́к не́кий име́ два сы́на. И рече́ юне́йший ею́ отцу́: о́тче, даждь ми досто́йную часть име́ния. И раздели́ и́ма име́ние. И не по мно́зех днех собра́в все мний сын, оты́де на страну́ дале́че, и ту расточи́ име́ние свое́, живы́й блу́дно. Изжи́вшу же ему́ все бысть глад кре́пок на стране́ той, и той нача́т лиша́тися. И шед прилепи́ся еди́ному от жи́тель тоя́ страны́, и посла́ его́ на се́ла своя́ пасти́ свиния́. И жела́ше насы́тити чре́во свое́ от роже́ц, я́же ядя́ху свиния́, и никто́же дая́ше ему́. В себе́ же прише́д, рече́: коли́ко нае́мником отца́ моего́ избыва́ют хле́бы, аз же гла́дом ги́блю? Воста́в иду́ ко отцу́ моему́, и реку́ ему́: о́тче, согреши́х на не́бо и пред тобо́ю, и уже́ несмь досто́ин нарещи́ся сын твой, сотвори́ мя я́ко еди́наго от нае́мник твои́х. И воста́в и́де ко отцу́ своему́. Еще́ же ему́ дале́че су́щу, узре́ его́ оте́ц его́, и мил ему́ бысть, и тек нападе́ на вы́ю его́, и облобыза́ его́. Рече́ же ему́ сын: о́тче, согреши́х на не́бо и пред тобо́ю, и уже́ несмь досто́ин нарещи́ся сын твой. Рече́ же оте́ц к рабо́м свои́м: изнеси́те оде́жду пе́рвую и облецы́те его́, и дади́те пе́рстень на ру́ку его́ и сапоги́ на но́зе, и приве́дше теле́ц упите́нный заколи́те, и я́дше весели́мся. Я́ко сын мой сей мертв бе, и оживе́, и изги́бл бе, и обре́теся. И нача́ша весели́тися. Бе же сын его́ ста́рей на селе́, и я́ко гряды́й прибли́жися к до́му, слы́ша пе́ние и ли́ки. И призва́в еди́наго от о́трок, вопроша́ше: что у́бо сия́ суть? Он же рече́ ему́, я́ко брат твой прии́де, и закла́ оте́ц твой теле́ц упите́нный, я́ко здра́ва его́ прия́т. Разгне́вався же, и не хотя́ше вни́ти. Оте́ц же его́ изше́д моля́ше его́. Он же отвеща́в рече́ отцу́: се толи́ко лет рабо́таю тебе́ и николи́же за́поведи твоя́ преступи́х, и мне николи́же дал еси́ козля́те, да со дру́ги свои́ми возвесели́лся бых. Егда́ же сын твой сей, изъеды́й твое́ име́ние с любоде́йцами, прии́де, закла́ ему́ теле́ц пито́мый. Он же рече́ ему́: ча́до, ты всегда́ со мно́ю еси́, и вся моя́ твоя́ суть. Возвесели́ти же ся и возра́довати подоба́ше, я́ко брат твой сей мертв бе, и оживе́, и изги́бл бе, и обре́теся. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: человѣ́къ нѣ́кїй и҆мѣ̀ два̀ сы́на. и҆ речѐ ю҆нѣ́йшїй є҆ю̀ ѻ҆тцꙋ̀: ѻ҆́тче, да́ждь мѝ досто́йнꙋю ча́сть и҆мѣ́нїѧ. и҆ раздѣлѝ и҆́ма и҆мѣ́нїе. и҆ не по мно́зѣхъ дне́хъ собра́въ всѐ мні́й сы́нъ, ѿи́де на странꙋ̀ дале́че, и҆ тꙋ̀ расточѝ и҆мѣ́нїе своѐ, живы́й блꙋ́днѡ. и҆зжи́вшꙋ же є҆мꙋ̀ всѐ, бы́сть гла́дъ крѣ́покъ на странѣ̀ то́й: и҆ то́й нача́тъ лиша́тисѧ. и҆ ше́дъ прилѣпи́сѧ є҆ди́номꙋ ѿ жи́тєль тоѧ̀ страны̀: и҆ посла̀ є҆го̀ на сє́ла своѧ̀ пастѝ свинїѧ̑. и҆ жела́ше насы́тити чре́во своѐ ѿ рожє́цъ, ꙗ҆̀же ꙗ҆дѧ́хꙋ свинїѧ̑: и҆ никто́же даѧ́ше є҆мꙋ̀. въ себе́ же прише́дъ, речѐ: коли́кѡ нае́мникѡмъ ѻ҆тца̀ моегѡ̀ и҆збыва́ютъ хлѣ́бы, а҆́зъ же гла́домъ ги́блю. воста́въ и҆дꙋ̀ ко ѻ҆тцꙋ̀ моемꙋ̀, и҆ рекꙋ̀ є҆мꙋ̀: ѻ҆́тче согрѣши́хъ на не́бо, и҆ пред̾ тобо́ю, и҆ ᲂу҆жѐ нѣ́смь досто́инъ нарещи́сѧ сы́нъ тво́й: сотвори́ мѧ ꙗ҆́кѡ є҆ди́наго ѿ нає́мникъ твои́хъ. и҆ воста́въ и҆́де ко ѻ҆тцꙋ̀ своемꙋ̀. є҆ще́ же є҆мꙋ̀ дале́че сꙋ́щꙋ, ᲂу҆зрѣ̀ є҆го̀ ѻ҆те́цъ є҆гѡ̀, и҆ ми́лъ є҆мꙋ̀ бы́сть: и҆ те́къ нападѐ на вы́ю є҆гѡ̀, и҆ ѡ҆блобыза̀ є҆го̀. рече́ же є҆мꙋ̀ сы́нъ: ѻ҆́тче, согрѣши́хъ на не́бо, и҆ пред̾ тобо́ю, и҆ ᲂу҆жѐ нѣ́смь досто́инъ нарещи́сѧ сы́нъ тво́й. рече́ же ѻ҆те́цъ къ рабѡ́мъ свои́мъ: и҆знеси́те ѻ҆де́ждꙋ пе́рвꙋю, и҆ ѡ҆блецы́те є҆го̀, и҆ дади́те пе́рстень на рꙋ́кꙋ є҆гѡ̀, и҆ сапогѝ на но́зѣ: и҆ приве́дше теле́цъ ᲂу҆питѣ́нный, заколи́те, и҆ ꙗ҆́дше весели́мсѧ. ꙗ҆́кѡ сы́нъ мо́й се́й ме́ртвъ бѣ̀, и҆ ѡ҆живѐ: и҆ и҆зги́блъ бѣ̀, и҆ ѡ҆брѣ́тесѧ. и҆ нача́ша весели́тисѧ. бѣ́ же сы́нъ є҆гѡ̀ ста́рѣй на селѣ̀: и҆ ꙗ҆́кѡ грѧды́й прибли́жисѧ къ до́мꙋ, слы́ша пѣ́нїе и҆ ли́ки. и҆ призва́въ є҆ди́наго ѿ ѻ҆́трѡкъ, вопроша́ше: что̀ ᲂу҆́бѡ сїѧ̑ сꙋ́ть; ѻ҆́нъ же речѐ є҆мꙋ̀: ꙗ҆́кѡ бра́тъ тво́й прїи́де, и҆ закла̀ ѻ҆те́цъ тво́й теле́цъ ᲂу҆питѣ́нный, ꙗ҆́кѡ здра́ва є҆го̀ прїѧ́тъ. разгнѣ́вавсѧ же и҆ не хотѧ́ше вни́ти. ѻ҆те́цъ же є҆гѡ̀ и҆зше́дъ, молѧ́ше є҆го̀. ѻ҆́нъ же ѿвѣща́въ, речѐ ѻ҆тцꙋ̀: сѐ толи́кѡ лѣ́тъ рабо́таю тебѣ̀, и҆ николи́же за́пѡвѣди твоѧ̀ престꙋпи́хъ, и҆ мнѣ̀ николи́же да́лъ є҆сѝ козлѧ́те, да со дрꙋ́ги свои́ми возвесели́лсѧ бы́хъ. є҆гда́ же сы́нъ тво́й се́й, и҆з̾ѣды́й твоѐ и҆мѣ́нїе съ любодѣ́йцами, прїи́де, закла̀ є҆мꙋ̀ теле́цъ пито́мый. ѻ҆́нъ же речѐ є҆мꙋ̀: ча́до, ты̀ всегда̀ со мно́ю є҆сѝ, и҆ всѧ̑ моѧ̑ твоѧ̑ сꙋ́ть. возвесели́ти же сѧ и҆ возра́довати подоба́ше, ꙗ҆́кѡ бра́тъ тво́й се́й ме́ртвъ бѣ̀ и҆ ѡ҆живѐ: и҆ и҆зги́блъ бѣ̀, и҆ ѡ҆брѣ́тесѧ. ",
}

add_evangelie_luki {
  ["номер"] = 80,
  ["комментарий"] = "Лк., 80 зач., XVI, 1-9.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: челове́к не́кий бе бога́т, и́же имя́ше приста́вника, и той оклевета́н бысть к нему́, я́ко расточа́ет име́ния его́. И пригласи́в его́ рече́ ему́: что се слы́шу о тебе́? Возда́ждь отве́т о приставле́нии домо́внем, не возмо́жеши бо ктому́ до́му стро́ити. Рече́ же в себе́ приста́вник до́му: что сотворю́, я́ко госпо́дь мой оте́млет строе́ние до́му от мене́? Копа́ти не могу́, проси́ти стыжу́ся. Разуме́х, что сотворю́, да егда́ отста́влен бу́ду от строе́ния до́му, прии́мут мя в до́мы своя́. И призва́в еди́наго кого́ждо до́лжник господи́на своего́, глаго́лаше пе́рвому: коли́цем до́лжен еси́ господи́ну моему́? Он же рече́: сто мер ма́сла. И рече́ ему́: приими́ писа́ние твое́, и сед ско́ро напиши́ пятьдеся́т. Пото́м же рече́ друго́му: ты же коли́цем до́лжен еси́? Он же рече́: сто мер пшени́цы. И глаго́ла ему́: приими́ писа́ние твое́, и напиши́ о́смьдесят. И похвали́ госпо́дь до́му строи́теля непра́веднаго, я́ко му́дре сотвори́, я́ко сы́нове ве́ка сего́ мудре́йши па́че сыно́в све́та в ро́де свое́м суть. И Аз вам глаго́лю: сотвори́те себе́ дру́ги от мамо́ны непра́вды, да егда́ оскуде́ете, прии́мут вы в ве́чныя кро́вы. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: чл҃вѣ́къ нѣ́кїй бѣ̀ бога́тъ, и҆́же и҆мѧ́ше приста́вника: и҆ то́й ѡ҆клевета́нъ бы́сть къ немꙋ̀, ꙗ҆́кѡ расточа́етъ и҆мѣ̑нїѧ є҆гѡ̀. и҆ пригласи́въ є҆го̀, речѐ є҆мꙋ̀: что̀ сѐ слы́шꙋ ѡ҆ тебѣ̀; возда́ждь ѿвѣ́тъ ѡ҆ приставле́нїи домо́внѣмъ: не возмо́жеши бо ктомꙋ̀ до́мꙋ стро́ити. рече́ же въ себѣ̀ приста́вникъ до́мꙋ: что̀ сотворю̀, ꙗ҆́кѡ гдⷭ҇ь мо́й ѿе́млетъ строе́нїе до́мꙋ ѿ менѐ; копа́ти не могꙋ̀, проси́ти стыжꙋ́сѧ. разꙋмѣ́хъ, что̀ сотворю̀: да є҆гда̀ ѿста́вленъ бꙋ́дꙋ ѿ строе́нїѧ до́мꙋ, прїи́мꙋтъ мѧ̀ въ до́мы своѧ̀. и҆ призва́въ є҆ди́наго кого́ждо дѡ́лжникъ гдⷭ҇и́на своегѡ̀, глаго́лаше пе́рвомꙋ: коли́цѣмъ до́лженъ є҆сѝ гдⷭ҇и́нꙋ моемꙋ̀; ѻ҆́нъ же речѐ: сто̀ мѣ́ръ ма́сла. и҆ речѐ є҆мꙋ̀: прїимѝ писа́нїе твоѐ, и҆ сѣ́дъ ско́рѡ напишѝ пѧтьдесѧ́тъ. пото́мъ же речѐ дрꙋго́мꙋ: ты́ же коли́цѣмъ до́лженъ є҆сѝ; ѻ҆́нъ же речѐ: сто̀ мѣ́ръ пшени́цы. и҆ глаго́ла є҆мꙋ̀: прїимѝ писа́нїе твоѐ, и҆ напишѝ ѻ҆́смьдесѧтъ. и҆ похвалѝ гдⷭ҇ь до́мꙋ строи́телѧ непра́веднаго, ꙗ҆́кѡ мꙋ́дрѣ сотворѝ. ꙗ҆́кѡ сы́нове вѣ́ка сегѡ̀ мꙋдрѣ́йши, па́че сынѡ́въ свѣ́та въ ро́дѣ свое́мъ сꙋ́ть. и҆ а҆́зъ ва́мъ глаго́лю: сотвори́те себѣ̀ дрꙋ́ги ѿ мамѡ́ны непра́вды, да є҆гда̀ ѡ҆скꙋдѣ́ете, прїи́мꙋтъ вы̀ въ вѣ́чныѧ кро́вы. ",
}

add_evangelie_luki {
  ["номер"] = 81,
  ["комментарий"] = "Лк., 81 зач., XVI, 10–15.",
  ["текст_ру"] = "Рече́ Госпо́дь: ве́рный в ма́ле, и во мно́зе ве́рен есть, и непра́ведный в ма́ле, и во мно́зе непра́веден есть. А́ще у́бо в непра́веднем име́нии ве́рни не бы́сте, во и́стиннем кто вам ве́ру и́мет? И а́ще в чуже́м ве́рни не бы́сте, ва́ше кто вам даст? Ники́йже раб мо́жет двема́ господи́нома рабо́тати, лю́бо еди́наго возненави́дит, а друга́го возлю́бит, или́ еди́наго держи́тся, о друзе́м же нераде́ти на́чнет. Не мо́жете Бо́гу рабо́тати и мамо́не. Слы́шаху же сия́ вся и фарисе́е, сребролю́бцы су́ще, руга́хуся Ему́. И рече́ им: вы есте́ оправда́юще себе́ пред челове́ки, Бог же весть сердца́ ва́ша, я́ко е́же есть в челове́цех высоко́, ме́рзость есть пред Бо́гом. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: вѣ́рный въ ма́лѣ, и҆ во мно́зѣ вѣ́ренъ є҆́сть: и҆ непра́ведный въ ма́лѣ, и҆ во мно́зѣ непра́веденъ є҆́сть. а҆́ще ᲂу҆́бѡ въ непра́веднѣмъ и҆мѣ́нїи вѣ́рни не бы́сте, во и҆́стиннѣмъ кто̀ ва́мъ вѣ́рꙋ и҆́метъ; и҆ а҆́ще въ чꙋже́мъ вѣ́рни не бы́сте, ва́ше кто̀ ва́мъ да́стъ; никі́йже ра́бъ мо́жетъ двѣма̀ гдⷭ҇и́нома рабо́тати: лю́бо є҆ди́наго возненави́дитъ, а҆ дрꙋга́го возлю́битъ: и҆лѝ є҆ди́нагѡ держи́тсѧ, ѡ҆ дрꙋзѣ́мъ же нерадѣ́ти на́чнетъ. не мо́жете бг҃ꙋ рабо́тати и҆ мамѡ́нѣ. слы́шахꙋ же сїѧ̑ всѧ̑ и҆ фарїсе́є, сребролю́бцы сꙋ́ще, рꙋга́хꙋсѧ є҆мꙋ̀. и҆ речѐ и҆̀мъ: вы̀ є҆стѐ ѡ҆правда́юще себѐ пред̾ человѣ́ки: бг҃ъ же вѣ́сть сердца̀ ва́ша: ꙗ҆́кѡ є҆́же є҆́сть въ человѣ́цѣхъ высоко̀, ме́рзость є҆́сть пред̾ бг҃омъ. ",
}

add_evangelie_luki {
  ["номер"] = 82,
  ["комментарий"] = "Лк., 82 зач., XVI, 15–18; XVII, 1–4.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: вы есте́ оправда́юще себе́ пред челове́ки, Бог же весть сердца́ ва́ша, я́ко е́же есть в челове́цех высоко́, ме́рзость есть пред Бо́гом. Зако́н и проро́цы до Иоа́нна, отто́ле Ца́рствие Бо́жие благовеству́ется, и всяк в не ну́дится. Удо́бее же есть не́бу и земли́ прейти́, не́же от зако́на еди́ной черте́ поги́бнути. Всяк пуща́яй жену́ свою́ и приводя́ и́ну прелюбы́ де́ет, и женя́йся пуще́ною от му́жа прелюбы́ твори́т. Рече́ же ко ученико́м Свои́м: невозмо́жно есть не приити́ собла́зном, го́ре же, его́же ра́ди прихо́дит. У́нее ему́ бы́ло бы, а́ще же́рнов осе́льский облежа́л бы о вы́и его́, и вве́ржен в мо́ре, не́же да соблазни́т ма́лых сих еди́наго. Внемли́те себе́. А́ще согреши́т к тебе́ брат твой, запрети́ ему́, и а́ще пока́ется, оста́ви ему́, и а́ще седми́щи на день согреши́т к тебе́ и седми́щи на день обрати́тся, глаго́ля: ка́юся, оста́ви ему́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: вы̀ є҆стѐ ѡ҆правда́юще себѐ пред̾ человѣ́ки: бг҃ъ же вѣ́сть сердца̀ ва́ша: ꙗ҆́кѡ є҆́же є҆́сть въ человѣ́цѣхъ высоко̀, ме́рзость є҆́сть пред̾ бг҃омъ. зако́нъ и҆ проро́цы до і҆ѡа́нна: ѿто́лѣ црⷭ҇твїе бж҃їе бл҃говѣствꙋ́етсѧ, и҆ всѧ́къ въ нѐ нꙋ́дитсѧ. ᲂу҆до́бѣе же є҆́сть нб҃ꙋ и҆ землѝ прейтѝ, не́же ѿ зако́на є҆ди́ной чертѣ̀ поги́бнꙋти. всѧ́къ пꙋща́ѧй женꙋ̀ свою̀, и҆ приводѧ̀ и҆́нꙋ, прелюбы̀ дѣ́етъ: и҆ женѧ́йсѧ пꙋще́ною ѿ мꙋ́жа, прелюбы̀ твори́тъ. рече́ же ко ᲂу҆ченикѡ́мъ свои́мъ: невозмо́жно є҆́сть не прїитѝ собла́знѡмъ, го́ре же є҆гѡ́же ра́ди прихо́дитъ. ᲂу҆́нее є҆мꙋ̀ бы́ло бы, а҆́ще же́рновъ ѻ҆се́льскїй ѡ҆блежа́лъ бы ѡ҆ вы́и є҆гѡ̀, и҆ вве́рженъ въ мо́ре, не́же да соблазни́тъ ма́лыхъ си́хъ є҆ди́наго. внемли́те себѣ̀: а҆́ще согрѣши́тъ къ тебѣ̀ бра́тъ тво́й, запретѝ є҆мꙋ̀: и҆ а҆́ще пока́етсѧ, ѡ҆ста́ви є҆мꙋ̀: и҆ а҆́ще седми́щи на де́нь согрѣши́тъ къ тебѣ̀, и҆ седми́щи на де́нь ѡ҆брати́тсѧ, глаго́лѧ: ка́юсѧ: ѡ҆ста́ви є҆мꙋ̀. ",
}

add_evangelie_luki {
  ["номер"] = 83,
  ["комментарий"] = "Лк., 83 зач., XVI, 19–31.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: челове́к не́кий бе бога́т, и облача́шеся в порфи́ру и ви́ссон, веселя́ся на вся дни све́тло. Нищь же бе не́кто, и́менем Ла́зарь, и́же лежа́ше пред враты́ его́ гно́ен и жела́ше насы́титися от крупи́ц па́дающих от трапе́зы бога́таго, но и пси приходя́ще облиза́ху гной его́. Бысть же умре́ти ни́щему и несе́ну бы́ти А́нгелы на ло́но Авраа́мле, у́мре же и бога́тый, и погребо́ша его́. И во а́де возве́д о́чи свои́, сый в му́ках, узре́ Авраа́ма издале́ча, и Ла́заря на ло́не его́, и той возгла́шь рече́: о́тче Авраа́ме, поми́луй мя и посли́ Ла́заря, да омо́чит коне́ц пе́рста своего́ в воде́ и устуди́т язы́к мой, я́ко стражду́ во пла́мени сем. Рече́ же Авраа́м: ча́до, помяни́, я́ко восприя́л еси́ блага́я твоя́ в животе́ твое́м, и Ла́зарь та́кожде зла́я, ны́не же зде утеша́ется, ты же стра́ждеши. И над все́ми си́ми между́ на́ми и ва́ми про́пасть вели́ка утверди́ся, я́ко да хотя́щии прейти́ отсю́ду к вам не возмо́гут, ни и́же отту́ду, к нам прехо́дят. Рече́ же: молю́ тя у́бо, о́тче, да по́слеши его́ в дом отца́ моего́. И́мам бо пять бра́тия, я́ко да засвиде́тельствует им, да не и ти́и прии́дут на ме́сто сие́ муче́ния. Глаго́ла ему́ Авраа́м: и́мут Моисе́а и проро́ки, да послу́шают их. Он же рече́: ни, о́тче Авраа́ме, но а́ще кто от ме́ртвых и́дет к ним, пока́ются. Рече́ же ему́: а́ще Моисе́а и проро́ки не послу́шают, ни а́ще кто от ме́ртвых воскре́снет, не и́мут ве́ры. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: человѣ́къ нѣ́кїй бѣ̀ бога́тъ, и҆ ѡ҆блача́шесѧ въ порфѵ́рꙋ и҆ вѵ́ссонъ, веселѧ́сѧ на всѧ̀ днѝ свѣ́тлѡ. ни́щъ же бѣ̀ нѣ́кто, и҆́менемъ ла́зарь, и҆́же лежа́ше пред̾ враты̀ є҆гѡ̀ гно́енъ. и҆ жела́ше насы́титисѧ ѿ крꙋпи́цъ па́дающихъ ѿ трапе́зы бога́тагѡ: но и҆ псѝ приходѧ́ще ѡ҆близа́хꙋ гно́й є҆гѡ̀. бы́сть же ᲂу҆мре́ти ни́щемꙋ, и҆ несе́нꙋ бы́ти а҆́гг҃лы на ло́но а҆враа́мле: ᲂу҆́мре же и҆ бога́тый, и҆ погребо́ша є҆го̀. и҆ во а҆́дѣ возве́дъ ѻ҆́чи своѝ, сы́й въ мꙋ́кахъ, ᲂу҆зрѣ̀ а҆враа́ма и҆здале́ча, и҆ ла́зарѧ на ло́нѣ є҆гѡ̀. и҆ то́й возгла́шь, речѐ: ѻ҆́ч҃е а҆враа́ме, поми́лꙋй мѧ̀, и҆ послѝ ла́зарѧ, да ѡ҆мо́читъ коне́цъ пе́рста своегѡ̀ въ водѣ̀, и҆ ᲂу҆стꙋди́тъ ѧ҆зы́къ мо́й, ꙗ҆́кѡ страждꙋ̀ во пла́мени се́мъ. рече́ же а҆враа́мъ: ча́до, помѧнѝ, ꙗ҆́кѡ воспрїѧ́лъ є҆сѝ блага̑ѧ твоѧ̑ въ животѣ̀ твое́мъ, и҆ ла́зарь та́коже ѕла̑ѧ: ны́нѣ же здѣ̀ ᲂу҆тѣша́етсѧ, ты́ же стра́ждеши. и҆ над̾ всѣ́ми си́ми, междꙋ̀ на́ми и҆ ва́ми про́пасть вели́ка ᲂу҆тверди́сѧ, ꙗ҆́кѡ да хотѧ́щїи прейтѝ ѿсю́дꙋ къ ва́мъ, не возмо́гꙋтъ, ни и҆̀же ѿтꙋ́дꙋ къ на́мъ прехо́дѧтъ. рече́ же: молю́ тѧ ᲂу҆́бѡ ѻ҆́ч҃е, да по́слеши є҆го̀ въ до́мъ ѻ҆тца̀ моегѡ̀. и҆́мамъ бо пѧ́ть бра́тїѧ, ꙗ҆́кѡ да засвидѣ́тельствꙋетъ и҆̀мъ, да не и҆ ті́и прїи́дꙋтъ на мѣ́сто сїѐ мꙋче́нїѧ. глаго́ла є҆мꙋ̀ а҆враа́мъ: и҆́мꙋтъ мѡѷсе́а и҆ проро́ки, да послꙋ́шаютъ и҆̀хъ. ѻ҆́нъ же речѐ: нѝ, ѻ҆́ч҃е а҆враа́ме, но а҆́ще кто̀ ѿ ме́ртвыхъ и҆́детъ къ ни́мъ, пока́ютсѧ. рече́ же є҆мꙋ̀: а҆́ще мѡѷсе́а и҆ проро́ки не послꙋ́шаютъ, ни а҆́ще кто̀ ѿ ме́ртвыхъ воскре́снетъ, не и҆́мꙋтъ вѣ́ры. ",
}

add_evangelie_luki {
  ["номер"] = 84,
  ["комментарий"] = "Лк., 84 зач., XVII, 3–10.",
  ["текст_ру"] = "Рече́ Госпо́дь: внемли́те себе́. А́ще согреши́т к тебе́ брат твой, запрети́ ему́, и а́ще пока́ется, оста́ви ему́, и а́ще седми́щи на день согреши́т к тебе́ и седми́щи на день обрати́тся, глаго́ля: ка́юся, оста́ви ему́. И реко́ша Апо́столи Го́сподеви: приложи́ нам ве́ру. Рече́ же Госпо́дь: а́ще бы́сте име́ли ве́ру я́ко зе́рно гору́шно, глаго́лали бы́сте у́бо я́годичине сей: восто́ргнися и всади́ся в мо́ре, и послу́шала бы вас. Кото́рый же от вас раба́ име́я орю́щ или́ пасу́щ, и́же прише́дшу ему́ с села́ рече́т: а́бие мину́в возля́зи? Но не рече́т ли ему́: угото́вай, что вечеря́ю, и препоя́сався служи́ ми, до́ндеже ям и пию́, и пото́м я́си и пие́ши ты? Еда́ и́мать хвалу́ рабу́ тому́, я́ко сотвори́ повеле́нная? Не мню. Та́ко и вы, егда́ сотворите́ вся повеле́нная вам, глаго́лите, я́ко раби́ неключи́ми есмы́, я́ко е́же до́лжни бе́хом сотвори́ти, сотвори́хом. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: внемли́те себѣ̀: а҆́ще согрѣши́тъ къ тебѣ̀ бра́тъ тво́й, запретѝ є҆мꙋ̀: и҆ а҆́ще пока́етсѧ, ѡ҆ста́ви є҆мꙋ̀: и҆ а҆́ще седми́щи на де́нь согрѣши́тъ къ тебѣ̀, и҆ седми́щи на де́нь ѡ҆брати́тсѧ, глаго́лѧ: ка́юсѧ: ѡ҆ста́ви є҆мꙋ̀. и҆ реко́ша а҆пⷭ҇ли гдⷭ҇еви, приложѝ на́мъ вѣ́рꙋ. рече́ же гдⷭ҇ь: а҆́ще бы́сте и҆мѣ́ли вѣ́рꙋ, ꙗ҆́кѡ зе́рно горꙋ́шно, глаго́лали бы́сте ᲂу҆́бѡ ꙗ҆́годичинѣ се́й: восто́ргнисѧ, и҆ всади́сѧ въ мо́ре: и҆ послꙋ́шала бы ва́съ. кото́рый же ѿ ва́съ, ра́бъ и҆мѣ́ѧ ѡ҆рю́щъ и҆лѝ пасꙋ́щъ, и҆́же прише́дшꙋ є҆мꙋ̀ съ села̀ рече́тъ а҆́бїе: минꙋ́въ возлѧ́зи. но не рече́тъ ли є҆мꙋ̀: ᲂу҆гото́вай что̀ вечерѧ́ю, и҆ препоѧ́савсѧ слꙋжи́ ми, до́ндеже ꙗ҆́мъ и҆ пїю̀, и҆ пото́мъ ꙗ҆́си, и҆ пїе́ши ты̀; є҆да̀ и҆́мать хвалꙋ̀ рабꙋ̀ томꙋ̀, ꙗ҆́кѡ сотворѝ повелѣ̑ннаѧ; не мню̀. та́кѡ и҆ вы̀, є҆гда̀ сотворитѐ всѧ̑ повелѣ̑ннаѧ ва́мъ, глаго́лите, ꙗ҆́кѡ рабѝ неключи́ми є҆смы̀: ꙗ҆́кѡ є҆́же до́лжни бѣ́хомъ сотвори́ти, сотвори́хомъ. ",
}

add_evangelie_luki {
  ["номер"] = 85,
  ["комментарий"] = "Лк., 85 зач., XVII, 12–19.",
  ["текст_ру"] = "Во вре́мя о́но, входя́щу Иису́сови в не́кую весь, срето́ша Его́ де́сять прокаже́нных муже́й, и́же ста́ша издале́ча. И ти́и вознесо́ша глас, глаго́люще: Иису́се Наста́вниче, поми́луй ны. И ви́дев рече́ им: ше́дше покажи́теся свяще́нником. И бысть иду́щым им, очи́стишася. Еди́н же от них, ви́дев, я́ко изцеле́, возврати́ся, со гла́сом ве́лиим сла́вя Бо́га, и паде́ ниц при ногу́ Его́, хвалу́ Ему́ воздая́, и той бе Самаряни́н. Отвеща́в же Иису́с рече́: не де́сять ли очи́стишася? Да де́вять где? Ка́ко не обрето́шася возвра́щшеся да́ти сла́ву Бо́гу, то́кмо иноплеме́нник сей? И рече́ ему́: воста́в иди́, ве́ра твоя́ спасе́ тя. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, входѧ́щꙋ і҆и҃сови въ нѣ́кꙋю ве́сь, срѣто́ша є҆го̀ де́сѧть прокаже́нныхъ мꙋже́й, и҆̀же ста́ша и҆здале́ча. и҆ ті́и вознесо́ша гла́съ, глаго́люще: і҆и҃се наста́вниче, поми́лꙋй ны̀. и҆ ви́дѣвъ речѐ и҆̀мъ: ше́дше покажи́тесѧ сщ҃е́нникѡмъ. и҆ бы́сть и҆дꙋ́щымъ и҆̀мъ, ѡ҆чи́стишасѧ. є҆ди́нъ же ѿ ни́хъ ви́дѣвъ, ꙗ҆́кѡ и҆сцѣлѣ̀, возврати́сѧ, со гла́сомъ ве́лїимъ сла́вѧ бг҃а. и҆ падѐ ни́цъ при ногꙋ̀ є҆гѡ̀, хвалꙋ̀ є҆мꙋ̀ воздаѧ̀: и҆ то́й бѣ̀ самарѧни́нъ. ѿвѣща́въ же і҆и҃съ речѐ: не де́сѧть ли ѡ҆чи́стишасѧ, да де́вѧть гдѣ̀; ка́кѡ не ѡ҆брѣто́шасѧ, возвра́щшесѧ да́ти сла́вꙋ бг҃ꙋ, то́кмѡ и҆ноплеме́нникъ се́й; и҆ речѐ є҆мꙋ̀: воста́въ, и҆дѝ, вѣ́ра твоѧ̀ спасѐ тѧ̀. ",
}

add_evangelie_luki {
  ["номер"] = 86,
  ["комментарий"] = "Лк., 86 зач., XVII, 20–25.",
  ["текст_ру"] = "Во вре́мя о́но, вопроше́н быв Иису́с от фарисе́й, когда́ прии́дет Ца́рствие Бо́жие, отвеща́в им рече́: не прии́дет Ца́рствие Бо́жие с соблюде́нием. Ниже́ реку́т: се зде, или́: о́нде. Се бо, Ца́рствие Бо́жие внутрь вас есть. Рече́ же ко ученико́м Свои́м: прии́дут дни́е, егда́ вожделе́ете еди́наго дне Сы́на Челове́ческаго ви́дети, и не у́зрите. И реку́т вам: се зде, се о́нде, не изы́дите, ни пожени́те. Я́ко бо мо́лния блиста́ющися от поднебе́сныя на поднебе́сней све́тится, та́ко бу́дет Сын Челове́ческий в день Свой. Пре́жде же подоба́ет Ему́ мно́го пострада́ти и искуше́ну бы́ти от ро́да сего́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, вопроше́нъ бы́въ і҆и҃съ ѿ фарїсє́й: когда̀ прїи́детъ црⷭ҇твїе бж҃їе; ѿвѣща́въ и҆̀мъ, речѐ: не прїи́детъ црⷭ҇твїе бж҃їе съ соблюде́нїемъ. нижѐ рекꙋ́тъ: сѐ здѣ̀, и҆лѝ ѻ҆́ндѣ: се́ бо црⷭ҇твїе бж҃їе внꙋ́трь ва́съ є҆́сть. рече́ же ко ᲂу҆ченикѡ́мъ свои́мъ: прїи́дꙋтъ дні́е, є҆гда̀ вожделѣ́ете є҆ди́нагѡ днѐ сн҃а чл҃вѣ́ческагѡ ви́дѣти, и҆ не ᲂу҆́зрите. и҆ рекꙋ́тъ ва́мъ: сѐ здѣ̀, сѐ ѻ҆́ндѣ: не и҆зы́дите, ни пожени́те. ꙗ҆́кѡ бо мо́лнїѧ блиста́ющисѧ ѿ поднбⷭ҇ныѧ, на поднбⷭ҇нѣй свѣ́титсѧ: та́кѡ бꙋ́детъ сн҃ъ чл҃вѣ́ческїй въ де́нь сво́й. пре́жде же подоба́етъ є҆мꙋ̀ мно́гѡ пострада́ти, и҆ і҆скꙋше́нꙋ бы́ти ѿ ро́да сегѡ̀. ",
}

add_evangelie_luki {
  ["номер"] = 87,
  ["комментарий"] = "Лк., 87 зач., XVII, 26–37.",
  ["текст_ру"] = "Рече́ Госпо́дь: я́коже бысть во дни Но́евы, та́ко бу́дет и во дни Сы́на Челове́ческа, ядя́ху, пия́ху, женя́хуся, посяга́ху, до него́же дне вни́де Но́е в ковче́г, и прии́де пото́п и погуби́ вся. Та́кожде и я́коже бысть во дни Ло́товы, ядя́ху, пия́ху, купова́ху, продая́ху, сажда́ху, зда́ху, во́ньже день изы́де Лот от Содо́млян, одожди́ ка́мы горя́щя и огнь с небесе́ и погуби́ вся. По тому́ же бу́дет и в день, во́ньже Сын Челове́ческий яви́тся. В той день, и́же бу́дет на кро́ве, и сосу́ди его́ в дому́, да не сла́зит взя́ти их, и и́же на селе́, та́кожде да не возврати́тся вспять. Помина́йте жену́ Ло́тову. И́же а́ще взы́щет ду́шу свою́ спасти́, погуби́т ю́, и и́же а́ще погуби́т ю́, живи́т ю́. Глаго́лю вам: в ту нощь бу́дета два на одре́ еди́ном, еди́н пое́млется, а други́й оставля́ется. Бу́дете две вку́пе ме́люще, еди́на пое́млется, а друга́я оставля́ется. Два бу́дета на селе́, еди́н пое́млется, а други́й оставля́ется. И отвеща́вше глаго́лаша Ему́: где, Го́споди? Он же рече́ им: иде́же те́ло, та́мо соберу́тся и орли́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: ꙗ҆́коже бы́сть во днѝ нѡ́евы, та́кѡ бꙋ́детъ и҆ во днѝ сн҃а человѣ́ческа. ꙗ҆дѧ́хꙋ, пїѧ́хꙋ, женѧ́хꙋсѧ, посѧга́хꙋ: до негѡ́же днѐ вни́де нѡ́е въ ковче́гъ: и҆ прїи́де пото́пъ, и҆ погꙋбѝ всѧ̑. та́кожде и҆ ꙗ҆́коже бы́сть во дни̑ лѡ́товы: ꙗ҆дѧ́хꙋ, пїѧ́хꙋ, кꙋпова́хꙋ, продаѧ́хꙋ, сажда́хꙋ, зда́хꙋ: во́ньже де́нь и҆зы́де лѡ́тъ ѿ содо́млѧнъ, ѡ҆дождѝ ка́мы горѧ́щѧ, и҆ ѻ҆́гнь съ небесѐ, и҆ погꙋбѝ всѧ̑. по томꙋ́ же бꙋ́детъ и҆ въ де́нь, во́ньже сн҃ъ чл҃вѣ́ческїй ꙗ҆ви́тсѧ. въ то́й де́нь, и҆́же бꙋ́детъ на кро́вѣ, и҆ сосꙋ́ди є҆гѡ̀ въ домꙋ̀, да не сла́зитъ взѧ́ти и҆̀хъ: и҆ и҆́же на селѣ̀, та́кожде да не возврати́тсѧ вспѧ́ть. помина́йте женꙋ̀ лѡ́товꙋ. и҆́же а҆́ще взы́щетъ дꙋ́шꙋ свою̀ спастѝ, погꙋби́тъ ю҆̀: и҆ и҆́же а҆́ще погꙋби́тъ ю҆̀, живи́тъ ю҆̀. глаго́лю ва́мъ: въ тꙋ̀ но́щь бꙋ́дета два̀ на ѻ҆дрѣ̀ є҆ди́номъ: є҆ди́нъ пое́млетсѧ, а҆ дрꙋгі́й ѡ҆ставлѧ́етсѧ. бꙋ́детѣ двѣ̀ вкꙋ́пѣ ме́лющѣ: є҆ди́на пое́млетсѧ, а҆ дрꙋга́ѧ ѡ҆ставлѧ́етсѧ. два̀ бꙋ́дета на селѣ̀: є҆ди́нъ пое́млетсѧ, а҆ дрꙋгі́й ѡ҆ставлѧ́етсѧ. и҆ ѿвѣща́вше глаго́лаша є҆мꙋ̀: гдѣ̀ гдⷭ҇и; ѻ҆́нъ же речѐ и҆̀мъ: и҆дѣ́же тѣ́ло, та́мѡ соберꙋ́тсѧ и҆ ѻ҆рлѝ. ",
}

add_evangelie_luki {
  ["номер"] = 88,
  ["комментарий"] = "Лк., 88 зач., XVIII, 2–8.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: судия́ бе не́кий в не́коем гра́де, Бо́га не боя́ся и челове́к не срамля́яся. Вдова́ же не́кая бе во гра́де том, и прихожда́ше к нему́, глаго́лющи: отмсти́ мене́ от сопе́рника моего́. И не хотя́ше на до́лзе вре́мени. Последи́ же рече́ в себе́: а́ще и Бо́га не бою́ся, и челове́к не срамля́юся, но зане́ твори́т ми труды́ вдови́ца сия́, да отмщу́ ея́, да не до конца́ приходя́щи застои́т мене́. Рече́ же Госпо́дь: слы́шите, что судия́ непра́вды глаго́лет? Бог же не и́мать ли сотвори́ти отмще́ние избра́нных Свои́х, вопию́щих к Нему́ день и нощь, и долготерпя́ о них? Глаго́лю вам, я́ко сотвори́т отмще́ние их вско́ре. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: сꙋдїѧ̀ бѣ̀ нѣ́кїй въ нѣ́коемъ гра́дѣ, бг҃а не боѧ́сѧ, и҆ человѣ̑къ не срамлѧ́ѧсѧ. вдова́ же нѣ́каѧ бѣ̀ во гра́дѣ то́мъ, и҆ прихожда́ше къ немꙋ̀, глаго́лющи: ѿмстѝ менѐ ѿ сопе́рника моегѡ̀. и҆ не хотѧ́ше на до́лзѣ вре́мени. послѣди́ же речѐ въ себѣ̀: а҆́ще и҆ бг҃а не бою́сѧ, и҆ человѣ̑къ не срамлѧ́юсѧ: но занѐ твори́тъ мѝ трꙋды̀ вдови́ца сїѧ̀, да ѿмщꙋ̀ є҆ѧ̀: да не до конца̀ приходѧ́щи, застои́тъ менѐ. рече́ же гдⷭ҇ь: слы́шите, что̀ сꙋдїѧ̀ непра́вды глаго́летъ; бг҃ъ же не и҆́мать ли сотвори́ти ѿмще́нїе и҆збра́нныхъ свои́хъ, вопїю́щихъ къ немꙋ̀ де́нь и҆ но́щь, и҆ долготерпѧ̀ ѡ҆ ни́хъ; глаго́лю ва́мъ, ꙗ҆́кѡ сотвори́тъ ѿмще́нїе и҆́хъ вско́рѣ. ",
}

add_evangelie_luki {
  ["номер"] = 89,
  ["комментарий"] = "Лк., 89 зач., XVIII, 10–14.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: челове́ка два внидо́ста в це́рковь помоли́тися, еди́н фарисе́й, а други́й мыта́рь. Фарисе́й же став, си́це в себе́ моля́шеся: Бо́же, хвалу́ Тебе́ воздаю́, я́ко несмь я́коже про́чии челове́цы, хи́щницы, непра́ведницы, прелюбоде́е, или́ я́коже сей мыта́рь. Пощу́ся двакра́ты в суббо́ту, десяти́ну даю́ всего́ ели́ко притяжу́. Мыта́рь же издале́ча стоя́, не хотя́ше ни о́чию возвести́ на не́бо, но бия́ше пе́рси своя́, глаго́ля: Бо́же, ми́лостив бу́ди мне гре́шнику. Глаго́лю вам, я́ко сни́де сей оправда́н в дом свой па́че о́наго, я́ко всяк вознося́йся смири́тся, смиря́яй же себе́ вознесе́тся. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: человѣ́ка два̀ внидо́ста въ це́рковь помоли́тисѧ: є҆ди́нъ фарїсе́й, а҆ дрꙋгі́й мыта́рь. фарїсе́й же ста́въ си́це въ себѣ̀ молѧ́шесѧ: бж҃е, хвалꙋ̀ тебѣ̀ воздаю̀, ꙗ҆́кѡ нѣ́смь ꙗ҆́коже про́чїи человѣ́цы, хи́щницы, непра́вєдницы, прелюбодѣ́є, и҆лѝ ꙗ҆́коже се́й мыта́рь. пощꙋ́сѧ двакра́ты въ сꙋббѡ́тꙋ, десѧти́нꙋ даю̀ всегѡ̀ є҆ли́кѡ притѧжꙋ̀. мыта́рь же и҆здале́ча стоѧ̀, не хотѧ́ше ни ѻ҆́чїю возвестѝ на нб҃о, но бїѧ́ше пє́рси своѧ̀, глаго́лѧ: бж҃е, ми́лостивъ бꙋ́ди мнѣ̀ грѣ́шникꙋ. глаго́лю ва́мъ, ꙗ҆́кѡ сни́де се́й ѡ҆правда́нъ въ до́мъ сво́й па́че ѻ҆́нагѡ: ꙗ҆́кѡ всѧ́къ возносѧ́йсѧ, смири́тсѧ: смирѧ́ѧй же себѐ, вознесе́тсѧ. ",
}

add_evangelie_luki {
  ["номер"] = 90,
  ["комментарий"] = "Лк., 90 зач., XVIII, 15–17, 26–30.",
  ["текст_ру"] = "Во вре́мя о́но, приноша́ху ко Иису́су младе́нцы, да их ко́снется, ви́девше же ученицы́ запрети́ша им. Иису́с же призва́в их, глаго́ла: оста́вите дете́й приходи́ти ко Мне и не брани́те им, таковы́х бо есть Ца́рствие Бо́жие. Ами́нь бо глаго́лю вам: и́же а́ще не прии́мет Ца́рствия Бо́жия я́ко отроча́, не и́мать вни́ти в не. Ре́ша же слы́шавшии: то кто мо́жет спасе́н бы́ти? Он же рече́: невозмо́жная от челове́к возмо́жна суть от Бо́га. Рече́ же Петр: се мы оста́вихом вся и по Тебе́ идо́хом. Он же рече́ им: ами́нь глаго́лю вам, я́ко никто́же есть, и́же оста́вит дом, или́ роди́тели, или́ бра́тию, или́ сестры́, или́ жену́, или́ ча́да, Ца́рствия ра́ди Бо́жия, и́же не прии́мет мно́жицею во вре́мя сие́, и в век гряду́щий живо́т ве́чный. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, приноша́хꙋ ко і҆и҃сꙋ младе́нцы, да и҆́хъ ко́снетсѧ: ви́дѣвше же ᲂу҆ченицы̀ запрети́ша и҆̀мъ. і҆и҃съ же призва́въ и҆̀хъ, глаго́ла: ѡ҆ста́вите дѣте́й приходи́ти ко мнѣ̀, и҆ не брани́те и҆̀мъ, таковы́хъ бо є҆́сть црⷭ҇твїе бж҃їе. а҆ми́нь бо глаго́лю ва́мъ: и҆́же а҆́ще не прїи́метъ црⷭ҇твїѧ бж҃їѧ ꙗ҆́кѡ ѻ҆троча̀, не и҆́мать вни́ти въ нѐ. рѣ́ша же слы́шавшїи: то̀ кто̀ мо́жетъ спасе́нъ бы́ти; ѻ҆́нъ же речѐ: невозмѡ́жнаѧ ѿ человѣ̑къ, возмѡ́жна сꙋ́ть ѿ бг҃а. рече́ же пе́тръ: сѐ мы̀ ѡ҆ста́вихомъ всѧ̑, и҆ по тебѣ̀ и҆до́хомъ. ѻ҆́нъ же речѐ и҆̀мъ: а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ никто́же є҆́сть, и҆́же ѡ҆ста́витъ до́мъ, и҆лѝ роди́тели, и҆лѝ бра́тїю, и҆лѝ сєстры̀, и҆лѝ женꙋ̀, и҆лѝ ча̑да црⷭ҇твїѧ ра́ди бж҃їѧ: и҆́же не прїи́метъ мно́жицею во вре́мѧ сїѐ, и҆ въ вѣ́къ грѧдꙋ́щїй живо́тъ вѣ́чный. ",
}

add_evangelie_luki {
  ["номер"] = 91,
  ["комментарий"] = "Лк., 91 зач., XVIII, 18-27.",
  ["текст_ру"] = "Во вре́мя о́но, челове́к не́кий приступи́ ко Иису́су, искуша́я Его́, и глаго́ля: Учи́телю благи́й, что сотвори́в, живо́т ве́чный насле́дствую? Рече́ же ему́ Иису́с: что Мя глаго́леши бла́га? Никто́же благ, то́кмо еди́н Бог. За́поведи ве́си, не прелюбы́ твори́, не уби́й, не укра́ди, не лжесвиде́тельствуй, чти отца́ твоего́ и ма́терь твою́. Он же рече́: вся сия́ сохрани́х от ю́ности моея́. Слы́шав же сия́ Иису́с рече́ ему́: еще́ еди́наго не доконча́л еси́, вся, ели́ка и́маши, прода́ждь и разда́й ни́щым, и име́ти и́маши сокро́вище на небеси́, и гряди́ во след Мене́. Он же слы́шав сие́, приско́рбен бысть, бе бо бога́т зело́. Ви́дев же его́ Иису́с приско́рбна бы́вша, рече́: ка́ко не удо́бь иму́щии бога́тство в Ца́рствие Бо́жие вни́дут. Удо́бее бо есть вельбу́ду сквозе́ иглине́ у́ши проити́, не́же бога́ту в Ца́рствие Бо́жие вни́ти. Ре́ша же слы́шавшии: то кто мо́жет спасе́н бы́ти? Он же рече́: невозмо́жная от челове́к возмо́жна суть от Бо́га. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, человѣ́къ нѣ́кїй пристꙋпѝ ко і҆и҃сꙋ, и҆скꙋша́ѧ є҆го̀, и҆ глаго́лѧ: ᲂу҆чт҃лю благі́й, что̀ сотвори́въ, живо́тъ вѣ́чный наслѣ́дствꙋю; рече́ же є҆мꙋ̀ і҆и҃съ: что́ мѧ глаго́леши бла́га; никто́же бла́гъ то́кмѡ є҆ди́нъ бг҃ъ. за́пѡвѣди вѣ́си: не прелюбы̀ творѝ: не ᲂу҆бі́й: не ᲂу҆кра́ди: не лжесвидѣ́тельствꙋй: чтѝ ѻ҆тца̀ твоего̀ и҆ ма́терь твою̀. ѻ҆́нъ же речѐ: всѧ̑ сїѧ̑ сохрани́хъ ѿ ю҆́ности моеѧ̀. слы́шавъ же сїѧ̀ і҆и҃съ, речѐ є҆мꙋ̀: є҆щѐ є҆ди́нагѡ не доконча́лъ є҆сѝ: всѧ̑ є҆ли̑ка и҆́маши, прода́ждь и҆ разда́й ни́щымъ, и҆ и҆мѣ́ти и҆́маши сокро́вище на нб҃сѝ, и҆ грѧдѝ во слѣ́дъ менѐ. ѻ҆́нъ же слы́шавъ сїѐ, приско́рбенъ бы́сть: бѣ́ бо бога́тъ ѕѣлѡ̀. ви́дѣвъ же є҆го̀ і҆и҃съ приско́рбна бы́вша, речѐ: ка́кѡ не ᲂу҆до́бь и҆мꙋ́щїи бога́тство, въ црⷭ҇твїе бж҃їе вни́дꙋтъ. ᲂу҆до́бѣе бо є҆́сть вельбꙋ́дꙋ сквозѣ̀ и҆глинѣ̀ ᲂу҆́ши проитѝ, не́же бога́тꙋ въ црⷭ҇твїе бж҃їе вни́ти. рѣ́ша же слы́шавшїи: то̀ кто̀ мо́жетъ спасе́нъ бы́ти; ѻ҆́нъ же речѐ: невозмѡ́жнаѧ ѿ человѣ̑къ, возмѡ́жна сꙋ́ть ѿ бг҃а. ",
}

add_evangelie_luki {
  ["номер"] = 92,
  ["комментарий"] = "Лк., 92 зач., XVIII, 31–34.",
  ["текст_ру"] = "Во вре́мя о́но, пое́м Иису́с обана́десяте ученика́ Своя́, рече́ к ним: се восхо́дим во Иерусали́м, и сконча́ются вся пи́санная проро́ки о Сы́не Челове́честе. Предадя́т бо Его́ язы́ком и поруга́ются Ему́, и укоря́т Его́ и оплю́ют Его́, и би́вше убию́т Его́, и в тре́тий день воскре́снет. И ти́и ничесо́же от сих разуме́ша, и бе глаго́л сей сокрове́н от них, и не разумева́ху глаго́лемых. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пое́мъ і҆и҃съ ѻ҆бана́десѧте ᲂу҆чєника̀ своѧ̀, речѐ къ ни́мъ: сѐ восхо́димъ во і҆ерꙋсали́мъ, и҆ сконча́ютсѧ всѧ̑ пи̑саннаѧ проро́ки ѡ҆ сн҃ѣ человѣ́честѣ. предадѧ́тъ бо є҆го̀ ꙗ҆зы́кѡмъ, и҆ порꙋга́ютсѧ є҆мꙋ̀, и҆ ᲂу҆корѧ́тъ є҆го̀, и҆ ѡ҆плю́ютъ є҆го̀: и҆ би́вше ᲂу҆бїю́тъ є҆го̀, и҆ въ тре́тїй де́нь воскре́снетъ. и҆ ті́и ничесо́же ѿ си́хъ разꙋмѣ́ша: и҆ бѣ̀ глаго́лъ се́й сокрове́нъ ѿ ни́хъ, и҆ не разꙋмѣва́хꙋ глаго́лемыхъ. ",
}

add_evangelie_luki {
  ["номер"] = 93,
  ["комментарий"] = "Лк., 93 зач., XVIII, 35-43.",
  ["текст_ру"] = "Во вре́мя о́но, егда́ прибли́жися Иису́с во Иерихо́н, слепе́ц не́кий седя́ше при пути́ прося́. Слы́шав же наро́д мимоходя́щь, вопроша́ше: что у́бо есть сие́? Пове́даша же ему́, я́ко Иису́с Назаряни́н мимохо́дит. И возопи́, глаго́ля: Иису́се Сы́не Дави́дов, поми́луй мя. И предиду́щии преща́ху ему́, да умолчи́т, он же па́че мно́жае вопия́ше: Сы́не Дави́дов, поми́луй мя. Став же Иису́с повеле́ привести́ его́ к Себе́. Прибли́жшу же ся ему́ к Нему́, вопроси́ его́, глаго́ля: что хо́щеши, да ти сотворю́? Он же рече́: Го́споди, да прозрю́. Иису́с же рече́ ему́: прозри́, ве́ра твоя́ спасе́ тя. И а́бие прозре́, и во след Его́ идя́ше, сла́вя Бо́га. И вси лю́дие ви́девше возда́ша хвалу́ Бо́гови. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, є҆гда̀ прибли́жисѧ і҆и҃съ во і҆ерїхѡ́нъ, слѣпе́цъ нѣ́кїй сѣдѧ́ше при пꙋтѝ просѧ̀. слы́шавъ же наро́дъ мимоходѧ́щь, вопроша́ше: что̀ ᲂу҆́бѡ є҆́сть сїѐ; повѣ́даша же є҆мꙋ̀, ꙗ҆́кѡ і҆и҃съ назарѧни́нъ мимохо́дитъ. и҆ возопѝ, глаго́лѧ: і҆и҃се сн҃е дв҃довъ, поми́лꙋй мѧ̀. и҆ пред̾идꙋ́щїи преща́хꙋ є҆мꙋ̀, да ᲂу҆молчи́тъ, ѻ҆́нъ же па́че мно́жае вопїѧ́ше: сн҃е дв҃довъ, поми́лꙋй мѧ̀. ста́въ же і҆и҃съ, повелѣ̀ привестѝ є҆го̀ къ себѣ̀. прибли́жшꙋ же сѧ є҆мꙋ̀ къ немꙋ̀, вопросѝ є҆го̀, глаго́лѧ: что̀ хо́щеши, да тѝ сотворю̀; ѻ҆́нъ же речѐ: гдⷭ҇и, да прозрю̀. і҆и҃съ же речѐ є҆мꙋ̀: прозрѝ, вѣ́ра твоѧ̀ спасе́ тѧ. и҆ а҆́бїе прозрѣ̀, и҆ во слѣ́дъ є҆гѡ̀ и҆дѧ́ше сла́вѧ бг҃а. и҆ всѝ лю́дїе ви́дѣвше, возда́ша хвалꙋ̀ бг҃ови. ",
}

add_evangelie_luki {
  ["номер"] = 94,
  ["комментарий"] = "Лк., 94 зач., XIX, 1-10.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с во Иерихо́н. И се муж нарица́емый Закхе́й, и сей бе ста́рей мытаре́м, и той бе бога́т. И иска́ше ви́дети Иису́са, кто есть, и не можа́ше от наро́да, я́ко во́зрастом мал бе. И предите́к, возле́зе на я́годичину, да ви́дит, я́ко туде́ хотя́ше мину́ти. И я́ко прии́де на ме́сто, воззре́в Иису́с ви́дев его́ и рече́ к нему́: Закхе́е, потща́вся сле́зи, днесь бо в дому́ твое́м подоба́ет Ми бы́ти. И потща́вся сле́зе и прия́т Его́ ра́дуяся. И ви́девше вси ропта́ху, глаго́люще, я́ко ко гре́шну му́жу вни́де вита́ти. Став же Закхе́й рече́ ко Го́споду: се пол име́ния моего́, Го́споди, дам ни́щым, и а́ще кого́ чим оби́дех, возвращу́ четвери́цею. Рече́ же к нему́ Иису́с, я́ко днесь спасе́ние до́му сему́ бысть, зане́ и сей сын Авраа́мль есть. Прии́де бо Сын Челове́чь взыска́ти и спасти́ поги́бшаго. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ во і҆ерїхѡ́нъ. и҆ сѐ мꙋ́жъ нарица́емый закхе́й и҆ се́й бѣ̀ ста́рѣй мытарє́мъ, и҆ то́й бѣ̀ бога́тъ. и҆ и҆ска́ше ви́дѣти і҆и҃са, кто́ є҆сть: и҆ не можа́ше ѿ наро́да, ꙗ҆́кѡ во́зрастомъ ма́лъ бѣ̀. и҆ предите́къ возлѣ́зе на ꙗ҆́годичинꙋ, да ви́дитъ, ꙗ҆́кѡ тꙋдѣ̀ хотѧ́ше минꙋ́ти: и҆ ꙗ҆́кѡ прїи́де на мѣ́сто, воззрѣ́въ і҆и҃съ, ви́дѣвъ є҆го̀, и҆ речѐ къ немꙋ̀: закхе́е, потща́всѧ слѣ́зи, дне́сь бо въ домꙋ̀ твое́мъ подоба́етъ мѝ бы́ти. и҆ потща́всѧ слѣ́зе, и҆ прїѧ́тъ є҆го̀ ра́дꙋѧсѧ. и҆ ви́дѣвше всѝ ропта́хꙋ, глаго́люще, ꙗ҆́кѡ ко грѣ́шнꙋ мꙋ́жꙋ вни́де вита́ти. ста́въ же закхе́й речѐ ко гдⷭ҇ꙋ: сѐ по́лъ и҆мѣ́нїѧ моегѡ̀, гдⷭ҇и, да́мъ ни́щымъ: и҆ а҆́ще кого̀ чи́мъ ѡ҆би́дѣхъ, возвращꙋ̀ четвери́цею. рече́ же къ немꙋ̀ і҆и҃съ, ꙗ҆́кѡ дне́сь спасе́нїе до́мꙋ семꙋ̀ бы́сть: занѐ и҆ се́й сы́нъ а҆враа́мль є҆́сть. прїи́де бо сн҃ъ человѣ́чь взыска́ти, и҆ спастѝ поги́бшаго. ",
}

add_evangelie_luki {
  ["номер"] = 95,
  ["комментарий"] = "Лк., 95 зач., XIX, 12–28.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: челове́к не́кий добра́ ро́да и́де на страну́ дале́че прия́ти себе́ ца́рство и возврати́тися. Призва́в же де́сять раб свои́х, даде́ им де́сять мнас и рече́ к ним: ку́плю де́йте, до́ндеже прииду́. И гра́ждане его́ ненави́дяху его́ и посла́ша моли́тву в след его́, глаго́люще: не хо́щем сему́, да ца́рствует над на́ми. И бысть егда́ возврати́ся прии́м ца́рство, рече́ пригласи́ти рабы́ ти́и, и́мже даде́ сребро́, да уве́сть, какову́ ку́плю суть сотвори́ли. Прии́де же пе́рвый, глаго́ля: го́споди, мнас твоя́ приде́ла де́сять мнас. И рече́ ему́: благи́й ра́бе и до́брый, я́ко о ма́ле ве́рен был еси́, бу́ди о́бласть име́я над десятию́ градо́в. И прии́де вторы́й, глаго́ля: го́споди, мнас твоя́ сотвори́ пять мнас. Рече́ же и тому́: и ты бу́ди над пятию́ градо́в. И други́й прии́де, глаго́ля: го́споди, се мнас твоя́, ю́же име́х положе́ну во убру́се. Боя́хся бо тебе́, я́ко челове́к яр еси́, взе́млеши, его́же не положи́, и жне́ши, его́же не се́яв. Глаго́ла же ему́: от уст твои́х сужду́ ти, лука́вый ра́бе, ве́дяше, я́ко аз челове́к яр есмь, вземлю́, его́же не положи́в, и жну, его́же не се́яв, и почто́ не вдал еси́ моего́ сребра́ купце́м, и аз прише́д с ли́хвою истяза́л бых е́? И предстоя́щым рече́: возьми́те от него́ мнас и дади́те иму́щему де́сять мнас. И ре́ша ему́: го́споди, и́мать де́сять мнас. Глаго́лю бо вам, я́ко вся́кому иму́щему да́стся, а от неиму́щаго, и е́же и́мать, оти́мется от него́. Оба́че враги́ моя́ о́ны, и́же не восхо́теша мне, да царь бых был над ни́ми, приведи́те се́мо и изсецы́те пре́до мно́ю. И сия́ рек, идя́ше преди́, восходя́ во Иерусали́м. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: человѣ́къ нѣ́кїй добра̀ ро́да и҆́де на странꙋ̀ дале́че, прїѧ́ти себѣ̀ црⷭ҇тво, и҆ возврати́тисѧ. призва́въ же де́сѧть ра̑бъ свои́хъ, дадѐ и҆̀мъ де́сѧть мна̑съ, и҆ речѐ къ ни́мъ: кꙋ́плю дѣ́йте до́ндеже прїидꙋ̀. и҆ гра́ждане є҆гѡ̀ ненави́дѧхꙋ є҆го̀, и҆ посла́ша моли́твꙋ въ слѣ́дъ є҆гѡ̀, глаго́люще: не хо́щемъ семꙋ̀, да ца́рствꙋетъ над̾ на́ми. и҆ бы́сть є҆гда̀ возврати́сѧ, прїи́мъ црⷭ҇тво, речѐ пригласи́ти рабы̀ ті́и, и҆̀мже дадѐ сребро̀, да ᲂу҆вѣ́сть, каковꙋ̀ кꙋ́плю сꙋ́ть сотвори́ли. прїи́де же пе́рвый, глаго́лѧ: гдⷭ҇и, мна́съ твоѧ̀ придѣ́ла де́сѧть мна̑съ. и҆ речѐ є҆мꙋ̀: благі́й ра́бе и҆ до́брый, ꙗ҆́кѡ ѡ҆ ма́лѣ вѣ́ренъ бы́лъ є҆сѝ, бꙋ́ди ѻ҆́бласть и҆мѣ́ѧ над̾ десѧтїю̀ градѡ́въ. и҆ прїи́де вторы́й, глаго́лѧ: гдⷭ҇и, мна́съ твоѧ̀ сотворѝ пѧ́ть мна̑съ. рече́ же и҆ томꙋ̀: и҆ ты̀ бꙋ́ди над̾ пѧтїю̀ градѡ́въ. и҆ дрꙋгі́й прїи́де, глаго́лѧ: гдⷭ҇и, сѐ мна́съ твоѧ̀, ю҆́же и҆мѣ́хъ положе́нꙋ во ᲂу҆брꙋ́сѣ. боѧ́хсѧ бо тебѐ, ꙗ҆́кѡ человѣ́къ ꙗ҆́ръ є҆сѝ: взе́млеши є҆гѡ́же не положѝ, и҆ жне́ши є҆гѡ́же не сѣ́ѧвъ. глаго́ла же є҆мꙋ̀: ѿ ᲂу҆́стъ твои́хъ сꙋждꙋ́ ти, лꙋка́вый ра́бе: вѣ́дѧше, ꙗ҆́кѡ а҆́зъ человѣ́къ ꙗ҆́ръ є҆́смь, вземлю̀ є҆гѡ́же не положи́въ, и҆ жнꙋ̀ є҆гѡ́же не сѣ́ѧвъ. и҆ почто̀ не вда́лъ є҆сѝ моегѡ̀ сребра̀ кꙋпцє́мъ, и҆ а҆́зъ прише́дъ, съ ли́хвою и҆стѧза́лъ бы́хъ є҆̀; и҆ предстоѧ́щымъ речѐ: воз̾ми́те ѿ негѡ̀ мна́съ, и҆ дади́те и҆мꙋ́щемꙋ де́сѧть мна̑съ. и҆ рѣ́ша є҆мꙋ̀: гдⷭ҇и, и҆́мать де́сѧть мна̑съ. глаго́лю бо ва́мъ, ꙗ҆́кѡ всѧ́комꙋ и҆мꙋ́щемꙋ да́стсѧ: а҆ ѿ неимꙋ́щагѡ, и҆ є҆́же и҆́мать, ѿи́метсѧ ѿ негѡ̀. ѻ҆ба́че врагѝ моѧ̀ ѻ҆́ны, и҆̀же не хотѣ́вшыѧ мнѣ̀, да цр҃ь бы́хъ бы́лъ над̾ ни́ми, приведи́те сѣ́мѡ, и҆ и҆зсѣцы́те предо мно́ю. и҆ сїѧ̑ ре́къ, и҆дѧ́ше предѝ восходѧ̀ во і҆ерꙋсали́мъ. ",
}

add_evangelie_luki {
  ["номер"] = 96,
  ["комментарий"] = "Лк., 96 зач., XIX, 29–40; XXII, 7–39.",
  ["текст_ру"] = "Во вре́мя о́но, я́ко прибли́жися Иису́с в Вифсфаги́ю и Вифа́нию, к горе́ нарица́емей Елео́н, посла́ два учени́к Свои́х, глаго́ля: иди́те в пря́мную весь, и в ню́же входя́ща обря́щета жребя́ привя́зано, на не́же никто́же николи́же от челове́к все́де, отре́шша е́ приведи́та. И а́ще кто вы вопроша́ет: почто́ отреша́ета? Си́це рцы́та ему́, я́ко Госпо́дь его́ тре́бует. Ше́дша же по́сланная обрето́ста, я́коже рече́ и́ма. Отреша́ющема же и́ма жребя́, реко́ша госпо́дие его́ к ни́ма: что отреша́ета жребя́? О́на же реко́ста, я́ко Госпо́дь его́ тре́бует. И приведо́ста е́ ко Иису́сови, и возве́ргше ри́зы своя́ на жребя́, всади́ша Иису́са. Иду́щу же Ему́, постила́ху ри́зы своя́ по пути́. Приближа́ющу же ся Ему́ уже́ а́бие к низхожде́нию го́ре Елео́нстей, нача́ша все мно́жество учени́к ра́дующеся хвали́ти Бо́га гла́сом ве́лиим о всех си́лах, я́же ви́деша, глаго́люще: благослове́н гряды́й Царь во и́мя Госпо́дне, мир на небеси́ и сла́ва в вы́шних. И не́цыи фарисе́е от наро́да ре́ша к Нему́: Учи́телю, запрети́ ученико́м Твои́м. И отвеща́в рече́ им: глаго́лю вам, я́ко а́ще си́и умолча́т, ка́мение возопие́т. Прии́де же день опресно́к, во́ньже подо́бно бе вре́мя жре́ти па́сху, и посла́ Петра́ и Иоа́нна, рек: ше́дша угото́вайта нам па́сху, да я́мы. О́на же реко́ста Ему́: где хо́щеши угото́ваем? Он же рече́ и́м: се восходя́щема ва́ма во град, сря́щет вы челове́к в скуде́льнице во́ду нося́, по нем иде́та в дом, во́ньже вхо́дит, и рце́та до́му влады́це: глаго́лет тебе́ Учи́тель, где есть оби́тель, иде́же па́сху со ученики́ Мои́ми снем? И той ва́ма пока́жет го́рницу ве́лию по́стлану, ту угото́вайта. Ше́дша же обрето́ста, я́коже рече́ и́ма, и угото́васта па́сху. И егда́ бысть час, возлеже́, и обана́десяте Апо́стола с Ним, и рече́ к ним: жела́нием возжеле́х сию́ па́сху я́сти с ва́ми, пре́жде да́же не прииму́ мук. Глаго́лю бо вам, я́ко отсе́ле не и́мам я́сти от него́, до́ндеже сконча́ются во Ца́рствии Бо́жии. И прии́м ча́шу, хвалу́ возда́в, рече́: приими́те сию́, и раздели́те себе́. Глаго́лю бо вам, я́ко не и́мам пи́ти от плода́ ло́знаго, до́ндеже Ца́рствие Бо́жие прии́дет. И прии́м хлеб, хвалу́ возда́в, преломи́ и даде́ им, глаго́ля: сие́ есть те́ло Мое́, е́же за вы дае́мо, сие́ твори́те в Мое́ воспомина́ние. Та́кожде же и ча́шу по ве́чери, глаго́ля: сия́ ча́ша Но́вый Заве́т Мое́ю кро́вию, я́же за вы пролива́ется. Оба́че се рука́ предаю́щаго Мя со Мно́ю есть на трапе́зе, и Сын у́бо Челове́ческий и́дет по рече́нному, оба́че го́ре челове́ку тому́, и́мже предае́тся. И ти́и нача́ша иска́ти в себе́, кото́рый у́бо от них хотя́й сие́ сотвори́ти. Бысть же и пря в них, кий мни́тся их бы́ти бо́лий. Он же рече́ им: ца́рие язы́к госпо́дствуют и́ми, и облада́ющии и́ми благода́теле нарица́ются, вы же не та́ко, но бо́лий в вас, да бу́дет я́ко мний, и ста́рей, я́ко служа́й. Кто бо бо́лий, возлежа́й ли, или́ служа́й? Не возлежа́й ли? Аз же посреде́ вас есмь я́ко служа́й. Вы же есте́ пребы́вше со Мно́ю в напа́стех Мои́х, и Аз завещава́ю вам, я́коже завеща́ Мне Оте́ц Мой, Ца́рство, да я́сте и пие́те на трапе́зе Мое́й во Ца́рствии Мое́м, и ся́дете на престо́лех, судя́ще обемана́десяте коле́нома Изра́илевыма. Рече́ же Госпо́дь: Си́моне, Си́моне, се сатана́ про́сит вас, дабы́ се́ял, я́ко пшени́цу, Аз же моли́хся о тебе́, да не оскуде́ет ве́ра твоя́, и ты не́когда обра́щься утверди́ бра́тию твою́. Он же рече́ Ему́: Го́споди, с Тобо́ю гото́в есмь и в темни́цу и в смерть ити́. Он же рече́: глаго́лю ти, Пе́тре, не возгласи́т пе́тель днесь, до́ндеже трикра́ты отве́ржешися Мене́ не ве́дети. И рече́ им: егда́ посла́х вы без влага́лища и без ме́ха и без сапо́г, еда́ что лише́ни бы́сте? Они́ же ре́ша: ничесо́же. Рече́ же им: но ны́не и́же и́мать влага́лище, да во́змет, та́кожде и мех, а и́же не и́мать, да прода́ст ри́зу свою́, и ку́пит нож. Глаго́лю бо вам, я́ко еще́ пи́саное се подоба́ет, да сконча́ется о Мне, е́же и со беззако́нными вмени́ся. И́бо е́же о Мне, кончи́ну и́мать. Они́ же ре́ша: Го́споди, се ножа́ зде два. Он же рече́ им: дово́льно есть. И изше́д и́де по обы́чаю в гору́ Елео́нскую, по Немже идо́ша ученицы́ Его́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ꙗ҆́кѡ прибли́жисѧ і҆и҃съ въ виѳсфагі́ю и҆ виѳа́нїю, къ горѣ̀ нарица́емѣй є҆леѡ́нъ, посла̀ два̀ ᲂу҆чени̑къ свои́хъ, глаго́лѧ: и҆ди́те въ прѧ́мнꙋю ве́сь, и҆ въ ню́же входѧ́ща ѡ҆брѧ́щета жребѧ̀ привѧ́зано, на не́же никто́же николи́же ѿ человѣ̑къ всѣ́де: ѿрѣ́шша є҆̀ приведи́та. и҆ а҆́ще кто̀ вы̀ вопроша́етъ: почто̀ ѿрѣша́ета; си́це рцы́та є҆мꙋ̀: ꙗ҆́кѡ гдⷭ҇ь є҆го̀ тре́бꙋетъ. ше́дша же пѡ́сланнаѧ, ѡ҆брѣто́ста, ꙗ҆́коже речѐ и҆́ма. ѿрѣша́ющема же и҆́ма жребѧ̀, реко́ша госпо́дїе є҆гѡ̀ къ ни́ма: что̀ ѿрѣша́ета жребѧ̀; ѻ҆́на же реко́ста: ꙗ҆́кѡ гдⷭ҇ь є҆го̀ тре́бꙋетъ. и҆ приведо́ста є҆̀ ко і҆и҃сови, и҆ возве́ргше ри̑зы своѧ̀ на жребѧ̀, всади́ша і҆и҃са. и҆дꙋ́щꙋ же є҆мꙋ̀, постила́хꙋ ри̑зы своѧ̀ по пꙋтѝ. приближа́ющꙋ же сѧ є҆мꙋ̀ ᲂу҆жѐ а҆́бїе къ низхожде́нїю горѣ̀ є҆леѡ́нстѣй, нача́ша всѐ мно́жество ᲂу҆чени̑къ ра́дꙋющесѧ хвали́ти бг҃а гла́сомъ ве́лїимъ, ѡ҆ всѣ́хъ си́лахъ ꙗ҆̀же ви́дѣша, глаго́люще: благослове́нъ грѧды́й цр҃ь во и҆́мѧ гдⷭ҇не: ми́ръ на нб҃сѝ, и҆ сла́ва въ вы́шнихъ. и҆ нѣ́цыи фарїсе́є ѿ наро́да рѣ́ша къ немꙋ̀: ᲂу҆чи́телю, запретѝ ᲂу҆ченикѡ́мъ твои́мъ. и҆ ѿвѣща́въ речѐ и҆̀мъ: глаго́лю ва́мъ, ꙗ҆́кѡ а҆́ще сі́и ᲂу҆молча́тъ, ка́менїе возопїе́тъ. прїи́де же де́нь ѻ҆прѣснѡ́къ, во́ньже подо́бно бѣ̀ вре́мѧ жре́ти па́схꙋ. и҆ посла̀ петра̀ и҆ і҆ѡа́нна, ре́къ: ше́дша ᲂу҆гото́вайта на́мъ па́схꙋ, да ꙗ҆́мы. ѻ҆́на же реко́ста є҆мꙋ̀: гдѣ̀ хо́щеши, ᲂу҆гото́ваемъ; ѻ҆́нъ же речѐ и҆̀мъ: сѐ восходѧ́щема ва́ма во гра́дъ, срѧ́щетъ вы̀ человѣ́къ, въ скꙋде́льницѣ во́дꙋ носѧ̀: по не́мъ и҆дѣ́та въ до́мъ, во́ньже вхо́дитъ. и҆ рцѣ́та до́мꙋ влады́цѣ: глаго́летъ тебѣ̀ ᲂу҆чи́тель, гдѣ̀ є҆́сть ѻ҆би́тель, и҆дѣ́же па́схꙋ со ᲂу҆ченикѝ мои́ми снѣ́мъ; и҆ то́й ва́ма пока́жетъ го́рницꙋ ве́лїю по́стланꙋ: тꙋ̀ ᲂу҆гото́вайта. ше́дша же ѡ҆брѣто́ста ꙗ҆́коже речѐ и҆́ма: и҆ ᲂу҆гото́васта па́схꙋ. и҆ є҆гда̀ бы́сть ча́съ, возлежѐ, и҆ ѻ҆бана́десѧте а҆пⷭ҇ла съ ни́мъ. и҆ речѐ къ ни́мъ: жела́нїемъ возжелѣ́хъ сїю̀ па́схꙋ ꙗ҆́сти съ ва́ми, пре́жде да́же не прїимꙋ̀ мꙋ́къ. глаго́лю бо ва́мъ, ꙗ҆́кѡ ѿсе́лѣ не и҆́мамъ ꙗ҆́сти ѿ негѡ̀, до́ндеже сконча́ютсѧ во црⷭ҇твїи бж҃їи. и҆ прїи́мъ ча́шꙋ, хвалꙋ̀ возда́въ речѐ: прїими́те сїю̀, и҆ раздѣли́те себѣ̀. глаго́лю бо ва́мъ, ꙗ҆́кѡ не и҆́мамъ пи́ти ѿ плода̀ ло́знагѡ, до́ндеже црⷭ҇твїе бж҃їе прїи́детъ. и҆ прїи́мъ хлѣ́бъ, хвалꙋ̀ возда́въ преломѝ: и҆ дадѐ и҆̀мъ глаго́лѧ: сїѐ є҆́сть тѣ́ло моѐ, є҆́же за вы̀ дае́мо: сїѐ твори́те въ моѐ воспомина́нїе. та́кожде же и҆ ча́шꙋ по ве́чери, глаго́лѧ: сїѧ̀ ча́ша, но́вый завѣ́тъ мое́ю кро́вїю, ꙗ҆́же за вы̀ пролива́етсѧ. ѻ҆ба́че сѐ рꙋка̀ предаю́щагѡ мѧ̀ со мно́ю є҆́сть на трапе́зѣ. и҆ сн҃ъ ᲂу҆́бѡ человѣ́ческїй и҆́детъ по рече́нномꙋ, ѻ҆ба́че го́ре человѣ́кꙋ томꙋ̀, и҆́мже предае́тсѧ. и҆ ті́и нача́ша и҆ска́ти въ себѣ̀, кото́рый ᲂу҆́бѡ ѿ ни́хъ хотѧ́й сїѐ сотвори́ти; бы́сть же и҆ прѧ̀ въ ни́хъ, кі́й мни́тсѧ и҆́хъ бы́ти бо́лїй; ѻ҆́нъ же речѐ и҆̀мъ: ца́рїе ꙗ҆зы̑къ госпо́дствꙋютъ и҆́ми, и҆ ѡ҆блада́ющїи и҆́ми, благода́телє нарица́ютсѧ. вы́ же не та́кѡ: но бо́лїй въ ва́съ, да бꙋ́детъ ꙗ҆́кѡ мні́й, и҆ ста́рѣй, ꙗ҆́кѡ слꙋжа́й. кто́ бо бо́лїй; возлежа́й ли и҆лѝ слꙋжа́й; не возлежа́й ли; а҆́зъ же посредѣ̀ ва́съ є҆́смь ꙗ҆́кѡ слꙋжа́й. вы́ же є҆стѐ пребы́вше со мно́ю въ напа́стехъ мои́хъ. и҆ а҆́зъ завѣщава́ю ва́мъ, ꙗ҆́коже завѣща̀ мнѣ̀ ѻ҆ц҃ъ мо́й, црⷭ҇тво: да ꙗ҆́сте и҆ пїе́те на трапе́зѣ мое́й во црⷭ҇твїи мое́мъ: и҆ сѧ́дете на престо́лѣхъ сꙋдѧ́ще ѻ҆бѣмана́десѧте колѣ́нома і҆и҃левыма. рече́ же гдⷭ҇ь: сі́мѡне, сі́мѡне, сѐ сатана̀ про́ситъ ва́съ, дабы̀ сѣ́ѧлъ ꙗ҆́кѡ пшени́цꙋ. а҆́зъ же моли́хсѧ ѡ҆ тебѣ̀, да не ѡ҆скꙋдѣ́етъ вѣ́ра твоѧ̀: и҆ ты̀ нѣ́когда ѡ҆бра́щьсѧ, ᲂу҆твердѝ бра́тїю твою̀. ѻ҆́нъ же речѐ є҆мꙋ̀: гдⷭ҇и, съ тобо́ю гото́въ є҆́смь и҆ въ темни́цꙋ и҆ въ сме́рть и҆тѝ. ѻ҆́нъ же речѐ: глаго́лю тѝ пе́тре, не возгласи́тъ пѣ́телъ дне́сь, до́ндеже трикра́ты ѿве́ржешисѧ менѐ не вѣ́дѣти. и҆ речѐ и҆̀мъ: є҆гда̀ посла́хъ вы̀ без̾ влага́лища, и҆ без̾ мѣ́ха, и҆ без̾ сапѡ́гъ, є҆да̀ что̀ лише́ни бы́сте; ѻ҆ни́ же рѣ́ша: ничесѡ́же. рече́ же и҆̀мъ: но ны́нѣ и҆́же и҆́мать влага́лище, да во́з̾метъ, та́кожде и҆ мѣ́хъ: а҆ и҆́же не и҆́мать, да прода́стъ ри́зꙋ свою̀, и҆ кꙋ́питъ но́жъ. глаго́лю бо ва́мъ: ꙗ҆́кѡ є҆щѐ пи́саное сѐ, подоба́етъ да сконча́етсѧ ѡ҆ мнѣ̀: є҆́же и҆ со беззако́нными вмѣни́сѧ. и҆́бо є҆́же ѡ҆ мнѣ̀, кончи́нꙋ и҆́мать. ѻ҆ни́ же рѣ́ша: гдⷭ҇и сѐ ножа̀ здѣ̀ два̀. ѻ҆́нъ же речѐ и҆̀мъ: дово́льно є҆́сть. и҆ и҆зше́дъ, и҆́де по ѻ҆бы́чаю въ го́рꙋ є҆леѡ́нскꙋю: по не́мже и҆до́ша ᲂу҆ченицы̀ є҆гѡ̀. ",
}

add_evangelie_luki {
  ["номер"] = 97,
  ["комментарий"] = "Лк., 97 зач., XIX, 37–44.",
  ["текст_ру"] = "Во вре́мя о́но, приближа́ющуся Иису́сови уже́ а́бие к низхожде́нию горе́ Елео́нстей, нача́ша все мно́жество учени́к ра́дующеся хвали́ти Бо́га гла́сом ве́лиим о всех си́лах, я́же ви́деша, глаго́люще: благослове́н гряды́й Царь во и́мя Госпо́дне, мир на небеси́ и сла́ва в вы́шних. И не́цыи фарисе́е от наро́да ре́ша к Нему́: Учи́телю, запрети́ ученико́м Твои́м. И отвеща́в рече́ им: глаго́лю вам, я́ко, а́ще си́и умолча́т, ка́мение возопие́т. И я́ко прибли́жися, ви́дев град, пла́кася о нем, глаго́ля: я́ко а́ще бы разуме́л и ты, в день сей твой, е́же к смире́нию твоему́, ны́не же скры́ся от о́чию твое́ю. Я́ко прии́дут дни́е на тя, и обложа́т врази́ твои́ остро́г о тебе́, и обы́дут тя, и обы́мут тя всю́ду, и разбию́т тя и ча́да твоя́ в тебе́, и не оста́вят ка́мень на ка́мени в тебе́, поне́же не разуме́ вре́мене посеще́ния твоего́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, приближа́ющꙋсѧ і҆и҃сови ᲂу҆жѐ а҆́бїе къ низхожде́нїю горѣ̀ є҆леѡ́нстѣй, нача́ша всѐ мно́жество ᲂу҆чени̑къ ра́дꙋющесѧ хвали́ти бг҃а гла́сомъ ве́лїимъ, ѡ҆ всѣ́хъ си́лахъ ꙗ҆̀же ви́дѣша, глаго́люще: благослове́нъ грѧды́й цр҃ь во и҆́мѧ гдⷭ҇не: ми́ръ на нб҃сѝ, и҆ сла́ва въ вы́шнихъ. и҆ нѣ́цыи фарїсе́є ѿ наро́да рѣ́ша къ немꙋ̀: ᲂу҆чи́телю, запретѝ ᲂу҆ченикѡ́мъ твои́мъ. и҆ ѿвѣща́въ речѐ и҆̀мъ: глаго́лю ва́мъ, ꙗ҆́кѡ а҆́ще сі́и ᲂу҆молча́тъ, ка́менїе возопїе́тъ. и҆ ꙗ҆́кѡ прибли́жисѧ, ви́дѣвъ гра́дъ, пла́касѧ ѡ҆ не́мъ, глаго́лѧ: ꙗ҆́кѡ а҆́ще бы разꙋмѣ́лъ и҆ ты̀ въ де́нь се́й тво́й, є҆́же къ смире́нїю твоемꙋ̀, ны́нѣ же скры́сѧ ѿ ѻ҆́чїю твое́ю. ꙗ҆́кѡ прїи́дꙋтъ дні́е на тѧ̀, и҆ ѡ҆бложа́тъ вразѝ твоѝ ѻ҆стро́гъ ѡ҆ тебѣ̀, и҆ ѡ҆бы́дꙋтъ тѧ̀, и҆ ѡ҆б̾и́мꙋтъ тѧ̀ всю́дꙋ. и҆ разбїю́тъ тѧ̀ и҆ ча̑да твоѧ̀ въ тебѣ̀: и҆ не ѡ҆ста́вѧтъ ка́мень на ка́мени въ тебѣ̀: поне́же не разꙋмѣ̀ вре́мене посѣще́нїѧ твоегѡ̀. ",
}

add_evangelie_luki {
  ["номер"] = 98,
  ["комментарий"] = "Лк., 98 зач., XIX, 45–48.",
  ["текст_ру"] = "Во вре́мя о́но, вшед Иису́с в це́рковь, нача́т изгони́ти продаю́щыя в ней и купу́ющыя, глаго́ля им: пи́сано есть: дом Мой дом моли́твы есть, вы же сотвори́сте его́ пеще́ру разбо́йником. И бе учя́ по вся дни в це́ркви. Архиере́е же и кни́жницы иска́ху Его́ погуби́ти, и старе́йшины лю́дем. И не обрета́ху, что сотворя́т Ему́, лю́дие бо вси держа́хуся Его́, послу́шающе Его́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, вше́дъ і҆и҃съ въ цр҃ковь, нача́тъ и҆згони́ти продаю́щыѧ въ не́й, и҆ кꙋпꙋ́ющыѧ, глаго́лѧ и҆̀мъ: пи́сано є҆́сть: до́мъ мо́й, до́мъ моли́твы є҆́сть: вы́ же сотвори́сте є҆го̀ пеще́рꙋ разбо́йникѡмъ. и҆ бѣ̀ ᲂу҆чѧ̀ по всѧ̀ днѝ въ це́ркви. а҆рхїере́є же и҆ кни́жницы и҆ска́хꙋ є҆го̀ погꙋби́ти, и҆ старѣ́йшины лю́демъ. и҆ не ѡ҆брѣта́хꙋ, что̀ сотворѧ́тъ є҆мꙋ̀: лю́дїе бо всѝ держа́хꙋсѧ є҆гѡ̀ послꙋ́шающе є҆гѡ̀. ",
}

add_evangelie_luki {
  ["номер"] = 99,
  ["комментарий"] = "Лк., 99 зач., XX, 1–8.",
  ["текст_ру"] = "Во вре́мя о́но, уча́щу Иису́су лю́ди в це́ркви и благовеству́ющу, приидо́ша свяще́нницы и кни́жницы со ста́рцы и ре́ша к Нему́, глаго́люще: рцы нам, ко́ею о́бластию сия́ твори́ши, или́ кто есть да́вый Тебе́ власть сию́? Отвеща́в же рече́ к ним: вопрошу́ вы и Аз еди́наго словесе́, и рцы́те Ми: креще́ние Иоа́нново с небесе́ ли бе, или́ от челове́к? Они́ же помышля́ху в себе́, глаго́люще, я́ко а́ще рече́м: с небесе́, рече́т: почто́ у́бо не ве́ровасте ему́? А́ще ли же рече́м: от челове́к, вси лю́дие ка́мением побию́т ны. Изве́стно бо бе о Иоа́нне, я́ко проро́к бе. И отвеща́ша: не ве́мы отку́ду. Иису́с же рече́ им: ни Аз глаго́лю вам, ко́ею о́бластию сия́ творю́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ᲂу҆ча́щꙋ і҆и҃сꙋ лю́ди въ це́ркви и҆ благовѣствꙋ́ющꙋ, прїидо́ша свѧще́нницы и҆ кни́жницы со ста́рцы, и҆ рѣ́ша къ немꙋ̀, глаго́люще: рцы̀ на́мъ, ко́ею ѻ҆́бластїю сїѧ̑ твори́ши; и҆лѝ кто̀ є҆́сть да́вый тебѣ̀ вла́сть сїю̀; ѿвѣща́въ же речѐ къ ни́мъ: вопрошꙋ̀ вы̀ и҆ а҆́зъ є҆ди́нагѡ словесѐ, и҆ рцы́те мѝ. креще́нїе і҆ѡа́нново, съ небесе́ ли бѣ̀, и҆лѝ ѿ человѣ̑къ; ѻ҆ни́ же помышлѧ́хꙋ къ себѣ̀ глаго́люще: ꙗ҆́кѡ а҆́ще рече́мъ, съ нб҃сѐ, рече́тъ: почто̀ ᲂу҆́бѡ не вѣ́ровасте є҆мꙋ̀; а҆́ще ли же рече́мъ, ѿ человѣ̑къ: всѝ лю́дїе ка́менїемъ побїю́тъ ны̀. и҆звѣ́стно бо бѣ̀ ѡ҆ і҆ѡа́ннѣ, ꙗ҆́кѡ проро́къ бѣ̀. и҆ ѿвѣща́ша: не вѣ́мы ѿкꙋ́дꙋ. і҆и҃съ же речѐ и҆̀мъ: ни а҆́зъ глаго́лю ва́мъ, ко́ею ѻ҆́бластїю сїѧ̑ творю̀. ",
}

add_evangelie_luki {
  ["номер"] = 100,
  ["комментарий"] = "Лк., 100 зач., XX, 9–18.",
  ["текст_ру"] = "Рече́ Госпо́дь при́тчу сию́: челове́к не́кий насади́ виногра́д, и вдаде́ его́ де́лателем, и оты́де на ле́та мно́га, и во вре́мя посла́ к де́лателем раба́, да от плода́ виногра́да даду́т ему́, де́латели же би́вше его́, посла́ша тща. И приложи́ посла́ти друга́го раба́, они́ же и того́ би́вше и доса́ждьше ему́, посла́ша тща. И приложи́ посла́ти тре́тияго, они́ же и того́ уя́звльше изгна́ша. Рече́ же господи́н виногра́да: что сотворю́? Послю́ сы́на моего́ возлю́бленнаго, еда́ ка́ко, его́ ви́девше, усрамя́тся. Ви́девше же его́ де́лателе, мы́шляху в себе́, глаго́люще: сей есть насле́дник, прииди́те, убие́м его́, да на́ше бу́дет достоя́ние. И изве́дше его́ вон из виногра́да, уби́ша. Что у́бо сотвори́т им господи́н виногра́да? Прии́дет и погуби́т де́латели сия́ и вдаст виногра́д ине́м. Слы́шавше же реко́ша: да не бу́дет. Он же воззре́в на них, рече́: что у́бо пи́саное сие́, ка́мень, его́же небрего́ша зи́ждущии, сей бысть во главу́ у́гла? Всяк пады́й на ка́мени том, сокруши́тся, а на не́мже паде́т, стры́ет его́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь при́тчꙋ сїю̀: человѣ́къ нѣ́кїй насадѝ вїногра́дъ, и҆ вдадѐ є҆го̀ дѣ́лателємъ, и҆ ѿи́де на лѣ́та мнѡ́га. и҆ во вре́мѧ посла̀ къ дѣ́лателємъ раба̀, да ѿ плода̀ вїногра́да дадꙋ́тъ є҆мꙋ̀: дѣ́латели же би́вше є҆го̀, посла́ша тща̀. и҆ приложѝ посла́ти дрꙋга́го раба̀: ѻ҆ни́ же и҆ того̀ би́вше, и҆ доса́ждьше є҆мꙋ̀, посла́ша тща̀. и҆ приложѝ посла́ти тре́тїѧго: ѻ҆ни́ же и҆ того̀ ᲂу҆ѧ́звльше, и҆згна́ша. рече́ же господи́нъ вїногра́да: что̀ сотворю̀; послю̀ сн҃а моего̀ возлю́бленнаго, є҆да̀ ка́кѡ є҆го̀ ви́дѣвше ᲂу҆срамѧ́тсѧ; ви́дѣвше же є҆го̀ дѣ́лателє, мы́шлѧхꙋ къ себѣ̀, глаго́люще: се́й є҆́сть наслѣ́дникъ, прїиди́те, ᲂу҆бїе́мъ є҆го̀, да на́ше бꙋ́детъ достоѧ́нїе. и҆ и҆зве́дше є҆го̀ во́нъ и҆з̾ вїногра́да, ᲂу҆би́ша. что̀ ᲂу҆́бѡ сотвори́тъ и҆̀мъ гдⷭ҇и́нъ вїногра́да; прїи́детъ и҆ погꙋби́тъ дѣ́латели сїѧ̑, и҆ вда́стъ вїногра́дъ и҆нѣ̑мъ. слы́шавше же реко́ша: да не бꙋ́детъ. ѻ҆́нъ же воззрѣ́въ на ни́хъ, речѐ: что̀ ᲂу҆́бѡ пи́саное сїѐ: ка́мень є҆го́же небрего́ша зи́ждꙋщїи, се́й бы́сть во главꙋ̀ ᲂу҆́гла; всѧ́къ пады́й на ка́мени то́мъ, сокрꙋши́тсѧ: а҆ на не́мже паде́тъ, стры́етъ є҆го̀. ",
}

add_evangelie_luki {
  ["номер"] = 101,
  ["комментарий"] = "Лк., 101 зач., XX, 19-26.",
  ["текст_ру"] = "Во вре́мя о́но, взыска́ша архиере́е и ста́рцы, возложи́ти ру́це на Иису́са, и убоя́шася наро́да, разуме́ша бо, я́ко к ним при́тчу сию́ рече́. И соблю́дше посла́ша ла́ятели, творя́ще себе́ пра́ведники бы́ти, да и́мут Его́ в словеси́, во е́же преда́ти Его́ нача́льству и о́бласти иге́монове. И вопроси́ша Его́, глаго́люще: Учи́телю, ве́мы, я́ко пра́во глаго́леши и учи́ши, и не на лица́ зри́ши, но вои́стинну пути́ Бо́жию учи́ши. Досто́ит ли нам ке́сареви дань дая́ти, или́ ни? Разуме́в же их лука́вство, рече́ к ним: что Мя искуша́ете? Покажи́те Ми ца́ту: чий и́мать о́браз и надписа́ние? Отвеща́вше же реко́ша: ке́сарев. Он же рече́ им: воздади́те у́бо, я́же ке́сарева, ке́сареви, и я́же Бо́жия, Бо́гови. И не мого́ша зазре́ти глаго́ла Его́ пред людьми́, и диви́шася о отве́те Его́ и умолча́ша. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, взыска́ша а҆рхїере́є и҆ ста́рцы, возложи́ти рꙋ́цѣ на і҆и҃са, и҆ ᲂу҆боѧ́шасѧ наро́да: разꙋмѣ́ша бо, ꙗ҆́кѡ къ ни́мъ при́тчꙋ сїю̀ речѐ. и҆ соблю́дше, посла́ша ла́ѧтели, творѧ́ще себѐ пра́ведники бы́ти: да и҆́мꙋтъ є҆го̀ въ словесѝ, во є҆́же преда́ти є҆го̀ нача́льствꙋ и҆ ѻ҆́бласти и҆ге́мѡновѣ. и҆ вопроси́ша є҆го̀ глаго́люще: ᲂу҆чт҃лю, вѣ́мы, ꙗ҆́кѡ пра́вѡ глаго́леши и҆ ᲂу҆чи́ши, и҆ не на лица̀ зри́ши, но вои́стиннꙋ пꙋтѝ бж҃їю ᲂу҆чи́ши. досто́итъ ли на́мъ ке́сареви да́нь даѧ́ти, и҆лѝ нѝ; разꙋмѣ́въ же и҆́хъ лꙋка́вство, речѐ къ ни́мъ: что́ мѧ и҆скꙋша́ете; покажи́те мѝ ца́тꙋ: чі́й и҆́мать ѻ҆́бразъ и҆ надписа́нїе; ѿвѣща́вше же реко́ша: ке́саревъ. ѻ҆́нъ же речѐ и҆̀мъ: воздади́те ᲂу҆̀бо ꙗ҆̀же ке́сарєва ке́сареви, и҆ ꙗ҆̀же бж҃їѧ бг҃ови. и҆ не мого́ша зазрѣ́ти глаго́ла є҆гѡ̀ пред̾ людьмѝ, и҆ диви́шасѧ ѡ҆ ѿвѣ́тѣ є҆гѡ̀, и҆ ᲂу҆молча́ша. ",
}

add_evangelie_luki {
  ["номер"] = 102,
  ["комментарий"] = "Лк., 102 зач., XX, 27–44.",
  ["текст_ру"] = "Во вре́мя о́но, приступи́ша ко Иису́су не́цыи от саддуке́й, глаго́лющии воскресе́нию не бы́ти, вопроша́ху Его́, глаго́люще: Учи́телю, Моисе́й написа́ нам: а́ще кому́ брат у́мрет имы́й жену́, и той безча́ден у́мрет, да брат его́ по́ймет жену́ и возста́вит се́мя бра́ту своему́. Седмь у́бо бра́тия бе, и пе́рвый поя́т жену́, у́мре безча́ден, и поя́т вторы́й жену́, и той у́мре безча́ден, и тре́тий поя́т ю́, та́кожде же и вси седмь, и не оста́виша чад и умро́ша. По́слежде же всех у́мре и жена́. В воскресе́ние у́бо, кото́раго их бу́дет жена́? Седмь бо име́ша ю́ жену́. И отвеща́в рече́ им Иису́с: сы́нове ве́ка сего́ же́нятся и посяга́ют, а сподо́бльшиися век он улучи́ти и воскресе́ние, е́же от ме́ртвых, ни же́нятся, ни посяга́ют, ни умре́ти бо ктому́ мо́гут, ра́вни бо суть А́нгелом и сы́нове суть Бо́жии, воскресе́ния сы́нове су́ще. А я́коже востаю́т ме́ртвии, и Моисе́й сказа́ при купине́, я́коже глаго́лет Го́спода Бо́га Авраа́мля и Бо́га Исаа́кова и Бо́га Иа́ковля, Бог же несть ме́ртвых, но живы́х, вси бо Тому́ жи́ви суть. Отвеща́вше же не́цыи от кни́жник реко́ша: Учи́телю, до́бре рекл еси́. Ктому́же не сме́яху Его́ вопроси́ти ничесо́же. Рече́ же к ним: ка́ко глаго́лют Христа́ Сы́на Дави́дова бы́ти? Сам бо Дави́д глаго́лет в кни́зе псало́мстей: рече́ Госпо́дь Го́сподеви моему́: седи́ одесну́ю Мене́, до́ндеже положу́ враги́ Твоя́ подно́жие нога́ма Твои́ма. Дави́д у́бо Го́спода Его́ нарица́ет, и ка́ко Сын ему́ есть? ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пристꙋпи́ша ко і҆и҃сꙋ нѣ́цыи ѿ саддꙋкє́й, глаго́лющїи воскресе́нїю не бы́ти, вопроша́хꙋ є҆го̀, глаго́люще: ᲂу҆чи́телю, мѡѷсе́й написа̀ на́мъ: а҆́ще комꙋ̀ бра́тъ ᲂу҆́мретъ, и҆мы́й женꙋ̀, и҆ то́й безча́денъ ᲂу҆́мретъ, да бра́тъ є҆гѡ̀ по́йметъ женꙋ̀, и҆ возста́витъ сѣ́мѧ бра́тꙋ своемꙋ̀. се́дмь ᲂу҆́бѡ бра́тїѧ бѣ̀, и҆ пе́рвый поѧ́тъ женꙋ̀, ᲂу҆́мре безча́денъ: и҆ поѧ́тъ вторы́й женꙋ̀, и҆ то́й ᲂу҆́мре безча́денъ: и҆ тре́тїй поѧ́тъ ю҆̀, та́кожде же и҆ всѝ се́дмь: и҆ не ѡ҆ста́виша ча̑дъ, и҆ ᲂу҆мро́ша. по́слѣжде же всѣ́хъ ᲂу҆́мре и҆ жена̀. въ воскресе́нїе ᲂу҆́бѡ, кото́рагѡ и҆́хъ бꙋ́детъ жена̀; се́дмь бо и҆мѣ́ша ю҆̀ женꙋ̀. и҆ ѿвѣща́въ речѐ и҆̀мъ і҆и҃съ: сы́нове вѣ́ка сегѡ̀ же́нѧтсѧ, и҆ посѧга́ютъ: а҆ сподо́бльшїисѧ вѣ́къ ѻ҆́нъ ᲂу҆лꙋчи́ти, и҆ воскресе́нїе є҆́же ѿ ме́ртвыхъ, ни же́нѧтсѧ, ни посѧга́ютъ. ни ᲂу҆мре́ти бо ктомꙋ̀ мо́гꙋтъ: ра́вни бо сꙋ́ть а҆́гг҃лѡмъ, и҆ сн҃ове сꙋ́ть бж҃їи, воскресе́нїѧ сн҃ове сꙋ́ще. а҆ ꙗ҆́коже востаю́тъ ме́ртвїи, и҆ мѡѷсе́й сказа̀ при кꙋпинѣ̀, ꙗ҆́коже глаго́летъ: гдⷭ҇а бг҃а а҆враа́млѧ, и҆ бг҃а і҆саа́кова, и҆ бг҃а і҆а́кѡвлѧ. бг҃ъ же нѣ́сть ме́ртвыхъ, но живы́хъ: вси́ бо томꙋ̀ жи́ви сꙋ́ть. ѿвѣща́вше же нѣ́цыи ѿ кни̑жникъ, реко́ша: ᲂу҆чи́телю, до́брѣ ре́клъ є҆сѝ. ктомꙋ́же не смѣ́ѧхꙋ є҆го̀ вопроси́ти ничесо́же. рече́ же къ ни́мъ: ка́кѡ глаго́лютъ хрⷭ҇та̀ сн҃а дв҃дова бы́ти; са́мъ бо дв҃дъ глаго́летъ въ кни́зѣ ѱало́мстѣй: речѐ гдⷭ҇ь гдⷭ҇еви моемꙋ̀, сѣдѝ ѡ҆деснꙋ́ю менѐ, до́ндеже положꙋ̀ врагѝ твоѧ̀ подно́жїе нога́ма твои́ма. дв҃дъ ᲂу҆́бѡ гдⷭ҇а є҆го̀ нарица́етъ: и҆ ка́кѡ сн҃ъ є҆мꙋ̀ є҆́сть; ",
}

add_evangelie_luki {
  ["номер"] = 103,
  ["комментарий"] = "Лк., 103 зач., XX, 45 – XXI, 4.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: внемли́те себе́ от кни́жник хотя́щих ходи́ти во оде́ждах и лю́бящих целова́ния на то́ржищих и председа́ния на со́нмищах и преждезва́ния на ве́черях, и́же снеда́ют до́мы вдови́ц и вино́ю дале́че мо́лятся, си́и прии́мут ли́шше осужде́ние. Воззре́в же ви́де вмета́ющыя в храм набдя́щий име́ния да́ры своя́ бога́тыя. Ви́дев же и не́кую вдови́цу убо́гу вмета́ющу ту две ле́пте, и рече́: вои́стинну глаго́лю вам, я́ко вдови́ца сия́ убо́гая мно́жае всех вве́рже, вси бо си́и от избы́тка своего́ вверго́ша в да́ры Бо́гови, сия́ же от лише́ния своего́ все житие́, е́же име́, вве́рже. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: внемли́те себѣ̀ ѿ кни̑жникъ, хотѧ́щихъ ходи́ти во ѻ҆де́ждахъ, и҆ лю́бѧщихъ цѣлова̑нїѧ на то́ржищахъ, и҆ предсѣда̑нїѧ на со́нмищахъ, и҆ преждезва̑нїѧ на ве́черѧхъ: и҆̀же снѣда́ютъ до́мы вдови́цъ, и҆ вино́ю дале́че мо́лѧтсѧ: сі́и прїи́мꙋтъ ли́шше ѡ҆сꙋжде́нїе. воззрѣ́въ же ви́дѣ вмета́ющыѧ въ хра́мъ набдѧ́щїй и҆мѣ̑нїѧ, да́ры своѧ̀ бога́тыѧ. ви́дѣвъ же и҆ нѣ́кꙋю вдови́цꙋ ᲂу҆бо́гꙋ, вмета́ющꙋ тꙋ̀ двѣ̀ ле́птѣ, и҆ речѐ: вои́стиннꙋ глаго́лю ва́мъ, ꙗ҆́кѡ вдови́ца сїѧ̀ ᲂу҆бо́гаѧ мно́жае всѣ́хъ вве́рже. вси́ бо сі́и ѿ и҆збы́тка своегѡ̀ вверго́ша въ да́ры бг҃ови: сїѧ́ же ѿ лише́нїѧ своегѡ̀ всѐ житїѐ, є҆́же и҆мѣ̀, вве́рже. ",
}

add_evangelie_luki {
  ["номер"] = 104,
  ["комментарий"] = "Лк., 104 зач., XXI, 5–7, 10–11, 20–24.",
  ["текст_ру"] = "Во вре́мя о́но, не́коим глаго́лющым ко Иису́сови о це́ркви, я́ко ка́мением до́брым и сосу́ды укра́шена, рече́: сия́ я́же ви́дите, прии́дут дни́е, в ня́же не оста́нет ка́мень на ка́мени, и́же не разори́тся. Вопроси́ша же Его́, глаго́люще: Учи́телю, когда́ у́бо сия́ бу́дут? И что есть зна́мение, егда́ хотя́т сия́ бы́ти? Тогда́ глаго́лаше им: воста́нет бо язы́к на язы́к, и ца́рство на ца́рство. Тру́си же вели́цы по ме́стам и гла́ди и па́губы бу́дут, страхова́ния же и зна́мения ве́лия с небесе́ бу́дут. Егда́ же у́зрите обстои́мь Иерусали́м во́и, тогда́ разуме́йте, я́ко прибли́жися запусте́ние ему́. Тогда́ су́щии во Иуде́и да бе́гают в го́ры, и и́же посреде́ его́, да исхо́дят, и и́же во страна́х, да не вхо́дят в онь. Я́ко дни́е отмще́нию си́и суть, я́ко испо́лнитися всему́ пи́санному. Го́ре же иму́щым во утро́бе и доя́щым в ты́я дни, бу́дет бо беда́ ве́лия на земли́ и гнев на лю́дех сих, и паду́т во о́стрии меча́, и плене́ни бу́дут во вся язы́ки, и Иерусали́м бу́дет попира́емь язы́ки, до́ндеже сконча́ются времена́ язы́к. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, нѣ́кѡимъ глаго́лющымъ ко і҆и҃сови ѡ҆ цр҃кви, ꙗ҆́кѡ ка́менїемъ до́брымъ и҆ сосꙋ́ды ᲂу҆кра́шена, речѐ: сїѧ̑ ꙗ҆̀же ви́дите, прїи́дꙋтъ дні́е, въ нѧ́же не ѡ҆ста́нетъ ка́мень на ка́мени, и҆́же не разори́тсѧ. вопроси́ша же є҆го̀, глаго́люще: ᲂу҆чи́телю, когда̀ ᲂу҆́бѡ сїѧ̑ бꙋ́дꙋтъ; и҆ что́ є҆сть зна́менїе, є҆гда̀ хотѧ́тъ сїѧ̑ бы́ти; тогда̀ глаго́лаше и҆̀мъ: воста́нетъ бо ꙗ҆зы́къ на ꙗ҆зы́къ, и҆ ца́рство на ца́рство. трꙋ́си же вели́цы по мѣ́стамъ, и҆ гла́ди и҆ па̑гꙋбы бꙋ́дꙋтъ: страхова̑нїѧ же и҆ зна́мєнїѧ вє́лїѧ съ небесѐ бꙋ́дꙋтъ. є҆гда́ же ᲂу҆́зрите ѡ҆бстои́мь і҆ерꙋсали́мъ вѡ́и, тогда̀ разꙋмѣ́йте, ꙗ҆́кѡ прибли́жисѧ запꙋстѣ́нїе є҆мꙋ̀. тогда̀ сꙋ́щїи во і҆ꙋде́и, да бѣ́гаютъ въ го́ры: и҆ и҆̀же посредѣ̀ є҆гѡ̀ да и҆схо́дѧтъ: и҆ и҆̀же во страна́хъ, да не вхо́дѧтъ въ ѻ҆́нь. ꙗ҆́кѡ дні́е ѿмще́нїю сі́и сꙋ́ть, ꙗ҆́кѡ и҆спо́лнитисѧ всемꙋ̀ пи́санномꙋ. го́ре же и҆мꙋ́щымъ во ᲂу҆тро́бѣ, и҆ доѧ́щымъ въ ты́ѧ днѝ: бꙋ́детъ бо бѣда̀ ве́лїѧ на землѝ, и҆ гнѣ́въ на лю́дехъ си́хъ. и҆ падꙋ́тъ во ѻ҆́стрїи меча̀, и҆ плѣне́ни бꙋ́дꙋтъ во всѧ̀ ꙗ҆зы́ки: и҆ і҆ерꙋсали́мъ бꙋ́детъ попира́емь ꙗ҆зы́ки, до́ндеже сконча́ютсѧ времена̀ ꙗ҆зы̑къ. ",
}

add_evangelie_luki {
  ["номер"] = 105,
  ["комментарий"] = "Лк., 105 зач., XXI, 8–9, 25–27, 33–36.",
  ["текст_ру"] = "Рече́ Госпо́дь: блюди́те, да не прельще́ни бу́дете, мно́зи бо прии́дут во и́мя Мое́, глаго́люще, я́ко Аз есмь, и вре́мя прибли́жися. Не изы́дите у́бо во след их. Егда́ же услы́шите бра́ни и нестрое́ния, не убо́йтеся, подоба́ет бо сим бы́ти пре́жде, но не у а́бие кончи́на. И бу́дут зна́мения в со́лнце и луне́ и звезда́х, и на земли́ туга́ язы́ком от неча́яния шу́ма морска́го и возмуще́ния, издыха́ющым челове́ком от стра́ха и ча́яния гряду́щих на вселе́нную, си́лы бо небе́сныя подви́гнутся, и тогда́ у́зрят Сы́на Челове́ческа гряду́ща на о́блацех с си́лою и сла́вою мно́гою. Не́бо и земля́ ми́мо и́дет, а словеса́ Моя́ не и́мут прейти́. Внемли́те же себе́, да не когда́ отягча́ют се́рдца ва́ша объяде́нием и пия́нством и печа́льми жите́йскими, и на́йдет на вы внеза́пу день той, я́ко сеть бо прии́дет на вся живу́щыя на лицы́ всея́ земли́. Бди́те у́бо на вся́ко вре́мя моля́щеся, да сподо́битеся убежа́ти всех сих хотя́щих бы́ти, и ста́ти пред Сы́ном Челове́ческим. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: блюди́те, да не прельще́ни бꙋ́дете: мно́зи бо прїи́дꙋтъ во и҆́мѧ моѐ, глаго́люще, ꙗ҆́кѡ а҆́зъ є҆́смь, и҆ вре́мѧ прибли́жисѧ: не и҆зы́дите ᲂу҆́бѡ во слѣ́дъ и҆́хъ. є҆гда́ же ᲂу҆слы́шите бра̑ни и҆ нестроє́нїѧ, не ᲂу҆бо́йтесѧ: подоба́етъ бо си́мъ бы́ти пре́жде, но не ᲂу҆̀ а҆́бїе кончи́на. и҆ бꙋ́дꙋтъ зна́мєнїѧ въ со́лнцѣ, и҆ лꙋнѣ̀, и҆ ѕвѣзда́хъ: и҆ на землѝ тꙋга̀ ꙗ҆зы́кѡмъ, ѿ неча́ѧнїѧ, шꙋ́ма морска́гѡ и҆ возмꙋще́нїѧ, и҆здыха́ющымъ человѣ́кѡмъ ѿ стра́ха и҆ ча́ѧнїѧ грѧдꙋ́щихъ на вселе́ннꙋю: си̑лы бо нбⷭ҇ныѧ подви́гнꙋтсѧ. и҆ тогда̀ ᲂу҆́зрѧтъ сн҃а человѣ́ческа грѧдꙋ́ща на ѻ҆́блацѣхъ съ си́лою и҆ сла́вою мно́гою. не́бо и҆ землѧ̀ ми́мѡ и҆́детъ, а҆ словеса̀ моѧ̀ не и҆́мꙋтъ прейтѝ. внемли́те же себѣ̀, да не когда̀ ѡ҆тѧгча́ютъ сердца̀ ва́ша ѡ҆б̾ѧде́нїемъ и҆ пїѧ́нствомъ, и҆ печа́льми жите́йскими, и҆ на́йдетъ на вы̀ внеза́пꙋ де́нь то́й. ꙗ҆́кѡ сѣ́ть бо прїи́детъ на всѧ̀ живꙋ́щыѧ на лицы̀ всеѧ̀ землѝ. бди́те ᲂу҆́бѡ на всѧ́ко вре́мѧ молѧ́щесѧ, да сподо́битесѧ ᲂу҆бѣжа́ти всѣ́хъ си́хъ хотѧ́щихъ бы́ти, и҆ ста́ти пред̾ сн҃омъ человѣ́ческимъ. ",
}

add_evangelie_luki {
  ["номер"] = 105,
  ["комментарий"] = "Лк., 105 зач., XXI, 8–19.",
  ["текст_ру"] = "Рече́ Госпо́дь: блюди́те, да не прельще́ни бу́дете, мно́зи бо прии́дут во и́мя Мое́, глаго́люще, я́ко Аз есмь, и вре́мя прибли́жися. Не изы́дите у́бо во след их. Егда́ же услы́шите бра́ни и нестрое́ния, не убо́йтеся, подоба́ет бо сим бы́ти пре́жде, но не у а́бие кончи́на. Тогда́ глаго́лаше им: воста́нет бо язы́к на язы́к, и ца́рство на ца́рство: тру́си же вели́цы по ме́стом и гла́ди и па́губы бу́дут, страхова́ния же и зна́мения ве́лия с небесе́ бу́дут. Пре́жде же сих всех возложа́т на вы ру́ки своя́ и иждену́т, предаю́ще на со́нмища и темни́цы, ведо́мы к царе́м и влады́кам, и́мене Моего́ ра́ди, прилучи́тся же вам во свиде́тельство. Положи́те у́бо на сердца́х ва́ших, не пре́жде поуча́тися отвещава́ти. Аз бо дам вам уста́ и прему́дрость, е́йже не возмо́гут проти́витися или́ отвеща́ти вси противля́ющиися вам. Пре́дани же бу́дете и роди́тели и бра́тиею и ро́дом и дру́ги, и умертвя́т от вас. И бу́дете ненави́дими от всех и́мене Моего́ ра́ди. И влас главы́ ва́шея не поги́бнет. В терпе́нии ва́шем стяжи́те ду́шы ва́ша. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: блюди́те, да не прельще́ни бꙋ́дете: мно́зи бо прїи́дꙋтъ во и҆́мѧ моѐ, глаго́люще, ꙗ҆́кѡ а҆́зъ є҆́смь, и҆ вре́мѧ прибли́жисѧ: не и҆зы́дите ᲂу҆́бѡ во слѣ́дъ и҆́хъ. є҆гда́ же ᲂу҆слы́шите бра̑ни и҆ нестроє́нїѧ, не ᲂу҆бо́йтесѧ: подоба́етъ бо си́мъ бы́ти пре́жде, но не ᲂу҆̀ а҆́бїе кончи́на. тогда̀ глаго́лаше и҆̀мъ: воста́нетъ бо ꙗ҆зы́къ на ꙗ҆зы́къ, и҆ ца́рство на ца́рство: трꙋ́си же вели́цы по мѣ́стѡмъ, и҆ гла́ди и҆ па̑гꙋбы бꙋ́дꙋтъ, страхова̑нїѧ же и҆ зна́мєнїѧ вє́лїѧ съ небесѐ бꙋ́дꙋтъ. пре́жде же си́хъ всѣ́хъ возложа́тъ на вы̀ рꙋ́ки своѧ̑, и҆ и҆жденꙋ́тъ, предаю́ще на сѡ́нмища и҆ темни́цы, ведо́мы къ царє́мъ и҆ влады́камъ, и҆́мене моегѡ̀ ра́ди. прилꙋчи́тсѧ же ва́мъ во свидѣ́тельство: положи́те ᲂу҆́бѡ на сердца́хъ ва́шихъ, не пре́жде поꙋча́тисѧ ѿвѣщава́ти. а҆́зъ бо да́мъ ва́мъ ᲂу҆ста̀ и҆ премꙋ́дрость, є҆́йже не возмо́гꙋтъ проти́витисѧ, и҆лѝ ѿвѣща́ти всѝ противлѧ́ющїисѧ ва́мъ. пре́дани же бꙋ́дете и҆ роди́тели, и҆ бра́тїею, и҆ ро́домъ, и҆ дрꙋ́ги, и҆ ᲂу҆мертвѧ́тъ ѿ ва́съ. и҆ бꙋ́дете ненави́дими ѿ всѣ́хъ и҆́мене моегѡ̀ ра́ди. и҆ вла́съ главы̀ ва́шеѧ не поги́бнетъ. въ терпѣ́нїи ва́шемъ стѧжи́те дꙋ́шы ва́шѧ. ",
}

add_evangelie_luki {
  ["номер"] = 106,
  ["комментарий"] = "Лк., 106 зач., XXI, 12–19.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: внемли́те от челове́к, возложа́т на вы ру́ки своя́ и иждену́т, предаю́ще на со́нмища и темни́цы, ведо́мы к царе́м и влады́кам, и́мене Моего́ ра́ди, прилучи́тся же вам во свиде́тельство. Положи́те у́бо на сердца́х ва́ших, не пре́жде поуча́тися отвещава́ти. Аз бо дам вам уста́ и прему́дрость, е́йже не возмо́гут проти́витися или́ отвеща́ти вси противля́ющиися вам. Пре́дани же бу́дете и роди́тели и бра́тиею и ро́дом и дру́ги, и умертвя́т от вас. И бу́дете ненави́дими от всех и́мене Моего́ ра́ди. И влас главы́ ва́шея не поги́бнет. В терпе́нии ва́шем стяжи́те ду́шы ва́ша. ",
