}

add_evangelie_luki {
  ["номер"] = 107,
  ["комментарий"] = "Лк., 107 зач., XXI, 28–33.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: восклони́теся и воздви́гните главы́ ва́ша, зане́ приближа́ется избавле́ние ва́ше. И рече́ при́тчу им: ви́дите смоко́вницу и вся древа́, егда́ прошиба́ются уже́, ви́дяще са́ми ве́сте, я́ко близ жа́тва есть. Та́ко и вы, егда́ у́зрите сия́ быва́юща, ве́дите, я́ко близ есть Ца́рствие Бо́жие. Ами́нь глаго́лю вам, я́ко не и́мать прейти́ род сей, до́ндеже вся сия́ бу́дут. Не́бо и земля́ ми́мо и́дет, а словеса́ Моя́ не и́мут прейти́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ч҃нкѡ́мъ: восклони́тесѧ, и҆ воздви́гните главы̀ ва́шѧ, занѐ приближа́етсѧ и҆збавле́нїе ва́ше. и҆ речѐ при́тчꙋ и҆̀мъ: ви́дите смоко́вницꙋ, и҆ всѧ̀ древа̀: є҆гда̀ прошиба́ютсѧ ᲂу҆жѐ, ви́дѧще са́ми вѣ́сте ꙗ҆́кѡ бли́зъ жа́тва є҆́сть. та́кѡ и҆ вы̀ є҆гда̀ ᲂу҆́зрите сїѧ̑ быва́юща, вѣ́дите, ꙗ҆́кѡ бли́зъ є҆́сть црⷭ҇твїе бж҃їе. а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ не и҆́мать прейтѝ ро́дъ се́й, до́ндеже всѧ̑ сїѧ̑ бꙋ́дꙋтъ. не́бо и҆ землѧ̀ ми́мѡ и҆́детъ, а҆ словеса̀ моѧ̀ не и҆́мꙋтъ прейтѝ. ",
