add_evangelie_luki {
  ["номер"] = 108,
  ["комментарий"] = "Лк., 108 зач., XXI, 37 – XXII, 8.",
  ["текст_ру"] = "Во вре́мя о́но, бе Иису́с во дни во це́ркви учя́, но́щию же исходя́ водворя́шеся в горе́ нарица́емей Елео́н. И вси лю́дие из у́тра прихожда́ху к Нему́ во це́рковь послу́шати Его́. Приближа́шеся же пра́здник опресно́к, глаго́лемый Па́сха. И иска́ху архиере́е и кни́жницы, ка́ко бы́ша уби́ли Его́, боя́хуся бо люде́й. Вни́де же сатана́ во Иу́ду нарица́емаго Искарио́т, су́ща от числа́ обоюна́десяте, и шед глаго́ла архиере́ом и воево́дам, ка́ко Его́ преда́ст им. И возра́довашася и совеща́ша ему́ сре́бреники да́ти, и испове́да и иска́ше подо́бна вре́мене, да преда́ст Его́ им без наро́да. Прии́де же день опресно́к, во́ньже подо́бно бе вре́мя жре́ти па́сху. И посла́ Петра́ и Иоа́нна, рек: ше́дша угото́вайта нам па́сху, да я́мы. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бѣ̀ і҆и҃съ во днѝ во цр҃кви ᲂу҆чѧ̀, но́щїю же и҆сходѧ̀ водворѧ́шесѧ въ горѣ̀, нарица́емѣй є҆леѡ́нъ. и҆ всѝ лю́дїе и҆з̾ ᲂу҆́тра прихожда́хꙋ къ немꙋ̀ во це́рковь, послꙋ́шати є҆гѡ̀. приближа́шесѧ же пра́здникъ ѻ҆прѣснѡ́къ, глаго́лемый па́сха. и҆ и҆ска́хꙋ а҆рхїере́є и҆ кни́жницы, ка́кѡ бы́ша ᲂу҆би́ли є҆го̀: боѧ́хꙋсѧ бо люде́й. вни́де же сатана̀ во і҆ꙋ́дꙋ нарица́емаго і҆скарїѡ́тъ, сꙋ́ща ѿ числа̀ ѻ҆боюна́десѧте. и҆ ше́дъ глаго́ла а҆рхїере́ѡмъ и҆ воево́дамъ, ка́кѡ є҆го̀ преда́стъ и҆̀мъ. и҆ возра́довашасѧ: и҆ совѣща́ша є҆мꙋ̀ сре́бреники да́ти. и҆ и҆сповѣ́да: и҆ и҆ска́ше подо́бна вре́мене, да преда́стъ є҆го̀ и҆̀мъ без̾ наро́да. прїи́де же де́нь ѻ҆прѣснѡ́къ, во́ньже подо́бно бѣ̀ вре́мѧ жре́ти па́схꙋ. и҆ посла̀ петра̀ и҆ і҆ѡа́нна, ре́къ: ше́дша ᲂу҆гото́вайта на́мъ па́схꙋ, да ꙗ҆́мы. ",
}

add_evangelie_luki {
  ["номер"] = 108,
  ["комментарий"] = "Лк., 108 зач., XXII, 1-39.",
  ["текст_ру"] = "Во вре́мя о́но, приближа́шеся пра́здник опресно́к, глаго́лемый Па́сха, и иска́ху архиере́е и кни́жницы, ка́ко бы́ша уби́ли Его́, боя́хуся бо люде́й. Вни́де же сатана́ во Иу́ду нарица́емаго Искарио́т, су́ща от числа́ обоюна́десяте, и шед глаго́ла архиере́ом и воево́дам, ка́ко Его́ преда́ст им. И возра́довашася и совеща́ша ему́ сре́бреники да́ти, и испове́да, и иска́ше подо́бна вре́мене, да преда́ст Его́ им без наро́да. Прии́де же день опресно́к, во́ньже подо́бно бе вре́мя жре́ти па́сху, и посла́ Петра́ и Иоа́нна, рек: ше́дша угото́вайта нам па́сху, да я́мы. О́на же реко́ста Ему́: где хо́щеши угото́ваем? Он же рече́ им: се восходя́щема ва́ма во град, сря́щет вы челове́к в скуде́льнице во́ду нося́, по нем иде́та в дом, во́ньже вхо́дит, и рце́та до́му влады́це: глаго́лет тебе́ Учи́тель, где есть оби́тель, иде́же па́сху со ученики́ Мои́ми снем? И той ва́ма пока́жет го́рницу ве́лию по́стлану, ту угото́вайта. Ше́дша же обрето́ста, я́коже рече́ и́ма, и угото́васта па́сху. И егда́ бысть час, возлеже́, и обана́десяте Апо́стола с Ним, и рече́ к ним: жела́нием возжеле́х сию́ па́сху я́сти с ва́ми, пре́жде да́же не прииму́ мук. Глаго́лю бо вам, я́ко отсе́ле не и́мам я́сти от него́, до́ндеже сконча́ются во Ца́рствии Бо́жии. И прии́м ча́шу, хвалу́ возда́в, рече́: приими́те сию́, и раздели́те себе́, глаго́лю бо вам, я́ко не и́мам пи́ти от плода́ ло́знаго, до́ндеже Ца́рствие Бо́жие прии́дет. И прии́м хлеб, хвалу́ возда́в, преломи́ и даде́ им, глаго́ля: сие́ есть те́ло Мое́, е́же за вы дае́мо, сие́ твори́те в Мое́ воспомина́ние. Та́кожде же и ча́шу по ве́чери, глаго́ля: сия́ ча́ша Но́вый Заве́т Мое́ю кро́вию, я́же за вы пролива́ется, оба́че се рука́ предаю́щаго Мя со Мно́ю есть на трапе́зе, и Сын у́бо Челове́ческий и́дет по рече́нному, оба́че го́ре челове́ку тому́, и́мже предае́тся. И ти́и нача́ша иска́ти в себе́, кото́рый у́бо от них хотя́й сие́ сотвори́ти. Бысть же и пря в них, кий мни́тся их бы́ти бо́лий. Он же рече́ им: ца́рие язы́к госпо́дствуют и́ми, и облада́ющии и́ми благода́теле нарица́ются, вы же не та́ко, но бо́лий в вас, да бу́дет я́ко мний, и ста́рей, я́ко служа́й. Кто бо бо́лий, возлежа́й ли или́ служа́й? Не возлежа́й ли? Аз же посреде́ вас есмь я́ко служа́й. Вы же есте́ пребы́вше со Мно́ю в напа́стех Мои́х, и Аз завещава́ю вам, я́коже завеща́ Мне Оте́ц Мой, Ца́рство, да я́сте и пие́те на трапе́зе Мое́й во Ца́рствии Мое́м, и ся́дете на престо́лех, судя́ще обемана́десяте коле́нома Изра́илевома. Рече́ же Госпо́дь: Си́моне, Си́моне, се сатана́ про́сит вас, дабы́ се́ял, я́ко пшени́цу, Аз же моли́хся о тебе́, да не оскуде́ет ве́ра твоя́, и ты не́когда обра́щься утверди́ бра́тию твою́. Он же рече́ Ему́: Го́споди, с Тобо́ю гото́в есмь и в темни́цу и на смерть ити́. Он же рече́: глаго́лю ти, Пе́тре, не возгласи́т пе́тель днесь, до́ндеже трикра́ты отве́ржешися Мене́ не ве́дети. И рече́ им: егда́ посла́х вы без влага́лища и без ме́ха и без сапо́г, еда́ что́ лише́ни бы́сте? Они́ же ре́ша: ничесо́же. Рече́ же им: но ны́не и́же и́мать влага́лище, да во́змет, та́кожде и мех, а и́же не и́мать, да прода́ст ри́зу свою́, и ку́пит нож. Глаго́лю бо вам, я́ко еще́ пи́саное се подоба́ет, да сконча́ется о Мне, е́же: и со беззако́нными вмени́ся. И́бо е́же о Мне, кончи́ну и́мать. Они́ же ре́ша: Го́споди, се ножа́ зде два. Он же рече́ им: дово́льно есть. И изше́д и́де по обы́чаю в го́ру Елео́нскую, по Немже идо́ша ученицы́ Его́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, приближа́шесѧ пра́здникъ ѻ҆прѣснѡ́къ, глаго́лемый па́сха. и҆ и҆ска́хꙋ а҆рхїере́є и҆ кни́жницы, ка́кѡ бы́ша ᲂу҆би́ли є҆го̀: боѧ́хꙋсѧ бо люде́й. вни́де же сатана̀ во і҆ꙋ́дꙋ нарица́емаго і҆скарїѡ́тъ, сꙋ́ща ѿ числа̀ ѻ҆боюна́десѧте. и҆ ше́дъ глаго́ла а҆рхїере́ѡмъ и҆ воево́дамъ, ка́кѡ є҆го̀ преда́стъ и҆̀мъ. и҆ возра́довашасѧ: и҆ совѣща́ша є҆мꙋ̀ сре́бреники да́ти. и҆ и҆сповѣ́да: и҆ и҆ска́ше подо́бна вре́мене, да преда́стъ є҆го̀ и҆̀мъ без̾ наро́да. прїи́де же де́нь ѻ҆прѣснѡ́къ, во́ньже подо́бно бѣ̀ вре́мѧ жре́ти па́схꙋ. и҆ посла̀ петра̀ и҆ і҆ѡа́нна, ре́къ: ше́дша ᲂу҆гото́вайта на́мъ па́схꙋ, да ꙗ҆́мы. ѻ҆́на же реко́ста є҆мꙋ̀: гдѣ̀ хо́щеши, ᲂу҆гото́ваемъ; ѻ҆́нъ же речѐ и҆̀мъ: сѐ восходѧ́щема ва́ма во гра́дъ, срѧ́щетъ вы̀ человѣ́къ, въ скꙋде́льницѣ во́дꙋ носѧ̀: по не́мъ и҆дѣ́та въ до́мъ, во́ньже вхо́дитъ. и҆ рцѣ́та до́мꙋ влады́цѣ: глаго́летъ тебѣ̀ ᲂу҆чи́тель, гдѣ̀ є҆́сть ѻ҆би́тель, и҆дѣ́же па́схꙋ со ᲂу҆ченикѝ мои́ми снѣ́мъ; и҆ то́й ва́ма пока́жетъ го́рницꙋ ве́лїю по́стланꙋ: тꙋ̀ ᲂу҆гото́вайта. ше́дша же ѡ҆брѣто́ста ꙗ҆́коже речѐ и҆́ма: и҆ ᲂу҆гото́васта па́схꙋ. и҆ є҆гда̀ бы́сть ча́съ, возлежѐ, и҆ ѻ҆бана́десѧте а҆пⷭ҇ла съ ни́мъ. и҆ речѐ къ ни́мъ: жела́нїемъ возжелѣ́хъ сїю̀ па́схꙋ ꙗ҆́сти съ ва́ми, пре́жде да́же не прїимꙋ̀ мꙋ́къ. глаго́лю бо ва́мъ, ꙗ҆́кѡ ѿсе́лѣ не и҆́мамъ ꙗ҆́сти ѿ негѡ̀, до́ндеже сконча́ютсѧ во црⷭ҇твїи бж҃їи. и҆ прїи́мъ ча́шꙋ, хвалꙋ̀ возда́въ речѐ: прїими́те сїю̀, и҆ раздѣли́те себѣ̀. глаго́лю бо ва́мъ, ꙗ҆́кѡ не и҆́мамъ пи́ти ѿ плода̀ ло́знагѡ, до́ндеже црⷭ҇твїе бж҃їе прїи́детъ. и҆ прїи́мъ хлѣ́бъ, хвалꙋ̀ возда́въ преломѝ: и҆ дадѐ и҆̀мъ глаго́лѧ: сїѐ є҆́сть тѣ́ло моѐ, є҆́же за вы̀ дае́мо: сїѐ твори́те въ моѐ воспомина́нїе. та́кожде же и҆ ча́шꙋ по ве́чери, глаго́лѧ: сїѧ̀ ча́ша, но́вый завѣ́тъ мое́ю кро́вїю, ꙗ҆́же за вы̀ пролива́етсѧ. ѻ҆ба́че сѐ рꙋка̀ предаю́щагѡ мѧ̀ со мно́ю є҆́сть на трапе́зѣ. и҆ сн҃ъ ᲂу҆́бѡ человѣ́ческїй и҆́детъ по рече́нномꙋ, ѻ҆ба́че го́ре человѣ́кꙋ томꙋ̀, и҆́мже предае́тсѧ. и҆ ті́и нача́ша и҆ска́ти въ себѣ̀, кото́рый ᲂу҆́бѡ ѿ ни́хъ хотѧ́й сїѐ сотвори́ти; бы́сть же и҆ прѧ̀ въ ни́хъ, кі́й мни́тсѧ и҆́хъ бы́ти бо́лїй; ѻ҆́нъ же речѐ и҆̀мъ: ца́рїе ꙗ҆зы̑къ госпо́дствꙋютъ и҆́ми, и҆ ѡ҆блада́ющїи и҆́ми, благода́телє нарица́ютсѧ. вы́ же не та́кѡ: но бо́лїй въ ва́съ, да бꙋ́детъ ꙗ҆́кѡ мні́й, и҆ ста́рѣй, ꙗ҆́кѡ слꙋжа́й. кто́ бо бо́лїй; возлежа́й ли и҆лѝ слꙋжа́й; не возлежа́й ли; а҆́зъ же посредѣ̀ ва́съ є҆́смь ꙗ҆́кѡ слꙋжа́й. вы́ же є҆стѐ пребы́вше со мно́ю въ напа́стехъ мои́хъ. и҆ а҆́зъ завѣщава́ю ва́мъ, ꙗ҆́коже завѣща̀ мнѣ̀ ѻ҆ц҃ъ мо́й, црⷭ҇тво: да ꙗ҆́сте и҆ пїе́те на трапе́зѣ мое́й во црⷭ҇твїи мое́мъ: и҆ сѧ́дете на престо́лѣхъ сꙋдѧ́ще ѻ҆бѣмана́десѧте колѣ́нома і҆и҃левыма. рече́ же гдⷭ҇ь: сі́мѡне, сі́мѡне, сѐ сатана̀ про́ситъ ва́съ, дабы̀ сѣ́ѧлъ ꙗ҆́кѡ пшени́цꙋ. а҆́зъ же моли́хсѧ ѡ҆ тебѣ̀, да не ѡ҆скꙋдѣ́етъ вѣ́ра твоѧ̀: и҆ ты̀ нѣ́когда ѡ҆бра́щьсѧ, ᲂу҆твердѝ бра́тїю твою̀. ѻ҆́нъ же речѐ є҆мꙋ̀: гдⷭ҇и, съ тобо́ю гото́въ є҆́смь и҆ въ темни́цꙋ и҆ въ сме́рть и҆тѝ. ѻ҆́нъ же речѐ: глаго́лю тѝ пе́тре, не возгласи́тъ пѣ́телъ дне́сь, до́ндеже трикра́ты ѿве́ржешисѧ менѐ не вѣ́дѣти. и҆ речѐ и҆̀мъ: є҆гда̀ посла́хъ вы̀ без̾ влага́лища, и҆ без̾ мѣ́ха, и҆ без̾ сапѡ́гъ, є҆да̀ что̀ лише́ни бы́сте; ѻ҆ни́ же рѣ́ша: ничесѡ́же. рече́ же и҆̀мъ: но ны́нѣ и҆́же и҆́мать влага́лище, да во́з̾метъ, та́кожде и҆ мѣ́хъ: а҆ и҆́же не и҆́мать, да прода́стъ ри́зꙋ свою̀, и҆ кꙋ́питъ но́жъ. глаго́лю бо ва́мъ: ꙗ҆́кѡ є҆щѐ пи́саное сѐ, подоба́етъ да сконча́етсѧ ѡ҆ мнѣ̀: є҆́же и҆ со беззако́нными вмѣни́сѧ. и҆́бо є҆́же ѡ҆ мнѣ̀, кончи́нꙋ и҆́мать. ѻ҆ни́ же рѣ́ша: гдⷭ҇и сѐ ножа̀ здѣ̀ два̀. ѻ҆́нъ же речѐ и҆̀мъ: дово́льно є҆́сть. и҆ и҆зше́дъ, и҆́де по ѻ҆бы́чаю въ го́рꙋ є҆леѡ́нскꙋю: по не́мже и҆до́ша ᲂу҆ченицы̀ є҆гѡ̀. ",
}

add_evangelie_luki {
  ["номер"] = 109,
  ["комментарий"] = "Лк., 109 зач., XXII, 39–42, 45 – XXIII, 1.",
  ["текст_ру"] = "Во вре́мя о́но, изше́д Иису́с и́де по обы́чаю в го́ру Елео́нскую, по Немже идо́ша ученицы́ Его́. Быв же на ме́сте, рече́ им: моли́теся, да не вни́дете в напа́сть. И Сам отступи́ от них я́ко верже́нием ка́мене, и покло́нь коле́на моля́шеся, глаго́ля: О́тче, а́ще во́лиши мимонести́ ча́шу сию́ от Мене́, оба́че не Моя́ во́ля, но Твоя́ да бу́дет. И прише́д ко ученико́м, обре́те их спя́щя от печа́ли и рече́ им: что спите́? Воста́вше моли́теся, да не вни́дете в напа́сть. Еще́ же Ему́ глаго́лющу, се наро́д, и нарица́емый Иу́да, еди́н от обоюна́десяте, идя́ше пред ни́ми, и приступи́ ко Иису́сови целова́ти Его́. Сие́ бо бе зна́мение дал им: Его́же а́ще лобжу́, Той есть. Иису́с же рече́ ему́: Иу́до, лобза́нием ли Сы́на Челове́ческаго предае́ши? Ви́девше же, и́же бе́ху о Нем быва́емое, ре́ша Ему́: Го́споди, а́ще уда́рим ноже́м? И уда́ри еди́н не́кий от них архиере́ова раба́ и уре́за ему́ у́хо десно́е. Отвеща́в же Иису́с рече́: оста́вите до сего́. И косну́в во у́хо его́, исцели́ его́. Рече́ же Иису́с ко прише́дшым Нань архиере́ом и воево́дам церко́вным и ста́рцем: я́ко на разбо́йника ли изыдо́сте со ору́жием и дреко́льми я́ти Мя? По вся дни су́щу Ми с ва́ми в це́ркви, не простро́сте руки́ на Мя, но се есть ва́ша годи́на и о́бласть те́мная. Е́мше же Его́ ведо́ша и введо́ша Его́ во двор архиере́ов. Петр же в след идя́ше издале́ча. Возгне́щшым же огнь посреде́ двора́ и вку́пе седя́щым им, седя́ше Петр посреде́ их. Узре́вши же его́ рабы́ня не́кая седя́ща при све́те и воззре́вши нань, рече́: и сей с Ним бе. Он же отве́ржеся Его́, глаго́ля: же́но, не зна́ю Его́. И по ма́ле други́й ви́дев его́, рече́: и ты от них еси́. Петр же рече́: челове́че, несмь. И мимоше́дшу я́ко часу́ еди́ному, ин не́кий крепля́шеся глаго́ля: вои́стинну и сей с Ним бе, и́бо Галиле́анин есть. Рече́ же Петр: челове́че, не вем, е́же глаго́леши. И а́бие, еще́ глаго́лющу ему́, возгласи́ пе́тель. И обра́щься Госпо́дь воззре́ на Петра́, и помяну́ Петр сло́во Госпо́дне, я́коже рече́ ему́: я́ко пре́жде да́же пе́тель не возгласи́т, отве́ржешися Мене́ трикра́ты. И изше́д вон пла́кася го́рько. И му́жие держа́щии Иису́са руга́хуся Ему́, бию́ще, и закры́вше Его́, бия́ху Его́ по лицу́ и вопроша́ху Его́, глаго́люще: прорцы́, кто есть ударе́й Тя? И и́на мно́га ху́ляще глаго́лаху Нань. И я́ко бысть день, собра́шася ста́рцы людсти́и и архиере́е и кни́жницы, и ведо́ша Его́ на сонм свой, глаго́люще: а́ще Ты еси́ Христо́с? Рцы нам. Рече́ же им: а́ще вам реку́, не и́мете ве́ры, а́ще же и вопрошу́ вы, не отвеща́ете Ми, ни отпустите́, отсе́ле бу́дет Сын Челове́ческий седя́й одесну́ю си́лы Бо́жия. Ре́ша же вси: Ты ли у́бо еси́ Сын Бо́жий? Он же к ним рече́: вы глаго́лете, я́ко Аз есмь. Они́ же ре́ша: что еще́ тре́буем свиде́тельства? Са́ми бо слы́шахом от уст Его́. И воста́вше все мно́жество их, ведо́ша Его́ к Пила́ту. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆зше́дъ і҆и҃съ и҆́де по ѻ҆бы́чаю въ го́рꙋ є҆леѡ́нскꙋю: по не́мже и҆до́ша ᲂу҆ченицы̀ є҆гѡ̀. бы́въ же на мѣ́стѣ, речѐ и҆̀мъ: моли́тесѧ, да не вни́дете въ напа́сть. и҆ са́мъ ѿстꙋпѝ ѿ ни́хъ ꙗ҆́кѡ верже́нїемъ ка́мене, и҆ покло́нь колѣ̑на молѧ́шесѧ, глаго́лѧ: ѻ҆́ч҃е, а҆́ще во́лиши мимонестѝ ча́шꙋ сїю̀ ѿ менѐ: ѻ҆ба́че не моѧ̀ во́лѧ, но твоѧ̀ да бꙋ́детъ. и҆ прише́дъ ко ᲂу҆ченикѡ́мъ, ѡ҆брѣ́те и҆̀хъ спѧ́щѧ ѿ печа́ли. и҆ речѐ и҆̀мъ: что̀ спитѐ; воста́вше моли́тесѧ, да не вни́дете въ напа́сть. є҆ще́ же є҆мꙋ̀ глаго́лющꙋ, сѐ наро́дъ, и҆ нарица́емый і҆ꙋ́да є҆ди́нъ ѿ ѻ҆боюна́десѧте, и҆дѧ́ше пред̾ ни́ми. и҆ пристꙋпѝ ко і҆и҃сови цѣлова́ти є҆го̀. сїе́ бо бѣ̀ зна́менїе да́лъ и҆̀мъ: є҆го́же а҆́ще лобжꙋ̀, то́й є҆́сть. і҆и҃съ же речѐ є҆мꙋ̀: і҆ꙋ́до, лобза́нїемъ ли сн҃а человѣ́ческаго предае́ши; ви́дѣвше же, и҆̀же бѣ́хꙋ ѡ҆ не́мъ быва́емое, рѣ́ша є҆мꙋ̀: гдⷭ҇и, а҆́ще ᲂу҆да́римъ ноже́мъ; и҆ ᲂу҆да́ри є҆ди́нъ нѣ́кїй ѿ ни́хъ а҆рхїере́ова раба̀, и҆ ᲂу҆рѣ́за є҆мꙋ̀ ᲂу҆́хо десно́е. ѿвѣща́въ же і҆и҃съ, речѐ: ѡ҆ста́вите до сегѡ̀, и҆ коснꙋ́въ во ᲂу҆́хо є҆гѡ̀, и҆сцѣлѝ є҆го̀. рече́ же і҆и҃съ ко прише́дшымъ на́нь а҆рхїере́ѡмъ, и҆ воево́дамъ церкѡ́внымъ, и҆ ста́рцємъ: ꙗ҆́кѡ на разбо́йника ли и҆зыдо́сте, со ѻ҆рꙋ́жїемъ и҆ дреко́льми ꙗ҆́ти мѧ̀; по всѧ̀ днѝ сꙋ́щꙋ мѝ съ ва́ми въ це́ркви, не простро́сте рꙋкѝ на мѧ̀: но сѐ є҆́сть ва́ша годи́на, и҆ ѻ҆́бласть те́мнаѧ. є҆́мше же є҆го̀ ведо́ша, и҆ введо́ша є҆го̀ во дво́ръ а҆рхїере́овъ: пе́тръ же во слѣ́дъ и҆дѧ́ше и҆здале́ча. возгнѣ́щшымъ же ѻ҆́гнь посредѣ̀ двора̀, и҆ вкꙋ́пѣ сѣдѧ́щымъ и҆̀мъ, сѣдѧ́ше пе́тръ посредѣ̀ и҆́хъ. ᲂу҆зрѣ́вши же є҆го̀ рабы́нѧ нѣ́каѧ, сѣдѧ́ща при свѣ́тѣ, и҆ воззрѣ́вши на́нь, речѐ: и҆ се́й съ ни́мъ бѣ̀. ѻ҆́нъ же ѿве́ржесѧ є҆гѡ̀, глаго́лѧ: же́но, не зна́ю є҆гѡ̀. и҆ по ма́лѣ дрꙋгі́й ви́дѣвъ є҆го̀, речѐ: и҆ ты̀ ѿ ни́хъ є҆сѝ. пе́тръ же речѐ: человѣ́че, нѣ́смь. и҆ мимоше́дшꙋ ꙗ҆́кѡ часꙋ̀ є҆ди́номꙋ, и҆́нъ нѣ́кїй крѣплѧ́шесѧ, глаго́лѧ: вои́стиннꙋ и҆ се́й съ ни́мъ бѣ̀: и҆́бо галїле́анинъ є҆́сть. рече́ же пе́тръ: человѣ́че, не вѣ́мъ є҆́же глаго́леши. и҆ а҆́бїе, є҆щѐ глаго́лющꙋ є҆мꙋ̀, возгласѝ пѣ́телъ. и҆ ѡ҆бра́щсѧ гдⷭ҇ь воззрѣ̀ на петра̀, и҆ помѧнꙋ̀ пе́тръ сло́во гдⷭ҇не, ꙗ҆́коже речѐ є҆мꙋ̀: ꙗ҆́кѡ пре́жде да́же пѣ́телъ не возгласи́тъ, ѿве́ржешисѧ менѐ трикра́ты. и҆ и҆зше́дъ во́нъ, пла́касѧ го́рькѡ. и҆ мꙋ́жїе, держа́щїи і҆и҃са, рꙋга́хꙋсѧ є҆мꙋ̀ бїю́ще. и҆ закры́вше є҆го̀, бїѧ́хꙋ є҆го̀ по лицꙋ̀, и҆ вопроша́хꙋ є҆го̀, глаго́люще: прорцы̀, кто́ є҆сть ᲂу҆даре́й тѧ̀; и҆ и҆́на мнѡ́га хꙋ́лѧще глаго́лахꙋ на́нь. и҆ ꙗ҆́кѡ бы́сть де́нь, собра́шасѧ ста́рцы людсті́и и҆ а҆рхїере́є, и҆ кни́жницы, и҆ ведо́ша є҆го̀ на со́нмъ сво́й, глаго́люще: а҆́ще ты̀ є҆сѝ хрⷭ҇то́съ, рцы̀ на́мъ; рече́ же и҆̀мъ: а҆́ще ва́мъ рекꙋ̀, не и҆́мете вѣ́ры. а҆́ще же и҆ вопрошꙋ̀ вы̀, не ѿвѣща́ете мѝ, ни ѿпꙋститѐ. ѿсе́лѣ бꙋ́детъ сн҃ъ человѣ́ческїй сѣдѧ́й ѡ҆деснꙋ́ю си́лы бж҃їѧ. рѣ́ша же всѝ: ты́ ли ᲂу҆́бѡ є҆сѝ сн҃ъ бж҃їй; ѻ҆́нъ же къ ни́мъ речѐ: вы̀ глаго́лете, ꙗ҆́кѡ а҆́зъ є҆́смь. ѻ҆ни́ же рѣ́ша: что̀ є҆щѐ тре́бꙋемъ свидѣ́тельства; са́ми бо слы́шахомъ ѿ ᲂу҆́стъ є҆гѡ̀. и҆ воста́вше всѐ мно́жество и҆́хъ, ведо́ша є҆го̀ къ пїла́тꙋ. ",
}

add_evangelie_luki {
  ["номер"] = 110,
  ["комментарий"] = "Лк., 110 зач., XXIII, 1–34, 44–56.",
  ["текст_ру"] = "Во вре́мя о́но, ведо́ша Иису́са архиере́и и кни́жницы, и ста́рцы людсти́и к Пила́ту, и нача́ша Нань ва́дити, глаго́люще: Сего́ обрето́хом развраща́юща язы́к наш и возбраня́юща ке́сареви дань дая́ти, глаго́люща Себе́ Христа́ Царя́ бы́ти. Пила́т же вопроси́ Его́, глаго́ля: Ты ли еси́ Царь Иуде́ом? Он же отвеща́в рече́ ему́: ты глаго́леши. Пила́т же рече́ ко архиере́ом и наро́ду: никоея́же обрета́ю вины́ в челове́це сем. Они́ же крепля́хуся глаго́люще, я́ко развраща́ет лю́ди, учя́ по всей Иуде́и, наче́н от Галиле́и до зде. Пила́т же слы́шав Галиле́ю, вопроси́, а́ще челове́к Галиле́анин есть? И разуме́в, я́ко от о́бласти И́родовы есть, посла́ Его́ ко И́роду, су́щу и тому́ во Иерусали́ме в ты́я дни. И́род же ви́дев Иису́са рад бысть зело́, бе бо жела́я от мно́га вре́мене ви́дети Его́, зане́ слы́шаше мно́га о Нем, и наде́яшеся зна́мение не́кое ви́дети от Него́ быва́емо. Вопроша́ше же Его́ словесы́ мно́ги, Он же ничесо́же отвещава́ше ему́. Стоя́ху же архиере́е и кни́жницы, приле́жно ва́дяще Нань. Укори́в же Его́ И́род с во́и свои́ми и поруга́вся, обо́лк его́ в ри́зу све́тлу, возврати́ Его́ к Пила́ту. Бы́ста же си дру́га И́род же и Пила́т в той день с собо́ю, пре́жде бо бе́ста вражду́ иму́ща между́ собо́ю. Пила́т же созва́ архиере́и и кня́зи и лю́ди, рече́ к ним: приведо́сте ми челове́ка сего́, я́ко развраща́юща лю́ди, и се аз пред ва́ми истяза́в, ни еди́ныя же обрета́ю в челове́це сем вины́, я́же Нань ва́дите. Но ни И́род, посла́х бо Его́ к нему́, и се ничто́же досто́йно сме́рти сотворе́но есть о Нем, показа́в у́бо Его́ отпущу́. Ну́жду же имя́ше на вся пра́здники отпуща́ти им еди́наго. Возопи́ша же вси наро́ди, глаго́люще: возми́ Сего́, отпусти́ же нам Вара́вву. И́же бе за не́кую крамолу́ бы́вшую во гра́де и уби́йство вве́ржен в темни́цу. Па́ки же Пила́т возгласи́, хотя́ отпусти́ти Иису́са. Они́ же возглаша́ху, глаго́люще: распни́, распни́ Его́. Он же трети́цею рече́ к ним: что бо зло сотвори́ Сей? Ничесо́же досто́йна сме́рти обрето́х о Нем, показа́в у́бо Его́ отпущу́. Они́ же прилежа́ху гла́сы вели́кими, прося́ще Его́ на распя́тие, и устоя́ху гла́си их и архиере́йстии. Пила́т же посуди́ бы́ти проше́нию их. Отпусти́ же и́же за крамолу́ и уби́йство всажде́ннаго в темни́цу, его́же проша́ху, Иису́са же преда́в во́ли их. И я́ко поведо́ша Его́, е́мше Си́мона не́коего Кирине́а, гряду́ща с села́, возложи́ша нань крест носи́ти по Иису́се. Идя́ше же во след Его́ наро́д мног люде́й, и жены́, я́же и пла́кахуся и рыда́ху Его́. Обра́щься же к ним Иису́с рече́: дще́ри Иерусали́мски, не пла́читеся о Мне, оба́че себе́ пла́чите и чад ва́ших. Я́ко се дни́е гряду́т, в ня́же реку́т: блаже́ны непло́ды, и утро́бы, я́же не роди́ша, и сосцы́, и́же не дои́ша. Тогда́ начну́т глаго́лати гора́м: пади́те на ны, и холмо́м: покры́йте ны. Зане́ а́ще в су́рове дре́ве сия́ творя́т, в су́се что бу́дет? Ведя́ху же и и́на два злоде́я с Ним уби́ти. И егда́ приидо́ша на ме́сто, нарица́емое Ло́бное, ту распя́ша Его́ и злоде́я, о́ваго у́бо одесну́ю, а друга́го ошу́юю. Иису́с же глаго́лаше: О́тче, отпусти́ им, не ве́дят бо что творя́т. Бе же час я́ко шесты́й, и тма бысть по всей земли́ до часа́ девя́таго, и поме́рче со́лнце, и заве́са церко́вная раздра́ся посреде́. И возгла́шь гла́сом ве́лиим Иису́с, рече́: О́тче, в ру́це Твои́ предаю́ дух Мой. И сия́ рек и́здше. Ви́дев же со́тник бы́вшее, просла́ви Бо́га, глаго́ля: вои́стинну челове́к сей пра́веден бе. И вси прише́дшии наро́ди на позо́р сей, ви́дяще быва́ющая, бию́ще пе́рси своя́ возвраща́хуся. Стоя́ху же вси зна́емии Его́ издале́ча, и жены́ спосле́дствовавшыя Ему́ от Галиле́и, зря́ще сия́. И се муж и́менем Ио́сиф, сове́тник сый, муж благ и пра́веден сей не бе приста́л сове́ту и де́лу их, от Аримафе́а гра́да Иуде́йска, и́же ча́яше и той Ца́рствия Бо́жия. Сей присту́пль к Пила́ту, проси́ те́ло Иису́сова, и снем е́ обви́т плащани́цею, и положи́ е́ во гро́бе изсе́чене, в не́мже не бе никто́же никогда́же положе́н. И день бе пято́к, и суббо́та света́ше. Во след же ше́дшыя жены́, я́же бя́ху пришли́ с Ним от Галиле́и, ви́деша гроб, и я́ко положе́но бысть те́ло Его́. Возвра́щшеся же угото́ваша арома́ты и ми́ро, и в суббо́ту у́бо умолча́ша по за́поведи. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ведо́ша і҆и҃са а҆рхїере́и, и҆ кни́жницы, и҆ ста́рцы людсті́и къ пїла́тꙋ, и҆ нача́ша на́нь ва́дити, глаго́люще: сего̀ ѡ҆брѣто́хомъ развраща́юща ꙗ҆зы́къ на́шъ, и҆ возбранѧ́юща ке́сареви да́нь даѧ́ти: глаго́люща себѐ хрⷭ҇та̀ цр҃ѧ̀ бы́ти. пїла́тъ же вопросѝ є҆го̀, глаго́лѧ: ты́ ли є҆сѝ цр҃ь і҆ꙋде́ѡмъ; ѻ҆́нъ же ѿвѣща́въ речѐ є҆мꙋ̀: ты̀ глаго́леши. пїла́тъ же речѐ ко а҆рхїере́ѡмъ и҆ наро́дꙋ: никоеѧ́же ѡ҆брѣта́ю вины̀ въ человѣ́цѣ се́мъ. ѻ҆ни́ же крѣплѧ́хꙋсѧ, глаго́люще: ꙗ҆́кѡ развраща́етъ лю́ди, ᲂу҆чѧ̀ по все́й і҆ꙋде́и, наче́нъ ѿ галїле́и до здѣ̀. пїла́тъ же слы́шавъ галїле́ю, вопросѝ: а҆́ще человѣ́къ галїле́анинъ є҆́сть; и҆ разꙋмѣ́въ, ꙗ҆́кѡ ѿ ѻ҆́бласти и҆́рѡдовы є҆́сть, посла̀ є҆го̀ ко и҆́рѡдꙋ, сꙋ́щꙋ и҆ томꙋ̀ во і҆ерꙋсали́мѣ въ ты́ѧ днѝ. и҆́рѡдъ же ви́дѣвъ і҆и҃са, ра́дъ бы́сть ѕѣлѡ̀: бѣ́ бо жела́ѧ ѿ мно́га вре́мене ви́дѣти є҆го̀: занѐ слы́шаше мнѡ́га ѡ҆ не́мъ, и҆ надѣ́ѧшесѧ зна́менїе нѣ́кое ви́дѣти ѿ негѡ̀ быва́емо. вопроша́ше же є҆го̀ словесы̀ мно́ги: ѻ҆́нъ же ничесѡ́же ѿвѣщава́ше є҆мꙋ̀. стоѧ́хꙋ же а҆рхїере́є и҆ кни́жницы прилѣ́жнѡ ва́дѧще на́нь. ᲂу҆кори́въ же є҆го̀ и҆́рѡдъ съ вѡ́и свои́ми, и҆ порꙋга́всѧ, ѡ҆бо́лкъ є҆го̀ въ ри́зꙋ свѣ́тлꙋ, возвратѝ є҆го̀ къ пїла́тꙋ. бы́ста же сѝ дрꙋ́га, и҆́рѡдъ же и҆ пїла́тъ въ то́й де́нь съ собо́ю: пре́жде бо бѣ́ста враждꙋ̀ и҆мꙋ́ща междꙋ̀ собо́ю. пїла́тъ же созва̀ а҆рхїерє́и, и҆ кнѧ́зи, и҆ лю́ди. речѐ къ ни́мъ: приведо́сте мѝ человѣ́ка сего̀, ꙗ҆́кѡ развраща́юща лю́ди: и҆ сѐ а҆́зъ пред̾ ва́ми и҆стѧза́въ, ни є҆ди́ныѧ же ѡ҆брѣта́ю въ человѣ́цѣ се́мъ вины̀, ꙗ҆̀же на́нь ва́дите. но ни и҆́рѡдъ: посла́хъ бо є҆го̀ къ немꙋ̀, и҆ сѐ ничто́же досто́йно сме́рти сотворе́но є҆́сть ѡ҆ не́мъ. показа́въ ᲂу҆́бѡ є҆го̀, ѿпꙋщꙋ̀. нꙋ́ждꙋ же и҆мѧ́ше на всѧ̀ пра́здники, ѿпꙋща́ти и҆̀мъ є҆ди́наго. возопи́ша же всѝ наро́ди глаго́люще: воз̾мѝ сего̀, ѿпꙋсти́ же на́мъ вара́ввꙋ: и҆́же бѣ̀ за нѣ́кꙋю крамолꙋ̀, бы́вшꙋю во гра́дѣ, и҆ ᲂу҆бі́йство вве́рженъ въ темни́цꙋ. па́ки же пїла́тъ возгласѝ, хотѧ̀ ѿпꙋсти́ти і҆и҃са. ѻ҆ни́ же возглаша́хꙋ, глаго́люще: распнѝ, распнѝ є҆го̀. ѻ҆́нъ же трети́цею речѐ къ ни́мъ: что́ бо ѕло̀ сотворѝ се́й; ничесѡ́же досто́йна сме́рти ѡ҆брѣто́хъ ѡ҆ не́мъ: показа́въ ᲂу҆́бѡ є҆го̀, ѿпꙋщꙋ̀. ѻ҆ни́ же прилѣжа́хꙋ гла́сы вели́кими, просѧ́ще є҆го̀ на распѧ́тїе, и҆ ѡу҆стоѧ́хꙋ гла́си и҆́хъ и҆ а҆рхїере́йстїи. пїла́тъ же посꙋдѝ бы́ти проше́нїю и҆́хъ. ѿпꙋсти́ же и҆́же за крамолꙋ̀ и҆ ᲂу҆бі́йство всажде́ннаго въ темни́цꙋ, є҆го́же проша́хꙋ: і҆и҃са же преда́въ во́ли и҆́хъ. и҆ ꙗ҆́кѡ поведо́ша є҆го̀, є҆́мше сі́мѡна нѣ́коего кѷрине́а грѧдꙋ́ща съ села̀, возложи́ша на́нь крⷭ҇тъ, носи́ти по і҆и҃сѣ. и҆дѧ́ше же во слѣ́дъ є҆гѡ̀ наро́дъ мно́гъ люде́й, и҆ жєны̀, ꙗ҆̀же и҆ пла́кахꙋсѧ и҆ рыда́хꙋ є҆гѡ̀. ѡ҆бра́щсѧ же къ ни́мъ і҆и҃съ, речѐ: дщє́ри і҆ерꙋсали́мски, не пла́читесѧ ѡ҆ мнѣ̀, ѻ҆ба́че себѐ пла́чите, и҆ ча̑дъ ва́шихъ. ꙗ҆́кѡ сѐ дні́е грѧдꙋ́тъ, въ нѧ́же рекꙋ́тъ: блаже́ны неплѡ́ды, и҆ ᲂу҆трѡ́бы, ꙗ҆̀же не роди́ша, и҆ сосцы̀, и҆̀же не дои́ша. тогда̀ начнꙋ́тъ глаго́лати гора́мъ: пади́те на ны̀. и҆ холмѡ́мъ: покры́йте ны̀. занѐ а҆́ще въ сꙋ́ровѣ дре́вѣ сїѧ̑ творѧ́тъ, въ сꙋ́сѣ что̀ бꙋ́детъ; ведѧ́хꙋ же и҆ и҆́на два̀ ѕлодѣ́ѧ съ ни́мъ ᲂу҆би́ти. и҆ є҆гда̀ прїидо́ша на мѣ́сто нарица́емое ло́бное, тꙋ̀ распѧ́ша є҆го̀, и҆ ѕлодѣ̑ѧ, ѻ҆́ваго ᲂу҆́бѡ ѡ҆деснꙋ́ю, а҆ дрꙋга́го ѡ҆шꙋ́юю. і҆и҃съ же глаго́лаше: ѻ҆́ч҃е, ѿпꙋстѝ и҆̀мъ: не вѣ́дѧтъ бо что̀ творѧ́тъ. бѣ́ же ча́съ ꙗ҆́кѡ шесты́й, и҆ тма̀ бы́сть по все́й землѝ до часа̀ девѧ́тагѡ. и҆ поме́рче со́лнце, и҆ завѣ́са цр҃ко́внаѧ раздра́сѧ посредѣ̀. и҆ возгла́шь гла́сомъ ве́лїимъ і҆и҃съ речѐ: ѻ҆́ч҃е, въ рꙋ́цѣ твоѝ предаю̀ дх҃ъ мо́й: и҆ сїѧ̑ ре́къ и҆́здше. ви́дѣвъ же со́тникъ бы́вшее, просла́ви бг҃а, глаго́лѧ: вои́стиннꙋ человѣ́къ се́й пра́веденъ бѣ̀. и҆ всѝ прише́дшїи наро́ди на позо́ръ се́й, ви́дѧще быва̑ющаѧ, бїю́ще пє́рси своѧ̀, возвраща́хꙋсѧ. стоѧ́хꙋ же всѝ зна́емїи є҆гѡ̀ и҆здале́ча, и҆ жєны̀ спослѣ́дствовавшыѧ є҆мꙋ̀ ѿ галїле́и, зрѧ́ще сїѧ̑. и҆ сѐ мꙋ́жъ и҆́менемъ і҆ѡ́сифъ, совѣ́тникъ, сы́й мꙋ́жъ бла́гъ и҆ пра́веденъ: се́й не бѣ̀ приста́лъ совѣ́тꙋ и҆ дѣ́лꙋ и҆́хъ, ѿ а҆рїмаѳе́а гра́да і҆ꙋде́йска, и҆́же ча́ѧше и҆ то́й црⷭ҇твїѧ бж҃їѧ. се́й пристꙋ́пль къ пїла́тꙋ, просѝ тѣ́ло і҆и҃сово. и҆ сне́мъ є҆̀, ѡ҆бви́тъ плащани́цею, и҆ положѝ є҆̀ во гро́бѣ и҆зсѣ́ченѣ, въ не́мже не бѣ̀ никто́же никогда́же положе́нъ. и҆ де́нь бѣ̀ пѧто́къ, и҆ сꙋббѡ́та свѣта́ше. во слѣ́дъ же ше́дшыѧ жєны̀, ꙗ҆̀же бѧ́хꙋ пришлѝ съ ни́мъ ѿ галїле́и, ви́дѣша гро́бъ, и҆ ꙗ҆́кѡ положе́но бы́сть тѣ́ло є҆гѡ̀. возвра́щшесѧ же ᲂу҆гото́ваша а҆рѡма́ты, и҆ мѵ́ро: и҆ въ сꙋббѡ́тꙋ ᲂу҆́бѡ ᲂу҆молча́ша по за́повѣди. ",
}

add_evangelie_luki {
  ["номер"] = 111,
  ["комментарий"] = "Лк., 111 зач., XXIII, 32–49.",
  ["текст_ру"] = "Во вре́мя о́но, ведя́ху со Иису́сом и и́на два злоде́я с Ним уби́ти. И егда́ приидо́ша на ме́сто, нарица́емое Ло́бное, ту распя́ша Его́ и злоде́я, о́ваго у́бо одесну́ю, а друга́го ошу́юю. Иису́с же глаго́лаше: О́тче, отпусти́ им, не ве́дят бо что творя́т. Разделя́юще же ри́зы Его́, мета́ху жре́бия. И стоя́ху лю́дие зря́ще. Руга́хуся же и кня́зи с ни́ми, глаго́люще: ины́я спасе́, да спасе́т и Себе́, а́ще Той есть Христо́с Бо́жий избра́нный. Руга́хуся же Ему́ и во́ини, приступа́юще и о́цет приде́юще Ему́, и глаго́лаху: а́ще Ты еси́ Царь Иуде́йск, спаси́ся Сам. Бе же и написа́ние напи́сано над Ним писмены́ е́ллинскими и ри́мскими и евре́йскими: Сей есть Царь Иуде́йск. Еди́н же от обе́шеною злоде́ю ху́ляше Его́, глаго́ля: а́ще Ты еси́ Христо́с, спаси́ Себе́ и на́ю. Отвеща́в же други́й преща́ше ему́, глаго́ля: ни ли ты бои́шися Бо́га, я́ко в то́мже осужде́н еси́? И мы у́бо в пра́вду, досто́йная бо по дело́м на́ю восприе́млева, Сей же ни еди́наго зла сотвори́. И глаго́лаше Иису́сови: помяни́ мя, Го́споди, егда́ прии́деши во Ца́рствии си. И рече́ ему́ Иису́с: ами́нь глаго́лю тебе́, днесь со Мно́ю бу́деши в раи́. Бе же час я́ко шесты́й, и тма бысть по всей земли́ до часа́ девя́таго, и поме́рче со́лнце, и заве́са церко́вная раздра́ся посреде́. И возгла́шь гла́сом ве́лиим Иису́с, рече́: О́тче, в ру́це Твои́ предаю́ дух Мой. И сия́ рек и́здше. Ви́дев же со́тник бы́вшее, просла́ви Бо́га, глаго́ля: вои́стинну челове́к сей пра́веден бе. И вси прише́дшии наро́ди на позо́р сей, ви́дяще быва́ющая, бию́ще пе́рси своя́ возвраща́хуся. Стоя́ху же вси зна́емии Его́ издале́ча, и жены́ спосле́дствовавшыя Ему́ от Галиле́и, зря́ще сия́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ведѧ́хꙋ со і҆и҃сомъ и҆ и҆́на два̀ ѕлодѣ́ѧ съ ни́мъ ᲂу҆би́ти. и҆ є҆гда̀ прїидо́ша на мѣ́сто нарица́емое ло́бное, тꙋ̀ распѧ́ша є҆го̀, и҆ ѕлодѣ̑ѧ, ѻ҆́ваго ᲂу҆́бѡ ѡ҆деснꙋ́ю, а҆ дрꙋга́го ѡ҆шꙋ́юю. і҆и҃съ же глаго́лаше: ѻ҆́ч҃е, ѿпꙋстѝ и҆̀мъ: не вѣ́дѧтъ бо что̀ творѧ́тъ. раздѣлѧ́юще же ри̑зы є҆гѡ̀, мета́хꙋ жрє́бїѧ. и҆ стоѧ́хꙋ лю́дїе зрѧ́ще. рꙋга́хꙋсѧ же и҆ кнѧ́зи съ ни́ми, глаго́люще: и҆ны̑ѧ спасѐ, да спасе́тъ и҆ себѐ, а҆́ще то́й є҆́сть хрⷭ҇то́съ бж҃їй и҆збра́нный. рꙋга́хꙋсѧ же є҆мꙋ̀ и҆ во́ини, пристꙋпа́юще, и҆ ѻ҆́цетъ придѣ́юще є҆мꙋ̀. и҆ глаго́лахꙋ: а҆́ще ты̀ є҆сѝ цр҃ь і҆ꙋде́йскъ, спаси́сѧ са́мъ. бѣ́ же и҆ написа́нїе напи́сано над̾ ни́мъ писмены̀ є҆́ллинскими, и҆ ри́мскими, и҆ є҆вре́йскими: се́й є҆́сть цр҃ь і҆ꙋде́йскъ. є҆ди́нъ же ѿ ѡ҆бѣ́шеною ѕлодѣ̑ю хꙋ́лѧше є҆го̀, глаго́лѧ: а҆́ще ты̀ є҆сѝ хрⷭ҇то́съ, спасѝ себѐ и҆ на́ю. ѿвѣща́въ же дрꙋгі́й, преща́ше є҆мꙋ̀, глаго́лѧ: ни лѝ ты̀ бои́шисѧ бг҃а, ꙗ҆́кѡ въ то́мже ѡ҆сꙋжде́нъ є҆сѝ; и҆ мы̀ ᲂу҆́бѡ въ пра́вдꙋ, достѡ́йнаѧ бо по дѣлѡ́мъ на́ю воспрїе́млева: се́й же ни є҆ди́нагѡ ѕла̀ сотворѝ. и҆ глаго́лаше і҆и҃сови: помѧни́ мѧ гдⷭ҇и, є҆гда̀ прїи́деши во црⷭ҇твїи сѝ. и҆ речѐ є҆мꙋ̀ і҆и҃съ: а҆ми́нь глаго́лю тебѣ̀, дне́сь со мно́ю бꙋ́деши въ раѝ. бѣ́ же ча́съ ꙗ҆́кѡ шесты́й, и҆ тма̀ бы́сть по все́й землѝ до часа̀ девѧ́тагѡ. и҆ поме́рче со́лнце, и҆ завѣ́са цр҃ко́внаѧ раздра́сѧ посредѣ̀. и҆ возгла́шь гла́сомъ ве́лїимъ і҆и҃съ речѐ: ѻ҆́ч҃е, въ рꙋ́цѣ твоѝ предаю̀ дх҃ъ мо́й: и҆ сїѧ̑ ре́къ и҆́здше. ви́дѣвъ же со́тникъ бы́вшее, просла́ви бг҃а, глаго́лѧ: вои́стиннꙋ человѣ́къ се́й пра́веденъ бѣ̀. и҆ всѝ прише́дшїи наро́ди на позо́ръ се́й, ви́дѧще быва̑ющаѧ, бїю́ще пє́рси своѧ̀, возвраща́хꙋсѧ. стоѧ́хꙋ же всѝ зна́емїи є҆гѡ̀ и҆здале́ча, и҆ жєны̀ спослѣ́дствовавшыѧ є҆мꙋ̀ ѿ галїле́и, зрѧ́ще сїѧ̑. ",
}

add_evangelie_luki {
  ["номер"] = 112,
  ["комментарий"] = "Лк., 112 зач., XXIV, 1–12.",
  ["текст_ру"] = "Во вре́мя о́но, во еди́ну от суббо́т, зело́ ра́но приидо́ша жены́ на гроб, нося́ще я́же угото́ваша арома́ты, и други́я с ни́ми. Обрето́ша же ка́мень отвале́н от гро́ба, и вше́дше не обрето́ша телесе́ Го́спода Иису́са. И бысть не домышля́ющымся им о сем, и се му́жа два ста́ста в них в ри́зах блеща́щихся. Пристра́шным же бы́вшым им и покло́ншым ли́ца на зе́млю, реко́ста к ним, что и́щете жива́го с ме́ртвыми? Несть зде, но воста́. Помяни́те, я́коже глаго́ла вам, еще́ сый в Галиле́и, глаго́ля, я́ко подоба́ет Сы́ну Челове́ческому пре́дану бы́ти в ру́це челове́к гре́шник, и про́пяту бы́ти, и в тре́тий день воскре́снути. И помяну́ша глаго́лы Его́, и возвра́щшеся от гро́ба, возвести́ша вся сия́ единомуна́десяте и всем про́чым. Бя́ше же Магдали́на Мари́а и Иоа́нна и Мари́а Иа́ковля, и про́чыя с ни́ми, я́же глаго́лаху ко Апо́столом сия́. И яви́шася пред ни́ми я́ко лжа глаго́лы их, и не ве́роваху им. Петр же воста́в тече́ ко гро́бу и прини́к ви́де ри́зы еди́ны лежа́щя, и оты́де, в себе́ дивя́ся бы́вшему. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, во є҆ди́нꙋ ѿ сꙋббѡ́тъ, ѕѣлѡ̀ ра́нѡ прїидо́ша жєны̀ на гро́бъ, носѧ́ще ꙗ҆̀же ᲂу҆гото́ваша а҆рѡма́ты, и҆ дрꙋгі́ѧ съ ни́ми. ѡ҆брѣто́ша же ка́мень ѿвале́нъ ѿ гро́ба: и҆ вше́дше, не ѡ҆брѣто́ша тѣлесѐ гдⷭ҇а і҆и҃са. и҆ бы́сть не домышлѧ́ющымсѧ и҆̀мъ ѡ҆ се́мъ, и҆ сѐ мꙋ́жа два̀ ста́ста въ ни́хъ въ ри́захъ блеща́щихсѧ. пристра́шнымъ же бы́вшымъ и҆̀мъ, и҆ покло́ншымъ ли́ца на зе́млю, реко́ста къ ни́мъ: что̀ и҆́щете жива́гѡ съ ме́ртвыми; нѣ́сть здѣ̀, но воста̀. помѧни́те ꙗ҆́коже глаго́ла ва́мъ, є҆щѐ сы́й въ галїле́и, глаго́лѧ: ꙗ҆́кѡ подоба́етъ сн҃ꙋ человѣ́ческомꙋ пре́данꙋ бы́ти въ рꙋ́цѣ человѣ̑къ грѣ̑шникъ, и҆ про́пѧтꙋ бы́ти, и҆ въ тре́тїй де́нь воскрⷭ҇нꙋти: и҆ помѧнꙋ́ша глаго́лы є҆гѡ̀. и҆ возвра́щшесѧ ѿ гро́ба, возвѣсти́ша всѧ̑ сїѧ̑ є҆диномꙋна́десѧте, и҆ всѣ́мъ про́чымъ. бѧ́ше же магдали́на марі́а, и҆ і҆ѡа́нна, и҆ марі́а і҆а́кѡвлѧ, и҆ про́чыѧ съ ни́ми, ꙗ҆̀же глаго́лахꙋ ко а҆по́столѡмъ сїѧ̑. и҆ ꙗ҆ви́шасѧ пред̾ ни́ми ꙗ҆́кѡ лжа̀ глаго́лы и҆́хъ, и҆ не вѣ́ровахꙋ и҆̀мъ. пе́тръ же воста́въ течѐ ко гро́бꙋ, и҆ прини́къ ви́дѣ ри̑зы є҆ди́ны лежа́щѧ, и҆ ѿи́де, въ себѣ̀ дивѧ́сѧ бы́вшемꙋ. ",
}

add_evangelie_luki {
  ["номер"] = 113,
  ["комментарий"] = "Лк., 113 зач., XXIV, 12–35.",
  ["текст_ру"] = "Во вре́мя о́но, Петр воста́в тече́ ко гро́бу и прини́к ви́де ри́зы еди́ны лежа́щя, и оты́де, в себе́ дивя́ся бы́вшему. И се два от них бе́ста иду́ща в то́йже день в весь отстоя́щу ста́дий шестьдеся́т от Иерусали́ма, е́йже и́мя Еммау́с, и та бесе́доваста к себе́ о всех сих приклю́чшихся. И бысть бесе́дующема и́ма и совопроща́ющемася, и Сам Иису́с прибли́жися идя́ше с ни́ма, о́чи же ею́ держа́стеся, да Его́ не позна́ета. Рече́ же к ни́ма: что суть словеса́ сия́, о ни́хже стяза́етася к себе́ иду́ща, и еста́ дря́хла? Отвеща́в же еди́н, ему́же и́мя Клео́па, рече́ к Нему́: Ты ли еди́н пришле́ц еси́ во Иерусали́м, и не уве́де бы́вших в нем во дни сия́? И рече́ и́ма: ки́их? О́на же ре́ста Ему́: я́же о Иису́се Назаряни́не, И́же бысть муж проро́к, си́лен де́лом и сло́вом пред Бо́гом и все́ми людьми́, ка́ко преда́ша Его́ архиере́и и кня́зи на́ши на осужде́ние сме́рти и распя́ша Его́. Мы же наде́яхомся, я́ко Сей есть хотя́ изба́вити Изра́иля, но и над все́ми си́ми, тре́тий сей день и́мать днесь, отне́лиже сия́ бы́ша. Но и жены́ не́кия от нас ужаси́ша ны, бы́вшыя ра́но у гро́ба, и не обре́тше телесе́ Его́, приидо́ша, глаго́люще, и явле́ние А́нгел ви́девше, и́же глаго́лют Его́ жи́ва. И идо́ша не́цыи от нас ко гро́бу и обрето́ша та́ко, я́коже и жены́ ре́ша, Самого́ же не ви́деша. И Той рече́ к нима: о несмы́сленная и ко́сная се́рдцем, е́же ве́ровати о всех, я́же глаго́лаша проро́цы. Не сия́ ли подоба́ше пострада́ти Христу́ и вни́ти в сла́ву Свою́? И наче́н от Моисе́а и от всех проро́к, сказа́ше и́ма от всех Писа́ний я́же о Нем. И прибли́жишася в весь, в ню́же идя́ста, и Той творя́шеся далеча́йше ити́. И ну́ждаста Его́, глаго́люще: обля́зи с на́ма, я́ко к ве́черу есть, и преклони́лся есть день. И вни́де с ни́ма облещи́. И бысть я́ко возлеже́ с ни́ма, и прии́м хлеб благослови́, и преломи́в дая́ше и́ма. О́нема же отверзо́стеся о́чи, и позна́ста Его́, и Той неви́димь бысть и́ма. И реко́ста к себе́: не се́рдце ли на́ю горя́ бе в на́ю, егда́ глаго́лаше на́ма на пути́ и я́ко ска́зоваше на́ма Писа́ния? И воста́вша в той час, возврати́стася во Иерусали́м и обрето́ста совоку́плены единагона́десяте и и́же бя́ху с ни́ми, глаго́лющих, я́ко вои́стинну воста́ Госпо́дь и яви́ся Си́мону. И та пове́даста, я́же бы́ша на пути́, и я́ко позна́ся и́ма в преломле́нии хле́ба. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пе́тръ воста́въ течѐ ко гро́бꙋ, и҆ прини́къ ви́дѣ ри̑зы є҆ди́ны лежа́щѧ, и҆ ѿи́де, въ себѣ̀ дивѧ́сѧ бы́вшемꙋ. и҆ сѐ, два̀ ѿ ни́хъ бѣ́ста и҆дꙋ́ща въ то́йже де́нь въ ве́сь, ѿстоѧ́щꙋ ста́дїй шестьдесѧ́тъ ѿ і҆ерꙋсали́ма, є҆́йже и҆́мѧ є҆ммаꙋ́съ. и҆ та̑ бесѣ́доваста къ себѣ̀ ѡ҆ всѣ́хъ си́хъ приклю́чшихсѧ. и҆ бы́сть бесѣ́дꙋющема и҆́ма и҆ совопроща́ющемасѧ: и҆ са́мъ і҆и҃съ прибли́жисѧ, и҆дѧ́ше съ ни́ма. ѻ҆́чи же є҆ю̀ держа́стѣсѧ, да є҆гѡ̀ не позна́ета. рече́ же къ ни́ма: что̀ сꙋ́ть словеса̀ сїѧ̀, ѡ҆ ни́хже стѧза́етасѧ къ себѣ̀ и҆дꙋ́ща, и҆ є҆ста̀ дрѧ́хла; ѿвѣща́въ же є҆ди́нъ, є҆мꙋ́же и҆́мѧ клео́па, речѐ къ немꙋ̀: ты́ ли є҆ди́нъ пришле́цъ є҆сѝ во і҆ерꙋсали́мъ, и҆ не ᲂу҆вѣ́дѣ бы́вшихъ въ не́мъ во днѝ сїѧ̀; и҆ речѐ и҆́ма: кі́ихъ; ѻ҆́на же рѣ́ста є҆мꙋ̀: ꙗ҆̀же ѡ҆ і҆и҃сѣ назарѧни́нѣ, и҆́же бы́сть мꙋ́жъ проро́къ, си́ленъ дѣ́ломъ и҆ сло́вомъ пред̾ бг҃омъ и҆ всѣ́ми людьмѝ. ка́кѡ преда́ша є҆го̀ а҆рхїере́и и҆ кнѧ́зи на́ши на ѡ҆сꙋжде́нїе сме́рти, и҆ распѧ́ша є҆го̀. мы́ же надѣ́ѧхомсѧ, ꙗ҆́кѡ се́й є҆́сть хотѧ̀ и҆зба́вити і҆и҃лѧ: но и҆ над̾ всѣ́ми си́ми тре́тїй се́й де́нь и҆́мать дне́сь, ѿне́лиже сїѧ̑ бы́ша. но и҆ жєны̀ нѣ́кїѧ ѿ на́съ ᲂу҆жаси́ша ны̀, бы́вшыѧ ра́нѡ ᲂу҆ гро́ба: и҆ не ѡ҆брѣ́тше тѣлесѐ є҆гѡ̀, прїидо́ша глаго́люще, и҆ ꙗ҆вле́нїе а҆́гг҃лъ ви́дѣвше, и҆̀же глаго́лютъ є҆го̀ жи́ва. и҆ и҆до́ша нѣ́цыи ѿ на́съ ко гро́бꙋ: и҆ ѡ҆брѣто́ша та́кѡ, ꙗ҆́коже и҆ жєны̀ рѣ́ша, самогѡ́ же не ви́дѣша. и҆ то́й речѐ къ ни́ма: ѽ несмы́слєннаѧ и҆ кѡ́снаѧ се́рдцемъ, є҆́же вѣ́ровати ѡ҆ всѣ́хъ, ꙗ҆̀же глаго́лаша проро́цы. не сїѧ̑ ли подоба́ше пострада́ти хрⷭ҇тꙋ̀, и҆ вни́ти въ сла́вꙋ свою̀; и҆ наче́нъ ѿ мѡѷсе́а, и҆ ѿ всѣ́хъ прорѡ́къ, сказа́ше и҆́ма ѿ всѣ́хъ писа́нїй ꙗ҆̀же ѡ҆ не́мъ. и҆ прибли́жишасѧ въ ве́сь, въ ню́же и҆дѧ́ста: и҆ то́й творѧ́шесѧ далеча́йше и҆тѝ. и҆ нꙋ́ждаста є҆го̀, глаго́люще: ѡ҆блѧ́зи съ на́ма, ꙗ҆́кѡ къ ве́черꙋ є҆́сть, и҆ преклони́лсѧ є҆́сть де́нь. и҆ вни́де съ ни́ма ѡ҆блещѝ. и҆ бы́сть ꙗ҆́кѡ возлежѐ съ ни́ма, и҆ прїи́мъ хлѣ́бъ благословѝ, и҆ преломи́въ даѧ́ше и҆́ма. ѻ҆́нѣма же ѿверзо́стѣсѧ ѻ҆́чи, и҆ позна́ста є҆го̀: и҆ то́й неви́димь бы́сть и҆́ма. и҆ реко́ста къ себѣ̀: не се́рдце ли на́ю горѧ̀ бѣ̀ въ на́ю, є҆гда̀ глаго́лаше на́ма на пꙋтѝ, и҆ ꙗ҆́кѡ ска́зоваше на́ма писа̑нїѧ; и҆ воста́вша въ то́й ча́съ, возврати́стасѧ во і҆ерꙋсали́мъ, и҆ ѡ҆брѣто́ста совокꙋ́плены є҆динагона́десѧте, и҆ и҆̀же бѧ́хꙋ съ ни́ми, глаго́лющихъ, ꙗ҆́кѡ вои́стиннꙋ воста̀ гдⷭ҇ь, и҆ ꙗ҆ви́сѧ сі́мѡнꙋ. и҆ та̀ повѣ́даста, ꙗ҆̀же бы́ша на пꙋтѝ: и҆ ꙗ҆́кѡ позна́сѧ и҆́ма въ преломле́нїи хлѣ́ба. ",
}

add_evangelie_luki {
  ["номер"] = 114,
  ["комментарий"] = "Лк., 114 зач., XXIV, 36–53.",
  ["текст_ру"] = "Во вре́мя о́но, воскре́с Иису́с от ме́ртвых, ста посреде́ учени́к Свои́х, и глаго́ла им: мир вам. Убоя́вшеся же и пристра́шни бы́вше, мня́ху дух ви́дяще, и рече́ им: что смуще́ни есте́? И почто́ помышле́ния вхо́дят в сердца́ ва́ша? Ви́дите ру́це Мои́ и но́зе Мои́, я́ко сам Аз есмь. Осяжи́те Мя и ви́дите, я́ко дух пло́ти и ко́сти не и́мать, я́коже Мене́ ви́дите иму́ща. И сие́ рек, показа́ им ру́це и но́зе. Еще́ же неве́рующым им от ра́дости и чудя́щымся, рече́ им: и́мате ли что сне́дно зде? Они́ же да́ша Ему́ ры́бы печены́ часть и от пчел сот. И взем пред ни́ми яде́, рече́ же им: сия́ суть словеса́, я́же глаго́лах к вам еще́ сый с ва́ми, я́ко подоба́ет сконча́тися всем напи́санным в зако́не Моисе́ове и проро́цех и псалме́х о Мне. Тогда́ отве́рзе им ум разуме́ти Писа́ния и рече́ им, я́ко та́ко пи́сано есть, и та́ко подоба́ше пострада́ти Христу́ и воскре́снути от ме́ртвых в тре́тий день, и пропове́датися во и́мя Его́ покая́нию и отпуще́нию грехо́в во всех язы́цех, наче́нше от Иерусали́ма. Вы же есте́ свиде́телие сим. И се Аз послю́ обетова́ние Отца́ Моего́ на вы, вы же седи́те во гра́де Иерусали́мсте, до́ндеже облече́теся си́лою свы́ше. Изве́д же их вон до Вифа́нии и воздви́г ру́це Свои́, и благослови́ их. И бысть егда́ благословля́ше их, отступи́ от них и возноша́шеся на не́бо. И ти́и поклони́шася Ему́, и возврати́шася во Иерусали́м с ра́достию вели́кою, и бя́ху вы́ну в це́ркви, хва́ляще и благословя́ще Бо́га. Ами́нь. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, воскре́съ і҆и҃съ ѿ ме́ртвыхъ, ста̀ посредѣ̀ ᲂу҆чени̑къ свои́хъ, и҆ глаго́ла и҆̀мъ: ми́ръ ва́мъ. ᲂу҆боѧ́вшесѧ же и҆ пристра́шни бы́вше, мнѧ́хꙋ дꙋ́хъ ви́дѧще. и҆ речѐ и҆̀мъ: что̀ смꙋще́ни є҆стѐ; и҆ почто̀ помышлє́нїѧ вхо́дѧтъ въ сердца̀ ва́ша; ви́дите рꙋ́цѣ моѝ, и҆ но́зѣ моѝ, ꙗ҆́кѡ са́мъ а҆́зъ є҆́смь. ѡ҆сѧжи́те мѧ̀ и҆ ви́дите, ꙗ҆́кѡ дꙋ́хъ пло́ти и҆ ко́сти не и҆́мать, ꙗ҆́коже менѐ ви́дите и҆мꙋ́ща. и҆ сїѐ ре́къ, показа̀ и҆̀мъ рꙋ́цѣ и҆ но́зѣ. є҆ще́ же невѣ́рꙋющымъ и҆̀мъ ѿ ра́дости, и҆ чꙋдѧ́щымсѧ, речѐ и҆̀мъ: и҆́мате ли что̀ снѣ́дно здѣ̀, ѻ҆ни́ же да́ша є҆мꙋ̀ ры́бы печены̀ ча́сть, и҆ ѿ пче́лъ со́тъ. и҆ взе́мъ, пред̾ ни́ми ꙗ҆дѐ. рече́ же и҆̀мъ: сїѧ̀ сꙋ́ть словеса̀, ꙗ҆̀же глаго́лахъ къ ва́мъ, є҆щѐ сы́й съ ва́ми, ꙗ҆́кѡ подоба́етъ сконча́тисѧ всѣ̑мъ напи̑саннымъ въ зако́нѣ мѡѷсе́овѣ, и҆ проро́цѣхъ и҆ ѱалмѣ́хъ ѡ҆ мнѣ̀. тогда̀ ѿве́рзе и҆̀мъ ᲂу҆́мъ, разꙋмѣ́ти писа̑нїѧ. и҆ речѐ и҆̀мъ: ꙗ҆́кѡ та́кѡ пи́сано є҆́сть, и҆ та́кѡ подоба́ше пострада́ти хрⷭ҇тꙋ̀ и҆ воскре́снꙋти ѿ ме́ртвыхъ въ тре́тїй де́нь, и҆ проповѣ́датисѧ во и҆́мѧ є҆гѡ̀ покаѧ́нїю и҆ ѿпꙋще́нїю грѣхѡ́въ, во всѣ́хъ ꙗ҆зы́цѣхъ, наче́нше ѿ і҆ерꙋсали́ма. вы́ же є҆стѐ свидѣ́телїе си̑мъ. и҆ сѐ а҆́зъ послю̀ ѡ҆бѣтова́нїе ѻ҆ц҃а̀ моегѡ̀ на вы̀: вы́ же сѣди́те во гра́дѣ і҆ерꙋсали́мстѣ, до́ндеже ѡ҆блече́тесѧ си́лою свы́ше. и҆зве́дъ же и҆̀хъ во́нъ до виѳа́нїи, и҆ воздви́гъ рꙋ́цѣ своѝ, и҆ бл҃гословѝ и҆̀хъ. и҆ бы́сть є҆гда̀ бл҃гословлѧ́ше и҆̀хъ, ѿстꙋпѝ ѿ ни́хъ, и҆ возноша́шесѧ на нб҃о. и҆ ті́и поклони́шасѧ є҆мꙋ̀, и҆ возврати́шасѧ во і҆ерꙋсали́мъ съ ра́достїю вели́кою. и҆ бѧ́хꙋ вы́нꙋ въ це́ркви, хва́лѧще и҆ благословѧ́ще бг҃а. а҆ми́нь. ",
}

add_evangelie_ioanna {
  ["номер"] = 1,
  ["комментарий"] = "Ин., 1 зач., I, 1–17.",
  ["текст_ру"] = "В нача́ле бе Сло́во, и Сло́во бе к Бо́гу, и Бог бе Сло́во. Сей бе искони́ к Бо́гу. Вся Тем бы́ша, и без Него́ ничто́же бысть, е́же бысть. В Том живо́т бе, и живо́т бе свет челове́ком, и свет во тме све́тится, и тма его́ не объя́т. Бысть челове́к по́слан от Бо́га, и́мя ему́ Иоа́нн. Сей прии́де во свиде́тельство, да свиде́тельствует о Све́те, да вси ве́ру и́мут ему́. Не бе той свет, но да свиде́тельствует о Све́те. Бе Свет и́стинный, И́же просвеща́ет вся́каго челове́ка гряду́щаго в мир. В ми́ре бе, и мир Тем бысть, и мир Его́ не позна́. Во своя́ прии́де, и свои́ Его́ не прия́ша. Ели́цы же прия́ша Его́, даде́ им о́бласть ча́дом Бо́жиим бы́ти, ве́рующым во и́мя Его́, и́же не от кро́ве, ни от по́хоти плотски́я, ни от по́хоти му́жеския, но от Бо́га роди́шася. И Сло́во плоть бысть и всели́ся в ны, и ви́дехом сла́ву Его́, сла́ву я́ко Единоро́днаго от Отца́, испо́лнь благода́ти и и́стины. Иоа́нн свиде́тельствует о Нем и воззва́ глаго́ля: Сей бе, Его́же рех, И́же по мне Гряды́й, пре́до мно́ю бысть, я́ко пе́рвее мене́ бе. И от исполне́ния Его́ мы вси прия́хом и благода́ть воз благода́ть. Я́ко зако́н Моисе́ом дан бысть, благода́ть же и и́стина Иису́с Христо́м бысть. ",
  ["текст_цс"] = "Въ нача́лѣ бѣ̀ сло́во, и҆ сло́во, бѣ̀ къ бг҃ꙋ, и҆ бг҃ъ бѣ̀ сло́во. се́й бѣ̀ и҆сконѝ къ бг҃ꙋ. всѧ̑ тѣ́мъ бы́ша, и҆ без̾ негѡ̀ ничто́же бы́сть, є҆́же бы́сть. въ то́мъ живо́тъ бѣ̀, и҆ живо́тъ бѣ̀ свѣ́тъ чл҃вѣ́кѡмъ. и҆ свѣ́тъ во тмѣ̀ свѣ́титсѧ, и҆ тма̀ є҆гѡ̀ не ѡ҆б̾ѧ́тъ. бы́сть человѣ́къ по́сланъ ѿ бг҃а, и҆́мѧ є҆мꙋ̀ і҆ѡа́ннъ. се́й прїи́де во свидѣ́тельство, да свидѣ́тельствꙋетъ ѡ҆ свѣ́тѣ, да всѝ вѣ́рꙋ и҆́мꙋтъ є҆мꙋ̀. не бѣ̀ то́й свѣ́тъ, но да свидѣ́тельствꙋетъ ѡ҆ свѣ́тѣ. бѣ̀ свѣ́тъ и҆́стинный, и҆́же просвѣща́етъ всѧ́каго человѣ́ка грѧдꙋ́щаго въ мі́ръ. въ мі́рѣ бѣ̀, и҆ мі́ръ тѣ́мъ бы́сть, и҆ мі́ръ є҆гѡ̀ не позна̀. во своѧ̑ прїи́де, и҆ своѝ є҆гѡ̀ не прїѧ́ша. є҆ли́цы же прїѧ́ша є҆го̀, дадѐ и҆̀мъ ѻ҆́бласть ча́дѡмъ бж҃їимъ бы́ти, вѣ́рꙋющымъ во и҆́мѧ є҆гѡ̀: и҆̀же не ѿ кро́ве, ни ѿ по́хоти плотскі́ѧ, ни ѿ по́хоти мꙋ́жескїѧ, но ѿ бг҃а роди́шасѧ. и҆ сло́во пло́ть бы́сть, и҆ всели́сѧ въ ны̀: и҆ ви́дѣхомъ сла́вꙋ є҆гѡ̀, сла́вꙋ ꙗ҆́кѡ є҆диноро́днагѡ ѿ ѻ҆ц҃а̀, и҆спо́лнь благода́ти и҆ и҆́стины. і҆ѡа́ннъ свидѣ́тельствꙋетъ ѡ҆ не́мъ, и҆ воззва̀, глаго́лѧ: се́й бѣ̀, є҆го́же рѣ́хъ, и҆́же по мнѣ̀ грѧды́й, предо мно́ю бы́сть: ꙗ҆́кѡ пе́рвѣе менѐ бѣ̀. и҆ ѿ и҆сполне́нїѧ є҆гѡ̀ мы̀ всѝ прїѧ́хомъ, и҆ благода́ть воз̾ благода́ть. ꙗ҆́кѡ зако́нъ мѡѷсе́омъ да́нъ бы́сть: благода́ть же и҆ и҆́стина і҆и҃съ хрⷭ҇то́мъ бы́сть. ",
}

add_evangelie_ioanna {
  ["номер"] = 2,
  ["комментарий"] = "Ин., 2 зач., I, 18–28.",
  ["текст_ру"] = "Бо́га никто́же ви́де нигде́же, Единоро́дный Сын, сый в ло́не О́тчи, Той испове́да. И сие́ есть свиде́тельство Иоа́нново, егда́ посла́ша жи́дове от Иерусали́ма иере́и и леви́ты, да вопро́сят его́: ты кто еси́? И испове́да и не отве́ржеся, и испове́да, я́ко несмь аз Христо́с. И вопроси́ша его́: что у́бо? Илиа́ ли еси́ ты? И глаго́ла: несмь. Проро́к ли еси́? И отвеща́: ни. Ре́ша же ему́: кто еси́? Да отве́т да́мы посла́вшым ны, что глаго́леши о тебе́ само́м? Рече́: аз глас вопию́щаго в пусты́ни, испра́вите путь Госпо́день, я́коже рече́ Иса́иа проро́к. И по́сланнии бе́ху от фарисе́й, и вопроси́ша его́ и ре́ша ему́: что у́бо креща́еши, а́ще ты не́си Христо́с, ни Илиа́, ни проро́к? Отвеща́ им Иоа́нн, глаго́ла: аз креща́ю водо́ю, посреде́ же вас стои́т, Его́же вы не ве́сте, Той есть Гряды́й по мне, И́же пре́до мно́ю бысть, Ему́же несмь аз досто́ин, да отрешу́ реме́нь сапогу́ Его́. Сия́ в Вифава́ре бы́ша об он пол Иорда́на, иде́же бе Иоа́нн крестя́. ",
  ["текст_цс"] = "Бг҃а никто́же ви́дѣ нигдѣ́же: є҆диноро́дный сн҃ъ, сы́й въ ло́нѣ ѻ҆́ч҃и, то́й и҆сповѣ́да. и҆ сїѐ є҆́сть свидѣ́тельство і҆ѡа́нново, є҆гда̀ посла́ша жи́дове ѿ і҆ерꙋсали́ма і҆ерє́и и҆ леѵі́ты, да вопро́сѧтъ є҆го̀: ты̀ кто́ є҆си; и҆ и҆сповѣ́да, и҆ не ѿве́ржесѧ, и҆ и҆сповѣ́да, ꙗ҆́кѡ нѣ́смь а҆́зъ хрⷭ҇то́съ. и҆ вопроси́ша є҆го̀: что̀ ᲂу҆́бѡ; и҆лїа́ ли є҆сѝ ты̀; и҆ глаго́ла: нѣ́смь. проро́къ ли є҆сѝ; и҆ ѿвѣща̀: нѝ. рѣ́ша же є҆мꙋ̀: кто̀ є҆сѝ; да ѿвѣ́тъ да́мы посла́вшымъ ны̀; что̀ глаго́леши ѡ҆ тебѣ̀ само́мъ; речѐ: а҆́зъ гла́съ вопїю́щагѡ въ пꙋсты́ни, и҆спра́вите пꙋ́ть гдⷭ҇нь, ꙗ҆́коже речѐ и҆са́їа проро́къ. и҆ по́сланнїи бѣ́хꙋ ѿ фарїсє́й. и҆ вопроси́ша є҆го̀, и҆ рѣ́ша є҆мꙋ̀: что̀ ᲂу҆́бѡ креща́еши, а҆́ще ты̀ нѣ́си хрⷭ҇то́съ, ни и҆лїа̀, ни проро́къ; ѿвѣща̀ и҆̀мъ і҆ѡа́ннъ, глаго́лѧ: а҆́зъ креща́ю водо́ю: посредѣ́ же ва́съ стои́тъ, є҆гѡ́же вы̀ не вѣ́сте. то́й є҆́сть грѧды́й по мнѣ̀, и҆́же предо мно́ю бы́сть: є҆мꙋ́же нѣ́смь а҆́зъ досто́инъ, да ѿрѣшꙋ̀ реме́нь сапогꙋ̀ є҆гѡ̀. сїѧ̑ въ виѳава́рѣ бы́ша ѡ҆б̾ ѻ҆́нъ по́лъ і҆ѻрда́на, и҆дѣ́же бѣ̀ і҆ѡа́ннъ крестѧ̀. ",
}

add_evangelie_ioanna {
  ["номер"] = 3,
  ["комментарий"] = "Ин., 3 зач., I, 29–34.",
  ["текст_ру"] = "Во вре́мя о́но, ви́де Иоа́нн Иису́са гряду́ща к себе́ и глаго́ла: се А́гнец Бо́жий, взе́мляй грехи́ ми́ра. Сей есть, о Не́мже аз рех: по мне гряде́т Муж, И́же пре́до мно́ю бысть, я́ко пе́рвее мене́ бе. И аз не ве́дех Его́, но да яви́тся Изра́илеви, сего́ ра́ди приидо́х аз в воде́ крестя́. И свиде́тельствова Иоа́нн, глаго́ля, я́ко ви́дех Ду́ха сходя́щ я́ко го́лубь с небесе́, и пребы́сть на Нем. И аз не ве́дех Его́, но Посла́вый мя крести́ти водо́ю, Той мне рече́: над Него́же у́зриши Ду́ха сходя́щ и пребыва́ющ на Нем, Той есть крестя́й Ду́хом Святы́м, и аз ви́дех и свиде́тельствовах, я́ко Сей есть Сын Бо́жий. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ви́дѣ і҆ѡа́ннъ і҆и҃са грѧдꙋ́ща къ себѣ̀, и҆ глаго́ла: сѐ а҆́гнецъ бж҃їй, взе́млѧй грѣхѝ мі́ра. се́й є҆́сть, ѡ҆ не́мже а҆́зъ рѣ́хъ: по мнѣ̀ грѧде́тъ мꙋ́жъ, и҆́же предо мно́ю бы́сть, ꙗ҆́кѡ пе́рвѣе менѐ бѣ̀. и҆ а҆́зъ не вѣ́дѣхъ є҆гѡ̀: но да ꙗ҆ви́тсѧ і҆и҃леви, сегѡ̀ ра́ди прїидо́хъ а҆́зъ въ водѣ̀ крестѧ̀. и҆ свидѣ́тельствова і҆ѡа́ннъ, глаго́лѧ: ꙗ҆́кѡ ви́дѣхъ дх҃ъ сходѧ́щъ ꙗ҆́кѡ го́лꙋбь съ небесѐ, и҆ пребы́сть на не́мъ. и҆ а҆́зъ не вѣ́дѣхъ є҆гѡ̀: но посла́вый мѧ̀ крести́ти водо́ю, то́й мнѣ̀ речѐ: над̾ него́же ᲂу҆́зриши дх҃ъ сходѧ́щъ, и҆ пребыва́ющъ на не́мъ, то́й є҆́сть крⷭ҇тѧ́й дх҃омъ ст҃ы́мъ. и҆ а҆́зъ ви́дѣхъ, и҆ свидѣ́тельствовахъ, ꙗ҆́кѡ се́й є҆́сть сн҃ъ бж҃їй. ",
}

add_evangelie_ioanna {
  ["номер"] = 4,
  ["комментарий"] = "Ин., 4 зач., I, 35–51.",
  ["текст_ру"] = "Во вре́мя о́но, стоя́ше Иоа́нн, и от учени́к его́ два. И узре́в Иису́са гряду́ща, глаго́ла: се А́гнец Бо́жий. И слы́шаста его́ о́ба ученика́ глаго́люща, и по Иису́се идо́ста. Обра́щься же Иису́с и ви́дев я́ по Себе́ иду́ща, глаго́ла и́ма: чесо́ и́щета? О́на же ре́ста Ему́: Равви́, е́же глаго́лется сказа́емо учи́телю, где живе́ши? И глаго́ла и́ма: прииди́та и ви́дита. Приидо́ста же и ви́деста, где живя́ше, и у Него́ пребы́ста день той. Бе же час я́ко деся́тый. Бе же Андре́й, брат Си́мона Петра́, еди́н от обою́ слы́шавшею от Иоа́нна и по Нем ше́дшею. Обре́те сей пре́жде бра́та своего́ Си́мона и глаго́ла ему́: обрето́хом Месси́ю, е́же есть сказа́емо Христо́с. И приведе́ его́ ко Иису́сови. Воззре́в же нань Иису́с рече́: ты еси́ Си́мон сын Ио́нин, ты нарече́шися Ки́фа, е́же сказа́ется Петр. Во у́трий же восхоте́ изы́ти в Галиле́ю, и обре́те Фили́ппа и глаго́ла ему́: гряди́ по Мне. Бе же Фили́пп от Вифсаи́ды, от гра́да Андре́ова и Петро́ва. Обре́те Фили́пп Нафана́ила и глаго́ла ему́: Его́же писа́ Моисе́й в зако́не и проро́цы, обрето́хом Иису́са сы́на Ио́сифова, и́же от Назаре́та. И глаго́ла ему́ Нафана́ил: от Назаре́та мо́жет ли что добро́ бы́ти? Глаго́ла ему́ Фили́пп: прииди́ и виждь. Ви́де же Иису́с Нафана́ила гряду́ща к Себе́ и глаго́ла о нем: се вои́стинну Изра́ильтянин, в не́мже льсти несть. Глаго́ла Ему́ Нафана́ил: ка́ко мя зна́еши? Отвеща́ Иису́с и рече́ ему́: пре́жде да́же не возгласи́ тебе́ Фили́пп, су́ща под смоко́вницею ви́дех тя. Отвеща́ Нафана́ил и глаго́ла Ему́: Равви́, Ты еси́ Сын Бо́жий, Ты еси́ Царь Изра́илев. Отвеща́ Иису́с и рече́ ему́: зане́ рех ти, я́ко ви́дех тя под смоко́вницею, ве́руеши, бо́льша сих у́зриши. И глаго́ла ему́: ами́нь, ами́нь глаго́лю вам, отсе́ле у́зрите не́бо отве́рсто и А́нгелы Бо́жия восходя́щя и нисходя́щя над Сы́на Челове́ческаго. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, стоѧ́ше і҆ѡа́ннъ, и҆ ѿ ᲂу҆ч҃нкъ є҆гѡ̀ два̀. и҆ ᲂу҆зрѣ́въ і҆и҃са грѧдꙋ́ща, глаго́ла: сѐ а҆́гнецъ бж҃їй. и҆ слы́шаста є҆го̀ ѻ҆́ба ᲂу҆ченика̀ глаго́люща, и҆ по і҆и҃сѣ и҆до́ста. ѡ҆бра́щсѧ же і҆и҃съ, и҆ ви́дѣвъ ѧ҆̀ по себѣ̀ и҆дꙋ́ща, глаго́ла и҆́ма: чесѡ̀ и҆́щета; ѻ҆́на же рѣ́ста є҆мꙋ̀: равві̀, є҆́же глаго́летсѧ сказа́емо, ᲂу҆чи́телю, гдѣ̀ живе́ши; и҆ глаго́ла и҆́ма: прїиди́та, и҆ ви́дита. прїидо́ста же и҆ ви́дѣста гдѣ̀ живѧ́ше, и҆ ᲂу҆ негѡ̀ пребы́ста де́нь то́й: бѣ́ же ча́съ ꙗ҆́кѡ десѧ́тый. бѣ́ же а҆ндре́й бра́тъ сі́мѡна петра̀, є҆ди́нъ ѿ ѻ҆бою̀ слы́шавшею ѿ і҆ѡа́нна, и҆ по не́мъ ше́дшею. ѡ҆брѣ́те се́й пре́жде бра́та своего̀ сі́мѡна, и҆ глаго́ла є҆мꙋ̀: ѡ҆брѣто́хомъ мессі́ю, є҆́же є҆́сть сказа́емо, хрⷭ҇то́съ. и҆ приведѐ є҆го̀ ко і҆и҃сови. воззрѣ́въ же на́нь і҆и҃съ речѐ: ты̀ є҆сѝ сі́мѡнъ, сн҃ъ і҆ѡ́нинъ: ты̀ нарече́шисѧ ки́фа, є҆́же сказа́етсѧ пе́тръ. во ᲂу҆́трїй же восхотѣ̀ и҆зы́ти въ галїле́ю, и҆ ѡ҆брѣ́те фїлі́ппа, и҆ глаго́ла є҆мꙋ̀: грѧдѝ по мнѣ̀. бѣ́ же фїлі́ппъ ѿ виѳсаі́ды, ѿ гра́да а҆ндре́ова и҆ петро́ва. ѡ҆брѣ́те фїлі́ппъ наѳана́ила, и҆ глаго́ла є҆мꙋ̀: є҆го́же писа̀ мѡѷсе́й въ зако́нѣ и҆ проро́цы, ѡ҆брѣто́хомъ і҆и҃са сн҃а і҆ѡ́сифова, и҆́же ѿ назаре́та. и҆ глаго́ла є҆мꙋ̀ наѳана́илъ: ѿ назаре́та мо́жетъ ли что̀ добро̀ бы́ти; глаго́ла є҆мꙋ̀ фїлі́ппъ: прїидѝ и҆ ви́ждь. ви́дѣ же і҆и҃съ наѳана́ила грѧдꙋ́ща къ себѣ̀, и҆ глаго́ла ѡ҆ не́мъ: сѐ вои́стиннꙋ і҆и҃льтѧнинъ, въ не́мже льстѝ нѣ́сть. глаго́ла є҆мꙋ̀ наѳана́илъ: ка́кѡ мѧ̀ зна́еши; ѿвѣща̀ і҆и҃съ, и҆ речѐ є҆мꙋ̀: пре́жде да́же не возгласѝ тебѐ фїлі́ппъ, сꙋ́ща под̾ смоко́вницею ви́дѣхъ тѧ̀. ѿвѣща̀ наѳана́илъ и҆ глаго́ла є҆мꙋ̀: равві̀, ты̀ є҆сѝ сн҃ъ бж҃їй, ты̀ є҆сѝ цр҃ь і҆и҃левъ. ѿвѣща̀ і҆и҃съ, и҆ речѐ є҆мꙋ̀: занѐ рѣ́хъ тѝ, ꙗ҆́кѡ ви́дѣхъ тѧ̀ под̾ смоко́вницею, вѣ́рꙋеши: бѡ́льша си́хъ ᲂу҆́зриши. и҆ глаго́ла є҆мꙋ̀: а҆ми́нь а҆ми́нь глаго́лю ва́мъ, ѿсе́лѣ ᲂу҆́зрите нб҃о ѿве́рсто, и҆ а҆́гг҃лы бж҃їѧ восходѧ́щѧ, и҆ нисходѧ́щѧ над̾ сн҃а человѣ́ческаго. ",
}

