add_evangelie_ioanna {
  ["номер"] = 6,
  ["комментарий"] = "Ин., 6 зач., II, 1–11.",
  ["текст_ру"] = "Во вре́мя о́но, брак бысть в Ка́не Галиле́йстей, и бе Ма́ти Иису́сова ту. Зван же бысть Иису́с и ученицы́ Его́ на брак. И недоста́вшу вину́, глаго́ла Ма́ти Иису́сова к Нему́: вина́ не и́мут. Глаго́ла Ей Иису́с: что есть Мне и Тебе́, Же́но? Не у прии́де час Мой. Глаго́ла Ма́ти Его́ слуга́м: е́же а́ще глаго́лет вам, сотвори́те. Бе́ху же ту водоно́сы ка́менни шесть, лежа́ще по очище́нию иуде́йску, вместя́щия по двема́ или́ трие́м ме́рам. Глаго́ла им Иису́с: напо́лните водоно́сы воды́. И напо́лниша их до верха́. И глаго́ла им: почерпи́те ны́не и принеси́те архитрикли́нови. И принесо́ша. Я́коже вкуси́ архитрикли́н вина́ бы́вшаго от воды́, и не ве́дяше, отку́ду есть, слуги́ же ве́дяху поче́рпшии во́ду, пригласи́ жениха́ архитрикли́н. И глаго́ла ему́: всяк челове́к пре́жде до́брое вино́ полага́ет, и егда́ упию́тся, тогда́ ху́ждшее, ты же соблю́л еси́ до́брое вино́ досе́ле. Се сотвори́ нача́ток зна́мением Иису́с в Ка́не Галиле́йстей и яви́ сла́ву Свою́, и ве́роваша в Него́ ученицы́ Его́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бра́къ бы́сть въ ка́нѣ галїле́йстѣй: и҆ бѣ̀ мт҃и і҆и҃сова тꙋ̀. зва́нъ же бы́сть і҆и҃съ и҆ ᲂу҆ченицы̀ є҆гѡ̀ на бра́къ. и҆ недоста́вшꙋ вїнꙋ̀, глаго́ла мт҃и і҆и҃сова къ немꙋ̀: вїна̀ не и҆́мꙋтъ. глаго́ла є҆́й і҆и҃съ: что́ є҆сть мнѣ̀ и҆ тебѣ̀ же́но; не ᲂу҆̀ прїи́де ча́съ мо́й. глаго́ла мт҃и є҆гѡ̀ слꙋга́мъ: є҆́же а҆́ще глаго́летъ ва́мъ, сотвори́те. бѣ́хꙋ же тꙋ̀ водоно́сы ка́менни ше́сть, лежа́ще по ѡ҆чище́нїю і҆ꙋде́йскꙋ, вмѣстѧ́щыѧ по двѣма̀ и҆лѝ трїе́мъ мѣ́рамъ. глаго́ла и҆̀мъ і҆и҃съ: напо́лните водоно́сы воды̀. и҆ напо́лниша и҆̀хъ до верха̀. и҆ глаго́ла и҆̀мъ: почерпи́те ны́нѣ, и҆ принеси́те а҆рхїтрїклі́нови. и҆ принесо́ша. ꙗ҆́коже вкꙋсѝ а҆рхїтрїклі́нъ вїна̀ бы́вшагѡ ѿ воды̀, и҆ не вѣ́дѧше ѿкꙋ́дꙋ є҆́сть: слꙋги́ же вѣ́дѧхꙋ поче́рпшїи во́дꙋ, пригласѝ жениха̀ а҆рхїтрїклі́нъ. и҆ глаго́ла є҆мꙋ̀: всѧ́къ человѣ́къ пре́жде до́брое вїно̀ полага́етъ, и҆ є҆гда̀ ᲂу҆пїю́тсѧ, тогда̀ хꙋ́ждшее: ты́ же соблю́лъ є҆сѝ до́брое вїно̀ досе́лѣ. сѐ сотворѝ нача́токъ зна́менїємъ і҆и҃съ въ ка́нѣ галїле́йстѣй, и҆ ꙗ҆вѝ сла́вꙋ свою̀: и҆ вѣ́роваша въ него̀ ᲂу҆чн҃цы̀ є҆гѡ̀. ",
}

add_evangelie_ioanna {
  ["номер"] = 7,
  ["комментарий"] = "Ин., 7 зач., II, 12–22.",
  ["текст_ру"] = "Во вре́мя о́но, сни́де Иису́с в Капернау́м Сам и Ма́ти Его́, и бра́тия Его́ и ученицы́ Его́, и ту не мно́ги дни пребы́ша. И близ бе Па́сха иуде́йска, и взы́де во Иерусали́м Иису́с и обре́те в це́ркви продаю́щыя о́вцы и волы́ и го́луби, и пе́няжники седя́щыя. И сотвори́ бичь от ве́рвий, вся изгна́ из це́ркве, о́вцы и волы́, и торжнико́м разсы́па пе́нязи и дски опрове́рже. И продаю́щым го́луби рече́: возьми́те сия́ отсю́ду и не твори́те до́му Отца́ Моего́ до́му ку́пленаго. Помяну́ша же ученицы́ Его́, я́ко пи́сано есть: жа́лость до́му Твоего́ снесть Мя. Отвеща́ша же иуде́е и ре́ша Ему́: ко́е зна́мение явля́еши нам, я́ко сия́ твори́ши? Отвеща́ Иису́с и рече́ им: разорите́ це́рковь сию́, и тре́ми де́ньми воздви́гну ю́. Ре́ша же иуде́е: четы́редесять и шестию́ лет создана́ бысть це́рковь сия́, и Ты ли тре́ми де́ньми воздви́гнеши ю́? Он же глаго́лаше о це́ркви те́ла Своего́. Егда́ у́бо воста́ от ме́ртвых, помяну́ша ученицы́ Его́, я́ко се глаго́лаше, и ве́роваша Писа́нию и словеси́, е́же рече́ Иису́с. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, сни́де і҆и҃съ въ капернаꙋ́мъ са́мъ, и҆ мт҃и є҆гѡ̀, и҆ бра́тїѧ є҆гѡ̀, и҆ ᲂу҆чн҃цы̀ є҆гѡ̀: и҆ тꙋ̀ не мно́ги днѝ пребы́ша. и҆ бли́зъ бѣ̀ па́сха і҆ꙋде́йска, и҆ взы́де во і҆ерꙋсали́мъ і҆и҃съ: и҆ ѡ҆брѣ́те въ цр҃кви продаю́щыѧ ѻ҆́вцы и҆ волы̀ и҆ го́лꙋби, и҆ пѣ́нѧжники сѣдѧ́щыѧ. и҆ сотворѝ би́чь ѿ ве́рвїй, всѧ̑ и҆згна̀ и҆з̾ цр҃кве, ѻ҆́вцы и҆ волы̀, и҆ торжникѡ́мъ разсы́па пѣ́нѧзи, и҆ дски̑ ѡ҆прове́рже. и҆ продаю́щымъ го́лꙋби речѐ: воз̾ми́те сїѧ̑ ѿсю́дꙋ, и҆ не твори́те до́мꙋ ѻ҆ц҃а̀ моегѡ̀, до́мꙋ кꙋ́пленагѡ. помѧнꙋ́ша же ᲂу҆ченицы̀ є҆гѡ̀, ꙗ҆́кѡ пи́сано є҆́сть: жа́лость до́мꙋ твоегѡ̀ снѣ́сть мѧ̀. ѿвѣща́ша же і҆ꙋде́є, и҆ рѣ́ша є҆мꙋ̀: ко́е зна́менїе ꙗ҆влѧ́еши на́мъ, ꙗ҆́кѡ сїѧ̑ твори́ши; ѿвѣща̀ і҆и҃съ, и҆ речѐ и҆̀мъ: разоритѐ цр҃ковь сїю̀, и҆ тре́ми де́ньми воздви́гнꙋ ю҆̀. рѣ́ша же і҆ꙋде́є: четы́редесѧть и҆ шестїю̀ лѣ́тъ создана̀ бы́сть це́рковь сїѧ̀, и҆ ты́ ли тре́ми де́ньми воздви́гнеши ю҆̀; ѻ҆́нъ же глаго́лаше ѡ҆ це́ркви тѣ́ла своегѡ̀. є҆гда̀ ᲂу҆́бѡ воста̀ ѿ ме́ртвыхъ, помѧнꙋ́ша ᲂу҆ченицы̀ є҆гѡ̀, ꙗ҆́кѡ сѐ глаго́лаше: и҆ вѣ́роваша писа́нїю, и҆ словесѝ, є҆́же речѐ і҆и҃съ. ",
}

add_evangelie_ioanna {
  ["номер"] = 8,
  ["комментарий"] = "Ин., 8 зач., III, 1–15.",
  ["текст_ру"] = "Во вре́мя о́но, челове́к не́кий бе от фарисе́й, Никоди́м и́мя ему́, князь Жидо́вский. Сей прии́де ко Иису́су но́щию и рече́ Ему́: Равви́, вем, я́ко от Бо́га прише́л еси́ учи́тель, никто́же бо мо́жет зна́мений сих твори́ти, и́хже Ты твори́ши, а́ще не бу́дет Бог с ним. Отвеща́ Иису́с и рече́ ему́: ами́нь, ами́нь глаго́лю тебе́: а́ще кто не роди́тся свы́ше, не мо́жет ви́дети Ца́рствия Бо́жия. Глаго́ла к Нему́ Никоди́м: ка́ко мо́жет челове́к роди́тися стар сый? Еда́ мо́жет второ́е вни́ти во утро́бу ма́тере своея́ и роди́тися? Отвеща́ Иису́с: ами́нь, ами́нь глаго́лю тебе́, а́ще кто не роди́тся водо́ю и Ду́хом, не мо́жет вни́ти во Ца́рствие Бо́жие. Рожде́нное от пло́ти плоть есть, и рожде́нное от Ду́ха дух есть. Не диви́ся, я́ко рех ти, подоба́ет вам роди́тися свы́ше. Дух, иде́же хо́щет, ды́шет, и глас его́ слы́шиши, но не ве́си, отку́ду прихо́дит и ка́мо и́дет, та́ко есть всяк челове́к рожде́нный от Ду́ха. Отвеща́ Никоди́м и рече́ Ему́: ка́ко мо́гут сия́ бы́ти? Отвеща́ Иису́с и рече́ ему́: ты еси́ учи́тель Изра́илев, и сих ли не ве́си? Ами́нь, ами́нь глаго́лю тебе́, я́ко, е́же ве́мы, глаго́лем, и е́же ви́дехом, свиде́тельствуем, и свиде́тельства На́шего не прие́млете. А́ще земна́я реко́х вам, и не ве́руете, ка́ко, а́ще реку́ вам небе́сная, ве́руете? И никто́же взы́де на не́бо, то́кмо сше́дый с небесе́ Сын Челове́ческий, сый на небеси́. И я́коже Моисе́й вознесе́ змию́ в пусты́ни, та́ко подоба́ет вознести́ся Сы́ну Челове́ческому, да всяк ве́руяй в Онь не поги́бнет, но и́мать живо́т ве́чный. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, человѣ́къ нѣ́кїй бѣ̀ ѿ фарїсє́й, нїкоди́мъ и҆́мѧ є҆мꙋ̀, кнѧ́зь жидо́вскїй. се́й прїи́де ко і҆и҃сꙋ но́щїю, и҆ речѐ є҆мꙋ̀: равві̀, вѣ́мъ, ꙗ҆́кѡ ѿ бг҃а прише́лъ є҆сѝ ᲂу҆чи́тель. никто́же бо мо́жетъ зна́менїй си́хъ твори́ти, и҆́хже ты̀ твори́ши, а҆́ще не бꙋ́детъ бг҃ъ съ ни́мъ. ѿвѣща̀ і҆и҃съ, и҆ речѐ є҆мꙋ̀: а҆ми́нь а҆ми́нь глаго́лю тебѣ̀, а҆́ще кто̀ не роди́тсѧ свы́ше, не мо́жетъ ви́дѣти црⷭ҇твїѧ бж҃їѧ. глаго́ла къ немꙋ̀ нїкоди́мъ: ка́кѡ мо́жетъ человѣ́къ роди́тисѧ ста́ръ сы́й; є҆да̀ мо́жетъ второ́е вни́ти во ᲂу҆тро́бꙋ ма́тере своеѧ̀, и҆ роди́тисѧ; ѿвѣща̀ і҆и҃съ: а҆ми́нь а҆ми́нь глаго́лю тебѣ̀, а҆́ще кто̀ не роди́тсѧ водо́ю и҆ дх҃омъ, не мо́жетъ вни́ти во ца́рствїе бж҃їе. рожде́нное ѿ пло́ти, пло́ть є҆́сть, и҆ рожде́нное ѿ дх҃а, дх҃ъ є҆́сть. не диви́сѧ, ꙗ҆́кѡ рѣ́хъ тѝ: подоба́етъ ва́мъ роди́тисѧ свы́ше. дх҃ъ и҆дѣ́же хо́щетъ, ды́шетъ, и҆ гла́съ є҆гѡ̀ слы́шиши: но не вѣ́си ѿкꙋ́дꙋ прихо́дитъ, и҆ ка́мѡ и҆́детъ: та́кѡ є҆́сть всѧ́къ человѣ́къ, рожде́нный ѿ дх҃а. ѿвѣща̀ нїкоди́мъ, и҆ речѐ є҆мꙋ̀: ка́кѡ мо́гꙋтъ сїѧ̑ бы́ти; ѿвѣща̀ і҆и҃съ, и҆ речѐ є҆мꙋ̀: ты̀ є҆сѝ ᲂу҆чи́тель і҆и҃левъ, и҆ си́хъ ли не вѣ́си; а҆ми́нь а҆ми́нь глаго́лю тебѣ̀, ꙗ҆́кѡ є҆́же вѣ́мы, глаго́лемъ: и҆ є҆́же ви́дѣхомъ, свидѣ́тельствꙋемъ: и҆ свидѣ́тельства на́шегѡ не прїе́млете. а҆́ще земна̑ѧ реко́хъ ва́мъ, и҆ не вѣ́рꙋете: ка́кѡ а҆́ще рекꙋ̀ ва́мъ нбⷭ҇наѧ, вѣ́рꙋете; и҆ никто́же взы́де на нб҃о, то́кмѡ сше́дый съ нб҃сѐ, сн҃ъ человѣ́ческїй, сы́й на нб҃сѝ. и҆ ꙗ҆́коже мѡѷсе́й вознесѐ ѕмїю̀ въ пꙋсты́ни: та́кѡ подоба́етъ вознести́сѧ сн҃ꙋ человѣ́ческомꙋ: да всѧ́къ вѣ́рꙋѧй въ ѻ҆́нь, не поги́бнетъ, но и҆́мать живо́тъ вѣ́чный. ",
}

add_evangelie_ioanna {
  ["номер"] = 9,
  ["комментарий"] = "Ин., 9 зач., III, 13–17.",
  ["текст_ру"] = "Рече́ Госпо́дь: никто́же взы́де на не́бо, то́кмо сше́дый с небесе́ Сын Челове́ческий, сый на небеси́. И я́коже Моисе́й вознесе́ змию́ в пусты́ни, та́ко подоба́ет вознести́ся Сы́ну Челове́ческому, да всяк ве́руяй в Онь не поги́бнет, но и́мать живо́т ве́чный. Та́ко бо возлюби́ Бог мир, я́ко и Сы́на Своего́ Единоро́днаго дал есть, да всяк ве́руяй в Онь не поги́бнет, но и́мать живо́т ве́чный. Не посла́ бо Бог Сы́на Своего́ в мир, да су́дит ми́рови, но да спасе́тся Им мир. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: никто́же взы́де на нб҃о, то́кмѡ сше́дый съ нб҃сѐ, сн҃ъ человѣ́ческїй, сы́й на нб҃сѝ. и҆ ꙗ҆́коже мѡѷсе́й вознесѐ ѕмїю̀ въ пꙋсты́ни: та́кѡ подоба́етъ вознести́сѧ сн҃ꙋ человѣ́ческомꙋ: да всѧ́къ вѣ́рꙋѧй въ ѻ҆́нь, не поги́бнетъ, но и҆́мать живо́тъ вѣ́чный. та́кѡ бо возлюбѝ бг҃ъ мі́ръ, ꙗ҆́кѡ и҆ сн҃а своего̀ є҆диноро́днаго да́лъ є҆́сть, да всѧ́къ вѣ́рꙋѧй въ ѻ҆́нь, не поги́бнетъ: но и҆́мать живо́тъ вѣ́чный. не посла́ бо бг҃ъ сн҃а своего̀ въ мі́ръ, да сꙋ́дитъ мі́рови: но да спасе́тсѧ и҆́мъ мі́ръ. ",
}

add_evangelie_ioanna {
  ["номер"] = 10,
  ["комментарий"] = "Ин., 10 зач., III, 16–21.",
  ["текст_ру"] = "Рече́ Госпо́дь: та́ко возлюби́ Бог мир, я́ко и Сы́на Своего́ Единоро́днаго дал есть, да всяк ве́руяй в Онь не поги́бнет, но и́мать живо́т ве́чный. Не посла́ бо Бог Сы́на Своего́ в мир, да су́дит ми́рови, но да спасе́тся Им мир. Ве́руяй в Онь не бу́дет осужде́н, а не ве́руяй уже́ осужде́н есть, я́ко не ве́рова во и́мя Единоро́днаго Сы́на Бо́жия. Сей же есть суд, я́ко свет прии́де в мир, и возлюби́ша челове́цы па́че тму, не́же свет, бе́ша бо их дела́ зла. Всяк бо де́лаяй зла́я ненави́дит све́та и не прихо́дит к све́ту, да не облича́тся дела́ его́, я́ко лука́ва суть. Творя́й же и́стину гряде́т к све́ту, да явя́тся дела́ его́, я́ко о Бо́зе суть соде́лана. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: та́кѡ возлюбѝ бг҃ъ мі́ръ, ꙗ҆́кѡ и҆ сн҃а своего̀ є҆диноро́днаго да́лъ є҆́сть, да всѧ́къ вѣ́рꙋѧй въ ѻ҆́нь, не поги́бнетъ: но и҆́мать живо́тъ вѣ́чный. не посла́ бо бг҃ъ сн҃а своего̀ въ мі́ръ, да сꙋ́дитъ мі́рови: но да спасе́тсѧ и҆́мъ мі́ръ. вѣ́рꙋѧй въ ѻ҆́нь, не бꙋ́детъ ѡ҆сꙋжде́нъ: а҆ не вѣ́рꙋѧй, ᲂу҆жѐ ѡ҆сꙋжде́нъ є҆́сть, ꙗ҆́кѡ не вѣ́рова во и҆́мѧ є҆диноро́днагѡ сн҃а бж҃їѧ. се́й же є҆́сть сꙋ́дъ, ꙗ҆́кѡ свѣ́тъ прїи́де въ мі́ръ, и҆ возлюби́ша человѣ́цы па́че тмꙋ̀, не́же свѣ́тъ: бѣ́ша бо и҆́хъ дѣла̀ ѕла̀. всѧ́къ бо дѣ́лаѧй ѕла̑ѧ, ненави́дитъ свѣ́та, и҆ не прихо́дитъ къ свѣ́тꙋ, да не ѡ҆блича́тсѧ дѣла̀ є҆гѡ̀, ꙗ҆́кѡ лꙋка̑ва сꙋ́ть. творѧ́й же и҆́стинꙋ, грѧде́тъ къ свѣ́тꙋ, да ꙗ҆вѧ́тсѧ дѣла̀ є҆гѡ̀, ꙗ҆́кѡ ѡ҆ бз҃ѣ сꙋ́ть содѣ́лана. ",
}

add_evangelie_ioanna {
  ["номер"] = 11,
  ["комментарий"] = "Ин., 11 зач., III, 22–33.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с и ученицы́ Его́ в Жидо́вскую зе́млю, и ту живя́ше с ни́ми и креща́ше. Бе же Иоа́нн крестя́ во Ено́не близ Сали́ма, я́ко во́ды мно́ги бя́ху ту, и прихожда́ху и креща́хуся. Не у бо бе всажде́н в темни́цу Иоа́нн. Бысть же стяза́ние от учени́к Иоа́нновых со иуде́и о очище́нии. И приидо́ша ко Иоа́нну и реко́ша ему́: равви́, И́же бе с тобо́ю об он пол Иорда́на, Ему́же ты свиде́тельствовал еси́, се Сей креща́ет, и вси гряду́т к Нему́. Отвеща́ Иоа́нн и рече́: не мо́жет челове́к приима́ти ничесо́же, а́ще не бу́дет дано́ ему́ с небесе́. Вы са́ми мне свиде́тельствуете, я́ко рех: несмь аз Христо́с, но я́ко по́слан есмь пред Ним. Име́яй неве́сту жени́х есть, а друг женихо́в, стоя́ и послу́шая его́, ра́достию ра́дуется за глас женихо́в, сия́ у́бо ра́дость моя́ испо́лнися. О́ному подоба́ет расти́, мне же ма́литися. Гряды́й свы́ше над все́ми есть, сый от земли́ от земли́ есть и от земли́ глаго́лет, Гряды́й с небесе́ над все́ми есть. И е́же ви́де и слы́ша, сие́ свиде́тельствует, и свиде́тельства Его́ никто́же прие́млет. Прие́мый Его́ свиде́тельство ве́рова, я́ко Бог и́стинен есть. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ и҆ ᲂу҆чн҃цы̀ є҆гѡ̀ въ жидо́вскꙋю зе́млю: и҆ тꙋ̀ живѧ́ше съ ни́ми, и҆ креща́ше. бѣ́ же і҆ѡа́ннъ крестѧ̀ во є҆нѡ́нѣ бли́зъ салі́ма, ꙗ҆́кѡ во́ды мно́ги бѧ́хꙋ тꙋ̀: и҆ прихожда́хꙋ и҆ креща́хꙋсѧ. не ᲂу҆́ бо бѣ̀ всажде́нъ въ темни́цꙋ і҆ѡа́ннъ. бы́сть же стѧза́нїе ѿ ᲂу҆чєни́къ і҆ѡа́нновыхъ со і҆ꙋдє́и ѡ҆ ѡ҆чище́нїи. и҆ прїидо́ша ко і҆ѡа́ннꙋ, и҆ реко́ша є҆мꙋ̀: равві̀, и҆́же бѣ̀ съ тобо́ю ѡ҆б̾ ѻ҆́нъ по́лъ і҆ѻрда́на, є҆мꙋ́же ты̀ свидѣ́тельствовалъ є҆сѝ, сѐ се́й креща́етъ, и҆ всѝ грѧдꙋ́тъ къ немꙋ̀. ѿвѣща̀ і҆ѡа́ннъ, и҆ речѐ: не мо́жетъ человѣ́къ прїима́ти ничесѡ́же, а҆́ще не бꙋ́детъ дано̀ є҆мꙋ̀ съ небесѐ. вы̀ са́ми мнѣ̀ свидѣ́тельствꙋете, ꙗ҆́кѡ рѣ́хъ: нѣ́смь а҆́зъ хрⷭ҇то́съ, но ꙗ҆́кѡ по́сланъ є҆́смь пред̾ ни́мъ. и҆мѣ́ѧй невѣ́стꙋ, жени́хъ є҆́сть: а҆ дрꙋ́гъ женихо́въ стоѧ̀ и҆ послꙋ́шаѧ є҆гѡ̀, ра́достїю ра́дꙋетсѧ за гла́съ женихо́въ: сїѧ̀ ᲂу҆́бѡ ра́дость моѧ̀ и҆спо́лнисѧ. ѻ҆́номꙋ подоба́етъ растѝ, мнѣ́ же ма́литисѧ. грѧды́й свы́ше, над̾ всѣ́ми є҆́сть: сы́й ѿ землѝ, ѿ землѝ є҆́сть, и҆ ѿ землѝ глаго́летъ: грѧды́й съ небесѐ, над̾ всѣ́ми є҆́сть. и҆ є҆́же ви́дѣ и҆ слы́ша, сїѐ свидѣ́тельствꙋетъ: и҆ свидѣ́тельства є҆гѡ̀ никто́же прїе́млетъ. прїе́мый є҆гѡ̀ свидѣ́тельство, вѣ́рова, ꙗ҆́кѡ бг҃ъ и҆́стиненъ є҆́сть. ",
}

add_evangelie_ioanna {
  ["номер"] = 12,
  ["комментарий"] = "Ин., 12 зач., IV, 5–42.",
  ["текст_ру"] = "Во вре́мя о́но, прии́де Иису́с во град Самари́йский, глаго́лемый Сиха́рь, близ ве́си, ю́же даде́ Иа́ков Ио́сифу сы́ну своему́. Бе же ту исто́чник Иа́ковль. Иису́с же тру́ждся от пути́, седя́ше та́ко на исто́чнице, бе же я́ко час шесты́й. Прии́де жена́ от Самари́и почерпа́ти во́ду. Глаго́ла ей Иису́с: даждь Ми пи́ти. Ученицы́ бо Его́ отшли́ бя́ху во град, да бра́шно ку́пят. Глаго́ла Ему́ жена́ Самаряны́ня: ка́ко ты Жидови́н сый от мене́ пи́ти про́сиши, жены́ Самаряны́ни су́щей? Не прикаса́ют бо ся жи́дове самаря́нех. Отвеща́ Иису́с и рече́ ей: а́ще бы ве́дала еси́ дар Бо́жий, и Кто есть глаго́ляй ти, даждь Ми пи́ти, ты бы проси́ла у Него́, и дал бы ти во́ду жи́ву. Глаго́ла Ему́ жена́: го́споди, ни почерпа́ла и́маши, и студене́ц есть глубо́к, отку́ду у́бо и́маши во́ду жи́ву? Еда́ ты бо́лий еси́ отца́ на́шего Иа́кова, и́же даде́ нам студене́ц сей, и той из него́ пит и сы́нове его́ и ско́ти его́? Отвеща́ Иису́с и рече́ ей: всяк пия́й от воды́ сея́, вжа́ждется па́ки, а и́же пие́т от воды́, ю́же Аз дам ему́, не вжа́ждется во ве́ки, но вода́, ю́же Аз дам ему́, бу́дет в нем исто́чник воды́ теку́щ в живо́т ве́чный. Глаго́ла к Нему́ жена́: Го́споди, даждь ми сию́ во́ду, да ни жа́жду, ни прихожду́ се́мо почерпа́ти. Глаго́ла ей Иису́с: иди́, пригласи́ му́жа твоего́ и прииди́ се́мо. Отвеща́ жена́ и рече́ Ему́: не и́мам му́жа. Глаго́ла ей Иису́с: до́бре рече́, я́ко му́жа не и́мам. Пять бо муже́й име́ла еси́, и ны́не, его́же и́маши, несть ти муж, се вои́стинну рекла́ еси́. Глаго́ла Ему́ жена́: Го́споди, ви́жу, я́ко проро́к еси́ Ты, отцы́ на́ши в горе́ сей поклони́шася, и вы глаго́лете, я́ко во Иерусали́мех есть ме́сто, иде́же кла́нятися подоба́ет. Глаго́ла ей Иису́с: же́но, ве́ру Ми ими́, я́ко гряде́т час, егда́ ни в горе́ сей, ни во Иерусали́мех покло́нитеся Отцу́. Вы кла́няетеся, его́же не ве́сте, мы кла́няемся, его́же ве́мы, я́ко спасе́ние от иуде́й есть, но гряде́т час, и ны́не есть, егда́ и́стиннии покло́нницы покло́нятся Отцу́ ду́хом и и́стиною, и́бо Оте́ц таковы́х и́щет покланя́ющихся Ему́. Дух есть Бог, и и́же кла́няется Ему́, ду́хом и и́стиною досто́ит кла́нятися. Глаго́ла Ему́ жена́: вем, я́ко Месси́а прии́дет, глаго́лемый Христо́с, егда́ Той прии́дет, возвести́т нам вся. Глаго́ла ей Иису́с: Аз есмь, глаго́ляй с тобо́ю. И тогда́ приидо́ша ученицы́ Его́ и чужда́хуся, я́ко с жено́ю глаго́лаше. Никто́же бо рече́: чесо́ и́щеши? Или́: что глаго́леши с не́ю? Оста́ви же водоно́с свой жена́, и и́де во град, и глаго́ла челове́ком: прииди́те и ви́дите Челове́ка, И́же рече́ ми вся, ели́ка сотвори́х, еда́ Той есть Христо́с? Изыдо́ша же из гра́да и грядя́ху к Нему́. Между́ же сим моля́ху Его́ ученицы́ Его́, глаго́люще: Равви́, яждь. Он же рече́ им: Аз бра́шно и́мам я́сти, его́же вы не ве́сте. Глаго́лаху же ученицы́ к себе́: еда́ кто принесе́ Ему́ я́сти? Глаго́ла им Иису́с: Мое́ бра́шно есть, да сотворю́ во́лю Посла́вшаго Мя и совершу́ де́ло Его́. Не вы ли глаго́лете, я́ко еще́ четы́ри ме́сяцы суть, и жа́тва прии́дет? Се, глаго́лю вам: возведи́те о́чи ва́ши и ви́дите ни́вы, я́ко пла́вы суть к жа́тве уже́. И жняй мзду прие́млет и собира́ет плод в живо́т ве́чный, да и се́яй вку́пе ра́дуется и жняй. О сем бо сло́во есть и́стинное, я́ко ин есть се́яй, и ин есть жняй. Аз посла́х вы жа́ти, иде́же вы не труди́стеся, ини́и труди́шася, и вы в труд их внидо́сте. От гра́да же того́ мно́зи ве́роваша в Онь от самаря́н, за сло́во жены́ свиде́тельствующия, я́ко рече́ ми вся, ели́ка сотвори́х. Егда́ у́бо приидо́ша к Нему́ самаря́не, моля́ху Его́, дабы́ пребы́л у них, и пребы́сть ту два дни. И мно́го па́че ве́роваша за сло́во Его́. Жене́ же глаго́лаху, я́ко не ктому́ за твою́ бесе́ду ве́руем, са́ми бо слы́шахом и ве́мы, я́ко Сей есть вои́стинну Спас ми́ру, Христо́с. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, прїи́де і҆и҃съ во гра́дъ самарі́йскїй глаго́лемый сїха́рь, бли́зъ ве́си, ю҆́же дадѐ і҆а́кѡвъ і҆ѡ́сифꙋ сы́нꙋ своемꙋ̀. бѣ́ же тꙋ̀ и҆сто́чникъ і҆а́кѡвль. і҆и҃съ же трꙋ́ждсѧ ѿ пꙋтѝ, сѣдѧ́ше та́кѡ на и҆сто́чницѣ: бѣ́ же ꙗ҆́кѡ ча́съ шесты́й. прїи́де жена̀ ѿ самарі́и почерпа́ти во́дꙋ. глаго́ла є҆́й і҆и҃съ: да́ждь мѝ пи́ти. ᲂу҆ченицы́ бо є҆гѡ̀ ѿшлѝ бѧ́хꙋ во гра́дъ, да бра́шно кꙋ́пѧтъ. глаго́ла є҆мꙋ̀ жена̀ самарѧны́нѧ: ка́кѡ ты̀ жидови́нъ сы́й ѿ менѐ пи́ти про́сиши, жены̀ самарѧны́ни сꙋ́щей; не прикаса́ютъ бо сѧ жи́дове самарѧ́нѣхъ. ѿвѣща̀ і҆и҃съ, и҆ речѐ є҆́й: а҆́ще бы вѣ́дала є҆сѝ да́ръ бж҃їй, и҆ кто̀ є҆́сть глаго́лѧй тѝ: да́ждь мѝ пи́ти: ты́ бы проси́ла ᲂу҆ негѡ̀, и҆ да́лъ бы тѝ во́дꙋ жи́вꙋ. глаго́ла є҆мꙋ̀ жена̀: гдⷭ҇и, ни почерпа́ла и҆́маши, и҆ стꙋдене́цъ є҆́сть глꙋбо́къ: ѿкꙋ́дꙋ ᲂу҆́бѡ и҆́маши во́дꙋ жи́вꙋ; є҆да̀ ты̀ бо́лїй є҆сѝ ѻ҆ц҃а̀ на́шегѡ і҆а́кѡва, и҆́же дадѐ на́мъ стꙋдене́цъ се́й, и҆ то́й и҆з̾ негѡ̀ пи́тъ, и҆ сы́нове є҆гѡ̀, и҆ ско́ти є҆гѡ̀; ѿвѣща̀ і҆и҃съ и҆ речѐ є҆́й: всѧ́къ пїѧ́й ѿ воды̀ сеѧ̀, вжа́ждетсѧ па́ки. а҆ и҆́же пїе́тъ ѿ воды̀, ю҆́же а҆́зъ да́мъ є҆мꙋ̀, не вжа́ждетсѧ во вѣ́ки: но вода̀, ю҆́же а҆́зъ да́мъ є҆мꙋ̀, бꙋ́детъ въ не́мъ и҆сто́чникъ воды̀ текꙋ́щъ въ живо́тъ вѣ́чный. глаго́ла къ немꙋ̀ жена̀: гдⷭ҇и, да́ждь мѝ сїю̀ во́дꙋ: да ни жа́ждꙋ, ни прихождꙋ̀ сѣ́мѡ почерпа́ти. глаго́ла є҆́й і҆и҃съ: и҆дѝ, пригласѝ мꙋ́жа твоего̀, и҆ прїидѝ сѣ́мѡ. ѿвѣща̀ жена̀ и҆ речѐ є҆мꙋ̀: не и҆́мамъ мꙋ́жа. глаго́ла є҆́й і҆и҃съ: до́брѣ речѐ, ꙗ҆́кѡ мꙋ́жа не и҆́мамъ. пѧ́ть бо мꙋже́й и҆мѣ́ла є҆сѝ: и҆ ны́нѣ є҆го́же и҆́маши, нѣ́сть тѝ мꙋ́жъ: сѐ вои́стиннꙋ рекла̀ є҆сѝ. глаго́ла є҆мꙋ̀ жена̀: гдⷭ҇и, ви́жꙋ ꙗ҆́кѡ проро́къ є҆сѝ ты̀. ѻ҆ц҃ы̀ на́ши въ горѣ̀ се́й поклони́шасѧ: и҆ вы̀ глаго́лете, ꙗ҆́кѡ во і҆ерꙋсали́мѣхъ є҆́сть мѣ́сто, и҆дѣ́же кла́нѧтисѧ подоба́етъ. глаго́ла є҆́й і҆и҃съ: же́но, вѣ́рꙋ мѝ и҆мѝ, ꙗ҆́кѡ грѧде́тъ ча́съ, є҆гда̀ ни въ горѣ̀ се́й, ни во і҆ерꙋсали́мѣхъ покло́нитесѧ ѻ҆ц҃ꙋ̀. вы̀ кла́нѧетесѧ, є҆гѡ́же не вѣ́сте: мы̀ кла́нѧемсѧ, є҆го́же вѣ́мы: ꙗ҆́кѡ спасе́нїе ѿ і҆ꙋдє́й є҆́сть. но грѧде́тъ ча́съ, и҆ ны́нѣ є҆́сть, є҆гда̀ и҆́стиннїи покло́нницы покло́нѧтсѧ ѻ҆ц҃ꙋ̀ дх҃омъ и҆ и҆́стиною: и҆́бо ѻ҆ц҃ъ таковы́хъ и҆́щетъ покланѧ́ющихсѧ є҆мꙋ̀. дх҃ъ є҆́сть бг҃ъ, и҆ и҆́же кла́нѧетсѧ є҆мꙋ̀, дх҃омъ и҆ и҆́стиною досто́итъ кла́нѧтисѧ. глаго́ла є҆мꙋ̀ жена̀: вѣ́мъ, ꙗ҆́кѡ мессі́а прїи́детъ глаго́лемый хрⷭ҇то́съ, є҆гда̀ то́й прїи́детъ, возвѣсти́тъ на́мъ всѧ̑. глаго́ла є҆́й і҆и҃съ: а҆́зъ є҆́смь, глаго́лѧй съ тобо́ю. и҆ тогда̀ прїидо́ша ᲂу҆ченицы̀ є҆гѡ̀, и҆ чꙋжда́хꙋсѧ, ꙗ҆́кѡ съ жено́ю глаго́лаше. никто́же бо речѐ: чесѡ̀ и҆́щеши; и҆лѝ что̀ глаго́леши съ не́ю; ѡ҆ста́ви же водоно́съ сво́й жена̀, и҆ и҆́де во гра́дъ, и҆ глаго́ла человѣ́кѡмъ: прїиди́те, и҆ ви́дите чл҃вѣ́ка, и҆́же рече́ ми всѧ̑, є҆ли̑ка сотвори́хъ: є҆да̀ то́й є҆́сть хрⷭ҇то́съ; и҆зыдо́ша же и҆з̾ гра́да, и҆ грѧдѧ́хꙋ къ немꙋ̀. междꙋ́ же си́мъ, молѧ́хꙋ є҆го̀ ᲂу҆ченицы̀ є҆гѡ̀, глаго́люще: равві̀, ꙗ҆́ждь. ѻ҆́нъ же речѐ и҆̀мъ: а҆́зъ бра́шно и҆́мамъ ꙗ҆́сти, є҆гѡ́же вы̀ не вѣ́сте. глаго́лахꙋ же ᲂу҆ченицы̀ къ себѣ̀: є҆да̀ кто̀ принесѐ є҆мꙋ̀ ꙗ҆́сти; глаго́ла и҆̀мъ і҆и҃съ: моѐ бра́шно є҆́сть, да сотворю̀ во́лю посла́вшагѡ мѧ̀, и҆ совершꙋ̀ дѣ́ло є҆гѡ̀. не вы́ ли глаго́лете, ꙗ҆́кѡ є҆щѐ четы́ри мѣ́сѧцы сꙋ́ть, и҆ жа́тва прїи́детъ; сѐ глаго́лю ва́мъ: возведи́те ѻ҆́чи ва́ши, и҆ ви́дите ни̑вы, ꙗ҆́кѡ пла́вы сꙋ́ть къ жа́твѣ ᲂу҆жѐ. и҆ жнѧ́й мздꙋ̀ прїе́млетъ, и҆ собира́етъ пло́дъ въ живо́тъ вѣ́чный: да и҆ сѣ́ѧй вкꙋ́пѣ ра́дꙋетсѧ и҆ жнѧ́й. ѡ҆ се́мъ бо сло́во є҆́сть и҆́стинное, ꙗ҆́кѡ и҆́нъ є҆́сть сѣ́ѧй, и҆ и҆́нъ є҆́сть жнѧ́й. а҆́зъ посла́хъ вы̀ жа́ти, и҆дѣ́же вы̀ не трꙋди́стесѧ: и҆ні́и трꙋди́шасѧ, и҆ вы̀ въ трꙋ́дъ и҆́хъ внидо́сте. ѿ гра́да же тогѡ̀, мно́зи вѣ́роваша въ ѻ҆́нь ѿ самарѧ́нъ, за сло́во жены̀ свидѣ́тельствꙋющїѧ, ꙗ҆́кѡ рече́ ми всѧ̑, є҆ли̑ка сотвори́хъ. є҆гда́ же прїидо́ша къ немꙋ̀ самарѧ́не, молѧ́хꙋ є҆го̀, дабы̀ пребы́лъ ᲂу҆ ни́хъ: и҆ пребы́сть тꙋ̀ два̀ днѝ. и҆ мно́гѡ па́че вѣ́роваша за сло́во є҆гѡ̀. женѣ́ же глаго́лахꙋ, ꙗ҆́кѡ не ктомꙋ̀ за твою̀ бесѣ́дꙋ вѣ́рꙋемъ: са́ми бо слы́шахомъ, и҆ вѣ́мы, ꙗ҆́кѡ се́й є҆́сть вои́стиннꙋ сп҃съ мі́рꙋ хрⷭ҇то́съ. ",
}

add_evangelie_ioanna {
  ["номер"] = 13,
  ["комментарий"] = "Ин., 13 зач., IV, 46–54.",
  ["текст_ру"] = "Во вре́мя о́но, бе не́кий царе́в муж, его́же сын боля́ше в Капернау́ме. Сей слы́шав, я́ко Иису́с прии́де от Иуде́и в Галиле́ю, и́де к Нему́ и моля́ше Его́, да сни́дет и исцели́т сы́на Его́, хотя́ше бо умре́ти. Рече́ у́бо Иису́с к нему́: а́ще зна́мений и чуде́с не ви́дите, не и́мате ве́ровати. Глаго́ла к Нему́ царе́в муж: Го́споди, сни́ди, пре́жде да́же не у́мрет отроча́ мое́. Глаго́ла ему́ Иису́с: иди́, сын твой жив есть. И ве́рова челове́к словеси́, е́же рече́ ему́ Иису́с, и идя́ше. А́бие же входя́щу ему́, се раби́ его́ срето́ша его́ и возвести́ша ему́, глаго́люще, я́ко сын твой жив есть. Вопроша́ше у́бо от них час, в кото́рый легча́е ему́ бысть, и ре́ша ему́, я́ко вчера́ в час седмы́й оста́ви его́ огнь. Разуме́ же оте́ц, я́ко той бе час, во́ньже рече́ ему́ Иису́с, я́ко сын твой жив есть, и ве́рова сам и весь дом его́. Сие́ па́ки второ́е зна́мение сотвори́ Иису́с, прише́д от Иуде́и в Галиле́ю. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бѣ̀ нѣ́кїй царе́въ мꙋ́жъ, є҆гѡ́же сы́нъ болѧ́ше, въ капернаꙋ́мѣ. се́й слы́шавъ, ꙗ҆́кѡ і҆и҃съ прїи́де ѿ і҆ꙋде́и въ галїле́ю, и҆́де къ немꙋ̀, и҆ молѧ́ше є҆го̀, да сни́детъ, и҆ и҆сцѣли́тъ сы́на є҆гѡ̀: хотѧ́ше бо ᲂу҆мре́ти. речѐ ᲂу҆́бѡ і҆и҃съ къ немꙋ̀: а҆́ще зна́менїй и҆ чꙋде́съ не ви́дите, не и҆́мате вѣ́ровати. глаго́ла къ немꙋ̀ царе́въ мꙋ́жъ: гдⷭ҇и, сни́ди пре́жде да́же не ᲂу҆́мретъ ѻ҆троча̀ моѐ. глаго́ла є҆мꙋ̀ і҆и҃съ: и҆дѝ, сы́нъ тво́й жи́въ є҆́сть. и҆ вѣ́рова человѣ́къ словесѝ, є҆́же речѐ є҆мꙋ̀ і҆и҃съ, и҆ и҆дѧ́ше. а҆́бїе же входѧ́щꙋ є҆мꙋ̀, сѐ рабѝ є҆гѡ̀ срѣто́ша є҆го̀, и҆ возвѣсти́ша є҆мꙋ̀ глаго́люще: ꙗ҆́кѡ сы́нъ тво́й жи́въ є҆́сть. вопроша́ше ᲂу҆́бѡ ѿ ни́хъ ча́съ, въ кото́рый легча́е є҆мꙋ̀ бы́сть; и҆ рѣ́ша є҆мꙋ̀, ꙗ҆́кѡ вчера̀ въ ча́съ седмы́й ѡ҆ста́ви є҆го̀ ѻ҆́гнь. разꙋмѣ́ же ѻ҆те́цъ, ꙗ҆́кѡ то́й бѣ̀ ча́съ, во́ньже речѐ є҆мꙋ̀ і҆и҃съ, ꙗ҆́кѡ сы́нъ тво́й жи́въ є҆́сть: и҆ вѣ́рова са́мъ, и҆ ве́сь до́мъ є҆гѡ̀. сїѐ па́ки второ́е зна́менїе сотворѝ і҆и҃съ, прише́дъ ѿ і҆ꙋде́и въ галїле́ю. ",
}

add_evangelie_ioanna {
  ["номер"] = 14,
  ["комментарий"] = "Ин., 14 зач., V, 1–15.",
  ["текст_ру"] = "Во вре́мя о́но, взы́де Иису́с во Иерусали́м. Есть же во Иерусали́мех на О́вчей купе́ли, я́же глаго́лется евре́йски Вифесда́, пять притво́р иму́щи. В тех слежа́ше мно́жество боля́щих, слепы́х, хромы́х, сухи́х, ча́ющих движе́ния воды́. А́нгел бо Госпо́день на вся́ко ле́то схожда́ше в купе́ль и возмуща́ше во́ду, и и́же пе́рвее вла́зяше по возмуще́нии воды́ здрав быва́ше, яце́м же неду́гом одержи́мь быва́ше. Бе же ту не́кий челове́к, три́десять и осмь лет имы́й в неду́зе свое́м. Сего́ ви́дев Иису́с лежа́ща и разуме́в, я́ко мно́га ле́та уже́ имя́ше в неду́зе, глаго́ла ему́: хо́щеши ли цел бы́ти? Отвеща́ Ему́ неду́жный: ей, Го́споди, челове́ка не и́мам, да егда́ возмути́тся вода́, вве́ржет мя в купе́ль, егда́ же прихожду́ аз, ин пре́жде мене́ сла́зит. Глаго́ла ему́ Иису́с: воста́ни, возми́ одр твой и ходи́. И а́бие здрав бысть челове́к, и взем одр свой и хожда́ше. Бе же суббо́та в той день. Глаго́лаху же жи́дове исцеле́вшему: суббо́та есть, и не досто́ит ти взя́ти одра́ твоего́. Он же отвеща́ им: И́же мя сотвори́ це́ла, Той мне рече́: возми́ одр твой и ходи́. Вопроси́ша же его́: кто есть Челове́к реки́й ти, возми́ одр твой и ходи́? Изцеле́вый же не ве́дяше, Кто есть, Иису́с бо укло́нься, наро́ду су́щу на ме́сте. Пото́м же обре́те его́ Иису́с в це́ркви и рече́ ему́: се здрав бысть, ктому́ не согреша́й, да не го́рше ти что бу́дет. И́де же челове́к и пове́да иуде́ом, я́ко Иису́с есть, и́же мя сотвори́ це́ла. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, взы́де і҆и҃съ во і҆ерꙋсали́мъ. є҆́сть же во і҆ерꙋсали́мѣхъ на ѻ҆́вчей кꙋпѣ́ли, ꙗ҆́же глаго́летсѧ є҆вре́йски виѳесда̀: пѧ́ть притвѡ́ръ и҆мꙋ́щи: въ тѣ́хъ слежа́ше мно́жество болѧ́щихъ, слѣпы́хъ, хромы́хъ, сꙋхи́хъ, ча́ющихъ движе́нїѧ воды̀. а҆́гг҃лъ бо гдⷭ҇нь на всѧ́ко лѣ́то схожда́ше въ кꙋпѣ́ль, и҆ возмꙋща́ше во́дꙋ: и҆ и҆́же пе́рвѣе вла́зѧше по возмꙋще́нїи воды̀ здра́въ быва́ше, ꙗ҆цѣ́мъ же недꙋ́гомъ ѡ҆держи́мь быва́ше. бѣ́ же тꙋ̀ нѣ́кїй человѣ́къ, три́десѧть и҆ ѻ҆́смь лѣ́тъ и҆мы́й въ недꙋ́зѣ свое́мъ. сего̀ ви́дѣвъ і҆и҃съ лежа́ща, и҆ разꙋмѣ́въ, ꙗ҆́кѡ мнѡ́га лѣ́та ᲂу҆жѐ и҆мѧ́ше въ недꙋ́зѣ, глаго́ла є҆мꙋ̀: хо́щеши ли цѣ́лъ бы́ти; ѿвѣща̀ є҆мꙋ̀ недꙋ́жный: є҆́й гдⷭ҇и, человѣ́ка не и҆́мамъ, да є҆гда̀ возмꙋти́тсѧ вода̀, вве́ржетъ мѧ̀ въ кꙋпѣ́ль: є҆гда́ же прихождꙋ̀ а҆́зъ, и҆́нъ пре́жде менѐ сла́зитъ. глаго́ла є҆мꙋ̀ і҆и҃съ: воста́ни, воз̾мѝ ѻ҆́дръ тво́й, и҆ ходѝ. и҆ а҆́бїе здра́въ бы́сть человѣ́къ, и҆ взе́мъ ѻ҆́дръ сво́й, и҆ хожда́ше: бѣ́ же сꙋббѡ́та въ то́й де́нь. глаго́лахꙋ же жи́дове и҆сцѣлѣ́вшемꙋ: сꙋббѡ́та є҆́сть, и҆ не досто́итъ тѝ взѧ́ти ѻ҆дра̀ твоегѡ̀. ѻ҆́нъ же ѿвѣща̀ и҆̀мъ: и҆́же мѧ̀ сотворѝ цѣ́ла, то́й мнѣ̀ речѐ: воз̾мѝ ѻ҆́дръ тво́й, и҆ ходѝ. вопроси́ша же є҆го̀: кто́ є҆сть человѣ́къ рекі́й тѝ, воз̾мѝ ѻ҆́дръ тво́й, и҆ ходѝ; и҆сцѣлѣ́вый же не вѣ́дѧше кто́ є҆сть: і҆и҃съ бо ᲂу҆кло́ньсѧ, наро́дꙋ сꙋ́щꙋ на мѣ́стѣ. пото́мъ же ѡ҆брѣ́те є҆го̀ і҆и҃съ въ це́ркви, и҆ речѐ є҆мꙋ̀: сѐ здра́въ бы́сть, ктомꙋ̀ не согрѣша́й, да не го́рше тѝ что̀ бꙋ́детъ. и҆́де же человѣ́къ, и҆ повѣ́да і҆ꙋде́ѡмъ, ꙗ҆́кѡ і҆и҃съ є҆́сть, и҆́же мѧ̀ сотворѝ цѣ́ла. ",
}

