add_evangelie_ioanna {
  ["номер"] = 15,
  ["комментарий"] = "Ин., 15 зач., V, 17–24.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: Оте́ц Мой досе́ле де́лает, и Аз де́лаю. И сего́ ра́ди па́че иска́ху Его́ иуде́е уби́ти, я́ко не то́кмо разоря́ше суббо́ту, но и Отца́ Своего́ глаго́лаше Бо́га, ра́вен Ся творя́ Бо́гу. Отвеща́в же Иису́с и рече́ им: ами́нь, ами́нь глаго́лю вам, не мо́жет Сын твори́ти о Себе́ ничесо́же, а́ще не е́же ви́дит Отца́ творя́ща, я́же бо Он твори́т, сия́ и Сын та́кожде твори́т. Оте́ц бо лю́бит Сы́на и вся показу́ет Ему́, я́же Сам твори́т, и бо́льша сих пока́жет Ему́ дела́, да вы чудите́ся. Я́коже бо Оте́ц воскреша́ет ме́ртвыя и живи́т, та́ко и Сын, и́хже хо́щет, живи́т. Оте́ц бо не су́дит никому́же, но суд весь даст Сы́нови, да вси чтут Сы́на, я́коже чтут Отца́, а и́же не чтит Сы́на, не чтит Отца́ посла́вшаго Его́. Ами́нь, ами́нь глаго́лю вам, я́ко слу́шаяй словесе́ Моего́ и ве́руяй Посла́вшему Мя и́мать живо́т ве́чный, и на суд не прии́дет, но пре́йдет от сме́рти в живо́т. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: ѻ҆ц҃ъ мо́й досе́лѣ дѣ́лаетъ, и҆ а҆́зъ дѣ́лаю. сегѡ́ же ра́ди па́че и҆ска́хꙋ є҆го̀ і҆ꙋде́є ᲂу҆би́ти, ꙗ҆́кѡ не то́кмѡ разорѧ́ше сꙋббѡ́тꙋ, но и҆ ѻ҆ц҃а̀ своего̀ глаго́лаше бг҃а, ра́венъ сѧ̀ творѧ̀ бг҃ꙋ. ѿвѣща́въ же і҆и҃съ, и҆ речѐ и҆̀мъ: а҆ми́нь а҆ми́нь глаго́лю ва́мъ: не мо́жетъ сн҃ъ твори́ти ѡ҆ себѣ̀ ничесѡ́же, а҆́ще не є҆́же ви́дитъ ѻ҆ц҃а̀ творѧ́ща: ꙗ҆̀же бо ѻ҆́нъ твори́тъ, сїѧ̑ и҆ сн҃ъ та́коже твори́тъ. ѻ҆ц҃ъ бо лю́битъ сн҃а, и҆ всѧ̑ показꙋ́етъ є҆мꙋ̀, ꙗ҆̀же са́мъ твори́тъ: и҆ бѡ́льша си́хъ пока́жетъ є҆мꙋ̀ дѣла̀, да вы̀ чꙋдите́сѧ. ꙗ҆́коже бо ѻ҆ц҃ъ воскреша́етъ ме́ртвыѧ, и҆ живи́тъ: та́кѡ и҆ сн҃ъ, и҆̀хже хо́щетъ, живи́тъ. ѻ҆ц҃ъ бо не сꙋ́дитъ никомꙋ́же, но сꙋ́дъ ве́сь да́стъ сн҃ови: да всѝ чтꙋ́тъ сн҃а, ꙗ҆́коже чтꙋ́тъ ѻ҆ц҃а̀: а҆ и҆́же не чти́тъ сн҃а, не чти́тъ ѻ҆ц҃а̀ посла́вшаго є҆го̀. а҆ми́нь а҆ми́нь глаго́лю ва́мъ: ꙗ҆́кѡ слꙋ́шаѧй словесѐ моегѡ̀, и҆ вѣ́рꙋѧй посла́вшемꙋ мѧ̀, и҆́мать живо́тъ вѣ́чный, и҆ на сꙋ́дъ не прїи́детъ: но пре́йдетъ ѿ сме́рти въ живо́тъ. ",
}

add_evangelie_ioanna {
  ["номер"] = 16,
  ["комментарий"] = "Ин., 16 зач., V, 24–30.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: ами́нь, ами́нь глаго́лю вам, я́ко слу́шаяй словесе́ Моего́ и ве́руяй Посла́вшему Мя и́мать живо́т ве́чный, и на суд не прии́дет, но пре́йдет от сме́рти в живо́т. Ами́нь, ами́нь глаго́лю вам, я́ко гряде́т час, и ны́не есть, егда́ ме́ртвии услы́шат глас Сы́на Бо́жия и услы́шавше оживу́т. Я́коже бо Оте́ц и́мать живо́т в Себе́, та́ко даст и Сы́нови живо́т име́ти в Себе́ и о́бласть даде́ Ему́ и суд твори́ти, я́ко Сын Челове́чь есть. Не диви́теся сему́, я́ко гряде́т час, во́ньже вси су́щии во гробе́х услы́шат глас Сы́на Бо́жия, и изы́дут сотво́ршии блага́я в воскреше́ние живота́, а сотво́ршии зла́я в воскреше́ние суда́. Не могу́ Аз о Себе́ твори́ти ничесо́же. Я́коже слы́шу, сужду́, и суд Мой пра́веден есть, я́ко не ищу́ во́ли Моея́, но во́ли посла́вшаго Мя Отца́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: а҆ми́нь а҆ми́нь глаго́лю ва́мъ: ꙗ҆́кѡ слꙋ́шаѧй словесѐ моегѡ̀, и҆ вѣ́рꙋѧй посла́вшемꙋ мѧ̀, и҆́мать живо́тъ вѣ́чный, и҆ на сꙋ́дъ не прїи́детъ: но пре́йдетъ ѿ сме́рти въ живо́тъ. а҆ми́нь а҆ми́нь глаго́лю ва́мъ: ꙗ҆́кѡ грѧде́тъ ча́съ, и҆ ны́нѣ є҆́сть, є҆гда̀ ме́ртвїи ᲂу҆слы́шатъ гла́съ сн҃а бж҃їѧ, и҆ ᲂу҆слы́шавше ѡ҆живꙋ́тъ. ꙗ҆́коже бо ѻ҆ц҃ъ и҆́мать живо́тъ въ себѣ̀, та́кѡ да́стъ и҆ сн҃ови живо́тъ и҆мѣ́ти въ себѣ̀. и҆ ѻ҆́бласть да́стъ є҆мꙋ̀ и҆ сꙋ́дъ твори́ти: ꙗ҆́кѡ сн҃ъ чл҃вѣ́чь є҆́сть, не диви́тесѧ семꙋ̀. ꙗ҆́кѡ грѧде́тъ ча́съ, во́ньже всѝ сꙋ́щїи во гробѣ́хъ, ᲂу҆слы́шатъ гла́съ сн҃а бж҃їѧ: и҆ и҆зы́дꙋтъ сотво́ршїи блага̑ѧ въ воскреше́нїе живота̀: а҆ сотво́ршїи ѕла̑ѧ въ воскреше́нїе сꙋда̀. не могꙋ̀ а҆́зъ ѡ҆ себѣ̀ твори́ти ничесо́же. ꙗ҆́коже слы́шꙋ, сꙋждꙋ̀: и҆ сꙋ́дъ мо́й пра́веденъ є҆́сть: ꙗ҆́кѡ не и҆щꙋ̀ во́ли моеѧ̀ но во́ли посла́вшагѡ мѧ̀ ѻ҆ц҃а̀. ",
}

add_evangelie_ioanna {
  ["номер"] = 17,
  ["комментарий"] = "Ин., 17 зач., V, 30 – VI, 2.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: я́коже слы́шу, сужду́, и суд Мой пра́веден есть, я́ко не ищу́ во́ли Моея́, но во́ли посла́вшаго Мя Отца́. А́ще Аз свиде́тельствую о Мне, свиде́тельство Мое́ несть и́стинно. Ин есть свиде́тельствуяй о Мне, и вем, я́ко и́стинно есть свиде́тельство, е́же свиде́тельствует о Мне. Вы посла́сте ко Иоа́нну, и свиде́тельствова о и́стине. Аз же не от челове́ка свиде́тельства прие́млю, но сия́ глаго́лю, да вы спасе́ни бу́дете. Он бе свети́льник горя́ и светя́, вы же хоте́сте возра́доватися в час свете́ния его́. Аз же и́мам свиде́тельство бо́ле Иоа́ннова, дела́ бо, я́же даде́ Мне Оте́ц, да совершу́ я́, та дела́, я́же Аз творю́, свиде́тельствуют о Мне, я́ко Оте́ц Мя посла́. И посла́вый Мя Оте́ц Той свиде́тельствова о Мне. Ни гла́са Его́ нигде́же слы́шасте, ни виде́ния Его́ ви́десте, и словесе́ Его́ не и́мате пребыва́юща в вас, зане́, Его́же Той посла́, Сему́ вы ве́ру не е́млете. Испыта́йте Писа́ния, я́ко вы мните́ в них име́ти живо́т ве́чный, и та суть свиде́тельствующая о Мне. И не хо́щете приити́ ко Мне, да живо́т и́мате. Сла́вы от челове́к не прие́млю, но разуме́х вы, я́ко любве́ Бо́жия не и́мате в себе́. Аз приидо́х во и́мя Отца́ Моего́, и не прие́млете Мене́, а́ще ин прии́дет во и́мя свое́, того́ прие́млете. Ка́ко вы мо́жете ве́ровати, сла́вы друг от дру́га прие́млюще, и сла́вы, я́же от Еди́наго Бо́га, не и́щете? Не мните́, я́ко Аз на вы реку́ ко Отцу́, есть, и́же на вы глаго́лет, Моисе́й, на́ньже вы упова́ете. А́ще бо бы́сте ве́ровали Моисе́ови, ве́ровали бы́сте у́бо и Мне, о Мне бо той писа́. А́ще ли того́ писа́нием не ве́руете, ка́ко Мои́м глаго́лом ве́ру и́мете? По сих и́де Иису́с на он пол мо́ря Галиле́и Тивериа́дска, и по Нем идя́ше наро́д мног, я́ко ви́дяху зна́мения Его́, я́же творя́ше на неду́жных. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: ꙗ҆́коже слы́шꙋ, сꙋждꙋ̀: и҆ сꙋ́дъ мо́й пра́веденъ є҆́сть: ꙗ҆́кѡ не и҆щꙋ̀ во́ли моеѧ̀ но во́ли посла́вшагѡ мѧ̀ ѻ҆ц҃а̀. а҆́ще а҆́зъ свидѣ́тельствꙋю ѡ҆ мнѣ̀, свидѣ́тельство моѐ нѣ́сть и҆́стинно. и҆́нъ є҆́сть свидѣ́тельствꙋѧй ѡ҆ мнѣ̀, и҆ вѣ́мъ, ꙗ҆́кѡ и҆́стинно є҆́сть свидѣ́тельство, є҆́же свидѣ́тельствꙋетъ ѡ҆ мнѣ̀. вы̀ посла́сте ко і҆ѡа́ннꙋ, и҆ свидѣ́тельствова ѡ҆ и҆́стинѣ. а҆́зъ же не ѿ человѣ́ка свидѣ́тєльства прїе́млю: но сїѧ̑ глаго́лю, да вы̀ спасе́ни бꙋ́дете. ѻ҆́нъ бѣ̀ свѣти́льникъ, горѧ̀ и҆ свѣтѧ̀: вы́ же хотѣ́сте возра́доватисѧ въ ча́съ свѣтѣ́нїѧ є҆гѡ̀. а҆́зъ же и҆́мамъ свидѣ́тельство бо́ле і҆ѡа́ннова: дѣла́ бо, ꙗ҆̀же дадѐ мнѣ̀ ѻ҆ц҃ъ, да совершꙋ̀ ѧ҆̀, та̀ дѣла̀, ꙗ҆̀же а҆́зъ творю̀, свидѣ́тельствꙋютъ ѡ҆ мнѣ̀, ꙗ҆́кѡ ѻ҆ц҃ъ мѧ̀ посла̀. и҆ посла́вый мѧ̀ ѻ҆ц҃ъ, то́й свидѣ́тельствова ѡ҆ мнѣ̀. ни гла́са є҆гѡ̀ нигдѣ́же слы́шасте, ни видѣ́нїѧ є҆гѡ̀ ви́дѣсте: и҆ словесѐ є҆гѡ̀ не и҆́мате пребыва́юща въ ва́съ. занѐ є҆го́же то́й посла̀, семꙋ̀ вы̀ вѣ́рꙋ не є҆́млете. и҆спыта́йте писа̑нїѧ, ꙗ҆́кѡ вы̀ мнитѐ въ ни́хъ и҆мѣ́ти живо́тъ вѣ́чный: и҆ та̀ сꙋ́ть свидѣ́тєльствꙋющаѧ ѡ҆ мнѣ̀. и҆ не хо́щете прїитѝ ко мнѣ̀, да живо́тъ и҆́мате. сла́вы ѿ человѣ̑къ не прїе́млю, но разꙋмѣ́хъ вы̀, ꙗ҆́кѡ любвѐ бж҃їѧ не и҆́мате въ себѣ̀. а҆́зъ прїидо́хъ во и҆́мѧ ѻ҆ц҃а̀ моегѡ̀, и҆ не прїе́млете менѐ: а҆́ще и҆́нъ прїи́детъ во и҆́мѧ своѐ, того̀ прїе́млете. ка́кѡ вы̀ мо́жете вѣ́ровати, сла̑вы дрꙋ́гъ ѿ дрꙋ́га прїе́млюще, и҆ сла́вꙋ, ꙗ҆́же ѿ є҆ди́нагѡ бг҃а, не и҆́щете; не мни́те, ꙗ҆́кѡ а҆́зъ на вы̀ рекꙋ̀ ко ѻ҆ц҃ꙋ̀: є҆́сть, и҆́же на вы̀ глаго́летъ, мѡѷсе́й, на́ньже вы̀ ᲂу҆пова́ете. а҆́ще бо бы́сте вѣ́ровали мѡѷсе́ови, вѣ́ровали бы́сте ᲂу҆́бѡ и҆ мнѣ̀: ѡ҆ мнѣ́ бо то́й писа̀. а҆́ще ли тогѡ̀ писа́нїємъ не вѣ́рꙋете, ка́кѡ мои́мъ глаго́лѡмъ вѣ́рꙋ и҆́мете; по си́хъ и҆́де і҆и҃съ на ѻ҆́нъ по́лъ мо́рѧ галїле́и тїверїа́дска: и҆ по не́мъ и҆дѧ́ше наро́дъ мно́гъ, ꙗ҆́кѡ ви́дѧхꙋ зна́мєнїѧ є҆гѡ̀, ꙗ҆̀же творѧ́ше на недꙋ́жныхъ. ",
}

add_evangelie_ioanna {
  ["номер"] = 18,
  ["комментарий"] = "Ин., 18 зач., VI, 5–14.",
  ["текст_ру"] = "Во вре́мя о́но, возве́д Иису́с о́чи и ви́дев, я́ко мног наро́д гряде́т к Нему́, глаго́ла к Фили́ппу: чим ку́пим хле́бы, да ядя́т си́и? Сие́ же глаго́лаше искуша́я его́, Сам бо ве́дяше, что хо́щет сотвори́ти. Отвеща́ Ему́ Фили́пп: двема́ сто́ма пе́нязь хле́бы не довле́ют им, да ко́ждо их ма́ло что прии́мет. Глаго́ла Ему́ еди́н от учени́к Его́, Андре́й, брат Си́мона Петра́: есть о́трочищь зде еди́н, и́же и́мать пять хлеб ячме́нных и две ры́бе, но си́и что суть в сели́ко? Рече́ же Иису́с: сотвори́те челове́ки возлещи́. Бе же трава́ мно́га на ме́сте. Возлеже́ у́бо муже́й число́м я́ко пять ты́сящ. Прия́т же хле́бы Иису́с и хвалу́ возда́в, подаде́ ученико́м, ученицы́ же возлежа́щым, та́кожде и от ры́бу, ели́ко хотя́ху. И я́ко насы́тишася, глаго́ла ученико́м Свои́м: собери́те избы́тки укру́х, да не поги́бнет ничто́же. Собра́ша же и испо́лниша двана́десяте ко́шя укру́х от пяти́х хлеб ячме́нных, и́же избы́ша я́дшым. Челове́цы же ви́девше зна́мение, е́же сотвори́ Иису́с, глаго́лаху, я́ко Сей есть вои́стинну Проро́к Гряды́й в мир. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, возве́дъ і҆и҃съ ѻ҆́чи и҆ ви́дѣвъ, ꙗ҆́кѡ мно́гъ наро́дъ грѧде́тъ къ немꙋ̀, глаго́ла къ фїлі́ппꙋ: чи́мъ кꙋ́пимъ хлѣ́бы, да ꙗ҆дѧ́тъ сі́и; сїе́ же глаго́лаше и҆скꙋша́ѧ є҆го̀: са́мъ бо вѣ́дѧше, что̀ хо́щетъ сотвори́ти. ѿвѣща̀ є҆мꙋ̀ фїлі́ппъ: двѣма̀ сто́ма пѣ̑нѧзь хлѣ́бы не довлѣ́ютъ и҆̀мъ, да ко́ждо и҆́хъ ма́ло что̀ прїи́метъ. глаго́ла є҆мꙋ̀ є҆ди́нъ ѿ ᲂу҆чєни́къ є҆гѡ̀ а҆ндре́й, бра́тъ сі́мѡна петра̀: є҆́сть ѻ҆́трочищь здѣ̀ є҆ди́нъ, и҆́же и҆́мать пѧ́ть хлѣ́бъ ꙗ҆чме́нныхъ, и҆ двѣ̀ ры́бѣ: но сі́и что̀ сꙋ́ть въ сели́ко; рече́ же і҆и҃съ: сотвори́те человѣ́ки возлещѝ. бѣ́ же трава̀ мно́га на мѣ́стѣ. возлежѐ ᲂу҆́бѡ мꙋже́й число́мъ ꙗ҆́кѡ пѧ́ть ты́сѧщъ. прїѧ́тъ же хлѣ́бы і҆и҃съ, и҆ хвалꙋ̀ возда́въ, подадѐ ᲂу҆ченикѡ́мъ, ᲂу҆ченицы́ же возлежа́щымъ: та́кожде и҆ ѿ ры́бꙋ, є҆ли́кѡ хотѧ́хꙋ. и҆ ꙗ҆́кѡ насы́тишасѧ, глаго́ла ᲂу҆ченикѡ́мъ свои́мъ: собери́те и҆збы́тки ᲂу҆крꙋ̑хъ, да не поги́бнетъ ничто́же. собра́ша же, и҆ и҆спо́лниша двана́десѧте кѡ́шѧ ᲂу҆крꙋ́хъ ѿ пѧти́хъ хлѣ̑бъ ꙗ҆чме́нныхъ, и҆̀же и҆збы́ша ꙗ҆́дшымъ. человѣ́цы же ви́дѣвше зна́менїе, є҆́же сотворѝ і҆и҃съ, глаго́лахꙋ: ꙗ҆́кѡ се́й є҆́сть вои́стиннꙋ проро́къ, грѧды́й въ мі́ръ. ",
}

add_evangelie_ioanna {
  ["номер"] = 19,
  ["комментарий"] = "Ин., 19 зач., VI, 14–27.",
  ["текст_ру"] = "Во вре́мя о́но, ви́девше челове́цы зна́мение, е́же сотвори́ Иису́с, глаго́лаху, я́ко Сей есть вои́стинну Проро́к Гряды́й в мир. Иису́с же разуме́в, я́ко хотя́т приити́, да восхи́тят Его́ и сотворя́т Его́ царя́, оты́де па́ки в го́ру еди́н. Я́ко по́зде бысть, снидо́ша ученицы́ Его́ на мо́ре, и влезо́ша в кора́бль, и идя́ху на он пол мо́ря в Капернау́м. И тма а́бие бысть, и не у бе прише́л к ним Иису́с. Мо́ре же, ве́тру ве́лию дыха́ющу, воздвиза́шеся. Гре́бше же я́ко ста́дий два́десять и пять, или́ три́десять, узре́ша Иису́са ходя́ща по мо́рю и близ корабля́ бы́вша, и убоя́шася. Он же глаго́ла им: Аз есмь, не бо́йтеся. Хотя́ху у́бо прия́ти Его́ в кора́бль, и а́бие кора́бль бысть на земли́, в ню́же идя́ху. Во у́трий же наро́д, и́же стоя́ше об он пол мо́ря, ви́дев, я́ко корабля́ ино́го не бе ту, то́кмо еди́н той, во́ньже внидо́ша ученицы́ Его́, и я́ко не вни́де со ученики́ Свои́ми Иису́с в кора́бль, но еди́ни ученицы́ Его́ идо́ша, и и́ни приидо́ша корабли́ от Тивериа́ды близ ме́ста, иде́же ядо́ша хле́бы, хвалу́ возда́вше Го́сподеви. Егда́ же ви́деша наро́ди, я́ко Иису́са не бысть ту, ни учени́к Его́, влезо́ша са́ми в корабли́ и приидо́ша в Капернау́м, и́щуще Иису́са, и обрето́ша Его́ об он пол мо́ря, ре́ша Ему́: Равви́, когда́ зде бысть? Отвеща́ им Иису́с и рече́: ами́нь, ами́нь глаго́лю вам, и́щете Мене́, не я́ко ви́десте зна́мение, но я́ко я́ли есте́ хле́бы и насы́тистеся. Де́лайте не бра́шно ги́блющее, но бра́шно пребыва́ющее в животе́ ве́чнем, е́же Сын Челове́ческий вам даст, Сего́ бо Оте́ц зна́мена Бог. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ви́дѣвше человѣ́цы зна́менїе, є҆́же сотворѝ і҆и҃съ, глаго́лахꙋ: ꙗ҆́кѡ се́й є҆́сть вои́стиннꙋ проро́къ, грѧды́й въ мі́ръ. і҆и҃съ же разꙋмѣ́въ, ꙗ҆́кѡ хотѧ́тъ прїитѝ, да восхи́тѧтъ є҆го̀ и҆ сотворѧ́тъ є҆го̀ цр҃ѧ̀, ѿи́де па́ки въ го́рꙋ є҆ди́нъ. ꙗ҆́кѡ по́здѣ бы́сть, снидо́ша ᲂу҆ченицы̀ є҆гѡ̀ на мо́ре. и҆ влѣзо́ша въ кора́бль, и҆ и҆дѧ́хꙋ на ѻ҆́нъ по́лъ мо́рѧ въ капернаꙋ́мъ: и҆ тма̀ а҆́бїе бы́сть, и҆ не ᲂу҆̀ бѣ̀ прише́лъ къ ни́мъ і҆и҃съ. мо́ре же вѣ́трꙋ ве́лїю дыха́ющꙋ, воздвиза́шесѧ. гре́бше же ꙗ҆́кѡ ста́дїй два́десѧть и҆ пѧ́ть, и҆лѝ три́десѧть, ᲂу҆зрѣ́ша і҆и҃са ходѧ́ща по мо́рю, и҆ бли́зъ кораблѧ̀ бы́вша, и҆ ᲂу҆боѧ́шасѧ. ѻ҆́нъ же глаго́ла и҆̀мъ: а҆́зъ є҆́смь, не бо́йтесѧ. хотѧ́хꙋ же прїѧ́ти є҆го̀ въ кора́бль, и҆ а҆́бїе кора́бль бы́сть на землѝ, въ ню́же и҆дѧ́хꙋ. во ᲂу҆́трїй же наро́дъ, и҆́же стоѧ́ше ѡ҆б̾ ѻ҆́нъ по́лъ мо́рѧ, ви́дѣвъ ꙗ҆́кѡ кораблѧ̀ и҆но́гѡ не бѣ̀ тꙋ̀, то́кмѡ є҆ди́нъ то́й, во́ньже внидо́ша ᲂу҆ченицы̀ є҆гѡ̀, и҆ ꙗ҆́кѡ не вни́де со ᲂу҆ченикѝ свои́ми і҆и҃съ въ кора́бль, но є҆ди́ни ᲂу҆чн҃цы̀ є҆гѡ̀ и҆до́ша: и҆ и҆́ни прїидо́ша кораблѝ ѿ тїверїа́ды бли́зъ мѣ́ста, и҆дѣ́же ꙗ҆до́ша хлѣ́бы, хвалꙋ̀ возда́вше гдⷭ҇ви. є҆гда́ же ви́дѣша наро́ди, ꙗ҆́кѡ і҆и҃са не бы́сть тꙋ̀, ни ᲂу҆чени̑къ є҆гѡ̀, влѣзо́ша са́ми въ кораблѝ, и҆ прїидо́ша въ капернаꙋ́мъ, и҆́щꙋще і҆и҃са. и҆ ѡ҆брѣто́ша є҆го̀ ѡ҆б̾ ѻ҆́нъ по́лъ мо́рѧ, рѣ́ша є҆мꙋ̀: равві̀, когда̀ здѣ̀ бы́сть; ѿвѣща̀ и҆́мъ і҆и҃съ, и҆ речѐ: а҆ми́нь а҆ми́нь глаго́лю ва́мъ, и҆́щете менѐ не ꙗ҆́кѡ ви́дѣсте зна́менїе, но ꙗ҆́кѡ ꙗ҆́ли є҆стѐ хлѣ́бы, и҆ насы́тистесѧ. дѣ́лайте не бра́шно ги́блющее, но бра́шно пребыва́ющее въ животѣ̀ вѣ́чнѣмъ, є҆́же сн҃ъ человѣ́ческїй ва́мъ да́стъ: сего́ бо ѻ҆ц҃ъ зна́мена бг҃ъ. ",
}

add_evangelie_ioanna {
  ["номер"] = 20,
  ["комментарий"] = "Ин., 20 зач., VI, 27–33.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: де́лайте не бра́шно ги́блющее, но бра́шно пребыва́ющее в животе́ ве́чнем, е́же Сын Челове́ческий вам даст, Сего́ бо Оте́ц зна́мена Бог. Ре́ша же к Нему́: что сотвори́м, да де́лаем дела́ Бо́жия? Отвеща́ Иису́с и рече́ им: се есть де́ло Бо́жие, да ве́руете в Того́, Его́же посла́ Он. Ре́ша же Ему́: ко́е у́бо Ты твори́ши зна́мение, да ви́дим и ве́ру и́мем Тебе́? Что де́лаеши? Отцы́ на́ши ядо́ша ма́нну в пусты́ни, я́коже есть пи́сано: хлеб с небесе́ даст им я́сти. Рече́ у́бо им Иису́с: ами́нь, ами́нь глаго́лю вам, не Моисе́й даде́ вам хлеб с небесе́, но Оте́ц Мой даст вам хле́ба и́стиннаго с небесе́. Хлеб бо Бо́жии есть сходя́й с небесе́ и дая́й живо́т ми́ру. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: дѣ́лайте не бра́шно ги́блющее, но бра́шно пребыва́ющее въ животѣ̀ вѣ́чнѣмъ, є҆́же сн҃ъ человѣ́ческїй ва́мъ да́стъ: сего́ бо ѻ҆ц҃ъ зна́мена бг҃ъ. рѣ́ша же къ немꙋ̀: что̀ сотвори́мъ, да дѣ́лаемъ дѣла̀ бж҃їѧ; ѿвѣща̀ і҆и҃съ, и҆ речѐ и҆̀мъ: сѐ є҆́сть дѣ́ло бж҃їе, да вѣ́рꙋете въ того̀, є҆го́же посла̀ ѻ҆́нъ. рѣ́ша же є҆мꙋ̀: ко́е ᲂу҆́бѡ ты̀ твори́ши зна́менїе, да ви́димъ, и҆ вѣ́рꙋ и҆́мемъ тебѣ̀; что̀ дѣ́лаеши; ѻ҆тцы̀ на́ши ꙗ҆до́ша ма́ннꙋ въ пꙋсты́ни, ꙗ҆́коже є҆́сть пи́сано: хлѣ́бъ съ небесѐ да́стъ и҆̀мъ ꙗ҆́сти. речѐ ᲂу҆́бѡ и҆̀мъ і҆и҃съ: а҆ми́нь а҆ми́нь глаго́лю ва́мъ, не мѡѷсе́й дадѐ ва́мъ хлѣ́бъ съ небесѐ: но ѻ҆ц҃ъ мо́й да́стъ ва́мъ хлѣ́ба и҆́стиннагѡ съ небесѐ. хлѣ́бъ бо бж҃їй є҆́сть сходѧ́й съ небесѐ, и҆ даѧ́й живо́тъ мі́рꙋ. ",
}

add_evangelie_ioanna {
  ["номер"] = 21,
  ["комментарий"] = "Ин., 21 зач., VI, 35–39.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: Аз есмь хлеб живо́тный, гряды́й ко Мне не и́мать взалка́тися, и ве́руяй в Мя не и́мать вжажда́тися никогда́же. Но рех вам, я́ко и ви́десте Мя, и не ве́руете. Все е́же даст Мне Оте́ц, ко Мне прии́дет, и гряду́щаго ко Мне не изжену́ вон, я́ко снидо́х с небесе́, не да творю́ во́лю Мою́, но во́лю посла́вшаго Мя Отца́. Се же есть во́ля посла́вшаго Мя Отца́, да все е́же даде́ Ми, не погублю́ от Него́, но воскрешу́ е́ в после́дний день. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: а҆́зъ є҆́смь хлѣ́бъ живо́тный, грѧды́й ко мнѣ̀ не и҆́мать взалка́тисѧ: и҆ вѣ́рꙋѧй въ мѧ̀ не и҆́мать вжажда́тисѧ никогда́же. но рѣ́хъ ва́мъ, ꙗ҆́кѡ и҆ ви́дѣсте мѧ̀, и҆ не вѣ́рꙋете. всѐ, є҆́же да́стъ мнѣ̀ ѻ҆ц҃ъ, ко мнѣ̀ прїи́детъ: и҆ грѧдꙋ́щаго ко мнѣ̀ не и҆зженꙋ̀ во́нъ. ꙗ҆́кѡ снидо́хъ съ нб҃сѐ, не да творю̀ во́лю мою̀, но во́лю посла́вшагѡ мѧ̀ ѻ҆ц҃а̀. се́ же є҆́сть во́лѧ посла́вшагѡ мѧ̀ ѻ҆ц҃а̀, да всѐ є҆́же дадѐ мѝ, не погꙋблю̀ ѿ негѡ̀, но воскрешꙋ̀ є҆̀ въ послѣ́днїй де́нь. ",
}

add_evangelie_ioanna {
  ["номер"] = 22,
  ["комментарий"] = "Ин., 22 зач., VI, 40–44.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: се есть во́ля Посла́вшаго Мя, да всяк ви́дяй Сы́на и ве́руяй в Него́ и́мать живо́т ве́чный, и воскрешу́ его́ Аз в после́дний день. Ропта́ху у́бо иуде́е о Нем, я́ко рече́: Аз есмь хлеб сше́дый с небесе́. И глаго́лаху: не Сей ли есть Иису́с сын Ио́сифов, Ему́же мы зна́ем отца́ и Ма́терь? Ка́ко у́бо глаго́лет Сей, я́ко с небесе́ снидо́х? Отвеща́ у́бо Иису́с и рече́ им: не ропщи́те между́ собо́ю, никто́же мо́жет приити́ ко Мне, а́ще не Оте́ц посла́вый Мя привлече́т его́, и Аз воскрешу́ его́ в после́дний день. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: сѐ є҆́сть во́лѧ посла́вшагѡ мѧ̀, да всѧ́къ ви́дѧй сн҃а, и҆ вѣ́рꙋѧй въ него̀, и҆́мать живо́тъ вѣ́чный, и҆ воскрешꙋ̀ є҆го̀ а҆́зъ въ послѣ́днїй де́нь. ропта́хꙋ ᲂу҆́бѡ і҆ꙋде́є ѡ҆ не́мъ, ꙗ҆́кѡ речѐ: а҆́зъ є҆́смь хлѣ́бъ сше́дый съ небесѐ. и҆ глаго́лахꙋ: не се́й ли є҆́сть і҆и҃съ сы́нъ і҆ѡ́сифовъ, є҆мꙋ́же мы̀ зна́емъ ѻ҆тца̀ и҆ мт҃рь; ка́кѡ ᲂу҆́бѡ глаго́летъ се́й, ꙗ҆́кѡ съ небесѐ снидо́хъ; ѿвѣща̀ ᲂу҆́бѡ і҆и҃съ, и҆ речѐ и҆̀мъ: не ропщи́те междꙋ̀ собо́ю: никто́же мо́жетъ прїитѝ ко мнѣ̀, а҆́ще не ѻ҆ц҃ъ посла́вый мѧ̀ привлече́тъ є҆го̀, и҆ а҆́зъ воскрешꙋ̀ є҆го̀ въ послѣ́днїй де́нь. ",
}

add_evangelie_ioanna {
  ["номер"] = 23,
  ["комментарий"] = "Ин., 23 зач., VI, 48–54.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: Аз есмь хлеб живо́тный. Отцы́ ва́ши ядо́ша ма́нну в пусты́ни и умро́ша. Сей есть хлеб сходя́й с небесе́, да а́ще кто от него́ яст, не у́мрет. Аз есмь хлеб живо́тный, и́же сше́дый с небесе́, а́ще кто снесть от хле́ба сего́, жив бу́дет во ве́ки, и хлеб, его́же Аз дам, Плоть Моя́ есть, ю́же Аз дам за живо́т ми́ра. Пря́хуся же между́ собо́ю жи́дове, глаго́люще: ка́ко мо́жет Сей нам да́ти Плоть Свою́ я́сти? Рече́ же им Иису́с: ами́нь, ами́нь глаго́лю вам, а́ще не сне́сте Пло́ти Сы́на Челове́ческаго, ни пие́те Кро́ве Его́, живота́ не и́мате в себе́. Яды́й Мою́ Плоть и пия́й Мою́ Кровь и́мать живо́т ве́чный, и Аз воскрешу́ его́ в после́дний день. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: а҆́зъ є҆́смь хлѣ́бъ живо́тный. ѻ҆тцы̀ ва́ши ꙗ҆до́ша ма́ннꙋ въ пꙋсты́ни, и҆ ᲂу҆мро́ша: се́й є҆́сть хлѣ́бъ, сходѧ́й съ небесѐ, да а҆́ще кто̀ ѿ негѡ̀ ꙗ҆́стъ, не ᲂу҆́мретъ. а҆́зъ є҆́смь хлѣ́бъ живо́тный, и҆́же сше́дый съ небесѐ: а҆́ще кто̀ снѣ́сть ѿ хлѣ́ба сегѡ̀, жи́въ бꙋ́детъ во вѣ́ки: и҆ хлѣ́бъ, є҆го́же а҆́зъ да́мъ, пло́ть моѧ̀ є҆́сть, ю҆́же а҆́зъ да́мъ за живо́тъ мі́ра. прѧ́хꙋсѧ же междꙋ̀ собо́ю жи́дове, глаго́люще: ка́кѡ мо́жетъ се́й на́мъ да́ти пло́ть свою̀ ꙗ҆́сти; рече́ же и҆̀мъ і҆и҃съ: а҆ми́нь а҆ми́нь глаго́лю ва́мъ, а҆́ще не снѣ́сте пло́ти сн҃а человѣ́ческагѡ, ни пїе́те кро́ве є҆гѡ̀, живота̀ не и҆́мате въ себѣ̀. ꙗ҆ды́й мою̀ пло́ть, и҆ пїѧ́й мою̀ кро́вь, и҆́мать живо́тъ вѣ́чный: и҆ а҆́зъ воскрешꙋ̀ є҆го̀ въ послѣ́днїй де́нь. ",
}

add_evangelie_ioanna {
  ["номер"] = 24,
  ["комментарий"] = "Ин., 24 зач., VI, 56–69.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: яды́й Мою́ Плоть и пия́й Мою́ Кровь во Мне пребыва́ет, и Аз в нем. Я́коже посла́ Мя живы́й Оте́ц, и Аз живу́ Отца́ ра́ди, и яды́й Мя, и той жив бу́дет Мене́ ра́ди. Сей есть хлеб сше́дый с небесе́, не я́коже ядо́ша отцы́ ва́ши ма́нну и умро́ша, яды́й хлеб сей жив бу́дет во ве́ки. Сия́ рече́ на со́нмищи, учя́ в Капернау́ме. Мно́зи у́бо слы́шавше от учени́к Его́, ре́ша: же́стоко есть сло́во сие́, и кто мо́жет Его́ послу́шати? Ве́дый же Иису́с в Себе́, я́ко ро́пщут о сем ученицы́ Его́, рече́ им: сие́ ли вы блазни́т? А́ще у́бо у́зрите Сы́на Челове́ческаго восходя́ща, иде́же бе пре́жде? Дух есть, и́же оживля́ет, плоть не по́льзует ничто́же. Глаго́лы, я́же Аз глаго́лах вам, дух суть и живо́т суть, но суть от вас не́цыи, и́же не ве́руют. Ве́дяше бо искони́ Иису́с, кто суть неве́рующии, и кто есть предая́й Его́. И глаго́лаше: сего́ ра́ди рех вам, я́ко никто́же мо́жет приити́ ко Мне, а́ще не бу́дет ему́ дано́ от Отца́ Моего́. От сего́ мно́зи от учени́к Его́ идо́ша вспять и ктому́ не хожда́ху с Ним. Рече́ же Иису́с обемана́десяте: еда́ и вы хо́щете ити́? Отвеща́ у́бо Ему́ Си́мон Петр: Го́споди, к кому́ и́дем? Глаго́лы живота́ ве́чнаго и́маши, и мы ве́ровахом и позна́хом, я́ко Ты еси́ Христо́с, Сын Бо́га жива́го. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: ꙗ҆ды́й мою̀ пло́ть, и҆ пїѧ́й мою̀ кро́вь, во мнѣ̀ пребыва́етъ, и҆ а҆́зъ въ не́мъ. ꙗ҆́коже посла̀ мѧ̀ живы́й ѻ҆ц҃ъ, и҆ а҆́зъ живꙋ̀ ѻ҆ц҃а̀ ра́ди: и҆ ꙗ҆ды́й мѧ̀, и҆ то́й жи́въ бꙋ́детъ менѐ ра́ди. се́й є҆́сть хлѣ́бъ сше́дый съ небесѐ: не ꙗ҆́коже ꙗ҆до́ша ѻ҆тцы̀ ва́ши ма́ннꙋ, и҆ ᲂу҆мро́ша: ꙗ҆ды́й хлѣ́бъ се́й, жи́въ бꙋ́детъ во вѣ́ки. сїѧ̑ речѐ на со́нмищи, ᲂу҆чѧ̀ въ капернаꙋ́мѣ. мно́зи ᲂу҆́бѡ слы́шавше ѿ ᲂу҆чєни́къ є҆гѡ̀ рѣ́ша: же́стоко є҆́сть сло́во сїѐ, и҆ кто̀ мо́жетъ є҆гѡ̀ послꙋ́шати; вѣ́дый же і҆и҃съ въ себѣ̀, ꙗ҆́кѡ ро́пщꙋтъ ѡ҆ се́мъ ᲂу҆ченицы̀ є҆гѡ̀, речѐ и҆̀мъ: сїе́ ли вы̀ блазни́тъ; а҆́ще ᲂу҆́бѡ ᲂу҆́зрите сн҃а человѣ́ческаго восходѧ́ща, и҆дѣ́же бѣ̀ пре́жде, дх҃ъ є҆́сть и҆́же ѡ҆живлѧ́етъ: пло́ть не по́льзꙋетъ ничто́же. глаго́лы, ꙗ҆̀же а҆́зъ глаго́лахъ ва́мъ, дх҃ъ сꙋ́ть и҆ живо́тъ сꙋ́ть. но сꙋ́ть ѿ ва́съ нѣ́цыи, и҆̀же не вѣ́рꙋютъ: вѣ́дѧше бо и҆сконѝ і҆и҃съ, кто̀ сꙋ́ть невѣ́рꙋющїи, и҆ кто̀ є҆́сть предаѧ́й є҆го̀. и҆ глаго́лаше: сегѡ̀ ра́ди рѣ́хъ ва́мъ, ꙗ҆́кѡ никто́же мо́жетъ прїитѝ ко мнѣ̀, а҆́ще не бꙋ́детъ є҆мꙋ̀ дано̀ ѿ ѻ҆ц҃а̀ моегѡ̀. ѿ сегѡ̀ мно́зи ѿ ᲂу҆чєни́къ є҆гѡ̀ и҆до́ша вспѧ́ть, и҆ ктомꙋ̀ не хожда́хꙋ съ ни́мъ. рече́ же і҆и҃съ ѻ҆бѣмана́десѧте: є҆да̀ и҆ вы̀ хо́щете и҆тѝ; ѿвѣща̀ ᲂу҆́бѡ є҆мꙋ̀ сі́мѡнъ пе́тръ: гдⷭ҇и, къ комꙋ̀ и҆́демъ; глаго́лы живота̀ вѣ́чнагѡ и҆́маши. и҆ мы̀ вѣ́ровахомъ и҆ позна́хомъ, ꙗ҆́кѡ ты̀ є҆сѝ хрⷭ҇то́съ сн҃ъ бг҃а жива́гѡ. ",
}

add_evangelie_ioanna {
  ["номер"] = 25,
  ["комментарий"] = "Ин., 25 зач., VII, 1–13.",
  ["текст_ру"] = "Во вре́мя о́но, хожда́ше Иису́с по сих в Галиле́и, не хотя́ше бо во Иуде́и ходи́ти, я́ко иска́ху Его́ иуде́е уби́ти. Бе же близ пра́здник иуде́йский, потче́ние се́ни. Ре́ша же к Нему́ бра́тия Его́: прейди́ отсю́ду, и иди́ во Иуде́ю, да и ученицы́ Твои́ ви́дят дела́ Твоя́, я́же твори́ши. Никто́же бо в та́йне ничесо́же твори́т, и и́щет сам я́ве бы́ти, а́ще сия́ твори́ши, яви́ Себе́ ми́рови. Ни бра́тия бо Его́ ве́роваху в Него́. Глаго́ла у́бо им Иису́с: вре́мя Мое́ не у прии́де, вре́мя же ва́ше всегда́ гото́во есть. Не мо́жет мир ненави́дети вас, Мене́ же ненави́дит, я́ко Аз свиде́тельствую о нем, я́ко дела́ Его́ зла суть. Вы взы́дите в пра́здник сей, Аз не взы́ду в пра́здник сей, я́ко вре́мя Мое́ не у испо́лнися. Сия́ рек им, оста́ в Галиле́и. Егда́ же взыдо́ша бра́тия Его́ в пра́здник, тогда́ и Сам взы́де, не я́ве, но я́ко тай. Жи́дове же иска́ху Его́ в пра́здник и глаго́лаху: где есть Он? И ро́пот мног бе о Нем в наро́дех, о́вии глаго́лаху, я́ко благ есть. Ини́и же глаго́лаху: ни, но льстит наро́ды. Ни кото́рый же у́бо я́ве глаго́лаше о Нем, стра́ха ра́ди иуде́йскаго. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, хожда́ше і҆и҃съ по си́хъ въ галїле́и: не хотѧ́ше бо во і҆ꙋде́и ходи́ти, ꙗ҆́кѡ и҆ска́хꙋ є҆го̀ і҆ꙋде́є ᲂу҆би́ти. бѣ́ же бли́зъ пра́здникъ і҆ꙋде́йскїй, потче́нїе сѣ́ни. рѣ́ша же къ немꙋ̀ бра́тїѧ є҆гѡ̀: прейдѝ ѿсю́дꙋ, и҆ и҆дѝ во і҆ꙋде́ю, да и҆ ᲂу҆ченицы̀ твоѝ ви́дѧтъ дѣла̀ твоѧ̀, ꙗ҆̀же твори́ши. никто́же бо въ та́йнѣ ничесо́же твори́тъ, и҆ и҆́щетъ са́мъ ꙗ҆́вѣ бы́ти: а҆́ще сїѧ̑ твори́ши, ꙗ҆вѝ себѐ мі́рови. ни бра́тїѧ бо є҆гѡ̀ вѣ́ровахꙋ въ него̀. глаго́ла ᲂу҆́бѡ и҆̀мъ і҆и҃съ: вре́мѧ моѐ не ᲂу҆̀ прїи́де, вре́мѧ же ва́ше всегда̀ гото́во є҆́сть. не мо́жетъ мі́ръ ненави́дѣти ва́съ: мене́ же ненави́дитъ, ꙗ҆́кѡ а҆́зъ свидѣ́тельствꙋю ѡ҆ не́мъ, ꙗ҆́кѡ дѣла̀ є҆гѡ̀ ѕла̀ сꙋ́ть. вы̀ взы́дите въ пра́здникъ се́й: а҆́зъ не взы́дꙋ въ пра́здникъ се́й, ꙗ҆́кѡ вре́мѧ моѐ не ᲂу҆̀ и҆спо́лнисѧ. сїѧ̑ ре́къ и҆̀мъ, ѡ҆ста̀ въ галїле́и. є҆гда́ же взыдо́ша бра́тїѧ є҆гѡ̀ въ пра́здникъ, тогда̀ и҆ са́мъ взы́де, не ꙗ҆́вѣ, но ꙗ҆́кѡ та́й. жи́довє же и҆ска́хꙋ є҆го̀ въ пра́здникъ, и҆ глаго́лахꙋ: гдѣ̀ є҆́сть ѻ҆́нъ; и҆ ро́потъ мно́гъ бѣ̀ ѡ҆ не́мъ въ наро́дѣхъ. ѻ҆́вїи глаго́лахꙋ, ꙗ҆́кѡ бла́гъ є҆́сть: и҆ні́и же глаго́лахꙋ: нѝ, но льсти́тъ наро́ды. ни кото́рый же ᲂу҆́бѡ ꙗ҆́вѣ глаго́лаше ѡ҆ не́мъ, стра́ха ра́ди і҆ꙋде́йскагѡ. ",
}

add_evangelie_ioanna {
  ["номер"] = 26,
  ["комментарий"] = "Ин., 26 зач., VII, 14–30.",
  ["текст_ру"] = "В преполове́ние Пятьдеся́тницы взы́де Иису́с во це́рковь и уча́ше. И дивля́хуся иуде́е, глаго́люще: ка́ко Сей кни́ги весть не учи́вся? Отвеща́ у́бо им Иису́с и рече́: Мое́ уче́ние несть Мое́, но Посла́вшаго Мя. А́ще кто хо́щет во́лю Его́ твори́ти, разуме́ет о уче́нии, ко́е от Бо́га есть, или́ Аз о Себе́ глаго́лю. Глаго́ляй о себе́ сла́вы своея́ и́щет, а Ищя́й сла́вы Посла́вшаго Его́, Сей и́стинен есть, и несть непра́вды в Нем. Не Моисе́й ли даде́ вам зако́н? И никто́же от вас твори́т зако́на. Что Мене́ и́щете уби́ти? Отвеща́ наро́д и рече́: бе́са ли и́маши? Кто Тебе́ и́щет уби́ти? Отвеща́ Иису́с и рече́ им: еди́но де́ло сотвори́х, и вси дивите́ся. Сего́ ра́ди Моисе́й даде́ вам обре́зание, не я́ко от Моисе́а есть, но от оте́ц, и в суббо́ту обре́заете челове́ка. А́ще обре́зание прие́млет челове́к в суббо́ту, да не разори́тся зако́н Моисе́ов, на Мя ли гне́ваетеся, я́ко всего́ челове́ка здра́ва сотвори́х в суббо́ту? Не суди́те на лица́, но пра́ведный суд суди́те. Глаго́лаху у́бо не́цыи от Иерусали́млян: не Сей ли есть, Его́же и́щут уби́ти? И се не обину́яся глаго́лет, и ничесо́же Ему́ не глаго́лют, еда́ ка́ко разуме́ша кня́зи, я́ко Сей есть Христо́с? Но Сего́ ве́мы, отку́ду есть, Христо́с же егда́ прии́дет, никто́же весть, отку́ду бу́дет. Воззва́ у́бо в це́ркви учя́ Иису́с и глаго́ля: и Мене́ ве́сте, и ве́сте, отку́ду есмь, и о Себе́ не приидо́х, но есть и́стинен Посла́вый Мя, Его́же вы не ве́сте. Аз вем Его́, я́ко от Него́ есмь, и Той Мя посла́. Иска́ху же да и́мут Его́, и никто́же возложи́ Нань руки́, я́ко не у бе прише́л час Его́. ",
  ["текст_цс"] = "Въ преполове́нїе пѧтьдесѧ́тницы взы́де і҆и҃съ во це́рковь, и҆ ᲂу҆ча́ше. и҆ дивлѧ́хꙋсѧ і҆ꙋде́є, глаго́люще: ка́кѡ се́й кни́ги вѣ́сть, не ᲂу҆чи́всѧ; ѿвѣща̀ ᲂу҆́бѡ и҆̀мъ і҆и҃съ, и҆ речѐ: моѐ ᲂу҆че́нїе нѣ́сть моѐ, но посла́вшагѡ мѧ̀. а҆́ще кто̀ хо́щетъ во́лю є҆гѡ̀ твори́ти, разꙋмѣ́етъ ѡ҆ ᲂу҆че́нїи, ко́е ѿ бг҃а є҆́сть: и҆лѝ а҆́зъ ѡ҆ себѣ̀ глаго́лю. глаго́лѧй ѡ҆ себѣ̀, сла́вы своеѧ̀ и҆́щетъ: а҆ и҆щѧ́й сла́вы посла́вшагѡ є҆го̀, се́й и҆́стиненъ є҆́сть, и҆ нѣ́сть непра́вды въ не́мъ. не мѡѷсе́й ли дадѐ ва́мъ зако́нъ; и҆ никто́же ѿ ва́съ твори́тъ зако́на. что̀ менѐ и҆́щете ᲂу҆би́ти; ѿвѣща̀ наро́дъ и҆ речѐ: бѣ́са ли и҆́маши; кто̀ тебѐ и҆́щетъ ᲂу҆би́ти; ѿвѣща̀ і҆и҃съ, и҆ речѐ и҆̀мъ: є҆ди́но дѣ́ло сотвори́хъ, и҆ всѝ дивите́сѧ. сегѡ̀ ра́ди мѡѷсе́й дадѐ ва́мъ ѡ҆брѣ́занїе, не ꙗ҆́кѡ ѿ мѡѷсе́а є҆́сть, но ѿ ѻ҆тє́цъ, и҆ въ сꙋббѡ́тꙋ ѡ҆брѣ́заете человѣ́ка. а҆́ще ѡ҆брѣ́занїе прїе́млетъ человѣ́къ въ сꙋббѡ́тꙋ, да не разори́тсѧ зако́нъ мѡѷсе́овъ: на мѧ́ ли гнѣ́ваетесѧ, ꙗ҆́кѡ всего̀ человѣ́ка здра́ва сотвори́хъ въ сꙋббѡ́тꙋ; не сꙋди́те на лица̀, но пра́ведный сꙋ́дъ сꙋди́те. глаго́лахꙋ ᲂу҆́бѡ нѣ́цыи ѿ і҆ерꙋсали́млѧнъ: не се́й ли є҆́сть, є҆го́же и҆́щꙋтъ ᲂу҆би́ти; и҆ сѐ не ѡ҆бинꙋ́ѧсѧ глаго́летъ, и҆ ничесѡ́же є҆мꙋ̀ не глаго́лютъ: є҆да̀ ка́кѡ разꙋмѣ́ша кнѧ́зи, ꙗ҆́кѡ се́й є҆́сть хрⷭ҇то́съ; но сего̀ вѣ́мы, ѿкꙋ́дꙋ є҆́сть: хрⷭ҇то́съ же є҆гда̀ прїи́детъ, никто́же вѣ́сть, ѿкꙋ́дꙋ бꙋ́детъ. воззва̀ ᲂу҆́бѡ въ це́ркви ᲂу҆чѧ̀ і҆и҃съ, и҆ глаго́лѧ: и҆ менѐ вѣ́сте, и҆ вѣ́сте ѿкꙋ́дꙋ є҆́смь, и҆ ѡ҆ себѣ̀ не прїидо́хъ: но є҆́сть и҆́стиненъ посла́вый мѧ̀, є҆гѡ́же вы̀ не вѣ́сте. а҆́зъ вѣ́мъ є҆го̀, ꙗ҆́кѡ ѿ негѡ̀ є҆́смь, и҆ то́й мѧ̀ посла̀. и҆ска́хꙋ же да и҆́мꙋтъ є҆го̀: и҆ никто́же возложѝ на́нь рꙋкѝ, ꙗ҆́кѡ не ᲂу҆̀ бѣ̀ прише́лъ ча́съ є҆гѡ̀. ",
}

add_evangelie_ioanna {
  ["номер"] = 27,
  ["комментарий"] = "Ин., 27 зач., VII, 37–52; VIII, 12.",
  ["текст_ру"] = "В после́дний день вели́кий пра́здника стоя́ше Иису́с и зва́ше, глаго́ля: а́ще кто жа́ждет, да прии́дет ко Мне и пие́т. Ве́руяй в Мя, я́коже рече́ Писа́ние, ре́ки от чре́ва его́ истеку́т воды́ жи́вы. Сие́ же рече́ о Ду́се Его́же хотя́ху приима́ти ве́рующии во и́мя Его́, не у бо бе Дух Святы́й, я́ко Иису́с не у бе просла́влен. Мно́зи же от наро́да слы́шавше сло́во, глаго́лаху: Сей есть вои́стинну проро́к. Друзи́и глаго́лаху: Сей есть Христо́с. О́вии же глаго́лаху: еда́ от Галиле́и Христо́с прихо́дит? Не Писа́ние ли рече́, я́ко от се́мене Дави́дова и от Вифлее́мския ве́си, иде́же бе Дави́д, Христо́с прии́дет? Ра́спря у́бо бысть в наро́де Его́ ра́ди. Не́цыи же от них хотя́ху я́ти Его́, но никто́же возложи́ Нань ру́це. Приидо́ша же слуги́ ко архиере́ом и фарисе́ом, и ре́ша им ти́и: почто́ не приведо́сте Его́? Отвеща́ша слуги́: николи́же та́ко есть глаго́лал челове́к, я́ко Сей Челове́к. Отвеща́ша у́бо им фарисе́е: еда́ и вы прельще́ни бы́сте? Еда́ кто от князь ве́рова в Онь, или́ от фарисе́й? Но наро́д сей, и́же не весть зако́на, про́кляти суть. Глаго́ла Никоди́м к ним, и́же прише́дый к Нему́ но́щию, еди́н сый от них: еда́ зако́н наш су́дит челове́ку, а́ще не слы́шит от него́ пре́жде и разуме́ет, что твори́т? Отвеща́ша и реко́ша ему́: еда́ и ты от Галиле́и еси́? Испыта́й и виждь, я́ко проро́к от Галиле́и не прихо́дит. Па́ки же им Иису́с рече́ глаго́ля: Аз есмь свет ми́ру, ходя́й по Мне не и́мать ходи́ти во тме, но и́мать свет живо́тный. ",
  ["текст_цс"] = "Въ послѣ́днїй де́нь вели́кїй пра́здника стоѧ́ше і҆и҃съ, и҆ зва́ше глаго́лѧ: а҆́ще кто̀ жа́ждетъ, да прїи́детъ ко мнѣ̀, и҆ пїе́тъ. вѣ́рꙋѧй въ мѧ̀, ꙗ҆́коже речѐ писа́нїе, рѣ́ки ѿ чре́ва є҆гѡ̀ и҆стекꙋ́тъ воды̀ жи́вы. сїе́ же речѐ ѡ҆ дс҃ѣ, є҆го́же хотѧ́хꙋ прїима́ти вѣ́рꙋющїи во и҆́мѧ є҆гѡ̀: не ᲂу҆́ бо бѣ̀ дх҃ъ ст҃ы́й, ꙗ҆́кѡ і҆и҃съ не ᲂу҆̀ бѣ̀ просла́вленъ. мно́зи же ѿ наро́да слы́шавше сло́во, глаго́лахꙋ: се́й є҆́сть вои́стиннꙋ проро́къ. дрꙋзі́и глаго́лахꙋ: се́й є҆́сть хрⷭ҇то́съ. ѻ҆́вїи же глаго́лахꙋ: є҆да̀ ѿ галїле́и хрⷭ҇то́съ прихо́дитъ; не писа́нїе ли речѐ, ꙗ҆́кѡ ѿ сѣ́мене даві́дова, и҆ ѿ виѳлее́мскїѧ ве́си, и҆дѣ́же бѣ̀ даві́дъ, хрⷭ҇то́съ прїи́детъ; ра́спрѧ же бы́сть въ наро́дѣ є҆гѡ̀ ра́ди. нѣ́цыи же ѿ ни́хъ хотѧ́хꙋ ꙗ҆́ти є҆го̀: но никто́же возложѝ на́нь рꙋ́цѣ. прїидо́ша же слꙋгѝ ко а҆рхїере́ѡмъ и҆ фарїсе́ѡмъ: и҆ рѣ́ша и҆̀мъ ті́и: почто̀ не приведо́сте є҆гѡ̀; ѿвѣща́ша слꙋгѝ: николи́же та́кѡ є҆́сть глаго́лалъ человѣ́къ, ꙗ҆́кѡ се́й человѣ́къ. ѿвѣща́ша ᲂу҆́бѡ и҆̀мъ фарїсе́є: є҆да̀ и҆ вы̀ прельще́ни бы́сте. є҆да̀ кто̀ ѿ кнѧ̑зь вѣ́рова въ ѻ҆́нь, и҆лѝ ѿ фарїсє́й; но наро́дъ се́й, и҆́же не вѣ́сть зако́на, про́клѧти сꙋ́ть. глаго́ла нїкоди́мъ къ ни́мъ, и҆́же прише́дый къ немꙋ̀ но́щїю, є҆ди́нъ сы́й ѿ ни́хъ: є҆да̀ зако́нъ на́шъ сꙋ́дитъ человѣ́кꙋ, а҆́ще не слы́шитъ ѿ негѡ̀ пре́жде, и҆ разꙋмѣ́етъ что̀ твори́тъ; ѿвѣща́ша и҆ реко́ша є҆мꙋ̀: є҆да̀ и҆ ты̀ ѿ галїле́и є҆сѝ, и҆спыта́й и҆ ви́ждь, ꙗ҆́кѡ проро́къ ѿ галїле́и не прихо́дитъ. па́ки же и҆̀мъ і҆и҃съ речѐ, глаго́лѧ: а҆́зъ є҆́смь свѣ́тъ мі́рꙋ. ходѧ́й по мнѣ̀ не и҆́мать ходи́ти во тмѣ̀, но и҆́мать свѣ́тъ живо́тный. ",
}

add_evangelie_ioanna {
  ["номер"] = 28,
  ["комментарий"] = "Ин., 28 зач., VIII, 3-11.",
  ["текст_ру"] = "Во вре́мя о́но, приведо́ша ко Иису́су кни́жницы и фарисе́е жену́, в прелюбодея́нии я́ту, и поста́виша ю́ посреде́, глаго́лаша Ему́: Учи́телю, сия́ жена́ я́та есть ны́не в прелюбодея́нии. В зако́не же нам Моисе́й повеле́ таковы́я ка́мением побива́ти, Ты же что глаго́леши? Сие́ же ре́ша искуша́юще Его́, да бы́ша име́ли что глаго́лати Нань. Иису́с же до́лу прекло́нься, пе́рстом писа́ше на земли́, не слага́я им. Я́коже прилежа́ху вопроша́юще Его́, воскло́нься рече́ к ним: и́же есть без греха́ в вас, пре́жде ве́рзи ка́мень на ню. И па́ки до́лу прекло́нься, писа́ше на земли́. Они́ же слы́шавше и со́вестию облича́еми, исхожда́ху еди́н по еди́ному, наче́нше от ста́рец до после́дних, и оста́ еди́н Иису́с, и жена́ посреде́ су́щи. Воскло́нься же Иису́с и ни еди́наго ви́дев, то́чию жену́, рече́ ей: же́но, где суть, и́же важда́ху на тя? Ники́йже ли тебе́ осуди́? Она́ же рече́: никто́же, Го́споди. Рече́ же ей Иису́с: ни Аз тебе́ осужда́ю, иди́ и отсе́ле ктому́ не согреша́й. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, приведо́ша ко і҆и҃сꙋ кни́жницы и҆ фарїсе́є женꙋ̀, въ прелюбодѣѧ́нїи ꙗ҆́тꙋ, и҆ поста́виша ю҆̀ посредѣ̀. глаго́лаша є҆мꙋ̀: ᲂу҆чи́телю, сїѧ̀ жена̀ ꙗ҆́та є҆́сть ны́нѣ къ прелюбодѣѧ́нїи. въ зако́нѣ же на́мъ мѡѷсе́й повелѣ̀ такѡвы́ѧ ка́менїемъ побива́ти: ты́ же что̀ глаго́леши; сїе́ же рѣ́ша и҆скꙋша́юще є҆го̀, да бы́ша и҆мѣ́ли что̀ глаго́лати на́нь. і҆и҃съ же до́лꙋ прекло́ньсѧ, пе́рстомъ писа́ше на землѝ, не слага́ѧ и҆̀мъ. ꙗ҆́коже прилѣжа́хꙋ вопроша́юще є҆го̀, воскло́ньсѧ речѐ къ ни́мъ: и҆́же є҆́сть без̾ грѣха̀ въ ва́съ, пре́жде ве́рзи ка́мень на ню̀. и҆ па́ки до́лꙋ прекло́ньсѧ, писа́ше на землѝ. ѻ҆ни́ же слы́шавше, и҆ со́вѣстїю ѡ҆блича́еми и҆схожда́хꙋ є҆ди́нъ по є҆ди́номꙋ, наче́нше ѿ ста́рєцъ до послѣ́днихъ: и҆ ѡ҆ста̀ є҆ди́нъ і҆и҃съ, и҆ жена̀ посредѣ̀ сꙋ́щи. воскло́ньсѧ же і҆и҃съ, и҆ ни є҆ди́нагѡ ви́дѣвъ, то́чїю женꙋ̀, речѐ є҆́й: же́но, гдѣ̀ сꙋ́ть, и҆̀же важда́хꙋ на тѧ̀; никі́йже ли тебѐ ѡ҆сꙋдѝ; ѻ҆на́ же речѐ: никто́же гдⷭ҇и. рече́ же є҆́й і҆и҃съ: ни а҆́зъ тебѐ ѡ҆сꙋжда́ю: и҆дѝ, и҆ ѿсе́лѣ ктомꙋ̀ не согрѣша́й. ",
}

add_evangelie_ioanna {
  ["номер"] = 29,
  ["комментарий"] = "Ин., 29 зач., VIII, 12–20.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: Аз есмь свет ми́ру, ходя́й по Мне не и́мать ходи́ти во тме, но и́мать свет живо́тный. Ре́ша у́бо Ему́ фарисе́е: Ты о Себе́ Сам свиде́тельствуеши, свиде́тельство Твое́ несть и́стинно. Отвеща́ Иису́с и рече́ им: а́ще Аз свиде́тельствую о Себе́, и́стинно есть свиде́тельство Мое́, я́ко вем, отку́ду приидо́х и ка́мо иду́, вы же не ве́сте, отку́ду прихожду́ и ка́мо гряду́. Вы по пло́ти су́дите, Аз не сужду́ никому́же. И а́ще сужду́ Аз, суд Мой и́стинен есть, я́ко еди́н несмь, но Аз и посла́вый Мя Оте́ц. И в зако́не же ва́шем пи́сано есть, я́ко двою́ челове́ку свиде́тельство и́стинно есть. Аз есмь свиде́тельствуяй о Мне Само́м, и свиде́тельствует о Мне посла́вый Мя Оте́ц. Глаго́лаху же Ему́: где есть Оте́ц Твой? Отвеща́ Иису́с: ни Мене́ ве́сте, ни Отца́ Моего́, а́ще Мя бы́сте ве́дали, и Отца́ Моего́ ве́дали бы́сте. Сия́ глаго́лы глаго́ла Иису́с в газофилаки́и, учя́ в це́ркви, и никто́же ят Его́, я́ко не у бе прише́л час Его́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: а҆́зъ є҆́смь свѣ́тъ мі́рꙋ. ходѧ́й по мнѣ̀, не и҆́мать ходи́ти во тмѣ̀, но и҆́мать свѣ́тъ живо́тный. рѣ́ша же є҆мꙋ̀ фарїсе́є: ты̀ ѡ҆ себѣ̀ са́мъ свидѣ́тельствꙋеши: свидѣ́тельство твоѐ нѣ́сть и҆́стинно. ѿвѣща̀ і҆и҃съ и҆ речѐ и҆̀мъ: а҆́ще а҆́зъ свидѣ́тельствꙋю ѡ҆ себѣ̀, и҆́стинно є҆́сть свидѣ́тельство моѐ: ꙗ҆́кѡ вѣ́мъ, ѿкꙋ́дꙋ прїидо́хъ, и҆ ка́мѡ и҆дꙋ̀. вы́ же не вѣ́сте, ѿкꙋ́дꙋ прихождꙋ̀, и҆ ка́мѡ грѧдꙋ̀. вы̀ по пло́ти сꙋ́дите: а҆́зъ не сꙋждꙋ̀ никомꙋ́же. и҆ а҆́ще сꙋждꙋ̀ а҆́зъ, сꙋ́дъ мо́й и҆́стиненъ є҆́сть: ꙗ҆́кѡ є҆ди́нъ нѣ́смь, но а҆́зъ и҆ посла́вый мѧ̀ ѻ҆ц҃ъ. и҆ въ зако́нѣ же ва́шемъ пи́сано є҆́сть, ꙗ҆́кѡ двою̀ человѣ́кꙋ свидѣ́тельство и҆́стинно є҆́сть. а҆́зъ є҆́смь свидѣ́тельствꙋѧй ѡ҆ мнѣ̀ само́мъ, и҆ свидѣ́тельствꙋетъ ѡ҆ мнѣ̀ посла́вый мѧ̀ ѻ҆ц҃ъ. глаго́лахꙋ же є҆мꙋ̀: гдѣ̀ є҆́сть ѻ҆ц҃ъ тво́й; ѿвѣща̀ і҆и҃съ: ни менѐ вѣ́сте, ни ѻ҆ц҃а̀ моегѡ̀: а҆́ще мѧ̀ бы́сте вѣ́дали, и҆ ѻ҆ц҃а̀ моего̀ вѣ́дали бы́сте. сїѧ̑ глаго́лы глаго́ла і҆и҃съ въ газофѷлакі́и, ᲂу҆чѧ̀ въ це́ркви, и҆ никто́же ꙗ҆́тъ є҆го̀, ꙗ҆́кѡ не ᲂу҆̀ бѣ̀ прише́лъ ча́съ є҆гѡ̀. ",
}

add_evangelie_ioanna {
  ["номер"] = 30,
  ["комментарий"] = "Ин., 30 зач., VIII, 21–30.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: Аз иду, и взы́щете Мене́, и во гресе́ ва́шем у́мрете, а́може Аз иду́, вы не мо́жете приити́. Глаго́лаху у́бо иуде́е: еда́ Ся Сам убие́т, я́ко глаго́лет, а́може Аз иду́, вы не мо́жете приити́? И рече́ им: вы от ни́жних есте́, Аз от вы́шних есмь, вы от ми́ра сего́ есте́, Аз несмь от ми́ра сего́. Рех у́бо вам, я́ко у́мрете во гресе́х ва́ших, а́ще бо не и́мете ве́ры, я́ко Аз есмь, у́мрете во гресе́х ва́ших. Глаго́лаху у́бо Ему́: Ты кто еси́? И рече́ им Иису́с: Нача́ток, я́ко и глаго́лю вам. Мно́га и́мам о вас глаго́лати и суди́ти, но Посла́вый Мя и́стинен есть, и Аз, я́же слы́шах от Него́, сия́ глаго́лю в ми́ре. Не разуме́ша у́бо, я́ко Отца́ им глаго́лаше. Рече́ же им Иису́с: егда́ вознесе́те Сы́на Челове́ческаго, тогда́ разуме́ете, я́ко Аз есмь, и о Себе́ ничесо́же творю́, но я́коже научи́ Мя Оте́ц Мой, сия́ глаго́лю. И посла́вый Мя со Мно́ю есть, не оста́ви Мене́ еди́наго Оте́ц, я́ко Аз уго́дная Ему́ всегда́ творю́. Сия́ Ему́ глаго́лющу, мно́зи ве́роваша в Него́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: а҆́зъ и҆дꙋ̀, и҆ взы́щете менѐ, и҆ во грѣсѣ̀ ва́шемъ ᲂу҆́мрете: а҆́може а҆́зъ и҆дꙋ̀, вы̀ не мо́жете прїитѝ. глаго́лахꙋ ᲂу҆́бѡ і҆ꙋде́є: є҆да́ сѧ са́мъ ᲂу҆бїе́тъ, ꙗ҆́кѡ глаго́летъ: а҆́може а҆́зъ и҆дꙋ̀, вы̀ не мо́жете прїитѝ; и҆ речѐ и҆̀мъ: вы̀ ѿ ни́жнихъ є҆стѐ, а҆́зъ ѿ вы́шнихъ є҆́смь: вы̀ ѿ мі́ра сегѡ̀ є҆стѐ, а҆́зъ нѣ́смь ѿ мі́ра сегѡ̀. рѣ́хъ ᲂу҆́бѡ ва́мъ, ꙗ҆́кѡ ᲂу҆́мрете во грѣсѣ́хъ ва́шихъ: а҆́ще бо не и҆́мете вѣ́ры, ꙗ҆́кѡ а҆́зъ є҆́смь, ᲂу҆́мрете во грѣсѣ́хъ ва́шихъ. глаго́лахꙋ же є҆мꙋ̀: ты̀ кто̀ є҆сѝ; и҆ речѐ и҆̀мъ і҆и҃съ: нача́токъ, ꙗ҆́кѡ и҆ глаго́лю ва́мъ. мнѡ́га и҆́мамъ ѡ҆ ва́съ глаго́лати и҆ сꙋди́ти, но посла́вый мѧ̀ и҆́стиненъ є҆́сть и҆ а҆́зъ, ꙗ҆̀же слы́шахъ ѿ негѡ̀, сїѧ̑ глаго́лю въ мі́рѣ. не разꙋмѣ́ша ᲂу҆́бѡ, ꙗ҆́кѡ ѻ҆ц҃а̀ и҆̀мъ глаго́лаше. рече́ же и҆̀мъ і҆и҃съ: є҆гда̀ вознесе́те сн҃а человѣ́ческаго, тогда̀ разꙋмѣ́ете, ꙗ҆́кѡ а҆́зъ є҆́смь, и҆ ѡ҆ себѣ̀ ничесо́же творю̀: но ꙗ҆́коже наꙋчи́ мѧ ѻ҆ц҃ъ мо́й, сїѧ̑ глаго́лю. и҆ посла́вый мѧ̀, со мно́ю є҆́сть: не ѡ҆ста́ви менѐ є҆ди́наго ѻ҆ц҃ъ, ꙗ҆́кѡ а҆́зъ ᲂу҆гѡ́днаѧ є҆мꙋ̀ всегда̀ творю̀. сїѧ̑ є҆мꙋ̀ глаго́лющꙋ, мно́зи вѣ́роваша въ него̀. ",
}

add_evangelie_ioanna {
  ["номер"] = 31,
  ["комментарий"] = "Ин., 31 зач., VIII, 31–42.",
  ["текст_ру"] = "Рече́ Госпо́дь к ве́ровавшым к Нему́ иуде́ем: а́ще вы пребу́дете во словеси́ Мое́м, вои́стинну ученицы́ Мои́ бу́дете и уразуме́ете и́стину, и и́стина свободи́т вы. Отвеща́ша и ре́ша Ему́: се́мя Авраа́мле есмы́ и никому́же рабо́тахом николи́же, ка́ко Ты глаго́леши, я́ко свобо́дни бу́дете? Отвеща́ им Иису́с: ами́нь, ами́нь глаго́лю вам, я́ко всяк творя́й грех раб есть греха́, раб же не пребыва́ет в дому́ во век, сын пребыва́ет во век. А́ще у́бо Сын вы свободи́т, вои́стинну свобо́дни бу́дете. Вем, я́ко се́мя Авраа́мле есте́, но и́щете Мене́ уби́ти, я́ко сло́во Мое́ не вмеща́ется в вы. Аз, е́же ви́дех у Отца́ Моего́, глаго́лю, и вы у́бо, е́же ви́десте у отца́ ва́шего, творите́. Отвеща́ша и ре́ша Ему́: оте́ц наш Авраа́м есть. Глаго́ла им Иису́с: а́ще ча́да Авраа́мля бы́сте бы́ли, дела́ Авраа́мля бы́сте твори́ли, ны́не же и́щете Мене́ уби́ти, Челове́ка, и́же и́стину вам глаго́лах, ю́же слы́шах от Бо́га, сего́ Авраа́м несть сотвори́л, вы творите́ дела́ отца́ ва́шего. Ре́ша же Ему́: мы от любодея́ния не́смы рожде́ни, еди́наго Отца́ и́мамы, Бо́га. Рече́ же им Иису́с: а́ще Бог Оте́ц ваш бы был, люби́ли бы́сте у́бо Мене́, Аз бо от Бо́га изыдо́х и приидо́х. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: къ вѣ́ровавшымъ къ немꙋ̀ і҆ꙋде́ємъ: а҆́ще вы̀ пребꙋ́дете во словесѝ мое́мъ, вои́стиннꙋ ᲂу҆ченицы̀ моѝ бꙋ́дете: и҆ разꙋмѣ́ете и҆́стинꙋ, и҆ и҆́стина свободи́тъ вы̀. ѿвѣща́ша и҆ рѣ́ша є҆мꙋ̀: сѣ́мѧ а҆враа́мле є҆смы̀, и҆ никомꙋ́же рабо́тахомъ николи́же: ка́кѡ ты̀ глаго́леши, ꙗ҆́кѡ свобо́дни бꙋ́дете; ѿвѣща̀ и҆̀мъ і҆и҃съ: а҆ми́нь а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ всѧ́къ творѧ́й грѣ́хъ, ра́бъ є҆́сть грѣха̀. ра́бъ же не пребыва́етъ въ домꙋ̀ во вѣ́къ: сн҃ъ пребыва́етъ во вѣ́къ. а҆́ще ᲂу҆́бѡ сн҃ъ вы̀ свободи́тъ, вои́стиннꙋ свобо́дни бꙋ́дете. вѣ́мъ, ꙗ҆́кѡ сѣ́мѧ а҆враа́мле є҆стѐ, но и҆́щете менѐ ᲂу҆би́ти, ꙗ҆́кѡ сло́во моѐ не вмѣща́етсѧ въ вы̀. а҆́зъ є҆́же ви́дѣхъ ᲂу҆ ѻ҆ц҃а̀ моегѡ̀, глаго́лю: и҆ вы̀ ᲂу҆́бѡ є҆́же ви́дѣсте ᲂу҆ ѻ҆тца̀ ва́шегѡ, творитѐ. ѿвѣща́ша и҆ рѣ́ша є҆мꙋ̀: ѻ҆ц҃ъ на́шъ а҆враа́мъ є҆́сть. глаго́ла и҆̀мъ і҆и҃съ: а҆́ще ча̑да а҆враа́млѧ бы́сте бы́ли, дѣла̀ а҆враа́млѧ бы́сте твори́ли. ны́нѣ же и҆́щете менѐ ᲂу҆би́ти, человѣ́ка, и҆́же и҆́стинꙋ ва́мъ глаго́лахъ, ю҆́же слы́шахъ ѿ бг҃а: сегѡ̀ а҆враа́мъ нѣ́сть сотвори́лъ. вы̀ творитѐ дѣла̀ ѻ҆тца̀ ва́шегѡ. рѣ́ша же є҆мꙋ̀: мы̀ ѿ любодѣѧ́нїѧ нѣ́смы рожде́ни, є҆ди́наго ѻ҆ц҃а̀ и҆́мамы бг҃а. рече́ же и҆̀мъ і҆и҃съ: а҆́ще бг҃ъ ѻ҆ц҃ъ ва́шъ бы̀ бы́лъ, люби́ли бы́сте ᲂу҆́бѡ менѐ, а҆́зъ бо ѿ бг҃а и҆зыдо́хъ, и҆ прїидо́хъ. ",
}

add_evangelie_ioanna {
  ["номер"] = 32,
  ["комментарий"] = "Ин., 32 зач., VIII, 42–51.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: а́ще Бог Оте́ц ваш бы был, люби́ли бы́сте у́бо Мене́, Аз бо от Бо́га изыдо́х и приидо́х. Не о Себе́ бо приидо́х, но Той Мя посла́, почто́ бесе́ды Моея́ не разуме́ете? Я́ко не мо́жете слы́шати словесе́ Моего́, вы отца́ ва́шего диа́вола есте́, и по́хоти отца́ ва́шего хо́щете твори́ти. Он человекоуби́йца бе искони́ и во и́стине не стои́т, я́ко несть и́стины в нем, егда́ глаго́лет лжу, от свои́х глаго́лет, я́ко ложь есть и оте́ц лжи. Аз же зане́ и́стину глаго́лю, не ве́руете Мне, кто от вас облича́ет Мя о гресе́? А́ще ли и́стину глаго́лю, почто́ вы не ве́руете Мне? И́же есть от Бо́га, глаго́лы Бо́жия послу́шает, сего́ ра́ди вы не послу́шаете, я́ко от Бо́га не́сте. Отвеща́ша же иуде́е и ре́ша Ему́: не до́бре ли мы глаго́лем, я́ко самаряни́н еси́ Ты и бе́са и́маши? Отвеща́ Иису́с: Аз бе́са не и́мам, но чту Отца́ Моего́, и вы не чте́те Мене́. Аз же не ищу́ сла́вы Моея́, есть Ищя́ и Судя́. Ами́нь, ами́нь глаго́лю вам, а́ще кто сло́во Мое́ соблюде́т, сме́рти не и́мать ви́дети во ве́ки. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: а҆́ще бг҃ъ ѻ҆ц҃ъ ва́шъ бы̀ бы́лъ, люби́ли бы́сте ᲂу҆́бѡ менѐ, а҆́зъ бо ѿ бг҃а и҆зыдо́хъ, и҆ прїидо́хъ. не ѡ҆ себѣ́ бо прїидо́хъ, но то́й мѧ̀ посла̀. почто̀ бесѣ́ды моеѧ̀ не разꙋмѣ́ете, ꙗ҆́кѡ не мо́жете слы́шати словесѐ моегѡ̀; вы̀ ѻ҆тца̀ ва́шегѡ дїа́вола є҆стѐ, и҆ по́хѡти ѻ҆ц҃а̀ ва́шегѡ хо́щете твори́ти. ѻ҆́нъ человѣкоꙋбі́йца бѣ̀ и҆сконѝ, и҆ во и҆́стинѣ не стои́тъ: ꙗ҆́кѡ нѣ́сть и҆́стины въ не́мъ. є҆гда̀ глаго́летъ лжꙋ̀, ѿ свои́хъ глаго́летъ, ꙗ҆́кѡ ло́жъ є҆́сть, и҆ ѻ҆те́цъ лжѝ. а҆́зъ же занѐ и҆́стинꙋ глаго́лю, не вѣ́рꙋете мнѣ̀. кто̀ ѿ ва́съ ѡ҆блича́етъ мѧ̀ ѡ҆ грѣсѣ̀; а҆́ще ли и҆́стинꙋ глаго́лю, почто̀ вы̀ не вѣ́рꙋете мнѣ̀; и҆́же є҆́сть ѿ бг҃а, глаго́лы бж҃їѧ послꙋ́шаетъ: сегѡ̀ ра́ди вы̀ не послꙋ́шаете, ꙗ҆́кѡ ѿ бг҃а нѣ́сте. ѿвѣща́ша же і҆ꙋде́є, и҆ рѣ́ша є҆мꙋ̀: не до́брѣ ли мы̀ глаго́лемъ, ꙗ҆́кѡ самарѧни́нъ є҆сѝ ты̀, и҆ бѣ́са и҆́маши; ѿвѣща̀ і҆и҃съ: а҆́зъ бѣ́са не и҆́мамъ, но чтꙋ̀ ѻ҆ц҃а̀ моего̀, и҆ вы̀ не чте́те менѐ. а҆́зъ же не и҆щꙋ̀ сла́вы моеѧ̀: є҆́сть и҆щѧ̀ и҆ сꙋдѧ̀. а҆ми́нь а҆ми́нь глаго́лю ва́мъ, а҆́ще кто̀ сло́во моѐ соблюде́тъ, сме́рти не и҆́мать ви́дѣти во вѣ́ки. ",
}

add_evangelie_ioanna {
  ["номер"] = 33,
  ["комментарий"] = "Ин., 33 зач., VIII, 51–59.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: ами́нь, ами́нь глаго́лю вам, а́ще кто сло́во Мое́ соблюде́т, сме́рти не и́мать ви́дети во ве́ки. Ре́ша у́бо Ему́ жи́дове: ны́не разуме́хом, я́ко бе́са и́маши. Авраа́м у́мре и проро́цы, и Ты глаго́леши: а́ще кто сло́во Мое́ соблюде́т, сме́рти не и́мать вкуси́ти во ве́ки. Еда́ Ты бо́лий еси́ отца́ на́шего Авраа́ма, и́же у́мре? И проро́цы умро́ша, кого́ Ся Сам Ты твори́ши? Отвеща́ Иису́с: а́ще Аз сла́влюся Сам, сла́ва Моя́ ничесо́же есть, есть Оте́ц Мой сла́вяй Мя, Его́же вы глаго́лете, я́ко Бог наш есть. И не позна́сте Его́, Аз же вем Его́, и а́ще реку́, я́ко не вем Его́, бу́ду подо́бен вам ложь, но вем Его́ и сло́во Его́ соблюда́ю. Авраа́м оте́ц ваш рад бы был, дабы́ ви́дел день Мой, и ви́де и возра́довася. Ре́ша у́бо иуде́е к Нему́: пяти́десять лет не у и́маши, и Авраа́ма ли еси́ ви́дел? Рече́ же им Иису́с: ами́нь, ами́нь глаго́лю вам, пре́жде да́же Авраа́м не бысть, Аз есмь. Взя́ша у́бо ка́мение, да ве́ргут Нань, Иису́с же скры́ся и изы́де из це́ркве, проше́д посреде́ их, и мимохожда́ше та́ко. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: а҆ми́нь а҆ми́нь глаго́лю ва́мъ, а҆́ще кто̀ сло́во моѐ соблюде́тъ, сме́рти не и҆́мать ви́дѣти во вѣ́ки. рѣ́ша ᲂу҆́бѡ є҆мꙋ̀ жи́дове: ны́нѣ разꙋмѣ́хомъ, ꙗ҆́кѡ бѣ́са и҆́маши. а҆враа́мъ ᲂу҆́мре, и҆ проро́цы, и҆ ты̀ глаго́леши: а҆́ще кто̀ сло́во моѐ соблюде́тъ, сме́рти не и҆́мать вкꙋси́ти во вѣ́ки. є҆да̀ ты̀ бо́лїй є҆сѝ ѻ҆ц҃а̀ на́шегѡ а҆враа́ма, и҆́же ᲂу҆́мре, и҆ проро́цы ᲂу҆мро́ша, кого́ сѧ са́мъ ты̀ твори́ши; ѿвѣща̀ і҆и҃съ: а҆́ще а҆́зъ сла́влюсѧ са́мъ, сла́ва моѧ̀ ничесо́же є҆́сть: є҆́сть ѻ҆ц҃ъ мо́й сла́вѧй мѧ̀, є҆го́же вы̀ глаго́лете, ꙗ҆́кѡ бг҃ъ на́шъ є҆́сть. и҆ не позна́сте є҆гѡ̀, а҆́зъ же вѣ́мъ є҆го̀: и҆ а҆́ще рекꙋ̀, ꙗ҆́кѡ не вѣ́мъ є҆гѡ̀, бꙋ́дꙋ подо́бенъ ва́мъ, ло́жъ: но вѣ́мъ є҆го̀, и҆ сло́во є҆гѡ̀ соблюда́ю. а҆враа́мъ ѻ҆те́цъ ва́шъ ра́дъ бы бы́лъ, дабы̀ ви́дѣлъ де́нь мо́й: и҆ ви́дѣ, и҆ возра́довасѧ. рѣ́ша же і҆ꙋде́є къ немꙋ̀: пѧти́десѧть лѣ́тъ не ᲂу҆̀ и҆́маши, и҆ а҆враа́ма ли є҆сѝ ви́дѣлъ; рече́ же и҆̀мъ і҆и҃съ: а҆ми́нь а҆ми́нь глаго́лю ва́мъ, пре́жде да́же а҆враа́мъ не бы́сть, а҆́зъ є҆́смь. взѧ́ша же ка́менїе, да ве́ргꙋтъ на́нь: і҆и҃съ же скры́сѧ, и҆ и҆зы́де и҆з̾ цр҃кве, проше́дъ посредѣ̀ и҆́хъ, и҆ мимохожда́ше та́кѡ. ",
}

add_evangelie_ioanna {
  ["номер"] = 34,
  ["комментарий"] = "Ин., 34 зач., IX, 1–38.",
  ["текст_ру"] = "Во вре́мя о́но, мимоиды́й Иису́с ви́де челове́ка сле́па от рождества́. И вопроси́ша Его́ ученицы́ Его́, глаго́люще: Равви́, кто согреши́, сей ли, или́ роди́теля его́, да слеп роди́ся? Отвеща́ Иису́с: ни сей согреши́, ни роди́теля его́, но да явя́тся дела́ Бо́жия на нем. Мне подоба́ет де́лати дела́ Посла́вшаго Мя, до́ндеже день есть, прии́дет нощь, егда́ никто́же мо́жет де́лати, егда́ в ми́ре есмь, свет есмь ми́ру. Сия́ рек, плю́ну на зе́млю, и сотвори́ бре́ние от плюнове́ния, и пома́за о́чи бре́нием слепо́му, и рече́ ему́: иди́, умы́йся в купе́ли Силоа́мсте, е́же сказа́ется по́слан. И́де у́бо и умы́ся, и прии́де ви́дя. Сосе́ди же и и́же бя́ху ви́дели его́ пре́жде, я́ко слеп бе, глаго́лаху: не сей ли есть седя́й и прося́й? О́вии глаго́лаху, я́ко сей есть, ини́и же глаго́лаху, я́ко подо́бен ему́ есть. Он же глаго́лаше, я́ко аз есмь. Глаго́лаху же ему́: ка́ко ти отверзо́стеся о́чи? Отвеща́ он и рече́: Челове́к нарица́емый Иису́с бре́ние сотвори́ и пома́за о́чи мои́ и рече́ ми: иди́ в купе́ль Силоа́млю и умы́йся. Шед же и умы́вся, прозре́х. Ре́ша у́бо ему́: кто Той есть? Глаго́ла: не вем. Ведо́ша же его́ к фарисе́ом, и́же бе иногда́ слеп. Бе же суббо́та, егда́ сотвори́ бре́ние Иису́с и отве́рзе ему́ о́чи. Па́ки же вопроша́ху его́ и фарисе́е, ка́ко прозре́. Он же рече́ им: бре́ние положи́ мне на о́чи, и умы́хся, и ви́жу. Глаго́лаху у́бо от фарисе́й не́цыи: несть Сей от Бо́га Челове́к, я́ко суббо́ту не храни́т. О́вии глаго́лаху: ка́ко мо́жет челове́к гре́шен сицева́ зна́мения твори́ти? И ра́спря бе в них. Глаго́лаху у́бо слепцу́ па́ки: ты что глаго́леши о Нем, я́ко отве́рзе о́чи твои́? Он же рече́, я́ко проро́к есть. Не я́ша у́бо ве́ры иуде́е о нем, я́ко слеп бе и прозре́, до́ндеже возгласи́ша роди́теля того́ прозре́вшаго, и вопроси́ша я́, глаго́люще: сей ли есть сын ва́ю, его́же вы глаго́лете, я́ко слеп роди́ся? Ка́ко у́бо ны́не ви́дит? Отвеща́ста же и́ма роди́теля его́ и ре́ста: ве́мы, я́ко сей есть сын на́ю и я́ко слеп роди́ся. Ка́ко же ны́не ви́дит, не ве́мы, или́ кто отве́рзе ему́ о́чи, мы не ве́мы, сам во́зраст и́мать, самого́ вопроси́те, сам о себе́ да глаго́лет. Сия́ реко́ста роди́теля его́, я́ко боя́стася жидо́в, уже́ бо бя́ху сложи́лися жи́дове, да а́ще кто Его́ испове́сть Христа́, отлуче́н со́нмища да бу́дет, сего́ ра́ди роди́теля его́ реко́ста, я́ко во́зраст и́мать, самого́ вопроси́те. Возгласи́ша же втори́цею челове́ка, и́же бе слеп, и ре́ша ему́: даждь сла́ву Бо́гу, мы ве́мы, я́ко Челове́к Сей гре́шен есть. Отвеща́ же он и рече́: а́ще гре́шен есть, не вем, еди́но вем, я́ко слеп бех, ны́не же ви́жу. Ре́ша же ему́ па́ки: что сотвори́ тебе́? Ка́ко отве́рзе о́чи твои́? Отвеща́ им: реко́х вам уже́, и не слы́шасте, что па́ки хо́щете слы́шати? Еда́ и вы ученицы́ Его́ хо́щете бы́ти? Они́ же укори́ша его́ и ре́ша ему́: ты учени́к еси́ Того́, мы же Моисе́овы есмы́ ученицы́. Мы ве́мы, я́ко Моисе́ови глаго́ла Бог, Сего́ же не ве́мы, отку́ду есть. Отвеща́ челове́к и рече́ им: о сем бо ди́вно есть, я́ко вы не ве́сте, отку́ду есть, и отве́рзе о́чи мои́. Вем же, я́ко гре́шники Бог не послу́шает, но а́ще кто Богочте́ц есть и во́лю Его́ твори́т, того́ послу́шает. От ве́ка несть слы́шано, я́ко кто отве́рзе о́чи сле́пу рожде́ну. А́ще не бы был Сей от Бо́га, не могл бы твори́ти ничесо́же. Отвеща́ша и ре́ша ему́: во гресе́х ты роди́лся еси́ весь, и ты ли ны учи́ши? И изгна́ша его́ вон. Услы́ша Иису́с, я́ко изгна́ша его́ вон, и обре́т его́, рече́ ему́: ты ве́руеши ли в Сы́на Бо́жия? Отвеща́ он и рече́: и кто есть, Го́споди, да ве́рую в Него́? Рече́ же ему́ Иису́с: и ви́дел еси́ Его́, и Глаго́ляй с тобо́ю Той есть. Он же рече́: ве́рую, Го́споди. И поклони́ся Ему́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, мимоиды́й і҆и҃съ ви́дѣ человѣ́ка слѣ́па ѿ рождества̀. и҆ вопроси́ша є҆го̀ ᲂу҆ченицы̀ є҆гѡ̀, глаго́люще: равві̀, кто̀ согрѣшѝ; се́й ли, и҆лѝ роди́тєлѧ є҆гѡ̀, да слѣ́пъ роди́сѧ; ѿвѣща̀ і҆и҃съ: ни се́й согрѣшѝ, ни роди́тєлѧ є҆гѡ̀, но да ꙗ҆вѧ́тсѧ дѣла̀ бж҃їѧ на не́мъ. мнѣ̀ подоба́етъ дѣ́лати дѣла̀ посла́вшагѡ мѧ̀, до́ндеже де́нь є҆́сть: прїи́детъ но́щь, є҆гда̀ никто́же мо́жетъ дѣ́лати. є҆гда̀ въ мі́рѣ є҆́смь, свѣ́тъ є҆́смь мі́рꙋ. сїѧ̑ ре́къ, плю́нꙋ на зе́млю, и҆ сотворѝ бре́нїе ѿ плюнове́нїѧ, и҆ пома́за ѻ҆́чи бре́нїемъ слѣпо́мꙋ. и҆ речѐ є҆мꙋ̀: и҆дѝ, ᲂу҆мы́йсѧ въ кꙋпѣ́ли сїлѡа́мстѣ, є҆́же сказа́етсѧ по́сланъ. и҆́де же и҆ ᲂу҆мы́сѧ, и҆ прїи́де ви́дѧ. сосѣ́ди же и҆ и҆̀же бѧ́хꙋ ви́дѣли є҆го̀ пре́жде, ꙗ҆́кѡ слѣ́пъ бѣ̀, глаго́лахꙋ: не се́й ли є҆́сть сѣдѧ́й и҆ просѧ́й; ѻ҆́вїи глаго́лахꙋ, ꙗ҆́кѡ се́й є҆́сть: и҆ні́и же глаго́лахꙋ, ꙗ҆́кѡ подо́бенъ є҆мꙋ̀ є҆́сть: ѻ҆́нъ же глаго́лаше, ꙗ҆́кѡ а҆́зъ є҆́смь. глаго́лахꙋ же є҆мꙋ̀: ка́кѡ тѝ ѿверзо́стѣсѧ ѻ҆́чи; ѿвѣща̀ ѻ҆́нъ и҆ речѐ: человѣ́къ нарица́емый і҆и҃съ бре́нїе сотворѝ, и҆ пома́за ѻ҆́чи моѝ, и҆ рече́ ми: и҆дѝ въ кꙋпѣ́ль сїлѡа́млю, и҆ ᲂу҆мы́йсѧ. ше́дъ же и҆ ᲂу҆мы́всѧ, прозрѣ́хъ. рѣ́ша же є҆мꙋ̀: кто̀ то́й є҆́сть; глаго́ла, не вѣ́мъ. ведо́ша же є҆го̀ къ фарїсе́ѡмъ, и҆́же бѣ̀ и҆ногда̀ слѣ́пъ. бѣ́ же сꙋббѡ́та, є҆гда̀ сотворѝ бре́нїе і҆и҃съ, и҆ ѿве́рзе є҆мꙋ̀ ѻ҆́чи. па́ки же вопроша́хꙋ є҆го̀ и҆ фарїсе́є: ка́кѡ прозрѣ̀; ѻ҆́нъ же речѐ и҆̀мъ: бре́нїе положѝ мнѣ̀ на ѻ҆́чи, и҆ ᲂу҆мы́хсѧ, и҆ ви́жꙋ. глаго́лахꙋ же ѿ фарїсє́й нѣ́цыи: нѣ́сть се́й ѿ бг҃а человѣ́къ, ꙗ҆́кѡ сꙋббѡ́тꙋ не храни́тъ. ѻ҆́вїи глаго́лахꙋ: ка́кѡ мо́жетъ человѣ́къ грѣ́шенъ сицєва̀ зна́мєнїѧ твори́ти; и҆ ра́спрѧ бѣ̀ въ ни́хъ. глаго́лахꙋ ᲂу҆́бѡ слѣпцꙋ̀ па́ки: ты̀ что̀ глаго́леши ѡ҆ не́мъ, ꙗ҆́кѡ ѿве́рзе ѻ҆́чи твоѝ; ѻ҆́нъ же речѐ, ꙗ҆́кѡ проро́къ є҆́сть. не ꙗ҆́ша ᲂу҆́бѡ вѣ́ры і҆ꙋде́є ѡ҆ не́мъ, ꙗ҆́кѡ слѣ́пъ бѣ̀ и҆ прозрѣ̀, до́ндеже возгласи́ша роди́тєлѧ тогѡ̀ прозрѣ́вшагѡ. и҆ вопроси́ша ѧ҆̀, глаго́люще: се́й ли є҆́сть сы́нъ ва́ю, є҆го́же вы̀ глаго́лете, ꙗ҆́кѡ слѣ́пъ роди́сѧ; ка́кѡ ᲂу҆́бѡ ны́нѣ ви́дитъ; ѿвѣща́ста же и҆́ма роди́тєлѧ є҆гѡ̀ и҆ рѣ́ста: вѣ́мы, ꙗ҆́кѡ се́й є҆́сть сы́нъ на́ю, и҆ ꙗ҆́кѡ слѣ́пъ роди́сѧ. ка́кѡ же ны́нѣ ви́дитъ, не вѣ́мы, и҆лѝ кто̀ ѿве́рзе є҆мꙋ̀ ѻ҆́чи, мы̀ не вѣ́мы. са́мъ во́зрастъ и҆́мать, самого̀ вопроси́те: са́мъ ѡ҆ себѣ̀ да глаго́летъ. сїѧ̑ реко́ста роди́тєлѧ є҆гѡ̀, ꙗ҆́кѡ боѧ́стасѧ жидѡ́въ: ᲂу҆же́ бо бѧ́хꙋ сложи́лисѧ жи́дове, да а҆́ще кто̀ є҆го̀ и҆сповѣ́сть хрⷭ҇та̀, ѿлꙋче́нъ со́нмища да бꙋ́детъ. сегѡ̀ ра́ди роди́тєлѧ є҆гѡ̀ реко́ста: ꙗ҆́кѡ во́зрастъ и҆́мать, самого̀ вопроси́те. возгласи́ша же втори́цею человѣ́ка, и҆́же бѣ̀ слѣ́пъ, и҆ рѣ́ша є҆мꙋ̀: да́ждь сла́вꙋ бг҃ꙋ, мы̀ вѣ́мы, ꙗ҆́кѡ человѣ́къ се́й грѣ́шенъ є҆́сть. ѿвѣща́ же ѻ҆́нъ, и҆ речѐ: а҆́ще грѣ́шенъ є҆́сть, не вѣ́мъ: є҆ди́но вѣ́мъ, ꙗ҆́кѡ слѣ́пъ бѣ́хъ, ны́нѣ же ви́жꙋ. рѣ́ша же є҆мꙋ̀ па́ки: что̀ сотворѝ тебѣ̀; ка́кѡ ѿве́рзе ѻ҆́чи твоѝ; ѿвѣща̀ и҆̀мъ: реко́хъ ва́мъ ᲂу҆жѐ, и҆ не слы́шасте: что̀ па́ки хо́щете слы́шати; є҆да̀ и҆ вы̀ ᲂу҆ченицы̀ є҆гѡ̀ хо́щете бы́ти; ѻ҆ни́ же ᲂу҆кори́ша є҆го̀, и҆ рѣ́ша є҆мꙋ̀: ты̀ ᲂу҆чени́къ є҆сѝ тогѡ̀, мы́ же мѡѷсе́овы є҆смы̀ ᲂу҆ченицы̀. мы̀ вѣ́мы, ꙗ҆́кѡ мѡѷсе́ови глаго́ла бг҃ъ: сегѡ́ же не вѣ́мы, ѿкꙋ́дꙋ є҆́сть. ѿвѣща̀ человѣ́къ, и҆ речѐ и҆̀мъ: ѡ҆ се́мъ бо ди́вно є҆́сть, ꙗ҆́кѡ вы̀ не вѣ́сте, ѿкꙋ́дꙋ є҆́сть, и҆ ѿве́рзе ѻ҆́чи моѝ. вѣ́мъ же, ꙗ҆́кѡ грѣ́шники бг҃ъ не послꙋ́шаетъ: но а҆́ще кто̀ бг҃очте́цъ є҆́сть, и҆ во́лю є҆гѡ̀ твори́тъ, тогѡ̀ послꙋ́шаетъ. ѿ вѣ́ка нѣ́сть слы́шано, ꙗ҆́кѡ кто̀ ѿве́рзе ѻ҆́чи слѣ́пꙋ рожде́нꙋ. а҆́ще не бы̀ бы́лъ се́й ѿ бг҃а, не мо́глъ бы твори́ти ничесѡ́же. ѿвѣща́ша и҆ рѣ́ша є҆мꙋ̀: во грѣсѣ́хъ ты̀ роди́лсѧ є҆сѝ ве́сь, и҆ ты́ ли ны̀ ᲂу҆чи́ши; и҆ и҆згна́ша є҆го̀ во́нъ. ᲂу҆слы́ша і҆и҃съ, ꙗ҆́кѡ и҆згна́ша є҆го̀ во́нъ, и҆ ѡ҆брѣ́тъ є҆го̀, речѐ є҆мꙋ̀: ты̀ вѣ́рꙋеши ли въ сн҃а бж҃їѧ; ѿвѣща̀ ѻ҆́нъ, и҆ речѐ: и҆ кто́ є҆сть гдⷭ҇и, да вѣ́рꙋю въ него̀; рече́ же є҆мꙋ̀ і҆и҃съ: и҆ ви́дѣлъ є҆сѝ є҆го̀, и҆ глаго́лѧй съ тобо́ю, то́й є҆́сть. ѻ҆́нъ же речѐ: вѣ́рꙋю гдⷭ҇и, и҆ поклони́сѧ є҆мꙋ̀. ",
}

add_evangelie_ioanna {
  ["номер"] = 35,
  ["комментарий"] = "Ин., 35 зач., IX, 39 – X, 9.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: на суд Аз в мир сей приидо́х, да неви́дящии ви́дят, и ви́дящии сле́пи бу́дут. И слы́шаша от фарисе́й сия́ су́щии с Ним и ре́ша Ему́: еда́ и мы сле́пи есмы́? Рече́ им Иису́с: а́ще бы́сте сле́пи бы́ли, не бы́сте име́ли греха́, ны́не же глаго́лете, я́ко ви́дим, грех ваш пребыва́ет. Ами́нь, ами́нь глаго́лю вам, не входя́й две́рьми во двор о́вчий, но прела́зя и́нуде, той тать есть и разбо́йник, а входя́й две́рьми па́стырь есть овца́м, сему́ две́рник отверза́ет, и о́вцы глас его́ слы́шат, и своя́ о́вцы глаша́ет по и́мени, и изго́нит их. И егда́ своя́ о́вцы иждене́т, пред ни́ми хо́дит, и о́вцы по нем и́дут, я́ко ве́дят глас его́, по чужде́м же не и́дут, но бежа́т от него́, я́ко не зна́ют чужда́го гла́са. Сию́ при́тчу рече́ им Иису́с, они́ же не разуме́ша, что бя́ше, я́же глаго́лаше им. Рече́ же па́ки им Иису́с: ами́нь, ами́нь глаго́лю вам, я́ко Аз есмь дверь овца́м. Вси, ели́ко их прии́де пре́жде Мене́, та́тие суть и разбо́йницы, но не послу́шаша их о́вцы. Аз есмь дверь, Мно́ю а́ще кто вни́дет, спасе́тся, и вни́дет и изы́дет, и па́жить обря́щет. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: на сꙋ́дъ а҆́зъ въ мі́ръ се́й прїидо́хъ, да неви́дѧщїи ви́дѧтъ, и҆ ви́дѧщїи слѣ́пи бꙋ́дꙋтъ. и҆ слы́шаша ѿ фарїсє́й сїѧ̑ сꙋ́щїи съ ни́мъ, и҆ рѣ́ша є҆мꙋ̀: є҆да̀ и҆ мы̀ слѣ́пи є҆смы̀; речѐ и҆̀мъ і҆и҃съ: а҆́ще бы́сте слѣ́пи бы́ли, не бы́сте и҆мѣ́ли грѣха̀: ны́нѣ же глаго́лете, ꙗ҆́кѡ ви́димъ, грѣ́хъ ва́шъ пребыва́етъ. а҆ми́нь а҆ми́нь глаго́лю ва́мъ: не входѧ́й две́рьми во дво́ръ ѻ҆́вчїй, но прела́зѧ и҆́нꙋдѣ, то́й та́ть є҆́сть и҆ разбо́йникъ. а҆ входѧ́й две́рьми, па́стырь є҆́сть ѻ҆вца́мъ. семꙋ̀ две́рникъ ѿверза́етъ, и҆ ѻ҆́вцы гла́съ є҆гѡ̀ слы́шатъ, и҆ своѧ̀ ѻ҆́вцы глаша́етъ по и҆́мени, и҆ и҆зго́нитъ и҆̀хъ. и҆ є҆гда̀ своѧ̀ ѻ҆́вцы и҆ждене́тъ, пред̾ ни́ми хо́дитъ, и҆ ѻ҆́вцы по не́мъ и҆́дꙋтъ, ꙗ҆́кѡ вѣ́дѧтъ гла́съ є҆гѡ̀. по чꙋжде́мъ же не и҆́дꙋтъ, но бѣжа́тъ ѿ негѡ̀, ꙗ҆́кѡ не зна́ютъ чꙋжда́гѡ гла́са. сїю̀ при́тчꙋ речѐ и҆̀мъ і҆и҃съ: ѻ҆ни́ же не разꙋмѣ́ша, что̀ бѧ́ше ꙗ҆̀же глаго́лаше и҆̀мъ. рече́ же па́ки и҆̀мъ і҆и҃съ: а҆ми́нь а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ а҆́зъ є҆́смь две́рь ѻ҆вца́мъ. всѝ, є҆ли́кѡ и҆́хъ прїи́де пре́жде менѐ, та́тїе сꙋ́ть и҆ разбо́йницы: но не послꙋ́шаша и҆́хъ ѻ҆́вцы. а҆́зъ є҆́смь две́рь: мно́ю а҆́ще кто̀ вни́детъ, спасе́тсѧ, и҆ вни́детъ, и҆ и҆зы́детъ, и҆ па́жить ѡ҆брѧ́щетъ. ",
}

