add_evangelie_ioanna {
  ["номер"] = 36,
  ["комментарий"] = "Ин., 36 зач., X, 9–16.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: Аз есмь дверь, Мно́ю а́ще кто вни́дет, спасе́тся, и вни́дет, и изы́дет, и па́жить обря́щет. Тать не прихо́дит, ра́зве да укра́дет, и убие́т, и погуби́т, Аз приидо́х, да живо́т и́мут и ли́шше и́мут. Аз есмь па́стырь до́брый, па́стырь до́брый ду́шу свою́ полага́ет за о́вцы. А нае́мник, и́же несть па́стырь, ему́же не суть о́вцы своя́, ви́дит во́лка гряду́ща и оставля́ет о́вцы, и бе́гает, и волк расхи́тит их, и распу́дит о́вцы. А нае́мник бежи́т, я́ко нае́мник есть и неради́т о овца́х. Аз есмь па́стырь до́брый, и зна́ю Моя́, и зна́ют Мя Моя́. Я́коже зна́ет Мя Оте́ц, и Аз зна́ю Отца́, и ду́шу Мою́ полага́ю за о́вцы. И и́ны о́вцы и́мам, я́же не суть от двора́ сего́, и ты́я Ми подоба́ет привести́, и глас Мой услы́шат, и бу́дет еди́но ста́до, и еди́н Па́стырь. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: а҆́зъ є҆́смь две́рь: мно́ю а҆́ще кто̀ вни́детъ, спасе́тсѧ, и҆ вни́детъ, и҆ и҆зы́детъ, и҆ па́жить ѡ҆брѧ́щетъ. та́ть не прихо́дитъ, ра́звѣ да ᲂу҆кра́детъ, и҆ ᲂу҆бїе́тъ, и҆ погꙋби́тъ: а҆́зъ прїидо́хъ, да живо́тъ и҆́мꙋтъ, и҆ ли́шше и҆́мꙋтъ. а҆́зъ є҆́смь па́стырь до́брый: па́стырь до́брый дꙋ́шꙋ свою̀ полага́етъ за ѻ҆́вцы. а҆ нае́мникъ, и҆́же нѣ́сть па́стырь, є҆мꙋ́же не сꙋ́ть ѻ҆́вцы своѧ̀, ви́дитъ во́лка грѧдꙋ́ща, и҆ ѡ҆ставлѧ́етъ ѻ҆́вцы, и҆ бѣ́гаетъ, и҆ во́лкъ расхи́титъ и҆̀хъ, и҆ распꙋ́дитъ ѻ҆́вцы. а҆ нае́мникъ бѣжи́тъ, ꙗ҆́кѡ нае́мникъ є҆́сть, и҆ неради́тъ ѡ҆ ѻ҆вца́хъ. а҆́зъ є҆́смь па́стырь до́брый, и҆ зна́ю моѧ̑, и҆ зна́ютъ мѧ̀ моѧ̑. ꙗ҆́коже зна́етъ мѧ̀ ѻ҆ц҃ъ, и҆ а҆́зъ зна́ю ѻ҆ц҃а̀: и҆ дꙋ́шꙋ мою̀ полага́ю за ѻ҆́вцы. и҆ и҆́ны ѻ҆́вцы и҆́мамъ, ꙗ҆̀же не сꙋ́ть ѿ двора̀ сегѡ̀: и҆ ты̑ѧ мѝ подоба́етъ привестѝ: и҆ гла́съ мо́й ᲂу҆слы́шатъ, и҆ бꙋ́детъ є҆ди́но ста́до, и҆ є҆ди́нъ па́стырь. ",
}

add_evangelie_ioanna {
  ["номер"] = 37,
  ["комментарий"] = "Ин., 37 зач., X, 17–28.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: сего́ ра́ди Мя Оте́ц лю́бит, я́ко Аз ду́шу Мою́ полага́ю, да па́ки прииму́ ю́. Никто́же во́змет ю́ от Мене́, но Аз полага́ю ю́ о Себе́, о́бласть и́мам положи́ти ю́ и о́бласть и́мам па́ки прия́ти ю́, сию́ за́поведь прия́х от Отца́ Моего́. Ра́спря же па́ки бысть во иуде́ех за словеса́ сия́. Глаго́лаху же мно́зи от них: бе́са и́мать и неи́стов есть, что Его́ послу́шаете? Ини́и глаго́лаху: си́и глаго́ли не суть бесну́ющагося, еда́ мо́жет бес слепо́му о́чи отве́рсти? Бы́ша же тогда́ обновле́ния во Иерусоли́мех, и зима́ бе. И хожда́ше Иису́с в це́ркви, в притво́ре Соломо́ни. Обыдо́ша же Его́ иуде́е и глаго́лаху Ему́: доко́ле ду́шы на́ша взе́млеши? А́ще Ты еси́ Христо́с, рцы нам не обину́яся. Отвеща́ им Иису́с: рех вам, и не ве́руете, дела́, я́же Аз творю́ о и́мени Отца́ Моего́, та свиде́тельствуют о Мне, но вы не ве́руете, не́сте бо от ове́ц Мои́х, я́коже рех вам. О́вцы Моя́ гла́са Моего́ слу́шают, и Аз зна́ю их, и по Мне гряду́т, и Аз живо́т ве́чный дам им. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: сегѡ̀ ра́ди мѧ̀ ѻ҆ц҃ъ лю́битъ, ꙗ҆́кѡ а҆́зъ дꙋ́шꙋ мою̀ полага́ю, да па́ки прїимꙋ̀ ю҆̀. никто́же во́з̾метъ ю҆̀ ѿ менѐ, но а҆́зъ полага́ю ю҆̀ ѡ҆ себѣ̀: ѻ҆́бласть и҆́мамъ положи́ти ю҆̀, и҆ ѻ҆́бласть и҆́мамъ па́ки прїѧ́ти ю҆̀: сїю̀ за́повѣдь прїѧ́хъ ѿ ѻ҆ц҃а̀ моегѡ̀. ра́спрѧ же па́ки бы́сть во і҆ꙋде́ехъ за словеса̀ сїѧ̀. глаго́лахꙋ же мно́зи ѿ ни́хъ: бѣ́са и҆́мать, и҆ неи́стовъ є҆́сть, что̀ є҆гѡ̀ послꙋ́шаете; и҆ні́и глаго́лахꙋ: сі́и глаго́ли не сꙋ́ть бѣснꙋ́ющагѡсѧ: є҆да̀ мо́жетъ бѣ́съ слѣпо́мꙋ ѻ҆́чи ѿве́рсти; бы́ша же тогда̀ ѡ҆бновлє́нїѧ во і҆еросолѵ́мѣхъ, и҆ зима̀ бѣ̀. и҆ хожда́ше і҆и҃съ въ цр҃кви, въ притво́рѣ соломѡ́ни. ѡ҆быдо́ша же є҆го̀ і҆ꙋде́є, и҆ глаго́лахꙋ є҆мꙋ̀: доко́лѣ дꙋ́шы на́шѧ взе́млеши; а҆́ще ты̀ є҆сѝ хрⷭ҇то́съ, рцы̀ на́мъ не ѡ҆бинꙋ́ѧсѧ. ѿвѣща̀ и҆̀мъ і҆и҃съ: рѣ́хъ ва́мъ, и҆ не вѣ́рꙋете: дѣла̀, ꙗ҆̀же а҆́зъ творю̀ ѡ҆ и҆́мени ѻ҆ц҃а̀ моегѡ̀, та̀ свидѣ́тельствꙋютъ ѡ҆ мнѣ̀. но вы̀ не вѣ́рꙋете: нѣ́сте бо ѿ ѻ҆ве́цъ мои́хъ, ꙗ҆́коже рѣ́хъ ва́мъ. ѻ҆́вцы моѧ̀ гла́са моегѡ̀ слꙋ́шаютъ: и҆ а҆́зъ зна́ю и҆̀хъ, и҆ по мнѣ̀ грѧдꙋ́тъ. и҆ а҆́зъ живо́тъ вѣ́чный да́мъ и҆̀мъ. ",
}

