  ["комментарий"] = "Ин., 37 зач., X, 22-28.",
  ["текст_ру"] = "Во вре́мя о́но, бы́ша обновле́ния во Иерусоли́мех, и зима́ бе. И хожда́ше Иису́с в це́ркви, в притво́ре Соломо́ни. Обыдо́ша же Его́ иуде́е и глаго́лаху Ему́: доко́ле ду́шы на́ша взе́млеши? А́ще Ты еси́ Христо́с, рцы нам не обину́яся. Отвеща́ им Иису́с: рех вам, и не ве́руете, дела́, я́же Аз творю́ о и́мени Отца́ Моего́, та свиде́тельствуют о Мне, но вы не ве́руете, не́сте бо от ове́ц Мои́х, я́коже рех вам. О́вцы Моя́ гла́са Моего́ слу́шают, и Аз зна́ю их, и по Мне гряду́т, и Аз живо́т ве́чный дам им. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бы́ша ѡ҆бновлє́нїѧ во і҆еросолѵ́мѣхъ, и҆ зима̀ бѣ̀. и҆ хожда́ше і҆и҃съ въ цр҃кви, въ притво́рѣ соломѡ́ни. ѡ҆быдо́ша же є҆го̀ і҆ꙋде́є, и҆ глаго́лахꙋ є҆мꙋ̀: доко́лѣ дꙋ́шы на́шѧ взе́млеши; а҆́ще ты̀ є҆сѝ хрⷭ҇то́съ, рцы̀ на́мъ не ѡ҆бинꙋ́ѧсѧ. ѿвѣща̀ и҆̀мъ і҆и҃съ: рѣ́хъ ва́мъ, и҆ не вѣ́рꙋете: дѣла̀, ꙗ҆̀же а҆́зъ творю̀ ѡ҆ и҆́мени ѻ҆ц҃а̀ моегѡ̀, та̀ свидѣ́тельствꙋютъ ѡ҆ мнѣ̀. но вы̀ не вѣ́рꙋете: нѣ́сте бо ѿ ѻ҆ве́цъ мои́хъ, ꙗ҆́коже рѣ́хъ ва́мъ. ѻ҆́вцы моѧ̀ гла́са моегѡ̀ слꙋ́шаютъ: и҆ а҆́зъ зна́ю и҆̀хъ, и҆ по мнѣ̀ грѧдꙋ́тъ. и҆ а҆́зъ живо́тъ вѣ́чный да́мъ и҆̀мъ. ",
}

add_evangelie_ioanna {
  ["номер"] = 38,
  ["комментарий"] = "Ин., 38 зач., X, 27–38.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: о́вцы Моя́ гла́са Моего́ слу́шают, и Аз зна́ю их, и по Мне гряду́т. И Аз живо́т ве́чный дам им, и не поги́бнут во ве́ки, и не восхи́тит их никто́же от руки́ Моея́. Оте́ц Мой, И́же даде́ Мне, бо́лий всех есть, и никто́же мо́жет восхи́тити их от руки́ Отца́ Моего́. Аз и Оте́ц еди́но есма́. Взя́ша же ка́мение па́ки иуде́е, да побию́т Его́. Отвеща́ им Иису́с: мно́га добра́ дела́ яви́х вам от Отца́ Моего́, за ко́е их де́ло ка́мение ме́щете на Мя? Отвеща́ша Ему́ иуде́е, глаго́люще: о добре́ де́ле ка́мение не ме́щем на Тя, но о хуле́, я́ко Ты, челове́к сый, твори́ши Себе́ Бо́га. Отвеща́ им Иису́с: несть ли пи́сано в зако́не ва́шем: Аз рех, бо́зи есте́? А́ще о́ны рече́ бо́ги, к ни́мже сло́во Бо́жие бысть, и не мо́жет разори́тися Писа́ние, Его́же Оте́ц святи́ и посла́ в мир, вы глаго́лете, я́ко хулу́ глаго́леши, зане́ рех: Сын Бо́жий есмь. А́ще не творю́ дела́ Отца́ Моего́, не ими́те Ми ве́ры, а́ще ли творю́, а́ще и Мне не ве́руете, дело́м Мои́м ве́руйте, да разуме́ете и ве́руете, я́ко во Мне Оте́ц, и Аз в Нем. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: ѻ҆́вцы моѧ̀ гла́са моегѡ̀ слꙋ́шаютъ: и҆ а҆́зъ зна́ю и҆̀хъ, и҆ по мнѣ̀ грѧдꙋ́тъ. и҆ а҆́зъ живо́тъ вѣ́чный да́мъ и҆̀мъ, и҆ не поги́бнꙋтъ во вѣ́ки, и҆ не восхи́титъ и҆́хъ никто́же ѿ рꙋкѝ моеѧ̀. ѻ҆ц҃ъ мо́й, и҆́же дадѐ мнѣ̀, бо́лїй всѣ́хъ є҆́сть: и҆ никто́же мо́жетъ восхи́тити и҆̀хъ ѿ рꙋкѝ ѻ҆ц҃а̀ моегѡ̀. а҆́зъ и҆ ѻ҆ц҃ъ є҆ди́но є҆сма̀. взѧ́ша же ка́менїе па́ки і҆ꙋде́є, да побїю́тъ є҆го̀. ѿвѣща̀ и҆̀мъ і҆и҃съ: мнѡ́га добра̀ дѣла̀ ꙗ҆ви́хъ ва́мъ ѿ ѻ҆ц҃а̀ моегѡ̀, за ко́е и҆́хъ дѣ́ло ка́менїе ме́щете на мѧ̀; ѿвѣща́ша є҆мꙋ̀ і҆ꙋде́є, глаго́люще: ѡ҆ добрѣ̀ дѣ́лѣ ка́менїе не ме́щемъ на тѧ̀, но ѡ҆ хꙋлѣ̀, ꙗ҆́кѡ ты̀ человѣ́къ сы́й, твори́ши себѐ бг҃а. ѿвѣща̀ и҆̀мъ і҆и҃съ: нѣ́сть ли пи́сано въ зако́нѣ ва́шемъ: а҆́зъ рѣ́хъ, бо́зи є҆стѐ; а҆́ще ѻ҆́ны речѐ бо́ги, къ ни́мже сло́во бж҃їе бы́сть, и҆ не мо́жетъ разори́тисѧ писа́нїе: є҆го́же ѻ҆ц҃ъ свѧтѝ и҆ посла̀ въ мі́ръ, вы̀ глаго́лете, ꙗ҆́кѡ хꙋлꙋ̀ глаго́леши, занѐ рѣ́хъ: сн҃ъ бж҃їй є҆́смь. а҆́ще не творю̀ дѣла̀ ѻ҆ц҃а̀ моегѡ̀, не и҆ми́те мѝ вѣ́ры. а҆́ще ли творю̀, а҆́ще и҆ мнѣ̀ не вѣ́рꙋете, дѣлѡ́мъ мои́мъ вѣ́рꙋйте: да разꙋмѣ́ете и҆ вѣ́рꙋете, ꙗ҆́кѡ во мнѣ̀ ѻ҆ц҃ъ и҆ а҆́зъ въ не́мъ. ",
}

add_evangelie_ioanna {
  ["номер"] = 39,
  ["комментарий"] = "Ин., 39 зач., XI, 1–45.",
  ["текст_ру"] = "Во вре́мя о́но, бе не́кто боля́ Ла́зарь от Вифа́нии, от ве́си Мари́ины и Ма́рфы сестры́ ея́. Бе же Мари́а пома́завшая Го́спода ми́ром и оте́ршая но́зе Его́ власы́ свои́ми, ея́же брат Ла́зарь боля́ше. Посла́сте у́бо сестре́ к Нему́, глаго́люще: Го́споди, се его́же лю́биши, боли́т. Слы́шав же Иису́с рече́: сия́ боле́знь несть к сме́рти, но о сла́ве Бо́жии, да просла́вится Сын Бо́жий ея́ ра́ди. Любля́ше же Иису́с Ма́рфу и сестру́ ея́ и Ла́заря. Егда́ же услы́ша, я́ко боли́т, тогда́ пребы́сть на не́мже бе ме́сте два дни. Пото́м же глаго́ла ученико́м: и́дем во Иуде́ю па́ки. Глаго́лаша Ему́ ученицы́: Равви́, ны́не иска́ху Тебе́ ка́мением поби́ти иуде́е, и па́ки ли и́деши та́мо? Отвеща́ Иису́с: не два ли на́десяте часа́ еста́ во дне? А́ще кто хо́дит во дне, не по́ткнется, я́ко свет ми́ра сего́ ви́дит, а́ще кто хо́дит в нощи́, по́ткнется, я́ко несть све́та в нем. Сия́ рече́ и посе́м глаго́ла им: Ла́зарь друг наш у́спе, но иду́, да возбужу́ его́. Ре́ша же ученицы́ Его́: Го́споди, а́ще у́спе, спасе́н бу́дет. Рече́ же Иису́с о сме́рти его́, они́ же мне́ша, я́ко о успе́нии сна глаго́лет. Тогда́ рече́ им Иису́с не обину́яся: Ла́зарь у́мре, и ра́дуюся вас ра́ди, да ве́руете, я́ко не бех та́мо, но и́дем к нему́. Рече́ же Фома́, глаго́лемый Близне́ц, ученико́м: и́дем и мы, да у́мрем с ним. Прише́д же Иису́с, обре́те его́ четы́ри дни уже́ иму́ща во гро́бе. Бе же Вифа́ниа близ Иерусали́ма, я́ко ста́дий пятьна́десять, и мно́зи от иуде́й бя́ху пришли́ к Ма́рфе и Мари́и, да уте́шат их о бра́те ею́. Ма́рфа у́бо егда́ услы́ша, я́ко Иису́с гряде́т, сре́те Его́, Мари́а же до́ма седя́ше. Рече́ же Ма́рфа ко Иису́су: Го́споди, а́ще бы зде был, не бы брат мой у́мерл, но и ны́не вем, я́ко ели́ка а́ще про́сиши от Бо́га, даст Тебе́ Бог. Глаго́ла ей Иису́с: воскре́снет брат твой. Глаго́ла Ему́ Ма́рфа: вем, я́ко воскре́снет в воскреше́ние, в после́дний день. Рече́ же ей Иису́с: Аз есмь воскреше́ние и живо́т. Ве́руяй в Мя, а́ще и у́мрет, оживе́т, и всяк живы́й и ве́руяй в Мя не у́мрет во ве́ки. Е́млеши ли ве́ру сему́? Глаго́ла Ему́: ей, Го́споди, аз ве́ровах, я́ко Ты еси́ Христо́с Сын Бо́жий, и́же в мир гряды́й. И сия́ ре́кши, и́де и пригласи́ Мари́ю сестру́ свою́ тай, ре́кши: Учи́тель прише́л есть и глаша́ет тя. Она́ же я́ко услы́ша, воста́ ско́ро и и́де к Нему́. Не уже́ бо бе прише́л Иису́с в весь, но бе на ме́сте, иде́же сре́те Его́ Ма́рфа. Иуде́е же у́бо су́щии с не́ю в дому́ и утеша́юще ю́, ви́девше Мари́ю, я́ко ско́ро воста́ и изы́де, по ней идо́ша, глаго́люще, я́ко и́дет на гроб, да пла́чет та́мо. Мари́а же я́ко прии́де, иде́же бе Иису́с, ви́девши Его́, паде́ Ему́ на ногу́, глаго́лющи Ему́: Го́споди, а́ще бы был зде, не бы у́мерл мой брат. Иису́с же, я́ко ви́де ю́ пла́чущуся и прише́дшыя с не́ю иуде́и пла́чущя, запрети́ ду́ху и возмути́ся Сам и рече́: где положи́сте его́? Глаго́лаша Ему́: Го́споди, прииди́ и виждь. Прослези́ся Иису́с. Глаго́лаху у́бо жи́дове: виждь, ка́ко любля́ше его́. Не́цыи же от них ре́ша: не можа́ше ли Сей, отве́рзый о́чи слепо́му, сотвори́ти, да и сей не у́мрет? Иису́с же па́ки претя́ в себе́, прии́де ко гро́бу. Бе же пеще́ра, и ка́мень лежа́ше на ней. Глаго́ла Иису́с: возьми́те ка́мень. Глаго́ла Ему́ сестра́ уме́ршаго Ма́рфа: Го́споди, уже́ смерди́т, четверодне́вен бо есть. Глаго́ла ей Иису́с: не рех ли ти, я́ко а́ще ве́руеши, у́зриши сла́ву Бо́жию? Взя́ша у́бо ка́мень, иде́же бе уме́рый лежя́. Иису́с же возве́д о́чи горе́ и рече́: О́тче, хвалу́ Тебе́ воздаю́, я́ко услы́шал еси́ Мя. Аз же ве́дех, я́ко всегда́ Мя послу́шаеши, но наро́да ра́ди стоя́щаго о́крест рех, да ве́ру и́мут, я́ко Ты Мя посла́л еси́. И сия́ рек, гла́сом вели́ким воззва́: Ла́заре, гряди́ вон. И изы́де уме́рый, обя́зан рука́ма и нога́ма укро́ем, и лице́ его́ убру́сом обя́зано. Глаго́ла им Иису́с: разреши́те его́ и оста́вите ити́. Мно́зи у́бо от иуде́й прише́дшии к Мари́и и ви́девше, я́же сотвори́ Иису́с, ве́роваша в Него́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, бѣ̀ нѣ́кто болѧ̀ ла́зарь ѿ виѳа́нїи, ѿ ве́си марі́ины и҆ ма́рѳы сестры̀ є҆ѧ̀. бѣ́ же марі́а пома́завшаѧ гдⷭ҇а мѵ́ромъ, и҆ ѡ҆те́рши но́зѣ є҆гѡ̀ власы̀ свои́ми: є҆ѧ́же бра́тъ ла́зарь болѧ́ше. посла́стѣ ᲂу҆́бѡ сєстрѣ̀ къ немꙋ̀ глаго́лющѣ: гдⷭ҇и, сѐ є҆го́же лю́биши, боли́тъ. слы́шавъ же і҆и҃съ, речѐ: сїѧ̀ болѣ́знь нѣ́сть къ сме́рти, но ѡ҆ сла́вѣ бж҃їи, да просла́витсѧ сн҃ъ бж҃їй є҆ѧ̀ ра́ди. люблѧ́ше же і҆и҃съ ма́рѳꙋ, и҆ сестрꙋ̀ є҆ѧ̀, и҆ ла́зарѧ. є҆гда́ же ᲂу҆слы́ша, ꙗ҆́кѡ боли́тъ, тогда̀ пребы́сть на не́мже бѣ̀ мѣ́стѣ два̀ днѝ. пото́мъ же глаго́ла ᲂу҆ченикѡ́мъ: и҆́демъ во і҆ꙋде́ю па́ки. глаго́лаша є҆мꙋ̀ ᲂу҆ченицы̀: равві̀, ны́нѣ и҆ска́хꙋ тебѐ ка́менїемъ поби́ти і҆ꙋде́є, и҆ па́ки ли и҆́деши та́мѡ; ѿвѣща̀ і҆и҃съ: не два́ ли на́десѧте часа̀ є҆ста̀ во днѐ; а҆́ще кто̀ хо́дитъ во днѐ, не по́ткнетсѧ, ꙗ҆́кѡ свѣ́тъ мі́ра сегѡ̀ ви́дитъ. а҆́ще кто̀ хо́дитъ въ нощѝ, по́ткнетсѧ, ꙗ҆́кѡ нѣ́сть свѣ́та въ не́мъ. сїѧ̑ речѐ, и҆ посе́мъ глаго́ла и҆̀мъ: ла́зарь дрꙋ́гъ на́шъ ᲂу҆́спе, но и҆дꙋ̀ да возбꙋжꙋ̀ є҆го̀. рѣ́ша же ᲂу҆ченицы̀ є҆гѡ̀: гдⷭ҇и, а҆́ще ᲂу҆́спе, спасе́нъ бꙋ́детъ. рече́ же і҆и҃съ ѡ҆ сме́рти є҆гѡ̀: ѻ҆ни́ же мнѣ́ша, ꙗ҆́кѡ ѡ҆ ᲂу҆спе́нїи сна̀ глаго́летъ. тогда̀ речѐ и҆̀мъ і҆и҃съ не ѡ҆бинꙋ́ѧсѧ: ла́зарь ᲂу҆́мре. и҆ ра́дꙋюсѧ ва́съ ра́ди, да вѣ́рꙋете, ꙗ҆́кѡ не бѣ́хъ та́мѡ: но и҆́демъ къ немꙋ̀. рече́ же ѳѡма̀, глаго́лемый близне́цъ, ᲂу҆ченикѡ́мъ: и҆́демъ и҆ мы̀, да ᲂу҆́мремъ съ ни́мъ. прише́дъ же і҆и҃съ, ѡ҆брѣ́те є҆го̀ четы́ри днѝ ᲂу҆жѐ и҆мꙋ́ща во гро́бѣ. бѣ́ же виѳа́нїа бли́зъ і҆ерꙋсали́ма ꙗ҆́кѡ. ста́дїй пѧтьна́десѧть. и҆ мно́зи ѿ і҆ꙋдє́й бѧ́хꙋ пришлѝ къ ма́рѳѣ и҆ марі́и, да ᲂу҆тѣ́шатъ и҆̀хъ ѡ҆ бра́тѣ є҆ю̀. ма́рѳа же є҆гда̀ ᲂу҆слы́ша, ꙗ҆́кѡ і҆и҃съ грѧде́тъ, срѣ́те є҆го̀: марі́а же до́ма сѣдѧ́ше. рече́ же ма́рѳа ко і҆и҃сꙋ: гдⷭ҇и, а҆́ще бы здѣ̀ бы́лъ, не бы̀ бра́тъ мо́й ᲂу҆́мерлъ. но и҆ ны́нѣ вѣ́мъ, ꙗ҆́кѡ є҆ли̑ка а҆́ще про́сиши ѿ бг҃а, да́стъ тебѣ̀ бг҃ъ. глаго́ла є҆́й і҆и҃съ: воскре́снетъ бра́тъ тво́й. глаго́ла є҆мꙋ̀ ма́рѳа: вѣ́мъ, ꙗ҆́кѡ воскре́снетъ въ воскреше́нїе, въ послѣ́днїй де́нь. рече́ же є҆́й і҆и҃съ: а҆́зъ є҆́смь воскреше́нїе и҆ живо́тъ: вѣ́рꙋѧй въ мѧ̀, а҆́ще и҆ ᲂу҆́мретъ, ѡ҆живе́тъ. и҆ всѧ́къ живы́й, и҆ вѣ́рꙋѧй въ мѧ̀, не ᲂу҆́мретъ во вѣ́ки: є҆́млеши ли вѣ́рꙋ семꙋ̀; глаго́ла є҆мꙋ̀: є҆́й гдⷭ҇и. а҆́зъ вѣ́ровахъ, ꙗ҆́кѡ ты̀ є҆сѝ хрⷭ҇то́съ сн҃ъ бж҃їй, и҆́же въ мі́ръ грѧды́й. и҆ сїѧ̑ ре́кши, и҆́де, и҆ пригласѝ марі́ю сестрꙋ̀ свою̀ та́й, ре́кши: ᲂу҆чи́тель прише́лъ є҆́сть, и҆ глаша́етъ тѧ̀. ѻ҆на́ же ꙗ҆́кѡ ᲂу҆слы́ша, воста̀ ско́рѡ, и҆ и҆́де къ немꙋ̀: не ᲂу҆же́ бо бѣ̀ прише́лъ і҆и҃съ въ ве́сь, но бѣ̀ на мѣ́стѣ, и҆дѣ́же срѣ́те є҆го̀ ма́рѳа. і҆ꙋде́є же ᲂу҆́бѡ сꙋ́щїи съ не́ю въ домꙋ̀, и҆ ᲂу҆тѣша́юще ю҆̀, ви́дѣвше марі́ю, ꙗ҆́кѡ ско́рѡ воста̀, и҆ и҆зы́де, по не́й и҆до́ша, глаго́люще: ꙗ҆́кѡ и҆́детъ на гро́бъ, да пла́четъ та́мѡ. марі́а же ꙗ҆́кѡ прїи́де, и҆дѣ́же бѣ̀ і҆и҃съ, ви́дѣвши є҆го̀, падѐ є҆мꙋ̀ на ногꙋ̀, глаго́лющи є҆мꙋ̀: гдⷭ҇и, а҆́ще бы бы́лъ здѣ̀, не бы̀ ᲂу҆́мерлъ мо́й бра́тъ. і҆и҃съ же ꙗ҆́кѡ ви́дѣ ю҆̀ пла́чꙋщꙋсѧ, и҆ прише́дшыѧ съ не́ю і҆ꙋдє́и пла́чꙋщѧ, запретѝ дꙋ́хꙋ, и҆ возмꙋти́сѧ са́мъ, и҆ речѐ: гдѣ̀ положи́сте є҆го̀; глаго́лаша є҆мꙋ̀: гдⷭ҇и, прїидѝ и҆ ви́ждь. прослези́сѧ і҆и҃съ. глаго́лахꙋ ᲂу҆́бѡ жи́дове: ви́ждь, ка́кѡ люблѧ́ше є҆го̀. нѣ́цыи же ѿ ни́хъ рѣ́ша: не можа́ше ли се́й ѿве́рзый ѻ҆́чи слѣпо́мꙋ, сотвори́ти, да и҆ се́й не ᲂу҆́мретъ; і҆и҃съ же па́ки претѧ̀ въ себѣ̀, прїи́де ко гро́бꙋ: бѣ́ же пеще́ра, и҆ ка́мень лежа́ше на не́й. глаго́ла і҆и҃съ: воз̾ми́те ка́мень. глаго́ла є҆мꙋ̀ сестра̀ ᲂу҆ме́ршагѡ, ма́рѳа: гдⷭ҇и, ᲂу҆жѐ смерди́тъ, четверодне́венъ бо є҆́сть. глаго́ла є҆́й і҆и҃съ: не рѣ́хъ ли тѝ, ꙗ҆́кѡ а҆́ще вѣ́рꙋеши, ᲂу҆́зриши сла́вꙋ бж҃їю; взѧ́ша же ка́мень, и҆дѣ́же бѣ̀ ᲂу҆ме́рый лежѧ̀. і҆и҃съ же возве́дъ ѻ҆́чи горѣ̀, и҆ речѐ: ѻ҆́ч҃е, хвалꙋ̀ тебѣ̀ воздаю̀, ꙗ҆́кѡ ᲂу҆слы́шалъ є҆сѝ мѧ̀. а҆́зъ же вѣ́дѣхъ, ꙗ҆́кѡ всегда́ мѧ послꙋ́шаеши: но наро́да ра́ди стоѧ́щагѡ ѻ҆́крестъ рѣ́хъ, да вѣ́рꙋ и҆́мꙋтъ, ꙗ҆́кѡ ты́ мѧ посла́лъ є҆сѝ. и҆ сїѧ̑ ре́къ, гла́сомъ вели́кимъ воззва̀: ла́заре, грѧдѝ во́нъ. и҆ и҆зы́де ᲂу҆ме́рый, ѡ҆бѧ́занъ рꙋка́ма и҆ нога́ма ᲂу҆кро́емъ, и҆ лицѐ є҆гѡ̀ ᲂу҆брꙋ́сомъ ѡ҆бѧ́зано. глаго́ла и҆̀мъ і҆и҃съ: разрѣши́те є҆го̀, и҆ ѡ҆ста́вите и҆тѝ. мно́зи бо ѿ і҆ꙋдє́й прише́дшїи къ марі́и, и҆ ви́дѣвше ꙗ҆̀же сотворѝ і҆и҃съ, вѣ́роваша въ него̀. ",
}

add_evangelie_ioanna {
  ["номер"] = 40,
  ["комментарий"] = "Ин., 40 зач., XI, 47–57.",
  ["текст_ру"] = "Во вре́мя о́но, собра́шася архиере́е и фарисе́е на Иису́са и глаго́лаху: что сотвори́м? Я́ко Челове́к Сей мно́га зна́мения твори́т? А́ще оста́вим Его́ та́ко, вси ве́руют в Него́, и прии́дут ри́мляне и во́змут ме́сто и язы́к наш. Еди́н же не́кто от них Каиа́фа, архиере́й сый ле́ту тому́, рече́ им: вы не ве́сте ничесо́же, ни помышля́ете, я́ко у́не есть нам, да еди́н челове́к у́мрет за лю́ди, а не весь язы́к поги́бнет. Сего́ же о себе́ не рече́, но архиере́й сый ле́ту тому́, прорече́, я́ко хотя́ше Иису́с умре́ти за лю́ди, и не то́кмо за лю́ди, но да и ча́да Бо́жия расточе́нная собере́т во еди́но. От того́же дне совеща́ша, да убию́т Его́. Иису́с же ктому́ не я́ве хожда́ше во Иуде́ех, но и́де отту́ду во страну́ близ пусты́ни, во Ефре́м нарица́емый град, и ту хожда́ше со ученики́ Свои́ми. Бе же близ фа́ска иуде́йска, и взыдо́ша мно́зи во Иеросоли́м от стран пре́жде Па́схи, да очи́стятся. Иска́ху у́бо Иису́са и глаго́лаху к себе́, в це́ркви стоя́ще: что мни́тся вам, я́ко не и́мать ли приити́ в пра́здник? Да́ша у́бо архиере́е и фарисе́е за́поведь, да а́ще кто ощути́т Его́, где бу́дет, пове́сть, я́ко да и́мут Его́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, собра́шасѧ а҆рхїере́є и҆ фарїсе́є на і҆и҃са и҆ глаго́лахꙋ: что̀ сотвори́мъ, ꙗ҆́кѡ человѣ́къ се́й мнѡ́га зна́мєнїѧ твори́тъ; а҆́ще ѡ҆ста́вимъ є҆го̀ та́кѡ, всѝ вѣ́рꙋютъ въ него̀: и҆ прїи́дꙋтъ ри́млѧне, и҆ во́з̾мꙋтъ мѣ́сто, и҆ ꙗ҆зы́къ на́шъ. є҆ди́нъ же нѣ́кто ѿ ни́хъ каїа́фа, а҆рхїере́й сы́й лѣ́тꙋ томꙋ̀, речѐ и҆̀мъ: вы̀ не вѣ́сте ничесѡ́же, ни помышлѧ́ете, ꙗ҆́кѡ ᲂу҆́не є҆́сть на́мъ, да є҆ди́нъ человѣ́къ ᲂу҆́мретъ за лю́ди, а҆ не ве́сь ꙗ҆зы́къ поги́бнетъ. сегѡ́ же ѡ҆ себѣ̀ не речѐ: но а҆рхїере́й сы́й лѣ́тꙋ томꙋ̀, проречѐ, ꙗ҆́кѡ хотѧ́ше і҆и҃съ ᲂу҆мре́ти за лю́ди: и҆ не то́кмѡ за лю́ди, но да и҆ ча̑да бж҃їѧ расточє́ннаѧ собере́тъ во є҆ди́но. ѿ тогѡ́же днѐ совѣща́ша, да ᲂу҆бїю́тъ є҆го̀. і҆и҃съ же ктомꙋ̀ не ꙗ҆́вѣ хожда́ше во і҆ꙋде́ехъ: но и҆́де ѿтꙋ́дꙋ во странꙋ̀ бли́зъ пꙋсты́ни, во є҆фре́мъ нарица́емый гра́дъ, и҆ тꙋ̀ хожда́ше со ᲂу҆ченикѝ свои́ми. бѣ́ же бли́зъ фа́ска і҆ꙋде́йска: и҆ взыдо́ша мно́зи во і҆еросолѵ́мъ ѿ стра́нъ пре́жде па́схи да ѡ҆чи́стѧтсѧ. и҆ска́хꙋ ᲂу҆́бѡ і҆и҃са, и҆ глаго́лахꙋ къ себѣ̀ въ це́ркви стоѧ́ще: что̀ мни́тсѧ ва́мъ, ꙗ҆́кѡ не и҆́мать ли прїитѝ въ пра́здникъ; да́ша ᲂу҆́бѡ а҆рхїере́є и҆ фарїсе́є за́повѣдь, да а҆́ще кто̀ ѡ҆щꙋти́тъ є҆го̀, гдѣ̀ бꙋ́детъ, повѣ́сть, ꙗ҆́кѡ да и҆́мꙋтъ є҆го̀. ",
}

add_evangelie_ioanna {
  ["номер"] = 41,
  ["комментарий"] = "Ин., 41 зач., XII, 1–18.",
  ["текст_ру"] = "Пре́жде шести́ дний Па́схи прии́де Иису́с в Вифа́нию, иде́же бе Ла́зарь уме́рый, его́же воскреси́ от ме́ртвых. Сотвори́ша же Ему́ ве́черю ту, и Ма́рфа служа́ше, Ла́зарь же еди́н бе от возлежа́щих с Ним. Мари́а же прие́мши ли́тру ми́ра на́рда писти́ка многоце́нны, пома́за но́зе Иису́сове, и отре́ власы́ свои́ми но́зе Его́. Хра́мина же испо́лнися от вони́ ма́сти благово́нныя. Глаго́ла же еди́н от учени́к Его́, Иу́да Си́монов Искарио́тский, и́же хотя́ше Его́ преда́ти: чесо́ ра́ди ми́ро сие́ не продано́ бысть на трех стех пе́нязь и дано́ ни́щым? Сие́ же рече́, не я́ко о ни́щих печа́шеся, но я́ко тать бе, и ковче́жец име́яше, и вмета́емая ноша́ше. Рече́ же Иису́с: не де́йте ея́, да в день погребе́ния Моего́ соблюде́т е́. Ни́щыя бо всегда́ и́мате с собо́ю, Мене́ же не всегда́ и́мате. Разуме́ же наро́д мног от иуде́й, я́ко ту есть, и приидо́ша не Иису́са ра́ди то́кмо, но да и Ла́заря ви́дят, его́же воскреси́ от ме́ртвых. Совеща́ша же архиере́е, да и Ла́заря убию́т, я́ко мно́зи его́ ра́ди идя́ху от иуде́й и ве́роваху во Иису́са. Во у́трий же день наро́д мног прише́дый в пра́здник, слы́шавше, я́ко Иису́с гряде́т во Иерусали́м, прия́ша ва́иа от фи́ник и изыдо́ша в сре́тение Ему́, и зва́ху глаго́люще: оса́нна, благослове́н гряды́й во и́мя Госпо́дне, Царь Изра́илев. Обре́т же Иису́с осля́, все́де на не, я́коже есть пи́сано: не бо́йся, дщи Сио́ня, се Царь твой гряде́т, седя́ на жребя́ти о́сли. Сих же не разуме́ша ученицы́ Его́ пре́жде, но егда́ просла́вися Иису́с, тогда́ помяну́ша, я́ко сия́ бы́ша о Нем пи́сана, и сия́ сотвори́ша Ему́. Свиде́тельствоваше же наро́д, и́же бе пре́жде с Ним, егда́ Ла́заря возгласи́ от гро́ба и воскреси́ его́ от ме́ртвых. Сего́ ра́ди и сре́те Его́ наро́д, я́ко слы́шаша Его́ сие́ сотво́рша зна́мение. ",
  ["текст_цс"] = "Пре́жде шестѝ дні́й па́схи, прїи́де і҆и҃съ въ виѳа́нїю, и҆дѣ́же бѣ̀ ла́зарь ᲂу҆ме́рый, є҆го́же воскресѝ ѿ ме́ртвыхъ. сотвори́ша же є҆мꙋ̀ ве́черю тꙋ̀, и҆ ма́рѳа слꙋжа́ше: ла́зарь же є҆ди́нъ бѣ̀ ѿ возлежа́щихъ съ ни́мъ. марі́а же прїе́мши лі́трꙋ мѵ́ра на́рда пїсті́ки многоцѣ́нны, пома́за но́зѣ і҆и҃совѣ, и҆ ѡ҆трѐ власы̀ свои́ми но́зѣ є҆гѡ̀. хра́мина же и҆спо́лнисѧ ѿ вонѝ ма́сти благово́нныѧ. глаго́ла же є҆ди́нъ ѿ ᲂу҆чени̑къ є҆гѡ̀, і҆ꙋ́да сі́мѡновъ і҆скарїѡ́тскїй, и҆́же хотѧ́ше є҆го̀ преда́ти: чесѡ̀ ра́ди мѵ́ро сїѐ не продано̀ бы́сть на тре́хъ стѣ́хъ пѣ̑нѧзь, и҆ дано̀ ни́щымъ; сїе́ же речѐ, не ꙗ҆́кѡ ѡ҆ ни́щихъ печа́шесѧ, но ꙗ҆́кѡ та́ть бѣ̀, и҆ ковче́жецъ и҆мѣ́ѧше, и҆ вмета́ємаѧ ноша́ше. рече́ же і҆и҃съ: не дѣ́йте є҆ѧ̀, да въ де́нь погребе́нїѧ моегѡ̀ соблюде́тъ є҆̀. ни́щыѧ бо всегда̀ и҆́мате съ собо́ю: мене́ же не всегда̀ и҆́мате. разꙋмѣ́ же наро́дъ мно́гъ ѿ і҆ꙋдє́й, ꙗ҆́кѡ тꙋ̀ є҆́сть: и҆ прїидо́ша не і҆и҃са ра́ди то́кмѡ, но да и҆ ла́зарѧ ви́дѧтъ, є҆го́же воскресѝ ѿ ме́ртвыхъ. совѣща́ша же а҆рхїере́є, да и҆ ла́зарѧ ᲂу҆бїю́тъ: ꙗ҆́кѡ мно́зи є҆гѡ̀ ра́ди и҆дѧ́хꙋ ѿ і҆ꙋдє́й, и҆ вѣ́ровахꙋ во і҆и҃са. во ᲂу҆́трїй же де́нь наро́дъ мно́гъ прише́дый въ пра́здникъ, слы́шавше ꙗ҆́кѡ і҆и҃съ грѧде́тъ во і҆ерꙋсали́мъ, прїѧ́ша ва̑їа ѿ фі̑нїкъ, и҆ и҆зыдо́ша въ срѣ́тенїе є҆мꙋ̀, и҆ зва́хꙋ глаго́люще: ѡ҆са́нна, благослове́нъ грѧды́й во и҆́мѧ гдⷭ҇не, цр҃ь і҆и҃левъ. ѡ҆брѣ́тъ же і҆и҃съ ѻ҆слѧ̀, всѣ́де на нѐ, ꙗ҆́коже є҆́сть пи́сано: не бо́йсѧ дщѝ сїѡ́нѧ, сѐ цр҃ь тво́й грѧде́тъ, сѣдѧ̀ на жребѧ́ти ѻ҆́сли. си́хъ же не разꙋмѣ́ша ᲂу҆ченицы̀ є҆гѡ̀ пре́жде: но є҆гда̀ просла́висѧ і҆и҃съ, тогда̀ помѧнꙋ́ша, ꙗ҆́кѡ сїѧ̑ бы́ша ѡ҆ не́мъ пи́сана, и҆ сїѧ̑ сотвори́ша є҆мꙋ̀. свидѣ́тельствоваше же наро́дъ, и҆́же бѣ̀ пре́жде съ ни́мъ, є҆гда̀ ла́зарѧ возгласѝ ѿ гро́ба, и҆ воскресѝ є҆го̀ ѿ ме́ртвыхъ. сегѡ̀ ра́ди и҆ срѣ́те є҆го̀ наро́дъ, ꙗ҆́кѡ слы́шаша є҆го̀ сїѐ сотво́рша зна́менїе. ",
}

add_evangelie_ioanna {
  ["номер"] = 41,
  ["комментарий"] = "Ин., 41 зач., XII, 17-50.",
  ["текст_ру"] = "Во вре́мя о́но, свиде́тельствоваше наро́д сый со Иису́сом, егда́ Ла́заря возгласи́ от гро́ба и воскреси́ его́ от ме́ртвых. Сего́ ра́ди и сре́те Его́ наро́д, я́ко слы́шаша Его́ сие́ сотво́рша зна́мение. Фарисе́е же ре́ша к себе́: ви́дите, я́ко ника́яже по́льза есть? Се мир по Нем и́дет. Бя́ху же не́цыи е́ллини от вше́дших, да покло́нятся в пра́здник. Си́и у́бо приступи́ша к Фили́ппу, и́же бе от Вифсаи́ды Галиле́йския, и моля́ху его́, глаго́люще: го́споди, хо́щем Иису́са ви́дети. Прии́де Фили́пп и глаго́ла Андре́ови, и па́ки Андре́й и Фили́пп глаго́ласта Иису́сови. Иису́с же отвеща́ и́ма, глаго́ля: прии́де час, да просла́вится Сын Челове́ческий. Ами́нь, ами́нь глаго́лю вам, а́ще зе́рно пшени́чно пад на земли́ не у́мрет, то еди́но пребыва́ет, а́ще же у́мрет, мног плод сотвори́т. Любя́й ду́шу свою́ погуби́т ю́, и ненави́дяй ду́шу свою́ в ми́ре сем в животе́ ве́чнем сохрани́т ю́. А́ще кто Мне слу́жит, Мне да после́дствует, и иде́же есмь Аз, ту и слуга́ Мой бу́дет, и а́ще кто Мне слу́жит, почти́т его́ Оте́ц Мой. Ны́не душа́ Моя́ возмути́ся, и что реку́? О́тче, спаси́ Мя от часа́ сего́, но сего́ ра́ди приидо́х на час сей. О́тче, просла́ви и́мя Твое́. Прии́де же глас с небесе́: и просла́вих, и па́ки просла́влю. Наро́д же стоя́й слы́шав, глаго́лаху: гром бысть. Ини́и глаго́лаху: А́нгел глаго́ла Ему́. Отвеща́ Иису́с и рече́: не Мене́ ра́ди глас сей бысть, но наро́да ра́ди. Ны́не суд есть ми́ру сему́, ны́не князь ми́ра сего́ изгна́н бу́дет вон. И а́ще Аз вознесе́н бу́ду от земли́, вся привлеку́ к Себе́. Сие́ же глаго́лаше, назна́менуя, ко́ею сме́ртию хотя́ше умре́ти. Отвеща́ Ему́ наро́д: мы слы́шахом от зако́на, я́ко Христо́с пребыва́ет во ве́ки, ка́ко Ты глаго́леши, вознести́ся подоба́ет Сы́ну Челове́ческому? Кто есть Сей Сын Челове́ческий? Рече́ же им Иису́с: еще́ ма́ло вре́мя свет в вас есть. Ходи́те, до́ндеже свет и́мате, да тма вас не и́мет, и ходя́й во тме не весть, ка́мо и́дет. До́ндеже свет и́мате, ве́руйте во свет, да сы́нове све́та бу́дете. Сия́ глаго́ла Иису́с, и отше́д скры́ся от них. Толи́ка зна́мения сотво́ршу Ему́ пред ни́ми, не ве́роваху в Него́, да сбу́дется сло́во Иса́ии проро́ка, е́же рече́: Го́споди, кто ве́рова слу́ху на́шему, и мы́шца Госпо́дня кому́ откры́ся? Сего́ ра́ди не можа́ху ве́ровати, я́ко па́ки рече́ Иса́иа: ослепи́ о́чи их и ока́менил есть сердца́ их, да не ви́дят очи́ма, ни разуме́ют се́рдцем, и обратя́тся, и исцелю́ их. Сия́ рече́ Иса́иа, егда́ ви́де сла́ву Его́ и глаго́ла о Нем. Оба́че у́бо и от князь мно́зи ве́роваша в Него́, но фарисе́й ра́ди не испове́доваху, да не из со́нмищ изгна́ни бу́дут. Возлюби́ша бо па́че сла́ву челове́ческую, не́же сла́ву Бо́жию. Иису́с же воззва́ и рече́: ве́руяй в Мя не ве́рует в Мя, но в Посла́вшаго Мя. И ви́дяй Мя ви́дит Посла́вшаго Мя. Аз свет в мир приидо́х, да всяк ве́руяй в Мя во тме не пребу́дет. И а́ще кто услы́шит глаго́лы Моя́ и не ве́рует, Аз не сужду́ ему́, не приидо́х бо, да сужду́ ми́рови, но да спасу́ мир. Отмета́яйся Мене́ и не прие́мляй глаго́л Мои́х и́мать судя́щаго ему́, сло́во, е́же глаго́лах, то су́дит ему́ в после́дний день. Я́ко Аз о Себе́ не глаго́лах, но посла́вый Мя Оте́ц, Той Мне за́поведь даде́, что реку́ и что возглаго́лю. И вем, я́ко за́поведь Его́ живо́т ве́чный есть, я́же у́бо Аз глаго́лю, я́коже рече́ Мне Оте́ц, та́ко глаго́лю. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, свидѣ́тельствоваше наро́дъ сы́й со і҆и҃сомъ, є҆гда̀ ла́зарѧ возгласѝ ѿ гро́ба, и҆ воскресѝ є҆го̀ ѿ ме́ртвыхъ. сегѡ̀ ра́ди и҆ срѣ́те є҆го̀ наро́дъ, ꙗ҆́кѡ слы́шаша є҆го̀ сїѐ сотво́рша зна́менїе. фарїсе́є же рѣ́ша къ себѣ̀: ви́дите, ꙗ҆́кѡ ника́ѧже по́льза є҆́сть, сѐ мі́ръ по не́мъ и҆́детъ. бѧ́хꙋ же нѣ́цыи є҆́ллини ѿ вше́дшихъ, да покло́нѧтсѧ въ пра́здникъ. сі́и ᲂу҆̀бо пристꙋпи́ша къ фїлі́ппꙋ, и҆́же бѣ̀ ѿ виѳсаі́ды галїле́йскїѧ, и҆ молѧ́хꙋ є҆го̀, глаго́люще: гдⷭ҇и, хо́щемъ і҆и҃са ви́дѣти. прїи́де фїлі́ппъ и҆ глаго́ла а҆ндре́ови: и҆ па́ки а҆ндре́й и҆ фїлі́ппъ глаго́ласта і҆и҃сови. і҆и҃съ же ѿвѣща̀ и҆́ма, глаго́лѧ: прїи́де ча́съ, да просла́витсѧ сн҃ъ человѣ́ческїй. а҆ми́нь а҆ми́нь глаго́лю ва́мъ, а҆́ще зе́рно пшени́чно па́дъ на землѝ не ᲂу҆́мретъ, то̀ є҆ди́но пребыва́етъ: а҆́ще ли ᲂу҆́мретъ, мно́гъ пло́дъ сотвори́тъ. любѧ́й дꙋ́шꙋ свою̀ погꙋби́тъ ю҆̀: и҆ ненави́дѧй дꙋ́шꙋ свою̀ въ мі́рѣ се́мъ, въ животѣ̀ вѣ́чнѣмъ сохрани́тъ ю҆̀. а҆́ще кто̀ мнѣ̀ слꙋ́житъ, мнѣ̀ да послѣ́дствꙋетъ: и҆ и҆дѣ́же є҆́смь а҆́зъ, тꙋ̀ и҆ слꙋга̀ мо́й бꙋ́детъ. и҆ а҆́ще кто̀ мнѣ̀ слꙋ́житъ, почти́тъ є҆го̀ ѻ҆ц҃ъ мо́й. ны́нѣ дꙋша̀ моѧ̀ возмꙋти́сѧ, и҆ что̀ рекꙋ̀; ѻ҆́ч҃е, спаси́ мѧ ѿ часа̀ сегѡ̀: но сегѡ̀ ра́ди прїидо́хъ на ча́съ се́й. ѻ҆́ч҃е, просла́ви и҆́мѧ твоѐ. прїи́де же гла́съ съ нб҃сѐ: и҆ просла́вихъ, и҆ па́ки просла́влю. наро́дъ же стоѧ́й слы́шавъ, глаго́лахꙋ: гро́мъ бы́сть. и҆ні́и глаго́лахꙋ: а҆́гг҃лъ глаго́ла є҆мꙋ̀. ѿвѣща̀ і҆и҃съ, и҆ речѐ: не менѐ ра́ди гла́съ се́й бы́сть, но наро́да ра́ди. ны́нѣ сꙋ́дъ є҆́сть мі́рꙋ семꙋ̀: ны́нѣ кнѧ́зь мі́ра сегѡ̀ и҆згна́нъ бꙋ́детъ во́нъ. и҆ а҆́ще а҆́зъ вознесе́нъ бꙋ́дꙋ ѿ землѝ, всѧ̑ привлекꙋ̀ къ себѣ̀. сїе́ же глаго́лаше, назна́менꙋѧ, ко́ею сме́ртїю хотѧ́ше ᲂу҆мре́ти. ѿвѣща̀ є҆мꙋ̀ наро́дъ: мы̀ слы́шахомъ ѿ зако́на, ꙗ҆́кѡ хрⷭ҇то́съ пребыва́етъ во вѣ́ки: ка́кѡ ты̀ глаго́леши, вознести́сѧ подоба́етъ сн҃ꙋ человѣ́ческомꙋ; кто̀ є҆́сть се́й сн҃ъ человѣ́ческїй; рече́ же и҆̀мъ і҆и҃съ: є҆щѐ ма́ло вре́мѧ свѣ́тъ въ ва́съ є҆́сть. ходи́те до́ндеже свѣ́тъ и҆́мате, да тма̀ ва́съ не и҆́метъ: и҆ ходѧ́й во тмѣ̀, не вѣ́сть, ка́мѡ и҆́детъ. до́ндеже свѣ́тъ и҆́мате, вѣ́рꙋйте во свѣ́тъ, да сы́нове свѣ́та бꙋ́дете. сїѧ̑ глаго́ла і҆и҃съ, и҆ ѿше́дъ скры́сѧ ѿ ни́хъ. толи̑ка зна́мєнїѧ сотво́ршꙋ є҆мꙋ̀ пред̾ ни́ми, не вѣ́ровахꙋ въ него̀. да сбꙋ́детсѧ сло́во и҆са́їи проро́ка, є҆́же речѐ: гдⷭ҇и, кто̀ вѣ́рова слꙋ́хꙋ на́шемꙋ; и҆ мы́шца гдⷭ҇нѧ комꙋ̀ ѿкры́сѧ; сегѡ̀ ра́ди не можа́хꙋ вѣ́ровати, ꙗ҆́кѡ па́ки речѐ и҆са́їа: ѡ҆слѣпѝ ѻ҆́чи и҆́хъ, и҆ ѡ҆ка́менилъ є҆́сть сердца̀ и҆́хъ, да не ви́дѧтъ ѻ҆чи́ма, ни разꙋмѣ́ютъ се́рдцемъ, и҆ ѡ҆братѧ́тсѧ, и҆ и҆сцѣлю̀ и҆̀хъ. сїѧ̑ речѐ и҆са́їа, є҆гда̀ ви́дѣ сла́вꙋ є҆гѡ̀, и҆ глаго́ла ѡ҆ не́мъ. ѻ҆ба́че ᲂу҆́бѡ и҆ ѿ кнѧ̑зь мно́зи вѣ́роваша въ него̀, но фарїсє́й ра́ди не и҆сповѣ́довахꙋ, да не и҆з̾ со́нмищъ и҆згна́ни бꙋ́дꙋтъ. возлюби́ша бо па́че сла́вꙋ человѣ́ческꙋю, не́же сла́вꙋ бж҃їю. і҆и҃съ же воззва̀, и҆ речѐ: вѣ́рꙋѧй въ мѧ̀, не вѣ́рꙋетъ въ мѧ̀, но въ посла́вшаго мѧ̀. и҆ ви́дѧй мѧ̀, ви́дитъ посла́вшаго мѧ̀. а҆́зъ свѣ́тъ въ мі́ръ прїидо́хъ, да всѧ́къ вѣ́рꙋѧй въ мѧ̀, во тмѣ̀ не пребꙋ́детъ. и҆ а҆́ще кто̀ ᲂу҆слы́шитъ глаго́лы моѧ̀ и҆ не вѣ́рꙋетъ, а҆́зъ не сꙋждꙋ̀ є҆мꙋ̀: не прїидо́хъ бо, да сꙋждꙋ̀ мі́рови, но да спасꙋ̀ мі́ръ. ѿмета́ѧйсѧ менѐ и҆ не прїе́млѧй глагѡ́лъ мои́хъ, и҆́мать сꙋдѧ́щаго є҆мꙋ̀: сло́во, є҆́же глаго́лахъ, то̀ сꙋ́дитъ є҆мꙋ̀ въ послѣ́днїй де́нь. ꙗ҆́кѡ а҆́зъ ѡ҆ себѣ̀ не глаго́лахъ: но посла́вый мѧ̀ ѻ҆ц҃ъ, то́й мнѣ̀ за́повѣдь дадѐ, что̀ рекꙋ̀, и҆ что̀ возглаго́лю. и҆ вѣ́мъ, ꙗ҆́кѡ за́повѣдь є҆гѡ̀ живо́тъ вѣ́чный є҆́сть: ꙗ҆̀же ᲂу҆́бѡ а҆́зъ глаго́лю, ꙗ҆́коже речѐ мнѣ̀ ѻ҆ц҃ъ, та́кѡ глаго́лю. ",
}

