  ["номер"] = 42,
  ["комментарий"] = "Ин., 42 зач., XII, 28-36.",
  ["текст_ру"] = "Рече́ Госпо́дь: О́тче, просла́ви и́мя Твое́. Прии́де же глас с небесе́: и просла́вих, и па́ки просла́влю. Наро́д же стоя́й слы́шав, глаго́лаху: гром бысть. Ини́и глаго́лаху: А́нгел глаго́ла Ему́. Отвеща́ Иису́с и рече́: не Мене́ ра́ди глас сей бысть, но наро́да ра́ди. Ны́не суд есть ми́ру сему́, ны́не князь ми́ра сего́ изгна́н бу́дет вон. И а́ще Аз вознесе́н бу́ду от земли́, вся привлеку́ к Себе́. Сие́ же глаго́лаше, назна́менуя, ко́ею сме́ртию хотя́ше умре́ти. Отвеща́ Ему́ наро́д: мы слы́шахом от зако́на, я́ко Христо́с пребыва́ет во ве́ки, ка́ко Ты глаго́леши, вознести́ся подоба́ет Сы́ну Челове́ческому? Кто есть Сей Сын Челове́ческий? Рече́ же им Иису́с: еще́ ма́ло вре́мя свет в вас есть. Ходи́те, до́ндеже свет и́мате, да тма вас не и́мет, и ходя́й во тме не весть, ка́мо и́дет. До́ндеже свет и́мате, ве́руйте во свет, да сы́нове све́та бу́дете. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь: ѻ҆́ч҃е, просла́ви и҆́мѧ твоѐ. прїи́де же гла́съ съ нб҃сѐ: и҆ просла́вихъ, и҆ па́ки просла́влю. наро́дъ же стоѧ́й слы́шавъ, глаго́лахꙋ: гро́мъ бы́сть. и҆ні́и глаго́лахꙋ: а҆́гг҃лъ глаго́ла є҆мꙋ̀. ѿвѣща̀ і҆и҃съ, и҆ речѐ: не менѐ ра́ди гла́съ се́й бы́сть, но наро́да ра́ди. ны́нѣ сꙋ́дъ є҆́сть мі́рꙋ семꙋ̀: ны́нѣ кнѧ́зь мі́ра сегѡ̀ и҆згна́нъ бꙋ́детъ во́нъ. и҆ а҆́ще а҆́зъ вознесе́нъ бꙋ́дꙋ ѿ землѝ, всѧ̑ привлекꙋ̀ къ себѣ̀. сїе́ же глаго́лаше, назна́менꙋѧ, ко́ею сме́ртїю хотѧ́ше ᲂу҆мре́ти. ѿвѣща̀ є҆мꙋ̀ наро́дъ: мы̀ слы́шахомъ ѿ зако́на, ꙗ҆́кѡ хрⷭ҇то́съ пребыва́етъ во вѣ́ки: ка́кѡ ты̀ глаго́леши, вознести́сѧ подоба́етъ сн҃ꙋ человѣ́ческомꙋ; кто̀ є҆́сть се́й сн҃ъ человѣ́ческїй; рече́ же и҆̀мъ і҆и҃съ: є҆щѐ ма́ло вре́мѧ свѣ́тъ въ ва́съ є҆́сть. ходи́те до́ндеже свѣ́тъ и҆́мате, да тма̀ ва́съ не и҆́метъ: и҆ ходѧ́й во тмѣ̀, не вѣ́сть, ка́мѡ и҆́детъ. до́ндеже свѣ́тъ и҆́мате, вѣ́рꙋйте во свѣ́тъ, да сы́нове свѣ́та бꙋ́дете. ",
}

add_evangelie_ioanna {
  ["номер"] = 43,
  ["комментарий"] = "Ин., 43 зач., XII, 36–47.",
  ["текст_ру"] = "Рече́ Госпо́дь ко прише́дшым к Нему́ иуде́ем: до́ндеже свет и́мате, ве́руйте во свет, да сы́нове све́та бу́дете. Сия́ глаго́ла Иису́с, и отше́д скры́ся от них. Толи́ка зна́мения сотво́ршу Ему́ пред ни́ми, не ве́роваху в Него́, да сбу́дется сло́во Иса́ии проро́ка, е́же рече́: Го́споди, кто ве́рова слу́ху на́шему, и мы́шца Госпо́дня кому́ откры́ся? Сего́ ра́ди не можа́ху ве́ровати, я́ко па́ки рече́ Иса́иа: ослепи́ о́чи их и ока́менил есть сердца́ их, да не ви́дят очи́ма, ни разуме́ют се́рдцем, и обратя́тся, и исцелю́ их. Сия́ рече́ Иса́иа, егда́ ви́де сла́ву Его́ и глаго́ла о Нем. Оба́че у́бо и от князь мно́зи ве́роваша в Него́, но фарисе́й ра́ди не испове́доваху, да не из со́нмищ изгна́ни бу́дут. Возлюби́ша бо па́че сла́ву челове́ческую, не́же сла́ву Бо́жию. Иису́с же воззва́ и рече́: ве́руяй в Мя не ве́рует в Мя, но в Посла́вшаго Мя. И ви́дяй Мя ви́дит Посла́вшаго Мя. Аз свет в мир приидо́х, да всяк ве́руяй в Мя во тме не пребу́дет. И а́ще кто услы́шит глаго́лы Моя́ и не ве́рует, Аз не сужду́ ему́, не приидо́х бо, да сужду́ ми́рови, но да спасу́ мир. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь ко прише́дшымъ къ немꙋ̀ і҆ꙋде́ємъ: до́ндеже свѣ́тъ и҆́мате, вѣ́рꙋйте во свѣ́тъ, да сы́нове свѣ́та бꙋ́дете. сїѧ̑ глаго́ла і҆и҃съ, и҆ ѿше́дъ скры́сѧ ѿ ни́хъ. толи̑ка зна́мєнїѧ сотво́ршꙋ є҆мꙋ̀ пред̾ ни́ми, не вѣ́ровахꙋ въ него̀. да сбꙋ́детсѧ сло́во и҆са́їи проро́ка, є҆́же речѐ: гдⷭ҇и, кто̀ вѣ́рова слꙋ́хꙋ на́шемꙋ; и҆ мы́шца гдⷭ҇нѧ комꙋ̀ ѿкры́сѧ; сегѡ̀ ра́ди не можа́хꙋ вѣ́ровати, ꙗ҆́кѡ па́ки речѐ и҆са́їа: ѡ҆слѣпѝ ѻ҆́чи и҆́хъ, и҆ ѡ҆ка́менилъ є҆́сть сердца̀ и҆́хъ, да не ви́дѧтъ ѻ҆чи́ма, ни разꙋмѣ́ютъ се́рдцемъ, и҆ ѡ҆братѧ́тсѧ, и҆ и҆сцѣлю̀ и҆̀хъ. сїѧ̑ речѐ и҆са́їа, є҆гда̀ ви́дѣ сла́вꙋ є҆гѡ̀, и҆ глаго́ла ѡ҆ не́мъ. ѻ҆ба́че ᲂу҆́бѡ и҆ ѿ кнѧ̑зь мно́зи вѣ́роваша въ него̀, но фарїсє́й ра́ди не и҆сповѣ́довахꙋ, да не и҆з̾ со́нмищъ и҆згна́ни бꙋ́дꙋтъ. возлюби́ша бо па́че сла́вꙋ человѣ́ческꙋю, не́же сла́вꙋ бж҃їю. і҆и҃съ же воззва̀, и҆ речѐ: вѣ́рꙋѧй въ мѧ̀, не вѣ́рꙋетъ въ мѧ̀, но въ посла́вшаго мѧ̀. и҆ ви́дѧй мѧ̀, ви́дитъ посла́вшаго мѧ̀. а҆́зъ свѣ́тъ въ мі́ръ прїидо́хъ, да всѧ́къ вѣ́рꙋѧй въ мѧ̀, во тмѣ̀ не пребꙋ́детъ. и҆ а҆́ще кто̀ ᲂу҆слы́шитъ глаго́лы моѧ̀ и҆ не вѣ́рꙋетъ, а҆́зъ не сꙋждꙋ̀ є҆мꙋ̀: не прїидо́хъ бо, да сꙋждꙋ̀ мі́рови, но да спасꙋ̀ мі́ръ. ",
}

add_evangelie_ioanna {
  ["номер"] = 44,
  ["комментарий"] = "Ин., 44 зач., XIII, 1-11.",
  ["текст_ру"] = "Во вре́мя о́но, пре́жде пра́здника Па́схи, ве́дый Иису́с, я́ко прии́де Ему́ час, да пре́йдет от ми́ра сего́ ко Отцу́, возлю́бль Своя́ су́щыя в ми́ре, до конца́ возлюби́ их. И ве́чери бы́вши, диа́волу уже́ вложи́вшу в се́рдце Иу́де Си́монову Искарио́тскому, да Его́ преда́ст, ве́дый Иису́с, я́ко вся даде́ Ему́ Оте́ц в ру́це, и я́ко от Бо́га изы́де и к Бо́гу гряде́т, воста́в с ве́чери и положи́ ри́зы, и прие́м ле́нтион, препоя́сася, пото́м же влия́ во́ду во умыва́льницу и нача́т умыва́ти но́ги ученико́м и отира́ти ле́нтием, и́мже бе препоя́сан. Прии́де же к Си́мону Петру́, и глаго́ла Ему́ той: Го́споди, Ты ли мои́ умы́еши но́зе? Отвеща́ Иису́с и рече́ ему́: е́же Аз творю́, ты не ве́си ны́не, разуме́еши же по сих. Глаго́ла Ему́ Петр: не умы́еши но́гу мое́ю во ве́ки. Отвеща́ ему́ Иису́с: а́ще не умы́ю тебе́, не и́маши ча́сти со Мно́ю. Глаго́ла Ему́ Си́мон Петр: Го́споди, не но́зе мои́ то́кмо, но и ру́це и главу́. Глаго́ла ему́ Иису́с: измове́нный не тре́бует, то́кмо но́зе умы́ти, есть бо весь чист, и вы чи́сти есте́, но не вси. Ве́дяше бо предаю́щаго Его́, сего́ ра́ди рече́, я́ко не вси чи́сти есте́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, пре́жде пра́здника па́схи, вѣ́дый і҆и҃съ, ꙗ҆́кѡ прїи́де є҆мꙋ̀ ча́съ, да пре́йдетъ ѿ мі́ра сегѡ̀ ко ѻ҆ц҃ꙋ̀, возлю́бль своѧ̑ сꙋ́щыѧ въ мі́рѣ, до конца̀ возлюбѝ ѧ҆̀. и҆ ве́чери бы́вши, дїа́волꙋ ᲂу҆жѐ вложи́вшꙋ въ се́рдце і҆ꙋ́дѣ сі́мѡновꙋ и҆скарїѡ́тскомꙋ, да є҆го̀ преда́стъ, вѣ́дый і҆и҃съ, ꙗ҆́кѡ всѧ̑ дадѐ є҆мꙋ̀ ѻ҆ц҃ъ въ рꙋ́цѣ, и҆ ꙗ҆́кѡ ѿ бг҃а и҆зы́де, и҆ къ бг҃ꙋ грѧде́тъ: воста́въ съ ве́чери, и҆ положѝ ри̑зы, и҆ прїе́мъ ле́нтїонъ, препоѧ́сасѧ. пото́мъ же влїѧ̀ во́дꙋ во ᲂу҆мыва́льницꙋ, и҆ нача́тъ ᲂу҆мыва́ти но́ги ᲂу҆ченикѡ́мъ, и҆ ѡ҆тира́ти ле́нтїемъ, и҆́мже бѣ̀ препоѧ́санъ. прїи́де же къ сі́мѡнꙋ петрꙋ̀, и҆ глаго́ла є҆мꙋ̀ то́й: гдⷭ҇и, ты́ ли моѝ ᲂу҆мы́еши но́зѣ; ѿвѣща̀ і҆и҃съ, и҆ речѐ є҆мꙋ̀: є҆́же а҆́зъ творю̀, ты̀ не вѣ́си ны́нѣ, разꙋмѣ́еши же по си́хъ. глаго́ла є҆мꙋ̀ пе́тръ: не ᲂу҆мы́еши нѡ́гꙋ мое́ю во вѣ́ки. ѿвѣща̀ є҆мꙋ̀ і҆и҃съ: а҆́ще не ᲂу҆мы́ю тебѐ, не и҆́маши ча́сти со мно́ю. глаго́ла є҆мꙋ̀ сі́мѡнъ пе́тръ: гдⷭ҇и, не но́зѣ моѝ то́кмѡ, но и҆ рꙋ́цѣ и҆ главꙋ̀. глаго́ла є҆мꙋ̀ і҆и҃съ: и҆змове́нный не тре́бꙋетъ, то́кмѡ но́зѣ ᲂу҆мы́ти, є҆́сть бо ве́сь чи́стъ: и҆ вы̀ чи́сти є҆стѐ, но не всѝ. вѣ́дѧше бо предаю́щаго є҆го̀ сегѡ̀ ра́ди речѐ: ꙗ҆́кѡ не всѝ чи́сти є҆стѐ. ",
}

add_evangelie_ioanna {
  ["номер"] = 45,
  ["комментарий"] = "Ин., 45 зач., XIII, 12–17.",
  ["текст_ру"] = "Во вре́мя о́но, егда́ умы́ Иису́с но́зе ученико́м, прия́т ри́зы Своя́, возле́г па́ки, рече́ им: ве́сте ли, что сотвори́х вам? Вы глаша́ете Мя Учи́теля и Го́спода, и до́бре глаго́лете, есмь бо. А́ще у́бо Аз умы́х ва́ши но́зе, Госпо́дь и Учи́тель, и вы до́лжни есте́ друг дру́гу умыва́ти но́зе. О́браз бо дах вам, да я́коже Аз сотвори́х вам, и вы твори́те. Ами́нь, ами́нь глаго́лю вам: несть раб бо́лий го́спода своего́, ни посла́нник бо́лий посла́вшаго его́. А́ще сия́ ве́сте, блаже́ни есте́, а́ще творите́ я́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, є҆гда̀ ᲂу҆мы̀ і҆и҃съ но́зѣ ᲂу҆ченикѡ́мъ, прїѧ́тъ ри̑зы своѧ̀, возле́гъ па́ки, речѐ и҆̀мъ: вѣ́сте ли что̀ сотвори́хъ ва́мъ; вы̀ глаша́ете мѧ̀ ᲂу҆чи́телѧ и҆ гдⷭ҇а: и҆ до́брѣ глаго́лете, є҆́смь бо. а҆́ще ᲂу҆́бѡ а҆́зъ ᲂу҆мы́хъ ва́ши но́зѣ, гдⷭ҇ь и҆ ᲂу҆чи́тель: и҆ вы̀ до́лжни є҆стѐ дрꙋ́гъ дрꙋ́гꙋ ᲂу҆мыва́ти но́зѣ. ѻ҆́бразъ бо да́хъ ва́мъ, да ꙗ҆́коже а҆́зъ сотвори́хъ ва́мъ, и҆ вы̀ твори́те. а҆ми́нь а҆ми́нь глаго́лю ва́мъ: нѣ́сть ра́бъ бо́лїй гдⷭ҇а своегѡ̀, ни посла́нникъ бо́лїй посла́вшагѡ є҆го̀. а҆́ще сїѧ̑ вѣ́сте, блаже́ни є҆стѐ, а҆́ще творитѐ ѧ҆̀. ",
}

add_evangelie_ioanna {
  ["номер"] = 46,
  ["комментарий"] = "Ин., 46 зач., XIII, 31 – XVIII, 1.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: ны́не просла́вися Сын Челове́ческий, и Бог просла́вися о Нем. А́ще Бог просла́вися о Нем, и Бог просла́вит Его́ в Себе́, и а́бие просла́вит Его́. Ча́дца, еще́ с ва́ми ма́ло есмь, взы́щете Мене́, и я́коже рех иуде́ем, я́ко а́може Аз иду́, вы не мо́жете приити́, и вам глаго́лю ны́не. За́поведь но́вую даю́ вам, да лю́бите друг дру́га, я́коже возлюби́х вы, да и вы лю́бите себе́. О сем разуме́ют вси, я́ко Мои́ ученицы́ есте́, а́ще любо́вь и́мате между́ собо́ю. Глаго́ла Ему́ Си́мон Петр: Го́споди, ка́мо и́деши? Отвеща́ ему́ Иису́с: а́може Аз иду́, не мо́жеши ны́не по Мне ити́, последи́ же по Мне и́деши. Глаго́ла Ему́ Петр: Го́споди, почто́ не могу́ ны́не по Тебе́ ити́? ны́не ду́шу мою́ за Тя положу́. Отвеща́ ему́ Иису́с: ду́шу ли твою́ за Мя положи́ши? Ами́нь, ами́нь глаго́лю тебе́, не возгласи́т але́ктор, до́ндеже отве́ржешися Мене́ три́щи. Да не смуща́ется се́рдце ва́ше, ве́руйте в Бо́га, и в Мя ве́руйте. В дому́ Отца́ Моего́ оби́тели мно́ги суть, а́ще ли же ни, рекл бых вам: иду́ угото́вати ме́сто вам. И а́ще поиду́ и угото́влю ме́сто вам, па́ки прииду́ и поиму́ вы к Себе́, да иде́же есмь Аз, и вы бу́дете, и а́може Аз иду́, ве́сте, и путь ве́сте. Глаго́ла Ему́ Фома́: Го́споди, не ве́мы, ка́мо и́деши, и ка́ко мо́жем путь ве́дети? Глаго́ла ему́ Иису́с: Аз есмь путь и и́стина и живо́т, никто́же прии́дет ко Отцу́, то́кмо Мно́ю. А́ще Мя бы́сте зна́ли, и Отца́ Моего́ зна́ли бы́сте у́бо, и отсе́ле позна́сте Его́, и ви́десте Его́. Глаго́ла Ему́ Фили́пп: Го́споди, покажи́ нам Отца́, и довле́ет нам. Глаго́ла ему́ Иису́с: толи́ко вре́мя с ва́ми есмь, и не позна́л еси́ Мене́, Фили́ппе? Ви́девый Мене́ ви́де Отца́, и ка́ко ты глаго́леши: покажи́ нам Отца́? Не ве́руеши ли, я́ко Аз во Отце́, и Оте́ц во Мне есть? Глаго́лы, я́же Аз глаго́лю вам, о Себе́ не глаго́лю, Оте́ц же во Мне пребыва́яй, Той твори́т дела́. Ве́руйте Мне, я́ко Аз во Отце́, и Оте́ц во Мне. А́ще ли же ни, за та дела́ ве́ру ими́те Ми. Ами́нь, ами́нь глаго́лю вам: ве́руяй в Мя, дела́, я́же Аз творю́, и той сотвори́т, и бо́льша сих сотвори́т, я́ко Аз ко Отцу́ Моему́ гряду́. И е́же а́ще что про́сите от Отца́ о и́мени Мое́м, то сотворю́, да просла́вится Оте́ц в Сы́не. И а́ще чесо́ про́сите во и́мя Мое́, Аз сотворю́. А́ще лю́бите Мя, за́поведи Моя́ соблюди́те, и Аз умолю́ Отца́, и ино́го Уте́шителя даст вам, да бу́дет с ва́ми в век, Дух и́стины, Его́же мир не мо́жет прия́ти, я́ко не ви́дит Его́, ниже́ зна́ет Его́, вы же зна́ете Его́, я́ко в вас пребыва́ет и в вас бу́дет. Не оста́влю вас си́ры, прииду́ к вам. Еще́ ма́ло, и мир ктому́ не ви́дит Мене́, вы же ви́дите Мя, я́ко Аз живу́, и вы жи́ви бу́дете. В той день разуме́ете вы, я́ко Аз во Отце́ Мое́м, и вы во Мне, и Аз в вас. Име́яй за́поведи Моя́ и соблюда́яй их, той есть любя́й Мя, а любя́й Мя возлю́блен бу́дет Отце́м Мои́м, и Аз возлюблю́ его́ и явлю́ся ему́ Сам. Глаго́ла Ему́ Иу́да не Искарио́тский: Го́споди, и что бысть, я́ко нам хо́щеши яви́тися, а не ми́рови? Отвеща́ Иису́с и рече́ ему́: а́ще кто лю́бит Мя, сло́во Мое́ соблюде́т, и Оте́ц Мой возлю́бит его́, и к нему́ прии́дема и оби́тель у него́ сотвори́ма. Не любя́й Мя слове́с Мои́х не соблюда́ет, и сло́во, е́же слы́шасте, несть Мое́, но посла́вшаго Мя Отца́. Сия́ глаго́лах вам в вас сый, Уте́шитель же, Дух Святы́й, Его́же по́слет Оте́ц во и́мя Мое́, той вы научи́т всему́ и воспомяне́т вам вся, я́же рех вам. Мир оставля́ю вам, мир Мой даю́ вам, не я́коже мир дае́т, Аз даю́ вам. Да не смуща́ется се́рдце ва́ше, ни устраша́ет. Слы́шасте, я́ко Аз рех вам: иду́ и прииду́ к вам. А́ще бы́сте люби́ли Мя, возра́довалися бы́сте у́бо, я́ко рех: иду́ ко Отцу́, я́ко Оте́ц Мой бо́лий Мене́ есть. И ны́не рех вам, пре́жде да́же не бу́дет, да, егда́ бу́дет, ве́ру и́мете. Ктому́ не мно́го глаго́лю с ва́ми, гряде́т бо сего́ ми́ра князь и во Мне не и́мать ничесо́же. Но да разуме́ет мир, я́ко люблю́ Отца́, и я́коже запове́да Мне Оте́ц, та́ко творю́, воста́ните, и́дем отсю́ду. Аз есмь лоза́ и́стинная, и Оте́ц Мой де́латель есть. Вся́ку розгу́ о Мне не творя́щую плода́, и́змет ю́, и вся́ку творя́щую плод, отреби́т ю́, да мно́жайший плод принесе́т. Уже́ вы чи́сти есте́ за сло́во, е́же глаго́лах вам. Бу́дите во Мне, и Аз в вас. Я́коже розга́ не мо́жет плода́ сотвори́ти о себе́, а́ще не бу́дет на лозе́, та́ко и вы, а́ще во Мне не пребу́дете. Аз есмь лоза́, вы же ро́ждие, и и́же бу́дет во Мне, и Аз в нем, той сотвори́т плод мног, я́ко без Мене́ не мо́жете твори́ти ничесо́же. А́ще кто во Мне не пребу́дет, изве́ржется вон, я́коже розга́, и изсы́шет, и собира́ют ю́ и во огнь влага́ют, и сгара́ет. А́ще пребу́дете во Мне и глаго́лы Мои́ в вас пребу́дут, ему́же а́ще хо́щете, проси́те, и бу́дет вам. О сем просла́вися Оте́ц Мой, да плод мног сотворите́ и бу́дете Мои́ учениицы́. Я́коже возлюби́ Мя Оте́ц, и Аз возлюби́х вас, бу́дите в любви́ Мое́й. А́ще за́поведи Моя́ соблюде́те, пребу́дете в любви́ Мое́й, я́коже Аз за́поведи Отца́ Моего́ соблюдо́х и пребыва́ю в Его́ любви́. Сия́ глаго́лах вам, да ра́дость Моя́ в вас бу́дет и ра́дость ва́ша испо́лнится. Сия́ есть за́поведь Моя́, да лю́бите друг дру́га, я́коже возлюби́х вы. Бо́льши сея́ любве́ никто́же и́мать, да кто ду́шу свою́ положи́т за дру́ги своя́. Вы дру́зи Мои́ есте́, а́ще творите́, ели́ка Аз запове́даю вам. Не ктому́ вас глаго́лю рабы́, я́ко раб не весть, что твори́т госпо́дь его́, вас же реко́х дру́ги, я́ко вся, я́же слы́шах от Отца́ Моего́, сказа́х вам. Не вы Мене́ избра́сте, но Аз избра́х вас и положи́х вас, да вы и́дете и плод принесе́те, и плод ваш пребу́дет, да его́же а́ще про́сите от Отца́ во и́мя Мое́, даст вам. Си запове́даю вам, да лю́бите друг дру́га. А́ще мир вас ненави́дит, ве́дите, я́ко Мене́ пре́жде вас возненави́де. А́ще от ми́ра бы́сте бы́ли, мир у́бо свое́ люби́л бы, я́коже от ми́ра не́сте, но Аз избра́х вы от ми́ра, сего́ ра́ди ненави́дит вас мир. Помина́йте сло́во, е́же Аз рех вам: несть раб бо́лий го́спода своего́. А́ще Мене́ изгна́ша, и вас изжену́т, а́ще сло́во Мое́ соблюдо́ша, и ва́ше соблюду́т. Но сия́ вся творя́т вам за и́мя Мое́, я́ко не ве́дят Посла́вшаго Мя. А́ще не бых прише́л и глаго́лал им, греха́ не бы́ша име́ли, ны́не же вины́ не и́мут о гресе́ свое́м. Ненави́дяй Мене́, и Отца́ Моего́ ненави́дит. А́ще дел не бых сотвори́л в них, и́хже ин никто́же сотвори́, греха́ не бы́ша име́ли, ны́не же и ви́деша, и возненави́деша Мене́ и Отца́ Моего́. Но да сбу́дется сло́во, пи́санное в зако́не их, я́ко возненави́деша Мя ту́не. Егда́ же прии́дет Уте́шитель, Его́же Аз послю́ вам от Отца́, Дух и́стины, И́же от Отца́ исхо́дит, Той свиде́тельствует о Мне. И вы же свиде́тельствуете, я́ко искони́ со Мно́ю есте́. Сия́ глаго́лах вам, да не соблазните́ся. От со́нмищ иждену́т вы, но прии́дет час, да всяк, и́же убие́т вы, мни́тся слу́жбу приноси́ти Бо́гу. И сия́ сотворя́т, я́ко не позна́ша Отца́, ни Мене́. Но сия́ глаго́лах вам, да егда́ прии́дет час, помина́йте се, я́ко Аз рех вам. Сих же вам испе́рва не рех, я́ко с ва́ми бех. Ны́не же иду́ к Посла́вшему Мя, и никто́же от вас вопроша́ет Мене́: ка́мо и́деши? Но я́ко сия́ глаго́лах вам, ско́рби испо́лних сердца́ ва́ша. Но Аз и́стину вам глаго́лю: у́не есть вам, да Аз иду́, а́ще бо не иду́ Аз, Уте́шитель не прии́дет к вам, а́ще ли же иду́, послю́ Его́ к вам, и прише́д Он обличи́т мир о гресе́ и о пра́вде и о суде́. О гресе́ у́бо, я́ко не ве́руют в Мя. О пра́вде же, я́ко ко Отцу́ Моему́ иду́, и ктому́ не ви́дите Мене́. О суде́ же, я́ко князь ми́ра сего́ осужде́н бысть. Еще́ мно́го и́мам глаго́лати вам, но не мо́жете носи́ти ны́не, егда́ же прии́дет Он, Дух и́стины, наста́вит вы на вся́ку и́стину, не о Себе́ бо глаго́лати и́мать, но ели́ка а́ще услы́шит, глаго́лати и́мать, и гряду́щая возвести́т вам. Он Мя просла́вит, я́ко от Моего́ прии́мет и возвести́т вам. Вся, ели́ка и́мать Оте́ц, Моя́ суть, сего́ ра́ди рех, я́ко от Моего́ прии́мет и возвести́т вам. Вма́ле, и ктому́ не ви́дите Мене́, и па́ки вма́ле, и у́зрите Мя, я́ко иду́ ко Отцу́. Ре́ша же от учени́к Его́ к себе́, что есть сие́, е́же глаго́лет нам: вма́ле, и не ви́дите Мене́, и па́ки вма́ле, и у́зрите Мя? И я́ко Аз иду́ ко Отцу́? Глаго́лаху у́бо: что сие́ есть, е́же глаго́лет, вма́ле? Не ве́мы, что глаго́лет. Разуме́ же Иису́с, я́ко хотя́ху Его́ вопроша́ти, и рече́ им: о сем ли стяза́етеся между́ собо́ю, я́ко рех: вма́ле, и не ви́дите Мене́, и па́ки вма́ле, и у́зрите Мя? Ами́нь, ами́нь глаго́лю вам, я́ко воспла́четеся и возрыда́ете вы, а мир возра́дуется, вы же печа́льни бу́дете, но печа́ль ва́ша в ра́дость бу́дет. Жена́ егда́ ражда́ет, скорбь и́мать, я́ко прии́де год ея́, егда́ же роди́т отроча́, ктому́ не по́мнит ско́рби за ра́дость, я́ко роди́ся челове́к в мир. И вы же печа́ль и́мате у́бо ны́не, па́ки же узрю́ вы, и возра́дуется се́рдце ва́ше, и ра́дости ва́шея никто́же во́змет от вас, и в той день Мене́ не воспро́сите ничесо́же. Ами́нь, ами́нь глаго́лю вам, я́ко ели́ка а́ще чесо́ про́сите от Отца́ во и́мя Мое́, даст вам. Досе́ле не проси́сте ничесо́же во и́мя Мое́, проси́те, и прии́мете, да ра́дость ва́ша испо́лнена бу́дет. Сия́ в при́тчах глаго́лах вам, но прии́дет час, егда́ ктому́ в при́тчах не глаго́лю вам, но я́ве о Отце́ возвещу́ вам. В той день во и́мя Мое́ воспро́сите, и не глаго́лю вам, я́ко Аз умолю́ Отца́ о вас. Сам бо Оте́ц лю́бит вы, я́ко вы Мене́ возлюби́сте и ве́ровасте, я́ко Аз от Бо́га изыдо́х. Изыдо́х от Отца́ и приидо́х в мир, и па́ки оставля́ю мир и иду́ ко Отцу́. Глаго́лаша Ему́ ученицы́ Его́: се ны́не не обину́яся глаго́леши, а при́тчи никоея́же не глаго́леши. Ны́не ве́мы, я́ко ве́си вся и не тре́буеши, да кто Тя вопроша́ет, о сем ве́руем, я́ко от Бо́га изше́л еси́. Отвеща́ им Иису́с: ны́не ли ве́руете? Се гряде́т час, и ны́не прии́де, да разы́детеся ко́ждо во своя́ и Мене́ еди́наго оста́вите, и несмь еди́н, я́ко Оте́ц со Мно́ю есть. Сия́ глаго́лах вам, да во Мне мир и́мате. В ми́ре ско́рбни бу́дете, но дерза́йте, я́ко Аз победи́х мир. Сия́ глаго́ла Иису́с и возведе́ о́чи Свои́ на не́бо и рече́: О́тче, прии́де час, просла́ви Сы́на Твоего́, да и Сын Твой просла́вит Тя, я́коже дал еси́ Ему́ власть вся́кия пло́ти, да вся́ко, е́же дал еси́ Ему́, даст им живо́т ве́чный. Се же есть живо́т ве́чный, да зна́ют Тебе́ еди́наго и́стиннаго Бо́га, и Его́же посла́л еси́ Иису́с Христа́. Аз просла́вих Тя на земли́, де́ло соверши́х, е́же дал еси́ Мне да сотворю́, и ны́не просла́ви Мя Ты, О́тче, у Тебе́ Самаго́ сла́вою, ю́же име́х у Тебе́ пре́жде мир не бысть. Яви́х и́мя Твое́ челове́ком, и́хже дал еси́ Мне от ми́ра, Твои́ бе́ша, и Мне их дал еси́, и сло́во Твое́ сохрани́ша. Ны́не разуме́ша, я́ко вся, ели́ка дал еси́ Мне, от Тебе́ суть, я́ко глаго́лы, и́хже дал еси́ Мне, дах им, и ти́и прия́ша и разуме́ша вои́стинну, я́ко от Тебе́ изыдо́х, и ве́роваша, я́ко Ты Мя посла́. Аз о сих молю́, не о всем ми́ре молю́, но о тех, и́хже дал еси́ Мне, я́ко Твои́ суть. И Моя́ вся Твоя́ суть, и Твоя́ Моя́, и просла́вихся в них. И ктому́ несмь в ми́ре, и си́и в ми́ре суть, и Аз к Тебе́ гряду́. О́тче Святы́й, соблюди́ их во и́мя Твое́, и́хже дал еси́ Мне, да бу́дут еди́но, я́коже и Мы. Егда́ бех с ни́ми в ми́ре, Аз соблюда́х их во и́мя Твое́, и́хже дал еси́ Мне, сохрани́х, и никто́же от них поги́бе, то́кмо сын поги́бельный, да сбу́дется Писа́ние. Ны́не же к Тебе́ гряду́, и сия́ глаго́лю в ми́ре, да и́мут ра́дость Мою́ испо́лнену в себе́. Аз дах им сло́во Твое́, и мир возненави́де их, я́ко не суть от ми́ра, я́коже и Аз от ми́ра несмь. Не молю́, да во́змеши их от ми́ра, но да соблюде́ши их от неприя́зни. От ми́ра не суть, я́коже и Аз от ми́ра несмь. Святи́ их во и́стину Твою́, сло́во Твое́ и́стина есть. Я́коже Мене́ посла́л еси́ в мир, и Аз посла́х их в мир, и за них Аз свящу́ Себе́, да и ти́и бу́дут свяще́ни во и́стину. Не о сих же молю́ то́кмо, но и о ве́рующих словесе́ их ра́ди в Мя, да вси еди́но суть, я́коже Ты, О́тче, во Мне, и Аз в Тебе́, да и ти́и в Нас еди́но бу́дут, да и мир ве́ру и́мет, я́ко Ты Мя посла́л еси́. И Аз сла́ву, ю́же дал еси́ Мне, дах им, да бу́дут еди́но, я́коже Мы еди́но есма́. Аз в них, и Ты во Мне, да бу́дут сверше́ни во еди́но, и да разуме́ет мир, я́ко Ты Мя посла́ и возлюби́л еси́ их, я́коже Мене́ возлюби́л еси́. О́тче, и́хже дал еси́ Мне, хощу́, да иде́же есмь Аз, и ти́и бу́дут со Мно́ю, да ви́дят сла́ву Мою́, ю́же дал еси́ Мне, я́ко возлюби́л Мя еси́ пре́жде сложе́ния ми́ра. О́тче пра́ведный, и мир Тебе́ не позна́, Аз же Тя позна́х, и си́и позна́ша, я́ко Ты Мя посла́ еси, и сказа́х им и́мя Твое́, и скажу́, да любы́, е́юже Мя еси́ возлюби́л, в них бу́дет, и Аз в них. И сия́ рек Иису́с, изы́де со ученики́ Свои́ми на он пол пото́ка Ке́дрска, иде́же бе вертогра́д, во́ньже вни́де Сам и ученицы́ Его́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: ны́нѣ просла́висѧ сн҃ъ чл҃вѣ́ческїй, и҆ бг҃ъ просла́висѧ ѡ҆ не́мъ. а҆́ще бг҃ъ просла́висѧ ѡ҆ не́мъ, и҆ бг҃ъ просла́витъ є҆го̀ въ себѣ̀, и҆ а҆́бїе просла́витъ є҆го̀. ча̑дца, є҆щѐ съ ва́ми ма́лѡ є҆́смь: взы́щете менѐ, и҆ ꙗ҆́коже рѣ́хъ і҆ꙋде́ємъ, ꙗ҆́кѡ а҆́може а҆́зъ и҆дꙋ̀, вы̀ не мо́жете прїитѝ, и҆ ва́мъ глаго́лю ны́нѣ. за́повѣдь но́вꙋю даю̀ ва́мъ, да лю́бите дрꙋ́гъ дрꙋ́га: ꙗ҆́коже возлюби́хъ вы̀, да и҆ вы̀ лю́бите себѐ. ѡ҆ се́мъ разꙋмѣ́ютъ всѝ, ꙗ҆́кѡ моѝ ᲂу҆ченицы̀ є҆стѐ, а҆́ще любо́вь и҆́мате междꙋ̀ собо́ю. глаго́ла є҆мꙋ̀ сі́мѡнъ пе́тръ: гдⷭ҇и, ка́мѡ и҆́деши; ѿвѣща̀ є҆мꙋ̀ і҆и҃съ: а҆́може а҆́зъ и҆дꙋ̀, не мо́жеши ны́нѣ по мнѣ̀ и҆тѝ, послѣди́ же по мнѣ̀ и҆́деши. глаго́ла є҆мꙋ̀ пе́тръ: гдⷭ҇и, почто̀ не могꙋ̀ ны́нѣ по тебѣ̀ и҆тѝ; ны́нѣ дꙋ́шꙋ мою̀ за тѧ̀ положꙋ̀. ѿвѣща̀ є҆мꙋ̀ і҆и҃съ: дꙋ́шꙋ ли твою̀ за мѧ̀ положи́ши; а҆ми́нь а҆ми́нь глаго́лю тебѣ̀: не возгласи́тъ а҆ле́ктѡръ, до́ндеже ѿве́ржешисѧ менѐ три́щи. да не смꙋща́етсѧ се́рдце ва́ше: вѣ́рꙋйте въ бг҃а, и҆ въ мѧ̀ вѣ́рꙋйте. въ домꙋ̀ ѻ҆ц҃а̀ моегѡ̀ ѻ҆би́тєли мнѡ́ги сꙋ́ть: а҆́ще ли же нѝ, ре́клъ бы́хъ ва́мъ: и҆дꙋ̀ ᲂу҆гото́вати мѣ́сто ва́мъ. и҆ а҆́ще поидꙋ̀ и҆ ᲂу҆гото́влю мѣ́сто ва́мъ, па́ки прїидꙋ̀, и҆ поимꙋ̀ вы̀ къ себѣ̀: да и҆дѣ́же є҆́смь а҆́зъ, и҆ вы̀ бꙋ́дете: и҆ а҆́може а҆́зъ и҆дꙋ̀ вѣ́сте, и҆ пꙋ́ть вѣ́сте. глаго́ла є҆мꙋ̀ ѳѡма̀: гдⷭ҇и, не вѣ́мы, ка́мѡ и҆́деши; и҆ ка́кѡ мо́жемъ пꙋ́ть вѣ́дѣти; глаго́ла є҆мꙋ̀ і҆и҃съ: а҆́зъ є҆́смь пꙋ́ть, и҆ и҆́стина, и҆ живо́тъ: никто́же прїи́детъ ко ѻ҆ц҃ꙋ̀, то́кмѡ мно́ю. а҆́ще мѧ̀ бы́сте зна́ли, и҆ ѻ҆ц҃а̀ моего̀ зна́ли бы́сте ᲂу҆́бѡ: и҆ ѿсе́лѣ позна́сте є҆го̀, и҆ ви́дѣсте є҆го̀. глаго́ла є҆мꙋ̀ фїлі́ппъ: гдⷭ҇и, покажѝ на́мъ ѻ҆ц҃а̀, и҆ довлѣ́етъ на́мъ. глаго́ла є҆мꙋ̀ і҆и҃съ: толи́ко вре́мѧ съ ва́ми є҆́смь, и҆ не позна́лъ є҆сѝ менѐ фїлі́ппе! ви́дѣвый менѐ, ви́дѣ ѻ҆ц҃а̀: и҆ ка́кѡ ты̀ глаго́леши, покажѝ на́мъ ѻ҆ц҃а̀; не вѣ́рꙋеши ли, ꙗ҆́кѡ а҆́зъ во ѻ҆ц҃ѣ̀, и҆ ѻ҆ц҃ъ во мнѣ̀ є҆́сть; глаго́лы ꙗ҆̀же а҆́зъ глаго́лю ва́мъ, ѡ҆ себѣ̀ не глаго́лю: ѻ҆ц҃ъ же во мнѣ̀ пребыва́ѧй, то́й твори́тъ дѣла̀. вѣ́рꙋйте мнѣ̀, ꙗ҆́кѡ а҆́зъ во ѻ҆ц҃ѣ̀, и҆ ѻ҆ц҃ъ во мнѣ̀. а҆́ще ли же нѝ, за та̀ дѣла̀ вѣ́рꙋ и҆ми́те мѝ. а҆ми́нь а҆ми́нь глаго́лю ва́мъ: вѣ́рꙋѧй въ мѧ̀, дѣла̀ ꙗ҆̀же а҆́зъ творю̀, и҆ то́й сотвори́тъ, и҆ бѡ́льша си́хъ сотвори́тъ, ꙗ҆́кѡ а҆́зъ ко ѻ҆ц҃ꙋ̀ моемꙋ̀ грѧдꙋ̀. и҆ є҆́же а҆́ще что̀ про́сите ѿ ѻ҆ц҃а̀ ѡ҆ и҆́мени мое́мъ, то̀ сотворю̀: да просла́витсѧ ѻ҆ц҃ъ въ сн҃ѣ. и҆ а҆́ще чесѡ̀ про́сите во и҆́мѧ моѐ, а҆́зъ сотворю̀: а҆́ще лю́бите мѧ̀, за́пѡвѣди моѧ̀ соблюди́те. и҆ а҆́зъ ᲂу҆молю̀ ѻ҆ц҃а̀, и҆ и҆но́го ᲂу҆тѣ́шителѧ да́стъ ва́мъ, да бꙋ́детъ съ ва́ми въ вѣ́къ: дх҃ъ и҆́стины, є҆гѡ́же мі́ръ не мо́жетъ прїѧ́ти, ꙗ҆́кѡ не ви́дитъ є҆гѡ̀, нижѐ зна́етъ є҆гѡ̀: вы́ же зна́ете є҆го̀, ꙗ҆́кѡ въ ва́съ пребыва́етъ, и҆ въ ва́съ бꙋ́детъ. не ѡ҆ста́влю ва́съ си́ры: прїидꙋ̀ къ ва́мъ. є҆щѐ ма́лѡ, и҆ мі́ръ ктомꙋ̀ не ви́дитъ менѐ: вы́ же ви́дите мѧ̀, ꙗ҆́кѡ а҆́зъ живꙋ̀, и҆ вы̀ жи́ви бꙋ́дете. въ то́й де́нь разꙋмѣ́ете вы̀, ꙗ҆́кѡ а҆́зъ во ѻ҆ц҃ѣ̀ мое́мъ, и҆ вы̀ во мнѣ̀, и҆ а҆́зъ въ ва́съ. и҆мѣ́ѧй за́пѡвѣди моѧ̀ и҆ соблюда́ѧй и҆̀хъ, то́й є҆́сть любѧ́й мѧ̀: а҆ любѧ́й мѧ̀, возлю́бленъ бꙋ́детъ ѻ҆ц҃е́мъ мои́мъ, и҆ а҆́зъ возлюблю̀ є҆го̀, и҆ ꙗ҆влю́сѧ є҆мꙋ̀ са́мъ. глаго́ла є҆мꙋ̀ і҆ꙋ́да, не і҆скарїѡ́тскїй: гдⷭ҇и, и҆ что̀ бы́сть, ꙗ҆́кѡ на́мъ хо́щеши ꙗ҆ви́тисѧ, а҆ не мі́рови; ѿвѣща̀ і҆и҃съ, и҆ речѐ є҆мꙋ̀: а҆́ще кто̀ лю́битъ мѧ̀, сло́во моѐ соблюде́тъ: и҆ ѻ҆ц҃ъ мо́й возлю́битъ є҆го̀, и҆ къ немꙋ̀ прїи́дема, и҆ ѻ҆би́тель ᲂу҆ негѡ̀ сотвори́ма. не любѧ́й мѧ̀, слове́съ мои́хъ не соблюда́етъ: и҆ сло́во, є҆́же слы́шасте, нѣ́сть моѐ, но посла́вшагѡ мѧ̀ ѻ҆ц҃а̀. сїѧ̑ глаго́лахъ ва́мъ, въ ва́съ сы́й: ᲂу҆тѣ́шитель же дх҃ъ ст҃ы́й, є҆го́же по́слетъ ѻ҆ц҃ъ во и҆́мѧ моѐ, то́й вы̀ наꙋчи́тъ всемꙋ̀ и҆ воспомѧне́тъ ва́мъ всѧ̑, ꙗ҆̀же рѣ́хъ ва́мъ. ми́ръ ѡ҆ставлѧ́ю ва́мъ: ми́ръ мо́й даю̀ ва́мъ, не ꙗ҆́коже мі́ръ дае́тъ, а҆́зъ даю̀ ва́мъ. да не смꙋща́етсѧ се́рдце ва́ше, ни ᲂу҆страша́етъ. слы́шасте, ꙗ҆́кѡ а҆́зъ рѣ́хъ ва́мъ: и҆дꙋ̀ и҆ прїидꙋ̀ къ ва́мъ. а҆́ще бы́сте люби́ли мѧ̀, возра́довалисѧ бы́сте ᲂу҆́бѡ, ꙗ҆́кѡ рѣ́хъ, и҆дꙋ̀ ко ѻ҆ц҃ꙋ̀: ꙗ҆́кѡ ѻ҆ц҃ъ мо́й бо́лїй менѐ є҆́сть. и҆ ны́нѣ рѣ́хъ ва́мъ, пре́жде да́же не бꙋ́детъ, да є҆гда̀ бꙋ́детъ, вѣ́рꙋ и҆́мете. ктомꙋ̀ не мно́гѡ глаго́лю съ ва́ми: грѧде́тъ бо сегѡ̀ мі́ра кнѧ́зь, и҆ во мнѣ̀ не и҆́мать ничесѡ́же. но да разꙋмѣ́етъ мі́ръ, ꙗ҆́кѡ люблю̀ ѻ҆ц҃а̀, и҆ ꙗ҆́коже заповѣ́да мнѣ̀ ѻ҆ц҃ъ, та́кѡ творю̀: воста́ните, и҆́демъ ѿсю́дꙋ. а҆́зъ є҆́смь лоза̀ и҆́стиннаѧ, и҆ ѻ҆ц҃ъ мо́й дѣ́латель є҆́сть. всѧ́кꙋ розгꙋ̀, ѡ҆ мнѣ̀ не творѧ́щꙋю плода̀, и҆́зметъ ю҆̀: и҆ всѧ́кꙋ творѧ́щꙋю пло́дъ, ѡ҆треби́тъ ю҆̀, да мно́жайшїй пло́дъ принесе́тъ. ᲂу҆жѐ вы̀ чи́сти є҆стѐ за сло́во, є҆́же глаго́лахъ ва́мъ. бꙋ́дите во мнѣ̀, и҆ а҆́зъ въ ва́съ: ꙗ҆́коже розга̀ не мо́жетъ плода̀ сотвори́ти ѡ҆ себѣ̀, а҆́ще не бꙋ́детъ на лозѣ̀, та́кѡ и҆ вы̀, а҆́ще во мнѣ̀ не пребꙋ́дете. а҆́зъ є҆́смь лоза̀, вы́ же ро́ждїє: и҆ и҆́же бꙋ́детъ во мнѣ̀, и҆ а҆́зъ въ не́мъ, то́й сотвори́тъ пло́дъ мно́гъ: ꙗ҆́кѡ без̾ менѐ не мо́жете твори́ти ничесѡ́же. а҆́ще кто̀ во мнѣ̀ не пребꙋ́детъ, и҆зве́ржетсѧ во́нъ, ꙗ҆́коже розга̀, и҆ и҆зсы́шетъ: и҆ собира́ютъ ю҆̀, и҆ во ѻ҆́гнь влага́ютъ, и҆ сгара́етъ. а҆́ще пребꙋ́дете во мнѣ̀, и҆ глаго́лы моѝ въ ва́съ пребꙋ́дꙋтъ: є҆мꙋ́же а҆́ще хо́щете, проси́те, и҆ бꙋ́детъ ва́мъ. ѡ҆ се́мъ просла́висѧ ѻ҆ц҃ъ мо́й да пло́дъ мно́гъ сотворитѐ и҆ бꙋ́дете моѝ ᲂу҆ченицы̀. ꙗ҆́коже возлюби́ мѧ ѻ҆ц҃ъ, и҆ а҆́зъ возлюби́хъ ва́съ: бꙋ́дите въ любвѝ мое́й. а҆́ще за́пѡвѣди моѧ̀ соблюде́те, пребꙋ́дете въ любвѝ мое́й: ꙗ҆́коже а҆́зъ за́пѡвѣди ѻ҆ц҃а̀ моегѡ̀ соблюдо́хъ, и҆ пребыва́ю въ є҆гѡ̀ любвѝ. сїѧ̑ глаго́лахъ ва́мъ, да ра́дость моѧ̀ въ ва́съ бꙋ́детъ, и҆ ра́дость ва́ша и҆спо́лнитсѧ. сїѧ̀ є҆́сть за́повѣдь моѧ̀, да лю́бите дрꙋ́гъ дрꙋ́га, ꙗ҆́коже возлюби́хъ вы̀. бо́льши сеѧ̀ любвѐ никто́же и҆́мать, да кто̀ дꙋ́шꙋ свою̀ положи́тъ за дрꙋ́ги своѧ̀. вы̀ дрꙋ́зи моѝ є҆стѐ, а҆́ще творитѐ, є҆ли̑ка а҆́зъ заповѣ́даю ва́мъ. не ктомꙋ̀ ва́съ глаго́лю рабы̑, ꙗ҆́кѡ ра́бъ не вѣ́сть, что̀ твори́тъ гдⷭ҇ь є҆гѡ̀: ва́съ же реко́хъ дрꙋ́ги, ꙗ҆́кѡ всѧ̑, ꙗ҆̀же слы́шахъ ѿ ѻ҆ц҃а̀ моегѡ̀, сказа́хъ ва́мъ. не вы̀ менѐ и҆збра́сте, но а҆́зъ и҆збра́хъ ва́съ и҆ положи́хъ ва́съ, да вы̀ и҆́дете, и҆ пло́дъ принесе́те, и҆ пло́дъ ва́шъ пребꙋ́детъ: да є҆гѡ́же а҆́ще про́сите ѿ ѻ҆ц҃а̀ во и҆́мѧ моѐ, да́стъ ва́мъ. сѝ заповѣ́даю ва́мъ, да лю́бите дрꙋ́гъ дрꙋ́га. а҆́ще мі́ръ ва́съ ненави́дитъ, вѣ́дите, ꙗ҆́кѡ менѐ пре́жде ва́съ возненави́дѣ. а҆́ще ѿ мі́ра бы́сте бы́ли, мі́ръ ᲂу҆́бѡ своѐ люби́лъ бы: ꙗ҆́коже ѿ мі́ра нѣ́сте, но а҆́зъ и҆збра́хъ вы̀ ѿ мі́ра, сегѡ̀ ра́ди ненави́дитъ ва́съ мі́ръ. помина́йте сло́во, є҆́же а҆́зъ рѣ́хъ ва́мъ: нѣ́сть ра́бъ бо́лїй гдⷭ҇а своегѡ̀. а҆́ще менѐ и҆згна́ша, и҆ ва́съ и҆зженꙋ́тъ: а҆́ще сло́во моѐ соблюдо́ша, и҆ ва́ше соблюдꙋ́тъ. но сїѧ̑ всѧ̑ творѧ́тъ ва́мъ за и҆́мѧ моѐ, ꙗ҆́кѡ не вѣ́дѧтъ посла́вшагѡ мѧ̀. а҆́ще не бы́хъ прише́лъ, и҆ глаго́лалъ и҆̀мъ, грѣха̀ не бы́ша и҆мѣ́ли: ны́нѣ же вины̀ не и҆́мꙋтъ ѡ҆ грѣсѣ̀ свое́мъ. ненави́дѧй менѐ, и҆ ѻ҆ц҃а̀ моего̀ ненави́дитъ. а҆́ще дѣ́лъ не бы́хъ сотвори́лъ въ ни́хъ, и҆̀хже и҆́нъ никто́же сотворѝ, грѣха̀ не бы́ша и҆мѣ́ли: ны́нѣ же и҆ ви́дѣша, и҆ возненави́дѣша менѐ, и҆ ѻ҆ц҃а̀ моего̀. но да сбꙋ́детсѧ сло́во пи́санное въ зако́нѣ и҆́хъ: ꙗ҆́кѡ возненави́дѣша мѧ̀ тꙋ́не. є҆гда́ же прїи́детъ ᲂу҆тѣ́шитель, є҆го́же а҆́зъ послю̀ ва́мъ ѿ ѻ҆ц҃а̀, дх҃ъ и҆́стины, и҆́же ѿ ѻ҆ц҃а̀ и҆схо́дитъ, то́й свидѣ́тельствꙋетъ ѡ҆ мнѣ̀. и҆ вы́ же свидѣ́тельствꙋете, ꙗ҆́кѡ и҆сконѝ со мно́ю є҆стѐ. сїѧ̑ глаго́лахъ ва́мъ, да не соблазните́сѧ. ѿ со́нмищъ и҆жденꙋ́тъ вы̀: но прїи́детъ ча́съ, да всѧ́къ и҆́же ᲂу҆бїе́тъ вы̀ мни́тсѧ слꙋ́жбꙋ приноси́ти бг҃ꙋ. и҆ сїѧ̑ сотворѧ́тъ, ꙗ҆́кѡ не позна́ша ѻ҆ц҃а̀, ни менѐ. но сїѧ̑ глаго́лахъ ва́мъ: да є҆гда̀ прїи́детъ ча́съ, помина́йте сѐ, ꙗ҆́кѡ а҆́зъ рѣ́хъ ва́мъ. си́хъ же ва́мъ и҆спе́рва не рѣ́хъ, ꙗ҆́кѡ съ ва́ми бѣ́хъ. ны́нѣ же и҆дꙋ̀ къ посла́вшемꙋ мѧ̀, и҆ никто́же ѿ ва́съ вопроша́етъ менѐ, ка́мѡ и҆́деши; но ꙗ҆́кѡ сїѧ̑ глаго́лахъ ва́мъ, ско́рби и҆спо́лнихъ сердца̀ ва́ша. но а҆́зъ и҆́стинꙋ ва́мъ глаго́лю, ᲂу҆́не є҆́сть ва́мъ, да а҆́зъ и҆дꙋ̀: а҆́ще бо не и҆дꙋ̀ а҆́зъ, ᲂу҆тѣ́шитель не прїи́детъ къ ва́мъ. а҆́ще ли же и҆дꙋ̀, послю̀ є҆го̀ къ ва́мъ. и҆ прише́дъ ѻ҆́нъ, ѡ҆бличи́тъ мі́ръ ѡ҆ грѣсѣ̀, и҆ ѡ҆ пра́вдѣ, и҆ ѡ҆ сꙋдѣ̀. ѡ҆ грѣсѣ̀ ᲂу҆́бѡ, ꙗ҆́кѡ не вѣ́рꙋютъ въ мѧ̀. ѡ҆ пра́вдѣ же, ꙗ҆́кѡ ко ѻ҆ц҃ꙋ̀ моемꙋ̀ и҆дꙋ̀, и҆ ктомꙋ̀ не ви́дите менѐ. ѡ҆ сꙋдѣ́ же, ꙗ҆́кѡ кнѧ́зь мі́ра сегѡ̀ ѡ҆сꙋжде́нъ бы́сть. є҆щѐ мно́гѡ и҆́мамъ глаго́лати ва́мъ, но не мо́жете носи́ти ны́нѣ. є҆гда́ же прїи́детъ ѻ҆́нъ, дх҃ъ и҆́стины, наста́витъ вы̀ на всѧ́кꙋ и҆́стинꙋ: не ѡ҆ себѣ́ бо глаго́лати и҆́мать, но є҆ли̑ка а҆́ще ᲂу҆слы́шитъ, глаго́лати и҆́мать и҆ грѧдꙋ̑щаѧ возвѣсти́тъ ва́мъ. ѻ҆́нъ мѧ̀ просла́витъ, ꙗ҆́кѡ ѿ моегѡ̀ прїи́метъ, и҆ возвѣсти́тъ ва́мъ. всѧ̑ є҆ли̑ка и҆́мать ѻ҆ц҃ъ, моѧ̑ сꙋ́ть: сегѡ̀ ра́ди рѣ́хъ, ꙗ҆́кѡ ѿ моегѡ̀ прїи́метъ, и҆ возвѣсти́тъ ва́мъ. вма́лѣ, и҆ ктомꙋ̀ не ви́дите менѐ: и҆ па́ки вма́лѣ, и҆ ᲂу҆́зрите мѧ̀, ꙗ҆́кѡ и҆дꙋ̀ ко ѻ҆ц҃ꙋ̀. рѣ́ша же ѿ ᲂу҆чени̑къ є҆гѡ̀ къ себѣ̀: что́ є҆сть сїѐ, є҆́же глаго́летъ на́мъ, вма́лѣ, и҆ не ви́дите менѐ; и҆ па́ки, вма́лѣ и҆ ᲂу҆́зрите мѧ̀; и҆ ꙗ҆́кѡ а҆́зъ и҆дꙋ̀ ко ѻ҆ц҃ꙋ̀, глаго́лахꙋ ᲂу҆́бѡ, что̀ сїѐ є҆́сть, є҆́же глаго́летъ, вма́лѣ; не вѣ́мы, что̀ глаго́летъ. разꙋмѣ́ же і҆и҃съ, ꙗ҆́кѡ хотѧ́хꙋ є҆го̀ вопроша́ти, и҆ речѐ и҆̀мъ: ѡ҆ се́мъ ли стѧза́етесѧ междꙋ̀ собо́ю, ꙗ҆́кѡ рѣ́хъ: вма́лѣ, и҆ не ви́дите менѐ: и҆ па́ки, вма́лѣ, и҆ ᲂу҆́зрите мѧ̀; а҆ми́нь а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ воспла́четесѧ и҆ возрыда́ете вы̀, а҆ мі́ръ возра́дꙋетсѧ: вы́ же печа́льни бꙋ́дете, но печа́ль ва́ша въ ра́дость бꙋ́детъ. жена̀, є҆гда̀ ражда́етъ, ско́рбь и҆́мать, ꙗ҆́кѡ прїи́де го́дъ є҆ѧ̀: є҆гда́ же роди́тъ ѻ҆троча̀, ктомꙋ̀ не по́мнитъ ско́рби за ра́дость, ꙗ҆́кѡ роди́сѧ человѣ́къ въ мі́ръ. и҆ вы́ же печа́ль и҆́мате ᲂу҆́бѡ ны́нѣ: па́ки же ᲂу҆зрю̀ вы̀, и҆ возра́дꙋетсѧ се́рдце ва́ше, и҆ ра́дости ва́шеѧ никто́же во́з̾метъ ѿ ва́съ: и҆ въ то́й де́нь менѐ не вопро́сите ничесѡ́же. а҆ми́нь а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ є҆ли̑ка а҆́ще чесѡ̀ про́сите ѿ ѻ҆ц҃а̀ во и҆́мѧ моѐ, да́стъ ва́мъ. досе́лѣ не проси́сте ничесѡ́же во и҆́мѧ моѐ: проси́те, и҆ прїи́мете, да ра́дость ва́ша и҆спо́лнена бꙋ́детъ. сїѧ̑ въ при́тчахъ глаго́лахъ ва́мъ: но прїи́детъ ча́съ, є҆гда̀ ктомꙋ̀ въ при́тчахъ не глаго́лю ва́мъ, но ꙗ҆́вѣ ѡ҆ ѻ҆ц҃ѣ̀ возвѣщꙋ̀ ва́мъ. въ то́й де́нь во и҆́мѧ моѐ вопро́сите, и҆ не глаго́лю ва́мъ, ꙗ҆́кѡ а҆́зъ ᲂу҆молю̀ ѻ҆ц҃а̀ ѡ҆ ва́съ. са́мъ бо ѻ҆ц҃ъ лю́битъ вы̀, ꙗ҆́кѡ вы̀ менѐ возлюби́сте, и҆ вѣ́ровасте, ꙗ҆́кѡ а҆́зъ ѿ бг҃а и҆зыдо́хъ. и҆зыдо́хъ ѿ ѻ҆ц҃а̀, и҆ прїидо́хъ въ мі́ръ: и҆ па́ки ѡ҆ставлѧ́ю мі́ръ, и҆ и҆дꙋ̀ ко ѻ҆ц҃ꙋ̀. глаго́лаша є҆мꙋ̀ ᲂу҆ченицы̀ є҆гѡ̀: сѐ ны́нѣ не ѡ҆бинꙋ́ѧсѧ глаго́леши, а҆ при́тчи никоеѧ́же не глаго́леши. ны́нѣ вѣ́мы, ꙗ҆́кѡ вѣ́си всѧ̑, и҆ не тре́бꙋеши, да кто́ тѧ вопроша́етъ: ѡ҆ се́мъ вѣ́рꙋемъ, ꙗ҆́кѡ ѿ бг҃а и҆зше́лъ є҆сѝ. ѿвѣща̀ и҆̀мъ і҆и҃съ: ны́нѣ ли вѣ́рꙋете; сѐ грѧде́тъ ча́съ, и҆ ны́нѣ прїи́де, да разы́детесѧ ко́ждо во своѧ̑, и҆ менѐ є҆ди́наго ѡ҆ста́вите: и҆ нѣ́смь є҆ди́нъ, ꙗ҆́кѡ ѻ҆ц҃ъ со мно́ю є҆́сть. сїѧ̑ глаго́лахъ ва́мъ, да во мнѣ̀ ми́ръ и҆́мате. въ мі́рѣ ско́рбни бꙋ́дете: но дерза́йте, ꙗ҆́кѡ а҆́зъ побѣди́хъ мі́ръ. сїѧ̑ глаго́ла і҆и҃съ, и҆ возведѐ ѻ҆́чи своѝ на нб҃о, и҆ речѐ: ѻ҆́ч҃е, прїи́де ча́съ: просла́ви сн҃а твоего̀, да и҆ сн҃ъ тво́й просла́витъ тѧ̀: ꙗ҆́коже да́лъ є҆сѝ є҆мꙋ̀ вла́сть всѧ́кїѧ пло́ти, да всѧ́ко є҆́же да́лъ є҆сѝ є҆мꙋ̀, да́стъ и҆̀мъ живо́тъ вѣ́чный. се́ же є҆́сть живо́тъ вѣ́чный, да зна́ютъ тебѐ є҆ди́наго и҆́стиннаго бг҃а, и҆ є҆го́же посла́лъ є҆сѝ і҆и҃съ хрⷭ҇та̀. а҆́зъ просла́вихъ тѧ̀ на землѝ: дѣ́ло соверши́хъ, є҆́же да́лъ є҆сѝ мнѣ̀ да сотворю̀. и҆ ны́нѣ просла́ви мѧ̀ ты̀ ѻ҆́ч҃е ᲂу҆ тебѐ самагѡ̀ сла́вою, ю҆́же и҆мѣ́хъ ᲂу҆ тебѐ пре́жде мі́ръ не бы́сть. ꙗ҆ви́хъ и҆́мѧ твоѐ человѣ́кѡмъ, и҆̀хже да́лъ є҆сѝ мнѣ̀ ѿ мі́ра: твоѝ бѣ́ша, и҆ мнѣ̀ и҆̀хъ да́лъ є҆сѝ, и҆ сло́во твоѐ сохрани́ша. ны́нѣ разꙋмѣ́ша, ꙗ҆́кѡ всѧ̑, є҆ли̑ка да́лъ є҆сѝ мнѣ̀, ѿ тебѐ сꙋ́ть: ꙗ҆́кѡ глаго́лы, и҆̀хже да́лъ є҆сѝ мнѣ̀, да́хъ и҆̀мъ: и҆ ті́и прїѧ́ша, и҆ разꙋмѣ́ша вои́стиннꙋ, ꙗ҆́кѡ ѿ тебѐ и҆зыдо́хъ, и҆ вѣ́роваша, ꙗ҆́кѡ ты́ мѧ посла̀. а҆́зъ ѡ҆ си́хъ молю̀: не ѡ҆ все́мъ мі́рѣ молю̀, но ѡ҆ тѣ́хъ, и҆̀хже да́лъ є҆сѝ мнѣ̀, ꙗ҆́кѡ твоѝ сꙋ́ть. и҆ моѧ̑ всѧ̑, твоѧ̑ сꙋ́ть: и҆ твоѧ̑, моѧ̑: и҆ просла́вихсѧ въ ни́хъ. и҆ ктомꙋ̀ нѣ́смь въ мі́рѣ, и҆ сі́и въ мі́рѣ сꙋ́ть, и҆ а҆́зъ къ тебѣ̀ грѧдꙋ̀. ѻ҆́ч҃е ст҃ы́й, соблюдѝ и҆̀хъ во и҆́мѧ твоѐ, и҆̀хже да́лъ є҆сѝ мнѣ̀, да бꙋ́дꙋтъ є҆ди́но, ꙗ҆́коже и҆ мы̀. є҆гда̀ бѣ́хъ съ ни́ми въ мі́рѣ, а҆́зъ соблюда́хъ и҆̀хъ во и҆́мѧ твоѐ: и҆̀хже да́лъ є҆сѝ мнѣ̀, сохрани́хъ, и҆ никто́же ѿ ни́хъ поги́бе, то́кмѡ сы́нъ поги́бельный, да сбꙋ́детсѧ писа́нїе. ны́нѣ же къ тебѣ̀ грѧдꙋ̀, и҆ сїѧ̑ глаго́лю въ мі́рѣ да и҆́мꙋтъ ра́дость мою̀ и҆спо́лненꙋ въ себѣ̀. а҆́зъ да́хъ и҆̀мъ сло́во твоѐ: и҆ мі́ръ возненави́дѣ и҆̀хъ, ꙗ҆́кѡ не сꙋ́ть ѿ мі́ра, ꙗ҆́коже и҆ а҆́зъ ѿ мі́ра нѣ́смь. не молю̀, да во́з̾меши и҆̀хъ ѿ мі́ра, но да соблюде́ши и҆̀хъ ѿ непрїѧ́зни. ѿ мі́ра не сꙋ́ть, ꙗ҆́коже и҆ а҆́зъ ѿ мі́ра нѣ́смь. свѧтѝ и҆̀хъ во и҆́стинꙋ твою̀: сло́во твоѐ и҆́стина є҆́сть. ꙗ҆́коже менѐ посла́лъ є҆сѝ въ мі́ръ, и҆ а҆́зъ посла́хъ и҆̀хъ въ мі́ръ. и҆ за ни́хъ а҆́зъ свѧщꙋ̀ себѐ, да и҆ ті́и бꙋ́дꙋтъ свѧще́ни во и҆́стинꙋ. не ѡ҆ си́хъ же молю̀ то́кмѡ, но и҆ ѡ҆ вѣ́рꙋющихъ словесѐ и҆́хъ ра́ди въ мѧ̀. да всѝ є҆ди́но сꙋ́ть, ꙗ҆́коже ты̀ ѻ҆́ч҃е во мнѣ̀, и҆ а҆́зъ въ тебѣ̀, да и҆ ті́и въ на́съ є҆ди́но бꙋ́дꙋтъ: да и҆ мі́ръ вѣ́рꙋ и҆́метъ, ꙗ҆́кѡ ты́ мѧ посла́лъ є҆сѝ. и҆ а҆́зъ сла́вꙋ, ю҆́же да́лъ є҆сѝ мнѣ̀, да́хъ и҆̀мъ: да бꙋ́дꙋтъ є҆ди́но, ꙗ҆́коже мы̀ є҆ди́но є҆сма̀. а҆́зъ въ ни́хъ, и҆ ты̀ во мнѣ̀, да бꙋ́дꙋтъ сверше́ни во є҆ди́но, и҆ да разꙋмѣ́етъ мі́ръ, ꙗ҆́кѡ ты́ мѧ посла̀, и҆ возлюби́лъ є҆сѝ и҆̀хъ, ꙗ҆́коже менѐ возлюби́лъ є҆сѝ. ѻ҆́ч҃е, и҆̀хже да́лъ є҆сѝ мнѣ̀, хощꙋ̀, да и҆дѣ́же є҆́смь а҆́зъ, и҆ ті́и бꙋ́дꙋтъ со мно́ю: да ви́дѧтъ сла́вꙋ мою̀, ю҆́же да́лъ є҆сѝ мнѣ̀, ꙗ҆́кѡ возлюби́лъ мѧ̀ є҆сѝ пре́жде сложе́нїѧ мі́ра. ѻ҆́ч҃е пра́ведный, и҆ мі́ръ тебѐ не позна̀, а҆́зъ же тѧ̀ позна́хъ, и҆ сі́и позна́ша, ꙗ҆́кѡ ты́ мѧ посла є҆сѝ̀. и҆ сказа́хъ и҆̀мъ и҆́мѧ твоѐ, и҆ скажꙋ̀, да любы̀, є҆́юже мѧ̀ є҆сѝ возлюби́лъ, въ ни́хъ бꙋ́детъ, и҆ а҆́зъ въ ни́хъ. и҆ сїѧ̑ ре́къ і҆и҃съ, и҆зы́де со ᲂу҆ченикѝ свои́ми на ѻ҆́нъ по́лъ пото́ка ке́дрска, и҆дѣ́же бѣ̀ вертогра́дъ, во́ньже вни́де са́мъ и҆ ᲂу҆ченицы̀ є҆гѡ̀. ",
}

