  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: да не смуща́ется се́рдце ва́ше, ве́руйте в Бо́га, и в Мя ве́руйте. В дому́ Отца́ Моего́ оби́тели мно́ги суть, а́ще ли же ни, рекл бых вам, иду́ угото́вати ме́сто вам. И а́ще поиду́ и угото́влю ме́сто вам, па́ки прииду́ и поиму́ вы к Себе́, да иде́же есмь Аз, и вы бу́дете, и а́може Аз иду́, ве́сте, и путь ве́сте. Глаго́ла Ему́ Фома́: Го́споди, не ве́мы, ка́мо и́деши, и ка́ко мо́жем путь ве́дети? Глаго́ла ему́ Иису́с: Аз есмь путь и и́стина, и живо́т, никто́же прии́дет ко Отцу́, то́кмо Мно́ю. А́ще Мя бы́сте зна́ли, и Отца́ Моего́ зна́ли бы́сте у́бо, и отсе́ле позна́сте Его́, и ви́десте Его́. Глаго́ла Ему́ Фили́пп: Го́споди, покажи́ нам Отца́, и довле́ет нам. Глаго́ла ему́ Иису́с: толи́ко вре́мя с ва́ми есмь, и не позна́л еси́ Мене́, Фили́ппе? Ви́девый Мене́ ви́де Отца́, и ка́ко ты глаго́леши: покажи́ нам Отца́? Не ве́руеши ли, я́ко Аз во Отце́, и Оте́ц во Мне есть? Глаго́лы, я́же Аз глаго́лю вам, о Себе́ не глаго́лю, Оте́ц же во Мне пребыва́яй, Той твори́т дела́. Ве́руйте Мне, я́ко Аз во Отце́, и Оте́ц во Мне. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: да не смꙋща́етсѧ се́рдце ва́ше: вѣ́рꙋйте въ бг҃а, и҆ въ мѧ̀ вѣ́рꙋйте. въ домꙋ̀ ѻ҆ц҃а̀ моегѡ̀ ѻ҆би́тєли мнѡ́ги сꙋ́ть: а҆́ще ли же нѝ, ре́клъ бы́хъ ва́мъ: и҆дꙋ̀ ᲂу҆гото́вати мѣ́сто ва́мъ. и҆ а҆́ще поидꙋ̀ и҆ ᲂу҆гото́влю мѣ́сто ва́мъ, па́ки прїидꙋ̀, и҆ поимꙋ̀ вы̀ къ себѣ̀: да и҆дѣ́же є҆́смь а҆́зъ, и҆ вы̀ бꙋ́дете: и҆ а҆́може а҆́зъ и҆дꙋ̀ вѣ́сте, и҆ пꙋ́ть вѣ́сте. глаго́ла є҆мꙋ̀ ѳѡма̀: гдⷭ҇и, не вѣ́мы, ка́мѡ и҆́деши; и҆ ка́кѡ мо́жемъ пꙋ́ть вѣ́дѣти; глаго́ла є҆мꙋ̀ і҆и҃съ: а҆́зъ є҆́смь пꙋ́ть, и҆ и҆́стина, и҆ живо́тъ: никто́же прїи́детъ ко ѻ҆ц҃ꙋ̀, то́кмѡ мно́ю. а҆́ще мѧ̀ бы́сте зна́ли, и҆ ѻ҆ц҃а̀ моего̀ зна́ли бы́сте ᲂу҆́бѡ: и҆ ѿсе́лѣ позна́сте є҆го̀, и҆ ви́дѣсте є҆го̀. глаго́ла є҆мꙋ̀ фїлі́ппъ: гдⷭ҇и, покажѝ на́мъ ѻ҆ц҃а̀, и҆ довлѣ́етъ на́мъ. глаго́ла є҆мꙋ̀ і҆и҃съ: толи́ко вре́мѧ съ ва́ми є҆́смь, и҆ не позна́лъ є҆сѝ менѐ фїлі́ппе! ви́дѣвый менѐ, ви́дѣ ѻ҆ц҃а̀: и҆ ка́кѡ ты̀ глаго́леши, покажѝ на́мъ ѻ҆ц҃а̀; не вѣ́рꙋеши ли, ꙗ҆́кѡ а҆́зъ во ѻ҆ц҃ѣ̀, и҆ ѻ҆ц҃ъ во мнѣ̀ є҆́сть; глаго́лы ꙗ҆̀же а҆́зъ глаго́лю ва́мъ, ѡ҆ себѣ̀ не глаго́лю: ѻ҆ц҃ъ же во мнѣ̀ пребыва́ѧй, то́й твори́тъ дѣла̀. вѣ́рꙋйте мнѣ̀, ꙗ҆́кѡ а҆́зъ во ѻ҆ц҃ѣ̀, и҆ ѻ҆ц҃ъ во мнѣ̀. ",
}

add_evangelie_ioanna {
  ["номер"] = 48,
  ["комментарий"] = "Ин., 48 зач., XIV, 10–21.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: глаго́лы, я́же Аз глаго́лю вам, о Себе́ не глаго́лю, Оте́ц же во Мне пребыва́яй, Той твори́т дела́, ве́руйте Мне, я́ко Аз во Отце́, и Оте́ц во Мне. А́ще ли же ни, за та дела́ ве́ру ими́те Ми. Ами́нь, ами́нь глаго́лю вам, ве́руяй в Мя, дела́, я́же Аз творю́, и той сотвори́т, и бо́льша сих сотвори́т, я́ко Аз ко Отцу́ Моему́ гряду́. И е́же а́ще что про́сите от Отца́ о и́мени Мое́м, то сотворю́, да просла́вится Оте́ц в Сы́не, и а́ще чесо́ про́сите во и́мя Мое́, Аз сотворю́. А́ще лю́бите Мя, за́поведи Моя́ соблюди́те, и Аз умолю́ Отца́, и ино́го Уте́шителя даст вам, да бу́дет с ва́ми в век, Дух и́стины, Его́же мир не мо́жет прия́ти, я́ко не ви́дит Его́, ниже́ зна́ет Его́, вы же зна́ете Его́, я́ко в вас пребыва́ет и в вас бу́дет. Не оста́влю вас си́ры, прииду́ к вам. Еще́ ма́ло, и мир ктому́ не ви́дит Мене́, вы же ви́дите Мя, я́ко Аз живу́, и вы жи́ви бу́дете, в той день разуме́ете вы, я́ко Аз во Отце́ Мое́м, и вы во Мне, и Аз в вас. Име́яй за́поведи Моя́ и соблюда́яй их, той есть любя́й Мя, а любя́й Мя возлю́блен бу́дет Отце́м Мои́м, и Аз возлюблю́ его́ и явлю́ся ему́ Сам. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: глаго́лы ꙗ҆̀же а҆́зъ глаго́лю ва́мъ, ѡ҆ себѣ̀ не глаго́лю: ѻ҆ц҃ъ же во мнѣ̀ пребыва́ѧй, то́й твори́тъ дѣла̀. вѣ́рꙋйте мнѣ̀, ꙗ҆́кѡ а҆́зъ во ѻ҆ц҃ѣ̀, и҆ ѻ҆ц҃ъ во мнѣ̀. а҆́ще ли же нѝ, за та̀ дѣла̀ вѣ́рꙋ и҆ми́те мѝ. а҆ми́нь а҆ми́нь глаго́лю ва́мъ: вѣ́рꙋѧй въ мѧ̀, дѣла̀ ꙗ҆̀же а҆́зъ творю̀, и҆ то́й сотвори́тъ, и҆ бѡ́льша си́хъ сотвори́тъ, ꙗ҆́кѡ а҆́зъ ко ѻ҆ц҃ꙋ̀ моемꙋ̀ грѧдꙋ̀. и҆ є҆́же а҆́ще что̀ про́сите ѿ ѻ҆ц҃а̀ ѡ҆ и҆́мени мое́мъ, то̀ сотворю̀: да просла́витсѧ ѻ҆ц҃ъ въ сн҃ѣ. и҆ а҆́ще чесѡ̀ про́сите во и҆́мѧ моѐ, а҆́зъ сотворю̀: а҆́ще лю́бите мѧ̀, за́пѡвѣди моѧ̀ соблюди́те. и҆ а҆́зъ ᲂу҆молю̀ ѻ҆ц҃а̀, и҆ и҆но́го ᲂу҆тѣ́шителѧ да́стъ ва́мъ, да бꙋ́детъ съ ва́ми въ вѣ́къ: дх҃ъ и҆́стины, є҆гѡ́же мі́ръ не мо́жетъ прїѧ́ти, ꙗ҆́кѡ не ви́дитъ є҆гѡ̀, нижѐ зна́етъ є҆гѡ̀: вы́ же зна́ете є҆го̀, ꙗ҆́кѡ въ ва́съ пребыва́етъ, и҆ въ ва́съ бꙋ́детъ. не ѡ҆ста́влю ва́съ си́ры: прїидꙋ̀ къ ва́мъ. є҆щѐ ма́лѡ, и҆ мі́ръ ктомꙋ̀ не ви́дитъ менѐ: вы́ же ви́дите мѧ̀, ꙗ҆́кѡ а҆́зъ живꙋ̀, и҆ вы̀ жи́ви бꙋ́дете. въ то́й де́нь разꙋмѣ́ете вы̀, ꙗ҆́кѡ а҆́зъ во ѻ҆ц҃ѣ̀ мое́мъ, и҆ вы̀ во мнѣ̀, и҆ а҆́зъ въ ва́съ. и҆мѣ́ѧй за́пѡвѣди моѧ̀ и҆ соблюда́ѧй и҆̀хъ, то́й є҆́сть любѧ́й мѧ̀: а҆ любѧ́й мѧ̀, возлю́бленъ бꙋ́детъ ѻ҆ц҃е́мъ мои́мъ, и҆ а҆́зъ возлюблю̀ є҆го̀, и҆ ꙗ҆влю́сѧ є҆мꙋ̀ са́мъ. ",
}

add_evangelie_ioanna {
