  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: име́яй за́поведи Моя́ и соблюда́яй их, той есть любя́й Мя, а любя́й Мя возлю́блен бу́дет Отце́м Мои́м, и Аз возлюблю́ его́ и явлю́ся ему́ Сам. Глаго́ла Ему́ Иу́да не Искарио́тский: Го́споди, и что бысть, я́ко нам хо́щеши яви́тися, а не ми́рови? Отвеща́ Иису́с и рече́ ему́: а́ще кто лю́бит Мя, сло́во Мое́ соблюде́т, и Оте́ц Мой возлю́бит его́, и к нему́ прии́дема и оби́тель у него́ сотвори́ма. Не любя́й Мя слове́с Мои́х не соблюда́ет, и сло́во, е́же слы́шасте, несть Мое́, но посла́вшаго Мя Отца́. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: и҆мѣ́ѧй за́пѡвѣди моѧ̀ и҆ соблюда́ѧй и҆̀хъ, то́й є҆́сть любѧ́й мѧ̀: а҆ любѧ́й мѧ̀, возлю́бленъ бꙋ́детъ ѻ҆ц҃е́мъ мои́мъ, и҆ а҆́зъ возлюблю̀ є҆го̀, и҆ ꙗ҆влю́сѧ є҆мꙋ̀ са́мъ. глаго́ла є҆мꙋ̀ і҆ꙋ́да, не і҆скарїѡ́тскїй: гдⷭ҇и, и҆ что̀ бы́сть, ꙗ҆́кѡ на́мъ хо́щеши ꙗ҆ви́тисѧ, а҆ не мі́рови; ѿвѣща̀ і҆и҃съ, и҆ речѐ є҆мꙋ̀: а҆́ще кто̀ лю́битъ мѧ̀, сло́во моѐ соблюде́тъ: и҆ ѻ҆ц҃ъ мо́й возлю́битъ є҆го̀, и҆ къ немꙋ̀ прїи́дема, и҆ ѻ҆би́тель ᲂу҆ негѡ̀ сотвори́ма. не любѧ́й мѧ̀, слове́съ мои́хъ не соблюда́етъ: и҆ сло́во, є҆́же слы́шасте, нѣ́сть моѐ, но посла́вшагѡ мѧ̀ ѻ҆ц҃а̀. ",
}

add_evangelie_ioanna {
  ["номер"] = 49,
  ["комментарий"] = "Ин., 49 зач., XIV, 27 – XV, 7.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: да не смуща́ется се́рдце ва́ше, ни устраша́ет. Слы́шасте, я́ко Аз рех вам: иду́ и прииду́ к вам. А́ще бы́сте люби́ли Мя, возра́довалися бы́сте у́бо, я́ко рех: иду́ ко Отцу́, я́ко Оте́ц Мой бо́лий Мене́ есть. И ны́не рех вам, пре́жде да́же не бу́дет, да, егда́ бу́дет, ве́ру и́мете. Ктому́ не мно́го глаго́лю с ва́ми, гряде́т бо сего́ ми́ра князь и во Мне не и́мать ничесо́же. Но да разуме́ет мир, я́ко люблю́ Отца́, и я́коже запове́да Мне Оте́ц, та́ко творю́, воста́ните, и́дем отсю́ду. Аз есмь лоза́ и́стинная, и Оте́ц Мой де́латель есть. Вся́ку розгу́ о Мне не творя́щую плода́, и́змет ю́, и вся́ку творя́щую плод, отреби́т ю́, да мно́жайший плод принесе́т. Уже́ вы чи́сти есте́ за сло́во, е́же глаго́лах вам. Бу́дите во Мне, и Аз в вас. Я́коже розга́ не мо́жет плода́ сотвори́ти о себе́, а́ще не бу́дет на лозе́, та́ко и вы, а́ще во Мне не пребу́дете. Аз есмь лоза́, вы же ро́ждие, и и́же бу́дет во Мне, и Аз в нем, той сотвори́т плод мног, я́ко без Мене́ не мо́жете твори́ти ничесо́же, а́ще кто во Мне не пребу́дет, изве́ржется вон, я́коже розга́, и изсы́шет, и собира́ют ю́ и во огнь влага́ют, и сгара́ет. А́ще пребу́дете во Мне и глаго́лы Мои́ в вас пребу́дут, ему́же а́ще хо́щете, проси́те, и бу́дет вам. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: да не смꙋща́етсѧ се́рдце ва́ше, ни ᲂу҆страша́етъ. слы́шасте, ꙗ҆́кѡ а҆́зъ рѣ́хъ ва́мъ: и҆дꙋ̀ и҆ прїидꙋ̀ къ ва́мъ. а҆́ще бы́сте люби́ли мѧ̀, возра́довалисѧ бы́сте ᲂу҆́бѡ, ꙗ҆́кѡ рѣ́хъ, и҆дꙋ̀ ко ѻ҆ц҃ꙋ̀: ꙗ҆́кѡ ѻ҆ц҃ъ мо́й бо́лїй менѐ є҆́сть. и҆ ны́нѣ рѣ́хъ ва́мъ, пре́жде да́же не бꙋ́детъ, да є҆гда̀ бꙋ́детъ, вѣ́рꙋ и҆́мете. ктомꙋ̀ не мно́гѡ глаго́лю съ ва́ми: грѧде́тъ бо сегѡ̀ мі́ра кнѧ́зь, и҆ во мнѣ̀ не и҆́мать ничесѡ́же. но да разꙋмѣ́етъ мі́ръ, ꙗ҆́кѡ люблю̀ ѻ҆ц҃а̀, и҆ ꙗ҆́коже заповѣ́да мнѣ̀ ѻ҆ц҃ъ, та́кѡ творю̀: воста́ните, и҆́демъ ѿсю́дꙋ. а҆́зъ є҆́смь лоза̀ и҆́стиннаѧ, и҆ ѻ҆ц҃ъ мо́й дѣ́латель є҆́сть. всѧ́кꙋ розгꙋ̀, ѡ҆ мнѣ̀ не творѧ́щꙋю плода̀, и҆́зметъ ю҆̀: и҆ всѧ́кꙋ творѧ́щꙋю пло́дъ, ѡ҆треби́тъ ю҆̀, да мно́жайшїй пло́дъ принесе́тъ. ᲂу҆жѐ вы̀ чи́сти є҆стѐ за сло́во, є҆́же глаго́лахъ ва́мъ. бꙋ́дите во мнѣ̀, и҆ а҆́зъ въ ва́съ: ꙗ҆́коже розга̀ не мо́жетъ плода̀ сотвори́ти ѡ҆ себѣ̀, а҆́ще не бꙋ́детъ на лозѣ̀, та́кѡ и҆ вы̀, а҆́ще во мнѣ̀ не пребꙋ́дете. а҆́зъ є҆́смь лоза̀, вы́ же ро́ждїє: и҆ и҆́же бꙋ́детъ во мнѣ̀, и҆ а҆́зъ въ не́мъ, то́й сотвори́тъ пло́дъ мно́гъ: ꙗ҆́кѡ без̾ менѐ не мо́жете твори́ти ничесѡ́же. а҆́ще кто̀ во мнѣ̀ не пребꙋ́детъ, и҆зве́ржетсѧ во́нъ, ꙗ҆́коже розга̀, и҆ и҆зсы́шетъ: и҆ собира́ютъ ю҆̀, и҆ во ѻ҆́гнь влага́ютъ, и҆ сгара́етъ. а҆́ще пребꙋ́дете во мнѣ̀, и҆ глаго́лы моѝ въ ва́съ пребꙋ́дꙋтъ: є҆мꙋ́же а҆́ще хо́щете, проси́те, и҆ бꙋ́детъ ва́мъ. ",
}

add_evangelie_ioanna {
  ["номер"] = 50,
  ["комментарий"] = "Ин., 50 зач., XV, 1–7.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: Аз есмь лоза́ и́стинная, и Оте́ц Мой де́латель есть. Вся́ку розгу́ о Мне не творя́щую плода́, и́змет ю́, и вся́ку творя́щую плод, отреби́т ю́, да мно́жайший плод принесе́т. Уже́ вы чи́сти есте́ за сло́во, е́же глаго́лах вам. Бу́дите во Мне, и Аз в вас. Я́коже розга́ не мо́жет плода́ сотвори́ти о себе́, а́ще не бу́дет на лозе́, та́ко и вы, а́ще во Мне не пребу́дете. Аз есмь лоза́, вы же ро́ждие, и и́же бу́дет во Мне, и Аз в нем, той сотвори́т плод мног, я́ко без Мене́ не мо́жете твори́ти ничесо́же. А́ще кто во Мне не пребу́дет, изве́ржется вон, я́коже розга́, и изсы́шет, и собира́ют ю́ и во огнь влага́ют, и сгара́ет. А́ще пребу́дете во Мне и глаго́лы Мои́ в вас пребу́дут, ему́же а́ще хо́щете, проси́те, и бу́дет вам. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: а҆́зъ є҆́смь лоза̀ и҆́стиннаѧ, и҆ ѻ҆ц҃ъ мо́й дѣ́латель є҆́сть. всѧ́кꙋ розгꙋ̀, ѡ҆ мнѣ̀ не творѧ́щꙋю плода̀, и҆́зметъ ю҆̀: и҆ всѧ́кꙋ творѧ́щꙋю пло́дъ, ѡ҆треби́тъ ю҆̀, да мно́жайшїй пло́дъ принесе́тъ. ᲂу҆жѐ вы̀ чи́сти є҆стѐ за сло́во, є҆́же глаго́лахъ ва́мъ. бꙋ́дите во мнѣ̀, и҆ а҆́зъ въ ва́съ: ꙗ҆́коже розга̀ не мо́жетъ плода̀ сотвори́ти ѡ҆ себѣ̀, а҆́ще не бꙋ́детъ на лозѣ̀, та́кѡ и҆ вы̀, а҆́ще во мнѣ̀ не пребꙋ́дете. а҆́зъ є҆́смь лоза̀, вы́ же ро́ждїє: и҆ и҆́же бꙋ́детъ во мнѣ̀, и҆ а҆́зъ въ не́мъ, то́й сотвори́тъ пло́дъ мно́гъ: ꙗ҆́кѡ без̾ менѐ не мо́жете твори́ти ничесѡ́же. а҆́ще кто̀ во мнѣ̀ не пребꙋ́детъ, и҆зве́ржетсѧ во́нъ, ꙗ҆́коже розга̀, и҆ и҆зсы́шетъ: и҆ собира́ютъ ю҆̀, и҆ во ѻ҆́гнь влага́ютъ, и҆ сгара́етъ. а҆́ще пребꙋ́дете во мнѣ̀, и҆ глаго́лы моѝ въ ва́съ пребꙋ́дꙋтъ: є҆мꙋ́же а҆́ще хо́щете, проси́те, и҆ бꙋ́детъ ва́мъ. ",
}

add_evangelie_ioanna {
  ["номер"] = 51,
  ["комментарий"] = "Ин., 51 зач., XV, 9-16.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: я́коже возлюби́ Мя Оте́ц, и Аз возлюби́х вас, бу́дите в любви́ Мое́й. А́ще за́поведи Моя́ соблюде́те, пребу́дете в любви́ Мое́й, я́коже Аз за́поведи Отца́ Моего́ соблюдо́х и пребыва́ю в Его́ любви́. Сия́ глаго́лах вам, да ра́дость Моя́ в вас бу́дет и ра́дость ва́ша испо́лнится. Сия́ есть за́поведь Моя́, да лю́бите друг дру́га, я́коже возлюби́х вы. Бо́льши сея́ любве́ никто́же и́мать, да кто ду́шу свою́ положи́т за дру́ги своя́. Вы дру́зи Мои́ есте́, а́ще творите́, ели́ка Аз запове́даю вам. Не ктому́ вас глаго́лю рабы́, я́ко раб не весть, что твори́т госпо́дь его́, вас же реко́х дру́ги, я́ко вся, я́же слы́шах от Отца́ Моего́, сказа́х вам. Не вы Мене́ избра́сте, но Аз избра́х вас и положи́х вас, да вы и́дете и плод принесе́те, и плод ваш пребу́дет, да его́же а́ще про́сите от Отца́ во и́мя Мое́, даст вам. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: ꙗ҆́коже возлюби́ мѧ ѻ҆ц҃ъ, и҆ а҆́зъ возлюби́хъ ва́съ: бꙋ́дите въ любвѝ мое́й. а҆́ще за́пѡвѣди моѧ̀ соблюде́те, пребꙋ́дете въ любвѝ мое́й: ꙗ҆́коже а҆́зъ за́пѡвѣди ѻ҆ц҃а̀ моегѡ̀ соблюдо́хъ, и҆ пребыва́ю въ є҆гѡ̀ любвѝ. сїѧ̑ глаго́лахъ ва́мъ, да ра́дость моѧ̀ въ ва́съ бꙋ́детъ, и҆ ра́дость ва́ша и҆спо́лнитсѧ. сїѧ̀ є҆́сть за́повѣдь моѧ̀, да лю́бите дрꙋ́гъ дрꙋ́га, ꙗ҆́коже возлюби́хъ вы̀. бо́льши сеѧ̀ любвѐ никто́же и҆́мать, да кто̀ дꙋ́шꙋ свою̀ положи́тъ за дрꙋ́ги своѧ̀. вы̀ дрꙋ́зи моѝ є҆стѐ, а҆́ще творитѐ, є҆ли̑ка а҆́зъ заповѣ́даю ва́мъ. не ктомꙋ̀ ва́съ глаго́лю рабы̑, ꙗ҆́кѡ ра́бъ не вѣ́сть, что̀ твори́тъ гдⷭ҇ь є҆гѡ̀: ва́съ же реко́хъ дрꙋ́ги, ꙗ҆́кѡ всѧ̑, ꙗ҆̀же слы́шахъ ѿ ѻ҆ц҃а̀ моегѡ̀, сказа́хъ ва́мъ. не вы̀ менѐ и҆збра́сте, но а҆́зъ и҆збра́хъ ва́съ, и҆ положи́хъ ва́съ, да вы̀ и҆́дете, и҆ пло́дъ принесе́те, и҆ пло́дъ ва́шъ пребꙋ́детъ: да є҆гѡ́же а҆́ще про́сите ѿ ѻ҆ц҃а̀ во и҆́мѧ моѐ, да́стъ ва́мъ. ",
}

add_evangelie_ioanna {
  ["номер"] = 52,
  ["комментарий"] = "Ин., 52 зач., XV, 17 – XVI, 2.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: си запове́даю вам, да лю́бите друг дру́га. А́ще мир вас ненави́дит, ве́дите, я́ко Мене́ пре́жде вас возненави́де. А́ще от ми́ра бы́сте бы́ли, мир у́бо свое́ люби́л бы, я́коже от ми́ра не́сте, но Аз избра́х вы от ми́ра, сего́ ра́ди ненави́дит вас мир. Помина́йте сло́во, е́же Аз рех вам: несть раб бо́лий го́спода своего́. А́ще Мене́ изгна́ша, и вас изжену́т, а́ще сло́во Мое́ соблюдо́ша, и ва́ше соблюду́т. Но сия́ вся творя́т вам за и́мя Мое́, я́ко не ве́дят Посла́вшаго Мя. А́ще не бых прише́л и глаго́лал им, греха́ не бы́ша име́ли, ны́не же вины́ не и́мут о гресе́ свое́м. Ненави́дяй Мене́, и Отца́ Моего́ ненави́дит. А́ще дел не бых сотвори́л в них, и́хже ин никто́же сотвори́, греха́ не бы́ша име́ли, ны́не же и ви́деша, и возненави́деша Мене́ и Отца́ Моего́. Но да сбу́дется сло́во, пи́санное в зако́не их, я́ко возненави́деша Мя ту́не. Егда́ же прии́дет Уте́шитель, Его́же Аз послю́ вам от Отца́, Дух и́стины, И́же от Отца́ исхо́дит, Той свиде́тельствует о Мне. И вы же свиде́тельствуете, я́ко искони́ со Мно́ю есте́. Сия́ глаго́лах вам, да не соблазните́ся. От со́нмищ иждену́т вы, но прии́дет час, да всяк, и́же убие́т вы, мни́тся слу́жбу приноси́ти Бо́гу. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: сѝ заповѣ́даю ва́мъ, да лю́бите дрꙋ́гъ дрꙋ́га. а҆́ще мі́ръ ва́съ ненави́дитъ, вѣ́дите, ꙗ҆́кѡ менѐ пре́жде ва́съ возненави́дѣ. а҆́ще ѿ мі́ра бы́сте бы́ли, мі́ръ ᲂу҆́бѡ своѐ люби́лъ бы: ꙗ҆́коже ѿ мі́ра нѣ́сте, но а҆́зъ и҆збра́хъ вы̀ ѿ мі́ра, сегѡ̀ ра́ди ненави́дитъ ва́съ мі́ръ. помина́йте сло́во, є҆́же а҆́зъ рѣ́хъ ва́мъ: нѣ́сть ра́бъ бо́лїй гдⷭ҇а своегѡ̀. а҆́ще менѐ и҆згна́ша, и҆ ва́съ и҆зженꙋ́тъ: а҆́ще сло́во моѐ соблюдо́ша, и҆ ва́ше соблюдꙋ́тъ. но сїѧ̑ всѧ̑ творѧ́тъ ва́мъ за и҆́мѧ моѐ, ꙗ҆́кѡ не вѣ́дѧтъ посла́вшагѡ мѧ̀. а҆́ще не бы́хъ прише́лъ, и҆ глаго́лалъ и҆̀мъ, грѣха̀ не бы́ша и҆мѣ́ли: ны́нѣ же вины̀ не и҆́мꙋтъ ѡ҆ грѣсѣ̀ свое́мъ. ненави́дѧй менѐ, и҆ ѻ҆ц҃а̀ моего̀ ненави́дитъ. а҆́ще дѣ́лъ не бы́хъ сотвори́лъ въ ни́хъ, и҆̀хже и҆́нъ никто́же сотворѝ, грѣха̀ не бы́ша и҆мѣ́ли: ны́нѣ же и҆ ви́дѣша, и҆ возненави́дѣша менѐ, и҆ ѻ҆ц҃а̀ моего̀. но да сбꙋ́детсѧ сло́во пи́санное въ зако́нѣ и҆́хъ: ꙗ҆́кѡ возненави́дѣша мѧ̀ тꙋ́не. є҆гда́ же прїи́детъ ᲂу҆тѣ́шитель, є҆го́же а҆́зъ послю̀ ва́мъ ѿ ѻ҆ц҃а̀, дх҃ъ и҆́стины, и҆́же ѿ ѻ҆ц҃а̀ и҆схо́дитъ, то́й свидѣ́тельствꙋетъ ѡ҆ мнѣ̀. и҆ вы́ же свидѣ́тельствꙋете, ꙗ҆́кѡ и҆сконѝ со мно́ю є҆стѐ. сїѧ̑ глаго́лахъ ва́мъ, да не соблазните́сѧ. ѿ со́нмищъ и҆жденꙋ́тъ вы̀: но прїи́детъ ча́съ, да всѧ́къ и҆́же ᲂу҆бїе́тъ вы̀ мни́тсѧ слꙋ́жбꙋ приноси́ти бг҃ꙋ. ",
}

add_evangelie_ioanna {
  ["номер"] = 53,
  ["комментарий"] = "Ин., 53 зач., XVI, 2–13.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: прии́дет час, да всяк, и́же убие́т вы, мни́тся слу́жбу приноси́ти Бо́гу. И сия́ сотворя́т, я́ко не позна́ша Отца́, ни Мене́. Но сия́ глаго́лах вам, да егда́ прии́дет час, помина́йте се, я́ко Аз рех вам. Сих же вам испе́рва не рех, я́ко с ва́ми бех. Ны́не же иду́ к Посла́вшему Мя, и никто́же от вас вопроша́ет Мене́: ка́мо и́деши? Но я́ко сия́ глаго́лах вам, ско́рби испо́лних се́рдца ва́ша. Но Аз и́стину вам глаго́лю: у́не есть вам, да Аз иду́, а́ще бо не иду́ Аз, Уте́шитель не прии́дет к вам, а́ще ли же иду́, послю́ Его́ к вам. И прише́д Он обличи́т мир о гресе́ и о пра́вде и о суде́. О гресе́ у́бо, я́ко не ве́руют в Мя. О пра́вде же, я́ко ко Отцу́ Моему́ иду́, и ктому́ не ви́дите Мене́. О суде́ же, я́ко князь ми́ра сего́ осужде́н бысть. Еще́ мно́го и́мам глаго́лати вам, но не мо́жете носи́ти ны́не, егда́ же прии́дет Он, Дух и́стины, наста́вит вы на вся́ку и́стину. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: прїи́детъ ча́съ, да всѧ́къ и҆́же ᲂу҆бїе́тъ вы̀ мни́тсѧ слꙋ́жбꙋ приноси́ти бг҃ꙋ. и҆ сїѧ̑ сотворѧ́тъ, ꙗ҆́кѡ не позна́ша ѻ҆ц҃а̀, ни менѐ. но сїѧ̑ глаго́лахъ ва́мъ: да є҆гда̀ прїи́детъ ча́съ, помина́йте сѐ, ꙗ҆́кѡ а҆́зъ рѣ́хъ ва́мъ. си́хъ же ва́мъ и҆спе́рва не рѣ́хъ, ꙗ҆́кѡ съ ва́ми бѣ́хъ. ны́нѣ же и҆дꙋ̀ къ посла́вшемꙋ мѧ̀, и҆ никто́же ѿ ва́съ вопроша́етъ менѐ, ка́мѡ и҆́деши; но ꙗ҆́кѡ сїѧ̑ глаго́лахъ ва́мъ, ско́рби и҆спо́лнихъ сердца̀ ва́ша. но а҆́зъ и҆́стинꙋ ва́мъ глаго́лю, ᲂу҆́не є҆́сть ва́мъ, да а҆́зъ и҆дꙋ̀: а҆́ще бо не и҆дꙋ̀ а҆́зъ, ᲂу҆тѣ́шитель не прїи́детъ къ ва́мъ. а҆́ще ли же и҆дꙋ̀, послю̀ є҆го̀ къ ва́мъ. и҆ прише́дъ ѻ҆́нъ, ѡ҆бличи́тъ мі́ръ ѡ҆ грѣсѣ̀, и҆ ѡ҆ пра́вдѣ, и҆ ѡ҆ сꙋдѣ̀. ѡ҆ грѣсѣ̀ ᲂу҆́бѡ, ꙗ҆́кѡ не вѣ́рꙋютъ въ мѧ̀. ѡ҆ пра́вдѣ же, ꙗ҆́кѡ ко ѻ҆ц҃ꙋ̀ моемꙋ̀ и҆дꙋ̀, и҆ ктомꙋ̀ не ви́дите менѐ. ѡ҆ сꙋдѣ́ же, ꙗ҆́кѡ кнѧ́зь мі́ра сегѡ̀ ѡ҆сꙋжде́нъ бы́сть. є҆щѐ мно́гѡ и҆́мамъ глаго́лати ва́мъ, но не мо́жете носи́ти ны́нѣ. є҆гда́ же прїи́детъ ѻ҆́нъ, дх҃ъ и҆́стины, наста́витъ вы̀ на всѧ́кꙋ и҆́стинꙋ. ",
}

add_evangelie_ioanna {
  ["номер"] = 54,
  ["комментарий"] = "Ин., 54 зач., XVI, 15–23.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: вся, ели́ка и́мать Оте́ц, Моя́ суть, сего́ ра́ди рех, я́ко от Моего́ прии́мет и возвести́т вам. Вма́ле, и ктому́ не ви́дите Мене́, и па́ки вма́ле, и у́зрите Мя, я́ко иду́ ко Отцу́. Ре́ша же от учени́к Его́ к себе́: что есть сие́, е́же глаго́лет нам: вма́ле, и не ви́дите Мене́? И па́ки вма́ле, и у́зрите Мя? И я́ко Аз иду́ ко Отцу́? Глаго́лаху у́бо: что сие́ есть, е́же глаго́лет, вма́ле? Не ве́мы, что глаго́лет. Разуме́ же Иису́с, я́ко хотя́ху Его́ вопроша́ти, и рече́ им: о сем ли стяза́етеся между́ собо́ю, я́ко рех: вма́ле, и не ви́дите Мене́, и па́ки вма́ле, и у́зрите Мя? Ами́нь, ами́нь глаго́лю вам, я́ко воспла́четеся и возрыда́ете вы, а мир возра́дуется, вы же печа́льни бу́дете, но печа́ль ва́ша в ра́дость бу́дет. Жена́ егда́ ражда́ет, скорбь и́мать, я́ко прии́де год ея́, егда́ же роди́т отроча́, ктому́ не по́мнит ско́рби за ра́дость, я́ко роди́ся челове́к в мир. И вы же печа́ль и́мате у́бо ны́не, па́ки же узрю́ вы, и возра́дуется се́рдце ва́ше, и ра́дости ва́шея никто́же во́змет от вас, и в той день Мене́ не воспро́сите ничесо́же. Ами́нь, ами́нь глаго́лю вам, я́ко ели́ка а́ще чесо́ про́сите от Отца́ во и́мя Мое́, даст вам. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: всѧ̑ є҆ли̑ка и҆́мать ѻ҆ц҃ъ, моѧ̑ сꙋ́ть: сегѡ̀ ра́ди рѣ́хъ, ꙗ҆́кѡ ѿ моегѡ̀ прїи́метъ, и҆ возвѣсти́тъ ва́мъ. вма́лѣ, и҆ ктомꙋ̀ не ви́дите менѐ: и҆ па́ки вма́лѣ, и҆ ᲂу҆́зрите мѧ̀, ꙗ҆́кѡ и҆дꙋ̀ ко ѻ҆ц҃ꙋ̀. рѣ́ша же ѿ ᲂу҆чени̑къ є҆гѡ̀ къ себѣ̀: что́ є҆сть сїѐ, є҆́же глаго́летъ на́мъ, вма́лѣ, и҆ не ви́дите менѐ; и҆ па́ки, вма́лѣ и҆ ᲂу҆́зрите мѧ̀; и҆ ꙗ҆́кѡ а҆́зъ и҆дꙋ̀ ко ѻ҆ц҃ꙋ̀, глаго́лахꙋ ᲂу҆́бѡ, что̀ сїѐ є҆́сть, є҆́же глаго́летъ, вма́лѣ; не вѣ́мы, что̀ глаго́летъ. разꙋмѣ́ же і҆и҃съ, ꙗ҆́кѡ хотѧ́хꙋ є҆го̀ вопроша́ти, и҆ речѐ и҆̀мъ: ѡ҆ се́мъ ли стѧза́етесѧ междꙋ̀ собо́ю, ꙗ҆́кѡ рѣ́хъ: вма́лѣ, и҆ не ви́дите менѐ: и҆ па́ки, вма́лѣ, и҆ ᲂу҆́зрите мѧ̀; а҆ми́нь а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ воспла́четесѧ и҆ возрыда́ете вы̀, а҆ мі́ръ возра́дꙋетсѧ: вы́ же печа́льни бꙋ́дете, но печа́ль ва́ша въ ра́дость бꙋ́детъ. жена̀, є҆гда̀ ражда́етъ, ско́рбь и҆́мать, ꙗ҆́кѡ прїи́де го́дъ є҆ѧ̀: є҆гда́ же роди́тъ ѻ҆троча̀, ктомꙋ̀ не по́мнитъ ско́рби за ра́дость, ꙗ҆́кѡ роди́сѧ человѣ́къ въ мі́ръ. и҆ вы́ же печа́ль и҆́мате ᲂу҆́бѡ ны́нѣ: па́ки же ᲂу҆зрю̀ вы̀, и҆ возра́дꙋетсѧ се́рдце ва́ше, и҆ ра́дости ва́шеѧ никто́же во́з̾метъ ѿ ва́съ: и҆ въ то́й де́нь менѐ не вопро́сите ничесѡ́же. а҆ми́нь а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ є҆ли̑ка а҆́ще чесѡ̀ про́сите ѿ ѻ҆ц҃а̀ во и҆́мѧ моѐ, да́стъ ва́мъ. ",
}

add_evangelie_ioanna {
  ["номер"] = 55,
  ["комментарий"] = "Ин., 55 зач., XVI, 23–33.",
  ["текст_ру"] = "Рече́ Госпо́дь Свои́м ученико́м: ами́нь, ами́нь глаго́лю вам, я́ко ели́ка а́ще чесо́ про́сите от Отца́ во и́мя Мое́, даст вам. Досе́ле не проси́сте ничесо́же во и́мя Мое́, проси́те, и прии́мете, да ра́дость ва́ша испо́лнена бу́дет. Сия́ в при́тчах глаго́лах вам, но прии́дет час, егда́ ктому́ в при́тчах не глаго́лю вам, но я́ве о Отце́ возвещу́ вам. В той день во и́мя Мое́ воспро́сите, и не глаго́лю вам, я́ко Аз умолю́ Отца́ о вас. Сам бо Оте́ц лю́бит вы, я́ко вы Мене́ возлюби́сте и ве́ровасте, я́ко Аз от Бо́га изыдо́х. Изыдо́х от Отца́ и приидо́х в мир, и па́ки оставля́ю мир и иду́ ко Отцу́. Глаго́лаша Ему́ ученицы́ Его́: се ны́не не обину́яся глаго́леши, а при́тчи никоея́же не глаго́леши. Ны́не ве́мы, я́ко ве́си вся и не тре́буеши, да кто Тя вопроша́ет, о сем ве́руем, я́ко от Бо́га изше́л еси́. Отвеща́ им Иису́с: ны́не ли ве́руете? Се гряде́т час, и ны́не прии́де, да разы́детеся ко́ждо во своя́ и Мене́ еди́наго оста́вите, и несмь еди́н, я́ко Оте́ц со Мно́ю есть. Сия́ глаго́лах вам, да во Мне мир и́мате. ",
  ["текст_цс"] = "Речѐ гдⷭ҇ь свои́мъ ᲂу҆ченикѡ́мъ: а҆ми́нь а҆ми́нь глаго́лю ва́мъ, ꙗ҆́кѡ є҆ли̑ка а҆́ще чесѡ̀ про́сите ѿ ѻ҆ц҃а̀ во и҆́мѧ моѐ, да́стъ ва́мъ. досе́лѣ не проси́сте ничесѡ́же во и҆́мѧ моѐ: проси́те, и҆ прїи́мете, да ра́дость ва́ша и҆спо́лнена бꙋ́детъ. сїѧ̑ въ при́тчахъ глаго́лахъ ва́мъ: но прїи́детъ ча́съ, є҆гда̀ ктомꙋ̀ въ при́тчахъ не глаго́лю ва́мъ, но ꙗ҆́вѣ ѡ҆ ѻ҆ц҃ѣ̀ возвѣщꙋ̀ ва́мъ. въ то́й де́нь во и҆́мѧ моѐ вопро́сите, и҆ не глаго́лю ва́мъ, ꙗ҆́кѡ а҆́зъ ᲂу҆молю̀ ѻ҆ц҃а̀ ѡ҆ ва́съ. са́мъ бо ѻ҆ц҃ъ лю́битъ вы̀, ꙗ҆́кѡ вы̀ менѐ возлюби́сте, и҆ вѣ́ровасте, ꙗ҆́кѡ а҆́зъ ѿ бг҃а и҆зыдо́хъ. и҆зыдо́хъ ѿ ѻ҆ц҃а̀, и҆ прїидо́хъ въ мі́ръ: и҆ па́ки ѡ҆ставлѧ́ю мі́ръ, и҆ и҆дꙋ̀ ко ѻ҆ц҃ꙋ̀. глаго́лаша є҆мꙋ̀ ᲂу҆ченицы̀ є҆гѡ̀: сѐ ны́нѣ не ѡ҆бинꙋ́ѧсѧ глаго́леши, а҆ при́тчи никоеѧ́же не глаго́леши. ны́нѣ вѣ́мы, ꙗ҆́кѡ вѣ́си всѧ̑, и҆ не тре́бꙋеши, да кто́ тѧ вопроша́етъ: ѡ҆ се́мъ вѣ́рꙋемъ, ꙗ҆́кѡ ѿ бг҃а и҆зше́лъ є҆сѝ. ѿвѣща̀ и҆̀мъ і҆и҃съ: ны́нѣ ли вѣ́рꙋете; сѐ грѧде́тъ ча́съ, и҆ ны́нѣ прїи́де, да разы́детесѧ ко́ждо во своѧ̑, и҆ менѐ є҆ди́наго ѡ҆ста́вите: и҆ нѣ́смь є҆ди́нъ, ꙗ҆́кѡ ѻ҆ц҃ъ со мно́ю є҆́сть. сїѧ̑ глаго́лахъ ва́мъ, да во мнѣ̀ ми́ръ и҆́мате. ",
}

add_evangelie_ioanna {
  ["номер"] = 56,
  ["комментарий"] = "Ин., 56 зач., XVII, 1–13.",
  ["текст_ру"] = "Во вре́мя о́но, возведе́ Иису́с о́чи Свои́ на не́бо и рече́: О́тче, прии́де час, просла́ви Сы́на Твоего́, да и Сын Твой просла́вит Тя. Я́коже дал еси́ Ему́ власть вся́кия пло́ти, да вся́ко, е́же дал еси́ Ему́, даст им живо́т ве́чный, се же есть живо́т ве́чный, да зна́ют Тебе́ еди́наго и́стиннаго Бо́га, и Его́же посла́л еси́ Иису́с Христа́. Аз просла́вих Тя на земли́, де́ло соверши́х, е́же дал еси́ Мне да сотворю́. И ны́не просла́ви Мя Ты, О́тче, у Тебе́ Самаго́ сла́вою, ю́же име́х у Тебе́ пре́жде мир не бысть. Яви́х и́мя Твое́ челове́ком, и́хже дал еси́ Мне от ми́ра. Твои́ бе́ша, и Мне их дал еси́, и сло́во Твое́ сохрани́ша. Ны́не разуме́ша, я́ко вся, ели́ка дал еси́ Мне, от Тебе́ суть. Я́ко глаго́лы, и́хже дал еси́ Мне, дах им, и ти́и прия́ша, и разуме́ша вои́стинну, я́ко от Тебе́ изыдо́х, и ве́роваша, я́ко Ты Мя посла́. Аз о сих молю́, не о всем ми́ре молю́, но о тех, и́хже дал еси́ Мне, я́ко Твои́ суть. И Моя́ вся Твоя́ суть, и Твоя́ Моя́, и просла́вихся в них. И ктому́ несмь в ми́ре, и си́и в ми́ре суть, и Аз к Тебе́ гряду́. О́тче Святы́й, соблюди́ их во и́мя Твое́, и́хже дал еси́ Мне, да бу́дут еди́но, я́коже и Мы. Егда́ бех с ни́ми в ми́ре, Аз соблюда́х их во и́мя Твое́, и́хже дал еси́ Мне, сохрани́х, и никто́же от них поги́бе, то́кмо сын поги́бельный, да сбу́дется Писа́ние. Ны́не же к Тебе́ гряду́, и сия́ глаго́лю в ми́ре, да и́мут ра́дость Мою́ испо́лнену в себе́. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, возведѐ і҆и҃съ ѻ҆́чи своѝ на нб҃о, и҆ речѐ: ѻ҆́ч҃е, прїи́де ча́съ: просла́ви сн҃а твоего̀, да и҆ сн҃ъ тво́й просла́витъ тѧ̀: ꙗ҆́коже да́лъ є҆сѝ є҆мꙋ̀ вла́сть всѧ́кїѧ пло́ти, да всѧ́ко є҆́же да́лъ є҆сѝ є҆мꙋ̀, да́стъ и҆̀мъ живо́тъ вѣ́чный. се́ же є҆́сть живо́тъ вѣ́чный, да зна́ютъ тебѐ є҆ди́наго и҆́стиннаго бг҃а, и҆ є҆го́же посла́лъ є҆сѝ і҆и҃съ хрⷭ҇та̀. а҆́зъ просла́вихъ тѧ̀ на землѝ: дѣ́ло соверши́хъ, є҆́же да́лъ є҆сѝ мнѣ̀ да сотворю̀. и҆ ны́нѣ просла́ви мѧ̀ ты̀ ѻ҆́ч҃е ᲂу҆ тебѐ самагѡ̀ сла́вою, ю҆́же и҆мѣ́хъ ᲂу҆ тебѐ пре́жде мі́ръ не бы́сть. ꙗ҆ви́хъ и҆́мѧ твоѐ человѣ́кѡмъ, и҆̀хже да́лъ є҆сѝ мнѣ̀ ѿ мі́ра: твоѝ бѣ́ша, и҆ мнѣ̀ и҆̀хъ да́лъ є҆сѝ, и҆ сло́во твоѐ сохрани́ша. ны́нѣ разꙋмѣ́ша, ꙗ҆́кѡ всѧ̑, є҆ли̑ка да́лъ є҆сѝ мнѣ̀, ѿ тебѐ сꙋ́ть: ꙗ҆́кѡ глаго́лы, и҆̀хже да́лъ є҆сѝ мнѣ̀, да́хъ и҆̀мъ: и҆ ті́и прїѧ́ша, и҆ разꙋмѣ́ша вои́стиннꙋ, ꙗ҆́кѡ ѿ тебѐ и҆зыдо́хъ, и҆ вѣ́роваша, ꙗ҆́кѡ ты́ мѧ посла̀. а҆́зъ ѡ҆ си́хъ молю̀: не ѡ҆ все́мъ мі́рѣ молю̀, но ѡ҆ тѣ́хъ, и҆̀хже да́лъ є҆сѝ мнѣ̀, ꙗ҆́кѡ твоѝ сꙋ́ть. и҆ моѧ̑ всѧ̑, твоѧ̑ сꙋ́ть: и҆ твоѧ̑, моѧ̑: и҆ просла́вихсѧ въ ни́хъ. и҆ ктомꙋ̀ нѣ́смь въ мі́рѣ, и҆ сі́и въ мі́рѣ сꙋ́ть, и҆ а҆́зъ къ тебѣ̀ грѧдꙋ̀. ѻ҆́ч҃е ст҃ы́й, соблюдѝ и҆̀хъ во и҆́мѧ твоѐ, и҆̀хже да́лъ є҆сѝ мнѣ̀, да бꙋ́дꙋтъ є҆ди́но, ꙗ҆́коже и҆ мы̀. є҆гда̀ бѣ́хъ съ ни́ми въ мі́рѣ, а҆́зъ соблюда́хъ и҆̀хъ во и҆́мѧ твоѐ: и҆̀хже да́лъ є҆сѝ мнѣ̀, сохрани́хъ, и҆ никто́же ѿ ни́хъ поги́бе, то́кмѡ сы́нъ поги́бельный, да сбꙋ́детсѧ писа́нїе. ны́нѣ же къ тебѣ̀ грѧдꙋ̀, и҆ сїѧ̑ глаго́лю въ мі́рѣ да и҆́мꙋтъ ра́дость мою̀ и҆спо́лненꙋ въ себѣ̀. ",
}

add_evangelie_ioanna {
  ["номер"] = 57,
  ["комментарий"] = "Ин., 57 зач., XVII, 18–26.",
  ["текст_ру"] = "Во вре́мя о́но, возве́д Иису́с о́чи Свои́ на не́бо, и рече́: я́коже Ты Мя, О́тче, посла́л еси́ в мир, и Аз посла́х их в мир, и за них Аз свящу́ Себе́, да и ти́и бу́дут свяще́ни во и́стину. Не о сих же молю́ то́кмо, но и о ве́рующих словесе́ их ра́ди в Мя, да вси еди́но бу́дут, я́коже Ты, О́тче, во Мне, и Аз в Тебе́, да и ти́и в Нас еди́но бу́дут, да и мир ве́ру и́мет, я́ко Ты Мя посла́л еси́. И Аз сла́ву, ю́же дал еси́ Мне, дах им, да бу́дут еди́но, я́коже Мы еди́но есма́. Аз в них, и Ты во Мне, да бу́дут сверше́ни во еди́но, и да разуме́ет мир, я́ко Ты Мя посла́ и возлюби́л еси́ их, я́коже Мене́ возлюби́л еси́. О́тче, и́хже дал еси́ Мне, хощу́, да иде́же есмь Аз, и ти́и бу́дут со Мно́ю, да ви́дят сла́ву Мою́, ю́же дал еси́ Мне, я́ко возлюби́л Мя еси́ пре́жде сложе́ния ми́ра. О́тче пра́ведный, и мир Тебе́ не позна́, Аз же Тя позна́х, и си́и позна́ша, я́ко Ты Мя посла́ еси́. И сказа́х им и́мя Твое́, и скажу́, да любы́, е́юже Мя еси́ возлюби́л, в них бу́дет, и Аз в них. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, возве́дъ і҆и҃съ ѻ҆́чи своѝ на нб҃о, и҆ речѐ: ꙗ҆́коже ты́ мѧ ѻ҆́ч҃е посла́лъ є҆сѝ въ мі́ръ, и҆ а҆́зъ посла́хъ и҆̀хъ въ мі́ръ. и҆ за ни́хъ а҆́зъ свѧщꙋ̀ себѐ, да и҆ ті́и бꙋ́дꙋтъ свѧще́ни во и҆́стинꙋ. не ѡ҆ си́хъ же молю̀ то́кмѡ, но и҆ ѡ҆ вѣ́рꙋющихъ словесѐ и҆́хъ ра́ди въ мѧ̀. да всѝ є҆ди́но сꙋ́ть, ꙗ҆́коже ты̀ ѻ҆́ч҃е во мнѣ̀, и҆ а҆́зъ въ тебѣ̀, да и҆ ті́и въ на́съ є҆ди́но бꙋ́дꙋтъ: да и҆ мі́ръ вѣ́рꙋ и҆́метъ, ꙗ҆́кѡ ты́ мѧ посла́лъ є҆сѝ. и҆ а҆́зъ сла́вꙋ, ю҆́же да́лъ є҆сѝ мнѣ̀, да́хъ и҆̀мъ: да бꙋ́дꙋтъ є҆ди́но, ꙗ҆́коже мы̀ є҆ди́но є҆сма̀. а҆́зъ въ ни́хъ, и҆ ты̀ во мнѣ̀, да бꙋ́дꙋтъ сверше́ни во є҆ди́но, и҆ да разꙋмѣ́етъ мі́ръ, ꙗ҆́кѡ ты́ мѧ посла̀, и҆ возлюби́лъ є҆сѝ и҆̀хъ, ꙗ҆́коже менѐ возлюби́лъ є҆сѝ. ѻ҆́ч҃е, и҆̀хже да́лъ є҆сѝ мнѣ̀, хощꙋ̀, да и҆дѣ́же є҆́смь а҆́зъ, и҆ ті́и бꙋ́дꙋтъ со мно́ю: да ви́дѧтъ сла́вꙋ мою̀, ю҆́же да́лъ є҆сѝ мнѣ̀, ꙗ҆́кѡ возлюби́лъ мѧ̀ є҆сѝ пре́жде сложе́нїѧ мі́ра. ѻ҆́ч҃е пра́ведный, и҆ мі́ръ тебѐ не позна̀, а҆́зъ же тѧ̀ позна́хъ, и҆ сі́и позна́ша, ꙗ҆́кѡ ты́ мѧ посла̀ є҆сѝ. и҆ сказа́хъ и҆̀мъ и҆́мѧ твоѐ, и҆ скажꙋ̀, да любы̀, є҆́юже мѧ̀ є҆сѝ возлюби́лъ, въ ни́хъ бꙋ́детъ, и҆ а҆́зъ въ ни́хъ. ",
}

add_evangelie_ioanna {
  ["номер"] = 58,
  ["комментарий"] = "Ин., 58 зач., XVIII, 1-28.",
  ["текст_ру"] = "Во вре́мя о́но, изы́де Иису́с со ученики́ Свои́ми на он пол пото́ка Ке́дрска, иде́же бе вертогра́д, во́ньже вни́де Сам и ученицы́ Его́. Ве́дяше же Иу́да предая́й Его́ ме́сто, я́ко мно́жицею собира́шеся Иису́с ту со ученики́ Свои́ми. Иу́да же прие́м спи́ру и от архиере́й и фарисе́й слуги́, прии́де та́мо со свети́лы и свеща́ми и ору́жии. Иису́с же ве́дый вся гряду́щая Нань, изше́д рече́ им: кого́ и́щете? Отвеща́ша Ему́: Иису́са Назоре́а. Глаго́ла им Иису́с: Аз есмь. Стоя́ше же и Иу́да, и́же предая́ше Его́, с ни́ми. Да я́коже рече́ им: Аз есмь, идо́ша вспять и падо́ша на земли́. Па́ки же вопроси́ их Иису́с: кого́ и́щете? Они́ же ре́ша: Иису́са Назоре́а. Отвеща́ Иису́с: рех вам, я́ко Аз есмь. А́ще у́бо Мене́ и́щете, оста́вите сих ити́. Да сбу́дется сло́во, е́же рече́, я́ко и́хже дал еси́ Мне, не погуби́х от них никого́же. Си́мон же Петр, имы́й нож, извлече́ его́ и уда́ри архиере́ова раба́ и уре́за ему́ у́хо десно́е, бе же и́мя рабу́ Малх. Рече́ же Иису́с Петро́ви: вонзи́ нож в но́жницу, ча́шу, ю́же даст Мне Оте́ц, не и́мам ли пи́ти ея́? Спи́ра же и ты́сящник и слуги́ иуде́йския я́ша Иису́са и связа́ша Его́, и ведо́ша Его́ ко А́нне пе́рвее, бе бо тесть Каиа́фе, и́же бе архиере́й ле́ту тому́. Бе же Каиа́фа да́вый сове́т иуде́ом, я́ко у́не есть еди́ному челове́ку умре́ти за лю́ди. По Иису́се же идя́ше Си́мон Петр и други́й учени́к, учени́к же той бе зна́емь архиере́ови и вни́де со Иису́сом во двор архиере́ов. Петр же стоя́ше при две́рех вне. Изы́де у́бо учени́к той, и́же бе зна́емь архиере́ови, и рече́ две́рнице и введе́ Петра́. Глаго́ла же раба́ две́рница Петро́ви: еда́ и ты учени́к еси́ Челове́ка Сего́? Глаго́ла он: несмь. Стоя́ху же раби́ и слуги́ огнь сотво́рше, я́ко зима́ бе, и гре́яхуся, бе же с ни́ми Петр стоя́ и гре́яся. Архиере́й же вопроси́ Иису́са о ученице́х Его́ и о уче́нии Его́. Отвеща́ ему́ Иису́с: Аз не обину́яся глаго́лах ми́ру, Аз всегда́ уча́х на со́нмищах и в це́ркви, иде́же всегда́ иуде́е сне́млются, и тай не глаго́лах ничесо́же, что Мя вопроша́еши? Вопроси́ слы́шавших, что глаго́лах им, се си́и ве́дят, я́же рех Аз. Сия́ же ре́кшу Ему́, еди́н от предстоя́щих слуг уда́ри в лани́ту Иису́са, рек: та́ко ли отвещава́еши архиере́ови? Отвеща́ ему́ Иису́с: а́ще зле глаго́лах, свиде́тельствуй о зле, а́ще ли до́бре, что Мя бие́ши? Посла́ же Его́ А́нна свя́зана к Каиа́фе архиере́ови. Бе же Си́мон Петр стоя́ и гре́яся. Ре́ша же ему́: еда́ и ты от учени́к Его́ еси́? Он же отве́ржеся и рече́: несмь. Глаго́ла еди́н от раб архиере́ов, ю́жика сый, ему́же Петр уре́за у́хо: не аз ли тя ви́дех в вертогра́де с Ним? Па́ки у́бо Петр отве́ржеся, и а́бие пе́тель возгласи́. Ведо́ша же Иису́са от Каиа́фы в прето́р. Бе же у́тро, и ти́и не внидо́ша в прето́р, да не оскверня́тся, но да ядя́т фа́ску. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, и҆зы́де і҆и҃съ со ᲂу҆ченикѝ свои́ми на ѻ҆́нъ по́лъ пото́ка ке́дрска, и҆дѣ́же бѣ̀ вертогра́дъ, во́ньже вни́де са́мъ и҆ ᲂу҆ченицы̀ є҆гѡ̀. вѣ́дѧше же і҆ꙋ́да предаѧ́й є҆го̀ мѣ́сто, ꙗ҆́кѡ мно́жицею. собира́шесѧ і҆и҃съ тꙋ̀ со ᲂу҆ченикѝ свои́ми. і҆ꙋ́да же прїе́мъ спі́рꙋ, и҆ ѿ а҆рхїерє́й и҆ фарїсє́й слꙋги̑, прїи́де та́мѡ со свѣти́лы и҆ свѣща́ми и҆ ѻ҆рꙋ́жїи. і҆и҃съ же вѣ́дый всѧ̑ грѧдꙋ̑щаѧ на́нь, и҆зше́дъ речѐ и҆̀мъ: когѡ̀ и҆́щете; ѿвѣща́ша є҆мꙋ̀: і҆и҃са назѡре́а. глаго́ла и҆̀мъ і҆и҃съ: а҆́зъ є҆́смь. стоѧ́ше же и҆ і҆ꙋ́да, и҆́же предаѧ́ше є҆го̀, съ ни́ми: да ꙗ҆́коже речѐ и҆̀мъ, а҆́зъ є҆́смь, и҆до́ша вспѧ́ть, и҆ падо́ша на землѝ. па́ки же вопросѝ и҆̀хъ і҆и҃съ: когѡ̀ и҆́щете; ѻ҆ни́ же рѣ́ша: і҆и҃са назѡре́а. ѿвѣща̀ і҆и҃съ: рѣ́хъ ва́мъ, ꙗ҆́кѡ а҆́зъ є҆́смь. а҆́ще ᲂу҆̀бо менѐ и҆́щете, ѡ҆ста́вите си́хъ и҆тѝ. да сбꙋ́детсѧ сло́во є҆́же речѐ: ꙗ҆́кѡ и҆̀хже да́лъ є҆сѝ мнѣ̀, не погꙋби́хъ ѿ ни́хъ никогѡ́же. сі́мѡнъ же пе́тръ и҆мы́й но́жъ, и҆звлечѐ є҆го̀, и҆ ᲂу҆да́ри а҆рхїере́ова раба̀, и҆ ᲂу҆рѣ́за є҆мꙋ̀ ᲂу҆́хо десно́е: бѣ́ же и҆́мѧ рабꙋ̀ ма́лхъ. рече́ же і҆и҃съ петро́ви: вонзѝ но́жъ въ но́жницꙋ. ча́шꙋ ю҆́же да́стъ мнѣ̀ ѻ҆ц҃ъ, не и҆́мамъ ли пи́ти є҆ѧ̀; спі́ра же и҆ ты́сѧщникъ, и҆ слꙋги̑ і҆ꙋдє́йскїѧ ꙗ҆́ша і҆и҃са и҆ свѧза́ша є҆го̀. и҆ ведо́ша є҆го̀ ко а҆́ннѣ пе́рвѣе, бѣ́ бо те́сть каїа́фѣ, и҆́же бѣ̀ а҆рхїере́й лѣ́тꙋ томꙋ̀. бѣ́ же каїа́фа да́вый совѣ́тъ і҆ꙋде́ѡмъ, ꙗ҆́кѡ ᲂу҆́не є҆́сть є҆ди́номꙋ человѣ́кꙋ ᲂу҆мре́ти за лю́ди. по і҆и҃сѣ же и҆дѧ́ше сі́мѡнъ пе́тръ, и҆ дрꙋгі́й ᲂу҆чени́къ: ᲂу҆чени́къ же то́й бѣ̀ зна́емь а҆рхїере́ови, и҆ вни́де со і҆и҃сомъ во дво́ръ а҆рхїере́овъ. пе́тръ же стоѧ́ше при две́рехъ внѣ̀: и҆зы́де ᲂу҆́бѡ ᲂу҆чени́къ то́й, и҆́же бѣ̀ зна́емь а҆рхїере́ови, и҆ речѐ две́рницѣ, и҆ введѐ петра̀. глаго́ла же раба̀ две́рница петро́ви: є҆да̀ и҆ ты̀ ᲂу҆чени́къ є҆сѝ человѣ́ка сегѡ̀; глаго́ла ѻ҆́нъ: нѣ́смь. стоѧ́хꙋ же рабѝ и҆ слꙋгѝ ѻ҆́гнь сотво́рше, ꙗ҆́кѡ зима̀ бѣ̀, и҆ грѣ́ѧхꙋсѧ. бѣ́ же съ ни́ми пе́тръ стоѧ̀ и҆ грѣ́ѧсѧ. а҆рхїере́й же вопросѝ і҆и҃са ѡ҆ ᲂу҆ченицѣ́хъ є҆гѡ̀, и҆ ѡ҆ ᲂу҆че́нїи є҆гѡ̀. ѿвѣща̀ є҆мꙋ̀ і҆и҃съ: а҆́зъ не ѡ҆бинꙋ́ѧсѧ глаго́лахъ мі́рꙋ: а҆́зъ всегда̀ ᲂу҆ча́хъ на со́нмищихъ, и҆ въ це́ркви, и҆дѣ́же всегда̀ і҆ꙋде́є сне́млютсѧ, и҆ та́й не глаго́лахъ ничесѡ́же. что́ мѧ вопроша́еши; вопросѝ слы́шавшихъ, что̀ глаго́лахъ и҆̀мъ: сѐ сі́и вѣ́дѧтъ, ꙗ҆̀же рѣ́хъ а҆́зъ. сїѧ̑ же ре́кшꙋ є҆мꙋ̀, є҆ди́нъ ѿ предстоѧ́щихъ слꙋ́гъ ᲂу҆да́ри въ лани́тꙋ і҆и҃са, ре́къ: та́кѡ ли ѿвѣщава́еши а҆рхїере́ови; ѿвѣща̀ є҆мꙋ̀ і҆и҃съ: а҆́ще ѕлѣ̀ глаго́лахъ, свидѣ́тельствꙋй ѡ҆ ѕлѣ̀: а҆́ще ли до́брѣ, что́ мѧ бїе́ши; посла́ же є҆го̀ а҆́нна свѧ́зана къ каїа́фѣ а҆рхїере́ови. бѣ́ же сі́мѡнъ пе́тръ стоѧ̀ и҆ грѣ́ѧсѧ. рѣ́ша же є҆мꙋ̀: є҆да̀ и҆ ты̀ ѿ ᲂу҆чени̑къ є҆гѡ̀ є҆сѝ; ѻ҆́нъ же ѿве́ржесѧ, и҆ речѐ: нѣ́смь. глаго́ла є҆ди́нъ ѿ ра̑бъ а҆рхїере́ѡвъ, ю҆́жика сы́й, є҆мꙋ́же пе́тръ ᲂу҆рѣ́за ᲂу҆́хо: не а҆́зъ ли тѧ̀ ви́дѣхъ въ вертогра́дѣ съ ни́мъ; па́ки ᲂу҆́бѡ пе́тръ ѿве́ржесѧ: и҆ а҆́бїе пѣ́телъ возгласѝ. ведо́ша же і҆и҃са ѿ каїа́фы въ претѡ́ръ: бѣ́ же ᲂу҆́тро: и҆ ті́и не внидо́ша въ претѡ́ръ, да не ѡ҆сквернѧ́тсѧ, но да ꙗ҆дѧ́тъ фа́скꙋ. ",
}

