add_evangelie_ioanna {
  ["номер"] = 66,
  ["комментарий"] = "Ин., 66 зач., XXI, 1–14.",
  ["текст_ру"] = "Во вре́мя о́но, яви́ся Иису́с ученико́м Свои́м, воста́в от ме́ртвых, на мо́ри Тивериа́дстем. Яви́ся же си́це: бя́ху вку́пе Си́мон Петр, и Фома́ нарица́емыи Близне́ц, и Нафана́ил, и́же бе от Ка́ны Галиле́йския, и сы́на Зеведе́ова, и и́на от учени́к Его́ два. Глаго́ла им Си́мон Петр: иду́ ры́бы лови́ти. Глаго́лаша ему́: и́дем и мы с тобо́ю. Изыдо́ша же и вседо́ша а́бие в кора́бль, и в ту нощь не я́ша ничесо́же. У́тру же бы́вшу, ста Иису́с при бре́зе, не позна́ша же ученицы́, я́ко Иису́с есть. Глаго́ла же им Иису́с: де́ти, еда́ что сне́дно и́мате? Отвеща́ша Ему́: ни. Он же рече́ им: вве́рзите мре́жу одесну́ю страну́ корабля́ и обря́щете. Вверго́ша же и ктому́ не можа́ху привлещи́ ея́ от мно́жества рыб. Глаго́ла же учени́к той, его́же любля́ше Иису́с, Петро́ви: Госпо́дь есть. Си́мон же Петр слы́шав, я́ко Госпо́дь есть, епенди́том препоя́сася, бе бо наг, и вве́ржеся в мо́ре, а друзи́и ученицы́ кораблеце́м приидо́ша, не бе́ша бо дале́че от земли́, но я́ко две сте лакте́й, влеку́ще мре́жу рыб. Я́коже излезо́ша на зе́млю, ви́деша огнь лежа́щь и ры́бу на нем лежа́щу и хлеб. И глаго́ла им Иису́с: принеси́те от рыб, я́же я́сте ны́не. Влез же Си́мон Петр, извлече́ мре́жу на зе́млю, по́лну вели́ких рыб сто и пятьдеся́т и три, и толи́ку су́щу, не прото́ржеся мре́жа. Глаго́ла им Иису́с: прииди́те, обе́дуйте. Ни еди́н же сме́яше от учени́к истяза́ти Его́: Ты кто еси́? Ве́дяще, я́ко Госпо́дь есть. Прии́де же Иису́с, и прия́т хлеб и даде́ им, и ры́бу та́кожде. Се уже́ тре́тие яви́ся Иису́с ученико́м Свои́м, воста́в от ме́ртвых. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ꙗ҆ви́сѧ і҆и҃съ ᲂу҆ченикѡ́мъ свои́мъ, воста́въ ѿ ме́ртвыхъ, на мо́ри тїверїа́дстѣмъ, ꙗ҆ви́сѧ же си́це. бѧ́хꙋ вкꙋ́пѣ сі́мѡнъ пе́тръ, и҆ ѳѡма̀ нарица́емый близне́цъ, и҆ наѳана́илъ, и҆́же бѣ̀ ѿ ка́ны галїле́йскїѧ, и҆ сн҃а зеведе́ѡва, и҆ и҆́на ѿ ᲂу҆чени̑къ є҆гѡ̀ два̀. глаго́ла и҆̀мъ сі́мѡнъ пе́тръ: и҆дꙋ̀ ры̑бы лови́ти. глаго́лаша є҆мꙋ̀: и҆́демъ и҆ мы̀ съ тобо́ю. и҆зыдо́ша же, и҆ всѣдо́ша а҆́бїе въ кора́бль, и҆ въ тꙋ̀ но́щь не ꙗ҆́ша ничесѡ́же. ᲂу҆́трꙋ же бы́вшꙋ ста̀ і҆и҃съ при бре́зѣ: не позна́ша же ᲂу҆ченицы̀, ꙗ҆́кѡ і҆и҃съ є҆́сть. глаго́ла же и҆̀мъ і҆и҃съ: дѣ́ти, є҆да̀ что̀ снѣ́дно и҆́мате; ѿвѣща́ша є҆мꙋ̀: нѝ. ѻ҆́нъ же речѐ и҆̀мъ: вве́рзите мре́жꙋ ѡ҆деснꙋ́ю странꙋ̀ кораблѧ̀, и҆ ѡ҆брѧ́щете. вверго́ша же, и҆ ктомꙋ̀ не можа́хꙋ привлещѝ є҆ѧ̀ ѿ мно́жества ры́бъ. глаго́ла же ᲂу҆чени́къ то́й, є҆го́же люблѧ́ше і҆и҃съ, петро́ви: гдⷭ҇ь є҆́сть. сі́мѡнъ же пе́тръ слы́шавъ, ꙗ҆́кѡ гдⷭ҇ь є҆́сть, є҆пендѵ́томъ препоѧ́сасѧ, бѣ́ бо на́гъ, и҆ вве́ржесѧ въ мо́ре. а҆ дрꙋзі́и ᲂу҆ченицы̀ кораблеце́мъ прїидо́ша, не бѣ́ша бо дале́че ѿ землѝ, но ꙗ҆́кѡ двѣ̀ стѣ̀ лакте́й, влекꙋ́ще мре́жꙋ ры́бъ: ꙗ҆́коже и҆злѣзо́ша на зе́млю, ви́дѣша ѻ҆́гнь лежа́щъ, и҆ ры́бꙋ на не́мъ лежа́щꙋ, и҆ хлѣ́бъ. и҆ глаго́ла и҆̀мъ і҆и҃съ: принеси́те ѿ ры́бъ ꙗ҆̀же ꙗ҆́сте ны́нѣ. влѣ́зъ же сі́мѡнъ пе́тръ, и҆звлечѐ мре́жꙋ на зе́млю, по́лнꙋ вели́кихъ ры́бъ, сто̀ и҆ пѧтьдесѧ́тъ и҆ трѝ: и҆ толи́кꙋ сꙋ́щꙋ не прото́ржесѧ мре́жа. глаго́ла и҆̀мъ і҆и҃съ: прїиди́те, ѡ҆бѣ́дꙋйте. ни є҆ди́нъ же смѣ́ѧше ѿ ᲂу҆чени̑къ и҆стѧза́ти є҆го̀, ты̀ кто̀ є҆сѝ; вѣ́дѧще, ꙗ҆́кѡ гдⷭ҇ь є҆́сть. прїи́де же і҆и҃съ, и҆ прїѧ́тъ хлѣ́бъ, и҆ дадѐ и҆̀мъ, и҆ ры́бꙋ та́кожде. сѐ ᲂу҆жѐ тре́тїе ꙗ҆ви́сѧ і҆и҃съ ᲂу҆ченикѡ́мъ свои́мъ, воста́въ ѿ ме́ртвыхъ. ",
}

add_evangelie_ioanna {
  ["номер"] = 67,
  ["комментарий"] = "Ин., 67 зач., XXI, 15–25.",
  ["текст_ру"] = "Во вре́мя о́но, яви́ся Иису́с ученико́м Свои́м, воста́в от ме́ртвых. И глаго́ла Си́мону Петру́: Си́моне Ио́нин, лю́биши ли Мя па́че сих? Глаго́ла Ему́: ей, Го́споди, Ты ве́си, я́ко люблю́ Тя. Глаго́ла ему́: паси́ а́гнцы Моя́. Глаго́ла ему́ па́ки второ́е: Си́моне Ио́нин, лю́биши ли Мя? Глаго́ла ему́: ей, Го́споди, Ты ве́си, я́ко люблю́ Тя. Глаго́ла ему́: паси́ о́вцы Моя́. Глаго́ла ему́ тре́тие: Си́моне Ио́нин, лю́биши ли Мя? Оскорбе́ же Петр, я́ко рече́ ему́ тре́тие, лю́биши ли Мя; и глаго́ла Ему́: Го́споди, Ты вся ве́си, Ты ве́си, я́ко люблю́ Тя. Глаго́ла ему́ Иису́с: паси́ о́вцы Моя́. Ами́нь, ами́нь, глаго́лю тебе́, егда́ бе юн, поя́сашеся сам, и хожда́ше, а́може хотя́ше, егда́ же состаре́ешися и возде́жеши ру́це твои́, и ин тя поя́шет, и веде́т, а́може не хо́щеши. Сие́ же рече́, назна́менуя, ко́ею сме́ртию просла́вит Бо́га. И сия́ рек, глаго́ла ему́: иди́ по Мне. Обра́щься же Петр, ви́де ученика́, его́же любля́ше Иису́с, во след иду́ща, и́же и возлеже́ на ве́чери на пе́рси Его́, и рече́: Го́споди, кто есть предая́й Тя? Сего́ ви́дев Петр, глаго́ла Иису́сови: Го́споди, сей же что? Глаго́ла ему́ Иису́с: а́ще хощу́, да той пребыва́ет, до́ндеже прииду́, что к тебе́? Ты по Мне гряди́. Изы́де же сло́во се в бра́тию, я́ко учени́к той не у́мрет, и не рече́ ему́ Иису́с, я́ко не у́мрет, но а́ще хощу́ тому́ пребыва́ти, до́ндеже прииду́, что к тебе́? Сей есть учени́к свиде́тельствуяй о сих, и́же и написа́ сия́, и вем, я́ко и́стинно есть свиде́тельство его́. Суть же и и́на мно́га, я́же сотвори́ Иису́с, я́же а́ще бы по еди́ному пи́сана быва́ют, ни самому́ мню всему́ ми́ру вмести́ти пи́шемых книг. Ами́нь. ",
  ["текст_цс"] = "Во вре́мѧ ѻ҆́но, ꙗ҆ви́сѧ і҆и҃съ ᲂу҆ченикѡ́мъ свои́мъ воста́въ ѿ ме́ртвыхъ, и҆ глаго́ла сі́мѡнꙋ петрꙋ̀: сі́мѡне і҆ѡ́нинъ, лю́биши ли мѧ̀ па́че си́хъ; глаго́ла є҆мꙋ̀: є҆́й гдⷭ҇и, ты̀ вѣ́си, ꙗ҆́кѡ люблю́ тѧ. глаго́ла є҆мꙋ̀: пасѝ а҆́гнцы моѧ̀. глаго́ла є҆мꙋ̀ па́ки второ́е: сі́мѡне і҆ѡ́нинъ, лю́биши ли мѧ̀; глаго́ла є҆мꙋ̀: є҆́й гдⷭ҇и, ты̀ вѣ́си, ꙗ҆́кѡ люблю́ тѧ. глаго́ла є҆мꙋ̀: пасѝ ѻ҆́вцы моѧ̀. глаго́ла є҆мꙋ̀ тре́тїе: сі́мѡне і҆ѡ́нинъ, лю́биши ли мѧ̀; ѡ҆скорбѣ́ же пе́тръ, ꙗ҆́кѡ речѐ є҆мꙋ̀ тре́тїе, лю́биши ли мѧ̀; и҆ глаго́ла є҆мꙋ̀: гдⷭ҇и, ты̀ всѧ̑ вѣ́си, ты̀ вѣ́си, ꙗ҆́кѡ люблю́ тѧ. глаго́ла є҆мꙋ̀ і҆и҃съ: пасѝ ѻ҆́вцы моѧ̀. а҆ми́нь, а҆ми́нь глаго́лю тебѣ̀, є҆гда̀ бѣ̀ ю҆́нъ, поѧ́сашесѧ са́мъ, и҆ хожда́ше а҆́може хотѧ́ше: є҆гда́ же состарѣ́ешисѧ, и҆ воздѣ́жеши рꙋ́цѣ твоѝ, и҆ и҆́нъ тѧ̀ поѧ́шетъ, и҆ веде́тъ, а҆́може не хо́щеши. сїе́ же речѐ, назна́менꙋѧ, ко́ею сме́ртїю просла́витъ бг҃а. и҆ сїѧ̑ ре́къ, глаго́ла є҆мꙋ̀: и҆дѝ по мнѣ̀. ѡ҆бра́щсѧ же пе́тръ, ви́дѣ ᲂу҆ченика̀, є҆го́же люблѧ́ше і҆и҃съ, во слѣ́дъ и҆дꙋ́ща, и҆́же и҆ возлежѐ на ве́чери на пе́рси є҆гѡ̀, и҆ речѐ: гдⷭ҇и, кто́ є҆сть предаѧ́й тѧ̀; сего̀ ви́дѣвъ пе́тръ, глаго́ла і҆и҃сови: гдⷭ҇и, се́й же что̀; глаго́ла є҆мꙋ̀ і҆и҃съ: а҆́ще хощꙋ̀, да то́й пребыва́етъ, до́ндеже прїидꙋ̀, что̀ къ тебѣ̀; ты̀ по мнѣ̀ грѧдѝ. и҆зы́де же сло́во сѐ въ бра́тїю, ꙗ҆́кѡ ᲂу҆чени́къ то́й не ᲂу҆́мретъ: и҆ не речѐ є҆мꙋ̀ і҆и҃съ, ꙗ҆́кѡ не ᲂу҆́мретъ: но а҆́ще хощꙋ̀ томꙋ̀ пребыва́ти до́ндеже прїидꙋ̀, что̀ къ тебѣ̀; се́й є҆́сть ᲂу҆чени́къ свидѣ́тельствꙋѧй ѡ҆ си́хъ, и҆́же и҆ написа̀ сїѧ̑: и҆ вѣ́мъ, ꙗ҆́кѡ и҆́стинно є҆́сть свидѣ́тельство є҆гѡ̀. сꙋ́ть же и҆ и҆́на мнѡ́га, ꙗ҆̀же сотворѝ і҆и҃съ: ꙗ҆̀же а҆́ще бы по є҆ди́номꙋ пи́сана быва́ютъ, ни самомꙋ̀ мню̀ всемꙋ̀ мі́рꙋ вмѣсти́ти пи́шемыхъ кни́гъ. а҆ми́нь. ",
}

